--  DDL for Trigger COIL_HISTORY_LOG
--------------------------------------------------------

  CREATE OR REPLACE TRIGGER "DBO"."COIL_HISTORY_LOG" 
  after update on coil  
  for each row

declare
  -- local variables here
  li_coil integer;
  li_job integer;
  --li_shift_coil integer;
  counts integer;
  li_err_seq integer;
  li_line_num integer;
  cursor distinct_job_cursor(li_coil_id integer ) is
         SELECT DISTINCT PRODUCTION_SHEET_ITEM.AB_JOB_NUM, AB_JOB.LINE_NUM
         FROM PRODUCTION_SHEET_ITEM, AB_JOB
         WHERE PRODUCTION_SHEET_ITEM.AB_JOB_NUM = AB_JOB.AB_JOB_NUM and COIL_ABC_NUM = li_coil_id and AB_JOB.LINE_NUM in (6,7);
  
begin
  if (:new.coil_status != :old.coil_status or :new.net_wt_balance != :old.net_wt_balance ) then
     insert into coil_track (coil_abc_num,coil_track_date,
            coil_pre_status, coil_cur_status, coil_pre_netwt,
            coil_cur_netwt, coil_modified_by, coil_pre_location, coil_cur_location)
            values (:old.coil_abc_num, sysdate, :old.coil_status, :new.coil_status, :old.net_wt_balance, :new.net_wt_balance, USER,'','');
       if ( :new.coil_status != :old.coil_status and :new.coil_status = 0 ) then
          li_coil := :new.coil_abc_num;
          FOR c_job IN distinct_job_cursor(li_coil ) LOOP
              li_job := c_job.ab_job_num;
              li_line_num := c_job.line_num;
              
              SELECT COUNT(*) INTO counts
               FROM shift_coil
               WHERE shift_coil.ab_job_num = li_job and shift_coil.coil_abc_num = li_coil;
              if counts < 1 then
                 SELECT error_evt_seq.nextval INTO li_err_seq from dual;
                 INSERT INTO error_evt (error_evt_id, evt_time, error_type_id, error_user,error_comment, line_id, shift_id, coil_abc_num, ab_job_num, sheet_skid_num, scrap_skid_num, dt_instance_num, opc_item, title, message, script, line_in_script, db_error_code,db_error_text )
                 values(li_err_seq, sysdate, 1, 'dbo', 'DAS operator missed job or coil', li_line_num,null,li_coil,li_job,null,null,null,null,null,null,null,null,null,null  );
              end if;
          END LOOP;
       end if;
  end if;
  --commit;
end coil_history_log;


ALTER TRIGGER "DBO"."COIL_HISTORY_LOG" ENABLE
