--  DDL for Trigger DONE_JOB_LINE_PRIORITY
--------------------------------------------------------

  CREATE OR REPLACE TRIGGER "DBO"."DONE_JOB_LINE_PRIORITY" 
  after update on ab_job  
  for each row
declare
  --
begin
  if (:new.job_status != :old.job_status AND ((:new.job_status = 0) OR (:new.job_status = 3))) then
     Update line_priority
     Set Priority_num = 0
     WHERE ab_job_num = :new.ab_job_num;
   end if;
   --commit;
 end Done_job_line_priority;


