--  DDL for Trigger DT_INSTANCE_ADD_TO_DT_SUMMARY
--------------------------------------------------------

  CREATE OR REPLACE TRIGGER "DBO"."DT_INSTANCE_ADD_TO_DT_SUMMARY" 
  after update on shift  
  for each row
declare
  -- local variables here
  li_count integer;
  Cursor cur_job is
         select distinct dt_instance.ab_job_num
         from dt_instance
         where dt_instance.shift_num = :new.shift_num;
  Cursor cur_dt_id(al_job IN ab_job.ab_job_num%type) is
         select dt_instance_detail.id cause_id,count(dt_instance_detail.id) id_count, sum(dt_instance_detail.duration) sum_duration 
         from dt_instance, dt_instance_detail
         where dt_instance.shift_num = :new.shift_num and
               dt_instance.ab_job_num = al_job and
               dt_instance.instance_num = dt_instance_detail.instance_num
               group by dt_instance_detail.id;
         
begin
  --
  if (:old.end_time is null and :new.end_time is not null) then
      --delete from dt_summary
      --where dt_summary.shift_num = :new.shift_num;
      
      for job_rec in cur_job
      loop
          for id_rec in cur_dt_id(job_rec.ab_job_num)
          loop
              -- need a condition here. if summary for id/job exist, then update, else insert
              -- change it later
              select count(*) into li_count from dt_summary
              where dt_summary.shift_num = :new.shift_num and dt_summary.ab_job_num = job_rec.ab_job_num and dt_summary.id = id_rec.cause_id; 
              
              if li_count > 0 then
                 update dt_summary
                 set dt_summary.count = dt_summary.count + id_rec.id_count,
                     dt_summary.duration = dt_summary.duration + id_rec.sum_duration
                 where dt_summary.shift_num = :new.shift_num and dt_summary.ab_job_num = job_rec.ab_job_num and dt_summary.id = id_rec.cause_id;
              else
                  INSERT INTO dt_summary (shift_num, ab_job_num, id, Count, duration, note)
                   values (:new.shift_num, job_rec.ab_job_num, id_rec.cause_id, id_rec.id_count, id_rec.sum_duration, 'auto added from dt_instance_detail');
              end if;
          end loop;
      end loop;
      
  end if;
end DT_INSTANCE_ADD_TO_DT_SUMMARY;


ALTER TRIGGER "DBO"."DT_INSTANCE_ADD_TO_DT_SUMMARY" ENABLE
