  CREATE OR REPLACE TRIGGER "DBO"."JOB_TIME_DATE_FINISHED" 
  before update on AB_JOB
  for each row

DECLARE
  -- local variables here
  li_system_log_key_num system_log.system_log_key_num%TYPE;

BEGIN
  IF (:new.job_done_time IS NOT NULL) AND (:new.job_status = 0) AND
     (:old.time_date_finished IS NULL) THEN
    /*:new.time_date_finished := :new.job_done_time;*/
    :new.time_date_finished := f_get_last_process_coil_date(:new.ab_job_num);
  
    li_system_log_key_num := system_log_id_seq.nextval;
    INSERT INTO system_log
      (system_log_key_num, system_log_timestamp, system_log_contents)
    VALUES
      (li_system_log_key_num,
       SYSDATE,
       'JOB_TIME_DATE_FINISHED was triggered for AB_JOB# ' ||
       :new.ab_job_num || '.');
  
  END IF;

END job_time_date_finished;


