  CREATE OR REPLACE TRIGGER "DBO"."SCRAP_SKID_DISPLAY_NUM_ADD" 
  before insert on scrap_skid  
  for each row
DECLARE
  -- local variables here
  ls_novelis_location_prefix VARCHAR2(16);
BEGIN
  IF :new.customer_id IN (10,
                          35,
                          1086,
                          1532,
                          1132,
                          1153,
                          1174,
                          1248,
                          1281,
                          1304,
                          1430,
                          1446,
                          1459,
                          1609,
                          1657,
                          1749,
                          1778,
                          1781,
                          2173,
                          2322,
                          2342,
                          2343,
                          2582,
                          2950) THEN
    --Novelis
  
    SELECT so.system_option_value
      INTO ls_novelis_location_prefix
      FROM system_options so
     WHERE upper(so.system_option_name) = 'NOVELIS LOCATION PREFIX';
  
    :new.scrap_skid_display_num := ls_novelis_location_prefix ||
                                   to_char(:new.scrap_skid_num);
  ELSE
    :new.scrap_skid_display_num := to_char(:new.scrap_skid_num);
  
  END IF;

END scrap_skid_display_num_add;


