  CREATE OR REPLACE TRIGGER "DBO"."SHEET_SKID_DISPLAY_NUM_ADD" 
  before insert on sheet_skid  
  for each row
DECLARE
  -- local variables here
  li_customer_id             INT;
  ls_novelis_location_prefix VARCHAR2(16);
BEGIN
  SELECT co.orig_customer_id
    INTO li_customer_id
    FROM ab_job j, customer_order co, order_item oi
   WHERE j.order_abc_num = oi.order_abc_num
     AND j.order_item_num = oi.order_item_num
     AND oi.order_abc_num = co.order_abc_num
     AND j.ab_job_num = :new.ab_job_num;

  IF li_customer_id IN (10,
                        35,
                        1086,
                        1532,
                        1132,
                        1153,
                        1174,
                        1248,
                        1281,
                        1304,
                        1430,
                        1446,
                        1459,
                        1609,
                        1657,
                        1749,
                        1778,
                        1781,
                        2173,
                        2322,
                        2342,
                        2343,
                        2582,
                        2950) THEN
    --Novelis
  
    SELECT so.system_option_value
      INTO ls_novelis_location_prefix
      FROM system_options so
     WHERE upper(so.system_option_name) = 'NOVELIS LOCATION PREFIX';
  
    :new.sheet_skid_display_num := ls_novelis_location_prefix ||
                                   to_char(:new.sheet_skid_num);
  
  ELSE
    :new.sheet_skid_display_num := to_char(:new.sheet_skid_num);
  
  END IF;

END sheet_skid_display_num_add;


