--  DDL for Trigger SKID_HISTORY_LOG
--------------------------------------------------------

  CREATE OR REPLACE TRIGGER "DBO"."SKID_HISTORY_LOG" 
  after update on sheet_skid  
  for each row

declare
  -- local variables here
  log_file_handle UTL_FILE.FILE_TYPE;
begin
  if (:new.skid_sheet_status != :old.skid_sheet_status or :new.sheet_net_wt != :old.sheet_net_wt or :new.ref_order_abc_num != :old.ref_order_abc_num) then
     insert into skid_track (sheet_skid_num, log_date, pre_status, cur_status, pre_sheet_net_wt, cur_sheet_net_wt,
     pre_skid_pieces, cur_skid_pieces, modified_by, pre_ref_order_no, cur_ref_order_no)
            values (:old.sheet_skid_num, sysdate, :old.skid_sheet_status, :new.skid_sheet_status,
             :old.sheet_net_wt, :new.sheet_net_wt, :old.skid_pieces, :new.skid_pieces, USER, :old.ref_order_abc_num, :new.ref_order_abc_num);
  end if;

  --for status from  --> to
  --(non ready)  --> (Ready) or
  --(non onhold) --> (On-Hold)
  --(non partial-rd) --> (partial-rd)
  --clear the edi-870 flag for all skid items
  
  if ((:old.skid_sheet_status != 2 and :new.skid_sheet_status = 2) or (:old.skid_sheet_status !=4 and :new.skid_sheet_status = 4) or (:old.skid_sheet_status !=13 and :new.skid_sheet_status = 13))then
     update production_sheet_item set prod_item_edi870_date = null
     where (prod_item_num in (select prod_item_num from sheet_skid_detail where sheet_skid_num = :new.sheet_skid_num));
  end if;
  
EXCEPTION
         WHEN OTHERS THEN
         log_file_handle := UTL_FILE.FOPEN('/tmp', 'skid_trigger_err_log', 'A');
         UTL_FILE.PUT_LINE(log_file_handle, 'Error ' || :old.sheet_skid_num || '  ' || :old.skid_sheet_status);
         UTL_FILE.fclose(log_file_handle);
         RETURN;
end skid_history_log;




