            values (:old.prod_item_num, sysdate, :old.prod_item_net_wt, :new.prod_item_net_wt, USER, 0, :old.prod_item_pieces, :new.prod_item_pieces,:old.prod_item_theoretical_wt, :new.prod_item_theoretical_wt,  :old.ab_job_num, :new.ab_job_num, :old.coil_abc_num, :new.coil_abc_num,:old.prod_item_status, :new.prod_item_status);
