--  DDL for Procedure DELETE_SHIFT
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."DELETE_SHIFT" (al_id in shift.shift_num%type) is
         Cursor c_instance IS
         SELECT INSTANCE_NUM FROM DT_INSTANCE
         WHERE SHIFT_NUM = al_id;

begin
  FOR instances IN c_instance LOOP
      DELETE FROM DT_INSTANCE_DETAIL
      WHERE DT_INSTANCE_DETAIL.INSTANCE_NUM = instances.instance_num;
      DELETE FROM DT_INSTANCE
      WHERE DT_INSTANCE.INSTANCE_NUM = instances.instance_num;
  END LOOP;
  
  DELETE FROM SHIFT_COIL
  WHERE SHIFT_COIL.SHIFT_NUM = al_id;
  
  DELETE FROM SHIFT
  WHERE SHIFT.SHIFT_NUM = al_id;
  commit;
  
end DELETE_SHIFT;
  GRANT EXECUTE ON "DBO"."DELETE_SHIFT" TO "AGERLANTS"
