--  DDL for Procedure EDIALCANSCRAP870BYJOB_BACKUP
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."EDIALCANSCRAP870BYJOB_BACKUP" IS

/*
                   DUNS: 01 039630926T
                   Customer: ALCAN(34,35,10,1153)
                   Alcan Rolled Product  	X.121  		  0015049350011G
                   Kingston Duns: 241003755
*/


edi_loc varchar2 (50) := '/templar/templar/incoming/senddata';

--v_edi_text_alcan varchar2(32767);
--edi_loc varchar2(50):='/tmp';
edi_file varchar2 (50) := 'edi_out.txt';
edi_file_prefix varchar2 (50) := 'S_alcan_scrap';
edi_file_handle UTL_FILE.FILE_TYPE;
su_duns varchar2(10);
ll_customer_id integer :=1153;

ll_gs_log integer;
ll_st_log integer;
--scrap_job_num ab_job.ab_job_num%type;
prime_nw coil.net_wt%type;
scrap_nw coil.net_wt%type;
--ll_bsn_log integer;


ls_today varchar2(20):= to_char(sysdate, 'YYYYMMDD');
ls_today_4 varchar2(20):= to_char(sysdate, 'YYMMDD');
ls_now varchar2(20) := to_char(sysdate, 'HH24MI'); -- time in 24 hours format....Tony

ls_po varchar2(20);
ls_so varchar2(30);
--ll_edi_file_id integer;
ll_edi_file_id_alcan integer;

ll_job_count integer;
--coil_of_the_job coil.coil_abc_num%type;
ll_ab_job ab_job.ab_job_num%type;

--ll_onhold_wt coil.net_wt%type;
--ll_reject_wt coil.net_wt%type;
--ll_reband_wt coil.net_wt%type;

--li_customer_id shipment.customer_id%TYPE;
--li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;

--date1 date;
--date2 date;
--coil_ini_date date;


li_HL01 integer;

Cursor cust_cur is
SELECT customer_id from customer where customer_id in (1153,1459,2582);        ---Add customer id here if you want to send 870 for more customers


Cursor alcan_870_cur IS
       SELECT a.ab_job_num, b.orig_customer_po, nvl(b.sales_order, ' ') sales_order
       FROM ab_job a, customer_order b
       WHERE (a.order_abc_num = b.order_abc_num) and
             (a.job_status = 0) and
             (b.orig_customer_id = ll_customer_id) and
             (a.scrap_870_date is null);

Cursor coil_info IS
       SELECT process_coil.coil_abc_num, process_coil.process_quantity, coil.coil_alloy2, coil.coil_org_num, nvl(coil.consumed_coil_num, ' ') consumed_coil_num , process_coil.process_end_wt
       FROM process_coil, coil
       WHERE (process_coil.ab_job_num = ll_ab_job) and
             (process_coil.coil_abc_num = coil.coil_abc_num);


TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
 x12_table store_tabletype;
i binary_integer := 0;

TYPE job_num_type IS TABLE OF ab_job.ab_job_num%type INDEX BY BINARY_INTEGER;
job_num job_num_type;
j binary_integer :=0;

--item_rec alcan_870_cur%rowtype;

BEGIN

for cust_rec in cust_cur
loop --- Outer loop of customer_id
     ll_customer_id := cust_rec.customer_id;
     i:=0;
     j:=0;

     SELECT count(*) into ll_job_count
       FROM ab_job a, customer_order b
       WHERE (a.order_abc_num = b.order_abc_num) and
             (a.job_status = 0) and
             (b.orig_customer_id = ll_customer_id) and
             (a.scrap_870_date is null);

 IF ll_job_count <> 0 THEN

    SELECT edi_st_log_seq.NEXTVAL INTO ll_st_log FROM DUAL;
    SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;

    select customer.customer_duns_number_string into su_duns from customer where customer.customer_id = ll_customer_id;

    x12_table(i) := 'ISA*00*'||'          *00*          *01*039630926T     *09*0015049350011G *'||ls_today_4 ||'*'|| ls_now ||'*U*00401*'||LPAD(to_char(ll_gs_log),9,'0')||'*0*P**'; i := i + 1;
    x12_table(i) := 'GS*RS*039630926T*'||'001504935001' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '004010'; i := i + 1;
    x12_table(i):= 'ST*870*' || to_char(ll_st_log); i := i +1;
    x12_table(i):= 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today || '***' || ls_now || '*****'; i := i +1;
    x12_table(i):= 'DTM*009*' || ls_today || '*' || ls_now; i := i +1;
    x12_table(i) := 'N1*SU**1*' || su_duns ||'*NA'; i := i +1;
    x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926T'; i := i + 1;


    --open alcan_870_cur;
    --fetch alcan_870_cur INTO item_rec;
    --close alcan_870_cur;

    li_HL01 := 1;

    for job_rec IN alcan_870_cur -- job loop
    loop
        ll_ab_job := job_rec.ab_job_num;
        ls_po := job_rec.orig_customer_po;
        ls_so := job_rec.sales_order;
        --ls_po := item_rec.customer_po;
        IF INSTR(ls_po,'-') > 0
        THEN
            ls_po := substr(ls_po, 0, instr(ls_po,'-')-1);
        END IF;


        job_num(j) := ll_ab_job;
        j := j+1;

        for coil_rec IN coil_info   --coil loop
        loop
                SELECT NVL(sum(production_sheet_item.prod_item_net_wt),0) into prime_nw
                FROM production_sheet_item
                WHERE (production_sheet_item.ab_job_num = ll_ab_job) and
                      (production_sheet_item.coil_abc_num = coil_rec.coil_abc_num);

                --ll_onhold_wt := NVL(f_get_coil_onhold_wt(coil_rec.coil_abc_num, coil_rec.process_quantity),0);
                --ll_reband_wt := NVL(f_get_coil_rebanded_wt(coil_rec.coil_abc_num, coil_rec.process_quantity),0);
                --ll_reject_wt := NVL(f_get_coil_rejected_wt(coil_rec.coil_abc_num, coil_rec.process_quantity),0);

                --scrap_nw := coil_rec.process_quantity - ll_onhold_wt - ll_reband_wt - ll_reject_wt - prime_nw;

                scrap_nw := coil_rec.process_quantity - coil_rec.process_end_wt - prime_nw;



                IF scrap_nw > 0 then
                   x12_table(i) := 'HL*'||to_char(li_HL01)||'**I'; i := i +1;

                   /*
                   SELECT NVL(ALLOY_TYPE.ALCAN_SCRAP_PO, '6800'||coil_rec.coil_alloy2) into ls_po
                       FROM ALLOY_TYPE
                       WHERE ALLOY_TYPE.ALLOY = coil_rec.coil_alloy2;
                   */
                   x12_table(i) := 'PRF*' || ls_po ||'****NA'; i := i+1;
                   x12_table(i) := 'DTM*206*' ||ls_today || '*' || ls_now ||'*ED'; i := i+1;
                   x12_table(i) := 'REF*SE*' || 'T1' ||coil_rec.coil_abc_num || '-' ||to_char(ll_ab_job) ; i := i+1;
                   --x12_table(i) := 'REF*SE*' ||coil_rec.coil_org_num; i := i+1;

                   --x12_table(i) := 'REF*IX*' || coil_rec.consumed_coil_num;
                   --i := i + 1;


                   x12_table(i) := 'REF*MI*' || to_char(ll_ab_job); i := i+1;
                   --x12_table(i) := 'REF*RV*' ||coil_rec.coil_org_num ||'*NA'; i := i+1;
                   x12_table(i) := 'REF*RV*' || 'T1' || coil_rec.coil_abc_num || '-' || to_char(ll_ab_job) || '*NA'; i := i+1;

                   --x12_table(i) := 'PO1**1*UN****' || '***SN*' ||coil_rec.coil_org_num; i := i+1;


                   IF ls_so = ' ' THEN
                      x12_table(i) := 'PO1**1*UN****' || '***SN*' || coil_rec.coil_org_num;
                      i := i + 1;
                   ELSE
                      x12_table(i) := 'PO1**1*UN***VO*' || ls_so || '***SN*' || coil_rec.coil_org_num;
                      i := i + 1;
                   END IF;


                   x12_table(i) := 'PID*S*MA*ST*S'; i := i+1; -- ST*S for scrap --Tony

                   x12_table(i) := 'PID*S*MAC*ST*05'; i := i+1;
                   --x12_table(i) := 'PID*S*MAC*ST*03'; i := i+1; or this one , need test

                   x12_table(i) := 'PID*S*PR*ST*19'; i := i+1;
                   x12_table(i) := 'MEA*WT*N*' || to_char(scrap_nw) || '*LB*01'; i := i+1;

                   li_HL01 := li_HL01 +1;
                end if; -- end if scrap_nw >0
        end loop; -- end of coil loop
    end loop;     -- end of job loop



    x12_table(i) :=  'CTT*' || to_char(li_HL01 - 1); i := i+1;
    x12_table(i) :=  'SE*' || to_char (i-1) ||'*'|| to_char(ll_st_log); i := i+1;
    x12_table(i) :=  'GE*1*' || to_char (ll_gs_log); i := i+1;
    x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');


-- Write EDI to file

    IF li_HL01 > 1 then --write to file only if items > 0
         SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id_alcan FROM DUAL;
-- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
--                edi_file:= edi_file_prefix || to_char(ll_edi_file_id_alcan) ||'.870';
                edi_file:= edi_file_prefix || to_char(ll_edi_file_id_alcan) ||'.edi';
                edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');

                for j in 0..i loop
                    UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
                                                       -- v_edi_text_alcan:=v_edi_text_alcan||x12_table(j)||CHR(10);
                end loop;
         UTL_FILE.FCLOSE(edi_file_handle);
    END IF;

    /*--added by Victor Huang on 06/05 for function acknowlegement
    INSERT INTO edi_fa(gs_num, duns_num, send_time, edi_file_name)
    VALUES(ll_gs_log, su_duns, sysdate, edi_file);
    COMMIT;*/

    --added by Victor Huang on 12/07 for verifying 997
  INSERT INTO outbound_edi_transaction(edi_file_id,duns_from,duns_to,interchange_control_number,
  group_control_number,transaction_time,edi_file_name,fa_receive_status,customer_id,set_control_num,transaction_type_id)
  VALUES(ll_edi_file_id_alcan,'039630926',su_duns,ll_gs_log,ll_gs_log, sysdate, edi_file,0,ll_customer_id,ll_st_log,'870 Scrap');
  COMMIT;

    edi_file := 'send_edi_log';
    edi_file_handle :=utl_file.fopen(edi_loc,edi_file,'a');
    utl_file.put_line(edi_file_handle,'Type: 870 Scrap');
    utl_file.put_line(edi_file_handle,'Sending Time: '||to_char(sysdate, 'MM/DD/YY HH24:MI'));
    utl_file.put_line(edi_file_handle,'Interchange Control #: '||ll_gs_log);
    utl_file.put_line(edi_file_handle,'Group Control #: '||ll_gs_log);
    utl_file.put_line(edi_file_handle,'Set Control #: '||ll_st_log);
    utl_file.put_line(edi_file_handle,'');
    utl_file.put_line(edi_file_handle,'');
    utl_file.fclose(edi_file_handle);



         FOR k in 0..j-1
             LOOP
                UPDATE ab_job set ab_job.scrap_870_date = sysdate
                WHERE ab_job.ab_job_num = job_num(k);
             END LOOP;

         commit;


 END IF;       --end if in select count(*)



end loop; ------ End of outer loop customer_id


EXCEPTION
     WHEN NO_DATA_FOUND THEN
          DBMS_OUTPUT.put_line('NO DATA FOUND!!!');
          RETURN;
     WHEN UTL_FILE.INVALID_PATH THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN;
     WHEN UTL_FILE.INVALID_MODE THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN;
    WHEN UTL_FILE.INVALID_OPERATION THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN;
    WHEN UTL_FILE.WRITE_ERROR THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN;
    WHEN OTHERS THEN
     UTL_FILE.FCLOSE_ALL;
     DBMS_OUTPUT.put_line('ERROR!!');
      RETURN;

 END;
  GRANT EXECUTE ON "DBO"."EDIALCANSCRAP870BYJOB_BACKUP" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Procedure EDI_ALCAN_870
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."EDI_ALCAN_870" IS

  /*
  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   Customer: Aleris(1980) DUNS:964790856     EDI ID:964790856      QUALIFIER: ZZ

   End User: Aleris, Customer ID 1980
   */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50) := get_edi_destination('EDI_DIR');

  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_prefix VARCHAR2(50) := 'S_alcan_';
  edi_file_handle utl_file.file_type;
  su_duns         VARCHAR2(10);
  ll_customer_id  customer.customer_id%TYPE;
  ll_cur_coil     coil.coil_abc_num%TYPE;

--  ll_cur_job ab_job.ab_job_num%TYPE;

  ll_gs_log INTEGER;
  ll_st_log INTEGER;

  ls_today   VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD');
  ls_today_4 VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  ls_now     VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  ls_po VARCHAR2(20);
  ls_finished_goods VARCHAR2(32);
  ls_cust_prod_line VARCHAR2(8);

  ld_scrap_870_date ab_job.scrap_870_date%TYPE;

  ls_coil_org_num coil.coil_org_num%TYPE;
  ls_heat coil.lot_num%TYPE;

--  ll_ref_order_abc_num sheet_skid.ref_order_abc_num%TYPE;
--  ll_ref_order_abc_item sheet_skid.ref_order_abc_item%TYPE;
--  ls_sheet_type order_item.sheet_type%TYPE;

  ll_prime_nw coil.net_wt%TYPE;
  ll_scrap_nw coil.net_wt%TYPE;
--  ll_process_quantity  coil.net_wt%TYPE;
--  ll_process_end_wt  coil.net_wt%TYPE;
--  lr_theo_unit_wt order_item.theoretical_unit_wt%TYPE;

  --ll_edi_file_id integer;
  ll_edi_file_id_aleris INTEGER;

  ll_item_count INTEGER;

  li_hl01 INTEGER;
  li_hllin INTEGER;

  CURSOR cust_cur IS
    SELECT customer_id FROM customer WHERE customer_id IN (1153,1459,2582); ---Add customer id here if you want to send 870 for more customers

  CURSOR coil_cur IS
  SELECT UNIQUE C.COIL_ABC_NUM
  FROM SHEET_SKID_DETAIL SKD
    JOIN SHEET_SKID SK ON SKD.SHEET_SKID_NUM = SK.SHEET_SKID_NUM
    JOIN PRODUCTION_SHEET_ITEM PSI ON SKD.PROD_ITEM_NUM = PSI.PROD_ITEM_NUM
    JOIN COIL C ON PSI.COIL_ABC_NUM = C.COIL_ABC_NUM
    JOIN AB_JOB AB ON SK.AB_JOB_NUM = AB.AB_JOB_NUM
    JOIN CUSTOMER_ORDER CO ON CO.ORDER_ABC_NUM = AB.ORDER_ABC_NUM
  WHERE (AB.JOB_STATUS = 0) AND
    ( C.COIL_STATUS IN (0, 3) ) AND
    ( CO.ORIG_CUSTOMER_ID = ll_customer_id ) AND
    ( PSI.PROD_ITEM_EDI870_DATE is NULL ) AND
    ( C.SCRAP_870_DATE is NULL ) AND
    ( SK.SKID_SHEET_STATUS in (0,2,4,12,13, 16) ); --Alex Gerlants. 03/22/2019. Added new status 16-Hold For Cert

  CURSOR alcan_870_cur IS
   SELECT production_sheet_item.ab_job_num,
           production_sheet_item.coil_abc_num,
           production_sheet_item.prod_item_pieces,
           production_sheet_item.prod_item_num,
           sheet_skid.sheet_skid_num,
           production_sheet_item.prod_item_net_wt,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_skid_display_num,
           sheet_skid.sheet_net_wt,
           sheet_skid.skid_pieces,
           coil.coil_org_num,
           coil.lot_num,
           nvl(coil.consumed_coil_num, ' ') consumed_coil,
           nvl(coil.material_num, ' ') material_num,
           nvl(customer_order.sales_order, ' ') sales_order,
           nvl(customer_order.orig_customer_po, 'NA') customer_po,
           nvl(order_item.enduser_part_num, ' ') enduser_parts,
           nvl(order_item.cust_prod_line_id, 'NA') customer_line_id,
           nvl(order_item.finished_goods_material_num, 'NA') finished_goods,
           (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
           NULL done
      FROM sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil,
           order_item,
           ab_job,
           customer_order
     WHERE (sheet_skid.skid_sheet_status IN (0, 2, 4, 13, 12, 16)) -- 2: Ready; 8: Warehouse Ready; 13: Partial Ready; 7: Partial; 12: Sample; 4: onhold
                                                                    --Alex Gerlants. 03/22/2019. Added new status 16-Hold For Cert
       AND (production_sheet_item.prod_item_edi870_date IS NULL)
       AND (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       AND (sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num)
       AND (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       AND (coil.customer_id = ll_customer_id)
       AND (sheet_skid.ref_order_abc_num = customer_order.order_abc_num)
       AND (production_sheet_item.ab_job_num = ab_job.ab_job_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (production_sheet_item.coil_abc_num = ll_cur_coil);

       CURSOR alcan_scrap_870_cur IS
       SELECT a.coil_abc_num,
              b.coil_org_num,
              a.ab_job_num,
              nvl(b.material_num, ' ') material_num,
               NVL(a.process_quantity, 0) process_quan,
               NVL(a.process_end_wt, 0) process_end_wt
       FROM process_coil a, coil b
       WHERE (b.coil_abc_num = ll_cur_coil)
         AND (a.coil_abc_num = b.coil_abc_num)
         AND (a.scrap_870_date is NULL);

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;

  item_rec  alcan_870_cur%ROWTYPE;
  coil_rec  coil_cur%ROWTYPE;

  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;

  TYPE coil_num_type IS TABLE OF coil.coil_abc_num%type INDEX BY BINARY_INTEGER;
  coil_num coil_num_type;
  p binary_integer :=0;

BEGIN
  
  return; --Alex Gerlants. 12/07/2020. Inserted this line to bypass the whole procedure as a part of 870 Novelis project.
          --                           Novelis 870 will be created for a job, after the job is successfully saved in status 0-Done.
          --                           Function dbo.f_edi_novelis_870_4job is responsible for this.

  FOR cust_rec IN cust_cur LOOP
    --- Outer loop of customer_id
    ll_customer_id := cust_rec.customer_id;
    i              := 0;
    k              := 0;
    p              := 0;

  SELECT count(COIL.COIL_ABC_NUM)
  INTO ll_item_count
    FROM AB_JOB,
         COIL,
         PRODUCTION_SHEET_ITEM,
         SHEET_SKID,
         SHEET_SKID_DETAIL,
         CUSTOMER_ORDER
   WHERE ( SHEET_SKID_DETAIL.SHEET_SKID_NUM = SHEET_SKID.SHEET_SKID_NUM ) and
         ( SHEET_SKID_DETAIL.PROD_ITEM_NUM = PRODUCTION_SHEET_ITEM.PROD_ITEM_NUM ) and
         ( COIL.COIL_ABC_NUM = PRODUCTION_SHEET_ITEM.COIL_ABC_NUM ) and
         ( AB_JOB.AB_JOB_NUM = SHEET_SKID.AB_JOB_NUM ) and
         ( AB_JOB.ORDER_ABC_NUM = CUSTOMER_ORDER.ORDER_ABC_NUM ) and
         ( AB_JOB.JOB_STATUS = 0 ) AND
         (  COIL.COIL_STATUS in (0, 3) ) AND
         ( CUSTOMER_ORDER.ORIG_CUSTOMER_ID = ll_customer_id ) AND
         ( PRODUCTION_SHEET_ITEM.PROD_ITEM_EDI870_DATE is NULL ) AND
         ( COIL.SCRAP_870_DATE is NULL ) AND
         ( SHEET_SKID.SKID_SHEET_STATUS in (0, 2,4,12,13, 16) ); --Alex Gerlants. 03/22/2019. Added new status 16-Hold For Cert

    IF (ll_item_count <> 0) THEN

      SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
      SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;

      SELECT customer.customer_duns_number_string
        INTO su_duns
        FROM customer
       WHERE customer.customer_id = ll_customer_id;

      x12_table(i) := 'ISA*00*' ||
                      '          *00*          *01*039630926T     *09*0015049350011G *' ||
                      ls_today_4 || '*' || ls_now || '*U*00401*' ||
                      lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
      i := i + 1;
      x12_table(i) := 'GS*RS*039630926T*' || '001504935001' || '*' ||
                      ls_today || '*' || ls_now || '*' ||
                      to_char(ll_gs_log) || '*X*' || '004010';
      i := i + 1;
      x12_table(i) := 'ST*870*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                      '***' || ls_now || '*****';
      i := i + 1;
      x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
      i := i + 1;
      x12_table(i) := 'N1*SU**1*' || su_duns;
      i := i + 1;
      x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926';
      i := i + 1;

      li_hl01 := 0;

      FOR coil_rec IN coil_cur LOOP    -- coil loop
          ll_cur_coil := coil_rec.coil_abc_num;

          coil_num(p) := ll_cur_coil;
          p := p + 1;


        FOR item_rec IN alcan_870_cur LOOP   -- item loop

        li_hl01 := li_hl01 + 1;

        x12_table(i) := 'HL*' || to_char(li_hl01) || '**I';
        i := i + 1;

              SELECT nvl(customer_order.orig_customer_po, 'NA'),
                     nvl(order_item.cust_prod_line_id, 'NA'),
                     nvl(order_item.finished_goods_material_num, 'NA')
              INTO ls_po, ls_cust_prod_line, ls_finished_goods
              FROM   order_item,
                     ab_job,
                     customer_order
             WHERE (ab_job.order_abc_num = customer_order.order_abc_num)
             AND (ab_job.order_abc_num = order_item.order_abc_num)
             AND (ab_job.order_item_num = order_item.order_item_num)
              AND (ab_job.ab_job_num = item_rec.ab_job_num);

        IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
           x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
           i := i + 1;
        END IF;

        x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
        i := i + 1;

        x12_table(i) := 'REF*SE*' || to_char(item_rec.prod_item_num);
        i := i + 1;


        x12_table(i) := 'REF*MI*' || to_char(item_rec.ab_job_num);
        i := i + 1;

        x12_table(i) := 'REF*RV*' || to_char(item_rec.prod_item_num) ||
                        '*NA';
        i := i + 1;

        x12_table(i) := 'REF*IX*' || to_char(item_rec.consumed_coil);
        i := i + 1;

        x12_table(i) := 'PO1**1*UN****' || '***SN*' ||
                          item_rec.coil_org_num || '***VP*' || item_rec.finished_goods;
        i := i + 1;

        IF item_rec.skid_sheet_status = 2 THEN
          x12_table(i) := 'PID*S*MA*ST*1*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 4 THEN
          x12_table(i) := 'PID*S*MA*ST*3*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 13 THEN
          x12_table(i) := 'PID*S*MA*ST*8*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
         ELSE
          x12_table(i) := 'PID*S*MA*ST*4*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        END IF;

        x12_table(i) := 'PID*S*MAC*ST*01';
        i := i + 1;
        x12_table(i) := 'PID*S*PR*ST*19';
        i := i + 1;
        x12_table(i) := 'MEA*WT*N*' || to_char(item_rec.prod_item_net_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*WT*G*' || to_char(item_rec.skid_gross_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*CT*NA*' || to_char(item_rec.prod_item_pieces) ||
                        '*PC';
        i := i + 1;

         item_num(k) := item_rec.prod_item_num;
        k := k + 1;

      END LOOP;  -- item loop

     SELECT scrap_870_date, coil_org_num, lot_num
     INTO ld_scrap_870_date, ls_coil_org_num, ls_heat
     FROM coil
     WHERE coil_abc_num = ll_cur_coil;

     IF (ld_scrap_870_date is NULL) THEN  -- scrap not sent

      FOR scrap_rec IN alcan_scrap_870_cur LOOP    -- scrap loop

        --scrap info

        SELECT NVL(sum(production_sheet_item.prod_item_net_wt),0)
        into ll_prime_nw
         FROM production_sheet_item
         WHERE (production_sheet_item.ab_job_num = scrap_rec.ab_job_num) and
               (production_sheet_item.coil_abc_num = ll_cur_coil);


                ll_scrap_nw := scrap_rec.process_quan - scrap_rec.process_end_wt - ll_prime_nw;



                IF ll_scrap_nw > 0 then

                   li_hl01 := li_hl01 + 1;

                   x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*I';
                   i := i + 1;

                   IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
                      x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
                      i := i + 1;
                   END IF;

                   x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
                    i := i + 1;

                    x12_table(i) := 'PO1**1*UN****' || '***SN*' || scrap_rec.coil_org_num ;
                    i := i + 1;

                    x12_table(i) := 'PID*S*MA*ST*S';
                    i := i + 1;
                    x12_table(i) := 'PID*S*MAC*ST*05';
                     i := i + 1;
                    x12_table(i) := 'PID*S*PR*ST*19';
                     i := i + 1;

                   x12_table(i) := 'MEA*WT*N*' || to_char(ll_scrap_nw) || '*LB*01';
                   i := i+1;
                 END IF;

        END LOOP;  -- scrap loop
      END IF;  -- scrap not sent
     END LOOP;   -- coil loop
      x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
      i := i + 1;
      x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
      i := i + 1;
      x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

      -- Write EDI to file

      IF li_hl01 > 1 THEN
        -- WRITE EDI FILE ONLY IF ITEM > 0
        SELECT edi_file_id_seq.nextval
          INTO ll_edi_file_id_aleris
          FROM dual;
        edi_file        := edi_file_prefix || to_char(ll_edi_file_id_aleris) || '.edi';
     -- edi_file        := 's_alcan_' || to_char(ll_edi_file_id_aleris) || '.870';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        FOR j IN 0 .. i LOOP
          utl_file.put_line(edi_file_handle, x12_table(j));

        END LOOP;
        utl_file.fclose(edi_file_handle);
      END IF; -- END WRITING EDI FILE

      --edi_file        := 'send_edi_log'; /* Alex Gerlants. 04/14/2017. Commented out. */
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      --For verifying 997
      INSERT INTO outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
        VALUES
          (ll_edi_file_id_aleris,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           SYSDATE,
           edi_file,
           0,
           ll_customer_id,
           ll_st_log,
           '870');
--         COMMIT;

     FOR m IN 0 .. k - 1 LOOP
       UPDATE production_sheet_item
           SET prod_item_edi870_date = SYSDATE,
               edi_file_id_870 = ll_edi_file_id_aleris /* Alex Gerlants. 09/06/2016. New column */
         WHERE production_sheet_item.prod_item_num = item_num(m);
    END LOOP;

--      COMMIT;

        FOR m in 0..p - 1 LOOP
                UPDATE coil
					SET coil.scrap_870_date = sysdate
                WHERE coil.coil_abc_num = coil_num(m);

               UPDATE process_coil
					SET scrap_870_date = sysdate
                WHERE ( coil_abc_num = coil_num(m)) AND (scrap_870_date is NULL);

             END LOOP;

        COMMIT;

    END IF; --end if in select count(*)

  END LOOP; ------ End of outer loop customer_id

EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN;
END;
  GRANT EXECUTE ON "DBO"."EDI_ALCAN_870" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Procedure EDI_ALCAN_870_06262017
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."EDI_ALCAN_870_06262017" IS

  /*
  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   Customer: Aleris(1980) DUNS:964790856     EDI ID:964790856      QUALIFIER: ZZ

   End User: Aleris, Customer ID 1980
   */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50) := get_edi_destination('EDI_DIR');

  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_prefix VARCHAR2(50) := 'S_alcan_';
  edi_file_handle utl_file.file_type;
  su_duns         VARCHAR2(10);
  ll_customer_id  customer.customer_id%TYPE;
  ll_cur_coil     coil.coil_abc_num%TYPE;

--  ll_cur_job ab_job.ab_job_num%TYPE;

  ll_gs_log INTEGER;
  ll_st_log INTEGER;

  ls_today   VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD');
  ls_today_4 VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  ls_now     VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  ls_po VARCHAR2(20);
  ls_finished_goods VARCHAR2(32);
  ls_cust_prod_line VARCHAR2(8);

  ld_scrap_870_date ab_job.scrap_870_date%TYPE;

  ls_coil_org_num coil.coil_org_num%TYPE;
  ls_heat coil.lot_num%TYPE;

--  ll_ref_order_abc_num sheet_skid.ref_order_abc_num%TYPE;
--  ll_ref_order_abc_item sheet_skid.ref_order_abc_item%TYPE;
--  ls_sheet_type order_item.sheet_type%TYPE;

  ll_prime_nw coil.net_wt%TYPE;
  ll_scrap_nw coil.net_wt%TYPE;
--  ll_process_quantity  coil.net_wt%TYPE;
--  ll_process_end_wt  coil.net_wt%TYPE;
--  lr_theo_unit_wt order_item.theoretical_unit_wt%TYPE;

  --ll_edi_file_id integer;
  ll_edi_file_id_aleris INTEGER;

  ll_item_count INTEGER;

  li_hl01 INTEGER;
  li_hllin INTEGER;

  CURSOR cust_cur IS
    SELECT customer_id FROM customer WHERE customer_id IN (1153,1459,2582); ---Add customer id here if you want to send 870 for more customers

  CURSOR coil_cur IS
  SELECT UNIQUE C.COIL_ABC_NUM
  FROM SHEET_SKID_DETAIL SKD
    JOIN SHEET_SKID SK ON SKD.SHEET_SKID_NUM = SK.SHEET_SKID_NUM
    JOIN PRODUCTION_SHEET_ITEM PSI ON SKD.PROD_ITEM_NUM = PSI.PROD_ITEM_NUM
    JOIN COIL C ON PSI.COIL_ABC_NUM = C.COIL_ABC_NUM
    JOIN AB_JOB AB ON SK.AB_JOB_NUM = AB.AB_JOB_NUM
    JOIN CUSTOMER_ORDER CO ON CO.ORDER_ABC_NUM = AB.ORDER_ABC_NUM
  WHERE (AB.JOB_STATUS = 0) AND
    ( C.COIL_STATUS IN (0, 3) ) AND
    ( CO.ORIG_CUSTOMER_ID = ll_customer_id ) AND
    ( PSI.PROD_ITEM_EDI870_DATE is NULL ) AND
    ( C.SCRAP_870_DATE is NULL ) AND
    ( SK.SKID_SHEET_STATUS in (0,2,4,12,13) );

  CURSOR alcan_870_cur IS
   SELECT production_sheet_item.ab_job_num,
           production_sheet_item.coil_abc_num,
           production_sheet_item.prod_item_pieces,
           production_sheet_item.prod_item_num,
           sheet_skid.sheet_skid_num,
           production_sheet_item.prod_item_net_wt,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_skid_display_num,
           sheet_skid.sheet_net_wt,
           sheet_skid.skid_pieces,
           coil.coil_org_num,
           coil.lot_num,
           nvl(coil.consumed_coil_num, ' ') consumed_coil,
           nvl(coil.material_num, ' ') material_num,
           nvl(customer_order.sales_order, ' ') sales_order,
           nvl(customer_order.orig_customer_po, 'NA') customer_po,
           nvl(order_item.enduser_part_num, ' ') enduser_parts,
           nvl(order_item.cust_prod_line_id, 'NA') customer_line_id,
           nvl(order_item.finished_goods_material_num, 'NA') finished_goods,
           (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
           NULL done
      FROM sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil,
           order_item,
           ab_job,
           customer_order
     WHERE (sheet_skid.skid_sheet_status IN (0, 2, 4, 13, 12)) -- 2: Ready; 8: Warehouse Ready; 13: Partial Ready; 7: Partial; 12: Sample; 4: onhold
       AND (production_sheet_item.prod_item_edi870_date IS NULL)
       AND (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       AND (sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num)
       AND (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       AND (coil.customer_id = ll_customer_id)
       AND (sheet_skid.ref_order_abc_num = customer_order.order_abc_num)
       AND (production_sheet_item.ab_job_num = ab_job.ab_job_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (production_sheet_item.coil_abc_num = ll_cur_coil);

       CURSOR alcan_scrap_870_cur IS
       SELECT a.coil_abc_num,
              b.coil_org_num,
              a.ab_job_num,
              nvl(b.material_num, ' ') material_num,
               NVL(a.process_quantity, 0) process_quan,
               NVL(a.process_end_wt, 0) process_end_wt
       FROM process_coil a, coil b
       WHERE (b.coil_abc_num = ll_cur_coil)
         AND (a.coil_abc_num = b.coil_abc_num)
         AND (a.scrap_870_date is NULL);

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;

  item_rec  alcan_870_cur%ROWTYPE;
  coil_rec  coil_cur%ROWTYPE;

  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;

  TYPE coil_num_type IS TABLE OF coil.coil_abc_num%type INDEX BY BINARY_INTEGER;
  coil_num coil_num_type;
  p binary_integer :=0;

BEGIN

  FOR cust_rec IN cust_cur LOOP
    --- Outer loop of customer_id
    ll_customer_id := cust_rec.customer_id;
    i              := 0;
    k              := 0;
    p              := 0;

  SELECT count(COIL.COIL_ABC_NUM)
  INTO ll_item_count
    FROM AB_JOB,
         COIL,
         PRODUCTION_SHEET_ITEM,
         SHEET_SKID,
         SHEET_SKID_DETAIL,
         CUSTOMER_ORDER
   WHERE ( SHEET_SKID_DETAIL.SHEET_SKID_NUM = SHEET_SKID.SHEET_SKID_NUM ) and
         ( SHEET_SKID_DETAIL.PROD_ITEM_NUM = PRODUCTION_SHEET_ITEM.PROD_ITEM_NUM ) and
         ( COIL.COIL_ABC_NUM = PRODUCTION_SHEET_ITEM.COIL_ABC_NUM ) and
         ( AB_JOB.AB_JOB_NUM = SHEET_SKID.AB_JOB_NUM ) and
         ( AB_JOB.ORDER_ABC_NUM = CUSTOMER_ORDER.ORDER_ABC_NUM ) and
         ( AB_JOB.JOB_STATUS = 0 ) AND
         (  COIL.COIL_STATUS in (0, 3) ) AND
         ( CUSTOMER_ORDER.ORIG_CUSTOMER_ID = ll_customer_id ) AND
         ( PRODUCTION_SHEET_ITEM.PROD_ITEM_EDI870_DATE is NULL ) AND
         ( COIL.SCRAP_870_DATE is NULL ) AND
         ( SHEET_SKID.SKID_SHEET_STATUS in (0, 2,4,12,13) );

    IF (ll_item_count <> 0) THEN

      SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
      SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;

      SELECT customer.customer_duns_number_string
        INTO su_duns
        FROM customer
       WHERE customer.customer_id = ll_customer_id;

      x12_table(i) := 'ISA*00*' ||
                      '          *00*          *01*039630926T     *09*0015049350011G *' ||
                      ls_today_4 || '*' || ls_now || '*U*00401*' ||
                      lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
      i := i + 1;
      x12_table(i) := 'GS*RS*039630926T*' || '001504935001' || '*' ||
                      ls_today || '*' || ls_now || '*' ||
                      to_char(ll_gs_log) || '*X*' || '004010';
      i := i + 1;
      x12_table(i) := 'ST*870*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                      '***' || ls_now || '*****';
      i := i + 1;
      x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
      i := i + 1;
      x12_table(i) := 'N1*SU**1*' || su_duns;
      i := i + 1;
      x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926';
      i := i + 1;

      li_hl01 := 0;

      FOR coil_rec IN coil_cur LOOP    -- coil loop
          ll_cur_coil := coil_rec.coil_abc_num;

          coil_num(p) := ll_cur_coil;
          p := p + 1;


        FOR item_rec IN alcan_870_cur LOOP   -- item loop

        li_hl01 := li_hl01 + 1;

        x12_table(i) := 'HL*' || to_char(li_hl01) || '**I';
        i := i + 1;

              SELECT nvl(customer_order.orig_customer_po, 'NA'),
                     nvl(order_item.cust_prod_line_id, 'NA'),
                     nvl(order_item.finished_goods_material_num, 'NA')
              INTO ls_po, ls_cust_prod_line, ls_finished_goods
              FROM   order_item,
                     ab_job,
                     customer_order
             WHERE (ab_job.order_abc_num = customer_order.order_abc_num)
             AND (ab_job.order_abc_num = order_item.order_abc_num)
             AND (ab_job.order_item_num = order_item.order_item_num)
              AND (ab_job.ab_job_num = item_rec.ab_job_num);

        IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
           x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
           i := i + 1;
        END IF;

        x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
        i := i + 1;

        x12_table(i) := 'REF*SE*' || to_char(item_rec.prod_item_num);
        i := i + 1;


        x12_table(i) := 'REF*MI*' || to_char(item_rec.ab_job_num);
        i := i + 1;

        x12_table(i) := 'REF*RV*' || to_char(item_rec.prod_item_num) ||
                        '*NA';
        i := i + 1;

        x12_table(i) := 'REF*IX*' || to_char(item_rec.consumed_coil);
        i := i + 1;

        x12_table(i) := 'PO1**1*UN****' || '***SN*' ||
                          item_rec.coil_org_num || '***VP*' || item_rec.finished_goods;
        i := i + 1;

        IF item_rec.skid_sheet_status = 2 THEN
          x12_table(i) := 'PID*S*MA*ST*1*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 4 THEN
          x12_table(i) := 'PID*S*MA*ST*3*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 13 THEN
          x12_table(i) := 'PID*S*MA*ST*8*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
         ELSE
          x12_table(i) := 'PID*S*MA*ST*4*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        END IF;

        x12_table(i) := 'PID*S*MAC*ST*01';
        i := i + 1;
        x12_table(i) := 'PID*S*PR*ST*19';
        i := i + 1;
        x12_table(i) := 'MEA*WT*N*' || to_char(item_rec.prod_item_net_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*WT*G*' || to_char(item_rec.skid_gross_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*CT*NA*' || to_char(item_rec.prod_item_pieces) ||
                        '*PC';
        i := i + 1;

         item_num(k) := item_rec.prod_item_num;
        k := k + 1;

      END LOOP;  -- item loop

     SELECT scrap_870_date, coil_org_num, lot_num
     INTO ld_scrap_870_date, ls_coil_org_num, ls_heat
     FROM coil
     WHERE coil_abc_num = ll_cur_coil;

     IF (ld_scrap_870_date is NULL) THEN  -- scrap not sent

      FOR scrap_rec IN alcan_scrap_870_cur LOOP    -- scrap loop

        --scrap info

        SELECT NVL(sum(production_sheet_item.prod_item_net_wt),0)
        into ll_prime_nw
         FROM production_sheet_item
         WHERE (production_sheet_item.ab_job_num = scrap_rec.ab_job_num) and
               (production_sheet_item.coil_abc_num = ll_cur_coil);


                ll_scrap_nw := scrap_rec.process_quan - scrap_rec.process_end_wt - ll_prime_nw;



                IF ll_scrap_nw > 0 then

                   li_hl01 := li_hl01 + 1;

                   x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*I';
                   i := i + 1;

                   IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
                      x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
                      i := i + 1;
                   END IF;

                   x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
                    i := i + 1;

                    x12_table(i) := 'PO1**1*UN****' || '***SN*' || scrap_rec.coil_org_num ;
                    i := i + 1;

                    x12_table(i) := 'PID*S*MA*ST*S';
                    i := i + 1;
                    x12_table(i) := 'PID*S*MAC*ST*05';
                     i := i + 1;
                    x12_table(i) := 'PID*S*PR*ST*19';
                     i := i + 1;

                   x12_table(i) := 'MEA*WT*N*' || to_char(ll_scrap_nw) || '*LB*01';
                   i := i+1;
                 END IF;

        END LOOP;  -- scrap loop
      END IF;  -- scrap not sent
     END LOOP;   -- coil loop
      x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
      i := i + 1;
      x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
      i := i + 1;
      x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

      -- Write EDI to file

      IF li_hl01 > 1 THEN
        -- WRITE EDI FILE ONLY IF ITEM > 0
        SELECT edi_file_id_seq.nextval
          INTO ll_edi_file_id_aleris
          FROM dual;
        edi_file        := edi_file_prefix || to_char(ll_edi_file_id_aleris) || '.edi';
     -- edi_file        := 's_alcan_' || to_char(ll_edi_file_id_aleris) || '.870';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        FOR j IN 0 .. i LOOP
          utl_file.put_line(edi_file_handle, x12_table(j));

        END LOOP;
        utl_file.fclose(edi_file_handle);
      END IF; -- END WRITING EDI FILE

      --edi_file        := 'send_edi_log'; /* Alex Gerlants. 04/14/2017. Commented out. */
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      --For verifying 997
      INSERT INTO outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
        VALUES
          (ll_edi_file_id_aleris,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           SYSDATE,
           edi_file,
           0,
           ll_customer_id,
           ll_st_log,
           '870');
--         COMMIT;

     FOR m IN 0 .. k - 1 LOOP
       UPDATE production_sheet_item
           SET prod_item_edi870_date = SYSDATE,
               edi_file_id_870 = ll_edi_file_id_aleris /* Alex Gerlants. 09/06/2016. New column */
         WHERE production_sheet_item.prod_item_num = item_num(m);
    END LOOP;

--      COMMIT;

        FOR m in 0..p - 1 LOOP
                UPDATE coil
					SET coil.scrap_870_date = sysdate
                WHERE coil.coil_abc_num = coil_num(m);

               UPDATE process_coil
					SET scrap_870_date = sysdate
                WHERE ( coil_abc_num = coil_num(m)) AND (scrap_870_date is NULL);

             END LOOP;

        COMMIT;

    END IF; --end if in select count(*)

  END LOOP; ------ End of outer loop customer_id

EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN;
END;
  GRANT EXECUTE ON "DBO"."EDI_ALCAN_870_06262017" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Procedure EDI_ALCAN_870_ALEX
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."EDI_ALCAN_870_ALEX" IS

  /*
  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   Customer: Aleris(1980) DUNS:964790856     EDI ID:964790856      QUALIFIER: ZZ

   End User: Aleris, Customer ID 1980
   */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50) := get_edi_destination('EDI_DIR');

  edi_file        VARCHAR2(50) := 'edi_out.txt';
  --edi_file_prefix VARCHAR2(50) := 'S_alcan_';
  edi_file_prefix VARCHAR2(50) := 'alex_alcan_';
  edi_file_handle utl_file.file_type;
  su_duns         VARCHAR2(10);
  ll_customer_id  customer.customer_id%TYPE;
  ll_cur_coil     coil.coil_abc_num%TYPE;

--  ll_cur_job ab_job.ab_job_num%TYPE;

  ll_gs_log INTEGER;
  ll_st_log INTEGER;

  ls_today   VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD');
  ls_today_4 VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  ls_now     VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  ls_po VARCHAR2(20);
  ls_finished_goods VARCHAR2(32);
  ls_cust_prod_line VARCHAR2(8);

  ld_scrap_870_date ab_job.scrap_870_date%TYPE;

  ls_coil_org_num coil.coil_org_num%TYPE;
  ls_heat coil.lot_num%TYPE;

--  ll_ref_order_abc_num sheet_skid.ref_order_abc_num%TYPE;
--  ll_ref_order_abc_item sheet_skid.ref_order_abc_item%TYPE;
--  ls_sheet_type order_item.sheet_type%TYPE;

  ll_prime_nw coil.net_wt%TYPE;
  ll_scrap_nw coil.net_wt%TYPE;
--  ll_process_quantity  coil.net_wt%TYPE;
--  ll_process_end_wt  coil.net_wt%TYPE;
--  lr_theo_unit_wt order_item.theoretical_unit_wt%TYPE;

  --ll_edi_file_id integer;
  ll_edi_file_id_aleris INTEGER;

  ll_item_count INTEGER;

  li_hl01 INTEGER;
  li_hllin INTEGER;

  ll_coil_abc_num INTEGER := 205955; --Alex Gerlants. 02/28/2017
  ll_ab_job_num   INTEGER := 97583; --Alex Gerlants. 02/28/2017


  CURSOR cust_cur IS
    --SELECT customer_id FROM customer WHERE customer_id IN (1153,1459,2582); ---Add customer id here if you want to send 870 for more customers
    SELECT customer_id FROM customer WHERE customer_id IN (1153); ---Add customer id here if you want to send 870 for more customers

/*
  CURSOR coil_cur IS
  SELECT UNIQUE C.COIL_ABC_NUM
  FROM SHEET_SKID_DETAIL SKD
    JOIN SHEET_SKID SK ON SKD.SHEET_SKID_NUM = SK.SHEET_SKID_NUM
    JOIN PRODUCTION_SHEET_ITEM PSI ON SKD.PROD_ITEM_NUM = PSI.PROD_ITEM_NUM
    JOIN COIL C ON PSI.COIL_ABC_NUM = C.COIL_ABC_NUM
    JOIN AB_JOB AB ON SK.AB_JOB_NUM = AB.AB_JOB_NUM
    JOIN CUSTOMER_ORDER CO ON CO.ORDER_ABC_NUM = AB.ORDER_ABC_NUM
  WHERE (AB.JOB_STATUS = 0) AND
    ( C.COIL_STATUS IN (0, 3) ) AND
    ( CO.ORIG_CUSTOMER_ID = ll_customer_id ) AND
    ( PSI.PROD_ITEM_EDI870_DATE is NULL ) AND
    ( C.SCRAP_870_DATE is NULL ) AND
    ( SK.SKID_SHEET_STATUS in (0,2,4,12,13) );
*/

  CURSOR coil_cur IS
  SELECT UNIQUE C.COIL_ABC_NUM
  FROM SHEET_SKID_DETAIL SKD
    JOIN SHEET_SKID SK ON SKD.SHEET_SKID_NUM = SK.SHEET_SKID_NUM
    JOIN PRODUCTION_SHEET_ITEM PSI ON SKD.PROD_ITEM_NUM = PSI.PROD_ITEM_NUM
    JOIN COIL C ON PSI.COIL_ABC_NUM = C.COIL_ABC_NUM
    JOIN AB_JOB AB ON SK.AB_JOB_NUM = AB.AB_JOB_NUM
    JOIN CUSTOMER_ORDER CO ON CO.ORDER_ABC_NUM = AB.ORDER_ABC_NUM
  WHERE (AB.JOB_STATUS = 0) AND
    ( C.COIL_STATUS IN (0, 3) ) AND
    ( CO.ORIG_CUSTOMER_ID = ll_customer_id ) AND
    ( PSI.PROD_ITEM_EDI870_DATE is NULL ) AND
    --( C.SCRAP_870_DATE is NULL ) AND
    ( SK.SKID_SHEET_STATUS in (0,2,4,12,13) )
    and ab.ab_job_num = ll_ab_job_num
    and C.COIL_ABC_NUM = ll_coil_abc_num
    and SKD.SHEET_SKID_NUM between 625038 and 625043;

/*
  CURSOR alcan_870_cur IS
   SELECT production_sheet_item.ab_job_num,
           production_sheet_item.coil_abc_num,
           production_sheet_item.prod_item_pieces,
           production_sheet_item.prod_item_num,
           sheet_skid.sheet_skid_num,
           production_sheet_item.prod_item_net_wt,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_skid_display_num,
           sheet_skid.sheet_net_wt,
           sheet_skid.skid_pieces,
           coil.coil_org_num,
           coil.lot_num,
           nvl(coil.consumed_coil_num, ' ') consumed_coil,
           nvl(coil.material_num, ' ') material_num,
           nvl(customer_order.sales_order, ' ') sales_order,
           nvl(customer_order.orig_customer_po, 'NA') customer_po,
           nvl(order_item.enduser_part_num, ' ') enduser_parts,
           nvl(order_item.cust_prod_line_id, 'NA') customer_line_id,
           nvl(order_item.finished_goods_material_num, 'NA') finished_goods,
           (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
           NULL done
      FROM sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil,
           order_item,
           ab_job,
           customer_order
     WHERE (sheet_skid.skid_sheet_status IN (0, 2, 4, 13, 12)) -- 2: Ready; 8: Warehouse Ready; 13: Partial Ready; 7: Partial; 12: Sample; 4: onhold
       AND (production_sheet_item.prod_item_edi870_date IS NULL)
       AND (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       AND (sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num)
       AND (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       AND (coil.customer_id = ll_customer_id)
       AND (sheet_skid.ref_order_abc_num = customer_order.order_abc_num)
       AND (production_sheet_item.ab_job_num = ab_job.ab_job_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (production_sheet_item.coil_abc_num = ll_cur_coil);
*/

  CURSOR alcan_870_cur IS
   SELECT production_sheet_item.ab_job_num,
           production_sheet_item.coil_abc_num,
           production_sheet_item.prod_item_pieces,
           production_sheet_item.prod_item_num,
           sheet_skid.sheet_skid_num,
           production_sheet_item.prod_item_net_wt,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_skid_display_num,
           sheet_skid.sheet_net_wt,
           sheet_skid.skid_pieces,
           coil.coil_org_num,
           coil.lot_num,
           nvl(coil.consumed_coil_num, ' ') consumed_coil,
           nvl(coil.material_num, ' ') material_num,
           nvl(customer_order.sales_order, ' ') sales_order,
           nvl(customer_order.orig_customer_po, 'NA') customer_po,
           nvl(order_item.enduser_part_num, ' ') enduser_parts,
           nvl(order_item.cust_prod_line_id, 'NA') customer_line_id,
           nvl(order_item.finished_goods_material_num, 'NA') finished_goods,
           (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
           NULL done
      FROM sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil,
           order_item,
           ab_job,
           customer_order
     WHERE (sheet_skid.skid_sheet_status IN (0, 2, 4, 13, 12)) -- 2: Ready; 8: Warehouse Ready; 13: Partial Ready; 7: Partial; 12: Sample; 4: onhold
       AND (production_sheet_item.prod_item_edi870_date IS NULL)
       AND (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       AND (sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num)
       AND (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       AND (coil.customer_id = ll_customer_id)
       AND (sheet_skid.ref_order_abc_num = customer_order.order_abc_num)
       AND (production_sheet_item.ab_job_num = ab_job.ab_job_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (production_sheet_item.coil_abc_num = ll_coil_abc_num);



       CURSOR alcan_scrap_870_cur IS
       SELECT a.coil_abc_num,
              b.coil_org_num,
              a.ab_job_num,
              nvl(b.material_num, ' ') material_num,
               NVL(a.process_quantity, 0) process_quan,
               NVL(a.process_end_wt, 0) process_end_wt
       FROM process_coil a, coil b
       WHERE (b.coil_abc_num = ll_cur_coil)
         AND (a.coil_abc_num = b.coil_abc_num);
         --AND (a.scrap_870_date is NULL); --Alex Gerlants. 02/28/2017. Commented out.

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;

  item_rec  alcan_870_cur%ROWTYPE;
  coil_rec  coil_cur%ROWTYPE;

  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;

  TYPE coil_num_type IS TABLE OF coil.coil_abc_num%type INDEX BY BINARY_INTEGER;
  coil_num coil_num_type;
  p binary_integer :=0;

BEGIN

  FOR cust_rec IN cust_cur LOOP
    --- Outer loop of customer_id
    ll_customer_id := cust_rec.customer_id;
    i              := 0;
    k              := 0;
    p              := 0;

  SELECT count(COIL.COIL_ABC_NUM)
  INTO ll_item_count
    FROM AB_JOB,
         COIL,
         PRODUCTION_SHEET_ITEM,
         SHEET_SKID,
         SHEET_SKID_DETAIL,
         CUSTOMER_ORDER
   WHERE ( SHEET_SKID_DETAIL.SHEET_SKID_NUM = SHEET_SKID.SHEET_SKID_NUM ) and
         ( SHEET_SKID_DETAIL.PROD_ITEM_NUM = PRODUCTION_SHEET_ITEM.PROD_ITEM_NUM ) and
         ( COIL.COIL_ABC_NUM = PRODUCTION_SHEET_ITEM.COIL_ABC_NUM ) and
         ( AB_JOB.AB_JOB_NUM = SHEET_SKID.AB_JOB_NUM ) and
         ( AB_JOB.ORDER_ABC_NUM = CUSTOMER_ORDER.ORDER_ABC_NUM ) and
         ( AB_JOB.JOB_STATUS = 0 ) AND
         (  COIL.COIL_STATUS in (0, 3) ) AND
         ( CUSTOMER_ORDER.ORIG_CUSTOMER_ID = ll_customer_id ) AND
         ( PRODUCTION_SHEET_ITEM.PROD_ITEM_EDI870_DATE is NULL ) AND
         --( COIL.SCRAP_870_DATE is NULL ) AND --Alex Gerlants. 02/28/2017. Commented out
         ( SHEET_SKID.SKID_SHEET_STATUS in (0, 2,4,12,13) )
         and AB_JOB.ab_job_num = ll_ab_job_num --Alex Gerlants. 02/28/2017
         and COIL.COIL_ABC_NUM = ll_coil_abc_num --Alex Gerlants. 02/28/2017
         and SHEET_SKID_DETAIL.SHEET_SKID_NUM between 625038 and 625043; --Alex Gerlants. 02/28/2017

    IF (ll_item_count <> 0) THEN

      SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
      SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;

      SELECT customer.customer_duns_number_string
        INTO su_duns
        FROM customer
       WHERE customer.customer_id = ll_customer_id;

      x12_table(i) := 'ISA*00*' ||
                      '          *00*          *01*039630926T     *09*0015049350011G *' ||
                      ls_today_4 || '*' || ls_now || '*U*00401*' ||
                      lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
      i := i + 1;
      x12_table(i) := 'GS*RS*039630926T*' || '001504935001' || '*' ||
                      ls_today || '*' || ls_now || '*' ||
                      to_char(ll_gs_log) || '*X*' || '004010';
      i := i + 1;
      x12_table(i) := 'ST*870*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                      '***' || ls_now || '*****';
      i := i + 1;
      x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
      i := i + 1;
      x12_table(i) := 'N1*SU**1*' || su_duns;
      i := i + 1;
      x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926';
      i := i + 1;

      li_hl01 := 0;

      FOR coil_rec IN coil_cur LOOP    -- coil loop
          ll_cur_coil := coil_rec.coil_abc_num;

          coil_num(p) := ll_cur_coil;
          p := p + 1;


        FOR item_rec IN alcan_870_cur LOOP   -- item loop

        li_hl01 := li_hl01 + 1;

        x12_table(i) := 'HL*' || to_char(li_hl01) || '**I';
        i := i + 1;

              SELECT nvl(customer_order.orig_customer_po, 'NA'),
                     nvl(order_item.cust_prod_line_id, 'NA'),
                     nvl(order_item.finished_goods_material_num, 'NA')
              INTO ls_po, ls_cust_prod_line, ls_finished_goods
              FROM   order_item,
                     ab_job,
                     customer_order
             WHERE (ab_job.order_abc_num = customer_order.order_abc_num)
             AND (ab_job.order_abc_num = order_item.order_abc_num)
             AND (ab_job.order_item_num = order_item.order_item_num)
              AND (ab_job.ab_job_num = item_rec.ab_job_num);

        IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
           x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
           i := i + 1;
        END IF;

        x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
        i := i + 1;

        x12_table(i) := 'REF*SE*' || to_char(item_rec.prod_item_num);
        i := i + 1;


        x12_table(i) := 'REF*MI*' || to_char(item_rec.ab_job_num);
        i := i + 1;

        x12_table(i) := 'REF*RV*' || to_char(item_rec.prod_item_num) ||
                        '*NA';
        i := i + 1;

        x12_table(i) := 'REF*IX*' || to_char(item_rec.consumed_coil);
        i := i + 1;

        x12_table(i) := 'PO1**1*UN****' || '***SN*' ||
                          item_rec.coil_org_num || '***VP*' || item_rec.finished_goods;
        i := i + 1;

        IF item_rec.skid_sheet_status = 2 THEN
          x12_table(i) := 'PID*S*MA*ST*1*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 4 THEN
          x12_table(i) := 'PID*S*MA*ST*3*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 13 THEN
          x12_table(i) := 'PID*S*MA*ST*8*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
         ELSE
          x12_table(i) := 'PID*S*MA*ST*4*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        END IF;

        x12_table(i) := 'PID*S*MAC*ST*01';
        i := i + 1;
        x12_table(i) := 'PID*S*PR*ST*19';
        i := i + 1;
        x12_table(i) := 'MEA*WT*N*' || to_char(item_rec.prod_item_net_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*WT*G*' || to_char(item_rec.skid_gross_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*CT*NA*' || to_char(item_rec.prod_item_pieces) ||
                        '*PC';
        i := i + 1;

         item_num(k) := item_rec.prod_item_num;
        k := k + 1;

      END LOOP;  -- item loop

     SELECT scrap_870_date, coil_org_num, lot_num
     INTO ld_scrap_870_date, ls_coil_org_num, ls_heat
     FROM coil
     WHERE coil_abc_num = ll_cur_coil;

     IF (ld_scrap_870_date is NULL) THEN  -- scrap not sent

      FOR scrap_rec IN alcan_scrap_870_cur LOOP    -- scrap loop

        --scrap info

        SELECT NVL(sum(production_sheet_item.prod_item_net_wt),0)
        into ll_prime_nw
         FROM production_sheet_item
         WHERE (production_sheet_item.ab_job_num = scrap_rec.ab_job_num) and
               (production_sheet_item.coil_abc_num = ll_cur_coil);


                ll_scrap_nw := scrap_rec.process_quan - scrap_rec.process_end_wt - ll_prime_nw;



                IF ll_scrap_nw > 0 then

                   li_hl01 := li_hl01 + 1;

                   x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*I';
                   i := i + 1;

                   IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
                      x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
                      i := i + 1;
                   END IF;

                   x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
                    i := i + 1;

                    x12_table(i) := 'PO1**1*UN****' || '***SN*' || scrap_rec.coil_org_num ;
                    i := i + 1;

                    x12_table(i) := 'PID*S*MA*ST*S';
                    i := i + 1;
                    x12_table(i) := 'PID*S*MAC*ST*05';
                     i := i + 1;
                    x12_table(i) := 'PID*S*PR*ST*19';
                     i := i + 1;

                   x12_table(i) := 'MEA*WT*N*' || to_char(ll_scrap_nw) || '*LB*01';
                   i := i+1;
                 END IF;

        END LOOP;  -- scrap loop
      END IF;  -- scrap not sent
     END LOOP;   -- coil loop
      x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
      i := i + 1;
      x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
      i := i + 1;
      x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

      -- Write EDI to file

      IF li_hl01 > 1 THEN
        -- WRITE EDI FILE ONLY IF ITEM > 0
        SELECT edi_file_id_seq.nextval
          INTO ll_edi_file_id_aleris
          FROM dual;
        edi_file        := edi_file_prefix || to_char(ll_edi_file_id_aleris) || '.edi';
     -- edi_file        := 's_alcan_' || to_char(ll_edi_file_id_aleris) || '.870';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        FOR j IN 0 .. i LOOP
          utl_file.put_line(edi_file_handle, x12_table(j));

        END LOOP;
        utl_file.fclose(edi_file_handle);
      END IF; -- END WRITING EDI FILE

      edi_file        := 'send_edi_log';
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      --For verifying 997
      INSERT INTO outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
        VALUES
          (ll_edi_file_id_aleris,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           SYSDATE,
           edi_file,
           0,
           ll_customer_id,
           ll_st_log,
           '870');
--         COMMIT;

     FOR m IN 0 .. k - 1 LOOP
       UPDATE production_sheet_item
           SET prod_item_edi870_date = SYSDATE,
               edi_file_id_870 = ll_edi_file_id_aleris /* Alex Gerlants. 09/06/2016. New column */
         WHERE production_sheet_item.prod_item_num = item_num(m);
    END LOOP;

--      COMMIT;

        FOR m in 0..p - 1 LOOP
                UPDATE coil
          SET coil.scrap_870_date = sysdate
                WHERE coil.coil_abc_num = coil_num(m);

               UPDATE process_coil
          SET scrap_870_date = sysdate
                WHERE ( coil_abc_num = coil_num(m)) AND (scrap_870_date is NULL);

             END LOOP;

        COMMIT;

    END IF; --end if in select count(*)

  END LOOP; ------ End of outer loop customer_id

EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN;
END;
  GRANT EXECUTE ON "DBO"."EDI_ALCAN_870_ALEX" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Procedure EDI_ALCAN_870_ALEX2
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."EDI_ALCAN_870_ALEX2" IS

  /*
  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   Customer: Aleris(1980) DUNS:964790856     EDI ID:964790856      QUALIFIER: ZZ

   End User: Aleris, Customer ID 1980
   */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50) := get_edi_destination('EDI_DIR');

  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_prefix VARCHAR2(50) := 's_alcan_alex_';
  edi_file_handle utl_file.file_type;
  su_duns         VARCHAR2(10);
  ll_customer_id  customer.customer_id%TYPE;
  ll_cur_coil     coil.coil_abc_num%TYPE;

--  ll_cur_job ab_job.ab_job_num%TYPE;

  ll_gs_log INTEGER;
  ll_st_log INTEGER;

  ls_today   VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD');
  ls_today_4 VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  ls_now     VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  ls_po VARCHAR2(20);
  ls_finished_goods VARCHAR2(32);
  ls_cust_prod_line VARCHAR2(8);

  ld_scrap_870_date ab_job.scrap_870_date%TYPE;

  ls_coil_org_num coil.coil_org_num%TYPE;
  ls_heat coil.lot_num%TYPE;

--  ll_ref_order_abc_num sheet_skid.ref_order_abc_num%TYPE;
--  ll_ref_order_abc_item sheet_skid.ref_order_abc_item%TYPE;
--  ls_sheet_type order_item.sheet_type%TYPE;

  ll_prime_nw coil.net_wt%TYPE;
  ll_scrap_nw coil.net_wt%TYPE;
--  ll_process_quantity  coil.net_wt%TYPE;
--  ll_process_end_wt  coil.net_wt%TYPE;
--  lr_theo_unit_wt order_item.theoretical_unit_wt%TYPE;

  --ll_edi_file_id integer;
  ll_edi_file_id_aleris INTEGER;

  ll_item_count INTEGER;

  li_hl01 INTEGER;
  li_hllin INTEGER;

  CURSOR cust_cur IS
    SELECT customer_id FROM customer WHERE customer_id IN (1153,1459,2582); ---Add customer id here if you want to send 870 for more customers

  CURSOR coil_cur IS
  SELECT UNIQUE C.COIL_ABC_NUM
  FROM SHEET_SKID_DETAIL SKD
    JOIN SHEET_SKID SK ON SKD.SHEET_SKID_NUM = SK.SHEET_SKID_NUM
    JOIN PRODUCTION_SHEET_ITEM PSI ON SKD.PROD_ITEM_NUM = PSI.PROD_ITEM_NUM
    JOIN COIL C ON PSI.COIL_ABC_NUM = C.COIL_ABC_NUM
    JOIN AB_JOB AB ON SK.AB_JOB_NUM = AB.AB_JOB_NUM
    JOIN CUSTOMER_ORDER CO ON CO.ORDER_ABC_NUM = AB.ORDER_ABC_NUM
  WHERE (AB.JOB_STATUS = 0) AND
    ( C.COIL_STATUS IN (0, 3) ) AND
    ( CO.ORIG_CUSTOMER_ID = 1153 ) AND
    --( PSI.PROD_ITEM_EDI870_DATE is NULL ) AND
    --( C.SCRAP_870_DATE is NULL ) AND
    --( SK.SKID_SHEET_STATUS in (0,2,4,12,13) )
    ( c.coil_abc_num in (212673) ) and
    ( ab.ab_job_num = 102261 ) and
    ( sk.sheet_skid_num in (655859) ) and
    ( psi.prod_item_num = 1375681 )    
    ;

  CURSOR alcan_870_cur IS
   SELECT production_sheet_item.ab_job_num,
           production_sheet_item.coil_abc_num,
           production_sheet_item.prod_item_pieces,
           production_sheet_item.prod_item_num,
           sheet_skid.sheet_skid_num,
           production_sheet_item.prod_item_net_wt,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_skid_display_num,
           sheet_skid.sheet_net_wt,
           sheet_skid.skid_pieces,
           coil.coil_org_num,
           coil.lot_num,
           nvl(coil.consumed_coil_num, ' ') consumed_coil,
           nvl(coil.material_num, ' ') material_num,
           nvl(customer_order.sales_order, ' ') sales_order,
           nvl(customer_order.orig_customer_po, 'NA') customer_po,
           nvl(order_item.enduser_part_num, ' ') enduser_parts,
           nvl(order_item.cust_prod_line_id, 'NA') customer_line_id,
           nvl(order_item.finished_goods_material_num, 'NA') finished_goods,
           (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
           NULL done
      FROM sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil,
           order_item,
           ab_job,
           customer_order
     WHERE (sheet_skid.skid_sheet_status IN (0, 2, 4, 13, 12)) -- 2: Ready; 8: Warehouse Ready; 13: Partial Ready; 7: Partial; 12: Sample; 4: onhold
       AND (production_sheet_item.prod_item_edi870_date IS NULL)
       AND (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       AND (sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num)
       AND (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       AND (coil.customer_id = ll_customer_id)
       AND (sheet_skid.ref_order_abc_num = customer_order.order_abc_num)
       AND (production_sheet_item.ab_job_num = ab_job.ab_job_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (production_sheet_item.coil_abc_num = ll_cur_coil);

       CURSOR alcan_scrap_870_cur IS
       SELECT a.coil_abc_num,
              b.coil_org_num,
              a.ab_job_num,
              nvl(b.material_num, ' ') material_num,
               NVL(a.process_quantity, 0) process_quan,
               NVL(a.process_end_wt, 0) process_end_wt
       FROM process_coil a, coil b
       WHERE (b.coil_abc_num = ll_cur_coil)
         AND (a.coil_abc_num = b.coil_abc_num)
         --AND (a.scrap_870_date is NULL)
         ;

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;

  item_rec  alcan_870_cur%ROWTYPE;
  coil_rec  coil_cur%ROWTYPE;

  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;

  TYPE coil_num_type IS TABLE OF coil.coil_abc_num%type INDEX BY BINARY_INTEGER;
  coil_num coil_num_type;
  p binary_integer :=0;

BEGIN

  FOR cust_rec IN cust_cur LOOP
    --- Outer loop of customer_id
    ll_customer_id := cust_rec.customer_id;
    i              := 0;
    k              := 0;
    p              := 0;

  SELECT count(COIL.COIL_ABC_NUM)
  INTO ll_item_count
    FROM AB_JOB,
         COIL,
         PRODUCTION_SHEET_ITEM,
         SHEET_SKID,
         SHEET_SKID_DETAIL,
         CUSTOMER_ORDER
   WHERE ( SHEET_SKID_DETAIL.SHEET_SKID_NUM = SHEET_SKID.SHEET_SKID_NUM ) and
         ( SHEET_SKID_DETAIL.PROD_ITEM_NUM = PRODUCTION_SHEET_ITEM.PROD_ITEM_NUM ) and
         ( COIL.COIL_ABC_NUM = PRODUCTION_SHEET_ITEM.COIL_ABC_NUM ) and
         ( AB_JOB.AB_JOB_NUM = SHEET_SKID.AB_JOB_NUM ) and
         ( AB_JOB.ORDER_ABC_NUM = CUSTOMER_ORDER.ORDER_ABC_NUM ) and
         ( AB_JOB.JOB_STATUS = 0 ) AND
         (  COIL.COIL_STATUS in (0, 3) ) AND
         ( CUSTOMER_ORDER.ORIG_CUSTOMER_ID = 1153 ) AND
         ( production_sheet_item.prod_item_num = 1375681 )
         --( PRODUCTION_SHEET_ITEM.PROD_ITEM_EDI870_DATE is NULL ) AND
         --( COIL.SCRAP_870_DATE is NULL ) AND
         --( SHEET_SKID.SKID_SHEET_STATUS in (0, 2,4,12,13) )
         ;

    IF (ll_item_count <> 0) THEN

      SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
      SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;

      SELECT customer.customer_duns_number_string
        INTO su_duns
        FROM customer
       WHERE customer.customer_id = ll_customer_id;

      x12_table(i) := 'ISA*00*' ||
                      '          *00*          *01*039630926T     *09*0015049350011G *' ||
                      ls_today_4 || '*' || ls_now || '*U*00401*' ||
                      lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
      i := i + 1;
      x12_table(i) := 'GS*RS*039630926T*' || '001504935001' || '*' ||
                      ls_today || '*' || ls_now || '*' ||
                      to_char(ll_gs_log) || '*X*' || '004010';
      i := i + 1;
      x12_table(i) := 'ST*870*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                      '***' || ls_now || '*****';
      i := i + 1;
      x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
      i := i + 1;
      x12_table(i) := 'N1*SU**1*' || su_duns;
      i := i + 1;
      x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926';
      i := i + 1;

      li_hl01 := 0;

      FOR coil_rec IN coil_cur LOOP    -- coil loop
          ll_cur_coil := coil_rec.coil_abc_num;

          coil_num(p) := ll_cur_coil;
          p := p + 1;


        FOR item_rec IN alcan_870_cur LOOP   -- item loop

        li_hl01 := li_hl01 + 1;

        x12_table(i) := 'HL*' || to_char(li_hl01) || '**I';
        i := i + 1;

              SELECT nvl(customer_order.orig_customer_po, 'NA'),
                     nvl(order_item.cust_prod_line_id, 'NA'),
                     nvl(order_item.finished_goods_material_num, 'NA')
              INTO ls_po, ls_cust_prod_line, ls_finished_goods
              FROM   order_item,
                     ab_job,
                     customer_order
             WHERE (ab_job.order_abc_num = customer_order.order_abc_num)
             AND (ab_job.order_abc_num = order_item.order_abc_num)
             AND (ab_job.order_item_num = order_item.order_item_num)
              AND (ab_job.ab_job_num = item_rec.ab_job_num);

        IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
           x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
           i := i + 1;
        END IF;

        x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
        i := i + 1;

        x12_table(i) := 'REF*SE*' || to_char(item_rec.prod_item_num);
        i := i + 1;


        x12_table(i) := 'REF*MI*' || to_char(item_rec.ab_job_num);
        i := i + 1;

        x12_table(i) := 'REF*RV*' || to_char(item_rec.prod_item_num) ||
                        '*NA';
        i := i + 1;

        x12_table(i) := 'REF*IX*' || to_char(item_rec.consumed_coil);
        i := i + 1;

        x12_table(i) := 'PO1**1*UN****' || '***SN*' ||
                          item_rec.coil_org_num || '***VP*' || item_rec.finished_goods;
        i := i + 1;

        IF item_rec.skid_sheet_status = 2 THEN
          x12_table(i) := 'PID*S*MA*ST*1*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 4 THEN
          x12_table(i) := 'PID*S*MA*ST*3*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 13 THEN
          x12_table(i) := 'PID*S*MA*ST*8*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
         ELSE
          x12_table(i) := 'PID*S*MA*ST*4*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        END IF;

        x12_table(i) := 'PID*S*MAC*ST*01';
        i := i + 1;
        x12_table(i) := 'PID*S*PR*ST*19';
        i := i + 1;
        x12_table(i) := 'MEA*WT*N*' || to_char(item_rec.prod_item_net_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*WT*G*' || to_char(item_rec.skid_gross_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*CT*NA*' || to_char(item_rec.prod_item_pieces) ||
                        '*PC';
        i := i + 1;

         item_num(k) := item_rec.prod_item_num;
        k := k + 1;

      END LOOP;  -- item loop

     SELECT scrap_870_date, coil_org_num, lot_num
     INTO ld_scrap_870_date, ls_coil_org_num, ls_heat
     FROM coil
     WHERE coil_abc_num = ll_cur_coil;

     IF (ld_scrap_870_date is NULL) THEN  -- scrap not sent

      FOR scrap_rec IN alcan_scrap_870_cur LOOP    -- scrap loop

        --scrap info

        SELECT NVL(sum(production_sheet_item.prod_item_net_wt),0)
        into ll_prime_nw
         FROM production_sheet_item
         WHERE (production_sheet_item.ab_job_num = scrap_rec.ab_job_num) and
               (production_sheet_item.coil_abc_num = ll_cur_coil);


                ll_scrap_nw := scrap_rec.process_quan - scrap_rec.process_end_wt - ll_prime_nw;



                IF ll_scrap_nw > 0 then

                   li_hl01 := li_hl01 + 1;

                   x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*I';
                   i := i + 1;

                   IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
                      x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
                      i := i + 1;
                   END IF;

                   x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
                    i := i + 1;

                    x12_table(i) := 'PO1**1*UN****' || '***SN*' || scrap_rec.coil_org_num ;
                    i := i + 1;

                    x12_table(i) := 'PID*S*MA*ST*S';
                    i := i + 1;
                    x12_table(i) := 'PID*S*MAC*ST*05';
                     i := i + 1;
                    x12_table(i) := 'PID*S*PR*ST*19';
                     i := i + 1;

                   x12_table(i) := 'MEA*WT*N*' || to_char(ll_scrap_nw) || '*LB*01';
                   i := i+1;
                 END IF;

        END LOOP;  -- scrap loop
      END IF;  -- scrap not sent
     END LOOP;   -- coil loop
      x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
      i := i + 1;
      x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
      i := i + 1;
      x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

      -- Write EDI to file

      IF li_hl01 > 1 THEN
        -- WRITE EDI FILE ONLY IF ITEM > 0
        SELECT edi_file_id_seq.nextval
          INTO ll_edi_file_id_aleris
          FROM dual;
        edi_file        := edi_file_prefix || to_char(ll_edi_file_id_aleris) || '.edi';
     -- edi_file        := 's_alcan_' || to_char(ll_edi_file_id_aleris) || '.870';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        FOR j IN 0 .. i LOOP
          utl_file.put_line(edi_file_handle, x12_table(j));

        END LOOP;
        utl_file.fclose(edi_file_handle);
      END IF; -- END WRITING EDI FILE

      --edi_file        := 'send_edi_log'; /* Alex Gerlants. 04/14/2017. Commented out. */
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      --For verifying 997
      INSERT INTO outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
        VALUES
          (ll_edi_file_id_aleris,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           SYSDATE,
           edi_file,
           0,
           ll_customer_id,
           ll_st_log,
           '870');
--         COMMIT;

     FOR m IN 0 .. k - 1 LOOP
       UPDATE production_sheet_item
           SET prod_item_edi870_date = SYSDATE,
               edi_file_id_870 = ll_edi_file_id_aleris /* Alex Gerlants. 09/06/2016. New column */
         WHERE production_sheet_item.prod_item_num = item_num(m);
    END LOOP;

--      COMMIT;

        FOR m in 0..p - 1 LOOP
                UPDATE coil
          SET coil.scrap_870_date = sysdate
                WHERE coil.coil_abc_num = coil_num(m);

               UPDATE process_coil
          SET scrap_870_date = sysdate
                WHERE ( coil_abc_num = coil_num(m)) AND (scrap_870_date is NULL);

             END LOOP;

        COMMIT;

    END IF; --end if in select count(*)

  END LOOP; ------ End of outer loop customer_id

EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN;
END;
