--  DDL for Procedure EDI_ALCAN_870_BAK
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."EDI_ALCAN_870_BAK" IS

  /*
  Aluminum Blanking: Ford Suppler Code: ZZ R0P7A
                     DUNS: 01 039630926T
  Customer: ALCAN(34,35,10,1153)
  Alcan Rolled Product    X.121       0015049350011G
  Kingston Duns: 241003755
  */

  edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';

  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_handle utl_file.file_type;
  su_duns         VARCHAR2(10);
  ll_customer_id  INTEGER := 1153;

  ll_gs_log INTEGER;
  ll_st_log INTEGER;
  --ll_bsn_log integer;

  ls_today   VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD');
  ls_today_4 VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  ls_now     VARCHAR2(20) := to_char(SYSDATE, 'HH24MI'); -- time in 24 hours format....Tony

  ls_po VARCHAR2(36);

  --ll_edi_file_id integer;
  ll_edi_file_id_alcan INTEGER;

  ll_item_count INTEGER;

  li_hl01 INTEGER;

  CURSOR cust_cur IS
    SELECT customer_id
      FROM customer
     WHERE customer_id IN (1153, 1459, 2582); ---Add customer id here if you want to send 870 for more customers

  CURSOR alcan_870_cur IS
    SELECT production_sheet_item.ab_job_num,
           production_sheet_item.prod_item_pieces,
           production_sheet_item.prod_item_num,
           sheet_skid.sheet_skid_num,
           sheet_skid.sheet_skid_display_num,
           production_sheet_item.prod_item_net_wt,
           sheet_skid.skid_sheet_status,
           coil.coil_org_num,
           nvl(coil.consumed_coil_num, ' ') consumed_coil,   --add james ni 10/22/2013
           nvl(customer_order.sales_order, ' ') sales_order,
           nvl(customer_order.orig_customer_po, 'NA') customer_po,
           (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
           NULL done
      FROM sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil,
           customer_order --,ab_job
     WHERE (sheet_skid.skid_sheet_status IN (2, 4, 8, 13))
       AND (production_sheet_item.prod_item_edi870_date IS NULL)
       AND (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       AND (sheet_skid_detail.prod_item_num =
           production_sheet_item.prod_item_num)
       AND (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       AND (coil.customer_id = ll_customer_id)
       AND -- Add Oswego id=1459 by Tony 04-29-03
           (sheet_skid.ref_order_abc_num = customer_order.order_abc_num);
  --(production_sheet_item.ab_job_num = ab_job.ab_job_num) and
  --(ab_job.order_abc_num = customer_order.order_abc_num) ;

  --End of change by tony

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;
  item_rec  alcan_870_cur%ROWTYPE;

  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;

BEGIN

  FOR cust_rec IN cust_cur LOOP
 
    --- Outer loop of customer_id
    ll_customer_id := cust_rec.customer_id;
    i              := 0;
    k              := 0;
    
  
    SELECT COUNT(*)
      INTO ll_item_count
      FROM sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil,
           customer_order
     WHERE (sheet_skid.skid_sheet_status IN (2, 4, 8, 13))
       AND (production_sheet_item.prod_item_edi870_date IS NULL)
       AND (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       AND (sheet_skid_detail.prod_item_num =
           production_sheet_item.prod_item_num)
       AND (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       AND (coil.customer_id = ll_customer_id)
       AND -- Add Oswego id=1459 by Tony 04-29-03
           (sheet_skid.ref_order_abc_num = customer_order.order_abc_num);
    -- if ll_item_count = 0 then return 100; end if;   -- nothing to send
    IF ll_item_count <> 0 THEN
    
      SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
      SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
    
      SELECT customer.customer_duns_number_string
        INTO su_duns
        FROM customer
       WHERE customer.customer_id = ll_customer_id;
    
      x12_table(i) := 'ISA*00*' ||
                      '          *00*          *01*039630926T     *09*0015049350011G *' ||
                      ls_today_4 || '*' || ls_now || '*U*00401*' ||
                      lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
      i := i + 1;
      x12_table(i) := 'GS*RS*039630926T*' || '001504935001' || '*' ||
                      ls_today || '*' || ls_now || '*' ||
                      to_char(ll_gs_log) || '*X*' || '004010';
      i := i + 1;
      x12_table(i) := 'ST*870*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                      '***' || ls_now || '*****';
      i := i + 1;
      x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
      i := i + 1;
--      x12_table(i) := 'N1*SU**1*' || su_duns || '*NA'; - by james 11/6/2013
      x12_table(i) := 'N1*SU**1*' || su_duns;      
      i := i + 1;
      x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926T';
      i := i + 1;
    
      --open alcan_870_cur;
      --fetch alcan_870_cur INTO item_rec;
      --close alcan_870_cur;
    
      li_hl01 := 1;
    
      FOR item_rec IN alcan_870_cur LOOP
        x12_table(i) := 'HL*' || to_char(li_hl01) || '**I';
        i := i + 1;
      
        ls_po := item_rec.customer_po;
      
        x12_table(i) := 'PRF*' || ls_po || '****NA';
        i := i + 1;
        x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
        i := i + 1;
        -- Nov 21 03, change per Alcan  ---tony
        --x12_table(i) := 'REF*SE*' ||item_rec.coil_org_num ||'-'||to_char(item_rec.sheet_skid_num); i := i+1;
      
        x12_table(i) := 'REF*SE*' || to_char(item_rec.prod_item_num);
        i := i + 1;
        
        --add james ni 10/22/2013
 --       x12_table(i) := 'REF*IX*' || to_char(item_rec.consumed_coil);
 --       i := i + 1;
     
        x12_table(i) := 'REF*MI*' || to_char(item_rec.ab_job_num);
        i := i + 1;
      
        -- Nov 21 03, change per Alcan  ---tony
        x12_table(i) := 'REF*RV*' || to_char(item_rec.prod_item_num) ||
                        '*NA';
        i := i + 1;
      
        --06/05/03 Don't send PO106 AND PO107 incase non sales order available as per Julia
        IF item_rec.sales_order = ' ' THEN
          x12_table(i) := 'PO1**1*UN****' || '***SN*' ||
                          item_rec.coil_org_num;
          i := i + 1;
        ELSE
          x12_table(i) := 'PO1**1*UN***VO*' || item_rec.sales_order ||
                          '***SN*' || item_rec.coil_org_num;
          i := i + 1;
        END IF;
      
        -- Added partial ready(13), On-hold(4) by Bing Feb-26-2002 
        -- deleted || '*NA' from each line by james 11/6/2013 
        IF item_rec.skid_sheet_status = 2 THEN
          x12_table(i) := 'PID*S*MA*ST*1*' ||
                          to_char(item_rec.sheet_skid_display_num);                        
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 13 THEN
          x12_table(i) := 'PID*S*MA*ST*8*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        ELSE
          x12_table(i) := 'PID*S*MA*ST*3*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        END IF;
      
        x12_table(i) := 'PID*S*MAC*ST*01';
        i := i + 1;
        x12_table(i) := 'PID*S*PR*ST*19';
        i := i + 1;
        x12_table(i) := 'MEA*WT*N*' || to_char(item_rec.prod_item_net_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*WT*G*' || to_char(item_rec.skid_gross_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*CT*NA*' || to_char(item_rec.prod_item_pieces) ||
                        '*PC';
        i := i + 1;
      
        li_hl01 := li_hl01 + 1;
      
        item_num(k) := item_rec.prod_item_num;
        k := k + 1;
      
      END LOOP;
      x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
      i := i + 1;
      x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
      i := i + 1;
      x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');
    
      -- Write EDI to file
    
      IF li_hl01 > 1 THEN
        -- WRITE EDI FILE ONLY IF ITEM > 0
        SELECT edi_file_id_seq.nextval INTO ll_edi_file_id_alcan FROM dual;
        edi_file        := 'S_alcan_' || to_char(ll_edi_file_id_alcan) ||
                           '.870';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
      
        FOR j IN 0 .. i LOOP
          utl_file.put_line(edi_file_handle, x12_table(j));
        
        END LOOP;
        utl_file.fclose(edi_file_handle);
      END IF; -- END WRITING EDI FILE
    
      --added by Victor Huang on 12/07 for verifying 997
      INSERT INTO outbound_edi_transaction
        (edi_file_id,
         duns_from,
         duns_to,
         interchange_control_number,
         group_control_number,
         transaction_time,
         edi_file_name,
         fa_receive_status,
         customer_id,
         set_control_num,
         transaction_type_id)
      VALUES
        (ll_edi_file_id_alcan,
         '039630926',
         su_duns,
         ll_gs_log,
         ll_gs_log,
         SYSDATE,
         edi_file,
         0,
         ll_customer_id,
         ll_st_log,
         '870');
      COMMIT;
    
      edi_file        := 'send_edi_log';
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);
    
      FOR m IN 0 .. k - 1 LOOP
        UPDATE production_sheet_item
           SET prod_item_edi870_date = SYSDATE
         WHERE production_sheet_item.prod_item_num = item_num(m);
      END LOOP;
    
      COMMIT;
    
    END IF; --end if in select count(*)
    
 
  END LOOP; ------ End of outer loop customer_id

EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN;
END;
  GRANT EXECUTE ON "DBO"."EDI_ALCAN_870_BAK" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Procedure EDI_ALCAN_870_ONE_JOB
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."EDI_ALCAN_870_ONE_JOB" 
     (
        al_ab_job_num  ab_job.ab_job_num%type
     )


is

  /*
  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   Customer: Aleris(1980) DUNS:964790856     EDI ID:964790856      QUALIFIER: ZZ

   End User: Aleris, Customer ID 1980
   */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50) := get_edi_destination('EDI_DIR');

  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_prefix VARCHAR2(50) := 's_alcan_870_one_job_';
  edi_file_handle utl_file.file_type;
  su_duns         VARCHAR2(10);
  ll_customer_id  customer.customer_id%TYPE;
  ll_cur_coil     coil.coil_abc_num%TYPE;

--  ll_cur_job ab_job.ab_job_num%TYPE;

  ll_gs_log INTEGER;
  ll_st_log INTEGER;

  ls_today   VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD');
  ls_today_4 VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  ls_now     VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  ls_po VARCHAR2(20);
  ls_finished_goods VARCHAR2(32);
  ls_cust_prod_line VARCHAR2(8);

  ld_scrap_870_date ab_job.scrap_870_date%TYPE;

  ls_coil_org_num coil.coil_org_num%TYPE;
  ls_heat coil.lot_num%TYPE;

--  ll_ref_order_abc_num sheet_skid.ref_order_abc_num%TYPE;
--  ll_ref_order_abc_item sheet_skid.ref_order_abc_item%TYPE;
--  ls_sheet_type order_item.sheet_type%TYPE;

  ll_prime_nw coil.net_wt%TYPE;
  ll_scrap_nw coil.net_wt%TYPE;
--  ll_process_quantity  coil.net_wt%TYPE;
--  ll_process_end_wt  coil.net_wt%TYPE;
--  lr_theo_unit_wt order_item.theoretical_unit_wt%TYPE;

  --ll_edi_file_id integer;
  ll_edi_file_id_aleris INTEGER;

  ll_item_count INTEGER;

  li_hl01 INTEGER;
  li_hllin INTEGER;

  --CURSOR cust_cur IS
  --  SELECT customer_id FROM customer WHERE customer_id IN (1153,1459,2582); ---Add customer id here if you want to send 870 for more customers

  CURSOR coil_cur IS
  SELECT UNIQUE C.COIL_ABC_NUM
  FROM SHEET_SKID_DETAIL SKD
    JOIN SHEET_SKID SK ON SKD.SHEET_SKID_NUM = SK.SHEET_SKID_NUM
    JOIN PRODUCTION_SHEET_ITEM PSI ON SKD.PROD_ITEM_NUM = PSI.PROD_ITEM_NUM
    JOIN COIL C ON PSI.COIL_ABC_NUM = C.COIL_ABC_NUM
    JOIN AB_JOB AB ON SK.AB_JOB_NUM = AB.AB_JOB_NUM
    JOIN CUSTOMER_ORDER CO ON CO.ORDER_ABC_NUM = AB.ORDER_ABC_NUM
  WHERE (AB.JOB_STATUS = 0) AND
    --( C.COIL_STATUS IN (0, 3) ) AND
    ( CO.ORIG_CUSTOMER_ID = ll_customer_id ) AND
    --( PSI.PROD_ITEM_EDI870_DATE is NULL ) AND
    --( C.SCRAP_870_DATE is NULL ) AND
    --( SK.SKID_SHEET_STATUS in (0,2,4,12,13) );
    ( ab.ab_job_num = al_ab_job_num )
    --and ( sk.sheet_skid_num in (703642, 703643, 703644, 703645) )
    ;

  CURSOR alcan_870_cur IS
   SELECT production_sheet_item.ab_job_num,
           production_sheet_item.coil_abc_num,
           production_sheet_item.prod_item_pieces,
           production_sheet_item.prod_item_num,
           sheet_skid.sheet_skid_num,
           production_sheet_item.prod_item_net_wt,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_skid_display_num,
           sheet_skid.sheet_net_wt,
           sheet_skid.skid_pieces,
           coil.coil_org_num,
           coil.lot_num,
           nvl(coil.consumed_coil_num, ' ') consumed_coil,
           nvl(coil.material_num, ' ') material_num,
           nvl(customer_order.sales_order, ' ') sales_order,
           nvl(customer_order.orig_customer_po, 'NA') customer_po,
           nvl(order_item.enduser_part_num, ' ') enduser_parts,
           nvl(order_item.cust_prod_line_id, 'NA') customer_line_id,
           nvl(order_item.finished_goods_material_num, 'NA') finished_goods,
           (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
           NULL done
      FROM sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil,
           order_item,
           ab_job,
           customer_order
     --WHERE (sheet_skid.skid_sheet_status IN (0, 2, 4, 13, 12)) -- 2: Ready; 8: Warehouse Ready; 13: Partial Ready; 7: Partial; 12: Sample; 4: onhold
     --  AND (production_sheet_item.prod_item_edi870_date IS NULL)
     where (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       AND (sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num)
       AND (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       AND (coil.customer_id = ll_customer_id)
       AND (sheet_skid.ref_order_abc_num = customer_order.order_abc_num)
       AND (production_sheet_item.ab_job_num = ab_job.ab_job_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (production_sheet_item.coil_abc_num = ll_cur_coil)
       and ( ab_job.ab_job_num = al_ab_job_num )
       --and ( sheet_skid.sheet_skid_num in (703642, 703643, 703644, 703645) )
       ;
     

       CURSOR alcan_scrap_870_cur IS
       SELECT a.coil_abc_num,
              b.coil_org_num,
              a.ab_job_num,
              nvl(b.material_num, ' ') material_num,
               NVL(a.process_quantity, 0) process_quan,
               NVL(a.process_end_wt, 0) process_end_wt
       FROM process_coil a, coil b
       WHERE (b.coil_abc_num = ll_cur_coil)
         AND (a.coil_abc_num = b.coil_abc_num);
         --AND (a.scrap_870_date is NULL);

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;

  item_rec  alcan_870_cur%ROWTYPE;
  coil_rec  coil_cur%ROWTYPE;

  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;

  TYPE coil_num_type IS TABLE OF coil.coil_abc_num%type INDEX BY BINARY_INTEGER;
  coil_num coil_num_type;
  p binary_integer :=0;

BEGIN

  --FOR cust_rec IN cust_cur LOOP
    --- Outer loop of customer_id
    --ll_customer_id := cust_rec.customer_id;
    
  select      distinct customer_order.orig_customer_id
  into        ll_customer_id
  from        process_coil
              join coil on coil.coil_abc_num = process_coil.coil_abc_num
              join production_sheet_item on coil.coil_abc_num = production_sheet_item.coil_abc_num and process_coil.ab_job_num = production_sheet_item.ab_job_num
              join sheet_skid_detail on production_sheet_item.prod_item_num = sheet_skid_detail.prod_item_num
              join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
              join ab_job on ab_job.ab_job_num = process_coil.ab_job_num
              join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
  where       ab_job.ab_job_num = al_ab_job_num;
    
  i              := 0;
  k              := 0;
  p              := 0;

  SELECT count(COIL.COIL_ABC_NUM)
  INTO ll_item_count
    FROM AB_JOB,
         COIL,
         PRODUCTION_SHEET_ITEM,
         SHEET_SKID,
         SHEET_SKID_DETAIL,
         CUSTOMER_ORDER
   WHERE ( SHEET_SKID_DETAIL.SHEET_SKID_NUM = SHEET_SKID.SHEET_SKID_NUM ) and
         ( SHEET_SKID_DETAIL.PROD_ITEM_NUM = PRODUCTION_SHEET_ITEM.PROD_ITEM_NUM ) and
         ( COIL.COIL_ABC_NUM = PRODUCTION_SHEET_ITEM.COIL_ABC_NUM ) and
         ( AB_JOB.AB_JOB_NUM = SHEET_SKID.AB_JOB_NUM ) and
         ( AB_JOB.ORDER_ABC_NUM = CUSTOMER_ORDER.ORDER_ABC_NUM ) and
         ( AB_JOB.JOB_STATUS = 0 ) AND
         --(  COIL.COIL_STATUS in (0, 3) ) AND
         ( CUSTOMER_ORDER.ORIG_CUSTOMER_ID = ll_customer_id ) AND
         --( PRODUCTION_SHEET_ITEM.PROD_ITEM_EDI870_DATE is NULL ) AND
         --( COIL.SCRAP_870_DATE is NULL ) AND
         --( SHEET_SKID.SKID_SHEET_STATUS in (0, 2,4,12,13) );
         ( ab_job.ab_job_num = al_ab_job_num )
         --and ( sheet_skid.sheet_skid_num in (703642, 703643, 703644, 703645) )
         ;

    IF (ll_item_count <> 0) THEN

      SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
      SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;

      SELECT customer.customer_duns_number_string
        INTO su_duns
        FROM customer
       WHERE customer.customer_id = ll_customer_id;

      x12_table(i) := 'ISA*00*' ||
                      '          *00*          *01*039630926T     *09*0015049350011G *' ||
                      ls_today_4 || '*' || ls_now || '*U*00401*' ||
                      lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
      i := i + 1;
      x12_table(i) := 'GS*RS*039630926T*' || '001504935001' || '*' ||
                      ls_today || '*' || ls_now || '*' ||
                      to_char(ll_gs_log) || '*X*' || '004010';
      i := i + 1;
      x12_table(i) := 'ST*870*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                      '***' || ls_now || '*****';
      i := i + 1;
      x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
      i := i + 1;
      x12_table(i) := 'N1*SU**1*' || su_duns;
      i := i + 1;
      x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926';
      i := i + 1;

      li_hl01 := 0;

      FOR coil_rec IN coil_cur LOOP    -- coil loop
          ll_cur_coil := coil_rec.coil_abc_num;

          coil_num(p) := ll_cur_coil;
          p := p + 1;


        FOR item_rec IN alcan_870_cur LOOP   -- item loop

        li_hl01 := li_hl01 + 1;

        x12_table(i) := 'HL*' || to_char(li_hl01) || '**I';
        i := i + 1;

              SELECT nvl(customer_order.orig_customer_po, 'NA'),
                     nvl(order_item.cust_prod_line_id, 'NA'),
                     nvl(order_item.finished_goods_material_num, 'NA')
              INTO ls_po, ls_cust_prod_line, ls_finished_goods
              FROM   order_item,
                     ab_job,
                     customer_order
             WHERE (ab_job.order_abc_num = customer_order.order_abc_num)
             AND (ab_job.order_abc_num = order_item.order_abc_num)
             AND (ab_job.order_item_num = order_item.order_item_num)
              AND (ab_job.ab_job_num = item_rec.ab_job_num);

        IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
           x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
           i := i + 1;
        END IF;

        x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
        i := i + 1;

        x12_table(i) := 'REF*SE*' || to_char(item_rec.prod_item_num);
        i := i + 1;


        x12_table(i) := 'REF*MI*' || to_char(item_rec.ab_job_num);
        i := i + 1;

        x12_table(i) := 'REF*RV*' || to_char(item_rec.prod_item_num) ||
                        '*NA';
        i := i + 1;

        x12_table(i) := 'REF*IX*' || to_char(item_rec.consumed_coil);
        i := i + 1;

        x12_table(i) := 'PO1**1*UN****' || '***SN*' ||
                          item_rec.coil_org_num || '***VP*' || item_rec.finished_goods;
        i := i + 1;

        IF item_rec.skid_sheet_status = 2 THEN
          x12_table(i) := 'PID*S*MA*ST*1*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 4 THEN
          x12_table(i) := 'PID*S*MA*ST*3*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 13 THEN
          x12_table(i) := 'PID*S*MA*ST*8*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
         ELSE
          x12_table(i) := 'PID*S*MA*ST*4*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        END IF;

        x12_table(i) := 'PID*S*MAC*ST*01';
        i := i + 1;
        x12_table(i) := 'PID*S*PR*ST*19';
        i := i + 1;
        x12_table(i) := 'MEA*WT*N*' || to_char(item_rec.prod_item_net_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*WT*G*' || to_char(item_rec.skid_gross_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*CT*NA*' || to_char(item_rec.prod_item_pieces) ||
                        '*PC';
        i := i + 1;

         item_num(k) := item_rec.prod_item_num;
        k := k + 1;

      END LOOP;  -- item loop

     SELECT scrap_870_date, coil_org_num, lot_num
     INTO ld_scrap_870_date, ls_coil_org_num, ls_heat
     FROM coil
     WHERE coil_abc_num = ll_cur_coil;
     
     ld_scrap_870_date := null; --Alex Gerlants. 01/12/2019. Added to get through

     IF (ld_scrap_870_date is NULL) THEN  -- scrap not sent

      FOR scrap_rec IN alcan_scrap_870_cur LOOP    -- scrap loop

        --scrap info

        SELECT NVL(sum(production_sheet_item.prod_item_net_wt),0)
        into ll_prime_nw
         FROM production_sheet_item
         WHERE (production_sheet_item.ab_job_num = scrap_rec.ab_job_num) and
               (production_sheet_item.coil_abc_num = ll_cur_coil);


                ll_scrap_nw := scrap_rec.process_quan - scrap_rec.process_end_wt - ll_prime_nw;



                IF ll_scrap_nw > 0 then

                   li_hl01 := li_hl01 + 1;

                   x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*I';
                   i := i + 1;

                   IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
                      x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
                      i := i + 1;
                   END IF;

                   x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
                    i := i + 1;

                    x12_table(i) := 'PO1**1*UN****' || '***SN*' || scrap_rec.coil_org_num ;
                    i := i + 1;

                    x12_table(i) := 'PID*S*MA*ST*S';
                    i := i + 1;
                    x12_table(i) := 'PID*S*MAC*ST*05';
                     i := i + 1;
                    x12_table(i) := 'PID*S*PR*ST*19';
                     i := i + 1;

                   x12_table(i) := 'MEA*WT*N*' || to_char(ll_scrap_nw) || '*LB*01';
                   i := i+1;
                 END IF;

        END LOOP;  -- scrap loop
      END IF;  -- scrap not sent
     END LOOP;   -- coil loop
      x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
      i := i + 1;
      x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
      i := i + 1;
      x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

      -- Write EDI to file

      IF li_hl01 > 1 THEN
        -- WRITE EDI FILE ONLY IF ITEM > 0
        SELECT edi_file_id_seq.nextval
          INTO ll_edi_file_id_aleris
          FROM dual;
        edi_file        := edi_file_prefix || to_char(ll_edi_file_id_aleris) || '.edi';
     -- edi_file        := 's_alcan_' || to_char(ll_edi_file_id_aleris) || '.870';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        FOR j IN 0 .. i LOOP
          utl_file.put_line(edi_file_handle, x12_table(j));

        END LOOP;
        utl_file.fclose(edi_file_handle);
      END IF; -- END WRITING EDI FILE

      --edi_file        := 'send_edi_log'; /* Alex Gerlants. 04/14/2017. Commented out. */
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      --For verifying 997
/*      
      INSERT INTO outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
        VALUES
          (ll_edi_file_id_aleris,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           SYSDATE,
           edi_file,
           0,
           ll_customer_id,
           ll_st_log,
           '870');
*/           
--         COMMIT;

     --FOR m IN 0 .. k - 1 LOOP
     --  UPDATE production_sheet_item
     --      SET prod_item_edi870_date = SYSDATE,
     --          edi_file_id_870 = ll_edi_file_id_aleris /* Alex Gerlants. 09/06/2016. New column */
     --    WHERE production_sheet_item.prod_item_num = item_num(m);
     --END LOOP;

--      COMMIT;

        /*
        FOR m in 0..p - 1 LOOP
                UPDATE coil
					SET coil.scrap_870_date = sysdate
                WHERE coil.coil_abc_num = coil_num(m);

               UPDATE process_coil
					SET scrap_870_date = sysdate
                WHERE ( coil_abc_num = coil_num(m)) AND (scrap_870_date is NULL);

         END LOOP;
         */

        COMMIT;

    END IF; --end if in select count(*)

  --END LOOP; ------ End of outer loop customer_id

EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN;
END;
--------------------------------------------------------
--  DDL for Procedure EDI_ALCAN_870_ONE_SKID
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."EDI_ALCAN_870_ONE_SKID" 
     (
        al_sheet_skid_num  sheet_skid.sheet_skid_num%type
     )
is


  /*
  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   Customer: Aleris(1980) DUNS:964790856     EDI ID:964790856      QUALIFIER: ZZ

   End User: Aleris, Customer ID 1980
   */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50) := get_edi_destination('EDI_DIR');

  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_prefix VARCHAR2(50) := 's_alcan_870_one_skid_';
  edi_file_handle utl_file.file_type;
  su_duns         VARCHAR2(10);
  ll_customer_id  customer.customer_id%TYPE;
  ll_cur_coil     coil.coil_abc_num%TYPE;

--  ll_cur_job ab_job.ab_job_num%TYPE;

  ll_gs_log INTEGER;
  ll_st_log INTEGER;

  ls_today   VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD');
  ls_today_4 VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  ls_now     VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  ls_po VARCHAR2(20);
  ls_finished_goods VARCHAR2(32);
  ls_cust_prod_line VARCHAR2(8);

  ld_scrap_870_date ab_job.scrap_870_date%TYPE;

  ls_coil_org_num coil.coil_org_num%TYPE;
  ls_heat coil.lot_num%TYPE;

--  ll_ref_order_abc_num sheet_skid.ref_order_abc_num%TYPE;
--  ll_ref_order_abc_item sheet_skid.ref_order_abc_item%TYPE;
--  ls_sheet_type order_item.sheet_type%TYPE;

  ll_prime_nw coil.net_wt%TYPE;
  ll_scrap_nw coil.net_wt%TYPE;
--  ll_process_quantity  coil.net_wt%TYPE;
--  ll_process_end_wt  coil.net_wt%TYPE;
--  lr_theo_unit_wt order_item.theoretical_unit_wt%TYPE;

  --ll_edi_file_id integer;
  ll_edi_file_id_aleris INTEGER;

  ll_item_count INTEGER;

  li_hl01 INTEGER;
  li_hllin INTEGER;

  CURSOR cust_cur IS
    SELECT customer_id FROM customer WHERE customer_id IN (1153,1459,2582); ---Add customer id here if you want to send 870 for more customers

  CURSOR coil_cur IS
  SELECT UNIQUE C.COIL_ABC_NUM
  FROM SHEET_SKID_DETAIL SKD
    JOIN SHEET_SKID SK ON SKD.SHEET_SKID_NUM = SK.SHEET_SKID_NUM
    JOIN PRODUCTION_SHEET_ITEM PSI ON SKD.PROD_ITEM_NUM = PSI.PROD_ITEM_NUM
    JOIN COIL C ON PSI.COIL_ABC_NUM = C.COIL_ABC_NUM
    JOIN AB_JOB AB ON SK.AB_JOB_NUM = AB.AB_JOB_NUM
    JOIN CUSTOMER_ORDER CO ON CO.ORDER_ABC_NUM = AB.ORDER_ABC_NUM
  WHERE (AB.JOB_STATUS = 0) AND
    --( C.COIL_STATUS IN (0, 3) ) AND
    ( CO.ORIG_CUSTOMER_ID in (1459, 1153) ) AND
    --( PSI.PROD_ITEM_EDI870_DATE is NULL ) AND
    --( C.SCRAP_870_DATE is NULL ) AND
    --( SK.SKID_SHEET_STATUS in (0,2,4,12,13) );
    ( sk.sheet_skid_num = al_sheet_skid_num 
    --and ( c.coil_org_num in ('1726314', '1727530') )
    );

  CURSOR alcan_870_cur IS
   SELECT production_sheet_item.ab_job_num,
           production_sheet_item.coil_abc_num,
           production_sheet_item.prod_item_pieces,
           production_sheet_item.prod_item_num,
           sheet_skid.sheet_skid_num,
           production_sheet_item.prod_item_net_wt,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_skid_display_num,
           sheet_skid.sheet_net_wt,
           sheet_skid.skid_pieces,
           coil.coil_org_num,
           coil.lot_num,
           nvl(coil.consumed_coil_num, ' ') consumed_coil,
           nvl(coil.material_num, ' ') material_num,
           nvl(customer_order.sales_order, ' ') sales_order,
           nvl(customer_order.orig_customer_po, 'NA') customer_po,
           nvl(order_item.enduser_part_num, ' ') enduser_parts,
           nvl(order_item.cust_prod_line_id, 'NA') customer_line_id,
           nvl(order_item.finished_goods_material_num, 'NA') finished_goods,
           (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
           NULL done
      FROM sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil,
           order_item,
           ab_job,
           customer_order
     --WHERE (sheet_skid.skid_sheet_status IN (0, 2, 4, 13, 12)) -- 2: Ready; 8: Warehouse Ready; 13: Partial Ready; 7: Partial; 12: Sample; 4: onhold
     --  AND (production_sheet_item.prod_item_edi870_date IS NULL)
     where (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       AND (sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num)
       AND (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       AND (coil.customer_id in (1459, 1153))
       AND (sheet_skid.ref_order_abc_num = customer_order.order_abc_num)
       AND (production_sheet_item.ab_job_num = ab_job.ab_job_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (production_sheet_item.coil_abc_num = ll_cur_coil)
       --and ( ab_job.ab_job_num = 105057 );
       and  ( sheet_skid.sheet_skid_num = al_sheet_skid_num 
       --and ( coil.coil_org_num in ('1726314', '1727530') )
       );

     

       CURSOR alcan_scrap_870_cur IS
       SELECT a.coil_abc_num,
              b.coil_org_num,
              a.ab_job_num,
              nvl(b.material_num, ' ') material_num,
               NVL(a.process_quantity, 0) process_quan,
               NVL(a.process_end_wt, 0) process_end_wt
       FROM process_coil a, coil b
       WHERE (b.coil_abc_num = ll_cur_coil)
         AND (a.coil_abc_num = b.coil_abc_num);
         --AND (a.scrap_870_date is NULL);

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;

  item_rec  alcan_870_cur%ROWTYPE;
  coil_rec  coil_cur%ROWTYPE;

  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;

  TYPE coil_num_type IS TABLE OF coil.coil_abc_num%type INDEX BY BINARY_INTEGER;
  coil_num coil_num_type;
  p binary_integer :=0;

BEGIN

  --FOR cust_rec IN cust_cur LOOP
    --- Outer loop of customer_id
    --ll_customer_id := cust_rec.customer_id;
    
  select      distinct customer_order.orig_customer_id
  into        ll_customer_id
  from        process_coil
              join coil on coil.coil_abc_num = process_coil.coil_abc_num
              join production_sheet_item on coil.coil_abc_num = production_sheet_item.coil_abc_num and process_coil.ab_job_num = production_sheet_item.ab_job_num
              join sheet_skid_detail on production_sheet_item.prod_item_num = sheet_skid_detail.prod_item_num
              join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
              join ab_job on ab_job.ab_job_num = process_coil.ab_job_num
              join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
  where       sheet_skid.sheet_skid_num = al_sheet_skid_num;
    
  i := 0;
  k := 0;
  p := 0;

  SELECT count(COIL.COIL_ABC_NUM)
  INTO ll_item_count
    FROM AB_JOB,
         COIL,
         PRODUCTION_SHEET_ITEM,
         SHEET_SKID,
         SHEET_SKID_DETAIL,
         CUSTOMER_ORDER
   WHERE ( SHEET_SKID_DETAIL.SHEET_SKID_NUM = SHEET_SKID.SHEET_SKID_NUM ) and
         ( SHEET_SKID_DETAIL.PROD_ITEM_NUM = PRODUCTION_SHEET_ITEM.PROD_ITEM_NUM ) and
         ( COIL.COIL_ABC_NUM = PRODUCTION_SHEET_ITEM.COIL_ABC_NUM ) and
         ( AB_JOB.AB_JOB_NUM = SHEET_SKID.AB_JOB_NUM ) and
         ( AB_JOB.ORDER_ABC_NUM = CUSTOMER_ORDER.ORDER_ABC_NUM ) and
         ( AB_JOB.JOB_STATUS = 0 ) AND
         --(  COIL.COIL_STATUS in (0, 3) ) AND
         ( CUSTOMER_ORDER.ORIG_CUSTOMER_ID in (1459, 1153) ) AND
         --( PRODUCTION_SHEET_ITEM.PROD_ITEM_EDI870_DATE is NULL ) AND
         --( COIL.SCRAP_870_DATE is NULL ) AND
         --( SHEET_SKID.SKID_SHEET_STATUS in (0, 2,4,12,13) );
         ( SHEET_SKID.sheet_skid_num = al_sheet_skid_num 
         --and ( coil.coil_org_num in ('1726314', '1727530') )
         );

    IF (ll_item_count <> 0) THEN

      SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
      SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;

      SELECT customer.customer_duns_number_string
        INTO su_duns
        FROM customer
       WHERE customer.customer_id = ll_customer_id;

      x12_table(i) := 'ISA*00*' ||
                      '          *00*          *01*039630926T     *09*0015049350011G *' ||
                      ls_today_4 || '*' || ls_now || '*U*00401*' ||
                      lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
      i := i + 1;
      x12_table(i) := 'GS*RS*039630926T*' || '001504935001' || '*' ||
                      ls_today || '*' || ls_now || '*' ||
                      to_char(ll_gs_log) || '*X*' || '004010';
      i := i + 1;
      x12_table(i) := 'ST*870*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                      '***' || ls_now || '*****';
      i := i + 1;
      x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
      i := i + 1;
      x12_table(i) := 'N1*SU**1*' || su_duns;
      i := i + 1;
      x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926';
      i := i + 1;

      li_hl01 := 0;

      FOR coil_rec IN coil_cur LOOP    -- coil loop
          ll_cur_coil := coil_rec.coil_abc_num;

          coil_num(p) := ll_cur_coil;
          p := p + 1;


        FOR item_rec IN alcan_870_cur LOOP   -- item loop

        li_hl01 := li_hl01 + 1;

        x12_table(i) := 'HL*' || to_char(li_hl01) || '**I';
        i := i + 1;

              SELECT nvl(customer_order.orig_customer_po, 'NA'),
                     nvl(order_item.cust_prod_line_id, 'NA'),
                     nvl(order_item.finished_goods_material_num, 'NA')
              INTO ls_po, ls_cust_prod_line, ls_finished_goods
              FROM   order_item,
                     ab_job,
                     customer_order
             WHERE (ab_job.order_abc_num = customer_order.order_abc_num)
             AND (ab_job.order_abc_num = order_item.order_abc_num)
             AND (ab_job.order_item_num = order_item.order_item_num)
              AND (ab_job.ab_job_num = item_rec.ab_job_num);

        IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
           x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
           i := i + 1;
        END IF;

        x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
        i := i + 1;

        x12_table(i) := 'REF*SE*' || to_char(item_rec.prod_item_num);
        i := i + 1;


        x12_table(i) := 'REF*MI*' || to_char(item_rec.ab_job_num);
        i := i + 1;

        x12_table(i) := 'REF*RV*' || to_char(item_rec.prod_item_num) ||
                        '*NA';
        i := i + 1;

        x12_table(i) := 'REF*IX*' || to_char(item_rec.consumed_coil);
        i := i + 1;

        x12_table(i) := 'PO1**1*UN****' || '***SN*' ||
                          item_rec.coil_org_num || '***VP*' || item_rec.finished_goods;
        i := i + 1;

        IF item_rec.skid_sheet_status = 2 THEN
          x12_table(i) := 'PID*S*MA*ST*1*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 4 THEN
          x12_table(i) := 'PID*S*MA*ST*3*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 13 THEN
          x12_table(i) := 'PID*S*MA*ST*8*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
         ELSE
          x12_table(i) := 'PID*S*MA*ST*4*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        END IF;

        x12_table(i) := 'PID*S*MAC*ST*01';
        i := i + 1;
        x12_table(i) := 'PID*S*PR*ST*19';
        i := i + 1;
        x12_table(i) := 'MEA*WT*N*' || to_char(item_rec.prod_item_net_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*WT*G*' || to_char(item_rec.skid_gross_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*CT*NA*' || to_char(item_rec.prod_item_pieces) ||
                        '*PC';
        i := i + 1;

         item_num(k) := item_rec.prod_item_num;
        k := k + 1;

      END LOOP;  -- item loop

     SELECT scrap_870_date, coil_org_num, lot_num
     INTO ld_scrap_870_date, ls_coil_org_num, ls_heat
     FROM coil
     WHERE coil_abc_num = ll_cur_coil;
     
     ld_scrap_870_date := null; --Alex Gerlants. 01/12/2019. Added to get through

     IF (ld_scrap_870_date is NULL) THEN  -- scrap not sent

      FOR scrap_rec IN alcan_scrap_870_cur LOOP    -- scrap loop

        --scrap info

        SELECT NVL(sum(production_sheet_item.prod_item_net_wt),0)
        into ll_prime_nw
         FROM production_sheet_item
         WHERE (production_sheet_item.ab_job_num = scrap_rec.ab_job_num) and
               (production_sheet_item.coil_abc_num = ll_cur_coil);


                ll_scrap_nw := scrap_rec.process_quan - scrap_rec.process_end_wt - ll_prime_nw;



                IF ll_scrap_nw > 0 then

                   li_hl01 := li_hl01 + 1;

                   x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*I';
                   i := i + 1;

                   IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
                      x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
                      i := i + 1;
                   END IF;

                   x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
                    i := i + 1;

                    x12_table(i) := 'PO1**1*UN****' || '***SN*' || scrap_rec.coil_org_num ;
                    i := i + 1;

                    x12_table(i) := 'PID*S*MA*ST*S';
                    i := i + 1;
                    x12_table(i) := 'PID*S*MAC*ST*05';
                     i := i + 1;
                    x12_table(i) := 'PID*S*PR*ST*19';
                     i := i + 1;

                   x12_table(i) := 'MEA*WT*N*' || to_char(ll_scrap_nw) || '*LB*01';
                   i := i+1;
                 END IF;

        END LOOP;  -- scrap loop
      END IF;  -- scrap not sent
     END LOOP;   -- coil loop
      x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
      i := i + 1;
      x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
      i := i + 1;
      x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

      -- Write EDI to file

      IF li_hl01 > 1 THEN
        -- WRITE EDI FILE ONLY IF ITEM > 0
        SELECT edi_file_id_seq.nextval
          INTO ll_edi_file_id_aleris
          FROM dual;
        edi_file        := edi_file_prefix || to_char(ll_edi_file_id_aleris) || '.edi';
     -- edi_file        := 's_alcan_' || to_char(ll_edi_file_id_aleris) || '.870';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        FOR j IN 0 .. i LOOP
          utl_file.put_line(edi_file_handle, x12_table(j));

        END LOOP;
        utl_file.fclose(edi_file_handle);
      END IF; -- END WRITING EDI FILE

      --edi_file        := 'send_edi_log'; /* Alex Gerlants. 04/14/2017. Commented out. */
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      --For verifying 997
      INSERT INTO outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
        VALUES
          (ll_edi_file_id_aleris,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           SYSDATE,
           edi_file,
           0,
           ll_customer_id,
           ll_st_log,
           '870');
--         COMMIT;

     --FOR m IN 0 .. k - 1 LOOP
     --  UPDATE production_sheet_item
     --      SET prod_item_edi870_date = SYSDATE,
     --          edi_file_id_870 = ll_edi_file_id_aleris /* Alex Gerlants. 09/06/2016. New column */
     --   WHERE production_sheet_item.prod_item_num = item_num(m);
     --END LOOP;

--      COMMIT;
        
       /*
       
        FOR m in 0..p - 1 LOOP
                UPDATE coil
					SET coil.scrap_870_date = sysdate
                WHERE coil.coil_abc_num = coil_num(m);

               UPDATE process_coil
					SET scrap_870_date = sysdate
                WHERE ( coil_abc_num = coil_num(m)) AND (scrap_870_date is NULL);

             END LOOP;
        */
        
        COMMIT;

    END IF; --end if in select count(*)

  --END LOOP; ------ End of outer loop customer_id

EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN;
END;
--------------------------------------------------------
--  DDL for Procedure EDI_ALCAN_870_ORIG
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."EDI_ALCAN_870_ORIG" IS

  /*
  Aluminum Blanking: Ford Suppler Code: ZZ R0P7A
                     DUNS: 01 039630926T
  Customer: ALCAN(34,35,10,1153)
  Alcan Rolled Product    X.121       0015049350011G
  Kingston Duns: 241003755
  */

  edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';

  --v_edi_text_alcan varchar2(32767);
  -- edi_loc varchar2(50):='/tmp';
  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_handle utl_file.file_type;
  su_duns         VARCHAR2(10);
  ll_customer_id  INTEGER := 1153;

  ll_gs_log INTEGER;
  ll_st_log INTEGER;
  --ll_bsn_log integer;

  ls_today   VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD');
  ls_today_4 VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  ls_now     VARCHAR2(20) := to_char(SYSDATE, 'HH24MI'); -- time in 24 hours format....Tony

  ls_po VARCHAR2(20);

  --ll_edi_file_id integer;
  ll_edi_file_id_alcan INTEGER;

  ll_item_count INTEGER;

  --li_customer_id shipment.customer_id%TYPE;
  --li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;

  li_hl01 INTEGER;
  /* Dec 23rd 02 changed by tony for re-assigned skid with other order
  Cursor alcan_870_cur IS
  SELECT   production_sheet_item.AB_JOB_NUM,
           production_sheet_item.prod_item_pieces,
           SHEET_SKID.SHEET_SKID_NUM,
           production_sheet_item.prod_item_net_wt,
           SHEET_SKID.SKID_SHEET_STATUS,
           coil.coil_org_num,
           NVL(customer_order.sales_order, 'NA') sales_order,
           NVL(customer_order.orig_customer_po, 'NA') customer_po,
           (SHEET_SKID.SHEET_NET_WT + SHEET_SKID.SHEET_TARE_WT) skid_gross_wt,
           NULL Done
  FROM    SHEET_SKID, production_sheet_item, sheet_skid_detail,coil,ab_job, customer_order
  WHERE        (sheet_skid.skid_sheet_status in ( 2, 4, 13)) and
               (production_sheet_item.prod_item_edi870_date is NULL ) and 
               (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num) and
               (sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num) and
               (coil.coil_abc_num = production_sheet_item.coil_abc_num ) and
               (coil.customer_id = 1153) and
               (production_sheet_item.ab_job_num = ab_job.ab_job_num) and
               (ab_job.order_abc_num = customer_order.order_abc_num) ;
  
  
  */

  --Begin of change 

  CURSOR cust_cur IS
    SELECT customer_id FROM customer WHERE customer_id IN (1153, 1459); ---Add customer id here if you want to send 870 for more customers

  CURSOR alcan_870_cur IS
    SELECT production_sheet_item.ab_job_num,
           production_sheet_item.prod_item_pieces,
           production_sheet_item.prod_item_num,
           sheet_skid.sheet_skid_num,
           production_sheet_item.prod_item_net_wt,
           sheet_skid.skid_sheet_status,
           coil.coil_org_num,
           nvl(customer_order.sales_order, ' ') sales_order,
           nvl(customer_order.orig_customer_po, 'NA') customer_po,
           (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
           NULL done
      FROM sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil,
           customer_order --,ab_job
     WHERE (sheet_skid.skid_sheet_status IN (2, 4, 8, 13))
       AND (production_sheet_item.prod_item_edi870_date IS NULL)
       AND (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       AND (sheet_skid_detail.prod_item_num =
           production_sheet_item.prod_item_num)
       AND (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       AND (coil.customer_id = ll_customer_id)
       AND -- Add Oswego id=1459 by Tony 04-29-03
           (sheet_skid.ref_order_abc_num = customer_order.order_abc_num);
  --(production_sheet_item.ab_job_num = ab_job.ab_job_num) and
  --(ab_job.order_abc_num = customer_order.order_abc_num) ;

  --End of change by tony

  --Type skidinfo_tabletype IS table of alcan_870_cur%ROWTYPE INDEX by binary_integer;
  --skidinfo_table skidinfo_tabletype;

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;
  item_rec  alcan_870_cur%ROWTYPE;

  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;

BEGIN

  FOR cust_rec IN cust_cur LOOP
    --- Outer loop of customer_id
    ll_customer_id := cust_rec.customer_id;
    i              := 0;
    k              := 0;
  
    SELECT COUNT(*)
      INTO ll_item_count
      FROM sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil,
           customer_order
     WHERE (sheet_skid.skid_sheet_status IN (2, 4, 8, 13))
       AND (production_sheet_item.prod_item_edi870_date IS NULL)
       AND (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       AND (sheet_skid_detail.prod_item_num =
           production_sheet_item.prod_item_num)
       AND (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       AND (coil.customer_id = ll_customer_id)
       AND -- Add Oswego id=1459 by Tony 04-29-03
           (sheet_skid.ref_order_abc_num = customer_order.order_abc_num);
    -- if ll_item_count = 0 then return 100; end if;   -- nothing to send
    IF ll_item_count <> 0 THEN
    
      SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
      SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
    
      SELECT customer.customer_duns_number_string
        INTO su_duns
        FROM customer
       WHERE customer.customer_id = ll_customer_id;
    
      x12_table(i) := 'ISA*00*' ||
                      '          *00*          *01*039630926T     *09*0015049350011G *' ||
                      ls_today_4 || '*' || ls_now || '*U*00401*' ||
                      lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
      i := i + 1;
      x12_table(i) := 'GS*RS*039630926T*' || '001504935001' || '*' ||
                      ls_today || '*' || ls_now || '*' ||
                      to_char(ll_gs_log) || '*X*' || '004010';
      i := i + 1;
      x12_table(i) := 'ST*870*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                      '***' || ls_now || '*****';
      i := i + 1;
      x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
      i := i + 1;
      x12_table(i) := 'N1*SU**1*' || su_duns || '*NA';
      i := i + 1;
      x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926T';
      i := i + 1;
    
      --open alcan_870_cur;
      --fetch alcan_870_cur INTO item_rec;
      --close alcan_870_cur;
    
      li_hl01 := 1;
    
      FOR item_rec IN alcan_870_cur LOOP
        x12_table(i) := 'HL*' || to_char(li_hl01) || '**I';
        i := i + 1;
      
        -- No need for this part due to the change in alcan_870_cur   ---------By Tony 04-29-03
      
        -- Referece PO and Sales order via Ref_order due to coil reassigning    Bing on Sep 5, 2002
        /*
          SELECT   
               NVL(customer_order.sales_order, 'NA') INTO item_rec.sales_order
          FROM   SHEET_SKID, customer_order
          WHERE       (customer_order.order_abc_num = sheet_skid.ref_order_abc_num)  and
                      (sheet_skid.sheet_skid_num = item_rec.sheet_skid_num);
                      
          SELECT   
               NVL(customer_order.orig_customer_po, 'NA') INTO item_rec.customer_po
          FROM        SHEET_SKID, customer_order
          WHERE       (customer_order.order_abc_num = sheet_skid.ref_order_abc_num)  and
                      (sheet_skid.sheet_skid_num = item_rec.sheet_skid_num);            
        */
      
        -- End of change tony 04-29-03
      
        -- Trunc PO by Bing on Jan 11, 2001
        ls_po := item_rec.customer_po;
        IF instr(item_rec.customer_po, '-') > 0 THEN
          ls_po := substr(item_rec.customer_po,
                          0,
                          instr(item_rec.customer_po, '-') - 1);
        END IF;
      
        x12_table(i) := 'PRF*' || ls_po || '****NA';
        i := i + 1;
        x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
        i := i + 1;
        -- Nov 21 03, change per Alcan  ---tony
        --x12_table(i) := 'REF*SE*' ||item_rec.coil_org_num ||'-'||to_char(item_rec.sheet_skid_num); i := i+1;
      
        x12_table(i) := 'REF*SE*' || to_char(item_rec.prod_item_num);
        i := i + 1;
      
        x12_table(i) := 'REF*MI*' || to_char(item_rec.ab_job_num);
        i := i + 1;
      
        -- Nov 21 03, change per Alcan  ---tony
        --x12_table(i) := 'REF*RV*' ||item_rec.coil_org_num || to_char(item_rec.sheet_skid_num) ||'*NA'; i := i+1;
        x12_table(i) := 'REF*RV*' || to_char(item_rec.prod_item_num) ||
                        '*NA';
        i := i + 1;
      
        --06/05/03 Don't send PO106 AND PO107 incase non sales order available as per Julia
        IF item_rec.sales_order = ' ' THEN
          x12_table(i) := 'PO1**1*UN****' || '***SN*' ||
                          item_rec.coil_org_num;
          i := i + 1;
        ELSE
          x12_table(i) := 'PO1**1*UN***VO*' || item_rec.sales_order ||
                          '***SN*' || item_rec.coil_org_num;
          i := i + 1;
        END IF;
      
        -- Added partial ready(13), On-hold(4) by Bing Feb-26-2002
        IF item_rec.skid_sheet_status = 2 THEN
          x12_table(i) := 'PID*S*MA*ST*1*' ||
                          to_char(item_rec.sheet_skid_num) || '*NA';
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 13 THEN
          x12_table(i) := 'PID*S*MA*ST*8*' ||
                          to_char(item_rec.sheet_skid_num) || '*NA';
          i := i + 1;
        ELSE
          x12_table(i) := 'PID*S*MA*ST*3*' ||
                          to_char(item_rec.sheet_skid_num) || '*NA';
          i := i + 1;
        END IF;
      
        x12_table(i) := 'PID*S*MAC*ST*01';
        i := i + 1;
        x12_table(i) := 'PID*S*PR*ST*19';
        i := i + 1;
        x12_table(i) := 'MEA*WT*N*' || to_char(item_rec.prod_item_net_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*WT*G*' || to_char(item_rec.skid_gross_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*CT*NA*' || to_char(item_rec.prod_item_pieces) ||
                        '*PC';
        i := i + 1;
      
        li_hl01 := li_hl01 + 1;
      
        item_num(k) := item_rec.prod_item_num;
        k := k + 1;
      
      END LOOP;
      x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
      i := i + 1;
      x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
      i := i + 1;
      x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');
    
      -- Write EDI to file
    
      IF li_hl01 > 1 THEN
        -- WRITE EDI FILE ONLY IF ITEM > 0
        SELECT edi_file_id_seq.nextval INTO ll_edi_file_id_alcan FROM dual;
        edi_file        := 'S_alcan_' || to_char(ll_edi_file_id_alcan) ||
                           '.870';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
      
        FOR j IN 0 .. i LOOP
          utl_file.put_line(edi_file_handle, x12_table(j));
          -- v_edi_text_alcan:=v_edi_text_alcan||x12_table(j)||CHR(10);
        END LOOP;
        utl_file.fclose(edi_file_handle);
      END IF; -- END WRITING EDI FILE
    
      /* --added by Victor Huang on 06/05 for funtion aknowlegement
      INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
      VALUES(ll_gs_log, su_duns, sysdate, edi_file);
      COMMIT;*/
    
      --added by Victor Huang on 12/07 for verifying 997
      INSERT INTO outbound_edi_transaction
        (edi_file_id,
         duns_from,
         duns_to,
         interchange_control_number,
         group_control_number,
         transaction_time,
         edi_file_name,
         fa_receive_status,
         customer_id,
         set_control_num,
         transaction_type_id)
      VALUES
        (ll_edi_file_id_alcan,
         '039630926',
         su_duns,
         ll_gs_log,
         ll_gs_log,
         SYSDATE,
         edi_file,
         0,
         ll_customer_id,
         ll_st_log,
         '870');
      COMMIT;
    
      edi_file        := 'send_edi_log';
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);
    
      /*
      UPDATE production_sheet_item
         SET prod_item_edi870_date= SYSDATE
             
         WHERE  production_sheet_item.prod_item_num in 
               ( select production_sheet_item.prod_item_num from SHEET_SKID, production_sheet_item, sheet_skid_detail,coil, customer_order
                  where 
                 (production_sheet_item.prod_item_edi870_date is NULL ) and 
                 (sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num) and
                 (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num) and
                 (sheet_skid.skid_sheet_status in (2, 4, 13)) and
                 (coil.coil_abc_num = production_sheet_item.coil_abc_num ) and
                 (coil.customer_id = ll_customer_id) and
                 (sheet_skid.ref_order_abc_num = customer_order.order_abc_num)
               );
       
      */
      FOR m IN 0 .. k - 1 LOOP
        UPDATE production_sheet_item
           SET prod_item_edi870_date = SYSDATE
         WHERE production_sheet_item.prod_item_num = item_num(m);
      END LOOP;
    
      COMMIT;
    
    END IF; --end if in select count(*)
  
  END LOOP; ------ End of outer loop customer_id

EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN;
END;
  GRANT EXECUTE ON "DBO"."EDI_ALCAN_870_ORIG" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Procedure EDI_ALCAN_870_PER_JOB
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."EDI_ALCAN_870_PER_JOB" 
     (
        al_ab_job_num  ab_job.ab_job_num%type
     )
is

  /*
  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   Customer: Aleris(1980) DUNS:964790856     EDI ID:964790856      QUALIFIER: ZZ

   End User: Aleris, Customer ID 1980
   */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50) := get_edi_destination('EDI_DIR');

  edi_file        VARCHAR2(50) := 'edi_out.txt';
  --edi_file_prefix VARCHAR2(50) := 'S_870_'; --Production
  edi_file_prefix VARCHAR2(50) := 's_870_'; --Development
  edi_file_handle utl_file.file_type;
  su_duns         VARCHAR2(10);
  ll_customer_id  customer.customer_id%TYPE;
  ll_cur_coil     coil.coil_abc_num%TYPE;

--  ll_cur_job ab_job.ab_job_num%TYPE;

  ll_gs_log INTEGER;
  ll_st_log INTEGER;

  ls_today   VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD');
  ls_today_4 VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  ls_now     VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  ls_po VARCHAR2(20);
  ls_finished_goods VARCHAR2(32);
  ls_cust_prod_line VARCHAR2(8);

  ld_scrap_870_date process_coil.scrap_870_date%TYPE;

  ls_coil_org_num coil.coil_org_num%TYPE;
  ls_heat coil.lot_num%TYPE;

--  ll_ref_order_abc_num sheet_skid.ref_order_abc_num%TYPE;
--  ll_ref_order_abc_item sheet_skid.ref_order_abc_item%TYPE;
--  ls_sheet_type order_item.sheet_type%TYPE;

  ll_prime_nw coil.net_wt%TYPE;
  ll_scrap_nw coil.net_wt%TYPE;
--  ll_process_quantity  coil.net_wt%TYPE;
--  ll_process_end_wt  coil.net_wt%TYPE;
--  lr_theo_unit_wt order_item.theoretical_unit_wt%TYPE;

  --ll_edi_file_id integer;
  ll_edi_file_id_870 INTEGER;

  ll_item_count INTEGER;

  li_hl01 INTEGER;
  li_hllin INTEGER;
  
  ll_rowcount number(8);

--  CURSOR cust_cur IS
--    SELECT customer_id FROM customer WHERE customer_id IN (1153,1459,2582); ---Add customer id here if you want to send 870 for more customers
/*
  CURSOR coil_cur IS
  SELECT UNIQUE C.COIL_ABC_NUM
  FROM SHEET_SKID_DETAIL SKD
    JOIN SHEET_SKID SK ON SKD.SHEET_SKID_NUM = SK.SHEET_SKID_NUM
    JOIN PRODUCTION_SHEET_ITEM PSI ON SKD.PROD_ITEM_NUM = PSI.PROD_ITEM_NUM
    JOIN COIL C ON PSI.COIL_ABC_NUM = C.COIL_ABC_NUM
    JOIN AB_JOB AB ON SK.AB_JOB_NUM = AB.AB_JOB_NUM
    JOIN CUSTOMER_ORDER CO ON CO.ORDER_ABC_NUM = AB.ORDER_ABC_NUM
  WHERE (AB.JOB_STATUS = 0) AND
    ( C.COIL_STATUS IN (0, 3) ) AND
    ( CO.ORIG_CUSTOMER_ID = ll_customer_id ) AND
    ( PSI.PROD_ITEM_EDI870_DATE is NULL ) AND
    ( C.SCRAP_870_DATE is NULL ) AND
    ( SK.SKID_SHEET_STATUS in (0,2,4,12,13, 16) );

  coil_rec  coil_cur%ROWTYPE;
*/  

/*  
  CURSOR alcan_870_cur IS
   SELECT production_sheet_item.ab_job_num,
           production_sheet_item.coil_abc_num,
           production_sheet_item.prod_item_pieces,
           production_sheet_item.prod_item_num,
           sheet_skid.sheet_skid_num,
           production_sheet_item.prod_item_net_wt,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_skid_display_num,
           sheet_skid.sheet_net_wt,
           sheet_skid.skid_pieces,
           coil.coil_org_num,
           coil.lot_num,
           nvl(coil.consumed_coil_num, ' ') consumed_coil,
           nvl(coil.material_num, ' ') material_num,
           
           nvl(customer_order.sales_order, ' ') sales_order,
           nvl(customer_order.orig_customer_po, 'NA') customer_po,
           nvl(order_item.enduser_part_num, ' ') enduser_parts,
           nvl(order_item.cust_prod_line_id, 'NA') customer_line_id,
           nvl(order_item.finished_goods_material_num, 'NA') finished_goods,
           nvl(customer_order.orig_customer_po, 'NA') orig_customer_po,
           (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
           NULL done
      FROM sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil,
           order_item,
           ab_job,
           customer_order
     WHERE (sheet_skid.skid_sheet_status IN (0, 2, 4, 13, 12, 16)) -- 2: Ready; 8: Warehouse Ready; 13: Partial Ready; 7: Partial; 12: Sample; 4: onhold
       AND (production_sheet_item.prod_item_edi870_date IS NULL)
       AND (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       AND (sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num)
       AND (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       AND (coil.customer_id = ll_customer_id)
       AND (sheet_skid.ref_order_abc_num = customer_order.order_abc_num)
       AND (production_sheet_item.ab_job_num = ab_job.ab_job_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (production_sheet_item.coil_abc_num = ll_cur_coil);
       
     item_rec  alcan_870_cur%ROWTYPE;

     CURSOR alcan_scrap_870_cur IS
     SELECT a.coil_abc_num,
              b.coil_org_num,
              a.ab_job_num,
              nvl(b.material_num, ' ') material_num,
               NVL(a.process_quantity, 0) process_quan,
               NVL(a.process_end_wt, 0) process_end_wt
       FROM process_coil a, coil b
       WHERE (b.coil_abc_num = ll_cur_coil)
         AND (a.coil_abc_num = b.coil_abc_num)
         AND (a.scrap_870_date is NULL);
*/  
   
--------------------------------------------------------------------------------------------------   
------------------------------------ Cursors Begin -----------------------------------------------
--------------------------------------------------------------------------------------------------

  cursor coil_cur is
  select distinct process_coil.coil_abc_num
  from   process_coil
         left outer join production_sheet_item on production_sheet_item.coil_abc_num = process_coil.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    (
              sheet_skid.skid_sheet_status in (0, 2, 4, 13, 12, 16)
           or sheet_skid.skid_sheet_status is null --This is for rejected coils without sheets  
         );
  
  coil_rec  coil_cur%ROWTYPE;
   
  --Cursor skid_coil_cur will select data for ab_job and coil_abc_num with skids.
  --If there is a reject coil without sheet skids, this cursor will not select it.
  cursor skid_coil_cur is
  select coil.coil_abc_num,   
         coil.lot_num,   
         coil.coil_org_num,   
         coil.coil_mid_num,
         nvl(coil.consumed_coil_num, ' ') consumed_coil,
         nvl(coil.material_num, ' ') material_num,
         coil.net_wt,   
         sheet_skid.sheet_tare_wt,   
         sheet_skid.sheet_net_wt,
         sheet_skid.skid_pieces,
         production_sheet_item.prod_item_pieces,
         production_sheet_item.prod_item_num,
         sheet_skid.skid_sheet_status,
         sheet_skid.sheet_skid_num,   
         production_sheet_item.prod_item_note,   
         sheet_skid.sheet_theoretical_wt,   
         production_sheet_item.prod_item_placement,   
         process_coil.process_quantity,   
         production_sheet_item.prod_item_net_wt,   
         sheet_skid.sheet_skid_display_num,
         nvl(customer_order.sales_order, ' ') sales_order,
         nvl(customer_order.orig_customer_po, 'NA') orig_customer_po,
         nvl(order_item.enduser_part_num, ' ') enduser_part_num,
         nvl(order_item.cust_prod_line_id, 'NA') cust_prod_line_id,
         nvl(order_item.finished_goods_material_num, 'NA') finished_goods_material_num,
         (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
         NULL done  
  from   coil   
         join process_coil on coil.coil_abc_num = process_coil.coil_abc_num
         join ab_job on ab_job.ab_job_num = process_coil.ab_job_num
         join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
         join customer_order on customer_order.order_abc_num = order_item.order_abc_num
         left outer join production_sheet_item on coil.coil_abc_num = production_sheet_item.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  ab_job.ab_job_num = al_ab_job_num
  and    coil.coil_abc_num = ll_cur_coil
  order by
         production_sheet_item.coil_abc_num,
         sheet_skid.sheet_skid_display_num;

  skid_coil_rec  skid_coil_cur%rowtype;
  
  cursor scrap_cur is
  select process_coil.coil_abc_num,
         process_coil.process_coil_status,
         process_coil.process_quantity,
         nvl(process_coil.process_end_wt, 0),
         sum(nvl(process_coil.process_end_wt, 0)),
         sum(nvl(production_sheet_item.prod_item_net_wt, 0)),
         case process_coil.process_coil_status
            when 7 then --Rebanded coils
               --(process_coil.process_quantity - sum(production_sheet_item.prod_item_net_wt) - (select process_end_wt from process_coil pc where pc.ab_job_num = 101143 and pc.coil_abc_num = process_coil.coil_abc_num))
               (process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - nvl(process_coil.process_end_wt, 0))
            when 3 then --Rejected coils
               case (select count(*) from production_sheet_item psi where psi.ab_job_num = al_ab_job_num and psi.coil_abc_num = process_coil.coil_abc_num)
                 when 0 then --Rejected coils without sheets
                   (process_coil.process_quantity - sum(nvl(process_coil.process_end_wt, 0)))
                 else --Rejected coils with sheets
                   (process_coil.process_quantity - nvl(process_coil.process_end_wt, 0) - sum(nvl(production_sheet_item.prod_item_net_wt, 0)))     
                end   
             else
               (process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - sum(nvl(process_coil.process_end_wt, 0)))
         end scrap_net_wt
  from   process_coil
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         join ab_job on ab_job.ab_job_num = process_coil.ab_job_num and coil.coil_abc_num = process_coil.coil_abc_num
         left outer join production_sheet_item on production_sheet_item.ab_job_num = process_coil.ab_job_num and production_sheet_item.coil_abc_num = process_coil.coil_abc_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    coil.coil_abc_num = ll_cur_coil
  group by
         process_coil.coil_abc_num,
         process_coil.process_coil_status,
         process_coil.process_quantity,
         process_coil.process_end_wt
  order by
         process_coil.coil_abc_num;
         
  scrap_rec  scrap_cur%rowtype;
   
--------------------------------------------------------------------------------------------------   
------------------------------------- Cursors End ------------------------------------------------
--------------------------------------------------------------------------------------------------   

  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;

  TYPE coil_num_type IS TABLE OF coil.coil_abc_num%type INDEX BY BINARY_INTEGER;
  coil_num coil_num_type;
  p binary_integer :=0;
  
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;  

BEGIN

  --FOR cust_rec IN cust_cur LOOP
    --- Outer loop of customer_id
    --ll_customer_id := cust_rec.customer_id;
  i              := 0;
  k              := 0;
  p              := 0;
    
  --open coil_cur;
  --fetch coil_cur into coil_rec;
  --ll_rowcount := coil_cur%rowcount;
  
  select count(distinct process_coil.coil_abc_num)
  into   ll_rowcount
  from   process_coil
         left outer join production_sheet_item on production_sheet_item.coil_abc_num = process_coil.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    (
              sheet_skid.skid_sheet_status in (0, 2, 4, 13, 12, 16)
           or sheet_skid.skid_sheet_status is null --This is for rejected coils without sheets  
         );
    
  if ll_rowcount > 0 then

/*
  SELECT count(COIL.COIL_ABC_NUM)
  INTO ll_item_count
    FROM AB_JOB,
         COIL,
         PRODUCTION_SHEET_ITEM,
         SHEET_SKID,
         SHEET_SKID_DETAIL,
         CUSTOMER_ORDER
   WHERE ( SHEET_SKID_DETAIL.SHEET_SKID_NUM = SHEET_SKID.SHEET_SKID_NUM ) and
         ( SHEET_SKID_DETAIL.PROD_ITEM_NUM = PRODUCTION_SHEET_ITEM.PROD_ITEM_NUM ) and
         ( COIL.COIL_ABC_NUM = PRODUCTION_SHEET_ITEM.COIL_ABC_NUM ) and
         ( AB_JOB.AB_JOB_NUM = SHEET_SKID.AB_JOB_NUM ) and
         ( AB_JOB.ORDER_ABC_NUM = CUSTOMER_ORDER.ORDER_ABC_NUM ) and
         ( AB_JOB.JOB_STATUS = 0 ) AND
         (  COIL.COIL_STATUS in (0, 3) ) AND
         ( CUSTOMER_ORDER.ORIG_CUSTOMER_ID = ll_customer_id ) AND
         ( PRODUCTION_SHEET_ITEM.PROD_ITEM_EDI870_DATE is NULL ) AND
         ( COIL.SCRAP_870_DATE is NULL ) AND
         ( SHEET_SKID.SKID_SHEET_STATUS in (0, 2,4,12,13, 16) ); --Alex Gerlants. 03/22/2019. Added new status 16-Hold For Cert

  IF (ll_item_count <> 0) THEN
*/
  select edi_st_log_seq.nextval into ll_st_log from dual;
  select edi_gs_log_seq.nextval into ll_gs_log from dual;
     
  select  customer_order.orig_customer_id
  into    ll_customer_id
  from    ab_job
          join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
  where   ab_job.ab_job_num = al_ab_job_num;
  
  select  customer.customer_duns_number_string
  into    su_duns
  from    customer
  where   customer.customer_id = ll_customer_id;

  --Production
  --x12_table(i) := 'ISA*00*' ||
  --                '          *00*          *01*039630926T     *09*0015049350011G *' ||
  --                ls_today_4 || '*' || ls_now || '*U*00401*' ||
  --                lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
        
  --Development                
  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *ZZ*2NDSFTP        *ZZ*NOVLSTEST      *' ||
                  ls_today_4 || '*' || ls_now || '*U*00401*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';    
                       
  i := i + 1;
        
  --Production
  --x12_table(i) := 'GS*RS*039630926T*' || '001504935001' || '*' ||
  --                ls_today || '*' || ls_now || '*' ||
  --                to_char(ll_gs_log) || '*X*' || '004010';
        
  --Development                
  x12_table(i) := 'GS*RS*2NDSFTP*' || 'NOVLSTEST' || '*' ||
                  ls_today || '*' || ls_now || '*' ||
                  to_char(ll_gs_log) || '*X*' || '004010';
                        
  i := i + 1;
      
  x12_table(i) := 'ST*870*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                  '***' || ls_now || '*****';
  i := i + 1;
  x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
  i := i + 1;
  x12_table(i) := 'N1*SU**1*' || su_duns;
  i := i + 1;
  x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926';
  i := i + 1;

  li_hl01 := 0;

  for coil_rec in coil_cur loop --Coil loop
     ll_cur_coil := coil_rec.coil_abc_num;

     coil_num(p) := ll_cur_coil;
     p := p + 1;

     select   coil.coil_org_num, coil.lot_num
     into     ls_coil_org_num, ls_heat
     from     coil
     where    coil.coil_abc_num = ll_cur_coil;
      

     for skid_coil_rec IN skid_coil_cur loop --Skid_coil loop

        li_hl01 := li_hl01 + 1;

        x12_table(i) := 'HL*' || to_char(li_hl01) || '**I';
        i := i + 1;

/* 
              SELECT nvl(customer_order.orig_customer_po, 'NA'),
                     nvl(order_item.cust_prod_line_id, 'NA'),
                     nvl(order_item.finished_goods_material_num, 'NA')
              INTO ls_po, ls_cust_prod_line, ls_finished_goods
              FROM   order_item,
                     ab_job,
                     customer_order
             WHERE (ab_job.order_abc_num = customer_order.order_abc_num)
             AND (ab_job.order_abc_num = order_item.order_abc_num)
             AND (ab_job.order_item_num = order_item.order_item_num)
              AND (ab_job.ab_job_num = item_rec.ab_job_num);
*/              
        ls_po := skid_coil_rec.orig_customer_po;
        ls_cust_prod_line := skid_coil_rec.cust_prod_line_id;
        ls_finished_goods := skid_coil_rec.finished_goods_material_num;

        IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
           x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
           i := i + 1;
        END IF;

        x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
        i := i + 1;

        x12_table(i) := 'REF*SE*' || to_char(skid_coil_rec.prod_item_num);
        i := i + 1;


        x12_table(i) := 'REF*MI*' || to_char(al_ab_job_num);
        i := i + 1;

        x12_table(i) := 'REF*RV*' || to_char(skid_coil_rec.prod_item_num) ||
                        '*NA';
        i := i + 1;

        x12_table(i) := 'REF*IX*' || to_char(skid_coil_rec.consumed_coil);
        i := i + 1;

        x12_table(i) := 'PO1**1*UN****' || '***SN*' ||
                          ls_coil_org_num || '***VP*' || skid_coil_rec.finished_goods_material_num;
        i := i + 1;

        if skid_coil_rec.skid_sheet_status = 2 then
          x12_table(i) := 'PID*S*MA*ST*1*' ||
                          to_char(skid_coil_rec.sheet_skid_display_num);
          i := i + 1;
        elsif skid_coil_rec.skid_sheet_status = 4 then
          x12_table(i) := 'PID*S*MA*ST*3*' ||
                          to_char(skid_coil_rec.sheet_skid_display_num);
          i := i + 1;
        elsif skid_coil_rec.skid_sheet_status = 13 then
          x12_table(i) := 'PID*S*MA*ST*8*' ||
                          to_char(skid_coil_rec.sheet_skid_display_num);
          i := i + 1;
        else
          x12_table(i) := 'PID*S*MA*ST*4*' ||
                          to_char(skid_coil_rec.sheet_skid_display_num);
          i := i + 1;
        end if;

        x12_table(i) := 'PID*S*MAC*ST*01';
        i := i + 1;
        x12_table(i) := 'PID*S*PR*ST*19';
        i := i + 1;
        x12_table(i) := 'MEA*WT*N*' || to_char(skid_coil_rec.prod_item_net_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*WT*G*' || to_char(skid_coil_rec.skid_gross_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*CT*NA*' || to_char(skid_coil_rec.prod_item_pieces) ||
                        '*PC';
        i := i + 1;

        item_num(k) := skid_coil_rec.prod_item_num;
        k := k + 1;

      end loop; --for skid_coil_rec IN skid_coil_cur loop

      /*
      select   process_coil.scrap_870_date, coil.coil_org_num, coil.lot_num
      into     ld_scrap_870_date, ls_coil_org_num, ls_heat
      from     coil
               join process_coil on coil.coil_abc_num = process_coil.coil_abc_num
      where    coil.coil_abc_num = ll_cur_coil;
      */

      --if (ld_scrap_870_date is null) then --Scrap not sent

         for scrap_rec in scrap_cur loop --Scrap loop

            --Scrap info
            /*
            SELECT   NVL(sum(production_sheet_item.prod_item_net_wt),0)
            into     ll_prime_nw
            FROM     production_sheet_item
            WHERE (  production_sheet_item.ab_job_num = scrap_rec.ab_job_num) and
                     (production_sheet_item.coil_abc_num = ll_cur_coil);
            */

            --ll_scrap_nw := scrap_rec.process_quan - scrap_rec.process_end_wt - ll_prime_nw;
            ll_scrap_nw := scrap_rec.scrap_net_wt;

            if ll_scrap_nw > 0 then

               li_hl01 := li_hl01 + 1;

               x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*I';
               i := i + 1;

               IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
                  x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
                  i := i + 1;
               END IF;

               x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
               i := i + 1;

               x12_table(i) := 'PO1**1*UN****' || '***SN*' || ls_coil_org_num ;
               i := i + 1;

               x12_table(i) := 'PID*S*MA*ST*S';
               i := i + 1;

               x12_table(i) := 'PID*S*MAC*ST*05';
               i := i + 1;

               x12_table(i) := 'PID*S*PR*ST*19';
               i := i + 1;

               x12_table(i) := 'MEA*WT*N*' || to_char(ll_scrap_nw) || '*LB*01';
               i := i+1;
             end if; --if ll_scrap_nw > 0 then
          end loop; --for scrap_rec in alcan_scrap_870_cur loop scrap loop
      --end if; --if (ld_scrap_870_date is null) then --Scrap not sent
  end loop; --for coil_rec in coil_cur loop. Coil loop
  
  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
  i := i + 1;

  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;

  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;

  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  -- Write EDI to file

  if li_hl01 > 1 then
      -- WRITE EDI FILE ONLY IF ITEM > 0
      SELECT edi_file_id_seq.nextval
        INTO ll_edi_file_id_870
        FROM dual;
      edi_file        := edi_file_prefix || to_char(ll_edi_file_id_870) || '.edi';
   -- edi_file        := 's_alcan_' || to_char(ll_edi_file_id_870) || '.870';
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

      FOR j IN 0 .. i LOOP
        utl_file.put_line(edi_file_handle, x12_table(j));

      END LOOP;
      utl_file.fclose(edi_file_handle);
    END IF; -- END WRITING EDI FILE

    --edi_file        := 'send_edi_log'; /* Alex Gerlants. 04/14/2017. Commented out. */
    edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
    utl_file.put_line(edi_file_handle, 'Type: 870');
    utl_file.put_line(edi_file_handle,
                      'Sending Time: ' ||
                      to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
    utl_file.put_line(edi_file_handle,
                      'Interchange Control #: ' || ll_gs_log);
    utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
    utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
    utl_file.put_line(edi_file_handle, '');
    utl_file.put_line(edi_file_handle, '');
    utl_file.fclose(edi_file_handle);

    --For verifying 997
/*    
    INSERT INTO outbound_edi_transaction
        (edi_file_id,
         duns_from,
         duns_to,
         interchange_control_number,
         group_control_number,
         transaction_time,
         edi_file_name,
         fa_receive_status,
         customer_id,
         set_control_num,
         transaction_type_id)
      VALUES
        (ll_edi_file_id_870,
         '039630926',
         su_duns,
         ll_gs_log,
         ll_gs_log,
         SYSDATE,
         edi_file,
         0,
         ll_customer_id,
         ll_st_log,
         '870');
*/

--      update    ab_job
--      set       edi_file_id_870 = ll_edi_file_id_870,  /* Alex Gerlants. 02/14/2020. New column */
--                edi_date_870 = sysdate /* Alex Gerlants. 02/14/2020. New column */
--      where     ab_job_num = al_ab_job_num;

/*
      for m in 0 .. k - 1 loop
         update   production_sheet_item
         set      prod_item_edi870_date = sysdate,
                  edi_file_id_870 = ll_edi_file_id_870 
         where    production_sheet_item.prod_item_num = item_num(m);
      end loop;

      for m in 0..p - 1 loop
         update   coil
         set      coil.scrap_870_date = sysdate
         where    coil.coil_abc_num = coil_num(m);

         update   process_coil
         set      scrap_870_date = sysdate
         where    ( coil_abc_num = coil_num(m)) and (scrap_870_date is null);

       end loop;

       commit;
*/
  end if; --end if in select count(*)

  --END LOOP; ------ End of outer loop customer_id

EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN;
END;
--------------------------------------------------------
--  DDL for Procedure EDI_ALCAN_870_REBAND
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."EDI_ALCAN_870_REBAND" IS

  /*
  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   */



  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR');

  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_handle utl_file.file_type;
  su_duns         VARCHAR2(10);
  ll_customer_id  customer.customer_id%TYPE;
  ll_cur_coil     coil.coil_abc_num%TYPE;

  ll_cur_job ab_job.ab_job_num%TYPE;

  ll_gs_log INTEGER;
  ll_st_log INTEGER;

  ls_today   VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD');
  ls_today_4 VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  ls_now     VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  ls_po VARCHAR2(20);
  ls_finished_goods VARCHAR2(32);
  ls_cust_prod_line VARCHAR2(8);

  ld_scrap_870_date ab_job.scrap_870_date%TYPE;
  ld_job_scrap_870_date ab_job.scrap_870_date%TYPE;

  ls_coil_org_num coil.coil_org_num%TYPE;
  ls_heat coil.lot_num%TYPE;
   ls_scrap_coil_org_num coil.coil_org_num%TYPE;

  ll_ref_order_abc_num sheet_skid.ref_order_abc_num%TYPE;
  ll_ref_order_abc_item sheet_skid.ref_order_abc_item%TYPE;
  ls_sheet_type order_item.sheet_type%TYPE;

  ll_prime_nw coil.net_wt%TYPE;
  ll_scrap_start_nw coil.net_wt%TYPE;
  ll_scrap_end_nw coil.net_wt%TYPE;
  ll_scrap_nw coil.net_wt%TYPE;
  ll_process_quantity  coil.net_wt%TYPE;
  ll_process_end_wt  coil.net_wt%TYPE;
  lr_theo_unit_wt order_item.theoretical_unit_wt%TYPE;

  --ll_edi_file_id integer;
  ll_edi_file_id_aleris INTEGER;

  ll_item_count INTEGER;

  li_hl01 INTEGER;
  li_hllin INTEGER;

  CURSOR cust_cur IS
    SELECT customer_id FROM customer WHERE customer_id IN (1153,1459,2582); ---Add customer id here if you want to send 870 for more customers

  CURSOR coil_cur IS
  SELECT UNIQUE COIL.COIL_ABC_NUM, AB_JOB.AB_JOB_NUM
    FROM AB_JOB,
         COIL,
         PRODUCTION_SHEET_ITEM,
         SHEET_SKID,
         SHEET_SKID_DETAIL,
         CUSTOMER_ORDER,
         PROCESS_COIL
   WHERE ( SHEET_SKID_DETAIL.SHEET_SKID_NUM = SHEET_SKID.SHEET_SKID_NUM ) and
         ( SHEET_SKID_DETAIL.PROD_ITEM_NUM = PRODUCTION_SHEET_ITEM.PROD_ITEM_NUM ) and
         ( COIL.COIL_ABC_NUM = PRODUCTION_SHEET_ITEM.COIL_ABC_NUM ) and
         ( AB_JOB.AB_JOB_NUM = SHEET_SKID.AB_JOB_NUM ) and
         ( COIL.COIL_ABC_NUM = PROCESS_COIL.COIL_ABC_NUM ) and
         ( AB_JOB.AB_JOB_NUM = PROCESS_COIL.AB_JOB_NUM ) and
         ( AB_JOB.ORDER_ABC_NUM = CUSTOMER_ORDER.ORDER_ABC_NUM ) and
         ( AB_JOB.JOB_STATUS = 0 ) AND
         (  COIL.COIL_STATUS = 7 ) AND
         ( CUSTOMER_ORDER.ORIG_CUSTOMER_ID = ll_customer_id ) AND
         ( PRODUCTION_SHEET_ITEM.PROD_ITEM_EDI870_DATE is NULL ) AND
         ( PROCESS_COIL.SCRAP_870_DATE is NULL ) AND
         ( COIL.SCRAP_870_DATE is NULL ) AND
         ( SHEET_SKID.SKID_SHEET_STATUS in (2,4,12,13) );

  CURSOR alcan_870_cur IS
   SELECT production_sheet_item.ab_job_num,
           production_sheet_item.coil_abc_num,
           production_sheet_item.prod_item_pieces,
           production_sheet_item.prod_item_num,
           sheet_skid.sheet_skid_num,
           production_sheet_item.prod_item_net_wt,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_skid_display_num,
           sheet_skid.sheet_net_wt,
           sheet_skid.skid_pieces,
           coil.coil_org_num,
           coil.lot_num,
           nvl(coil.consumed_coil_num, ' ') consumed_coil,
           nvl(coil.material_num, ' ') material_num,
           nvl(customer_order.sales_order, ' ') sales_order,
           nvl(customer_order.orig_customer_po, 'NA') customer_po,
           nvl(order_item.enduser_part_num, ' ') enduser_parts,
           nvl(order_item.cust_prod_line_id, 'NA') customer_line_id,
           nvl(order_item.finished_goods_material_num, 'NA') finished_goods,
           (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
           NULL done
      FROM sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil,
           order_item,
           ab_job,
           customer_order
     WHERE (sheet_skid.skid_sheet_status IN (2, 4, 13, 12)) -- 2: Ready; 8: Warehouse Ready; 13: Partial Ready; 7: Partial; 12: Sample; 4: onhold
       AND (production_sheet_item.prod_item_edi870_date IS NULL)
       AND (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       AND (sheet_skid_detail.prod_item_num =
           production_sheet_item.prod_item_num)
       AND (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       AND (coil.customer_id = ll_customer_id)
       AND (sheet_skid.ref_order_abc_num = customer_order.order_abc_num)
 		   AND (production_sheet_item.ab_job_num = ab_job.ab_job_num)
		   AND (ab_job.order_abc_num = order_item.order_abc_num)
		   AND (ab_job.order_item_num = order_item.order_item_num)
      AND (production_sheet_item.coil_abc_num = ll_cur_coil)
      AND (production_sheet_item.ab_job_num = ll_cur_job);


  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;

  item_rec  alcan_870_cur%ROWTYPE;
  coil_rec  coil_cur%ROWTYPE;

  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;


BEGIN

  FOR cust_rec IN cust_cur LOOP
    --- Outer loop of customer_id
    ll_customer_id := cust_rec.customer_id;
    i              := 0;
    k              := 0;

  SELECT count(COIL.COIL_ABC_NUM)
  INTO ll_item_count
    FROM AB_JOB,
         COIL,
         PRODUCTION_SHEET_ITEM,
         SHEET_SKID,
         SHEET_SKID_DETAIL,
         CUSTOMER_ORDER,
         PROCESS_COIL
   WHERE ( SHEET_SKID_DETAIL.SHEET_SKID_NUM = SHEET_SKID.SHEET_SKID_NUM ) and
         ( SHEET_SKID_DETAIL.PROD_ITEM_NUM = PRODUCTION_SHEET_ITEM.PROD_ITEM_NUM ) and
         ( COIL.COIL_ABC_NUM = PRODUCTION_SHEET_ITEM.COIL_ABC_NUM ) and
         ( COIL.COIL_ABC_NUM = PROCESS_COIL.COIL_ABC_NUM ) and
         ( AB_JOB.AB_JOB_NUM = PROCESS_COIL.AB_JOB_NUM ) and
         ( AB_JOB.AB_JOB_NUM = SHEET_SKID.AB_JOB_NUM ) and
         ( AB_JOB.ORDER_ABC_NUM = CUSTOMER_ORDER.ORDER_ABC_NUM ) and
         ( AB_JOB.JOB_STATUS = 0 ) AND
         (  COIL.COIL_STATUS = 7 ) AND
         ( CUSTOMER_ORDER.ORIG_CUSTOMER_ID = ll_customer_id ) AND
         ( PRODUCTION_SHEET_ITEM.PROD_ITEM_EDI870_DATE is NULL ) AND
         ( PROCESS_COIL.SCRAP_870_DATE is NULL ) AND
         ( COIL.SCRAP_870_DATE is NULL ) AND
         ( SHEET_SKID.SKID_SHEET_STATUS in (2,4,12,13) );

    IF (ll_item_count <> 0) THEN


      SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
      SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;

      SELECT customer.customer_duns_number_string
        INTO su_duns
        FROM customer
       WHERE customer.customer_id = ll_customer_id;

      x12_table(i) := 'ISA*00*' ||
                      '          *00*          *01*039630926T     *09*0015049350011G *' ||
                      ls_today_4 || '*' || ls_now || '*U*00401*' ||
                      lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
      i := i + 1;
      x12_table(i) := 'GS*RS*039630926T*' || '001504935001' || '*' ||
                      ls_today || '*' || ls_now || '*' ||
                      to_char(ll_gs_log) || '*X*' || '004010';
      i := i + 1;
      x12_table(i) := 'ST*870*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                      '***' || ls_now || '*****';
      i := i + 1;
      x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
      i := i + 1;
      x12_table(i) := 'N1*SU**1*' || su_duns;
      i := i + 1;
      x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926';
      i := i + 1;

      li_hl01 := 0;

      FOR coil_rec IN coil_cur LOOP    -- coil loop
          ll_cur_coil := coil_rec.coil_abc_num;
          ll_cur_job := coil_rec.ab_job_num;



        FOR item_rec IN alcan_870_cur LOOP   -- item loop


        li_hl01 := li_hl01 + 1;

        x12_table(i) := 'HL*' || to_char(li_hl01) || '**I';
        i := i + 1;

              SELECT nvl(customer_order.orig_customer_po, 'NA'),
                     nvl(order_item.cust_prod_line_id, 'NA'),
                     nvl(order_item.finished_goods_material_num, 'NA')
              INTO ls_po, ls_cust_prod_line, ls_finished_goods
              FROM   order_item,
			               ab_job,
                     customer_order
             WHERE (ab_job.order_abc_num = customer_order.order_abc_num)
		         AND (ab_job.order_abc_num = order_item.order_abc_num)
		         AND (ab_job.order_item_num = order_item.order_item_num)
              AND (ab_job.ab_job_num = ll_cur_job);

        IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
           x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
           i := i + 1;
        END IF;

        x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
        i := i + 1;

        x12_table(i) := 'REF*SE*' || to_char(item_rec.prod_item_num);
        i := i + 1;


        x12_table(i) := 'REF*MI*' || to_char(item_rec.ab_job_num);
        i := i + 1;

        x12_table(i) := 'REF*RV*' || to_char(item_rec.prod_item_num) ||
                        '*NA';
        i := i + 1;

        x12_table(i) := 'REF*IX*' || to_char(item_rec.consumed_coil);
        i := i + 1;

        x12_table(i) := 'PO1**1*UN****' || '***SN*' ||
                          item_rec.coil_org_num || '***VP*' || item_rec.finished_goods;
        i := i + 1;

        IF item_rec.skid_sheet_status = 2 THEN
          x12_table(i) := 'PID*S*MA*ST*1*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 4 THEN
          x12_table(i) := 'PID*S*MA*ST*3*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 13 THEN
          x12_table(i) := 'PID*S*MA*ST*8*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
         ELSE
          x12_table(i) := 'PID*S*MA*ST*4*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        END IF;

        x12_table(i) := 'PID*S*MAC*ST*01';
        i := i + 1;
        x12_table(i) := 'PID*S*PR*ST*19';
        i := i + 1;
        x12_table(i) := 'MEA*WT*N*' || to_char(item_rec.prod_item_net_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*WT*G*' || to_char(item_rec.skid_gross_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*CT*NA*' || to_char(item_rec.prod_item_pieces) ||
                        '*PC';
        i := i + 1;

         item_num(k) := item_rec.prod_item_num;
        k := k + 1;

      END LOOP;  -- item loop


     SELECT scrap_870_date, coil_org_num, lot_num
     INTO ld_scrap_870_date, ls_coil_org_num, ls_heat
     FROM coil
     WHERE coil_abc_num = ll_cur_coil;

     SELECT scrap_870_date
     INTO ld_job_scrap_870_date
     FROM process_coil
     WHERE (coil_abc_num = ll_cur_coil) AND (ab_job_num = ll_cur_job);

     IF (ld_scrap_870_date is NULL) AND (ld_job_scrap_870_date is NULL) THEN  -- scrap not sent

             SELECT b.coil_org_num,
               NVL(a.process_quantity, 0) process_quan,
               NVL(a.process_end_wt, 0) process_end_wt
           INTO ls_scrap_coil_org_num, ll_scrap_start_nw, ll_scrap_end_nw
           FROM process_coil a, coil b
           WHERE (b.coil_abc_num = ll_cur_coil)
           AND (a.coil_abc_num = b.coil_abc_num)
            AND (a.ab_job_num = ll_cur_job);

        --scrap info

        SELECT NVL(sum(production_sheet_item.prod_item_net_wt),0)
        into ll_prime_nw
         FROM production_sheet_item
         WHERE (production_sheet_item.ab_job_num = ll_cur_job) and
               (production_sheet_item.coil_abc_num = ll_cur_coil);


                ll_scrap_nw := ll_scrap_start_nw - ll_scrap_end_nw - ll_prime_nw;



                IF ll_scrap_nw > 0 then

                   li_hl01 := li_hl01 + 1;

                   x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*I';
                   i := i + 1;

                   IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
                      x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
                      i := i + 1;
                   END IF;

                   x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
                    i := i + 1;

                    x12_table(i) := 'PO1**1*UN****' || '***SN*' || ls_scrap_coil_org_num ;
                    i := i + 1;

                    x12_table(i) := 'PID*S*MA*ST*S';
                    i := i + 1;
                    x12_table(i) := 'PID*S*MAC*ST*05';
                     i := i + 1;
                    x12_table(i) := 'PID*S*PR*ST*19';
                     i := i + 1;

                   x12_table(i) := 'MEA*WT*N*' || to_char(ll_scrap_nw) || '*LB*01';
                   i := i+1;
                 END IF;

       END IF;  -- scrap not sent
     END LOOP;   -- coil loop

      x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
      i := i + 1;
      x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
      i := i + 1;
      x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

      -- Write EDI to file

      IF li_hl01 > 1 THEN
        -- WRITE EDI FILE ONLY IF ITEM > 0
        SELECT edi_file_id_seq.nextval
          INTO ll_edi_file_id_aleris
          FROM dual;
        edi_file        := 'S_alcan_' || to_char(ll_edi_file_id_aleris) ||
                           '.870';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        FOR j IN 0 .. i LOOP
          utl_file.put_line(edi_file_handle, x12_table(j));

        END LOOP;
        utl_file.fclose(edi_file_handle);
      END IF; -- END WRITING EDI FILE


      --For verifying 997
      /*INSERT INTO outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
        VALUES
          (ll_edi_file_id_aleris,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           SYSDATE,
           edi_file,
           0,
           ll_customer_id,
           ll_st_log,
           '870');
        COMMIT;
      */
      edi_file        := 'send_edi_log';
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      FOR coil_rec IN coil_cur LOOP    -- coil loop date
          UPDATE process_coil set scrap_870_date = sysdate
          WHERE (coil_abc_num = coil_rec.coil_abc_num) AND (ab_job_num = coil_rec.ab_job_num);
     END LOOP;   -- coil loop date

     commit;

     FOR m IN 0 .. k - 1 LOOP
       UPDATE production_sheet_item
           SET prod_item_edi870_date = SYSDATE,
               edi_file_id_870 = ll_edi_file_id_aleris /* Alex Gerlants. 09/06/2016. New column */
         WHERE production_sheet_item.prod_item_num = item_num(m);
     END LOOP;

     COMMIT;


    END IF; --end if in select count(*)

  END LOOP; ------ End of outer loop customer_id

EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN;
END;
  GRANT EXECUTE ON "DBO"."EDI_ALCAN_870_REBAND" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Procedure EDI_ALCAN_870_REBAND_COILS2
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."EDI_ALCAN_870_REBAND_COILS2" 
     (
        al_customer_id  customer.customer_id%type
     )
is

  /*
  /*
   Aluminum Blanking: duns:039630926     edi id:039630926t        qualifier: 01
   */



  --Alex Gerlants. 11/15/2016. commented out, and added the line after.
  --edi_loc varchar2(50) := '/templar/templar/incoming/senddata';
  edi_loc varchar2(50) := dbo.get_edi_destination('EDI_DIR');

  edi_file        varchar2(50) := 'edi_out.txt';
  edi_file_handle utl_file.file_type;
  
  --edi_file_prefix varchar2(50) := 'S_alcan_870_reband_'; --Production
  edi_file_prefix varchar2(50) := 's_alcan_870_reband_'; --Development
  --edi_file_prefix varchar2(50) := 'Alex_alcan_';
  
  su_duns         varchar2(10);
  --ll_customer_id  customer.customer_id%type;
  ll_cur_coil     coil.coil_abc_num%type;

  ll_cur_job ab_job.ab_job_num%type;

  ll_gs_log integer;
  ll_st_log integer;

  ls_today   varchar2(20) := to_char(sysdate, 'YYYYMMDD');
  ls_today_4 varchar2(20) := to_char(sysdate, 'YYMMDD');
  ls_now     varchar2(20) := to_char(sysdate, 'HH24MI');

  ls_po varchar2(20);
  ls_finished_goods varchar2(32);
  ls_cust_prod_line varchar2(8);

  ld_scrap_870_date ab_job.scrap_870_date%type;
  ld_job_scrap_870_date ab_job.scrap_870_date%type;

  ls_coil_org_num coil.coil_org_num%type;
  ls_heat coil.lot_num%type;
   ls_scrap_coil_org_num coil.coil_org_num%type;

  ll_ref_order_abc_num sheet_skid.ref_order_abc_num%type;
  ll_ref_order_abc_item sheet_skid.ref_order_abc_item%type;
  ls_sheet_type order_item.sheet_type%type;

  ll_prime_nw coil.net_wt%type;
  ll_scrap_start_nw coil.net_wt%type;
  ll_scrap_end_nw coil.net_wt%type;
  ll_scrap_nw coil.net_wt%type;
  ll_process_quantity  coil.net_wt%type;
  ll_process_end_wt  coil.net_wt%type;
  lr_theo_unit_wt order_item.theoretical_unit_wt%type;

  --ll_edi_file_id integer;
  ll_edi_file_id_aleris integer;

  ll_item_count integer;

  li_hl01 integer;
  li_hllin integer;
  ll_cur_prod_item_num production_sheet_item.prod_item_num%type;

--  cursor cust_cur is
--    select customer_id from customer where customer_id in (1153,1459,2582); ---add customer id here if you want to send 870 for more customers

  cursor coil_cur is
  select distinct coil.coil_abc_num, ab_job.ab_job_num
    from ab_job,
         coil,
         production_sheet_item,
         sheet_skid,
         sheet_skid_detail,
         customer_order,
         process_coil
   where ( sheet_skid_detail.sheet_skid_num = sheet_skid.sheet_skid_num ) and
         ( sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num ) and
         ( coil.coil_abc_num = production_sheet_item.coil_abc_num ) and
         ( ab_job.ab_job_num = sheet_skid.ab_job_num ) and
         ( coil.coil_abc_num = process_coil.coil_abc_num ) and
         ( ab_job.ab_job_num = process_coil.ab_job_num ) and
         ( ab_job.order_abc_num = customer_order.order_abc_num ) and
         ( ab_job.job_status = 0 ) and
         --( coil.coil_status = 7 ) and
         ( process_coil.process_coil_status = 7 ) and
         ( customer_order.orig_customer_id = al_customer_id ) and
         ( production_sheet_item.prod_item_edi870_date is null ) and
         ( process_coil.scrap_870_date is null ) and
         ( coil.scrap_870_date is null ) and
         ( sheet_skid.skid_sheet_status in (2,4,12,13) );

  cursor alcan_870_cur is
   select production_sheet_item.ab_job_num,
           production_sheet_item.coil_abc_num,
           production_sheet_item.prod_item_pieces,
           production_sheet_item.prod_item_num,
           sheet_skid.sheet_skid_num,
           production_sheet_item.prod_item_net_wt,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_skid_display_num,
           sheet_skid.sheet_net_wt,
           sheet_skid.skid_pieces,
           coil.coil_org_num,
           coil.lot_num,
           nvl(coil.consumed_coil_num, ' ') consumed_coil,
           nvl(coil.material_num, ' ') material_num,
           nvl(customer_order.sales_order, ' ') sales_order,
           nvl(customer_order.orig_customer_po, 'NA') customer_po,
           nvl(order_item.enduser_part_num, ' ') enduser_parts,
           nvl(order_item.cust_prod_line_id, 'NA') customer_line_id,
           nvl(order_item.finished_goods_material_num, 'NA') finished_goods,
           (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
           null done
      from sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil,
           order_item,
           ab_job,
           customer_order
     where (sheet_skid.skid_sheet_status in (2, 4, 13, 12)) -- 2: ready; 8: warehouse ready; 13: partial ready; 7: partial; 12: sample; 4: onhold
       and (production_sheet_item.prod_item_edi870_date is null)
       and (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       and (sheet_skid_detail.prod_item_num =
           production_sheet_item.prod_item_num)
       and (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       and (coil.customer_id = al_customer_id)
       and (sheet_skid.ref_order_abc_num = customer_order.order_abc_num)
 		   and (production_sheet_item.ab_job_num = ab_job.ab_job_num)
		   and (ab_job.order_abc_num = order_item.order_abc_num)
		   and (ab_job.order_item_num = order_item.order_item_num)
      and (production_sheet_item.coil_abc_num = ll_cur_coil)
      and (production_sheet_item.ab_job_num = ll_cur_job);


  type store_tabletype is table of varchar2(32767) index by binary_integer;
  x12_table store_tabletype;
  i         binary_integer := 0;

  item_rec  alcan_870_cur%rowtype;
  coil_rec  coil_cur%rowtype;

  type prod_item_type is table of production_sheet_item.prod_item_num%type index by binary_integer;
  item_num prod_item_type;
  k        binary_integer := 0;


begin

  --for cust_rec in cust_cur loop
    --- outer loop of customer_id
    --ll_customer_id := cust_rec.customer_id;
    i              := 0;
    k              := 0;

  select count(coil.coil_abc_num)
  into ll_item_count
    from ab_job,
         coil,
         production_sheet_item,
         sheet_skid,
         sheet_skid_detail,
         customer_order,
         process_coil
   where ( sheet_skid_detail.sheet_skid_num = sheet_skid.sheet_skid_num ) and
         ( sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num ) and
         ( coil.coil_abc_num = production_sheet_item.coil_abc_num ) and
         ( coil.coil_abc_num = process_coil.coil_abc_num ) and
         ( ab_job.ab_job_num = process_coil.ab_job_num ) and
         ( ab_job.ab_job_num = sheet_skid.ab_job_num ) and
         ( ab_job.order_abc_num = customer_order.order_abc_num ) and
         ( ab_job.job_status = 0 ) and
         --( coil.coil_status = 7 ) and
         ( process_coil.process_coil_status = 7 ) and
         ( customer_order.orig_customer_id = al_customer_id ) and
         ( production_sheet_item.prod_item_edi870_date is null ) and
         ( process_coil.scrap_870_date is null ) and
         ( coil.scrap_870_date is null ) and
         ( sheet_skid.skid_sheet_status in (2,4,12,13) );

    if (ll_item_count <> 0) then


      select edi_st_log_seq.nextval into ll_st_log from dual;
      select edi_gs_log_seq.nextval into ll_gs_log from dual;

      select customer.customer_duns_number_string
        into su_duns
        from customer
       where customer.customer_id = al_customer_id;

      --Production
      --x12_table(i) := 'ISA*00*' ||
      --                '          *00*          *01*039630926T     *09*0015049350011G *' ||
      --                ls_today_4 || '*' || ls_now || '*U*00401*' ||
      --                lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
      
      --Development                
      x12_table(i) := 'ISA*00*' ||
                      '          *00*          *ZZ*2NDSFTP        *ZZ*NOVLSTEST      *' ||
                      ls_today_4 || '*' || ls_now || '*U*00401*' ||
                      lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';    
                     
      i := i + 1;
      
      --Production
      --x12_table(i) := 'GS*RS*039630926T*' || '001504935001' || '*' ||
      --                ls_today || '*' || ls_now || '*' ||
      --                to_char(ll_gs_log) || '*X*' || '004010';
      
      --Development                
      x12_table(i) := 'GS*RS*2NDSFTP*' || 'NOVLSTEST' || '*' ||
                      ls_today || '*' || ls_now || '*' ||
                      to_char(ll_gs_log) || '*X*' || '004010';
                      
      i := i + 1;
      
      x12_table(i) := 'ST*870*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                      '***' || ls_now || '*****';
      i := i + 1;
      x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
      i := i + 1;
      x12_table(i) := 'N1*SU**1*' || su_duns;
      i := i + 1;
      x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926';
      i := i + 1;

      li_hl01 := 0;

      for coil_rec in coil_cur loop    -- coil loop
          ll_cur_coil := coil_rec.coil_abc_num;
          ll_cur_job := coil_rec.ab_job_num;

          for item_rec in alcan_870_cur loop   -- item loop
            ll_cur_prod_item_num := item_rec.prod_item_num;

            li_hl01 := li_hl01 + 1;

            x12_table(i) := 'HL*' || to_char(li_hl01) || '**I';
            i := i + 1;

            select nvl(customer_order.orig_customer_po, 'NA'),
                   nvl(order_item.cust_prod_line_id, 'NA'),
                   nvl(order_item.finished_goods_material_num, 'NA')
            into   ls_po, ls_cust_prod_line, ls_finished_goods
            from   order_item,
                   ab_job,
                   customer_order
            where  (ab_job.order_abc_num = customer_order.order_abc_num)
            and    (ab_job.order_abc_num = order_item.order_abc_num)
            and    (ab_job.order_item_num = order_item.order_item_num)
            and    (ab_job.ab_job_num = ll_cur_job);

            if (ls_po <> ls_finished_goods) and (ls_po <> 'NA' ) then
               x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
               i := i + 1;
            end if;

            x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
            i := i + 1;

            x12_table(i) := 'REF*SE*' || to_char(item_rec.prod_item_num);
            i := i + 1;


            x12_table(i) := 'REF*MI*' || to_char(item_rec.ab_job_num);
            i := i + 1;

            x12_table(i) := 'REF*RV*' || to_char(item_rec.prod_item_num) ||
                            '*NA';
            i := i + 1;

            x12_table(i) := 'REF*IX*' || to_char(item_rec.consumed_coil);
            i := i + 1;

            x12_table(i) := 'PO1**1*UN****' || '***SN*' ||
                              item_rec.coil_org_num || '***VP*' || item_rec.finished_goods;
            i := i + 1;

            if item_rec.skid_sheet_status = 2 then
              x12_table(i) := 'PID*S*MA*ST*1*' ||
                              to_char(item_rec.sheet_skid_display_num);
              i := i + 1;
            elsif item_rec.skid_sheet_status = 4 then
              x12_table(i) := 'PID*S*MA*ST*3*' ||
                              to_char(item_rec.sheet_skid_display_num);
              i := i + 1;
            elsif item_rec.skid_sheet_status = 13 then
              x12_table(i) := 'PID*S*MA*ST*8*' ||
                              to_char(item_rec.sheet_skid_display_num);
              i := i + 1;
             else
              x12_table(i) := 'PID*S*MA*ST*4*' ||
                              to_char(item_rec.sheet_skid_display_num);
              i := i + 1;
            end if;

            x12_table(i) := 'PID*S*MAC*ST*01';
            i := i + 1;
            x12_table(i) := 'PID*S*PR*ST*19';
            i := i + 1;
            x12_table(i) := 'MEA*WT*N*' || to_char(item_rec.prod_item_net_wt) ||
                            '*LB*01';
            i := i + 1;
            x12_table(i) := 'MEA*WT*G*' || to_char(item_rec.skid_gross_wt) ||
                            '*LB*01';
            i := i + 1;
            x12_table(i) := 'MEA*CT*NA*' || to_char(item_rec.prod_item_pieces) ||
                            '*PC';
            i := i + 1;

             item_num(k) := item_rec.prod_item_num;
            k := k + 1;

          end loop;  -- item loop


     select scrap_870_date, coil_org_num, lot_num
     into ld_scrap_870_date, ls_coil_org_num, ls_heat
     from coil
     where coil_abc_num = ll_cur_coil;

     select scrap_870_date
     into ld_job_scrap_870_date
     from process_coil
     where (coil_abc_num = ll_cur_coil) and (ab_job_num = ll_cur_job);

     if (ld_scrap_870_date is null) and (ld_job_scrap_870_date is null) then  -- scrap not sent

             select b.coil_org_num,
               nvl(a.process_quantity, 0) process_quan,
               nvl(a.process_end_wt, 0) process_end_wt
           into ls_scrap_coil_org_num, ll_scrap_start_nw, ll_scrap_end_nw
           from process_coil a, coil b
           where (b.coil_abc_num = ll_cur_coil)
           and (a.coil_abc_num = b.coil_abc_num)
            and (a.ab_job_num = ll_cur_job);

        --scrap info

        select   nvl(sum(production_sheet_item.prod_item_net_wt),0)
        into     ll_prime_nw
        from     production_sheet_item
        where    production_sheet_item.ab_job_num = ll_cur_job
        and      production_sheet_item.coil_abc_num = ll_cur_coil;
        --and      production_sheet_item.prod_item_num = ll_cur_prod_item_num;


                ll_scrap_nw := ll_scrap_start_nw - ll_scrap_end_nw - ll_prime_nw;

                if ll_scrap_nw > 0 then

                   li_hl01 := li_hl01 + 1;

                   x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*I';
                   i := i + 1;

                   if (ls_po <> ls_finished_goods) and (ls_po <> 'NA' ) then
                      x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
                      i := i + 1;
                   end if;

                   x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
                    i := i + 1;

                    x12_table(i) := 'PO1**1*UN****' || '***SN*' || ls_scrap_coil_org_num ;
                    i := i + 1;

                    x12_table(i) := 'PID*S*MA*ST*S';
                    i := i + 1;
                    x12_table(i) := 'PID*S*MAC*ST*05';
                     i := i + 1;
                    x12_table(i) := 'PID*S*PR*ST*19';
                     i := i + 1;

                   x12_table(i) := 'MEA*WT*N*' || to_char(ll_scrap_nw) || '*LB*01';
                   i := i+1;
                 end if;

       end if;  -- scrap not sent
     end loop;   -- coil loop

      x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
      i := i + 1;
      x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
      i := i + 1;
      x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

      -- write edi to file

      if li_hl01 > 1 then
        -- write edi file only if item > 0
        select   edi_file_id_seq.nextval
        into     ll_edi_file_id_aleris
        from     dual;
          
        edi_file        := edi_file_prefix || to_char(ll_edi_file_id_aleris);
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        for j in 0 .. i loop
          utl_file.put_line(edi_file_handle, x12_table(j));

        end loop;
        
        utl_file.fclose(edi_file_handle);
      end if; -- end writing edi file


      --for verifying 997
/*      
      insert into outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
        values
          (ll_edi_file_id_aleris,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           sysdate,
           edi_file,
           0,
           al_customer_id,
           ll_st_log,
           '870');
--        commit;
*/

      edi_file        := 'send_edi_log';
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(sysdate, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

/*
      for coil_rec in coil_cur loop
         update   process_coil
         set      scrap_870_date = sysdate
         where    coil_abc_num = coil_rec.coil_abc_num
         and      ab_job_num = coil_rec.ab_job_num;
      end loop;


--      commit;


      for m in 0 .. k - 1 loop
       
         update   production_sheet_item
         set      prod_item_edi870_date = sysdate,
                  edi_file_id_870 = ll_edi_file_id_aleris
         where    production_sheet_item.prod_item_num = item_num(m);
       
      end loop;

     commit; -- Just 1 commit for all updates above
*/
    end if; --end if in select count(*)

  --end loop; ------ end of outer loop customer_id

exception
  when utl_file.invalid_path then
    utl_file.fclose_all;
    return;
  when utl_file.invalid_mode then
    utl_file.fclose_all;
    return;
  when utl_file.invalid_operation then
    utl_file.fclose_all;
    return;
  when utl_file.write_error then
    utl_file.fclose_all;
    return;
  when others then
    utl_file.fclose_all;
    return;
end;
