--  DDL for Procedure EDI_ALCAN_870_REJ_COILS
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."EDI_ALCAN_870_REJ_COILS" 
     (
        al_customer_id  customer.customer_id%type
     )
is

  --alex gerlants. 11/15/2016. commented out, and added the line after.
  --edi_loc varchar2(50) := '/templar/templar/incoming/senddata';
  edi_loc varchar2(50) := get_edi_destination('EDI_DIR');

  edi_file        varchar2(50) := 'edi_out.txt';
  --edi_file_prefix varchar2(50) := 'S_alcan_870_reject_'; --Production
  edi_file_prefix varchar2(50) := 's_alcan_870_reject_'; --Development
  --edi_file_prefix varchar2(50) := 'Alex_alcan_';
  edi_file_handle utl_file.file_type;
  su_duns         varchar2(20); /* alex gerlants. changed from (10) to (20) */
  ll_cur_coil     coil.coil_abc_num%type;

  ll_gs_log integer;
  ll_st_log integer;

  ls_today   varchar2(20) := to_char(sysdate, 'YYYYMMDD');
  ls_today_4 varchar2(20) := to_char(sysdate, 'YYMMDD');
  ls_now     varchar2(20) := to_char(sysdate, 'HH24MI');

  ls_po varchar2(20);
  ls_finished_goods varchar2(32);
  --ls_cust_prod_line varchar2(8);

  --ld_scrap_870_date ab_job.scrap_870_date%type;

  --ls_coil_org_num coil.coil_org_num%type;
  --ls_heat coil.lot_num%type;

--  ll_ref_order_abc_num sheet_skid.ref_order_abc_num%type;
--  ll_ref_order_abc_item sheet_skid.ref_order_abc_item%type;
--  ls_sheet_type order_item.sheet_type%type;

 -- ll_prime_nw coil.net_wt%type;
  ll_scrap_nw coil.net_wt%type;
--  ll_process_quantity  coil.net_wt%type;
--  ll_process_end_wt  coil.net_wt%type;
--  lr_theo_unit_wt order_item.theoretical_unit_wt%type;

  --ll_edi_file_id integer;
  ll_edi_file_id integer;

  --ll_item_count integer;

  li_hl01 integer;
  li_hllin integer;
  
  --li_coil_status   coil.coil_status%type; /* alex gerlants. new variable */
  
  ll_rejected_coils     integer; /* alex gerlants. 07/25/2017 */
  --ls_isa_header_created char(1) := 'N'; /* alex gerlants. 07/25/2017 */

  consumed_coil_num coil.consumed_coil_num%type;
  li_coil_status    coil.coil_status%type;
  ld_scrap_870_date coil.scrap_870_date%type;
     
   /* alex gerlants. 07/25/2017. begin */  
   cursor rejected_coils_cur is
   select coil.coil_abc_num coil_abc_num,
          coil.coil_org_num coil_org_num,
          ab_job.ab_job_num ab_job_num,
          nvl(coil.material_num, ' ') material_num,
          nvl(coil.net_wt, 0) net_wt,
          nvl(coil.net_wt_balance, 0) net_wt_balance,
          nvl(customer_order.orig_customer_po, 'NA') orig_customer_po,
          nvl(order_item.cust_prod_line_id, 'NA') cust_prod_line_id,
          nvl(order_item.finished_goods_material_num, 'NA') finished_goods_material_num,
          nvl(coil.consumed_coil_num, ' ') consumed_coil_num,
          coil.coil_status,
          coil.scrap_870_date
   from   reject_coil
          join coil on coil.coil_abc_num = reject_coil.coil_abc_num
          join ab_job on reject_coil.ab_job_num = ab_job.ab_job_num
          join customer_order on ab_job.order_abc_num = customer_order.order_abc_num
          join order_item on ab_job.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
   where  coil.customer_id = al_customer_id
   and    ab_job.job_status = 0 
   and    coil.scrap_870_date is null;
   
   reject_rec  rejected_coils_cur%rowtype;
   
   /* alex gerlants. 07/25/2017. end */
       

  type store_tabletype is table of varchar2(32767) index by binary_integer;
  x12_table store_tabletype;
  i         binary_integer := 0;

  /*
  item_rec  alcan_870_cur%rowtype;
  coil_rec  coil_cur%rowtype;

  type prod_item_type is table of production_sheet_item.prod_item_num%type index by binary_integer;
  item_num prod_item_type;
  k        binary_integer := 0;
  */
  
  type coil_num_type is table of coil.coil_abc_num%type index by binary_integer;
  coil_num coil_num_type;
  p binary_integer :=0;


begin

  --for cust_rec in cust_cur loop
    --- outer loop of customer_id
  --  ll_customer_id := cust_rec.customer_id;
    i              := 0;
    --k              := 0;
    --p              := 0;

  --check for rejected coils
    select count(*)
    into   ll_rejected_coils
    from   reject_coil
           join coil on coil.coil_abc_num = reject_coil.coil_abc_num
           join ab_job on reject_coil.ab_job_num = ab_job.ab_job_num
           join customer_order on ab_job.order_abc_num = customer_order.order_abc_num
           join order_item on ab_job.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
    where  coil.customer_id = al_customer_id
    and    ab_job.job_status = 0 
    and    coil.scrap_870_date is null;

    if (ll_rejected_coils > 0) then

      select edi_st_log_seq.nextval into ll_st_log from dual;
      select edi_gs_log_seq.nextval into ll_gs_log from dual;

 
      select customer.customer_duns_number_string
        into su_duns
        from customer
       where customer.customer_id = al_customer_id;
       
      --Production
      --x12_table(i) := 'ISA*00*' ||
      --                '          *00*          *01*039630926T     *09*0015049350011G *' ||
      --                ls_today_4 || '*' || ls_now || '*U*00401*' ||
      --                lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
      
      --Development                
      x12_table(i) := 'ISA*00*' ||
                      '          *00*          *ZZ*2NDSFTP        *ZZ*NOVLSTEST      *' ||
                      ls_today_4 || '*' || ls_now || '*U*00401*' ||
                      lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';    
                     
      i := i + 1;
      --Production
      --x12_table(i) := 'GS*RS*039630926T*' || '001504935001' || '*' ||
      --                ls_today || '*' || ls_now || '*' ||
      --                to_char(ll_gs_log) || '*X*' || '004010';
      
      --Development                
      x12_table(i) := 'GS*RS*2NDSFTP*' || 'NOVLSTEST' || '*' ||
                      ls_today || '*' || ls_now || '*' ||
                      to_char(ll_gs_log) || '*X*' || '004010';
                      
      i := i + 1;
      
      x12_table(i) := 'ST*870*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                      '***' || ls_now || '*****';
      i := i + 1;
      x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
      i := i + 1;
      x12_table(i) := 'N1*SU**1*' || su_duns;
      i := i + 1;
      x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926';
      i := i + 1;
      
      --ls_isa_header_created := 'Y'; /* alex gerlants. 07/25/2017 */

      li_hl01 := 0;

      ----------------------------------------------------------------------
      
      for reject_rec in rejected_coils_cur loop
        
        ll_cur_coil := reject_rec.coil_abc_num;
        
        coil_num(p) := ll_cur_coil;
        p := p + 1;
        
        ls_po := reject_rec.orig_customer_po;
        ls_finished_goods := reject_rec.finished_goods_material_num;
        consumed_coil_num := reject_rec.consumed_coil_num;
         
        ll_scrap_nw := reject_rec.net_wt - reject_rec.net_wt_balance;
        
        if ll_scrap_nw > 0 then

           li_hl01 := li_hl01 + 1;

           x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*I';
           i := i + 1;

           if (ls_po <> ls_finished_goods) and (ls_po <> 'NA' ) then
              x12_table(i) := 'PRF*' || reject_rec.orig_customer_po || '****' || reject_rec.cust_prod_line_id;
              i := i + 1;
           end if;

           x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
            i := i + 1;

           x12_table(i) := 'REF*IX*' || to_char(consumed_coil_num);
            i := i + 1;
            
           x12_table(i) := 'PO1**1*UN****' || '***SN*' || reject_rec.coil_org_num ;
            i := i + 1;

           x12_table(i) := 'PID*S*MA*ST*S';
            i := i + 1;
           x12_table(i) := 'PID*S*MAC*ST*05';
             i := i + 1;
           x12_table(i) := 'PID*S*PR*ST*19';
             i := i + 1;

           x12_table(i) := 'MEA*WT*N*' || to_char(ll_scrap_nw) || '*LB*01';
            i := i+1;
         end if;
      end loop;
     
      ----------------------------------------------------------------------     
     
     
      x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
      i := i + 1;
      x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
      i := i + 1;
      x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

      -- write edi to file

      if li_hl01 > 0 then  --alex gerlants. changed from "> 1" to "> 0"
        -- write edi file only if item > 0
        select edi_file_id_seq.nextval
          into ll_edi_file_id
          from dual;
        edi_file        := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';
     -- edi_file        := 's_alcan_' || to_char(ll_edi_file_id) || '.870';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        for j in 0 .. i loop
          utl_file.put_line(edi_file_handle, x12_table(j));

        end loop;
        utl_file.fclose(edi_file_handle);
      end if; -- end writing edi file

      --edi_file        := 'send_edi_log'; /* alex gerlants. 04/14/2017. commented out. */
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(sysdate, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      --for verifying 997
      /*
      insert into outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
        values
          (ll_edi_file_id,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           sysdate,
           edi_file,
           0,
           al_customer_id,
           ll_st_log,
           '870');
           
        for m in 0..p - 1 loop
            select  coil.coil_status, coil.scrap_870_date
            into    li_coil_status, ld_scrap_870_date
            from    coil
            where   coil.coil_abc_num = coil_num(m);
            
            if li_coil_status <> 7 then --skip rebanded coils
              --coil.scrap_870_date and process_coil.scrap_870_date are updated in edi_alcan_870
              --thus if it already updated, do not update here
              if ld_scrap_870_date is null then
                update  coil
                set     coil.scrap_870_date = sysdate,
                        coil.edi_file_id_870_reject = ll_edi_file_id;
                        
                update  process_coil
                set     scrap_870_date = sysdate
                where   coil_abc_num = coil_num(m);
              else --ld_scrap_870_date is not null, update edi_file_id only
                update  coil
                set     coil.edi_file_id_870_reject = ll_edi_file_id
                where   coil.coil_abc_num = coil_num(m);
              end if;
            end if; --if li_coil_status <> 7 then
        end loop; --for m in 0..p - 1 loop

        commit;
        */
        
    end if; --if (ll_rejected_coils > 0) then
    

exception
  when utl_file.invalid_path then
    utl_file.fclose_all;
    return;
  when utl_file.invalid_mode then
    utl_file.fclose_all;
    return;
  when utl_file.invalid_operation then
    utl_file.fclose_all;
    return;
  when utl_file.write_error then
    utl_file.fclose_all;
    return;
  when others then
    utl_file.fclose_all;
    return;
end;
--------------------------------------------------------
--  DDL for Procedure EDI_ALCAN_870_REJ_COILS2
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."EDI_ALCAN_870_REJ_COILS2" 
     (
        al_customer_id  customer.customer_id%type
     )
is

  --Alex Gerlants. 11/15/2016. commented out, and added the line after.
  --edi_loc varchar2(50) := '/templar/templar/incoming/senddata';
  edi_loc varchar2(50) := get_edi_destination('EDI_DIR');

  edi_file        varchar2(50) := 'edi_out.txt';
  --edi_file_prefix varchar2(50) := 'S_alcan_870_reject_'; --Production
  edi_file_prefix varchar2(50) := 's_alcan_870_reject_'; --Development
  --edi_file_prefix varchar2(50) := 'Alex_alcan_';
  edi_file_handle utl_file.file_type;
  su_duns         varchar2(20); /* alex gerlants. changed from (10) to (20) */
  ll_cur_coil     coil.coil_abc_num%type;

  ll_gs_log integer;
  ll_st_log integer;

  ls_today   varchar2(20) := to_char(sysdate, 'YYYYMMDD');
  ls_today_4 varchar2(20) := to_char(sysdate, 'YYMMDD');
  ls_now     varchar2(20) := to_char(sysdate, 'HH24MI');

  ls_po varchar2(20);
  ls_finished_goods varchar2(32);
  ll_scrap_nw coil.net_wt%type;
  ll_edi_file_id integer;
  li_hl01 integer;
  li_hllin integer;
  
  --li_coil_status   coil.coil_status%type; /* alex gerlants. new variable */
  
  ll_rejected_coils     integer; /* alex gerlants. 07/25/2017 */
  --ls_isa_header_created char(1) := 'N'; /* alex gerlants. 07/25/2017 */

  consumed_coil_num coil.consumed_coil_num%type;
  li_coil_status    coil.coil_status%type;
  ld_scrap_870_date coil.scrap_870_date%type;
  
  ll_count          number(8); --Alex Gerlants. 02/03/2020
  ll_count_2process number(8); --Alex Gerlants. 02/03/2020
     
   /* alex gerlants. 07/25/2017. begin */ 
   /* 
   cursor rejected_coils_cur is
   select coil.coil_abc_num coil_abc_num,
          coil.coil_org_num coil_org_num,
          ab_job.ab_job_num ab_job_num,
          nvl(coil.material_num, ' ') material_num,
          nvl(coil.net_wt, 0) net_wt,
          nvl(coil.net_wt_balance, 0) net_wt_balance,
          nvl(customer_order.orig_customer_po, 'NA') orig_customer_po,
          nvl(order_item.cust_prod_line_id, 'NA') cust_prod_line_id,
          nvl(order_item.finished_goods_material_num, 'NA') finished_goods_material_num,
          nvl(coil.consumed_coil_num, ' ') consumed_coil_num,
          coil.coil_status,
          coil.scrap_870_date
   from   reject_coil
          join coil on coil.coil_abc_num = reject_coil.coil_abc_num
          join ab_job on reject_coil.ab_job_num = ab_job.ab_job_num
          join customer_order on ab_job.order_abc_num = customer_order.order_abc_num
          join order_item on ab_job.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
   where  coil.customer_id = al_customer_id
   and    ab_job.job_status = 0 
   and    coil.scrap_870_date is null;
   
   reject_rec  rejected_coils_cur%rowtype;
   */
   /* alex gerlants. 07/25/2017. end */
   
   --Alex Gerlants. 02/03/2020. Begin
   cursor rejected_coils_cur is
   select coil.coil_abc_num coil_abc_num,
          coil.coil_org_num coil_org_num,
          ab_job.ab_job_num ab_job_num,
          nvl(coil.material_num, ' ') material_num,
          nvl(coil.net_wt, 0) net_wt,
          nvl(coil.net_wt_balance, 0) net_wt_balance,
          nvl(customer_order.orig_customer_po, 'NA') orig_customer_po,
          nvl(order_item.cust_prod_line_id, 'NA') cust_prod_line_id,
          nvl(order_item.finished_goods_material_num, 'NA') finished_goods_material_num,
          nvl(coil.consumed_coil_num, ' ') consumed_coil_num,
          coil.coil_status,
          coil.scrap_870_date coil_scrap_870_date,
          process_coil.scrap_870_date process_coil_scrap_870_date,
          nvl(process_coil.process_quantity, 0) process_quan,
          nvl(process_coil.process_end_wt, 0) process_end_wt
   from   reject_coil
          join coil on coil.coil_abc_num = reject_coil.coil_abc_num
          join process_coil on coil.coil_abc_num = process_coil.coil_abc_num
          join ab_job on reject_coil.ab_job_num = ab_job.ab_job_num
          join customer_order on ab_job.order_abc_num = customer_order.order_abc_num
          join order_item on ab_job.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
   where  coil.customer_id = al_customer_id
   and    coil.coil_status = 3
   and    ab_job.job_status = 0 
   and    coil.scrap_870_date is null
   and    process_coil.scrap_870_date is null;
  
   reject_rec  rejected_coils_cur%rowtype;
   --Alex Gerlants. 02/03/2020. End

  type store_tabletype is table of varchar2(32767) index by binary_integer;
  x12_table store_tabletype;
  i         binary_integer := 0;

  /*
  item_rec  alcan_870_cur%rowtype;
  coil_rec  coil_cur%rowtype;

  type prod_item_type is table of production_sheet_item.prod_item_num%type index by binary_integer;
  item_num prod_item_type;
  k        binary_integer := 0;
  */
  
  type coil_num_type is table of coil.coil_abc_num%type index by binary_integer;
  coil_num coil_num_type;
  p binary_integer :=0;


begin

    i                 := 0;
    ll_count_2process := 0;
    
    --First, determine if any coil in rejected_coils_cur is rejected without sheets,
    --and these coils have not been process before
    for reject_rec in rejected_coils_cur loop
        
        ll_cur_coil := reject_rec.coil_abc_num;
        
        select   count(*)
        into     ll_count
        from     production_sheet_item
        where    coil_abc_num = ll_cur_coil;
        
        if ll_count > 0 or ( reject_rec.coil_scrap_870_date is not null or reject_rec.process_coil_scrap_870_date is not null ) then
          continue; --Rejected coils in production_sheet_item produced sheets, 
                    --and they are picked up in edi_alcan_870
        end if;
        
        --if reject_rec.coil_scrap_870_date is not null or reject_rec.process_coil_scrap_870_date is not null then
        --  continue;
        --end if;
        
        ll_count_2process := ll_count_2process + 1;
    end loop;

  --check for rejected coils
/*  
    select count(*)
    into   ll_rejected_coils
    from   reject_coil
           join coil on coil.coil_abc_num = reject_coil.coil_abc_num
           join ab_job on reject_coil.ab_job_num = ab_job.ab_job_num
           join customer_order on ab_job.order_abc_num = customer_order.order_abc_num
           join order_item on ab_job.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
    where  coil.customer_id = al_customer_id
    and    ab_job.job_status = 0 
    and    coil.scrap_870_date is null;

    if (ll_rejected_coils > 0) then
*/      
    if ll_count_2process > 0 then
      select edi_st_log_seq.nextval into ll_st_log from dual;
      select edi_gs_log_seq.nextval into ll_gs_log from dual;

      select   customer.customer_duns_number_string
      into     su_duns
      from     customer
      where    customer.customer_id = al_customer_id;
       
      --Production
      --x12_table(i) := 'ISA*00*' ||
      --                '          *00*          *01*039630926T     *09*0015049350011G *' ||
      --                ls_today_4 || '*' || ls_now || '*U*00401*' ||
      --                lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
      
      --Development                
      x12_table(i) := 'ISA*00*' ||
                      '          *00*          *ZZ*2NDSFTP        *ZZ*NOVLSTEST      *' ||
                      ls_today_4 || '*' || ls_now || '*U*00401*' ||
                      lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';    
                     
      i := i + 1;
      
      --Production
      --x12_table(i) := 'GS*RS*039630926T*' || '001504935001' || '*' ||
      --                ls_today || '*' || ls_now || '*' ||
      --                to_char(ll_gs_log) || '*X*' || '004010';
      
      --Development                
      x12_table(i) := 'GS*RS*2NDSFTP*' || 'NOVLSTEST' || '*' ||
                      ls_today || '*' || ls_now || '*' ||
                      to_char(ll_gs_log) || '*X*' || '004010';
                      
      i := i + 1;
      
      x12_table(i) := 'ST*870*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                      '***' || ls_now || '*****';
      i := i + 1;
      x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
      i := i + 1;
      x12_table(i) := 'N1*SU**1*' || su_duns;
      i := i + 1;
      x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926';
      i := i + 1;
      
      --ls_isa_header_created := 'Y'; /* alex gerlants. 07/25/2017 */

      li_hl01 := 0;

      ----------------------------------------------------------------------
      
      for reject_rec in rejected_coils_cur loop
        
        ll_cur_coil := reject_rec.coil_abc_num;
        
        coil_num(p) := ll_cur_coil;
        p := p + 1;
        
        ls_po := reject_rec.orig_customer_po;
        ls_finished_goods := reject_rec.finished_goods_material_num;
        consumed_coil_num := reject_rec.consumed_coil_num;
         
        ll_scrap_nw := reject_rec.process_quan - reject_rec.process_end_wt;
        
        if ll_scrap_nw > 0 then

           li_hl01 := li_hl01 + 1;

           x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*I';
           i := i + 1;

           if (ls_po <> ls_finished_goods) and (ls_po <> 'NA' ) then
              x12_table(i) := 'PRF*' || reject_rec.orig_customer_po || '****' || reject_rec.cust_prod_line_id;
              i := i + 1;
           end if;

           x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
            i := i + 1;

           x12_table(i) := 'REF*IX*' || to_char(consumed_coil_num);
            i := i + 1;
            
           x12_table(i) := 'PO1**1*UN****' || '***SN*' || reject_rec.coil_org_num ;
            i := i + 1;

           x12_table(i) := 'PID*S*MA*ST*S';
            i := i + 1;
           x12_table(i) := 'PID*S*MAC*ST*05';
             i := i + 1;
           x12_table(i) := 'PID*S*PR*ST*19';
             i := i + 1;

           x12_table(i) := 'MEA*WT*N*' || to_char(ll_scrap_nw) || '*LB*01';
            i := i+1;
         end if;
      end loop;
     
      ----------------------------------------------------------------------     
     
     
      x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
      i := i + 1;
      x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
      i := i + 1;
      x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

      -- write edi to file

      if li_hl01 > 0 then  --alex gerlants. changed from "> 1" to "> 0"
        -- write edi file only if item > 0
        select edi_file_id_seq.nextval
          into ll_edi_file_id
          from dual;
        edi_file        := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';
     -- edi_file        := 's_alcan_' || to_char(ll_edi_file_id) || '.870';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        for j in 0 .. i loop
          utl_file.put_line(edi_file_handle, x12_table(j));

        end loop;
        utl_file.fclose(edi_file_handle);
      end if; -- end writing edi file

      --edi_file        := 'send_edi_log'; /* alex gerlants. 04/14/2017. commented out. */
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(sysdate, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      --for verifying 997
/*      
      insert into outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
        values
          (ll_edi_file_id,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           sysdate,
           edi_file,
           0,
           al_customer_id,
           ll_st_log,
           '870');
*/
           
        for m in 0..p - 1 loop
            select  coil.coil_status, coil.scrap_870_date
            into    li_coil_status, ld_scrap_870_date
            from    coil
            where   coil.coil_abc_num = coil_num(m);
/*            
            if li_coil_status <> 7 then --skip rebanded coils...just in case
              --coil.scrap_870_date and process_coil.scrap_870_date are updated in edi_alcan_870
              --thus if it already updated, do not update here
              if ld_scrap_870_date is null then
                update  coil
                set     coil.scrap_870_date = sysdate,
                        coil.edi_file_id_870_reject = ll_edi_file_id;
                        
                update  process_coil
                set     scrap_870_date = sysdate
                where   coil_abc_num = coil_num(m);
              else --ld_scrap_870_date is not null, update edi_file_id only
                update  coil
                set     coil.edi_file_id_870_reject = ll_edi_file_id
                where   coil.coil_abc_num = coil_num(m);
              end if;
            end if; --if li_coil_status <> 7 then
*/            
        end loop; --for m in 0..p - 1 loop

--        commit;
        
        
    end if; --if (ll_rejected_coils > 0) then
    

exception
  when utl_file.invalid_path then
    utl_file.fclose_all;
    return;
  when utl_file.invalid_mode then
    utl_file.fclose_all;
    return;
  when utl_file.invalid_operation then
    utl_file.fclose_all;
    return;
  when utl_file.write_error then
    utl_file.fclose_all;
    return;
  when others then
    utl_file.fclose_all;
    return;
end;
