--  DDL for Procedure EDI_ALCAN_870_REWORK
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."EDI_ALCAN_870_REWORK" is

--CREATE OR REPLACE PROCEDURE edi_alcan_870 IS

  /*
  Aluminum Blanking: Ford Suppler Code: ZZ R0P7A
                     DUNS: 01 039630926T
  Customer: ALCAN(34,35,10,1153)
  Alcan Rolled Product    X.121       0015049350011G
  Kingston Duns: 241003755
  */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR');

  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_handle utl_file.file_type;
  su_duns         VARCHAR2(10);
  ll_customer_id  INTEGER := 1153;

  ll_gs_log INTEGER;
  ll_st_log INTEGER;
  --ll_bsn_log integer;

  ls_today   VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD');
  ls_today_4 VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  ls_now     VARCHAR2(20) := to_char(SYSDATE, 'HH24MI'); -- time in 24 hours format....Tony

  ls_po VARCHAR2(36);

  --ll_edi_file_id integer;
  ll_edi_file_id_alcan INTEGER;

  ll_item_count INTEGER;

  li_hl01 INTEGER;

  CURSOR cust_cur IS
    SELECT customer_id
      FROM customer
     WHERE customer_id IN (1153, 1459, 2582); ---Add customer id here if you want to send 870 for more customers

  CURSOR alcan_870_cur IS
    SELECT production_sheet_item.ab_job_num,
           production_sheet_item.prod_item_pieces,
           production_sheet_item.prod_item_num,
           sheet_skid.sheet_skid_num,
           sheet_skid.sheet_skid_display_num,
           production_sheet_item.prod_item_net_wt,
           sheet_skid.skid_sheet_status,
           coil.coil_org_num,
           nvl(coil.consumed_coil_num, ' ') consumed_coil,   --add james ni 10/22/2013
           nvl(customer_order.sales_order, ' ') sales_order,
           nvl(customer_order.orig_customer_po, 'NA') customer_po,
           (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
           NULL done
      FROM sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil,
           customer_order --,ab_job
     WHERE (sheet_skid.skid_sheet_status IN (2, 4, 8, 13))
       AND (production_sheet_item.prod_item_edi870_date IS NULL)
       AND (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       AND (sheet_skid_detail.prod_item_num =
           production_sheet_item.prod_item_num)
       AND (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       AND (coil.customer_id = ll_customer_id)
       AND -- Add Oswego id=1459 by Tony 04-29-03
           (sheet_skid.ref_order_abc_num = customer_order.order_abc_num);
  --(production_sheet_item.ab_job_num = ab_job.ab_job_num) and
  --(ab_job.order_abc_num = customer_order.order_abc_num) ;

  --End of change by tony

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;
  item_rec  alcan_870_cur%ROWTYPE;

  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;

BEGIN

  FOR cust_rec IN cust_cur LOOP
    --- Outer loop of customer_id
    ll_customer_id := cust_rec.customer_id;
    i              := 0;
    k              := 0;

    SELECT COUNT(*)
      INTO ll_item_count
      FROM sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil,
           customer_order
     WHERE (sheet_skid.skid_sheet_status IN (2, 4, 8, 13))
       AND (production_sheet_item.prod_item_edi870_date IS NULL)
       AND (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       AND (sheet_skid_detail.prod_item_num =
           production_sheet_item.prod_item_num)
       AND (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       AND (coil.customer_id = ll_customer_id)
       AND -- Add Oswego id=1459 by Tony 04-29-03
           (sheet_skid.ref_order_abc_num = customer_order.order_abc_num);
    -- if ll_item_count = 0 then return 100; end if;   -- nothing to send
    IF ll_item_count <> 0 THEN

      SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
      SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;

      SELECT customer.customer_duns_number_string
        INTO su_duns
        FROM customer
       WHERE customer.customer_id = ll_customer_id;

      x12_table(i) := 'ISA*00*' ||
                      '          *00*          *01*039630926T     *09*0015049350011G *' ||
                      ls_today_4 || '*' || ls_now || '*U*00401*' ||
                      lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
      i := i + 1;
      x12_table(i) := 'GS*RS*039630926T*' || '001504935001' || '*' ||
                      ls_today || '*' || ls_now || '*' ||
                      to_char(ll_gs_log) || '*X*' || '004010';
      i := i + 1;
      x12_table(i) := 'ST*870*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                      '***' || ls_now || '*****';
      i := i + 1;
      x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
      i := i + 1;
      x12_table(i) := 'N1*SU**1*' || su_duns || '*NA';
      i := i + 1;
      x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926T';
      i := i + 1;

      --open alcan_870_cur;
      --fetch alcan_870_cur INTO item_rec;
      --close alcan_870_cur;

      li_hl01 := 1;

      FOR item_rec IN alcan_870_cur LOOP
        x12_table(i) := 'HL*' || to_char(li_hl01) || '**I';
        i := i + 1;

        ls_po := item_rec.customer_po;

        x12_table(i) := 'PRF*' || ls_po || '****NA';
        i := i + 1;
        x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
        i := i + 1;
        -- Nov 21 03, change per Alcan  ---tony
        --x12_table(i) := 'REF*SE*' ||item_rec.coil_org_num ||'-'||to_char(item_rec.sheet_skid_num); i := i+1;

        x12_table(i) := 'REF*SE*' || to_char(item_rec.prod_item_num);
        i := i + 1;

        --add james ni 10/22/2013
        x12_table(i) := 'REF*IX*' || to_char(item_rec.consumed_coil);
        i := i + 1;

        x12_table(i) := 'REF*MI*' || to_char(item_rec.ab_job_num);
        i := i + 1;

        -- Nov 21 03, change per Alcan  ---tony
        x12_table(i) := 'REF*RV*' || to_char(item_rec.prod_item_num) ||
                        '*NA';
        i := i + 1;

        --06/05/03 Don't send PO106 AND PO107 incase non sales order available as per Julia
        IF item_rec.sales_order = ' ' THEN
          x12_table(i) := 'PO1**1*UN****' || '***SN*' ||
                          item_rec.coil_org_num;
          i := i + 1;
        ELSE
          x12_table(i) := 'PO1**1*UN***VO*' || item_rec.sales_order ||
                          '***SN*' || item_rec.coil_org_num;
          i := i + 1;
        END IF;

        -- Added partial ready(13), On-hold(4) by Bing Feb-26-2002
        IF item_rec.skid_sheet_status = 2 THEN
          x12_table(i) := 'PID*S*MA*ST*1*' ||
                          to_char(item_rec.sheet_skid_display_num) || '*NA';
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 13 THEN
          x12_table(i) := 'PID*S*MA*ST*8*' ||
                          to_char(item_rec.sheet_skid_display_num) || '*NA';
          i := i + 1;

        ELSIF item_rec.skid_sheet_status = 4 THEN -- Add by Tony to handle rework status 10-28-13
          x12_table(i) := 'PID*S*MA*ST*6*' ||
                          to_char(item_rec.sheet_skid_display_num) || '*NA';
          i := i + 1;

        ELSE
          x12_table(i) := 'PID*S*MA*ST*3*' ||
                          to_char(item_rec.sheet_skid_display_num) || '*NA';
          i := i + 1;
        END IF;

        x12_table(i) := 'PID*S*MAC*ST*01';
        i := i + 1;
        x12_table(i) := 'PID*S*PR*ST*19';
        i := i + 1;
        x12_table(i) := 'MEA*WT*N*' || to_char(item_rec.prod_item_net_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*WT*G*' || to_char(item_rec.skid_gross_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*CT*NA*' || to_char(item_rec.prod_item_pieces) ||
                        '*PC';
        i := i + 1;

        li_hl01 := li_hl01 + 1;

        item_num(k) := item_rec.prod_item_num;
        k := k + 1;

      END LOOP;
      x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
      i := i + 1;
      x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
      i := i + 1;
      x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

      -- Write EDI to file

      IF li_hl01 > 1 THEN
        -- WRITE EDI FILE ONLY IF ITEM > 0
        SELECT edi_file_id_seq.nextval INTO ll_edi_file_id_alcan FROM dual;
        edi_file        := 'S_alcan_' || to_char(ll_edi_file_id_alcan) ||
                           '.870';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        FOR j IN 0 .. i LOOP
          utl_file.put_line(edi_file_handle, x12_table(j));

        END LOOP;
        utl_file.fclose(edi_file_handle);
      END IF; -- END WRITING EDI FILE

      --added by Victor Huang on 12/07 for verifying 997
      INSERT INTO outbound_edi_transaction
        (edi_file_id,
         duns_from,
         duns_to,
         interchange_control_number,
         group_control_number,
         transaction_time,
         edi_file_name,
         fa_receive_status,
         customer_id,
         set_control_num,
         transaction_type_id)
      VALUES
        (ll_edi_file_id_alcan,
         '039630926',
         su_duns,
         ll_gs_log,
         ll_gs_log,
         SYSDATE,
         edi_file,
         0,
         ll_customer_id,
         ll_st_log,
         '870');
      COMMIT;

      edi_file        := 'send_edi_log';
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      FOR m IN 0 .. k - 1 LOOP
        UPDATE production_sheet_item
           SET prod_item_edi870_date = SYSDATE,
               edi_file_id_870 = ll_edi_file_id_alcan /* Alex Gerlants. 09/06/2016. New column */
         WHERE production_sheet_item.prod_item_num = item_num(m);
      END LOOP;

      COMMIT;

    END IF; --end if in select count(*)

  END LOOP; ------ End of outer loop customer_id

EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN;
end edi_alcan_870_rework;
  GRANT EXECUTE ON "DBO"."EDI_ALCAN_870_REWORK" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Procedure EDI_ALCAN_SCRAP_870_BY_JOB
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."EDI_ALCAN_SCRAP_870_BY_JOB" IS

/*
                   DUNS: 01 039630926T
                   Customer: ALCAN(34,35,10,1153)
                   Alcan Rolled Product  	X.121  		  0015049350011G
                   Kingston Duns: 241003755
*/


edi_loc varchar2 (50) := '/templar/templar/incoming/senddata';

--v_edi_text_alcan varchar2(32767);
--edi_loc varchar2(50):='/tmp';
edi_file varchar2 (50) := 'edi_out.txt';
edi_file_prefix varchar2 (50) := 'S_alcan_scrap';
edi_file_handle UTL_FILE.FILE_TYPE;
su_duns varchar2(10);
ll_customer_id  INTEGER;

ll_gs_log integer;
ll_st_log integer;
--scrap_job_num ab_job.ab_job_num%type;
prime_nw coil.net_wt%type;
scrap_nw coil.net_wt%type;
--ll_bsn_log integer;


ls_today varchar2(20):= to_char(sysdate, 'YYYYMMDD');
ls_today_4 varchar2(20):= to_char(sysdate, 'YYMMDD');
ls_now varchar2(20) := to_char(sysdate, 'HH24MI'); -- time in 24 hours format....Tony

ls_po varchar2(20);
ls_so varchar2(30);
--ll_edi_file_id integer;
ll_edi_file_id_alcan integer;

ll_job_count integer;
--coil_of_the_job coil.coil_abc_num%type;
ll_ab_job ab_job.ab_job_num%type;

--ll_onhold_wt coil.net_wt%type;
--ll_reject_wt coil.net_wt%type;
--ll_reband_wt coil.net_wt%type;

--li_customer_id shipment.customer_id%TYPE;
--li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;

--date1 date;
--date2 date;
--coil_ini_date date;


li_HL01 integer;

Cursor cust_cur is
--Add customer id here if you want to send 870 for more customers
SELECT customer_id from customer where customer_id in (1153,1459,2582);


Cursor alcan_870_cur IS
       SELECT a.ab_job_num, b.orig_customer_po, nvl(b.sales_order, ' ') sales_order
       FROM ab_job a, customer_order b
       WHERE (a.order_abc_num = b.order_abc_num) and
             (a.job_status = 0) and
             (b.orig_customer_id = ll_customer_id) and
             (a.scrap_870_date is null);

Cursor coil_info IS
       SELECT process_coil.coil_abc_num, process_coil.process_quantity, coil.coil_alloy2, coil.coil_org_num, nvl(coil.consumed_coil_num, ' ') consumed_coil_num , process_coil.process_end_wt
       FROM process_coil, coil
       WHERE (process_coil.ab_job_num = ll_ab_job) and
             (process_coil.coil_abc_num = coil.coil_abc_num);


TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
 x12_table store_tabletype;
i binary_integer := 0;

TYPE job_num_type IS TABLE OF ab_job.ab_job_num%type INDEX BY BINARY_INTEGER;
job_num job_num_type;
j binary_integer :=0;

--item_rec alcan_870_cur%rowtype;

BEGIN

for cust_rec in cust_cur

loop --- Outer loop of customer_id
     ll_customer_id := cust_rec.customer_id;
     i:=0;
     j:=0;
 --james
     SELECT count(*) into ll_job_count
       FROM ab_job a, customer_order b
       WHERE (a.order_abc_num = b.order_abc_num) and
             (a.job_status = 0) and
             (b.orig_customer_id = ll_customer_id) and
             (a.scrap_870_date is null);

 IF ll_job_count <> 0 THEN

    SELECT edi_st_log_seq.NEXTVAL INTO ll_st_log FROM DUAL;
    SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;

    select customer.customer_duns_number_string into su_duns from customer where customer.customer_id = ll_customer_id;

    x12_table(i) := 'ISA*00*'||'          *00*          *01*039630926T     *09*0015049350011G *'||ls_today_4 ||'*'|| ls_now ||'*U*00401*'||LPAD(to_char(ll_gs_log),9,'0')||'*0*P**'; i := i + 1;
    x12_table(i) := 'GS*RS*039630926T*'||'001504935001' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '004010'; i := i + 1;
    x12_table(i):= 'ST*870*' || to_char(ll_st_log); i := i +1;
    x12_table(i):= 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today || '***' || ls_now || '*****'; i := i +1;
    x12_table(i):= 'DTM*009*' || ls_today || '*' || ls_now; i := i +1;
    x12_table(i) := 'N1*SU**1*' || su_duns ||'*NA'; i := i +1;
    x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926T'; i := i + 1;


    --open alcan_870_cur;
    --fetch alcan_870_cur INTO item_rec;
    --close alcan_870_cur;

    li_HL01 := 1;

    for job_rec IN alcan_870_cur -- job loop
    loop
        ll_ab_job := job_rec.ab_job_num;
        ls_po := job_rec.orig_customer_po;
        ls_so := job_rec.sales_order;
        --ls_po := item_rec.customer_po;
        IF INSTR(ls_po,'-') > 0
        THEN
            ls_po := substr(ls_po, 0, instr(ls_po,'-')-1);
        END IF;


        job_num(j) := ll_ab_job;
        j := j+1;

        for coil_rec IN coil_info   --coil loop
        loop
                SELECT NVL(sum(production_sheet_item.prod_item_net_wt),0) into prime_nw
                FROM production_sheet_item
                WHERE (production_sheet_item.ab_job_num = ll_ab_job) and
                      (production_sheet_item.coil_abc_num = coil_rec.coil_abc_num);

                --ll_onhold_wt := NVL(f_get_coil_onhold_wt(coil_rec.coil_abc_num, coil_rec.process_quantity),0);
                --ll_reband_wt := NVL(f_get_coil_rebanded_wt(coil_rec.coil_abc_num, coil_rec.process_quantity),0);
                --ll_reject_wt := NVL(f_get_coil_rejected_wt(coil_rec.coil_abc_num, coil_rec.process_quantity),0);

                --scrap_nw := coil_rec.process_quantity - ll_onhold_wt - ll_reband_wt - ll_reject_wt - prime_nw;

                scrap_nw := coil_rec.process_quantity - coil_rec.process_end_wt - prime_nw;



                IF scrap_nw > 0 then
                   x12_table(i) := 'HL*'||to_char(li_HL01)||'**I'; i := i +1;


                   --SELECT NVL(ALLOY_TYPE.ALCAN_SCRAP_PO, '6800'||coil_rec.coil_alloy2) into ls_po
                       --FROM ALLOY_TYPE
                     --  WHERE ALLOY_TYPE.ALLOY = coil_rec.coil_alloy2;


                   x12_table(i) := 'PRF*' || ls_po ||'****NA'; i := i+1;
                   x12_table(i) := 'DTM*206*' ||ls_today || '*' || ls_now ||'*ED'; i := i+1;
                   x12_table(i) := 'REF*SE*' || 'T1' ||coil_rec.coil_abc_num || '-' ||to_char(ll_ab_job) ; i := i+1;
                   --x12_table(i) := 'REF*SE*' ||coil_rec.coil_org_num; i := i+1;

                   x12_table(i) := 'REF*IX*' || coil_rec.consumed_coil_num;
                   i := i + 1;


                   x12_table(i) := 'REF*MI*' || to_char(ll_ab_job); i := i+1;
                   --x12_table(i) := 'REF*RV*' ||coil_rec.coil_org_num ||'*NA'; i := i+1;
                   x12_table(i) := 'REF*RV*' || 'T1' || coil_rec.coil_abc_num || '-' || to_char(ll_ab_job) || '*NA'; i := i+1;

                   --x12_table(i) := 'PO1**1*UN****' || '***SN*' ||coil_rec.coil_org_num; i := i+1;


                   IF ls_so = ' ' THEN
                      x12_table(i) := 'PO1**1*UN****' || '***SN*' || coil_rec.coil_org_num;
                      i := i + 1;
                   ELSE
                      x12_table(i) := 'PO1**1*UN***VO*' || ls_so || '***SN*' || coil_rec.coil_org_num;
                      i := i + 1;
                   END IF;


                   x12_table(i) := 'PID*S*MA*ST*S'; i := i+1; -- ST*S for scrap --Tony

                   x12_table(i) := 'PID*S*MAC*ST*05'; i := i+1;
                   --x12_table(i) := 'PID*S*MAC*ST*03'; i := i+1; or this one , need test

                   x12_table(i) := 'PID*S*PR*ST*19'; i := i+1;
                   x12_table(i) := 'MEA*WT*N*' || to_char(scrap_nw) || '*LB*01'; i := i+1;

                   li_HL01 := li_HL01 +1;
                end if; -- end if scrap_nw >0
        end loop; -- end of coil loop
    end loop;     -- end of job loop



    x12_table(i) :=  'CTT*' || to_char(li_HL01 - 1); i := i+1;
    x12_table(i) :=  'SE*' || to_char (i-1) ||'*'|| to_char(ll_st_log); i := i+1;
    x12_table(i) :=  'GE*1*' || to_char (ll_gs_log); i := i+1;
    x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');


-- Write EDI to file

    IF li_HL01 > 1 then --write to file only if items > 0
         SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id_alcan FROM DUAL;
-- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
--                edi_file:= 's_alcan_scrap' || to_char(ll_edi_file_id_alcan) ||'.870';
                edi_file:= edi_file_prefix || to_char(ll_edi_file_id_alcan) ||'.edi';
                edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');

                for j in 0..i loop
                   UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
                                 -- v_edi_text_alcan:=v_edi_text_alcan||x12_table(j)||CHR(10);
                end loop;
         UTL_FILE.FCLOSE(edi_file_handle);
    END IF;

    --added by Victor Huang on 06/05 for function acknowlegement
    --INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
    --VALUES(ll_gs_log, su_duns, sysdate, edi_file);
    --COMMIT;

    --added by Victor Huang on 12/07 for verifying 997

  INSERT INTO outbound_edi_transaction(edi_file_id,duns_from,duns_to,interchange_control_number,
  group_control_number,transaction_time,edi_file_name,fa_receive_status,customer_id,set_control_num,transaction_type_id)
  VALUES(ll_edi_file_id_alcan,'039630926',su_duns,ll_gs_log,ll_gs_log, sysdate, edi_file,0,ll_customer_id,ll_st_log,'870 Scrap');
  COMMIT;

    edi_file := 'send_edi_log';
    edi_file_handle :=utl_file.fopen(edi_loc,edi_file,'a');
    utl_file.put_line(edi_file_handle,'Type: 870 Scrap');
    utl_file.put_line(edi_file_handle,'Sending Time: '||to_char(sysdate, 'MM/DD/YY HH24:MI'));
    utl_file.put_line(edi_file_handle,'Interchange Control #: '||ll_gs_log);
    utl_file.put_line(edi_file_handle,'Group Control #: '||ll_gs_log);
    utl_file.put_line(edi_file_handle,'Set Control #: '||ll_st_log);
    utl_file.put_line(edi_file_handle,'');
    utl_file.put_line(edi_file_handle,'');
    utl_file.fclose(edi_file_handle);



         FOR k in 0..j-1
             LOOP
                UPDATE ab_job set ab_job.scrap_870_date = sysdate
                WHERE ab_job.ab_job_num = job_num(k);
             END LOOP;

         commit;


 END IF;       --end if in select count(*)

 --james

end loop; ------ End of outer loop customer_id


EXCEPTION
     WHEN NO_DATA_FOUND THEN
          DBMS_OUTPUT.put_line('NO DATA FOUND!!!');
          RETURN;
     WHEN UTL_FILE.INVALID_PATH THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN;
     WHEN UTL_FILE.INVALID_MODE THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN;
    WHEN UTL_FILE.INVALID_OPERATION THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN;
    WHEN UTL_FILE.WRITE_ERROR THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN;
    WHEN OTHERS THEN
     UTL_FILE.FCLOSE_ALL;
     DBMS_OUTPUT.put_line('ERROR!!');
      RETURN;
 END;
  GRANT EXECUTE ON "DBO"."EDI_ALCAN_SCRAP_870_BY_JOB" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Procedure EDI_ALERIS_870
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."EDI_ALERIS_870" IS

  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   Customer: Aleris(1980) DUNS:964790856     EDI ID:964790856      QUALIFIER: ZZ
   This version of the stored procedure was copied from production on
   May 23, 2016 by Patrick Reynolds.
   The only main difference between the DEV and PROD version of the stored prcedure is that
   the DEV version had the update section all commented out.
   There was also an additional index (p) variable in the PROD code
   that the DEV version did not have.
   End User: Aleris, Customer ID 1980
   */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR');

  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_prefix VARCHAR2(50) := 'S_aleris_';
  edi_file_handle utl_file.file_type;
  su_duns         VARCHAR2(10);
  ll_customer_id  INTEGER := 1980;
  li_scrap_job_done  INTEGER := 2;

  ll_cur_job ab_job.ab_job_num%TYPE;

  ll_gs_log INTEGER;
  ll_st_log INTEGER;

  ls_today   VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD');
  ls_today_4 VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  ls_now     VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  ls_po VARCHAR2(32);
   ls_enduser_po VARCHAR2(32);
   ls_enduser_item_po VARCHAR2(32);
  ld_scrap_870_date ab_job.scrap_870_date%TYPE;

  ls_coil_org_num coil.coil_org_num%TYPE;
  ls_heat coil.lot_num%TYPE;
  ln_coil_thickness coil.coil_gauge%TYPE;
  ln_width  rectangle.rt_width%TYPE;
  ln_length rectangle.rt_length%TYPE;

  ll_ref_order_abc_num sheet_skid.ref_order_abc_num%TYPE;
  ll_ref_order_abc_item sheet_skid.ref_order_abc_item%TYPE;
  ls_sheet_type order_item.sheet_type%TYPE;

  ll_prime_nw coil.net_wt%TYPE;
  ll_scrap_nw coil.net_wt%TYPE;
  -- ll_process_quantity  coil.net_wt%TYPE;
  -- ll_process_end_wt  coil.net_wt%TYPE;
  lr_theo_unit_wt order_item.theoretical_unit_wt%TYPE;

  --ll_edi_file_id integer;
  ll_edi_file_id_aleris INTEGER;

  ll_item_count INTEGER;
  ll_job_count INTEGER;

  li_hl01 INTEGER;
  li_hllin INTEGER;


  CURSOR cust_cur IS
    SELECT customer_id FROM customer WHERE customer_id IN (1980); ---Add customer id here if you want to send 870 for more customers

  CURSOR job_cur IS
   SELECT UNIQUE production_sheet_item.ab_job_num
    FROM sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil,
           customer_order
     WHERE (sheet_skid.skid_sheet_status IN (2, 8))
       AND (production_sheet_item.prod_item_edi870_date IS NULL)
       AND (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       AND (sheet_skid_detail.prod_item_num =
           production_sheet_item.prod_item_num)
       AND (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       AND (coil.customer_id = 1980)
       AND (sheet_skid.ref_order_abc_num = customer_order.order_abc_num)
   UNION
       SELECT UNIQUE a.ab_job_num
       FROM ab_job a, customer_order b
       WHERE (a.order_abc_num = b.order_abc_num) and
             (a.job_status = 0) and
             (b.orig_customer_id = 1980) and
             (a.scrap_870_date is null);


  CURSOR aleris_870_cur IS
    SELECT production_sheet_item.ab_job_num,
           production_sheet_item.coil_abc_num,
           production_sheet_item.prod_item_pieces,
           production_sheet_item.prod_item_num,
           sheet_skid.sheet_skid_num,
           production_sheet_item.prod_item_net_wt,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_net_wt,
           sheet_skid.skid_pieces,
           coil.coil_org_num,
           coil.lot_num,
           nvl(customer_order.sales_order, ' ') sales_order,
           nvl(customer_order.orig_customer_po, 'NA') customer_po,
           nvl(customer_order.enduser_po, 'NA') enduser_po,
           nvl(order_item.enduser_part_num, ' ') enduser_parts,
           (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
           NULL done
      FROM sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil,
           order_item,
			     ab_job,
           customer_order
     WHERE (sheet_skid.skid_sheet_status IN (2, 4, 7, 8, 13)) -- 2: Ready; 8: Warehouse Ready; 4: onhold 13: Partial Ready
       AND (production_sheet_item.prod_item_edi870_date IS NULL)
       AND (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       AND (sheet_skid_detail.prod_item_num =
           production_sheet_item.prod_item_num)
       AND (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       AND (coil.customer_id = ll_customer_id)
       AND (sheet_skid.ref_order_abc_num = customer_order.order_abc_num)
 		   AND (production_sheet_item.ab_job_num = ab_job.ab_job_num)
		   AND (ab_job.order_abc_num = order_item.order_abc_num)
		   AND (ab_job.order_item_num = order_item.order_item_num)
      AND (production_sheet_item.ab_job_num = ll_cur_job);

      CURSOR aleris_scrap_870_cur IS
       SELECT coil_abc_num,
               NVL(process_quantity, 0) process_quan,
               NVL(process_end_wt, 0) process_end_wt
       FROM process_coil
       WHERE (process_coil.ab_job_num = ll_cur_job);

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;
  item_rec  aleris_870_cur%ROWTYPE;

  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;

  TYPE job_num_type IS TABLE OF ab_job.ab_job_num%type INDEX BY BINARY_INTEGER;
  job_num job_num_type;
  p binary_integer :=0;

BEGIN

  FOR cust_rec IN cust_cur LOOP
    --- Outer loop of customer_id
    ll_customer_id := cust_rec.customer_id;
    i              := 0;
    k              := 0;
    p              := 0;

    SELECT COUNT(*)
      INTO ll_item_count
      FROM sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil,
           customer_order
     WHERE (sheet_skid.skid_sheet_status IN (2, 8)) -- 2: Ready; 8: Warehouse Ready; 13: Partial Ready
       AND (production_sheet_item.prod_item_edi870_date IS NULL)
       AND (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       AND (sheet_skid_detail.prod_item_num =
           production_sheet_item.prod_item_num)
       AND (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       AND (coil.customer_id = ll_customer_id)
       AND (sheet_skid.ref_order_abc_num = customer_order.order_abc_num);

       SELECT count(a.ab_job_num)
       INTO ll_job_count
       FROM ab_job a, customer_order b
       WHERE (a.order_abc_num = b.order_abc_num) and
             (a.job_status = 0) and
             (b.orig_customer_id = 1980) and
             (a.scrap_870_date is null);


    IF (ll_item_count <> 0) or (ll_job_count <> 0)THEN

      SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
      SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;

      SELECT customer.customer_duns_number_string
        INTO su_duns
        FROM customer
       WHERE customer.customer_id = ll_customer_id;

      x12_table(i) := 'ISA*00*' ||
                      '          *00*          *01*039630926T     *ZZ*964790856      *' ||
                      ls_today_4 || '*' || ls_now || '*U*00401*' ||
                      lpad(to_char(ll_gs_log), 9, '0') || '*0*P*>';
      i := i + 1;
      x12_table(i) := 'GS*RS*039630926T*' || '964790856' || '*' || ls_today || '*' ||
                      ls_now || '*' || to_char(ll_gs_log) || '*X*' ||
                      '004010';
      i := i + 1;
      x12_table(i) := 'ST*870*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                      '***' || ls_now || '*****';
      i := i + 1;

      x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926T';
      i := i + 1;

       x12_table(i) := 'N1*MF**1*' || su_duns;
      i := i + 1;

      li_hl01 := 0;


      FOR job_rec IN job_cur LOOP    -- job loop


          ll_cur_job := job_rec.ab_job_num;

          job_num(p) := ll_cur_job;
          p := p + 1;

             SELECT nvl(customer_order.orig_customer_po, 'NA'), nvl(customer_order.enduser_po, 'NA')
              INTO ls_po, ls_enduser_po
              FROM ab_job, customer_order
              WHERE (ab_job.ab_job_num = ll_cur_job)
              and (ab_job.order_abc_num = customer_order.order_abc_num);


        li_hl01 := li_hl01 + 1;

        x12_table(i) := 'HL*' || to_char(li_hl01) || '**O*1';
        i := i + 1;

        x12_table(i) := 'PRF*' || ls_enduser_po || '***' || ls_today;
        i := i + 1;

        li_hl01 := li_hl01 + 1;

         x12_table(i) := 'HL*' || to_char(li_hl01) || '*1*I*1';
        i := i + 1;

        x12_table(i) := 'PRF*RV*300578504';
        i := i + 1;

        li_hllin := li_hl01;



      FOR item_rec IN aleris_870_cur LOOP  -- item loop


        li_hl01 := li_hl01 + 1;

        x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*F';
        i := i + 1;

        ls_po := item_rec.customer_po;
        ls_enduser_item_po := item_rec.enduser_po;

        x12_table(i) := 'PRF*' || ls_enduser_item_po || '***' || ls_today;
        i := i + 1;

        x12_table(i) := 'REF*SE*' || item_rec.sheet_skid_num;
         i := i + 1;

        x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now || '*ES';
        i := i + 1;

        x12_table(i) := 'DTM*206*' || ls_today;
        i := i + 1;


        x12_table(i) := 'PO1**1*UN***VO*' || ls_enduser_item_po ||
                          '*SN*' || item_rec.coil_org_num || '*HN*' || item_rec.lot_num || '***BP*' || item_rec.enduser_parts;
         i := i + 1;


         x12_table(i) := 'PID*S*MAC*ST*01***67';
          i := i + 1;
         x12_table(i) := 'PID*S*22*ST*20***22';
          i := i + 1;

       IF item_rec.skid_sheet_status = 2 THEN
          x12_table(i) := 'PID*S*MA*ST*1***70' ;
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 13 THEN
          x12_table(i) := 'PID*S*MA*ST*8***70';
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 4 THEN
          x12_table(i) := 'PID*S*MA*ST*6***70';
          i := i + 1;
        ELSE
          x12_table(i) := 'PID*S*MA*ST*3***70';
          i := i + 1;
        END IF;

        x12_table(i) := 'PID*S*PR*ST*19***66';
          i := i + 1;


    SELECT MAX(coil_gauge)
      INTO ln_coil_thickness
      FROM coil
     WHERE coil.coil_abc_num IN
           (SELECT coil_abc_num
              FROM production_sheet_item
             WHERE production_sheet_item.prod_item_num IN
                   (SELECT prod_item_num
                      FROM sheet_skid_detail
                     WHERE sheet_skid_detail.sheet_skid_num =
                           item_rec.sheet_skid_num));

    x12_table(i) := 'MEA*PD*TH*' ||
                    TRIM(to_char(ln_coil_thickness, '99999.99')) || '*ED';
    i := i + 1;
    x12_table(i) := 'MEA*PD*TH*' ||
                    TRIM(to_char(ln_coil_thickness * 25.4, '99999.99')) ||
                    '*MB';
    i := i + 1;

    SELECT ss.ref_order_abc_num, ss.ref_order_abc_item
      INTO ll_ref_order_abc_num, ll_ref_order_abc_item
      FROM sheet_skid ss
     WHERE ss.sheet_skid_num = item_rec.sheet_skid_num;

    SELECT sheet_type, NVL(theoretical_unit_wt, 0)
      INTO ls_sheet_type, lr_theo_unit_wt
      FROM order_item
     WHERE order_abc_num = ll_ref_order_abc_num
       AND order_item_num = ll_ref_order_abc_item;

    CASE TRIM(upper(ls_sheet_type))
      WHEN 'RECTANGLE' THEN
        SELECT t.rt_length, t.rt_width
          INTO ln_length, ln_width
          FROM rectangle t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
      WHEN 'PARALLELOGRAM' THEN
        SELECT t.p_length, t.p_width
          INTO ln_length, ln_width
          FROM parallelogram t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
      WHEN 'FENDER' THEN
        SELECT t.fe_length, t.fe_side
          INTO ln_length, ln_width
          FROM fender t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
      WHEN 'CHEVRON' THEN
        SELECT t.ch_length, t.ch_width
          INTO ln_length, ln_width
          FROM chevron t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
      WHEN 'CIRCLE' THEN
        SELECT t.c_diameter, t.c_diameter
          INTO ln_length, ln_width
          FROM circle t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
      WHEN 'TRAPEZOID' THEN
        SELECT t.tr_long_length, t.tr_width
          INTO ln_length, ln_width
          FROM trapezoid t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
      WHEN 'L.TRAPEZOID' THEN
        SELECT t.ltr_long_length, t.ltr_width
          INTO ln_length, ln_width
          FROM left_trapezoid t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
      WHEN 'R.TRAPEZOID' THEN
        SELECT t.rtr_long_length, t.rtr_width
          INTO ln_length, ln_width
          FROM right_trapezoid t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
      WHEN 'REINFORCEMENT' THEN
        SELECT t.re_length, t.re_width
          INTO ln_length, ln_width
          FROM reinforcement t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
      WHEN 'LIFTGATE' THEN
        SELECT t.li_length, t.li_width
          INTO ln_length, ln_width
          FROM liftgate_shape t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
      ELSE
        SELECT t.x_1, t.x_2
          INTO ln_length, ln_width
          FROM x1_shape t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
    END CASE;

    x12_table(i) := 'MEA*PD*WD*' || TRIM(to_char(ln_width, '99999.99')) ||
                    '*ED';
    i := i + 1;

    x12_table(i) := 'MEA*PD*WD*' ||
                    TRIM(to_char(ln_width * 25.4, '99999.99')) || '*MB';
    i := i + 1;

    x12_table(i) := 'MEA*CT*LN*' || TRIM(to_char(ln_length, '99999.99')) ||
                    '*ED';
    i := i + 1;

    x12_table(i) := 'MEA*PD*LN*' ||
                    TRIM(to_char(ln_length * 25.4, '99999.99')) || '*MB'; -- Linear MillMeter
    i := i + 1;

   x12_table(i) := 'MEA*CT*NL*' || to_char(item_rec.prod_item_pieces) ||
                    '*PC';
    i := i + 1;

    x12_table(i) := 'MEA*WT*WT*' || to_char(item_rec.prod_item_pieces * lr_theo_unit_wt, '99999') ||
                    '*24';
    i := i + 1;

    x12_table(i) := 'MEA*WT*WT*' || to_char(item_rec.prod_item_pieces * lr_theo_unit_wt * 0.4536, '99999') || '*53';
    i := i + 1;

    x12_table(i) := 'MEA*WT*WT*' || to_char(item_rec.prod_item_net_wt) ||
                    '*01';
    i := i + 1;

    x12_table(i) := 'MEA*WT*WT*' ||
                    to_char(item_rec.prod_item_net_wt * 0.4536, '99999') || '*50';
    i := i + 1;



 --       x12_table(i) := 'MEA*WT*G*' || to_char(item_rec.skid_gross_wt) ||'*LB*01';
 --       i := i + 1;
 --       x12_table(i) := 'MEA*CT*NA*' || to_char(item_rec.prod_item_pieces) || '*PC';
--        i := i + 1;
        item_num(k) := item_rec.prod_item_num;
        k := k + 1;

      END LOOP;  -- item loop

     SELECT scrap_870_date, job_status
     INTO ld_scrap_870_date, li_scrap_job_done
     FROM ab_job
     WHERE ab_job_num = ll_cur_job;

     IF (ld_scrap_870_date is NULL) AND (li_scrap_job_done = 0) THEN  -- scrap not sent and job is done

      FOR scrap_rec IN aleris_scrap_870_cur LOOP    -- scrap loop

        --scrap info

        SELECT coil_org_num, lot_num
        INTO ls_coil_org_num, ls_heat
        FROM coil
        WHERE coil_abc_num = scrap_rec.coil_abc_num;

        SELECT NVL(sum(production_sheet_item.prod_item_net_wt),0)
        into ll_prime_nw
         FROM production_sheet_item
         WHERE (production_sheet_item.ab_job_num = ll_cur_job) and
               (production_sheet_item.coil_abc_num = scrap_rec.coil_abc_num);


                ll_scrap_nw := scrap_rec.process_quan - scrap_rec.process_end_wt - ll_prime_nw;



                IF ll_scrap_nw > 0 then

                   li_hl01 := li_hl01 + 1;

                   x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*F';
                   i := i + 1;

                   x12_table(i) := 'PRF*' || ls_enduser_po || '***' || ls_today;
                   i := i +1;

                    x12_table(i) := 'PO1**1*UN***VO*' || ls_enduser_po ||
                          '*SN*' || ls_coil_org_num || '*HN*' || ls_heat || '***BP* ';
                     i := i + 1;

                    x12_table(i) := 'PID*S*MAC*ST*05***67';
                    i := i + 1;
                    x12_table(i) := 'PID*S*DAF*ST*3***72';
                     i := i + 1;
                    x12_table(i) := 'PID*S*DAC*ST*258***73';
                     i := i + 1;

                   x12_table(i) := 'MEA*WT*WT*' || to_char(ll_scrap_nw) || '*01';
                   i := i+1;
                   x12_table(i) := 'MEA*WT*WT*' || to_char(ll_scrap_nw * 0.4536, '99999') || '*50';
                   i := i+1;
                 END IF;

        END LOOP;  -- scrap loop
      END IF;  -- scrap not sent


     END LOOP;   -- job loop

      x12_table(i) := 'CTT*' || to_char(li_hl01);
      i := i + 1;
      x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
      i := i + 1;
      x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

      -- Write EDI to file

      IF li_hl01 > 1 THEN
        -- WRITE EDI FILE ONLY IF ITEM > 0
        SELECT edi_file_id_seq.nextval
          INTO ll_edi_file_id_aleris
          FROM dual;
-- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
--        edi_file        := 's_aleris_' || to_char(ll_edi_file_id_aleris) ||
--                           '.870';
         edi_file        := edi_file_prefix || to_char(ll_edi_file_id_aleris) || '.edi';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        FOR j IN 0 .. i LOOP
          utl_file.put_line(edi_file_handle, x12_table(j));

        END LOOP;
        utl_file.fclose(edi_file_handle);
      END IF; -- END WRITING EDI FILE

     --edi_file        := 'send_edi_log'; /* Alex Gerlants. 04/14/2017. Commented out. */
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      --For verifying 997
      INSERT INTO outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
        VALUES
          (ll_edi_file_id_aleris,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           SYSDATE,
           edi_file,
           0,
           ll_customer_id,
           ll_st_log,
           '870');
      --  COMMIT;


 -- Release this commented section
 --    1. when testing the update portion of this stored procedure, or
 --    2. before releasing the SP to PROD.
 -- Patrick Reynolds May 23, 2016

     FOR m IN 0 .. k - 1 LOOP
       UPDATE production_sheet_item
           SET prod_item_edi870_date = SYSDATE,
               edi_file_id_870 = ll_edi_file_id_aleris /* Alex Gerlants. 09/06/2016. New column */
        WHERE production_sheet_item.prod_item_num = item_num(m);
     END LOOP;

--      COMMIT;

       FOR m in 0..p - 1
           LOOP
               UPDATE ab_job set ab_job.scrap_870_date = sysdate
               WHERE ab_job.ab_job_num = job_num(m);
            END LOOP;

      commit;

    END IF; --end if in select count(*)

  END LOOP; ------ End of outer loop customer_id

EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN;
END;
  GRANT EXECUTE ON "DBO"."EDI_ALERIS_870" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Procedure EDI_ARCONIC_861_TEST
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."EDI_ARCONIC_861_TEST" 
(  as_bol            in  inbound_shipment.bol%TYPE, 
   ai_edi_file_id    in  inbound_shipment.edi_file_id%TYPE
)

IS

  /*
  This function creates Arconic EDI 861.
  edi_file_id and bol are from inbound_shipment table, received_time is generated the current moment by the system.
  This function will be called from Coil Receiving after a successful saving
  */

  type edi_861_tabletype is
     table of varchar2(32767) index by binary_integer;
  
  edi_861    edi_861_tabletype;
  j          binary_integer;
  i          integer;
  --skip_edi INTEGER := 1;
  
  --edi_file_prefix VARCHAR2(50) := 'S_arconic_861_'; --Production
  edi_file_prefix VARCHAR2(50) := 's_arconic_861_'; --Development

/*
  CURSOR shipment_cursor IS
    SELECT ss.bol, ss.edi_file_id
      FROM inbound_shipment_status   ss,
           inbound_shipment          s,
           inbound_shipment_customer c
     WHERE ss.edi_file_id = s.edi_file_id
       AND ss.bol = s.bol
       AND s.ship_from = c.ship_from
       and s.bol = as_bol
       AND c.customer_id IN (2784) --ARCONIC-TN
       AND -- customers for 861
           ss.status = 3;
*/          
           
  /*cursor shipment_cursor is
  select bol, edi_file_id
  from inbound_shipment_status
  where status = 3 ;*/

  CURSOR coil_status_cursor(as_bol VARCHAR2) IS
    SELECT distinct status
      FROM inbound_coil_status
     WHERE bol = as_bol
     and edi_file_id = ai_edi_file_id;

  CURSOR bol_and_edi_file_id_cursor IS
    SELECT distinct
           a.coil_number,
           a.temper,
           a.net_weight,
           a.gross_weight,
           a.lineal_feed,
           a.coil_width,
           a.coil_gauge,
           a.density,
           a.lot,
           a.pack_id,
           a.alloy,
           a.ps_coil_number,
           b.damaged_code,
           b.damaged_fault
      FROM inbound_coil a, inbound_coil_status b
     WHERE a.bol = b.bol
       and a.edi_file_id = b.edi_file_id
       AND a.item_num = b.item_num
       and a.bol = as_bol
       AND a.edi_file_id = ai_edi_file_id ;

  li_coil_ready  INTEGER;
  li_gs_log      INTEGER;
  li_st_log      INTEGER;
  ls_today_short VARCHAR2(20);
  ls_today       VARCHAR2(20);
  ls_now         VARCHAR2(20);

  ld_received_time  DATE;
  ls_received_time  VARCHAR2(13);
  li_customer_id    INT;
  ls_vo             VARCHAR2(20);
  ls_coil_number    VARCHAR2(40);
  ls_ps_coil_number VARCHAR2(40);
  ls_temper         VARCHAR2(8);
  ln_net_weight     NUMBER(8, 0);
  ln_gross_weight   NUMBER(8, 0);
  ln_lineal_feed    NUMBER(7, 2);
  ln_coil_width     NUMBER(7, 2);
  ln_coil_gauge     NUMBER(5, 4);
  ln_density        NUMBER;
  ls_lot            VARCHAR2(40);
  ls_pack_id        VARCHAR2(40);
  ls_alloy          VARCHAR2(40);
  ln_damage_fault   NUMBER(1);
  ln_damage_code    NUMBER(3);

  edi_location    VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_handle utl_file.file_type;
  li_edi_861_id   INTEGER;
  ls_dun          VARCHAR2(32);
  ls_ship_from    VARCHAR2(40);

  coil_count INTEGER;

  li_coil_abc_num INTEGER;

  li_count INTEGER;
  
  ls_received_date  VARCHAR2(8);
  li_inbound_shipment_status  inbound_shipment_status.status%TYPE;

  
BEGIN
    
/*
    select    status
    into      li_inbound_shipment_status
    from      inbound_shipment_status
    where     bol = as_bol
    and       edi_file_id = ai_edi_file_id;
    
    if li_inbound_shipment_status = 1 then --861 already created
      return 1;
    end if;
*/    

    li_coil_ready := 0;

    --if not all coils are imported or mark damaged yet, don't send them
    FOR coil_status_cloop IN coil_status_cursor(as_bol) loop
                                                --shipment_cloop.edi_file_id) LOOP
      IF (coil_status_cloop.status = 1 OR coil_status_cloop.status = 2) THEN
        --status 1:imported  2:marked damaged
        li_coil_ready := 1;
      ELSE
        li_coil_ready := 0;
      END IF;
      EXIT WHEN li_coil_ready = 0;
    END LOOP;

    coil_count := 0;
    j          := 0;

    IF (li_coil_ready = 1) THEN
      SELECT edi_st_log_seq.nextval INTO li_st_log FROM dual;
      SELECT edi_gs_log_seq.nextval INTO li_gs_log FROM dual;
      ls_today_short := to_char(SYSDATE, 'yymmdd');
      ls_today       := to_char(SYSDATE, 'yyyymmdd');
      ls_now         := to_char(SYSDATE, 'hh24mi');

      SELECT distinct vo
        INTO ls_vo
        FROM inbound_shipment
       WHERE bol = as_bol;
         --AND edi_file_id = shipment_cloop.edi_file_id;

      /*ld_received_time := sysdate;   --set the received time as current system time*/
      SELECT COUNT(*)
        INTO li_count
        FROM receiving_bol r
       WHERE r.bol = as_bol;

      IF li_count = 1 THEN
        SELECT distinct nvl(r.created_date, sysdate)
          INTO ld_received_time
          FROM receiving_bol r
         WHERE r.bol = as_bol;
      ELSE
        ld_received_time := SYSDATE;
      END IF;
      
      SELECT distinct ship_from
        INTO ls_ship_from
        FROM inbound_shipment
       WHERE bol = as_bol;
         
      SELECT distinct customer_id
        INTO li_customer_id
        FROM inbound_shipment_customer
       WHERE ship_from = ls_ship_from;

      SELECT customer.customer_duns_number_string
        INTO ls_dun
        FROM customer
       WHERE customer.customer_id = li_customer_id;      

      ls_received_time := to_char(ld_received_time, 'yyyymmdd*hh24mi'); --need this format in EDI861 file

      --Production
      --edi_861(j) := 'ISA*00*' ||
      --                '          *00*          *01*039630926T     *09*' || rpad(ls_dun, 15, ' ') || '*' ||
      --                ls_received_time || '*U*00401*' ||
      --                lpad(to_char(li_gs_log), 9, '0') || '*0*P*>';
      
      --Development                
      edi_861(j) := 'ISA*00*' ||
                      '          *00*          *ZZ*2NDSFTP        *ZZ*ARNCQFMW       *' ||
                      ls_received_time || '*U*00401*' ||
                      lpad(to_char(li_gs_log), 9, '0') || '*0*T*>';
                      
      j := j + 1;

      --Production
      --edi_861(j) := 'GS*SH*R0P7A' || 'TN*961613887' || '*' || ls_today || '*' ||
      --                ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                      
      --Development
      edi_861(j) := 'GS*SH*2NDSFTP' || 'TN*ARNCQFMW' || '*' || ls_today || '*' ||
                     ls_now || '*' || to_char(li_gs_log) || '*X*' || '004010';
      j := j + 1;
      
      edi_861(j) := 'ST*861*' || li_st_log;
      j := j + 1;
      
      edi_861(j) := 'BRA*' || as_bol || '*' || ls_today ||
                    '*00*1*' || ls_now;
      j := j + 1;
      
      edi_861(j) := 'REF*MA*' || as_bol;
      j := j + 1;
      
      edi_861(j) := 'DTM*050*' || ls_received_time || '*ED';
      j := j + 1;
      
/*
      SELECT distinct ship_from
        INTO ls_ship_from
        FROM inbound_shipment
       WHERE bol = as_bol;
         
      SELECT distinct customer_id
        INTO li_customer_id
        FROM inbound_shipment_customer
       WHERE ship_from = ls_ship_from;

      SELECT customer.customer_duns_number_string
        INTO ls_dun
        FROM customer
       WHERE customer.customer_id = li_customer_id;
*/
       
      edi_861(j) := 'N1*MF**1*' || ls_dun; --Arconic DUNS
      j := j + 1;
      
      edi_861(j) := 'N1*OU**1*039630926'; --ALBL DUNS
      j := j + 1;

      /*if li_customer_id = 1153 then
         ls_dun := '241003755';--'Novelis Kingston'
      elsif  li_customer_id = 1459 then
         ls_dun := '003980216';--'Novelis Oswego'
      else
         ls_dun := '241003755';
      end if;*/

      edi_861(j) := 'N1*SU**1*' || ls_dun;
      j := j + 1;

      FOR cloop IN bol_and_edi_file_id_cursor() LOOP
        ls_coil_number    := cloop.coil_number;
        ls_temper         := cloop.temper;
        ln_net_weight     := cloop.net_weight;
        ln_gross_weight   := cloop.gross_weight;
        ln_lineal_feed    := cloop.lineal_feed;
        ln_coil_width     := cloop.coil_width;
        ln_coil_gauge     := cloop.coil_gauge;
        ln_density        := cloop.density;
        ls_lot            := cloop.lot;
        ls_pack_id        := cloop.pack_id;
        ls_alloy          := cloop.alloy;
        ls_ps_coil_number := cloop.ps_coil_number;
        ln_damage_fault   := cloop.damaged_fault;
        ln_damage_code    := cloop.damaged_code;

        IF (ls_ps_coil_number IS NULL) OR (length(ls_ps_coil_number) = 0) THEN
          ls_ps_coil_number := ls_coil_number;
        END IF;

        edi_861(j) := 'RCD**1*UN';
        j := j + 1;
        
        edi_861(j) := 'LIN**VO*' || ls_vo || '*VN*01' || '*SN*' || ls_coil_number ||
                      '*HN*' || ls_lot;
        j := j + 1;
        edi_861(j) := 'PID*S*MAC*ST*01***67';
        j := j + 1;
        
        edi_861(j) := 'PID*S*MA*ST*7***70';
        j := j + 1;


        --add these two segments only for damaged coils
/*        
        IF ln_damage_code <> 0 THEN
          edi_861(j) := 'PID*S*DAC*ST*' || ln_damage_code;
          j := j + 1;
        END IF;
        IF ln_damage_fault <> 0 THEN
          edi_861(j) := 'PID*S*DAF*ST*' || ln_damage_fault;
          j := j + 1;
        END IF;

        edi_861(j) := 'PID*S*QAS*ST*2';
        j := j + 1;

*/
        SELECT COUNT(*)
          INTO li_count
          FROM coil c
         WHERE c.coil_org_num = ls_coil_number
           --AND c.coil_mid_num = ls_pack_id
           AND c.customer_id IN (li_customer_id);

        IF li_count = 1 THEN
          SELECT nvl(c.coil_abc_num, 0)
            INTO li_coil_abc_num
            FROM coil c
           WHERE c.coil_org_num = ls_coil_number
             --AND c.coil_mid_num = ls_pack_id
             AND c.customer_id IN (2784);
        ELSE
          li_coil_abc_num := 0;
        END IF;

        edi_861(j) := 'REF*SE*' || li_coil_abc_num;
        j := j + 1;
        
        ls_received_date := to_char(ld_received_time, 'yyyymmdd');
        
        edi_861(j) := 'DTM*206*' || ls_received_date;
        j := j + 1;
        
        --edi_861(j) := 'REF*BM*' || shipment_cloop.bol;
        --j := j + 1;
        
        --edi_861(j) := 'REF*RV*' || ls_ps_coil_number;
        --j := j + 1;
        
        --edi_861(j) := 'PRF*' || ls_vo;
        --j := j + 1;
        
        edi_861(j) := 'MEA*WT**' || ln_net_weight || '*01';
        j := j + 1;
        
        edi_861(j) := 'MEA*WT**' || ln_gross_weight || '*24';
        j := j + 1;
        
        edi_861(j) := 'MEA*PD*TH*' || to_char(ln_coil_gauge, 'FM90.0000') || '*ED';
        j := j + 1;
        edi_861(j) := 'MEA*PD*WD*' || to_char(ln_coil_width, 'FM99990.0000') || '*ED';
        j := j + 1;
        
        edi_861(j) := 'MEA*PD*LN*' || ln_lineal_feed || '*LF';
        j := j + 1;

        coil_count := coil_count + 1;
      END LOOP;

      edi_861(j) := 'CTT*' || coil_count;
      j := j + 1;
      edi_861(j) := 'SE*' || to_char(j - 1) || '*' || li_st_log;
      j := j + 1;
      edi_861(j) := 'GE*1*' || li_gs_log;
      j := j + 1;
      edi_861(j) := 'IEA*1*' || lpad(to_char(li_gs_log), 9, '0');

      IF coil_count > 0 THEN
        --IF skip_edi = 0 THEN
          SELECT edi_file_id_seq.nextval INTO li_edi_861_id FROM dual;
-- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
--          edi_file        := 's_Novelis_' || to_char(li_edi_861_id) || '.861';
          edi_file        := edi_file_prefix || to_char(li_edi_861_id) || '.edi';
          edi_file_handle := utl_file.fopen(edi_location, edi_file, 'W');
          --write edi to file
          FOR i IN 0 .. j LOOP
            utl_file.put_line(edi_file_handle, edi_861(i));
          END LOOP;
          utl_file.fclose(edi_file_handle);
        --END IF;

        /*--added by Victor Huang on 06/05 for function acknowlegement
         INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
         VALUES(li_gs_log, ls_dun, sysdate, edi_file);
         COMMIT;
        */
        --added by Victor Huang on 12/07 for verifying 997
/*        
        INSERT INTO outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
        VALUES
          (li_edi_861_id,
           '039630926',
           ls_dun,
           li_gs_log,
           li_gs_log,
           SYSDATE,
           edi_file,
           0,
           li_customer_id,
           li_st_log,
           '861');
        --COMMIT;
*/        

        edi_file        := 'send_edi_log';
        edi_file_handle := utl_file.fopen(edi_location, edi_file, 'a');
        utl_file.put_line(edi_file_handle, 'Type: 861');
        utl_file.put_line(edi_file_handle,
                          'Sending Time: ' ||
                          to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
        utl_file.put_line(edi_file_handle,
                          'Interchange Control #: ' || li_gs_log);
        utl_file.put_line(edi_file_handle,
                          'Group Control #: ' || li_gs_log);
        utl_file.put_line(edi_file_handle, 'Set Control #: ' || li_st_log);
        utl_file.put_line(edi_file_handle, '');
        utl_file.put_line(edi_file_handle, '');
        utl_file.fclose(edi_file_handle);

/*
        UPDATE inbound_shipment_status
           SET status = 1
         WHERE bol = as_bol
           AND edi_file_id = ai_edi_file_id;

        COMMIT;
*/

      END IF;
    END IF;
  --END LOOP; --loop end for edi_file_id/bol

  return;

EXCEPTION
  WHEN dup_val_on_index THEN
    ROLLBACK;
    RETURN;
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN;

END edi_arconic_861_test;
--------------------------------------------------------
--  DDL for Procedure EDI_ARCONIC_870
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."EDI_ARCONIC_870" (al_ab_job_num ab_job.ab_job_num%TYPE) 

IS

  /*
  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   Customer: Aleris(1980) DUNS:964790856     EDI ID:964790856      QUALIFIER: ZZ

   End User: Aleris, Customer ID 1980
   */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50) := get_edi_destination('EDI_DIR');

  edi_file        VARCHAR2(50) := 'edi_out.txt';
  
  --edi_file_prefix VARCHAR2(50) := 'S_arconic_870_'; --Production
  edi_file_prefix VARCHAR2(50) := 's_arconic_870_'; --Development
  
  edi_file_handle utl_file.file_type;
  su_duns         VARCHAR2(10);
  ll_customer_id  customer.customer_id%TYPE;
  ll_cur_coil     coil.coil_abc_num%TYPE;

--  ll_cur_job ab_job.ab_job_num%TYPE;

  ll_gs_log INTEGER;
  ll_st_log INTEGER;

  ls_today   VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD');
  ls_today_4 VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  ls_now     VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  ls_po VARCHAR2(20);
  ls_finished_goods VARCHAR2(32);
  ls_cust_prod_line VARCHAR2(8);

  ld_scrap_870_date ab_job.scrap_870_date%TYPE;

  ls_coil_org_num coil.coil_org_num%TYPE;
  ls_heat coil.lot_num%TYPE;

--  ll_ref_order_abc_num sheet_skid.ref_order_abc_num%TYPE;
--  ll_ref_order_abc_item sheet_skid.ref_order_abc_item%TYPE;
--  ls_sheet_type order_item.sheet_type%TYPE;

  ll_prime_nw coil.net_wt%TYPE;
  ll_scrap_nw coil.net_wt%TYPE;
--  ll_process_quantity  coil.net_wt%TYPE;
--  ll_process_end_wt  coil.net_wt%TYPE;
--  lr_theo_unit_wt order_item.theoretical_unit_wt%TYPE;

  --ll_edi_file_id integer;
  ll_edi_file_id_aleris INTEGER;

  ll_item_count INTEGER;

  li_hl01 INTEGER;
  li_hllin INTEGER;
  ls_today_2digits_year VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');

  CURSOR cust_cur IS
    SELECT customer_id FROM customer WHERE customer_id IN (1153,1459,2582); ---Add customer id here if you want to send 870 for more customers

  CURSOR coil_cur IS
  SELECT UNIQUE C.COIL_ABC_NUM
  FROM SHEET_SKID_DETAIL SKD
    JOIN SHEET_SKID SK ON SKD.SHEET_SKID_NUM = SK.SHEET_SKID_NUM
    JOIN PRODUCTION_SHEET_ITEM PSI ON SKD.PROD_ITEM_NUM = PSI.PROD_ITEM_NUM
    JOIN COIL C ON PSI.COIL_ABC_NUM = C.COIL_ABC_NUM
    JOIN AB_JOB AB ON SK.AB_JOB_NUM = AB.AB_JOB_NUM
    JOIN CUSTOMER_ORDER CO ON CO.ORDER_ABC_NUM = AB.ORDER_ABC_NUM
  WHERE (AB.JOB_STATUS = 0) AND
    --( C.COIL_STATUS IN (0, 3) ) AND
    ( CO.ORIG_CUSTOMER_ID in (2784) ) AND
    --( PSI.PROD_ITEM_EDI870_DATE is NULL ) AND
    --( C.SCRAP_870_DATE is NULL ) AND
    --( SK.SKID_SHEET_STATUS in (0,2,4,12,13) );
    ( ab.ab_job_num = al_ab_job_num );

  CURSOR alcan_870_cur IS
   SELECT production_sheet_item.ab_job_num,
           production_sheet_item.coil_abc_num,
           production_sheet_item.prod_item_pieces,
           production_sheet_item.prod_item_num,
           sheet_skid.sheet_skid_num,
           production_sheet_item.prod_item_net_wt,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_skid_display_num,
           sheet_skid.sheet_net_wt,
           sheet_skid.skid_pieces,
           coil.coil_org_num,
           coil.lot_num,
           nvl(coil.consumed_coil_num, ' ') consumed_coil,
           nvl(coil.material_num, ' ') material_num,
           nvl(customer_order.sales_order, ' ') sales_order,
           nvl(customer_order.orig_customer_po, 'NA') customer_po,
           nvl(order_item.enduser_part_num, ' ') enduser_parts,
           nvl(order_item.cust_prod_line_id, 'NA') customer_line_id,
           nvl(order_item.finished_goods_material_num, 'NA') finished_goods,
           (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
           NULL done
      FROM sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil,
           order_item,
           ab_job,
           customer_order
     --WHERE (sheet_skid.skid_sheet_status IN (0, 2, 4, 13, 12)) -- 2: Ready; 8: Warehouse Ready; 13: Partial Ready; 7: Partial; 12: Sample; 4: onhold
     --  AND (production_sheet_item.prod_item_edi870_date IS NULL)
     where (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       AND (sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num)
       AND (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       AND (coil.customer_id in (2784))
       AND (sheet_skid.ref_order_abc_num = customer_order.order_abc_num)
       AND (production_sheet_item.ab_job_num = ab_job.ab_job_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (production_sheet_item.coil_abc_num = 215802)
       and ( ab_job.ab_job_num = al_ab_job_num );
     

       CURSOR alcan_scrap_870_cur IS
       SELECT a.coil_abc_num,
              b.coil_org_num,
              a.ab_job_num,
              nvl(b.material_num, ' ') material_num,
               NVL(a.process_quantity, 0) process_quan,
               NVL(a.process_end_wt, 0) process_end_wt
       FROM process_coil a, coil b
       WHERE (b.coil_abc_num = 215802)
         AND (a.coil_abc_num = b.coil_abc_num);
         --AND (a.scrap_870_date is NULL);

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;

  item_rec  alcan_870_cur%ROWTYPE;
  coil_rec  coil_cur%ROWTYPE;

  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;

  TYPE coil_num_type IS TABLE OF coil.coil_abc_num%type INDEX BY BINARY_INTEGER;
  coil_num coil_num_type;
  p binary_integer :=0;

BEGIN

  FOR cust_rec IN cust_cur LOOP
    --- Outer loop of customer_id
    ll_customer_id := cust_rec.customer_id;
    i              := 0;
    k              := 0;
    p              := 0;

  SELECT count(COIL.COIL_ABC_NUM)
  INTO ll_item_count
    FROM AB_JOB,
         COIL,
         PRODUCTION_SHEET_ITEM,
         SHEET_SKID,
         SHEET_SKID_DETAIL,
         CUSTOMER_ORDER
   WHERE ( SHEET_SKID_DETAIL.SHEET_SKID_NUM = SHEET_SKID.SHEET_SKID_NUM ) and
         ( SHEET_SKID_DETAIL.PROD_ITEM_NUM = PRODUCTION_SHEET_ITEM.PROD_ITEM_NUM ) and
         ( COIL.COIL_ABC_NUM = PRODUCTION_SHEET_ITEM.COIL_ABC_NUM ) and
         ( AB_JOB.AB_JOB_NUM = SHEET_SKID.AB_JOB_NUM ) and
         ( AB_JOB.ORDER_ABC_NUM = CUSTOMER_ORDER.ORDER_ABC_NUM ) and
         ( AB_JOB.JOB_STATUS = 0 ) AND
         --(  COIL.COIL_STATUS in (0, 3) ) AND
         ( CUSTOMER_ORDER.ORIG_CUSTOMER_ID in (2784) ) AND
         --( PRODUCTION_SHEET_ITEM.PROD_ITEM_EDI870_DATE is NULL ) AND
         --( COIL.SCRAP_870_DATE is NULL ) AND
         --( SHEET_SKID.SKID_SHEET_STATUS in (0, 2,4,12,13) );
         ( ab_job.ab_job_num = al_ab_job_num );

    IF (ll_item_count <> 0) THEN

      SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
      SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;

      SELECT customer.customer_duns_number_string
        INTO su_duns
        FROM customer
       WHERE customer.customer_id = ll_customer_id;

      --Production
      --x12_table(i) := 'ISA*00*' ||
      --                '          *00*          *01*039630926T     *09*961613887      *' ||
      --                ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
      --                lpad(to_char(ll_gs_log), 9, '0') || '*0*P*>';
      
      --Development                
      x12_table(i) := 'ISA*00*' ||
                      '          *00*          *ZZ*2NDSFTP        *ZZ*ARNCQFMW       *' ||
                      ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                      lpad(to_char(ll_gs_log), 9, '0') || '*0*T*>';
                      
      i := i + 1;

      --Production
      --x12_table(1) := 'GS*SH*R0P7A' || 'TN*961613887' || '*' || ls_today || '*' ||
      --                ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                      
      --Development
      x12_table(1) := 'GS*SH*2NDSFTP' || 'TN*ARNCQFMW' || '*' || ls_today || '*' ||
                     ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                      
      i := i + 1;
      
      x12_table(i) := 'ST*870*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                      '***' || ls_now || '*****';
      i := i + 1;
      x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
      i := i + 1;
      x12_table(i) := 'N1*SU**1*' || su_duns;
      i := i + 1;
      x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926';
      i := i + 1;

      li_hl01 := 0;

      FOR coil_rec IN coil_cur LOOP    -- coil loop
          ll_cur_coil := coil_rec.coil_abc_num;

          coil_num(p) := ll_cur_coil;
          p := p + 1;


        FOR item_rec IN alcan_870_cur LOOP   -- item loop

        li_hl01 := li_hl01 + 1;

        x12_table(i) := 'HL*' || to_char(li_hl01) || '**I';
        i := i + 1;

          SELECT nvl(customer_order.orig_customer_po, 'NA'),
                 nvl(order_item.cust_prod_line_id, 'NA'),
                 nvl(order_item.finished_goods_material_num, 'NA')
          INTO ls_po, ls_cust_prod_line, ls_finished_goods
          FROM   order_item,
                 ab_job,
                 customer_order
         WHERE (ab_job.order_abc_num = customer_order.order_abc_num)
         AND (ab_job.order_abc_num = order_item.order_abc_num)
         AND (ab_job.order_item_num = order_item.order_item_num)
          AND (ab_job.ab_job_num = item_rec.ab_job_num);

        IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
           x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
           i := i + 1;
        END IF;

        x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
        i := i + 1;

        x12_table(i) := 'REF*SE*' || to_char(item_rec.prod_item_num);
        i := i + 1;


        x12_table(i) := 'REF*MI*' || to_char(item_rec.ab_job_num);
        i := i + 1;

        x12_table(i) := 'REF*RV*' || to_char(item_rec.prod_item_num) ||
                        '*NA';
        i := i + 1;

        x12_table(i) := 'REF*IX*' || to_char(item_rec.consumed_coil);
        i := i + 1;

        x12_table(i) := 'PO1**1*UN****' || '***SN*' ||
                          item_rec.coil_org_num || '***VP*' || item_rec.finished_goods;
        i := i + 1;

        IF item_rec.skid_sheet_status = 2 THEN
          x12_table(i) := 'PID*S*MA*ST*1*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 4 THEN
          x12_table(i) := 'PID*S*MA*ST*3*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 13 THEN
          x12_table(i) := 'PID*S*MA*ST*8*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
         ELSE
          x12_table(i) := 'PID*S*MA*ST*4*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        END IF;

        x12_table(i) := 'PID*S*MAC*ST*01';
        i := i + 1;
        x12_table(i) := 'PID*S*PR*ST*19';
        i := i + 1;
        x12_table(i) := 'MEA*WT*N*' || to_char(item_rec.prod_item_net_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*WT*G*' || to_char(item_rec.skid_gross_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*CT*NA*' || to_char(item_rec.prod_item_pieces) ||
                        '*PC';
        i := i + 1;

         item_num(k) := item_rec.prod_item_num;
        k := k + 1;

      END LOOP;  -- item loop

     SELECT scrap_870_date, coil_org_num, lot_num
     INTO ld_scrap_870_date, ls_coil_org_num, ls_heat
     FROM coil
     WHERE coil_abc_num = ll_cur_coil;
     
     ld_scrap_870_date := null; --Alex Gerlants. 01/12/2019. Added to get through

     IF (ld_scrap_870_date is NULL) THEN  -- scrap not sent

      FOR scrap_rec IN alcan_scrap_870_cur LOOP    -- scrap loop

        --scrap info

        SELECT NVL(sum(production_sheet_item.prod_item_net_wt),0)
        into ll_prime_nw
         FROM production_sheet_item
         WHERE (production_sheet_item.ab_job_num = scrap_rec.ab_job_num) and
               (production_sheet_item.coil_abc_num = ll_cur_coil);


          ll_scrap_nw := scrap_rec.process_quan - scrap_rec.process_end_wt - ll_prime_nw;



          IF ll_scrap_nw > 0 then

             li_hl01 := li_hl01 + 1;

             x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*I';
             i := i + 1;

             IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
                x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
                i := i + 1;
             END IF;

             x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
              i := i + 1;

              x12_table(i) := 'PO1**1*UN****' || '***SN*' || scrap_rec.coil_org_num ;
              i := i + 1;

              x12_table(i) := 'PID*S*MA*ST*S';
              i := i + 1;
              x12_table(i) := 'PID*S*MAC*ST*05';
               i := i + 1;
              x12_table(i) := 'PID*S*PR*ST*19';
               i := i + 1;

             x12_table(i) := 'MEA*WT*N*' || to_char(ll_scrap_nw) || '*LB*01';
             i := i+1;
           END IF;

        END LOOP;  -- scrap loop
      END IF;  -- scrap not sent
     END LOOP;   -- coil loop
      x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
      i := i + 1;
      x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
      i := i + 1;
      x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

      -- Write EDI to file

      IF li_hl01 > 1 THEN
        -- WRITE EDI FILE ONLY IF ITEM > 0
        SELECT edi_file_id_seq.nextval
          INTO ll_edi_file_id_aleris
          FROM dual;
        edi_file        := edi_file_prefix || to_char(ll_edi_file_id_aleris) || '.edi';
     -- edi_file        := 's_alcan_' || to_char(ll_edi_file_id_aleris) || '.870';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        FOR j IN 0 .. i LOOP
          utl_file.put_line(edi_file_handle, x12_table(j));

        END LOOP;
        utl_file.fclose(edi_file_handle);
      END IF; -- END WRITING EDI FILE

      --edi_file        := 'send_edi_log'; /* Alex Gerlants. 04/14/2017. Commented out. */
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      --For verifying 997
      INSERT INTO outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
        VALUES
          (ll_edi_file_id_aleris,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           SYSDATE,
           edi_file,
           0,
           ll_customer_id,
           ll_st_log,
           '870');
--         COMMIT;

     FOR m IN 0 .. k - 1 LOOP
       UPDATE production_sheet_item
           SET prod_item_edi870_date = SYSDATE,
               edi_file_id_870 = ll_edi_file_id_aleris /* Alex Gerlants. 09/06/2016. New column */
         WHERE production_sheet_item.prod_item_num = item_num(m);
     END LOOP;

--      COMMIT;

        
        FOR m in 0..p - 1 LOOP
                UPDATE coil
					SET coil.scrap_870_date = sysdate
                WHERE coil.coil_abc_num = coil_num(m);

               UPDATE process_coil
					SET scrap_870_date = sysdate
                WHERE ( coil_abc_num = coil_num(m)) AND (scrap_870_date is NULL);

         END LOOP;
         

        COMMIT;

    END IF; --end if in select count(*)

  END LOOP; ------ End of outer loop customer_id

EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN;
END;
--------------------------------------------------------
--  DDL for Procedure EDI_ARCONIC_870_04302019
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."EDI_ARCONIC_870_04302019" (al_ab_job_num ab_job.ab_job_num%TYPE) 

IS

  /*
  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   Customer: Aleris(1980) DUNS:964790856     EDI ID:964790856      QUALIFIER: ZZ

   End User: Aleris, Customer ID 1980
   */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50) := get_edi_destination('EDI_DIR');

  edi_file        VARCHAR2(50) := 'edi_out.txt';
  
  --edi_file_prefix VARCHAR2(50) := 'S_arconic_870_'; --Production
  edi_file_prefix VARCHAR2(50) := 's_arconic_870_'; --Development
  
  edi_file_handle utl_file.file_type;
  su_duns         VARCHAR2(10);
  ll_customer_id  customer.customer_id%TYPE;
  ll_cur_coil     coil.coil_abc_num%TYPE;

--  ll_cur_job ab_job.ab_job_num%TYPE;

  ll_gs_log INTEGER;
  ll_st_log INTEGER;

  ls_today   VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD');
  ls_today_4 VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  ls_now     VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  ls_po VARCHAR2(20);
  ls_finished_goods VARCHAR2(32);
  ls_cust_prod_line VARCHAR2(8);

  ld_scrap_870_date ab_job.scrap_870_date%TYPE;

  ls_coil_org_num coil.coil_org_num%TYPE;
  ls_heat coil.lot_num%TYPE;

--  ll_ref_order_abc_num sheet_skid.ref_order_abc_num%TYPE;
--  ll_ref_order_abc_item sheet_skid.ref_order_abc_item%TYPE;
--  ls_sheet_type order_item.sheet_type%TYPE;

  ll_prime_nw coil.net_wt%TYPE;
  ll_scrap_nw coil.net_wt%TYPE;
--  ll_process_quantity  coil.net_wt%TYPE;
--  ll_process_end_wt  coil.net_wt%TYPE;
--  lr_theo_unit_wt order_item.theoretical_unit_wt%TYPE;

  --ll_edi_file_id integer;
  ll_edi_file_id_aleris INTEGER;

  ll_item_count INTEGER;

  li_hl01 INTEGER;
  li_hllin INTEGER;
  ls_today_2digits_year VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');

  CURSOR cust_cur IS
    SELECT customer_id FROM customer WHERE customer_id IN (1153,1459,2582); ---Add customer id here if you want to send 870 for more customers

  CURSOR coil_cur IS
  SELECT UNIQUE C.COIL_ABC_NUM
  FROM SHEET_SKID_DETAIL SKD
    JOIN SHEET_SKID SK ON SKD.SHEET_SKID_NUM = SK.SHEET_SKID_NUM
    JOIN PRODUCTION_SHEET_ITEM PSI ON SKD.PROD_ITEM_NUM = PSI.PROD_ITEM_NUM
    JOIN COIL C ON PSI.COIL_ABC_NUM = C.COIL_ABC_NUM
    JOIN AB_JOB AB ON SK.AB_JOB_NUM = AB.AB_JOB_NUM
    JOIN CUSTOMER_ORDER CO ON CO.ORDER_ABC_NUM = AB.ORDER_ABC_NUM
  WHERE (AB.JOB_STATUS = 0) AND
    --( C.COIL_STATUS IN (0, 3) ) AND
    ( CO.ORIG_CUSTOMER_ID in (2784) ) AND
    --( PSI.PROD_ITEM_EDI870_DATE is NULL ) AND
    --( C.SCRAP_870_DATE is NULL ) AND
    --( SK.SKID_SHEET_STATUS in (0,2,4,12,13) );
    ( ab.ab_job_num = al_ab_job_num );

  CURSOR alcan_870_cur IS
   SELECT production_sheet_item.ab_job_num,
           production_sheet_item.coil_abc_num,
           production_sheet_item.prod_item_pieces,
           production_sheet_item.prod_item_num,
           sheet_skid.sheet_skid_num,
           production_sheet_item.prod_item_net_wt,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_skid_display_num,
           sheet_skid.sheet_net_wt,
           sheet_skid.skid_pieces,
           coil.coil_org_num,
           coil.lot_num,
           nvl(coil.consumed_coil_num, ' ') consumed_coil,
           nvl(coil.material_num, ' ') material_num,
           nvl(customer_order.sales_order, ' ') sales_order,
           nvl(customer_order.orig_customer_po, 'NA') customer_po,
           nvl(order_item.enduser_part_num, ' ') enduser_parts,
           nvl(order_item.cust_prod_line_id, 'NA') customer_line_id,
           nvl(order_item.finished_goods_material_num, 'NA') finished_goods,
           (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
           NULL done
      FROM sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil,
           order_item,
           ab_job,
           customer_order
     --WHERE (sheet_skid.skid_sheet_status IN (0, 2, 4, 13, 12)) -- 2: Ready; 8: Warehouse Ready; 13: Partial Ready; 7: Partial; 12: Sample; 4: onhold
     --  AND (production_sheet_item.prod_item_edi870_date IS NULL)
     where (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       AND (sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num)
       AND (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       AND (coil.customer_id in (2784))
       AND (sheet_skid.ref_order_abc_num = customer_order.order_abc_num)
       AND (production_sheet_item.ab_job_num = ab_job.ab_job_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (production_sheet_item.coil_abc_num = 215802)
       and ( ab_job.ab_job_num = al_ab_job_num );
     

       CURSOR alcan_scrap_870_cur IS
       SELECT a.coil_abc_num,
              b.coil_org_num,
              a.ab_job_num,
              nvl(b.material_num, ' ') material_num,
               NVL(a.process_quantity, 0) process_quan,
               NVL(a.process_end_wt, 0) process_end_wt
       FROM process_coil a, coil b
       WHERE (b.coil_abc_num = 215802)
         AND (a.coil_abc_num = b.coil_abc_num);
         --AND (a.scrap_870_date is NULL);

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;

  item_rec  alcan_870_cur%ROWTYPE;
  coil_rec  coil_cur%ROWTYPE;

  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;

  TYPE coil_num_type IS TABLE OF coil.coil_abc_num%type INDEX BY BINARY_INTEGER;
  coil_num coil_num_type;
  p binary_integer :=0;

BEGIN

  FOR cust_rec IN cust_cur LOOP
    --- Outer loop of customer_id
    ll_customer_id := cust_rec.customer_id;
    i              := 0;
    k              := 0;
    p              := 0;

  SELECT count(COIL.COIL_ABC_NUM)
  INTO ll_item_count
    FROM AB_JOB,
         COIL,
         PRODUCTION_SHEET_ITEM,
         SHEET_SKID,
         SHEET_SKID_DETAIL,
         CUSTOMER_ORDER
   WHERE ( SHEET_SKID_DETAIL.SHEET_SKID_NUM = SHEET_SKID.SHEET_SKID_NUM ) and
         ( SHEET_SKID_DETAIL.PROD_ITEM_NUM = PRODUCTION_SHEET_ITEM.PROD_ITEM_NUM ) and
         ( COIL.COIL_ABC_NUM = PRODUCTION_SHEET_ITEM.COIL_ABC_NUM ) and
         ( AB_JOB.AB_JOB_NUM = SHEET_SKID.AB_JOB_NUM ) and
         ( AB_JOB.ORDER_ABC_NUM = CUSTOMER_ORDER.ORDER_ABC_NUM ) and
         ( AB_JOB.JOB_STATUS = 0 ) AND
         --(  COIL.COIL_STATUS in (0, 3) ) AND
         ( CUSTOMER_ORDER.ORIG_CUSTOMER_ID in (2784) ) AND
         --( PRODUCTION_SHEET_ITEM.PROD_ITEM_EDI870_DATE is NULL ) AND
         --( COIL.SCRAP_870_DATE is NULL ) AND
         --( SHEET_SKID.SKID_SHEET_STATUS in (0, 2,4,12,13) );
         ( ab_job.ab_job_num = al_ab_job_num );

    IF (ll_item_count <> 0) THEN

      SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
      SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;

      SELECT customer.customer_duns_number_string
        INTO su_duns
        FROM customer
       WHERE customer.customer_id = ll_customer_id;

      --Production
      --x12_table(i) := 'ISA*00*' ||
      --                '          *00*          *01*039630926T     *09*961613887      *' ||
      --                ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
      --                lpad(to_char(ll_gs_log), 9, '0') || '*0*P*>';
      
      --Development                
      x12_table(i) := 'ISA*00*' ||
                      '          *00*          *ZZ*2NDSFTP        *ZZ*ARNCQFMW       *' ||
                      ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                      lpad(to_char(ll_gs_log), 9, '0') || '*0*T*>';
                      
      i := i + 1;

      --Production
      --x12_table(1) := 'GS*SH*R0P7A' || 'TN*961613887' || '*' || ls_today || '*' ||
      --                ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                      
      --Development
      x12_table(1) := 'GS*SH*2NDSFTP' || 'TN*ARNCQFMW' || '*' || ls_today || '*' ||
                     ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                      
      i := i + 1;
      
      x12_table(i) := 'ST*870*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                      '***' || ls_now || '*****';
      i := i + 1;
      x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
      i := i + 1;
      x12_table(i) := 'N1*SU**1*' || su_duns;
      i := i + 1;
      x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926';
      i := i + 1;

      li_hl01 := 0;

      FOR coil_rec IN coil_cur LOOP    -- coil loop
          ll_cur_coil := coil_rec.coil_abc_num;

          coil_num(p) := ll_cur_coil;
          p := p + 1;


        FOR item_rec IN alcan_870_cur LOOP   -- item loop

        li_hl01 := li_hl01 + 1;

        x12_table(i) := 'HL*' || to_char(li_hl01) || '**I';
        i := i + 1;

          SELECT nvl(customer_order.orig_customer_po, 'NA'),
                 nvl(order_item.cust_prod_line_id, 'NA'),
                 nvl(order_item.finished_goods_material_num, 'NA')
          INTO ls_po, ls_cust_prod_line, ls_finished_goods
          FROM   order_item,
                 ab_job,
                 customer_order
         WHERE (ab_job.order_abc_num = customer_order.order_abc_num)
         AND (ab_job.order_abc_num = order_item.order_abc_num)
         AND (ab_job.order_item_num = order_item.order_item_num)
          AND (ab_job.ab_job_num = item_rec.ab_job_num);

        IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
           x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
           i := i + 1;
        END IF;

        x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
        i := i + 1;

        x12_table(i) := 'REF*SE*' || to_char(item_rec.prod_item_num);
        i := i + 1;


        x12_table(i) := 'REF*MI*' || to_char(item_rec.ab_job_num);
        i := i + 1;

        x12_table(i) := 'REF*RV*' || to_char(item_rec.prod_item_num) ||
                        '*NA';
        i := i + 1;

        x12_table(i) := 'REF*IX*' || to_char(item_rec.consumed_coil);
        i := i + 1;

        x12_table(i) := 'PO1**1*UN****' || '***SN*' ||
                          item_rec.coil_org_num || '***VP*' || item_rec.finished_goods;
        i := i + 1;

        IF item_rec.skid_sheet_status = 2 THEN
          x12_table(i) := 'PID*S*MA*ST*1*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 4 THEN
          x12_table(i) := 'PID*S*MA*ST*3*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 13 THEN
          x12_table(i) := 'PID*S*MA*ST*8*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
         ELSE
          x12_table(i) := 'PID*S*MA*ST*4*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        END IF;

        x12_table(i) := 'PID*S*MAC*ST*01';
        i := i + 1;
        x12_table(i) := 'PID*S*PR*ST*19';
        i := i + 1;
        x12_table(i) := 'MEA*WT*N*' || to_char(item_rec.prod_item_net_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*WT*G*' || to_char(item_rec.skid_gross_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*CT*NA*' || to_char(item_rec.prod_item_pieces) ||
                        '*PC';
        i := i + 1;

         item_num(k) := item_rec.prod_item_num;
        k := k + 1;

      END LOOP;  -- item loop

     SELECT scrap_870_date, coil_org_num, lot_num
     INTO ld_scrap_870_date, ls_coil_org_num, ls_heat
     FROM coil
     WHERE coil_abc_num = ll_cur_coil;
     
     ld_scrap_870_date := null; --Alex Gerlants. 01/12/2019. Added to get through

     IF (ld_scrap_870_date is NULL) THEN  -- scrap not sent

      FOR scrap_rec IN alcan_scrap_870_cur LOOP    -- scrap loop

        --scrap info

        SELECT NVL(sum(production_sheet_item.prod_item_net_wt),0)
        into ll_prime_nw
         FROM production_sheet_item
         WHERE (production_sheet_item.ab_job_num = scrap_rec.ab_job_num) and
               (production_sheet_item.coil_abc_num = ll_cur_coil);


          ll_scrap_nw := scrap_rec.process_quan - scrap_rec.process_end_wt - ll_prime_nw;



          IF ll_scrap_nw > 0 then

             li_hl01 := li_hl01 + 1;

             x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*I';
             i := i + 1;

             IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
                x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
                i := i + 1;
             END IF;

             x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
              i := i + 1;

              x12_table(i) := 'PO1**1*UN****' || '***SN*' || scrap_rec.coil_org_num ;
              i := i + 1;

              x12_table(i) := 'PID*S*MA*ST*S';
              i := i + 1;
              x12_table(i) := 'PID*S*MAC*ST*05';
               i := i + 1;
              x12_table(i) := 'PID*S*PR*ST*19';
               i := i + 1;

             x12_table(i) := 'MEA*WT*N*' || to_char(ll_scrap_nw) || '*LB*01';
             i := i+1;
           END IF;

        END LOOP;  -- scrap loop
      END IF;  -- scrap not sent
     END LOOP;   -- coil loop
      x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
      i := i + 1;
      x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
      i := i + 1;
      x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

      -- Write EDI to file

      IF li_hl01 > 1 THEN
        -- WRITE EDI FILE ONLY IF ITEM > 0
        SELECT edi_file_id_seq.nextval
          INTO ll_edi_file_id_aleris
          FROM dual;
        edi_file        := edi_file_prefix || to_char(ll_edi_file_id_aleris) || '.edi';
     -- edi_file        := 's_alcan_' || to_char(ll_edi_file_id_aleris) || '.870';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        FOR j IN 0 .. i LOOP
          utl_file.put_line(edi_file_handle, x12_table(j));

        END LOOP;
        utl_file.fclose(edi_file_handle);
      END IF; -- END WRITING EDI FILE

      --edi_file        := 'send_edi_log'; /* Alex Gerlants. 04/14/2017. Commented out. */
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      --For verifying 997
      INSERT INTO outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
        VALUES
          (ll_edi_file_id_aleris,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           SYSDATE,
           edi_file,
           0,
           ll_customer_id,
           ll_st_log,
           '870');
--         COMMIT;

     FOR m IN 0 .. k - 1 LOOP
       UPDATE production_sheet_item
           SET prod_item_edi870_date = SYSDATE,
               edi_file_id_870 = ll_edi_file_id_aleris /* Alex Gerlants. 09/06/2016. New column */
         WHERE production_sheet_item.prod_item_num = item_num(m);
     END LOOP;

--      COMMIT;

        
        FOR m in 0..p - 1 LOOP
                UPDATE coil
					SET coil.scrap_870_date = sysdate
                WHERE coil.coil_abc_num = coil_num(m);

               UPDATE process_coil
					SET scrap_870_date = sysdate
                WHERE ( coil_abc_num = coil_num(m)) AND (scrap_870_date is NULL);

         END LOOP;
         

        COMMIT;

    END IF; --end if in select count(*)

  END LOOP; ------ End of outer loop customer_id

EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN;
END;
--------------------------------------------------------
--  DDL for Procedure EDI_ARCONIC_870_ALEX
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."EDI_ARCONIC_870_ALEX" IS

  /*
  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   Customer: Aleris(1980) DUNS:964790856     EDI ID:964790856      QUALIFIER: ZZ

   End User: Aleris, Customer ID 1980
   */

  --Alex Gerlants. 11/19/2018. Initial release
  --Copied from edi_alcan_870
  edi_loc VARCHAR2(50) := get_edi_destination('EDI_DIR');

  edi_file        VARCHAR2(50) := 'edi_out.txt';
  --edi_file_prefix VARCHAR2(50) := 'S_arconic_870_';
  edi_file_prefix VARCHAR2(50) := 's_arconic_870_';
  edi_file_handle utl_file.file_type;
  su_duns         VARCHAR2(10);
  ll_customer_id  customer.customer_id%TYPE;
  ll_cur_coil     coil.coil_abc_num%TYPE;

--  ll_cur_job ab_job.ab_job_num%TYPE;

  ll_gs_log INTEGER;
  ll_st_log INTEGER;

  ls_today   VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD');
  --ls_today_4 VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  ls_now     VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  ls_po VARCHAR2(20);
  ls_finished_goods VARCHAR2(32);
  ls_cust_prod_line VARCHAR2(8);

  ld_scrap_870_date ab_job.scrap_870_date%TYPE;

  ls_coil_org_num coil.coil_org_num%TYPE;
  ls_heat coil.lot_num%TYPE;

--  ll_ref_order_abc_num sheet_skid.ref_order_abc_num%TYPE;
--  ll_ref_order_abc_item sheet_skid.ref_order_abc_item%TYPE;
--  ls_sheet_type order_item.sheet_type%TYPE;

  ll_prime_nw coil.net_wt%TYPE;
  ll_scrap_nw coil.net_wt%TYPE;
--  ll_process_quantity  coil.net_wt%TYPE;
--  ll_process_end_wt  coil.net_wt%TYPE;
--  lr_theo_unit_wt order_item.theoretical_unit_wt%TYPE;

  --ll_edi_file_id integer;
  ll_edi_file_id INTEGER;

  ll_item_count INTEGER;

  li_hl01 INTEGER;
  li_hllin INTEGER;

  CURSOR cust_cur IS
    --SELECT customer_id FROM customer WHERE customer_id IN (1153,1459,2582); ---Add customer id here if you want to send 870 for more customers
    select customer_id from customer where lower(customer_short_name) like'%arconic%';

  CURSOR coil_cur IS
  SELECT UNIQUE C.COIL_ABC_NUM
  FROM SHEET_SKID_DETAIL SKD
    JOIN SHEET_SKID SK ON SKD.SHEET_SKID_NUM = SK.SHEET_SKID_NUM
    JOIN PRODUCTION_SHEET_ITEM PSI ON SKD.PROD_ITEM_NUM = PSI.PROD_ITEM_NUM
    JOIN COIL C ON PSI.COIL_ABC_NUM = C.COIL_ABC_NUM
    JOIN AB_JOB AB ON SK.AB_JOB_NUM = AB.AB_JOB_NUM
    JOIN CUSTOMER_ORDER CO ON CO.ORDER_ABC_NUM = AB.ORDER_ABC_NUM
  WHERE (AB.JOB_STATUS = 0) AND
    ( C.COIL_STATUS IN (0, 3) ) AND
    ( CO.ORIG_CUSTOMER_ID = ll_customer_id ) AND
    ( PSI.PROD_ITEM_EDI870_DATE is NULL ) AND
    ( C.SCRAP_870_DATE is NULL ) AND
    ( SK.SKID_SHEET_STATUS in (0,2,4,12,13) 
    and (c.coil_abc_num = 103546) --Testing
    );

  CURSOR alcan_870_cur IS
   SELECT production_sheet_item.ab_job_num,
           production_sheet_item.coil_abc_num,
           production_sheet_item.prod_item_pieces,
           production_sheet_item.prod_item_num,
           sheet_skid.sheet_skid_num,
           production_sheet_item.prod_item_net_wt,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_skid_display_num,
           sheet_skid.sheet_net_wt,
           sheet_skid.skid_pieces,
           coil.coil_org_num,
           coil.lot_num,
           nvl(coil.consumed_coil_num, ' ') consumed_coil,
           nvl(coil.material_num, ' ') material_num,
           nvl(customer_order.sales_order, ' ') sales_order,
           nvl(customer_order.orig_customer_po, 'NA') customer_po,
           nvl(order_item.enduser_part_num, ' ') enduser_parts,
           nvl(order_item.cust_prod_line_id, 'NA') customer_line_id,
           nvl(order_item.finished_goods_material_num, 'NA') finished_goods,
           (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
           NULL done
      FROM sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil,
           order_item,
           ab_job,
           customer_order
     WHERE (sheet_skid.skid_sheet_status IN (0, 2, 4, 13, 12)) -- 2: Ready; 8: Warehouse Ready; 13: Partial Ready; 7: Partial; 12: Sample; 4: onhold
       AND (production_sheet_item.prod_item_edi870_date IS NULL)
       AND (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       AND (sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num)
       AND (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       AND (coil.customer_id = ll_customer_id)
       AND (sheet_skid.ref_order_abc_num = customer_order.order_abc_num)
       AND (production_sheet_item.ab_job_num = ab_job.ab_job_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (production_sheet_item.coil_abc_num = ll_cur_coil);

       CURSOR alcan_scrap_870_cur IS
       SELECT a.coil_abc_num,
              b.coil_org_num,
              a.ab_job_num,
              nvl(b.material_num, ' ') material_num,
               NVL(a.process_quantity, 0) process_quan,
               NVL(a.process_end_wt, 0) process_end_wt
       FROM process_coil a, coil b
       WHERE (b.coil_abc_num = ll_cur_coil)
         AND (a.coil_abc_num = b.coil_abc_num)
         AND (a.scrap_870_date is NULL);

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;

  item_rec  alcan_870_cur%ROWTYPE;
  coil_rec  coil_cur%ROWTYPE;

  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;

  TYPE coil_num_type IS TABLE OF coil.coil_abc_num%type INDEX BY BINARY_INTEGER;
  coil_num coil_num_type;
  p binary_integer :=0;

BEGIN

  FOR cust_rec IN cust_cur LOOP
    --- Outer loop of customer_id
    ll_customer_id := cust_rec.customer_id;
    i              := 0;
    k              := 0;
    p              := 0;

  SELECT count(COIL.COIL_ABC_NUM)
  INTO ll_item_count
    FROM AB_JOB,
         COIL,
         PRODUCTION_SHEET_ITEM,
         SHEET_SKID,
         SHEET_SKID_DETAIL,
         CUSTOMER_ORDER
   WHERE ( SHEET_SKID_DETAIL.SHEET_SKID_NUM = SHEET_SKID.SHEET_SKID_NUM ) and
         ( SHEET_SKID_DETAIL.PROD_ITEM_NUM = PRODUCTION_SHEET_ITEM.PROD_ITEM_NUM ) and
         ( COIL.COIL_ABC_NUM = PRODUCTION_SHEET_ITEM.COIL_ABC_NUM ) and
         ( AB_JOB.AB_JOB_NUM = SHEET_SKID.AB_JOB_NUM ) and
         ( AB_JOB.ORDER_ABC_NUM = CUSTOMER_ORDER.ORDER_ABC_NUM ) and
         ( AB_JOB.JOB_STATUS = 0 ) AND
         (  COIL.COIL_STATUS in (0, 3) ) AND
         ( CUSTOMER_ORDER.ORIG_CUSTOMER_ID = ll_customer_id ) AND
         ( PRODUCTION_SHEET_ITEM.PROD_ITEM_EDI870_DATE is NULL ) AND
         ( COIL.SCRAP_870_DATE is NULL ) AND
         ( SHEET_SKID.SKID_SHEET_STATUS in (0, 2,4,12,13) 
         and (coil.coil_abc_num = 103546) --Testing
         );

    IF (ll_item_count <> 0) THEN

      SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
      SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;

      SELECT customer.customer_duns_number_string
        INTO su_duns
        FROM customer
       WHERE customer.customer_id = ll_customer_id;

      --Original code
      --x12_table(i) := 'ISA*00*' ||
      --                '          *00*          *01*039630926T     *09*0015049350011G *' ||
      --                ls_today_4 || '*' || ls_now || '*U*00401*' ||
      --                lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
                      
                      
      --Production
      --x12_table(i) := 'ISA*00*' ||
      --                '          *00*          *01*039630926T     *ZZ*ARNCQFMW      *' ||
      --                ls_today || '*' || ls_now || '*U*00200*' ||
      --                lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
      
      --Development                
      x12_table(i) := 'ISA*00*' ||
                      '          *00*          *ZZ*2NDSFTP        *ZZ*ARNCQFMW      *' ||
                      ls_today || '*' || ls_now || '*U*00200*' ||
                      lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';
                      
      i := i + 1;
      
      --Original code
      --x12_table(i) := 'GS*RS*039630926T*' || '001504935001' || '*' ||
      --                ls_today || '*' || ls_now || '*' ||
      --                to_char(ll_gs_log) || '*X*' || '004010';
      
      
      --Production
      --x12_table(1) := 'GS*RC*039630926TTN*' || 'ARNCQFMW' || '*' || ls_today || '*' ||
      --                ls_now || '*' || to_char(ll_gs_log) || '*X*' || '002002';
      
      --Development                
      x12_table(1) := 'GS*RC*2NDSFTPTN*' || 'ARNCQFMW' || '*' || ls_today || '*' ||
                      ls_now || '*' || to_char(ll_gs_log) || '*X*' || '002002';
      
      i := i + 1;
      
      x12_table(i) := 'ST*870*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                      '***' || ls_now || '*****';
      i := i + 1;
      x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
      i := i + 1;
      x12_table(i) := 'N1*SU**1*' || su_duns;
      i := i + 1;
      x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926';
      i := i + 1;

      li_hl01 := 0;

      FOR coil_rec IN coil_cur LOOP    -- coil loop
          ll_cur_coil := coil_rec.coil_abc_num;

          coil_num(p) := ll_cur_coil;
          p := p + 1;


        FOR item_rec IN alcan_870_cur LOOP   -- item loop

        li_hl01 := li_hl01 + 1;

        x12_table(i) := 'HL*' || to_char(li_hl01) || '**I';
        i := i + 1;

              SELECT nvl(customer_order.orig_customer_po, 'NA'),
                     nvl(order_item.cust_prod_line_id, 'NA'),
                     nvl(order_item.finished_goods_material_num, 'NA')
              INTO ls_po, ls_cust_prod_line, ls_finished_goods
              FROM   order_item,
                     ab_job,
                     customer_order
             WHERE (ab_job.order_abc_num = customer_order.order_abc_num)
             AND (ab_job.order_abc_num = order_item.order_abc_num)
             AND (ab_job.order_item_num = order_item.order_item_num)
              AND (ab_job.ab_job_num = item_rec.ab_job_num);

        IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
           x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
           i := i + 1;
        END IF;

        x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
        i := i + 1;

        x12_table(i) := 'REF*SE*' || to_char(item_rec.prod_item_num);
        i := i + 1;


        x12_table(i) := 'REF*MI*' || to_char(item_rec.ab_job_num);
        i := i + 1;

        x12_table(i) := 'REF*RV*' || to_char(item_rec.prod_item_num) ||
                        '*NA';
        i := i + 1;

        x12_table(i) := 'REF*IX*' || to_char(item_rec.consumed_coil);
        i := i + 1;

        x12_table(i) := 'PO1**1*UN****' || '***SN*' ||
                          item_rec.coil_org_num || '***VP*' || item_rec.finished_goods;
        i := i + 1;

        IF item_rec.skid_sheet_status = 2 THEN
          x12_table(i) := 'PID*S*MA*ST*1*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 4 THEN
          x12_table(i) := 'PID*S*MA*ST*3*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 13 THEN
          x12_table(i) := 'PID*S*MA*ST*8*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
         ELSE
          x12_table(i) := 'PID*S*MA*ST*4*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        END IF;

        x12_table(i) := 'PID*S*MAC*ST*01';
        i := i + 1;
        x12_table(i) := 'PID*S*PR*ST*19';
        i := i + 1;
        x12_table(i) := 'MEA*WT*N*' || to_char(item_rec.prod_item_net_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*WT*G*' || to_char(item_rec.skid_gross_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*CT*NA*' || to_char(item_rec.prod_item_pieces) ||
                        '*PC';
        i := i + 1;

         item_num(k) := item_rec.prod_item_num;
        k := k + 1;

      END LOOP;  -- item loop

     SELECT scrap_870_date, coil_org_num, lot_num
     INTO ld_scrap_870_date, ls_coil_org_num, ls_heat
     FROM coil
     WHERE coil_abc_num = ll_cur_coil;

     IF (ld_scrap_870_date is NULL) THEN  -- scrap not sent

      FOR scrap_rec IN alcan_scrap_870_cur LOOP    -- scrap loop

        --scrap info

        SELECT NVL(sum(production_sheet_item.prod_item_net_wt),0)
        into ll_prime_nw
         FROM production_sheet_item
         WHERE (production_sheet_item.ab_job_num = scrap_rec.ab_job_num) and
               (production_sheet_item.coil_abc_num = ll_cur_coil);


                ll_scrap_nw := scrap_rec.process_quan - scrap_rec.process_end_wt - ll_prime_nw;



                IF ll_scrap_nw > 0 then

                   li_hl01 := li_hl01 + 1;

                   x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*I';
                   i := i + 1;

                   IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
                      x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
                      i := i + 1;
                   END IF;

                   x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
                    i := i + 1;

                    x12_table(i) := 'PO1**1*UN****' || '***SN*' || scrap_rec.coil_org_num ;
                    i := i + 1;

                    x12_table(i) := 'PID*S*MA*ST*S';
                    i := i + 1;
                    x12_table(i) := 'PID*S*MAC*ST*05';
                     i := i + 1;
                    x12_table(i) := 'PID*S*PR*ST*19';
                     i := i + 1;

                   x12_table(i) := 'MEA*WT*N*' || to_char(ll_scrap_nw) || '*LB*01';
                   i := i+1;
                 END IF;

        END LOOP;  -- scrap loop
      END IF;  -- scrap not sent
     END LOOP;   -- coil loop
      x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
      i := i + 1;
      x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
      i := i + 1;
      x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

      -- Write EDI to file

      IF li_hl01 > 1 THEN
        -- WRITE EDI FILE ONLY IF ITEM > 0
        SELECT edi_file_id_seq.nextval
          INTO ll_edi_file_id
          FROM dual;
        edi_file        := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';
     -- edi_file        := 's_alcan_' || to_char(ll_edi_file_id) || '.870';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        FOR j IN 0 .. i LOOP
          utl_file.put_line(edi_file_handle, x12_table(j));

        END LOOP;
        utl_file.fclose(edi_file_handle);
      END IF; -- END WRITING EDI FILE

      --edi_file        := 'send_edi_log'; /* Alex Gerlants. 04/14/2017. Commented out. */
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      --For verifying 997
      /* Alex Gerlants. Commented out for testing. Begin
      
      INSERT INTO outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
        VALUES
          (ll_edi_file_id,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           SYSDATE,
           edi_file,
           0,
           ll_customer_id,
           ll_st_log,
           '870');

     
     FOR m IN 0 .. k - 1 LOOP
       UPDATE production_sheet_item
           SET prod_item_edi870_date = SYSDATE,
               edi_file_id_870 = ll_edi_file_id
         WHERE production_sheet_item.prod_item_num = item_num(m);
     END LOOP;


     FOR m in 0..p - 1 LOOP
                UPDATE coil
					SET coil.scrap_870_date = sysdate
                WHERE coil.coil_abc_num = coil_num(m);

               UPDATE process_coil
					SET scrap_870_date = sysdate
                WHERE ( coil_abc_num = coil_num(m)) AND (scrap_870_date is NULL);

      END LOOP;

      COMMIT;
      */ -- Alex Gerlants. Commented out for testing. End
      
    END IF; --end if in select count(*)
      
  END LOOP; ------ End of outer loop customer_id

EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN;
END;
--------------------------------------------------------
--  DDL for Procedure EDI_ARCONIC_870_ONE_JOB
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."EDI_ARCONIC_870_ONE_JOB" IS

  /*
  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   Customer: Aleris(1980) DUNS:964790856     EDI ID:964790856      QUALIFIER: ZZ

   End User: Aleris, Customer ID 1980
   */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50) := get_edi_destination('EDI_DIR');

  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_prefix VARCHAR2(50) := 's_arconic_870_one_job_';
  edi_file_handle utl_file.file_type;
  su_duns         VARCHAR2(10);
  ll_customer_id  customer.customer_id%TYPE;
  ll_cur_coil     coil.coil_abc_num%TYPE;

--  ll_cur_job ab_job.ab_job_num%TYPE;

  ll_gs_log INTEGER;
  ll_st_log INTEGER;

  ls_today   VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD');
  ls_today_4 VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  ls_now     VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  ls_po VARCHAR2(20);
  ls_finished_goods VARCHAR2(32);
  ls_cust_prod_line VARCHAR2(8);

  ld_scrap_870_date ab_job.scrap_870_date%TYPE;

  ls_coil_org_num coil.coil_org_num%TYPE;
  ls_heat coil.lot_num%TYPE;

--  ll_ref_order_abc_num sheet_skid.ref_order_abc_num%TYPE;
--  ll_ref_order_abc_item sheet_skid.ref_order_abc_item%TYPE;
--  ls_sheet_type order_item.sheet_type%TYPE;

  ll_prime_nw coil.net_wt%TYPE;
  ll_scrap_nw coil.net_wt%TYPE;
--  ll_process_quantity  coil.net_wt%TYPE;
--  ll_process_end_wt  coil.net_wt%TYPE;
--  lr_theo_unit_wt order_item.theoretical_unit_wt%TYPE;

  --ll_edi_file_id integer;
  ll_edi_file_id_aleris INTEGER;

  ll_item_count INTEGER;

  li_hl01 INTEGER;
  li_hllin INTEGER;
  
  ls_today_2digits_year VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');

  CURSOR cust_cur IS
    SELECT customer_id FROM customer WHERE customer_id IN (2784); ---Add customer id here if you want to send 870 for more customers

  CURSOR coil_cur IS
  SELECT UNIQUE C.COIL_ABC_NUM
  FROM SHEET_SKID_DETAIL SKD
    JOIN SHEET_SKID SK ON SKD.SHEET_SKID_NUM = SK.SHEET_SKID_NUM
    JOIN PRODUCTION_SHEET_ITEM PSI ON SKD.PROD_ITEM_NUM = PSI.PROD_ITEM_NUM
    JOIN COIL C ON PSI.COIL_ABC_NUM = C.COIL_ABC_NUM
    JOIN AB_JOB AB ON SK.AB_JOB_NUM = AB.AB_JOB_NUM
    JOIN CUSTOMER_ORDER CO ON CO.ORDER_ABC_NUM = AB.ORDER_ABC_NUM
  WHERE (AB.JOB_STATUS = 0) AND
    --( C.COIL_STATUS IN (0, 3) ) AND
    ( CO.ORIG_CUSTOMER_ID in (2784) ) AND
    --( PSI.PROD_ITEM_EDI870_DATE is NULL ) AND
    --( C.SCRAP_870_DATE is NULL ) AND
    --( SK.SKID_SHEET_STATUS in (0,2,4,12,13) );
    ( ab.ab_job_num = 105938 );

  CURSOR alcan_870_cur IS
   SELECT production_sheet_item.ab_job_num,
           production_sheet_item.coil_abc_num,
           production_sheet_item.prod_item_pieces,
           production_sheet_item.prod_item_num,
           sheet_skid.sheet_skid_num,
           production_sheet_item.prod_item_net_wt,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_skid_display_num,
           sheet_skid.sheet_net_wt,
           sheet_skid.skid_pieces,
           coil.coil_org_num,
           coil.lot_num,
           nvl(coil.consumed_coil_num, ' ') consumed_coil,
           nvl(coil.material_num, ' ') material_num,
           nvl(customer_order.sales_order, ' ') sales_order,
           nvl(customer_order.orig_customer_po, 'NA') customer_po,
           nvl(order_item.enduser_part_num, ' ') enduser_parts,
           nvl(order_item.cust_prod_line_id, 'NA') customer_line_id,
           nvl(order_item.finished_goods_material_num, 'NA') finished_goods,
           (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
           NULL done
      FROM sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil,
           order_item,
           ab_job,
           customer_order
     --WHERE (sheet_skid.skid_sheet_status IN (0, 2, 4, 13, 12)) -- 2: Ready; 8: Warehouse Ready; 13: Partial Ready; 7: Partial; 12: Sample; 4: onhold
     --  AND (production_sheet_item.prod_item_edi870_date IS NULL)
     where (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       AND (sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num)
       AND (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       AND (coil.customer_id in (2784))
       AND (sheet_skid.ref_order_abc_num = customer_order.order_abc_num)
       AND (production_sheet_item.ab_job_num = ab_job.ab_job_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       --AND (production_sheet_item.coil_abc_num = 215802)
       and ( ab_job.ab_job_num = 105938 );
     

       CURSOR alcan_scrap_870_cur IS
       SELECT a.coil_abc_num,
              b.coil_org_num,
              a.ab_job_num,
              nvl(b.material_num, ' ') material_num,
               NVL(a.process_quantity, 0) process_quan,
               NVL(a.process_end_wt, 0) process_end_wt
       FROM process_coil a, coil b
       WHERE (b.coil_abc_num = ll_cur_coil)
         AND (a.coil_abc_num = b.coil_abc_num);
         --AND (a.scrap_870_date is NULL);

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;

  item_rec  alcan_870_cur%ROWTYPE;
  coil_rec  coil_cur%ROWTYPE;

  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;

  TYPE coil_num_type IS TABLE OF coil.coil_abc_num%type INDEX BY BINARY_INTEGER;
  coil_num coil_num_type;
  p binary_integer :=0;

BEGIN

  FOR cust_rec IN cust_cur LOOP
    --- Outer loop of customer_id
    ll_customer_id := cust_rec.customer_id;
    i              := 0;
    k              := 0;
    p              := 0;

  SELECT count(COIL.COIL_ABC_NUM)
  INTO ll_item_count
    FROM AB_JOB,
         COIL,
         PRODUCTION_SHEET_ITEM,
         SHEET_SKID,
         SHEET_SKID_DETAIL,
         CUSTOMER_ORDER
   WHERE ( SHEET_SKID_DETAIL.SHEET_SKID_NUM = SHEET_SKID.SHEET_SKID_NUM ) and
         ( SHEET_SKID_DETAIL.PROD_ITEM_NUM = PRODUCTION_SHEET_ITEM.PROD_ITEM_NUM ) and
         ( COIL.COIL_ABC_NUM = PRODUCTION_SHEET_ITEM.COIL_ABC_NUM ) and
         ( AB_JOB.AB_JOB_NUM = SHEET_SKID.AB_JOB_NUM ) and
         ( AB_JOB.ORDER_ABC_NUM = CUSTOMER_ORDER.ORDER_ABC_NUM ) and
         ( AB_JOB.JOB_STATUS = 0 ) AND
         --(  COIL.COIL_STATUS in (0, 3) ) AND
         ( CUSTOMER_ORDER.ORIG_CUSTOMER_ID in (2784) ) AND
         --( PRODUCTION_SHEET_ITEM.PROD_ITEM_EDI870_DATE is NULL ) AND
         --( COIL.SCRAP_870_DATE is NULL ) AND
         --( SHEET_SKID.SKID_SHEET_STATUS in (0, 2,4,12,13) );
         ( ab_job.ab_job_num = 105938 );

    IF (ll_item_count <> 0) THEN

      SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
      SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;

      SELECT customer.customer_duns_number_string
        INTO su_duns
        FROM customer
       WHERE customer.customer_id = ll_customer_id;

       --Production
      --x12_table(i) := 'ISA*00*' ||
      --                '          *00*          *01*039630926T     *09*961613887      *' ||
      --                ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
      --                lpad(to_char(ll_gs_log), 9, '0') || '*0*P*>';
      
      --Development                
      x12_table(i) := 'ISA*00*' ||
                      '          *00*          *ZZ*2NDSFTP        *ZZ*ARNCQFMW       *' ||
                      ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                      lpad(to_char(ll_gs_log), 9, '0') || '*0*T*>';
                      
      i := i + 1;

      --Alex Gerlants. 10/16/2018. Changed from "002002" to "004010"
      --Production
      --x12_table(1) := 'GS*SH*R0P7A' || 'TN*961613887' || '*' || ls_today || '*' ||
      --                ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                      
      --Development
      x12_table(1) := 'GS*SH*2NDSFTP' || 'TN*ARNCQFMW' || '*' || ls_today || '*' ||
                     ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                      
      i := i + 1;
      
      x12_table(i) := 'ST*870*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                      '***' || ls_now || '*****';
      i := i + 1;
      x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
      i := i + 1;
      x12_table(i) := 'N1*SU**1*' || su_duns;
      i := i + 1;
      x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926';
      i := i + 1;

      li_hl01 := 0;

      FOR coil_rec IN coil_cur LOOP    -- coil loop
          ll_cur_coil := coil_rec.coil_abc_num;

          coil_num(p) := ll_cur_coil;
          p := p + 1;


        FOR item_rec IN alcan_870_cur LOOP   -- item loop

        li_hl01 := li_hl01 + 1;

        x12_table(i) := 'HL*' || to_char(li_hl01) || '**I';
        i := i + 1;

              SELECT nvl(customer_order.orig_customer_po, 'NA'),
                     nvl(order_item.cust_prod_line_id, 'NA'),
                     nvl(order_item.finished_goods_material_num, 'NA')
              INTO ls_po, ls_cust_prod_line, ls_finished_goods
              FROM   order_item,
                     ab_job,
                     customer_order
             WHERE (ab_job.order_abc_num = customer_order.order_abc_num)
             AND (ab_job.order_abc_num = order_item.order_abc_num)
             AND (ab_job.order_item_num = order_item.order_item_num)
              AND (ab_job.ab_job_num = item_rec.ab_job_num);

        IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
           x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
           i := i + 1;
        END IF;

        x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
        i := i + 1;

        x12_table(i) := 'REF*SE*' || to_char(item_rec.prod_item_num);
        i := i + 1;


        x12_table(i) := 'REF*MI*' || to_char(item_rec.ab_job_num);
        i := i + 1;

        x12_table(i) := 'REF*RV*' || to_char(item_rec.prod_item_num) ||
                        '*NA';
        i := i + 1;

        x12_table(i) := 'REF*IX*' || to_char(item_rec.consumed_coil);
        i := i + 1;

        x12_table(i) := 'PO1**1*UN****' || '***SN*' ||
                          item_rec.coil_org_num || '***VP*' || item_rec.finished_goods;
        i := i + 1;

        IF item_rec.skid_sheet_status = 2 THEN
          x12_table(i) := 'PID*S*MA*ST*1*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 4 THEN
          x12_table(i) := 'PID*S*MA*ST*3*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 13 THEN
          x12_table(i) := 'PID*S*MA*ST*8*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
         ELSE
          x12_table(i) := 'PID*S*MA*ST*4*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        END IF;

        x12_table(i) := 'PID*S*MAC*ST*01';
        i := i + 1;
        x12_table(i) := 'PID*S*PR*ST*19';
        i := i + 1;
        x12_table(i) := 'MEA*WT*N*' || to_char(item_rec.prod_item_net_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*WT*G*' || to_char(item_rec.skid_gross_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*CT*NA*' || to_char(item_rec.prod_item_pieces) ||
                        '*PC';
        i := i + 1;

         item_num(k) := item_rec.prod_item_num;
        k := k + 1;

      END LOOP;  -- item loop

     SELECT scrap_870_date, coil_org_num, lot_num
     INTO ld_scrap_870_date, ls_coil_org_num, ls_heat
     FROM coil
     WHERE coil_abc_num = ll_cur_coil;
     
     ld_scrap_870_date := null; --Alex Gerlants. 01/12/2019. Added to get through

     IF (ld_scrap_870_date is NULL) THEN  -- scrap not sent

      FOR scrap_rec IN alcan_scrap_870_cur LOOP    -- scrap loop

        --scrap info

        SELECT NVL(sum(production_sheet_item.prod_item_net_wt),0)
        into ll_prime_nw
         FROM production_sheet_item
         WHERE (production_sheet_item.ab_job_num = scrap_rec.ab_job_num) and
               (production_sheet_item.coil_abc_num = ll_cur_coil);


                ll_scrap_nw := scrap_rec.process_quan - scrap_rec.process_end_wt - ll_prime_nw;



                IF ll_scrap_nw > 0 then

                   li_hl01 := li_hl01 + 1;

                   x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*I';
                   i := i + 1;

                   IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
                      x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
                      i := i + 1;
                   END IF;

                   x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
                    i := i + 1;

                    x12_table(i) := 'PO1**1*UN****' || '***SN*' || scrap_rec.coil_org_num ;
                    i := i + 1;

                    x12_table(i) := 'PID*S*MA*ST*S';
                    i := i + 1;
                    x12_table(i) := 'PID*S*MAC*ST*05';
                     i := i + 1;
                    x12_table(i) := 'PID*S*PR*ST*19';
                     i := i + 1;

                   x12_table(i) := 'MEA*WT*N*' || to_char(ll_scrap_nw) || '*LB*01';
                   i := i+1;
                 END IF;

        END LOOP;  -- scrap loop
      END IF;  -- scrap not sent
     END LOOP;   -- coil loop
      x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
      i := i + 1;
      x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
      i := i + 1;
      x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

      -- Write EDI to file

      IF li_hl01 > 1 THEN
        -- WRITE EDI FILE ONLY IF ITEM > 0
        SELECT edi_file_id_seq.nextval
          INTO ll_edi_file_id_aleris
          FROM dual;
        edi_file        := edi_file_prefix || to_char(ll_edi_file_id_aleris) || '.edi';
     -- edi_file        := 's_alcan_' || to_char(ll_edi_file_id_aleris) || '.870';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        FOR j IN 0 .. i LOOP
          utl_file.put_line(edi_file_handle, x12_table(j));

        END LOOP;
        utl_file.fclose(edi_file_handle);
      END IF; -- END WRITING EDI FILE

      --edi_file        := 'send_edi_log'; /* Alex Gerlants. 04/14/2017. Commented out. */
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      --For verifying 997
/*      
      INSERT INTO outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
        VALUES
          (ll_edi_file_id_aleris,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           SYSDATE,
           edi_file,
           0,
           ll_customer_id,
           ll_st_log,
           '870');
*/           
--         COMMIT;

     --FOR m IN 0 .. k - 1 LOOP
     --  UPDATE production_sheet_item
     --      SET prod_item_edi870_date = SYSDATE,
     --          edi_file_id_870 = ll_edi_file_id_aleris /* Alex Gerlants. 09/06/2016. New column */
     --    WHERE production_sheet_item.prod_item_num = item_num(m);
     --END LOOP;

--      COMMIT;

        /*
        FOR m in 0..p - 1 LOOP
                UPDATE coil
					SET coil.scrap_870_date = sysdate
                WHERE coil.coil_abc_num = coil_num(m);

               UPDATE process_coil
					SET scrap_870_date = sysdate
                WHERE ( coil_abc_num = coil_num(m)) AND (scrap_870_date is NULL);

         END LOOP;
         */

        COMMIT;

    END IF; --end if in select count(*)

  END LOOP; ------ End of outer loop customer_id

EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN;
END;
--------------------------------------------------------
--  DDL for Procedure EDI_ARCONIC_870_REBAND
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."EDI_ARCONIC_870_REBAND" (al_ab_job_num ab_job.ab_job_num%TYPE)

IS

  /*
  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   */

  
  
  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR');  

  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_handle utl_file.file_type;
  su_duns         VARCHAR2(10);
  ll_customer_id  customer.customer_id%TYPE;
  ll_cur_coil     coil.coil_abc_num%TYPE;
  
  ll_cur_job ab_job.ab_job_num%TYPE;

  ll_gs_log INTEGER;
  ll_st_log INTEGER;

  ls_today   VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD');
  ls_today_4 VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  ls_now     VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  ls_po VARCHAR2(20);
  ls_finished_goods VARCHAR2(32);
  ls_cust_prod_line VARCHAR2(8);

  ld_scrap_870_date ab_job.scrap_870_date%TYPE;
  ld_job_scrap_870_date ab_job.scrap_870_date%TYPE;
  
  ls_coil_org_num coil.coil_org_num%TYPE;
  ls_heat coil.lot_num%TYPE;
   ls_scrap_coil_org_num coil.coil_org_num%TYPE;
 
  ll_ref_order_abc_num sheet_skid.ref_order_abc_num%TYPE;
  ll_ref_order_abc_item sheet_skid.ref_order_abc_item%TYPE;
  ls_sheet_type order_item.sheet_type%TYPE;
  
  ll_prime_nw coil.net_wt%TYPE;
  ll_scrap_start_nw coil.net_wt%TYPE; 
  ll_scrap_end_nw coil.net_wt%TYPE; 
  ll_scrap_nw coil.net_wt%TYPE;
  ll_process_quantity  coil.net_wt%TYPE;
  ll_process_end_wt  coil.net_wt%TYPE;
  lr_theo_unit_wt order_item.theoretical_unit_wt%TYPE;

  --ll_edi_file_id integer;
  ll_edi_file_id_aleris INTEGER;

  ll_item_count INTEGER;

  li_hl01 INTEGER;
  li_hllin INTEGER;
  ls_today_2digits_year VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');

  CURSOR cust_cur IS
    SELECT customer_id FROM customer WHERE customer_id IN (1153,1459,2582); ---Add customer id here if you want to send 870 for more customers

  CURSOR coil_cur IS
  SELECT UNIQUE COIL.COIL_ABC_NUM, AB_JOB.AB_JOB_NUM
    FROM AB_JOB,   
         COIL,   
         PRODUCTION_SHEET_ITEM,   
         SHEET_SKID,   
         SHEET_SKID_DETAIL,   
         CUSTOMER_ORDER,
         PROCESS_COIL 
   WHERE ( SHEET_SKID_DETAIL.SHEET_SKID_NUM = SHEET_SKID.SHEET_SKID_NUM ) and  
         ( SHEET_SKID_DETAIL.PROD_ITEM_NUM = PRODUCTION_SHEET_ITEM.PROD_ITEM_NUM ) and  
         ( COIL.COIL_ABC_NUM = PRODUCTION_SHEET_ITEM.COIL_ABC_NUM ) and  
         ( AB_JOB.AB_JOB_NUM = SHEET_SKID.AB_JOB_NUM ) and  
         ( COIL.COIL_ABC_NUM = PROCESS_COIL.COIL_ABC_NUM ) and  
         ( AB_JOB.AB_JOB_NUM = PROCESS_COIL.AB_JOB_NUM ) and  
         ( AB_JOB.ORDER_ABC_NUM = CUSTOMER_ORDER.ORDER_ABC_NUM ) and  
         ( AB_JOB.JOB_STATUS = 0 ) AND  
         (  COIL.COIL_STATUS = 7 ) AND  
         ( CUSTOMER_ORDER.ORIG_CUSTOMER_ID = ll_customer_id ) AND  
         ( PRODUCTION_SHEET_ITEM.PROD_ITEM_EDI870_DATE is NULL ) AND  
         ( PROCESS_COIL.SCRAP_870_DATE is NULL ) AND  
         ( COIL.SCRAP_870_DATE is NULL ) AND  
         ( SHEET_SKID.SKID_SHEET_STATUS in (2,4,12,13) );
             
  CURSOR alcan_870_cur IS 
   SELECT production_sheet_item.ab_job_num,
           production_sheet_item.coil_abc_num,
           production_sheet_item.prod_item_pieces,
           production_sheet_item.prod_item_num,
           sheet_skid.sheet_skid_num,
           production_sheet_item.prod_item_net_wt,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_skid_display_num,
           sheet_skid.sheet_net_wt,
           sheet_skid.skid_pieces,
           coil.coil_org_num,
           coil.lot_num,
           nvl(coil.consumed_coil_num, ' ') consumed_coil,
           nvl(coil.material_num, ' ') material_num,
           nvl(customer_order.sales_order, ' ') sales_order,
           nvl(customer_order.orig_customer_po, 'NA') customer_po,
           nvl(order_item.enduser_part_num, ' ') enduser_parts,
           nvl(order_item.cust_prod_line_id, 'NA') customer_line_id,
           nvl(order_item.finished_goods_material_num, 'NA') finished_goods,
           (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
           NULL done
      FROM sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil,
           order_item,
           ab_job, 
           customer_order
     WHERE (sheet_skid.skid_sheet_status IN (2, 4, 13, 12)) -- 2: Ready; 8: Warehouse Ready; 13: Partial Ready; 7: Partial; 12: Sample; 4: onhold
       AND (production_sheet_item.prod_item_edi870_date IS NULL)
       AND (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       AND (sheet_skid_detail.prod_item_num =
           production_sheet_item.prod_item_num)
       AND (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       AND (coil.customer_id = ll_customer_id)
       AND (sheet_skid.ref_order_abc_num = customer_order.order_abc_num)
 		   AND (production_sheet_item.ab_job_num = ab_job.ab_job_num)
		   AND (ab_job.order_abc_num = order_item.order_abc_num)
		   AND (ab_job.order_item_num = order_item.order_item_num)
      AND (production_sheet_item.coil_abc_num = ll_cur_coil)
      AND (production_sheet_item.ab_job_num = ll_cur_job);
       

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;
  
  item_rec  alcan_870_cur%ROWTYPE;
  coil_rec  coil_cur%ROWTYPE;

  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;
  
 
BEGIN

  FOR cust_rec IN cust_cur LOOP
    --- Outer loop of customer_id
    ll_customer_id := cust_rec.customer_id;
    i              := 0;
    k              := 0;
  
  SELECT count(COIL.COIL_ABC_NUM)
  INTO ll_item_count
    FROM AB_JOB,   
         COIL,   
         PRODUCTION_SHEET_ITEM,   
         SHEET_SKID,   
         SHEET_SKID_DETAIL,   
         CUSTOMER_ORDER,
         PROCESS_COIL 
   WHERE ( SHEET_SKID_DETAIL.SHEET_SKID_NUM = SHEET_SKID.SHEET_SKID_NUM ) and  
         ( SHEET_SKID_DETAIL.PROD_ITEM_NUM = PRODUCTION_SHEET_ITEM.PROD_ITEM_NUM ) and  
         ( COIL.COIL_ABC_NUM = PRODUCTION_SHEET_ITEM.COIL_ABC_NUM ) and  
         ( COIL.COIL_ABC_NUM = PROCESS_COIL.COIL_ABC_NUM ) and  
         ( AB_JOB.AB_JOB_NUM = PROCESS_COIL.AB_JOB_NUM ) and  
         ( AB_JOB.AB_JOB_NUM = SHEET_SKID.AB_JOB_NUM ) and  
         ( AB_JOB.ORDER_ABC_NUM = CUSTOMER_ORDER.ORDER_ABC_NUM ) and  
         ( AB_JOB.JOB_STATUS = 0 ) AND  
         (  COIL.COIL_STATUS = 7 ) AND  
         ( CUSTOMER_ORDER.ORIG_CUSTOMER_ID = ll_customer_id ) AND  
         ( PRODUCTION_SHEET_ITEM.PROD_ITEM_EDI870_DATE is NULL ) AND  
         ( PROCESS_COIL.SCRAP_870_DATE is NULL ) AND  
         ( COIL.SCRAP_870_DATE is NULL ) AND  
         ( SHEET_SKID.SKID_SHEET_STATUS in (2,4,12,13) );
              
    IF (ll_item_count <> 0) THEN
    
   
      SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
      SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
    
      SELECT customer.customer_duns_number_string
        INTO su_duns
        FROM customer
       WHERE customer.customer_id = ll_customer_id;
    
      --Production
      --x12_table(i) := 'ISA*00*' ||
      --                '          *00*          *01*039630926T     *09*961613887      *' ||
      --                ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
      --                lpad(to_char(ll_gs_log), 9, '0') || '*0*P*>';
      
      --Development                
      x12_table(i) := 'ISA*00*' ||
                      '          *00*          *ZZ*2NDSFTP        *ZZ*ARNCQFMW       *' ||
                      ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                      lpad(to_char(ll_gs_log), 9, '0') || '*0*T*>';
                      
      i := i + 1;

      --Production
      --x12_table(1) := 'GS*SH*R0P7A' || 'TN*961613887' || '*' || ls_today || '*' ||
      --                ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                      
      --Development
      x12_table(1) := 'GS*SH*2NDSFTP' || 'TN*ARNCQFMW' || '*' || ls_today || '*' ||
                     ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                      
      i := i + 1;
      x12_table(i) := 'ST*870*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                      '***' || ls_now || '*****';
      i := i + 1;
      x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
      i := i + 1;
      x12_table(i) := 'N1*SU**1*' || su_duns;      
      i := i + 1;
      x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926';
      i := i + 1;
    
      li_hl01 := 0;

      FOR coil_rec IN coil_cur LOOP    -- coil loop
          ll_cur_coil := coil_rec.coil_abc_num;
          ll_cur_job := coil_rec.ab_job_num;

    
                                
        FOR item_rec IN alcan_870_cur LOOP   -- item loop
              

        li_hl01 := li_hl01 + 1;
        
        x12_table(i) := 'HL*' || to_char(li_hl01) || '**I';
        i := i + 1;       
 
              SELECT nvl(customer_order.orig_customer_po, 'NA'),
                     nvl(order_item.cust_prod_line_id, 'NA'),
                     nvl(order_item.finished_goods_material_num, 'NA')
              INTO ls_po, ls_cust_prod_line, ls_finished_goods
              FROM   order_item,
			               ab_job, 
                     customer_order
             WHERE (ab_job.order_abc_num = customer_order.order_abc_num)
		         AND (ab_job.order_abc_num = order_item.order_abc_num)
		         AND (ab_job.order_item_num = order_item.order_item_num)
              AND (ab_job.ab_job_num = ll_cur_job);
              
        IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN      
           x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;      
           i := i + 1;
        END IF;
        
        x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
        i := i + 1;
      
        x12_table(i) := 'REF*SE*' || to_char(item_rec.prod_item_num);
        i := i + 1;
        
 
        x12_table(i) := 'REF*MI*' || to_char(item_rec.ab_job_num);
        i := i + 1;
      
        x12_table(i) := 'REF*RV*' || to_char(item_rec.prod_item_num) ||
                        '*NA';
        i := i + 1;
 
        x12_table(i) := 'REF*IX*' || to_char(item_rec.consumed_coil);
        i := i + 1;
             
        x12_table(i) := 'PO1**1*UN****' || '***SN*' ||
                          item_rec.coil_org_num || '***VP*' || item_rec.finished_goods;
        i := i + 1;
      
        IF item_rec.skid_sheet_status = 2 THEN
          x12_table(i) := 'PID*S*MA*ST*1*' ||
                          to_char(item_rec.sheet_skid_display_num);                        
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 4 THEN
          x12_table(i) := 'PID*S*MA*ST*3*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 13 THEN
          x12_table(i) := 'PID*S*MA*ST*8*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
         ELSE
          x12_table(i) := 'PID*S*MA*ST*4*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        END IF;
      
        x12_table(i) := 'PID*S*MAC*ST*01';
        i := i + 1;
        x12_table(i) := 'PID*S*PR*ST*19';
        i := i + 1;
        x12_table(i) := 'MEA*WT*N*' || to_char(item_rec.prod_item_net_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*WT*G*' || to_char(item_rec.skid_gross_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*CT*NA*' || to_char(item_rec.prod_item_pieces) ||
                        '*PC';
        i := i + 1;
        
         item_num(k) := item_rec.prod_item_num;
        k := k + 1;

      END LOOP;  -- item loop

 
     SELECT scrap_870_date, coil_org_num, lot_num
     INTO ld_scrap_870_date, ls_coil_org_num, ls_heat
     FROM coil
     WHERE coil_abc_num = ll_cur_coil;
     
     SELECT scrap_870_date
     INTO ld_job_scrap_870_date
     FROM process_coil
     WHERE (coil_abc_num = ll_cur_coil) AND (ab_job_num = ll_cur_job);
     
     IF (ld_scrap_870_date is NULL) AND (ld_job_scrap_870_date is NULL) THEN  -- scrap not sent
 
             SELECT b.coil_org_num,
               NVL(a.process_quantity, 0) process_quan, 
               NVL(a.process_end_wt, 0) process_end_wt
           INTO ls_scrap_coil_org_num, ll_scrap_start_nw, ll_scrap_end_nw
           FROM process_coil a, coil b
           WHERE (b.coil_abc_num = ll_cur_coil)
           AND (a.coil_abc_num = b.coil_abc_num)
            AND (a.ab_job_num = ll_cur_job);
        
        --scrap info 
             
        SELECT NVL(sum(production_sheet_item.prod_item_net_wt),0) 
        into ll_prime_nw
         FROM production_sheet_item
         WHERE (production_sheet_item.ab_job_num = ll_cur_job) and
               (production_sheet_item.coil_abc_num = ll_cur_coil);
               
               
                ll_scrap_nw := ll_scrap_start_nw - ll_scrap_end_nw - ll_prime_nw;                 
                
                
                
                IF ll_scrap_nw > 0 then
                
                   li_hl01 := li_hl01 + 1;
                   
                   x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*I';
                   i := i + 1;
               
                   IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN      
                      x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;      
                      i := i + 1;
                   END IF;
                                  
                   x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
                    i := i + 1;
                    
                    x12_table(i) := 'PO1**1*UN****' || '***SN*' || ls_scrap_coil_org_num ;
                    i := i + 1;
                                    
                    x12_table(i) := 'PID*S*MA*ST*S';
                    i := i + 1;       
                    x12_table(i) := 'PID*S*MAC*ST*05';
                     i := i + 1;
                    x12_table(i) := 'PID*S*PR*ST*19';
                     i := i + 1;              
                             
                   x12_table(i) := 'MEA*WT*N*' || to_char(ll_scrap_nw) || '*LB*01'; 
                   i := i+1;
                 END IF;
      
       END IF;  -- scrap not sent
     END LOOP;   -- coil loop
     
      x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
      i := i + 1;
      x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
      i := i + 1;
      x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');
    
      -- Write EDI to file
    
      IF li_hl01 > 1 THEN
        -- WRITE EDI FILE ONLY IF ITEM > 0
        SELECT edi_file_id_seq.nextval
          INTO ll_edi_file_id_aleris
          FROM dual;
        edi_file        := 'S_alcan_' || to_char(ll_edi_file_id_aleris) ||
                           '.870';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
      
        FOR j IN 0 .. i LOOP
          utl_file.put_line(edi_file_handle, x12_table(j));
        
        END LOOP;
        utl_file.fclose(edi_file_handle);
      END IF; -- END WRITING EDI FILE
 
  
      --For verifying 997
      /*INSERT INTO outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
        VALUES
          (ll_edi_file_id_aleris,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           SYSDATE,
           edi_file,
           0,
           ll_customer_id,
           ll_st_log,
           '870');
        COMMIT;
      */
      edi_file        := 'send_edi_log';
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);
  
      FOR coil_rec IN coil_cur LOOP    -- coil loop date
          UPDATE process_coil set scrap_870_date = sysdate
          WHERE (coil_abc_num = coil_rec.coil_abc_num) AND (ab_job_num = coil_rec.ab_job_num);
     END LOOP;   -- coil loop date
         
     commit;
     
     FOR m IN 0 .. k - 1 LOOP
       UPDATE production_sheet_item
           SET prod_item_edi870_date = SYSDATE,
               edi_file_id_870 = ll_edi_file_id_aleris /* Alex Gerlants. 09/06/2016. New column */
         WHERE production_sheet_item.prod_item_num = item_num(m);
     END LOOP;
    
     COMMIT;
     
    
    END IF; --end if in select count(*)
  
  END LOOP; ------ End of outer loop customer_id

EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN;
END;
--------------------------------------------------------
--  DDL for Procedure EDI_ARCONIC_870_TEST
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."EDI_ARCONIC_870_TEST" (al_ab_job_num ab_job.ab_job_num%TYPE)
IS

  /*
  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   Customer: Aleris(1980) DUNS:964790856     EDI ID:964790856      QUALIFIER: ZZ

   End User: Aleris, Customer ID 1980
   */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata/arconic_test'; --Development
  edi_loc VARCHAR2(50) := get_edi_destination('EDI_DIR'); --Production

  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_prefix VARCHAR2(50) := 's_arconic_870_';     --Development
  --edi_file_prefix VARCHAR2(50) := 'S_arconic_870_';          --Production
  edi_file_handle utl_file.file_type;
  su_duns         VARCHAR2(20); /* Alex Gerlants. Changed from (10) to (20) */
  ll_customer_id  customer.customer_id%TYPE;
  ll_cur_coil     coil.coil_abc_num%TYPE;

--  ll_cur_job ab_job.ab_job_num%TYPE;

  ll_gs_log INTEGER;
  ll_st_log INTEGER;

  ls_today   VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD');
  ls_today_4 VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  ls_now     VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  ls_po VARCHAR2(20);
  ls_finished_goods VARCHAR2(32);
  ls_cust_prod_line VARCHAR2(8);

  ld_scrap_870_date ab_job.scrap_870_date%TYPE;

  ls_coil_org_num coil.coil_org_num%TYPE;
  ls_lot_num coil.lot_num%TYPE;

--  ll_ref_order_abc_num sheet_skid.ref_order_abc_num%TYPE;
--  ll_ref_order_abc_item sheet_skid.ref_order_abc_item%TYPE;
--  ls_sheet_type order_item.sheet_type%TYPE;

  ll_prime_nw coil.net_wt%TYPE;
  ll_scrap_nw coil.net_wt%TYPE;
--  ll_process_quantity  coil.net_wt%TYPE;
--  ll_process_end_wt  coil.net_wt%TYPE;
--  lr_theo_unit_wt order_item.theoretical_unit_wt%TYPE;

  --ll_edi_file_id integer;
  ll_edi_file_id INTEGER;

  ll_item_count INTEGER;

  li_hl01 INTEGER;
  li_hllin INTEGER;
  
  li_coil_status   coil.coil_status%TYPE; /* Alex Gerlants. New variable */
  ls_today_2digits_year VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  
  CURSOR cust_cur IS
    SELECT customer_id FROM customer WHERE customer_id IN (2784);

/*
  CURSOR coil_cur IS
  SELECT UNIQUE C.COIL_ABC_NUM
  FROM SHEET_SKID_DETAIL SKD
    JOIN SHEET_SKID SK ON SKD.SHEET_SKID_NUM = SK.SHEET_SKID_NUM
    JOIN PRODUCTION_SHEET_ITEM PSI ON SKD.PROD_ITEM_NUM = PSI.PROD_ITEM_NUM
    JOIN COIL C ON PSI.COIL_ABC_NUM = C.COIL_ABC_NUM
    JOIN AB_JOB AB ON SK.AB_JOB_NUM = AB.AB_JOB_NUM
    JOIN CUSTOMER_ORDER CO ON CO.ORDER_ABC_NUM = AB.ORDER_ABC_NUM
where ab.ab_job_num = al_ab_job_num;
*/

/*
  cursor coil_cur is
  select distinct  process_coil.coil_abc_num
  from   process_coil
  where  ab_job_num = al_ab_job_num;
*/
    cursor coil_cur is
    select distinct coil.coil_abc_num
    FROM "COIL",   
         "PRODUCTION_SHEET_ITEM",   
         "SHEET_SKID",   
         "SHEET_SKID_DETAIL",   
         "PROCESS_COIL"  
   WHERE ( "COIL"."COIL_ABC_NUM" = "PRODUCTION_SHEET_ITEM"."COIL_ABC_NUM" ) and  
         ( "SHEET_SKID_DETAIL"."SHEET_SKID_NUM" = "SHEET_SKID"."SHEET_SKID_NUM" ) and  
         ( "SHEET_SKID_DETAIL"."PROD_ITEM_NUM" = "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NUM" ) and  
         ( "COIL"."COIL_ABC_NUM" = "PROCESS_COIL"."COIL_ABC_NUM" ) and  
         ( "PRODUCTION_SHEET_ITEM"."AB_JOB_NUM" = "PROCESS_COIL"."AB_JOB_NUM" ) and  
         ( ( "PRODUCTION_SHEET_ITEM"."AB_JOB_NUM" = al_ab_job_num ) );
    
--  WHERE (AB.JOB_STATUS = 0) AND
--    ( C.COIL_STATUS IN (0, 3, 7) ) AND /* Alex Gerlants. Added "7" for Rebanded */
--    ( CO.ORIG_CUSTOMER_ID = ll_customer_id ) AND
--    ( PSI.PROD_ITEM_EDI870_DATE is NULL ) AND
--    ( C.SCRAP_870_DATE is NULL ) AND
--    ( SK.SKID_SHEET_STATUS in (0,2,4,12,13) );

  CURSOR cur_870 IS
   SELECT production_sheet_item.ab_job_num,
           production_sheet_item.coil_abc_num,
           production_sheet_item.prod_item_pieces,
           production_sheet_item.prod_item_num,
           sheet_skid.sheet_skid_num,
           production_sheet_item.prod_item_net_wt,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_skid_display_num,
           sheet_skid.sheet_net_wt,
           sheet_skid.skid_pieces,
           coil.coil_org_num,
           coil.lot_num,
           nvl(coil.consumed_coil_num, ' ') consumed_coil,
           nvl(coil.material_num, ' ') material_num,
           nvl(customer_order.sales_order, ' ') sales_order,
           nvl(customer_order.orig_customer_po, 'NA') customer_po,
           nvl(order_item.enduser_part_num, ' ') enduser_parts,
           nvl(order_item.cust_prod_line_id, 'NA') customer_line_id,
           nvl(order_item.finished_goods_material_num, 'NA') finished_goods,
           (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
           NULL done
      FROM sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil,
           order_item,
           ab_job,
           customer_order
where    (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       AND (sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num)
       AND (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       AND (sheet_skid.ref_order_abc_num = customer_order.order_abc_num)
       AND (production_sheet_item.ab_job_num = ab_job.ab_job_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (coil.customer_id = ll_customer_id)
       and (ab_job.ab_job_num = al_ab_job_num);
       --and (sheet_skid.skid_sheet_status IN (0, 2, 4, 13, 12)); -- 2: Ready; 8: Warehouse Ready; 13: Partial Ready; 7: Partial; 12: Sample; 4: onhold;
       
/*                 
     WHERE (sheet_skid.skid_sheet_status IN (0, 2, 4, 13, 12)) -- 2: Ready; 8: Warehouse Ready; 13: Partial Ready; 7: Partial; 12: Sample; 4: onhold
       AND (production_sheet_item.prod_item_edi870_date IS NULL)
       AND (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       AND (sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num)
       AND (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       AND (coil.customer_id = ll_customer_id)
       AND (sheet_skid.ref_order_abc_num = customer_order.order_abc_num)
       AND (production_sheet_item.ab_job_num = ab_job.ab_job_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (production_sheet_item.coil_abc_num = ll_cur_coil);
*/

       CURSOR scrap_cur_870 IS
       SELECT a.coil_abc_num,
              b.coil_org_num,
              b.lot_num,
              a.ab_job_num,
              nvl(b.material_num, ' ') material_num,
               NVL(a.process_quantity, 0) process_quan,
               NVL(a.process_end_wt, 0) process_end_wt
       FROM process_coil a, coil b
       WHERE (a.coil_abc_num = b.coil_abc_num)
       and   (b.coil_abc_num = ll_cur_coil)
       --AND   (a.scrap_870_date is NULL)
       ;
         

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;

  item_rec  cur_870%ROWTYPE;
  coil_rec  coil_cur%ROWTYPE;

  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;

  TYPE coil_num_type IS TABLE OF coil.coil_abc_num%type INDEX BY BINARY_INTEGER;
  coil_num coil_num_type;
  p binary_integer :=0;

BEGIN

  --FOR cust_rec IN cust_cur LOOP
    --- Outer loop of customer_id
    --ll_customer_id := cust_rec.customer_id;
    i              := 0;
    k              := 0;
    p              := 0;
    
  select   customer_order.orig_customer_id
  into     ll_customer_id
  from     ab_job
           join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
  where    ab_job.ab_job_num = al_ab_job_num;

  SELECT count(COIL.COIL_ABC_NUM)
  INTO ll_item_count
    FROM AB_JOB,
         COIL,
         PRODUCTION_SHEET_ITEM,
         SHEET_SKID,
         SHEET_SKID_DETAIL,
         CUSTOMER_ORDER
   WHERE ( SHEET_SKID_DETAIL.SHEET_SKID_NUM = SHEET_SKID.SHEET_SKID_NUM ) and
         ( SHEET_SKID_DETAIL.PROD_ITEM_NUM = PRODUCTION_SHEET_ITEM.PROD_ITEM_NUM ) and
         ( COIL.COIL_ABC_NUM = PRODUCTION_SHEET_ITEM.COIL_ABC_NUM ) and
         ( AB_JOB.AB_JOB_NUM = SHEET_SKID.AB_JOB_NUM ) and
         ( AB_JOB.ORDER_ABC_NUM = CUSTOMER_ORDER.ORDER_ABC_NUM ) and
         ( CUSTOMER_ORDER.ORIG_CUSTOMER_ID = ll_customer_id ) AND
         (ab_job.ab_job_num = al_ab_job_num);
         --and ( AB_JOB.JOB_STATUS = 0 ) and
         --(COIL.COIL_STATUS in (0, 3, 7)) and 
         --( SHEET_SKID.SKID_SHEET_STATUS in (0, 2,4,12,13) );
/*         
         ( AB_JOB.JOB_STATUS = 0 ) AND
         (  COIL.COIL_STATUS in (0, 3, 7) ) AND
         ( CUSTOMER_ORDER.ORIG_CUSTOMER_ID = ll_customer_id ) AND
         ( PRODUCTION_SHEET_ITEM.PROD_ITEM_EDI870_DATE is NULL ) AND
         ( COIL.SCRAP_870_DATE is NULL ) AND
         ( SHEET_SKID.SKID_SHEET_STATUS in (0, 2,4,12,13) );
*/         

    IF (ll_item_count <> 0) THEN

      SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
      SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;

 
      SELECT customer.customer_duns_number_string
        INTO su_duns
        FROM customer
       WHERE customer.customer_id = ll_customer_id;
       
      --Production
      --x12_table(i) := 'ISA*00*' ||
      --                '          *00*          *01*039630926T     *09*961613887      *' ||
      --                ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
      --                lpad(to_char(ll_gs_log), 9, '0') || '*0*P*>';
      
      --Development                
      x12_table(i) := 'ISA*00*' ||
                      '          *00*          *ZZ*2NDSFTP        *ZZ*ARNCQFMW       *' ||
                      ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                      lpad(to_char(ll_gs_log), 9, '0') || '*0*T*>';
                      
      i := i + 1;

      --Alex Gerlants. 10/16/2018. Changed from "002002" to "004010"
      --Production
      --x12_table(1) := 'GS*SH*R0P7A' || 'TN*961613887' || '*' || ls_today || '*' ||
      --                ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                      
      --Development
      x12_table(1) := 'GS*SH*2NDSFTP' || 'TN*ARNCQFMW' || '*' || ls_today || '*' ||
                     ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                      
      i := i + 1;
  
      x12_table(i) := 'ST*870*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                      '***' || ls_now || '*****';
      i := i + 1;
      x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
      i := i + 1;
      x12_table(i) := 'N1*SU**1*' || su_duns;
      i := i + 1;
      x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926';
      i := i + 1;

      li_hl01 := 0;

      --FOR coil_rec IN coil_cur LOOP    -- coil loop
      --    ll_cur_coil := coil_rec.coil_abc_num;
      --
      --    coil_num(p) := ll_cur_coil;
      --    p := p + 1;


        FOR item_rec IN cur_870 LOOP   -- item loop
          
              ll_cur_coil := item_rec.coil_abc_num;
        
              coil_num(p) := ll_cur_coil;
              p := p + 1;

              li_hl01 := li_hl01 + 1;

              x12_table(i) := 'HL*' || to_char(li_hl01) || '**I';
              i := i + 1;

              SELECT nvl(customer_order.orig_customer_po, 'NA'),
                     nvl(order_item.cust_prod_line_id, 'NA'),
                     nvl(order_item.finished_goods_material_num, 'NA')
              INTO ls_po, ls_cust_prod_line, ls_finished_goods
              FROM   order_item,
                     ab_job,
                     customer_order
             WHERE (ab_job.order_abc_num = customer_order.order_abc_num)
             AND (ab_job.order_abc_num = order_item.order_abc_num)
             AND (ab_job.order_item_num = order_item.order_item_num)
              AND (ab_job.ab_job_num = item_rec.ab_job_num);

        IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
           x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
           i := i + 1;
        END IF;

        x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
        i := i + 1;

        --x12_table(i) := 'REF*SE*' || to_char(item_rec.prod_item_num);
        --i := i + 1;


        x12_table(i) := 'REF*MI*' || to_char(item_rec.ab_job_num);
        i := i + 1;

        --x12_table(i) := 'REF*RV*' || to_char(item_rec.prod_item_num) || '*NA';
        --i := i + 1;

        --x12_table(i) := 'REF*IX*' || to_char(item_rec.consumed_coil);
        --i := i + 1;

        --x12_table(i) := 'PO1**1*UN****' || '***SN*' ||
        --                  item_rec.coil_org_num || '***VP*' || item_rec.finished_goods;
        x12_table(i) := 'PO1**1*UN****' || '***SN*' ||
                          item_rec.coil_org_num || '***VP';
        i := i + 1;
        
        x12_table(i) := 'REF*BT*' || item_rec.lot_num;
        i := i + 1;
        
        select  coil.coil_status
        into    li_coil_status
        from    coil
        where   coil.coil_abc_num = ll_cur_coil;
            
        if li_coil_status = 7 then
           x12_table(i) := 'PID*S*MA*AA*7*' ||
                            to_char(item_rec.sheet_skid_display_num);
           i := i + 1;
        else

          IF item_rec.skid_sheet_status = 2 THEN --Ready
            x12_table(i) := 'PID*S*MA*AA*1*' ||
                            to_char(item_rec.sheet_skid_display_num);
            i := i + 1;
          ELSIF item_rec.skid_sheet_status = 4 THEN --Onhold
            x12_table(i) := 'PID*S*MA*AA*3*' ||
                            to_char(item_rec.sheet_skid_display_num);
            i := i + 1;
          ELSIF item_rec.skid_sheet_status = 12 THEN --Sample. Added for Arconic
            x12_table(i) := 'PID*S*MA*AA*SAMPLE*' ||
                            to_char(item_rec.sheet_skid_display_num);
            i := i + 1;
          ELSIF item_rec.skid_sheet_status = 13 THEN --Partial-Rd
            x12_table(i) := 'PID*S*MA*AA*8*' ||
                            to_char(item_rec.sheet_skid_display_num);
            i := i + 1;
          ELSE
            x12_table(i) := 'PID*S*MA*AA*4*' ||
                            to_char(item_rec.sheet_skid_display_num);
            i := i + 1;
          END IF;
        end if;

        --x12_table(i) := 'PID*S*MAC*AA*01';
        --i := i + 1;
        
        if li_coil_status = 7 then
           x12_table(i) := 'PID*S*PR*AA*18';
        else
           x12_table(i) := 'PID*S*PR*AA*19';
        end if;
        i := i + 1;
        
        x12_table(i) := 'MEA*WT*N*' || to_char(item_rec.prod_item_net_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*WT*G*' || to_char(item_rec.skid_gross_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*CT*NA*' || to_char(item_rec.prod_item_pieces) ||
                        '*PC';
        i := i + 1;

         item_num(k) := item_rec.prod_item_num;
        k := k + 1;

      END LOOP;  -- item loop

      for coil_rec in coil_cur loop    --New coil loop for scrap
          ll_cur_coil := coil_rec.coil_abc_num;
          
               SELECT scrap_870_date, coil_org_num, lot_num
               INTO ld_scrap_870_date, ls_coil_org_num, ls_lot_num
               FROM coil
               WHERE coil_abc_num = ll_cur_coil;

               IF (ld_scrap_870_date is NULL) THEN  -- scrap not sent

                FOR scrap_rec IN scrap_cur_870 LOOP    -- scrap loop

                  --scrap info

                  SELECT NVL(sum(production_sheet_item.prod_item_net_wt),0)
                  into ll_prime_nw
                   FROM production_sheet_item
                   WHERE (production_sheet_item.ab_job_num = scrap_rec.ab_job_num) and
                         (production_sheet_item.coil_abc_num = ll_cur_coil);


                          ll_scrap_nw := scrap_rec.process_quan - scrap_rec.process_end_wt - ll_prime_nw;



                          IF ll_scrap_nw > 0 then

                             li_hl01 := li_hl01 + 1;

                             x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*I';
                             i := i + 1;

                             IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
                                x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
                                i := i + 1;
                             END IF;

                             x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
                              i := i + 1;

                              x12_table(i) := 'PO1**1*UN****' || '***SN*' || scrap_rec.coil_org_num ;
                              i := i + 1;
                              
                              x12_table(i) := 'REF*BT*' || scrap_rec.lot_num;
                              i := i + 1;

                              x12_table(i) := 'PID*S*MA*AA*S';
                              i := i + 1;
                              x12_table(i) := 'PID*S*MAC*AA*05';
                               i := i + 1;
                              x12_table(i) := 'PID*S*PR*AA*19';
                               i := i + 1;

                             x12_table(i) := 'MEA*WT*N*' || to_char(ll_scrap_nw) || '*LB*01';
                             i := i+1;
                           END IF;

                      END LOOP;  -- scrap loop
                    END IF;  -- scrap not sent
      end loop; --New coil loop for scrap
     --END LOOP;   -- coil loop
      x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
      i := i + 1;
      x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
      i := i + 1;
      x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

      -- Write EDI to file

      IF li_hl01 > 1 THEN
        -- WRITE EDI FILE ONLY IF ITEM > 0
        SELECT edi_file_id_seq.nextval
          INTO ll_edi_file_id
          FROM dual;
        edi_file        := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';
     -- edi_file        := 's_alcan_' || to_char(ll_edi_file_id) || '.870';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        FOR j IN 0 .. i LOOP
          utl_file.put_line(edi_file_handle, x12_table(j));

        END LOOP;
        utl_file.fclose(edi_file_handle);
      END IF; -- END WRITING EDI FILE

      --edi_file        := 'send_edi_log'; /* Alex Gerlants. 04/14/2017. Commented out. */
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

/*
      insert into outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
        VALUES
          (ll_edi_file_id,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           SYSDATE,
           edi_file,
           0,
           ll_customer_id,
           ll_st_log,
           '870');

        for m in 0 .. k - 1 loop
           update production_sheet_item
           set    prod_item_edi870_date = SYSDATE,
                  edi_file_id_870 = ll_edi_file_id
           where  production_sheet_item.prod_item_num = item_num(m);
        end loop;

        for m in 0..p - 1 loop
            select  coil.coil_status
            into    li_coil_status
            from    coil
            where   coil.coil_abc_num = coil_num(m);
            
            if li_coil_status <> 7 then
                update coil
                set    coil.scrap_870_date = sysdate
                where  coil.coil_abc_num = coil_num(m);
            end if;
             
            update process_coil
					  set    scrap_870_date = sysdate
            where  (coil_abc_num = coil_num(m)) and (scrap_870_date is null);

          end loop;

        commit;
*/
   
    end if; --end if in select count(*)
    
    /* Alex Gerlants. 07/25/2017. Begin */
    --Check for rejected coils without sheets, just scrap,
    --and create 870 if these coils are found.
    --edi_alcan_870_rej_coils(ll_customer_id);
    /* Alex Gerlants. 07/25/2017. End */


  --END LOOP; ------ End of outer loop customer_id

EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN;
END;
--------------------------------------------------------
--  DDL for Procedure EDI_ARCONIC_870_TEST2
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."EDI_ARCONIC_870_TEST2" IS

  /*
  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   Customer: Aleris(1980) DUNS:964790856     EDI ID:964790856      QUALIFIER: ZZ

   End User: Aleris, Customer ID 1980
   */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50) := get_edi_destination('EDI_DIR');

  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_prefix VARCHAR2(50) := 's_arconic2_870_';
  edi_file_handle utl_file.file_type;
  su_duns         VARCHAR2(10);
  ll_customer_id  customer.customer_id%TYPE;
  ll_cur_coil     coil.coil_abc_num%TYPE;

--  ll_cur_job ab_job.ab_job_num%TYPE;

  ll_gs_log INTEGER;
  ll_st_log INTEGER;

  ls_today   VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD');
  ls_today_4 VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  ls_now     VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  ls_po VARCHAR2(20);
  ls_finished_goods VARCHAR2(32);
  ls_cust_prod_line VARCHAR2(8);

  ld_scrap_870_date ab_job.scrap_870_date%TYPE;

  ls_coil_org_num coil.coil_org_num%TYPE;
  ls_heat coil.lot_num%TYPE;

--  ll_ref_order_abc_num sheet_skid.ref_order_abc_num%TYPE;
--  ll_ref_order_abc_item sheet_skid.ref_order_abc_item%TYPE;
--  ls_sheet_type order_item.sheet_type%TYPE;

  ll_prime_nw coil.net_wt%TYPE;
  ll_scrap_nw coil.net_wt%TYPE;
--  ll_process_quantity  coil.net_wt%TYPE;
--  ll_process_end_wt  coil.net_wt%TYPE;
--  lr_theo_unit_wt order_item.theoretical_unit_wt%TYPE;

  --ll_edi_file_id integer;
  ll_edi_file_id_aleris INTEGER;

  ll_item_count INTEGER;

  li_hl01 INTEGER;
  li_hllin INTEGER;

  CURSOR cust_cur IS
    SELECT customer_id FROM customer WHERE customer_id IN (2784); ---Add customer id here if you want to send 870 for more customers

  CURSOR coil_cur IS
  SELECT UNIQUE C.COIL_ABC_NUM
  FROM SHEET_SKID_DETAIL SKD
    JOIN SHEET_SKID SK ON SKD.SHEET_SKID_NUM = SK.SHEET_SKID_NUM
    JOIN PRODUCTION_SHEET_ITEM PSI ON SKD.PROD_ITEM_NUM = PSI.PROD_ITEM_NUM
    JOIN COIL C ON PSI.COIL_ABC_NUM = C.COIL_ABC_NUM
    JOIN AB_JOB AB ON SK.AB_JOB_NUM = AB.AB_JOB_NUM
    JOIN CUSTOMER_ORDER CO ON CO.ORDER_ABC_NUM = AB.ORDER_ABC_NUM
  WHERE (AB.JOB_STATUS = 0) AND
    ( C.COIL_STATUS IN (0, 3) ) AND
    ( CO.ORIG_CUSTOMER_ID = ll_customer_id ) AND
    ( PSI.PROD_ITEM_EDI870_DATE is NULL ) AND
    ( C.SCRAP_870_DATE is NULL ) AND
    ( SK.SKID_SHEET_STATUS in (0,2,4,12,13, 16) ) --Alex Gerlants. 03/22/2019. Added new status 16-Hold For Cert
    and ( SK.ab_job_num = 105938 );

  CURSOR alcan_870_cur IS
   SELECT production_sheet_item.ab_job_num,
           production_sheet_item.coil_abc_num,
           production_sheet_item.prod_item_pieces,
           production_sheet_item.prod_item_num,
           sheet_skid.sheet_skid_num,
           production_sheet_item.prod_item_net_wt,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_skid_display_num,
           sheet_skid.sheet_net_wt,
           sheet_skid.skid_pieces,
           coil.coil_org_num,
           coil.lot_num,
           nvl(coil.consumed_coil_num, ' ') consumed_coil,
           nvl(coil.material_num, ' ') material_num,
           nvl(customer_order.sales_order, ' ') sales_order,
           nvl(customer_order.orig_customer_po, 'NA') customer_po,
           nvl(order_item.enduser_part_num, ' ') enduser_parts,
           nvl(order_item.cust_prod_line_id, 'NA') customer_line_id,
           nvl(order_item.finished_goods_material_num, 'NA') finished_goods,
           (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
           NULL done
      FROM sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil,
           order_item,
           ab_job,
           customer_order
     WHERE (sheet_skid.skid_sheet_status IN (0, 2, 4, 13, 12, 16)) -- 2: Ready; 8: Warehouse Ready; 13: Partial Ready; 7: Partial; 12: Sample; 4: onhold
                                                                    --Alex Gerlants. 03/22/2019. Added new status 16-Hold For Cert
       AND (production_sheet_item.prod_item_edi870_date IS NULL)
       AND (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       AND (sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num)
       AND (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       AND (coil.customer_id = ll_customer_id)
       AND (sheet_skid.ref_order_abc_num = customer_order.order_abc_num)
       AND (production_sheet_item.ab_job_num = ab_job.ab_job_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (production_sheet_item.coil_abc_num = ll_cur_coil)
       and ( sheet_skid.ab_job_num = 105938 );

       CURSOR alcan_scrap_870_cur IS
       SELECT a.coil_abc_num,
              b.coil_org_num,
              a.ab_job_num,
              nvl(b.material_num, ' ') material_num,
               NVL(a.process_quantity, 0) process_quan,
               NVL(a.process_end_wt, 0) process_end_wt
       FROM process_coil a, coil b
       WHERE (b.coil_abc_num = ll_cur_coil)
         AND (a.coil_abc_num = b.coil_abc_num)
         AND (a.scrap_870_date is NULL);

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;

  item_rec  alcan_870_cur%ROWTYPE;
  coil_rec  coil_cur%ROWTYPE;

  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;

  TYPE coil_num_type IS TABLE OF coil.coil_abc_num%type INDEX BY BINARY_INTEGER;
  coil_num coil_num_type;
  p binary_integer :=0;

BEGIN

  FOR cust_rec IN cust_cur LOOP
    --- Outer loop of customer_id
    ll_customer_id := cust_rec.customer_id;
    i              := 0;
    k              := 0;
    p              := 0;

  SELECT count(COIL.COIL_ABC_NUM)
  INTO ll_item_count
    FROM AB_JOB,
         COIL,
         PRODUCTION_SHEET_ITEM,
         SHEET_SKID,
         SHEET_SKID_DETAIL,
         CUSTOMER_ORDER
   WHERE ( SHEET_SKID_DETAIL.SHEET_SKID_NUM = SHEET_SKID.SHEET_SKID_NUM ) and
         ( SHEET_SKID_DETAIL.PROD_ITEM_NUM = PRODUCTION_SHEET_ITEM.PROD_ITEM_NUM ) and
         ( COIL.COIL_ABC_NUM = PRODUCTION_SHEET_ITEM.COIL_ABC_NUM ) and
         ( AB_JOB.AB_JOB_NUM = SHEET_SKID.AB_JOB_NUM ) and
         ( AB_JOB.ORDER_ABC_NUM = CUSTOMER_ORDER.ORDER_ABC_NUM ) and
         ( AB_JOB.JOB_STATUS = 0 ) AND
         (  COIL.COIL_STATUS in (0, 3) ) AND
         ( CUSTOMER_ORDER.ORIG_CUSTOMER_ID = ll_customer_id ) AND
         ( PRODUCTION_SHEET_ITEM.PROD_ITEM_EDI870_DATE is NULL ) AND
         ( COIL.SCRAP_870_DATE is NULL ) AND
         ( SHEET_SKID.SKID_SHEET_STATUS in (0, 2,4,12,13, 16) ) --Alex Gerlants. 03/22/2019. Added new status 16-Hold For Cert
         and ( sheet_skid.ab_job_num = 105938 );

    IF (ll_item_count <> 0) THEN

      SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
      SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;

      SELECT customer.customer_duns_number_string
        INTO su_duns
        FROM customer
       WHERE customer.customer_id = ll_customer_id;

      x12_table(i) := 'ISA*00*' ||
                      '          *00*          *01*039630926T     *09*0015049350011G *' ||
                      ls_today_4 || '*' || ls_now || '*U*00401*' ||
                      lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
      i := i + 1;
      x12_table(i) := 'GS*RS*039630926T*' || '001504935001' || '*' ||
                      ls_today || '*' || ls_now || '*' ||
                      to_char(ll_gs_log) || '*X*' || '004010';
      i := i + 1;
      x12_table(i) := 'ST*870*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                      '***' || ls_now || '*****';
      i := i + 1;
      x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
      i := i + 1;
      x12_table(i) := 'N1*SU**1*' || su_duns;
      i := i + 1;
      x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926';
      i := i + 1;

      li_hl01 := 0;

      FOR coil_rec IN coil_cur LOOP    -- coil loop
          ll_cur_coil := coil_rec.coil_abc_num;

          coil_num(p) := ll_cur_coil;
          p := p + 1;


        FOR item_rec IN alcan_870_cur LOOP   -- item loop

        li_hl01 := li_hl01 + 1;

        x12_table(i) := 'HL*' || to_char(li_hl01) || '**I';
        i := i + 1;

              SELECT nvl(customer_order.orig_customer_po, 'NA'),
                     nvl(order_item.cust_prod_line_id, 'NA'),
                     nvl(order_item.finished_goods_material_num, 'NA')
              INTO ls_po, ls_cust_prod_line, ls_finished_goods
              FROM   order_item,
                     ab_job,
                     customer_order
             WHERE (ab_job.order_abc_num = customer_order.order_abc_num)
             AND (ab_job.order_abc_num = order_item.order_abc_num)
             AND (ab_job.order_item_num = order_item.order_item_num)
              AND (ab_job.ab_job_num = item_rec.ab_job_num);

        IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
           x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
           i := i + 1;
        END IF;

        x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
        i := i + 1;

        x12_table(i) := 'REF*SE*' || to_char(item_rec.prod_item_num);
        i := i + 1;


        x12_table(i) := 'REF*MI*' || to_char(item_rec.ab_job_num);
        i := i + 1;

        x12_table(i) := 'REF*RV*' || to_char(item_rec.prod_item_num) ||
                        '*NA';
        i := i + 1;

        x12_table(i) := 'REF*IX*' || to_char(item_rec.consumed_coil);
        i := i + 1;

        x12_table(i) := 'PO1**1*UN****' || '***SN*' ||
                          item_rec.coil_org_num || '***VP*' || item_rec.finished_goods;
        i := i + 1;

        IF item_rec.skid_sheet_status = 2 THEN
          x12_table(i) := 'PID*S*MA*ST*1*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 4 THEN
          x12_table(i) := 'PID*S*MA*ST*3*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        ELSIF item_rec.skid_sheet_status = 13 THEN
          x12_table(i) := 'PID*S*MA*ST*8*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
         ELSE
          x12_table(i) := 'PID*S*MA*ST*4*' ||
                          to_char(item_rec.sheet_skid_display_num);
          i := i + 1;
        END IF;

        x12_table(i) := 'PID*S*MAC*ST*01';
        i := i + 1;
        x12_table(i) := 'PID*S*PR*ST*19';
        i := i + 1;
        x12_table(i) := 'MEA*WT*N*' || to_char(item_rec.prod_item_net_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*WT*G*' || to_char(item_rec.skid_gross_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*CT*NA*' || to_char(item_rec.prod_item_pieces) ||
                        '*PC';
        i := i + 1;

         item_num(k) := item_rec.prod_item_num;
        k := k + 1;

      END LOOP;  -- item loop

     SELECT scrap_870_date, coil_org_num, lot_num
     INTO ld_scrap_870_date, ls_coil_org_num, ls_heat
     FROM coil
     WHERE coil_abc_num = ll_cur_coil;

     IF (ld_scrap_870_date is NULL) THEN  -- scrap not sent

      FOR scrap_rec IN alcan_scrap_870_cur LOOP    -- scrap loop

        --scrap info

        SELECT NVL(sum(production_sheet_item.prod_item_net_wt),0)
        into ll_prime_nw
         FROM production_sheet_item
         WHERE (production_sheet_item.ab_job_num = scrap_rec.ab_job_num) and
               (production_sheet_item.coil_abc_num = ll_cur_coil);


                ll_scrap_nw := scrap_rec.process_quan - scrap_rec.process_end_wt - ll_prime_nw;



                IF ll_scrap_nw > 0 then

                   li_hl01 := li_hl01 + 1;

                   x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*I';
                   i := i + 1;

                   IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
                      x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
                      i := i + 1;
                   END IF;

                   x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
                    i := i + 1;

                    x12_table(i) := 'PO1**1*UN****' || '***SN*' || scrap_rec.coil_org_num ;
                    i := i + 1;

                    x12_table(i) := 'PID*S*MA*ST*S';
                    i := i + 1;
                    x12_table(i) := 'PID*S*MAC*ST*05';
                     i := i + 1;
                    x12_table(i) := 'PID*S*PR*ST*19';
                     i := i + 1;

                   x12_table(i) := 'MEA*WT*N*' || to_char(ll_scrap_nw) || '*LB*01';
                   i := i+1;
                 END IF;

        END LOOP;  -- scrap loop
      END IF;  -- scrap not sent
     END LOOP;   -- coil loop
      x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
      i := i + 1;
      x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
      i := i + 1;
      x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

      -- Write EDI to file

      IF li_hl01 > 1 THEN
        -- WRITE EDI FILE ONLY IF ITEM > 0
        SELECT edi_file_id_seq.nextval
          INTO ll_edi_file_id_aleris
          FROM dual;
        edi_file        := edi_file_prefix || to_char(ll_edi_file_id_aleris) || '.edi';
     -- edi_file        := 's_alcan_' || to_char(ll_edi_file_id_aleris) || '.870';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        FOR j IN 0 .. i LOOP
          utl_file.put_line(edi_file_handle, x12_table(j));

        END LOOP;
        utl_file.fclose(edi_file_handle);
      END IF; -- END WRITING EDI FILE

      --edi_file        := 'send_edi_log'; /* Alex Gerlants. 04/14/2017. Commented out. */
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      --For verifying 997
      INSERT INTO outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
        VALUES
          (ll_edi_file_id_aleris,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           SYSDATE,
           edi_file,
           0,
           ll_customer_id,
           ll_st_log,
           '870');
--         COMMIT;

     FOR m IN 0 .. k - 1 LOOP
       UPDATE production_sheet_item
           SET prod_item_edi870_date = SYSDATE,
               edi_file_id_870 = ll_edi_file_id_aleris /* Alex Gerlants. 09/06/2016. New column */
         WHERE production_sheet_item.prod_item_num = item_num(m);
    END LOOP;

--      COMMIT;

        FOR m in 0..p - 1 LOOP
                UPDATE coil
					SET coil.scrap_870_date = sysdate
                WHERE coil.coil_abc_num = coil_num(m);

               UPDATE process_coil
					SET scrap_870_date = sysdate
                WHERE ( coil_abc_num = coil_num(m)) AND (scrap_870_date is NULL);

             END LOOP;

        COMMIT;

    END IF; --end if in select count(*)

  END LOOP; ------ End of outer loop customer_id

EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN;
END;
