      edi_846(j) := 'DTM*206*' || ls_today || '*' || ls_now || '*ET' || '~'; j := j + 1;
      --edi_846(j) := 'DTM*105*' || ls_today; j := j + 1;
      edi_846(j) := 'REF*SE*' || to_char(skid_rec.sheet_skid_num) || '~'; j := j + 1;
      
      --edi_846(j) := 'QTY*01*1'; j := j + 1;
      
      --edi_846(j) := '--------------------------------------------------------------------'; j := j + 1;
      
