--  DDL for Procedure P_CHECK_997
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."P_CHECK_997" is

Cursor cur IS
SELECT *
FROM 		outbound_edi_transaction;

type line_tabletype is table of varchar2(32767) index by binary_integer;
line line_tabletype;
j binary_integer := 0;
i int;
li_edi_file_id int;
li_icn int;
ld_transaction_time date;
edi_location varchar2(50):='/templar/templar/incoming/senddata';
edi_file varchar2 (50) := 'check_997.log';
edi_file_handle UTL_FILE.FILE_TYPE;

begin

for cur_rec in cur loop
       if cur_rec.fa_received_time is null  then
           if (sysdate - cur_rec.transaction_time > 0.083333 and --2 hours
              sysdate - cur_rec.transaction_time < 1) then
               
              line(j):= 'EDI_FILE_ID: '||cur_rec.edi_file_id||', '||'ICN: '||cur_rec.interchange_control_number||
                        ', '||'TRANSCATION_TIME: '||to_char(cur_rec.transaction_time, 'MM/DD/YY HH24:MI')||', '||
                        'TRANSACTION_TYPE_ID: '|| cur_rec.transaction_type_id;
              j := j + 1;
           end if;
       end if;      
end loop;

if j > 0 then
  edi_file_handle :=utl_file.fopen(edi_location,edi_file,'W');
   
  FOR i IN 0..j-1 LOOP
      utl_file.put_line(edi_file_handle,line(i));
    END LOOP;
    
  utl_file.fclose(edi_file_handle);
end if;
  
end P_CHECK_997;
  GRANT EXECUTE ON "DBO"."P_CHECK_997" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Procedure P_CHECK_SHIFT_END
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."P_CHECK_SHIFT_END" is

li_i shift.dt_total%type ;
Cursor cur_shift IS
SELECT shift.shift_num
FROM shift
where shift.end_time is null and 
shift.start_time is not null and
sysdate - shift.planned_ending_time > 0.105;

begin
  --li_i := 1;
  for cur_rec in cur_shift
  loop
      li_i := update_shift_dt_total( cur_rec.shift_num );
      update shift
      set shift.end_time = shift.planned_ending_time, shift.dt_total = li_i
      where shift.shift_num = cur_rec.shift_num;
      
      update line_current_status
      set line_current_status.scrap_skid_num = null,
          line_current_status.sheet_skid_num = null,
          line_current_status.coil_abc_num = null,
          line_current_status.ab_job_num = null,
          line_current_status.shift_num = null
      where line_current_status.shift_num = cur_rec.shift_num;
  end loop;
  commit;
  
  
end p_check_shift_end;
  GRANT EXECUTE ON "DBO"."P_CHECK_SHIFT_END" TO "AGERLANTS"
