--  DDL for Procedure P_CHECK_STATUS_UNMATCHED_COIL
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."P_CHECK_STATUS_UNMATCHED_COIL" is

Cursor cur IS
SELECT c.CUSTOMER_ID,cu.CUSTOMER_SHORT_NAME, p.AB_JOB_NUM, c.COIL_ABC_NUM, c.NET_WT, c.NET_WT_BALANCE, c.COIL_STATUS, p.PROCESS_COIL_STATUS, p.PROCESS_DATE
FROM PROCESS_COIL p, COIL c, customer cu
WHERE c.CUSTOMER_ID = cu.CUSTOMER_ID
and c.COIL_ABC_NUM  = p.COIL_ABC_NUM
AND c.COIL_STATUS <> 0
AND p.PROCESS_COIL_STATUS = 0;

type line_tabletype is table of varchar2(32767) index by binary_integer;
line line_tabletype;
j binary_integer := 0;
i int;
coil_count int := 0;

log_file_location varchar2(50):='/export/home/oracle9i';
--log_file_location varchar2(50):='/export/home/oracle11g';
log_file varchar2 (50) := 'check_status_unmatched_coil.log';
log_file_handle UTL_FILE.FILE_TYPE;

begin

SELECT count(*) into coil_count
FROM PROCESS_COIL p, COIL c, customer cu
WHERE c.CUSTOMER_ID = cu.CUSTOMER_ID
and c.COIL_ABC_NUM  = p.COIL_ABC_NUM
AND c.COIL_STATUS <> 0
AND p.PROCESS_COIL_STATUS = 0;

if coil_count > 0 then
  for cur_rec in cur loop
         line(j):= 'COIL_ID: '||to_char(cur_rec.coil_abc_num)||', '||'ABC_JOB_NUM: '||cur_rec.ab_job_num||
                          ', '||'CUSTOMER_NAME: '||cur_rec.customer_short_name||';';
         j := j + 1;
  end loop;
  
  log_file_handle :=utl_file.fopen(log_file_location,log_file,'W');
     
  FOR i IN 0..j-1 LOOP
        utl_file.put_line(log_file_handle,line(i));
  END LOOP;
      
  utl_file.fclose(log_file_handle);  
end if;
  
end p_check_status_unmatched_coil;
