  for coils_rec in coils_cur loop
    ls_customer_name := coils_rec.customer_name;
    ll_coil_abc_num := coils_rec.coil_abc_num;
    ll_coil_net_wt := coils_rec.coil_net_wt;
    ll_sum_process_wt := coils_rec.sum_process_wt;
    
    for process_coils_rec in process_coils_cur loop
      ll_ab_job_num := process_coils_rec.ab_job_num;
      ls_line_desc := process_coils_rec.line_desc;
      ld_time_date_finished := process_coils_rec.time_date_finished;
      
      --utl_file.put_line(edi_file_handle, to_char(ll_ab_job_num) || '     ' || to_char(ll_coil_abc_num) || '           ' || to_char(ll_coil_net_wt) || '           ' || to_char(ll_sum_process_wt));
      
      insert into coils_weight_zeroed_out values
         (
            ls_customer_name,
            ll_coil_abc_num,
            ll_ab_job_num,
            ll_coil_net_wt,
            ll_sum_process_wt,
            ls_line_desc,
            ld_time_date_finished
          );
    end loop;
  end loop;

  commit;
  
  --utl_file.fclose(edi_file_handle);
end;
