    case cloop.coil_status
      when 3 then         -- 3:Rejeced
           ls_coil_status := '2';
           edi_846(j) := 'LIN**PO*' || cloop.purchase_order_num || '*BP*' || cloop.part_num || '*IN*' || cloop.coil_abc_num || '*VN*' || cloop.coil_org_num || '*PK*' || cloop.coil_mid_num || '*VO*' || cloop.supplier_sales_num; j := j + 1;
      when 7 then       -- 7:Rebanded
           ls_coil_status := '7';
           edi_846(j) := 'LIN**PO*' || cloop.purchase_order_num || '*BP*' || cloop.part_num || '*IN*' || cloop.coil_abc_num || '*VN*' || cloop.coil_org_num || '*PK*' || cloop.coil_abc_num || '*VO*' || cloop.supplier_sales_num; j := j + 1;
