set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."P_EDI_870_COIL_STATUS_NOVELIS" IS

Cursor coil_cur IS
select e.coil_abc_num, e.coil_status_change_date
from edi_870_coil_status e
--where e.edi_870_date is null;
where e.coil_abc_num = 84723;

li_return INT;
BEGIN

for coil_rec in coil_cur loop 

li_return := F_EDI_870_COIL_STATUS_NOVELIS(coil_rec.coil_abc_num, coil_rec.coil_status_change_date);

end loop; 

END P_EDI_870_COIL_STATUS_NOVELIS;
