set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."P_EDI_NOVELIS_SCRAP_870" IS
  --BEGIN
  /*
  Aluminum Blanking: Ford Suppler Code: ZZ R0P7A
                     DUNS: 01 039630926T
  Customer: ALCAN(34,35,10,1153)
  Alcan Rolled Product    X.121        0015049350011G
  Kingston Duns: 241003755
  */

  edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';

  --v_edi_text_alcan varchar2(32767);
  -- edi_loc varchar2(50):='/tmp';
  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_prefix VARCHAR2(50) := 'S_novelis_scrap_';
  edi_file_handle utl_file.file_type;
  su_duns         VARCHAR2(10);
  ll_customer_id  INTEGER := 1153;

  ll_gs_log INTEGER;
  ll_st_log INTEGER;
  --ll_bsn_log integer;

  ls_today   VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD');
  ls_today_4 VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  ls_now     VARCHAR2(20) := to_char(SYSDATE, 'HH24MI'); -- time in 24 hours format....Tony

  ls_po VARCHAR2(20);

  --ll_edi_file_id integer;
  ll_edi_file_id_alcan INTEGER;

  ll_item_count INTEGER;
  ls_alloy      scrap_skid.scrap_alloy2%TYPE;
  --li_customer_id shipment.customer_id%TYPE;
  --li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;

  li_hl01 INTEGER;
  /* Dec 23rd 02 changed by tony for re-assigned skid with other order
  Cursor alcan_870_cur IS
  SELECT   production_sheet_item.AB_JOB_NUM,
           production_sheet_item.prod_item_pieces,
           SHEET_SKID.SHEET_SKID_NUM,
           production_sheet_item.prod_item_net_wt,
           SHEET_SKID.SKID_SHEET_STATUS,
           coil.coil_org_num,
           NVL(customer_order.sales_order, 'NA') sales_order,
           NVL(customer_order.orig_customer_po, 'NA') customer_po,
           (SHEET_SKID.SHEET_NET_WT + SHEET_SKID.SHEET_TARE_WT) skid_gross_wt,
           NULL Done
  FROM     SHEET_SKID, production_sheet_item, sheet_skid_detail,coil,ab_job, customer_order
  WHERE        (sheet_skid.skid_sheet_status in ( 2, 4, 13)) and
               (production_sheet_item.prod_item_edi870_date is NULL ) and
               (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num) and
               (sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num) and
               (coil.coil_abc_num = production_sheet_item.coil_abc_num ) and
               (coil.customer_id = 1153) and
               (production_sheet_item.ab_job_num = ab_job.ab_job_num) and
               (ab_job.order_abc_num = customer_order.order_abc_num) ;


  */

  --Begin of change

  CURSOR cust_cur IS
    SELECT customer_id
      FROM customer
     WHERE customer_id IN (1153, 1459, 2582); ---Add customer id here if you want to send 870 for more customers

  --End of change by tony

  CURSOR c_novelis_scrap_pack_870 IS
    SELECT return_scrap_item.return_scrap_item_num,
           return_scrap_item.coil_abc_num,
           return_scrap_item.ab_job_num,
           return_scrap_item.return_item_net_wt,
           return_scrap_item.return_item_date,
           return_scrap_item.scrap_item_pieces,
           scrap_skid.scrap_skid_num,
           scrap_skid.scrap_skid_display_num,
           scrap_skid.customer_id,
           scrap_skid.scrap_temper,
           scrap_skid.scrap_alloy2,
           scrap_skid.scrap_net_wt,
           scrap_skid.scrap_tare_wt,
           scrap_skid.skid_scrap_status,
           scrap_skid.scrap_date,
           scrap_skid.scrap_cust_po
      FROM return_scrap_item, scrap_skid, scrap_skid_detail
     WHERE (return_scrap_item.scrap_item_870_date IS NULL AND
           return_scrap_item.scrap_870_icn IS NULL)
       AND scrap_skid.customer_id = ll_customer_id
       AND scrap_skid.skid_scrap_status IN (2, 4, 13)
       AND return_scrap_item.return_scrap_item_num =
           scrap_skid_detail.return_scrap_item_num
       AND scrap_skid.scrap_skid_num = scrap_skid_detail.scrap_skid_num;

  --Type skidinfo_tabletype IS table of alcan_870_cur%ROWTYPE INDEX by binary_integer;
  --skidinfo_table skidinfo_tabletype;

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;
  --item_rec alcan_870_cur%rowtype;
  --scrap_item_rec c_novelis_scrap_pack_870%rowtype;
  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;
  --TYPE scrap_item_type IS TABLE OF return_scrap_item.return_scrap_item_num%type INDEX BY BINARY_INTEGER;
  --scrap_item_num scrap_item_type;

BEGIN

  FOR cust_rec IN cust_cur LOOP
    --- Outer loop of customer_id
    ll_customer_id := cust_rec.customer_id;
    i              := 0;
    k              := 0;

    SELECT COUNT(*)
      INTO ll_item_count
      FROM return_scrap_item, scrap_skid, scrap_skid_detail
     WHERE (return_scrap_item.scrap_item_870_date IS NULL AND
           return_scrap_item.scrap_870_icn IS NULL)
       AND scrap_skid.customer_id = ll_customer_id
       AND scrap_skid.skid_scrap_status IN (2, 4, 13)
       AND return_scrap_item.return_scrap_item_num =
           scrap_skid_detail.return_scrap_item_num
       AND scrap_skid.scrap_skid_num = scrap_skid_detail.scrap_skid_num;
    -- if ll_item_count = 0 then return 100; end if;   -- nothing to send

    IF ll_item_count > 0 THEN

      SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
      SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;

      SELECT customer.customer_duns_number_string
        INTO su_duns
        FROM customer
       WHERE customer.customer_id = ll_customer_id;

      x12_table(i) := 'ISA*00*' ||
                      '          *00*          *01*039630926T     *09*0015049350011G *' ||
                      ls_today_4 || '*' || ls_now || '*U*00401*' ||
                      lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
      i := i + 1;
      x12_table(i) := 'GS*RS*039630926T*' || '001504935001' || '*' ||
                      ls_today || '*' || ls_now || '*' ||
                      to_char(ll_gs_log) || '*X*' || '004010';
      i := i + 1;
      x12_table(i) := 'ST*870*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                      '***' || ls_now || '*****';
      i := i + 1;
      x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
      i := i + 1;
--      x12_table(i) := 'N1*SU**1*' || su_duns || '*NA'; - by james 11/6/2013
      x12_table(i) := 'N1*SU**1*' || su_duns;
      i := i + 1;
      x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926T';
      i := i + 1;

      --open alcan_870_cur;
      --fetch alcan_870_cur INTO item_rec;
      --close alcan_870_cur;

      li_hl01 := 1;

      FOR item_rec IN c_novelis_scrap_pack_870 LOOP
        x12_table(i) := 'HL*' || to_char(li_hl01) || '**I';
        i := i + 1;

        -- No need for this part due to the change in alcan_870_cur   ---------By Tony 04-29-03

        -- Referece PO and Sales order via Ref_order due to coil reassigning    Bing on Sep 5, 2002
        /*
          SELECT
               NVL(customer_order.sales_order, 'NA') INTO item_rec.sales_order
          FROM   SHEET_SKID, customer_order
          WHERE       (customer_order.order_abc_num = sheet_skid.ref_order_abc_num)  and
                      (sheet_skid.sheet_skid_num = item_rec.sheet_skid_num);

          SELECT
               NVL(customer_order.orig_customer_po, 'NA') INTO item_rec.customer_po
          FROM         SHEET_SKID, customer_order
          WHERE       (customer_order.order_abc_num = sheet_skid.ref_order_abc_num)  and
                      (sheet_skid.sheet_skid_num = item_rec.sheet_skid_num);
        */

        -- End of change tony 04-29-03

        -- Trunc PO by Bing on Jan 11, 2001
        ls_alloy := item_rec.scrap_alloy2;

        --SELECT NVL(ALCAN_SCRAP_PO, '6800'||ls_alloy) into ls_po
        --FROM ALLOY_TYPE
        --WHERE ALLOY = upper(rtrim(ltrim(ls_alloy))) and CUSTOMER_ID = ll_customer_id;

        ls_alloy := upper(ltrim(rtrim(ls_alloy)));
        --Change this to real PO later
        ls_po := 'NA';
        --Tony
        x12_table(i) := 'PRF*' || ls_po || '****NA';
        i := i + 1;
        x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
        i := i + 1;
        -- Nov 21 03, change per Alcan  ---tony
        --x12_table(i) := 'REF*SE*' ||item_rec.coil_org_num ||'-'||to_char(item_rec.sheet_skid_num); i := i+1;
        x12_table(i) := 'DTM*ZZZ*' || ls_today || '*' || ls_now || '*ED';
        i := i + 1;

        x12_table(i) := 'REF*SE*' ||
                        to_char(item_rec.scrap_skid_display_num);
        i := i + 1;
        --x12_table(i) := 'REF*SE*' || 'NA'; i := i+1;
        x12_table(i) := 'REF*MI*' || to_char(item_rec.ab_job_num);
        i := i + 1;

        -- Nov 21 03, change per Alcan  ---tony
        --x12_table(i) := 'REF*RV*' ||item_rec.coil_org_num || to_char(item_rec.sheet_skid_num) ||'*NA'; i := i+1;

        --Testing
        x12_table(i) := 'REF*RV*' ||
                        to_char(item_rec.return_scrap_item_num) || '*NA';
        i := i + 1;
        --x12_table(i) := 'REF*RV*' || 'NA' ||'*NA'; i := i+1;

        --06/05/03 Don't send PO106 AND PO107 incase non sales order available as per Julia
        --IF item_rec.sales_order = ' ' THEN
        --   x12_table(i) := 'PO1**1*UN****' || '***SN*' ||item_rec.Scrap_Skid_Num ; i := i+1;
        x12_table(i) := 'PO1**1*UN****' || '***SN*' || 'NA';
        i := i + 1;
        --ELSE
        --    x12_table(i) := 'PO1**1*UN***VO*' || item_rec.sales_order ||'***SN*' ||item_rec.coil_org_num; i := i+1;
        --END IF;

        -- Added partial ready(13), On-hold(4) by Bing Feb-26-2002
        --IF item_rec.skid_sheet_status = 2 then
        x12_table(i) := 'PID*S*55***' || ls_alloy;
        i := i + 1;
        x12_table(i) := 'PID*S*MAC*ST*03';
        i := i + 1;

        x12_table(i) := 'PID*S*MA*ST*Z*' ||
                        to_char(item_rec.scrap_skid_display_num);
        i := i + 1;
        --ELSIF item_rec.skid_sheet_status = 13 then
        --x12_table(i) := 'PID*S*MA*ST*8*' || to_char(item_rec.sheet_skid_num) || '*NA'; i := i+1;
        --ELSE
        --x12_table(i) := 'PID*S*MA*ST*3*' || to_char(item_rec.sheet_skid_num) || '*NA'; i := i+1;
        --END IF;

        x12_table(i) := 'PID*S*PR*ST*99';
        i := i + 1;
        x12_table(i) := 'MEA*WT*N*' || to_char(item_rec.scrap_net_wt) ||
                        '*LB*01';
        i := i + 1;
        x12_table(i) := 'MEA*WT*G*' ||
                        to_char(item_rec.scrap_net_wt +
                                item_rec.scrap_tare_wt) || '*LB*01';
        i := i + 1;
        --    x12_table(i) := 'MEA*CT*NA*' || to_char(item_rec.scrap_item_pieces ) || '*PC'; i:= i+1;

        li_hl01 := li_hl01 + 1;

        item_num(k) := item_rec.return_scrap_item_num;
        k := k + 1;

      END LOOP;
      x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
      i := i + 1;
      x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
      i := i + 1;
      x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

      -- Write EDI to file

      IF li_hl01 > 1 THEN
        -- WRITE EDI FILE ONLY IF ITEM > 0
        SELECT edi_file_id_seq.nextval INTO ll_edi_file_id_alcan FROM dual;
-- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
--        edi_file        := 'S_novelis_scrap_' ||
--                           to_char(ll_edi_file_id_alcan) || '.870';
        edi_file        := edi_file_prefix || to_char(ll_edi_file_id_alcan) || '.edi';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        FOR j IN 0 .. i LOOP
          utl_file.put_line(edi_file_handle, x12_table(j));
          -- v_edi_text_alcan:=v_edi_text_alcan||x12_table(j)||CHR(10);
        END LOOP;
        utl_file.fclose(edi_file_handle);
      END IF; -- END WRITING EDI FILE

      /* --added by Victor Huang on 06/05 for function acknowlegement
      INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
      VALUES(ll_gs_log, su_duns, sysdate, edi_file);
      COMMIT;*/

      --added by Victor Huang on 12/07 for verifying 997
      INSERT INTO outbound_edi_transaction
        (edi_file_id,
         duns_from,
         duns_to,
         interchange_control_number,
         group_control_number,
         transaction_time,
         edi_file_name,
         fa_receive_status,
         customer_id,
         set_control_num,
         transaction_type_id)
      VALUES
        (ll_edi_file_id_alcan,
         '039630926',
         su_duns,
         ll_gs_log,
         ll_gs_log,
         SYSDATE,
         edi_file,
         0,
         ll_customer_id,
         ll_st_log,
         '870');
      COMMIT;

      edi_file        := 'send_edi_log';
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      /*
      UPDATE production_sheet_item
         SET prod_item_edi870_date= SYSDATE

         WHERE  production_sheet_item.prod_item_num in
               ( select production_sheet_item.prod_item_num from SHEET_SKID, production_sheet_item, sheet_skid_detail,coil, customer_order
                  where
                 (production_sheet_item.prod_item_edi870_date is NULL ) and
                 (sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num) and
                 (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num) and
                 (sheet_skid.skid_sheet_status in (2, 4, 13)) and
                 (coil.coil_abc_num = production_sheet_item.coil_abc_num ) and
                 (coil.customer_id = ll_customer_id) and
                 (sheet_skid.ref_order_abc_num = customer_order.order_abc_num)
               );

      */
      FOR m IN 0 .. k - 1 LOOP
        UPDATE return_scrap_item
           SET return_scrap_item.scrap_item_870_date = SYSDATE,
               return_scrap_item.scrap_870_icn       = ll_gs_log
         WHERE return_scrap_item.return_scrap_item_num = item_num(m);
      END LOOP;

      COMMIT;

    END IF; --end if in select count(*)

  END LOOP; ------ End of outer loop customer_id

EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN;
END;
--END p_edi_novelis_scrap_870;
  GRANT EXECUTE ON "DBO"."P_EDI_NOVELIS_SCRAP_870" TO "AGERLANTS"
--------------------------------------------------------
