--  DDL for Procedure P_I863_TO_PST_AND_LW
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."P_I863_TO_PST_AND_LW" is
  
  ls_coil_org_num varchar2(32);
  li_coil_abc_num integer;
  li_edi_file_id integer;
  li_count integer;

  ls_yts_val_11 varchar2(20);
  ls_uts_val_11 varchar2(20);
  ls_elong_val_11 varchar2(20);
  ls_r_val_11 varchar2(20);
  ls_n_val_11 varchar2(20);
  ls_thickness_11 varchar2(20);
  
  ls_yts_val_12 varchar2(20);
  ls_uts_val_12 varchar2(20);
  ls_elong_val_12 varchar2(20);
  ls_r_val_12 varchar2(20);
  ls_n_val_12 varchar2(20);
  ls_thickness_12 varchar2(20);
  
  ls_yts_val_13 varchar2(20);
  ls_uts_val_13 varchar2(20);
  ls_elong_val_13 varchar2(20);
  ls_r_val_13 varchar2(20);
  ls_n_val_13 varchar2(20);
  ls_thickness_13 varchar2(20);
  
  ls_yts_val_21 varchar2(20);
  ls_uts_val_21 varchar2(20);
  ls_elong_val_21 varchar2(20);
  ls_r_val_21 varchar2(20);
  ls_n_val_21 varchar2(20);
  ls_thickness_21 varchar2(20);

  ls_wd varchar2(20);
  ls_th varchar2(20);
  ld_date date;
  
  ls_lube_weight varchar2(20);
  
  
  Cursor  id_and_coil_cursor IS
  SELECT  edi_file_id, coil_num
  FROM 		inbound_863
  WHERE   (status is null) or (status = 0); 
  
  id_and_coil_item id_and_coil_cursor%rowtype;
   
begin

OPEN id_and_coil_cursor;

Loop
    FETCH id_and_coil_cursor INTO id_and_coil_item;
    EXIT WHEN id_and_coil_cursor%NOTFOUND;

    li_edi_file_id := id_and_coil_item.edi_file_id;
    ls_coil_org_num := id_and_coil_item.coil_num;
    
    select count(coil_abc_num) into li_count
    from coil
    where coil_org_num = ls_coil_org_num and customer_id = 1153;
    
    --need to handle li_count <> 1 ???
    if li_count = 1 then
       ld_date := sysdate;
       
       select coil_abc_num into li_coil_abc_num 
       from coil
       where coil_org_num = ls_coil_org_num and customer_id = 1153;
           
       select tty_f_m2, ttu_f_m2, tel_f_m2, trl_f_m2, tnl_f_m2,
              tto_f_m2, tts_f_m2, tes_f_m2, trd_f_m2, tnd_f_m2,
              ttt_f_m2, ttl_f_m2, tet_f_m2, trt_f_m2, tnt_f_m2,
              tty_b_m2, ttu_b_m2, tel_b_m2, trl_b_m2, tnl_b_m2,
              wd, th,
              two              
       into ls_yts_val_11, ls_uts_val_11, ls_elong_val_11, ls_r_val_11, ls_n_val_11,
            ls_yts_val_12, ls_uts_val_12, ls_elong_val_12, ls_r_val_12, ls_n_val_12,
            ls_yts_val_13, ls_uts_val_13, ls_elong_val_13, ls_r_val_13, ls_n_val_13,
            ls_yts_val_21, ls_uts_val_21, ls_elong_val_21, ls_r_val_21, ls_n_val_21,
            ls_wd, ls_th,
            ls_lube_weight
       from inbound_863
       where edi_file_id = li_edi_file_id and coil_num = ls_coil_org_num;     
       
       if not( (ls_yts_val_11 is null) and (ls_uts_val_11 is null) and (ls_elong_val_11 is null) and (ls_r_val_11 is null) and (ls_n_val_11 is null) ) then      
         insert into pst_test_result(coil_abc_num, position, created_date, source_id, test_type, yts_val, uts_val, elong_val, r_val, n_val, thickness, width)
         values (li_coil_abc_num, '11', ld_date, 1153, 4, to_number(ls_yts_val_11), to_number(ls_uts_val_11), to_number(ls_elong_val_11), to_number(ls_r_val_11), to_number(ls_n_val_11), to_number(ls_th), to_number(ls_wd) );
       end if;
       
       if not( (ls_yts_val_12 is null) and (ls_uts_val_12 is null) and (ls_elong_val_12 is null) and (ls_r_val_12 is null) and (ls_n_val_12 is null) ) then
         insert into pst_test_result(coil_abc_num, position, created_date, source_id, test_type, yts_val, uts_val, elong_val, r_val, n_val, thickness, width)
         values (li_coil_abc_num, '12', ld_date, 1153, 4, to_number(ls_yts_val_12), to_number(ls_uts_val_12), to_number(ls_elong_val_12), to_number(ls_r_val_12), to_number(ls_n_val_12), to_number(ls_th), to_number(ls_wd) );
       end if;
       
       if not( (ls_yts_val_13 is null) and (ls_uts_val_13 is null) and (ls_elong_val_13 is null) and (ls_r_val_13 is null) and (ls_n_val_13 is null) ) then
         insert into pst_test_result(coil_abc_num, position, created_date, source_id, test_type, yts_val, uts_val, elong_val, r_val, n_val, thickness, width)
         values (li_coil_abc_num, '13', ld_date, 1153, 4, to_number(ls_yts_val_13), to_number(ls_uts_val_13), to_number(ls_elong_val_13), to_number(ls_r_val_13), to_number(ls_n_val_13), to_number(ls_th), to_number(ls_wd) );
       end if;
       
       if not( (ls_yts_val_21 is null) and (ls_uts_val_21 is null) and (ls_elong_val_21 is null) and (ls_r_val_21 is null) and (ls_n_val_21 is null) ) then
         insert into pst_test_result(coil_abc_num, position, created_date, source_id, test_type, yts_val, uts_val, elong_val, r_val, n_val, thickness, width)
         values (li_coil_abc_num, '21', ld_date, 1153, 4, to_number(ls_yts_val_21), to_number(ls_uts_val_21), to_number(ls_elong_val_21), to_number(ls_r_val_21), to_number(ls_n_val_21), to_number(ls_th), to_number(ls_wd) );
       end if;
       
       if not( ls_lube_weight is null ) then
         insert into lube_weight(coil_abc_num, lube_weight_item_num, lube_weight, process_date, process_by)
         values (li_coil_abc_num, li_edi_file_id, to_number(ls_lube_weight), ld_date, 'ALCAN');
       
         select count(*) into li_count from coil_lube_weight
         where coil_abc_num = li_coil_abc_num;
         if li_count = 0 then
            insert into coil_lube_weight(coil_abc_num, source_customer_id, ready_status, set_ready_time)
            values (li_coil_abc_num, 1153, 1, ld_date);
         else
             update coil_lube_weight
             set source_customer_id = 1153, ready_status = 1, set_ready_time = ld_date
             where coil_abc_num = li_coil_abc_num;
         end if;
       end if; 
        
       update inbound_863
       set status = 1
       where edi_file_id = li_edi_file_id and coil_num = ls_coil_org_num;
       
   end if;
   
   commit;
       
End Loop; 

return;

exception
 when dup_val_on_index then
 rollback;
 return ;
end P_I863_TO_PST_AND_LW;
  GRANT EXECUTE ON "DBO"."P_I863_TO_PST_AND_LW" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Procedure P_INVENTORY_REPORT
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."P_INVENTORY_REPORT" (p_date        IN VARCHAR2,
                                               p_customer_id IN VARCHAR2) -- p_date in "MM-DD-YYYY"; p_customer_id: 0 for All customers

 IS
  l_output        utl_file.file_type;
  l_thecursor     INTEGER DEFAULT dbms_sql.open_cursor;
  l_columnvalue   VARCHAR2(2000);
  l_status        INTEGER;
  l_colcnt        NUMBER DEFAULT 0;
  l_separator     VARCHAR2(10) DEFAULT '';
  l_cnt           NUMBER DEFAULT 0;
  l_dir           VARCHAR2(256) := '/tmp';
  l_filename      VARCHAR2(256) := 'ir.csv';
  l_csv_separator VARCHAR2(1) := ',';
  l_query         VARCHAR2(2000);
  l_customer_name VARCHAR2(32);
  l_customer_id   customer.customer_id%TYPE;

BEGIN
  l_customer_id := to_number(p_customer_id);
  IF l_customer_id = 0 THEN
    l_customer_name := 'ALL';
  ELSE
    SELECT c.customer_short_name
      INTO l_customer_name
      FROM customer c
     WHERE c.customer_id = l_customer_id;
  END IF;

  l_customer_name := TRIM(l_customer_name);
  l_filename      := l_customer_name || '_' || p_date || '.csv';

  l_query := 'select t.coil_abc_num, t.coil_org_num, t.coil_mid_num, (CASE t.coil_status WHEN 0 THEN ''Done'' WHEN 1 THEN ''inProcess'' WHEN 2 THEN ''New'' WHEN 3 THEN ''Rejected'' WHEN 4 THEN ''OnHold'' WHEN 5 THEN ''InTransit'' WHEN 6 THEN ''Returned'' WHEN 7 THEN ''Rebanded'' WHEN 8 THEN ''Retry'' WHEN 10 THEN ''Gone'' ELSE ''Other'' END ), t.coil_temper, t.lot_num, t.coil_gauge, t.coil_alloy2, t.coil_width, t.date_received, t.coil_entry_date, t.net_wt, t.net_wt_balance, f_get_coil_duration(t.coil_abc_num)' ||
