--  DDL for Procedure P_RECOVERY_REPORT
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."P_RECOVERY_REPORT" ( p_date in varchar2, p_customer_id in varchar2) -- p_date in "MM-DD-YYYY"; p_customer_id: 0 for All customers

is
    l_output        utl_file.file_type;
    l_theCursor     integer default dbms_sql.open_cursor;
    l_columnValue   varchar2(2000);
    l_status        integer;
    l_colCnt        number default 0;
    l_separator     varchar2(10) default '';
    l_cnt           number default 0;
    l_dir           varchar2(256) := '/tmp';
    l_filename      varchar2(256) := 'recovery_report.csv';
    l_csv_separator varchar2(1):= ',';
    l_query         varchar2(2000);
    l_customer_name varchar2(32);
    l_customer_id   customer.customer_id%type;
    
begin
    l_customer_id := to_number(p_customer_id); 
    if l_customer_id = 0 then
      l_customer_name := 'ALL';
    else    
      select c.customer_short_name into l_customer_name
      from customer c
      where c.customer_id = l_customer_id;
    end if;
    
    l_customer_name := trim(l_customer_name);    
    l_filename := 'recovery_report_' || p_date || '_' || l_customer_name||'.csv';
    
    
    l_query := 'select cu1.customer_short_name, j.job_done_time, c.coil_org_num, c.lot_num, Null, j.ab_job_num, o.orig_customer_po,  cu2.customer_short_name, i.material_end_use, Null, l.line_desc, c.coil_alloy2, c.coil_temper, c.coil_gauge, c.coil_width, f_get_part_length_per_job(j.ab_job_num), (select process_quantity from process_coil where coil_abc_num = c.coil_abc_num and ab_job_num = j.ab_job_num), f_get_coil_ship_wt(c.coil_abc_num, j.ab_job_num), f_get_coil_rebanded_wt(c.coil_abc_num, process_quantity), f_get_coil_rejected_wt(c.coil_abc_num, process_quantity) '||
               ' from coil c, ab_job j, process_coil p, customer_order o, order_item i, customer cu1, customer cu2, line l'||
               ' where (j.order_item_num = i.order_item_num and j.order_abc_num = i.order_abc_num)'||
               ' and i.order_abc_num = o.order_abc_num'||
               ' and o.orig_customer_id = cu1.customer_id'||
               ' and o.enduser_id = cu2.customer_id'||
               ' and c.coil_abc_num = p.coil_abc_num'||
               ' and j.ab_job_num = p.ab_job_num'||
               ' and l.line_num = j.line_num'||
               ' and TO_CHAR(j.job_done_time, ''MM-DD-YYYY'') = ''' || p_date || ''''||
               ' order by cu1.customer_short_name, j.job_done_time, c.coil_org_num, j.ab_job_num';
    
    if l_customer_id <> 0
    then l_query := l_query || 'and o.orig_customer_id = ' || p_customer_id;
    end if;
                                 
    l_output := utl_file.fopen( l_dir, l_filename, 'w' );
    
    utl_file.put_line(l_output, 'Customer Name, Process Date, Coil#, Coil Lot#, Pack#, AB Job#, Customer PO#, End User,  Material End Use, Product Type, BL#, Alloy, Temper, Gauge, Width, Length, Coil Begin WT, Total Ship WT, Reband WT, Reject WT');

    dbms_sql.parse(  l_theCursor,  l_query, dbms_sql.native );

    for i in 1 .. 255 loop
        begin
            dbms_sql.define_column( l_theCursor, i, l_columnValue, 2000 );
            l_colCnt := i;
        exception
            when others then
                if ( sqlcode = -1007 ) then exit;
                else
                    raise;
                end if;
        end;
    end loop;

    dbms_sql.define_column( l_theCursor, 1, l_columnValue, 2000 );

    l_status := dbms_sql.execute(l_theCursor);

    loop
        exit when ( dbms_sql.fetch_rows(l_theCursor) <= 0 );
        l_separator := '';
        for i in 1 .. l_colCnt loop
            dbms_sql.column_value( l_theCursor, i, l_columnValue );
            utl_file.put( l_output, l_separator || l_columnValue );
            l_separator := l_csv_separator;
        end loop;
        utl_file.new_line( l_output );
        l_cnt := l_cnt+1;
    end loop;
    dbms_sql.close_cursor(l_theCursor);

    utl_file.fclose( l_output );
    
end P_RECOVERY_REPORT;
  GRANT EXECUTE ON "DBO"."P_RECOVERY_REPORT" TO "AGERLANTS"
