--  DDL for Procedure P_RECOVERY_REPORT_A_C
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."P_RECOVERY_REPORT_A_C" ( p_date in varchar2, p_customer_id in varchar2) -- p_date in "MM-DD-YYYY"; p_customer_id: 0 for All customers

is
    l_output        utl_file.file_type;
    l_output_kingston_auto utl_file.file_type;
    l_theCursor     integer default dbms_sql.open_cursor;
    l_columnValue   varchar2(2000);
    l_status        integer;
    l_colCnt        number default 0;
    l_separator     varchar2(10) default '';
    l_cnt           number default 0;
    l_dir           varchar2(256) := '/tmp';
    l_filename      varchar2(256) := 'recovery_report.csv';
    l_filename_kingston_auto varchar2(256) := 'recovery_report_kingston_auto.csv';
    l_csv_separator varchar2(1):= ',';
    l_query         varchar2(2000);
    l_customer_name varchar2(32);
    l_customer_id   customer.customer_id%type;
    
   cursor select_cursor is
               select cu1.customer_short_name customer_short_name, cu1.customer_id customer_id, j.job_done_time job_done_time, c.coil_org_num coil_org_num, c.lot_num lot_num, j.ab_job_num ab_job_num, o.orig_customer_po orig_customer_po,  cu2.customer_short_name end_user, cu2.customer_id end_user_id, i.material_end_use material_end_use, l.line_desc line_desc, c.coil_alloy2 coil_alloy2, c.coil_temper coil_temper, c.coil_gauge coil_gauge, c.coil_width coil_width, f_get_part_length_per_job(j.ab_job_num) length, (select process_quantity from process_coil where coil_abc_num = c.coil_abc_num and ab_job_num = j.ab_job_num) begin_wt, NVL(f_get_coil_ship_wt(c.coil_abc_num, j.ab_job_num),0) ship_wt, f_get_coil_rebanded_wt(c.coil_abc_num, process_quantity) reband_wt, f_get_coil_rejected_wt(c.coil_abc_num, process_quantity) reject_wt
               from coil c, ab_job j, process_coil p, customer_order o, order_item i, customer cu1, customer cu2, line l
               where (j.order_item_num = i.order_item_num and j.order_abc_num = i.order_abc_num)
               and i.order_abc_num = o.order_abc_num
               and o.orig_customer_id = cu1.customer_id
               and o.enduser_id = cu2.customer_id
               and c.coil_abc_num = p.coil_abc_num
               and j.ab_job_num = p.ab_job_num
               and l.line_num = j.line_num
               --and c.net_wt > 0           --excluding warehouse coil
               and TO_CHAR(j.job_done_time, 'MM-DD-YYYY') =  p_date 
               order by cu1.customer_short_name, c.coil_org_num, j.ab_job_num;
               
    ls_customer_name_cur customer.customer_short_name%type := '';
    li_customer_id_cur customer.customer_id%type :=0;
    ldt_process_date_cur ab_job.due_date%type := sysdate;
    ls_coil_org_num_cur coil.coil_org_num%type := '';
