    ls_po_cur customer_order.orig_customer_po%type := '';
    ls_end_user_cur customer.customer_short_name%type := '';
    li_end_user_id_cur customer.customer_id%type := 0;
    ls_material_end_use_cur order_item.material_end_use%type := '';
