    li_total_wt_cur coil.net_wt%type := 0;
    li_reband_wt_cur coil.net_wt%type := 0;
    ls_reband_wt_cur varchar2(64) := '';      --used for combined reband wt
    li_reject_wt_cur coil.net_wt%type := 0;
    ls_reject_wt_cur varchar2(64) := '';      --used for combined reject wt
    
    ls_customer_name_pre customer.customer_short_name%type := '';
    li_customer_id_pre customer.customer_id%type :=0;
