             utl_file.put_line(l_output_kingston_auto, ls_customer_name_cur||','||to_char(ldt_process_date_cur, 'MM-DD-YY')||','||ls_coil_org_num_cur||','||ls_coil_lot_cur||','||' '||','||ls_ab_job_num_cur||','||ls_po_cur||','||ls_end_user_cur||','||ls_material_end_use_cur||','||' '||','||ls_bl_desc_cur||','||ls_alloy_cur||','||ls_temper_cur||','||to_char(li_gauge_cur)||','||to_char(li_width_cur)||','||to_char(li_length_cur)||','||to_char(li_begin_wt_cur)||','||to_char(li_total_wt_cur)||','||ls_reband_wt_cur||','||ls_reject_wt_cur);
           else
             utl_file.put_line(l_output, ls_customer_name_cur||','||to_char(ldt_process_date_cur, 'MM-DD-YY')||','||ls_coil_org_num_cur||','||ls_coil_lot_cur||','||' '||','||ls_ab_job_num_cur||','||ls_po_cur||','||ls_end_user_cur||','||ls_material_end_use_cur||','||' '||','||ls_bl_desc_cur||','||ls_alloy_cur||','||ls_temper_cur||','||to_char(li_gauge_cur)||','||to_char(li_width_cur)||','||to_char(li_length_cur)||','||to_char(li_begin_wt_cur)||','||to_char(li_total_wt_cur)||','||ls_reband_wt_cur||','||ls_reject_wt_cur);
