--  DDL for Procedure REPLICATE_COIL_DATA
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."REPLICATE_COIL_DATA" IS
--v_status integer;
--v_customer_id number(6,0);
--v_coil_abc_num NUMBER(6,0);
--v_coil_org_num varchar2(100);
--v_alloy2 varchar2(50);
--v_coil_temper varchar2
out_file  UTL_FILE.File_Type;
  CURSOR coil_cursor IS
  SELECT coil_abc_num, 
         customer_id,
         coil_org_num, 
         coil_alloy2, 
         coil_temper 
  FROM coil
  WHERE (customer_id=35 or customer_id =1153);-- and replicate <> 1;
  coil_rec coil_cursor%rowtype;
BEGIN
-- Beginning of the procedure    
  
 -- SELECT coil_abc_num
--        INTO v_coil_abc_num
--  FROM coil
--     WHERE (customer_id=35 or customer_id =1153) and replicate <> 1;
--      IF NOT SQL%FOUND THEN
--         RETURN;
--      END IF; 

    open coil_cursor;
    fetch coil_cursor into coil_rec;
    if coil_cursor%NOTFOUND THEN
    close coil_cursor;
    return;
    else 
    close coil_cursor;
    end if;
   
--  v_status:=0;
  out_file:= UTL_FILE.FOPEN('/tmp','coil_info','w');

  
  for cur_record in coil_cursor loop
       UTL_FILE.PUT_LINE(out_file,to_char(cur_record.coil_abc_num)||','||to_char(cur_record.customer_id)||','
         ||cur_record.coil_org_num||','
         ||cur_record.coil_alloy2||','||cur_record.coil_temper||',');  
  end loop;
     UTL_FILE.FFLUSH(out_file);
     UTL_FILE.FCLOSE(out_file);  
  IF coil_cursor%ISOPEN THEN 
        close coil_cursor;
      END IF;
       
   
   
   EXCEPTION
     WHEN UTL_FILE.INVALID_PATH THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN; 
     WHEN UTL_FILE.INVALID_MODE THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN;
    WHEN UTL_FILE.INVALID_OPERATION THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN;   
    WHEN UTL_FILE.WRITE_ERROR THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN;      
    WHEN OTHERS THEN
     UTL_FILE.FCLOSE_ALL;
      RETURN;
      
END;
  GRANT EXECUTE ON "DBO"."REPLICATE_COIL_DATA" TO "AGERLANTS"
