--  DDL for Procedure T_EDI_846_FOR_NOVELIS_KINGSTON
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."T_EDI_846_FOR_NOVELIS_KINGSTON" is
/*
This procedure creates EDI846 (Inventory Advice) for Novelis Kingston, which includes Novelis's coil information.
This procedure will be called from the cron job in the OS, runs periodically.
*/



  type edi_846_tabletype is table of varchar2(32767) index by binary_integer;
  edi_846 edi_846_tabletype;
  j binary_integer := 0;
  i integer := 0;
  edi_file_prefix VARCHAR2(50) := 'S_novelis_kingston_';

  li_customer_id int := 1153;          --Novelis Kingston : 1153
                                       --Novelis Oswego : 1459
  ls_duns varchar2(16) := '241003755'; --'241003755':Novelis Kingston's DUNS#
                                       --'003980216':Novelis Oswego's DUNS#

  ls_coil_status varchar2(2);
  ls_skid_status varchar2(2);

  cursor coil_cursor is
  select c.coil_abc_num, c.coil_org_num, NVL(c.coil_mid_num, 'NA') coil_mid_num, NVL(c.part_num, 'NA') part_num, NVL(c.supplier_sales_num, 'NA') supplier_sales_num, NVL(c.purchase_order_num, 'NA') purchase_order_num,  c.net_wt_balance, c.coil_status
  from coil c
  where -- c.coil_status not in (0, 10) and
        c.coil_status in (1, 2, 3, 4, 7, 11) and    -- coil status: 0:Done; 1:InProcess; 2:New; 3:Rejected; 4:OhHold; 6:Returned; 7:Rebanded; 10:Gone;  11:QAOnHold
        c.customer_id = li_customer_id   ;

  cursor skid_cursor is
  select psi.prod_item_num,
         ss.sheet_skid_num,
         psi.prod_item_net_wt,
         ss.skid_sheet_status,
        (ss.sheet_net_wt + ss.sheet_tare_wt) skid_gross_wt,
         c.coil_org_num, NVL(c.coil_mid_num, 'NA') coil_mid_num, NVL(c.part_num, 'NA') part_num, NVL(c.supplier_sales_num, 'NA') supplier_sales_num, NVL(c.purchase_order_num, 'NA') purchase_order_num
  from coil c, sheet_skid ss, production_sheet_item psi, sheet_skid_detail ssd
  where c.coil_abc_num = psi.coil_abc_num and
        psi.prod_item_num = ssd.prod_item_num and
        ssd.sheet_skid_num = ss.sheet_skid_num and
        ss.skid_sheet_status in (2, 4, 13) and  --Skid status: 2:Ready; 4:OnHold; 13:Partial Ready
        c.customer_id = li_customer_id   ;


  /*cursor coil_cursor_donebutnotshipped is
  select distinct c.coil_abc_num, c.coil_org_num, NVL(c.coil_mid_num, 'NA') coil_mid_num, NVL(c.part_num, 'NA') part_num, NVL(c.supplier_sales_num, 'NA') supplier_sales_num, NVL(c.purchase_order_num, 'NA') purchase_order_num,  c.net_wt_balance, c.coil_status
  from coil c, sheet_skid ss, production_sheet_item psi, sheet_skid_detail ssd
  where c.coil_abc_num = psi.coil_abc_num and
        psi.prod_item_num = ssd.prod_item_num and
        ssd.sheet_skid_num = ss.sheet_skid_num and
        c.coil_status = 0 and    -- coil status: 0:Done; 1:InProcess; 2:New; 3:Rejected; 4:OhHold; 6:Returned; 7:Rebanded  11:QAOnHold
        ss.skid_sheet_status <> 0 and
        c.customer_id = li_customer_id   ;  */


  li_gs_log INTEGER;
  li_st_log INTEGER;
  ls_today_short VARCHAR2(20);
  ls_today VARCHAR2(20);
  ls_now VARCHAR2(20);

--  li_coil_abc_num coil.coil_abc_num%type;
--  ls_coil_org_num coil.coil_org_num%type;
--  ls_coil_mid_num coil.coil_mid_num%type;
--  ls_part_num coil.part_num%type;
--  ls_supplier_sales_num coil.supplier_sales_num%type;
--  ls_purchase_order_num coil.purchase_order_num%type;
--  li_total_skid_net_wt sheet_skid.sheet_net_wt%type;
--  li_total_skid_tare_wt sheet_skid.sheet_tare_wt%type;
--  li_total_net_wt coil.net_wt%type;
--  li_total_gross_wt coil.net_wt%type;

  edi_location varchar2(50):='/templar/templar/incoming/senddata';
  edi_file varchar2 (50) := 'edi_out.txt';
  edi_file_handle UTL_FILE.FILE_TYPE;

  li_coil_count int := 0;
  li_edi_846_id int;

begin

   SELECT EDI_ST_LOG_SEQ.NEXTVAL INTO li_st_log FROM dual;
   SELECT EDI_GS_LOG_SEQ.NEXTVAL INTO li_gs_log FROM dual;
   ls_today_short := to_char(SYSDATE, 'yymmdd');
   ls_today := to_char(SYSDATE, 'yyyymmdd');
   ls_now := to_char(SYSDATE, 'hh24mi');

   edi_846(j):= 'ISA*00*          *00*          *01*039630926T     *09*0015049350011G *'
    ||  ls_today_short  || '*' ||  ls_now  || '*U*00401*' || LPAD(to_char(li_gs_log),9,'0') || '*0*T*:'; j := j + 1;
   edi_846(j):= 'GS*IB*039630926T*0015049350011G*' ||  ls_today  || '*' || ls_now || '*' || li_gs_log || '*X*004010'   ; j :=j + 1;
   edi_846(j):= 'ST*846*' || li_st_log ; j :=j + 1;
   edi_846(j):= 'BIA*00*IP*' || li_st_log || '*' || ls_today; j := j + 1;
   edi_846(j):= 'N1*OU**92*039630926'; j := j + 1;    --'039630926': ABCo's DUNS#
   edi_846(j):= 'N1*SU**92*'  ||  ls_duns; j := j + 1;

   for cloop in coil_cursor loop
    --Coils data

    edi_846(j):= 'LIN**PO*' || cloop.purchase_order_num || '*BP*' || cloop.part_num || '*IN*' || cloop.coil_abc_num || '*VN*' || cloop.coil_org_num || '*PK*' || cloop.coil_abc_num || '*VO*' || cloop.supplier_sales_num; j := j + 1;
    case cloop.coil_status
      when 1 then ls_coil_status := '7';
      when 2 then ls_coil_status := 'Q';
      when 3 then ls_coil_status := 'M';
      when 4 then ls_coil_status := '2';
      when 7 then ls_coil_status := '7';
      when 11 then ls_coil_status := '2';
    end case;      -- 7: In process; Q: Not Scheduled; M: Return Material to Mill; 2: Hold for Inspection
    edi_846(j):= 'PID*S*MA*ST*' || ls_coil_status; j := j + 1;
    edi_846(j):= 'MEA*PD*N*' || cloop.net_wt_balance || '*LB'; j := j + 1;
    edi_846(j):= 'MEA*PD*G*' || cloop.net_wt_balance || '*LB'; j := j + 1;
    edi_846(j):= 'QTY*01*1'; j := j + 1;

    li_coil_count := li_coil_count + 1;
   end loop;

   for cloop_donebutnotshipped in skid_cursor loop
   /*for cloop_donebutnotshipped in coil_cursor_donebutnotshipped loop
    --Coils data

    select sum(ss.sheet_net_wt) into li_total_skid_net_wt
    from sheet_skid ss, sheet_skid_detail ssd, production_sheet_item psi
    where ss.sheet_skid_num = ssd.sheet_skid_num and
          ssd.prod_item_num = psi.prod_item_num and
          ss.skid_sheet_status <> 0 and
          psi.coil_abc_num = cloop_donebutnotshipped.coil_abc_num;

    select sum(ss.sheet_tare_wt) into li_total_skid_tare_wt from sheet_skid ss, sheet_skid_detail ssd, production_sheet_item psi
    where ss.sheet_skid_num = ssd.sheet_skid_num and
          ssd.prod_item_num = psi.prod_item_num and
          ss.skid_sheet_status <> 0 and
          psi.coil_abc_num = cloop_donebutnotshipped.coil_abc_num;

    edi_846(j):= 'LIN**PO*' || cloop_donebutnotshipped.purchase_order_num || '*BP*' || cloop_donebutnotshipped.part_num || '*IN*' || cloop_donebutnotshipped.coil_abc_num || '*VN*' || cloop_donebutnotshipped.coil_org_num || '*PK*' || cloop_donebutnotshipped.coil_abc_num || '*VO*' || cloop_donebutnotshipped.supplier_sales_num; j := j + 1;
    edi_846(j):= 'PID*S*MA*ST*8'; j := j + 1;   -- 8: processing complete
    edi_846(j):= 'QTY*01*1'; j := j + 1;
    li_total_net_wt := cloop_donebutnotshipped.net_wt_balance + li_total_skid_net_wt;
    edi_846(j):= 'MEA*PD*N*' || li_total_net_wt || '*LB'; j := j + 1;
    li_total_gross_wt := cloop_donebutnotshipped.net_wt_balance + li_total_skid_net_wt + li_total_skid_tare_wt;
    edi_846(j):= 'MEA*PD*G*' || li_total_gross_wt || '*LB'; j := j + 1;

    li_coil_count := li_coil_count + 1;   */

    edi_846(j):= 'LIN**PO*' || cloop_donebutnotshipped.purchase_order_num || '*BP*' || cloop_donebutnotshipped.part_num || '*IN*' || cloop_donebutnotshipped.prod_item_num || '*VN*' || cloop_donebutnotshipped.coil_org_num || '*PK*' || cloop_donebutnotshipped.sheet_skid_num || '*VO*' || cloop_donebutnotshipped.supplier_sales_num; j := j + 1;
    case cloop_donebutnotshipped.skid_sheet_status
      when 2 then ls_skid_status := '1';
      when 4 then ls_skid_status := '3';
      when 13 then ls_skid_status := '8';
    end case;      --Skid status: 2:Ready; 4:OnHold; 13:Partial Ready
    edi_846(j):= 'PID*S*MA*ST*'  ||  ls_skid_status; j := j + 1;   -- 8: processing complete
    edi_846(j):= 'MEA*PD*N*' || cloop_donebutnotshipped.prod_item_net_wt || '*LB'; j := j + 1;
    edi_846(j):= 'MEA*PD*G*' || cloop_donebutnotshipped.skid_gross_wt || '*LB'; j := j + 1;
    edi_846(j):= 'QTY*01*1'; j := j + 1;

    li_coil_count := li_coil_count + 1;
   end loop;

   --edi_846(j):= 'CTT*' || li_coil_count; j := j + 1;
   edi_846(j):= 'SE*' || to_char(j-1) || '*' || li_st_log; j := j + 1;
   edi_846(j):= 'GE*1*' || li_gs_log; j := j + 1;
   edi_846(j):= 'IEA*1*' || LPAD(to_char(li_gs_log),9,'0');

   if li_coil_count > 0 then
     SELECT edi_file_id_seq.NEXTVAL INTO li_edi_846_id FROM DUAL;

-- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
--   edi_file := 's_novelis_kingston_' || to_char(li_edi_846_id) || '.846';
     edi_file := edi_file_prefix || to_char(li_edi_846_id) || '.edi';

     edi_file_handle :=utl_file.fopen(edi_location,edi_file,'W');
     --write edi to file
     FOR i IN 0..j LOOP
         utl_file.put_line(edi_file_handle,edi_846(i));
         END LOOP;
     utl_file.fclose(edi_file_handle);

     -- for verifying 997
      INSERT INTO outbound_edi_transaction(edi_file_id,duns_from,duns_to,interchange_control_number,
      group_control_number,transaction_time,edi_file_name,fa_receive_status,customer_id,set_control_num,transaction_type_id)
      VALUES(li_edi_846_id,'039630926',ls_duns,li_gs_log,li_gs_log, sysdate, edi_file,0,li_customer_id,li_st_log,'846');
      COMMIT;

      edi_file := 'send_edi_log';
      edi_file_handle :=utl_file.fopen(edi_location,edi_file,'a');
      utl_file.put_line(edi_file_handle,'Type: 846');
      utl_file.put_line(edi_file_handle,'Sending Time: ' || to_char(sysdate, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,'Interchange Control #: ' || li_gs_log);
      utl_file.put_line(edi_file_handle,'Group Control #: ' || li_gs_log);
      utl_file.put_line(edi_file_handle,'Set Control #: ' || li_st_log);
      utl_file.put_line(edi_file_handle,'');
      utl_file.put_line(edi_file_handle,'');
      utl_file.fclose(edi_file_handle);

      commit;
    end if;


  return;

  EXCEPTION
     WHEN dup_val_on_index then
     rollback;
     return ;
     WHEN UTL_FILE.INVALID_PATH THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN ;
     WHEN UTL_FILE.INVALID_MODE THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN ;
    WHEN UTL_FILE.INVALID_OPERATION THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN ;
    WHEN UTL_FILE.WRITE_ERROR THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN ;
    WHEN OTHERS THEN
     UTL_FILE.FCLOSE_ALL;
      RETURN ;
end t_edi_846_for_novelis_kingston;
