--  DDL for Procedure UPDATE_COIL_FROM_PROCESS_COIL
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."UPDATE_COIL_FROM_PROCESS_COIL" is

CURSOR c_coil_abc_num is
SELECT c.COIL_ABC_NUM, p.ab_job_num
FROM PROCESS_COIL p, COIL c
WHERE c.COIL_ABC_NUM  = p.COIL_ABC_NUM
AND c.COIL_STATUS <> 0
AND p.PROCESS_COIL_STATUS = 0;

ll_coil_abc_num long;
li_coil_status int;
li_system_log_key_num int;  
begin

for c_coil_abc_num_rec in c_coil_abc_num loop
        -- update coil status to 'DONE'
        UPDATE COIL
        SET COIL.NET_WT_BALANCE = 0, COIL.COIL_STATUS = 0
        WHERE COIL.COIL_ABC_NUM = c_coil_abc_num_rec.coil_abc_num;
        --log record
        SELECT system_log_id_seq.NEXTVAL INTO li_system_log_key_num FROM dual;
        insert into system_log(system_log_key_num, system_log_timestamp, system_log_contents)
        values (li_system_log_key_num, sysdate, 'Update_coil_from_process_coil procedure run on ' || sysdate || ' for Coil# ' || ll_coil_abc_num || ' in Job# ' || 
      c_coil_abc_num_rec.ab_job_num);
end loop;
commit;
   
end update_coil_from_process_coil;
  GRANT EXECUTE ON "DBO"."UPDATE_COIL_FROM_PROCESS_COIL" TO "AGERLANTS"
