--  DDL for Procedure UPDATE_SCRAP_FROM_WORKSHEET
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."UPDATE_SCRAP_FROM_WORKSHEET" (coil_num  in coil.coil_abc_num%type) is
       cursor cur_worksheet is
              SELECT COIL_ABC_NUM, 
                     AB_JOB_NUM, 
                     SCRAP_ITEM_TYPE, 
                     SCRAP_ITEM_OD, 
                     SCRAP_ITEM_MILL, 
                     SUM(SCRAP_ITEM_PIECE) tot_scrap_pcs, 
                     SUM(SCRAP_ITEM_NET_WT) tot_scrap_nw
              FROM QUALITY_SCRAP_WORKSHEET
              WHERE COIL_ABC_NUM = coil_num
              GROUP BY COIL_ABC_NUM, AB_JOB_NUM, SCRAP_ITEM_TYPE, SCRAP_ITEM_OD, SCRAP_ITEM_MILL;
begin
  delete quality_coil_eval_scrap
   where quality_coil_eval_scrap.coil_abc_num = coil_num ;
  FOR ws_rec IN cur_worksheet LOOP
      insert into quality_coil_eval_scrap
                    (coil_abc_num,
                     ab_job_num,
                     scrap_item_type,
                     scrap_item_piece,
                     scrap_item_net_wt,
                     scrap_item_od,
                     scrap_item_mill)
      values
        (coil_num, ws_rec.ab_job_num, ws_rec.scrap_item_type, ws_rec.tot_scrap_pcs, ws_rec.tot_scrap_nw,
         ws_rec.scrap_item_od, ws_rec.scrap_item_mill );
  END LOOP;
  commit;
end UPDATE_SCRAP_FROM_WORKSHEET;
  GRANT EXECUTE ON "DBO"."UPDATE_SCRAP_FROM_WORKSHEET" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Procedure UPDATE_SCRAP_SKID_FROM_QUALITY
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."UPDATE_SCRAP_SKID_FROM_QUALITY" (coil_num  in coil.coil_abc_num%type,
                                                           shift_num in shift.shift_num%type) is
  li_i       integer;
  skid_num   scrap_skid.scrap_skid_num%type;
  job_num    ab_job.ab_job_num%type;
  item_count integer;
  item_num   integer;
  skid_nw_sum integer;
  Cursor cur_skid IS
    SELECT DISTINCT SCRAP_SKID_NUM
      FROM QUALITY_SCRAP_WORKSHEET
     WHERE COIL_ABC_NUM = coil_num
       and SCRAP_SKID_NUM is not null;
  CURSOR cur_skid_job(c_skid integer) is
    Select DISTINCT ab_job_num
      FROM quality_scrap_worksheet
     WHERE scrap_skid_num = c_skid;
  pcs_job    integer;
  net_wt_job integer;

begin

  FOR skid_rec IN cur_skid LOOP
    skid_num := skid_rec.SCRAP_SKID_NUM;
    FOR job_rec in cur_skid_job(skid_num) loop
      job_num := job_rec.ab_job_num;
      select sum(scrap_item_piece), sum(scrap_item_net_wt)
        into pcs_job, net_wt_job
        from quality_scrap_worksheet
       where coil_abc_num = coil_num
         and ab_job_num = job_num
         and scrap_skid_num = skid_num;
    
      select count(*)
        into item_count
        from return_scrap_item, scrap_skid_detail
       where return_scrap_item.coil_abc_num = coil_num
         and return_scrap_item.ab_job_num = job_num
         and scrap_skid_detail.return_scrap_item_num =
             return_scrap_item.return_scrap_item_num
         and scrap_skid_detail.scrap_skid_num = skid_num;
    
      if item_count = 1 THEN
        select scrap_skid_detail.return_scrap_item_num
          into item_num
          from return_scrap_item, scrap_skid_detail
         where return_scrap_item.coil_abc_num = coil_num
           and return_scrap_item.ab_job_num = job_num
           and scrap_skid_detail.return_scrap_item_num =
               return_scrap_item.return_scrap_item_num
           and scrap_skid_detail.scrap_skid_num = skid_num;
      
        update return_scrap_item
           set return_scrap_item.return_item_net_wt = net_wt_job,
               return_scrap_item.scrap_item_pieces  = pcs_job,
               return_scrap_item.return_item_date   = sysdate,
               return_scrap_item.shift_num          = shift_num
         where return_scrap_item.return_scrap_item_num = item_num;
      
      else
        -- if not do insert
        select return_scrap_item_id_seq.nextval into item_num from dual;
        insert into return_scrap_item
          (return_scrap_item.return_scrap_item_num,
           return_scrap_item.coil_abc_num,
           return_scrap_item.ab_job_num,
           return_scrap_item.return_item_net_wt,
           return_scrap_item.return_item_date,
           return_scrap_item.return_item_notes,
           return_scrap_item.scrap_item_pieces,
           return_scrap_item.shift_num)
        values
          (item_num,
           coil_num,
           job_num,
           net_wt_job,
           sysdate,
           'DAS',
           pcs_job,
           shift_num);
      
        insert into scrap_skid_detail
          (scrap_skid_detail.scrap_skid_num,
           scrap_skid_detail.return_scrap_item_num)
        values
          (skid_num, item_num);
        li_i := 0;
      end if;
    end loop;
    --To do list update skid netwt from all items
    select SUM(return_scrap_item.return_item_net_wt)
      into skid_nw_sum
      from return_scrap_item, scrap_skid_detail
     where return_scrap_item.return_scrap_item_num = scrap_skid_detail.return_scrap_item_num and
           scrap_skid_detail.scrap_skid_num = skid_num ;
    update scrap_skid
       set scrap_skid.scrap_net_wt = skid_nw_sum
     where scrap_skid.scrap_skid_num = skid_num;
    
    commit;
  END LOOP;
end UPDATE_SCRAP_SKID_FROM_QUALITY;
  GRANT EXECUTE ON "DBO"."UPDATE_SCRAP_SKID_FROM_QUALITY" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Procedure UPDATE_SHEET_SKID_WT
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."UPDATE_SHEET_SKID_WT" (skid_id in sheet_skid.sheet_skid_num%type, new_wt in sheet_skid.sheet_net_wt%type ) is
--skid_old_wt sheet_skid.sheet_net_wt%type;
item_wt production_sheet_item.prod_item_net_wt%type;
item_num production_sheet_item.prod_item_num%type;

begin
  --select NVL(sheet_skid.sheet_net_wt,0) into skid_old_wt
  --FROM SHEET_SKID
  --WHERE sheet_skid.sheet_skid_num = skid_id;
  
  SELECT MAX( SHEET_SKID_DETAIL.PROD_ITEM_NUM ) into item_num
  FROM SHEET_SKID_DETAIL
  WHERE SHEET_SKID_DETAIL.SHEET_SKID_NUM = skid_id;
  
  SELECT NVL(SUM(production_sheet_item.prod_item_net_wt), 0 ) into item_wt
  FROM production_sheet_item
  WHERE (production_sheet_item.prod_item_num in 
  ( SELECT sheet_skid_detail.prod_item_num 
    FROM sheet_skid_detail
    WHERE sheet_skid_detail.sheet_skid_num = skid_id)) and
    (production_sheet_item.prod_item_num <> item_num) ;
    
    update sheet_skid
    set sheet_skid.sheet_net_wt = new_wt
    where sheet_skid.sheet_skid_num = skid_id;
    item_wt := new_wt - item_wt;
        
    update production_sheet_item
    set production_sheet_item.prod_item_net_wt = item_wt
    where production_sheet_item.prod_item_num = item_num ;
    
    commit;
  
end UPDATE_SHEET_SKID_WT;
  GRANT EXECUTE ON "DBO"."UPDATE_SHEET_SKID_WT" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Procedure UPDATE_SHIFT_COIL
--------------------------------------------------------
set define off;

  CREATE OR REPLACE PROCEDURE "DBO"."UPDATE_SHIFT_COIL" (coil_num  in coil.coil_abc_num%type, shift_num in shift.shift_num%type) is
       job_num    ab_job.ab_job_num%type;
       skid_wt sheet_skid.sheet_net_wt%type;
       scrap_wt sheet_skid.sheet_net_wt%type;
       process_w sheet_skid.sheet_net_wt%type;
       CURSOR cur_job is
       Select DISTINCT ab_job_num
              FROM shift_coil
              WHERE shift_coil.shift_num = shift_num and 
                    shift_coil.coil_abc_num = coil_num ;

begin
  --job_num    ab_job.ab_job_num%type;
  skid_wt := 0;
  scrap_wt := 0;
  FOR job_rec in cur_job loop
      job_num := job_rec.ab_job_num;
      select NVL(sum( production_sheet_item.prod_item_net_wt ),0) into skid_wt
      from production_sheet_item
      where production_sheet_item.ab_job_num = job_num and
            production_sheet_item.coil_abc_num = coil_num and 
            production_sheet_item.shift_num = shift_num;
      select NVL(sum( return_scrap_item.return_item_net_wt ),0) into scrap_wt
      from return_scrap_item
      where return_scrap_item.ab_job_num = job_num and
            return_scrap_item.coil_abc_num = coil_num and
            return_scrap_item.shift_num = shift_num;
      process_w := skid_wt + scrap_wt;
      update shift_coil
      set shift_coil.process_wt = process_w
      where shift_coil.shift_num = shift_num and
            shift_coil.ab_job_num = job_num and
            shift_coil.coil_abc_num = coil_num;
  End loop;
  commit;
end update_shift_coil;
  GRANT EXECUTE ON "DBO"."UPDATE_SHIFT_COIL" TO "AGERLANTS"
