           customer_order.created_date,
           order_item.order_item_num,
           order_item.enduser_part_num,
           order_item.supplier_code,
           order_item.gauge,
           sheet_skid. ab_job_num,
           sheet_skid.sheet_skid_num,
           sheet_skid.sheet_skid_display_num, --added by Victor H. on 06-2012 for Novelis locatio code request
           sheet_skid.sheet_net_wt,
           sheet_skid.sheet_tare_wt,
           sheet_skid. skid_pieces,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_theoretical_wt,
           NULL done,
           coil.coil_org_num,
           coil.coil_gauge,
           coil.coil_width
      from customer_order
           join order_item on order_item.order_abc_num = customer_order.order_abc_num
           join ab_job on ab_job.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
           join sheet_skid on sheet_skid.ab_job_num = ab_job.ab_job_num
           join sheet_packing_item on sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
           join shipment on shipment.packing_list = sheet_packing_item.packing_list
           join process_coil on process_coil.ab_job_num = ab_job.ab_job_num
           join coil on coil.coil_abc_num = process_coil.coil_abc_num
     where shipment.packing_list = al_packing_list
     order by sheet_skid.sheet_skid_display_num,
              coil.coil_org_num;
/*      
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
  --      (SHIPMENT.SHIPMENT_EDI856_DATE is NULL);
*/
  --TYPE skidinfo_tabletype IS TABLE OF alcan_ford_856_cur%ROWTYPE INDEX BY BINARY_INTEGER;
  --skidinfo_table skidinfo_tabletype;
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table    store_tabletype;
  i            BINARY_INTEGER := 0;
  skidinfo_rec alcan_ford_856_cur%ROWTYPE;

  /*CURSOR packing_list_same_bol IS
  SELECT packing_list
    FROM shipment
   WHERE bill_of_lading = ll_bill_of_lading;*/

  CURSOR c_ship_to IS
    SELECT DISTINCT des_sh_cust_id --, PACKING_LIST
      FROM shipment
     WHERE bill_of_lading = ll_bill_of_lading
       AND shipment.shipment_status = 0;
  --ORDER BY PACKING_LIST;
  
  cursor c_coil is
  select distinct 
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num,
         coil.coil_gauge,
         coil.coil_width
         --process_coil.coil_abc_num
         --outbound_edi_transaction.transaction_time,
         --outbound_edi_transaction.edi_file_name
  from   customer_order
         join order_item on order_item.order_abc_num = customer_order.order_abc_num
         join ab_job on ab_job.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
         join sheet_skid on sheet_skid.ab_job_num = ab_job.ab_job_num
         join sheet_packing_item on sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
         join shipment on shipment.packing_list = sheet_packing_item.packing_list
         join process_coil on process_coil.ab_job_num = ab_job.ab_job_num
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         --join outbound_edi_transaction on outbound_edi_transaction.edi_file_id = shipment.edi_file_id_856
  --where  shipment.packing_list = 105586 --Production
  where  shipment.packing_list = al_packing_list --Develpment
  order by
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num;

BEGIN

  edi_loc := dbo.get_edi_destination('EDI_DIR'); --Alex Gerlants. 11/15/2016

  -- edi_alcan_870; -- Send 870 first

  -- Get Customer ID, End user ID
  --SELECT customer_id, des_sh_cust_id
  --  INTO li_customer_id, li_des_sh_cust_id
  -- FROM shipment
  -- WHERE shipment.packing_list = al_packing_list;
  --IF NOT SQL%FOUND THEN
 --   RETURN - 1;
  --END IF;

  -- Get Customer ID, End user ID, authorization code
  SELECT customer_id, des_sh_cust_id, nvl(shipment_athorization_code, 'NA')
    INTO li_customer_id, li_des_sh_cust_id, ls_auth_code
  FROM shipment
  WHERE shipment.packing_list = al_packing_list;
  IF NOT SQL%FOUND THEN
   RETURN - 1;
  END IF;

  -- dbms_output.put_line (to_char(li_customer_id) || '  ' || to_char(li_des_sh_cust_id) );

  IF NOT (li_customer_id IN (34, 35, 10, 1153, 1459, 2582)) -- AND (li_des_sh_cust_id IN (
  --10,41,51,69,70,71,72,77,78,79,1055,1062,1073,1086,1096,1099,1114,1112,1153,
  --1206,1251,1253,1268,1269,1270,1322,1325,1328,1331,1332,1346,1347, 1382, 1383)))
   THEN

    --***********************************************************************************************88
    --IF NOT ((li_customer_id IN (34,35,10,1153)) AND (li_des_sh_cust_id IN (SELECT CUSTOMER_ID
    --FROM CUSTOMER
    --WHERE CUSTOMER_DUNS_NUMBER_STRING is not null))) THEN

    RETURN 200;
  END IF;

  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(sheet_skid.sheet_net_wt),
         SUM(sheet_skid.sheet_net_wt) + SUM(sheet_skid.sheet_tare_wt),
         SUM(sheet_skid.skid_pieces)
    INTO ll_shipment_nt, ll_shipment_gt, ll_shipment_pc
    FROM sheet_skid, sheet_packing_item, shipment
   WHERE shipment.packing_list = sheet_packing_item.packing_list
     AND sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
     AND shipment.packing_list = al_packing_list;
  IF ll_shipment_pc = 0 THEN
    RETURN 100;
  END IF; -- empty shipment

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  -- Retrieve ABCO info
  -- ls_sender_vanid := '3010007080';
  --ls_ic := 'R0P7A';

  -- Retrieve ALCAN supply code and Ford Stamping Plant location code
  --SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf
  --FROM customer_customer  WHERE o_customer_id = li_customer_id and e_customer_id = 49;  --Ford customer_id =49

  ls_sf := '039630926';
  --SELECT NVL(communication_code,'UNKNOWN') INTO ls_st FROM customer_system
  --WHERE customer_id = li_des_sh_cust_id;

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.vehicle_id_prefix, '9999'),
         nvl(shipment.equipment_type, 'NA'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'PT'), -- Protected Trailer
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE)
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_vehicle_id_prefix,
         ls_eq_type,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_carrier_initial,
         ldt_shipment
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;

  --Check all packing_lists are done against a BOL
  /*
  for pl_rec in packing_list_same_bol loop
      select shipment.shipment_status into ll_temp from shipment
             where shipment.packing_list = pl_rec.packing_list;
      if ll_temp > 0 then
         return pl_rec.packing_list;
      end if;

  end loop;
  */
  --End of packing list checking

  SELECT nvl(customer_duns_number_string, '00000000'), customer_short_name
    INTO ls_st_duns, ls_des_cust_name
    FROM customer
   WHERE customer_id = li_des_sh_cust_id;

  IF (ls_st_duns = '00000000') THEN
    RETURN 200;
  END IF; --No Ship to DUNS

  SELECT nvl(customer_duns_number_string, '00000000')
    INTO ls_su
    FROM customer
   WHERE customer_id = li_customer_id;
  IF (ls_su = '00000000') THEN
    RETURN 200;
  END IF; --No Supplier DUNS

  -- Get SCAC(Standard Carrier Alpha Code)
  SELECT nvl(carrier.scac, 'NONE'), LPAD(carrier.carrier_full_name, 17)
    INTO ls_scac, ls_carrier_full_name
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);

  -- Get Receiver and Customer VAN ID
  -- SELECT NVL(customer_system.van_account_num, 'nothing'), NVL(customer_system.gs03, 'nothing')
  -- INTO ls_receiver_vanid, ls_receiver_gs03    -- ls_receiver_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --   (select shipment.des_sh_cust_id  from shipment  where shipment.packing_list = al_packing_list);

  -- SELECT NVL(customer_system.van_account_num, 'nothing'),NVL(customer_system.gs03, 'nothing')
  -- INTO   ls_customer_vanid, ls_customer_gs03   -- ls_customer_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --       (select shipment.customer_id from shipment where shipment.packing_list = al_packing_list);

  -- Generate Header Info.
  --x12_table(i) := 'ISA*00*'||'          *00*          *ZZ*R0P7A          *ZZ*F159B          *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0') ||'*0*P**';
  --x12_table(i) := 'GS*SH*R0P7A*'||ls_st || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  --Alex Gerlants. 10/16/2018. Changed from "00200" to "00401"
  --Production
  --x12_table(i) := 'ISA*00*' ||
  --                '          *00*          *01*039630926T     *09*0015049350011G *' ||
  --                ls_today || '*' || ls_now || '*U*00401*' ||
  --                lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
  
  --Development                
  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *ZZ*2NDSFTP        *ZZ*008861627T     *' ||
                  ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';
                  
  i := i + 1;

  --Alex Gerlants. 10/16/2018. Changed from "002002" to "004010"
  x12_table(1) := 'GS*SH*R0P7A*' || '001504935001' || '*' || ls_today || '*' ||
                  ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;
  --x12_table(i):= 'BSN*00*' || to_char(ll_bill_of_lading) || '*' || ls_today || '*' || ls_now;
  x12_table(i) := 'BSN*00*' || to_char(al_packing_list) || '*' || ls_today || '*' ||
                  ls_now;
  i := i + 1;
  
  --Alex Gerlants. 08/07/2018.
  --Changed to populate with actual ship date instead of current date and time.
  --The reason is that when we send 856 on a later date, this date is not correct.
  --x12_table(i) := 'DTM*011*' || ls_today || '*' || ls_now;
  --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                                                      to_char(ldt_shipment, 'HH24MI');
  i := i + 1;
  
  --Alex Gerlants. 10/18/2018. Changed from "YYMMDD" to "YYYYMMDD"
  --Moved here from the below
  x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                  to_char(ldt_shipment, 'HH24MI');
  i := i + 1;

  -- First Level HL
  x12_table(i) := 'HL*01**S';
  i := i + 1;
  --Alex Gerlants. 10/16/2018. Changed from "MEA*PD*G*" to "MEA*WT*G*"
  x12_table(i) := 'MEA*WT*G*' || to_char(ll_shipment_gt) || '*LB';
  i := i + 1;
  x12_table(i) := 'MEA*WT*N*' || to_char(ll_shipment_nt) || '*LB';
  i := i + 1;
  x12_table(i) := 'TD1*PLT90*' || to_char(li_rowcount);
  li_td1 := i;
  i := i + 1;
  x12_table(i) := 'TD5*B*02*' || ls_scac || '*M*' || ls_carrier_full_name;
  i := i + 1;
  -- segment was modified to include trailer number.  Patrick Reynolds 11/30/2016
  x12_table(i) := 'TD3*' || ls_carrier_desc_code || '*' || ls_scac || '*' || ls_vehicle_id_prefix;
  i := i + 1;
  x12_table(i) := 'REF*BM*' || to_char(al_packing_list);
  i := i + 1;
  x12_table(i) := 'REF*PK*' || to_char(al_packing_list);
  i := i + 1;
  -- segment was modified to include equipment type.  Patrick Reynolds 11/30/2016
  x12_table(i) := 'REF*EQ*' || ls_eq_type;
  i := i + 1; --waiting for Novilis, ----tony
  --- Testing for multi order ASN ----Tony

  x12_table(i) := 'REF*MB*' || to_char(ll_bill_of_lading);
  i := i + 1;
  SELECT COUNT(*)
    INTO ll_temp
    FROM shipment
   WHERE shipment.bill_of_lading = ll_bill_of_lading
     AND shipment.shipment_status = 0;
     
  --Alex Gerlants. 10/16/2018. Removed 2 lines below
  --x12_table(i) := 'REF*SS*' || to_char(ll_temp);
  --i := i + 1;
  li_des_id := 1;
  
  --Alex Gerlants. 10/16/2018. Removed 7 lines below
  /*
  FOR c_stop IN c_ship_to LOOP
    IF li_des_sh_cust_id = c_stop.des_sh_cust_id THEN
      x12_table(i) := 'REF*QN*' || to_char(li_des_id);
      i := i + 1;
    END IF;
    li_des_id := li_des_id + 1;
  END LOOP;
  */

  /*
  IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
     x12_table(i):= 'REF*ZZ*' || ls_st;i:=i+1;
  end if;
  */

  ----Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  --x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
  --                to_char(ldt_shipment, 'HH24MI');
  --i := i + 1;
  
  x12_table(i) := 'N1*ST*' || ls_des_cust_name || '*1*' || ls_st_duns;
  i := i + 1;
  x12_table(i) := 'N1*SF*Aluminum Blanking Co*1*' || ls_sf;
  i := i + 1;
  x12_table(i) := 'N1*SU**1*' || ls_su;
  i := i + 1;

  --if not (li_des_sh_cust_id = 1096 or li_des_sh_cust_id = 1251) then
  --         x12_table(i):= 'N1*IC**92*' || ls_ic; i := i +1;        --- Deleted 04-30-03 by Tony according to alcan Julia's email
  --end if;

  --         x12_table(i):= 'N1*CN**92*' || ls_st_duns; i := i +1; --Ship to DUNs --- Deleted 04-30-03 by Tony according to alcan Julia's email

  -- Second Level HL based on End User PO( only one part# is included in one shipement per FORD's request)
  OPEN alcan_ford_856_cur;
  FETCH alcan_ford_856_cur
    INTO skidinfo_rec;
  --    ls_enduser_part := skidinfo_rec.ENDUSER_PART_NUM;
  --    ls_enduser_po := skidinfo_rec.ENDUSER_PO;

  /*
    if skidinfo_rec.ORIG_CUSTOMER_PO IN ('68Q68517') then    --Do NOT send 856 to Ford for some flipping related POs )
         edi_file_prefix := 'nosend_alcan_ford_ford';
    end if;
  */

  SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
    INTO ls_enduser_part
    FROM "ORDER_ITEM", "SHEET_SKID"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
     AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
     AND ("SHEET_SKID"."SHEET_SKID_NUM" = skidinfo_rec.sheet_skid_num);

  /*
      SELECT "CUSTOMER_ORDER"."ENDUSER_PO" into ls_enduser_po
             FROM "SHEET_SKID",
                  "CUSTOMER_ORDER"
                  WHERE ( "SHEET_SKID"."REF_ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM" ) and
                        (SHEET_SKID.SHEET_SKID_NUM = skidinfo_rec.SHEET_SKID_NUM);
  */

  x12_table(i) := 'HL*02*01*O';
  i := i + 1;
  IF ls_enduser_part IS NULL THEN
    ls_enduser_part := 'NA';
  END IF;
  x12_table(i) := 'LIN**BP*' || ls_enduser_part;
  i := i + 1;
  x12_table(i) := 'SN1**' || to_char(ll_shipment_pc) || '*EA*0';
  i := i + 1;

  --
  --ls_po := skidinfo_rec.ORIG_CUSTOMER_PO;
  SELECT "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO"
    INTO ls_po
    FROM "SHEET_SKID", "CUSTOMER_ORDER"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
         "CUSTOMER_ORDER"."ORDER_ABC_NUM")
     AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num);

  --IF INSTR(skidinfo_rec.ORIG_CUSTOMER_PO,'-') > 0
  --New PO format for Novelis SAP include '-'
  /*IF instr(ls_po, '-') > 0 THEN
    ls_po := substr(ls_po, 0, instr(ls_po, '-') - 1);
  END IF;*/

  --   IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
  x12_table(i) := 'PRF*' || ls_po || '***' ||
                  to_char(skidinfo_rec.created_date, 'YYMMDD');
  i := i + 1;
  --   end if;

  CLOSE alcan_ford_856_cur;

   --  Novelis SAP order number
 x12_table(i) := 'REF*IL*' || ls_auth_code;
 i := i + 1;
  --  end if;

  -- Third Level HL Under a P.O.
  li_hl01 := 3;

  --Skid loop begin ----------------------------------------------------------------
  FOR skidinfo_rec IN alcan_ford_856_cur LOOP
      IF length(to_char(li_hl01)) = 1 THEN
        x12_table(i) := 'HL*0' || to_char(li_hl01) || '*02*I';
        i := i + 1;
      ELSE
        x12_table(i) := 'HL*' || to_char(li_hl01) || '*02*I';
        i := i + 1;
      END IF;

      --    IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
      --       x12_table(i) := 'SN1**'||to_char(skidinfo_rec.skid_pieces)||'*EA';i:=i+1;
      --    else
      x12_table(i) := 'SN1**1*PF';
      i := i + 1;
      --    end if;

      --if li_des_sh_cust_id = 1096 -- To Budd or li_des_sh_cust_id = 1251 then
      --   then
      --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; i := i +1;
      --      x12_table(i) :=  'MEA*PD*TH*' || to_char(skidinfo_rec.sheet_net_wt) || '*24'; i := i +1;
      --elsif   li_des_sh_cust_id = 1251   --To Eagle Steel
      --  then
      --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; i := i +1;
      --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*24'; i := i +1;
      --      x12_table(i) :=  'MEA*PD*TH*' || to_char(skidinfo_rec.gauge) || '*EM'; i:=i+1;
      --    x12_table(i) :=  'MEA*PD*WD*'||'44.875'||'*IN'; i:=i+1;
      --    x12_table(i) :=  'MEA*PD*LN*'||to_char(skidinfo_rec.skid_pieces)||'*LF';  i:=i+1;
      --else  --All else, Ford dirct shiping program
                        
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*N" to "MEA*WT*N"
      x12_table(i) := 'MEA*WT*N*' || to_char(skidinfo_rec.sheet_net_wt) ||
                      '*01';
      i := i + 1;
                        
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*WT" to "MEA*CT*NL"
      x12_table(i) := 'MEA*CT*NL*' || to_char(skidinfo_rec.skid_pieces) ||
                      '*PC';
      i := i + 1;

      -- changed to all gross wt per novelis 1/30/2015
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*G" to "MEA*WT*G"
      x12_table(i) := 'MEA*WT*G*' || to_char(skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt) || '*01';
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      x12_table(i) := 'MEA*PD*GG*' || skidinfo_rec.coil_gauge;
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      x12_table(i) := 'MEA*PD*WD*' || skidinfo_rec.coil_width;
      i := i + 1;

      /*
      IF (skidinfo_rec.sheet_theoretical_wt IS NULL) OR
         (skidinfo_rec.sheet_theoretical_wt = 0) THEN
        x12_table(i) := 'MEA*PD*G*' || to_char(ll_shipment_gt) || '*01';
        i := i + 1;
      ELSE
        x12_table(i) := 'MEA*PD*G*' ||
                        to_char(skidinfo_rec.sheet_theoretical_wt) || '*01';
        i := i + 1;
      END IF;
      */
      --end if;

      -- fill in lot num
      SELECT COUNT(*)
        INTO li_rc
        FROM sheet_skid_detail
       WHERE sheet_skid_detail.sheet_skid_num = skidinfo_rec.sheet_skid_num;

      ls_lot_num := skidinfo_rec.lot_num;
      ls_coil_id := skidinfo_rec.coil_id;

      IF li_rc = 1 THEN
        SELECT lot_num, coil_org_num
          INTO ls_lot_num, ls_coil_id
          FROM coil
         WHERE coil.coil_abc_num =
               (SELECT coil_abc_num
                  FROM production_sheet_item
                 WHERE production_sheet_item.prod_item_num =
                       (SELECT prod_item_num
                          FROM sheet_skid_detail
                         WHERE sheet_skid_detail.sheet_skid_num =
                               skidinfo_rec.sheet_skid_num));
      --Alex Gerlants. 10/16/2018. Begin
      else --More than 1 item
        select count(*)
        into   li_rc
        from coil
        where coil.coil_abc_num in
               (select coil_abc_num
                from   production_sheet_item
                where  production_sheet_item.prod_item_num in
                       (select prod_item_num
                        from   sheet_skid_detail
                        where  sheet_skid_detail.sheet_skid_num =
                               skidinfo_rec.sheet_skid_num))
         and ltrim(rtrim(lower(lot_num))) not in ('na', 'n/a');
         
         if li_rc > 0 Then
            select lot_num, coil_org_num
            into   ls_lot_num, ls_coil_id
            from coil
            where coil.coil_abc_num in
                   (select coil_abc_num
                    from   production_sheet_item
                    where  production_sheet_item.prod_item_num in
                           (select prod_item_num
                            from   sheet_skid_detail
                            where  sheet_skid_detail.sheet_skid_num =
                                   skidinfo_rec.sheet_skid_num))
             and ltrim(rtrim(lower(lot_num))) not in ('na', 'n/a')
             and rownum = 1;
         end if;
      --Alex Gerlants. 10/16/2018. End
      END IF;

      --if li_des_sh_cust_id = 1251   --Eagle need coil ID here instead of lot number
      --then
      --x12_table(i) :=  'REF*HC*' || skidinfo_rec.coil_id ; i := i +1;
      --else
                        
      --Alex Gerlants. 10/18/2018. Changed from "REF*HC" to "REF*BT"
      x12_table(i) := 'REF*BT*' || ls_lot_num;
      i := i + 1;
      --end if;

      --x12_table(i) := 'REF*LS*' || to_char(skidinfo_rec.sheet_skid_num);
      --Alex Gerlants. 10/18/2018. Changed from "REF*LS" to "REF*SE"
      x12_table(i) := 'REF*SE*' || skidinfo_rec.sheet_skid_display_num; --added by Victor H. on 06-2012 for Novelis locatio code request
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      x12_table(i) := 'REF*LS*' || skidinfo_rec.coil_org_num;
      i := i + 1;
      
      li_hl01 := li_hl01 + 1;
      li_rowcount := alcan_ford_856_cur%ROWCOUNT;
      x12_table(li_td1) := 'TD1*PLT90*' || to_char(li_rowcount);
  END LOOP; --End of 'FOR skidinfo_rec IN alcan_ford_856_cur LOOP'
  --Skid loop end ------------------------------------------------------------------

  -- DBMS_OUTPUT.PUT_LINE ('rowcount' || to_char(li_rowcount));

  -- if li_des_sh_cust_id = 1096 or li_des_sh_cust_id = 1251 then
  --   x12_table(i) :=  'CTT*' || to_char(li_HL01 - 1) ||'*' || to_char(ll_shipment_pc*2) ;
  --   i := i +1;
  -- else
  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                  to_char(li_rowcount + ll_shipment_pc);
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  -- Write X.12 to file
  -- To FORD

  /** Write file to /templar/templar/incoming/senddata
  /*
  **/

  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  --edi_file:= 'S_alcan_ford_ford_' || to_char(ll_edi_file_id) ||'.x12';

  -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
  -- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
    --        v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
  END LOOP;
  utl_file.fclose(edi_file_handle);

  --To ALCAN

  /*
  SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;
  SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id_alcan FROM DUAL;
  edi_file:= 'S_alcan_ford_alcan_' || to_char(ll_edi_file_id_alcan) ||'.x12';
  edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');
  x12_table(0) := 'ISA*00*'||'          *00*          *01*039630926T     *09*0015049350011G *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0')||'*0*P**';
  x12_table(1) := 'GS*SH*R0P7A*'||'001504935001' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  x12_table(i-1) :=  'GE*1*' || to_char (ll_gs_log);
  x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');
  for j in 0..i loop
   UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
       v_edi_text_alcan:=v_edi_text_alcan||x12_table(j)||CHR(10);
  end loop;
  UTL_FILE.FCLOSE(edi_file_handle);

  */

  /* The following code added by Tony, for update archive*/

  --  INSERT INTO edi_log (edi_log_timestamp,customer_id,
  --         customer_edi_name,edi_log_contents,edi_file_id,edi_text)
  --    VALUES (SYSDATE,li_customer_id,ll_customer_edi_name,
  --           'EDI:'||ll_customer_edi_name||' generated successfully.',ll_edi_file_id,v_edi_text);
  --   COMMIT;

  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE,
         edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;
--  COMMIT;

  /* --added by Victor Huang on 06/05 for function acknowlegement
  INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
  VALUES(ll_gs_log, ls_su, sysdate, edi_file);
  COMMIT;*/

  --added by Victor Huang on 12/07 for verifying 997
  INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (ll_edi_file_id,
     '039630926',
     ls_su,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856');
  COMMIT;

  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  --exception
  --   when invalid_operation
  --   then
  --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

  --  when others
  --  then
  --      DBMS_OUTPUT.PUT_LINE ('System Error');
  --      UTL_FILE.FCLOSE(edi_file_handle);

  RETURN 1;
END alex_novelis_856_new_10192018;
