--  DDL for Function CREATENEW
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."CREATENEW" return number is
  Result number;
cursor c is
  select l.line_num, l.priority_num, l.ab_job_num, l.status
  from line_priority_copy l;

begin
for cloop in c loop
  insert into line_priority(line_num, ab_job_num, priority_num, status)
  values (cloop.line_num, cloop.ab_job_num, cloop.priority_num, cloop.status);
  
end loop; 
commit; 
  return(Result);
end createnew;
  GRANT EXECUTE ON "DBO"."CREATENEW" TO "AGERLANTS"
