--  DDL for Function EDI_ALCAN_ALCAN_SCRAP_856_X12
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_ALCAN_ALCAN_SCRAP_856_X12" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*
  Aluminum Blanking: DUNS: 01 039630926T
  Customer: ALCAN(34,35,10,1153)
  Alcan Rolled Product    X.121       0015049350011G
  */

   --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR');

  --edi_loc varchar2(50):='/tmp';--
  edi_file        VARCHAR2(50) := 'edi_out.txt'; --
  edi_file_prefix VARCHAR2(50) := 'S_alcan_alcan_scrap'; --
  edi_file_handle utl_file.file_type; --

  li_customer_id    shipment.customer_id%TYPE; --
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE; --
  ll_gs_log         INTEGER;
  ll_st_log         INTEGER;
  ll_bsn_log        INTEGER;

  shipment_skid_count INTEGER;

  ls_today         VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD'); --
  ls_now           VARCHAR2(20) := to_char(SYSDATE, 'HH24MI'); --
  ls_today_4digits VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD'); --

  alloy_po alloy_type.alcan_scrap_po%TYPE;
  ll_alloy alloy_type.alloy%TYPE;
  hl_order INTEGER;

  li_hl01        INTEGER;
  ll_shipment_nt INTEGER;
  ll_shipment_gt INTEGER;
  po_nt          INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_scac              carrier.scac%TYPE;
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_caarrier_initial  VARCHAR2(50);
  su_duns              VARCHAR2(20);
  ldt_shipment         DATE;

  ll_edi_file_id INTEGER;

  CURSOR alcan_scrap_856_cur IS
    SELECT DISTINCT scrap_skid.scrap_alloy2
      FROM scrap_skid, shipment, scrap_packing_item
     WHERE shipment.packing_list = al_packing_list
       AND scrap_packing_item.packing_list = shipment.packing_list
       AND scrap_skid.scrap_skid_num = scrap_packing_item.scrap_skid_num;

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table     store_tabletype;
  i             BINARY_INTEGER := 0;
  alloyinfo_rec alcan_scrap_856_cur%ROWTYPE;

  CURSOR item_cur IS
    SELECT scrap_skid.scrap_skid_num,
           scrap_skid.scrap_skid_display_num,
           scrap_skid.scrap_alloy2,
           scrap_skid.scrap_net_wt,
           scrap_skid.scrap_tare_wt
      FROM scrap_skid, scrap_packing_item
     WHERE scrap_packing_item.packing_list = al_packing_list
       AND scrap_packing_item.scrap_skid_num = scrap_skid.scrap_skid_num
       AND scrap_skid.scrap_alloy2 = ll_alloy;

  --TYPE item_table_type IS table of item_cur%ROWTYPE INDEX BY BINARY_INTEGER;
  --item_table item_table_type;
  item_rec item_cur%ROWTYPE;

BEGIN
  
  RETURN 1; --Alex Gerlants. 12/19/2018. This function will do nothing for now.

  SELECT customer_id, des_sh_cust_id
    INTO li_customer_id, li_des_sh_cust_id
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;
  IF NOT SQL%FOUND THEN
    RETURN - 1;
  END IF;

  IF NOT (li_customer_id IN (34, 35, 10, 1153, 1459, 2582)) -- AND (li_des_sh_cust_id IN (
  --10,41,51,69,70,71,72,77,78,79,1055,1062,1073,1086,1096,1099,1114,1112,1153,
  --1206,1251,1253,1268,1269,1270,1322,1325,1328,1331,1332,1346,1347, 1382, 1383)))
   THEN
    RETURN 200;
  END IF;

  SELECT COUNT(*)
    INTO shipment_skid_count
    FROM scrap_packing_item
   WHERE packing_list = al_packing_list;

  IF shipment_skid_count = 0 THEN
    RETURN 100;
  END IF;

  SELECT customer.customer_duns_number_string
    INTO su_duns
    FROM customer
   WHERE customer.customer_id = li_customer_id;

  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(scrap_skid.scrap_net_wt),
         SUM(scrap_skid.scrap_net_wt) + SUM(scrap_skid.scrap_tare_wt)
    INTO ll_shipment_nt, ll_shipment_gt
    FROM scrap_skid, scrap_packing_item, shipment
   WHERE shipment.packing_list = scrap_packing_item.packing_list
     AND scrap_packing_item.scrap_skid_num = scrap_skid.scrap_skid_num
     AND shipment.packing_list = al_packing_list;

  IF ll_shipment_nt <= 0 THEN
    RETURN 100;
  END IF; -- empty shipment

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  -- Retrieve ABCO info
  -- ls_sender_vanid := '3010007080';
  --    ls_ic := 'R0P7A';

  -- Retrieve ALCAN supply code and Ford Stamping Plant location code
  --   SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf
  --          FROM customer_customer
  --               WHERE o_customer_id = li_customer_id and e_customer_id = 49;  --Ford customer_id =49

  --SELECT NVL(communication_code,'UNKNOWN') INTO ls_st FROM customer_system
  --WHERE customer_id = li_des_sh_cust_id;

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'TL'), -- Protected Trailer
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE)
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_caarrier_initial,
         ldt_shipment
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;

  SELECT nvl(carrier.scac, 'NONE')
    INTO ls_scac
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);

  -- Get Resceiver and Customer VAN ID
  -- SELECT NVL(customer_system.van_account_num, 'nothing'), NVL(customer_system.gs03, 'nothing')
  -- INTO ls_receiver_vanid, ls_receiver_gs03    -- ls_receiver_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --   (select shipment.des_sh_cust_id  from shipment  where shipment.packing_list = al_packing_list);

  -- SELECT NVL(customer_system.van_account_num, 'nothing'),NVL(customer_system.gs03, 'nothing')
  -- INTO   ls_customer_vanid, ls_customer_gs03   -- ls_customer_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --       (select shipment.customer_id from shipment where shipment.packing_list = al_packing_list);

  -- Generate Header Info.
  --x12_table(i) := 'ISA*00*'||'          *00*          *ZZ*R0P7A          *ZZ*F159B          *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0') ||'*0*P**';
  --x12_table(i) := 'GS*SH*R0P7A*'||ls_st || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';

  -----------------------------------------
  -- New Code Start from here . TONY     --
  -----------------------------------------

  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *01*039630926T     *09*0015049350011G *' ||
                  ls_today || '*' || ls_now || '*U*00401*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
  i := i + 1;
  x12_table(1) := 'GS*SH*039630926T*' || '001504935' || '*' ||
                  ls_today_4digits || '*' || ls_now || '*' ||
                  to_char(ll_gs_log) || '*X*' || '004010';
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'BSN*32*' || to_char(al_packing_list) || '*' ||
                  ls_today_4digits || '*' || ls_now;
  i := i + 1;
  x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                  to_char(ldt_shipment, 'HH24MI');
  i := i + 1;

  x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD');
  i := i + 1;

  li_hl01 := 1;

  -- First Level HL shipment level
  x12_table(i) := 'HL*' || to_char(li_hl01) || '**S';
  li_hl01 := li_hl01 + 1;
  i := i + 1;
  x12_table(i) := 'MEA*PD*G*' || to_char(ll_shipment_gt) || '*LB';
  i := i + 1;
  x12_table(i) := 'MEA*PD*N*' || to_char(ll_shipment_nt) || '*LB';
  i := i + 1;
  x12_table(i) := 'MEA*PD**0.0000*BB';
  i := i + 1;

  x12_table(i) := 'TD1*LIF52*' || to_char(shipment_skid_count);
  --li_td1 :=i;
  i := i + 1;
  x12_table(i) := 'TD5*B*02*' || ls_scac || '*M';
  i := i + 1;
  x12_table(i) := 'TD3*' || ls_carrier_desc_code || '**' || ls_vehicle_id;
  i := i + 1;
  x12_table(i) := 'REF*BM*' || to_char(ll_bill_of_lading);
  i := i + 1;
  x12_table(i) := 'REF*PK*' || to_char(al_packing_list);
  i := i + 1;
  x12_table(i) := 'REF*EQ*FB';
  i := i + 1;
  /*
  IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
     x12_table(i):= 'REF*ZZ*' || ls_st;i:=i+1;
  end if;
  */

  --x12_table(i):= 'DTM*017*' || to_char(ldt_shipment,'YYMMDD') || '*' || to_char(ldt_shipment,'HHMI');
  --i := i+1;
  --x12_table(i):= 'N1*ST**1*' || ls_st_duns; i := i +1;
  x12_table(i) := 'N1*OU*Aluminum Blanking Co*1*039630926';
  i := i + 1;

  x12_table(i) := 'N1*SF*Aluminum Blanking Co*1*039630926';
  i := i + 1;
  x12_table(i) := 'N1*SU**1*' || su_duns;
  i := i + 1;

  --may not be needed
  --open alcan_scrap_856_cur;
  --fetch alcan_scrap_856_cur INTO alloyinfo_rec;

  --These may not be needed

  FOR alloyinfo_rec IN alcan_scrap_856_cur LOOP

    hl_order := li_hl01;
    x12_table(i) := 'HL*' || to_char(li_hl01) || '*1*O';
    li_hl01 := li_hl01 + 1;
    i := i + 1;
    x12_table(i) := 'LIN**BP*N/A';
    i := i + 1;

    ll_alloy := alloyinfo_rec.scrap_alloy2;

    SELECT nvl(alcan_scrap_po, '6800' || ll_alloy)
      INTO alloy_po
      FROM alloy_type
     WHERE alloy = upper(rtrim(ltrim(ll_alloy)))
       AND customer_id = li_customer_id;

    SELECT SUM(scrap_skid.scrap_net_wt)
      INTO po_nt
      FROM scrap_skid, scrap_packing_item
     WHERE scrap_packing_item.packing_list = al_packing_list
       AND scrap_packing_item.scrap_skid_num = scrap_skid.scrap_skid_num
       AND scrap_skid.scrap_alloy2 = ll_alloy;

    x12_table(i) := 'SN1**' || po_nt || '*01';
    i := i + 1;

    --  x12_table(i) := 'PRF*' || alloy_po || '***20030102'; i:=i+1;
    x12_table(i) := 'PRF*' || 'NA' || '***20030102';
    i := i + 1;
    x12_table(i) := 'PER*SR*PROD CONTROL*TE*248-338-4422';
    i := i + 1;

    --open item_cur;
    --fetch item_cur INTO item_rec;
    FOR item_rec IN item_cur LOOP

      x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(hl_order) || '*I';
      li_hl01 := li_hl01 + 1;
      i := i + 1;
      x12_table(i) := 'PID*S*55***' || upper(rtrim(ltrim(ll_alloy)));
      i := i + 1;
      x12_table(i) := 'MEA*PD*G*' ||
                      to_char(item_rec.scrap_net_wt +
                              item_rec.scrap_tare_wt) || '*01';
      i := i + 1;
      x12_table(i) := 'MEA*PD*N*' || to_char(item_rec.scrap_net_wt) ||
                      '*01';
      i := i + 1;
      x12_table(i) := 'REF*SE*' || to_char(item_rec.scrap_skid_display_num);
      i := i + 1;

    END LOOP;
    --close item_cur;

  END LOOP;
  --close alcan_scrap_856_cur;

  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                  to_char(ll_shipment_nt);
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  -- Write X.12 to file
  -- To alcan

  /** Write file to /templar/templar/incoming/senddata
  /*
  **/

  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  --edi_file:= 'S_alcan_ford_ford_' || to_char(ll_edi_file_id) ||'.x12';

  -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
  -- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
    --        v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
  END LOOP;
  utl_file.fclose(edi_file_handle);

  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
     shipment_edi856_date = SYSDATE,
     edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;
  COMMIT;

  /*--added by Victor Huang on 06/05 for function acknowlegement
    INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
    VALUES(ll_gs_log, su_duns, sysdate, edi_file);
    COMMIT;
  */
  --added by Victor Huang on 12/07 for verifying 997
  INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (ll_edi_file_id,
     '039630926',
     su_duns,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856 Scrap');
  COMMIT;

  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856 Scrap');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  --exception
  --   when invalid_operation
  --   then
  --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

  --  when others
  --  then
  --      DBMS_OUTPUT.PUT_LINE ('System Error');
  --      UTL_FILE.FCLOSE(edi_file_handle);

  RETURN 1;
END edi_alcan_alcan_scrap_856_x12;
  GRANT EXECUTE ON "DBO"."EDI_ALCAN_ALCAN_SCRAP_856_X12" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function EDI_ALCAN_ALCAN_SCRAP_856_X12_
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_ALCAN_ALCAN_SCRAP_856_X12_" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*
  Aluminum Blanking: DUNS: 01 039630926T
  Customer: ALCAN(34,35,10,1153)
  Alcan Rolled Product    X.121       0015049350011G
  */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR');
  --edi_loc varchar2(50):='/tmp';--
  edi_file        VARCHAR2(50) := 'edi_out.txt'; --
  edi_file_prefix VARCHAR2(50) := 'S_alcan_alcan_scrap'; --
  edi_file_handle utl_file.file_type; --

  li_customer_id    shipment.customer_id%TYPE; --
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE; --
  ll_gs_log         INTEGER;
  ll_st_log         INTEGER;
  ll_bsn_log        INTEGER;

  shipment_skid_count INTEGER;

  ls_today         VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD'); --
  ls_now           VARCHAR2(20) := to_char(SYSDATE, 'HH24MI'); --
  ls_today_4digits VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD'); --

  alloy_po alloy_type.alcan_scrap_po%TYPE;
  ll_alloy alloy_type.alloy%TYPE;
  hl_order INTEGER;

  li_hl01        INTEGER;
  ll_shipment_nt INTEGER;
  ll_shipment_gt INTEGER;
  po_nt          INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_scac              carrier.scac%TYPE;
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_caarrier_initial  VARCHAR2(50);
  su_duns              VARCHAR2(20);
  ldt_shipment         DATE;

  ll_edi_file_id INTEGER;

  CURSOR alcan_scrap_856_cur IS
    SELECT DISTINCT scrap_skid.scrap_alloy2
      FROM scrap_skid, shipment, scrap_packing_item
     WHERE shipment.packing_list = al_packing_list
       AND scrap_packing_item.packing_list = shipment.packing_list
       AND scrap_skid.scrap_skid_num = scrap_packing_item.scrap_skid_num;

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table     store_tabletype;
  i             BINARY_INTEGER := 0;
  alloyinfo_rec alcan_scrap_856_cur%ROWTYPE;

  CURSOR item_cur IS
    SELECT scrap_skid.scrap_skid_num,
           scrap_skid.scrap_alloy2,
           scrap_skid.scrap_net_wt,
           scrap_skid.scrap_tare_wt
      FROM scrap_skid, scrap_packing_item
     WHERE scrap_packing_item.packing_list = al_packing_list
       AND scrap_packing_item.scrap_skid_num = scrap_skid.scrap_skid_num
       AND scrap_skid.scrap_alloy2 = ll_alloy;

  --TYPE item_table_type IS table of item_cur%ROWTYPE INDEX BY BINARY_INTEGER;
  --item_table item_table_type;
  item_rec item_cur%ROWTYPE;

BEGIN
  SELECT customer_id, des_sh_cust_id
    INTO li_customer_id, li_des_sh_cust_id
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;
  IF NOT SQL%FOUND THEN
    RETURN - 1;
  END IF;

  IF NOT (li_customer_id IN (34, 35, 10, 1153, 1459)) -- AND (li_des_sh_cust_id IN (
  --10,41,51,69,70,71,72,77,78,79,1055,1062,1073,1086,1096,1099,1114,1112,1153,
  --1206,1251,1253,1268,1269,1270,1322,1325,1328,1331,1332,1346,1347, 1382, 1383)))
   THEN
    RETURN 200;
  END IF;

  SELECT COUNT(*)
    INTO shipment_skid_count
    FROM scrap_packing_item
   WHERE packing_list = al_packing_list;

  IF shipment_skid_count = 0 THEN
    RETURN 100;
  END IF;

  SELECT customer.customer_duns_number_string
    INTO su_duns
    FROM customer
   WHERE customer.customer_id = li_customer_id;

  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(scrap_skid.scrap_net_wt),
         SUM(scrap_skid.scrap_net_wt) + SUM(scrap_skid.scrap_tare_wt)
    INTO ll_shipment_nt, ll_shipment_gt
    FROM scrap_skid, scrap_packing_item, shipment
   WHERE shipment.packing_list = scrap_packing_item.packing_list
     AND scrap_packing_item.scrap_skid_num = scrap_skid.scrap_skid_num
     AND shipment.packing_list = al_packing_list;

  IF ll_shipment_nt <= 0 THEN
    RETURN 100;
  END IF; -- empty shipment

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  -- Retrieve ABCO info
  -- ls_sender_vanid := '3010007080';
  --    ls_ic := 'R0P7A';

  -- Retrieve ALCAN supply code and Ford Stamping Plant location code
  --   SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf
  --          FROM customer_customer
  --               WHERE o_customer_id = li_customer_id and e_customer_id = 49;  --Ford customer_id =49

  --SELECT NVL(communication_code,'UNKNOWN') INTO ls_st FROM customer_system
  --WHERE customer_id = li_des_sh_cust_id;

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'TL'), -- Protected Trailer
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE)
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_caarrier_initial,
         ldt_shipment
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;

  SELECT nvl(carrier.scac, 'NONE')
    INTO ls_scac
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);

  -- Get Resceiver and Customer VAN ID
  -- SELECT NVL(customer_system.van_account_num, 'nothing'), NVL(customer_system.gs03, 'nothing')
  -- INTO ls_receiver_vanid, ls_receiver_gs03    -- ls_receiver_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --   (select shipment.des_sh_cust_id  from shipment  where shipment.packing_list = al_packing_list);

  -- SELECT NVL(customer_system.van_account_num, 'nothing'),NVL(customer_system.gs03, 'nothing')
  -- INTO   ls_customer_vanid, ls_customer_gs03   -- ls_customer_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --       (select shipment.customer_id from shipment where shipment.packing_list = al_packing_list);

  -- Generate Header Info.
  --x12_table(i) := 'ISA*00*'||'          *00*          *ZZ*R0P7A          *ZZ*F159B          *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0') ||'*0*P**';
  --x12_table(i) := 'GS*SH*R0P7A*'||ls_st || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';

  -----------------------------------------
  -- New Code Start from here . TONY     --
  -----------------------------------------

  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *01*039630926T     *09*0015049350011G *' ||
                  ls_today || '*' || ls_now || '*U*00401*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
  i := i + 1;
  x12_table(1) := 'GS*SH*039630926T*' || '001504935' || '*' ||
                  ls_today_4digits || '*' || ls_now || '*' ||
                  to_char(ll_gs_log) || '*X*' || '004010';
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'BSN*32*' || to_char(al_packing_list) || '*' ||
                  ls_today_4digits || '*' || ls_now;
  i := i + 1;
  x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                  to_char(ldt_shipment, 'HH24MI');
  i := i + 1;

  x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD');
  i := i + 1;

  li_hl01 := 1;

  -- First Level HL shipment level
  x12_table(i) := 'HL*' || to_char(li_hl01) || '**S';
  li_hl01 := li_hl01 + 1;
  i := i + 1;
  x12_table(i) := 'MEA*PD*G*' || to_char(ll_shipment_gt) || '*LB';
  i := i + 1;
  x12_table(i) := 'MEA*PD*N*' || to_char(ll_shipment_nt) || '*LB';
  i := i + 1;
  x12_table(i) := 'MEA*PD**0.0000*BB';
  i := i + 1;

  x12_table(i) := 'TD1*LIF52*' || to_char(shipment_skid_count);
  --li_td1 :=i;
  i := i + 1;
  x12_table(i) := 'TD5*B*02*' || ls_scac || '*M';
  i := i + 1;
  x12_table(i) := 'TD3*' || ls_carrier_desc_code || '**' || ls_vehicle_id;
  i := i + 1;
  x12_table(i) := 'REF*BM*' || to_char(ll_bill_of_lading);
  i := i + 1;
  x12_table(i) := 'REF*PK*' || to_char(al_packing_list);
  i := i + 1;
  x12_table(i) := 'REF*EQ*FB';
  i := i + 1;
  /*
  IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
     x12_table(i):= 'REF*ZZ*' || ls_st;i:=i+1;
  end if;
  */

  --x12_table(i):= 'DTM*017*' || to_char(ldt_shipment,'YYMMDD') || '*' || to_char(ldt_shipment,'HHMI');
  --i := i+1;
  --x12_table(i):= 'N1*ST**1*' || ls_st_duns; i := i +1;
  x12_table(i) := 'N1*OU*Aluminum Blanking Co*1*039630926';
  i := i + 1;

  x12_table(i) := 'N1*SF*Aluminum Blanking Co*1*039630926';
  i := i + 1;
  x12_table(i) := 'N1*SU**1*' || su_duns;
  i := i + 1;

  --may not be needed
  --open alcan_scrap_856_cur;
  --fetch alcan_scrap_856_cur INTO alloyinfo_rec;

  --These may not be needed

  FOR alloyinfo_rec IN alcan_scrap_856_cur LOOP

    hl_order := li_hl01;
    x12_table(i) := 'HL*' || to_char(li_hl01) || '*1*O';
    li_hl01 := li_hl01 + 1;
    i := i + 1;
    x12_table(i) := 'LIN**BP*N/A';
    i := i + 1;

    ll_alloy := alloyinfo_rec.scrap_alloy2;

    SELECT nvl(alcan_scrap_po, '6800' || ll_alloy)
      INTO alloy_po
      FROM alloy_type
     WHERE alloy = upper(rtrim(ltrim(ll_alloy)))
       AND customer_id = li_customer_id;

    SELECT SUM(scrap_skid.scrap_net_wt)
      INTO po_nt
      FROM scrap_skid, scrap_packing_item
     WHERE scrap_packing_item.packing_list = al_packing_list
       AND scrap_packing_item.scrap_skid_num = scrap_skid.scrap_skid_num
       AND scrap_skid.scrap_alloy2 = ll_alloy;

    x12_table(i) := 'SN1**' || po_nt || '*01';
    i := i + 1;

    --  x12_table(i) := 'PRF*' || alloy_po || '***20030102'; i:=i+1;
    x12_table(i) := 'PRF*' || 'NA' || '***20030102';
    i := i + 1;
    x12_table(i) := 'PER*SR*PROD CONTROL*TE*248-338-4422';
    i := i + 1;

    --open item_cur;
    --fetch item_cur INTO item_rec;
    FOR item_rec IN item_cur LOOP

      x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(hl_order) || '*I';
      li_hl01 := li_hl01 + 1;
      i := i + 1;
      x12_table(i) := 'PID*S*55***' || upper(rtrim(ltrim(ll_alloy)));
      i := i + 1;
      x12_table(i) := 'MEA*PD*G*' ||
                      to_char(item_rec.scrap_net_wt +
                              item_rec.scrap_tare_wt) || '*01';
      i := i + 1;
      x12_table(i) := 'MEA*PD*N*' || to_char(item_rec.scrap_net_wt) ||
                      '*01';
      i := i + 1;
      x12_table(i) := 'REF*SE*' || to_char(item_rec.scrap_skid_num);
      i := i + 1;

    END LOOP;
    --close item_cur;

  END LOOP;
  --close alcan_scrap_856_cur;

  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                  to_char(ll_shipment_nt);
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  -- Write X.12 to file
  -- To alcan

  /** Write file to /templar/templar/incoming/senddata
  /*
  **/

  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  --edi_file:= 'S_alcan_ford_ford_' || to_char(ll_edi_file_id) ||'.x12';
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
    --        v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
  END LOOP;
  utl_file.fclose(edi_file_handle);

  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE,
         edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;
  COMMIT;

  /*--added by Victor Huang on 06/05 for funtion aknowlegement
    INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
    VALUES(ll_gs_log, su_duns, sysdate, edi_file);
    COMMIT;
  */
  --added by Victor Huang on 12/07 for verifying 997
  INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (ll_edi_file_id,
     '039630926',
     su_duns,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856 Scrap');
  COMMIT;

  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856 Scrap');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  --exception
  --   when invalid_operation
  --   then
  --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

  --  when others
  --  then
  --      DBMS_OUTPUT.PUT_LINE ('System Error');
  --      UTL_FILE.FCLOSE(edi_file_handle);

  RETURN 1;
END edi_alcan_alcan_scrap_856_x12_;
  GRANT EXECUTE ON "DBO"."EDI_ALCAN_ALCAN_SCRAP_856_X12_" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function EDI_ALCAN_BUDD_856
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_ALCAN_BUDD_856" (al_packing_list shipment.packing_list%TYPE) return integer
/*
Returns:   Integer
               1 = if it succeeds
              -1 = if a system error occurs
             100 = no process data
             200 = no EDI defined
*/
is
/*
Aluminum Blanking: Ford Suppler Code: ZZ R0P7A
                   DUNS: 01 039630926T
Customer: ALCAN(34,35,10,)
Alcan Rolled Product  	X.121  		  0015049350011G
End User: Ford (ZZ F159B)
          Ford Chicago Stamping Plant(51) MS02A
          Ford Walton Hills Stamping Plant(77) MS03A
          Ford Woodhaven Stamping Plant(71) AF30A MS09A
          Ford Maumee Stamping Plant(78)    AF06A MS08A

          (not in use)Ford Monroe Stamping              AP06A

          (not in use) Warehouses: IDS(41)               R5G3B
          (not in use) Wayne Steel Distribution Center(79) RWSDC
*/

v_edi_text_ford varchar2(32767);
-- v_edi_text_alcan varchar2(32767);
-- ll_customer_edi_name VARCHAR2(20);

edi_loc varchar2 (50) := '/templar/templar/incoming/senddata';
--edi_loc varchar2 (50) :='/tmp';
edi_file varchar2 (50) := 'edi_out.txt';
edi_file_handle UTL_FILE.FILE_TYPE;
edi_file_prefix VARCHAR(2) := 'S_alcan_budd_budd_';

li_customer_id shipment.customer_id%TYPE;
li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;

-- ls_sender_vanid varchar2 (50);
-- ls_receiver_vanid varchar2 (50);
-- ls_customer_vanid varchar2(50);
-- ls_receiver_gs03 varchar2(50);
-- ls_customer_gs03 varchar2(50);
ls_st varchar2(50);
ls_sf varchar2(50);
ls_ic varchar2(50);
ll_gs_log integer;
ll_st_log integer;
ll_bsn_log integer;

ls_today varchar2(20):= to_char(sysdate, 'YYMMDD');
ls_now varchar2(20) := to_char(sysdate, 'HH24MI');

-- ll_newrow integer;
-- ll_sheet_skid_num integer;
li_rowcount integer;
-- li_rownum integer;
-- li_rownum1 integer;
li_HL01 integer;
-- li_HL02 integer;
ll_shipment_nt integer;
ll_shipment_gt integer;
ll_shipment_pc integer;
-- li_enduser_id integer;
li_td1 integer;
li_rc integer;

ll_bill_of_lading integer;
ls_vehicle_id  varchar2(50);
ls_scac carrier.scac%TYPE;
ls_tran_method_code varchar2(50);
ls_carrier_desc_code varchar2(50);
ls_caarrier_initial varchar2(50);
ls_lot_num varchar2(25);
budd_part varchar2(50);
budd_po varchar2(50);
budd_line varchar2(10);
ldt_shipment date;
-- ld_shipdate date;

-- ls_enduser_part varchar2(50);
-- ls_enduser_po varchar2(50);

ll_edi_file_id integer;
-- ll_edi_file_id_alcan integer;

Cursor alcan_ford_856_cur IS
SELECT SHEET_PACKING_ITEM.SH_PACKING_ITEM,
         'MULTIPLE' LOT_NUM,
         CUSTOMER_ORDER.ORIG_CUSTOMER_PO,
         CUSTOMER_ORDER.ORDER_ABC_NUM,
         CUSTOMER_ORDER.ENDUSER_PO,
         ORDER_ITEM.ORDER_ITEM_NUM,
         ORDER_ITEM.ENDUSER_PART_NUM,
         ORDER_ITEM.SUPPLIER_CODE,
         ORDER_ITEM.GAUGE,
--         COIL.COIL_WIDTH,
         SHEET_SKID. AB_JOB_NUM,
         SHEET_SKID.SHEET_SKID_NUM,
         SHEET_SKID.SHEET_NET_WT,
         SHEET_SKID.SHEET_TARE_WT,
         SHEET_SKID.SKID_PIECES,
         SHEET_SKID.SHEET_THEORETICAL_WT,
         SHEET_SKID.SKID_SHEET_STATUS,
          NULL DONE
FROM CUSTOMER_ORDER,
         ORDER_ITEM,
         SHEET_SKID,
--         COIL,
--         PROCESS_COIL,
         AB_JOB,
         SHIPMENT,
         SHEET_PACKING_ITEM
WHERE (ORDER_ITEM.ORDER_ABC_NUM = CUSTOMER_ORDER.ORDER_ABC_NUM ) and
         (AB_JOB.ORDER_ABC_NUM = ORDER_ITEM.ORDER_ABC_NUM) and
         (AB_JOB.ORDER_ITEM_NUM = ORDER_ITEM.ORDER_ITEM_NUM) and
--         (COIL.COIL_ABC_NUM = PROCESS_COIL.COIL_ABC_NUM) and
--         (PROCESS_COIL.AB_JOB_NUM = AB_JOB.AB_JOB_NUM) and
         (SHEET_SKID.AB_JOB_NUM = AB_JOB.AB_JOB_NUM) and
         (SHIPMENT.PACKING_LIST =SHEET_PACKING_ITEM.PACKING_LIST) and
         (SHEET_PACKING_ITEM.SHEET_SKID_NUM = SHEET_SKID.SHEET_SKID_NUM) and
         (SHIPMENT.PACKING_LIST = al_packing_list );
   --      (SHIPMENT.SHIPMENT_EDI856_DATE is NULL);


-- Type skidinfo_tabletype IS table of alcan_ford_856_cur%ROWTYPE INDEX by binary_integer;
-- skidinfo_table skidinfo_tabletype;
TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
 x12_table store_tabletype;
i binary_integer := 0;
skidinfo_rec alcan_ford_856_cur%rowtype;

begin
-- Get Customer ID, End user ID
SELECT customer_id, des_sh_cust_id
INTO li_customer_id, li_des_sh_cust_id FROM shipment
WHERE shipment.packing_list = al_packing_list;
IF NOT SQL%FOUND THEN  RETURN -1; END IF;

-- dbms_output.put_line (to_char(li_customer_id) || '  ' || to_char(li_des_sh_cust_id) );
-- Ship to Budd, Eagle
IF NOT ((li_customer_id IN (34,35,10,1153)) AND (li_des_sh_cust_id in (1096,1251))) THEN
return 200;   END IF;

-- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
SELECT SUM(sheet_skid.sheet_net_wt),SUM(sheet_skid.sheet_net_wt)+SUM(sheet_skid.sheet_tare_wt), SUM(sheet_skid.skid_pieces)
INTO ll_shipment_nt,ll_shipment_gt, ll_shipment_pc FROM sheet_skid, sheet_packing_item, shipment
WHERE SHIPMENT.PACKING_LIST =SHEET_PACKING_ITEM.PACKING_LIST and
      SHEET_PACKING_ITEM.SHEET_SKID_NUM = SHEET_SKID.SHEET_SKID_NUM and
      SHIPMENT.PACKING_LIST = al_packing_list;
if ll_shipment_pc = 0 then return 100; end if;   -- empty shipment

-- Get gs, st and bsn log sequence number
SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;
SELECT edi_st_log_seq.NEXTVAL INTO ll_st_log FROM DUAL;
SELECT edi_bsn_log_seq.NEXTVAL INTO ll_bsn_log FROM DUAL;

-- Retrieve ABCO info
 -- ls_sender_vanid := '3010007080';
 ls_ic := '113658';

-- Retrieve ALCAN supply code and Ford Stamping Plant location code
SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf
FROM customer_customer 	WHERE o_customer_id = li_customer_id and e_customer_id = 49;  --Ford customer_id =49

--SELECT communication_code INTO ls_st FROM customer_system
--WHERE customer_id = li_des_sh_cust_id;
  ls_st :='098015605'; --***************************************May need to be changed

-- Get Shipment Info.

SELECT shipment.bill_of_lading,
       NVL(shipment.vehicle_id,'9999'),
	   NVL(shipment.transportation_method_code,'Motor'),
	   NVL(shipment.carrier_description_code, 'PT'),  -- Protected Trailer
	   NVL(shipment.carrier_initial, 'NA'),
       NVL(shipment.shipment_actualed_date_time,SYSDATE)
INTO 	ll_bill_of_lading, ls_vehicle_id, ls_tran_method_code,
      ls_carrier_desc_code, ls_caarrier_initial, ldt_shipment
FROM  shipment
WHERE shipment.packing_list = al_packing_list; --*/

--ll_bill_of_lading:=21191;
--ls_vehicle_id:='9999';
--ls_tran_method_code:='Motor';
--ls_carrier_desc_code:='PT';
--ls_caarrier_initial:='NA';
--ldt_shipment:=SYSDATE;




-- Get SCAC(Standard Carrier Alpha Code)
SELECT NVL(carrier.scac, 'NONE') INTO ls_scac
FROM carrier WHERE carrier_id =(SELECT carrier_id  FROM shipment  WHERE shipment.packing_list = al_packing_list);

-- Get Resceiver and Customer VAN ID
-- SELECT NVL(customer_system.van_account_num, 'nothing'), NVL(customer_system.gs03, 'nothing')
-- INTO ls_receiver_vanid, ls_receiver_gs03    -- ls_receiver_vanid
-- FROM  customer_system WHERE customer_system.customer_id =
   --   (select shipment.des_sh_cust_id  from shipment  where shipment.packing_list = al_packing_list);

-- SELECT NVL(customer_system.van_account_num, 'nothing'),NVL(customer_system.gs03, 'nothing')
-- INTO 	ls_customer_vanid, ls_customer_gs03   -- ls_customer_vanid
-- FROM  customer_system WHERE customer_system.customer_id =
--       (select shipment.customer_id from shipment where shipment.packing_list = al_packing_list);


-- Generate Header Info.
x12_table(i) := 'ISA*00*'||'          *00*          *01*039630926T     *01*098015605      *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0') ||'*0*P**';
i := i + 1;
x12_table(i) := 'GS*SH*039630926T*'||ls_st || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
i := i + 1;
x12_table(i):= 'ST*856*' || to_char(ll_st_log);
i := i +1;
x12_table(i):= 'BSN*00*' || to_char(al_packing_list) || '*' || ls_today || '*' || ls_now;
i := i +1;
x12_table(i):= 'DTM*011*' || to_char(ldt_shipment,'YYMMDD') || '*' || to_char(ldt_shipment,'HH24MI');
i := i +1;

-- First Level HL
x12_table(i) := 'HL*01**S*1'; i := i +1;
x12_table(i):= 'MEA*PD*G*' || to_char(ll_shipment_gt) || '*LB'; i := i +1;
x12_table(i):= 'MEA*PD*N*' || to_char(ll_shipment_nt) || '*LB'; i := i +1;
x12_table(i):= 'TD1*PLT90*' || to_char(li_rowcount); li_td1 :=i;  i := i +1;
x12_table(i):= 'TD5*B*02*' || ls_scac ||'*M'; i := i +1;
x12_table(i):= 'TD3*' || ls_carrier_desc_code || '**' || ls_vehicle_id; i := i +1;
--x12_table(i):= 'REF*BM*' ||  to_char(ll_bill_of_lading); i := i +1;
x12_table(i):= 'REF*PK*' || to_char(al_packing_list); i := i +1;
x12_table(i):= 'N1*ST**01*' || '098015605'; i := i +1;
x12_table(i):= 'N1*SF**01*' || '113658'; i := i +1;
x12_table(i):= 'N1*SU**92*' || ls_ic; i := i +1;
x12_table(i):= 'FOB*PP';i:=i+1;
-- Second Level HL based on End User PO( only one part# is included in one shipement per FORD's request)
open alcan_ford_856_cur;
fetch alcan_ford_856_cur INTO skidinfo_rec;
--    ls_enduser_part := skidinfo_rec.ENDUSER_PART_NUM;
--    ls_enduser_po := skidinfo_rec.ENDUSER_PO;
x12_table(i) :='HL*02*01*O*1'; i := i +1;


--Find BUDD PO, Replace it with Ref in Order later.
if
skidinfo_rec.ENDUSER_PART_NUM in ('1L24-16016-A', 'RM1L24 16016','RM1L24-16016','1L24 16016')
then
budd_part := 'RM1L24 16016 AB' ; budd_po := '5500006884'; budd_line :='03';
else
budd_part := 'RM1L24 16015 AA' ; budd_po := '5500006825'; budd_line :='01';
end if;



x12_table(i) :='LIN**BP*'|| budd_part ||'*VO*'|| skidinfo_rec.ENDUSER_PART_NUM||'*PL*'|| to_char(skidinfo_rec.ORDER_ITEM_NUM); i := i +1;
x12_table(i) :='SN1**' || to_char(ll_shipment_nt) ||'*LB'; i := i +1;
--x12_table(i) := 'MEA**' || to_char(ll_shipment_nt) || '*LB'; i := i +1;


x12_table(i) := 'PRF*'|| budd_po ||'***'||to_char(ldt_shipment,'YYMMDD')||'*'||budd_line;i:=i+1;
x12_table(i) := 'REF*SO*'||to_char(ll_bill_of_lading);i:=i+1;
close alcan_ford_856_cur;

-- Third Level HL Under a P.O.
li_HL01 := 3;

for skidinfo_rec IN alcan_ford_856_cur
loop
if length(to_char(li_HL01)) = 1  then
x12_table(i) := 'HL*0' || to_char(li_HL01) || '*02*I'; i := i +1;
else
x12_table(i) := 'HL*' || to_char(li_HL01) || '*02*I'; i := i +1;
end if;
x12_table(i) :=  'SN1**1*PC'; i := i +1;
x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.SHEET_THEORETICAL_WT) || '*24'; i := i +1;
x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; i := i +1;
x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.skid_pieces) || '*PC'; i := i +1;
x12_table(i) :=  'MEA*PD*TH*' || to_char(skidinfo_rec.gauge) || '*EM'; i:=i+1;
x12_table(i) :=  'MEA*PD*WD*'||'44.875'||'*IN'; i:=i+1;
x12_table(i) :=  'MEA*PD*LN*'||to_char(skidinfo_rec.skid_pieces)||'*LF';  i:=i+1;
-- fill in lot num

ls_lot_num := skidinfo_rec.lot_num;

SELECT count(*) INTO li_rc 	FROM sheet_skid_detail
WHERE sheet_skid_detail.sheet_skid_num = skidinfo_rec.sheet_skid_num;
if li_rc = 1 then
select lot_num  INTO ls_lot_num from coil where coil.coil_abc_num =
 (select coil_abc_num from production_sheet_item where production_sheet_item.prod_item_num =
 (select prod_item_num from sheet_skid_detail where sheet_skid_detail.sheet_skid_num = skidinfo_rec.sheet_skid_num ));
end if;

x12_table(i) :=  'REF*HC*' || ls_lot_num ; i := i +1;
x12_table(i) :=  'REF*LS*' || to_char(skidinfo_rec.sheet_skid_num); i := i +1;
li_HL01 := li_HL01 + 1;
li_rowcount := alcan_ford_856_cur%ROWCOUNT;
x12_table(li_td1):= 'TD1*PLT90*' || to_char(li_rowcount);
end loop;

-- DBMS_OUTPUT.PUT_LINE ('rowcount' || to_char(li_rowcount));

x12_table(i) :=  'CTT*' || to_char(li_HL01 - 1) ||'*' || to_char(li_rowcount + ll_shipment_nt) ;
i := i +1;
x12_table(i) :=  'SE*' || to_char (i-1) ||'*'|| to_char(ll_st_log);
i := i +1;
x12_table(i) :=  'GE*1*' || to_char (ll_gs_log); i := i + 1;
x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');


-- Write X.12 to file
-- To FORD
SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id FROM DUAL;

-- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
-- edi_file:= 'S_alcan_budd_budd_' || to_char(ll_edi_file_id) ||'.x12';
edi_file:= edi_file_prefix || to_char(ll_edi_file_id) ||'.edi';
edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');
for j in 0..i loop
 UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
     v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
end loop;
UTL_FILE.FCLOSE(edi_file_handle);
--To ALCAN

/*
SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;
SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id_alcan FROM DUAL;
edi_file:= 'S_alcan_BUDD_alcan_' || to_char(ll_edi_file_id_alcan) ||'.x12';
edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');
x12_table(0) := 'ISA*00*'||'          *00*          *01*039630926T     *09*0015049350011G *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0')||'*0*P**';
x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');
for j in 0..i loop
 UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
     v_edi_text_alcan:=v_edi_text_alcan||x12_table(j)||CHR(10);
end loop;
UTL_FILE.FCLOSE(edi_file_handle);
  */

/* The following code added by Tony, for update archive*/

--  INSERT INTO edi_log (edi_log_timestamp,customer_id,
--         customer_edi_name,edi_log_contents,edi_file_id,edi_text)
--    VALUES (SYSDATE,li_customer_id,ll_customer_edi_name,
--           'EDI:'||ll_customer_edi_name||' generated successfully.',ll_edi_file_id,v_edi_text);
--   COMMIT;



--exception
--   when invalid_operation
 --   then
 --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

--  when others
--  then
 --      DBMS_OUTPUT.PUT_LINE ('System Error');
 --      UTL_FILE.FCLOSE(edi_file_handle);

--UPDATE shipment
--     SET shipment_des_edi856_date= SYSDATE,
--         shipment_edi856_date=SYSDATE
--     WHERE shipment.packing_list = al_packing_list;
--   COMMIT;


return 1;
end edi_alcan_budd_856;
  GRANT EXECUTE ON "DBO"."EDI_ALCAN_BUDD_856" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function EDI_ALCAN_EAGLE_856
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_ALCAN_EAGLE_856" (al_packing_list shipment.packing_list%TYPE) return integer
/*
Returns:   Integer
               1 = if it succeeds
              -1 = if a system error occurs
             100 = no process data
             200 = no EDI defined
*/
is
v_edi_text_ford varchar2(32767);
v_edi_text_alcan varchar2(32767);
-- ll_customer_edi_name VARCHAR2(20);

--Alex Gerlants. 11/15/2016. Commented out, and added the line after.
--edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
edi_loc VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR');

--edi_loc varchar2(50):='/tmp';
edi_file varchar2 (50) := 'edi_out.txt';
edi_file_handle UTL_FILE.FILE_TYPE;
edi_file_prefix VARCHAR2(50) := 'S_alcan_ford_ford_';

li_customer_id shipment.customer_id%TYPE;
li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;

-- ls_sender_vanid varchar2 (50);
-- ls_receiver_vanid varchar2 (50);
-- ls_customer_vanid varchar2(50);
-- ls_receiver_gs03 varchar2(50);
-- ls_customer_gs03 varchar2(50);
ls_st varchar2(50);
ls_sf varchar2(50);
ls_ic varchar2(50);
ll_gs_log integer;
ll_st_log integer;
ll_bsn_log integer;

ls_today varchar2(20):= to_char(sysdate, 'YYMMDD');
ls_now varchar2(20) := to_char(sysdate, 'HH24MI');

-- ll_newrow integer;
-- ll_sheet_skid_num integer;
li_rowcount integer;
-- li_rownum integer;
-- li_rownum1 integer;
li_HL01 integer;
-- li_HL02 integer;
ll_shipment_nt integer;
ll_shipment_gt integer;
ll_shipment_pc integer;
-- li_enduser_id integer;
li_td1 integer;
li_rc integer;

ll_bill_of_lading integer;
ls_vehicle_id  varchar2(50);
ls_scac carrier.scac%TYPE;
ls_tran_method_code varchar2(50);
ls_carrier_desc_code varchar2(50);
ls_caarrier_initial varchar2(50);
ldt_shipment date;
-- ld_shipdate date;

-- ls_enduser_part varchar2(50);
-- ls_enduser_po varchar2(50);

ll_edi_file_id integer;
ll_edi_file_id_alcan integer;

Cursor alcan_ford_856_cur IS
SELECT SHEET_PACKING_ITEM.SH_PACKING_ITEM,
         'MULTIPLE' LOT_NUM,
         CUSTOMER_ORDER.ORIG_CUSTOMER_PO,
         CUSTOMER_ORDER.ORDER_ABC_NUM,
         CUSTOMER_ORDER.ENDUSER_PO,
         ORDER_ITEM.ORDER_ITEM_NUM,
         ORDER_ITEM.ENDUSER_PART_NUM,
         ORDER_ITEM.SUPPLIER_CODE,
         ORDER_ITEM.GAUGE,
         SHEET_SKID. AB_JOB_NUM,
         SHEET_SKID.SHEET_SKID_NUM,
         SHEET_SKID.SHEET_NET_WT,
         SHEET_SKID.SHEET_TARE_WT,
         SHEET_SKID. SKID_PIECES,
         SHEET_SKID.SKID_SHEET_STATUS,
          NULL DONE
FROM CUSTOMER_ORDER,
         ORDER_ITEM,
         SHEET_SKID,
         AB_JOB,
         SHIPMENT,
         SHEET_PACKING_ITEM
WHERE (ORDER_ITEM.ORDER_ABC_NUM = CUSTOMER_ORDER.ORDER_ABC_NUM ) and
         (AB_JOB.ORDER_ABC_NUM = ORDER_ITEM.ORDER_ABC_NUM) and
         (AB_JOB.ORDER_ITEM_NUM = ORDER_ITEM.ORDER_ITEM_NUM) and
         (SHEET_SKID.AB_JOB_NUM = AB_JOB.AB_JOB_NUM) and
         (SHIPMENT.PACKING_LIST =SHEET_PACKING_ITEM.PACKING_LIST) and
         (SHEET_PACKING_ITEM.SHEET_SKID_NUM = SHEET_SKID.SHEET_SKID_NUM) and
         (SHIPMENT.PACKING_LIST = al_packing_list );
   --      (SHIPMENT.SHIPMENT_EDI856_DATE is NULL);


-- Type skidinfo_tabletype IS table of alcan_ford_856_cur%ROWTYPE INDEX by binary_integer;
-- skidinfo_table skidinfo_tabletype;
TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
 x12_table store_tabletype;
i binary_integer := 0;
skidinfo_rec alcan_ford_856_cur%rowtype;

begin
-- Get Customer ID, End user ID
SELECT customer_id, des_sh_cust_id
INTO li_customer_id, li_des_sh_cust_id FROM shipment
WHERE shipment.packing_list = al_packing_list;
IF NOT SQL%FOUND THEN  RETURN -1; END IF;

-- dbms_output.put_line (to_char(li_customer_id) || '  ' || to_char(li_des_sh_cust_id) );

IF NOT ((li_customer_id IN (34,35,10,1153)) AND (li_des_sh_cust_id IN (51,71,77,78,1096,1251,79))) THEN
return 200;   END IF;

-- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
SELECT SUM(sheet_skid.sheet_net_wt),SUM(sheet_skid.sheet_net_wt)+SUM(sheet_skid.sheet_tare_wt), SUM(sheet_skid.skid_pieces)
INTO ll_shipment_nt,ll_shipment_gt, ll_shipment_pc FROM sheet_skid, sheet_packing_item, shipment
WHERE SHIPMENT.PACKING_LIST =SHEET_PACKING_ITEM.PACKING_LIST and
      SHEET_PACKING_ITEM.SHEET_SKID_NUM = SHEET_SKID.SHEET_SKID_NUM and
      SHIPMENT.PACKING_LIST = al_packing_list;
if ll_shipment_pc = 0 then return 100; end if;   -- empty shipment

-- Get gs, st and bsn log sequence number
SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;
SELECT edi_st_log_seq.NEXTVAL INTO ll_st_log FROM DUAL;
SELECT edi_bsn_log_seq.NEXTVAL INTO ll_bsn_log FROM DUAL;

-- Retrieve ABCO info
 -- ls_sender_vanid := '3010007080';
 ls_ic := 'R0P7A';

-- Retrieve ALCAN supply code and Ford Stamping Plant location code
SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf
FROM customer_customer 	WHERE o_customer_id = li_customer_id and e_customer_id = 49;  --Ford customer_id =49
SELECT communication_code INTO ls_st FROM customer_system
WHERE customer_id = li_des_sh_cust_id;

-- Get Shipment Info.
SELECT shipment.bill_of_lading,
       NVL(shipment.vehicle_id,'9999'),
		   NVL(shipment.transportation_method_code,'Motor'),
		   NVL(shipment.carrier_description_code, 'PT'),  -- Protected Trailer
		   NVL(shipment.carrier_initial, 'NA'),
       NVL(shipment.shipment_actualed_date_time,SYSDATE)
INTO 	ll_bill_of_lading, ls_vehicle_id, ls_tran_method_code,
      ls_carrier_desc_code, ls_caarrier_initial, ldt_shipment
FROM  shipment WHERE shipment.packing_list = al_packing_list;

-- Get SCAC(Standard Carrier Alpha Code)
SELECT NVL(carrier.scac, 'NONE') INTO ls_scac
FROM carrier WHERE carrier_id =(SELECT carrier_id  FROM shipment  WHERE shipment.packing_list = al_packing_list);

-- Get Resceiver and Customer VAN ID
-- SELECT NVL(customer_system.van_account_num, 'nothing'), NVL(customer_system.gs03, 'nothing')
-- INTO ls_receiver_vanid, ls_receiver_gs03    -- ls_receiver_vanid
-- FROM  customer_system WHERE customer_system.customer_id =
   --   (select shipment.des_sh_cust_id  from shipment  where shipment.packing_list = al_packing_list);

-- SELECT NVL(customer_system.van_account_num, 'nothing'),NVL(customer_system.gs03, 'nothing')
-- INTO 	ls_customer_vanid, ls_customer_gs03   -- ls_customer_vanid
-- FROM  customer_system WHERE customer_system.customer_id =
--       (select shipment.customer_id from shipment where shipment.packing_list = al_packing_list);


-- Generate Header Info.
if li_des_sh_cust_id = 1251   --TO Eagle Steel, send Eagle steel only
then
x12_table(i) := 'ISA*00*'||'          *00*          *01*039630926T     *01*557529971      *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0') ||'*0*P**';
else
x12_table(i) := 'ISA*00*'||'          *00*          *ZZ*R0P7A          *ZZ*F159B          *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0') ||'*0*P**';
end if;
--x12_table(i) := 'GS*SH*R0P7A*'||ls_st || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
i := i + 1;

if li_des_sh_cust_id=1096      --Budd
then
--  x12_table(i) := 'GS*SH*R0P7A*'||'RMATS' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002FORD';
--  Above will switch to follow when eRMA go live with Budd
    x12_table(i) := 'GS*SH*R0P7A*'||'ERMA1' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002FORD';
elsif li_des_sh_cust_id = 1251        -- Eagle steel
  then
    x12_table(i) := 'GS*SH*039630926T*'||'557529971' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002FORD';
else
  x12_table(i) := 'GS*SH*R0P7A*'||ls_st || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
end if;
i := i + 1;


x12_table(i):= 'ST*856*' || to_char(ll_st_log);
i := i +1;
x12_table(i):= 'BSN*00*' || to_char(al_packing_list) || '*' || ls_today || '*' || ls_now;
i := i +1;
x12_table(i):= 'DTM*011*' || to_char(ldt_shipment,'YYMMDD') || '*' || to_char(ldt_shipment,'HH24MI');
i := i +1;

-- First Level HL
x12_table(i) := 'HL*01**S'; i := i +1;
x12_table(i):= 'MEA*PD*G*' || to_char(ll_shipment_gt) || '*LB'; i := i +1;
x12_table(i):= 'MEA*PD*N*' || to_char(ll_shipment_nt) || '*LB'; i := i +1;
x12_table(i):= 'TD1*PLT90*' || to_char(li_rowcount); li_td1 :=i;  i := i +1;
x12_table(i):= 'TD5*B*02*' || ls_scac ||'*M'; i := i +1;
x12_table(i):= 'TD3*' || ls_carrier_desc_code || '**' || ls_vehicle_id; i := i +1;
x12_table(i):= 'REF*BM*' ||  to_char(ll_bill_of_lading); i := i +1;
x12_table(i):= 'REF*PK*' || to_char(al_packing_list); i := i +1;
IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
x12_table(i):= 'REF*ZZ*' || ls_st;i:=i+1;
end if;
x12_table(i):= 'N1*ST**92*' || ls_st; i := i +1;
x12_table(i):= 'N1*SF**92*' || ls_sf; i := i +1;

if not (li_des_sh_cust_id = 1096 or li_des_sh_cust_id = 1251) then
x12_table(i):= 'N1*IC**92*' || ls_ic; i := i +1;
end if;

-- Second Level HL based on End User PO( only one part# is included in one shipement per FORD's request)
open alcan_ford_856_cur;
fetch alcan_ford_856_cur INTO skidinfo_rec;
--    ls_enduser_part := skidinfo_rec.ENDUSER_PART_NUM;
--    ls_enduser_po := skidinfo_rec.ENDUSER_PO;
x12_table(i) :='HL*02*01*O'; i := i +1;
x12_table(i) :='LIN**BP*'|| skidinfo_rec.ENDUSER_PART_NUM; i := i +1;
x12_table(i) :='SN1**' || to_char(ll_shipment_pc) ||'*EA*0'; i := i +1;
IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
x12_table(i) :='PRF*'||skidinfo_rec.ENDUSER_PO;i:=i+1;
end if;
close alcan_ford_856_cur;

-- Third Level HL Under a P.O.
li_HL01 := 3;

for skidinfo_rec IN alcan_ford_856_cur
loop
if length(to_char(li_HL01)) = 1  then
x12_table(i) := 'HL*0' || to_char(li_HL01) || '*02*I'; i := i +1;
else
x12_table(i) := 'HL*' || to_char(li_HL01) || '*02*I'; i := i +1;
end if;

IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
x12_table(i) := 'SN1**'||to_char(skidinfo_rec.skid_pieces)||'*EA';i:=i+1;
else
x12_table(i) :=  'SN1**1*PF'; i := i +1;
end if;



if li_des_sh_cust_id = 1096 -- To Budd or li_des_sh_cust_id = 1251 then
   then
   		x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; i := i +1;
   		x12_table(i) :=  'MEA*PD*TH*' || to_char(skidinfo_rec.sheet_net_wt) || '*24'; i := i +1;
elsif   li_des_sh_cust_id = 1251   --To Eagle Steel
	then
  		x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; i := i +1;
   		x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*24'; i := i +1;
   		x12_table(i) :=  'MEA*PD*TH*' || to_char(skidinfo_rec.gauge) || '*EM'; i:=i+1;
		x12_table(i) :=  'MEA*PD*WD*'||'44.875'||'*IN'; i:=i+1;
		x12_table(i) :=  'MEA*PD*LN*'||to_char(skidinfo_rec.skid_pieces)||'*LF';  i:=i+1;
else  --All else, Ford dirct shiping program
		x12_table(i) :=  'MEA*PD*N*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; i := i +1;
		x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.skid_pieces) || '*PC'; i := i +1;
end if;

-- fill in lot num
SELECT count(*) INTO li_rc 	FROM sheet_skid_detail
WHERE sheet_skid_detail.sheet_skid_num = skidinfo_rec.sheet_skid_num;
if li_rc = 1 then
select lot_num  INTO skidinfo_rec.lot_num from coil where coil.coil_abc_num =
 (select coil_abc_num from production_sheet_item where production_sheet_item.prod_item_num =
 (select prod_item_num from sheet_skid_detail where sheet_skid_detail.sheet_skid_num = skidinfo_rec.sheet_skid_num ));
end if;

x12_table(i) :=  'REF*HC*' || skidinfo_rec.lot_num ; i := i +1;
x12_table(i) :=  'REF*LS*' || to_char(skidinfo_rec.sheet_skid_num); i := i +1;
li_HL01 := li_HL01 + 1;
li_rowcount := alcan_ford_856_cur%ROWCOUNT;
x12_table(li_td1):= 'TD1*PLT90*' || to_char(li_rowcount);
end loop;

-- DBMS_OUTPUT.PUT_LINE ('rowcount' || to_char(li_rowcount));

 if li_des_sh_cust_id = 1096 or li_des_sh_cust_id = 1251 then
   x12_table(i) :=  'CTT*' || to_char(li_HL01 - 1) ||'*' || to_char(ll_shipment_pc*2) ;
   i := i +1;
 else
   x12_table(i) :=  'CTT*' || to_char(li_HL01 - 1) ||'*' || to_char(li_rowcount + ll_shipment_pc) ;
   i := i +1;
 end if;
x12_table(i) :=  'SE*' || to_char (i-1) ||'*'|| to_char(ll_st_log);
i := i +1;
x12_table(i) :=  'GE*1*' || to_char (ll_gs_log); i := i + 1;
x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');


-- Write X.12 to file
-- To FORD

--*************Temp solution for WSDC, only sending to Alcan********************
if li_des_sh_cust_id<>79 THEN
   SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id FROM DUAL;
 --    edi_file:= edi_file_prefix || to_char(ll_edi_file_id) ||'.x12';
     edi_file:= edi_file_prefix || to_char(ll_edi_file_id) ||'.edi';
     edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');
     for j in 0..i loop
        UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
        v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
     end loop;
   UTL_FILE.FCLOSE(edi_file_handle);
END IF;
--******************* WSDC customer ID = 79 SKID FORD FILE***********************

--To ALCAN

SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;
SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id_alcan FROM DUAL;

-- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
-- edi_file:= 'S_alcan_ford_alcan_' || to_char(ll_edi_file_id_alcan) ||'.x12';
-- edi_file:= 'S_alcan_ford_alcan_' || to_char(ll_edi_file_id_alcan) ||'.edi';
edi_file:= edi_file_prefix || to_char(ll_edi_file_id_alcan) ||'.edi';
edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');
x12_table(0) := 'ISA*00*'||'          *00*          *01*039630926T     *09*0015049350011G *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0')||'*0*P**';
x12_table(1) := 'GS*SH*R0P7A*'||'001504935001' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
x12_table(i-1) :=  'GE*1*' || to_char (ll_gs_log);
x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');
for j in 0..i loop
 UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
     v_edi_text_alcan:=v_edi_text_alcan||x12_table(j)||CHR(10);
end loop;
UTL_FILE.FCLOSE(edi_file_handle);

/* The following code added by Tony, for update archive*/

--  INSERT INTO edi_log (edi_log_timestamp,customer_id,
--         customer_edi_name,edi_log_contents,edi_file_id,edi_text)
--    VALUES (SYSDATE,li_customer_id,ll_customer_edi_name,
--           'EDI:'||ll_customer_edi_name||' generated successfully.',ll_edi_file_id,v_edi_text);
--   COMMIT;

  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  UPDATE shipment
     SET shipment_des_edi856_date= SYSDATE,
         shipment_edi856_date=SYSDATE,
         edi_file_id_856 = ll_edi_file_id
     WHERE shipment.packing_list = al_packing_list;
   COMMIT;

--exception
--   when invalid_operation
 --   then
 --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

--  when others
--  then
 --      DBMS_OUTPUT.PUT_LINE ('System Error');
 --      UTL_FILE.FCLOSE(edi_file_handle);

return 1;
end edi_alcan_eagle_856;
  GRANT EXECUTE ON "DBO"."EDI_ALCAN_EAGLE_856" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function EDI_ALCAN_FORD_856_X12
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_ALCAN_FORD_856_X12" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*
  Aluminum Blanking: Ford Suppler Code: ZZ R0P7A
                     DUNS: 01 039630926T
  Customer: ALCAN(34,35,10,1153)
  Alcan Rolled Product    X.121       0015049350011G
  End User: Ford (ZZ F159B)
            Ford Chicago Stamping Plant(51) MS02A
            Ford Walton Hills Stamping Plant(77) MS03A
            Ford Woodhaven Stamping Plant(71) AF30A MS09A
            Ford Maumee Stamping Plant(78)    AF06A MS08A
            Ford Ogihara  (1579 )           F7BFC

            Budd Company (Customer ID: 1096) B821L
            Eagle Steel (1251) MZF6B
            (not in use)Ford Monroe Stamping              AP06A

            (not in use) Warehouses: IDS(41)               R5G3B
            (not in use) Wayne Steel Distribution Center(79) RWSDC

  */

  --v_edi_text_ford varchar2(32767);
  --v_edi_text_alcan varchar2(32767);
  --ll_customer_edi_name VARCHAR2(20);

  edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  --edi_loc varchar2(50):='/tmp';
  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_prefix VARCHAR2(50) := 'S_alcan_ford_ford_';
  edi_file_handle utl_file.file_type;

  li_customer_id    shipment.customer_id%TYPE;
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;

  -- ls_sender_vanid varchar2 (50);
  -- ls_receiver_vanid varchar2 (50);
  -- ls_customer_vanid varchar2(50);
  -- ls_receiver_gs03 varchar2(50);
  -- ls_customer_gs03 varchar2(50);
  ls_st      VARCHAR2(50);
  ls_sf      VARCHAR2(50);
  ls_sf2     VARCHAR2(50);
  ls_ic      VARCHAR2(50);
  ll_gs_log  INTEGER;
  ll_st_log  INTEGER;
  ll_bsn_log INTEGER;

  ls_today VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  ls_now   VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  --ll_newrow         INTEGER;
  --ll_sheet_skid_num INTEGER;
  li_rowcount       INTEGER;
  --li_rownum         INTEGER;
  --li_rownum1        INTEGER;
  li_hl01           INTEGER;
  --li_hl02           INTEGER;
  ll_shipment_nt    INTEGER;
  ll_shipment_gt    INTEGER;
  ll_shipment_pc    INTEGER;
  --li_enduser_id     INTEGER;
  li_td1            INTEGER;
  li_rc             INTEGER;
  ll_cumulative_pc  INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_scac              carrier.scac%TYPE;
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_caarrier_initial  VARCHAR2(50);
  ldt_shipment         DATE;
  --ld_shipdate          DATE;
  ld_cumulative_start  DATE;

  ls_enduser_part VARCHAR2(50);
  ls_enduser_po   VARCHAR2(50);

  ls_lot  VARCHAR2(25);
  ls_coil VARCHAR2(25);

  ll_edi_file_id       INTEGER;
  --ll_edi_file_id_alcan INTEGER;

  CURSOR alcan_ford_856_cur IS
    SELECT sheet_packing_item.sh_packing_item,
           'MULTIPLE' lot_num,
           'MULTIPLE' coil_id,
           customer_order.orig_customer_po,
           customer_order.order_abc_num,
           customer_order.enduser_po,
           order_item.order_item_num,
           order_item.enduser_part_num,
           order_item.supplier_code,
           order_item.gauge,
           sheet_skid. ab_job_num,
           sheet_skid.sheet_skid_num,
           sheet_skid.sheet_skid_display_num,
           sheet_skid.sheet_net_wt,
           sheet_skid.sheet_theoretical_wt,
           sheet_skid.sheet_tare_wt,
           sheet_skid. skid_pieces,
           sheet_skid.skid_sheet_status,
           NULL done
      FROM customer_order,
           order_item,
           sheet_skid,
           ab_job,
           shipment,
           sheet_packing_item
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
  --      (SHIPMENT.SHIPMENT_EDI856_DATE is NULL);

  --TYPE skidinfo_tabletype IS TABLE OF alcan_ford_856_cur%ROWTYPE INDEX BY BINARY_INTEGER;
  --skidinfo_table skidinfo_tabletype;
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table    store_tabletype;
  i            BINARY_INTEGER := 0;
  skidinfo_rec alcan_ford_856_cur%ROWTYPE;

BEGIN
  -- Get Customer ID, End user ID
  SELECT customer_id, des_sh_cust_id
    INTO li_customer_id, li_des_sh_cust_id
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;
  IF NOT SQL%FOUND THEN
    RETURN - 1;
  END IF;

  -- dbms_output.put_line (to_char(li_customer_id) || '  ' || to_char(li_des_sh_cust_id) );

  --if al_packing_list = 35609 then
  --return 0;
  --end if;

  --IF NOT ((li_customer_id IN (34,35,10,1153)) AND (li_des_sh_cust_id IN (51,71,77,78,1096,1251,79, 1347, 1382,1383, 1104, 1401,1401, 1388, 1149, 1579)))
  -- Delete 1382 per Alcan By tony 03/29/04
  --IF NOT ((li_customer_id IN (34,35,10,1153)) AND (li_des_sh_cust_id IN (51,71,77,78,1096,1251,79, 1347,1383, 1104, 1401,1401, 1388, 1149, 1579)))

  IF NOT ((li_customer_id IN (34, 35, 10, 1153)) AND
      (li_des_sh_cust_id IN (51,
                                 71,
                                 77,
                                 78,
                                 1096,
                                 1251,
                                 79,
                                 1347,
                                 1104,
                                 1401,
                                 1401,
                                 1388,
                                 1149,
                                 1579)))
  --Delete 1383 per WoodHaven, -By tony 10-18-05
   THEN
    RETURN 200;
  END IF;

  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(sheet_skid.sheet_net_wt),
         SUM(sheet_skid.sheet_net_wt) + SUM(sheet_skid.sheet_tare_wt),
         SUM(sheet_skid.skid_pieces)
    INTO ll_shipment_nt, ll_shipment_gt, ll_shipment_pc
    FROM sheet_skid, sheet_packing_item, shipment
   WHERE shipment.packing_list = sheet_packing_item.packing_list
     AND sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
     AND shipment.packing_list = al_packing_list;
  IF ll_shipment_pc = 0 THEN
    RETURN 100;
  END IF; -- empty shipment

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  -- Retrieve ABCO info
  -- ls_sender_vanid := '3010007080';
  ls_ic := 'R0P7A';

  -- Retrieve ALCAN supply code and Ford Stamping Plant location code
  --Changed by tony 01-07-09
  --SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf
  SELECT nvl(supply_code, 'D5X8R')
    INTO ls_sf
    FROM customer_customer
   WHERE o_customer_id = li_customer_id
     AND e_customer_id = 49; --Ford customer_id =49
  SELECT communication_code
    INTO ls_st
    FROM customer_system
   WHERE customer_id = li_des_sh_cust_id;

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'PT'), -- Protected Trailer
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE)
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_caarrier_initial,
         ldt_shipment
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;

  -- Get SCAC(Standard Carrier Alpha Code)
  SELECT nvl(carrier.scac, 'NONE')
    INTO ls_scac
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);

  -- Get Resceiver and Customer VAN ID
  -- SELECT NVL(customer_system.van_account_num, 'nothing'), NVL(customer_system.gs03, 'nothing')
  -- INTO ls_receiver_vanid, ls_receiver_gs03    -- ls_receiver_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --   (select shipment.des_sh_cust_id  from shipment  where shipment.packing_list = al_packing_list);

  -- SELECT NVL(customer_system.van_account_num, 'nothing'),NVL(customer_system.gs03, 'nothing')
  -- INTO   ls_customer_vanid, ls_customer_gs03   -- ls_customer_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --       (select shipment.customer_id from shipment where shipment.packing_list = al_packing_list);

  -- Generate Header Info.
  IF li_des_sh_cust_id = 1251 --TO Eagle Steel, send Eagle steel only
   THEN
    --x12_table(i) := 'ISA*00*'||'          *00*          *01*039630926T     *01*557529971      *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0') ||'*0*P**';
    x12_table(i) := 'ISA*00*' ||
                    '          *00*          *01*039630926T     *ZZ*557529971X12   *' ||
                    ls_today || '*' || ls_now || '*U*00200*' ||
                    lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
  ELSE
    x12_table(i) := 'ISA*00*' ||
                    '          *00*          *ZZ*R0P7A          *ZZ*F159B          *' ||
                    ls_today || '*' || ls_now || '*U*00200*' ||
                    lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
  END IF;
  --x12_table(i) := 'GS*SH*R0P7A*'||ls_st || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  i := i + 1;

  IF li_des_sh_cust_id = 1096 OR li_des_sh_cust_id = 1579 --Budd or Ogihara ERMA
   THEN
    --  x12_table(i) := 'GS*SH*R0P7A*'||'RMATS' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002FORD';
    --  Above will switch to follow when eRMA go live with Budd
    x12_table(i) := 'GS*SH*R0P7A*' || 'ERMA1' || '*' || ls_today || '*' ||
                    ls_now || '*' || to_char(ll_gs_log) || '*X*' ||
                    '002002FORD';
  ELSIF li_des_sh_cust_id = 1251 -- Eagle steel
   THEN
    --x12_table(i) := 'GS*SH*039630926T*'||'557529971' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002FORD';
    x12_table(i) := 'GS*SH*039630926T*' || '557529971X12' || '*' ||
                    ls_today || '*' || ls_now || '*' || to_char(ll_gs_log) ||
                    '*X*' || '002002FORD';
  ELSE
    x12_table(i) := 'GS*SH*R0P7A*' || ls_st || '*' || ls_today || '*' ||
                    ls_now || '*' || to_char(ll_gs_log) || '*X*' ||
                    '002002';
  END IF;
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'BSN*00*' || to_char(al_packing_list) || '*' || ls_today || '*' ||
                  ls_now; --changed by tony

  i := i + 1;
  x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYMMDD') || '*' ||
                  to_char(ldt_shipment, 'HH24MI');
  i := i + 1;

  -- First Level HL
  x12_table(i) := 'HL*01**S';
  i := i + 1;
  x12_table(i) := 'MEA*PD*G*' || to_char(ll_shipment_gt) || '*LB';
  i := i + 1;
  x12_table(i) := 'MEA*PD*N*' || to_char(ll_shipment_nt) || '*LB';
  i := i + 1;
  x12_table(i) := 'TD1*PLT90*' || to_char(li_rowcount);
  li_td1 := i;
  i := i + 1;
  x12_table(i) := 'TD5*B*02*' || ls_scac || '*M';
  i := i + 1;
  x12_table(i) := 'TD3*' || ls_carrier_desc_code || '**' || ls_vehicle_id;
  i := i + 1;
  x12_table(i) := 'REF*BM*' || to_char(ll_bill_of_lading);
  i := i + 1;
  --x12_table(i):= 'REF*BM*' ||  to_char(al_packing_list); i := i +1; -- Changed by tony for multi-parts shipment
  x12_table(i) := 'REF*PK*' || to_char(al_packing_list);
  i := i + 1;
  IF li_des_sh_cust_id = 1096 OR li_des_sh_cust_id = 1251 OR
     li_des_sh_cust_id = 1579 THEN
    x12_table(i) := 'REF*ZZ*' || ls_st;
    i := i + 1;
  END IF;
  x12_table(i) := 'N1*ST**92*' || ls_st;
  i := i + 1;

  -- Second Level HL based on End User PO( only one part# is included in one shipement per FORD's request)

  OPEN alcan_ford_856_cur;
  FETCH alcan_ford_856_cur
    INTO skidinfo_rec;

  --    ls_enduser_part := skidinfo_rec.ENDUSER_PART_NUM;
  --    ls_enduser_po := skidinfo_rec.ENDUSER_PO;

  --SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf

  SELECT "ORDER_ITEM"."ENDUSER_PART_NUM",
         nvl("ORDER_ITEM"."SUPPLIER_CODE", 'D5X8R')
    INTO ls_enduser_part, ls_sf2
  --Changed by tony 01-07-09
  --SELECT "ORDER_ITEM"."ENDUSER_PART_NUM", NVL("ORDER_ITEM"."SUPPLIER_CODE", 'D5X8F' ) into ls_enduser_part, ls_sf2
    FROM "ORDER_ITEM", "SHEET_SKID"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
     AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
     AND ("SHEET_SKID"."SHEET_SKID_NUM" = skidinfo_rec.sheet_skid_num);

  SELECT "CUSTOMER_ORDER"."ENDUSER_PO"
    INTO ls_enduser_po
    FROM "SHEET_SKID", "CUSTOMER_ORDER"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
         "CUSTOMER_ORDER"."ORDER_ABC_NUM")
     AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num);

  IF ls_sf2 = 'D5X8R' THEN
    ls_sf := ls_sf2;
  END IF;

  -- turn these Three lines off when buddle flipper is online
  --  if skidinfo_rec.ORIG_CUSTOMER_PO IN ('68Q68517') then    --Do NOT send 856 to Ford for some flipping related POs )
  --       edi_file_prefix := 'nosend_alcan_ford_ford';
  --  end if;
  -- end buddle flipper

  -- Get cumulative pc for part every year starting Aug 1st. Per Novelis by tony

  x12_table(i) := 'N1*SF**92*' || ls_sf;
  i := i + 1;

  IF NOT (li_des_sh_cust_id = 1096 OR li_des_sh_cust_id = 1251 OR
      li_des_sh_cust_id = 1579) THEN
    x12_table(i) := 'N1*IC**92*' || ls_ic;
    i := i + 1;
  END IF;

  ld_cumulative_start := add_months(trunc(SYSDATE, 'YYYY'), 7);
  IF (SYSDATE - ld_cumulative_start) < 0 THEN
    ld_cumulative_start := add_months(ld_cumulative_start, -12);
  END IF;

  SELECT SUM(sheet_skid.skid_pieces)
    INTO ll_cumulative_pc
    FROM shipment, sheet_packing_item, sheet_skid, order_item
   WHERE shipment.packing_list = sheet_packing_item.packing_list
     AND sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
     AND (sheet_skid.ref_order_abc_num = order_item.order_abc_num AND
         sheet_skid.ref_order_abc_item = order_item.order_item_num)
     AND order_item.enduser_part_num = ls_enduser_part
     AND shipment.shipment_actualed_date_time >= ld_cumulative_start;

  -- ll_cumulative_pc := ll_cumulative_pc + ll_shipment_pc;

  x12_table(i) := 'HL*02*01*O';
  i := i + 1;
  x12_table(i) := 'LIN**BP*' || ls_enduser_part;
  i := i + 1;
  x12_table(i) := 'SN1**' || to_char(ll_shipment_pc) || '*EA*' ||
                  to_char(ll_cumulative_pc);
  i := i + 1;
  IF li_des_sh_cust_id = 1096 OR li_des_sh_cust_id = 1251 OR
     li_des_sh_cust_id = 1579 THEN
    --x12_table(i) :='PRF*';i:=i+1; --temp for test
    x12_table(i) := 'PRF*' || ls_enduser_po;
    i := i + 1;
  END IF;
  CLOSE alcan_ford_856_cur;

  -- Third Level HL Under a P.O.
  li_hl01 := 3;

  FOR skidinfo_rec IN alcan_ford_856_cur LOOP
    IF length(to_char(li_hl01)) = 1 THEN
      x12_table(i) := 'HL*0' || to_char(li_hl01) || '*02*I';
      i := i + 1;
    ELSE
      x12_table(i) := 'HL*' || to_char(li_hl01) || '*02*I';
      i := i + 1;
    END IF;

    IF li_des_sh_cust_id = 1096 OR li_des_sh_cust_id = 1251 OR
       li_des_sh_cust_id = 1579 THEN
      x12_table(i) := 'SN1**' || to_char(skidinfo_rec.skid_pieces) || '*EA';
      i := i + 1;
    ELSE
      x12_table(i) := 'SN1**1*PF';
      i := i + 1;
    END IF;

    IF li_des_sh_cust_id = 1096 OR li_des_sh_cust_id = 1579 -- To Budd or li_des_sh_cust_id = 1251 then
     THEN
      x12_table(i) := 'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) ||
                      '*01';
      i := i + 1;
      x12_table(i) := 'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) ||
                      '*24';
      i := i + 1;
    ELSIF li_des_sh_cust_id = 1251 --To Eagle Steel
     THEN
      x12_table(i) := 'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) ||
                      '*01';
      i := i + 1;
      x12_table(i) := 'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) ||
                      '*24';
      i := i + 1;
      x12_table(i) := 'MEA*PD*TH*' || to_char(skidinfo_rec.gauge) || '*EM';
      i := i + 1;
      x12_table(i) := 'MEA*PD*WD*' || '44.875' || '*IN';
      i := i + 1;
      x12_table(i) := 'MEA*PD*LN*' || to_char(skidinfo_rec.skid_pieces) ||
                      '*LF';
      i := i + 1;
    ELSE
      --All else, Ford dirct shiping program
      x12_table(i) := 'MEA*PD*N*' || to_char(skidinfo_rec.sheet_net_wt) ||
                      '*01';
      i := i + 1;
      x12_table(i) := 'MEA*PD*WT*' || to_char(skidinfo_rec.skid_pieces) ||
                      '*PC';
      i := i + 1;
    END IF;

    ls_lot  := skidinfo_rec.lot_num;
    ls_coil := skidinfo_rec.coil_id;

    -- fill in lot num
    SELECT COUNT(*)
      INTO li_rc
      FROM sheet_skid_detail
     WHERE sheet_skid_detail.sheet_skid_num = skidinfo_rec.sheet_skid_num;
    IF li_rc = 1 THEN
      SELECT lot_num, coil_org_num
        INTO ls_lot, ls_coil
        FROM coil
       WHERE coil.coil_abc_num =
             (SELECT coil_abc_num
                FROM production_sheet_item
               WHERE production_sheet_item.prod_item_num =
                     (SELECT prod_item_num
                        FROM sheet_skid_detail
                       WHERE sheet_skid_detail.sheet_skid_num =
                             skidinfo_rec.sheet_skid_num));
    END IF;

    IF li_des_sh_cust_id = 1251 --Eagle need coil ID here instead of lot number
     THEN
      x12_table(i) := 'REF*HC*' || ls_coil;
      i := i + 1;
    ELSE
      x12_table(i) := 'REF*HC*' || ls_lot;
      i := i + 1;
    END IF;

    x12_table(i) := 'REF*LS*' ||
                    to_char(skidinfo_rec.sheet_skid_display_num);
    i := i + 1;
    li_hl01 := li_hl01 + 1;
    li_rowcount := alcan_ford_856_cur%ROWCOUNT;
    x12_table(li_td1) := 'TD1*PLT90*' || to_char(li_rowcount);
  END LOOP;

  -- DBMS_OUTPUT.PUT_LINE ('rowcount' || to_char(li_rowcount));

  IF li_des_sh_cust_id = 1096 OR li_des_sh_cust_id = 1251 OR
     li_des_sh_cust_id = 1579 THEN
    x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                    to_char(ll_shipment_pc * 2);
    i := i + 1;
  ELSE
    x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                    to_char(li_rowcount + ll_shipment_pc);
    i := i + 1;
  END IF;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  -- Write X.12 to file
  -- To FORD

  --*************Temp solution for WSDC, only sending to Alcan********************
  --if li_des_sh_cust_id<>79 THEN
  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  --edi_file:= 'S_alcan_ford_ford_' || to_char(ll_edi_file_id) ||'.x12';
  -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
  -- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
    --v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
  END LOOP;
  utl_file.fclose(edi_file_handle);
  --END IF;
  --******************* WSDC customer ID = 79 SKID FORD FILE***********************

  --To ALCAN

  /*

  SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;
  SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id_alcan FROM DUAL;
  edi_file:= 'S_alcan_ford_alcan_' || to_char(ll_edi_file_id_alcan) ||'.x12';
  edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');
  x12_table(0) := 'ISA*00*'||'          *00*          *01*039630926T     *09*0015049350011G *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0')||'*0*P**';
  x12_table(1) := 'GS*SH*R0P7A*'||'001504935001' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  x12_table(i-1) :=  'GE*1*' || to_char (ll_gs_log);
  x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');
  for j in 0..i loop
   UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
       v_edi_text_alcan:=v_edi_text_alcan||x12_table(j)||CHR(10);
  end loop;
  UTL_FILE.FCLOSE(edi_file_handle);

  */

  /* The following code added by Tony, for update archive*/

  --  INSERT INTO edi_log (edi_log_timestamp,customer_id,
  --         customer_edi_name,edi_log_contents,edi_file_id,edi_text)
  --    VALUES (SYSDATE,li_customer_id,ll_customer_edi_name,
  --           'EDI:'||ll_customer_edi_name||' generated successfully.',ll_edi_file_id,v_edi_text);
  --   COMMIT;

  /*
    UPDATE shipment
       SET shipment_des_edi856_date= SYSDATE,
           shipment_edi856_date=SYSDATE
       WHERE shipment.packing_list = al_packing_list;
     COMMIT;
  */

  --exception
  --   when invalid_operation
  --   then
  --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

  --  when others
  --  then
  --      DBMS_OUTPUT.PUT_LINE ('System Error');
  --      UTL_FILE.FCLOSE(edi_file_handle);

  RETURN 1;
END edi_alcan_ford_856_x12;
  GRANT EXECUTE ON "DBO"."EDI_ALCAN_FORD_856_X12" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function EDI_ALCAN_FORD_856_X12_ORIG
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_ALCAN_FORD_856_X12_ORIG" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*
  Aluminum Blanking: Ford Suppler Code: ZZ R0P7A
                     DUNS: 01 039630926T
  Customer: ALCAN(34,35,10,1153)
  Alcan Rolled Product    X.121       0015049350011G          
  End User: Ford (ZZ F159B)
            Ford Chicageo Stamping Plant(51) MS02A
            Ford Walton Hills Stamping Plant(77) MS03A
            Ford Woodhaven Stamping Plant(71) AF30A MS09A
            Ford Maumee Stamping Plant(78)    AF06A MS08A
            Ford Ogihara  (1579 )           F7BFC
  
            Budd Company (Customer ID: 1096) B821L
            Eagle Steel (1251) MZF6B
            (not in use)Ford Monroe Stamping              AP06A
            
            (not in use) Warehouses: IDS(41)               R5G3B
            (not in use) Wayne Steel Distribution Center(79) RWSDC
            
  */

  --v_edi_text_ford varchar2(32767);
  --v_edi_text_alcan varchar2(32767);
  ll_customer_edi_name VARCHAR2(20);

  edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  --edi_loc varchar2(50):='/tmp';
  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_prefix VARCHAR2(50) := 'S_alcan_ford_ford_';
  edi_file_handle utl_file.file_type;

  li_customer_id    shipment.customer_id%TYPE;
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;

  -- ls_sender_vanid varchar2 (50);
  -- ls_receiver_vanid varchar2 (50);
  -- ls_customer_vanid varchar2(50);
  -- ls_receiver_gs03 varchar2(50);
  -- ls_customer_gs03 varchar2(50);
  ls_st      VARCHAR2(50);
  ls_sf      VARCHAR2(50);
  ls_sf2     VARCHAR2(50);
  ls_ic      VARCHAR2(50);
  ll_gs_log  INTEGER;
  ll_st_log  INTEGER;
  ll_bsn_log INTEGER;

  ls_today VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  ls_now   VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  ll_newrow         INTEGER;
  ll_sheet_skid_num INTEGER;
  li_rowcount       INTEGER;
  li_rownum         INTEGER;
  li_rownum1        INTEGER;
  li_hl01           INTEGER;
  li_hl02           INTEGER;
  ll_shipment_nt    INTEGER;
  ll_shipment_gt    INTEGER;
  ll_shipment_pc    INTEGER;
  li_enduser_id     INTEGER;
  li_td1            INTEGER;
  li_rc             INTEGER;
  ll_cumulative_pc  INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_scac              carrier.scac%TYPE;
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_caarrier_initial  VARCHAR2(50);
  ldt_shipment         DATE;
  ld_shipdate          DATE;
  ld_cumulative_start  DATE;

  ls_enduser_part VARCHAR2(50);
  ls_enduser_po   VARCHAR2(50);

  ls_lot  VARCHAR2(25);
  ls_coil VARCHAR2(25);

  ll_edi_file_id       INTEGER;
  ll_edi_file_id_alcan INTEGER;

  CURSOR alcan_ford_856_cur IS
    SELECT sheet_packing_item.sh_packing_item,
           'MULTIPLE' lot_num,
           'MULTIPLE' coil_id,
           customer_order.orig_customer_po,
           customer_order.order_abc_num,
           customer_order.enduser_po,
           order_item.order_item_num,
           order_item.enduser_part_num,
           order_item.supplier_code,
           order_item.gauge,
           sheet_skid. ab_job_num,
           sheet_skid.sheet_skid_num,
           sheet_skid.sheet_net_wt,
           sheet_skid.sheet_theoretical_wt,
           sheet_skid.sheet_tare_wt,
           sheet_skid. skid_pieces,
           sheet_skid.skid_sheet_status,
           NULL done
      FROM customer_order,
           order_item,
           sheet_skid,
           ab_job,
           shipment,
           sheet_packing_item
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
  --      (SHIPMENT.SHIPMENT_EDI856_DATE is NULL); 

  TYPE skidinfo_tabletype IS TABLE OF alcan_ford_856_cur%ROWTYPE INDEX BY BINARY_INTEGER;
  skidinfo_table skidinfo_tabletype;
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table    store_tabletype;
  i            BINARY_INTEGER := 0;
  skidinfo_rec alcan_ford_856_cur%ROWTYPE;

BEGIN
  -- Get Customer ID, End user ID
  SELECT customer_id, des_sh_cust_id
    INTO li_customer_id, li_des_sh_cust_id
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;
  IF NOT SQL%FOUND THEN
    RETURN - 1;
  END IF;

  -- dbms_output.put_line (to_char(li_customer_id) || '  ' || to_char(li_des_sh_cust_id) );

  --if al_packing_list = 35609 then
  --return 0;
  --end if;

  --IF NOT ((li_customer_id IN (34,35,10,1153)) AND (li_des_sh_cust_id IN (51,71,77,78,1096,1251,79, 1347, 1382,1383, 1104, 1401,1401, 1388, 1149, 1579))) 
  -- Delete 1382 per Alcan By tony 03/29/04
  --IF NOT ((li_customer_id IN (34,35,10,1153)) AND (li_des_sh_cust_id IN (51,71,77,78,1096,1251,79, 1347,1383, 1104, 1401,1401, 1388, 1149, 1579))) 

  IF NOT ((li_customer_id IN (34, 35, 10, 1153)) AND
      (li_des_sh_cust_id IN (51,
                                 71,
                                 77,
                                 78,
                                 1096,
                                 1251,
                                 79,
                                 1347,
                                 1104,
                                 1401,
                                 1401,
                                 1388,
                                 1149,
                                 1579)))
  --Delete 1383 per WoodHaven, -By tony 10-18-05
   THEN
    RETURN 200;
  END IF;

  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(sheet_skid.sheet_net_wt),
         SUM(sheet_skid.sheet_net_wt) + SUM(sheet_skid.sheet_tare_wt),
         SUM(sheet_skid.skid_pieces)
    INTO ll_shipment_nt, ll_shipment_gt, ll_shipment_pc
    FROM sheet_skid, sheet_packing_item, shipment
   WHERE shipment.packing_list = sheet_packing_item.packing_list
     AND sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
     AND shipment.packing_list = al_packing_list;
  IF ll_shipment_pc = 0 THEN
    RETURN 100;
  END IF; -- empty shipment

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  -- Retrieve ABCO info
  -- ls_sender_vanid := '3010007080';
  ls_ic := 'R0P7A';

  -- Retrieve ALCAN supply code and Ford Stamping Plant location code 
  --Changed by tony 01-07-09
  --SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf
  SELECT nvl(supply_code, 'D5X8R')
    INTO ls_sf
    FROM customer_customer
   WHERE o_customer_id = li_customer_id
     AND e_customer_id = 49; --Ford customer_id =49
  SELECT communication_code
    INTO ls_st
    FROM customer_system
   WHERE customer_id = li_des_sh_cust_id;

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'PT'), -- Protected Trailer 
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE)
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_caarrier_initial,
         ldt_shipment
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;

  -- Get SCAC(Standard Carrier Alpha Code)
  SELECT nvl(carrier.scac, 'NONE')
    INTO ls_scac
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);

  -- Get Resceiver and Customer VAN ID
  -- SELECT NVL(customer_system.van_account_num, 'nothing'), NVL(customer_system.gs03, 'nothing')
  -- INTO ls_receiver_vanid, ls_receiver_gs03    -- ls_receiver_vanid 
  -- FROM  customer_system WHERE customer_system.customer_id = 
  --   (select shipment.des_sh_cust_id  from shipment  where shipment.packing_list = al_packing_list);

  -- SELECT NVL(customer_system.van_account_num, 'nothing'),NVL(customer_system.gs03, 'nothing')
  -- INTO   ls_customer_vanid, ls_customer_gs03   -- ls_customer_vanid 
  -- FROM  customer_system WHERE customer_system.customer_id = 
  --       (select shipment.customer_id from shipment where shipment.packing_list = al_packing_list);

  -- Generate Header Info.
  IF li_des_sh_cust_id = 1251 --TO Eagle Steel, send Eagle steel only
   THEN
    --x12_table(i) := 'ISA*00*'||'          *00*          *01*039630926T     *01*557529971      *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0') ||'*0*P**';
    x12_table(i) := 'ISA*00*' ||
                    '          *00*          *01*039630926T     *ZZ*557529971X12   *' ||
                    ls_today || '*' || ls_now || '*U*00200*' ||
                    lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
  ELSE
    x12_table(i) := 'ISA*00*' ||
                    '          *00*          *ZZ*R0P7A          *ZZ*F159B          *' ||
                    ls_today || '*' || ls_now || '*U*00200*' ||
                    lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
  END IF;
  --x12_table(i) := 'GS*SH*R0P7A*'||ls_st || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002'; 
  i := i + 1;

  IF li_des_sh_cust_id = 1096 OR li_des_sh_cust_id = 1579 --Budd or Ogihara ERMA
   THEN
    --  x12_table(i) := 'GS*SH*R0P7A*'||'RMATS' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002FORD';
    --  Above will switch to follow when eRMA go live with Budd
    x12_table(i) := 'GS*SH*R0P7A*' || 'ERMA1' || '*' || ls_today || '*' ||
                    ls_now || '*' || to_char(ll_gs_log) || '*X*' ||
                    '002002FORD';
  ELSIF li_des_sh_cust_id = 1251 -- Eagle steel
   THEN
    --x12_table(i) := 'GS*SH*039630926T*'||'557529971' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002FORD';
    x12_table(i) := 'GS*SH*039630926T*' || '557529971X12' || '*' ||
                    ls_today || '*' || ls_now || '*' || to_char(ll_gs_log) ||
                    '*X*' || '002002FORD';
  ELSE
    x12_table(i) := 'GS*SH*R0P7A*' || ls_st || '*' || ls_today || '*' ||
                    ls_now || '*' || to_char(ll_gs_log) || '*X*' ||
                    '002002';
  END IF;
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'BSN*00*' || to_char(al_packing_list) || '*' || ls_today || '*' ||
                  ls_now; --changed by tony

  i := i + 1;
  x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYMMDD') || '*' ||
                  to_char(ldt_shipment, 'HH24MI');
  i := i + 1;

  -- First Level HL
  x12_table(i) := 'HL*01**S';
  i := i + 1;
  x12_table(i) := 'MEA*PD*G*' || to_char(ll_shipment_gt) || '*LB';
  i := i + 1;
  x12_table(i) := 'MEA*PD*N*' || to_char(ll_shipment_nt) || '*LB';
  i := i + 1;
  x12_table(i) := 'TD1*PLT90*' || to_char(li_rowcount);
  li_td1 := i;
  i := i + 1;
  x12_table(i) := 'TD5*B*02*' || ls_scac || '*M';
  i := i + 1;
  x12_table(i) := 'TD3*' || ls_carrier_desc_code || '**' || ls_vehicle_id;
  i := i + 1;
  x12_table(i) := 'REF*BM*' || to_char(ll_bill_of_lading);
  i := i + 1;
  --x12_table(i):= 'REF*BM*' ||  to_char(al_packing_list); i := i +1; -- Changed by tony for multi-parts shipment
  x12_table(i) := 'REF*PK*' || to_char(al_packing_list);
  i := i + 1;
  IF li_des_sh_cust_id = 1096 OR li_des_sh_cust_id = 1251 OR
     li_des_sh_cust_id = 1579 THEN
    x12_table(i) := 'REF*ZZ*' || ls_st;
    i := i + 1;
  END IF;
  x12_table(i) := 'N1*ST**92*' || ls_st;
  i := i + 1;

  -- Second Level HL based on End User PO( only one part# is included in one shipement per FORD's request)

  OPEN alcan_ford_856_cur;
  FETCH alcan_ford_856_cur
    INTO skidinfo_rec;

  --    ls_enduser_part := skidinfo_rec.ENDUSER_PART_NUM;
  --    ls_enduser_po := skidinfo_rec.ENDUSER_PO;

  --SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf

  SELECT "ORDER_ITEM"."ENDUSER_PART_NUM",
         nvl("ORDER_ITEM"."SUPPLIER_CODE", 'D5X8R')
    INTO ls_enduser_part, ls_sf2
  --Changed by tony 01-07-09
  --SELECT "ORDER_ITEM"."ENDUSER_PART_NUM", NVL("ORDER_ITEM"."SUPPLIER_CODE", 'D5X8F' ) into ls_enduser_part, ls_sf2
    FROM "ORDER_ITEM", "SHEET_SKID"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
     AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
     AND ("SHEET_SKID"."SHEET_SKID_NUM" = skidinfo_rec.sheet_skid_num);

  SELECT "CUSTOMER_ORDER"."ENDUSER_PO"
    INTO ls_enduser_po
    FROM "SHEET_SKID", "CUSTOMER_ORDER"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
         "CUSTOMER_ORDER"."ORDER_ABC_NUM")
     AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num);

  IF ls_sf2 = 'D5X8R' THEN
    ls_sf := ls_sf2;
  END IF;

  -- turn these Three lines off when buddle flipper is online
  --  if skidinfo_rec.ORIG_CUSTOMER_PO IN ('68Q68517') then    --Do NOT send 856 to Ford for some flipping related POs )
  --       edi_file_prefix := 'nosend_alcan_ford_ford';
  --  end if; 
  -- end buddle flipper

  -- Get cumulative pc for part every year starting Aug 1st. Per Novelis by tony 

  x12_table(i) := 'N1*SF**92*' || ls_sf;
  i := i + 1;

  IF NOT (li_des_sh_cust_id = 1096 OR li_des_sh_cust_id = 1251 OR
      li_des_sh_cust_id = 1579) THEN
    x12_table(i) := 'N1*IC**92*' || ls_ic;
    i := i + 1;
  END IF;

  ld_cumulative_start := add_months(trunc(SYSDATE, 'YYYY'), 7);
  IF (SYSDATE - ld_cumulative_start) < 0 THEN
    ld_cumulative_start := add_months(ld_cumulative_start, -12);
  END IF;

  SELECT SUM(sheet_skid.skid_pieces)
    INTO ll_cumulative_pc
    FROM shipment, sheet_packing_item, sheet_skid, order_item
   WHERE shipment.packing_list = sheet_packing_item.packing_list
     AND sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
     AND (sheet_skid.ref_order_abc_num = order_item.order_abc_num AND
         sheet_skid.ref_order_abc_item = order_item.order_item_num)
     AND order_item.enduser_part_num = ls_enduser_part
     AND shipment.shipment_actualed_date_time >= ld_cumulative_start;

  -- ll_cumulative_pc := ll_cumulative_pc + ll_shipment_pc;

  x12_table(i) := 'HL*02*01*O';
  i := i + 1;
  x12_table(i) := 'LIN**BP*' || ls_enduser_part;
  i := i + 1;
  x12_table(i) := 'SN1**' || to_char(ll_shipment_pc) || '*EA*' ||
                  to_char(ll_cumulative_pc);
  i := i + 1;
  IF li_des_sh_cust_id = 1096 OR li_des_sh_cust_id = 1251 OR
     li_des_sh_cust_id = 1579 THEN
    --x12_table(i) :='PRF*';i:=i+1; --temp for test
    x12_table(i) := 'PRF*' || ls_enduser_po;
    i := i + 1;
  END IF;
  CLOSE alcan_ford_856_cur;

  -- Third Level HL Under a P.O.
  li_hl01 := 3;

  FOR skidinfo_rec IN alcan_ford_856_cur LOOP
    IF length(to_char(li_hl01)) = 1 THEN
      x12_table(i) := 'HL*0' || to_char(li_hl01) || '*02*I';
      i := i + 1;
    ELSE
      x12_table(i) := 'HL*' || to_char(li_hl01) || '*02*I';
      i := i + 1;
    END IF;
  
    IF li_des_sh_cust_id = 1096 OR li_des_sh_cust_id = 1251 OR
       li_des_sh_cust_id = 1579 THEN
      x12_table(i) := 'SN1**' || to_char(skidinfo_rec.skid_pieces) || '*EA';
      i := i + 1;
    ELSE
      x12_table(i) := 'SN1**1*PF';
      i := i + 1;
    END IF;
  
    IF li_des_sh_cust_id = 1096 OR li_des_sh_cust_id = 1579 -- To Budd or li_des_sh_cust_id = 1251 then
     THEN
      x12_table(i) := 'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) ||
                      '*01';
      i := i + 1;
      x12_table(i) := 'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) ||
                      '*24';
      i := i + 1;
    ELSIF li_des_sh_cust_id = 1251 --To Eagle Steel
     THEN
      x12_table(i) := 'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) ||
                      '*01';
      i := i + 1;
      x12_table(i) := 'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) ||
                      '*24';
      i := i + 1;
      x12_table(i) := 'MEA*PD*TH*' || to_char(skidinfo_rec.gauge) || '*EM';
      i := i + 1;
      x12_table(i) := 'MEA*PD*WD*' || '44.875' || '*IN';
      i := i + 1;
      x12_table(i) := 'MEA*PD*LN*' || to_char(skidinfo_rec.skid_pieces) ||
                      '*LF';
      i := i + 1;
    ELSE
      --All else, Ford dirct shiping program
      x12_table(i) := 'MEA*PD*N*' || to_char(skidinfo_rec.sheet_net_wt) ||
                      '*01';
      i := i + 1;
      x12_table(i) := 'MEA*PD*WT*' || to_char(skidinfo_rec.skid_pieces) ||
                      '*PC';
      i := i + 1;
    END IF;
  
    ls_lot  := skidinfo_rec.lot_num;
    ls_coil := skidinfo_rec.coil_id;
  
    -- fill in lot num
    SELECT COUNT(*)
      INTO li_rc
      FROM sheet_skid_detail
     WHERE sheet_skid_detail.sheet_skid_num = skidinfo_rec.sheet_skid_num;
    IF li_rc = 1 THEN
      SELECT lot_num, coil_org_num
        INTO ls_lot, ls_coil
        FROM coil
       WHERE coil.coil_abc_num =
             (SELECT coil_abc_num
                FROM production_sheet_item
               WHERE production_sheet_item.prod_item_num =
                     (SELECT prod_item_num
                        FROM sheet_skid_detail
                       WHERE sheet_skid_detail.sheet_skid_num =
                             skidinfo_rec.sheet_skid_num));
    END IF;
  
    IF li_des_sh_cust_id = 1251 --Eagle need coil ID here instead of lot number
     THEN
      x12_table(i) := 'REF*HC*' || ls_coil;
      i := i + 1;
    ELSE
      x12_table(i) := 'REF*HC*' || ls_lot;
      i := i + 1;
    END IF;
  
    x12_table(i) := 'REF*LS*' || to_char(skidinfo_rec.sheet_skid_num);
    i := i + 1;
    li_hl01 := li_hl01 + 1;
    li_rowcount := alcan_ford_856_cur%ROWCOUNT;
    x12_table(li_td1) := 'TD1*PLT90*' || to_char(li_rowcount);
  END LOOP;

  -- DBMS_OUTPUT.PUT_LINE ('rowcount' || to_char(li_rowcount));

  IF li_des_sh_cust_id = 1096 OR li_des_sh_cust_id = 1251 OR
     li_des_sh_cust_id = 1579 THEN
    x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                    to_char(ll_shipment_pc * 2);
    i := i + 1;
  ELSE
    x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                    to_char(li_rowcount + ll_shipment_pc);
    i := i + 1;
  END IF;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  -- Write X.12 to file
  -- To FORD

  --*************Temp solution for WSDC, only sending to Alcan********************
  --if li_des_sh_cust_id<>79 THEN
  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  --edi_file:= 'S_alcan_ford_ford_' || to_char(ll_edi_file_id) ||'.x12';
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
    --v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);        
  END LOOP;
  utl_file.fclose(edi_file_handle);
  --END IF;   
  --******************* WSDC customer ID = 79 SKID FORD FILE***********************

  --To ALCAN

  /*
  
  SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;
  SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id_alcan FROM DUAL;
  edi_file:= 'S_alcan_ford_alcan_' || to_char(ll_edi_file_id_alcan) ||'.x12';
  edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');
  x12_table(0) := 'ISA*00*'||'          *00*          *01*039630926T     *09*0015049350011G *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0')||'*0*P**';
  x12_table(1) := 'GS*SH*R0P7A*'||'001504935001' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  x12_table(i-1) :=  'GE*1*' || to_char (ll_gs_log);
  x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');
  for j in 0..i loop
   UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
       v_edi_text_alcan:=v_edi_text_alcan||x12_table(j)||CHR(10);        
  end loop;
  UTL_FILE.FCLOSE(edi_file_handle);
  
  */

  /* The following code added by Tony, for update archive*/

  --  INSERT INTO edi_log (edi_log_timestamp,customer_id,
  --         customer_edi_name,edi_log_contents,edi_file_id,edi_text)
  --    VALUES (SYSDATE,li_customer_id,ll_customer_edi_name,
  --           'EDI:'||ll_customer_edi_name||' generated successfully.',ll_edi_file_id,v_edi_text);       
  --   COMMIT;

  /*
    UPDATE shipment
       SET shipment_des_edi856_date= SYSDATE,
           shipment_edi856_date=SYSDATE
       WHERE shipment.packing_list = al_packing_list;
     COMMIT;
  */

  --exception
  --   when invalid_operation
  --   then
  --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

  --  when others
  --  then
  --      DBMS_OUTPUT.PUT_LINE ('System Error');
  --      UTL_FILE.FCLOSE(edi_file_handle);  

  RETURN 1;
END edi_alcan_ford_856_x12_orig;
  GRANT EXECUTE ON "DBO"."EDI_ALCAN_FORD_856_X12_ORIG" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function EDI_ALCAN_TEST
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_ALCAN_TEST" (group_id integer, set_num integer )  return integer is
  Result integer;
  edi_loc varchar2 (50) := '/templar/templar/incoming/senddata';
  --edi_loc varchar2(50):='/tmp';

  edi_file varchar2 (50) := 'edi_out.txt';
  edi_file_prefix varchar2 (50) := 'S_alcan_test';
  edi_file_handle UTL_FILE.FILE_TYPE;
  -- ls_sf varchar2(50);
  -- ls_ic varchar2(50);
  -- ls_su varchar2(50);
  -- ls_st_duns varchar2(50);
  ll_gs_log integer;
  ll_st_log integer;
  ll_bsn_log integer;

  ls_today varchar2(20):= to_char(sysdate, 'YYYYMMDD');
  ls_today_4 varchar2(20):= to_char(sysdate, 'YYMMDD');
  ls_now varchar2(20) := to_char(sysdate, 'HH24MI'); -- time in 24 hours format....Tony

  ll_edi_file_id_alcan integer;


  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i binary_integer := 0;
  j binary_integer := 0;


begin
   SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;
   SELECT edi_st_log_seq.NEXTVAL INTO ll_st_log FROM DUAL;
   SELECT edi_bsn_log_seq.NEXTVAL INTO ll_bsn_log FROM DUAL;

   x12_table(i) := 'ISA*00*'||'          *00*          *01*039630926T     *09*0015049350011G *'||ls_today_4 ||'*'|| ls_now ||'*U*00401*'||LPAD(to_char(ll_gs_log),9,'0')||'*0*P**'; i := i + 1;
   x12_table(i) := 'GS*FA*039630926T*'||'001504935' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '004010'; i := i + 1;
--   x12_table(i):= 'ST*997*' || to_char(ll_st_log); i := i +1;
   x12_table(i):= 'ST*997*0001'; i := i+1; -- || to_char(ll_st_log); i := i +1;
   x12_table(i):= 'AK1*SH*' || to_char( group_id ); i := i+1; -- Change 3141 to real GS group id
   x12_table(i):= 'AK9*A*' || to_char(set_num) || '*'|| to_char(set_num) || '*' || to_char(set_num); i := i+1; -- Change 2 to real total ST number

   --x12_table(i) :=  'CTT*' || to_char(li_HL01 - 1); i := i+1;
   --x12_table(i) :=  'SE*' || to_char (i-1) ||'*'|| to_char(ll_st_log); i := i+1;
   x12_table(i) :=  'SE*' || to_char (i-1) ||'*0001'; i := i + 1; --|| to_char(ll_st_log); i := i+1;

   x12_table(i) :=  'GE*1*' || to_char (ll_gs_log); i := i+1;
   x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');


   SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id_alcan FROM DUAL;
   -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
   -- edi_file:= 'S_alcan_test' || to_char(ll_edi_file_id_alcan) ||'.997';
   edi_file:= edi_file_prefix || to_char(ll_edi_file_id_alcan) ||'.edi';
   edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');

                for j in 0..i loop
                    UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
                end loop;
   UTL_FILE.FCLOSE(edi_file_handle);

   Result := 0;

   return(Result);
end EDI_ALCAN_TEST;
  GRANT EXECUTE ON "DBO"."EDI_ALCAN_TEST" TO "AGERLANTS"
