--  DDL for Function EDI_ALCOA_HAYES_856_X12
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_ALCOA_HAYES_856_X12" (al_packing_list shipment.packing_list%TYPE) return integer
/*
Returns:   Integer
               1 = if it succeeds
              -1 = if a system error occurs
             100 = no process data
             200 = no EDI defined
*/
is
/*
Aluminum Blanking: DUNS: 01 039630926T
Customer: ALCOA-TEXARKANA(1188)
SHIP TO HAYES LEMMERZ (01  089290118)

*/

--Alex Gerlants. 11/15/2016. Commented out, and added the line after.
--edi_loc varchar2 (50) := '/templar/templar/incoming/senddata';
edi_loc VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR');

--edi_loc varchar2(50):='/tmp';
edi_file varchar2 (50) := 'edi_out.txt';
edi_file_prefix varchar2 (50) := 'S_alcoa_hayes_';
edi_file_handle UTL_FILE.FILE_TYPE;

li_customer_id shipment.customer_id%TYPE;
li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;

ls_sf varchar2(50);
--ls_ic varchar2(50);
--ls_su varchar2(50);
ls_st_duns varchar2(50);
--ls_po varchar2(30);
ll_gs_log integer;
ll_st_log integer;
ll_bsn_log integer;

ls_today varchar2(20):= to_char(sysdate, 'YYMMDD');
ls_now varchar2(20) := to_char(sysdate, 'HH24MI');
ls_today_4dy varchar2(20) := to_char(sysdate,'YYYYMMDD');

Shipment_Skid_Count integer;
li_HL01 integer;
--li_HL02 integer;
ll_shipment_nt integer;
ll_shipment_gt integer;
ll_shipment_pc integer;
--li_enduser_id integer;
OrderAbcNum integer;
OrderItemNum integer;


--li_td1 integer;
--li_rc integer;

Cumulative integer;

ll_bill_of_lading integer;
ls_vehicle_id  varchar2(50);
ls_scac carrier.scac%TYPE;
ls_tran_method_code varchar2(50);
ls_carrier_desc_code varchar2(50);
ls_caarrier_initial varchar2(50);
ldt_shipment date;
--ld_shipdate date;

--ls_enduser_part varchar2(50);
--ls_enduser_po varchar2(50);

ll_edi_file_id integer;
--ll_edi_file_id_alcan integer;

--ls_lot_num varchar2(32);
--ls_coil_id varchar2(32);

Cursor alcoa_hayes_856_cur IS
SELECT SHEET_PACKING_ITEM.SH_PACKING_ITEM,
         'MULTIPLE' LOT_NUM,
         'MULTIPLE' COIL_ID,
         CUSTOMER_ORDER.ORIG_CUSTOMER_PO,
         CUSTOMER_ORDER.ORDER_ABC_NUM,
         CUSTOMER_ORDER.ENDUSER_PO,
         CUSTOMER_ORDER.CREATED_DATE,
         ORDER_ITEM.ORDER_ITEM_NUM,
         ORDER_ITEM.ENDUSER_PART_NUM,
         ORDER_ITEM.SUPPLIER_CODE,
         ORDER_ITEM.GAUGE,
         SHEET_SKID. AB_JOB_NUM,
         SHEET_SKID.SHEET_SKID_NUM,
         SHEET_SKID.SHEET_NET_WT,
         SHEET_SKID.SHEET_TARE_WT,
         SHEET_SKID. SKID_PIECES,
         SHEET_SKID.SKID_SHEET_STATUS,
         SHEET_SKID.SHEET_THEORETICAL_WT,
          NULL DONE
FROM CUSTOMER_ORDER,
         ORDER_ITEM,
         SHEET_SKID,
         --AB_JOB,
         SHIPMENT,
         SHEET_PACKING_ITEM
WHERE --(ORDER_ITEM.ORDER_ABC_NUM = CUSTOMER_ORDER.ORDER_ABC_NUM ) and
       --  (AB_JOB.ORDER_ABC_NUM = ORDER_ITEM.ORDER_ABC_NUM) and
       --  (AB_JOB.ORDER_ITEM_NUM = ORDER_ITEM.ORDER_ITEM_NUM) and
       --  (SHEET_SKID.AB_JOB_NUM = AB_JOB.AB_JOB_NUM) and
         (SHIPMENT.PACKING_LIST = al_packing_list ) and
         (SHIPMENT.PACKING_LIST =SHEET_PACKING_ITEM.PACKING_LIST) and
         (SHEET_PACKING_ITEM.SHEET_SKID_NUM = SHEET_SKID.SHEET_SKID_NUM) and
         (SHEET_SKID.REF_ORDER_ABC_ITEM = ORDER_ITEM.ORDER_ITEM_NUM and
         SHEET_SKID.REF_ORDER_ABC_NUM = ORDER_ITEM.ORDER_ABC_NUM) and
         (SHEET_SKID.REF_ORDER_ABC_NUM = customer_order.order_abc_num);
   --      (SHIPMENT.SHIPMENT_EDI856_DATE is NULL);


--Type skidinfo_tabletype IS table of alcoa_hayes_856_cur%ROWTYPE INDEX by binary_integer;
--skidinfo_table skidinfo_tabletype;
TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
 x12_table store_tabletype;
i binary_integer := 0;
skidinfo_rec alcoa_hayes_856_cur%rowtype;

begin


-- Get Customer ID, End user ID
SELECT customer_id, des_sh_cust_id
INTO li_customer_id, li_des_sh_cust_id FROM shipment
WHERE shipment.packing_list = al_packing_list;
IF NOT SQL%FOUND THEN  RETURN -1; END IF;


       IF NOT (li_customer_id IN (1188) and li_des_sh_cust_id in (45))THEN
            return 200;
       END IF;


       SELECT COUNT(*) INTO Shipment_Skid_Count
              FROM SHEET_PACKING_ITEM
                   WHERE PACKING_LIST  = al_packing_list;

       IF Shipment_Skid_Count = 0 THEN RETURN 100;
       END IF;



-- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
SELECT SUM(sheet_skid.sheet_net_wt),SUM(sheet_skid.sheet_net_wt)+SUM(sheet_skid.sheet_tare_wt), SUM(sheet_skid.skid_pieces)
INTO ll_shipment_nt,ll_shipment_gt, ll_shipment_pc FROM sheet_skid, sheet_packing_item, shipment
WHERE SHIPMENT.PACKING_LIST =SHEET_PACKING_ITEM.PACKING_LIST and
      SHEET_PACKING_ITEM.SHEET_SKID_NUM = SHEET_SKID.SHEET_SKID_NUM and
      SHIPMENT.PACKING_LIST = al_packing_list;
if ll_shipment_pc = 0 then return 100; end if;   -- empty shipment

-- Get gs, st and bsn log sequence number
SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;
SELECT edi_st_log_seq.NEXTVAL INTO ll_st_log FROM DUAL;
SELECT edi_bsn_log_seq.NEXTVAL INTO ll_bsn_log FROM DUAL;

-- Retrieve ABCO info
 -- ls_sender_vanid := '3010007080';
 --ls_ic := 'R0P7A';

-- Retrieve ALCAN supply code and Ford Stamping Plant location code
--SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf
--FROM customer_customer 	WHERE o_customer_id = li_customer_id and e_customer_id = 49;  --Ford customer_id =49

       ls_sf := '033253-02'; --Alcoa's supplier Code 107840
--SELECT NVL(communication_code,'UNKNOWN') INTO ls_st FROM customer_system
--WHERE customer_id = li_des_sh_cust_id;


-- Get Shipment Info.
SELECT shipment.bill_of_lading,
       NVL(shipment.vehicle_id,'9999'),
		   NVL(shipment.transportation_method_code,'Motor'),
		   NVL(shipment.carrier_description_code, 'PT'),  -- Protected Trailer
		   NVL(shipment.carrier_initial, 'NA'),
       NVL(shipment.shipment_actualed_date_time,SYSDATE)
INTO 	ll_bill_of_lading, ls_vehicle_id, ls_tran_method_code,
      ls_carrier_desc_code, ls_caarrier_initial, ldt_shipment
FROM  shipment WHERE shipment.packing_list = al_packing_list;

      SELECT NVL(CUSTOMER_DUNS_NUMBER_STRING, '00000000') INTO ls_st_duns
             FROM customer WHERE CUSTOMER_ID = li_des_sh_cust_id;

--     IF ( ls_st_duns = '00000000' ) then
--     return 200;
--     end if;    --No Ship to DUNS

--SELECT NVL(CUSTOMER_DUNS_NUMBER_STRING, '00000000') INTO ls_su
--FROM customer WHERE CUSTOMER_ID = li_customer_id;
--     IF ( ls_su = '00000000' ) then
--     return 200;
--     end if;    --No Supplier DUNS



-- Get SCAC(Standard Carrier Alpha Code)
SELECT NVL(carrier.scac, 'NONE') INTO ls_scac
FROM carrier WHERE carrier_id =(SELECT carrier_id  FROM shipment  WHERE shipment.packing_list = al_packing_list);

-- Get Resceiver and Customer VAN ID
-- SELECT NVL(customer_system.van_account_num, 'nothing'), NVL(customer_system.gs03, 'nothing')
-- INTO ls_receiver_vanid, ls_receiver_gs03    -- ls_receiver_vanid
-- FROM  customer_system WHERE customer_system.customer_id =
   --   (select shipment.des_sh_cust_id  from shipment  where shipment.packing_list = al_packing_list);

-- SELECT NVL(customer_system.van_account_num, 'nothing'),NVL(customer_system.gs03, 'nothing')
-- INTO 	ls_customer_vanid, ls_customer_gs03   -- ls_customer_vanid
-- FROM  customer_system WHERE customer_system.customer_id =
--       (select shipment.customer_id from shipment where shipment.packing_list = al_packing_list);


-- Generate Header Info.
--x12_table(i) := 'ISA*00*'||'          *00*          *ZZ*R0P7A          *ZZ*F159B          *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0') ||'*0*P**';
--x12_table(i) := 'GS*SH*R0P7A*'||ls_st || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';


               x12_table(i) := 'ISA*00*'||'          *00*          *01*039630926T     *01*089290118      *'||ls_today ||'*'|| ls_now ||'*U*00401*'||LPAD(to_char(ll_gs_log),9,'0')||'*0*P**';
               i := i + 1;

               x12_table(1) := 'GS*SH*039630926T*'||'089290118' || '*' || ls_today_4dy ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '004010';
               i := i + 1;
--                               'GS*SH*039630926T*089290118*20040323*1430*6187*X*004010'

x12_table(i):= 'ST*856*' || to_char(ll_st_log);
i := i +1;
x12_table(i):= 'BSN*00*' || to_char(al_packing_list) || '*' || ls_today_4dy || '*' || ls_now;
i := i +1;
x12_table(i):= 'DTM*011*' || to_char(ldt_shipment,'YYYYMMDD') || '*' || to_char(ldt_shipment,'HH24MI');
i := i +1;

-- First Level HL
x12_table(i) := 'HL*1**S'; i := i +1;
x12_table(i):= 'MEA*PD*G*' || to_char(ll_shipment_gt) || '*LB'; i := i +1;
x12_table(i):= 'MEA*PD*T*' || to_char(ll_shipment_gt - ll_shipment_nt) || '*LB'; i := i +1;
x12_table(i):= 'TD1*PLT71*' || to_char(Shipment_Skid_Count); i := i +1;
x12_table(i):= 'TD5*B*92*' || ls_scac ||'*M'; i := i +1;
x12_table(i):= 'TD3*' || ls_carrier_desc_code || '**' || ls_vehicle_id; i := i +1;
x12_table(i):= 'REF*BM*' ||  to_char(ll_bill_of_lading); i := i +1;
x12_table(i):= 'REF*PK*' || to_char(al_packing_list); i := i +1;

--x12_table(i):= 'DTM*017*' || to_char(ldt_shipment,'YYMMDD') || '*' || to_char(ldt_shipment,'HH24MI');
--i := i+1;
x12_table(i):= 'N1*ST**01*' || ls_st_duns; i := i +1;
x12_table(i):= 'N1*SF**92*' || ls_sf; i := i +1;
--x12_table(i):= 'N1*SU**1*' || ls_su; i := i +1;


-- Second Level HL based on End User PO( only one part# is included in one shipement per FORD's request)

   open alcoa_hayes_856_cur;
   fetch alcoa_hayes_856_cur INTO skidinfo_rec;
         --ls_enduser_part := skidinfo_rec.ENDUSER_PART_NUM;
         OrderAbcNum := skidinfo_rec.ORDER_ABC_NUM;
         OrderItemNum := skidinfo_rec.ORDER_ITEM_NUM;
   close alcoa_hayes_856_cur;

   SELECT SUM(sheet_skid.SHEET_NET_WT) into Cumulative FROM sheet_skid
          WHERE sheet_skid.ref_order_abc_num = OrderAbcNum  and
                sheet_skid.ref_order_abc_item = OrderItemNum and
                sheet_skid.skid_sheet_status = 0;

--    ls_enduser_po := skidinfo_rec.ENDUSER_PO;

/*
  if skidinfo_rec.ORIG_CUSTOMER_PO IN ('68Q68517') then    --Do NOT send 856 to Ford for some flipping related POs )
       edi_file_prefix := 'nosend_alcan_ford_ford';
  end if;
*/

  --SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"  into ls_enduser_part
  --         FROM "ORDER_ITEM",
  --              "SHEET_SKID"
  --              WHERE ( "SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM" ) and
  --              ( "SHEET_SKID"."REF_ORDER_ABC_ITEM" = "ORDER_ITEM"."ORDER_ITEM_NUM" )  and
  --              ( "SHEET_SKID"."SHEET_SKID_NUM" = skidinfo_rec.SHEET_SKID_NUM);

/*
    SELECT "CUSTOMER_ORDER"."ENDUSER_PO" into ls_enduser_po
           FROM "SHEET_SKID",
                "CUSTOMER_ORDER"
                WHERE ( "SHEET_SKID"."REF_ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM" ) and
                      (SHEET_SKID.SHEET_SKID_NUM = skidinfo_rec.SHEET_SKID_NUM);
*/



--  x12_table(i) :='HL*02*01*O'; i := i +1;
--  IF ls_enduser_part is NULL
--     then ls_enduser_part := 'NA';
--  end if;
--  x12_table(i) :='LIN**BP*'|| ls_enduser_part; i := i +1;
--  x12_table(i) :='SN1**' || to_char(ll_shipment_pc) ||'*EA*0'; i := i +1;



  --
  --ls_po := skidinfo_rec.ORIG_CUSTOMER_PO;
 -- SELECT "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO" into ls_po
  --         FROM "SHEET_SKID",
  --              "CUSTOMER_ORDER"
  --              WHERE ( "SHEET_SKID"."REF_ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM" ) and
  --                    (SHEET_SKID.SHEET_SKID_NUM = skidinfo_rec.SHEET_SKID_NUM);




  --IF INSTR(skidinfo_rec.ORIG_CUSTOMER_PO,'-') > 0
  --  IF INSTR(ls_po,'-') > 0
  --  THEN
  --     ls_po := substr(ls_po, 0, instr(ls_po,'-')-1);
  --  END IF;

--   IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
   --   x12_table(i) :='PRF*'|| ls_po || '***' || to_char(skidinfo_rec.CREATED_DATE,'YYMMDD');i:=i+1;
--   end if;

   --close alcoa_hayes_856_cur;

-- Third Level HL Under a P.O.

   li_HL01 := 2;

for skidinfo_rec IN alcoa_hayes_856_cur
loop
--    if length(to_char(li_HL01)) = 1  then
--       x12_table(i) := 'HL*0' || to_char(li_HL01) || '*1*I'; i := i +1;
--    else
--        x12_table(i) := 'HL*' || to_char(li_HL01) || '*1*I'; i := i +1;
--    end if;


    x12_table(i) := 'HL*' || to_char(li_HL01) || '*1*I'; i := i +1;
    x12_table(i) :='LIN**BP*'|| skidinfo_rec.ENDUSER_PART_NUM; i := i +1;
        x12_table(i) :=  'SN1**' || to_char(skidinfo_rec.SHEET_NET_WT)||'*LB*' || to_char(Cumulative + skidinfo_rec.SHEET_NET_WT); i := i +1;
        --x12_table(i) :='PRF*'|| skidinfo_rec.ENDUSER_PO || '***' || to_char(skidinfo_rec.CREATED_DATE,'YYYYMMDD');i:=i+1;
        x12_table(i) :='PRF*ALCOAINC***' || to_char(skidinfo_rec.CREATED_DATE,'YYYYMMDD');i:=i+1;

------------------ Testing
        --x12_table(i) := 'REF*SE*' || skidinfo_rec.SHEET_SKID_NUM ; i := i +1;
        --x12_table(i) := 'CLD*'||to_char(Shipment_Skid_Count)||'*'||to_char(skidinfo_rec.skid_pieces)||'***EA';
        --i := i + 1;
----------------- End Testing



--		x12_table(i) :=  'MEA*PD*N*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; i := i +1;
--		x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.skid_pieces) || '*PC'; i := i +1;
--    if (skidinfo_rec.SHEET_THEORETICAL_WT is null) or (skidinfo_rec.SHEET_THEORETICAL_WT = 0) then
--       x12_table(i) :=  'MEA*PD*G*' || to_char(ll_shipment_gt) || '*01'; i := i+1;
--    else
