 --   then
 --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

--  when others
--  then
 --      DBMS_OUTPUT.PUT_LINE ('System Error');
 --      UTL_FILE.FCLOSE(edi_file_handle);

return 1;
end edi_alcoa_hayes_856_x12;
  GRANT EXECUTE ON "DBO"."EDI_ALCOA_HAYES_856_X12" TO "AGERLANTS"
