--  DDL for Function EDI_ALERIS_856_X12
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_ALERIS_856_X12" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*
  Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
  Customer: Aleris(1980) DUNS:964790856     EDI ID:964790856      QUALIFIER: ZZ

  End User: Aleris, Customer ID 1980

  */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc         VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR');

  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_prefix VARCHAR2(50) := 'S_aleris_856_'; --Change s to S before sending
  edi_file_handle utl_file.file_type;

  li_customer_id    shipment.customer_id%TYPE;
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;

  ls_sf          VARCHAR2(50):= '039630926T';
  ls_su          VARCHAR2(50);
  ls_st_duns     VARCHAR2(50);
  ls_po          VARCHAR2(30);
  ls_enduser_po  customer_order.enduser_po%TYPE;
  ls_sales_order customer_order.sales_order%TYPE;
  ls_auth_code   VARCHAR2(32);
  ll_gs_log      INTEGER;
  ll_st_log      INTEGER;
  ll_bsn_log     INTEGER;
  ls_heat        coil.lot_num%TYPE;
  ls_coil_org_num  coil.coil_org_num%TYPE;

  ls_today VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  ls_now   VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');
  ls_today1 VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD');


  li_rowcount INTEGER;
  li_hl01     INTEGER;
  --li_hl02        INTEGER;
  ll_shipment_nt INTEGER;
  ll_shipment_gt INTEGER;
  ll_shipment_pc INTEGER;
  li_td1         INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_scac              carrier.scac%TYPE;
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_caarrier_initial  VARCHAR2(50);
  ldt_shipment         DATE;

  ls_enduser_part VARCHAR2(50);
  -- li_des_id       INTEGER;

  ll_edi_file_id INTEGER;

  -- ls_lot_num        VARCHAR2(32);
  -- ls_coil_id        VARCHAR2(32);
  ln_width          rectangle.rt_width%TYPE;
  ln_length         rectangle.rt_length%TYPE;
  ln_coil_thickness coil.coil_gauge%TYPE;

  ll_ref_order_abc_num  sheet_skid.ref_order_abc_num%TYPE;
  ll_ref_order_abc_item sheet_skid.ref_order_abc_item%TYPE;
  ls_sheet_type         order_item.sheet_type%TYPE;

  CURSOR aleris_856_cur IS
    SELECT sheet_packing_item.sh_packing_item,
           'MULTIPLE' lot_num,
           'MULTIPLE' coil_id,
           customer_order.orig_customer_po,
           customer_order.order_abc_num,
           customer_order.enduser_po,
           customer_order.created_date,
           order_item.order_item_num,
           order_item.enduser_part_num,
           order_item.supplier_code,
           order_item.gauge,
           sheet_skid. ab_job_num,
           sheet_skid.sheet_skid_num,
           sheet_skid.sheet_net_wt,
           sheet_skid.sheet_tare_wt,
           sheet_skid. skid_pieces,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_theoretical_wt,
           NULL done
      FROM customer_order,
           order_item,
           sheet_skid,
           ab_job,
           shipment,
           sheet_packing_item
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table    store_tabletype;
  i            BINARY_INTEGER := 0;
  skidinfo_rec aleris_856_cur%ROWTYPE;

BEGIN

  -- Get Customer ID, End user ID
  SELECT customer_id, des_sh_cust_id, nvl(shipment_athorization_code, 'NA')
    INTO li_customer_id, li_des_sh_cust_id, ls_auth_code
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;
  IF NOT SQL%FOUND THEN
    RETURN - 1;
  END IF;

  IF NOT (li_customer_id IN (1980)) -- AND (li_des_sh_cust_id IN ()))
   THEN
    RETURN 200;
  END IF;

  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(sheet_skid.sheet_net_wt),
         SUM(sheet_skid.sheet_net_wt) + SUM(sheet_skid.sheet_tare_wt),
         SUM(sheet_skid.skid_pieces)
    INTO ll_shipment_nt, ll_shipment_gt, ll_shipment_pc
    FROM sheet_skid, sheet_packing_item, shipment
   WHERE shipment.packing_list = sheet_packing_item.packing_list
     AND sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
     AND shipment.packing_list = al_packing_list;
  IF ll_shipment_pc = 0 THEN
    RETURN 100;
  END IF; -- empty shipment

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'PT'), -- Protected Trailer
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE)
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_caarrier_initial,
         ldt_shipment
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;

   ls_st_duns := '00000000';
    SELECT nvl(max(edi_code),'00000000')
    INTO ls_st_duns
    FROM customer_customer_edi_code
    WHERE from_customer_id = li_customer_id AND to_customer_id = li_des_sh_cust_id;

  IF (ls_st_duns = '00000000') THEN
    SELECT nvl(customer_duns_number_string, '00000000')
           INTO ls_st_duns
           FROM customer
            WHERE customer_id = li_des_sh_cust_id;
   END IF;

  IF (ls_st_duns = '00000000') THEN
    RETURN 200;
  END IF; --No Ship to DUNS

  SELECT nvl(customer_duns_number_string, '00000000')
    INTO ls_su
    FROM customer
   WHERE customer_id = li_customer_id;
  IF (ls_su = '00000000') THEN
    RETURN 200;
  END IF; --No Supplier DUNS

  -- Get SCAC(Standard Carrier Alpha Code)
  SELECT nvl(carrier.scac, 'NONE')
    INTO ls_scac
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);

  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *01*039630926T     *ZZ*964790856      *' ||
                  ls_today || '*' || ls_now || '*U*00200*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*P*>'; -- change T to P before sending
  i := i + 1;

  x12_table(1) := 'GS*SH*039630926T*' || '964790856' || '*' || ls_today || '*' ||
                  ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'BSN*00*' || to_char(al_packing_list) || '*' || ls_today || '*' ||
                  ls_now;
  i := i + 1;
  x12_table(i) := 'DTM*011*' || ls_today || '*' || ls_now;
  i := i + 1;

  -- First Level HL
  x12_table(i) := 'HL*01**S';
  i := i + 1;
  x12_table(i) := 'TD1*COL52*1****G*' || to_char(ll_shipment_gt) || '*LB';
  i := i + 1;
  x12_table(i) := 'TD1*COL52*1****N*' || to_char(ll_shipment_nt) || '*LB';
  i := i + 1;
  x12_table(i) := 'TD1*PLT90*' || to_char(li_rowcount);
  li_td1 := i;
  i := i + 1;
  x12_table(i) := 'TD5*B*02*' || ls_scac || '*M';
  i := i + 1;
  x12_table(i) := 'TD3*' || ls_carrier_desc_code || '**' || ls_vehicle_id;
  i := i + 1;
  x12_table(i) := 'REF*BM*' || to_char(al_packing_list);
  i := i + 1;

  x12_table(i) := 'N1*ST**1*' || ls_st_duns;
  i := i + 1;
  x12_table(i) := 'N1*SF**1*' || ls_sf;
  i := i + 1;
  x12_table(i) := 'N1*MF**1*' || ls_su;
  i := i + 1;

  OPEN aleris_856_cur;
  FETCH aleris_856_cur
    INTO skidinfo_rec;

  SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
    INTO ls_enduser_part
    FROM "ORDER_ITEM", "SHEET_SKID"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
     AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
     AND ("SHEET_SKID"."SHEET_SKID_NUM" = skidinfo_rec.sheet_skid_num);

  x12_table(i) := 'HL*02*01*O';
  i := i + 1;
  IF ls_enduser_part IS NULL THEN
    ls_enduser_part := 'NULL';
  END IF;

  SELECT "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO",
         "CUSTOMER_ORDER"."ENDUSER_PO",
         "CUSTOMER_ORDER"."SALES_ORDER"
    INTO ls_po, ls_enduser_po, ls_sales_order
    FROM "SHEET_SKID", "CUSTOMER_ORDER"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
         "CUSTOMER_ORDER"."ORDER_ABC_NUM")
     AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num);

      --james 04-01-14 - first skid's first coil's heat and coil id
     SELECT coil.coil_org_num,
           coil.lot_num
     INTO ls_coil_org_num, ls_heat
      FROM sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil,
           shipment,
           sheet_packing_item
      WHERE  (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       AND (sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num)
       AND (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list)
       AND (sheet_packing_item.sh_packing_item = 1)
       AND rownum = 1;

       x12_table(i) := 'LIN**VO*' || ls_enduser_po || '*HN*' || ls_heat ||'*VN*' ||
                ls_enduser_part  || '*SN*' || ls_coil_org_num;
       i := i + 1;

       x12_table(i) := 'PRF*' || ls_enduser_po || '***' || ls_today1;
       i := i + 1;

    --james 04-01-14 -end

  --x12_table(i) := 'LIN**VO*' || ls_enduser_po || '*HN**VN*' ||
  --               ls_enduser_part; --SalesOrder, Lot/Heat#
  --i := i + 1;

  x12_table(i) := 'REF*PO*' || ls_enduser_po;
  i := i + 1;
  x12_table(i) := 'REF*PM*' || ls_enduser_part;
  i := i + 1;

  CLOSE aleris_856_cur;

  -- Third Level HL Under a P.O.
  li_hl01 := 3;

  FOR skidinfo_rec IN aleris_856_cur LOOP
    IF length(to_char(li_hl01)) = 1 THEN
      x12_table(i) := 'HL*0' || to_char(li_hl01) || '*02*I';
      i := i + 1;
    ELSE
      x12_table(i) := 'HL*' || to_char(li_hl01) || '*02*I';
      i := i + 1;
    END IF;

    --james 03-14-14 - skid's first heat and coil ID
     SELECT coil.coil_org_num,
           coil.lot_num
     INTO ls_coil_org_num, ls_heat
      FROM sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil
      WHERE  (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       AND (sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num)
       AND (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num)
       AND rownum = 1;

    x12_table(i) := 'REF**SN*' || ls_coil_org_num || '*HN*' || ls_heat;
    i := i + 1;

    --james 03-14-14

    x12_table(i) := 'MEA*WT*WT*' || to_char(skidinfo_rec.sheet_net_wt) ||
                    '*01';
    i := i + 1;
    x12_table(i) := 'MEA*WT*WT*' ||
                    to_char(skidinfo_rec.sheet_net_wt * 0.4536) || '*50';
    i := i + 1;
    x12_table(i) := 'MEA*CT*NL*' || to_char(skidinfo_rec.skid_pieces) ||
                    '*PC';
    i := i + 1;

    SELECT MAX(coil_gauge)
      INTO ln_coil_thickness
      FROM coil
     WHERE coil.coil_abc_num IN
           (SELECT coil_abc_num
              FROM production_sheet_item
             WHERE production_sheet_item.prod_item_num IN
                   (SELECT prod_item_num
                      FROM sheet_skid_detail
                     WHERE sheet_skid_detail.sheet_skid_num =
                           skidinfo_rec.sheet_skid_num));

    x12_table(i) := 'MEA*PD*TH*' ||
                    TRIM(to_char(ln_coil_thickness, '99999.99')) || '*IN';
    i := i + 1;
    x12_table(i) := 'MEA*PD*TH*' ||
                    TRIM(to_char(ln_coil_thickness * 25.4, '99999.99')) ||
                    '*MM';
    i := i + 1;

    SELECT ss.ref_order_abc_num, ss.ref_order_abc_item
      INTO ll_ref_order_abc_num, ll_ref_order_abc_item
      FROM sheet_skid ss
     WHERE ss.sheet_skid_num = skidinfo_rec.sheet_skid_num;

    SELECT oi.sheet_type
      INTO ls_sheet_type
      FROM order_item oi
     WHERE oi.order_abc_num = ll_ref_order_abc_num
       AND oi.order_item_num = ll_ref_order_abc_item;

    CASE TRIM(upper(ls_sheet_type))
      WHEN 'RECTANGLE' THEN
        SELECT t.rt_length, t.rt_width
          INTO ln_length, ln_width
          FROM rectangle t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
      WHEN 'PARALLELOGRAM' THEN
        SELECT t.p_length, t.p_width
          INTO ln_length, ln_width
          FROM parallelogram t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
      WHEN 'FENDER' THEN
        SELECT t.fe_length, t.fe_side
          INTO ln_length, ln_width
          FROM fender t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
      WHEN 'CHEVRON' THEN
        SELECT t.ch_length, t.ch_width
          INTO ln_length, ln_width
          FROM chevron t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
      WHEN 'CIRCLE' THEN
        SELECT t.c_diameter, t.c_diameter
          INTO ln_length, ln_width
          FROM circle t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
      WHEN 'TRAPEZOID' THEN
        SELECT t.tr_long_length, t.tr_width
          INTO ln_length, ln_width
          FROM trapezoid t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
      WHEN 'L.TRAPEZOID' THEN
        SELECT t.ltr_long_length, t.ltr_width
          INTO ln_length, ln_width
          FROM left_trapezoid t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
      WHEN 'R.TRAPEZOID' THEN
        SELECT t.rtr_long_length, t.rtr_width
          INTO ln_length, ln_width
          FROM right_trapezoid t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
      WHEN 'REINFORCEMENT' THEN
        SELECT t.re_length, t.re_width
          INTO ln_length, ln_width
          FROM reinforcement t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
      WHEN 'LIFTGATE' THEN
        SELECT t.li_length, t.li_width
          INTO ln_length, ln_width
          FROM liftgate_shape t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
      ELSE
        SELECT t.x_1, t.x_2
          INTO ln_length, ln_width
          FROM x1_shape t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
    END CASE;

    x12_table(i) := 'MEA*PD*WD*' || TRIM(to_char(ln_width, '99999.99')) ||
                    '*IN';
    i := i + 1;
    x12_table(i) := 'MEA*PD*WD*' ||
                    TRIM(to_char(ln_width * 25.4, '99999.99')) || '*MM';
    i := i + 1;
    x12_table(i) := 'MEA*PD*LN*' ||
                    TRIM(to_char(ln_length * 0.0254, '99999.99')) || '*LM'; -- Linear Meter
    i := i + 1;
    x12_table(i) := 'MEA*PD*LN*' ||
                    TRIM(to_char(ln_length * 0.0833333, '99999.99')) ||
                    '*LF'; -- Linear Feet
    i := i + 1;

    x12_table(i) := 'REF*LS*' || skidinfo_rec.sheet_skid_num;
    i := i + 1;
    x12_table(i) := 'REF*SE*' || skidinfo_rec.sheet_skid_num;
    i := i + 1;
    li_hl01 := li_hl01 + 1;

    li_rowcount := aleris_856_cur%ROWCOUNT;
    x12_table(li_td1) := 'TD1*PLT90*' || to_char(li_rowcount);
  END LOOP;

  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                  to_char(li_rowcount + ll_shipment_pc);
  i := i + 1;

  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;

-- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
-- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));

  END LOOP;
  utl_file.fclose(edi_file_handle);

  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE,
         edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;
  COMMIT;

    --WILL ADD THE FOLLOWING CODE AFTER RECEIVE 997 FROM ALERIS
    INSERT INTO outbound_edi_transaction
      (edi_file_id,
       duns_from,
       duns_to,
       interchange_control_number,
       group_control_number,
       transaction_time,
       edi_file_name,
       fa_receive_status,
       customer_id,
       set_control_num,
       transaction_type_id)
    VALUES
      (ll_edi_file_id,
       '039630926',
       ls_su,
       ll_gs_log,
       ll_gs_log,
       SYSDATE,
       edi_file,
       0,
       li_customer_id,
       ll_st_log,
       '856');
    COMMIT;

  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  RETURN 1;
END edi_aleris_856_x12;
  GRANT EXECUTE ON "DBO"."EDI_ALERIS_856_X12" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function EDI_ALERIS_856_X12_MULTI_PO
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_ALERIS_856_X12_MULTI_PO" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*
  Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
  Customer: Aleris(1980) DUNS:964790856     EDI ID:964790856      QUALIFIER: ZZ

  End User: Aleris, Customer ID 1980

  */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc         VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR');

  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_prefix VARCHAR2(50) := 'S_aleris_856_'; --Change s to S before sending
  edi_file_handle utl_file.file_type;

  li_customer_id    shipment.customer_id%TYPE;
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;

  ls_sf          VARCHAR2(50) := '039630926T';
  ls_su          VARCHAR2(50);
  ls_st_duns     VARCHAR2(50);
  ls_po          VARCHAR2(30);
  ls_enduser_po  customer_order.enduser_po%TYPE;
  ls_sales_order customer_order.sales_order%TYPE;
  ls_auth_code   VARCHAR2(32);
  ll_gs_log      INTEGER;
  ll_st_log      INTEGER;
  ll_bsn_log     INTEGER;
  ls_heat        coil.lot_num%TYPE;
  ls_coil_org_num  coil.coil_org_num%TYPE;

  ls_today VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  ls_now   VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');
  ls_today1 VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD');


  li_rowcount INTEGER;
  li_hl01     INTEGER;
  li_hllin    INTEGER;

  --li_hl02        INTEGER;
  ll_shipment_nt INTEGER;
  ll_shipment_gt INTEGER;
  ll_shipment_pc INTEGER;
  li_td1         INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_scac              carrier.scac%TYPE;
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_caarrier_initial  VARCHAR2(50);
  ldt_shipment         DATE;

  ls_enduser_part VARCHAR2(50);
  -- li_des_id       INTEGER;

  ll_edi_file_id INTEGER;

  -- ls_lot_num        VARCHAR2(32);
  -- ls_coil_id        VARCHAR2(32);
  ln_width          rectangle.rt_width%TYPE;
  ln_length         rectangle.rt_length%TYPE;
  ln_coil_thickness coil.coil_gauge%TYPE;

  ll_ref_order_abc_num  sheet_skid.ref_order_abc_num%TYPE;
  ll_ref_order_abc_item sheet_skid.ref_order_abc_item%TYPE;
  ls_sheet_type         order_item.sheet_type%TYPE;

  CURSOR aleris_856_po_cur IS
    SELECT UNIQUE
           customer_order.enduser_po,
           order_item.enduser_part_num
      FROM customer_order,
           order_item,
           sheet_skid,
           ab_job,
           shipment,
           sheet_packing_item
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);

  CURSOR aleris_856_cur IS
    SELECT sheet_packing_item.sh_packing_item,
           'MULTIPLE' lot_num,
           'MULTIPLE' coil_id,
           customer_order.orig_customer_po,
           customer_order.order_abc_num,
           customer_order.enduser_po,
           customer_order.created_date,
           order_item.order_item_num,
           order_item.enduser_part_num,
           order_item.supplier_code,
           order_item.gauge,
           sheet_skid. ab_job_num,
           sheet_skid.sheet_skid_num,
           sheet_skid.sheet_net_wt,
           sheet_skid.sheet_tare_wt,
           sheet_skid. skid_pieces,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_theoretical_wt,
           NULL done
      FROM customer_order,
           order_item,
           sheet_skid,
           ab_job,
           shipment,
           sheet_packing_item
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table    store_tabletype;
  i            BINARY_INTEGER := 0;
  skidinfo_rec aleris_856_cur%ROWTYPE;
  poinfo_rec aleris_856_po_cur%ROWTYPE;

BEGIN

  -- Get Customer ID, End user ID
  SELECT customer_id, des_sh_cust_id, nvl(shipment_athorization_code, 'NA')
    INTO li_customer_id, li_des_sh_cust_id, ls_auth_code
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;
  IF NOT SQL%FOUND THEN
    RETURN - 1;
  END IF;

  IF NOT (li_customer_id IN (1980)) -- AND (li_des_sh_cust_id IN ()))
   THEN
    RETURN 200;
  END IF;

  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(sheet_skid.sheet_net_wt),
         SUM(sheet_skid.sheet_net_wt) + SUM(sheet_skid.sheet_tare_wt),
         SUM(sheet_skid.skid_pieces)
    INTO ll_shipment_nt, ll_shipment_gt, ll_shipment_pc
    FROM sheet_skid, sheet_packing_item, shipment
   WHERE shipment.packing_list = sheet_packing_item.packing_list
     AND sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
     AND shipment.packing_list = al_packing_list;
  IF ll_shipment_pc = 0 THEN
    RETURN 100;
  END IF; -- empty shipment

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'PT'), -- Protected Trailer
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE)
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_caarrier_initial,
         ldt_shipment
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;

   ls_st_duns := '00000000';
    SELECT nvl(max(edi_code),'00000000')
    INTO ls_st_duns
    FROM customer_customer_edi_code
    WHERE from_customer_id = li_customer_id AND to_customer_id = li_des_sh_cust_id;

  IF (ls_st_duns = '00000000') THEN
    SELECT nvl(customer_duns_number_string, '00000000')
           INTO ls_st_duns
           FROM customer
            WHERE customer_id = li_des_sh_cust_id;
   END IF;

  IF (ls_st_duns = '00000000') THEN
    RETURN 200;
  END IF; --No Ship to DUNS

  SELECT nvl(customer_duns_number_string, '00000000')
    INTO ls_su
    FROM customer
   WHERE customer_id = li_customer_id;
  IF (ls_su = '00000000') THEN
    RETURN 200;
  END IF; --No Supplier DUNS

  -- Get SCAC(Standard Carrier Alpha Code)
  SELECT nvl(carrier.scac, 'NONE')
    INTO ls_scac
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);


  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *01*039630926T     *ZZ*964790856      *' ||
                  ls_today || '*' || ls_now || '*U*00200*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*P*>'; -- change T to P before sending
  i := i + 1;

  x12_table(1) := 'GS*SH*039630926T*' || '964790856' || '*' || ls_today || '*' ||
                  ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'BSN*00*' || to_char(al_packing_list) || '*' || ls_today || '*' ||
                  ls_now;
  i := i + 1;
  x12_table(i) := 'DTM*011*' || ls_today || '*' || ls_now;
  i := i + 1;

  -- First Level HL
  x12_table(i) := 'HL*01**S';
  i := i + 1;
  x12_table(i) := 'TD1*COL52*1****G*' || to_char(ll_shipment_gt) || '*LB';
  i := i + 1;
  x12_table(i) := 'TD1*COL52*1****N*' || to_char(ll_shipment_nt) || '*LB';
  i := i + 1;
  x12_table(i) := 'TD1*PLT90*' || to_char(li_rowcount);
  li_td1 := i;
  i := i + 1;
  x12_table(i) := 'TD5*B*02*' || ls_scac || '*M';
  i := i + 1;
  x12_table(i) := 'TD3*' || ls_carrier_desc_code || '**' || ls_vehicle_id;
  i := i + 1;
  x12_table(i) := 'REF*BM*' || to_char(al_packing_list);
  i := i + 1;

  x12_table(i) := 'N1*ST**1*' || ls_st_duns;
  i := i + 1;
  x12_table(i) := 'N1*SF**1*' || ls_sf;
  i := i + 1;
  x12_table(i) := 'N1*MF**1*' || ls_su;
  i := i + 1;

  li_hl01 := 1;


 -- retrieve PO list
   OPEN aleris_856_po_cur;
  FETCH aleris_856_po_cur
    INTO poinfo_rec;

   CLOSE aleris_856_po_cur;

 --start retrieve skid based on PO
   FOR poinfo_rec IN aleris_856_po_cur LOOP  -- loop 1

       li_hl01 := li_hl01 + 1;

       x12_table(i) := 'HL*' || to_char(li_hl01) || '*01*O';
       i := i + 1;

      SELECT coil.coil_org_num,
           coil.lot_num
     INTO ls_coil_org_num, ls_heat
      FROM sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil,
           shipment,
           sheet_packing_item
      WHERE  (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       AND (sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num)
       AND (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list)
       AND (sheet_packing_item.sh_packing_item = 1)
       AND rownum = 1;

       SELECT "COIL"."COIL_ORG_NUM"
       INTO ls_coil_org_num
        FROM "SHIPMENT",
         "SHEET_PACKING_ITEM",
         "SHEET_SKID",
         "SHEET_SKID_DETAIL",
         "PRODUCTION_SHEET_ITEM",
         "COIL",
         "AB_JOB",
         "CUSTOMER_ORDER",
         "ORDER_ITEM"
           WHERE ( "SHEET_PACKING_ITEM"."PACKING_LIST" = "SHIPMENT"."PACKING_LIST" ) and
         ( "SHEET_SKID"."SHEET_SKID_NUM" = "SHEET_PACKING_ITEM"."SHEET_SKID_NUM" ) and
         ( "SHEET_SKID_DETAIL"."SHEET_SKID_NUM" = "SHEET_SKID"."SHEET_SKID_NUM" ) and
         ( "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NUM" = "SHEET_SKID_DETAIL"."PROD_ITEM_NUM" ) and
         ( "PRODUCTION_SHEET_ITEM"."COIL_ABC_NUM" = "COIL"."COIL_ABC_NUM" ) and
         ( "AB_JOB"."AB_JOB_NUM" = "PRODUCTION_SHEET_ITEM"."AB_JOB_NUM" ) and
         ( "AB_JOB"."ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM" ) and
         ( "ORDER_ITEM"."ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM" ) and
         ( "ORDER_ITEM"."ORDER_ITEM_NUM" = "AB_JOB"."ORDER_ITEM_NUM" ) and
         ( "ORDER_ITEM"."ORDER_ABC_NUM" = "AB_JOB"."ORDER_ABC_NUM" ) and
         ( "SHIPMENT"."PACKING_LIST" = al_packing_list ) and
         ("ORDER_ITEM"."ENDUSER_PART_NUM" = poinfo_rec.enduser_part_num) and
         ("CUSTOMER_ORDER"."ENDUSER_PO" = poinfo_rec.enduser_po) and
         rownum = 1;

       x12_table(i) := 'LIN**VO*' || poinfo_rec.enduser_po || '*HN*' || ls_heat ||'*VN*' ||
                poinfo_rec.enduser_part_num  || '*SN*' || ls_coil_org_num;
       i := i + 1;
       li_hllin := li_hl01;

       x12_table(i) := 'PRF*' || poinfo_rec.enduser_po || '***' || ls_today1;
       i := i + 1;


       x12_table(i) := 'REF*PO*' || poinfo_rec.enduser_po;
        i := i + 1;
        x12_table(i) := 'REF*PM*' || poinfo_rec.enduser_part_num;
         i := i + 1;

           OPEN aleris_856_cur;
             FETCH aleris_856_cur
             INTO skidinfo_rec;

             CLOSE aleris_856_cur;

  FOR skidinfo_rec IN aleris_856_cur LOOP  -- loop 2

     SELECT "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO",
         "CUSTOMER_ORDER"."ENDUSER_PO",
         "CUSTOMER_ORDER"."SALES_ORDER"
    INTO ls_po, ls_enduser_po, ls_sales_order
    FROM "SHEET_SKID", "CUSTOMER_ORDER"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
         "CUSTOMER_ORDER"."ORDER_ABC_NUM")
     AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num);

    SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
    INTO ls_enduser_part
    FROM "ORDER_ITEM", "SHEET_SKID"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
     AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
     AND ("SHEET_SKID"."SHEET_SKID_NUM" = skidinfo_rec.sheet_skid_num);

      --james 04-01-14 - first skid's first coil's heat and coil id
  IF (poinfo_rec.enduser_po = ls_enduser_po) AND (poinfo_rec.enduser_part_num = ls_enduser_part) THEN


    li_hl01 := li_hl01 + 1;

    IF length(to_char(li_hl01)) = 1 THEN
      x12_table(i) := 'HL*0' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*I';
      i := i + 1;
    ELSE
      x12_table(i) := 'HL*' || to_char(li_hl01) ||'*' || to_char(li_hllin) || '*I';
      i := i + 1;
    END IF;

    --james 03-14-14 - skid's first heat and coil ID
     SELECT coil.coil_org_num,
           coil.lot_num
     INTO ls_coil_org_num, ls_heat
      FROM sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil
      WHERE  (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       AND (sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num)
       AND (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num)
       AND rownum = 1;

    x12_table(i) := 'REF**SN*' || ls_coil_org_num || '*HN*' || ls_heat;
    i := i + 1;

    --james 03-14-14

    x12_table(i) := 'MEA*WT*WT*' || to_char(skidinfo_rec.sheet_net_wt) ||
                    '*01';
    i := i + 1;
    x12_table(i) := 'MEA*WT*WT*' ||
                    to_char(skidinfo_rec.sheet_net_wt * 0.4536) || '*50';
    i := i + 1;
    x12_table(i) := 'MEA*CT*NL*' || to_char(skidinfo_rec.skid_pieces) ||
                    '*PC';
    i := i + 1;

    SELECT MAX(coil_gauge)
      INTO ln_coil_thickness
      FROM coil
     WHERE coil.coil_abc_num IN
           (SELECT coil_abc_num
              FROM production_sheet_item
             WHERE production_sheet_item.prod_item_num IN
                   (SELECT prod_item_num
                      FROM sheet_skid_detail
                     WHERE sheet_skid_detail.sheet_skid_num =
                           skidinfo_rec.sheet_skid_num));

    x12_table(i) := 'MEA*PD*TH*' ||
                    TRIM(to_char(ln_coil_thickness, '99999.99')) || '*IN';
    i := i + 1;
    x12_table(i) := 'MEA*PD*TH*' ||
                    TRIM(to_char(ln_coil_thickness * 25.4, '99999.99')) ||
                    '*MM';
    i := i + 1;

    SELECT ss.ref_order_abc_num, ss.ref_order_abc_item
      INTO ll_ref_order_abc_num, ll_ref_order_abc_item
      FROM sheet_skid ss
     WHERE ss.sheet_skid_num = skidinfo_rec.sheet_skid_num;

    SELECT oi.sheet_type
      INTO ls_sheet_type
      FROM order_item oi
     WHERE oi.order_abc_num = ll_ref_order_abc_num
       AND oi.order_item_num = ll_ref_order_abc_item;

    CASE TRIM(upper(ls_sheet_type))
      WHEN 'RECTANGLE' THEN
        SELECT t.rt_length, t.rt_width
          INTO ln_length, ln_width
          FROM rectangle t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
      WHEN 'PARALLELOGRAM' THEN
        SELECT t.p_length, t.p_width
          INTO ln_length, ln_width
          FROM parallelogram t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
      WHEN 'FENDER' THEN
        SELECT t.fe_length, t.fe_side
          INTO ln_length, ln_width
          FROM fender t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
      WHEN 'CHEVRON' THEN
        SELECT t.ch_length, t.ch_width
          INTO ln_length, ln_width
          FROM chevron t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
      WHEN 'CIRCLE' THEN
        SELECT t.c_diameter, t.c_diameter
          INTO ln_length, ln_width
          FROM circle t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
      WHEN 'TRAPEZOID' THEN
        SELECT t.tr_long_length, t.tr_width
          INTO ln_length, ln_width
          FROM trapezoid t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
      WHEN 'L.TRAPEZOID' THEN
        SELECT t.ltr_long_length, t.ltr_width
          INTO ln_length, ln_width
          FROM left_trapezoid t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
      WHEN 'R.TRAPEZOID' THEN
        SELECT t.rtr_long_length, t.rtr_width
          INTO ln_length, ln_width
          FROM right_trapezoid t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
      WHEN 'REINFORCEMENT' THEN
        SELECT t.re_length, t.re_width
          INTO ln_length, ln_width
          FROM reinforcement t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
      WHEN 'LIFTGATE' THEN
        SELECT t.li_length, t.li_width
          INTO ln_length, ln_width
          FROM liftgate_shape t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
      ELSE
        SELECT t.x_1, t.x_2
          INTO ln_length, ln_width
          FROM x1_shape t
         WHERE t.order_abc_num = ll_ref_order_abc_num
           AND t.order_item_num = ll_ref_order_abc_item;
    END CASE;

    x12_table(i) := 'MEA*PD*WD*' || TRIM(to_char(ln_width, '99999.99')) ||
                    '*IN';
    i := i + 1;
    x12_table(i) := 'MEA*PD*WD*' ||
                    TRIM(to_char(ln_width * 25.4, '99999.99')) || '*MM';
    i := i + 1;
    x12_table(i) := 'MEA*PD*LN*' ||
                    TRIM(to_char(ln_length * 0.0254, '99999.99')) || '*LM'; -- Linear Meter
    i := i + 1;
    x12_table(i) := 'MEA*PD*LN*' ||
                    TRIM(to_char(ln_length * 0.0833333, '99999.99')) ||
                    '*LF'; -- Linear Feet
    i := i + 1;

    x12_table(i) := 'REF*LS*' || skidinfo_rec.sheet_skid_num;
    i := i + 1;
    x12_table(i) := 'REF*SE*' || skidinfo_rec.sheet_skid_num;
    i := i + 1;

    li_rowcount := aleris_856_cur%ROWCOUNT;
    x12_table(li_td1) := 'TD1*PLT90*' || to_char(li_rowcount);
  END IF;
  END LOOP; -- loop 2
  END LOOP; -- Loop 1

  x12_table(i) := 'CTT*' || to_char(li_hl01) || '*' ||
                  to_char(li_rowcount + ll_shipment_pc);
  i := i + 1;

  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;

-- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
-- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));

  END LOOP;
  utl_file.fclose(edi_file_handle);

  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE,
         edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;
--   COMMIT;

    --WILL ADD THE FOLLOWING CODE AFTER RECEIVE 997 FROM ALERIS
    INSERT INTO outbound_edi_transaction
      (edi_file_id,
       duns_from,
       duns_to,
       interchange_control_number,
       group_control_number,
       transaction_time,
       edi_file_name,
       fa_receive_status,
       customer_id,
       set_control_num,
       transaction_type_id)
    VALUES
      (ll_edi_file_id,
       '964790856',
       ls_su,
       ll_gs_log,
       ll_gs_log,
       SYSDATE,
       edi_file,
       0,
       li_customer_id,
       ll_st_log,
       '856');
    COMMIT;

  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  RETURN 1;
END edi_aleris_856_x12_multi_po;
  GRANT EXECUTE ON "DBO"."EDI_ALERIS_856_X12_MULTI_PO" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function EDI_ARCONIC_856_X12
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_ARCONIC_856_X12" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*
  Aluminum Blanking: Ford Supplier Code: ZZ R0P7A
                     DUNS: 01 039630926T
  Customer: Arconic-TN (2784)
*/
   --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50);

  --edi_loc varchar2(50):='/tmp';
  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_prefix VARCHAR2(50) := 'S_arconic_856_'; --Production
  --edi_file_prefix VARCHAR2(50) := 's_arconic_856_'; --Development
  edi_file_handle utl_file.file_type;

  li_customer_id    shipment.customer_id%TYPE;
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;

  -- ls_sender_vanid varchar2 (50);
  -- ls_receiver_vanid varchar2 (50);
  -- ls_customer_vanid varchar2(50);
  -- ls_receiver_gs03 varchar2(50);
  -- ls_customer_gs03 varchar2(50);
  --ls_st varchar2(50);
  ls_sf VARCHAR2(50);
  ls_eq_type VARCHAR2(10);  -- Added by Patrick Reynolds 11/30/2016
  ls_su      VARCHAR2(50);
  ls_st_duns VARCHAR2(50);
  ls_po      VARCHAR2(30);
  ls_auth_code   VARCHAR2(32);
  ll_gs_log  INTEGER;
  ll_st_log  INTEGER;
  ll_bsn_log INTEGER;

  ls_today VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD'); --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  ls_today_2digits_year VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD'); --Alex Gerlants. 10/16/2018. Test
  ls_now   VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  li_rowcount INTEGER;
  li_hl01 INTEGER;
  ll_shipment_nt INTEGER;
  ll_shipment_gt INTEGER;
  ll_shipment_pc INTEGER;
  li_td1 INTEGER;
  li_rc  INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_vehicle_id_prefix VARCHAR2(50);  -- Added by Patrick Reynolds 11/30/2016
  ls_scac              carrier.scac%TYPE;
  ls_carrier_full_name VARCHAR2(18);
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_carrier_initial   VARCHAR2(50);  -- Not used in stored procedure.  Discovered by Patrick Reynolds 11/30/2016
  ldt_shipment         DATE;
   ll_temp         INTEGER;
  ls_enduser_part VARCHAR2(50);
  li_des_id       INTEGER;

  ll_edi_file_id INTEGER;

  ls_lot_num VARCHAR2(32);
  ls_coil_id VARCHAR2(32);
  ls_des_cust_name VARCHAR2(18);
  
  ls_coil_org_num		        coil.coil_org_num%TYPE; --Alex Gerlants. 01/25/2019
  ll_coil_gauge		          coil.coil_gauge%TYPE;   --Alex Gerlants. 01/25/2019
  ll_coil_width		          coil.coil_width%TYPE;   --Alex Gerlants. 01/25/2019
  ld_ship_date              date;
  li_is_novelis             integer;
  ln_skid_type_if_whed      sheet_skid.skid_type_if_whed%TYPE;   --Alex Gerlants. 04/01/2019
  scrap_item                integer;

  CURSOR arconic_856_cur IS
    SELECT sheet_packing_item.sh_packing_item,
           'MULTIPLE' lot_num,
           'MULTIPLE' coil_id,
           customer_order.orig_customer_po,
           customer_order.order_abc_num,
           customer_order.enduser_po,
           customer_order.created_date,
           order_item.order_item_num,
           order_item.enduser_part_num,
           order_item.supplier_code,
           order_item.gauge,
           sheet_skid. ab_job_num,
           sheet_skid.sheet_skid_num,
           sheet_skid.sheet_skid_display_num, --added by Victor H. on 06-2012 for Novelis locatio code request
           sheet_skid.sheet_net_wt,
           sheet_skid.sheet_tare_wt,
           sheet_skid. skid_pieces,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_theoretical_wt,
           NULL done
      FROM customer_order,
           order_item,
           sheet_skid,
           ab_job,
           shipment,
           sheet_packing_item
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
/*      
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
  --      (SHIPMENT.SHIPMENT_EDI856_DATE is NULL);
*/
  --TYPE skidinfo_tabletype IS TABLE OF arconic_856_cur%ROWTYPE INDEX BY BINARY_INTEGER;
  --skidinfo_table skidinfo_tabletype;
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table    store_tabletype;
  i            BINARY_INTEGER := 0;
  skidinfo_rec arconic_856_cur%ROWTYPE;

  /*CURSOR packing_list_same_bol IS
  SELECT packing_list
    FROM shipment
   WHERE bill_of_lading = ll_bill_of_lading;*/

  CURSOR c_ship_to IS
    SELECT DISTINCT des_sh_cust_id --, PACKING_LIST
      FROM shipment
     WHERE bill_of_lading = ll_bill_of_lading
       AND shipment.shipment_status = 0;
  --ORDER BY PACKING_LIST;
  
  cursor c_coil is
  select distinct 
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num,
         coil.coil_gauge,
         coil.coil_width
         --process_coil.coil_abc_num
         --outbound_edi_transaction.transaction_time,
         --outbound_edi_transaction.edi_file_name
  from   customer_order
         join order_item on order_item.order_abc_num = customer_order.order_abc_num
         join ab_job on ab_job.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
         join sheet_skid on sheet_skid.ab_job_num = ab_job.ab_job_num
         join sheet_packing_item on sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
         join shipment on shipment.packing_list = sheet_packing_item.packing_list
         join process_coil on process_coil.ab_job_num = ab_job.ab_job_num
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         --join outbound_edi_transaction on outbound_edi_transaction.edi_file_id = shipment.edi_file_id_856
  --where  shipment.packing_list = 105586 --Production
  where  shipment.packing_list = al_packing_list 
  order by
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num;

BEGIN
  
  -- Get Customer ID, End user ID, authorization code
  select   customer_id, des_sh_cust_id, nvl(shipment_athorization_code, 'NA')
  into     li_customer_id, li_des_sh_cust_id, ls_auth_code
  from     shipment
  where    shipment.packing_list = al_packing_list;
  
  if not SQL%FOUND then
    return - 1;
  end if;
  
  if not li_customer_id = 2784 then --Arconic TN only
    return 200;
  end if;
  
  select shipment_edi856_date
  into   ld_ship_date
  from   shipment
  where  shipment.packing_list = al_packing_list;
   
  if not (ld_ship_date is null) then --ASN already sent
    return 100;
  end if;
  
  select max(sc_packing_item)
  into   scrap_item
  from   scrap_packing_item
  where  packing_list = al_packing_list;  
  
  if scrap_item > 0 then
    return 1;
  end if;
  
  select count(*)
  into   li_rowcount
  from   reject_coil_packing_item
         join coil on coil.coil_abc_num = reject_coil_packing_item.coil_abc_num
         join shipment on shipment.packing_list = reject_coil_packing_item.packing_list
         join customer on customer.customer_id = shipment.customer_id
  where  shipment.packing_list = al_packing_list;
  
  if li_rowcount > 0 then
    return 1;
  end if;

  edi_loc := dbo.get_edi_destination('EDI_DIR');



  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(sheet_skid.sheet_net_wt),
         SUM(sheet_skid.sheet_net_wt) + SUM(sheet_skid.sheet_tare_wt),
         SUM(sheet_skid.skid_pieces)
    INTO ll_shipment_nt, ll_shipment_gt, ll_shipment_pc
    FROM sheet_skid, sheet_packing_item, shipment
   WHERE shipment.packing_list = sheet_packing_item.packing_list
     AND sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
     AND shipment.packing_list = al_packing_list;
     
  IF ll_shipment_pc = 0 THEN
    RETURN 2; --Nothing to do here
  END IF;

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  ls_sf := '039630926';

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.vehicle_id_prefix, '9999'),
         nvl(shipment.equipment_type, 'NA'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'PT'), -- Protected Trailer
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE)
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_vehicle_id_prefix,
         ls_eq_type,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_carrier_initial,
         ldt_shipment
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;

  SELECT nvl(customer_duns_number_string, '00000000'), customer_short_name
    INTO ls_st_duns, ls_des_cust_name
    FROM customer
   WHERE customer_id = li_des_sh_cust_id;

  IF (ls_st_duns = '00000000') THEN
    ls_st_duns := '';
  END IF; --Arconic does not need destination DUNS

  SELECT nvl(customer_duns_number_string, '00000000')
    INTO ls_su
    FROM customer
   WHERE customer_id = li_customer_id;
  IF (ls_su = '00000000') THEN
    RETURN 200;
  END IF; --No Supplier DUNS

  -- Get SCAC(Standard Carrier Alpha Code)
  SELECT nvl(carrier.scac, 'NONE'), LPAD(carrier.carrier_full_name, 17)
    INTO ls_scac, ls_carrier_full_name
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);

  -- Generate Header Info.
  --Production
  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *01*039630926T     *01*961613887      *' ||
                  ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*P*>';
  
  --Development                
  --x12_table(i) := 'ISA*00*' ||
  --                '          *00*          *ZZ*2NDSFTP        *ZZ*ARNCQFMW       *' ||
  --                ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
  --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T*>';
                  
  i := i + 1;

  --Alex Gerlants. 10/16/2018. Changed from "002002" to "004010"
  --Production
  x12_table(1) := 'GS*SH*R0P7ATN*' || '961613887' || '*' || ls_today || '*' ||
                  ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  --Development
  --x12_table(1) := 'GS*SH*2NDSFTP' || 'TN*ARNCQFMW' || '*' || ls_today || '*' ||
  --               ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;

  x12_table(i) := 'BSN*00*' || to_char(al_packing_list) || '*' || ls_today || '*' ||
                  ls_now;
  i := i + 1;

  x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                                                      to_char(ldt_shipment, 'HH24MI');
  i := i + 1;
  
  x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                  to_char(ldt_shipment, 'HH24MI');
  i := i + 1;

  -- First Level HL
  x12_table(i) := 'HL*01**S';
  i := i + 1;

  x12_table(i) := 'MEA*WT*G*' || to_char(ll_shipment_gt) || '*LB';
  i := i + 1;
  x12_table(i) := 'MEA*WT*N*' || to_char(ll_shipment_nt) || '*LB';
  i := i + 1;
  x12_table(i) := 'TD1*PLT90*' || to_char(li_rowcount);
  li_td1 := i;
  i := i + 1;
  x12_table(i) := 'TD5*B*2*' || ls_scac || '*M*' || ls_carrier_full_name;
  i := i + 1;

  x12_table(i) := 'TD3*' || ls_carrier_desc_code || '*' || ls_scac || '*' || ls_vehicle_id_prefix;
  i := i + 1;
  x12_table(i) := 'REF*BM*' || to_char(al_packing_list);
  i := i + 1;
  x12_table(i) := 'REF*PK*' || to_char(al_packing_list);
  i := i + 1;

  x12_table(i) := 'REF*EQ*' || ls_eq_type;
  i := i + 1;

  x12_table(i) := 'REF*MB*' || to_char(ll_bill_of_lading);
  i := i + 1;
  SELECT COUNT(*)
    INTO ll_temp
    FROM shipment
   WHERE shipment.bill_of_lading = ll_bill_of_lading
     AND shipment.shipment_status = 0;

  li_des_id := 1;
  
  x12_table(i) := 'N1*ST*' || ls_des_cust_name || '*1*' || ls_st_duns;
  i := i + 1;
  x12_table(i) := 'N1*SF*Aluminum Blanking Co*1*' || ls_sf;
  i := i + 1;
  x12_table(i) := 'N1*SU**1*' || ls_su;
  i := i + 1;

  -- Second Level HL based on End User PO( only one part# is included in one shipement per FORD's request)
  OPEN arconic_856_cur;
  FETCH arconic_856_cur
    INTO skidinfo_rec;

  SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
    INTO ls_enduser_part
    FROM "ORDER_ITEM", "SHEET_SKID"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
     AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
     AND ("SHEET_SKID"."SHEET_SKID_NUM" = skidinfo_rec.sheet_skid_num);

  x12_table(i) := 'HL*02*01*O';
  i := i + 1;
  IF ls_enduser_part IS NULL THEN
    ls_enduser_part := 'NA';
  END IF;
  x12_table(i) := 'LIN**BP*' || ls_enduser_part;
  i := i + 1;
  x12_table(i) := 'SN1**' || to_char(ll_shipment_pc) || '*EA*0';
  i := i + 1;

  SELECT "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO"
    INTO ls_po
    FROM "SHEET_SKID", "CUSTOMER_ORDER"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
         "CUSTOMER_ORDER"."ORDER_ABC_NUM")
     AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num);

  x12_table(i) := 'PRF*' || ls_po || '***' ||
                  to_char(skidinfo_rec.created_date, 'YYYYMMDD');
  i := i + 1;
  --   end if;

  CLOSE arconic_856_cur;

   --  Novelis SAP order number
 x12_table(i) := 'REF*IL*' || ls_auth_code;
 i := i + 1;
  --  end if;

  -- Third Level HL Under a P.O.
  li_hl01 := 3;

  --Skid loop begin ----------------------------------------------------------------
  FOR skidinfo_rec IN arconic_856_cur LOOP
    
      --In case of a split skid, we are creating just 1 HL for this skid
      --with just 1 coil for this skid.
      select distinct 
             coil.coil_org_num,
             coil.coil_gauge,
             coil.coil_width,
             coil.lot_num,
             nvl(skid_type_if_whed, -1) --Alex Gerlants. 04/01/2019
      into   ls_coil_org_num,
             ll_coil_gauge,
             ll_coil_width,
             ls_lot_num,
             ln_skid_type_if_whed --Alex Gerlants. 04/01/2019
      FROM "COIL",   
           "PRODUCTION_SHEET_ITEM",   
           "SHEET_SKID",   
           "SHEET_SKID_DETAIL",   
           "PROCESS_COIL"  
     WHERE ( "COIL"."COIL_ABC_NUM" = "PRODUCTION_SHEET_ITEM"."COIL_ABC_NUM" ) and  
           ( "SHEET_SKID_DETAIL"."SHEET_SKID_NUM" = "SHEET_SKID"."SHEET_SKID_NUM" ) and  
           ( "SHEET_SKID_DETAIL"."PROD_ITEM_NUM" = "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NUM" ) and  
           ( "COIL"."COIL_ABC_NUM" = "PROCESS_COIL"."COIL_ABC_NUM" ) and  
           ( "PRODUCTION_SHEET_ITEM"."AB_JOB_NUM" = "PROCESS_COIL"."AB_JOB_NUM" ) and  
           ( (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num)  ) and
           ( (rownum = 1)  ); --We need just 1 coil for each skid
  
      --Alex Gerlants. 04/01/2019. Begin
      if ln_skid_type_if_whed > -1 then --Warehouse skid
          --Get gauge and part width
          select distinct order_item.gauge,
                 f_get_part_width_per_job(ab_job.ab_job_num) 
          into   ll_coil_gauge,
                 ll_coil_width
          from   sheet_skid
                 join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
                 join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
                 join customer_order on customer_order.order_abc_num = order_item.order_abc_num
          where  sheet_skid_num = skidinfo_rec.sheet_skid_num
          and    (order_item.gauge is not null and f_get_part_width_per_job(sheet_skid.ab_job_num) is not null)
          and    rownum = 1;
      end if;
      --Alex Gerlants. 04/01/2019. End
  
      IF length(to_char(li_hl01)) = 1 THEN
        x12_table(i) := 'HL*0' || to_char(li_hl01) || '*02*I';
        i := i + 1;
      ELSE
        x12_table(i) := 'HL*' || to_char(li_hl01) || '*02*I';
        i := i + 1;
      END IF;

      x12_table(i) := 'SN1**1*PF';
      i := i + 1;
                        
      x12_table(i) := 'MEA*WT*N*' || to_char(skidinfo_rec.sheet_net_wt) ||
                      '*01';
      i := i + 1;
                        
      x12_table(i) := 'MEA*CT*NL*' || to_char(skidinfo_rec.skid_pieces) ||
                      '*PC';
      i := i + 1;

      x12_table(i) := 'MEA*WT*G*' || to_char(skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt) || '*01';
      i := i + 1;
      
      x12_table(i) := 'MEA*PD*GG*' || ll_coil_gauge;
      i := i + 1;
      
      x12_table(i) := 'MEA*PD*WD*' || ll_coil_width;
      i := i + 1;
                        
      x12_table(i) := 'REF*BT*' || ls_lot_num;
      i := i + 1;

      x12_table(i) := 'REF*SE*' || skidinfo_rec.sheet_skid_display_num; --added by Victor H. on 06-2012 for Novelis locatio code request
      i := i + 1;
      
      x12_table(i) := 'REF*LS*' || ls_coil_org_num;
      i := i + 1;
      
      li_hl01 := li_hl01 + 1;
      li_rowcount := arconic_856_cur%ROWCOUNT;
      x12_table(li_td1) := 'TD1*PLT90*' || to_char(li_rowcount);
  END LOOP; --End of 'FOR skidinfo_rec IN arconic_856_cur LOOP'
  --Skid loop end ------------------------------------------------------------------

  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                  to_char(li_rowcount + ll_shipment_pc);
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  -- Write X.12 to file
  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
  END LOOP;
  utl_file.fclose(edi_file_handle);

  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE,
         edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;
  
  INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (ll_edi_file_id,
     '039630926',
     ls_su,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856');
  COMMIT;
 

  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  --exception
  --   when invalid_operation
  --   then
  --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

  --  when others
  --  then
  --      DBMS_OUTPUT.PUT_LINE ('System Error');
  --      UTL_FILE.FCLOSE(edi_file_handle);

  RETURN 1;
END edi_arconic_856_X12;
--------------------------------------------------------
--  DDL for Function EDI_ARCONIC_856_X12_ALEX
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_ARCONIC_856_X12_ALEX" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*
  Aluminum Blanking: Ford Supplier Code: ZZ R0P7A
                     DUNS: 01 039630926T
  Customer: ALCAN(34,35,10,1153)
  Alcan Rolled Product    X.121       0015049350011G
  End User: Ford (ZZ F159B)
            Ford Chicago Stamping Plant(51) MS02A
            Ford Walton Hills Stamping Plant(77) MS03A
            Ford Woodhaven Stamping Plant(71) AF30A MS09A
            Ford Maumee Stamping Plant(78)    AF06A MS08A

            Budd Company (Customer ID: 1096) B821L
            Eagle Steel (1251) MZF6B
            (not in use)Ford Monroe Stamping              AP06A

            (not in use) Warehouses: IDS(41)               R5G3B
            (not in use) Wayne Steel Distribution Center(79) RWSDC

  */

  --v_edi_text_ford varchar2(32767);
  --v_edi_text_alcan varchar2(32767);
  --ll_customer_edi_name VARCHAR2(20);

   --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50);

  --edi_loc varchar2(50):='/tmp';
  edi_file        VARCHAR2(50) := 'edi_out.txt';
 --edi_file_prefix VARCHAR2(50) := 'S_arconic_856_'; --Production
 edi_file_prefix VARCHAR2(50) := 's_arconic_856_';   --Development
  edi_file_handle utl_file.file_type;

  li_customer_id    shipment.customer_id%TYPE;
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;

  -- ls_sender_vanid varchar2 (50);
  -- ls_receiver_vanid varchar2 (50);
  -- ls_customer_vanid varchar2(50);
  -- ls_receiver_gs03 varchar2(50);
  -- ls_customer_gs03 varchar2(50);
  --ls_st varchar2(50);
  ls_sf VARCHAR2(50);
  ls_eq_type VARCHAR2(10);  -- Added by Patrick Reynolds 11/30/2016
  ls_su      VARCHAR2(50);
  ls_st_duns VARCHAR2(50);
  ls_po      VARCHAR2(30);
  ls_auth_code   VARCHAR2(32);
  ll_gs_log  INTEGER;
  ll_st_log  INTEGER;
  ll_bsn_log INTEGER;

  ls_today VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  ls_now   VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  --ll_newrow integer;
  --ll_sheet_skid_num integer;
  li_rowcount INTEGER;
  --li_rownum integer;
  --li_rownum1 integer;
  li_hl01 INTEGER;
  --li_HL02 integer;
  ll_shipment_nt INTEGER;
  ll_shipment_gt INTEGER;
  ll_shipment_pc INTEGER;
  --li_enduser_id integer;
  li_td1 INTEGER;
  li_rc  INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_vehicle_id_prefix VARCHAR2(50);  -- Added by Patrick Reynolds 11/30/2016
  ls_scac              carrier.scac%TYPE;
  ls_carrier_full_name VARCHAR2(18);
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_carrier_initial   VARCHAR2(50);  -- Not used in stored procedure.  Discovered by Patrick Reynolds 11/30/2016
  ldt_shipment         DATE;
  --ld_shipdate date;
  ll_temp         INTEGER;
  ls_enduser_part VARCHAR2(50);
  li_des_id       INTEGER;
  --li_stop         INTEGER;
  --ls_enduser_po varchar2(50);

  ll_edi_file_id INTEGER;
  --ll_edi_file_id_alcan integer;
  li_count       integer;

  ls_lot_num VARCHAR2(32);
  ls_coil_id VARCHAR2(32);
  ls_des_cust_name VARCHAR2(18);

  CURSOR arconic_856_cur IS
    SELECT sheet_packing_item.sh_packing_item,
           'MULTIPLE' lot_num,
           'MULTIPLE' coil_id,
           customer_order.orig_customer_po,
           customer_order.order_abc_num,
           customer_order.enduser_po,
           customer_order.created_date,
           order_item.order_item_num,
           order_item.enduser_part_num,
           order_item.supplier_code,
           order_item.gauge,
           sheet_skid. ab_job_num,
           sheet_skid.sheet_skid_num,
           sheet_skid.sheet_skid_display_num, --added by Victor H. on 06-2012 for Novelis locatio code request
           sheet_skid.sheet_net_wt,
           sheet_skid.sheet_tare_wt,
           sheet_skid. skid_pieces,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_theoretical_wt,
           NULL done
      FROM customer_order,
           order_item,
           sheet_skid,
           ab_job,
           shipment,
           sheet_packing_item
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
  --      (SHIPMENT.SHIPMENT_EDI856_DATE is NULL);

  --TYPE skidinfo_tabletype IS TABLE OF arconic_856_cur%ROWTYPE INDEX BY BINARY_INTEGER;
  --skidinfo_table skidinfo_tabletype;
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table    store_tabletype;
  i            BINARY_INTEGER := 0;
  skidinfo_rec arconic_856_cur%ROWTYPE;

  /*CURSOR packing_list_same_bol IS
  SELECT packing_list
    FROM shipment
   WHERE bill_of_lading = ll_bill_of_lading;*/

  CURSOR c_ship_to IS
    SELECT DISTINCT des_sh_cust_id --, PACKING_LIST
      FROM shipment
     WHERE bill_of_lading = ll_bill_of_lading
       AND shipment.shipment_status = 0;
  --ORDER BY PACKING_LIST;

BEGIN

  edi_loc := dbo.get_edi_destination('EDI_DIR'); --Alex Gerlants. 11/15/2016

  -- edi_alcan_870; -- Send 870 first

  -- Get Customer ID, End user ID
  --SELECT customer_id, des_sh_cust_id
  --  INTO li_customer_id, li_des_sh_cust_id
  -- FROM shipment
  -- WHERE shipment.packing_list = al_packing_list;
  --IF NOT SQL%FOUND THEN
 --   RETURN - 1;
  --END IF;

  -- Get Customer ID, End user ID, authorization code
  SELECT customer_id, des_sh_cust_id, nvl(shipment_athorization_code, 'NA')
    INTO li_customer_id, li_des_sh_cust_id, ls_auth_code
  FROM shipment
  WHERE shipment.packing_list = al_packing_list;
  IF NOT SQL%FOUND THEN
   RETURN - 1;
  END IF;

  -- dbms_output.put_line (to_char(li_customer_id) || '  ' || to_char(li_des_sh_cust_id) );

  select   count(*)
  into     li_count
  from     customer
  where    customer_id = li_customer_id
  and      (
                lower(customer_full_name) like '%arconic%'
             or lower(customer_short_name) like '%arconic%'
           );

  if li_count <= 0 Then --Customer is NOT Novelis
    return 200;
  end if;

  --IF NOT (li_customer_id IN (34, 35, 10, 1153, 1459, 2582)) -- AND (li_des_sh_cust_id IN (
  ----10,41,51,69,70,71,72,77,78,79,1055,1062,1073,1086,1096,1099,1114,1112,1153,
  ----1206,1251,1253,1268,1269,1270,1322,1325,1328,1331,1332,1346,1347, 1382, 1383)))
  -- THEN
  --
  --  --***********************************************************************************************88
  --  --IF NOT ((li_customer_id IN (34,35,10,1153)) AND (li_des_sh_cust_id IN (SELECT CUSTOMER_ID
  --  --FROM CUSTOMER
  --  --WHERE CUSTOMER_DUNS_NUMBER_STRING is not null))) THEN
  --
  --  RETURN 200;
  --END IF;

  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(sheet_skid.sheet_net_wt),
         SUM(sheet_skid.sheet_net_wt) + SUM(sheet_skid.sheet_tare_wt),
         SUM(sheet_skid.skid_pieces)
    INTO ll_shipment_nt, ll_shipment_gt, ll_shipment_pc
    FROM sheet_skid, sheet_packing_item, shipment
   WHERE shipment.packing_list = sheet_packing_item.packing_list
     AND sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
     AND shipment.packing_list = al_packing_list;
  IF ll_shipment_pc = 0 THEN
    RETURN 100;
  END IF; -- empty shipment

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  -- Retrieve ABCO info
  -- ls_sender_vanid := '3010007080';
  --ls_ic := 'R0P7A';

  -- Retrieve ALCAN supply code and Ford Stamping Plant location code
  --SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf
  --FROM customer_customer  WHERE o_customer_id = li_customer_id and e_customer_id = 49;  --Ford customer_id =49

  ls_sf := '039630926';
  --SELECT NVL(communication_code,'UNKNOWN') INTO ls_st FROM customer_system
  --WHERE customer_id = li_des_sh_cust_id;

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.vehicle_id_prefix, '9999'),
         nvl(shipment.equipment_type, 'NA'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'PT'), -- Protected Trailer
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE)
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_vehicle_id_prefix,
         ls_eq_type,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_carrier_initial,
         ldt_shipment
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;

  --Check all packing_lists are done against a BOL
  /*
  for pl_rec in packing_list_same_bol loop
      select shipment.shipment_status into ll_temp from shipment
             where shipment.packing_list = pl_rec.packing_list;
      if ll_temp > 0 then
         return pl_rec.packing_list;
      end if;

  end loop;
  */
  --End of packing list checking

  SELECT nvl(customer_duns_number_string, '00000000'), customer_short_name
    INTO ls_st_duns, ls_des_cust_name
    FROM customer
   WHERE customer_id = li_des_sh_cust_id;

  IF (ls_st_duns = '00000000') THEN
    RETURN 200;
  END IF; --No Ship to DUNS

  SELECT nvl(customer_duns_number_string, '00000000')
    INTO ls_su
    FROM customer
   WHERE customer_id = li_customer_id;
  IF (ls_su = '00000000') THEN
    RETURN 200;
  END IF; --No Supplier DUNS

  -- Get SCAC(Standard Carrier Alpha Code)
  SELECT nvl(carrier.scac, 'NONE'), LPAD(carrier.carrier_full_name, 17)
    INTO ls_scac, ls_carrier_full_name
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);

  -- Get Receiver and Customer VAN ID
  -- SELECT NVL(customer_system.van_account_num, 'nothing'), NVL(customer_system.gs03, 'nothing')
  -- INTO ls_receiver_vanid, ls_receiver_gs03    -- ls_receiver_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --   (select shipment.des_sh_cust_id  from shipment  where shipment.packing_list = al_packing_list);

  -- SELECT NVL(customer_system.van_account_num, 'nothing'),NVL(customer_system.gs03, 'nothing')
  -- INTO   ls_customer_vanid, ls_customer_gs03   -- ls_customer_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --       (select shipment.customer_id from shipment where shipment.packing_list = al_packing_list);

  -- Generate Header Info.
  --x12_table(i) := 'ISA*00*'||'          *00*          *ZZ*R0P7A          *ZZ*F159B          *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0') ||'*0*P**';
  --x12_table(i) := 'GS*SH*R0P7A*'||ls_st || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
                  
  --Production
  --x12_table(i) := 'ISA*00*' ||
  --                '          *00*          *01*039630926T     *ZZ*ARNCQFMW      *' ||
  --                ls_today || '*' || ls_now || '*U*00200*' ||
  --                lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
  
  --Development                
  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *ZZ*2NDSFTP        *ZZ*ARNCQFMW      *' ||
                  ls_today || '*' || ls_now || '*U*00200*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';
                                   
  i := i + 1;

  --Production
  --x12_table(1) := 'GS*RC*039630926TTN*' || 'ARNCQFMW' || '*' || ls_today || '*' ||
  --                ls_now || '*' || to_char(ll_gs_log) || '*X*' || '002002';
  
  --Development                
  x12_table(1) := 'GS*RC*2NDSFTPTN*' || 'ARNCQFMW' || '*' || ls_today || '*' ||
                  ls_now || '*' || to_char(ll_gs_log) || '*X*' || '002002';
                  
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;
  --x12_table(i):= 'BSN*00*' || to_char(ll_bill_of_lading) || '*' || ls_today || '*' || ls_now;
  x12_table(i) := 'BSN*00*' || to_char(al_packing_list) || '*' || ls_today || '*' ||
                  ls_now;
  i := i + 1;
  
  --Alex Gerlants. 08/07/2018.
  --Changed to populate with actual ship date instead of current date and time.
  --The reason is that when we send 856 on a later date, this date is not correct.
  --x12_table(i) := 'DTM*011*' || ls_today || '*' || ls_now;
  x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYMMDD') || '*' ||
                                                      to_char(ldt_shipment, 'HH24MI');
  i := i + 1;

  -- First Level HL
  x12_table(i) := 'HL*01**S';
  i := i + 1;
  x12_table(i) := 'MEA*PD*G*' || to_char(ll_shipment_gt) || '*LB';
  i := i + 1;
  x12_table(i) := 'MEA*PD*N*' || to_char(ll_shipment_nt) || '*LB';
  i := i + 1;
  x12_table(i) := 'TD1*PLT90*' || to_char(li_rowcount);
  li_td1 := i;
  i := i + 1;
  x12_table(i) := 'TD5*B*02*' || ls_scac || '*M*' || ls_carrier_full_name;
  i := i + 1;
  -- segment was modified to include trailer number.  Patrick Reynolds 11/30/2016
  x12_table(i) := 'TD3*' || ls_carrier_desc_code || '*' || ls_scac || '*' || ls_vehicle_id_prefix;
  i := i + 1;
  x12_table(i) := 'REF*BM*' || to_char(al_packing_list);
  i := i + 1;
  x12_table(i) := 'REF*PK*' || to_char(al_packing_list);
  i := i + 1;
  -- segment was modified to include equipment type.  Patrick Reynolds 11/30/2016
  x12_table(i) := 'REF*EQ*' || ls_eq_type;
  i := i + 1; --waiting for Novilis, ----tony
  --- Testing for multi order ASN ----Tony

  x12_table(i) := 'REF*MB*' || to_char(ll_bill_of_lading);
  i := i + 1;
  SELECT COUNT(*)
    INTO ll_temp
    FROM shipment
   WHERE shipment.bill_of_lading = ll_bill_of_lading
     AND shipment.shipment_status = 0;
  x12_table(i) := 'REF*SS*' || to_char(ll_temp);
  i := i + 1;
  li_des_id := 1;
  FOR c_stop IN c_ship_to LOOP
    IF li_des_sh_cust_id = c_stop.des_sh_cust_id THEN
      x12_table(i) := 'REF*QN*' || to_char(li_des_id);
      i := i + 1;
    END IF;
    li_des_id := li_des_id + 1;
  END LOOP;

  /*
  IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
     x12_table(i):= 'REF*ZZ*' || ls_st;i:=i+1;
  end if;
  */

  x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYMMDD') || '*' ||
                  to_char(ldt_shipment, 'HH24MI');
  i := i + 1;
  x12_table(i) := 'N1*ST*' || ls_des_cust_name || '*1*' || ls_st_duns;
  i := i + 1;
  x12_table(i) := 'N1*SF*Aluminum Blanking Co*1*' || ls_sf;
  i := i + 1;
  x12_table(i) := 'N1*SU**1*' || ls_su;
  i := i + 1;

  --if not (li_des_sh_cust_id = 1096 or li_des_sh_cust_id = 1251) then
  --         x12_table(i):= 'N1*IC**92*' || ls_ic; i := i +1;        --- Deleted 04-30-03 by Tony according to alcan Julia's email
  --end if;

  --         x12_table(i):= 'N1*CN**92*' || ls_st_duns; i := i +1; --Ship to DUNs --- Deleted 04-30-03 by Tony according to alcan Julia's email

  -- Second Level HL based on End User PO( only one part# is included in one shipement per FORD's request)
  OPEN arconic_856_cur;
  FETCH arconic_856_cur
    INTO skidinfo_rec;
  --    ls_enduser_part := skidinfo_rec.ENDUSER_PART_NUM;
  --    ls_enduser_po := skidinfo_rec.ENDUSER_PO;

  /*
    if skidinfo_rec.ORIG_CUSTOMER_PO IN ('68Q68517') then    --Do NOT send 856 to Ford for some flipping related POs )
         edi_file_prefix := 'nosend_alcan_ford_ford';
    end if;
  */

  SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
    INTO ls_enduser_part
    FROM "ORDER_ITEM", "SHEET_SKID"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
     AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
     AND ("SHEET_SKID"."SHEET_SKID_NUM" = skidinfo_rec.sheet_skid_num);

  /*
      SELECT "CUSTOMER_ORDER"."ENDUSER_PO" into ls_enduser_po
             FROM "SHEET_SKID",
                  "CUSTOMER_ORDER"
                  WHERE ( "SHEET_SKID"."REF_ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM" ) and
                        (SHEET_SKID.SHEET_SKID_NUM = skidinfo_rec.SHEET_SKID_NUM);
  */

  x12_table(i) := 'HL*02*01*O';
  i := i + 1;
  IF ls_enduser_part IS NULL THEN
    ls_enduser_part := 'NA';
  END IF;
  x12_table(i) := 'LIN**BP*' || ls_enduser_part;
  i := i + 1;
  x12_table(i) := 'SN1**' || to_char(ll_shipment_pc) || '*EA*0';
  i := i + 1;

  --
  --ls_po := skidinfo_rec.ORIG_CUSTOMER_PO;
  SELECT "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO"
    INTO ls_po
    FROM "SHEET_SKID", "CUSTOMER_ORDER"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
         "CUSTOMER_ORDER"."ORDER_ABC_NUM")
     AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num);

  --IF INSTR(skidinfo_rec.ORIG_CUSTOMER_PO,'-') > 0
  --New PO format for Novelis SAP include '-'
  /*IF instr(ls_po, '-') > 0 THEN
    ls_po := substr(ls_po, 0, instr(ls_po, '-') - 1);
  END IF;*/

  --   IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
  x12_table(i) := 'PRF*' || ls_po || '***' ||
                  to_char(skidinfo_rec.created_date, 'YYMMDD');
  i := i + 1;
  --   end if;

  CLOSE arconic_856_cur;

   --  Novelis SAP order number
 x12_table(i) := 'REF*IL*' || ls_auth_code;
 i := i + 1;
  --  end if;

  -- Third Level HL Under a P.O.
  li_hl01 := 3;

  FOR skidinfo_rec IN arconic_856_cur LOOP
    IF length(to_char(li_hl01)) = 1 THEN
      x12_table(i) := 'HL*0' || to_char(li_hl01) || '*02*I';
      i := i + 1;
    ELSE
      x12_table(i) := 'HL*' || to_char(li_hl01) || '*02*I';
      i := i + 1;
    END IF;

    --    IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
    --       x12_table(i) := 'SN1**'||to_char(skidinfo_rec.skid_pieces)||'*EA';i:=i+1;
    --    else
    x12_table(i) := 'SN1**1*PF';
    i := i + 1;
    --    end if;

    --if li_des_sh_cust_id = 1096 -- To Budd or li_des_sh_cust_id = 1251 then
    --   then
    --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; i := i +1;
    --      x12_table(i) :=  'MEA*PD*TH*' || to_char(skidinfo_rec.sheet_net_wt) || '*24'; i := i +1;
    --elsif   li_des_sh_cust_id = 1251   --To Eagle Steel
    --  then
    --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; i := i +1;
    --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*24'; i := i +1;
    --      x12_table(i) :=  'MEA*PD*TH*' || to_char(skidinfo_rec.gauge) || '*EM'; i:=i+1;
    --    x12_table(i) :=  'MEA*PD*WD*'||'44.875'||'*IN'; i:=i+1;
    --    x12_table(i) :=  'MEA*PD*LN*'||to_char(skidinfo_rec.skid_pieces)||'*LF';  i:=i+1;
    --else  --All else, Ford dirct shiping program
    x12_table(i) := 'MEA*PD*N*' || to_char(skidinfo_rec.sheet_net_wt) ||
                    '*01';
    i := i + 1;
    x12_table(i) := 'MEA*PD*WT*' || to_char(skidinfo_rec.skid_pieces) ||
                    '*PC';
    i := i + 1;

    -- changed to all gross wt per novelis 1/30/2015
      x12_table(i) := 'MEA*PD*G*' || to_char(skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt) || '*01';
      i := i + 1;

    /*
    IF (skidinfo_rec.sheet_theoretical_wt IS NULL) OR
       (skidinfo_rec.sheet_theoretical_wt = 0) THEN
      x12_table(i) := 'MEA*PD*G*' || to_char(ll_shipment_gt) || '*01';
      i := i + 1;
    ELSE
      x12_table(i) := 'MEA*PD*G*' ||
                      to_char(skidinfo_rec.sheet_theoretical_wt) || '*01';
      i := i + 1;
    END IF;
    */
    --end if;

    -- fill in lot num
    SELECT COUNT(*)
      INTO li_rc
      FROM sheet_skid_detail
     WHERE sheet_skid_detail.sheet_skid_num = skidinfo_rec.sheet_skid_num;

    ls_lot_num := skidinfo_rec.lot_num;
    ls_coil_id := skidinfo_rec.coil_id;

    IF li_rc = 1 THEN
      SELECT lot_num, coil_org_num
        INTO ls_lot_num, ls_coil_id
        FROM coil
       WHERE coil.coil_abc_num =
             (SELECT coil_abc_num
                FROM production_sheet_item
               WHERE production_sheet_item.prod_item_num =
                     (SELECT prod_item_num
                        FROM sheet_skid_detail
                       WHERE sheet_skid_detail.sheet_skid_num =
                             skidinfo_rec.sheet_skid_num));
    END IF;

    --if li_des_sh_cust_id = 1251   --Eagle need coil ID here instead of lot number
    --then
    --x12_table(i) :=  'REF*HC*' || skidinfo_rec.coil_id ; i := i +1;
    --else
    x12_table(i) := 'REF*HC*' || ls_lot_num;
    i := i + 1;
    --end if;

    --x12_table(i) := 'REF*LS*' || to_char(skidinfo_rec.sheet_skid_num);
    x12_table(i) := 'REF*LS*' || skidinfo_rec.sheet_skid_display_num; --added by Victor H. on 06-2012 for Novelis locatio code request
    i := i + 1;
    li_hl01 := li_hl01 + 1;
    li_rowcount := arconic_856_cur%ROWCOUNT;
    x12_table(li_td1) := 'TD1*PLT90*' || to_char(li_rowcount);
  END LOOP;

  -- DBMS_OUTPUT.PUT_LINE ('rowcount' || to_char(li_rowcount));

  -- if li_des_sh_cust_id = 1096 or li_des_sh_cust_id = 1251 then
  --   x12_table(i) :=  'CTT*' || to_char(li_HL01 - 1) ||'*' || to_char(ll_shipment_pc*2) ;
  --   i := i +1;
  -- else
  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                  to_char(li_rowcount + ll_shipment_pc);
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  -- Write X.12 to file
  -- To FORD

  /** Write file to /templar/templar/incoming/senddata
  /*
  **/

  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  --edi_file:= 'S_alcan_ford_ford_' || to_char(ll_edi_file_id) ||'.x12';

  -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
  -- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
    --        v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
  END LOOP;
  utl_file.fclose(edi_file_handle);

  --To ALCAN

  /*
  SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;
  SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id_alcan FROM DUAL;
  edi_file:= 'S_alcan_ford_alcan_' || to_char(ll_edi_file_id_alcan) ||'.x12';
  edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');
  x12_table(0) := 'ISA*00*'||'          *00*          *01*039630926T     *09*0015049350011G *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0')||'*0*P**';
  x12_table(1) := 'GS*SH*R0P7A*'||'001504935001' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  x12_table(i-1) :=  'GE*1*' || to_char (ll_gs_log);
  x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');
  for j in 0..i loop
   UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
       v_edi_text_alcan:=v_edi_text_alcan||x12_table(j)||CHR(10);
  end loop;
  UTL_FILE.FCLOSE(edi_file_handle);

  */

  /* The following code added by Tony, for update archive*/

  --  INSERT INTO edi_log (edi_log_timestamp,customer_id,
  --         customer_edi_name,edi_log_contents,edi_file_id,edi_text)
  --    VALUES (SYSDATE,li_customer_id,ll_customer_edi_name,
  --           'EDI:'||ll_customer_edi_name||' generated successfully.',ll_edi_file_id,v_edi_text);
  --   COMMIT;


  /* Alex Gerlants. Commented out for testing. Begin
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE,
         edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;

  INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
  VALUES(ll_gs_log, ls_su, sysdate, edi_file);
  COMMIT;*/

  --added by Victor Huang on 12/07 for verifying 997
  /* Alex Gerlants. Commented out for testing
  INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (ll_edi_file_id,
     '039630926',
     ls_su,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856');
  COMMIT;
  */ -- Alex Gerlants. Commented out for testing. End

  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  --exception
  --   when invalid_operation
  --   then
  --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

  --  when others
  --  then
  --      DBMS_OUTPUT.PUT_LINE ('System Error');
  --      UTL_FILE.FCLOSE(edi_file_handle);

  RETURN 1;
END edi_arconic_856_x12_alex;
--------------------------------------------------------
--  DDL for Function EDI_ARCONIC_856_X12_ALEX2
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_ARCONIC_856_X12_ALEX2" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*
  Aluminum Blanking: Ford Supplier Code: ZZ R0P7A
                     DUNS: 01 039630926T
  Customer: Arconic-TN (2784)
*/
   --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50);

  --edi_loc varchar2(50):='/tmp';
  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_prefix VARCHAR2(50) := 'S_arconic_856_'; --Production
  --edi_file_prefix VARCHAR2(50) := 's_arconic_856_'; --Development
  edi_file_handle utl_file.file_type;

  li_customer_id    shipment.customer_id%TYPE;
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;

  -- ls_sender_vanid varchar2 (50);
  -- ls_receiver_vanid varchar2 (50);
  -- ls_customer_vanid varchar2(50);
  -- ls_receiver_gs03 varchar2(50);
  -- ls_customer_gs03 varchar2(50);
  --ls_st varchar2(50);
  ls_sf VARCHAR2(50);
  ls_eq_type VARCHAR2(10);  -- Added by Patrick Reynolds 11/30/2016
  ls_su      VARCHAR2(50);
  ls_st_duns VARCHAR2(50);
  ls_po      VARCHAR2(30);
  ls_auth_code   VARCHAR2(32);
  ll_gs_log  INTEGER;
  ll_st_log  INTEGER;
  ll_bsn_log INTEGER;

  ls_today VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD'); --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  ls_today_2digits_year VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD'); --Alex Gerlants. 10/16/2018. Test
  ls_now   VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  li_rowcount INTEGER;
  li_hl01 INTEGER;
  ll_shipment_nt INTEGER;
  ll_shipment_gt INTEGER;
  ll_shipment_pc INTEGER;
  li_td1 INTEGER;
  li_rc  INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_vehicle_id_prefix VARCHAR2(50);  -- Added by Patrick Reynolds 11/30/2016
  ls_scac              carrier.scac%TYPE;
  ls_carrier_full_name VARCHAR2(18);
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_carrier_initial   VARCHAR2(50);  -- Not used in stored procedure.  Discovered by Patrick Reynolds 11/30/2016
  ldt_shipment         DATE;
   ll_temp         INTEGER;
  ls_enduser_part VARCHAR2(50);
  li_des_id       INTEGER;

  ll_edi_file_id INTEGER;

  ls_lot_num VARCHAR2(32);
  ls_coil_id VARCHAR2(32);
  ls_des_cust_name VARCHAR2(18);
  
  ls_coil_org_num		        coil.coil_org_num%TYPE; --Alex Gerlants. 01/25/2019
  ll_coil_gauge		          coil.coil_gauge%TYPE;   --Alex Gerlants. 01/25/2019
  ll_coil_width		          coil.coil_width%TYPE;   --Alex Gerlants. 01/25/2019
  ld_ship_date              date;
  li_is_novelis             integer;
  ln_skid_type_if_whed      sheet_skid.skid_type_if_whed%TYPE;   --Alex Gerlants. 04/01/2019
  scrap_item                integer;
  li_hl02                   integer; --Alex Gerlants. 10/13/2025. 2436_Arconic_856_Multiple_Parts
  ls_enduser_part_prev      varchar2(50); --Alex Gerlants. 10/13/2025. 2436_Arconic_856_Multiple_Parts
  li_loop_counter           integer; --Alex Gerlants. 10/13/2025. 2436_Arconic_856_Multiple_Parts
  li_order_counter          integer; --Alex Gerlants. 10/13/2025. 2436_Arconic_856_Multiple_Parts

  CURSOR arconic_856_cur IS
    SELECT sheet_packing_item.sh_packing_item,
           'MULTIPLE' lot_num,
           'MULTIPLE' coil_id,
           customer_order.orig_customer_po,
           customer_order.order_abc_num,
           customer_order.enduser_po,
           customer_order.created_date,
           order_item.order_item_num,
           order_item.enduser_part_num,
           order_item.supplier_code,
           order_item.gauge,
           sheet_skid. ab_job_num,
           sheet_skid.sheet_skid_num,
           sheet_skid.sheet_skid_display_num, --added by Victor H. on 06-2012 for Novelis locatio code request
           sheet_skid.sheet_net_wt,
           sheet_skid.sheet_tare_wt,
           sheet_skid. skid_pieces,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_theoretical_wt,
           NULL done
      FROM customer_order,
           order_item,
           sheet_skid,
           ab_job,
           shipment,
           sheet_packing_item
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
/*      
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
  --      (SHIPMENT.SHIPMENT_EDI856_DATE is NULL);
*/
  --TYPE skidinfo_tabletype IS TABLE OF arconic_856_cur%ROWTYPE INDEX BY BINARY_INTEGER;
  --skidinfo_table skidinfo_tabletype;
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table    store_tabletype;
  i            BINARY_INTEGER := 0;
  skidinfo_rec arconic_856_cur%ROWTYPE;

  /*CURSOR packing_list_same_bol IS
  SELECT packing_list
    FROM shipment
   WHERE bill_of_lading = ll_bill_of_lading;*/

  CURSOR c_ship_to IS
    SELECT DISTINCT des_sh_cust_id --, PACKING_LIST
      FROM shipment
     WHERE bill_of_lading = ll_bill_of_lading
       AND shipment.shipment_status = 0;
  --ORDER BY PACKING_LIST;
  
  cursor c_coil is
  select distinct 
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num,
         coil.coil_gauge,
         coil.coil_width
         --process_coil.coil_abc_num
         --outbound_edi_transaction.transaction_time,
         --outbound_edi_transaction.edi_file_name
  from   customer_order
         join order_item on order_item.order_abc_num = customer_order.order_abc_num
         join ab_job on ab_job.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
         join sheet_skid on sheet_skid.ab_job_num = ab_job.ab_job_num
         join sheet_packing_item on sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
         join shipment on shipment.packing_list = sheet_packing_item.packing_list
         join process_coil on process_coil.ab_job_num = ab_job.ab_job_num
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         --join outbound_edi_transaction on outbound_edi_transaction.edi_file_id = shipment.edi_file_id_856
  --where  shipment.packing_list = 105586 --Production
  where  shipment.packing_list = al_packing_list 
  order by
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num;

BEGIN
  
  -- Get Customer ID, End user ID, authorization code
  select   customer_id, des_sh_cust_id, nvl(shipment_athorization_code, 'NA')
  into     li_customer_id, li_des_sh_cust_id, ls_auth_code
  from     shipment
  where    shipment.packing_list = al_packing_list;
  
  if not SQL%FOUND then
    return - 1;
  end if;
  
  if not li_customer_id = 2784 then --Arconic TN only
    return 200;
  end if;
  
  select shipment_edi856_date
  into   ld_ship_date
  from   shipment
  where  shipment.packing_list = al_packing_list;
   
  if not (ld_ship_date is null) then --ASN already sent
    return 100;
  end if;
  
  select max(sc_packing_item)
  into   scrap_item
  from   scrap_packing_item
  where  packing_list = al_packing_list;  
  
  if scrap_item > 0 then
    return 1;
  end if;
  
  select count(*)
  into   li_rowcount
  from   reject_coil_packing_item
         join coil on coil.coil_abc_num = reject_coil_packing_item.coil_abc_num
         join shipment on shipment.packing_list = reject_coil_packing_item.packing_list
         join customer on customer.customer_id = shipment.customer_id
  where  shipment.packing_list = al_packing_list;
  
  if li_rowcount > 0 then
    return 1;
  end if;

  edi_loc := dbo.get_edi_destination('EDI_DIR');



  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(sheet_skid.sheet_net_wt),
         SUM(sheet_skid.sheet_net_wt) + SUM(sheet_skid.sheet_tare_wt),
         SUM(sheet_skid.skid_pieces)
    INTO ll_shipment_nt, ll_shipment_gt, ll_shipment_pc
    FROM sheet_skid, sheet_packing_item, shipment
   WHERE shipment.packing_list = sheet_packing_item.packing_list
     AND sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
     AND shipment.packing_list = al_packing_list;
     
  IF ll_shipment_pc = 0 THEN
    RETURN 2; --Nothing to do here
  END IF;

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  ls_sf := '039630926';

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.vehicle_id_prefix, '9999'),
         nvl(shipment.equipment_type, 'NA'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'PT'), -- Protected Trailer
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE)
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_vehicle_id_prefix,
         ls_eq_type,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_carrier_initial,
         ldt_shipment
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;

  SELECT nvl(customer_duns_number_string, '00000000'), customer_short_name
    INTO ls_st_duns, ls_des_cust_name
    FROM customer
   WHERE customer_id = li_des_sh_cust_id;

  IF (ls_st_duns = '00000000') THEN
    ls_st_duns := '';
  END IF; --Arconic does not need destination DUNS

  SELECT nvl(customer_duns_number_string, '00000000')
    INTO ls_su
    FROM customer
   WHERE customer_id = li_customer_id;
  IF (ls_su = '00000000') THEN
    RETURN 200;
  END IF; --No Supplier DUNS

  -- Get SCAC(Standard Carrier Alpha Code)
  SELECT nvl(carrier.scac, 'NONE'), LPAD(carrier.carrier_full_name, 17)
    INTO ls_scac, ls_carrier_full_name
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);

  -- Generate Header Info.
  --Production
  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *01*039630926T     *01*961613887      *' ||
                  ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*P*>';
  
  --Development                
  --x12_table(i) := 'ISA*00*' ||
  --                '          *00*          *ZZ*2NDSFTP        *ZZ*ARNCQFMW       *' ||
  --                ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
  --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T*>';
                  
  i := i + 1;

  --Alex Gerlants. 10/16/2018. Changed from "002002" to "004010"
  --Production
  x12_table(1) := 'GS*SH*R0P7ATN*' || '961613887' || '*' || ls_today || '*' ||
                  ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  --Development
  --x12_table(1) := 'GS*SH*2NDSFTP' || 'TN*ARNCQFMW' || '*' || ls_today || '*' ||
  --               ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;

  x12_table(i) := 'BSN*00*' || to_char(al_packing_list) || '*' || ls_today || '*' ||
                  ls_now;
  i := i + 1;

  x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                                                      to_char(ldt_shipment, 'HH24MI');
  i := i + 1;
  
  x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                  to_char(ldt_shipment, 'HH24MI');
  i := i + 1;

  -- First Level HL
  x12_table(i) := 'HL*01**S';
  i := i + 1;

  x12_table(i) := 'MEA*WT*G*' || to_char(ll_shipment_gt) || '*LB';
  i := i + 1;
  x12_table(i) := 'MEA*WT*N*' || to_char(ll_shipment_nt) || '*LB';
  i := i + 1;
  x12_table(i) := 'TD1*PLT90*' || to_char(li_rowcount);
  li_td1 := i;
  i := i + 1;
  x12_table(i) := 'TD5*B*2*' || ls_scac || '*M*' || ls_carrier_full_name;
  i := i + 1;

  x12_table(i) := 'TD3*' || ls_carrier_desc_code || '*' || ls_scac || '*' || ls_vehicle_id_prefix;
  i := i + 1;
  x12_table(i) := 'REF*BM*' || to_char(al_packing_list);
  i := i + 1;
  x12_table(i) := 'REF*PK*' || to_char(al_packing_list);
  i := i + 1;

  x12_table(i) := 'REF*EQ*' || ls_eq_type;
  i := i + 1;

  x12_table(i) := 'REF*MB*' || to_char(ll_bill_of_lading);
  i := i + 1;
  SELECT COUNT(*)
    INTO ll_temp
    FROM shipment
   WHERE shipment.bill_of_lading = ll_bill_of_lading
     AND shipment.shipment_status = 0;

  li_des_id := 1;
  
  x12_table(i) := 'N1*ST*' || ls_des_cust_name || '*1*' || ls_st_duns;
  i := i + 1;
  x12_table(i) := 'N1*SF*Aluminum Blanking Co*1*' || ls_sf;
  i := i + 1;
  x12_table(i) := 'N1*SU**1*' || ls_su;
  i := i + 1;

/*
  -- Second Level HL based on End User PO( only one part# is included in one shipement per FORD's request)
  OPEN arconic_856_cur;
  FETCH arconic_856_cur
    INTO skidinfo_rec;

  SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
    INTO ls_enduser_part
    FROM "ORDER_ITEM", "SHEET_SKID"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
     AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
     AND ("SHEET_SKID"."SHEET_SKID_NUM" = skidinfo_rec.sheet_skid_num);
     
  ls_enduser_part:= skidinfo_rec.enduser_part_num; --Alex Gerlants. 10/13/2025. 2436_Arconic_856_Multiple_Part

  x12_table(i) := 'HL*02*01*O';
  i := i + 1;
  IF ls_enduser_part IS NULL THEN
    ls_enduser_part := 'NA';
  END IF;
  x12_table(i) := 'LIN**BP*' || ls_enduser_part;
  i := i + 1;
  x12_table(i) := 'SN1**' || to_char(ll_shipment_pc) || '*EA*0';
  i := i + 1;

  SELECT "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO"
    INTO ls_po
    FROM "SHEET_SKID", "CUSTOMER_ORDER"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
         "CUSTOMER_ORDER"."ORDER_ABC_NUM")
     AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num);

  x12_table(i) := 'PRF*' || ls_po || '***' ||
                  to_char(skidinfo_rec.created_date, 'YYYYMMDD');
  i := i + 1;
  --   end if;

  CLOSE arconic_856_cur;

   --  Novelis SAP order number
 x12_table(i) := 'REF*IL*' || ls_auth_code;
 i := i + 1;
  --  end if;
*/

  -- Third Level HL Under a P.O.
  li_hl01 := 2; --Alex Gerlants. 10/13/2025. 2436_Arconic_856_Multiple_Part. Changed from 3 to 2
  li_hl02 := 1; --Alex Gerlants. 10/13/2025. 2436_Arconic_856_Multiple_Part
  li_order_counter := 1; --Alex Gerlants. 10/13/2025. 2436_Arconic_856_Multiple_Part
  ls_enduser_part := ''; --Alex Gerlants. 10/13/2025. 2436_Arconic_856_Multiple_Part
  ls_enduser_part_prev := ''; --Alex Gerlants. 10/13/2025. 2436_Arconic_856_Multiple_Part
  
  open arconic_856_cur;
  fetch arconic_856_cur
    into skidinfo_rec;
     
  ls_enduser_part:= skidinfo_rec.enduser_part_num; --Alex Gerlants. 10/13/2025. 2436_Arconic_856_Multiple_Part
  
  
  
  x12_table(i) := 'HL*0' || to_char(li_hl01) || '*0' || to_char(li_order_counter) || '*O';
  
  li_hl01 := li_hl01 + 1;
  li_hl02 := li_hl02 + 1;
  
  i := i + 1;
          
  IF ls_enduser_part IS NULL THEN
    ls_enduser_part := 'NA';
  END IF;
          
  x12_table(i) := 'LIN**BP*' || ls_enduser_part;
  i := i + 1;
  x12_table(i) := 'SN1**' || to_char(ll_shipment_pc) || '*EA*0';
  i := i + 1;
          
  SELECT "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO"
    INTO ls_po
    FROM "SHEET_SKID", "CUSTOMER_ORDER"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
         "CUSTOMER_ORDER"."ORDER_ABC_NUM")
     AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num);

  x12_table(i) := 'PRF*' || ls_po || '***' ||
                  to_char(skidinfo_rec.created_date, 'YYYYMMDD');
  i := i + 1;
          
   x12_table(i) := 'REF*IL*' || ls_auth_code;
   i := i + 1;
   
   close arconic_856_cur;
   
   li_loop_counter := 0;

  --Skid loop begin ----------------------------------------------------------------
  FOR skidinfo_rec IN arconic_856_cur LOOP
      li_loop_counter := li_loop_counter + 1;
      
      if li_loop_counter > 1 then
          ls_enduser_part:= skidinfo_rec.enduser_part_num; --Alex Gerlants. 10/13/2025. 2436_Arconic_856_Multiple_Part
          
          if ls_enduser_part <> ls_enduser_part_prev then
              li_order_counter := li_order_counter + 1;
              
              IF length(to_char(li_hl01)) < 10 then
                 if length(to_char(li_order_counter)) < 10 then
                    x12_table(i) := 'HL*0' || to_char(li_hl01) || '*0' || to_char(li_order_counter) || '*O';
                 else
                    x12_table(i) := 'HL*0' || to_char(li_hl01) || to_char(li_order_counter) || '*O';
                 end if;
              else
                 if length(to_char(li_order_counter)) < 10 then
                    x12_table(i) := 'HL*' || to_char(li_hl01) || '*0' || to_char(li_order_counter) || '*O';
                 else
                    x12_table(i) := 'HL*' || to_char(li_hl01) || to_char(li_order_counter) || '*O';
                 end if;
              end if;
              
              li_hl02 := li_hl01;
              
              li_hl01 := li_hl01 + 1;
              --li_hl02 := li_hl02 + 1;
              
              i := i + 1;
              
              IF ls_enduser_part IS NULL THEN
                ls_enduser_part := 'NA';
              END IF;
              
              x12_table(i) := 'LIN**BP*' || ls_enduser_part;
              i := i + 1;
              x12_table(i) := 'SN1**' || to_char(ll_shipment_pc) || '*EA*0';
              i := i + 1;
              
              SELECT "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO"
                INTO ls_po
                FROM "SHEET_SKID", "CUSTOMER_ORDER"
               WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
                     "CUSTOMER_ORDER"."ORDER_ABC_NUM")
                 AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num);

              x12_table(i) := 'PRF*' || ls_po || '***' ||
                              to_char(skidinfo_rec.created_date, 'YYYYMMDD');
              i := i + 1;
              
               x12_table(i) := 'REF*IL*' || ls_auth_code;
                i := i + 1;     
          end if;
      end if;
    
      --In case of a split skid, we are creating just 1 HL for this skid
      --with just 1 coil for this skid.
      select distinct 
             coil.coil_org_num,
             coil.coil_gauge,
             coil.coil_width,
             coil.lot_num,
             nvl(skid_type_if_whed, -1) --Alex Gerlants. 04/01/2019
      into   ls_coil_org_num,
             ll_coil_gauge,
             ll_coil_width,
             ls_lot_num,
             ln_skid_type_if_whed --Alex Gerlants. 04/01/2019
      FROM "COIL",   
           "PRODUCTION_SHEET_ITEM",   
           "SHEET_SKID",   
           "SHEET_SKID_DETAIL",   
           "PROCESS_COIL"  
     WHERE ( "COIL"."COIL_ABC_NUM" = "PRODUCTION_SHEET_ITEM"."COIL_ABC_NUM" ) and  
           ( "SHEET_SKID_DETAIL"."SHEET_SKID_NUM" = "SHEET_SKID"."SHEET_SKID_NUM" ) and  
           ( "SHEET_SKID_DETAIL"."PROD_ITEM_NUM" = "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NUM" ) and  
           ( "COIL"."COIL_ABC_NUM" = "PROCESS_COIL"."COIL_ABC_NUM" ) and  
           ( "PRODUCTION_SHEET_ITEM"."AB_JOB_NUM" = "PROCESS_COIL"."AB_JOB_NUM" ) and  
           ( (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num)  ) and
           ( (rownum = 1)  ); --We need just 1 coil for each skid
  
      --Alex Gerlants. 04/01/2019. Begin
      if ln_skid_type_if_whed > -1 then --Warehouse skid
          --Get gauge and part width
          select distinct order_item.gauge,
                 f_get_part_width_per_job(ab_job.ab_job_num) 
          into   ll_coil_gauge,
                 ll_coil_width
          from   sheet_skid
                 join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
                 join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
                 join customer_order on customer_order.order_abc_num = order_item.order_abc_num
          where  sheet_skid_num = skidinfo_rec.sheet_skid_num
          and    (order_item.gauge is not null and f_get_part_width_per_job(sheet_skid.ab_job_num) is not null)
          and    rownum = 1;
      end if;
      --Alex Gerlants. 04/01/2019. End
  
      if length(to_char(li_hl01)) < 10 then
         if length(to_char(li_hl02)) < 10 then
            x12_table(i) := 'HL*0' || to_char(li_hl01) || '*0' || to_char(li_hl02) || '*I';
         else
            x12_table(i) := 'HL*0' || to_char(li_hl01) || to_char(li_hl02) || '*I';
         end if;
      else
         if length(to_char(li_hl02)) < 10 then
            x12_table(i) := 'HL*' || to_char(li_hl01) || '*0' || '*' || to_char(li_hl02) || '*I';
         else
            x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hl02) || '*I';
         end if;
      end if;
      
      i := i + 1;

      x12_table(i) := 'SN1**1*PF';
      i := i + 1;
                        
      x12_table(i) := 'MEA*WT*N*' || to_char(skidinfo_rec.sheet_net_wt) ||
                      '*01';
      i := i + 1;
                        
      x12_table(i) := 'MEA*CT*NL*' || to_char(skidinfo_rec.skid_pieces) ||
                      '*PC';
      i := i + 1;

      x12_table(i) := 'MEA*WT*G*' || to_char(skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt) || '*01';
      i := i + 1;
      
      x12_table(i) := 'MEA*PD*GG*' || ll_coil_gauge;
      i := i + 1;
      
      x12_table(i) := 'MEA*PD*WD*' || ll_coil_width;
      i := i + 1;
                        
      x12_table(i) := 'REF*BT*' || ls_lot_num;
      i := i + 1;

      x12_table(i) := 'REF*SE*' || skidinfo_rec.sheet_skid_display_num; --added by Victor H. on 06-2012 for Novelis locatio code request
      i := i + 1;
      
      x12_table(i) := 'REF*LS*' || ls_coil_org_num;
      i := i + 1;
      
      li_hl01 := li_hl01 + 1;
      li_rowcount := arconic_856_cur%ROWCOUNT;
      x12_table(li_td1) := 'TD1*PLT90*' || to_char(li_rowcount);
      
      ls_enduser_part_prev := ls_enduser_part; --Alex Gerlants. 10/13/2025. 2436_Arconic_856_Multiple_Part
  END LOOP; --End of 'FOR skidinfo_rec IN arconic_856_cur LOOP'
  --Skid loop end ------------------------------------------------------------------

  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                  to_char(li_rowcount + ll_shipment_pc);
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  -- Write X.12 to file
  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
  END LOOP;
  utl_file.fclose(edi_file_handle);

  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE,
         edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;
  
  INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (ll_edi_file_id,
     '039630926',
     ls_su,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856');
  COMMIT;
 

  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  --exception
  --   when invalid_operation
  --   then
  --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

  --  when others
  --  then
  --      DBMS_OUTPUT.PUT_LINE ('System Error');
  --      UTL_FILE.FCLOSE(edi_file_handle);

  RETURN 1;
END edi_arconic_856_X12_alex2;
--------------------------------------------------------
--  DDL for Function EDI_ARCONIC_856_X12_RERUN
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_ARCONIC_856_X12_RERUN" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*
  Aluminum Blanking: Ford Supplier Code: ZZ R0P7A
                     DUNS: 01 039630926T
  Customer: Arconic-TN (2784)
*/
   --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50);

  --edi_loc varchar2(50):='/tmp';
  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_prefix VARCHAR2(50) := 's_arconic_856_'; --Production
  --edi_file_prefix VARCHAR2(50) := 's_arconic_856_'; --Development
  edi_file_handle utl_file.file_type;

  li_customer_id    shipment.customer_id%TYPE;
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;

  -- ls_sender_vanid varchar2 (50);
  -- ls_receiver_vanid varchar2 (50);
  -- ls_customer_vanid varchar2(50);
  -- ls_receiver_gs03 varchar2(50);
  -- ls_customer_gs03 varchar2(50);
  --ls_st varchar2(50);
  ls_sf VARCHAR2(50);
  ls_eq_type VARCHAR2(10);  -- Added by Patrick Reynolds 11/30/2016
  ls_su      VARCHAR2(50);
  ls_st_duns VARCHAR2(50);
  ls_po      VARCHAR2(30);
  ls_auth_code   VARCHAR2(32);
  ll_gs_log  INTEGER;
  ll_st_log  INTEGER;
  ll_bsn_log INTEGER;

  ls_today VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD'); --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  ls_today_2digits_year VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD'); --Alex Gerlants. 10/16/2018. Test
  ls_now   VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  li_rowcount INTEGER;
  li_hl01 INTEGER;
  ll_shipment_nt INTEGER;
  ll_shipment_gt INTEGER;
  ll_shipment_pc INTEGER;
  li_td1 INTEGER;
  li_rc  INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_vehicle_id_prefix VARCHAR2(50);  -- Added by Patrick Reynolds 11/30/2016
  ls_scac              carrier.scac%TYPE;
  ls_carrier_full_name VARCHAR2(18);
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_carrier_initial   VARCHAR2(50);  -- Not used in stored procedure.  Discovered by Patrick Reynolds 11/30/2016
  ldt_shipment         DATE;
   ll_temp         INTEGER;
  ls_enduser_part VARCHAR2(50);
  li_des_id       INTEGER;

  ll_edi_file_id INTEGER;

  ls_lot_num VARCHAR2(32);
  ls_coil_id VARCHAR2(32);
  ls_des_cust_name VARCHAR2(18);
  
  ls_coil_org_num		        coil.coil_org_num%TYPE; --Alex Gerlants. 01/25/2019
  ll_coil_gauge		          coil.coil_gauge%TYPE;   --Alex Gerlants. 01/25/2019
  ll_coil_width		          coil.coil_width%TYPE;   --Alex Gerlants. 01/25/2019
  ld_ship_date              date;
  li_is_novelis             integer;
  ln_skid_type_if_whed      sheet_skid.skid_type_if_whed%TYPE;   --Alex Gerlants. 04/01/2019
  scrap_item                integer;

  CURSOR arconic_856_cur IS
    SELECT sheet_packing_item.sh_packing_item,
           'MULTIPLE' lot_num,
           'MULTIPLE' coil_id,
           customer_order.orig_customer_po,
           customer_order.order_abc_num,
           customer_order.enduser_po,
           customer_order.created_date,
           order_item.order_item_num,
           order_item.enduser_part_num,
           order_item.supplier_code,
           order_item.gauge,
           sheet_skid. ab_job_num,
           sheet_skid.sheet_skid_num,
           sheet_skid.sheet_skid_display_num, --added by Victor H. on 06-2012 for Novelis locatio code request
           sheet_skid.sheet_net_wt,
           sheet_skid.sheet_tare_wt,
           sheet_skid. skid_pieces,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_theoretical_wt,
           NULL done
      FROM customer_order,
           order_item,
           sheet_skid,
           ab_job,
           shipment,
           sheet_packing_item
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
/*      
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
  --      (SHIPMENT.SHIPMENT_EDI856_DATE is NULL);
*/
  --TYPE skidinfo_tabletype IS TABLE OF arconic_856_cur%ROWTYPE INDEX BY BINARY_INTEGER;
  --skidinfo_table skidinfo_tabletype;
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table    store_tabletype;
  i            BINARY_INTEGER := 0;
  skidinfo_rec arconic_856_cur%ROWTYPE;

  /*CURSOR packing_list_same_bol IS
  SELECT packing_list
    FROM shipment
   WHERE bill_of_lading = ll_bill_of_lading;*/

  CURSOR c_ship_to IS
    SELECT DISTINCT des_sh_cust_id --, PACKING_LIST
      FROM shipment
     WHERE bill_of_lading = ll_bill_of_lading
       AND shipment.shipment_status = 0;
  --ORDER BY PACKING_LIST;
  
  cursor c_coil is
  select distinct 
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num,
         coil.coil_gauge,
         coil.coil_width
         --process_coil.coil_abc_num
         --outbound_edi_transaction.transaction_time,
         --outbound_edi_transaction.edi_file_name
  from   customer_order
         join order_item on order_item.order_abc_num = customer_order.order_abc_num
         join ab_job on ab_job.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
         join sheet_skid on sheet_skid.ab_job_num = ab_job.ab_job_num
         join sheet_packing_item on sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
         join shipment on shipment.packing_list = sheet_packing_item.packing_list
         join process_coil on process_coil.ab_job_num = ab_job.ab_job_num
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         --join outbound_edi_transaction on outbound_edi_transaction.edi_file_id = shipment.edi_file_id_856
  --where  shipment.packing_list = 105586 --Production
  where  shipment.packing_list = al_packing_list 
  order by
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num;

BEGIN
  
  -- Get Customer ID, End user ID, authorization code
  select   customer_id, des_sh_cust_id, nvl(shipment_athorization_code, 'NA')
  into     li_customer_id, li_des_sh_cust_id, ls_auth_code
  from     shipment
  where    shipment.packing_list = al_packing_list;
  
  if not SQL%FOUND then
    return - 1;
  end if;
  
  if not li_customer_id = 2784 then --Arconic TN only
    return 200;
  end if;
  
  /*
  select shipment_edi856_date
  into   ld_ship_date
  from   shipment
  where  shipment.packing_list = al_packing_list;
   
  if not (ld_ship_date is null) then --ASN already sent
    return 100;
  end if;
  */
  
  select max(sc_packing_item)
  into   scrap_item
  from   scrap_packing_item
  where  packing_list = al_packing_list;  
  
  if scrap_item > 0 then
    return 1;
  end if;
  
  select count(*)
  into   li_rowcount
  from   reject_coil_packing_item
         join coil on coil.coil_abc_num = reject_coil_packing_item.coil_abc_num
         join shipment on shipment.packing_list = reject_coil_packing_item.packing_list
         join customer on customer.customer_id = shipment.customer_id
  where  shipment.packing_list = al_packing_list;
  
  if li_rowcount > 0 then
    return 1;
  end if;

  edi_loc := dbo.get_edi_destination('EDI_DIR');



  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(sheet_skid.sheet_net_wt),
         SUM(sheet_skid.sheet_net_wt) + SUM(sheet_skid.sheet_tare_wt),
         SUM(sheet_skid.skid_pieces)
    INTO ll_shipment_nt, ll_shipment_gt, ll_shipment_pc
    FROM sheet_skid, sheet_packing_item, shipment
   WHERE shipment.packing_list = sheet_packing_item.packing_list
     AND sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
     AND shipment.packing_list = al_packing_list;
     
  IF ll_shipment_pc = 0 THEN
    RETURN 2; --Nothing to do here
  END IF;

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  ls_sf := '039630926';

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.vehicle_id_prefix, '9999'),
         nvl(shipment.equipment_type, 'NA'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'PT'), -- Protected Trailer
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE)
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_vehicle_id_prefix,
         ls_eq_type,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_carrier_initial,
         ldt_shipment
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;

  SELECT nvl(customer_duns_number_string, '00000000'), customer_short_name
    INTO ls_st_duns, ls_des_cust_name
    FROM customer
   WHERE customer_id = li_des_sh_cust_id;

  IF (ls_st_duns = '00000000') THEN
    ls_st_duns := '';
  END IF; --Arconic does not need destination DUNS

  SELECT nvl(customer_duns_number_string, '00000000')
    INTO ls_su
    FROM customer
   WHERE customer_id = li_customer_id;
  IF (ls_su = '00000000') THEN
    RETURN 200;
  END IF; --No Supplier DUNS

  -- Get SCAC(Standard Carrier Alpha Code)
  SELECT nvl(carrier.scac, 'NONE'), LPAD(carrier.carrier_full_name, 17)
    INTO ls_scac, ls_carrier_full_name
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);

  -- Generate Header Info.
  --Production
  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *01*039630926T     *01*961613887      *' ||
                  ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*P*>';
  
  --Development                
  --x12_table(i) := 'ISA*00*' ||
  --                '          *00*          *ZZ*2NDSFTP        *ZZ*ARNCQFMW       *' ||
  --                ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
  --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T*>';
                  
  i := i + 1;

  --Alex Gerlants. 10/16/2018. Changed from "002002" to "004010"
  --Production
  x12_table(1) := 'GS*SH*R0P7ATN*' || '961613887' || '*' || ls_today || '*' ||
                  ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  --Development
  --x12_table(1) := 'GS*SH*2NDSFTP' || 'TN*ARNCQFMW' || '*' || ls_today || '*' ||
  --               ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;

  x12_table(i) := 'BSN*00*' || to_char(al_packing_list) || '*' || ls_today || '*' ||
                  ls_now;
  i := i + 1;

  x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                                                      to_char(ldt_shipment, 'HH24MI');
  i := i + 1;
  
  x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                  to_char(ldt_shipment, 'HH24MI');
  i := i + 1;

  -- First Level HL
  x12_table(i) := 'HL*01**S';
  i := i + 1;

  x12_table(i) := 'MEA*WT*G*' || to_char(ll_shipment_gt) || '*LB';
  i := i + 1;
  x12_table(i) := 'MEA*WT*N*' || to_char(ll_shipment_nt) || '*LB';
  i := i + 1;
  x12_table(i) := 'TD1*PLT90*' || to_char(li_rowcount);
  li_td1 := i;
  i := i + 1;
  x12_table(i) := 'TD5*B*2*' || ls_scac || '*M*' || ls_carrier_full_name;
  i := i + 1;

  x12_table(i) := 'TD3*' || ls_carrier_desc_code || '*' || ls_scac || '*' || ls_vehicle_id_prefix;
  i := i + 1;
  x12_table(i) := 'REF*BM*' || to_char(al_packing_list);
  i := i + 1;
  x12_table(i) := 'REF*PK*' || to_char(al_packing_list);
  i := i + 1;

  x12_table(i) := 'REF*EQ*' || ls_eq_type;
  i := i + 1;

  x12_table(i) := 'REF*MB*' || to_char(ll_bill_of_lading);
  i := i + 1;
  SELECT COUNT(*)
    INTO ll_temp
    FROM shipment
   WHERE shipment.bill_of_lading = ll_bill_of_lading
     AND shipment.shipment_status = 0;

  li_des_id := 1;
  
  x12_table(i) := 'N1*ST*' || ls_des_cust_name || '*1*' || ls_st_duns;
  i := i + 1;
  x12_table(i) := 'N1*SF*Aluminum Blanking Co*1*' || ls_sf;
  i := i + 1;
  x12_table(i) := 'N1*SU**1*' || ls_su;
  i := i + 1;

  -- Second Level HL based on End User PO( only one part# is included in one shipement per FORD's request)
  OPEN arconic_856_cur;
  FETCH arconic_856_cur
    INTO skidinfo_rec;

  SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
    INTO ls_enduser_part
    FROM "ORDER_ITEM", "SHEET_SKID"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
     AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
     AND ("SHEET_SKID"."SHEET_SKID_NUM" = skidinfo_rec.sheet_skid_num);

  x12_table(i) := 'HL*02*01*O';
  i := i + 1;
  IF ls_enduser_part IS NULL THEN
    ls_enduser_part := 'NA';
  END IF;
  x12_table(i) := 'LIN**BP*' || ls_enduser_part;
  i := i + 1;
  x12_table(i) := 'SN1**' || to_char(ll_shipment_pc) || '*EA*0';
  i := i + 1;

  SELECT "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO"
    INTO ls_po
    FROM "SHEET_SKID", "CUSTOMER_ORDER"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
         "CUSTOMER_ORDER"."ORDER_ABC_NUM")
     AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num);

  x12_table(i) := 'PRF*' || ls_po || '***' ||
                  to_char(skidinfo_rec.created_date, 'YYYYMMDD');
  i := i + 1;
  --   end if;

  CLOSE arconic_856_cur;

   --  Novelis SAP order number
 x12_table(i) := 'REF*IL*' || ls_auth_code;
 i := i + 1;
  --  end if;

  -- Third Level HL Under a P.O.
  li_hl01 := 3;

  --Skid loop begin ----------------------------------------------------------------
  FOR skidinfo_rec IN arconic_856_cur LOOP
    
      --In case of a split skid, we are creating just 1 HL for this skid
      --with just 1 coil for this skid.
      select distinct 
             coil.coil_org_num,
             coil.coil_gauge,
             coil.coil_width,
             coil.lot_num,
             nvl(skid_type_if_whed, -1) --Alex Gerlants. 04/01/2019
      into   ls_coil_org_num,
             ll_coil_gauge,
             ll_coil_width,
             ls_lot_num,
             ln_skid_type_if_whed --Alex Gerlants. 04/01/2019
      FROM "COIL",   
           "PRODUCTION_SHEET_ITEM",   
           "SHEET_SKID",   
           "SHEET_SKID_DETAIL",   
           "PROCESS_COIL"  
     WHERE ( "COIL"."COIL_ABC_NUM" = "PRODUCTION_SHEET_ITEM"."COIL_ABC_NUM" ) and  
           ( "SHEET_SKID_DETAIL"."SHEET_SKID_NUM" = "SHEET_SKID"."SHEET_SKID_NUM" ) and  
           ( "SHEET_SKID_DETAIL"."PROD_ITEM_NUM" = "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NUM" ) and  
           ( "COIL"."COIL_ABC_NUM" = "PROCESS_COIL"."COIL_ABC_NUM" ) and  
           ( "PRODUCTION_SHEET_ITEM"."AB_JOB_NUM" = "PROCESS_COIL"."AB_JOB_NUM" ) and  
           ( (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num)  ) and
           ( (rownum = 1)  ); --We need just 1 coil for each skid
  
      --Alex Gerlants. 04/01/2019. Begin
      if ln_skid_type_if_whed > -1 then --Warehouse skid
          --Get gauge and part width
          select distinct order_item.gauge,
                 f_get_part_width_per_job(ab_job.ab_job_num) 
          into   ll_coil_gauge,
                 ll_coil_width
          from   sheet_skid
                 join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
                 join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
                 join customer_order on customer_order.order_abc_num = order_item.order_abc_num
          where  sheet_skid_num = skidinfo_rec.sheet_skid_num
          and    (order_item.gauge is not null and f_get_part_width_per_job(sheet_skid.ab_job_num) is not null)
          and    rownum = 1;
      end if;
      --Alex Gerlants. 04/01/2019. End
  
      IF length(to_char(li_hl01)) = 1 THEN
        x12_table(i) := 'HL*0' || to_char(li_hl01) || '*02*I';
        i := i + 1;
      ELSE
        x12_table(i) := 'HL*' || to_char(li_hl01) || '*02*I';
        i := i + 1;
      END IF;

      x12_table(i) := 'SN1**1*PF';
      i := i + 1;
                        
      x12_table(i) := 'MEA*WT*N*' || to_char(skidinfo_rec.sheet_net_wt) ||
                      '*01';
      i := i + 1;
                        
      x12_table(i) := 'MEA*CT*NL*' || to_char(skidinfo_rec.skid_pieces) ||
                      '*PC';
      i := i + 1;

      x12_table(i) := 'MEA*WT*G*' || to_char(skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt) || '*01';
      i := i + 1;
      
      x12_table(i) := 'MEA*PD*GG*' || ll_coil_gauge;
      i := i + 1;
      
      x12_table(i) := 'MEA*PD*WD*' || ll_coil_width;
      i := i + 1;
                        
      x12_table(i) := 'REF*BT*' || ls_lot_num;
      i := i + 1;

      x12_table(i) := 'REF*SE*' || skidinfo_rec.sheet_skid_display_num; --added by Victor H. on 06-2012 for Novelis locatio code request
      i := i + 1;
      
      x12_table(i) := 'REF*LS*' || ls_coil_org_num;
      i := i + 1;
      
      li_hl01 := li_hl01 + 1;
      li_rowcount := arconic_856_cur%ROWCOUNT;
      x12_table(li_td1) := 'TD1*PLT90*' || to_char(li_rowcount);
  END LOOP; --End of 'FOR skidinfo_rec IN arconic_856_cur LOOP'
  --Skid loop end ------------------------------------------------------------------

  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                  to_char(li_rowcount + ll_shipment_pc);
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  -- Write X.12 to file
  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
  END LOOP;
  utl_file.fclose(edi_file_handle);

  /*
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE,
         edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;
  
  INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (ll_edi_file_id,
     '039630926',
     ls_su,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856');
  COMMIT;
  */

  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  --exception
  --   when invalid_operation
  --   then
  --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

  --  when others
  --  then
  --      DBMS_OUTPUT.PUT_LINE ('System Error');
  --      UTL_FILE.FCLOSE(edi_file_handle);

  RETURN 1;
END edi_arconic_856_X12_rerun;
--------------------------------------------------------
--  DDL for Function EDI_CONST_856_X12
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_CONST_856_X12" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*


  */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR');

  --edi_loc varchar2(50):='/tmp';
  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_prefix VARCHAR2(50) := 'S_constellium_856_'; --Production
  --edi_file_prefix VARCHAR2(50) := 's_constellium_856_'; --Development
  edi_file_handle utl_file.file_type;

  li_customer_id    shipment.customer_id%TYPE;
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;
  ls_sf VARCHAR2(50);
  ls_eq_type VARCHAR2(10);
  ls_su      VARCHAR2(50);
  ls_st_duns VARCHAR2(50);
  ls_po      VARCHAR2(30);
  ls_auth_code   VARCHAR2(32);
  ll_gs_log  INTEGER;
  ll_st_log  INTEGER;
  ll_bsn_log INTEGER;

  ls_today VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD'); --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  ls_today_2digits_year VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD'); --Alex Gerlants. 10/16/2018. Test
  ls_now   VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  li_rowcount INTEGER;
  li_hl01 INTEGER;
  ll_shipment_nt INTEGER;
  ll_shipment_gt INTEGER;
  ll_shipment_pc INTEGER;
  li_td1 INTEGER;
  li_rc  INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_vehicle_id_prefix VARCHAR2(50);
  ls_scac              carrier.scac%TYPE;
  ls_carrier_full_name VARCHAR2(18);
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_carrier_initial   VARCHAR2(50);  -- Not used in stored procedure.  Discovered by Patrick Reynolds 11/30/2016
  ldt_shipment         DATE;
   ll_temp         INTEGER;
  ls_enduser_part VARCHAR2(50);
  li_des_id       INTEGER;

  ll_edi_file_id INTEGER;

  ls_lot_num VARCHAR2(32);
  ls_coil_id VARCHAR2(32);
  ls_des_cust_name VARCHAR2(18);
  
  ls_coil_org_num		        coil.coil_org_num%TYPE; --Alex Gerlants. 01/25/2019
  ll_coil_gauge		          coil.coil_gauge%TYPE;   --Alex Gerlants. 01/25/2019
  ll_coil_width		          coil.coil_width%TYPE;   --Alex Gerlants. 01/25/2019
  ld_ship_date              date;
  li_is_constellium         integer;
  ln_skid_type_if_whed      sheet_skid.skid_type_if_whed%TYPE;   --Alex Gerlants. 04/01/2019
  li_skid_count             integer;
  ls_cust_short_name        customer.customer_short_name%TYPE;
  ll_coil_abc_num		        coil.coil_abc_num%TYPE;
  ls_cust_prod_line_id      order_item.cust_prod_line_id%TYPE;
  ls_orig_customer_po       customer_order.orig_customer_po%TYPE;
  ls_vo                     coil.vo%TYPE;
  ls_coil_alloy             coil.coil_alloy%TYPE;
  ls_coil_temper            coil.coil_temper%TYPE;
  ld_lineal_feed            inbound_coil.lineal_feed%TYPE;
  ld_created_date           customer_order.created_date%TYPE;
  li_count                  integer;
  ls_plant_code             customer.plant_code%TYPE;

  CURSOR const_856_cur IS
    SELECT sheet_packing_item.sh_packing_item,
           'MULTIPLE' lot_num,
           'MULTIPLE' coil_id,
           customer_order.orig_customer_po,
           customer_order.order_abc_num,
           customer_order.enduser_po,
           customer_order.created_date,
           order_item.order_item_num,
           order_item.enduser_part_num,
           order_item.supplier_code,
           order_item.gauge,
           sheet_skid. ab_job_num,
           sheet_skid.sheet_skid_num,
           sheet_skid.sheet_skid_display_num, --added by Victor H. on 06-2012 for Novelis locatio code request
           sheet_skid.sheet_net_wt,
           sheet_skid.sheet_tare_wt,
           sheet_skid. skid_pieces,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_theoretical_wt,
           NULL done
      FROM customer_order,
           order_item,
           sheet_skid,
           ab_job,
           shipment,
           sheet_packing_item
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
       
  cursor po_cur is
  select distinct customer_order.orig_customer_po, customer_order.created_date
  from   sheet_packing_item
         join sheet_skid on sheet_skid.sheet_skid_num = sheet_packing_item.sheet_skid_num
         join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
         join process_coil on ab_job.ab_job_num = process_coil.ab_job_num
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         join customer_order on customer_order.order_abc_num = sheet_skid.ref_order_abc_num
  where  sheet_packing_item.packing_list = al_packing_list;

  --TYPE skidinfo_tabletype IS TABLE OF const_856_cur%ROWTYPE INDEX BY BINARY_INTEGER;
  --skidinfo_table skidinfo_tabletype;
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table    store_tabletype;
  i            BINARY_INTEGER := 0;
  skidinfo_rec const_856_cur%ROWTYPE;
  po_rec       po_cur%ROWTYPE;
  

  CURSOR c_ship_to IS
    SELECT DISTINCT des_sh_cust_id
      FROM shipment
     WHERE bill_of_lading = ll_bill_of_lading
       AND shipment.shipment_status = 0;
  
  cursor c_coil is
  select distinct 
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num,
         coil.coil_gauge,
         coil.coil_width
  from   customer_order
         join order_item on order_item.order_abc_num = customer_order.order_abc_num
         join ab_job on ab_job.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
         join sheet_skid on sheet_skid.ab_job_num = ab_job.ab_job_num
         join sheet_packing_item on sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
         join shipment on shipment.packing_list = sheet_packing_item.packing_list
         join process_coil on process_coil.ab_job_num = ab_job.ab_job_num
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         --join outbound_edi_transaction on outbound_edi_transaction.edi_file_id = shipment.edi_file_id_856
  --where  shipment.packing_list = 105586 --Production
  where  shipment.packing_list = al_packing_list --Development
  order by
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num;
  
  

BEGIN
  
  select dbo.f_is_constellium(al_packing_list)
  into   li_is_constellium
  from   dual;
  
  if li_is_constellium = 0 then --Customer is NOT Constellium
    return 1; --Nothing to do here
  end if;
  

  select shipment_edi856_date
  into   ld_ship_date
  from   shipment
  where  shipment.packing_list = al_packing_list;
   
  if not (ld_ship_date is null) then --ASN already sent
    return 100;
  end if;


  

  -- edi_alcan_870; -- Send 870 first

  -- Get Customer ID, End user ID
  --SELECT customer_id, des_sh_cust_id
  --  INTO li_customer_id, li_des_sh_cust_id
  -- FROM shipment
  -- WHERE shipment.packing_list = al_packing_list;
  --IF NOT SQL%FOUND THEN
 --   RETURN - 1;
  --END IF;

  -- Get Customer ID, End user ID, authorization code
  SELECT customer_id, des_sh_cust_id, nvl(shipment_athorization_code, 'NA')
    INTO li_customer_id, li_des_sh_cust_id, ls_auth_code
  FROM shipment
  WHERE shipment.packing_list = al_packing_list;
  IF NOT SQL%FOUND THEN
   RETURN - 1;
  END IF;

  -- dbms_output.put_line (to_char(li_customer_id) || '  ' || to_char(li_des_sh_cust_id) );

  /*
  IF NOT (li_customer_id IN (34, 35, 10, 1153, 1459, 2582)) -- AND (li_des_sh_cust_id IN (
   THEN

    --***********************************************************************************************88
    --IF NOT ((li_customer_id IN (34,35,10,1153)) AND (li_des_sh_cust_id IN (SELECT CUSTOMER_ID
    --FROM CUSTOMER
    --WHERE CUSTOMER_DUNS_NUMBER_STRING is not null))) THEN

    RETURN 200;
  END IF;
  */

  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(sheet_skid.sheet_net_wt),
         SUM(sheet_skid.sheet_net_wt) + SUM(sheet_skid.sheet_tare_wt),
         SUM(sheet_skid.skid_pieces)
    INTO ll_shipment_nt, ll_shipment_gt, ll_shipment_pc
    FROM sheet_skid, sheet_packing_item, shipment
   WHERE shipment.packing_list = sheet_packing_item.packing_list
     AND sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
     AND shipment.packing_list = al_packing_list;
  IF ll_shipment_pc = 0 THEN
    RETURN 100;
  END IF; -- empty shipment

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  -- Retrieve ABCO info
  -- ls_sender_vanid := '3010007080';
  --ls_ic := 'R0P7A';

  -- Retrieve ALCAN supply code and Ford Stamping Plant location code
  --SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf
  --FROM customer_customer  WHERE o_customer_id = li_customer_id and e_customer_id = 49;  --Ford customer_id =49

  ls_sf := '039630926';
  --SELECT NVL(communication_code,'UNKNOWN') INTO ls_st FROM customer_system
  --WHERE customer_id = li_des_sh_cust_id;

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.vehicle_id_prefix, '9999'),
         nvl(shipment.equipment_type, 'NA'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'PT'), -- Protected Trailer
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE)
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_vehicle_id_prefix,
         ls_eq_type,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_carrier_initial,
         ldt_shipment
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;

  --Check all packing_lists are done against a BOL
  /*
  for pl_rec in packing_list_same_bol loop
      select shipment.shipment_status into ll_temp from shipment
             where shipment.packing_list = pl_rec.packing_list;
      if ll_temp > 0 then
         return pl_rec.packing_list;
      end if;

  end loop;
  */
  --End of packing list checking

  --SELECT nvl(customer_duns_number_string, '00000000'), customer_short_name
  SELECT nvl(customer_duns_number_string, '00000000'), nvl(plant_code, '00000000'), customer_short_name
--    INTO ls_st_duns, ls_des_cust_name
    INTO ls_st_duns, ls_plant_code, ls_des_cust_name --Alex Gerlants. 02/12/2026. Email from Troy received on Thu 2/12/2026 9:09 AM
    FROM customer
   WHERE customer_id = li_des_sh_cust_id;

   if (ls_plant_code = '00000000') THEN
      ls_plant_code := ls_st_duns;
      
      IF (ls_st_duns = '00000000') THEN
        RETURN 200;
      END IF; --No Ship to DUNS
   end if;

  SELECT nvl(customer_duns_number_string, '00000000'), upper(customer_short_name)
    INTO ls_su, ls_cust_short_name
    FROM customer
   WHERE customer_id = li_customer_id;
  IF (ls_su = '00000000') THEN
    RETURN 200;
  END IF; --No Supplier DUNS

  -- Get SCAC(Standard Carrier Alpha Code)
  SELECT nvl(carrier.scac, 'NONE'), LPAD(carrier.carrier_full_name, 17)
    INTO ls_scac, ls_carrier_full_name
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);
  
  --Email from Troy Haag received on Fri 5/20/2022 4:29 PM.
  --Approval email from Lisa received on Mon 5/23/2022 10:10 AM.
  --Change the last character from "*" to "@
  --Production
  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *01*039630926T     *01*043207177      *' ||
                  ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*P*@';
  
  --Development                
  --x12_table(i) := 'ISA*00*' ||
  --                '          *00*          *ZZ*2NDSFTP        *01*043207177      *' ||
  --                ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
  --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';
                  
  i := i + 1;

  --Alex Gerlants. 10/16/2018. Changed from "002002" to "004010"
  --Production
  x12_table(1) := 'GS*SH*039630926T*' || '043207177' || '*' || ls_today || '*' ||
                  ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  --Development
  --x12_table(1) := 'GS*SH*2NDSFTP*' || '043207177' || '*' || ls_today || '*' ||
  --               ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;
  --x12_table(i):= 'BSN*00*' || to_char(ll_bill_of_lading) || '*' || ls_today || '*' || ls_now;
  x12_table(i) := 'BSN*00*' || to_char(al_packing_list) || '*' || ls_today || '*' ||
                  ls_now;
  i := i + 1;
  
  --Alex Gerlants. 08/07/2018.
  --Changed to populate with actual ship date instead of current date and time.
  --The reason is that when we send 856 on a later date, this date is not correct.
  --x12_table(i) := 'DTM*011*' || ls_today || '*' || ls_now;
  --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                                                      to_char(ldt_shipment, 'HH24MI');
  i := i + 1;
  
  --Alex Gerlants. 10/18/2018. Changed from "YYMMDD" to "YYYYMMDD"
  --Moved here from the below
  x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                  to_char(ldt_shipment, 'HH24MI');
  i := i + 1;

  -- First Level HL
  x12_table(i) := 'HL*01**S*1';
  i := i + 1;
  
  select    count(*)
  into      li_skid_count
  from      sheet_packing_item
  where     packing_list = al_packing_list;
  
  x12_table(i) := 'TD1*PLT90*' || to_char(li_skid_count) || '****G*' || to_char(ll_shipment_gt) || '*LB';
  li_td1 := i;
  i := i + 1;
  
  x12_table(i) := 'TD1*PLT90*' || to_char(li_skid_count) || '****N*' || to_char(ll_shipment_nt) || '*LB';
  li_td1 := li_td1 + i;
  i := i + 1;
  
  x12_table(i) := 'TD5*B*2*' || ls_scac || '*M*' || ltrim(rtrim(ls_carrier_full_name)) || '*CC';
  i := i + 1;
  
  x12_table(i) := 'TD3*' || ls_carrier_desc_code || '*' || ls_scac || '*' || ls_vehicle_id_prefix;
  i := i + 1;
  
  x12_table(i) := 'REF*CN*' || to_char(al_packing_list);
  i := i + 1;
  
  x12_table(i) := 'REF*BM*' || to_char(al_packing_list);
  i := i + 1;  

  SELECT COUNT(*)
    INTO ll_temp
    FROM shipment
   WHERE shipment.bill_of_lading = ll_bill_of_lading
     AND shipment.shipment_status = 0;
     
  --Alex Gerlants. 10/16/2018. Removed 2 lines below
  --x12_table(i) := 'REF*SS*' || to_char(ll_temp);
  --i := i + 1;
  li_des_id := 1;
  
  x12_table(i) := 'N1*SF*Aluminum Blanking Co*1*' || ls_sf;
  i := i + 1;
  
  x12_table(i) := 'N1*MF*' || rtrim(ltrim(ls_cust_short_name)) || '*1*' || ls_su;
  i := i + 1;
  
  --x12_table(i) := 'N1*ST*' || rtrim(ltrim(ls_des_cust_name)) || '*1*' || ls_st_duns;
  x12_table(i) := 'N1*ST*' || rtrim(ltrim(ls_des_cust_name)) || '*1*' || ls_plant_code; --Alex Gerlants. 02/12/2026. Email from Troy received on Thu 2/12/2026 9:09 AM
  i := i + 1;
  
  --x12_table(i) := 'N1*MA*' || rtrim(ltrim(ls_des_cust_name)) || '*1*' || ls_st_duns;
  x12_table(i) := 'N1*MA*' || rtrim(ltrim(ls_des_cust_name)) || '*1*' || ls_plant_code; --Alex Gerlants. 02/12/2026. Email from Troy received on Thu 2/12/2026 9:09 AM
  i := i + 1;

  -- Second Level HL based on End User PO( only one part# is included in one shipement per FORD's request)
  OPEN const_856_cur;
  FETCH const_856_cur
    INTO skidinfo_rec;
  --    ls_enduser_part := skidinfo_rec.ENDUSER_PART_NUM;
  --    ls_enduser_po := skidinfo_rec.ENDUSER_PO;

  /*
    if skidinfo_rec.ORIG_CUSTOMER_PO IN ('68Q68517') then    --Do NOT send 856 to Ford for some flipping related POs )
         edi_file_prefix := 'nosend_alcan_ford_ford';
    end if;
  */

  SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
    INTO ls_enduser_part
    FROM "ORDER_ITEM", "SHEET_SKID"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
     AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
     AND ("SHEET_SKID"."SHEET_SKID_NUM" = skidinfo_rec.sheet_skid_num);

  /*
      SELECT "CUSTOMER_ORDER"."ENDUSER_PO" into ls_enduser_po
             FROM "SHEET_SKID",
                  "CUSTOMER_ORDER"
                  WHERE ( "SHEET_SKID"."REF_ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM" ) and
                        (SHEET_SKID.SHEET_SKID_NUM = skidinfo_rec.SHEET_SKID_NUM);
  */

  x12_table(i) := 'HL*02*01*O';
  i := i + 1;
  IF ls_enduser_part IS NULL THEN
    ls_enduser_part := 'NA';
  END IF;
  --x12_table(i) := 'LIN**BP*' || ls_enduser_part;
  --i := i + 1;
  --x12_table(i) := 'SN1**' || to_char(ll_shipment_pc) || '*EA*0';
  --i := i + 1;

  --
  --ls_po := skidinfo_rec.ORIG_CUSTOMER_PO;
  SELECT "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO"
    INTO ls_po
    FROM "SHEET_SKID", "CUSTOMER_ORDER"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
         "CUSTOMER_ORDER"."ORDER_ABC_NUM")
     AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num);

  --IF INSTR(skidinfo_rec.ORIG_CUSTOMER_PO,'-') > 0
  --New PO format for Novelis SAP include '-'
  /*IF instr(ls_po, '-') > 0 THEN
    ls_po := substr(ls_po, 0, instr(ls_po, '-') - 1);
  END IF;*/

  for po_rec in po_cur loop --******************************************************
    ls_orig_customer_po := po_rec.orig_customer_po;
    ld_created_date := po_rec.created_date;
    
    x12_table(i) := 'PRF*' || ls_orig_customer_po || '***' ||
                    to_char(ld_created_date, 'YYYYMMDD');
    i := i + 1;
  end loop;
  --   end if;

  CLOSE const_856_cur;

   --  Novelis SAP order number
 --x12_table(i) := 'REF*IL*' || ls_auth_code;
 --i := i + 1;
  --  end if;

  -- Third Level HL Under a P.O.
  li_hl01 := 3;

  --Skid loop begin ----------------------------------------------------------------
  FOR skidinfo_rec IN const_856_cur LOOP
    
      --In case of a split skid, we are creating just 1 HL for this skid
      --with just 1 coil for this skid.
      select distinct
             coil.coil_abc_num, 
             coil.coil_org_num,
             coil.coil_gauge,
             coil.coil_width,
             coil.lot_num,
             nvl(skid_type_if_whed, -1),
             coil.vo,
             coil.coil_alloy,
             coil.coil_temper
      into   ll_coil_abc_num,
             ls_coil_org_num,
             ll_coil_gauge,
             ll_coil_width,
             ls_lot_num,
             ln_skid_type_if_whed, --Alex Gerlants. 04/01/2019
             ls_vo,
             ls_coil_alloy,
             ls_coil_temper
      FROM "COIL",   
           "PRODUCTION_SHEET_ITEM",   
           "SHEET_SKID",   
           "SHEET_SKID_DETAIL",   
           "PROCESS_COIL"  
     WHERE ( "COIL"."COIL_ABC_NUM" = "PRODUCTION_SHEET_ITEM"."COIL_ABC_NUM" ) and  
           ( "SHEET_SKID_DETAIL"."SHEET_SKID_NUM" = "SHEET_SKID"."SHEET_SKID_NUM" ) and  
           ( "SHEET_SKID_DETAIL"."PROD_ITEM_NUM" = "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NUM" ) and  
           ( "COIL"."COIL_ABC_NUM" = "PROCESS_COIL"."COIL_ABC_NUM" ) and  
           ( "PRODUCTION_SHEET_ITEM"."AB_JOB_NUM" = "PROCESS_COIL"."AB_JOB_NUM" ) and  
           ( (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num)  ) and
           ( (rownum = 1)  ); --We need just 1 coil for each skid
  
      --Alex Gerlants. 04/01/2019. Begin
      --if ln_skid_type_if_whed > -1 then --Warehouse skid
          --Get gauge and part width
          select distinct order_item.gauge,
                 f_get_part_width_per_job(ab_job.ab_job_num),
                 enduser_part_num,
                 nvl(cust_prod_line_id, '')
          into   ll_coil_gauge,
                 ll_coil_width,
                 ls_enduser_part,
                 ls_cust_prod_line_id
          from   sheet_skid
                 join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
                 join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
                 join customer_order on customer_order.order_abc_num = order_item.order_abc_num
          where  sheet_skid_num = skidinfo_rec.sheet_skid_num
          and    (order_item.gauge is not null and f_get_part_width_per_job(sheet_skid.ab_job_num) is not null)
          and    rownum = 1;
      --end if;
      --Alex Gerlants. 04/01/2019. End
  
      IF length(to_char(li_hl01)) = 1 THEN
        x12_table(i) := 'HL*0' || to_char(li_hl01) || '*02*I';
        i := i + 1;
      ELSE
        x12_table(i) := 'HL*' || to_char(li_hl01) || '*02*I';
        i := i + 1;
      END IF;
      
      /* Alex Gerlants. 01/02/2023. Comment out begin
      select distinct 
                inbound_coil.vo, inbound_coil.lot, inbound_coil.lineal_feed
      into      ls_vo, ls_lot_num, ld_lineal_feed
      from      inbound_coil
                join inbound_coil_status on inbound_coil_status.coil_number = inbound_coil.coil_number
      where     inbound_coil_status.coil_abc_num = ll_coil_abc_num;
      */
      --Alex Gerlants. 01/02/2023. Comment out end
      
      --Alex Gerlants. 01/02/2023. New SQL statement. Join inbound_coil with coil instead of inbound_coil_status, Begin
      --Count first...just in case
      select    count(*)
      into      li_count
      from      inbound_coil
                join coil on coil.coil_org_num = inbound_coil.coil_number
      where     coil.coil_abc_num = ll_coil_abc_num;
      
      if li_count > 0 then
        select distinct 
                  inbound_coil.vo, inbound_coil.lot, inbound_coil.lineal_feed
        into      ls_vo, ls_lot_num, ld_lineal_feed
        from      inbound_coil
                  join coil on coil.coil_org_num = inbound_coil.coil_number
        where     coil.coil_abc_num = ll_coil_abc_num; 
      else
        ls_vo := '';
        ls_lot_num := '';
        ld_lineal_feed := 0;
      end if;     
      --Alex Gerlants. 01/02/2023. New SQL statement. Join inbound_coil with coil instead of inbound_coil_status. End      
      
    
      x12_table(i) := 'LIN*1*BP*' || ls_enduser_part || '*SN*' || ls_coil_org_num || '*HN*' || ls_lot_num || '*LS*' || to_char(ll_coil_abc_num) || '*JN*' || ls_vo;
      i := i + 1;
      
      x12_table(i) := 'PID*S*55**' || ls_coil_alloy;
      i := i + 1;
      
      x12_table(i) := 'PID*S*16**' || ls_coil_temper;
      i := i + 1;

      x12_table(i) := 'MEA*WT*WT*' || to_char(skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt) ||
                      '*01';
      i := i + 1;
                        
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*WT" to "MEA*CT*NL"
      x12_table(i) := 'MEA*CT*NL*' || to_char(skidinfo_rec.skid_pieces) ||
                      '*PC';
      i := i + 1;

      -- changed to all gross wt per novelis 1/30/2015
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*G" to "MEA*WT*G"
      --x12_table(i) := 'MEA*WT*G*' || to_char(skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt) || '*01';
      --i := i + 1;
 
      x12_table(i) := 'MEA*PD*TH*' || ltrim(rtrim(to_char(ll_coil_gauge, '0.0000')));
      i := i + 1;

      x12_table(i) := 'MEA*PD*WD*' || ll_coil_width;
      i := i + 1;
      
      x12_table(i) := 'MEA*PD*LN*' || to_char(ld_lineal_feed);
      i := i + 1;

      --Alex Gerlants. 10/18/2018. Changed from "REF*LS" to "REF*SE"
      x12_table(i) := 'REF*SE*' || skidinfo_rec.sheet_skid_display_num; --added by Victor H. on 06-2012 for Novelis locatio code request
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      --x12_table(i) := 'REF*LS*' || ls_coil_org_num;
      --i := i + 1;
      
      li_hl01 := li_hl01 + 1;
      li_rowcount := const_856_cur%ROWCOUNT;
      --x12_table(li_td1) := 'TD1*PLT90*' || to_char(li_rowcount);
  END LOOP; --End of 'FOR skidinfo_rec IN const_856_cur LOOP'
  --Skid loop end ------------------------------------------------------------------

  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                  to_char(li_rowcount + ll_shipment_pc);
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  -- Write X.12 to file
  -- To FORD

  /** Write file to /templar/templar/incoming/senddata
  /*
  **/

  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  --edi_file:= 'S_alcan_ford_ford_' || to_char(ll_edi_file_id) ||'.x12';

  -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
  -- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
    --        v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
  END LOOP;
  utl_file.fclose(edi_file_handle);

  --To ALCAN

  /*
  SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;
  SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id_alcan FROM DUAL;
  edi_file:= 'S_alcan_ford_alcan_' || to_char(ll_edi_file_id_alcan) ||'.x12';
  edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');
  x12_table(0) := 'ISA*00*'||'          *00*          *01*039630926T     *09*0015049350011G *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0')||'*0*P**';
  x12_table(1) := 'GS*SH*R0P7A*'||'001504935001' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  x12_table(i-1) :=  'GE*1*' || to_char (ll_gs_log);
  x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');
  for j in 0..i loop
   UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
       v_edi_text_alcan:=v_edi_text_alcan||x12_table(j)||CHR(10);
  end loop;
  UTL_FILE.FCLOSE(edi_file_handle);

  */

  /* The following code added by Tony, for update archive*/

  --  INSERT INTO edi_log (edi_log_timestamp,customer_id,
  --         customer_edi_name,edi_log_contents,edi_file_id,edi_text)
  --    VALUES (SYSDATE,li_customer_id,ll_customer_edi_name,
  --           'EDI:'||ll_customer_edi_name||' generated successfully.',ll_edi_file_id,v_edi_text);
  --   COMMIT;

  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  

  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE,
         edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;


--  COMMIT;

  /* --added by Victor Huang on 06/05 for function acknowlegement
  INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
  VALUES(ll_gs_log, ls_su, sysdate, edi_file);
  COMMIT;*/

  --added by Victor Huang on 12/07 for verifying 997
  INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (ll_edi_file_id,
     '039630926',
     ls_su,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856');
     
  COMMIT;

  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  --exception
  --   when invalid_operation
  --   then
  --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

  --  when others
  --  then
  --      DBMS_OUTPUT.PUT_LINE ('System Error');
  --      UTL_FILE.FCLOSE(edi_file_handle);

  RETURN 1;
END edi_const_856_X12;
--------------------------------------------------------
--  DDL for Function EDI_CONST_856_X12_07222021
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_CONST_856_X12_07222021" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*


  */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR');

  --edi_loc varchar2(50):='/tmp';
  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_prefix VARCHAR2(50) := 'S_constellium_856_'; --Production
  --edi_file_prefix VARCHAR2(50) := 's_constellium_856_'; --Development
  edi_file_handle utl_file.file_type;

  li_customer_id    shipment.customer_id%TYPE;
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;
  ls_sf VARCHAR2(50);
  ls_eq_type VARCHAR2(10);
  ls_su      VARCHAR2(50);
  ls_st_duns VARCHAR2(50);
  ls_po      VARCHAR2(30);
  ls_auth_code   VARCHAR2(32);
  ll_gs_log  INTEGER;
  ll_st_log  INTEGER;
  ll_bsn_log INTEGER;

  ls_today VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD'); --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  ls_today_2digits_year VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD'); --Alex Gerlants. 10/16/2018. Test
  ls_now   VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  li_rowcount INTEGER;
  li_hl01 INTEGER;
  ll_shipment_nt INTEGER;
  ll_shipment_gt INTEGER;
  ll_shipment_pc INTEGER;
  li_td1 INTEGER;
  li_rc  INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_vehicle_id_prefix VARCHAR2(50);
  ls_scac              carrier.scac%TYPE;
  ls_carrier_full_name VARCHAR2(18);
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_carrier_initial   VARCHAR2(50);  -- Not used in stored procedure.  Discovered by Patrick Reynolds 11/30/2016
  ldt_shipment         DATE;
   ll_temp         INTEGER;
  ls_enduser_part VARCHAR2(50);
  li_des_id       INTEGER;

  ll_edi_file_id INTEGER;

  ls_lot_num VARCHAR2(32);
  ls_coil_id VARCHAR2(32);
  ls_des_cust_name VARCHAR2(18);
  
  ls_coil_org_num		        coil.coil_org_num%TYPE; --Alex Gerlants. 01/25/2019
  ll_coil_gauge		          coil.coil_gauge%TYPE;   --Alex Gerlants. 01/25/2019
  ll_coil_width		          coil.coil_width%TYPE;   --Alex Gerlants. 01/25/2019
  ld_ship_date              date;
  li_is_constellium         integer;
  ln_skid_type_if_whed      sheet_skid.skid_type_if_whed%TYPE;   --Alex Gerlants. 04/01/2019
  li_skid_count             integer;
  ls_cust_short_name        customer.customer_short_name%TYPE;
  ll_coil_abc_num		        coil.coil_abc_num%TYPE;
  ls_cust_prod_line_id      order_item.cust_prod_line_id%TYPE;
  ls_orig_customer_po       customer_order.orig_customer_po%TYPE;
  ls_vo                     coil.vo%TYPE;
  ls_coil_alloy             coil.coil_alloy%TYPE;
  ls_coil_temper            coil.coil_temper%TYPE;
  ld_lineal_feed            inbound_coil.lineal_feed%TYPE;
  ld_created_date           customer_order.created_date%TYPE;

  CURSOR const_856_cur IS
    SELECT sheet_packing_item.sh_packing_item,
           'MULTIPLE' lot_num,
           'MULTIPLE' coil_id,
           customer_order.orig_customer_po,
           customer_order.order_abc_num,
           customer_order.enduser_po,
           customer_order.created_date,
           order_item.order_item_num,
           order_item.enduser_part_num,
           order_item.supplier_code,
           order_item.gauge,
           sheet_skid. ab_job_num,
           sheet_skid.sheet_skid_num,
           sheet_skid.sheet_skid_display_num, --added by Victor H. on 06-2012 for Novelis locatio code request
           sheet_skid.sheet_net_wt,
           sheet_skid.sheet_tare_wt,
           sheet_skid. skid_pieces,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_theoretical_wt,
           NULL done
      FROM customer_order,
           order_item,
           sheet_skid,
           ab_job,
           shipment,
           sheet_packing_item
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
       
  cursor po_cur is
  select distinct customer_order.orig_customer_po, customer_order.created_date
  from   sheet_packing_item
         join sheet_skid on sheet_skid.sheet_skid_num = sheet_packing_item.sheet_skid_num
         join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
         join process_coil on ab_job.ab_job_num = process_coil.ab_job_num
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         join customer_order on customer_order.order_abc_num = sheet_skid.ref_order_abc_num
  where  sheet_packing_item.packing_list = al_packing_list;

  --TYPE skidinfo_tabletype IS TABLE OF const_856_cur%ROWTYPE INDEX BY BINARY_INTEGER;
  --skidinfo_table skidinfo_tabletype;
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table    store_tabletype;
  i            BINARY_INTEGER := 0;
  skidinfo_rec const_856_cur%ROWTYPE;
  po_rec       po_cur%ROWTYPE;
  

  CURSOR c_ship_to IS
    SELECT DISTINCT des_sh_cust_id
      FROM shipment
     WHERE bill_of_lading = ll_bill_of_lading
       AND shipment.shipment_status = 0;
  
  cursor c_coil is
  select distinct 
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num,
         coil.coil_gauge,
         coil.coil_width
  from   customer_order
         join order_item on order_item.order_abc_num = customer_order.order_abc_num
         join ab_job on ab_job.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
         join sheet_skid on sheet_skid.ab_job_num = ab_job.ab_job_num
         join sheet_packing_item on sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
         join shipment on shipment.packing_list = sheet_packing_item.packing_list
         join process_coil on process_coil.ab_job_num = ab_job.ab_job_num
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         --join outbound_edi_transaction on outbound_edi_transaction.edi_file_id = shipment.edi_file_id_856
  --where  shipment.packing_list = 105586 --Production
  where  shipment.packing_list = al_packing_list --Development
  order by
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num;
  
  

BEGIN
  
  select dbo.f_is_constellium(al_packing_list)
  into   li_is_constellium
  from   dual;
  
  if li_is_constellium = 0 then --Customer is NOT Constellium
    return 1; --Nothing to do here
  end if;
  

  select shipment_edi856_date
  into   ld_ship_date
  from   shipment
  where  shipment.packing_list = al_packing_list;
   
  if not (ld_ship_date is null) then --ASN already sent
    return 100;
  end if;


  

  -- edi_alcan_870; -- Send 870 first

  -- Get Customer ID, End user ID
  --SELECT customer_id, des_sh_cust_id
  --  INTO li_customer_id, li_des_sh_cust_id
  -- FROM shipment
  -- WHERE shipment.packing_list = al_packing_list;
  --IF NOT SQL%FOUND THEN
 --   RETURN - 1;
  --END IF;

  -- Get Customer ID, End user ID, authorization code
  SELECT customer_id, des_sh_cust_id, nvl(shipment_athorization_code, 'NA')
    INTO li_customer_id, li_des_sh_cust_id, ls_auth_code
  FROM shipment
  WHERE shipment.packing_list = al_packing_list;
  IF NOT SQL%FOUND THEN
   RETURN - 1;
  END IF;

  -- dbms_output.put_line (to_char(li_customer_id) || '  ' || to_char(li_des_sh_cust_id) );

  /*
  IF NOT (li_customer_id IN (34, 35, 10, 1153, 1459, 2582)) -- AND (li_des_sh_cust_id IN (
   THEN

    --***********************************************************************************************88
    --IF NOT ((li_customer_id IN (34,35,10,1153)) AND (li_des_sh_cust_id IN (SELECT CUSTOMER_ID
    --FROM CUSTOMER
    --WHERE CUSTOMER_DUNS_NUMBER_STRING is not null))) THEN

    RETURN 200;
  END IF;
  */

  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(sheet_skid.sheet_net_wt),
         SUM(sheet_skid.sheet_net_wt) + SUM(sheet_skid.sheet_tare_wt),
         SUM(sheet_skid.skid_pieces)
    INTO ll_shipment_nt, ll_shipment_gt, ll_shipment_pc
    FROM sheet_skid, sheet_packing_item, shipment
   WHERE shipment.packing_list = sheet_packing_item.packing_list
     AND sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
     AND shipment.packing_list = al_packing_list;
  IF ll_shipment_pc = 0 THEN
    RETURN 100;
  END IF; -- empty shipment

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  -- Retrieve ABCO info
  -- ls_sender_vanid := '3010007080';
  --ls_ic := 'R0P7A';

  -- Retrieve ALCAN supply code and Ford Stamping Plant location code
  --SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf
  --FROM customer_customer  WHERE o_customer_id = li_customer_id and e_customer_id = 49;  --Ford customer_id =49

  ls_sf := '039630926';
  --SELECT NVL(communication_code,'UNKNOWN') INTO ls_st FROM customer_system
  --WHERE customer_id = li_des_sh_cust_id;

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.vehicle_id_prefix, '9999'),
         nvl(shipment.equipment_type, 'NA'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'PT'), -- Protected Trailer
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE)
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_vehicle_id_prefix,
         ls_eq_type,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_carrier_initial,
         ldt_shipment
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;

  --Check all packing_lists are done against a BOL
  /*
  for pl_rec in packing_list_same_bol loop
      select shipment.shipment_status into ll_temp from shipment
             where shipment.packing_list = pl_rec.packing_list;
      if ll_temp > 0 then
         return pl_rec.packing_list;
      end if;

  end loop;
  */
  --End of packing list checking

  SELECT nvl(customer_duns_number_string, '00000000'), customer_short_name
    INTO ls_st_duns, ls_des_cust_name
    FROM customer
   WHERE customer_id = li_des_sh_cust_id;

  IF (ls_st_duns = '00000000') THEN
    RETURN 200;
  END IF; --No Ship to DUNS

  SELECT nvl(customer_duns_number_string, '00000000'), upper(customer_short_name)
    INTO ls_su, ls_cust_short_name
    FROM customer
   WHERE customer_id = li_customer_id;
  IF (ls_su = '00000000') THEN
    RETURN 200;
  END IF; --No Supplier DUNS

  -- Get SCAC(Standard Carrier Alpha Code)
  SELECT nvl(carrier.scac, 'NONE'), LPAD(carrier.carrier_full_name, 17)
    INTO ls_scac, ls_carrier_full_name
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);

  --Production
  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *01*039630926T     *01*043207177      *' ||
                  ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
  
  --Development                
  --x12_table(i) := 'ISA*00*' ||
  --                '          *00*          *ZZ*2NDSFTP        *01*043207177      *' ||
  --                ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
  --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';
                  
  i := i + 1;

  --Alex Gerlants. 10/16/2018. Changed from "002002" to "004010"
  --Production
  x12_table(1) := 'GS*SH*039630926T*' || '043207177' || '*' || ls_today || '*' ||
                  ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  --Development
  --x12_table(1) := 'GS*SH*2NDSFTP*' || '043207177' || '*' || ls_today || '*' ||
  --               ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;
  --x12_table(i):= 'BSN*00*' || to_char(ll_bill_of_lading) || '*' || ls_today || '*' || ls_now;
  x12_table(i) := 'BSN*00*' || to_char(al_packing_list) || '*' || ls_today || '*' ||
                  ls_now;
  i := i + 1;
  
  --Alex Gerlants. 08/07/2018.
  --Changed to populate with actual ship date instead of current date and time.
  --The reason is that when we send 856 on a later date, this date is not correct.
  --x12_table(i) := 'DTM*011*' || ls_today || '*' || ls_now;
  --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                                                      to_char(ldt_shipment, 'HH24MI');
  i := i + 1;
  
  --Alex Gerlants. 10/18/2018. Changed from "YYMMDD" to "YYYYMMDD"
  --Moved here from the below
  x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                  to_char(ldt_shipment, 'HH24MI');
  i := i + 1;

  -- First Level HL
  x12_table(i) := 'HL*01**S*1';
  i := i + 1;
  
  select    count(*)
  into      li_skid_count
  from      sheet_packing_item
  where     packing_list = al_packing_list;
  
  x12_table(i) := 'TD1*PLT90*' || to_char(li_skid_count) || '****G*' || to_char(ll_shipment_gt) || '*LB';
  li_td1 := i;
  i := i + 1;
  
  x12_table(i) := 'TD1*PLT90*' || to_char(li_skid_count) || '****N*' || to_char(ll_shipment_nt) || '*LB';
  li_td1 := li_td1 + i;
  i := i + 1;
  
  x12_table(i) := 'TD5*B*2*' || ls_scac || '*M*' || ltrim(rtrim(ls_carrier_full_name)) || '*CC';
  i := i + 1;
  
  x12_table(i) := 'TD3*' || ls_carrier_desc_code || '*' || ls_scac || '*' || ls_vehicle_id_prefix;
  i := i + 1;
  
  x12_table(i) := 'REF*CN*' || to_char(al_packing_list);
  i := i + 1;
  
  x12_table(i) := 'REF*BM*' || to_char(al_packing_list);
  i := i + 1;  

  SELECT COUNT(*)
    INTO ll_temp
    FROM shipment
   WHERE shipment.bill_of_lading = ll_bill_of_lading
     AND shipment.shipment_status = 0;
     
  --Alex Gerlants. 10/16/2018. Removed 2 lines below
  --x12_table(i) := 'REF*SS*' || to_char(ll_temp);
  --i := i + 1;
  li_des_id := 1;
  
  x12_table(i) := 'N1*SF*Aluminum Blanking Co*1*' || ls_sf;
  i := i + 1;
  
  x12_table(i) := 'N1*MF*' || rtrim(ltrim(ls_cust_short_name)) || '*1*' || ls_su;
  i := i + 1;
  
  x12_table(i) := 'N1*ST*' || rtrim(ltrim(ls_des_cust_name)) || '*1*' || ls_st_duns;
  i := i + 1;
  
  x12_table(i) := 'N1*MA*' || rtrim(ltrim(ls_des_cust_name)) || '*1*' || ls_st_duns;
  i := i + 1;

  -- Second Level HL based on End User PO( only one part# is included in one shipement per FORD's request)
  OPEN const_856_cur;
  FETCH const_856_cur
    INTO skidinfo_rec;
  --    ls_enduser_part := skidinfo_rec.ENDUSER_PART_NUM;
  --    ls_enduser_po := skidinfo_rec.ENDUSER_PO;

  /*
    if skidinfo_rec.ORIG_CUSTOMER_PO IN ('68Q68517') then    --Do NOT send 856 to Ford for some flipping related POs )
         edi_file_prefix := 'nosend_alcan_ford_ford';
    end if;
  */

  SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
    INTO ls_enduser_part
    FROM "ORDER_ITEM", "SHEET_SKID"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
     AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
     AND ("SHEET_SKID"."SHEET_SKID_NUM" = skidinfo_rec.sheet_skid_num);

  /*
      SELECT "CUSTOMER_ORDER"."ENDUSER_PO" into ls_enduser_po
             FROM "SHEET_SKID",
                  "CUSTOMER_ORDER"
                  WHERE ( "SHEET_SKID"."REF_ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM" ) and
                        (SHEET_SKID.SHEET_SKID_NUM = skidinfo_rec.SHEET_SKID_NUM);
  */

  x12_table(i) := 'HL*02*01*O';
  i := i + 1;
  IF ls_enduser_part IS NULL THEN
    ls_enduser_part := 'NA';
  END IF;
  --x12_table(i) := 'LIN**BP*' || ls_enduser_part;
  --i := i + 1;
  --x12_table(i) := 'SN1**' || to_char(ll_shipment_pc) || '*EA*0';
  --i := i + 1;

  --
  --ls_po := skidinfo_rec.ORIG_CUSTOMER_PO;
  SELECT "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO"
    INTO ls_po
    FROM "SHEET_SKID", "CUSTOMER_ORDER"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
         "CUSTOMER_ORDER"."ORDER_ABC_NUM")
     AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num);

  --IF INSTR(skidinfo_rec.ORIG_CUSTOMER_PO,'-') > 0
  --New PO format for Novelis SAP include '-'
  /*IF instr(ls_po, '-') > 0 THEN
    ls_po := substr(ls_po, 0, instr(ls_po, '-') - 1);
  END IF;*/

  for po_rec in po_cur loop --******************************************************
    ls_orig_customer_po := po_rec.orig_customer_po;
    ld_created_date := po_rec.created_date;
    
    x12_table(i) := 'PRF*' || ls_orig_customer_po || '***' ||
                    to_char(ld_created_date, 'YYYYMMDD');
    i := i + 1;
  end loop;
  --   end if;

  CLOSE const_856_cur;

   --  Novelis SAP order number
 --x12_table(i) := 'REF*IL*' || ls_auth_code;
 --i := i + 1;
  --  end if;

  -- Third Level HL Under a P.O.
  li_hl01 := 3;

  --Skid loop begin ----------------------------------------------------------------
  FOR skidinfo_rec IN const_856_cur LOOP
    
      --In case of a split skid, we are creating just 1 HL for this skid
      --with just 1 coil for this skid.
      select distinct
             coil.coil_abc_num, 
             coil.coil_org_num,
             coil.coil_gauge,
             coil.coil_width,
             coil.lot_num,
             nvl(skid_type_if_whed, -1),
             coil.vo,
             coil.coil_alloy,
             coil.coil_temper
      into   ll_coil_abc_num,
             ls_coil_org_num,
             ll_coil_gauge,
             ll_coil_width,
             ls_lot_num,
             ln_skid_type_if_whed, --Alex Gerlants. 04/01/2019
             ls_vo,
             ls_coil_alloy,
             ls_coil_temper
      FROM "COIL",   
           "PRODUCTION_SHEET_ITEM",   
           "SHEET_SKID",   
           "SHEET_SKID_DETAIL",   
           "PROCESS_COIL"  
     WHERE ( "COIL"."COIL_ABC_NUM" = "PRODUCTION_SHEET_ITEM"."COIL_ABC_NUM" ) and  
           ( "SHEET_SKID_DETAIL"."SHEET_SKID_NUM" = "SHEET_SKID"."SHEET_SKID_NUM" ) and  
           ( "SHEET_SKID_DETAIL"."PROD_ITEM_NUM" = "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NUM" ) and  
           ( "COIL"."COIL_ABC_NUM" = "PROCESS_COIL"."COIL_ABC_NUM" ) and  
           ( "PRODUCTION_SHEET_ITEM"."AB_JOB_NUM" = "PROCESS_COIL"."AB_JOB_NUM" ) and  
           ( (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num)  ) and
           ( (rownum = 1)  ); --We need just 1 coil for each skid
  
      --Alex Gerlants. 04/01/2019. Begin
      --if ln_skid_type_if_whed > -1 then --Warehouse skid
          --Get gauge and part width
          select distinct order_item.gauge,
                 f_get_part_width_per_job(ab_job.ab_job_num),
                 enduser_part_num,
                 nvl(cust_prod_line_id, '')
          into   ll_coil_gauge,
                 ll_coil_width,
                 ls_enduser_part,
                 ls_cust_prod_line_id
          from   sheet_skid
                 join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
                 join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
                 join customer_order on customer_order.order_abc_num = order_item.order_abc_num
          where  sheet_skid_num = skidinfo_rec.sheet_skid_num
          and    (order_item.gauge is not null and f_get_part_width_per_job(sheet_skid.ab_job_num) is not null)
          and    rownum = 1;
      --end if;
      --Alex Gerlants. 04/01/2019. End
  
      IF length(to_char(li_hl01)) = 1 THEN
        x12_table(i) := 'HL*0' || to_char(li_hl01) || '*02*I';
        i := i + 1;
      ELSE
        x12_table(i) := 'HL*' || to_char(li_hl01) || '*02*I';
        i := i + 1;
      END IF;
      
      select distinct 
                inbound_coil.vo, inbound_coil.lot, inbound_coil.lineal_feed
      into      ls_vo, ls_lot_num, ld_lineal_feed
      from      inbound_coil
                join inbound_coil_status on inbound_coil_status.coil_number = inbound_coil.coil_number
      where     inbound_coil_status.coil_abc_num = ll_coil_abc_num;      
      
    
      x12_table(i) := 'LIN*1*BP*' || ls_enduser_part || '*SN*' || ls_coil_org_num || '*HN*' || ls_lot_num || '*LS*' || to_char(ll_coil_abc_num) || '*JN*' || ls_vo;
      i := i + 1;
      
      x12_table(i) := 'PID*S*55**' || ls_coil_alloy;
      i := i + 1;
      
      x12_table(i) := 'PID*S*16**' || ls_coil_temper;
      i := i + 1;

      x12_table(i) := 'MEA*WT*WT*' || to_char(skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt) ||
                      '*01';
      i := i + 1;
                        
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*WT" to "MEA*CT*NL"
      x12_table(i) := 'MEA*CT*NL*' || to_char(skidinfo_rec.skid_pieces) ||
                      '*PC';
      i := i + 1;

      -- changed to all gross wt per novelis 1/30/2015
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*G" to "MEA*WT*G"
      --x12_table(i) := 'MEA*WT*G*' || to_char(skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt) || '*01';
      --i := i + 1;
 
      x12_table(i) := 'MEA*PD*TH*' || ltrim(rtrim(to_char(ll_coil_gauge, '0.0000')));
      i := i + 1;

      x12_table(i) := 'MEA*PD*WD*' || ll_coil_width;
      i := i + 1;
      
      x12_table(i) := 'MEA*PD*LN*' || to_char(ld_lineal_feed);
      i := i + 1;

      --Alex Gerlants. 10/18/2018. Changed from "REF*LS" to "REF*SE"
      x12_table(i) := 'REF*SE*' || skidinfo_rec.sheet_skid_display_num; --added by Victor H. on 06-2012 for Novelis locatio code request
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      --x12_table(i) := 'REF*LS*' || ls_coil_org_num;
      --i := i + 1;
      
      li_hl01 := li_hl01 + 1;
      li_rowcount := const_856_cur%ROWCOUNT;
      --x12_table(li_td1) := 'TD1*PLT90*' || to_char(li_rowcount);
  END LOOP; --End of 'FOR skidinfo_rec IN const_856_cur LOOP'
  --Skid loop end ------------------------------------------------------------------

  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                  to_char(li_rowcount + ll_shipment_pc);
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  -- Write X.12 to file
  -- To FORD

  /** Write file to /templar/templar/incoming/senddata
  /*
  **/

  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  --edi_file:= 'S_alcan_ford_ford_' || to_char(ll_edi_file_id) ||'.x12';

  -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
  -- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
    --        v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
  END LOOP;
  utl_file.fclose(edi_file_handle);

  --To ALCAN

  /*
  SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;
  SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id_alcan FROM DUAL;
  edi_file:= 'S_alcan_ford_alcan_' || to_char(ll_edi_file_id_alcan) ||'.x12';
  edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');
  x12_table(0) := 'ISA*00*'||'          *00*          *01*039630926T     *09*0015049350011G *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0')||'*0*P**';
  x12_table(1) := 'GS*SH*R0P7A*'||'001504935001' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  x12_table(i-1) :=  'GE*1*' || to_char (ll_gs_log);
  x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');
  for j in 0..i loop
   UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
       v_edi_text_alcan:=v_edi_text_alcan||x12_table(j)||CHR(10);
  end loop;
  UTL_FILE.FCLOSE(edi_file_handle);

  */

  /* The following code added by Tony, for update archive*/

  --  INSERT INTO edi_log (edi_log_timestamp,customer_id,
  --         customer_edi_name,edi_log_contents,edi_file_id,edi_text)
  --    VALUES (SYSDATE,li_customer_id,ll_customer_edi_name,
  --           'EDI:'||ll_customer_edi_name||' generated successfully.',ll_edi_file_id,v_edi_text);
  --   COMMIT;

  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  

  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE,
         edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;


--  COMMIT;

  /* --added by Victor Huang on 06/05 for function acknowlegement
  INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
  VALUES(ll_gs_log, ls_su, sysdate, edi_file);
  COMMIT;*/

  --added by Victor Huang on 12/07 for verifying 997
  INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (ll_edi_file_id,
     '039630926',
     ls_su,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856');
     
  COMMIT;

  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  --exception
  --   when invalid_operation
  --   then
  --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

  --  when others
  --  then
  --      DBMS_OUTPUT.PUT_LINE ('System Error');
  --      UTL_FILE.FCLOSE(edi_file_handle);

  RETURN 1;
END edi_const_856_X12_07222021;
--------------------------------------------------------
--  DDL for Function EDI_CONST_856_X12_RERUN
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_CONST_856_X12_RERUN" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*


  */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR');

  --edi_loc varchar2(50):='/tmp';
  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_prefix VARCHAR2(50) := 's_constellium_856_'; --Production
  --edi_file_prefix VARCHAR2(50) := 's_constellium_856_'; --Development
  edi_file_handle utl_file.file_type;

  li_customer_id    shipment.customer_id%TYPE;
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;
  ls_sf VARCHAR2(50);
  ls_eq_type VARCHAR2(10);
  ls_su      VARCHAR2(50);
  ls_st_duns VARCHAR2(50);
  ls_po      VARCHAR2(30);
  ls_auth_code   VARCHAR2(32);
  ll_gs_log  INTEGER;
  ll_st_log  INTEGER;
  ll_bsn_log INTEGER;

  ls_today VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD'); --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  ls_today_2digits_year VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD'); --Alex Gerlants. 10/16/2018. Test
  ls_now   VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  li_rowcount INTEGER;
  li_hl01 INTEGER;
  ll_shipment_nt INTEGER;
  ll_shipment_gt INTEGER;
  ll_shipment_pc INTEGER;
  li_td1 INTEGER;
  li_rc  INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_vehicle_id_prefix VARCHAR2(50);
  ls_scac              carrier.scac%TYPE;
  ls_carrier_full_name VARCHAR2(18);
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_carrier_initial   VARCHAR2(50);  -- Not used in stored procedure.  Discovered by Patrick Reynolds 11/30/2016
  ldt_shipment         DATE;
   ll_temp         INTEGER;
  ls_enduser_part VARCHAR2(50);
  li_des_id       INTEGER;

  ll_edi_file_id INTEGER;

  ls_lot_num VARCHAR2(32);
  ls_coil_id VARCHAR2(32);
  ls_des_cust_name VARCHAR2(18);
  
  ls_coil_org_num		        coil.coil_org_num%TYPE; --Alex Gerlants. 01/25/2019
  ll_coil_gauge		          coil.coil_gauge%TYPE;   --Alex Gerlants. 01/25/2019
  ll_coil_width		          coil.coil_width%TYPE;   --Alex Gerlants. 01/25/2019
  ld_ship_date              date;
  li_is_constellium         integer;
  ln_skid_type_if_whed      sheet_skid.skid_type_if_whed%TYPE;   --Alex Gerlants. 04/01/2019
  li_skid_count             integer;
  ls_cust_short_name        customer.customer_short_name%TYPE;
  ll_coil_abc_num		        coil.coil_abc_num%TYPE;
  ls_cust_prod_line_id      order_item.cust_prod_line_id%TYPE;
  ls_orig_customer_po       customer_order.orig_customer_po%TYPE;
  ls_vo                     coil.vo%TYPE;
  ls_coil_alloy             coil.coil_alloy%TYPE;
  ls_coil_temper            coil.coil_temper%TYPE;
  ld_lineal_feed            inbound_coil.lineal_feed%TYPE;
  ld_created_date           customer_order.created_date%TYPE;

  CURSOR const_856_cur IS
    SELECT sheet_packing_item.sh_packing_item,
           'MULTIPLE' lot_num,
           'MULTIPLE' coil_id,
           customer_order.orig_customer_po,
           customer_order.order_abc_num,
           customer_order.enduser_po,
           customer_order.created_date,
           order_item.order_item_num,
           order_item.enduser_part_num,
           order_item.supplier_code,
           order_item.gauge,
           sheet_skid. ab_job_num,
           sheet_skid.sheet_skid_num,
           sheet_skid.sheet_skid_display_num, --added by Victor H. on 06-2012 for Novelis locatio code request
           sheet_skid.sheet_net_wt,
           sheet_skid.sheet_tare_wt,
           sheet_skid. skid_pieces,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_theoretical_wt,
           NULL done
      FROM customer_order,
           order_item,
           sheet_skid,
           ab_job,
           shipment,
           sheet_packing_item
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
       
  cursor po_cur is
  select distinct customer_order.orig_customer_po, customer_order.created_date
  from   sheet_packing_item
         join sheet_skid on sheet_skid.sheet_skid_num = sheet_packing_item.sheet_skid_num
         join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
         join process_coil on ab_job.ab_job_num = process_coil.ab_job_num
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         join customer_order on customer_order.order_abc_num = sheet_skid.ref_order_abc_num
  where  sheet_packing_item.packing_list = al_packing_list;

  --TYPE skidinfo_tabletype IS TABLE OF const_856_cur%ROWTYPE INDEX BY BINARY_INTEGER;
  --skidinfo_table skidinfo_tabletype;
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table    store_tabletype;
  i            BINARY_INTEGER := 0;
  skidinfo_rec const_856_cur%ROWTYPE;
  po_rec       po_cur%ROWTYPE;
  

  CURSOR c_ship_to IS
    SELECT DISTINCT des_sh_cust_id
      FROM shipment
     WHERE bill_of_lading = ll_bill_of_lading
       AND shipment.shipment_status = 0;
  
  cursor c_coil is
  select distinct 
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num,
         coil.coil_gauge,
         coil.coil_width
  from   customer_order
         join order_item on order_item.order_abc_num = customer_order.order_abc_num
         join ab_job on ab_job.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
         join sheet_skid on sheet_skid.ab_job_num = ab_job.ab_job_num
         join sheet_packing_item on sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
         join shipment on shipment.packing_list = sheet_packing_item.packing_list
         join process_coil on process_coil.ab_job_num = ab_job.ab_job_num
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         --join outbound_edi_transaction on outbound_edi_transaction.edi_file_id = shipment.edi_file_id_856
  --where  shipment.packing_list = 105586 --Production
  where  shipment.packing_list = al_packing_list --Development
  order by
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num;
  
  

BEGIN
  
  select dbo.f_is_constellium(al_packing_list)
  into   li_is_constellium
  from   dual;
  
  if li_is_constellium = 0 then --Customer is NOT Constellium
    return 1; --Nothing to do here
  end if;
  
  /*
  select shipment_edi856_date
  into   ld_ship_date
  from   shipment
  where  shipment.packing_list = al_packing_list;
   
  if not (ld_ship_date is null) then --ASN already sent
    return 100;
  end if;
  */

  

  -- edi_alcan_870; -- Send 870 first

  -- Get Customer ID, End user ID
  --SELECT customer_id, des_sh_cust_id
  --  INTO li_customer_id, li_des_sh_cust_id
  -- FROM shipment
  -- WHERE shipment.packing_list = al_packing_list;
  --IF NOT SQL%FOUND THEN
 --   RETURN - 1;
  --END IF;

  -- Get Customer ID, End user ID, authorization code
  SELECT customer_id, des_sh_cust_id, nvl(shipment_athorization_code, 'NA')
    INTO li_customer_id, li_des_sh_cust_id, ls_auth_code
  FROM shipment
  WHERE shipment.packing_list = al_packing_list;
  IF NOT SQL%FOUND THEN
   RETURN - 1;
  END IF;

  -- dbms_output.put_line (to_char(li_customer_id) || '  ' || to_char(li_des_sh_cust_id) );

  /*
  IF NOT (li_customer_id IN (34, 35, 10, 1153, 1459, 2582)) -- AND (li_des_sh_cust_id IN (
   THEN

    --***********************************************************************************************88
    --IF NOT ((li_customer_id IN (34,35,10,1153)) AND (li_des_sh_cust_id IN (SELECT CUSTOMER_ID
    --FROM CUSTOMER
    --WHERE CUSTOMER_DUNS_NUMBER_STRING is not null))) THEN

    RETURN 200;
  END IF;
  */

  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(sheet_skid.sheet_net_wt),
         SUM(sheet_skid.sheet_net_wt) + SUM(sheet_skid.sheet_tare_wt),
         SUM(sheet_skid.skid_pieces)
    INTO ll_shipment_nt, ll_shipment_gt, ll_shipment_pc
    FROM sheet_skid, sheet_packing_item, shipment
   WHERE shipment.packing_list = sheet_packing_item.packing_list
     AND sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
     AND shipment.packing_list = al_packing_list;
  IF ll_shipment_pc = 0 THEN
    RETURN 100;
  END IF; -- empty shipment

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  -- Retrieve ABCO info
  -- ls_sender_vanid := '3010007080';
  --ls_ic := 'R0P7A';

  -- Retrieve ALCAN supply code and Ford Stamping Plant location code
  --SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf
  --FROM customer_customer  WHERE o_customer_id = li_customer_id and e_customer_id = 49;  --Ford customer_id =49

  ls_sf := '039630926';
  --SELECT NVL(communication_code,'UNKNOWN') INTO ls_st FROM customer_system
  --WHERE customer_id = li_des_sh_cust_id;

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.vehicle_id_prefix, '9999'),
         nvl(shipment.equipment_type, 'NA'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'PT'), -- Protected Trailer
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE)
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_vehicle_id_prefix,
         ls_eq_type,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_carrier_initial,
         ldt_shipment
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;

  --Check all packing_lists are done against a BOL
  /*
  for pl_rec in packing_list_same_bol loop
      select shipment.shipment_status into ll_temp from shipment
             where shipment.packing_list = pl_rec.packing_list;
      if ll_temp > 0 then
         return pl_rec.packing_list;
      end if;

  end loop;
  */
  --End of packing list checking

  SELECT nvl(customer_duns_number_string, '00000000'), customer_short_name
    INTO ls_st_duns, ls_des_cust_name
    FROM customer
   WHERE customer_id = li_des_sh_cust_id;

  IF (ls_st_duns = '00000000') THEN
    RETURN 200;
  END IF; --No Ship to DUNS

  SELECT nvl(customer_duns_number_string, '00000000'), upper(customer_short_name)
    INTO ls_su, ls_cust_short_name
    FROM customer
   WHERE customer_id = li_customer_id;
  IF (ls_su = '00000000') THEN
    RETURN 200;
  END IF; --No Supplier DUNS

  -- Get SCAC(Standard Carrier Alpha Code)
  SELECT nvl(carrier.scac, 'NONE'), LPAD(carrier.carrier_full_name, 17)
    INTO ls_scac, ls_carrier_full_name
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);

  --Production
  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *01*039630926T     *01*043207177      *' ||
                  ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
  
  --Development                
  --x12_table(i) := 'ISA*00*' ||
  --                '          *00*          *ZZ*2NDSFTP        *01*043207177      *' ||
  --                ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
  --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';
                  
  i := i + 1;

  --Alex Gerlants. 10/16/2018. Changed from "002002" to "004010"
  --Production
  x12_table(1) := 'GS*SH*039630926T*' || '043207177' || '*' || ls_today || '*' ||
                  ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  --Development
  --x12_table(1) := 'GS*SH*2NDSFTP*' || '043207177' || '*' || ls_today || '*' ||
  --               ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;
  --x12_table(i):= 'BSN*00*' || to_char(ll_bill_of_lading) || '*' || ls_today || '*' || ls_now;
  x12_table(i) := 'BSN*00*' || to_char(al_packing_list) || '*' || ls_today || '*' ||
                  ls_now;
  i := i + 1;
  
  --Alex Gerlants. 08/07/2018.
  --Changed to populate with actual ship date instead of current date and time.
  --The reason is that when we send 856 on a later date, this date is not correct.
  --x12_table(i) := 'DTM*011*' || ls_today || '*' || ls_now;
  --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                                                      to_char(ldt_shipment, 'HH24MI');
  i := i + 1;
  
  --Alex Gerlants. 10/18/2018. Changed from "YYMMDD" to "YYYYMMDD"
  --Moved here from the below
  x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                  to_char(ldt_shipment, 'HH24MI');
  i := i + 1;

  -- First Level HL
  x12_table(i) := 'HL*01**S*1';
  i := i + 1;
  
  select    count(*)
  into      li_skid_count
  from      sheet_packing_item
  where     packing_list = al_packing_list;
  
  x12_table(i) := 'TD1*PLT90*' || to_char(li_skid_count) || '****G*' || to_char(ll_shipment_gt) || '*LB';
  li_td1 := i;
  i := i + 1;
  
  x12_table(i) := 'TD1*PLT90*' || to_char(li_skid_count) || '****N*' || to_char(ll_shipment_nt) || '*LB';
  li_td1 := li_td1 + i;
  i := i + 1;
  
  x12_table(i) := 'TD5*B*2*' || ls_scac || '*M*' || ltrim(rtrim(ls_carrier_full_name)) || '*CC';
  i := i + 1;
  
  x12_table(i) := 'TD3*' || ls_carrier_desc_code || '*' || ls_scac || '*' || ls_vehicle_id_prefix;
  i := i + 1;
  
  x12_table(i) := 'REF*CN*' || to_char(al_packing_list);
  i := i + 1;
  
  x12_table(i) := 'REF*BM*' || to_char(al_packing_list);
  i := i + 1;  

  SELECT COUNT(*)
    INTO ll_temp
    FROM shipment
   WHERE shipment.bill_of_lading = ll_bill_of_lading
     AND shipment.shipment_status = 0;
     
  --Alex Gerlants. 10/16/2018. Removed 2 lines below
  --x12_table(i) := 'REF*SS*' || to_char(ll_temp);
  --i := i + 1;
  li_des_id := 1;
  
  x12_table(i) := 'N1*SF*Aluminum Blanking Co*1*' || ls_sf;
  i := i + 1;
  
  x12_table(i) := 'N1*MF*' || rtrim(ltrim(ls_cust_short_name)) || '*1*' || ls_su;
  i := i + 1;
  
  x12_table(i) := 'N1*ST*' || rtrim(ltrim(ls_des_cust_name)) || '*1*' || ls_st_duns;
  i := i + 1;
  
  x12_table(i) := 'N1*MA*' || rtrim(ltrim(ls_des_cust_name)) || '*1*' || ls_st_duns;
  i := i + 1;

  -- Second Level HL based on End User PO( only one part# is included in one shipement per FORD's request)
  OPEN const_856_cur;
  FETCH const_856_cur
    INTO skidinfo_rec;
  --    ls_enduser_part := skidinfo_rec.ENDUSER_PART_NUM;
  --    ls_enduser_po := skidinfo_rec.ENDUSER_PO;

  /*
    if skidinfo_rec.ORIG_CUSTOMER_PO IN ('68Q68517') then    --Do NOT send 856 to Ford for some flipping related POs )
         edi_file_prefix := 'nosend_alcan_ford_ford';
    end if;
  */

  SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
    INTO ls_enduser_part
    FROM "ORDER_ITEM", "SHEET_SKID"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
     AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
     AND ("SHEET_SKID"."SHEET_SKID_NUM" = skidinfo_rec.sheet_skid_num);

  /*
      SELECT "CUSTOMER_ORDER"."ENDUSER_PO" into ls_enduser_po
             FROM "SHEET_SKID",
                  "CUSTOMER_ORDER"
                  WHERE ( "SHEET_SKID"."REF_ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM" ) and
                        (SHEET_SKID.SHEET_SKID_NUM = skidinfo_rec.SHEET_SKID_NUM);
  */

  x12_table(i) := 'HL*02*01*O';
  i := i + 1;
  IF ls_enduser_part IS NULL THEN
    ls_enduser_part := 'NA';
  END IF;
  --x12_table(i) := 'LIN**BP*' || ls_enduser_part;
  --i := i + 1;
  --x12_table(i) := 'SN1**' || to_char(ll_shipment_pc) || '*EA*0';
  --i := i + 1;

  --
  --ls_po := skidinfo_rec.ORIG_CUSTOMER_PO;
  SELECT "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO"
    INTO ls_po
    FROM "SHEET_SKID", "CUSTOMER_ORDER"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
         "CUSTOMER_ORDER"."ORDER_ABC_NUM")
     AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num);

  --IF INSTR(skidinfo_rec.ORIG_CUSTOMER_PO,'-') > 0
  --New PO format for Novelis SAP include '-'
  /*IF instr(ls_po, '-') > 0 THEN
    ls_po := substr(ls_po, 0, instr(ls_po, '-') - 1);
  END IF;*/

  for po_rec in po_cur loop --******************************************************
    ls_orig_customer_po := po_rec.orig_customer_po;
    ld_created_date := po_rec.created_date;
    
    x12_table(i) := 'PRF*' || ls_orig_customer_po || '***' ||
                    to_char(ld_created_date, 'YYYYMMDD');
    i := i + 1;
  end loop;
  --   end if;

  CLOSE const_856_cur;

   --  Novelis SAP order number
 --x12_table(i) := 'REF*IL*' || ls_auth_code;
 --i := i + 1;
  --  end if;

  -- Third Level HL Under a P.O.
  li_hl01 := 3;

  --Skid loop begin ----------------------------------------------------------------
  FOR skidinfo_rec IN const_856_cur LOOP
    
      --In case of a split skid, we are creating just 1 HL for this skid
      --with just 1 coil for this skid.
      select distinct
             coil.coil_abc_num, 
             coil.coil_org_num,
             coil.coil_gauge,
             coil.coil_width,
             coil.lot_num,
             nvl(skid_type_if_whed, -1),
             coil.vo,
             coil.coil_alloy,
             coil.coil_temper
      into   ll_coil_abc_num,
             ls_coil_org_num,
             ll_coil_gauge,
             ll_coil_width,
             ls_lot_num,
             ln_skid_type_if_whed, --Alex Gerlants. 04/01/2019
             ls_vo,
             ls_coil_alloy,
             ls_coil_temper
      FROM "COIL",   
           "PRODUCTION_SHEET_ITEM",   
           "SHEET_SKID",   
           "SHEET_SKID_DETAIL",   
           "PROCESS_COIL"  
     WHERE ( "COIL"."COIL_ABC_NUM" = "PRODUCTION_SHEET_ITEM"."COIL_ABC_NUM" ) and  
           ( "SHEET_SKID_DETAIL"."SHEET_SKID_NUM" = "SHEET_SKID"."SHEET_SKID_NUM" ) and  
           ( "SHEET_SKID_DETAIL"."PROD_ITEM_NUM" = "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NUM" ) and  
           ( "COIL"."COIL_ABC_NUM" = "PROCESS_COIL"."COIL_ABC_NUM" ) and  
           ( "PRODUCTION_SHEET_ITEM"."AB_JOB_NUM" = "PROCESS_COIL"."AB_JOB_NUM" ) and  
           ( (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num)  ) and
           ( (rownum = 1)  ); --We need just 1 coil for each skid
  
      --Alex Gerlants. 04/01/2019. Begin
      --if ln_skid_type_if_whed > -1 then --Warehouse skid
          --Get gauge and part width
          select distinct order_item.gauge,
                 f_get_part_width_per_job(ab_job.ab_job_num),
                 enduser_part_num,
                 nvl(cust_prod_line_id, '')
          into   ll_coil_gauge,
                 ll_coil_width,
                 ls_enduser_part,
                 ls_cust_prod_line_id
          from   sheet_skid
                 join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
                 join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
                 join customer_order on customer_order.order_abc_num = order_item.order_abc_num
          where  sheet_skid_num = skidinfo_rec.sheet_skid_num
          and    (order_item.gauge is not null and f_get_part_width_per_job(sheet_skid.ab_job_num) is not null)
          and    rownum = 1;
      --end if;
      --Alex Gerlants. 04/01/2019. End
  
      IF length(to_char(li_hl01)) = 1 THEN
        x12_table(i) := 'HL*0' || to_char(li_hl01) || '*02*I';
        i := i + 1;
      ELSE
        x12_table(i) := 'HL*' || to_char(li_hl01) || '*02*I';
        i := i + 1;
      END IF;
      
      select distinct 
                inbound_coil.vo, inbound_coil.lot, inbound_coil.lineal_feed
      into      ls_vo, ls_lot_num, ld_lineal_feed
      from      inbound_coil
                join inbound_coil_status on inbound_coil_status.coil_number = inbound_coil.coil_number
      where     inbound_coil_status.coil_abc_num = ll_coil_abc_num;      
      
    
      x12_table(i) := 'LIN*1*BP*' || ls_enduser_part || '*SN*' || ls_coil_org_num || '*HN*' || ls_lot_num || '*LS*' || to_char(ll_coil_abc_num) || '*JN*' || ls_vo;
      i := i + 1;
      
      x12_table(i) := 'PID*S*55**' || ls_coil_alloy;
      i := i + 1;
      
      x12_table(i) := 'PID*S*16**' || ls_coil_temper;
      i := i + 1;

      x12_table(i) := 'MEA*WT*WT*' || to_char(skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt) ||
                      '*01';
      i := i + 1;
                        
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*WT" to "MEA*CT*NL"
      x12_table(i) := 'MEA*CT*NL*' || to_char(skidinfo_rec.skid_pieces) ||
                      '*PC';
      i := i + 1;

      -- changed to all gross wt per novelis 1/30/2015
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*G" to "MEA*WT*G"
      --x12_table(i) := 'MEA*WT*G*' || to_char(skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt) || '*01';
      --i := i + 1;
 
      x12_table(i) := 'MEA*PD*TH*' || ltrim(rtrim(to_char(ll_coil_gauge, '0.0000')));
      i := i + 1;

      x12_table(i) := 'MEA*PD*WD*' || ll_coil_width;
      i := i + 1;
      
      x12_table(i) := 'MEA*PD*LN*' || to_char(ld_lineal_feed);
      i := i + 1;

      --Alex Gerlants. 10/18/2018. Changed from "REF*LS" to "REF*SE"
      x12_table(i) := 'REF*SE*' || skidinfo_rec.sheet_skid_display_num; --added by Victor H. on 06-2012 for Novelis locatio code request
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      --x12_table(i) := 'REF*LS*' || ls_coil_org_num;
      --i := i + 1;
      
      li_hl01 := li_hl01 + 1;
      li_rowcount := const_856_cur%ROWCOUNT;
      --x12_table(li_td1) := 'TD1*PLT90*' || to_char(li_rowcount);
  END LOOP; --End of 'FOR skidinfo_rec IN const_856_cur LOOP'
  --Skid loop end ------------------------------------------------------------------

  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                  to_char(li_rowcount + ll_shipment_pc);
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  -- Write X.12 to file
  -- To FORD

  /** Write file to /templar/templar/incoming/senddata
  /*
  **/

  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  --edi_file:= 'S_alcan_ford_ford_' || to_char(ll_edi_file_id) ||'.x12';

  -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
  -- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
    --        v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
  END LOOP;
  utl_file.fclose(edi_file_handle);

  --To ALCAN

  /*
  SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;
  SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id_alcan FROM DUAL;
  edi_file:= 'S_alcan_ford_alcan_' || to_char(ll_edi_file_id_alcan) ||'.x12';
  edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');
  x12_table(0) := 'ISA*00*'||'          *00*          *01*039630926T     *09*0015049350011G *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0')||'*0*P**';
  x12_table(1) := 'GS*SH*R0P7A*'||'001504935001' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  x12_table(i-1) :=  'GE*1*' || to_char (ll_gs_log);
  x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');
  for j in 0..i loop
   UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
       v_edi_text_alcan:=v_edi_text_alcan||x12_table(j)||CHR(10);
  end loop;
  UTL_FILE.FCLOSE(edi_file_handle);

  */

  /* The following code added by Tony, for update archive*/

  --  INSERT INTO edi_log (edi_log_timestamp,customer_id,
  --         customer_edi_name,edi_log_contents,edi_file_id,edi_text)
  --    VALUES (SYSDATE,li_customer_id,ll_customer_edi_name,
  --           'EDI:'||ll_customer_edi_name||' generated successfully.',ll_edi_file_id,v_edi_text);
  --   COMMIT;

  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  
  /*
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE,
         edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;
   */

--  COMMIT;

  /* --added by Victor Huang on 06/05 for function acknowlegement
  INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
  VALUES(ll_gs_log, ls_su, sysdate, edi_file);
  COMMIT;*/

  --added by Victor Huang on 12/07 for verifying 997
  /*
  INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (ll_edi_file_id,
     '039630926',
     ls_su,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856');
     
  COMMIT;
  */

  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  --exception
  --   when invalid_operation
  --   then
  --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

  --  when others
  --  then
  --      DBMS_OUTPUT.PUT_LINE ('System Error');
  --      UTL_FILE.FCLOSE(edi_file_handle);

  RETURN 1;
END edi_const_856_X12_rerun;
--------------------------------------------------------
--  DDL for Function EDI_KAISER_856
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_KAISER_856" (al_packing_list shipment.packing_list%TYPE) return integer
/*
Returns:   Integer
               1 = if it succeeds
              -1 = if a system error occurs
             100 = no process data
             200 = no EDI defined
*/
is
/*
For Kaiser customer only Cust_id=45
             Ship to Cust ID 45, 1014, 1082, 1146 only
*/

-- v_edi_text_ford varchar2(32767);
-- v_edi_text_alcan varchar2(32767);
-- ll_customer_edi_name VARCHAR2(20);



--Alex Gerlants. 11/15/2016. Commented out, and added the line after.
--edi_loc varchar2 (50) := '/tmp';
edi_loc VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR');

--edi_loc varchar2 (50) := '/templar/templar/incoming/senddata';

edi_file varchar2 (50) := 'edi_out.txt';
edi_file_prefix varchar2(50) := 'S_Kaiser_Kaiser';
edi_file_handle UTL_FILE.FILE_TYPE;

li_customer_id shipment.customer_id%TYPE;
li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;

-- ls_sender_vanid varchar2 (50);
-- ls_receiver_vanid varchar2 (50);
-- ls_customer_vanid varchar2(50);
-- ls_receiver_gs03 varchar2(50);
-- ls_customer_gs03 varchar2(50);
ls_st varchar2(50);
ls_sf varchar2(50);
ls_ic varchar2(50);
ll_gs_log integer;
ll_st_log integer;
ll_bsn_log integer;

ls_today varchar2(20):= to_char(sysdate, 'YYMMDD');
ls_now varchar2(20) := to_char(sysdate, 'HHMI');

-- ll_newrow integer;
-- ll_sheet_skid_num integer;
li_rowcount integer;
-- li_rownum integer;
-- li_rownum1 integer;
li_HL01 integer;
-- li_HL02 integer;
ll_shipment_nt integer;
ll_shipment_gt integer;
ll_shipment_pc integer;
li_enduser_id integer;
li_td1 integer;
-- li_rc integer;

ll_bill_of_lading integer;
ls_vehicle_id  varchar2(50);
ls_scac carrier.scac%TYPE;
ls_tran_method_code varchar2(50);
ls_carrier_desc_code varchar2(50);
ls_caarrier_initial varchar2(50);
ldt_shipment date;
-- ld_shipdate date;

-- ls_enduser_part varchar2(50);
-- ls_enduser_po varchar2(50);

ll_edi_file_id integer;
-- ll_edi_file_id_alcan integer;

Cursor alcan_ford_856_cur IS
SELECT SHEET_PACKING_ITEM.SH_PACKING_ITEM,
         'MULTIPLE' LOT_NUM,
         CUSTOMER_ORDER.ORIG_CUSTOMER_PO,
         CUSTOMER_ORDER.ORDER_ABC_NUM,
         CUSTOMER_ORDER.ENDUSER_PO,
         ORDER_ITEM.ORDER_ITEM_NUM,
         ORDER_ITEM.ENDUSER_PART_NUM,
         ORDER_ITEM.SUPPLIER_CODE,
         SHEET_SKID. AB_JOB_NUM,
         SHEET_SKID.SHEET_SKID_NUM,
         SHEET_SKID.SHEET_NET_WT,
         SHEET_SKID.SHEET_TARE_WT,
         SHEET_SKID.SHEET_THEORETICAL_WT,
         SHEET_SKID. SKID_PIECES,
         SHEET_SKID.SKID_SHEET_STATUS,
          NULL DONE
FROM CUSTOMER_ORDER,
         ORDER_ITEM,
         SHEET_SKID,
         AB_JOB,
         SHIPMENT,
         SHEET_PACKING_ITEM
WHERE (ORDER_ITEM.ORDER_ABC_NUM = CUSTOMER_ORDER.ORDER_ABC_NUM ) and
         (AB_JOB.ORDER_ABC_NUM = ORDER_ITEM.ORDER_ABC_NUM) and
         (AB_JOB.ORDER_ITEM_NUM = ORDER_ITEM.ORDER_ITEM_NUM) and
         (SHEET_SKID.AB_JOB_NUM = AB_JOB.AB_JOB_NUM) and
         (SHIPMENT.PACKING_LIST =SHEET_PACKING_ITEM.PACKING_LIST) and
         (SHEET_PACKING_ITEM.SHEET_SKID_NUM = SHEET_SKID.SHEET_SKID_NUM) and
         (SHIPMENT.PACKING_LIST = al_packing_list );
   --      (SHIPMENT.SHIPMENT_EDI856_DATE is NULL);


-- Type skidinfo_tabletype IS table of alcan_ford_856_cur%ROWTYPE INDEX by binary_integer;
-- skidinfo_table skidinfo_tabletype;
TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
 x12_table store_tabletype;
i binary_integer := 0;
skidinfo_rec alcan_ford_856_cur%rowtype;

begin
-- Get Customer ID, End user ID
SELECT customer_id, des_sh_cust_id, shipment_enduser_id
INTO li_customer_id, li_des_sh_cust_id, li_enduser_id FROM shipment
WHERE shipment.packing_list = al_packing_list;
IF NOT SQL%FOUND THEN  RETURN -1; END IF;

-- dbms_output.put_line (to_char(li_customer_id) || '  ' || to_char(li_des_sh_cust_id) );

IF NOT ((li_customer_id = 188) and (li_des_sh_cust_id in (45,1014,1082,1146,1169))) THEN
return 200;   END IF;

-- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
SELECT SUM(sheet_skid.sheet_net_wt),SUM(sheet_skid.sheet_net_wt)+SUM(sheet_skid.sheet_tare_wt), SUM(sheet_skid.skid_pieces)
INTO ll_shipment_nt,ll_shipment_gt, ll_shipment_pc FROM sheet_skid, sheet_packing_item, shipment
WHERE SHIPMENT.PACKING_LIST =SHEET_PACKING_ITEM.PACKING_LIST and
      SHEET_PACKING_ITEM.SHEET_SKID_NUM = SHEET_SKID.SHEET_SKID_NUM and
      SHIPMENT.PACKING_LIST = al_packing_list;
if ll_shipment_pc = 0 then return 100; end if;   -- empty shipment

-- Get gs, st and bsn log sequence number
SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;
SELECT edi_st_log_seq.NEXTVAL INTO ll_st_log FROM DUAL;
SELECT edi_bsn_log_seq.NEXTVAL INTO ll_bsn_log FROM DUAL;

-- Retrieve ABCO info
 -- ls_sender_vanid := '3010007080';
 SELECT communication_code INTO ls_st
       FROM customer_system
       WHERE customer_id=li_des_sh_cust_id;

 SELECT communication_code INTO ls_ic
      FROM customer_system
      WHERE customer_id=li_enduser_id;

--ls_ic := 'R0P7A';




/*

-- Retrieve ALCAN supply code and Ford Stamping Plant location code
SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf
FROM customer_customer 	WHERE o_customer_id = li_customer_id and e_customer_id = 49;  --Ford customer_id =49
SELECT communication_code INTO ls_st FROM customer_system
WHERE customer_id = li_des_sh_cust_id;

*/
ls_sf:='039630926';

-- Get Shipment Info.
SELECT shipment.bill_of_lading,
       NVL(shipment.vehicle_id,'9999'),
		   NVL(shipment.transportation_method_code,'Motor'),
		   NVL(shipment.carrier_description_code, 'PT'),  -- Protected Trailer
		   NVL(shipment.carrier_initial, 'NA'),
       NVL(shipment.shipment_actualed_date_time,SYSDATE)
INTO 	ll_bill_of_lading, ls_vehicle_id, ls_tran_method_code,
      ls_carrier_desc_code, ls_caarrier_initial, ldt_shipment
FROM  shipment WHERE shipment.packing_list = al_packing_list;

-- Get SCAC(Standard Carrier Alpha Code)
SELECT NVL(carrier.scac, 'NONE') INTO ls_scac
FROM carrier WHERE carrier_id =(SELECT carrier_id  FROM shipment  WHERE shipment.packing_list = al_packing_list);

-- Get Resceiver and Customer VAN ID
-- SELECT NVL(customer_system.van_account_num, 'nothing'), NVL(customer_system.gs03, 'nothing')
-- INTO ls_receiver_vanid, ls_receiver_gs03    -- ls_receiver_vanid
-- FROM  customer_system WHERE customer_system.customer_id =
   --   (select shipment.des_sh_cust_id  from shipment  where shipment.packing_list = al_packing_list);

-- SELECT NVL(customer_system.van_account_num, 'nothing'),NVL(customer_system.gs03, 'nothing')
-- INTO 	ls_customer_vanid, ls_customer_gs03   -- ls_customer_vanid
-- FROM  customer_system WHERE customer_system.customer_id =
--       (select shipment.customer_id from shipment where shipment.packing_list = al_packing_list);


-- Generate Header Info.
/*Production ID: 01/021820469*/
--x12_table(i) := 'ISA*00*'||'          *00*          *01*039630926T     *01*021820469      *'||ls_today ||'*'|| ls_now ||'*U*00300*'||LPAD(to_char(ll_gs_log),9,'0') ||'*1*T**';
--i := i + 1;
/*Test ID: ZZ/KAISEREDITST*/
x12_table(i) := 'ISA*00*'||'          *00*          *01*039630926T     *ZZ*KAISEREDITST   *'||ls_today ||'*'|| ls_now ||'*U*00300*'||LPAD(to_char(ll_gs_log),9,'0') ||'*1*T**';
i := i + 1;
--x12_table(i) := 'GS*SH*039630926T*'||'021820469'|| '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '003030';
x12_table(i) := 'GS*SH*039630926T*'||'KAISEREDITST'|| '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '003030';
i := i + 1;

x12_table(i):= 'ST*856*' || to_char(ll_st_log);
i := i +1;
x12_table(i):= 'BSN*00*' || to_char(ll_bill_of_lading) || '*' || ls_today || '*' || ls_now;
i := i +1;
x12_table(i):= 'DTM*011*' || to_char(ldt_shipment,'YYMMDD') || '*' || to_char(ldt_shipment,'HHMI');
i := i +1;



-- First Level HL
x12_table(i) := 'HL*0001**S'; i := i +1;
x12_table(i):= 'MEA**G*' || to_char(ll_shipment_gt) || '*LB'; i := i +1;
--x12_table(i):= 'MEA*PD*N*' || to_char(ll_shipment_nt) || '*LB'; i := i +1;
x12_table(i):= 'TD1*PKG01*' || to_char(li_rowcount); li_td1 :=i;  i := i +1;
x12_table(i):= 'TD5*O*02*' || ls_scac ||'*M'; i := i +1;
x12_table(i):= 'TD3*' || ls_carrier_desc_code || '**' || ls_vehicle_id; i := i +1;
x12_table(i):= 'REF*BM*' ||  to_char(ll_bill_of_lading); i := i +1;
--x12_table(i):= 'REF*PK*' || to_char(al_packing_list); i := i +1;





-- Second Level HL based on End User PO( only one part# is included in one shipement per FORD's request)
open alcan_ford_856_cur;
fetch alcan_ford_856_cur INTO skidinfo_rec;
--    ls_enduser_part := skidinfo_rec.ENDUSER_PART_NUM;
--    ls_enduser_po := skidinfo_rec.ENDUSER_PO;
x12_table(i) :='HL*0002**O'; i := i +1;
x12_table(i) :='LIN**ZZ*T*VO*'|| skidinfo_rec.ORIG_CUSTOMER_PO; i := i +1;
x12_table(i) :='FOB*PP'; i:=i+1;
x12_table(i):= 'N1*SF**01*' || ls_sf; i := i +1;
x12_table(i):= 'N1*MP**01*' || '021820469'; i := i +1;


x12_table(i):= 'N1*ST**ZZ*' || ls_st; i := i +1;
x12_table(i):= 'N1*MA**ZZ*' || ls_ic; i := i +1;

-- x12_table(i) :='SN1**' || to_char(ll_shipment_pc) ||'*EA*0'; i := i +1;
close alcan_ford_856_cur;

-- Third Level HL Under a P.O.
li_HL01 := 3;
for skidinfo_rec IN alcan_ford_856_cur
loop
if length(to_char(li_HL01)) = 1  then
x12_table(i) := 'HL*000' || to_char(li_HL01) || '**I'; i := i +1;
else
x12_table(i) := 'HL*00' || to_char(li_HL01) || '**I'; i := i +1;
end if;

x12_table(i) := 'LIN**CA*000000*ZZ*060*VU*'||to_char(skidinfo_rec.SHEET_SKID_NUM); i := i+1;
x12_table(i) :=  'SN1**1*PC'; i := i +1;
x12_table(i) :=  'MEA*PK*G*' || to_char(skidinfo_rec.sheet_net_wt+skidinfo_rec.sheet_tare_wt) || '*01'; i := i +1;
x12_table(i) :=  'MEA*PK*N*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; i := i +1;

x12_table(i) :=  'MEA*PK*WT*' || to_char(skidinfo_rec.sheet_theoretical_wt) || '*24'; i := i +1;

/* Additional information might be needed by Kaiser  */
x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.skid_pieces) || '*PC'; i := i +1;
/* End */



/*        ---------Not required by Kaiser
-- fill in lot num
SELECT count(*) INTO li_rc 	FROM sheet_skid_detail
WHERE sheet_skid_detail.sheet_skid_num = skidinfo_rec.sheet_skid_num;
if li_rc = 1 then
select lot_num  INTO skidinfo_rec.lot_num from coil where coil.coil_abc_num =
 (select coil_abc_num from production_sheet_item where production_sheet_item.prod_item_num =
 (select prod_item_num from sheet_skid_detail where sheet_skid_detail.sheet_skid_num = skidinfo_rec.sheet_skid_num ));
end if;

x12_table(i) :=  'REF*HC*' || skidinfo_rec.lot_num ; i := i +1;
x12_table(i) :=  'REF*LS*' || to_char(skidinfo_rec.sheet_skid_num); i := i +1;
  Not required by Kaiser   */

li_HL01 := li_HL01 + 1;

li_rowcount := alcan_ford_856_cur%ROWCOUNT;
x12_table(li_td1):= 'TD1*PKG01*' || to_char(li_rowcount);

end loop;

/* End of Skid Loop   */

-- DBMS_OUTPUT.PUT_LINE ('rowcount' || to_char(li_rowcount));


x12_table(i) :=  'CTT*' || to_char(li_HL01 - 1) ||'*' || to_char(li_rowcount) ;
i := i +1;
x12_table(i) :=  'SE*' || to_char (i-1) ||'*'|| to_char(ll_st_log);
i := i +1;
x12_table(i) :=  'GE*1*' || to_char (ll_gs_log); i := i + 1;
x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');

SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id FROM DUAL;

-- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
-- edi_file:= 'S_Kaiser_Kaiser' || to_char(ll_edi_file_id) ||'.x12';
edi_file := edi_file_prefix || to_char(ll_edi_file_id) ||'.edi';

edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');
for j in 0..i loop
 UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
--     v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
end loop;
UTL_FILE.FCLOSE(edi_file_handle);

/* Update flag */
  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  UPDATE shipment
     SET shipment_des_edi856_date= SYSDATE,
         shipment_edi856_date=SYSDATE,
         edi_file_id_856 = ll_edi_file_id
     WHERE shipment.packing_list = al_packing_list;
  COMMIT;


--exception
--   when invalid_operation
--   then
--      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

--  when others
--  then
 --      DBMS_OUTPUT.PUT_LINE ('System Error');
 --      UTL_FILE.FCLOSE(edi_file_handle);

return 1;
end edi_kaiser_856;
  GRANT EXECUTE ON "DBO"."EDI_KAISER_856" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function EDI_MISA_856_X12
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_MISA_856_X12" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*


  */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR');

  --edi_loc varchar2(50):='/tmp';
  edi_file        VARCHAR2(50) := 'edi_out.txt';
  --edi_file_prefix VARCHAR2(50) := 'S_misa_856_'; --Production
  edi_file_prefix VARCHAR2(50) := 's_misa_856_'; --Development
  edi_file_handle utl_file.file_type;

  li_customer_id    shipment.customer_id%TYPE;
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;
  ls_sf VARCHAR2(50);
  ls_eq_type VARCHAR2(10);
  ls_su      VARCHAR2(50);
  ls_st_duns VARCHAR2(50);
  ls_po      VARCHAR2(30);
  ls_auth_code   VARCHAR2(32);
  ll_gs_log  INTEGER;
  ll_st_log  INTEGER;
  ll_bsn_log INTEGER;

  ls_today VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD'); --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  ls_today_2digits_year VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD'); --Alex Gerlants. 10/16/2018. Test
  ls_now   VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  li_rowcount INTEGER;
  li_hl01 INTEGER;
  li_hl01_link   integer;
  ll_shipment_nt INTEGER;
  ll_shipment_nt_kg INTEGER;
  ll_shipment_gt INTEGER;
  ll_shipment_gt_kg INTEGER;
  ll_shipment_pc INTEGER;
  li_td1 INTEGER;
  --li_rc  INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_vehicle_id_prefix VARCHAR2(50);
  ls_scac              carrier.scac%TYPE;
  ls_carrier_full_name VARCHAR2(18);
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_carrier_initial   VARCHAR2(50);  -- Not used in stored procedure.  Discovered by Patrick Reynolds 11/30/2016
  ldt_shipment         DATE;
   ll_temp         INTEGER;
  ls_enduser_part VARCHAR2(50);
  li_des_id       INTEGER;

  ll_edi_file_id INTEGER;

  ls_lot_num VARCHAR2(32);
  --ls_coil_id VARCHAR2(32);
  ls_des_cust_name VARCHAR2(18);
  
  ls_coil_org_num		        coil.coil_org_num%TYPE;
  ll_coil_gauge		          coil.coil_gauge%TYPE;
  ll_coil_gauge_mm          number(10,3);
  ll_coil_width		          coil.coil_width%TYPE;
  ll_coil_width_mm          number(10,3);
  ll_skid_gross_weight      number(8);
  ld_ship_date              date;
  ln_skid_type_if_whed      sheet_skid.skid_type_if_whed%TYPE;
  li_skid_count             integer;
  ls_cust_short_name        customer.customer_short_name%TYPE;
  ll_coil_abc_num		        coil.coil_abc_num%TYPE;
  ls_cust_prod_line_id      order_item.cust_prod_line_id%TYPE;
  ls_orig_customer_po       customer_order.orig_customer_po%TYPE;
  ls_vo                     coil.vo%TYPE;
  ls_coil_alloy             coil.coil_alloy%TYPE;
  ls_coil_temper            coil.coil_temper%TYPE;
  ld_lineal_feed            inbound_coil.lineal_feed%TYPE;
  ld_created_date           customer_order.created_date%TYPE;
  li_count                  integer;
  ls_plant_code             customer.plant_code%TYPE;
  ll_customer_id            shipment.customer_id%TYPE;
  ls_customer_duns_number_string customer.customer_duns_number_string%TYPE;
  ls_des_cust_duns          customer.customer_duns_number_string%TYPE;
  ll_po_weight              integer;
  ll_po_skid_count          integer;
  ll_po_piece_count         integer;
  ll_po_weight_kg           integer;
  ls_billto_albl            shipment.billto_albl%TYPE;
  ll_skid_gross_weight_lb   integer;
  ll_skid_gross_weight_kg   integer;
  li_part_length            number(8,3);
  li_part_length_mm         number(8,3);
  ll_prod_item_net_wt_lb    production_sheet_item.prod_item_net_wt%TYPE;
  ll_prod_item_net_wt_kg    production_sheet_item.prod_item_net_wt%TYPE;

  CURSOR misa_856_cur IS
    SELECT sheet_packing_item.sh_packing_item,
           'MULTIPLE' lot_num,
           'MULTIPLE' coil_id,
           customer_order.orig_customer_po,
           customer_order.order_abc_num,
           customer_order.enduser_po,
           customer_order.created_date,
           order_item.order_item_num,
           order_item.enduser_part_num,
           order_item.supplier_code,
           order_item.gauge,
           sheet_skid. ab_job_num,
           sheet_skid.sheet_skid_num,
           sheet_skid.sheet_skid_display_num, --added by Victor H. on 06-2012 for Novelis locatio code request
           sheet_skid.sheet_net_wt,
           sheet_skid.sheet_tare_wt,
           sheet_skid.skid_pieces,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_theoretical_wt,
           NULL done,
           production_sheet_item.coil_abc_num,
           coil.coil_org_num,
           production_sheet_item.prod_item_net_wt,
           production_sheet_item.prod_item_pieces
      FROM customer_order,
           order_item,
           sheet_skid,
           ab_job,
           shipment,
           sheet_packing_item,
           sheet_skid_detail,
           production_sheet_item,
           coil
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       and (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       and (sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       and (production_sheet_item.coil_abc_num = coil.coil_abc_num)
       AND (shipment.packing_list = al_packing_list)
       and (customer_order.orig_customer_po = ls_orig_customer_po)
       order by sheet_skid.sheet_skid_num;
       
  cursor po_cur is
  select distinct customer_order.orig_customer_po, customer_order.created_date
  from   sheet_packing_item
         join sheet_skid on sheet_skid.sheet_skid_num = sheet_packing_item.sheet_skid_num
         join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
         join process_coil on ab_job.ab_job_num = process_coil.ab_job_num
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         join customer_order on customer_order.order_abc_num = sheet_skid.ref_order_abc_num
  where  sheet_packing_item.packing_list = al_packing_list;

  --TYPE skidinfo_tabletype IS TABLE OF misa_856_cur%ROWTYPE INDEX BY BINARY_INTEGER;
  --skidinfo_table skidinfo_tabletype;
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table    store_tabletype;
  i            BINARY_INTEGER := 0;
  skidinfo_rec misa_856_cur%ROWTYPE;
  po_rec       po_cur%ROWTYPE;
  
/*
  CURSOR c_ship_to IS
    SELECT DISTINCT des_sh_cust_id
      FROM shipment
     WHERE bill_of_lading = ll_bill_of_lading
       AND shipment.shipment_status = 0;
  
  cursor c_coil is
  select distinct 
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num,
         coil.coil_gauge,
         coil.coil_width
  from   customer_order
         join order_item on order_item.order_abc_num = customer_order.order_abc_num
         join ab_job on ab_job.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
         join sheet_skid on sheet_skid.ab_job_num = ab_job.ab_job_num
         join sheet_packing_item on sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
         join shipment on shipment.packing_list = sheet_packing_item.packing_list
         join process_coil on process_coil.ab_job_num = ab_job.ab_job_num
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         --join outbound_edi_transaction on outbound_edi_transaction.edi_file_id = shipment.edi_file_id_856
  --where  shipment.packing_list = 105586 --Production
  where  shipment.packing_list = al_packing_list --Development
  order by
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num;
*/  
  

BEGIN
  
  select customer_id
  into   ll_customer_id
  from   shipment
  where  packing_list = al_packing_list;
  
  /* Commented out. TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY
  if ll_customer_id <> 2244 then --Customer is NOT Misa
    return 1; --Nothing to do here
  end if;
  */

  select shipment_edi856_date
  into   ld_ship_date
  from   shipment
  where  shipment.packing_list = al_packing_list;
   
  if not (ld_ship_date is null) then --ASN already sent
    return 100;
  end if;


  

  -- edi_alcan_870; -- Send 870 first

  -- Get Customer ID, End user ID
  --SELECT customer_id, des_sh_cust_id
  --  INTO li_customer_id, li_des_sh_cust_id
  -- FROM shipment
  -- WHERE shipment.packing_list = al_packing_list;
  --IF NOT SQL%FOUND THEN
 --   RETURN - 1;
  --END IF;

  -- Get Customer ID, End user ID, authorization code
  SELECT customer_id, des_sh_cust_id, nvl(shipment_athorization_code, 'NA')
    INTO li_customer_id, li_des_sh_cust_id, ls_auth_code
  FROM shipment
  WHERE shipment.packing_list = al_packing_list;
  IF NOT SQL%FOUND THEN
   RETURN - 1;
  END IF;

  -- dbms_output.put_line (to_char(li_customer_id) || '  ' || to_char(li_des_sh_cust_id) );

  /*
  IF NOT (li_customer_id IN (34, 35, 10, 1153, 1459, 2582)) -- AND (li_des_sh_cust_id IN (
   THEN

    --***********************************************************************************************88
    --IF NOT ((li_customer_id IN (34,35,10,1153)) AND (li_des_sh_cust_id IN (SELECT CUSTOMER_ID
    --FROM CUSTOMER
    --WHERE CUSTOMER_DUNS_NUMBER_STRING is not null))) THEN

    RETURN 200;
  END IF;
  */

  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(sheet_skid.sheet_net_wt),
         SUM(sheet_skid.sheet_net_wt) + SUM(sheet_skid.sheet_tare_wt),
         SUM(sheet_skid.skid_pieces),
         count(distinct sheet_skid.sheet_skid_num)
    INTO ll_shipment_nt, ll_shipment_gt, ll_shipment_pc, li_skid_count
    FROM sheet_skid, sheet_packing_item, shipment
   WHERE shipment.packing_list = sheet_packing_item.packing_list
     AND sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
     AND shipment.packing_list = al_packing_list;
  IF ll_shipment_pc = 0 THEN
    RETURN 100;
  END IF; -- empty shipment

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  -- Retrieve ABCO info
  -- ls_sender_vanid := '3010007080';
  --ls_ic := 'R0P7A';

  -- Retrieve ALCAN supply code and Ford Stamping Plant location code
  --SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf
  --FROM customer_customer  WHERE o_customer_id = li_customer_id and e_customer_id = 49;  --Ford customer_id =49

  ls_sf := '039630926';
  --SELECT NVL(communication_code,'UNKNOWN') INTO ls_st FROM customer_system
  --WHERE customer_id = li_des_sh_cust_id;

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.vehicle_id_prefix, '9999'),
         nvl(shipment.equipment_type, 'NA'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'PT'), -- Protected Trailer
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE)
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_vehicle_id_prefix,
         ls_eq_type,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_carrier_initial,
         ldt_shipment
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;

  --Check all packing_lists are done against a BOL
  /*
  for pl_rec in packing_list_same_bol loop
      select shipment.shipment_status into ll_temp from shipment
             where shipment.packing_list = pl_rec.packing_list;
      if ll_temp > 0 then
         return pl_rec.packing_list;
      end if;

  end loop;
  */
  --End of packing list checking

  --SELECT nvl(customer_duns_number_string, '00000000'), customer_short_name
  SELECT nvl(customer_duns_number_string, '00000000'), nvl(plant_code, '00000000'), customer_short_name, nvl(customer_duns_number_string, '00000000')
--    INTO ls_st_duns, ls_des_cust_name
    INTO ls_st_duns, ls_plant_code, ls_des_cust_name, ls_des_cust_duns
    FROM customer
   WHERE customer_id = li_des_sh_cust_id;

   if (ls_plant_code = '00000000') THEN
      ls_plant_code := ls_st_duns;
      
      IF (ls_st_duns = '00000000') THEN
        RETURN 200;
      END IF; --No Ship to DUNS
   end if;

  SELECT nvl(customer_duns_number_string, '00000000'), upper(customer_short_name)
    INTO ls_su, ls_cust_short_name
    FROM customer
   WHERE customer_id = li_customer_id;
  IF (ls_su = '00000000') THEN
    RETURN 200;
  END IF; --No Supplier DUNS

  -- Get SCAC(Standard Carrier Alpha Code)
  SELECT nvl(carrier.scac, 'NONE'), LPAD(carrier.carrier_full_name, 17)
    INTO ls_scac, ls_carrier_full_name
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);
  
  --Email from Troy Haag received on Fri 5/20/2022 4:29 PM.
  --Approval email from Lisa received on Mon 5/23/2022 10:10 AM.
  --Change the last character from "*" to "@
  --Production
  --x12_table(i) := 'ISA*00*' ||
  --                '          *00*          *01*039630926T     *09*043071377GM    *' ||
  --                ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
  --                lpad(to_char(ll_gs_log), 9, '0') || '*0*P*|' || '~';
  
  --Development                
  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *ZZ*2NDSFTP        *09*043071377GM    *' ||
                  ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*T*|' || '~';
                  
  i := i + 1;

  --Alex Gerlants. 10/16/2018. Changed from "002002" to "004010"
  --Production
  --x12_table(1) := 'GS*SH*039630926T*' || '043071377GM' || '*' || ls_today || '*' ||
  --                ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010' || '~';
                  
  --Development
  x12_table(1) := 'GS*SH*2NDSFTP*' || '043071377GM' || '*' || ls_today || '*' ||
                 ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010' || '~';
                  
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_gs_log) || '~';
  i := i + 1;
  --x12_table(i):= 'BSN*00*' || to_char(ll_bill_of_lading) || '*' || ls_today || '*' || ls_now || '~';
  x12_table(i) := 'BSN*00*' || to_char(al_packing_list) || '*' || ls_today || '*' || ls_now || '~';
  i := i + 1;
  
  --Alex Gerlants. 08/07/2018.
  --Changed to populate with actual ship date instead of current date and time.
  --The reason is that when we send 856 on a later date, this date is not correct.
  --x12_table(i) := 'DTM*011*' || ls_today || '*' || ls_now;
  --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  --x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' || to_char(ldt_shipment, 'HH24MI') || '~';
  x12_table(i) := 'DTM*011*' || to_char(sysdate, 'YYYYMMDD*HHMI') || '*ED' || '~';
  i := i + 1;
  
  --Alex Gerlants. 10/18/2018. Changed from "YYMMDD" to "YYYYMMDD"
  --Moved here from the below
  --x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
   --               to_char(ldt_shipment, 'HH24MI') || '~';
  --i := i + 1;

  -- First Level HL
  x12_table(i) := 'HL*1**S*1' || '~';
  i := i + 1;
  
  select    count(*)
  into      li_skid_count
  from      sheet_packing_item
  where     packing_list = al_packing_list;
  
  ll_shipment_gt_kg := ll_shipment_gt * 0.453592;
  ll_shipment_nt_kg := ll_shipment_nt * 0.453592;
  
  --x12_table(i) := 'TD1*PLT90*' || to_char(li_skid_count) || '****G*' || to_char(ll_shipment_gt) || '*LB' || '~';
  
  x12_table(i) := 'MEA*PD*G*' || to_char(ll_shipment_gt) || '*LB' || '~';
  i := i + 1;
  
  x12_table(i) := 'MEA*PD*G*' || to_char(ll_shipment_gt_kg) || '*KG' || '~';
  i := i + 1;
  
  x12_table(i) := 'MEA*PD*N*' || to_char(ll_shipment_nt) || '*LB' || '~';
  --li_td1 := li_td1 + i;
  i := i + 1;
  
  --x12_table(i) := 'TD1*PLT90*' || to_char(li_skid_count) || '****N*' || to_char(ll_shipment_nt) || '*LB' || '~';
  x12_table(i) := 'MEA*PD*N*' || to_char(ll_shipment_nt_kg) || '*KG' || '~';
  --li_td1 := li_td1 + i;
  i := i + 1;
  
  x12_table(i) := 'TD1*LIF52*' || To_char(li_skid_count) || '~';
  i := i + 1;
  
  --TD5*O*2*SCAC*M*SCAC DESC*CL~
  --TD3*TL*SCAC
  
  x12_table(i) := 'TD5*O*2*' || ls_scac || '*M*' || ltrim(rtrim(ls_carrier_full_name)) || '*CL' || '~';
  i := i + 1;
  
  x12_table(i) := 'TD3*' || ls_carrier_desc_code || '*' || ls_scac || '*' || ls_vehicle_id_prefix || '~';
  i := i + 1;
  
  x12_table(i) := 'REF*BM*' || to_char(al_packing_list) || '~';
  i := i + 1;
 
  --
  x12_table(i) := 'REF*MB*' || to_char(ll_bill_of_lading) || '~';
  i := i + 1;
  
  select   nvl(billto_albl, 'N')
  into     ls_billto_albl
  from     shipment
  where    packing_list = al_packing_list;
  
  if ls_billto_albl = 'N' then
    x12_table(i) := 'FOB*PP' || '~';
  else
    x12_table(i) := 'FOB*PO' || '~';
  end if;
  i := i + 1;

  SELECT COUNT(*)
    INTO ll_temp
    FROM shipment
   WHERE shipment.bill_of_lading = ll_bill_of_lading
     AND shipment.shipment_status = 0;
     
  --Alex Gerlants. 10/16/2018. Removed 2 lines below
  --x12_table(i) := 'REF*SS*' || to_char(ll_temp);
  --i := i + 1;
  li_des_id := 1;
  
  --N1*OU**1*DUNS~
  --N1*MF**1*DUNS~
  --N1*SF**1*DUNS~
  --N1*ST**1*DUNS~
  
  x12_table(i) := 'N1*OU**1*' || ls_sf || '~';
  i := i + 1;
  
  select customer_duns_number_string 
  into   ls_customer_duns_number_string  
  from   customer
  where  customer_id = li_des_sh_cust_id;
  
  x12_table(i) := 'N1*MF*' || ls_customer_duns_number_string || '~'; --Misa DUNS
  i := i + 1;
  
  x12_table(i) := 'N1*SF*1*' || ls_sf || '~';
  i := i + 1;
  
  --x12_table(i) := 'N1*ST*' || rtrim(ltrim(ls_des_cust_name)) || '*1*' || ls_st_duns;
  x12_table(i) := 'N1*ST**1*' || ls_st_duns || '~';
  i := i + 1;
  


  -- Second Level HL based on End User PO( only one part# is included in one shipement per FORD's request)
--  OPEN misa_856_cur;
--  FETCH misa_856_cur
--    INTO skidinfo_rec;

/*
  SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
    INTO ls_enduser_part
    FROM "ORDER_ITEM", "SHEET_SKID"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
     AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
     AND ("SHEET_SKID"."SHEET_SKID_NUM" = skidinfo_rec.sheet_skid_num);
*/

  /*
      SELECT "CUSTOMER_ORDER"."ENDUSER_PO" into ls_enduser_po
             FROM "SHEET_SKID",
                  "CUSTOMER_ORDER"
                  WHERE ( "SHEET_SKID"."REF_ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM" ) and
                        (SHEET_SKID.SHEET_SKID_NUM = skidinfo_rec.SHEET_SKID_NUM);
  */

  /*
  x12_table(i) := 'HL*2*1*O' || '~';
  i := i + 1;
  IF ls_enduser_part IS NULL THEN
    ls_enduser_part := 'NA';
  END IF;

  SELECT "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO"
    INTO ls_po
    FROM "SHEET_SKID", "CUSTOMER_ORDER"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
         "CUSTOMER_ORDER"."ORDER_ABC_NUM")
     AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num);

  for po_rec in po_cur loop --******************************************************
    ls_orig_customer_po := po_rec.orig_customer_po;
    ld_created_date := po_rec.created_date;
    
    x12_table(i) := 'PRF*' || ls_orig_customer_po || '***' ||
                    to_char(ld_created_date, 'YYYYMMDD') || '~';
    i := i + 1;
  end loop;
  */

  --CLOSE misa_856_cur;

  -- Third Level HL Under a P.O.
  li_hl01 := 2;

  for po_rec in po_cur loop
    ls_orig_customer_po := po_rec.orig_customer_po;
    ld_created_date := po_rec.created_date;
    
    --x12_table(i) := 'HL*2*1*O' || '~';
    x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || '1' || '*O' || '~';
    i := i + 1;
    li_hl01_link := li_hl01;
    li_hl01 := li_hl01 + 1;
    
    x12_table(i) := 'LIN**PO*' || ls_orig_customer_po || '~';
    i := i + 1;
    
    select sum(sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt), 
           count(distinct sheet_skid.sheet_skid_num),
           sum(sheet_skid.skid_pieces)
    into   ll_po_weight, 
           ll_po_skid_count,
           ll_po_piece_count
    from   sheet_skid
    where  sheet_skid_num in
    (
      select distinct sheet_skid.sheet_skid_num
      from   sheet_packing_item
             join sheet_skid on sheet_skid.sheet_skid_num = sheet_packing_item.sheet_skid_num
             join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
             join process_coil on ab_job.ab_job_num = process_coil.ab_job_num
             join coil on coil.coil_abc_num = process_coil.coil_abc_num
             --join customer_order on customer_order.order_abc_num = sheet_skid.ref_order_abc_num
             join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
             join order_item on order_item.order_abc_num = ab_job.order_abc_num and  order_item.order_item_num = ab_job.order_item_num
      where  customer_order.orig_customer_po = ls_orig_customer_po and sheet_packing_item.packing_list = al_packing_list
    );
    
    ll_po_weight_kg := ll_po_weight * 0.453592;
    
    x12_table(i) := 'SN1**' || to_char(ll_po_weight) || '*LB' || '~';
    i := i + 1;
    
    x12_table(i) := 'SN1**' || to_char(ll_po_weight_kg) || '*KG' || '~';
    i := i + 1;
    
    x12_table(i) := 'PRF*' || ls_orig_customer_po || '~';
    i := i + 1;
    
    x12_table(i) := 'MEA*CT*NL*' || ll_po_piece_count || '*PC' || '~';
    i := i + 1;

    --Skid loop begin ----------------------------------------------------------------
    FOR skidinfo_rec IN misa_856_cur LOOP
        
        --In case of a split skid, we are creating just 1 HL for this skid
        --with just 1 coil for this skid.
        select distinct
               coil.coil_abc_num, 
               coil.coil_org_num,
               coil.coil_gauge,
               coil.coil_width,
               coil.lot_num,
               nvl(skid_type_if_whed, -1),
               coil.vo,
               coil.coil_alloy,
               coil.coil_temper
        into   ll_coil_abc_num,
               ls_coil_org_num,
               ll_coil_gauge,
               ll_coil_width,
               ls_lot_num,
               ln_skid_type_if_whed, --Alex Gerlants. 04/01/2019
               ls_vo,
               ls_coil_alloy,
               ls_coil_temper
        FROM "COIL",   
             "PRODUCTION_SHEET_ITEM",   
             "SHEET_SKID",   
             "SHEET_SKID_DETAIL",   
             "PROCESS_COIL"  
       WHERE ( "COIL"."COIL_ABC_NUM" = "PRODUCTION_SHEET_ITEM"."COIL_ABC_NUM" ) and  
             ( "SHEET_SKID_DETAIL"."SHEET_SKID_NUM" = "SHEET_SKID"."SHEET_SKID_NUM" ) and  
             ( "SHEET_SKID_DETAIL"."PROD_ITEM_NUM" = "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NUM" ) and  
             ( "COIL"."COIL_ABC_NUM" = "PROCESS_COIL"."COIL_ABC_NUM" ) and  
             ( "PRODUCTION_SHEET_ITEM"."AB_JOB_NUM" = "PROCESS_COIL"."AB_JOB_NUM" ) and  
             ( (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num)  ) and
             ( (rownum = 1)  ); --We need just 1 coil for each skid
      
        --Alex Gerlants. 04/01/2019. Begin
        --if ln_skid_type_if_whed > -1 then --Warehouse skid
            --Get gauge and part width
            select distinct order_item.gauge,
                   f_get_part_width_per_job(ab_job.ab_job_num),
                   enduser_part_num,
                   nvl(cust_prod_line_id, '')
            into   ll_coil_gauge,
                   ll_coil_width,
                   ls_enduser_part,
                   ls_cust_prod_line_id
            from   sheet_skid
                   join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
                   join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
                   join customer_order on customer_order.order_abc_num = order_item.order_abc_num
            where  sheet_skid_num = skidinfo_rec.sheet_skid_num
            and    (order_item.gauge is not null and f_get_part_width_per_job(sheet_skid.ab_job_num) is not null)
            and    rownum = 1;
        --end if;
        --Alex Gerlants. 04/01/2019. End
      
        --IF length(to_char(li_hl01)) = 1 THEN
          x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hl01_link) || '*I' || '~';
          i := i + 1;
        --ELSE
        --  x12_table(i) := 'HL*' || to_char(li_hl01) || '*2*I' || '~';
        --  i := i + 1;
        --END IF;
          
        /* Alex Gerlants. 01/02/2023. Comment out begin
        select distinct 
                  inbound_coil.vo, inbound_coil.lot, inbound_coil.lineal_feed
        into      ls_vo, ls_lot_num, ld_lineal_feed
        from      inbound_coil
                  join inbound_coil_status on inbound_coil_status.coil_number = inbound_coil.coil_number
        where     inbound_coil_status.coil_abc_num = ll_coil_abc_num;
        */
        --Alex Gerlants. 01/02/2023. Comment out end
          
        --Alex Gerlants. 01/02/2023. New SQL statement. Join inbound_coil with coil instead of inbound_coil_status, Begin
        --Count first...just in case
        select    count(*)
        into      li_count
        from      inbound_coil
                  join coil on coil.coil_org_num = inbound_coil.coil_number
        where     coil.coil_abc_num = ll_coil_abc_num;
          
        if li_count > 0 then
          select distinct 
                    inbound_coil.vo, inbound_coil.lot, inbound_coil.lineal_feed
          into      ls_vo, ls_lot_num, ld_lineal_feed
          from      inbound_coil
                    join coil on coil.coil_org_num = inbound_coil.coil_number
          where     coil.coil_abc_num = ll_coil_abc_num; 
        else
          ls_vo := '';
          ls_lot_num := '';
          ld_lineal_feed := 0;
        end if;     
        --Alex Gerlants. 01/02/2023. New SQL statement. Join inbound_coil with coil instead of inbound_coil_status. End      
          
        --x12_table(i) := 'HL*' || to_char(li_hl01) || '*2*I' || '~';
        
        x12_table(i) := 'SN1**' || to_char(skidinfo_rec.prod_item_pieces) || '*PC' || '~';
        i := i + 1;
        
        ll_skid_gross_weight := skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt;
        ll_skid_gross_weight_lb := (skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt);
        ll_skid_gross_weight_kg := (skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt) * 0.453592;
        ll_prod_item_net_wt_lb := skidinfo_rec.prod_item_net_wt;
        ll_prod_item_net_wt_kg := skidinfo_rec.prod_item_net_wt * 0.453592;
        
        x12_table(i) := 'MEA*WT*WT*' || to_char(ll_skid_gross_weight) || '*LB' || '~';
        i := i + 1;
        
        x12_table(i) := 'MEA*WT*WT*' || to_char(ll_prod_item_net_wt_kg) || '*KG' || '~';
        i := i + 1;
        
        ll_coil_gauge := skidinfo_rec.gauge;
        
        --x12_table(i) := 'MEA*PD*TH*' || to_char(ll_coil_gauge) || '*ED' || '~';
        --i := i + 1;
        
        --x12_table(i) := 'LIN*1*BP*' || ls_enduser_part || '*SN*' || ls_coil_org_num || '*HN*' || ls_lot_num || '*LS*' || to_char(ll_coil_abc_num) || '*JN*' || ls_vo || '~';
        --i := i + 1;
          
        --x12_table(i) := 'PID*S*55**' || ls_coil_alloy || '~';
        --i := i + 1;
          
        --x12_table(i) := 'PID*S*16**' || ls_coil_temper || '~';
        --i := i + 1;

        
                            
        --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*WT" to "MEA*CT*NL"
        --x12_table(i) := 'MEA*CT*NL*' || to_char(skidinfo_rec.skid_pieces) || '*PC' || '~';
        --i := i + 1;

        -- changed to all gross wt per novelis 1/30/2015
        --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*G" to "MEA*WT*G"
        --x12_table(i) := 'MEA*WT*G*' || to_char(skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt) || '*01';
        --i := i + 1;
    
        ll_coil_gauge_mm := ll_coil_gauge * 25.4;
        ll_coil_width_mm := ll_coil_width * 25.4;
    
        x12_table(i) := 'MEA*PD*TH*' || ltrim(rtrim(to_char(ll_coil_gauge, '0.0000'))) || '*IN' || '~'; --Inches
        i := i + 1;
        
        x12_table(i) := 'MEA*PD*TH*' || ltrim(rtrim(to_char(ll_coil_gauge_mm, '0.0000'))) || '*MM' || '~'; --Millimeters
        i := i + 1;

        x12_table(i) := 'MEA*PD*WD*' || to_char(ll_coil_width) || '*IN' || '~'; --Inches
        i := i + 1;
        
        x12_table(i) := 'MEA*PD*WD*' || to_char(ll_coil_width_mm) || '*MM' || '~'; --Millimeters
        i := i + 1;
        
        select f_get_part_dims_4order_item(skidinfo_rec.order_abc_num, skidinfo_rec.order_item_num, 'length')
        into   li_part_length
        from   dual;
        
        x12_table(i) := 'MEA*PD*LN*' || to_char(li_part_length) || '*IN' || '~';
        i := i + 1;
        
        li_part_length_mm := li_part_length * 25.4;
        
        x12_table(i) := 'MEA*PD*LN*' || to_char(li_part_length_mm) || '*MM' || '~';
        i := i + 1;

        x12_table(i) := 'REF*SE*' || skidinfo_rec.sheet_skid_display_num || '~';
        i := i + 1;
        
        select   coil_org_num
        into     ls_coil_org_num
        from     coil
        where    coil_abc_num = skidinfo_rec.coil_abc_num;
        
        x12_table(i) := 'REF*SN*' || ls_coil_org_num || '~';
        i := i + 1;
          
        --Alex Gerlants. 10/18/2018. New line 
        --x12_table(i) := 'REF*LS*' || ls_coil_org_num;
        --i := i + 1;
          
        li_hl01 := li_hl01 + 1;
        li_rowcount := misa_856_cur%ROWCOUNT;
        --x12_table(li_td1) := 'TD1*PLT90*' || to_char(li_rowcount);
    END LOOP; --End of 'FOR skidinfo_rec IN misa_856_cur LOOP'
    --Skid loop end ------------------------------------------------------------------
  end loop; --for po_rec in po_cur loop
  
  --CLOSE misa_856_cur;

  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                  to_char(li_rowcount + ll_shipment_pc) || '~';
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_gs_log) || '~';
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log) || '~';
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0') || '~';

  -- Write X.12 to file
  -- To FORD

  /** Write file to /templar/templar/incoming/senddata
  /*
  **/

  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  --edi_file:= 'S_alcan_ford_ford_' || to_char(ll_edi_file_id) ||'.x12';

  -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
  -- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
  edi_file := edi_file_prefix || 'BOL_' || to_char(al_packing_list) || '_' || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
    --        v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
  END LOOP;
  utl_file.fclose(edi_file_handle);

  --To ALCAN

  /*
  SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;
  SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id_alcan FROM DUAL;
  edi_file:= 'S_alcan_ford_alcan_' || to_char(ll_edi_file_id_alcan) ||'.x12';
  edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');
  x12_table(0) := 'ISA*00*'||'          *00*          *01*039630926T     *09*0015049350011G *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0')||'*0*P**';
  x12_table(1) := 'GS*SH*R0P7A*'||'001504935001' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  x12_table(i-1) :=  'GE*1*' || to_char (ll_gs_log);
  x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');
  for j in 0..i loop
   UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
       v_edi_text_alcan:=v_edi_text_alcan||x12_table(j)||CHR(10);
  end loop;
  UTL_FILE.FCLOSE(edi_file_handle);

  */

  /* The following code added by Tony, for update archive*/

  --  INSERT INTO edi_log (edi_log_timestamp,customer_id,
  --         customer_edi_name,edi_log_contents,edi_file_id,edi_text)
  --    VALUES (SYSDATE,li_customer_id,ll_customer_edi_name,
  --           'EDI:'||ll_customer_edi_name||' generated successfully.',ll_edi_file_id,v_edi_text);
  --   COMMIT;

  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  
  /*  TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE,
         edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;
   */


--  COMMIT;

  /* --added by Victor Huang on 06/05 for function acknowlegement
  INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
  VALUES(ll_gs_log, ls_su, sysdate, edi_file);
  COMMIT;*/

  /*  TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY
  INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (ll_edi_file_id,
     '039630926',
     ls_su,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856');
  */
     
  COMMIT;

  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  --exception
  --   when invalid_operation
  --   then
  --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

  --  when others
  --  then
  --      DBMS_OUTPUT.PUT_LINE ('System Error');
  --      UTL_FILE.FCLOSE(edi_file_handle);

  RETURN 1;
END edi_misa_856_X12;
--------------------------------------------------------
--  DDL for Function EDI_MISA_856_X12_4BOL
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_MISA_856_X12_4BOL" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*


  */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR');

  --edi_loc varchar2(50):='/tmp';
  edi_file        VARCHAR2(50) := 'edi_out.txt';
  --edi_file_prefix VARCHAR2(50) := 'S_misa_856_'; --Production
  edi_file_prefix VARCHAR2(50) := 's_misa_856_'; --Development
  edi_file_handle utl_file.file_type;

  li_customer_id    shipment.customer_id%TYPE;
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;
  ls_sf VARCHAR2(50);
  ls_eq_type VARCHAR2(10);
  ls_su      VARCHAR2(50);
  ls_st_duns VARCHAR2(50);
  ls_po      VARCHAR2(30);
  ls_auth_code   VARCHAR2(32);
  ll_gs_log  INTEGER;
  ll_st_log  INTEGER;
  ll_bsn_log INTEGER;

  ls_today VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD'); --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  ls_today_2digits_year VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD'); --Alex Gerlants. 10/16/2018. Test
  ls_now   VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  li_rowcount INTEGER;
  li_hl01 INTEGER;
  li_hl01_link   integer;
  ll_shipment_nt INTEGER;
  ll_shipment_nt_kg INTEGER;
  ll_shipment_gt INTEGER;
  ll_shipment_gt_kg INTEGER;
  ll_shipment_pc INTEGER;
  li_td1 INTEGER;
  --li_rc  INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_vehicle_id_prefix VARCHAR2(50);
  ls_scac              carrier.scac%TYPE;
  ls_carrier_full_name VARCHAR2(18);
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_carrier_initial   VARCHAR2(50);  -- Not used in stored procedure.  Discovered by Patrick Reynolds 11/30/2016
  ldt_shipment         DATE;
   ll_temp         INTEGER;
  ls_enduser_part VARCHAR2(50);
  li_des_id       INTEGER;

  ll_edi_file_id INTEGER;

  ls_lot_num VARCHAR2(32);
  --ls_coil_id VARCHAR2(32);
  ls_des_cust_name VARCHAR2(18);
  
  ls_coil_org_num		        coil.coil_org_num%TYPE; --Alex Gerlants. 01/25/2019
  ll_coil_gauge		          coil.coil_gauge%TYPE;   --Alex Gerlants. 01/25/2019
  ll_coil_width		          coil.coil_width%TYPE;   --Alex Gerlants. 01/25/2019
  ld_ship_date              date;
  --li_is_constellium         integer;
  ln_skid_type_if_whed      sheet_skid.skid_type_if_whed%TYPE;   --Alex Gerlants. 04/01/2019
  li_skid_count             integer;
  ls_cust_short_name        customer.customer_short_name%TYPE;
  ll_coil_abc_num		        coil.coil_abc_num%TYPE;
  ls_cust_prod_line_id      order_item.cust_prod_line_id%TYPE;
  ls_orig_customer_po       customer_order.orig_customer_po%TYPE;
  ls_vo                     coil.vo%TYPE;
  ls_coil_alloy             coil.coil_alloy%TYPE;
  ls_coil_temper            coil.coil_temper%TYPE;
  ld_lineal_feed            inbound_coil.lineal_feed%TYPE;
  ld_created_date           customer_order.created_date%TYPE;
  li_count                  integer;
  ls_plant_code             customer.plant_code%TYPE;
  ll_customer_id            shipment.customer_id%TYPE;
  ls_customer_duns_number_string customer.customer_duns_number_string%TYPE;
  ls_des_cust_duns          customer.customer_duns_number_string%TYPE;
  ll_po_weight              integer;
  ll_po_skid_count          integer;
  ll_po_piece_count         integer;
  ll_po_weight_kg           integer;
  ls_billto_albl            shipment.billto_albl%TYPE;
  ll_skid_gross_weight_lb   integer;
  ll_skid_gross_weight_kg   integer;
  li_part_length            number(8,3);
  ll_prod_item_net_wt_lb    production_sheet_item.prod_item_net_wt%TYPE;
  ll_prod_item_net_wt_kg    production_sheet_item.prod_item_net_wt%TYPE;

  CURSOR misa_856_cur IS
    SELECT sheet_packing_item.sh_packing_item,
           'MULTIPLE' lot_num,
           'MULTIPLE' coil_id,
           customer_order.orig_customer_po,
           customer_order.order_abc_num,
           customer_order.enduser_po,
           customer_order.created_date,
           order_item.order_item_num,
           order_item.enduser_part_num,
           order_item.supplier_code,
           order_item.gauge,
           sheet_skid. ab_job_num,
           sheet_skid.sheet_skid_num,
           sheet_skid.sheet_skid_display_num, --added by Victor H. on 06-2012 for Novelis locatio code request
           sheet_skid.sheet_net_wt,
           sheet_skid.sheet_tare_wt,
           sheet_skid.skid_pieces,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_theoretical_wt,
           NULL done,
           production_sheet_item.coil_abc_num,
           coil.coil_org_num,
           production_sheet_item.prod_item_net_wt,
           production_sheet_item.prod_item_pieces
      FROM customer_order,
           order_item,
           sheet_skid,
           ab_job,
           shipment,
           sheet_packing_item,
           sheet_skid_detail,
           production_sheet_item,
           coil
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       and (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       and (sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       and (production_sheet_item.coil_abc_num = coil.coil_abc_num)
       AND (shipment.packing_list = al_packing_list)
       and (customer_order.orig_customer_po = ls_orig_customer_po)
       order by sheet_skid.sheet_skid_num;
       
  cursor po_cur is
  select distinct customer_order.orig_customer_po, customer_order.created_date
  from   sheet_packing_item
         join sheet_skid on sheet_skid.sheet_skid_num = sheet_packing_item.sheet_skid_num
         join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
         join process_coil on ab_job.ab_job_num = process_coil.ab_job_num
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         join customer_order on customer_order.order_abc_num = sheet_skid.ref_order_abc_num
  where  sheet_packing_item.packing_list = al_packing_list;

  --TYPE skidinfo_tabletype IS TABLE OF misa_856_cur%ROWTYPE INDEX BY BINARY_INTEGER;
  --skidinfo_table skidinfo_tabletype;
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table    store_tabletype;
  i            BINARY_INTEGER := 0;
  skidinfo_rec misa_856_cur%ROWTYPE;
  po_rec       po_cur%ROWTYPE;
  
/*
  CURSOR c_ship_to IS
    SELECT DISTINCT des_sh_cust_id
      FROM shipment
     WHERE bill_of_lading = ll_bill_of_lading
       AND shipment.shipment_status = 0;
  
  cursor c_coil is
  select distinct 
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num,
         coil.coil_gauge,
         coil.coil_width
  from   customer_order
         join order_item on order_item.order_abc_num = customer_order.order_abc_num
         join ab_job on ab_job.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
         join sheet_skid on sheet_skid.ab_job_num = ab_job.ab_job_num
         join sheet_packing_item on sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
         join shipment on shipment.packing_list = sheet_packing_item.packing_list
         join process_coil on process_coil.ab_job_num = ab_job.ab_job_num
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         --join outbound_edi_transaction on outbound_edi_transaction.edi_file_id = shipment.edi_file_id_856
  --where  shipment.packing_list = 105586 --Production
  where  shipment.packing_list = al_packing_list --Development
  order by
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num;
*/  
  

BEGIN
  
  select customer_id
  into   ll_customer_id
  from   shipment
  where  packing_list = al_packing_list;
  
  /* Commented out. TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY
  if ll_customer_id <> 2244 then --Customer is NOT Misa
    return 1; --Nothing to do here
  end if;
  */

  select shipment_edi856_date
  into   ld_ship_date
  from   shipment
  where  shipment.packing_list = al_packing_list;
   
  if not (ld_ship_date is null) then --ASN already sent
    return 100;
  end if;


  

  -- edi_alcan_870; -- Send 870 first

  -- Get Customer ID, End user ID
  --SELECT customer_id, des_sh_cust_id
  --  INTO li_customer_id, li_des_sh_cust_id
  -- FROM shipment
  -- WHERE shipment.packing_list = al_packing_list;
  --IF NOT SQL%FOUND THEN
 --   RETURN - 1;
  --END IF;

  -- Get Customer ID, End user ID, authorization code
  SELECT customer_id, des_sh_cust_id, nvl(shipment_athorization_code, 'NA')
    INTO li_customer_id, li_des_sh_cust_id, ls_auth_code
  FROM shipment
  WHERE shipment.packing_list = al_packing_list;
  IF NOT SQL%FOUND THEN
   RETURN - 1;
  END IF;

  -- dbms_output.put_line (to_char(li_customer_id) || '  ' || to_char(li_des_sh_cust_id) );

  /*
  IF NOT (li_customer_id IN (34, 35, 10, 1153, 1459, 2582)) -- AND (li_des_sh_cust_id IN (
   THEN

    --***********************************************************************************************88
    --IF NOT ((li_customer_id IN (34,35,10,1153)) AND (li_des_sh_cust_id IN (SELECT CUSTOMER_ID
    --FROM CUSTOMER
    --WHERE CUSTOMER_DUNS_NUMBER_STRING is not null))) THEN

    RETURN 200;
  END IF;
  */

  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(sheet_skid.sheet_net_wt),
         SUM(sheet_skid.sheet_net_wt) + SUM(sheet_skid.sheet_tare_wt),
         SUM(sheet_skid.skid_pieces),
         count(distinct sheet_skid.sheet_skid_num)
    INTO ll_shipment_nt, ll_shipment_gt, ll_shipment_pc, li_skid_count
    FROM sheet_skid, sheet_packing_item, shipment
   WHERE shipment.packing_list = sheet_packing_item.packing_list
     AND sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
     AND shipment.packing_list = al_packing_list;
  IF ll_shipment_pc = 0 THEN
    RETURN 100;
  END IF; -- empty shipment

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  -- Retrieve ABCO info
  -- ls_sender_vanid := '3010007080';
  --ls_ic := 'R0P7A';

  -- Retrieve ALCAN supply code and Ford Stamping Plant location code
  --SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf
  --FROM customer_customer  WHERE o_customer_id = li_customer_id and e_customer_id = 49;  --Ford customer_id =49

  ls_sf := '039630926';
  --SELECT NVL(communication_code,'UNKNOWN') INTO ls_st FROM customer_system
  --WHERE customer_id = li_des_sh_cust_id;

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.vehicle_id_prefix, '9999'),
         nvl(shipment.equipment_type, 'NA'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'PT'), -- Protected Trailer
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE)
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_vehicle_id_prefix,
         ls_eq_type,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_carrier_initial,
         ldt_shipment
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;

  --Check all packing_lists are done against a BOL
  /*
  for pl_rec in packing_list_same_bol loop
      select shipment.shipment_status into ll_temp from shipment
             where shipment.packing_list = pl_rec.packing_list;
      if ll_temp > 0 then
         return pl_rec.packing_list;
      end if;

  end loop;
  */
  --End of packing list checking

  --SELECT nvl(customer_duns_number_string, '00000000'), customer_short_name
  SELECT nvl(customer_duns_number_string, '00000000'), nvl(plant_code, '00000000'), customer_short_name, nvl(customer_duns_number_string, '00000000')
--    INTO ls_st_duns, ls_des_cust_name
    INTO ls_st_duns, ls_plant_code, ls_des_cust_name, ls_des_cust_duns
    FROM customer
   WHERE customer_id = li_des_sh_cust_id;

   if (ls_plant_code = '00000000') THEN
      ls_plant_code := ls_st_duns;
      
      IF (ls_st_duns = '00000000') THEN
        RETURN 200;
      END IF; --No Ship to DUNS
   end if;

  SELECT nvl(customer_duns_number_string, '00000000'), upper(customer_short_name)
    INTO ls_su, ls_cust_short_name
    FROM customer
   WHERE customer_id = li_customer_id;
  IF (ls_su = '00000000') THEN
    RETURN 200;
  END IF; --No Supplier DUNS

  -- Get SCAC(Standard Carrier Alpha Code)
  SELECT nvl(carrier.scac, 'NONE'), LPAD(carrier.carrier_full_name, 17)
    INTO ls_scac, ls_carrier_full_name
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);
  
  --Email from Troy Haag received on Fri 5/20/2022 4:29 PM.
  --Approval email from Lisa received on Mon 5/23/2022 10:10 AM.
  --Change the last character from "*" to "@
  --Production
  --x12_table(i) := 'ISA*00*' ||
  --                '          *00*          *01*039630926T     *09*043071377GM    *' ||
  --                ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
  --                lpad(to_char(ll_gs_log), 9, '0') || '*0*P*@' || '~';
  
  --Development                
  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *ZZ*2NDSFTP        *09*043071377GM    *' ||
                  ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*T**' || '~';
                  
  i := i + 1;

  --Alex Gerlants. 10/16/2018. Changed from "002002" to "004010"
  --Production
  --x12_table(1) := 'GS*SH*039630926T*' || '043071377GM' || '*' || ls_today || '*' ||
  --                ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010' || '~';
                  
  --Development
  x12_table(1) := 'GS*SH*2NDSFTP*' || '043071377GM' || '*' || ls_today || '*' ||
                 ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010' || '~';
                  
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_gs_log) || '~';
  i := i + 1;
  --x12_table(i):= 'BSN*00*' || to_char(ll_bill_of_lading) || '*' || ls_today || '*' || ls_now || '~';
  x12_table(i) := 'BSN*00*' || to_char(al_packing_list) || '*' || ls_today || '*' || ls_now || '~';
  i := i + 1;
  
  --Alex Gerlants. 08/07/2018.
  --Changed to populate with actual ship date instead of current date and time.
  --The reason is that when we send 856 on a later date, this date is not correct.
  --x12_table(i) := 'DTM*011*' || ls_today || '*' || ls_now;
  --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  --x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' || to_char(ldt_shipment, 'HH24MI') || '~';
  x12_table(i) := 'DTM*011*' || to_char(sysdate, 'YYYYMMDD*HHMI') || '*ED' || '~';
  i := i + 1;
  
  --Alex Gerlants. 10/18/2018. Changed from "YYMMDD" to "YYYYMMDD"
  --Moved here from the below
  --x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
   --               to_char(ldt_shipment, 'HH24MI') || '~';
  --i := i + 1;

  -- First Level HL
  x12_table(i) := 'HL*1**S*1' || '~';
  i := i + 1;
  
  select    count(*)
  into      li_skid_count
  from      sheet_packing_item
  where     packing_list = al_packing_list;
  
  ll_shipment_gt_kg := ll_shipment_gt * 0.453592;
  ll_shipment_nt_kg := ll_shipment_nt * 0.453592;
  
  --x12_table(i) := 'TD1*PLT90*' || to_char(li_skid_count) || '****G*' || to_char(ll_shipment_gt) || '*LB' || '~';
  x12_table(i) := 'MEA*PD*G*' || to_char(ll_shipment_gt_kg) || '*KG' || '~';
  li_td1 := i;
  i := i + 1;
  
  --x12_table(i) := 'TD1*PLT90*' || to_char(li_skid_count) || '****N*' || to_char(ll_shipment_nt) || '*LB' || '~';
  x12_table(i) := 'MEA*PD*N*' || to_char(ll_shipment_nt_kg) || '*KG' || '~';
  li_td1 := li_td1 + i;
  i := i + 1;
  
  x12_table(i) := 'TD1*LIF52*' || To_char(li_skid_count) || '~';
  i := i + 1;
  
  --TD5*O*2*SCAC*M*SCAC DESC*CL~
  --TD3*TL*SCAC
  
  x12_table(i) := 'TD5*O*2*' || ls_scac || '*M*' || ltrim(rtrim(ls_carrier_full_name)) || '*CL' || '~';
  i := i + 1;
  
  x12_table(i) := 'TD3*' || ls_carrier_desc_code || '*' || ls_scac || '*' || ls_vehicle_id_prefix || '~';
  i := i + 1;
  
  x12_table(i) := 'REF*BM*' || to_char(al_packing_list) || '~';
  i := i + 1;
 
  --
  x12_table(i) := 'REF*MB*' || to_char(ll_bill_of_lading) || '~';
  i := i + 1;
  
  select   nvl(billto_albl, 'N')
  into     ls_billto_albl
  from     shipment
  where    packing_list = al_packing_list;
  
  if ls_billto_albl = 'N' then
    x12_table(i) := 'FOB*PP' || '~';
  else
    x12_table(i) := 'FOB*PO' || '~';
  end if;
  i := i + 1;

  SELECT COUNT(*)
    INTO ll_temp
    FROM shipment
   WHERE shipment.bill_of_lading = ll_bill_of_lading
     AND shipment.shipment_status = 0;
     
  --Alex Gerlants. 10/16/2018. Removed 2 lines below
  --x12_table(i) := 'REF*SS*' || to_char(ll_temp);
  --i := i + 1;
  li_des_id := 1;
  
  --N1*OU**1*DUNS~
  --N1*MF**1*DUNS~
  --N1*SF**1*DUNS~
  --N1*ST**1*DUNS~
  
  x12_table(i) := 'N1*OU**1*' || ls_sf || '~';
  i := i + 1;
  
  select customer_duns_number_string 
  into   ls_customer_duns_number_string  
  from   customer
  where  customer_id = li_des_sh_cust_id;
  
  x12_table(i) := 'N1*MF*' || ls_customer_duns_number_string || '~'; --Misa DUNS
  i := i + 1;
  
  x12_table(i) := 'N1*SF*1*' || ls_sf || '~';
  i := i + 1;
  
  --x12_table(i) := 'N1*ST*' || rtrim(ltrim(ls_des_cust_name)) || '*1*' || ls_st_duns;
  x12_table(i) := 'N1*ST**1*' || ls_st_duns || '~';
  i := i + 1;
  


  -- Second Level HL based on End User PO( only one part# is included in one shipement per FORD's request)
--  OPEN misa_856_cur;
--  FETCH misa_856_cur
--    INTO skidinfo_rec;

/*
  SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
    INTO ls_enduser_part
    FROM "ORDER_ITEM", "SHEET_SKID"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
     AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
     AND ("SHEET_SKID"."SHEET_SKID_NUM" = skidinfo_rec.sheet_skid_num);
*/

  /*
      SELECT "CUSTOMER_ORDER"."ENDUSER_PO" into ls_enduser_po
             FROM "SHEET_SKID",
                  "CUSTOMER_ORDER"
                  WHERE ( "SHEET_SKID"."REF_ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM" ) and
                        (SHEET_SKID.SHEET_SKID_NUM = skidinfo_rec.SHEET_SKID_NUM);
  */

  /*
  x12_table(i) := 'HL*2*1*O' || '~';
  i := i + 1;
  IF ls_enduser_part IS NULL THEN
    ls_enduser_part := 'NA';
  END IF;

  SELECT "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO"
    INTO ls_po
    FROM "SHEET_SKID", "CUSTOMER_ORDER"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
         "CUSTOMER_ORDER"."ORDER_ABC_NUM")
     AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num);

  for po_rec in po_cur loop --******************************************************
    ls_orig_customer_po := po_rec.orig_customer_po;
    ld_created_date := po_rec.created_date;
    
    x12_table(i) := 'PRF*' || ls_orig_customer_po || '***' ||
                    to_char(ld_created_date, 'YYYYMMDD') || '~';
    i := i + 1;
  end loop;
  */

  --CLOSE misa_856_cur;

  -- Third Level HL Under a P.O.
  li_hl01 := 2;

  for po_rec in po_cur loop
    ls_orig_customer_po := po_rec.orig_customer_po;
    ld_created_date := po_rec.created_date;
    
    --x12_table(i) := 'HL*2*1*O' || '~';
    x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || '1' || '*O' || '~';
    i := i + 1;
    li_hl01_link := li_hl01;
    li_hl01 := li_hl01 + 1;
    
    x12_table(i) := 'LIN**PO*' || ls_orig_customer_po || '~';
    i := i + 1;
    
    select sum(sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt), 
           count(distinct sheet_skid.sheet_skid_num),
           sum(sheet_skid.skid_pieces)
    into   ll_po_weight, 
           ll_po_skid_count,
           ll_po_piece_count
    from   sheet_skid
    where  sheet_skid_num in
    (
      select distinct sheet_skid.sheet_skid_num
      from   sheet_packing_item
             join sheet_skid on sheet_skid.sheet_skid_num = sheet_packing_item.sheet_skid_num
             join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
             join process_coil on ab_job.ab_job_num = process_coil.ab_job_num
             join coil on coil.coil_abc_num = process_coil.coil_abc_num
             --join customer_order on customer_order.order_abc_num = sheet_skid.ref_order_abc_num
             join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
             join order_item on order_item.order_abc_num = ab_job.order_abc_num and  order_item.order_item_num = ab_job.order_item_num
      where  customer_order.orig_customer_po = ls_orig_customer_po and sheet_packing_item.packing_list = al_packing_list
    );
    
    ll_po_weight_kg := ll_po_weight * 0.453592;
    --x12_table(i) := 'SN1**' || to_char(ll_po_weight) || '*LB' || '~';
    x12_table(i) := 'SN1**' || to_char(ll_po_weight_kg) || '*KG' || '~';
    i := i + 1;
    
    x12_table(i) := 'PRF*' || ls_orig_customer_po || '~';
    i := i + 1;
    
    x12_table(i) := 'MEA*CT*NL*' || ll_po_piece_count || '*PC' || '~';
    i := i + 1;

    --Skid loop begin ----------------------------------------------------------------
    FOR skidinfo_rec IN misa_856_cur LOOP
        
        --In case of a split skid, we are creating just 1 HL for this skid
        --with just 1 coil for this skid.
        select distinct
               coil.coil_abc_num, 
               coil.coil_org_num,
               coil.coil_gauge,
               coil.coil_width,
               coil.lot_num,
               nvl(skid_type_if_whed, -1),
               coil.vo,
               coil.coil_alloy,
               coil.coil_temper
        into   ll_coil_abc_num,
               ls_coil_org_num,
               ll_coil_gauge,
               ll_coil_width,
               ls_lot_num,
               ln_skid_type_if_whed, --Alex Gerlants. 04/01/2019
               ls_vo,
               ls_coil_alloy,
               ls_coil_temper
        FROM "COIL",   
             "PRODUCTION_SHEET_ITEM",   
             "SHEET_SKID",   
             "SHEET_SKID_DETAIL",   
             "PROCESS_COIL"  
       WHERE ( "COIL"."COIL_ABC_NUM" = "PRODUCTION_SHEET_ITEM"."COIL_ABC_NUM" ) and  
             ( "SHEET_SKID_DETAIL"."SHEET_SKID_NUM" = "SHEET_SKID"."SHEET_SKID_NUM" ) and  
             ( "SHEET_SKID_DETAIL"."PROD_ITEM_NUM" = "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NUM" ) and  
             ( "COIL"."COIL_ABC_NUM" = "PROCESS_COIL"."COIL_ABC_NUM" ) and  
             ( "PRODUCTION_SHEET_ITEM"."AB_JOB_NUM" = "PROCESS_COIL"."AB_JOB_NUM" ) and  
             ( (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num)  ) and
             ( (rownum = 1)  ); --We need just 1 coil for each skid
      
        --Alex Gerlants. 04/01/2019. Begin
        --if ln_skid_type_if_whed > -1 then --Warehouse skid
            --Get gauge and part width
            select distinct order_item.gauge,
                   f_get_part_width_per_job(ab_job.ab_job_num),
                   enduser_part_num,
                   nvl(cust_prod_line_id, '')
            into   ll_coil_gauge,
                   ll_coil_width,
                   ls_enduser_part,
                   ls_cust_prod_line_id
            from   sheet_skid
                   join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
                   join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
                   join customer_order on customer_order.order_abc_num = order_item.order_abc_num
            where  sheet_skid_num = skidinfo_rec.sheet_skid_num
            and    (order_item.gauge is not null and f_get_part_width_per_job(sheet_skid.ab_job_num) is not null)
            and    rownum = 1;
        --end if;
        --Alex Gerlants. 04/01/2019. End
      
        --IF length(to_char(li_hl01)) = 1 THEN
          x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hl01_link) || '*I' || '~';
          i := i + 1;
        --ELSE
        --  x12_table(i) := 'HL*' || to_char(li_hl01) || '*2*I' || '~';
        --  i := i + 1;
        --END IF;
          
        /* Alex Gerlants. 01/02/2023. Comment out begin
        select distinct 
                  inbound_coil.vo, inbound_coil.lot, inbound_coil.lineal_feed
        into      ls_vo, ls_lot_num, ld_lineal_feed
        from      inbound_coil
                  join inbound_coil_status on inbound_coil_status.coil_number = inbound_coil.coil_number
        where     inbound_coil_status.coil_abc_num = ll_coil_abc_num;
        */
        --Alex Gerlants. 01/02/2023. Comment out end
          
        --Alex Gerlants. 01/02/2023. New SQL statement. Join inbound_coil with coil instead of inbound_coil_status, Begin
        --Count first...just in case
        select    count(*)
        into      li_count
        from      inbound_coil
                  join coil on coil.coil_org_num = inbound_coil.coil_number
        where     coil.coil_abc_num = ll_coil_abc_num;
          
        if li_count > 0 then
          select distinct 
                    inbound_coil.vo, inbound_coil.lot, inbound_coil.lineal_feed
          into      ls_vo, ls_lot_num, ld_lineal_feed
          from      inbound_coil
                    join coil on coil.coil_org_num = inbound_coil.coil_number
          where     coil.coil_abc_num = ll_coil_abc_num; 
        else
          ls_vo := '';
          ls_lot_num := '';
          ld_lineal_feed := 0;
        end if;     
        --Alex Gerlants. 01/02/2023. New SQL statement. Join inbound_coil with coil instead of inbound_coil_status. End      
          
        --x12_table(i) := 'HL*' || to_char(li_hl01) || '*2*I' || '~';
        
        x12_table(i) := 'SN1**' || to_char(skidinfo_rec.prod_item_pieces) || '*PC' || '~';
        i := i + 1;
        
        ll_skid_gross_weight_lb := (skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt);
        ll_skid_gross_weight_kg := (skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt) * 0.453592;
        ll_prod_item_net_wt_lb := skidinfo_rec.prod_item_net_wt;
        ll_prod_item_net_wt_kg := skidinfo_rec.prod_item_net_wt * 0.453592;
        
        x12_table(i) := 'MEA*WT*WT*' || to_char(ll_prod_item_net_wt_kg) || '*50' || '~'; --'50' means 'KG'
        i := i + 1;
        
        ll_coil_gauge := skidinfo_rec.gauge;
        
        --x12_table(i) := 'MEA*PD*TH*' || to_char(ll_coil_gauge) || '*ED' || '~';
        --i := i + 1;
        
        --x12_table(i) := 'LIN*1*BP*' || ls_enduser_part || '*SN*' || ls_coil_org_num || '*HN*' || ls_lot_num || '*LS*' || to_char(ll_coil_abc_num) || '*JN*' || ls_vo || '~';
        --i := i + 1;
          
        --x12_table(i) := 'PID*S*55**' || ls_coil_alloy || '~';
        --i := i + 1;
          
        --x12_table(i) := 'PID*S*16**' || ls_coil_temper || '~';
        --i := i + 1;

        
                            
        --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*WT" to "MEA*CT*NL"
        --x12_table(i) := 'MEA*CT*NL*' || to_char(skidinfo_rec.skid_pieces) || '*PC' || '~';
        --i := i + 1;

        -- changed to all gross wt per novelis 1/30/2015
        --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*G" to "MEA*WT*G"
        --x12_table(i) := 'MEA*WT*G*' || to_char(skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt) || '*01';
        --i := i + 1;
     
        x12_table(i) := 'MEA*PD*TH*' || ltrim(rtrim(to_char(ll_coil_gauge, '0.0000'))) || '*ED' || '~';
        i := i + 1;

        x12_table(i) := 'MEA*PD*WD*' || to_char(ll_coil_width) || '*ED' || '~';
        i := i + 1;
        
        select f_get_part_dims_4order_item(skidinfo_rec.order_abc_num, skidinfo_rec.order_item_num, 'length')
        into   li_part_length
        from   dual;
        
        x12_table(i) := 'MEA*PD*LN*' || to_char(li_part_length) || '*IN' || '~';
        i := i + 1;

        x12_table(i) := 'REF*SE*' || skidinfo_rec.sheet_skid_display_num || '~';
        i := i + 1;
        
        select   coil_org_num
        into     ls_coil_org_num
        from     coil
        where    coil_abc_num = skidinfo_rec.coil_abc_num;
        
        x12_table(i) := 'REF*SN*' || ls_coil_org_num || '~';
        i := i + 1;
          
        --Alex Gerlants. 10/18/2018. New line 
        --x12_table(i) := 'REF*LS*' || ls_coil_org_num;
        --i := i + 1;
          
        li_hl01 := li_hl01 + 1;
        li_rowcount := misa_856_cur%ROWCOUNT;
        --x12_table(li_td1) := 'TD1*PLT90*' || to_char(li_rowcount);
    END LOOP; --End of 'FOR skidinfo_rec IN misa_856_cur LOOP'
    --Skid loop end ------------------------------------------------------------------
  end loop; --for po_rec in po_cur loop
  
  --CLOSE misa_856_cur;

  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                  to_char(li_rowcount + ll_shipment_pc) || '~';
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_gs_log) || '~';
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log) || '~';
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0') || '~';

  -- Write X.12 to file
  -- To FORD

  /** Write file to /templar/templar/incoming/senddata
  /*
  **/

  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  --edi_file:= 'S_alcan_ford_ford_' || to_char(ll_edi_file_id) ||'.x12';

  -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
  -- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
  edi_file := edi_file_prefix || 'BOL_' || to_char(al_packing_list) || '_' || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
    --        v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
  END LOOP;
  utl_file.fclose(edi_file_handle);

  --To ALCAN

  /*
  SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;
  SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id_alcan FROM DUAL;
  edi_file:= 'S_alcan_ford_alcan_' || to_char(ll_edi_file_id_alcan) ||'.x12';
  edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');
  x12_table(0) := 'ISA*00*'||'          *00*          *01*039630926T     *09*0015049350011G *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0')||'*0*P**';
  x12_table(1) := 'GS*SH*R0P7A*'||'001504935001' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  x12_table(i-1) :=  'GE*1*' || to_char (ll_gs_log);
  x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');
  for j in 0..i loop
   UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
       v_edi_text_alcan:=v_edi_text_alcan||x12_table(j)||CHR(10);
  end loop;
  UTL_FILE.FCLOSE(edi_file_handle);

  */

  /* The following code added by Tony, for update archive*/

  --  INSERT INTO edi_log (edi_log_timestamp,customer_id,
  --         customer_edi_name,edi_log_contents,edi_file_id,edi_text)
  --    VALUES (SYSDATE,li_customer_id,ll_customer_edi_name,
  --           'EDI:'||ll_customer_edi_name||' generated successfully.',ll_edi_file_id,v_edi_text);
  --   COMMIT;

  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  
  /*  TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE,
         edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;
   */


--  COMMIT;

  /* --added by Victor Huang on 06/05 for function acknowlegement
  INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
  VALUES(ll_gs_log, ls_su, sysdate, edi_file);
  COMMIT;*/

  /*  TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY
  INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (ll_edi_file_id,
     '039630926',
     ls_su,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856');
  */
     
  COMMIT;

  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  --exception
  --   when invalid_operation
  --   then
  --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

  --  when others
  --  then
  --      DBMS_OUTPUT.PUT_LINE ('System Error');
  --      UTL_FILE.FCLOSE(edi_file_handle);

  RETURN 1;
END edi_misa_856_X12_4bol;
--------------------------------------------------------
--  DDL for Function EDI_NOVELIS_856_RERUN
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_NOVELIS_856_RERUN" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*
  Aluminum Blanking: Ford Supplier Code: ZZ R0P7A
                     DUNS: 01 039630926T
  Customer: ALCAN(34,35,10,1153)
  Alcan Rolled Product    X.121       0015049350011G
  End User: Ford (ZZ F159B)
            Ford Chicago Stamping Plant(51) MS02A
            Ford Walton Hills Stamping Plant(77) MS03A
            Ford Woodhaven Stamping Plant(71) AF30A MS09A
            Ford Maumee Stamping Plant(78)    AF06A MS08A

            Budd Company (Customer ID: 1096) B821L
            Eagle Steel (1251) MZF6B
            (not in use)Ford Monroe Stamping              AP06A

            (not in use) Warehouses: IDS(41)               R5G3B
            (not in use) Wayne Steel Distribution Center(79) RWSDC

  */

  --v_edi_text_ford varchar2(32767);
  --v_edi_text_alcan varchar2(32767);
  --ll_customer_edi_name VARCHAR2(20);

   --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50);

  --edi_loc varchar2(50):='/tmp';
  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_prefix VARCHAR2(50) := 's_novelis_856_'; --Production
  --edi_file_prefix VARCHAR2(50) := 's_novelis_856_'; --Development
  edi_file_handle utl_file.file_type;

  li_customer_id    shipment.customer_id%TYPE;
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;

  -- ls_sender_vanid varchar2 (50);
  -- ls_receiver_vanid varchar2 (50);
  -- ls_customer_vanid varchar2(50);
  -- ls_receiver_gs03 varchar2(50);
  -- ls_customer_gs03 varchar2(50);
  --ls_st varchar2(50);
  ls_sf VARCHAR2(50);
  ls_eq_type VARCHAR2(10);  -- Added by Patrick Reynolds 11/30/2016
  ls_su      VARCHAR2(50);
  ls_st_duns VARCHAR2(50);
  ls_po      VARCHAR2(30);
  ls_auth_code   VARCHAR2(32);
  ll_gs_log  INTEGER;
  ll_st_log  INTEGER;
  ll_bsn_log INTEGER;

  ls_today VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD'); --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  ls_today_2digits_year VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD'); --Alex Gerlants. 10/16/2018. Test
  ls_now   VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  li_rowcount INTEGER;
  li_hl01 INTEGER;
  ll_shipment_nt INTEGER;
  ll_shipment_gt INTEGER;
  ll_shipment_pc INTEGER;
  li_td1 INTEGER;
  li_rc  INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_vehicle_id_prefix VARCHAR2(50);  -- Added by Patrick Reynolds 11/30/2016
  ls_scac              carrier.scac%TYPE;
  ls_carrier_full_name VARCHAR2(18);
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_carrier_initial   VARCHAR2(50);  -- Not used in stored procedure.  Discovered by Patrick Reynolds 11/30/2016
  ldt_shipment         DATE;
   ll_temp         INTEGER;
  ls_enduser_part VARCHAR2(50);
  li_des_id       INTEGER;

  ll_edi_file_id INTEGER;

  ls_lot_num VARCHAR2(32);
  ls_coil_id VARCHAR2(32);
  ls_des_cust_name VARCHAR2(18);
  
  ls_coil_org_num		        coil.coil_org_num%TYPE; --Alex Gerlants. 01/25/2019
  ll_coil_gauge		          coil.coil_gauge%TYPE;   --Alex Gerlants. 01/25/2019
  ll_coil_width		          coil.coil_width%TYPE;   --Alex Gerlants. 01/25/2019
  ld_ship_date              date;
  li_is_novelis             integer;
  ln_skid_type_if_whed      sheet_skid.skid_type_if_whed%TYPE;   --Alex Gerlants. 04/01/2019
  ls_time                   char(4); --Alex Gerlants. 01/09/2020

  CURSOR alcan_ford_856_cur IS
    SELECT sheet_packing_item.sh_packing_item,
           'MULTIPLE' lot_num,
           'MULTIPLE' coil_id,
           customer_order.orig_customer_po,
           customer_order.order_abc_num,
           customer_order.enduser_po,
           customer_order.created_date,
           order_item.order_item_num,
           order_item.enduser_part_num,
           order_item.supplier_code,
           order_item.gauge,
           sheet_skid. ab_job_num,
           sheet_skid.sheet_skid_num,
           sheet_skid.sheet_skid_display_num, --added by Victor H. on 06-2012 for Novelis locatio code request
           sheet_skid.sheet_net_wt,
           sheet_skid.sheet_tare_wt,
           sheet_skid. skid_pieces,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_theoretical_wt,
           NULL done
      FROM customer_order,
           order_item,
           sheet_skid,
           ab_job,
           shipment,
           sheet_packing_item
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
/*      
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
  --      (SHIPMENT.SHIPMENT_EDI856_DATE is NULL);
*/
  --TYPE skidinfo_tabletype IS TABLE OF alcan_ford_856_cur%ROWTYPE INDEX BY BINARY_INTEGER;
  --skidinfo_table skidinfo_tabletype;
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table    store_tabletype;
  i            BINARY_INTEGER := 0;
  skidinfo_rec alcan_ford_856_cur%ROWTYPE;

  /*CURSOR packing_list_same_bol IS
  SELECT packing_list
    FROM shipment
   WHERE bill_of_lading = ll_bill_of_lading;*/

  CURSOR c_ship_to IS
    SELECT DISTINCT des_sh_cust_id --, PACKING_LIST
      FROM shipment
     WHERE bill_of_lading = ll_bill_of_lading
       AND shipment.shipment_status = 0;
  --ORDER BY PACKING_LIST;
  
  cursor c_coil is
  select distinct 
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num,
         coil.coil_gauge,
         coil.coil_width
         --process_coil.coil_abc_num
         --outbound_edi_transaction.transaction_time,
         --outbound_edi_transaction.edi_file_name
  from   customer_order
         join order_item on order_item.order_abc_num = customer_order.order_abc_num
         join ab_job on ab_job.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
         join sheet_skid on sheet_skid.ab_job_num = ab_job.ab_job_num
         join sheet_packing_item on sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
         join shipment on shipment.packing_list = sheet_packing_item.packing_list
         join process_coil on process_coil.ab_job_num = ab_job.ab_job_num
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         --join outbound_edi_transaction on outbound_edi_transaction.edi_file_id = shipment.edi_file_id_856
  --where  shipment.packing_list = 105586 --Production
  where  shipment.packing_list = al_packing_list --Develpment
  order by
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num;

BEGIN
  
  select f_is_novelis(al_packing_list)
  into   li_is_novelis
  from   dual;
  
  if li_is_novelis = 0 then --Customer is NOT Novelis
    return 1; --Nothing to do here
  end if;
  
  /*
  select shipment_edi856_date
  into   ld_ship_date
  from   shipment
  where  shipment.packing_list = al_packing_list;
   
  if not (ld_ship_date is null) then --ASN already sent
    return 100;
  end if;
  */

  edi_loc := dbo.get_edi_destination('EDI_DIR'); --Alex Gerlants. 11/15/2016

  -- Get Customer ID, End user ID, authorization code
  SELECT customer_id, des_sh_cust_id, nvl(shipment_athorization_code, 'NA')
    INTO li_customer_id, li_des_sh_cust_id, ls_auth_code
  FROM shipment
  WHERE shipment.packing_list = al_packing_list;
  IF NOT SQL%FOUND THEN
   RETURN - 1;
  END IF;

  -- dbms_output.put_line (to_char(li_customer_id) || '  ' || to_char(li_des_sh_cust_id) );

  IF NOT (li_customer_id IN (34, 35, 10, 1153, 1459, 2582)) -- AND (li_des_sh_cust_id IN (
  --10,41,51,69,70,71,72,77,78,79,1055,1062,1073,1086,1096,1099,1114,1112,1153,
  --1206,1251,1253,1268,1269,1270,1322,1325,1328,1331,1332,1346,1347, 1382, 1383)))
   THEN

    --***********************************************************************************************88
    --IF NOT ((li_customer_id IN (34,35,10,1153)) AND (li_des_sh_cust_id IN (SELECT CUSTOMER_ID
    --FROM CUSTOMER
    --WHERE CUSTOMER_DUNS_NUMBER_STRING is not null))) THEN

    RETURN 200;
  END IF;

  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(sheet_skid.sheet_net_wt),
         SUM(sheet_skid.sheet_net_wt) + SUM(sheet_skid.sheet_tare_wt),
         SUM(sheet_skid.skid_pieces)
    INTO ll_shipment_nt, ll_shipment_gt, ll_shipment_pc
    FROM sheet_skid, sheet_packing_item, shipment
   WHERE shipment.packing_list = sheet_packing_item.packing_list
     AND sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
     AND shipment.packing_list = al_packing_list;
  IF ll_shipment_pc = 0 THEN
    RETURN 100;
  END IF; -- empty shipment

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  -- Retrieve ABCO info
  -- ls_sender_vanid := '3010007080';
  --ls_ic := 'R0P7A';

  -- Retrieve ALCAN supply code and Ford Stamping Plant location code
  --SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf
  --FROM customer_customer  WHERE o_customer_id = li_customer_id and e_customer_id = 49;  --Ford customer_id =49

  ls_sf := '039630926';
  --SELECT NVL(communication_code,'UNKNOWN') INTO ls_st FROM customer_system
  --WHERE customer_id = li_des_sh_cust_id;

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.vehicle_id_prefix, '9999'),
         nvl(shipment.equipment_type, 'NA'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'PT'), -- Protected Trailer
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE)
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_vehicle_id_prefix,
         ls_eq_type,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_carrier_initial,
         ldt_shipment
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;

  --Check all packing_lists are done against a BOL
  /*
  for pl_rec in packing_list_same_bol loop
      select shipment.shipment_status into ll_temp from shipment
             where shipment.packing_list = pl_rec.packing_list;
      if ll_temp > 0 then
         return pl_rec.packing_list;
      end if;

  end loop;
  */
  --End of packing list checking

  SELECT nvl(customer_duns_number_string, '00000000'), customer_short_name
    INTO ls_st_duns, ls_des_cust_name
    FROM customer
   WHERE customer_id = li_des_sh_cust_id;

  IF (ls_st_duns = '00000000') THEN
    RETURN 200;
  END IF; --No Ship to DUNS

  SELECT nvl(customer_duns_number_string, '00000000')
    INTO ls_su
    FROM customer
   WHERE customer_id = li_customer_id;
  IF (ls_su = '00000000') THEN
    RETURN 200;
  END IF; --No Supplier DUNS

  -- Get SCAC(Standard Carrier Alpha Code)
  SELECT nvl(carrier.scac, 'NONE'), LPAD(carrier.carrier_full_name, 17)
    INTO ls_scac, ls_carrier_full_name
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);

  -- Get Receiver and Customer VAN ID
  -- SELECT NVL(customer_system.van_account_num, 'nothing'), NVL(customer_system.gs03, 'nothing')
  -- INTO ls_receiver_vanid, ls_receiver_gs03    -- ls_receiver_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --   (select shipment.des_sh_cust_id  from shipment  where shipment.packing_list = al_packing_list);

  -- SELECT NVL(customer_system.van_account_num, 'nothing'),NVL(customer_system.gs03, 'nothing')
  -- INTO   ls_customer_vanid, ls_customer_gs03   -- ls_customer_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --       (select shipment.customer_id from shipment where shipment.packing_list = al_packing_list);

  -- Generate Header Info.
  --x12_table(i) := 'ISA*00*'||'          *00*          *ZZ*R0P7A          *ZZ*F159B          *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0') ||'*0*P**';
  --x12_table(i) := 'GS*SH*R0P7A*'||ls_st || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  --Alex Gerlants. 10/16/2018. Changed from "00200" to "00401"
  --Production
  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *01*039630926T     *09*0015049350011G *' ||
                  ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
  
  --Development                
  --x12_table(i) := 'ISA*00*' ||
  --                '          *00*          *ZZ*2NDSFTP        *ZZ*NOVLSTEST      *' ||
  --                ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
  --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';
                  
  i := i + 1;

  --Alex Gerlants. 10/16/2018. Changed from "002002" to "004010"
  --Production
  x12_table(1) := 'GS*SH*R0P7A*' || '001504935001' || '*' || ls_today || '*' ||
                  ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  --Development
  --x12_table(1) := 'GS*SH*2NDSFTP*' || 'NOVLSTEST' || '*' || ls_today || '*' ||
  --               ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;
  --x12_table(i):= 'BSN*00*' || to_char(ll_bill_of_lading) || '*' || ls_today || '*' || ls_now;
  x12_table(i) := 'BSN*00*' || to_char(al_packing_list) || '*' || ls_today || '*' ||
                  ls_now;
  i := i + 1;
  
  --Alex Gerlants. 08/07/2018.
  --Changed to populate with actual ship date instead of current date and time.
  --The reason is that when we send 856 on a later date, this date is not correct.
  --x12_table(i) := 'DTM*011*' || ls_today || '*' || ls_now;
  --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  
  --Alex Gerlants. 01/09/2020. Added the IF statement below.
  --If users do not enter time part in shipment.shipment_actualed_date_time,
  --856 will have system time in 'DTM*011*' and 'DTM*017*'
  
  ls_time := to_char(ldt_shipment, 'HH24MI');
  
  if ls_time <> '0000' then --User entered time
    x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                                                        to_char(ldt_shipment, 'HH24MI');
  else --User did not enter time  
    x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                                                        to_char(sysdate, 'HH24MI');
  end if;
  i := i + 1;
  
  --Alex Gerlants. 10/18/2018. Changed from "YYMMDD" to "YYYYMMDD"
  --Moved here from the below
  if ls_time <> '0000' then --User entered time
    x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                    to_char(ldt_shipment, 'HH24MI');
  else --User did not enter time
    x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                    to_char(sysdate, 'HH24MI');
  end if;
  i := i + 1;

  -- First Level HL
  x12_table(i) := 'HL*01**S';
  i := i + 1;
  --Alex Gerlants. 10/16/2018. Changed from "MEA*PD*G*" to "MEA*WT*G*"
  x12_table(i) := 'MEA*WT*G*' || to_char(ll_shipment_gt) || '*LB';
  i := i + 1;
  x12_table(i) := 'MEA*WT*N*' || to_char(ll_shipment_nt) || '*LB';
  i := i + 1;
  x12_table(i) := 'TD1*PLT90*' || to_char(li_rowcount);
  li_td1 := i;
  i := i + 1;
  x12_table(i) := 'TD5*B*2*' || ls_scac || '*M*' || ls_carrier_full_name;
  i := i + 1;
  -- segment was modified to include trailer number.  Patrick Reynolds 11/30/2016
  x12_table(i) := 'TD3*' || ls_carrier_desc_code || '*' || ls_scac || '*' || ls_vehicle_id_prefix;
  i := i + 1;
  x12_table(i) := 'REF*BM*' || to_char(al_packing_list);
  i := i + 1;
  x12_table(i) := 'REF*PK*' || to_char(al_packing_list);
  i := i + 1;
  -- segment was modified to include equipment type.  Patrick Reynolds 11/30/2016
  x12_table(i) := 'REF*EQ*' || ls_eq_type;
  i := i + 1; --waiting for Novilis, ----tony
  --- Testing for multi order ASN ----Tony

  x12_table(i) := 'REF*MB*' || to_char(ll_bill_of_lading);
  i := i + 1;
  SELECT COUNT(*)
    INTO ll_temp
    FROM shipment
   WHERE shipment.bill_of_lading = ll_bill_of_lading
     AND shipment.shipment_status = 0;
     
  --Alex Gerlants. 10/16/2018. Removed 2 lines below
  --x12_table(i) := 'REF*SS*' || to_char(ll_temp);
  --i := i + 1;
  li_des_id := 1;
  
  --Alex Gerlants. 10/16/2018. Removed 7 lines below
  /*
  FOR c_stop IN c_ship_to LOOP
    IF li_des_sh_cust_id = c_stop.des_sh_cust_id THEN
      x12_table(i) := 'REF*QN*' || to_char(li_des_id);
      i := i + 1;
    END IF;
    li_des_id := li_des_id + 1;
  END LOOP;
  */

  /*
  IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
     x12_table(i):= 'REF*ZZ*' || ls_st;i:=i+1;
  end if;
  */

  ----Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  --x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
  --                to_char(ldt_shipment, 'HH24MI');
  --i := i + 1;
  
  x12_table(i) := 'N1*ST*' || ls_des_cust_name || '*1*' || ls_st_duns;
  i := i + 1;
  x12_table(i) := 'N1*SF*Aluminum Blanking Co*1*' || ls_sf;
  i := i + 1;
  x12_table(i) := 'N1*SU**1*' || ls_su;
  i := i + 1;

  --if not (li_des_sh_cust_id = 1096 or li_des_sh_cust_id = 1251) then
  --         x12_table(i):= 'N1*IC**92*' || ls_ic; i := i +1;        --- Deleted 04-30-03 by Tony according to alcan Julia's email
  --end if;

  --         x12_table(i):= 'N1*CN**92*' || ls_st_duns; i := i +1; --Ship to DUNs --- Deleted 04-30-03 by Tony according to alcan Julia's email

  -- Second Level HL based on End User PO( only one part# is included in one shipement per FORD's request)
  OPEN alcan_ford_856_cur;
  FETCH alcan_ford_856_cur
    INTO skidinfo_rec;
  --    ls_enduser_part := skidinfo_rec.ENDUSER_PART_NUM;
  --    ls_enduser_po := skidinfo_rec.ENDUSER_PO;

  /*
    if skidinfo_rec.ORIG_CUSTOMER_PO IN ('68Q68517') then    --Do NOT send 856 to Ford for some flipping related POs )
         edi_file_prefix := 'nosend_alcan_ford_ford';
    end if;
  */

  SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
    INTO ls_enduser_part
    FROM "ORDER_ITEM", "SHEET_SKID"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
     AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
     AND ("SHEET_SKID"."SHEET_SKID_NUM" = skidinfo_rec.sheet_skid_num);

  /*
      SELECT "CUSTOMER_ORDER"."ENDUSER_PO" into ls_enduser_po
             FROM "SHEET_SKID",
                  "CUSTOMER_ORDER"
                  WHERE ( "SHEET_SKID"."REF_ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM" ) and
                        (SHEET_SKID.SHEET_SKID_NUM = skidinfo_rec.SHEET_SKID_NUM);
  */

  x12_table(i) := 'HL*02*01*O';
  i := i + 1;
  IF ls_enduser_part IS NULL THEN
    ls_enduser_part := 'NA';
  END IF;
  x12_table(i) := 'LIN**BP*' || ls_enduser_part;
  i := i + 1;
  x12_table(i) := 'SN1**' || to_char(ll_shipment_pc) || '*EA*0';
  i := i + 1;

  --
  --ls_po := skidinfo_rec.ORIG_CUSTOMER_PO;
  SELECT "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO"
    INTO ls_po
    FROM "SHEET_SKID", "CUSTOMER_ORDER"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
         "CUSTOMER_ORDER"."ORDER_ABC_NUM")
     AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num);

  --IF INSTR(skidinfo_rec.ORIG_CUSTOMER_PO,'-') > 0
  --New PO format for Novelis SAP include '-'
  /*IF instr(ls_po, '-') > 0 THEN
    ls_po := substr(ls_po, 0, instr(ls_po, '-') - 1);
  END IF;*/

  --   IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
  x12_table(i) := 'PRF*' || ls_po || '***' ||
                  to_char(skidinfo_rec.created_date, 'YYYYMMDD');
  i := i + 1;
  --   end if;

  CLOSE alcan_ford_856_cur;

   --  Novelis SAP order number
 x12_table(i) := 'REF*IL*' || ls_auth_code;
 i := i + 1;
  --  end if;

  -- Third Level HL Under a P.O.
  li_hl01 := 3;

  --Skid loop begin ----------------------------------------------------------------
  FOR skidinfo_rec IN alcan_ford_856_cur LOOP
    
      --In case of a split skid, we are creating just 1 HL for this skid
      --with just 1 coil for this skid.
      select distinct 
             coil.coil_org_num,
             coil.coil_gauge,
             coil.coil_width,
             coil.lot_num,
             nvl(skid_type_if_whed, -1) --Alex Gerlants. 04/01/2019
      into   ls_coil_org_num,
             ll_coil_gauge,
             ll_coil_width,
             ls_lot_num,
             ln_skid_type_if_whed --Alex Gerlants. 04/01/2019
      FROM "COIL",   
           "PRODUCTION_SHEET_ITEM",   
           "SHEET_SKID",   
           "SHEET_SKID_DETAIL",   
           "PROCESS_COIL"  
     WHERE ( "COIL"."COIL_ABC_NUM" = "PRODUCTION_SHEET_ITEM"."COIL_ABC_NUM" ) and  
           ( "SHEET_SKID_DETAIL"."SHEET_SKID_NUM" = "SHEET_SKID"."SHEET_SKID_NUM" ) and  
           ( "SHEET_SKID_DETAIL"."PROD_ITEM_NUM" = "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NUM" ) and  
           ( "COIL"."COIL_ABC_NUM" = "PROCESS_COIL"."COIL_ABC_NUM" ) and  
           ( "PRODUCTION_SHEET_ITEM"."AB_JOB_NUM" = "PROCESS_COIL"."AB_JOB_NUM" ) and  
           ( (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num)  ) and
           ( (rownum = 1)  ); --We need just 1 coil for each skid
  
      --Alex Gerlants. 04/01/2019. Begin
      if ln_skid_type_if_whed > -1 then --Warehouse skid
          --Get gauge and part width
          select distinct order_item.gauge,
                 f_get_part_width_per_job(ab_job.ab_job_num) 
          into   ll_coil_gauge,
                 ll_coil_width
          from   sheet_skid
                 join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
                 join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
                 join customer_order on customer_order.order_abc_num = order_item.order_abc_num
          where  sheet_skid_num = skidinfo_rec.sheet_skid_num
          and    (order_item.gauge is not null and f_get_part_width_per_job(sheet_skid.ab_job_num) is not null)
          and    rownum = 1;
      end if;
      --Alex Gerlants. 04/01/2019. End
  
      IF length(to_char(li_hl01)) = 1 THEN
        x12_table(i) := 'HL*0' || to_char(li_hl01) || '*02*I';
        i := i + 1;
      ELSE
        x12_table(i) := 'HL*' || to_char(li_hl01) || '*02*I';
        i := i + 1;
      END IF;

      --    IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
      --       x12_table(i) := 'SN1**'||to_char(skidinfo_rec.skid_pieces)||'*EA';i:=i+1;
      --    else
      x12_table(i) := 'SN1**1*PF';
      i := i + 1;
      --    end if;

      --if li_des_sh_cust_id = 1096 -- To Budd or li_des_sh_cust_id = 1251 then
      --   then
      --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; i := i +1;
      --      x12_table(i) :=  'MEA*PD*TH*' || to_char(skidinfo_rec.sheet_net_wt) || '*24'; i := i +1;
      --elsif   li_des_sh_cust_id = 1251   --To Eagle Steel
      --  then
      --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; i := i +1;
      --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*24'; i := i +1;
      --      x12_table(i) :=  'MEA*PD*TH*' || to_char(skidinfo_rec.gauge) || '*EM'; i:=i+1;
      --    x12_table(i) :=  'MEA*PD*WD*'||'44.875'||'*IN'; i:=i+1;
      --    x12_table(i) :=  'MEA*PD*LN*'||to_char(skidinfo_rec.skid_pieces)||'*LF';  i:=i+1;
      --else  --All else, Ford dirct shiping program
                        
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*N" to "MEA*WT*N"
      x12_table(i) := 'MEA*WT*N*' || to_char(skidinfo_rec.sheet_net_wt) ||
                      '*01';
      i := i + 1;
                        
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*WT" to "MEA*CT*NL"
      x12_table(i) := 'MEA*CT*NL*' || to_char(skidinfo_rec.skid_pieces) ||
                      '*PC';
      i := i + 1;

      -- changed to all gross wt per novelis 1/30/2015
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*G" to "MEA*WT*G"
      x12_table(i) := 'MEA*WT*G*' || to_char(skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt) || '*01';
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      x12_table(i) := 'MEA*PD*GG*' || ll_coil_gauge;
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      x12_table(i) := 'MEA*PD*WD*' || ll_coil_width;
      i := i + 1;

      /*
      IF (skidinfo_rec.sheet_theoretical_wt IS NULL) OR
         (skidinfo_rec.sheet_theoretical_wt = 0) THEN
        x12_table(i) := 'MEA*PD*G*' || to_char(ll_shipment_gt) || '*01';
        i := i + 1;
      ELSE
        x12_table(i) := 'MEA*PD*G*' ||
                        to_char(skidinfo_rec.sheet_theoretical_wt) || '*01';
        i := i + 1;
      END IF;
      */
      --end if;

      -- fill in lot num
      /*
      SELECT COUNT(*)
        INTO li_rc
        FROM sheet_skid_detail
       WHERE sheet_skid_detail.sheet_skid_num = skidinfo_rec.sheet_skid_num;

      ls_lot_num := skidinfo_rec.lot_num;
      ls_coil_id := skidinfo_rec.coil_id;

      IF li_rc = 1 THEN
        SELECT lot_num, coil_org_num
          INTO ls_lot_num, ls_coil_id
          FROM coil
         WHERE coil.coil_abc_num =
               (SELECT coil_abc_num
                  FROM production_sheet_item
                 WHERE production_sheet_item.prod_item_num =
                       (SELECT prod_item_num
                          FROM sheet_skid_detail
                         WHERE sheet_skid_detail.sheet_skid_num =
                               skidinfo_rec.sheet_skid_num));
      END IF;
      */
      --if li_des_sh_cust_id = 1251   --Eagle need coil ID here instead of lot number
      --then
      --x12_table(i) :=  'REF*HC*' || skidinfo_rec.coil_id ; i := i +1;
      --else
                        
      --Alex Gerlants. 10/18/2018. Changed from "REF*HC" to "REF*BT"
      x12_table(i) := 'REF*BT*' || ls_lot_num;
      i := i + 1;
      --end if;

      --x12_table(i) := 'REF*LS*' || to_char(skidinfo_rec.sheet_skid_num);
      --Alex Gerlants. 10/18/2018. Changed from "REF*LS" to "REF*SE"
      x12_table(i) := 'REF*SE*' || skidinfo_rec.sheet_skid_display_num; --added by Victor H. on 06-2012 for Novelis locatio code request
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      x12_table(i) := 'REF*LS*' || ls_coil_org_num;
      i := i + 1;
      
      li_hl01 := li_hl01 + 1;
      li_rowcount := alcan_ford_856_cur%ROWCOUNT;
      x12_table(li_td1) := 'TD1*PLT90*' || to_char(li_rowcount);
  END LOOP; --End of 'FOR skidinfo_rec IN alcan_ford_856_cur LOOP'
  --Skid loop end ------------------------------------------------------------------

  -- DBMS_OUTPUT.PUT_LINE ('rowcount' || to_char(li_rowcount));

  -- if li_des_sh_cust_id = 1096 or li_des_sh_cust_id = 1251 then
  --   x12_table(i) :=  'CTT*' || to_char(li_HL01 - 1) ||'*' || to_char(ll_shipment_pc*2) ;
  --   i := i +1;
  -- else
  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                  to_char(li_rowcount + ll_shipment_pc);
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  -- Write X.12 to file
  -- To FORD

  /** Write file to /templar/templar/incoming/senddata
  /*
  **/

  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  --edi_file:= 'S_alcan_ford_ford_' || to_char(ll_edi_file_id) ||'.x12';

  -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
  -- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
    --        v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
  END LOOP;
  utl_file.fclose(edi_file_handle);

  --To ALCAN

  /*
  SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;
  SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id_alcan FROM DUAL;
  edi_file:= 'S_alcan_ford_alcan_' || to_char(ll_edi_file_id_alcan) ||'.x12';
  edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');
  x12_table(0) := 'ISA*00*'||'          *00*          *01*039630926T     *09*0015049350011G *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0')||'*0*P**';
  x12_table(1) := 'GS*SH*R0P7A*'||'001504935001' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  x12_table(i-1) :=  'GE*1*' || to_char (ll_gs_log);
  x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');
  for j in 0..i loop
   UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
       v_edi_text_alcan:=v_edi_text_alcan||x12_table(j)||CHR(10);
  end loop;
  UTL_FILE.FCLOSE(edi_file_handle);

  */

  /* The following code added by Tony, for update archive*/

  --  INSERT INTO edi_log (edi_log_timestamp,customer_id,
  --         customer_edi_name,edi_log_contents,edi_file_id,edi_text)
  --    VALUES (SYSDATE,li_customer_id,ll_customer_edi_name,
  --           'EDI:'||ll_customer_edi_name||' generated successfully.',ll_edi_file_id,v_edi_text);
  --   COMMIT;

  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  /*
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE,
         edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;
   */
--  COMMIT;

  /* --added by Victor Huang on 06/05 for function acknowlegement
  INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
  VALUES(ll_gs_log, ls_su, sysdate, edi_file);
  COMMIT;*/

  --added by Victor Huang on 12/07 for verifying 997
  /*
  INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (ll_edi_file_id,
     '039630926',
     ls_su,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856');
  COMMIT;
  */

  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  --exception
  --   when invalid_operation
  --   then
  --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

  --  when others
  --  then
  --      DBMS_OUTPUT.PUT_LINE ('System Error');
  --      UTL_FILE.FCLOSE(edi_file_handle);

  RETURN 1;
END edi_novelis_856_rerun;
--------------------------------------------------------
--  DDL for Function EDI_NOVELIS_856_SHEETS_SCRAP
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_NOVELIS_856_SHEETS_SCRAP" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*
  Aluminum Blanking: Ford Supplier Code: ZZ R0P7A
                     DUNS: 01 039630926T
  Customer: ALCAN(34,35,10,1153)
  Alcan Rolled Product    X.121       0015049350011G
  End User: Ford (ZZ F159B)
            Ford Chicago Stamping Plant(51) MS02A
            Ford Walton Hills Stamping Plant(77) MS03A
            Ford Woodhaven Stamping Plant(71) AF30A MS09A
            Ford Maumee Stamping Plant(78)    AF06A MS08A

            Budd Company (Customer ID: 1096) B821L
            Eagle Steel (1251) MZF6B
            (not in use)Ford Monroe Stamping              AP06A

            (not in use) Warehouses: IDS(41)               R5G3B
            (not in use) Wayne Steel Distribution Center(79) RWSDC

  */

  --v_edi_text_ford varchar2(32767);
  --v_edi_text_alcan varchar2(32767);
  --ll_customer_edi_name VARCHAR2(20);

   --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50);

  --edi_loc varchar2(50):='/tmp';
  edi_file        VARCHAR2(50) := 'edi_out.txt';
  --edi_file_prefix VARCHAR2(50) := 'S_novelis_856_'; --Production
  edi_file_prefix VARCHAR2(50) := 's_novelis_856_'; --Development
  edi_file_handle utl_file.file_type;

  li_customer_id    shipment.customer_id%TYPE;
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;

  -- ls_sender_vanid varchar2 (50);
  -- ls_receiver_vanid varchar2 (50);
  -- ls_customer_vanid varchar2(50);
  -- ls_receiver_gs03 varchar2(50);
  -- ls_customer_gs03 varchar2(50);
  --ls_st varchar2(50);
  ls_sf VARCHAR2(50);
  ls_eq_type VARCHAR2(10);  -- Added by Patrick Reynolds 11/30/2016
  ls_su      VARCHAR2(50);
  ls_st_duns VARCHAR2(50);
  ls_po      VARCHAR2(30);
  ls_auth_code   VARCHAR2(32);
  ll_gs_log  INTEGER;
  ll_st_log  INTEGER;
  ll_bsn_log INTEGER;

  ls_today VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD'); --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  ls_today_2digits_year VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD'); --Alex Gerlants. 10/16/2018. Test
  ls_now   VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  li_rowcount INTEGER;
  li_hl01 INTEGER;
  ll_shipment_nt INTEGER;
  ll_shipment_gt INTEGER;
  ll_shipment_pc INTEGER;
  li_td1 INTEGER;
  --li_rc  INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_vehicle_id_prefix VARCHAR2(50);  -- Added by Patrick Reynolds 11/30/2016
  ls_scac              carrier.scac%TYPE;
  ls_carrier_full_name VARCHAR2(18);
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_carrier_initial   VARCHAR2(50);  -- Not used in stored procedure.  Discovered by Patrick Reynolds 11/30/2016
  ldt_shipment         DATE;
   ll_temp         INTEGER;
  ls_enduser_part VARCHAR2(50);
  --li_des_id       INTEGER;

  ll_edi_file_id INTEGER;

  ls_lot_num VARCHAR2(32);
  --ls_coil_id VARCHAR2(32);
  ls_des_cust_name VARCHAR2(18);
  
  ls_coil_org_num		        coil.coil_org_num%TYPE; --Alex Gerlants. 01/25/2019
  ll_coil_gauge		          coil.coil_gauge%TYPE;   --Alex Gerlants. 01/25/2019
  ll_coil_width		          coil.coil_width%TYPE;   --Alex Gerlants. 01/25/2019
  ld_ship_date              date;
  li_is_novelis             integer;
  ln_skid_type_if_whed      sheet_skid.skid_type_if_whed%TYPE;   --Alex Gerlants. 04/01/2019
  ls_time                   char(4); --Alex Gerlants. 01/09/2020
  ll_alloy                  alloy_type.alloy%TYPE;
  hl_order                  INTEGER;
  po_nt                     integer;
  ll_count                  integer;

  CURSOR alcan_ford_856_cur IS
    SELECT sheet_packing_item.sh_packing_item,
           'MULTIPLE' lot_num,
           'MULTIPLE' coil_id,
           customer_order.orig_customer_po,
           customer_order.order_abc_num,
           customer_order.enduser_po,
           customer_order.created_date,
           order_item.order_item_num,
           order_item.enduser_part_num,
           order_item.supplier_code,
           order_item.gauge,
           sheet_skid. ab_job_num,
           sheet_skid.sheet_skid_num,
           sheet_skid.sheet_skid_display_num, --added by Victor H. on 06-2012 for Novelis locatio code request
           sheet_skid.sheet_net_wt,
           sheet_skid.sheet_tare_wt,
           sheet_skid. skid_pieces,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_theoretical_wt,
           NULL done
      FROM customer_order,
           order_item,
           sheet_skid,
           ab_job,
           shipment,
           sheet_packing_item
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
       
       skidinfo_rec alcan_ford_856_cur%ROWTYPE;
       
-------------------- Sheets end  -----------------------------------------------

-------------------- Scrap begin  ----------------------------------------------       
       
  CURSOR alcan_scrap_856_cur IS
    SELECT DISTINCT scrap_skid.scrap_alloy2
      FROM scrap_skid, shipment, scrap_packing_item
     WHERE shipment.packing_list = al_packing_list
       AND scrap_packing_item.packing_list = shipment.packing_list
       AND scrap_skid.scrap_skid_num = scrap_packing_item.scrap_skid_num;
       
     alloyinfo_rec alcan_scrap_856_cur%ROWTYPE;

  CURSOR item_cur IS
    SELECT scrap_skid.scrap_skid_num,
           scrap_skid.scrap_skid_display_num,
           scrap_skid.scrap_alloy2,
           scrap_skid.scrap_net_wt,
           scrap_skid.scrap_tare_wt
      FROM scrap_skid, scrap_packing_item
     WHERE scrap_packing_item.packing_list = al_packing_list
       AND scrap_packing_item.scrap_skid_num = scrap_skid.scrap_skid_num
       AND scrap_skid.scrap_alloy2 = ll_alloy;

  item_rec item_cur%ROWTYPE;
  
-------------------- Scrap end   ----------------------------------------------  
  
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table     store_tabletype;
  i             BINARY_INTEGER := 0;
       
/*      
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
  --      (SHIPMENT.SHIPMENT_EDI856_DATE is NULL);

  --TYPE skidinfo_tabletype IS TABLE OF alcan_ford_856_cur%ROWTYPE INDEX BY BINARY_INTEGER;
  --skidinfo_table skidinfo_tabletype;
  

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table    store_tabletype;
  i            BINARY_INTEGER := 0;
 
  CURSOR packing_list_same_bol IS
  SELECT packing_list
    FROM shipment
   WHERE bill_of_lading = ll_bill_of_lading;

  CURSOR c_ship_to IS
    SELECT DISTINCT des_sh_cust_id --, PACKING_LIST
      FROM shipment
     WHERE bill_of_lading = ll_bill_of_lading
       AND shipment.shipment_status = 0;
     --ORDER BY PACKING_LIST;
  
  cursor c_coil is
  select distinct 
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num,
         coil.coil_gauge,
         coil.coil_width
         --process_coil.coil_abc_num
         --outbound_edi_transaction.transaction_time,
         --outbound_edi_transaction.edi_file_name
  from   customer_order
         join order_item on order_item.order_abc_num = customer_order.order_abc_num
         join ab_job on ab_job.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
         join sheet_skid on sheet_skid.ab_job_num = ab_job.ab_job_num
         join sheet_packing_item on sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
         join shipment on shipment.packing_list = sheet_packing_item.packing_list
         join process_coil on process_coil.ab_job_num = ab_job.ab_job_num
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         --join outbound_edi_transaction on outbound_edi_transaction.edi_file_id = shipment.edi_file_id_856
  --where  shipment.packing_list = 105586 --Production
  where  shipment.packing_list = al_packing_list --Develpment
  order by
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num;
*/



BEGIN
  
  select f_is_novelis(al_packing_list)
  into   li_is_novelis
  from   dual;
  
  if li_is_novelis = 0 then --Customer is NOT Novelis
    return 1; --Nothing to do here
  end if;
  
  select shipment_edi856_date
  into   ld_ship_date
  from   shipment
  where  shipment.packing_list = al_packing_list;
   
  if not (ld_ship_date is null) then --ASN already sent
    return 100;
  end if;

  edi_loc := dbo.get_edi_destination('EDI_DIR'); --Alex Gerlants. 11/15/2016

  -- Get Customer ID, End user ID, authorization code
  SELECT customer_id, des_sh_cust_id, nvl(shipment_athorization_code, 'NA')
    INTO li_customer_id, li_des_sh_cust_id, ls_auth_code
  FROM shipment
  WHERE shipment.packing_list = al_packing_list;
  IF NOT SQL%FOUND THEN
   RETURN - 1;
  END IF;

  -- dbms_output.put_line (to_char(li_customer_id) || '  ' || to_char(li_des_sh_cust_id) );

  --Alex Gerlants. 03/03/2021. Added '2950'  to the list below <== NOVELIS-GUTHRIE
  IF NOT (li_customer_id IN (34, 35, 10, 1153, 1459, 2582, 2950)) -- AND (li_des_sh_cust_id IN (
  --10,41,51,69,70,71,72,77,78,79,1055,1062,1073,1086,1096,1099,1114,1112,1153,
  --1206,1251,1253,1268,1269,1270,1322,1325,1328,1331,1332,1346,1347, 1382, 1383)))
   THEN

    --***********************************************************************************************88
    --IF NOT ((li_customer_id IN (34,35,10,1153)) AND (li_des_sh_cust_id IN (SELECT CUSTOMER_ID
    --FROM CUSTOMER
    --WHERE CUSTOMER_DUNS_NUMBER_STRING is not null))) THEN

    RETURN 200;
  END IF;

  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(sheet_skid.sheet_net_wt),
         SUM(sheet_skid.sheet_net_wt) + SUM(sheet_skid.sheet_tare_wt),
         SUM(sheet_skid.skid_pieces)
    INTO ll_shipment_nt, ll_shipment_gt, ll_shipment_pc
    FROM sheet_skid, sheet_packing_item, shipment
   WHERE shipment.packing_list = sheet_packing_item.packing_list
     AND sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
     AND shipment.packing_list = al_packing_list;
  IF ll_shipment_pc = 0 THEN
    RETURN 100;
  END IF; -- empty shipment

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  -- Retrieve ABCO info
  -- ls_sender_vanid := '3010007080';
  --ls_ic := 'R0P7A';

  -- Retrieve ALCAN supply code and Ford Stamping Plant location code
  --SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf
  --FROM customer_customer  WHERE o_customer_id = li_customer_id and e_customer_id = 49;  --Ford customer_id =49

  ls_sf := '039630926';
  --SELECT NVL(communication_code,'UNKNOWN') INTO ls_st FROM customer_system
  --WHERE customer_id = li_des_sh_cust_id;

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.vehicle_id_prefix, '9999'),
         nvl(shipment.equipment_type, 'NA'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'PT'), -- Protected Trailer
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE)
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_vehicle_id_prefix,
         ls_eq_type,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_carrier_initial,
         ldt_shipment
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;

  --Check all packing_lists are done against a BOL
  /*
  for pl_rec in packing_list_same_bol loop
      select shipment.shipment_status into ll_temp from shipment
             where shipment.packing_list = pl_rec.packing_list;
      if ll_temp > 0 then
         return pl_rec.packing_list;
      end if;

  end loop;
  */
  --End of packing list checking

  SELECT nvl(customer_duns_number_string, '00000000'), customer_short_name
    INTO ls_st_duns, ls_des_cust_name
    FROM customer
   WHERE customer_id = li_des_sh_cust_id;

  IF (ls_st_duns = '00000000') THEN
    RETURN 200;
  END IF; --No Ship to DUNS

  SELECT nvl(customer_duns_number_string, '00000000')
    INTO ls_su
    FROM customer
   WHERE customer_id = li_customer_id;
  IF (ls_su = '00000000') THEN
    RETURN 200;
  END IF; --No Supplier DUNS

  -- Get SCAC(Standard Carrier Alpha Code)
  SELECT nvl(carrier.scac, 'NONE'), LPAD(carrier.carrier_full_name, 17)
    INTO ls_scac, ls_carrier_full_name
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);

  -- Get Receiver and Customer VAN ID
  -- SELECT NVL(customer_system.van_account_num, 'nothing'), NVL(customer_system.gs03, 'nothing')
  -- INTO ls_receiver_vanid, ls_receiver_gs03    -- ls_receiver_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --   (select shipment.des_sh_cust_id  from shipment  where shipment.packing_list = al_packing_list);

  -- SELECT NVL(customer_system.van_account_num, 'nothing'),NVL(customer_system.gs03, 'nothing')
  -- INTO   ls_customer_vanid, ls_customer_gs03   -- ls_customer_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --       (select shipment.customer_id from shipment where shipment.packing_list = al_packing_list);

  -- Generate Header Info.
  --x12_table(i) := 'ISA*00*'||'          *00*          *ZZ*R0P7A          *ZZ*F159B          *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0') ||'*0*P**';
  --x12_table(i) := 'GS*SH*R0P7A*'||ls_st || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  --Alex Gerlants. 10/16/2018. Changed from "00200" to "00401"
  --Production
  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *01*039630926T     *09*0015049350011G *' ||
                  ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
  
  --Development                
  --x12_table(i) := 'ISA*00*' ||
  --                '          *00*          *ZZ*2NDSFTP        *ZZ*NOVLSTEST      *' ||
  --                ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
  --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';
                  
  i := i + 1;

  --Alex Gerlants. 10/16/2018. Changed from "002002" to "004010"
  --Production
  x12_table(1) := 'GS*SH*R0P7A*' || '001504935001' || '*' || ls_today || '*' ||
                  ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  --Development
  --x12_table(1) := 'GS*SH*2NDSFTP*' || 'NOVLSTEST' || '*' || ls_today || '*' ||
  --               ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;
  --x12_table(i):= 'BSN*00*' || to_char(ll_bill_of_lading) || '*' || ls_today || '*' || ls_now;
  x12_table(i) := 'BSN*00*' || to_char(al_packing_list) || '*' || ls_today || '*' ||
                  ls_now;
  i := i + 1;
  
  --Alex Gerlants. 08/07/2018.
  --Changed to populate with actual ship date instead of current date and time.
  --The reason is that when we send 856 on a later date, this date is not correct.
  --x12_table(i) := 'DTM*011*' || ls_today || '*' || ls_now;
  --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  
  --Alex Gerlants. 01/09/2020. Added the IF statement below.
  --If users do not enter time part in shipment.shipment_actualed_date_time,
  --856 will have system time in 'DTM*011*' and 'DTM*017*'
  
  ls_time := to_char(ldt_shipment, 'HH24MI');
  
  if ls_time <> '0000' then --User entered time
    x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                                                        to_char(ldt_shipment, 'HH24MI');
  else --User did not enter time  
    x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                                                        to_char(sysdate, 'HH24MI');
  end if;
  i := i + 1;
  
  --Alex Gerlants. 10/18/2018. Changed from "YYMMDD" to "YYYYMMDD"
  --Moved here from the below
  if ls_time <> '0000' then --User entered time
    x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                    to_char(ldt_shipment, 'HH24MI');
  else --User did not enter time
    x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                    to_char(sysdate, 'HH24MI');
  end if;
  i := i + 1;

  -- First Level HL
  x12_table(i) := 'HL*01**S';
  i := i + 1;
  --Alex Gerlants. 10/16/2018. Changed from "MEA*PD*G*" to "MEA*WT*G*"
  x12_table(i) := 'MEA*WT*G*' || to_char(ll_shipment_gt) || '*LB';
  i := i + 1;
  x12_table(i) := 'MEA*WT*N*' || to_char(ll_shipment_nt) || '*LB';
  i := i + 1;
  x12_table(i) := 'TD1*PLT90*' || to_char(li_rowcount);
  li_td1 := i;
  i := i + 1;
  x12_table(i) := 'TD5*B*2*' || ls_scac || '*M*' || ls_carrier_full_name;
  i := i + 1;
  -- segment was modified to include trailer number.  Patrick Reynolds 11/30/2016
  x12_table(i) := 'TD3*' || ls_carrier_desc_code || '*' || ls_scac || '*' || ls_vehicle_id_prefix;
  i := i + 1;
  x12_table(i) := 'REF*BM*' || to_char(al_packing_list);
  i := i + 1;
  x12_table(i) := 'REF*PK*' || to_char(al_packing_list);
  i := i + 1;
  -- segment was modified to include equipment type.  Patrick Reynolds 11/30/2016
  x12_table(i) := 'REF*EQ*' || ls_eq_type;
  i := i + 1; --waiting for Novilis, ----tony
  --- Testing for multi order ASN ----Tony

  x12_table(i) := 'REF*MB*' || to_char(ll_bill_of_lading);
  i := i + 1;
  SELECT COUNT(*)
    INTO ll_temp
    FROM shipment
   WHERE shipment.bill_of_lading = ll_bill_of_lading
     AND shipment.shipment_status = 0;
     
  --Alex Gerlants. 10/16/2018. Removed 2 lines below
  --x12_table(i) := 'REF*SS*' || to_char(ll_temp);
  --i := i + 1;
  --li_des_id := 1;
  
  --Alex Gerlants. 10/16/2018. Removed 7 lines below
  /*
  FOR c_stop IN c_ship_to LOOP
    IF li_des_sh_cust_id = c_stop.des_sh_cust_id THEN
      x12_table(i) := 'REF*QN*' || to_char(li_des_id);
      i := i + 1;
    END IF;
    li_des_id := li_des_id + 1;
  END LOOP;
  */

  /*
  IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
     x12_table(i):= 'REF*ZZ*' || ls_st;i:=i+1;
  end if;
  */

  ----Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  --x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
  --                to_char(ldt_shipment, 'HH24MI');
  --i := i + 1;
  
  x12_table(i) := 'N1*ST*' || ls_des_cust_name || '*1*' || ls_st_duns;
  i := i + 1;
  x12_table(i) := 'N1*SF*Aluminum Blanking Co*1*' || ls_sf;
  i := i + 1;
  x12_table(i) := 'N1*SU**1*' || ls_su;
  i := i + 1;

  --if not (li_des_sh_cust_id = 1096 or li_des_sh_cust_id = 1251) then
  --         x12_table(i):= 'N1*IC**92*' || ls_ic; i := i +1;        --- Deleted 04-30-03 by Tony according to alcan Julia's email
  --end if;

  --         x12_table(i):= 'N1*CN**92*' || ls_st_duns; i := i +1; --Ship to DUNs --- Deleted 04-30-03 by Tony according to alcan Julia's email

  -- Second Level HL based on End User PO( only one part# is included in one shipement per FORD's request)


  /*
      SELECT "CUSTOMER_ORDER"."ENDUSER_PO" into ls_enduser_po
             FROM "SHEET_SKID",
                  "CUSTOMER_ORDER"
                  WHERE ( "SHEET_SKID"."REF_ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM" ) and
                        (SHEET_SKID.SHEET_SKID_NUM = skidinfo_rec.SHEET_SKID_NUM);
  */

  x12_table(i) := 'HL*02*01*O';
  i := i + 1;
  IF ls_enduser_part IS NULL THEN
    ls_enduser_part := 'NA';
  END IF;
  x12_table(i) := 'LIN**BP*' || ls_enduser_part;
  i := i + 1;
  x12_table(i) := 'SN1**' || to_char(ll_shipment_pc) || '*EA*0';
  i := i + 1;

  --
  --ls_po := skidinfo_rec.ORIG_CUSTOMER_PO;


  --IF INSTR(skidinfo_rec.ORIG_CUSTOMER_PO,'-') > 0
  --New PO format for Novelis SAP include '-'
  /*IF instr(ls_po, '-') > 0 THEN
    ls_po := substr(ls_po, 0, instr(ls_po, '-') - 1);
  END IF;*/

  --   IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
  x12_table(i) := 'PRF*' || ls_po || '***' ||
                  to_char(skidinfo_rec.created_date, 'YYYYMMDD');
  i := i + 1;
  --   end if;

  CLOSE alcan_ford_856_cur;

   --  Novelis SAP order number
 x12_table(i) := 'REF*IL*' || ls_auth_code;
 i := i + 1;
  --  end if;

  -- Third Level HL Under a P.O.
  li_hl01 := 3;
  
  select count(*)
  into   ll_count
        FROM customer_order,
           order_item,
           sheet_skid,
           ab_job,
           shipment,
           sheet_packing_item
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);

  if ll_count > 0 then
      OPEN alcan_ford_856_cur;
  FETCH alcan_ford_856_cur
    INTO skidinfo_rec;
  --    ls_enduser_part := skidinfo_rec.ENDUSER_PART_NUM;
  --    ls_enduser_po := skidinfo_rec.ENDUSER_PO;

  /*
    if skidinfo_rec.ORIG_CUSTOMER_PO IN ('68Q68517') then    --Do NOT send 856 to Ford for some flipping related POs )
         edi_file_prefix := 'nosend_alcan_ford_ford';
    end if;
  */

  SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
    INTO ls_enduser_part
    FROM "ORDER_ITEM", "SHEET_SKID"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
     AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
     AND ("SHEET_SKID"."SHEET_SKID_NUM" = skidinfo_rec.sheet_skid_num);
     
     SELECT "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO"
    INTO ls_po
    FROM "SHEET_SKID", "CUSTOMER_ORDER"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
         "CUSTOMER_ORDER"."ORDER_ABC_NUM")
     AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num);
     
      --Skid loop begin ----------------------------------------------------------------
      FOR skidinfo_rec IN alcan_ford_856_cur LOOP
        
          --In case of a split skid, we are creating just 1 HL for this skid
          --with just 1 coil for this skid.
          select distinct 
                 coil.coil_org_num,
                 coil.coil_gauge,
                 coil.coil_width,
                 coil.lot_num,
                 nvl(skid_type_if_whed, -1) --Alex Gerlants. 04/01/2019
          into   ls_coil_org_num,
                 ll_coil_gauge,
                 ll_coil_width,
                 ls_lot_num,
                 ln_skid_type_if_whed --Alex Gerlants. 04/01/2019
          FROM "COIL",   
               "PRODUCTION_SHEET_ITEM",   
               "SHEET_SKID",   
               "SHEET_SKID_DETAIL",   
               "PROCESS_COIL"  
         WHERE ( "COIL"."COIL_ABC_NUM" = "PRODUCTION_SHEET_ITEM"."COIL_ABC_NUM" ) and  
               ( "SHEET_SKID_DETAIL"."SHEET_SKID_NUM" = "SHEET_SKID"."SHEET_SKID_NUM" ) and  
               ( "SHEET_SKID_DETAIL"."PROD_ITEM_NUM" = "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NUM" ) and  
               ( "COIL"."COIL_ABC_NUM" = "PROCESS_COIL"."COIL_ABC_NUM" ) and  
               ( "PRODUCTION_SHEET_ITEM"."AB_JOB_NUM" = "PROCESS_COIL"."AB_JOB_NUM" ) and  
               ( (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num)  ) and
               ( (rownum = 1)  ); --We need just 1 coil for each skid
      
          --Alex Gerlants. 04/01/2019. Begin
          if ln_skid_type_if_whed > -1 then --Warehouse skid
              --Get gauge and part width
              select distinct order_item.gauge,
                     f_get_part_width_per_job(ab_job.ab_job_num) 
              into   ll_coil_gauge,
                     ll_coil_width
              from   sheet_skid
                     join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
                     join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
                     join customer_order on customer_order.order_abc_num = order_item.order_abc_num
              where  sheet_skid_num = skidinfo_rec.sheet_skid_num
              and    (order_item.gauge is not null and f_get_part_width_per_job(sheet_skid.ab_job_num) is not null)
              and    rownum = 1;
          end if;
          --Alex Gerlants. 04/01/2019. End
      
          IF length(to_char(li_hl01)) = 1 THEN
            x12_table(i) := 'HL*0' || to_char(li_hl01) || '*02*I';
            i := i + 1;
          ELSE
            x12_table(i) := 'HL*' || to_char(li_hl01) || '*02*I';
            i := i + 1;
          END IF;

          --    IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
          --       x12_table(i) := 'SN1**'||to_char(skidinfo_rec.skid_pieces)||'*EA';i:=i+1;
          --    else
          x12_table(i) := 'SN1**1*PF';
          i := i + 1;
          --    end if;

          --if li_des_sh_cust_id = 1096 -- To Budd or li_des_sh_cust_id = 1251 then
          --   then
          --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; i := i +1;
          --      x12_table(i) :=  'MEA*PD*TH*' || to_char(skidinfo_rec.sheet_net_wt) || '*24'; i := i +1;
          --elsif   li_des_sh_cust_id = 1251   --To Eagle Steel
          --  then
          --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; i := i +1;
          --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*24'; i := i +1;
          --      x12_table(i) :=  'MEA*PD*TH*' || to_char(skidinfo_rec.gauge) || '*EM'; i:=i+1;
          --    x12_table(i) :=  'MEA*PD*WD*'||'44.875'||'*IN'; i:=i+1;
          --    x12_table(i) :=  'MEA*PD*LN*'||to_char(skidinfo_rec.skid_pieces)||'*LF';  i:=i+1;
          --else  --All else, Ford dirct shiping program
                            
          --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*N" to "MEA*WT*N"
          x12_table(i) := 'MEA*WT*N*' || to_char(skidinfo_rec.sheet_net_wt) ||
                          '*01';
          i := i + 1;
                            
          --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*WT" to "MEA*CT*NL"
          x12_table(i) := 'MEA*CT*NL*' || to_char(skidinfo_rec.skid_pieces) ||
                          '*PC';
          i := i + 1;

          -- changed to all gross wt per novelis 1/30/2015
          --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*G" to "MEA*WT*G"
          x12_table(i) := 'MEA*WT*G*' || to_char(skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt) || '*01';
          i := i + 1;
          
          --Alex Gerlants. 10/18/2018. New line 
          x12_table(i) := 'MEA*PD*GG*' || ll_coil_gauge;
          i := i + 1;
          
          --Alex Gerlants. 10/18/2018. New line 
          x12_table(i) := 'MEA*PD*WD*' || ll_coil_width;
          i := i + 1;

          /*
          IF (skidinfo_rec.sheet_theoretical_wt IS NULL) OR
             (skidinfo_rec.sheet_theoretical_wt = 0) THEN
            x12_table(i) := 'MEA*PD*G*' || to_char(ll_shipment_gt) || '*01';
            i := i + 1;
          ELSE
            x12_table(i) := 'MEA*PD*G*' ||
                            to_char(skidinfo_rec.sheet_theoretical_wt) || '*01';
            i := i + 1;
          END IF;
          */
          --end if;

          -- fill in lot num
          /*
          SELECT COUNT(*)
            INTO li_rc
            FROM sheet_skid_detail
           WHERE sheet_skid_detail.sheet_skid_num = skidinfo_rec.sheet_skid_num;

          ls_lot_num := skidinfo_rec.lot_num;
          ls_coil_id := skidinfo_rec.coil_id;

          IF li_rc = 1 THEN
            SELECT lot_num, coil_org_num
              INTO ls_lot_num, ls_coil_id
              FROM coil
             WHERE coil.coil_abc_num =
                   (SELECT coil_abc_num
                      FROM production_sheet_item
                     WHERE production_sheet_item.prod_item_num =
                           (SELECT prod_item_num
                              FROM sheet_skid_detail
                             WHERE sheet_skid_detail.sheet_skid_num =
                                   skidinfo_rec.sheet_skid_num));
          END IF;
          */
          --if li_des_sh_cust_id = 1251   --Eagle need coil ID here instead of lot number
          --then
          --x12_table(i) :=  'REF*HC*' || skidinfo_rec.coil_id ; i := i +1;
          --else
                            
          --Alex Gerlants. 10/18/2018. Changed from "REF*HC" to "REF*BT"
          x12_table(i) := 'REF*BT*' || ls_lot_num;
          i := i + 1;
          --end if;

          --x12_table(i) := 'REF*LS*' || to_char(skidinfo_rec.sheet_skid_num);
          --Alex Gerlants. 10/18/2018. Changed from "REF*LS" to "REF*SE"
          x12_table(i) := 'REF*SE*' || skidinfo_rec.sheet_skid_display_num; --added by Victor H. on 06-2012 for Novelis locatio code request
          i := i + 1;
          
          --Alex Gerlants. 10/18/2018. New line 
          x12_table(i) := 'REF*LS*' || ls_coil_org_num;
          i := i + 1;
          
          li_hl01 := li_hl01 + 1;
          li_rowcount := alcan_ford_856_cur%ROWCOUNT;
          x12_table(li_td1) := 'TD1*PLT90*' || to_char(li_rowcount);
      END LOOP; --End of 'FOR skidinfo_rec IN alcan_ford_856_cur LOOP'
  --Skid loop end ------------------------------------------------------------------
  end if; --if ll_count > 0 then
  
  ---  Scrap loop begin  ----------------------------------------------------------

  hl_order := li_hl01;
  x12_table(i) := 'HL*' || to_char(li_hl01) || '*1*O';
  li_hl01 := li_hl01 + 1;
  i := i + 1;
      
  x12_table(i) := 'LIN**BP*SCRAP';
  i := i + 1;
  
  SELECT SUM(scrap_skid.scrap_net_wt)
  INTO po_nt
  FROM scrap_skid, scrap_packing_item
  WHERE scrap_packing_item.packing_list = al_packing_list
  AND scrap_packing_item.scrap_skid_num = scrap_skid.scrap_skid_num;
  
  x12_table(i) := 'SN1**' || po_nt || '*01';
  i := i + 1;
  
  x12_table(i) := 'PRF*' || 'NA' || '***20030102';
  i := i + 1;
    
  x12_table(i) := 'REF*IL*' || ls_auth_code;
  i := i + 1;
  
  FOR alloyinfo_rec IN alcan_scrap_856_cur LOOP
    ll_alloy := alloyinfo_rec.scrap_alloy2;

    --open item_cur;
    --fetch item_cur INTO item_rec;
    FOR item_rec IN item_cur LOOP

      x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(hl_order) || '*I';
      li_hl01 := li_hl01 + 1;
      i := i + 1;
      x12_table(i) := 'PID*S*55***' || upper(rtrim(ltrim(ll_alloy)));
      i := i + 1;
      x12_table(i) := 'MEA*WT*G*' ||
                      to_char(item_rec.scrap_net_wt +
                              item_rec.scrap_tare_wt) || '*01';
      i := i + 1;
      x12_table(i) := 'MEA*WT*N*' || to_char(item_rec.scrap_net_wt) ||
                      '*01';
      i := i + 1;
      
      x12_table(i) := 'REF*SE*' || to_char(item_rec.scrap_skid_display_num);
      i := i + 1;
      x12_table(i) := 'REF*LS*' || to_char(item_rec.scrap_skid_display_num);
      i := i + 1;

    END LOOP; --FOR item_rec IN item_cur LOOP
    --close item_cur;

  END LOOP; --FOR alloyinfo_rec IN alcan_scrap_856_cur LOOP
  ---  Scrap loop end  ------------------------------------------------------------

  -- DBMS_OUTPUT.PUT_LINE ('rowcount' || to_char(li_rowcount));

  -- if li_des_sh_cust_id = 1096 or li_des_sh_cust_id = 1251 then
  --   x12_table(i) :=  'CTT*' || to_char(li_HL01 - 1) ||'*' || to_char(ll_shipment_pc*2) ;
  --   i := i +1;
  -- else
  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                  to_char(li_rowcount + ll_shipment_pc);
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  -- Write X.12 to file
  -- To FORD

  /** Write file to /templar/templar/incoming/senddata
  /*
  **/

  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  --edi_file:= 'S_alcan_ford_ford_' || to_char(ll_edi_file_id) ||'.x12';

  -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
  -- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
    --        v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
  END LOOP;
  utl_file.fclose(edi_file_handle);

  --To ALCAN

  /*
  SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;
  SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id_alcan FROM DUAL;
  edi_file:= 'S_alcan_ford_alcan_' || to_char(ll_edi_file_id_alcan) ||'.x12';
  edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');
  x12_table(0) := 'ISA*00*'||'          *00*          *01*039630926T     *09*0015049350011G *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0')||'*0*P**';
  x12_table(1) := 'GS*SH*R0P7A*'||'001504935001' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  x12_table(i-1) :=  'GE*1*' || to_char (ll_gs_log);
  x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');
  for j in 0..i loop
   UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
       v_edi_text_alcan:=v_edi_text_alcan||x12_table(j)||CHR(10);
  end loop;
  UTL_FILE.FCLOSE(edi_file_handle);

  */

  /* The following code added by Tony, for update archive*/

  --  INSERT INTO edi_log (edi_log_timestamp,customer_id,
  --         customer_edi_name,edi_log_contents,edi_file_id,edi_text)
  --    VALUES (SYSDATE,li_customer_id,ll_customer_edi_name,
  --           'EDI:'||ll_customer_edi_name||' generated successfully.',ll_edi_file_id,v_edi_text);
  --   COMMIT;

  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE,
         edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;
--  COMMIT;

  /* --added by Victor Huang on 06/05 for function acknowlegement
  INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
  VALUES(ll_gs_log, ls_su, sysdate, edi_file);
  COMMIT;*/

  --added by Victor Huang on 12/07 for verifying 997
  INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (ll_edi_file_id,
     '039630926',
     ls_su,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856');
  COMMIT;

  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  --exception
  --   when invalid_operation
  --   then
  --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

  --  when others
  --  then
  --      DBMS_OUTPUT.PUT_LINE ('System Error');
  --      UTL_FILE.FCLOSE(edi_file_handle);

  RETURN 1;
END edi_novelis_856_sheets_scrap;
