--  DDL for Function EDI_NOVELIS_856_X12
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_NOVELIS_856_X12" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*
  Aluminum Blanking: Ford Supplier Code: ZZ R0P7A
                     DUNS: 01 039630926T
  Customer: ALCAN(34,35,10,1153)
  Alcan Rolled Product    X.121       0015049350011G
  End User: Ford (ZZ F159B)
            Ford Chicago Stamping Plant(51) MS02A
            Ford Walton Hills Stamping Plant(77) MS03A
            Ford Woodhaven Stamping Plant(71) AF30A MS09A
            Ford Maumee Stamping Plant(78)    AF06A MS08A

            Budd Company (Customer ID: 1096) B821L
            Eagle Steel (1251) MZF6B
            (not in use)Ford Monroe Stamping              AP06A

            (not in use) Warehouses: IDS(41)               R5G3B
            (not in use) Wayne Steel Distribution Center(79) RWSDC

  */

  --v_edi_text_ford varchar2(32767);
  --v_edi_text_alcan varchar2(32767);
  --ll_customer_edi_name VARCHAR2(20);

   --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50);

  --edi_loc varchar2(50):='/tmp';
  edi_file        VARCHAR2(50) := 'edi_out.txt';
  --edi_file_prefix VARCHAR2(50) := 'S_novelis_856_'; --Production
  edi_file_prefix VARCHAR2(50) := 's_novelis_856_'; --Development
  edi_file_handle utl_file.file_type;

  li_customer_id    shipment.customer_id%TYPE;
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;

  -- ls_sender_vanid varchar2 (50);
  -- ls_receiver_vanid varchar2 (50);
  -- ls_customer_vanid varchar2(50);
  -- ls_receiver_gs03 varchar2(50);
  -- ls_customer_gs03 varchar2(50);
  --ls_st varchar2(50);
  ls_sf VARCHAR2(50);
  ls_eq_type VARCHAR2(10);  -- Added by Patrick Reynolds 11/30/2016
  ls_su      VARCHAR2(50);
  ls_st_duns VARCHAR2(50);
  ls_po      VARCHAR2(30);
  ls_auth_code   VARCHAR2(32);
  ll_gs_log  INTEGER;
  ll_st_log  INTEGER;
  ll_bsn_log INTEGER;

  ls_today VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD'); --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  ls_today_2digits_year VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD'); --Alex Gerlants. 10/16/2018. Test
  ls_now   VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  li_rowcount INTEGER;
  li_hl01 INTEGER;
  ll_shipment_nt INTEGER;
  ll_shipment_gt INTEGER;
  ll_shipment_pc INTEGER;
  li_td1 INTEGER;
  li_rc  INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_vehicle_id_prefix VARCHAR2(50);  -- Added by Patrick Reynolds 11/30/2016
  ls_scac              carrier.scac%TYPE;
  ls_carrier_full_name VARCHAR2(18);
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_carrier_initial   VARCHAR2(50);  -- Not used in stored procedure.  Discovered by Patrick Reynolds 11/30/2016
  ldt_shipment         DATE;
   ll_temp         INTEGER;
  ls_enduser_part VARCHAR2(50);
  li_des_id       INTEGER;

  ll_edi_file_id INTEGER;

  ls_lot_num VARCHAR2(32);
  ls_coil_id VARCHAR2(32);
  ls_des_cust_name VARCHAR2(18);
  
  ls_coil_org_num		        coil.coil_org_num%TYPE; --Alex Gerlants. 01/25/2019
  ll_coil_gauge		          coil.coil_gauge%TYPE;   --Alex Gerlants. 01/25/2019
  ll_coil_width		          coil.coil_width%TYPE;   --Alex Gerlants. 01/25/2019
  ld_ship_date              date;
  li_is_novelis             integer;
  ln_skid_type_if_whed      sheet_skid.skid_type_if_whed%TYPE;   --Alex Gerlants. 04/01/2019
  ls_time                   char(4); --Alex Gerlants. 01/09/2020

  CURSOR alcan_ford_856_cur IS
    SELECT sheet_packing_item.sh_packing_item,
           'MULTIPLE' lot_num,
           'MULTIPLE' coil_id,
           customer_order.orig_customer_po,
           customer_order.order_abc_num,
           customer_order.enduser_po,
           customer_order.created_date,
           order_item.order_item_num,
           order_item.enduser_part_num,
           order_item.supplier_code,
           order_item.gauge,
           sheet_skid. ab_job_num,
           sheet_skid.sheet_skid_num,
           sheet_skid.sheet_skid_display_num, --added by Victor H. on 06-2012 for Novelis locatio code request
           sheet_skid.sheet_net_wt,
           sheet_skid.sheet_tare_wt,
           sheet_skid. skid_pieces,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_theoretical_wt,
           NULL done
      FROM customer_order,
           order_item,
           sheet_skid,
           ab_job,
           shipment,
           sheet_packing_item
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
/*      
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
  --      (SHIPMENT.SHIPMENT_EDI856_DATE is NULL);
*/
  --TYPE skidinfo_tabletype IS TABLE OF alcan_ford_856_cur%ROWTYPE INDEX BY BINARY_INTEGER;
  --skidinfo_table skidinfo_tabletype;
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table    store_tabletype;
  i            BINARY_INTEGER := 0;
  skidinfo_rec alcan_ford_856_cur%ROWTYPE;

  /*CURSOR packing_list_same_bol IS
  SELECT packing_list
    FROM shipment
   WHERE bill_of_lading = ll_bill_of_lading;*/

  CURSOR c_ship_to IS
    SELECT DISTINCT des_sh_cust_id --, PACKING_LIST
      FROM shipment
     WHERE bill_of_lading = ll_bill_of_lading
       AND shipment.shipment_status = 0;
  --ORDER BY PACKING_LIST;
  
  cursor c_coil is
  select distinct 
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num,
         coil.coil_gauge,
         coil.coil_width
         --process_coil.coil_abc_num
         --outbound_edi_transaction.transaction_time,
         --outbound_edi_transaction.edi_file_name
  from   customer_order
         join order_item on order_item.order_abc_num = customer_order.order_abc_num
         join ab_job on ab_job.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
         join sheet_skid on sheet_skid.ab_job_num = ab_job.ab_job_num
         join sheet_packing_item on sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
         join shipment on shipment.packing_list = sheet_packing_item.packing_list
         join process_coil on process_coil.ab_job_num = ab_job.ab_job_num
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         --join outbound_edi_transaction on outbound_edi_transaction.edi_file_id = shipment.edi_file_id_856
  --where  shipment.packing_list = 105586 --Production
  where  shipment.packing_list = al_packing_list --Develpment
  order by
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num;

BEGIN
  
  select f_is_novelis(al_packing_list)
  into   li_is_novelis
  from   dual;
  
  if li_is_novelis = 0 then --Customer is NOT Novelis
    return 1; --Nothing to do here
  end if;
  
  select shipment_edi856_date
  into   ld_ship_date
  from   shipment
  where  shipment.packing_list = al_packing_list;
   
  if not (ld_ship_date is null) then --ASN already sent
    return 100;
  end if;

  edi_loc := dbo.get_edi_destination('EDI_DIR'); --Alex Gerlants. 11/15/2016

  -- Get Customer ID, End user ID, authorization code
  SELECT customer_id, des_sh_cust_id, nvl(shipment_athorization_code, 'NA')
    INTO li_customer_id, li_des_sh_cust_id, ls_auth_code
  FROM shipment
  WHERE shipment.packing_list = al_packing_list;
  IF NOT SQL%FOUND THEN
   RETURN - 1;
  END IF;

  -- dbms_output.put_line (to_char(li_customer_id) || '  ' || to_char(li_des_sh_cust_id) );

  --Alex Gerlants. 03/03/2021. Added '2950'  to the list below <== NOVELIS-GUTHRIE
  IF NOT (li_customer_id IN (34, 35, 10, 1153, 1459, 2582, 2950)) -- AND (li_des_sh_cust_id IN (
  --10,41,51,69,70,71,72,77,78,79,1055,1062,1073,1086,1096,1099,1114,1112,1153,
  --1206,1251,1253,1268,1269,1270,1322,1325,1328,1331,1332,1346,1347, 1382, 1383)))
   THEN

    --***********************************************************************************************88
    --IF NOT ((li_customer_id IN (34,35,10,1153)) AND (li_des_sh_cust_id IN (SELECT CUSTOMER_ID
    --FROM CUSTOMER
    --WHERE CUSTOMER_DUNS_NUMBER_STRING is not null))) THEN

    RETURN 200;
  END IF;

  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(sheet_skid.sheet_net_wt),
         SUM(sheet_skid.sheet_net_wt) + SUM(sheet_skid.sheet_tare_wt),
         SUM(sheet_skid.skid_pieces)
    INTO ll_shipment_nt, ll_shipment_gt, ll_shipment_pc
    FROM sheet_skid, sheet_packing_item, shipment
   WHERE shipment.packing_list = sheet_packing_item.packing_list
     AND sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
     AND shipment.packing_list = al_packing_list;
  IF ll_shipment_pc = 0 THEN
    RETURN 100;
  END IF; -- empty shipment

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  -- Retrieve ABCO info
  -- ls_sender_vanid := '3010007080';
  --ls_ic := 'R0P7A';

  -- Retrieve ALCAN supply code and Ford Stamping Plant location code
  --SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf
  --FROM customer_customer  WHERE o_customer_id = li_customer_id and e_customer_id = 49;  --Ford customer_id =49

  ls_sf := '039630926';
  --SELECT NVL(communication_code,'UNKNOWN') INTO ls_st FROM customer_system
  --WHERE customer_id = li_des_sh_cust_id;

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.vehicle_id_prefix, '9999'),
         nvl(shipment.equipment_type, 'NA'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'PT'), -- Protected Trailer
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE)
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_vehicle_id_prefix,
         ls_eq_type,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_carrier_initial,
         ldt_shipment
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;

  --Check all packing_lists are done against a BOL
  /*
  for pl_rec in packing_list_same_bol loop
      select shipment.shipment_status into ll_temp from shipment
             where shipment.packing_list = pl_rec.packing_list;
      if ll_temp > 0 then
         return pl_rec.packing_list;
      end if;

  end loop;
  */
  --End of packing list checking

  SELECT nvl(customer_duns_number_string, '00000000'), customer_short_name
    INTO ls_st_duns, ls_des_cust_name
    FROM customer
   WHERE customer_id = li_des_sh_cust_id;

  IF (ls_st_duns = '00000000') THEN
    RETURN 200;
  END IF; --No Ship to DUNS

  SELECT nvl(customer_duns_number_string, '00000000')
    INTO ls_su
    FROM customer
   WHERE customer_id = li_customer_id;
  IF (ls_su = '00000000') THEN
    RETURN 200;
  END IF; --No Supplier DUNS

  -- Get SCAC(Standard Carrier Alpha Code)
  SELECT nvl(carrier.scac, 'NONE'), LPAD(carrier.carrier_full_name, 17)
    INTO ls_scac, ls_carrier_full_name
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);

  -- Get Receiver and Customer VAN ID
  -- SELECT NVL(customer_system.van_account_num, 'nothing'), NVL(customer_system.gs03, 'nothing')
  -- INTO ls_receiver_vanid, ls_receiver_gs03    -- ls_receiver_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --   (select shipment.des_sh_cust_id  from shipment  where shipment.packing_list = al_packing_list);

  -- SELECT NVL(customer_system.van_account_num, 'nothing'),NVL(customer_system.gs03, 'nothing')
  -- INTO   ls_customer_vanid, ls_customer_gs03   -- ls_customer_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --       (select shipment.customer_id from shipment where shipment.packing_list = al_packing_list);

  -- Generate Header Info.
  --x12_table(i) := 'ISA*00*'||'          *00*          *ZZ*R0P7A          *ZZ*F159B          *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0') ||'*0*P**';
  --x12_table(i) := 'GS*SH*R0P7A*'||ls_st || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  --Alex Gerlants. 10/16/2018. Changed from "00200" to "00401"
  --Production
  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *01*039630926T     *09*0015049350011G *' ||
                  ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
  
  --Development                
  --x12_table(i) := 'ISA*00*' ||
  --                '          *00*          *ZZ*2NDSFTP        *ZZ*NOVLSTEST      *' ||
  --                ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
  --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';
                  
  i := i + 1;

  --Alex Gerlants. 10/16/2018. Changed from "002002" to "004010"
  --Production
  x12_table(1) := 'GS*SH*R0P7A*' || '001504935001' || '*' || ls_today || '*' ||
                  ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  --Development
  --x12_table(1) := 'GS*SH*2NDSFTP*' || 'NOVLSTEST' || '*' || ls_today || '*' ||
  --               ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;
  --x12_table(i):= 'BSN*00*' || to_char(ll_bill_of_lading) || '*' || ls_today || '*' || ls_now;
  x12_table(i) := 'BSN*00*' || to_char(al_packing_list) || '*' || ls_today || '*' ||
                  ls_now;
  i := i + 1;
  
  --Alex Gerlants. 08/07/2018.
  --Changed to populate with actual ship date instead of current date and time.
  --The reason is that when we send 856 on a later date, this date is not correct.
  --x12_table(i) := 'DTM*011*' || ls_today || '*' || ls_now;
  --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  
  --Alex Gerlants. 01/09/2020. Added the IF statement below.
  --If users do not enter time part in shipment.shipment_actualed_date_time,
  --856 will have system time in 'DTM*011*' and 'DTM*017*'
  
  ls_time := to_char(ldt_shipment, 'HH24MI');
  
  if ls_time <> '0000' then --User entered time
    x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                                                        to_char(ldt_shipment, 'HH24MI');
  else --User did not enter time  
    x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                                                        to_char(sysdate, 'HH24MI');
  end if;
  i := i + 1;
  
  --Alex Gerlants. 10/18/2018. Changed from "YYMMDD" to "YYYYMMDD"
  --Moved here from the below
  if ls_time <> '0000' then --User entered time
    x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                    to_char(ldt_shipment, 'HH24MI');
  else --User did not enter time
    x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                    to_char(sysdate, 'HH24MI');
  end if;
  i := i + 1;

  -- First Level HL
  x12_table(i) := 'HL*01**S';
  i := i + 1;
  --Alex Gerlants. 10/16/2018. Changed from "MEA*PD*G*" to "MEA*WT*G*"
  x12_table(i) := 'MEA*WT*G*' || to_char(ll_shipment_gt) || '*LB';
  i := i + 1;
  x12_table(i) := 'MEA*WT*N*' || to_char(ll_shipment_nt) || '*LB';
  i := i + 1;
  x12_table(i) := 'TD1*PLT90*' || to_char(li_rowcount);
  li_td1 := i;
  i := i + 1;
  x12_table(i) := 'TD5*B*2*' || ls_scac || '*M*' || ls_carrier_full_name;
  i := i + 1;
  -- segment was modified to include trailer number.  Patrick Reynolds 11/30/2016
  x12_table(i) := 'TD3*' || ls_carrier_desc_code || '*' || ls_scac || '*' || ls_vehicle_id_prefix;
  i := i + 1;
  x12_table(i) := 'REF*BM*' || to_char(al_packing_list);
  i := i + 1;
  x12_table(i) := 'REF*PK*' || to_char(al_packing_list);
  i := i + 1;
  -- segment was modified to include equipment type.  Patrick Reynolds 11/30/2016
  x12_table(i) := 'REF*EQ*' || ls_eq_type;
  i := i + 1; --waiting for Novilis, ----tony
  --- Testing for multi order ASN ----Tony

  x12_table(i) := 'REF*MB*' || to_char(ll_bill_of_lading);
  i := i + 1;
  SELECT COUNT(*)
    INTO ll_temp
    FROM shipment
   WHERE shipment.bill_of_lading = ll_bill_of_lading
     AND shipment.shipment_status = 0;
     
  --Alex Gerlants. 10/16/2018. Removed 2 lines below
  --x12_table(i) := 'REF*SS*' || to_char(ll_temp);
  --i := i + 1;
  li_des_id := 1;
  
  --Alex Gerlants. 10/16/2018. Removed 7 lines below
  /*
  FOR c_stop IN c_ship_to LOOP
    IF li_des_sh_cust_id = c_stop.des_sh_cust_id THEN
      x12_table(i) := 'REF*QN*' || to_char(li_des_id);
      i := i + 1;
    END IF;
    li_des_id := li_des_id + 1;
  END LOOP;
  */

  /*
  IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
     x12_table(i):= 'REF*ZZ*' || ls_st;i:=i+1;
  end if;
  */

  ----Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  --x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
  --                to_char(ldt_shipment, 'HH24MI');
  --i := i + 1;
  
  x12_table(i) := 'N1*ST*' || ls_des_cust_name || '*1*' || ls_st_duns;
  i := i + 1;
  x12_table(i) := 'N1*SF*Aluminum Blanking Co*1*' || ls_sf;
  i := i + 1;
  x12_table(i) := 'N1*SU**1*' || ls_su;
  i := i + 1;

  --if not (li_des_sh_cust_id = 1096 or li_des_sh_cust_id = 1251) then
  --         x12_table(i):= 'N1*IC**92*' || ls_ic; i := i +1;        --- Deleted 04-30-03 by Tony according to alcan Julia's email
  --end if;

  --         x12_table(i):= 'N1*CN**92*' || ls_st_duns; i := i +1; --Ship to DUNs --- Deleted 04-30-03 by Tony according to alcan Julia's email

  -- Second Level HL based on End User PO( only one part# is included in one shipement per FORD's request)
  OPEN alcan_ford_856_cur;
  FETCH alcan_ford_856_cur
    INTO skidinfo_rec;
  --    ls_enduser_part := skidinfo_rec.ENDUSER_PART_NUM;
  --    ls_enduser_po := skidinfo_rec.ENDUSER_PO;

  /*
    if skidinfo_rec.ORIG_CUSTOMER_PO IN ('68Q68517') then    --Do NOT send 856 to Ford for some flipping related POs )
         edi_file_prefix := 'nosend_alcan_ford_ford';
    end if;
  */

  SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
    INTO ls_enduser_part
    FROM "ORDER_ITEM", "SHEET_SKID"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
     AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
     AND ("SHEET_SKID"."SHEET_SKID_NUM" = skidinfo_rec.sheet_skid_num);

  /*
      SELECT "CUSTOMER_ORDER"."ENDUSER_PO" into ls_enduser_po
             FROM "SHEET_SKID",
                  "CUSTOMER_ORDER"
                  WHERE ( "SHEET_SKID"."REF_ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM" ) and
                        (SHEET_SKID.SHEET_SKID_NUM = skidinfo_rec.SHEET_SKID_NUM);
  */

  x12_table(i) := 'HL*02*01*O';
  i := i + 1;
  IF ls_enduser_part IS NULL THEN
    ls_enduser_part := 'NA';
  END IF;
  x12_table(i) := 'LIN**BP*' || ls_enduser_part;
  i := i + 1;
  x12_table(i) := 'SN1**' || to_char(ll_shipment_pc) || '*EA*0';
  i := i + 1;

  --
  --ls_po := skidinfo_rec.ORIG_CUSTOMER_PO;
  SELECT "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO"
    INTO ls_po
    FROM "SHEET_SKID", "CUSTOMER_ORDER"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
         "CUSTOMER_ORDER"."ORDER_ABC_NUM")
     AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num);

  --IF INSTR(skidinfo_rec.ORIG_CUSTOMER_PO,'-') > 0
  --New PO format for Novelis SAP include '-'
  /*IF instr(ls_po, '-') > 0 THEN
    ls_po := substr(ls_po, 0, instr(ls_po, '-') - 1);
  END IF;*/

  --   IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
  x12_table(i) := 'PRF*' || ls_po || '***' ||
                  to_char(skidinfo_rec.created_date, 'YYYYMMDD');
  i := i + 1;
  --   end if;

  CLOSE alcan_ford_856_cur;

   --  Novelis SAP order number
 x12_table(i) := 'REF*IL*' || ls_auth_code;
 i := i + 1;
  --  end if;

  -- Third Level HL Under a P.O.
  li_hl01 := 3;

  --Skid loop begin ----------------------------------------------------------------
  FOR skidinfo_rec IN alcan_ford_856_cur LOOP
    
      --In case of a split skid, we are creating just 1 HL for this skid
      --with just 1 coil for this skid.
      select distinct 
             coil.coil_org_num,
             coil.coil_gauge,
             coil.coil_width,
             coil.lot_num,
             nvl(skid_type_if_whed, -1) --Alex Gerlants. 04/01/2019
      into   ls_coil_org_num,
             ll_coil_gauge,
             ll_coil_width,
             ls_lot_num,
             ln_skid_type_if_whed --Alex Gerlants. 04/01/2019
      FROM "COIL",   
           "PRODUCTION_SHEET_ITEM",   
           "SHEET_SKID",   
           "SHEET_SKID_DETAIL",   
           "PROCESS_COIL"  
     WHERE ( "COIL"."COIL_ABC_NUM" = "PRODUCTION_SHEET_ITEM"."COIL_ABC_NUM" ) and  
           ( "SHEET_SKID_DETAIL"."SHEET_SKID_NUM" = "SHEET_SKID"."SHEET_SKID_NUM" ) and  
           ( "SHEET_SKID_DETAIL"."PROD_ITEM_NUM" = "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NUM" ) and  
           ( "COIL"."COIL_ABC_NUM" = "PROCESS_COIL"."COIL_ABC_NUM" ) and  
           ( "PRODUCTION_SHEET_ITEM"."AB_JOB_NUM" = "PROCESS_COIL"."AB_JOB_NUM" ) and  
           ( (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num)  ) and
           ( (rownum = 1)  ); --We need just 1 coil for each skid
  
      --Alex Gerlants. 04/01/2019. Begin
      if ln_skid_type_if_whed > -1 then --Warehouse skid
          --Get gauge and part width
          select distinct order_item.gauge,
                 f_get_part_width_per_job(ab_job.ab_job_num) 
          into   ll_coil_gauge,
                 ll_coil_width
          from   sheet_skid
                 join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
                 join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
                 join customer_order on customer_order.order_abc_num = order_item.order_abc_num
          where  sheet_skid_num = skidinfo_rec.sheet_skid_num
          and    (order_item.gauge is not null and f_get_part_width_per_job(sheet_skid.ab_job_num) is not null)
          and    rownum = 1;
      end if;
      --Alex Gerlants. 04/01/2019. End
  
      IF length(to_char(li_hl01)) = 1 THEN
        x12_table(i) := 'HL*0' || to_char(li_hl01) || '*02*I';
        i := i + 1;
      ELSE
        x12_table(i) := 'HL*' || to_char(li_hl01) || '*02*I';
        i := i + 1;
      END IF;

      --    IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
      --       x12_table(i) := 'SN1**'||to_char(skidinfo_rec.skid_pieces)||'*EA';i:=i+1;
      --    else
      x12_table(i) := 'SN1**1*PF';
      i := i + 1;
      --    end if;

      --if li_des_sh_cust_id = 1096 -- To Budd or li_des_sh_cust_id = 1251 then
      --   then
      --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; i := i +1;
      --      x12_table(i) :=  'MEA*PD*TH*' || to_char(skidinfo_rec.sheet_net_wt) || '*24'; i := i +1;
      --elsif   li_des_sh_cust_id = 1251   --To Eagle Steel
      --  then
      --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; i := i +1;
      --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*24'; i := i +1;
      --      x12_table(i) :=  'MEA*PD*TH*' || to_char(skidinfo_rec.gauge) || '*EM'; i:=i+1;
      --    x12_table(i) :=  'MEA*PD*WD*'||'44.875'||'*IN'; i:=i+1;
      --    x12_table(i) :=  'MEA*PD*LN*'||to_char(skidinfo_rec.skid_pieces)||'*LF';  i:=i+1;
      --else  --All else, Ford dirct shiping program
                        
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*N" to "MEA*WT*N"
      x12_table(i) := 'MEA*WT*N*' || to_char(skidinfo_rec.sheet_net_wt) ||
                      '*01';
      i := i + 1;
                        
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*WT" to "MEA*CT*NL"
      x12_table(i) := 'MEA*CT*NL*' || to_char(skidinfo_rec.skid_pieces) ||
                      '*PC';
      i := i + 1;

      -- changed to all gross wt per novelis 1/30/2015
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*G" to "MEA*WT*G"
      x12_table(i) := 'MEA*WT*G*' || to_char(skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt) || '*01';
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      x12_table(i) := 'MEA*PD*GG*' || ll_coil_gauge;
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      x12_table(i) := 'MEA*PD*WD*' || ll_coil_width;
      i := i + 1;

      /*
      IF (skidinfo_rec.sheet_theoretical_wt IS NULL) OR
         (skidinfo_rec.sheet_theoretical_wt = 0) THEN
        x12_table(i) := 'MEA*PD*G*' || to_char(ll_shipment_gt) || '*01';
        i := i + 1;
      ELSE
        x12_table(i) := 'MEA*PD*G*' ||
                        to_char(skidinfo_rec.sheet_theoretical_wt) || '*01';
        i := i + 1;
      END IF;
      */
      --end if;

      -- fill in lot num
      /*
      SELECT COUNT(*)
        INTO li_rc
        FROM sheet_skid_detail
       WHERE sheet_skid_detail.sheet_skid_num = skidinfo_rec.sheet_skid_num;

      ls_lot_num := skidinfo_rec.lot_num;
      ls_coil_id := skidinfo_rec.coil_id;

      IF li_rc = 1 THEN
        SELECT lot_num, coil_org_num
          INTO ls_lot_num, ls_coil_id
          FROM coil
         WHERE coil.coil_abc_num =
               (SELECT coil_abc_num
                  FROM production_sheet_item
                 WHERE production_sheet_item.prod_item_num =
                       (SELECT prod_item_num
                          FROM sheet_skid_detail
                         WHERE sheet_skid_detail.sheet_skid_num =
                               skidinfo_rec.sheet_skid_num));
      END IF;
      */
      --if li_des_sh_cust_id = 1251   --Eagle need coil ID here instead of lot number
      --then
      --x12_table(i) :=  'REF*HC*' || skidinfo_rec.coil_id ; i := i +1;
      --else
                        
      --Alex Gerlants. 10/18/2018. Changed from "REF*HC" to "REF*BT"
      x12_table(i) := 'REF*BT*' || ls_lot_num;
      i := i + 1;
      --end if;

      --x12_table(i) := 'REF*LS*' || to_char(skidinfo_rec.sheet_skid_num);
      --Alex Gerlants. 10/18/2018. Changed from "REF*LS" to "REF*SE"
      x12_table(i) := 'REF*SE*' || skidinfo_rec.sheet_skid_display_num; --added by Victor H. on 06-2012 for Novelis locatio code request
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      x12_table(i) := 'REF*LS*' || ls_coil_org_num;
      i := i + 1;
      
      li_hl01 := li_hl01 + 1;
      li_rowcount := alcan_ford_856_cur%ROWCOUNT;
      x12_table(li_td1) := 'TD1*PLT90*' || to_char(li_rowcount);
  END LOOP; --End of 'FOR skidinfo_rec IN alcan_ford_856_cur LOOP'
  --Skid loop end ------------------------------------------------------------------

  -- DBMS_OUTPUT.PUT_LINE ('rowcount' || to_char(li_rowcount));

  -- if li_des_sh_cust_id = 1096 or li_des_sh_cust_id = 1251 then
  --   x12_table(i) :=  'CTT*' || to_char(li_HL01 - 1) ||'*' || to_char(ll_shipment_pc*2) ;
  --   i := i +1;
  -- else
  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                  to_char(li_rowcount + ll_shipment_pc);
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  -- Write X.12 to file
  -- To FORD

  /** Write file to /templar/templar/incoming/senddata
  /*
  **/

  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  --edi_file:= 'S_alcan_ford_ford_' || to_char(ll_edi_file_id) ||'.x12';

  -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
  -- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  --edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  edi_file_handle := utl_file.fopen('/TEMPLAR/TEMPLAR/INCOMING/SENDDATA/', edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
    --        v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
  END LOOP;
  utl_file.fclose(edi_file_handle);

  --To ALCAN

  /*
  SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;
  SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id_alcan FROM DUAL;
  edi_file:= 'S_alcan_ford_alcan_' || to_char(ll_edi_file_id_alcan) ||'.x12';
  edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');
  x12_table(0) := 'ISA*00*'||'          *00*          *01*039630926T     *09*0015049350011G *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0')||'*0*P**';
  x12_table(1) := 'GS*SH*R0P7A*'||'001504935001' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  x12_table(i-1) :=  'GE*1*' || to_char (ll_gs_log);
  x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');
  for j in 0..i loop
   UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
       v_edi_text_alcan:=v_edi_text_alcan||x12_table(j)||CHR(10);
  end loop;
  UTL_FILE.FCLOSE(edi_file_handle);

  */

  /* The following code added by Tony, for update archive*/

  --  INSERT INTO edi_log (edi_log_timestamp,customer_id,
  --         customer_edi_name,edi_log_contents,edi_file_id,edi_text)
  --    VALUES (SYSDATE,li_customer_id,ll_customer_edi_name,
  --           'EDI:'||ll_customer_edi_name||' generated successfully.',ll_edi_file_id,v_edi_text);
  --   COMMIT;

  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE,
         edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;
--  COMMIT;

  /* --added by Victor Huang on 06/05 for function acknowlegement
  INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
  VALUES(ll_gs_log, ls_su, sysdate, edi_file);
  COMMIT;*/

  --added by Victor Huang on 12/07 for verifying 997
  INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (ll_edi_file_id,
     '039630926',
     ls_su,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856');
  COMMIT;

  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  --exception
  --   when invalid_operation
  --   then
  --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

  --  when others
  --  then
  --      DBMS_OUTPUT.PUT_LINE ('System Error');
  --      UTL_FILE.FCLOSE(edi_file_handle);

  RETURN 1;
END edi_novelis_856_X12;
--------------------------------------------------------
--  DDL for Function EDI_NOVELIS_856_X12_01142020
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_NOVELIS_856_X12_01142020" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*
  Aluminum Blanking: Ford Supplier Code: ZZ R0P7A
                     DUNS: 01 039630926T
  Customer: ALCAN(34,35,10,1153)
  Alcan Rolled Product    X.121       0015049350011G
  End User: Ford (ZZ F159B)
            Ford Chicago Stamping Plant(51) MS02A
            Ford Walton Hills Stamping Plant(77) MS03A
            Ford Woodhaven Stamping Plant(71) AF30A MS09A
            Ford Maumee Stamping Plant(78)    AF06A MS08A

            Budd Company (Customer ID: 1096) B821L
            Eagle Steel (1251) MZF6B
            (not in use)Ford Monroe Stamping              AP06A

            (not in use) Warehouses: IDS(41)               R5G3B
            (not in use) Wayne Steel Distribution Center(79) RWSDC

  */

  --v_edi_text_ford varchar2(32767);
  --v_edi_text_alcan varchar2(32767);
  --ll_customer_edi_name VARCHAR2(20);

   --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50);

  --edi_loc varchar2(50):='/tmp';
  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_prefix VARCHAR2(50) := 'S_novelis_856_'; --Production
  --edi_file_prefix VARCHAR2(50) := 's_novelis_856_'; --Development
  edi_file_handle utl_file.file_type;

  li_customer_id    shipment.customer_id%TYPE;
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;

  -- ls_sender_vanid varchar2 (50);
  -- ls_receiver_vanid varchar2 (50);
  -- ls_customer_vanid varchar2(50);
  -- ls_receiver_gs03 varchar2(50);
  -- ls_customer_gs03 varchar2(50);
  --ls_st varchar2(50);
  ls_sf VARCHAR2(50);
  ls_eq_type VARCHAR2(10);  -- Added by Patrick Reynolds 11/30/2016
  ls_su      VARCHAR2(50);
  ls_st_duns VARCHAR2(50);
  ls_po      VARCHAR2(30);
  ls_auth_code   VARCHAR2(32);
  ll_gs_log  INTEGER;
  ll_st_log  INTEGER;
  ll_bsn_log INTEGER;

  ls_today VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD'); --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  ls_today_2digits_year VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD'); --Alex Gerlants. 10/16/2018. Test
  ls_now   VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  li_rowcount INTEGER;
  li_hl01 INTEGER;
  ll_shipment_nt INTEGER;
  ll_shipment_gt INTEGER;
  ll_shipment_pc INTEGER;
  li_td1 INTEGER;
  li_rc  INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_vehicle_id_prefix VARCHAR2(50);  -- Added by Patrick Reynolds 11/30/2016
  ls_scac              carrier.scac%TYPE;
  ls_carrier_full_name VARCHAR2(18);
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_carrier_initial   VARCHAR2(50);  -- Not used in stored procedure.  Discovered by Patrick Reynolds 11/30/2016
  ldt_shipment         DATE;
   ll_temp         INTEGER;
  ls_enduser_part VARCHAR2(50);
  li_des_id       INTEGER;

  ll_edi_file_id INTEGER;

  ls_lot_num VARCHAR2(32);
  ls_coil_id VARCHAR2(32);
  ls_des_cust_name VARCHAR2(18);
  
  ls_coil_org_num		        coil.coil_org_num%TYPE; --Alex Gerlants. 01/25/2019
  ll_coil_gauge		          coil.coil_gauge%TYPE;   --Alex Gerlants. 01/25/2019
  ll_coil_width		          coil.coil_width%TYPE;   --Alex Gerlants. 01/25/2019
  ld_ship_date              date;
  li_is_novelis             integer;
  ln_skid_type_if_whed      sheet_skid.skid_type_if_whed%TYPE;   --Alex Gerlants. 04/01/2019

  CURSOR alcan_ford_856_cur IS
    SELECT sheet_packing_item.sh_packing_item,
           'MULTIPLE' lot_num,
           'MULTIPLE' coil_id,
           customer_order.orig_customer_po,
           customer_order.order_abc_num,
           customer_order.enduser_po,
           customer_order.created_date,
           order_item.order_item_num,
           order_item.enduser_part_num,
           order_item.supplier_code,
           order_item.gauge,
           sheet_skid. ab_job_num,
           sheet_skid.sheet_skid_num,
           sheet_skid.sheet_skid_display_num, --added by Victor H. on 06-2012 for Novelis locatio code request
           sheet_skid.sheet_net_wt,
           sheet_skid.sheet_tare_wt,
           sheet_skid. skid_pieces,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_theoretical_wt,
           NULL done
      FROM customer_order,
           order_item,
           sheet_skid,
           ab_job,
           shipment,
           sheet_packing_item
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
/*      
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
  --      (SHIPMENT.SHIPMENT_EDI856_DATE is NULL);
*/
  --TYPE skidinfo_tabletype IS TABLE OF alcan_ford_856_cur%ROWTYPE INDEX BY BINARY_INTEGER;
  --skidinfo_table skidinfo_tabletype;
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table    store_tabletype;
  i            BINARY_INTEGER := 0;
  skidinfo_rec alcan_ford_856_cur%ROWTYPE;

  /*CURSOR packing_list_same_bol IS
  SELECT packing_list
    FROM shipment
   WHERE bill_of_lading = ll_bill_of_lading;*/

  CURSOR c_ship_to IS
    SELECT DISTINCT des_sh_cust_id --, PACKING_LIST
      FROM shipment
     WHERE bill_of_lading = ll_bill_of_lading
       AND shipment.shipment_status = 0;
  --ORDER BY PACKING_LIST;
  
  cursor c_coil is
  select distinct 
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num,
         coil.coil_gauge,
         coil.coil_width
         --process_coil.coil_abc_num
         --outbound_edi_transaction.transaction_time,
         --outbound_edi_transaction.edi_file_name
  from   customer_order
         join order_item on order_item.order_abc_num = customer_order.order_abc_num
         join ab_job on ab_job.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
         join sheet_skid on sheet_skid.ab_job_num = ab_job.ab_job_num
         join sheet_packing_item on sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
         join shipment on shipment.packing_list = sheet_packing_item.packing_list
         join process_coil on process_coil.ab_job_num = ab_job.ab_job_num
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         --join outbound_edi_transaction on outbound_edi_transaction.edi_file_id = shipment.edi_file_id_856
  --where  shipment.packing_list = 105586 --Production
  where  shipment.packing_list = al_packing_list --Develpment
  order by
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num;

BEGIN
  
  select f_is_novelis(al_packing_list)
  into   li_is_novelis
  from   dual;
  
  if li_is_novelis = 0 then --Customer is NOT Novelis
    return 1; --Nothing to do here
  end if;
  
  select shipment_edi856_date
  into   ld_ship_date
  from   shipment
  where  shipment.packing_list = al_packing_list;
   
  if not (ld_ship_date is null) then --ASN already sent
    return 100;
  end if;

  edi_loc := dbo.get_edi_destination('EDI_DIR'); --Alex Gerlants. 11/15/2016

  -- edi_alcan_870; -- Send 870 first

  -- Get Customer ID, End user ID
  --SELECT customer_id, des_sh_cust_id
  --  INTO li_customer_id, li_des_sh_cust_id
  -- FROM shipment
  -- WHERE shipment.packing_list = al_packing_list;
  --IF NOT SQL%FOUND THEN
 --   RETURN - 1;
  --END IF;

  -- Get Customer ID, End user ID, authorization code
  SELECT customer_id, des_sh_cust_id, nvl(shipment_athorization_code, 'NA')
    INTO li_customer_id, li_des_sh_cust_id, ls_auth_code
  FROM shipment
  WHERE shipment.packing_list = al_packing_list;
  IF NOT SQL%FOUND THEN
   RETURN - 1;
  END IF;

  -- dbms_output.put_line (to_char(li_customer_id) || '  ' || to_char(li_des_sh_cust_id) );

  IF NOT (li_customer_id IN (34, 35, 10, 1153, 1459, 2582)) -- AND (li_des_sh_cust_id IN (
  --10,41,51,69,70,71,72,77,78,79,1055,1062,1073,1086,1096,1099,1114,1112,1153,
  --1206,1251,1253,1268,1269,1270,1322,1325,1328,1331,1332,1346,1347, 1382, 1383)))
   THEN

    --***********************************************************************************************88
    --IF NOT ((li_customer_id IN (34,35,10,1153)) AND (li_des_sh_cust_id IN (SELECT CUSTOMER_ID
    --FROM CUSTOMER
    --WHERE CUSTOMER_DUNS_NUMBER_STRING is not null))) THEN

    RETURN 200;
  END IF;

  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(sheet_skid.sheet_net_wt),
         SUM(sheet_skid.sheet_net_wt) + SUM(sheet_skid.sheet_tare_wt),
         SUM(sheet_skid.skid_pieces)
    INTO ll_shipment_nt, ll_shipment_gt, ll_shipment_pc
    FROM sheet_skid, sheet_packing_item, shipment
   WHERE shipment.packing_list = sheet_packing_item.packing_list
     AND sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
     AND shipment.packing_list = al_packing_list;
  IF ll_shipment_pc = 0 THEN
    RETURN 100;
  END IF; -- empty shipment

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  -- Retrieve ABCO info
  -- ls_sender_vanid := '3010007080';
  --ls_ic := 'R0P7A';

  -- Retrieve ALCAN supply code and Ford Stamping Plant location code
  --SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf
  --FROM customer_customer  WHERE o_customer_id = li_customer_id and e_customer_id = 49;  --Ford customer_id =49

  ls_sf := '039630926';
  --SELECT NVL(communication_code,'UNKNOWN') INTO ls_st FROM customer_system
  --WHERE customer_id = li_des_sh_cust_id;

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.vehicle_id_prefix, '9999'),
         nvl(shipment.equipment_type, 'NA'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'PT'), -- Protected Trailer
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE)
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_vehicle_id_prefix,
         ls_eq_type,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_carrier_initial,
         ldt_shipment
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;

  --Check all packing_lists are done against a BOL
  /*
  for pl_rec in packing_list_same_bol loop
      select shipment.shipment_status into ll_temp from shipment
             where shipment.packing_list = pl_rec.packing_list;
      if ll_temp > 0 then
         return pl_rec.packing_list;
      end if;

  end loop;
  */
  --End of packing list checking

  SELECT nvl(customer_duns_number_string, '00000000'), customer_short_name
    INTO ls_st_duns, ls_des_cust_name
    FROM customer
   WHERE customer_id = li_des_sh_cust_id;

  IF (ls_st_duns = '00000000') THEN
    RETURN 200;
  END IF; --No Ship to DUNS

  SELECT nvl(customer_duns_number_string, '00000000')
    INTO ls_su
    FROM customer
   WHERE customer_id = li_customer_id;
  IF (ls_su = '00000000') THEN
    RETURN 200;
  END IF; --No Supplier DUNS

  -- Get SCAC(Standard Carrier Alpha Code)
  SELECT nvl(carrier.scac, 'NONE'), LPAD(carrier.carrier_full_name, 17)
    INTO ls_scac, ls_carrier_full_name
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);

  -- Get Receiver and Customer VAN ID
  -- SELECT NVL(customer_system.van_account_num, 'nothing'), NVL(customer_system.gs03, 'nothing')
  -- INTO ls_receiver_vanid, ls_receiver_gs03    -- ls_receiver_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --   (select shipment.des_sh_cust_id  from shipment  where shipment.packing_list = al_packing_list);

  -- SELECT NVL(customer_system.van_account_num, 'nothing'),NVL(customer_system.gs03, 'nothing')
  -- INTO   ls_customer_vanid, ls_customer_gs03   -- ls_customer_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --       (select shipment.customer_id from shipment where shipment.packing_list = al_packing_list);

  -- Generate Header Info.
  --x12_table(i) := 'ISA*00*'||'          *00*          *ZZ*R0P7A          *ZZ*F159B          *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0') ||'*0*P**';
  --x12_table(i) := 'GS*SH*R0P7A*'||ls_st || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  --Alex Gerlants. 10/16/2018. Changed from "00200" to "00401"
  --Production
  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *01*039630926T     *09*0015049350011G *' ||
                  ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
  
  --Development                
  --x12_table(i) := 'ISA*00*' ||
  --                '          *00*          *ZZ*2NDSFTP        *ZZ*NOVLSTEST      *' ||
  --                ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
  --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';
                  
  i := i + 1;

  --Alex Gerlants. 10/16/2018. Changed from "002002" to "004010"
  --Production
  x12_table(1) := 'GS*SH*R0P7A*' || '001504935001' || '*' || ls_today || '*' ||
                  ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  --Development
  --x12_table(1) := 'GS*SH*2NDSFTP*' || 'NOVLSTEST' || '*' || ls_today || '*' ||
  --               ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;
  --x12_table(i):= 'BSN*00*' || to_char(ll_bill_of_lading) || '*' || ls_today || '*' || ls_now;
  x12_table(i) := 'BSN*00*' || to_char(al_packing_list) || '*' || ls_today || '*' ||
                  ls_now;
  i := i + 1;
  
  --Alex Gerlants. 08/07/2018.
  --Changed to populate with actual ship date instead of current date and time.
  --The reason is that when we send 856 on a later date, this date is not correct.
  --x12_table(i) := 'DTM*011*' || ls_today || '*' || ls_now;
  --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                                                      to_char(ldt_shipment, 'HH24MI');
  i := i + 1;
  
  --Alex Gerlants. 10/18/2018. Changed from "YYMMDD" to "YYYYMMDD"
  --Moved here from the below
  x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                  to_char(ldt_shipment, 'HH24MI');
  i := i + 1;

  -- First Level HL
  x12_table(i) := 'HL*01**S';
  i := i + 1;
  --Alex Gerlants. 10/16/2018. Changed from "MEA*PD*G*" to "MEA*WT*G*"
  x12_table(i) := 'MEA*WT*G*' || to_char(ll_shipment_gt) || '*LB';
  i := i + 1;
  x12_table(i) := 'MEA*WT*N*' || to_char(ll_shipment_nt) || '*LB';
  i := i + 1;
  x12_table(i) := 'TD1*PLT90*' || to_char(li_rowcount);
  li_td1 := i;
  i := i + 1;
  x12_table(i) := 'TD5*B*2*' || ls_scac || '*M*' || ls_carrier_full_name;
  i := i + 1;
  -- segment was modified to include trailer number.  Patrick Reynolds 11/30/2016
  x12_table(i) := 'TD3*' || ls_carrier_desc_code || '*' || ls_scac || '*' || ls_vehicle_id_prefix;
  i := i + 1;
  x12_table(i) := 'REF*BM*' || to_char(al_packing_list);
  i := i + 1;
  x12_table(i) := 'REF*PK*' || to_char(al_packing_list);
  i := i + 1;
  -- segment was modified to include equipment type.  Patrick Reynolds 11/30/2016
  x12_table(i) := 'REF*EQ*' || ls_eq_type;
  i := i + 1; --waiting for Novilis, ----tony
  --- Testing for multi order ASN ----Tony

  x12_table(i) := 'REF*MB*' || to_char(ll_bill_of_lading);
  i := i + 1;
  SELECT COUNT(*)
    INTO ll_temp
    FROM shipment
   WHERE shipment.bill_of_lading = ll_bill_of_lading
     AND shipment.shipment_status = 0;
     
  --Alex Gerlants. 10/16/2018. Removed 2 lines below
  --x12_table(i) := 'REF*SS*' || to_char(ll_temp);
  --i := i + 1;
  li_des_id := 1;
  
  --Alex Gerlants. 10/16/2018. Removed 7 lines below
  /*
  FOR c_stop IN c_ship_to LOOP
    IF li_des_sh_cust_id = c_stop.des_sh_cust_id THEN
      x12_table(i) := 'REF*QN*' || to_char(li_des_id);
      i := i + 1;
    END IF;
    li_des_id := li_des_id + 1;
  END LOOP;
  */

  /*
  IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
     x12_table(i):= 'REF*ZZ*' || ls_st;i:=i+1;
  end if;
  */

  ----Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  --x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
  --                to_char(ldt_shipment, 'HH24MI');
  --i := i + 1;
  
  x12_table(i) := 'N1*ST*' || ls_des_cust_name || '*1*' || ls_st_duns;
  i := i + 1;
  x12_table(i) := 'N1*SF*Aluminum Blanking Co*1*' || ls_sf;
  i := i + 1;
  x12_table(i) := 'N1*SU**1*' || ls_su;
  i := i + 1;

  --if not (li_des_sh_cust_id = 1096 or li_des_sh_cust_id = 1251) then
  --         x12_table(i):= 'N1*IC**92*' || ls_ic; i := i +1;        --- Deleted 04-30-03 by Tony according to alcan Julia's email
  --end if;

  --         x12_table(i):= 'N1*CN**92*' || ls_st_duns; i := i +1; --Ship to DUNs --- Deleted 04-30-03 by Tony according to alcan Julia's email

  -- Second Level HL based on End User PO( only one part# is included in one shipement per FORD's request)
  OPEN alcan_ford_856_cur;
  FETCH alcan_ford_856_cur
    INTO skidinfo_rec;
  --    ls_enduser_part := skidinfo_rec.ENDUSER_PART_NUM;
  --    ls_enduser_po := skidinfo_rec.ENDUSER_PO;

  /*
    if skidinfo_rec.ORIG_CUSTOMER_PO IN ('68Q68517') then    --Do NOT send 856 to Ford for some flipping related POs )
         edi_file_prefix := 'nosend_alcan_ford_ford';
    end if;
  */

  SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
    INTO ls_enduser_part
    FROM "ORDER_ITEM", "SHEET_SKID"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
     AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
     AND ("SHEET_SKID"."SHEET_SKID_NUM" = skidinfo_rec.sheet_skid_num);

  /*
      SELECT "CUSTOMER_ORDER"."ENDUSER_PO" into ls_enduser_po
             FROM "SHEET_SKID",
                  "CUSTOMER_ORDER"
                  WHERE ( "SHEET_SKID"."REF_ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM" ) and
                        (SHEET_SKID.SHEET_SKID_NUM = skidinfo_rec.SHEET_SKID_NUM);
  */

  x12_table(i) := 'HL*02*01*O';
  i := i + 1;
  IF ls_enduser_part IS NULL THEN
    ls_enduser_part := 'NA';
  END IF;
  x12_table(i) := 'LIN**BP*' || ls_enduser_part;
  i := i + 1;
  x12_table(i) := 'SN1**' || to_char(ll_shipment_pc) || '*EA*0';
  i := i + 1;

  --
  --ls_po := skidinfo_rec.ORIG_CUSTOMER_PO;
  SELECT "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO"
    INTO ls_po
    FROM "SHEET_SKID", "CUSTOMER_ORDER"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
         "CUSTOMER_ORDER"."ORDER_ABC_NUM")
     AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num);

  --IF INSTR(skidinfo_rec.ORIG_CUSTOMER_PO,'-') > 0
  --New PO format for Novelis SAP include '-'
  /*IF instr(ls_po, '-') > 0 THEN
    ls_po := substr(ls_po, 0, instr(ls_po, '-') - 1);
  END IF;*/

  --   IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
  x12_table(i) := 'PRF*' || ls_po || '***' ||
                  to_char(skidinfo_rec.created_date, 'YYYYMMDD');
  i := i + 1;
  --   end if;

  CLOSE alcan_ford_856_cur;

   --  Novelis SAP order number
 x12_table(i) := 'REF*IL*' || ls_auth_code;
 i := i + 1;
  --  end if;

  -- Third Level HL Under a P.O.
  li_hl01 := 3;

  --Skid loop begin ----------------------------------------------------------------
  FOR skidinfo_rec IN alcan_ford_856_cur LOOP
    
      --In case of a split skid, we are creating just 1 HL for this skid
      --with just 1 coil for this skid.
      select distinct 
             coil.coil_org_num,
             coil.coil_gauge,
             coil.coil_width,
             coil.lot_num,
             nvl(skid_type_if_whed, -1) --Alex Gerlants. 04/01/2019
      into   ls_coil_org_num,
             ll_coil_gauge,
             ll_coil_width,
             ls_lot_num,
             ln_skid_type_if_whed --Alex Gerlants. 04/01/2019
      FROM "COIL",   
           "PRODUCTION_SHEET_ITEM",   
           "SHEET_SKID",   
           "SHEET_SKID_DETAIL",   
           "PROCESS_COIL"  
     WHERE ( "COIL"."COIL_ABC_NUM" = "PRODUCTION_SHEET_ITEM"."COIL_ABC_NUM" ) and  
           ( "SHEET_SKID_DETAIL"."SHEET_SKID_NUM" = "SHEET_SKID"."SHEET_SKID_NUM" ) and  
           ( "SHEET_SKID_DETAIL"."PROD_ITEM_NUM" = "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NUM" ) and  
           ( "COIL"."COIL_ABC_NUM" = "PROCESS_COIL"."COIL_ABC_NUM" ) and  
           ( "PRODUCTION_SHEET_ITEM"."AB_JOB_NUM" = "PROCESS_COIL"."AB_JOB_NUM" ) and  
           ( (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num)  ) and
           ( (rownum = 1)  ); --We need just 1 coil for each skid
  
      --Alex Gerlants. 04/01/2019. Begin
      if ln_skid_type_if_whed > -1 then --Warehouse skid
          --Get gauge and part width
          select distinct order_item.gauge,
                 f_get_part_width_per_job(ab_job.ab_job_num) 
          into   ll_coil_gauge,
                 ll_coil_width
          from   sheet_skid
                 join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
                 join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
                 join customer_order on customer_order.order_abc_num = order_item.order_abc_num
          where  sheet_skid_num = skidinfo_rec.sheet_skid_num
          and    (order_item.gauge is not null and f_get_part_width_per_job(sheet_skid.ab_job_num) is not null)
          and    rownum = 1;
      end if;
      --Alex Gerlants. 04/01/2019. End
  
      IF length(to_char(li_hl01)) = 1 THEN
        x12_table(i) := 'HL*0' || to_char(li_hl01) || '*02*I';
        i := i + 1;
      ELSE
        x12_table(i) := 'HL*' || to_char(li_hl01) || '*02*I';
        i := i + 1;
      END IF;

      --    IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
      --       x12_table(i) := 'SN1**'||to_char(skidinfo_rec.skid_pieces)||'*EA';i:=i+1;
      --    else
      x12_table(i) := 'SN1**1*PF';
      i := i + 1;
      --    end if;

      --if li_des_sh_cust_id = 1096 -- To Budd or li_des_sh_cust_id = 1251 then
      --   then
      --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; i := i +1;
      --      x12_table(i) :=  'MEA*PD*TH*' || to_char(skidinfo_rec.sheet_net_wt) || '*24'; i := i +1;
      --elsif   li_des_sh_cust_id = 1251   --To Eagle Steel
      --  then
      --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; i := i +1;
      --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*24'; i := i +1;
      --      x12_table(i) :=  'MEA*PD*TH*' || to_char(skidinfo_rec.gauge) || '*EM'; i:=i+1;
      --    x12_table(i) :=  'MEA*PD*WD*'||'44.875'||'*IN'; i:=i+1;
      --    x12_table(i) :=  'MEA*PD*LN*'||to_char(skidinfo_rec.skid_pieces)||'*LF';  i:=i+1;
      --else  --All else, Ford dirct shiping program
                        
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*N" to "MEA*WT*N"
      x12_table(i) := 'MEA*WT*N*' || to_char(skidinfo_rec.sheet_net_wt) ||
                      '*01';
      i := i + 1;
                        
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*WT" to "MEA*CT*NL"
      x12_table(i) := 'MEA*CT*NL*' || to_char(skidinfo_rec.skid_pieces) ||
                      '*PC';
      i := i + 1;

      -- changed to all gross wt per novelis 1/30/2015
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*G" to "MEA*WT*G"
      x12_table(i) := 'MEA*WT*G*' || to_char(skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt) || '*01';
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      x12_table(i) := 'MEA*PD*GG*' || ll_coil_gauge;
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      x12_table(i) := 'MEA*PD*WD*' || ll_coil_width;
      i := i + 1;

      /*
      IF (skidinfo_rec.sheet_theoretical_wt IS NULL) OR
         (skidinfo_rec.sheet_theoretical_wt = 0) THEN
        x12_table(i) := 'MEA*PD*G*' || to_char(ll_shipment_gt) || '*01';
        i := i + 1;
      ELSE
        x12_table(i) := 'MEA*PD*G*' ||
                        to_char(skidinfo_rec.sheet_theoretical_wt) || '*01';
        i := i + 1;
      END IF;
      */
      --end if;

      -- fill in lot num
      /*
      SELECT COUNT(*)
        INTO li_rc
        FROM sheet_skid_detail
       WHERE sheet_skid_detail.sheet_skid_num = skidinfo_rec.sheet_skid_num;

      ls_lot_num := skidinfo_rec.lot_num;
      ls_coil_id := skidinfo_rec.coil_id;

      IF li_rc = 1 THEN
        SELECT lot_num, coil_org_num
          INTO ls_lot_num, ls_coil_id
          FROM coil
         WHERE coil.coil_abc_num =
               (SELECT coil_abc_num
                  FROM production_sheet_item
                 WHERE production_sheet_item.prod_item_num =
                       (SELECT prod_item_num
                          FROM sheet_skid_detail
                         WHERE sheet_skid_detail.sheet_skid_num =
                               skidinfo_rec.sheet_skid_num));
      END IF;
      */
      --if li_des_sh_cust_id = 1251   --Eagle need coil ID here instead of lot number
      --then
      --x12_table(i) :=  'REF*HC*' || skidinfo_rec.coil_id ; i := i +1;
      --else
                        
      --Alex Gerlants. 10/18/2018. Changed from "REF*HC" to "REF*BT"
      x12_table(i) := 'REF*BT*' || ls_lot_num;
      i := i + 1;
      --end if;

      --x12_table(i) := 'REF*LS*' || to_char(skidinfo_rec.sheet_skid_num);
      --Alex Gerlants. 10/18/2018. Changed from "REF*LS" to "REF*SE"
      x12_table(i) := 'REF*SE*' || skidinfo_rec.sheet_skid_display_num; --added by Victor H. on 06-2012 for Novelis locatio code request
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      x12_table(i) := 'REF*LS*' || ls_coil_org_num;
      i := i + 1;
      
      li_hl01 := li_hl01 + 1;
      li_rowcount := alcan_ford_856_cur%ROWCOUNT;
      x12_table(li_td1) := 'TD1*PLT90*' || to_char(li_rowcount);
  END LOOP; --End of 'FOR skidinfo_rec IN alcan_ford_856_cur LOOP'
  --Skid loop end ------------------------------------------------------------------

  -- DBMS_OUTPUT.PUT_LINE ('rowcount' || to_char(li_rowcount));

  -- if li_des_sh_cust_id = 1096 or li_des_sh_cust_id = 1251 then
  --   x12_table(i) :=  'CTT*' || to_char(li_HL01 - 1) ||'*' || to_char(ll_shipment_pc*2) ;
  --   i := i +1;
  -- else
  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                  to_char(li_rowcount + ll_shipment_pc);
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  -- Write X.12 to file
  -- To FORD

  /** Write file to /templar/templar/incoming/senddata
  /*
  **/

  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  --edi_file:= 'S_alcan_ford_ford_' || to_char(ll_edi_file_id) ||'.x12';

  -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
  -- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
    --        v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
  END LOOP;
  utl_file.fclose(edi_file_handle);

  --To ALCAN

  /*
  SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;
  SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id_alcan FROM DUAL;
  edi_file:= 'S_alcan_ford_alcan_' || to_char(ll_edi_file_id_alcan) ||'.x12';
  edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');
  x12_table(0) := 'ISA*00*'||'          *00*          *01*039630926T     *09*0015049350011G *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0')||'*0*P**';
  x12_table(1) := 'GS*SH*R0P7A*'||'001504935001' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  x12_table(i-1) :=  'GE*1*' || to_char (ll_gs_log);
  x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');
  for j in 0..i loop
   UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
       v_edi_text_alcan:=v_edi_text_alcan||x12_table(j)||CHR(10);
  end loop;
  UTL_FILE.FCLOSE(edi_file_handle);

  */

  /* The following code added by Tony, for update archive*/

  --  INSERT INTO edi_log (edi_log_timestamp,customer_id,
  --         customer_edi_name,edi_log_contents,edi_file_id,edi_text)
  --    VALUES (SYSDATE,li_customer_id,ll_customer_edi_name,
  --           'EDI:'||ll_customer_edi_name||' generated successfully.',ll_edi_file_id,v_edi_text);
  --   COMMIT;

  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE,
         edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;
--  COMMIT;

  /* --added by Victor Huang on 06/05 for function acknowlegement
  INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
  VALUES(ll_gs_log, ls_su, sysdate, edi_file);
  COMMIT;*/

  --added by Victor Huang on 12/07 for verifying 997
  INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (ll_edi_file_id,
     '039630926',
     ls_su,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856');
  COMMIT;

  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  --exception
  --   when invalid_operation
  --   then
  --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

  --  when others
  --  then
  --      DBMS_OUTPUT.PUT_LINE ('System Error');
  --      UTL_FILE.FCLOSE(edi_file_handle);

  RETURN 1;
END edi_novelis_856_X12_01142020;
--------------------------------------------------------
--  DDL for Function EDI_NOVELIS_856_X12_01212020
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_NOVELIS_856_X12_01212020" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*
  Aluminum Blanking: Ford Supplier Code: ZZ R0P7A
                     DUNS: 01 039630926T
  Customer: ALCAN(34,35,10,1153)
  Alcan Rolled Product    X.121       0015049350011G
  End User: Ford (ZZ F159B)
            Ford Chicago Stamping Plant(51) MS02A
            Ford Walton Hills Stamping Plant(77) MS03A
            Ford Woodhaven Stamping Plant(71) AF30A MS09A
            Ford Maumee Stamping Plant(78)    AF06A MS08A

            Budd Company (Customer ID: 1096) B821L
            Eagle Steel (1251) MZF6B
            (not in use)Ford Monroe Stamping              AP06A

            (not in use) Warehouses: IDS(41)               R5G3B
            (not in use) Wayne Steel Distribution Center(79) RWSDC

  */

  --v_edi_text_ford varchar2(32767);
  --v_edi_text_alcan varchar2(32767);
  --ll_customer_edi_name VARCHAR2(20);

   --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50);

  --edi_loc varchar2(50):='/tmp';
  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_prefix VARCHAR2(50) := 'S_novelis_856_'; --Production
  --edi_file_prefix VARCHAR2(50) := 's_novelis_856_'; --Development
  edi_file_handle utl_file.file_type;

  li_customer_id    shipment.customer_id%TYPE;
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;

  -- ls_sender_vanid varchar2 (50);
  -- ls_receiver_vanid varchar2 (50);
  -- ls_customer_vanid varchar2(50);
  -- ls_receiver_gs03 varchar2(50);
  -- ls_customer_gs03 varchar2(50);
  --ls_st varchar2(50);
  ls_sf VARCHAR2(50);
  ls_eq_type VARCHAR2(10);  -- Added by Patrick Reynolds 11/30/2016
  ls_su      VARCHAR2(50);
  ls_st_duns VARCHAR2(50);
  ls_po      VARCHAR2(30);
  ls_auth_code   VARCHAR2(32);
  ll_gs_log  INTEGER;
  ll_st_log  INTEGER;
  ll_bsn_log INTEGER;

  ls_today VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD'); --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  ls_today_2digits_year VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD'); --Alex Gerlants. 10/16/2018. Test
  ls_now   VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  li_rowcount INTEGER;
  li_hl01 INTEGER;
  ll_shipment_nt INTEGER;
  ll_shipment_gt INTEGER;
  ll_shipment_pc INTEGER;
  li_td1 INTEGER;
  li_rc  INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_vehicle_id_prefix VARCHAR2(50);  -- Added by Patrick Reynolds 11/30/2016
  ls_scac              carrier.scac%TYPE;
  ls_carrier_full_name VARCHAR2(18);
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_carrier_initial   VARCHAR2(50);  -- Not used in stored procedure.  Discovered by Patrick Reynolds 11/30/2016
  ldt_shipment         DATE;
   ll_temp         INTEGER;
  ls_enduser_part VARCHAR2(50);
  li_des_id       INTEGER;

  ll_edi_file_id INTEGER;

  ls_lot_num VARCHAR2(32);
  ls_coil_id VARCHAR2(32);
  ls_des_cust_name VARCHAR2(18);
  
  ls_coil_org_num		        coil.coil_org_num%TYPE; --Alex Gerlants. 01/25/2019
  ll_coil_gauge		          coil.coil_gauge%TYPE;   --Alex Gerlants. 01/25/2019
  ll_coil_width		          coil.coil_width%TYPE;   --Alex Gerlants. 01/25/2019
  ld_ship_date              date;
  li_is_novelis             integer;
  ln_skid_type_if_whed      sheet_skid.skid_type_if_whed%TYPE;   --Alex Gerlants. 04/01/2019

  CURSOR alcan_ford_856_cur IS
    SELECT sheet_packing_item.sh_packing_item,
           'MULTIPLE' lot_num,
           'MULTIPLE' coil_id,
           customer_order.orig_customer_po,
           customer_order.order_abc_num,
           customer_order.enduser_po,
           customer_order.created_date,
           order_item.order_item_num,
           order_item.enduser_part_num,
           order_item.supplier_code,
           order_item.gauge,
           sheet_skid. ab_job_num,
           sheet_skid.sheet_skid_num,
           sheet_skid.sheet_skid_display_num, --added by Victor H. on 06-2012 for Novelis locatio code request
           sheet_skid.sheet_net_wt,
           sheet_skid.sheet_tare_wt,
           sheet_skid. skid_pieces,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_theoretical_wt,
           NULL done
      FROM customer_order,
           order_item,
           sheet_skid,
           ab_job,
           shipment,
           sheet_packing_item
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
/*      
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
  --      (SHIPMENT.SHIPMENT_EDI856_DATE is NULL);
*/
  --TYPE skidinfo_tabletype IS TABLE OF alcan_ford_856_cur%ROWTYPE INDEX BY BINARY_INTEGER;
  --skidinfo_table skidinfo_tabletype;
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table    store_tabletype;
  i            BINARY_INTEGER := 0;
  skidinfo_rec alcan_ford_856_cur%ROWTYPE;

  /*CURSOR packing_list_same_bol IS
  SELECT packing_list
    FROM shipment
   WHERE bill_of_lading = ll_bill_of_lading;*/

  CURSOR c_ship_to IS
    SELECT DISTINCT des_sh_cust_id --, PACKING_LIST
      FROM shipment
     WHERE bill_of_lading = ll_bill_of_lading
       AND shipment.shipment_status = 0;
  --ORDER BY PACKING_LIST;
  
  cursor c_coil is
  select distinct 
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num,
         coil.coil_gauge,
         coil.coil_width
         --process_coil.coil_abc_num
         --outbound_edi_transaction.transaction_time,
         --outbound_edi_transaction.edi_file_name
  from   customer_order
         join order_item on order_item.order_abc_num = customer_order.order_abc_num
         join ab_job on ab_job.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
         join sheet_skid on sheet_skid.ab_job_num = ab_job.ab_job_num
         join sheet_packing_item on sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
         join shipment on shipment.packing_list = sheet_packing_item.packing_list
         join process_coil on process_coil.ab_job_num = ab_job.ab_job_num
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         --join outbound_edi_transaction on outbound_edi_transaction.edi_file_id = shipment.edi_file_id_856
  --where  shipment.packing_list = 105586 --Production
  where  shipment.packing_list = al_packing_list --Develpment
  order by
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num;

BEGIN
  
  select f_is_novelis(al_packing_list)
  into   li_is_novelis
  from   dual;
  
  if li_is_novelis = 0 then --Customer is NOT Novelis
    return 1; --Nothing to do here
  end if;
  
  select shipment_edi856_date
  into   ld_ship_date
  from   shipment
  where  shipment.packing_list = al_packing_list;
   
  if not (ld_ship_date is null) then --ASN already sent
    return 100;
  end if;

  edi_loc := dbo.get_edi_destination('EDI_DIR'); --Alex Gerlants. 11/15/2016

  -- edi_alcan_870; -- Send 870 first

  -- Get Customer ID, End user ID
  --SELECT customer_id, des_sh_cust_id
  --  INTO li_customer_id, li_des_sh_cust_id
  -- FROM shipment
  -- WHERE shipment.packing_list = al_packing_list;
  --IF NOT SQL%FOUND THEN
 --   RETURN - 1;
  --END IF;

  -- Get Customer ID, End user ID, authorization code
  SELECT customer_id, des_sh_cust_id, nvl(shipment_athorization_code, 'NA')
    INTO li_customer_id, li_des_sh_cust_id, ls_auth_code
  FROM shipment
  WHERE shipment.packing_list = al_packing_list;
  IF NOT SQL%FOUND THEN
   RETURN - 1;
  END IF;

  -- dbms_output.put_line (to_char(li_customer_id) || '  ' || to_char(li_des_sh_cust_id) );

  IF NOT (li_customer_id IN (34, 35, 10, 1153, 1459, 2582)) -- AND (li_des_sh_cust_id IN (
  --10,41,51,69,70,71,72,77,78,79,1055,1062,1073,1086,1096,1099,1114,1112,1153,
  --1206,1251,1253,1268,1269,1270,1322,1325,1328,1331,1332,1346,1347, 1382, 1383)))
   THEN

    --***********************************************************************************************88
    --IF NOT ((li_customer_id IN (34,35,10,1153)) AND (li_des_sh_cust_id IN (SELECT CUSTOMER_ID
    --FROM CUSTOMER
    --WHERE CUSTOMER_DUNS_NUMBER_STRING is not null))) THEN

    RETURN 200;
  END IF;

  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(sheet_skid.sheet_net_wt),
         SUM(sheet_skid.sheet_net_wt) + SUM(sheet_skid.sheet_tare_wt),
         SUM(sheet_skid.skid_pieces)
    INTO ll_shipment_nt, ll_shipment_gt, ll_shipment_pc
    FROM sheet_skid, sheet_packing_item, shipment
   WHERE shipment.packing_list = sheet_packing_item.packing_list
     AND sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
     AND shipment.packing_list = al_packing_list;
  IF ll_shipment_pc = 0 THEN
    RETURN 100;
  END IF; -- empty shipment

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  -- Retrieve ABCO info
  -- ls_sender_vanid := '3010007080';
  --ls_ic := 'R0P7A';

  -- Retrieve ALCAN supply code and Ford Stamping Plant location code
  --SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf
  --FROM customer_customer  WHERE o_customer_id = li_customer_id and e_customer_id = 49;  --Ford customer_id =49

  ls_sf := '039630926';
  --SELECT NVL(communication_code,'UNKNOWN') INTO ls_st FROM customer_system
  --WHERE customer_id = li_des_sh_cust_id;

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.vehicle_id_prefix, '9999'),
         nvl(shipment.equipment_type, 'NA'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'PT'), -- Protected Trailer
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE)
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_vehicle_id_prefix,
         ls_eq_type,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_carrier_initial,
         ldt_shipment
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;

  --Check all packing_lists are done against a BOL
  /*
  for pl_rec in packing_list_same_bol loop
      select shipment.shipment_status into ll_temp from shipment
             where shipment.packing_list = pl_rec.packing_list;
      if ll_temp > 0 then
         return pl_rec.packing_list;
      end if;

  end loop;
  */
  --End of packing list checking

  SELECT nvl(customer_duns_number_string, '00000000'), customer_short_name
    INTO ls_st_duns, ls_des_cust_name
    FROM customer
   WHERE customer_id = li_des_sh_cust_id;

  IF (ls_st_duns = '00000000') THEN
    RETURN 200;
  END IF; --No Ship to DUNS

  SELECT nvl(customer_duns_number_string, '00000000')
    INTO ls_su
    FROM customer
   WHERE customer_id = li_customer_id;
  IF (ls_su = '00000000') THEN
    RETURN 200;
  END IF; --No Supplier DUNS

  -- Get SCAC(Standard Carrier Alpha Code)
  SELECT nvl(carrier.scac, 'NONE'), LPAD(carrier.carrier_full_name, 17)
    INTO ls_scac, ls_carrier_full_name
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);

  -- Get Receiver and Customer VAN ID
  -- SELECT NVL(customer_system.van_account_num, 'nothing'), NVL(customer_system.gs03, 'nothing')
  -- INTO ls_receiver_vanid, ls_receiver_gs03    -- ls_receiver_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --   (select shipment.des_sh_cust_id  from shipment  where shipment.packing_list = al_packing_list);

  -- SELECT NVL(customer_system.van_account_num, 'nothing'),NVL(customer_system.gs03, 'nothing')
  -- INTO   ls_customer_vanid, ls_customer_gs03   -- ls_customer_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --       (select shipment.customer_id from shipment where shipment.packing_list = al_packing_list);

  -- Generate Header Info.
  --x12_table(i) := 'ISA*00*'||'          *00*          *ZZ*R0P7A          *ZZ*F159B          *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0') ||'*0*P**';
  --x12_table(i) := 'GS*SH*R0P7A*'||ls_st || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  --Alex Gerlants. 10/16/2018. Changed from "00200" to "00401"
  --Production
  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *01*039630926T     *09*0015049350011G *' ||
                  ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
  
  --Development                
  --x12_table(i) := 'ISA*00*' ||
  --                '          *00*          *ZZ*2NDSFTP        *ZZ*NOVLSTEST      *' ||
  --                ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
  --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';
                  
  i := i + 1;

  --Alex Gerlants. 10/16/2018. Changed from "002002" to "004010"
  --Production
  x12_table(1) := 'GS*SH*R0P7A*' || '001504935001' || '*' || ls_today || '*' ||
                  ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  --Development
  --x12_table(1) := 'GS*SH*2NDSFTP*' || 'NOVLSTEST' || '*' || ls_today || '*' ||
  --               ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;
  --x12_table(i):= 'BSN*00*' || to_char(ll_bill_of_lading) || '*' || ls_today || '*' || ls_now;
  x12_table(i) := 'BSN*00*' || to_char(al_packing_list) || '*' || ls_today || '*' ||
                  ls_now;
  i := i + 1;
  
  --Alex Gerlants. 08/07/2018.
  --Changed to populate with actual ship date instead of current date and time.
  --The reason is that when we send 856 on a later date, this date is not correct.
  --x12_table(i) := 'DTM*011*' || ls_today || '*' || ls_now;
  --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                                                      to_char(ldt_shipment, 'HH24MI');
  i := i + 1;
  
  --Alex Gerlants. 10/18/2018. Changed from "YYMMDD" to "YYYYMMDD"
  --Moved here from the below
  x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                  to_char(ldt_shipment, 'HH24MI');
  i := i + 1;

  -- First Level HL
  x12_table(i) := 'HL*01**S';
  i := i + 1;
  --Alex Gerlants. 10/16/2018. Changed from "MEA*PD*G*" to "MEA*WT*G*"
  x12_table(i) := 'MEA*WT*G*' || to_char(ll_shipment_gt) || '*LB';
  i := i + 1;
  x12_table(i) := 'MEA*WT*N*' || to_char(ll_shipment_nt) || '*LB';
  i := i + 1;
  x12_table(i) := 'TD1*PLT90*' || to_char(li_rowcount);
  li_td1 := i;
  i := i + 1;
  x12_table(i) := 'TD5*B*2*' || ls_scac || '*M*' || ls_carrier_full_name;
  i := i + 1;
  -- segment was modified to include trailer number.  Patrick Reynolds 11/30/2016
  x12_table(i) := 'TD3*' || ls_carrier_desc_code || '*' || ls_scac || '*' || ls_vehicle_id_prefix;
  i := i + 1;
  x12_table(i) := 'REF*BM*' || to_char(al_packing_list);
  i := i + 1;
  x12_table(i) := 'REF*PK*' || to_char(al_packing_list);
  i := i + 1;
  -- segment was modified to include equipment type.  Patrick Reynolds 11/30/2016
  x12_table(i) := 'REF*EQ*' || ls_eq_type;
  i := i + 1; --waiting for Novilis, ----tony
  --- Testing for multi order ASN ----Tony

  x12_table(i) := 'REF*MB*' || to_char(ll_bill_of_lading);
  i := i + 1;
  SELECT COUNT(*)
    INTO ll_temp
    FROM shipment
   WHERE shipment.bill_of_lading = ll_bill_of_lading
     AND shipment.shipment_status = 0;
     
  --Alex Gerlants. 10/16/2018. Removed 2 lines below
  --x12_table(i) := 'REF*SS*' || to_char(ll_temp);
  --i := i + 1;
  li_des_id := 1;
  
  --Alex Gerlants. 10/16/2018. Removed 7 lines below
  /*
  FOR c_stop IN c_ship_to LOOP
    IF li_des_sh_cust_id = c_stop.des_sh_cust_id THEN
      x12_table(i) := 'REF*QN*' || to_char(li_des_id);
      i := i + 1;
    END IF;
    li_des_id := li_des_id + 1;
  END LOOP;
  */

  /*
  IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
     x12_table(i):= 'REF*ZZ*' || ls_st;i:=i+1;
  end if;
  */

  ----Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  --x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
  --                to_char(ldt_shipment, 'HH24MI');
  --i := i + 1;
  
  x12_table(i) := 'N1*ST*' || ls_des_cust_name || '*1*' || ls_st_duns;
  i := i + 1;
  x12_table(i) := 'N1*SF*Aluminum Blanking Co*1*' || ls_sf;
  i := i + 1;
  x12_table(i) := 'N1*SU**1*' || ls_su;
  i := i + 1;

  --if not (li_des_sh_cust_id = 1096 or li_des_sh_cust_id = 1251) then
  --         x12_table(i):= 'N1*IC**92*' || ls_ic; i := i +1;        --- Deleted 04-30-03 by Tony according to alcan Julia's email
  --end if;

  --         x12_table(i):= 'N1*CN**92*' || ls_st_duns; i := i +1; --Ship to DUNs --- Deleted 04-30-03 by Tony according to alcan Julia's email

  -- Second Level HL based on End User PO( only one part# is included in one shipement per FORD's request)
  OPEN alcan_ford_856_cur;
  FETCH alcan_ford_856_cur
    INTO skidinfo_rec;
  --    ls_enduser_part := skidinfo_rec.ENDUSER_PART_NUM;
  --    ls_enduser_po := skidinfo_rec.ENDUSER_PO;

  /*
    if skidinfo_rec.ORIG_CUSTOMER_PO IN ('68Q68517') then    --Do NOT send 856 to Ford for some flipping related POs )
         edi_file_prefix := 'nosend_alcan_ford_ford';
    end if;
  */

  SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
    INTO ls_enduser_part
    FROM "ORDER_ITEM", "SHEET_SKID"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
     AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
     AND ("SHEET_SKID"."SHEET_SKID_NUM" = skidinfo_rec.sheet_skid_num);

  /*
      SELECT "CUSTOMER_ORDER"."ENDUSER_PO" into ls_enduser_po
             FROM "SHEET_SKID",
                  "CUSTOMER_ORDER"
                  WHERE ( "SHEET_SKID"."REF_ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM" ) and
                        (SHEET_SKID.SHEET_SKID_NUM = skidinfo_rec.SHEET_SKID_NUM);
  */

  x12_table(i) := 'HL*02*01*O';
  i := i + 1;
  IF ls_enduser_part IS NULL THEN
    ls_enduser_part := 'NA';
  END IF;
  x12_table(i) := 'LIN**BP*' || ls_enduser_part;
  i := i + 1;
  x12_table(i) := 'SN1**' || to_char(ll_shipment_pc) || '*EA*0';
  i := i + 1;

  --
  --ls_po := skidinfo_rec.ORIG_CUSTOMER_PO;
  SELECT "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO"
    INTO ls_po
    FROM "SHEET_SKID", "CUSTOMER_ORDER"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
         "CUSTOMER_ORDER"."ORDER_ABC_NUM")
     AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num);

  --IF INSTR(skidinfo_rec.ORIG_CUSTOMER_PO,'-') > 0
  --New PO format for Novelis SAP include '-'
  /*IF instr(ls_po, '-') > 0 THEN
    ls_po := substr(ls_po, 0, instr(ls_po, '-') - 1);
  END IF;*/

  --   IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
  x12_table(i) := 'PRF*' || ls_po || '***' ||
                  to_char(skidinfo_rec.created_date, 'YYYYMMDD');
  i := i + 1;
  --   end if;

  CLOSE alcan_ford_856_cur;

   --  Novelis SAP order number
 x12_table(i) := 'REF*IL*' || ls_auth_code;
 i := i + 1;
  --  end if;

  -- Third Level HL Under a P.O.
  li_hl01 := 3;

  --Skid loop begin ----------------------------------------------------------------
  FOR skidinfo_rec IN alcan_ford_856_cur LOOP
    
      --In case of a split skid, we are creating just 1 HL for this skid
      --with just 1 coil for this skid.
      select distinct 
             coil.coil_org_num,
             coil.coil_gauge,
             coil.coil_width,
             coil.lot_num,
             nvl(skid_type_if_whed, -1) --Alex Gerlants. 04/01/2019
      into   ls_coil_org_num,
             ll_coil_gauge,
             ll_coil_width,
             ls_lot_num,
             ln_skid_type_if_whed --Alex Gerlants. 04/01/2019
      FROM "COIL",   
           "PRODUCTION_SHEET_ITEM",   
           "SHEET_SKID",   
           "SHEET_SKID_DETAIL",   
           "PROCESS_COIL"  
     WHERE ( "COIL"."COIL_ABC_NUM" = "PRODUCTION_SHEET_ITEM"."COIL_ABC_NUM" ) and  
           ( "SHEET_SKID_DETAIL"."SHEET_SKID_NUM" = "SHEET_SKID"."SHEET_SKID_NUM" ) and  
           ( "SHEET_SKID_DETAIL"."PROD_ITEM_NUM" = "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NUM" ) and  
           ( "COIL"."COIL_ABC_NUM" = "PROCESS_COIL"."COIL_ABC_NUM" ) and  
           ( "PRODUCTION_SHEET_ITEM"."AB_JOB_NUM" = "PROCESS_COIL"."AB_JOB_NUM" ) and  
           ( (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num)  ) and
           ( (rownum = 1)  ); --We need just 1 coil for each skid
  
      --Alex Gerlants. 04/01/2019. Begin
      if ln_skid_type_if_whed > -1 then --Warehouse skid
          --Get gauge and part width
          select distinct order_item.gauge,
                 f_get_part_width_per_job(ab_job.ab_job_num) 
          into   ll_coil_gauge,
                 ll_coil_width
          from   sheet_skid
                 join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
                 join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
                 join customer_order on customer_order.order_abc_num = order_item.order_abc_num
          where  sheet_skid_num = skidinfo_rec.sheet_skid_num
          and    (order_item.gauge is not null and f_get_part_width_per_job(sheet_skid.ab_job_num) is not null)
          and    rownum = 1;
      end if;
      --Alex Gerlants. 04/01/2019. End
  
      IF length(to_char(li_hl01)) = 1 THEN
        x12_table(i) := 'HL*0' || to_char(li_hl01) || '*02*I';
        i := i + 1;
      ELSE
        x12_table(i) := 'HL*' || to_char(li_hl01) || '*02*I';
        i := i + 1;
      END IF;

      --    IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
      --       x12_table(i) := 'SN1**'||to_char(skidinfo_rec.skid_pieces)||'*EA';i:=i+1;
      --    else
      x12_table(i) := 'SN1**1*PF';
      i := i + 1;
      --    end if;

      --if li_des_sh_cust_id = 1096 -- To Budd or li_des_sh_cust_id = 1251 then
      --   then
      --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; i := i +1;
      --      x12_table(i) :=  'MEA*PD*TH*' || to_char(skidinfo_rec.sheet_net_wt) || '*24'; i := i +1;
      --elsif   li_des_sh_cust_id = 1251   --To Eagle Steel
      --  then
      --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; i := i +1;
      --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*24'; i := i +1;
      --      x12_table(i) :=  'MEA*PD*TH*' || to_char(skidinfo_rec.gauge) || '*EM'; i:=i+1;
      --    x12_table(i) :=  'MEA*PD*WD*'||'44.875'||'*IN'; i:=i+1;
      --    x12_table(i) :=  'MEA*PD*LN*'||to_char(skidinfo_rec.skid_pieces)||'*LF';  i:=i+1;
      --else  --All else, Ford dirct shiping program
                        
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*N" to "MEA*WT*N"
      x12_table(i) := 'MEA*WT*N*' || to_char(skidinfo_rec.sheet_net_wt) ||
                      '*01';
      i := i + 1;
                        
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*WT" to "MEA*CT*NL"
      x12_table(i) := 'MEA*CT*NL*' || to_char(skidinfo_rec.skid_pieces) ||
                      '*PC';
      i := i + 1;

      -- changed to all gross wt per novelis 1/30/2015
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*G" to "MEA*WT*G"
      x12_table(i) := 'MEA*WT*G*' || to_char(skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt) || '*01';
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      x12_table(i) := 'MEA*PD*GG*' || ll_coil_gauge;
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      x12_table(i) := 'MEA*PD*WD*' || ll_coil_width;
      i := i + 1;

      /*
      IF (skidinfo_rec.sheet_theoretical_wt IS NULL) OR
         (skidinfo_rec.sheet_theoretical_wt = 0) THEN
        x12_table(i) := 'MEA*PD*G*' || to_char(ll_shipment_gt) || '*01';
        i := i + 1;
      ELSE
        x12_table(i) := 'MEA*PD*G*' ||
                        to_char(skidinfo_rec.sheet_theoretical_wt) || '*01';
        i := i + 1;
      END IF;
      */
      --end if;

      -- fill in lot num
      /*
      SELECT COUNT(*)
        INTO li_rc
        FROM sheet_skid_detail
       WHERE sheet_skid_detail.sheet_skid_num = skidinfo_rec.sheet_skid_num;

      ls_lot_num := skidinfo_rec.lot_num;
      ls_coil_id := skidinfo_rec.coil_id;

      IF li_rc = 1 THEN
        SELECT lot_num, coil_org_num
          INTO ls_lot_num, ls_coil_id
          FROM coil
         WHERE coil.coil_abc_num =
               (SELECT coil_abc_num
                  FROM production_sheet_item
                 WHERE production_sheet_item.prod_item_num =
                       (SELECT prod_item_num
                          FROM sheet_skid_detail
                         WHERE sheet_skid_detail.sheet_skid_num =
                               skidinfo_rec.sheet_skid_num));
      END IF;
      */
      --if li_des_sh_cust_id = 1251   --Eagle need coil ID here instead of lot number
      --then
      --x12_table(i) :=  'REF*HC*' || skidinfo_rec.coil_id ; i := i +1;
      --else
                        
      --Alex Gerlants. 10/18/2018. Changed from "REF*HC" to "REF*BT"
      x12_table(i) := 'REF*BT*' || ls_lot_num;
      i := i + 1;
      --end if;

      --x12_table(i) := 'REF*LS*' || to_char(skidinfo_rec.sheet_skid_num);
      --Alex Gerlants. 10/18/2018. Changed from "REF*LS" to "REF*SE"
      x12_table(i) := 'REF*SE*' || skidinfo_rec.sheet_skid_display_num; --added by Victor H. on 06-2012 for Novelis locatio code request
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      x12_table(i) := 'REF*LS*' || ls_coil_org_num;
      i := i + 1;
      
      li_hl01 := li_hl01 + 1;
      li_rowcount := alcan_ford_856_cur%ROWCOUNT;
      x12_table(li_td1) := 'TD1*PLT90*' || to_char(li_rowcount);
  END LOOP; --End of 'FOR skidinfo_rec IN alcan_ford_856_cur LOOP'
  --Skid loop end ------------------------------------------------------------------

  -- DBMS_OUTPUT.PUT_LINE ('rowcount' || to_char(li_rowcount));

  -- if li_des_sh_cust_id = 1096 or li_des_sh_cust_id = 1251 then
  --   x12_table(i) :=  'CTT*' || to_char(li_HL01 - 1) ||'*' || to_char(ll_shipment_pc*2) ;
  --   i := i +1;
  -- else
  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                  to_char(li_rowcount + ll_shipment_pc);
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  -- Write X.12 to file
  -- To FORD

  /** Write file to /templar/templar/incoming/senddata
  /*
  **/

  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  --edi_file:= 'S_alcan_ford_ford_' || to_char(ll_edi_file_id) ||'.x12';

  -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
  -- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
    --        v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
  END LOOP;
  utl_file.fclose(edi_file_handle);

  --To ALCAN

  /*
  SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;
  SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id_alcan FROM DUAL;
  edi_file:= 'S_alcan_ford_alcan_' || to_char(ll_edi_file_id_alcan) ||'.x12';
  edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');
  x12_table(0) := 'ISA*00*'||'          *00*          *01*039630926T     *09*0015049350011G *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0')||'*0*P**';
  x12_table(1) := 'GS*SH*R0P7A*'||'001504935001' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  x12_table(i-1) :=  'GE*1*' || to_char (ll_gs_log);
  x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');
  for j in 0..i loop
   UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
       v_edi_text_alcan:=v_edi_text_alcan||x12_table(j)||CHR(10);
  end loop;
  UTL_FILE.FCLOSE(edi_file_handle);

  */

  /* The following code added by Tony, for update archive*/

  --  INSERT INTO edi_log (edi_log_timestamp,customer_id,
  --         customer_edi_name,edi_log_contents,edi_file_id,edi_text)
  --    VALUES (SYSDATE,li_customer_id,ll_customer_edi_name,
  --           'EDI:'||ll_customer_edi_name||' generated successfully.',ll_edi_file_id,v_edi_text);
  --   COMMIT;

  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE,
         edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;
--  COMMIT;

  /* --added by Victor Huang on 06/05 for function acknowlegement
  INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
  VALUES(ll_gs_log, ls_su, sysdate, edi_file);
  COMMIT;*/

  --added by Victor Huang on 12/07 for verifying 997
  INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (ll_edi_file_id,
     '039630926',
     ls_su,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856');
  COMMIT;

  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  --exception
  --   when invalid_operation
  --   then
  --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

  --  when others
  --  then
  --      DBMS_OUTPUT.PUT_LINE ('System Error');
  --      UTL_FILE.FCLOSE(edi_file_handle);

  RETURN 1;
END edi_novelis_856_X12_01212020;
--------------------------------------------------------
--  DDL for Function EDI_NOVELIS_856_X12_04022019
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_NOVELIS_856_X12_04022019" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*
  Aluminum Blanking: Ford Supplier Code: ZZ R0P7A
                     DUNS: 01 039630926T
  Customer: ALCAN(34,35,10,1153)
  Alcan Rolled Product    X.121       0015049350011G
  End User: Ford (ZZ F159B)
            Ford Chicago Stamping Plant(51) MS02A
            Ford Walton Hills Stamping Plant(77) MS03A
            Ford Woodhaven Stamping Plant(71) AF30A MS09A
            Ford Maumee Stamping Plant(78)    AF06A MS08A

            Budd Company (Customer ID: 1096) B821L
            Eagle Steel (1251) MZF6B
            (not in use)Ford Monroe Stamping              AP06A

            (not in use) Warehouses: IDS(41)               R5G3B
            (not in use) Wayne Steel Distribution Center(79) RWSDC

  */

  --v_edi_text_ford varchar2(32767);
  --v_edi_text_alcan varchar2(32767);
  --ll_customer_edi_name VARCHAR2(20);

   --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50);

  --edi_loc varchar2(50):='/tmp';
  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_prefix VARCHAR2(50) := 'S_novelis_856_'; --Production
  --edi_file_prefix VARCHAR2(50) := 's_novelis_856_'; --Development
  edi_file_handle utl_file.file_type;

  li_customer_id    shipment.customer_id%TYPE;
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;

  -- ls_sender_vanid varchar2 (50);
  -- ls_receiver_vanid varchar2 (50);
  -- ls_customer_vanid varchar2(50);
  -- ls_receiver_gs03 varchar2(50);
  -- ls_customer_gs03 varchar2(50);
  --ls_st varchar2(50);
  ls_sf VARCHAR2(50);
  ls_eq_type VARCHAR2(10);  -- Added by Patrick Reynolds 11/30/2016
  ls_su      VARCHAR2(50);
  ls_st_duns VARCHAR2(50);
  ls_po      VARCHAR2(30);
  ls_auth_code   VARCHAR2(32);
  ll_gs_log  INTEGER;
  ll_st_log  INTEGER;
  ll_bsn_log INTEGER;

  ls_today VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD'); --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  ls_today_2digits_year VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD'); --Alex Gerlants. 10/16/2018. Test
  ls_now   VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  li_rowcount INTEGER;
  li_hl01 INTEGER;
  ll_shipment_nt INTEGER;
  ll_shipment_gt INTEGER;
  ll_shipment_pc INTEGER;
  li_td1 INTEGER;
  li_rc  INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_vehicle_id_prefix VARCHAR2(50);  -- Added by Patrick Reynolds 11/30/2016
  ls_scac              carrier.scac%TYPE;
  ls_carrier_full_name VARCHAR2(18);
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_carrier_initial   VARCHAR2(50);  -- Not used in stored procedure.  Discovered by Patrick Reynolds 11/30/2016
  ldt_shipment         DATE;
   ll_temp         INTEGER;
  ls_enduser_part VARCHAR2(50);
  li_des_id       INTEGER;

  ll_edi_file_id INTEGER;

  ls_lot_num VARCHAR2(32);
  ls_coil_id VARCHAR2(32);
  ls_des_cust_name VARCHAR2(18);
  
  ls_coil_org_num		coil.coil_org_num%TYPE; --Alex Gerlants. 01/25/2019
  ll_coil_gauge		  coil.coil_gauge%TYPE;   --Alex Gerlants. 01/25/2019
  ll_coil_width		  coil.coil_width%TYPE;   --Alex Gerlants. 01/25/2019
  ld_ship_date      date;
  li_is_novelis     integer;

  CURSOR alcan_ford_856_cur IS
    SELECT sheet_packing_item.sh_packing_item,
           'MULTIPLE' lot_num,
           'MULTIPLE' coil_id,
           customer_order.orig_customer_po,
           customer_order.order_abc_num,
           customer_order.enduser_po,
           customer_order.created_date,
           order_item.order_item_num,
           order_item.enduser_part_num,
           order_item.supplier_code,
           order_item.gauge,
           sheet_skid. ab_job_num,
           sheet_skid.sheet_skid_num,
           sheet_skid.sheet_skid_display_num, --added by Victor H. on 06-2012 for Novelis locatio code request
           sheet_skid.sheet_net_wt,
           sheet_skid.sheet_tare_wt,
           sheet_skid. skid_pieces,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_theoretical_wt,
           NULL done
      FROM customer_order,
           order_item,
           sheet_skid,
           ab_job,
           shipment,
           sheet_packing_item
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
/*      
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
  --      (SHIPMENT.SHIPMENT_EDI856_DATE is NULL);
*/
  --TYPE skidinfo_tabletype IS TABLE OF alcan_ford_856_cur%ROWTYPE INDEX BY BINARY_INTEGER;
  --skidinfo_table skidinfo_tabletype;
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table    store_tabletype;
  i            BINARY_INTEGER := 0;
  skidinfo_rec alcan_ford_856_cur%ROWTYPE;

  /*CURSOR packing_list_same_bol IS
  SELECT packing_list
    FROM shipment
   WHERE bill_of_lading = ll_bill_of_lading;*/

  CURSOR c_ship_to IS
    SELECT DISTINCT des_sh_cust_id --, PACKING_LIST
      FROM shipment
     WHERE bill_of_lading = ll_bill_of_lading
       AND shipment.shipment_status = 0;
  --ORDER BY PACKING_LIST;
  
  cursor c_coil is
  select distinct 
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num,
         coil.coil_gauge,
         coil.coil_width
         --process_coil.coil_abc_num
         --outbound_edi_transaction.transaction_time,
         --outbound_edi_transaction.edi_file_name
  from   customer_order
         join order_item on order_item.order_abc_num = customer_order.order_abc_num
         join ab_job on ab_job.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
         join sheet_skid on sheet_skid.ab_job_num = ab_job.ab_job_num
         join sheet_packing_item on sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
         join shipment on shipment.packing_list = sheet_packing_item.packing_list
         join process_coil on process_coil.ab_job_num = ab_job.ab_job_num
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         --join outbound_edi_transaction on outbound_edi_transaction.edi_file_id = shipment.edi_file_id_856
  --where  shipment.packing_list = 105586 --Production
  where  shipment.packing_list = al_packing_list --Develpment
  order by
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num;

BEGIN
  
  select f_is_novelis(al_packing_list)
  into   li_is_novelis
  from   dual;
  
  if li_is_novelis = 0 then --Customer is NOT Novelis
    return 1; --Nothing to do here
  end if;
  
  select shipment_edi856_date
  into   ld_ship_date
  from   shipment
  where  shipment.packing_list = al_packing_list;
   
  if not (ld_ship_date is null) then --ASN already sent
    return 100;
  end if;

  edi_loc := dbo.get_edi_destination('EDI_DIR'); --Alex Gerlants. 11/15/2016

  -- edi_alcan_870; -- Send 870 first

  -- Get Customer ID, End user ID
  --SELECT customer_id, des_sh_cust_id
  --  INTO li_customer_id, li_des_sh_cust_id
  -- FROM shipment
  -- WHERE shipment.packing_list = al_packing_list;
  --IF NOT SQL%FOUND THEN
 --   RETURN - 1;
  --END IF;

  -- Get Customer ID, End user ID, authorization code
  SELECT customer_id, des_sh_cust_id, nvl(shipment_athorization_code, 'NA')
    INTO li_customer_id, li_des_sh_cust_id, ls_auth_code
  FROM shipment
  WHERE shipment.packing_list = al_packing_list;
  IF NOT SQL%FOUND THEN
   RETURN - 1;
  END IF;

  -- dbms_output.put_line (to_char(li_customer_id) || '  ' || to_char(li_des_sh_cust_id) );

  IF NOT (li_customer_id IN (34, 35, 10, 1153, 1459, 2582)) -- AND (li_des_sh_cust_id IN (
  --10,41,51,69,70,71,72,77,78,79,1055,1062,1073,1086,1096,1099,1114,1112,1153,
  --1206,1251,1253,1268,1269,1270,1322,1325,1328,1331,1332,1346,1347, 1382, 1383)))
   THEN

    --***********************************************************************************************88
    --IF NOT ((li_customer_id IN (34,35,10,1153)) AND (li_des_sh_cust_id IN (SELECT CUSTOMER_ID
    --FROM CUSTOMER
    --WHERE CUSTOMER_DUNS_NUMBER_STRING is not null))) THEN

    RETURN 200;
  END IF;

  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(sheet_skid.sheet_net_wt),
         SUM(sheet_skid.sheet_net_wt) + SUM(sheet_skid.sheet_tare_wt),
         SUM(sheet_skid.skid_pieces)
    INTO ll_shipment_nt, ll_shipment_gt, ll_shipment_pc
    FROM sheet_skid, sheet_packing_item, shipment
   WHERE shipment.packing_list = sheet_packing_item.packing_list
     AND sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
     AND shipment.packing_list = al_packing_list;
  IF ll_shipment_pc = 0 THEN
    RETURN 100;
  END IF; -- empty shipment

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  -- Retrieve ABCO info
  -- ls_sender_vanid := '3010007080';
  --ls_ic := 'R0P7A';

  -- Retrieve ALCAN supply code and Ford Stamping Plant location code
  --SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf
  --FROM customer_customer  WHERE o_customer_id = li_customer_id and e_customer_id = 49;  --Ford customer_id =49

  ls_sf := '039630926';
  --SELECT NVL(communication_code,'UNKNOWN') INTO ls_st FROM customer_system
  --WHERE customer_id = li_des_sh_cust_id;

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.vehicle_id_prefix, '9999'),
         nvl(shipment.equipment_type, 'NA'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'PT'), -- Protected Trailer
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE)
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_vehicle_id_prefix,
         ls_eq_type,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_carrier_initial,
         ldt_shipment
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;

  --Check all packing_lists are done against a BOL
  /*
  for pl_rec in packing_list_same_bol loop
      select shipment.shipment_status into ll_temp from shipment
             where shipment.packing_list = pl_rec.packing_list;
      if ll_temp > 0 then
         return pl_rec.packing_list;
      end if;

  end loop;
  */
  --End of packing list checking

  SELECT nvl(customer_duns_number_string, '00000000'), customer_short_name
    INTO ls_st_duns, ls_des_cust_name
    FROM customer
   WHERE customer_id = li_des_sh_cust_id;

  IF (ls_st_duns = '00000000') THEN
    RETURN 200;
  END IF; --No Ship to DUNS

  SELECT nvl(customer_duns_number_string, '00000000')
    INTO ls_su
    FROM customer
   WHERE customer_id = li_customer_id;
  IF (ls_su = '00000000') THEN
    RETURN 200;
  END IF; --No Supplier DUNS

  -- Get SCAC(Standard Carrier Alpha Code)
  SELECT nvl(carrier.scac, 'NONE'), LPAD(carrier.carrier_full_name, 17)
    INTO ls_scac, ls_carrier_full_name
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);

  -- Get Receiver and Customer VAN ID
  -- SELECT NVL(customer_system.van_account_num, 'nothing'), NVL(customer_system.gs03, 'nothing')
  -- INTO ls_receiver_vanid, ls_receiver_gs03    -- ls_receiver_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --   (select shipment.des_sh_cust_id  from shipment  where shipment.packing_list = al_packing_list);

  -- SELECT NVL(customer_system.van_account_num, 'nothing'),NVL(customer_system.gs03, 'nothing')
  -- INTO   ls_customer_vanid, ls_customer_gs03   -- ls_customer_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --       (select shipment.customer_id from shipment where shipment.packing_list = al_packing_list);

  -- Generate Header Info.
  --x12_table(i) := 'ISA*00*'||'          *00*          *ZZ*R0P7A          *ZZ*F159B          *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0') ||'*0*P**';
  --x12_table(i) := 'GS*SH*R0P7A*'||ls_st || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  --Alex Gerlants. 10/16/2018. Changed from "00200" to "00401"
  --Production
  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *01*039630926T     *09*0015049350011G *' ||
                  ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
  
  --Development                
  --x12_table(i) := 'ISA*00*' ||
  --                '          *00*          *ZZ*2NDSFTP        *ZZ*NOVLSTEST      *' ||
  --                ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
  --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';
                  
  i := i + 1;

  --Alex Gerlants. 10/16/2018. Changed from "002002" to "004010"
  --Production
  x12_table(1) := 'GS*SH*R0P7A*' || '001504935001' || '*' || ls_today || '*' ||
                  ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  --Development
  --x12_table(1) := 'GS*SH*2NDSFTP*' || 'NOVLSTEST' || '*' || ls_today || '*' ||
  --               ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;
  --x12_table(i):= 'BSN*00*' || to_char(ll_bill_of_lading) || '*' || ls_today || '*' || ls_now;
  x12_table(i) := 'BSN*00*' || to_char(al_packing_list) || '*' || ls_today || '*' ||
                  ls_now;
  i := i + 1;
  
  --Alex Gerlants. 08/07/2018.
  --Changed to populate with actual ship date instead of current date and time.
  --The reason is that when we send 856 on a later date, this date is not correct.
  --x12_table(i) := 'DTM*011*' || ls_today || '*' || ls_now;
  --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                                                      to_char(ldt_shipment, 'HH24MI');
  i := i + 1;
  
  --Alex Gerlants. 10/18/2018. Changed from "YYMMDD" to "YYYYMMDD"
  --Moved here from the below
  x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                  to_char(ldt_shipment, 'HH24MI');
  i := i + 1;

  -- First Level HL
  x12_table(i) := 'HL*01**S';
  i := i + 1;
  --Alex Gerlants. 10/16/2018. Changed from "MEA*PD*G*" to "MEA*WT*G*"
  x12_table(i) := 'MEA*WT*G*' || to_char(ll_shipment_gt) || '*LB';
  i := i + 1;
  x12_table(i) := 'MEA*WT*N*' || to_char(ll_shipment_nt) || '*LB';
  i := i + 1;
  x12_table(i) := 'TD1*PLT90*' || to_char(li_rowcount);
  li_td1 := i;
  i := i + 1;
  x12_table(i) := 'TD5*B*2*' || ls_scac || '*M*' || ls_carrier_full_name;
  i := i + 1;
  -- segment was modified to include trailer number.  Patrick Reynolds 11/30/2016
  x12_table(i) := 'TD3*' || ls_carrier_desc_code || '*' || ls_scac || '*' || ls_vehicle_id_prefix;
  i := i + 1;
  x12_table(i) := 'REF*BM*' || to_char(al_packing_list);
  i := i + 1;
  x12_table(i) := 'REF*PK*' || to_char(al_packing_list);
  i := i + 1;
  -- segment was modified to include equipment type.  Patrick Reynolds 11/30/2016
  x12_table(i) := 'REF*EQ*' || ls_eq_type;
  i := i + 1; --waiting for Novilis, ----tony
  --- Testing for multi order ASN ----Tony

  x12_table(i) := 'REF*MB*' || to_char(ll_bill_of_lading);
  i := i + 1;
  SELECT COUNT(*)
    INTO ll_temp
    FROM shipment
   WHERE shipment.bill_of_lading = ll_bill_of_lading
     AND shipment.shipment_status = 0;
     
  --Alex Gerlants. 10/16/2018. Removed 2 lines below
  --x12_table(i) := 'REF*SS*' || to_char(ll_temp);
  --i := i + 1;
  li_des_id := 1;
  
  --Alex Gerlants. 10/16/2018. Removed 7 lines below
  /*
  FOR c_stop IN c_ship_to LOOP
    IF li_des_sh_cust_id = c_stop.des_sh_cust_id THEN
      x12_table(i) := 'REF*QN*' || to_char(li_des_id);
      i := i + 1;
    END IF;
    li_des_id := li_des_id + 1;
  END LOOP;
  */

  /*
  IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
     x12_table(i):= 'REF*ZZ*' || ls_st;i:=i+1;
  end if;
  */

  ----Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  --x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
  --                to_char(ldt_shipment, 'HH24MI');
  --i := i + 1;
  
  x12_table(i) := 'N1*ST*' || ls_des_cust_name || '*1*' || ls_st_duns;
  i := i + 1;
  x12_table(i) := 'N1*SF*Aluminum Blanking Co*1*' || ls_sf;
  i := i + 1;
  x12_table(i) := 'N1*SU**1*' || ls_su;
  i := i + 1;

  --if not (li_des_sh_cust_id = 1096 or li_des_sh_cust_id = 1251) then
  --         x12_table(i):= 'N1*IC**92*' || ls_ic; i := i +1;        --- Deleted 04-30-03 by Tony according to alcan Julia's email
  --end if;

  --         x12_table(i):= 'N1*CN**92*' || ls_st_duns; i := i +1; --Ship to DUNs --- Deleted 04-30-03 by Tony according to alcan Julia's email

  -- Second Level HL based on End User PO( only one part# is included in one shipement per FORD's request)
  OPEN alcan_ford_856_cur;
  FETCH alcan_ford_856_cur
    INTO skidinfo_rec;
  --    ls_enduser_part := skidinfo_rec.ENDUSER_PART_NUM;
  --    ls_enduser_po := skidinfo_rec.ENDUSER_PO;

  /*
    if skidinfo_rec.ORIG_CUSTOMER_PO IN ('68Q68517') then    --Do NOT send 856 to Ford for some flipping related POs )
         edi_file_prefix := 'nosend_alcan_ford_ford';
    end if;
  */

  SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
    INTO ls_enduser_part
    FROM "ORDER_ITEM", "SHEET_SKID"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
     AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
     AND ("SHEET_SKID"."SHEET_SKID_NUM" = skidinfo_rec.sheet_skid_num);

  /*
      SELECT "CUSTOMER_ORDER"."ENDUSER_PO" into ls_enduser_po
             FROM "SHEET_SKID",
                  "CUSTOMER_ORDER"
                  WHERE ( "SHEET_SKID"."REF_ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM" ) and
                        (SHEET_SKID.SHEET_SKID_NUM = skidinfo_rec.SHEET_SKID_NUM);
  */

  x12_table(i) := 'HL*02*01*O';
  i := i + 1;
  IF ls_enduser_part IS NULL THEN
    ls_enduser_part := 'NA';
  END IF;
  x12_table(i) := 'LIN**BP*' || ls_enduser_part;
  i := i + 1;
  x12_table(i) := 'SN1**' || to_char(ll_shipment_pc) || '*EA*0';
  i := i + 1;

  --
  --ls_po := skidinfo_rec.ORIG_CUSTOMER_PO;
  SELECT "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO"
    INTO ls_po
    FROM "SHEET_SKID", "CUSTOMER_ORDER"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
         "CUSTOMER_ORDER"."ORDER_ABC_NUM")
     AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num);

  --IF INSTR(skidinfo_rec.ORIG_CUSTOMER_PO,'-') > 0
  --New PO format for Novelis SAP include '-'
  /*IF instr(ls_po, '-') > 0 THEN
    ls_po := substr(ls_po, 0, instr(ls_po, '-') - 1);
  END IF;*/

  --   IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
  x12_table(i) := 'PRF*' || ls_po || '***' ||
                  to_char(skidinfo_rec.created_date, 'YYYYMMDD');
  i := i + 1;
  --   end if;

  CLOSE alcan_ford_856_cur;

   --  Novelis SAP order number
 x12_table(i) := 'REF*IL*' || ls_auth_code;
 i := i + 1;
  --  end if;

  -- Third Level HL Under a P.O.
  li_hl01 := 3;

  --Skid loop begin ----------------------------------------------------------------
  FOR skidinfo_rec IN alcan_ford_856_cur LOOP
    
      --In case of a split skid, we are creating just 1 HL for this skid
      --with just 1 coil for this skid.
      select distinct coil.coil_org_num, coil.coil_gauge, coil.coil_width, coil.lot_num
      into   ls_coil_org_num, ll_coil_gauge, ll_coil_width, ls_lot_num
      FROM "COIL",   
           "PRODUCTION_SHEET_ITEM",   
           "SHEET_SKID",   
           "SHEET_SKID_DETAIL",   
           "PROCESS_COIL"  
     WHERE ( "COIL"."COIL_ABC_NUM" = "PRODUCTION_SHEET_ITEM"."COIL_ABC_NUM" ) and  
           ( "SHEET_SKID_DETAIL"."SHEET_SKID_NUM" = "SHEET_SKID"."SHEET_SKID_NUM" ) and  
           ( "SHEET_SKID_DETAIL"."PROD_ITEM_NUM" = "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NUM" ) and  
           ( "COIL"."COIL_ABC_NUM" = "PROCESS_COIL"."COIL_ABC_NUM" ) and  
           ( "PRODUCTION_SHEET_ITEM"."AB_JOB_NUM" = "PROCESS_COIL"."AB_JOB_NUM" ) and  
           ( (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num)  ) and
           ( (rownum = 1)  ); --We need just 1 coil for each skid
  
      IF length(to_char(li_hl01)) = 1 THEN
        x12_table(i) := 'HL*0' || to_char(li_hl01) || '*02*I';
        i := i + 1;
      ELSE
        x12_table(i) := 'HL*' || to_char(li_hl01) || '*02*I';
        i := i + 1;
      END IF;

      --    IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
      --       x12_table(i) := 'SN1**'||to_char(skidinfo_rec.skid_pieces)||'*EA';i:=i+1;
      --    else
      x12_table(i) := 'SN1**1*PF';
      i := i + 1;
      --    end if;

      --if li_des_sh_cust_id = 1096 -- To Budd or li_des_sh_cust_id = 1251 then
      --   then
      --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; i := i +1;
      --      x12_table(i) :=  'MEA*PD*TH*' || to_char(skidinfo_rec.sheet_net_wt) || '*24'; i := i +1;
      --elsif   li_des_sh_cust_id = 1251   --To Eagle Steel
      --  then
      --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; i := i +1;
      --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*24'; i := i +1;
      --      x12_table(i) :=  'MEA*PD*TH*' || to_char(skidinfo_rec.gauge) || '*EM'; i:=i+1;
      --    x12_table(i) :=  'MEA*PD*WD*'||'44.875'||'*IN'; i:=i+1;
      --    x12_table(i) :=  'MEA*PD*LN*'||to_char(skidinfo_rec.skid_pieces)||'*LF';  i:=i+1;
      --else  --All else, Ford dirct shiping program
                        
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*N" to "MEA*WT*N"
      x12_table(i) := 'MEA*WT*N*' || to_char(skidinfo_rec.sheet_net_wt) ||
                      '*01';
      i := i + 1;
                        
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*WT" to "MEA*CT*NL"
      x12_table(i) := 'MEA*CT*NL*' || to_char(skidinfo_rec.skid_pieces) ||
                      '*PC';
      i := i + 1;

      -- changed to all gross wt per novelis 1/30/2015
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*G" to "MEA*WT*G"
      x12_table(i) := 'MEA*WT*G*' || to_char(skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt) || '*01';
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      x12_table(i) := 'MEA*PD*GG*' || ll_coil_gauge;
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      x12_table(i) := 'MEA*PD*WD*' || ll_coil_width;
      i := i + 1;

      /*
      IF (skidinfo_rec.sheet_theoretical_wt IS NULL) OR
         (skidinfo_rec.sheet_theoretical_wt = 0) THEN
        x12_table(i) := 'MEA*PD*G*' || to_char(ll_shipment_gt) || '*01';
        i := i + 1;
      ELSE
        x12_table(i) := 'MEA*PD*G*' ||
                        to_char(skidinfo_rec.sheet_theoretical_wt) || '*01';
        i := i + 1;
      END IF;
      */
      --end if;

      -- fill in lot num
      /*
      SELECT COUNT(*)
        INTO li_rc
        FROM sheet_skid_detail
       WHERE sheet_skid_detail.sheet_skid_num = skidinfo_rec.sheet_skid_num;

      ls_lot_num := skidinfo_rec.lot_num;
      ls_coil_id := skidinfo_rec.coil_id;

      IF li_rc = 1 THEN
        SELECT lot_num, coil_org_num
          INTO ls_lot_num, ls_coil_id
          FROM coil
         WHERE coil.coil_abc_num =
               (SELECT coil_abc_num
                  FROM production_sheet_item
                 WHERE production_sheet_item.prod_item_num =
                       (SELECT prod_item_num
                          FROM sheet_skid_detail
                         WHERE sheet_skid_detail.sheet_skid_num =
                               skidinfo_rec.sheet_skid_num));
      END IF;
      */
      --if li_des_sh_cust_id = 1251   --Eagle need coil ID here instead of lot number
      --then
      --x12_table(i) :=  'REF*HC*' || skidinfo_rec.coil_id ; i := i +1;
      --else
                        
      --Alex Gerlants. 10/18/2018. Changed from "REF*HC" to "REF*BT"
      x12_table(i) := 'REF*BT*' || ls_lot_num;
      i := i + 1;
      --end if;

      --x12_table(i) := 'REF*LS*' || to_char(skidinfo_rec.sheet_skid_num);
      --Alex Gerlants. 10/18/2018. Changed from "REF*LS" to "REF*SE"
      x12_table(i) := 'REF*SE*' || skidinfo_rec.sheet_skid_display_num; --added by Victor H. on 06-2012 for Novelis locatio code request
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      x12_table(i) := 'REF*LS*' || ls_coil_org_num;
      i := i + 1;
      
      li_hl01 := li_hl01 + 1;
      li_rowcount := alcan_ford_856_cur%ROWCOUNT;
      x12_table(li_td1) := 'TD1*PLT90*' || to_char(li_rowcount);
  END LOOP; --End of 'FOR skidinfo_rec IN alcan_ford_856_cur LOOP'
  --Skid loop end ------------------------------------------------------------------

  -- DBMS_OUTPUT.PUT_LINE ('rowcount' || to_char(li_rowcount));

  -- if li_des_sh_cust_id = 1096 or li_des_sh_cust_id = 1251 then
  --   x12_table(i) :=  'CTT*' || to_char(li_HL01 - 1) ||'*' || to_char(ll_shipment_pc*2) ;
  --   i := i +1;
  -- else
  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                  to_char(li_rowcount + ll_shipment_pc);
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  -- Write X.12 to file
  -- To FORD

  /** Write file to /templar/templar/incoming/senddata
  /*
  **/

  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  --edi_file:= 'S_alcan_ford_ford_' || to_char(ll_edi_file_id) ||'.x12';

  -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
  -- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
    --        v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
  END LOOP;
  utl_file.fclose(edi_file_handle);

  --To ALCAN

  /*
  SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;
  SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id_alcan FROM DUAL;
  edi_file:= 'S_alcan_ford_alcan_' || to_char(ll_edi_file_id_alcan) ||'.x12';
  edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');
  x12_table(0) := 'ISA*00*'||'          *00*          *01*039630926T     *09*0015049350011G *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0')||'*0*P**';
  x12_table(1) := 'GS*SH*R0P7A*'||'001504935001' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  x12_table(i-1) :=  'GE*1*' || to_char (ll_gs_log);
  x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');
  for j in 0..i loop
   UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
       v_edi_text_alcan:=v_edi_text_alcan||x12_table(j)||CHR(10);
  end loop;
  UTL_FILE.FCLOSE(edi_file_handle);

  */

  /* The following code added by Tony, for update archive*/

  --  INSERT INTO edi_log (edi_log_timestamp,customer_id,
  --         customer_edi_name,edi_log_contents,edi_file_id,edi_text)
  --    VALUES (SYSDATE,li_customer_id,ll_customer_edi_name,
  --           'EDI:'||ll_customer_edi_name||' generated successfully.',ll_edi_file_id,v_edi_text);
  --   COMMIT;

  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE,
         edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;
--  COMMIT;

  /* --added by Victor Huang on 06/05 for function acknowlegement
  INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
  VALUES(ll_gs_log, ls_su, sysdate, edi_file);
  COMMIT;*/

  --added by Victor Huang on 12/07 for verifying 997
  INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (ll_edi_file_id,
     '039630926',
     ls_su,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856');
  COMMIT;

  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  --exception
  --   when invalid_operation
  --   then
  --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

  --  when others
  --  then
  --      DBMS_OUTPUT.PUT_LINE ('System Error');
  --      UTL_FILE.FCLOSE(edi_file_handle);

  RETURN 1;
END edi_novelis_856_X12_04022019;
--------------------------------------------------------
--  DDL for Function EDI_NOVELIS_856_X12_10012019
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_NOVELIS_856_X12_10012019" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*
  Aluminum Blanking: Ford Supplier Code: ZZ R0P7A
                     DUNS: 01 039630926T
  Customer: ALCAN(34,35,10,1153)
  Alcan Rolled Product    X.121       0015049350011G
  End User: Ford (ZZ F159B)
            Ford Chicago Stamping Plant(51) MS02A
            Ford Walton Hills Stamping Plant(77) MS03A
            Ford Woodhaven Stamping Plant(71) AF30A MS09A
            Ford Maumee Stamping Plant(78)    AF06A MS08A

            Budd Company (Customer ID: 1096) B821L
            Eagle Steel (1251) MZF6B
            (not in use)Ford Monroe Stamping              AP06A

            (not in use) Warehouses: IDS(41)               R5G3B
            (not in use) Wayne Steel Distribution Center(79) RWSDC

  */

  --v_edi_text_ford varchar2(32767);
  --v_edi_text_alcan varchar2(32767);
  --ll_customer_edi_name VARCHAR2(20);

   --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50);

  --edi_loc varchar2(50):='/tmp';
  edi_file        VARCHAR2(50) := 'edi_out.txt';
  --edi_file_prefix VARCHAR2(50) := 'S_novelis_856_'; --Production
  edi_file_prefix VARCHAR2(50) := 's_novelis_856_'; --Development
  edi_file_handle utl_file.file_type;

  li_customer_id    shipment.customer_id%TYPE;
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;

  -- ls_sender_vanid varchar2 (50);
  -- ls_receiver_vanid varchar2 (50);
  -- ls_customer_vanid varchar2(50);
  -- ls_receiver_gs03 varchar2(50);
  -- ls_customer_gs03 varchar2(50);
  --ls_st varchar2(50);
  ls_sf VARCHAR2(50);
  ls_eq_type VARCHAR2(10);  -- Added by Patrick Reynolds 11/30/2016
  ls_su      VARCHAR2(50);
  ls_st_duns VARCHAR2(50);
  ls_po      VARCHAR2(30);
  ls_auth_code   VARCHAR2(32);
  ll_gs_log  INTEGER;
  ll_st_log  INTEGER;
  ll_bsn_log INTEGER;

  ls_today VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD'); --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  ls_today_2digits_year VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD'); --Alex Gerlants. 10/16/2018. Test
  ls_now   VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  li_rowcount INTEGER;
  li_hl01 INTEGER;
  ll_shipment_nt INTEGER;
  ll_shipment_gt INTEGER;
  ll_shipment_pc INTEGER;
  li_td1 INTEGER;
  li_rc  INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_vehicle_id_prefix VARCHAR2(50);  -- Added by Patrick Reynolds 11/30/2016
  ls_scac              carrier.scac%TYPE;
  ls_carrier_full_name VARCHAR2(18);
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_carrier_initial   VARCHAR2(50);  -- Not used in stored procedure.  Discovered by Patrick Reynolds 11/30/2016
  ldt_shipment         DATE;
   ll_temp         INTEGER;
  ls_enduser_part VARCHAR2(50);
  li_des_id       INTEGER;

  ll_edi_file_id INTEGER;

  ls_lot_num VARCHAR2(32);
  ls_coil_id VARCHAR2(32);
  ls_des_cust_name VARCHAR2(18);
  
  ls_coil_org_num		        coil.coil_org_num%TYPE; --Alex Gerlants. 01/25/2019
  ll_coil_gauge		          coil.coil_gauge%TYPE;   --Alex Gerlants. 01/25/2019
  ll_coil_width		          coil.coil_width%TYPE;   --Alex Gerlants. 01/25/2019
  ld_ship_date              date;
  li_is_novelis             integer;
  ln_skid_type_if_whed      sheet_skid.skid_type_if_whed%TYPE;   --Alex Gerlants. 04/01/2019

  CURSOR alcan_ford_856_cur IS
    SELECT sheet_packing_item.sh_packing_item,
           'MULTIPLE' lot_num,
           'MULTIPLE' coil_id,
           customer_order.orig_customer_po,
           customer_order.order_abc_num,
           customer_order.enduser_po,
           customer_order.created_date,
           order_item.order_item_num,
           order_item.enduser_part_num,
           order_item.supplier_code,
           order_item.gauge,
           sheet_skid. ab_job_num,
           sheet_skid.sheet_skid_num,
           sheet_skid.sheet_skid_display_num, --added by Victor H. on 06-2012 for Novelis locatio code request
           sheet_skid.sheet_net_wt,
           sheet_skid.sheet_tare_wt,
           sheet_skid. skid_pieces,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_theoretical_wt,
           NULL done

/*      
      from customer_order
           join order_item on customer_order.order_abc_num = order_item.order_abc_num
           join sheet_skid on order_item.order_abc_num = sheet_skid.ref_order_abc_num and order_item.order_item_num = sheet_skid.ref_order_abc_item
           join sheet_packing_item on sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
           join shipment on shipment.packing_list = sheet_packing_item.packing_list
     where shipment.packing_list = al_packing_list;
*/


      FROM customer_order,
           order_item,
           sheet_skid,
           ab_job,
           shipment,
           sheet_packing_item
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);


/*      
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
  --      (SHIPMENT.SHIPMENT_EDI856_DATE is NULL);
*/

  --TYPE skidinfo_tabletype IS TABLE OF alcan_ford_856_cur%ROWTYPE INDEX BY BINARY_INTEGER;
  --skidinfo_table skidinfo_tabletype;
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table    store_tabletype;
  i            BINARY_INTEGER := 0;
  skidinfo_rec alcan_ford_856_cur%ROWTYPE;

  /*CURSOR packing_list_same_bol IS
  SELECT packing_list
    FROM shipment
   WHERE bill_of_lading = ll_bill_of_lading;*/

  CURSOR c_ship_to IS
    SELECT DISTINCT des_sh_cust_id --, PACKING_LIST
      FROM shipment
     WHERE bill_of_lading = ll_bill_of_lading
       AND shipment.shipment_status = 0;
  --ORDER BY PACKING_LIST;
  
  cursor c_coil is
  select distinct 
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num,
         coil.coil_gauge,
         coil.coil_width
         --process_coil.coil_abc_num
         --outbound_edi_transaction.transaction_time,
         --outbound_edi_transaction.edi_file_name
  from   customer_order
         join order_item on order_item.order_abc_num = customer_order.order_abc_num
         join ab_job on ab_job.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
         join sheet_skid on sheet_skid.ab_job_num = ab_job.ab_job_num
         join sheet_packing_item on sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
         join shipment on shipment.packing_list = sheet_packing_item.packing_list
         join process_coil on process_coil.ab_job_num = ab_job.ab_job_num
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         --join outbound_edi_transaction on outbound_edi_transaction.edi_file_id = shipment.edi_file_id_856
  --where  shipment.packing_list = 105586 --Production
  where  shipment.packing_list = al_packing_list --Develpment
  order by
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num;

BEGIN
  
  select f_is_novelis(al_packing_list)
  into   li_is_novelis
  from   dual;
  
  if li_is_novelis = 0 then --Customer is NOT Novelis
    return 1; --Nothing to do here
  end if;
  
  select shipment_edi856_date
  into   ld_ship_date
  from   shipment
  where  shipment.packing_list = al_packing_list;
   
  if not (ld_ship_date is null) then --ASN already sent
    return 100;
  end if;

  edi_loc := dbo.get_edi_destination('EDI_DIR'); --Alex Gerlants. 11/15/2016

  -- edi_alcan_870; -- Send 870 first

  -- Get Customer ID, End user ID
  --SELECT customer_id, des_sh_cust_id
  --  INTO li_customer_id, li_des_sh_cust_id
  -- FROM shipment
  -- WHERE shipment.packing_list = al_packing_list;
  --IF NOT SQL%FOUND THEN
 --   RETURN - 1;
  --END IF;

  -- Get Customer ID, End user ID, authorization code
  SELECT customer_id, des_sh_cust_id, nvl(shipment_athorization_code, 'NA')
    INTO li_customer_id, li_des_sh_cust_id, ls_auth_code
  FROM shipment
  WHERE shipment.packing_list = al_packing_list;
  IF NOT SQL%FOUND THEN
   RETURN - 1;
  END IF;

  -- dbms_output.put_line (to_char(li_customer_id) || '  ' || to_char(li_des_sh_cust_id) );

  IF NOT (li_customer_id IN (34, 35, 10, 1153, 1459, 2582)) -- AND (li_des_sh_cust_id IN (
  --10,41,51,69,70,71,72,77,78,79,1055,1062,1073,1086,1096,1099,1114,1112,1153,
  --1206,1251,1253,1268,1269,1270,1322,1325,1328,1331,1332,1346,1347, 1382, 1383)))
   THEN

    --***********************************************************************************************88
    --IF NOT ((li_customer_id IN (34,35,10,1153)) AND (li_des_sh_cust_id IN (SELECT CUSTOMER_ID
    --FROM CUSTOMER
    --WHERE CUSTOMER_DUNS_NUMBER_STRING is not null))) THEN

    RETURN 200;
  END IF;

  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(sheet_skid.sheet_net_wt),
         SUM(sheet_skid.sheet_net_wt) + SUM(sheet_skid.sheet_tare_wt),
         SUM(sheet_skid.skid_pieces)
    INTO ll_shipment_nt, ll_shipment_gt, ll_shipment_pc
    FROM sheet_skid, sheet_packing_item, shipment
   WHERE shipment.packing_list = sheet_packing_item.packing_list
     AND sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
     AND shipment.packing_list = al_packing_list;
  IF ll_shipment_pc = 0 THEN
    RETURN 100;
  END IF; -- empty shipment

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  -- Retrieve ABCO info
  -- ls_sender_vanid := '3010007080';
  --ls_ic := 'R0P7A';

  -- Retrieve ALCAN supply code and Ford Stamping Plant location code
  --SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf
  --FROM customer_customer  WHERE o_customer_id = li_customer_id and e_customer_id = 49;  --Ford customer_id =49

  ls_sf := '039630926';
  --SELECT NVL(communication_code,'UNKNOWN') INTO ls_st FROM customer_system
  --WHERE customer_id = li_des_sh_cust_id;

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.vehicle_id_prefix, '9999'),
         nvl(shipment.equipment_type, 'NA'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'PT'), -- Protected Trailer
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE)
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_vehicle_id_prefix,
         ls_eq_type,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_carrier_initial,
         ldt_shipment
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;

  --Check all packing_lists are done against a BOL
  /*
  for pl_rec in packing_list_same_bol loop
      select shipment.shipment_status into ll_temp from shipment
             where shipment.packing_list = pl_rec.packing_list;
      if ll_temp > 0 then
         return pl_rec.packing_list;
      end if;

  end loop;
  */
  --End of packing list checking

  SELECT nvl(customer_duns_number_string, '00000000'), customer_short_name
    INTO ls_st_duns, ls_des_cust_name
    FROM customer
   WHERE customer_id = li_des_sh_cust_id;

  IF (ls_st_duns = '00000000') THEN
    RETURN 200;
  END IF; --No Ship to DUNS

  SELECT nvl(customer_duns_number_string, '00000000')
    INTO ls_su
    FROM customer
   WHERE customer_id = li_customer_id;
  IF (ls_su = '00000000') THEN
    RETURN 200;
  END IF; --No Supplier DUNS

  -- Get SCAC(Standard Carrier Alpha Code)
  SELECT nvl(carrier.scac, 'NONE'), LPAD(carrier.carrier_full_name, 17)
    INTO ls_scac, ls_carrier_full_name
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);

  -- Get Receiver and Customer VAN ID
  -- SELECT NVL(customer_system.van_account_num, 'nothing'), NVL(customer_system.gs03, 'nothing')
  -- INTO ls_receiver_vanid, ls_receiver_gs03    -- ls_receiver_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --   (select shipment.des_sh_cust_id  from shipment  where shipment.packing_list = al_packing_list);

  -- SELECT NVL(customer_system.van_account_num, 'nothing'),NVL(customer_system.gs03, 'nothing')
  -- INTO   ls_customer_vanid, ls_customer_gs03   -- ls_customer_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --       (select shipment.customer_id from shipment where shipment.packing_list = al_packing_list);

  -- Generate Header Info.
  --x12_table(i) := 'ISA*00*'||'          *00*          *ZZ*R0P7A          *ZZ*F159B          *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0') ||'*0*P**';
  --x12_table(i) := 'GS*SH*R0P7A*'||ls_st || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  --Alex Gerlants. 10/16/2018. Changed from "00200" to "00401"
  --Production
  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *01*039630926T     *09*0015049350011G *' ||
                  ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
  
  --Development                
  --x12_table(i) := 'ISA*00*' ||
  --                '          *00*          *ZZ*2NDSFTP        *ZZ*NOVLSTEST      *' ||
  --                ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
  --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';
                  
  i := i + 1;

  --Alex Gerlants. 10/16/2018. Changed from "002002" to "004010"
  --Production
  x12_table(1) := 'GS*SH*R0P7A*' || '001504935001' || '*' || ls_today || '*' ||
                  ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  --Development
  --x12_table(1) := 'GS*SH*2NDSFTP*' || 'NOVLSTEST' || '*' || ls_today || '*' ||
  --               ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;
  --x12_table(i):= 'BSN*00*' || to_char(ll_bill_of_lading) || '*' || ls_today || '*' || ls_now;
  x12_table(i) := 'BSN*00*' || to_char(al_packing_list) || '*' || ls_today || '*' ||
                  ls_now;
  i := i + 1;
  
  --Alex Gerlants. 08/07/2018.
  --Changed to populate with actual ship date instead of current date and time.
  --The reason is that when we send 856 on a later date, this date is not correct.
  --x12_table(i) := 'DTM*011*' || ls_today || '*' || ls_now;
  --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                                                      to_char(ldt_shipment, 'HH24MI');
  i := i + 1;
  
  --Alex Gerlants. 10/18/2018. Changed from "YYMMDD" to "YYYYMMDD"
  --Moved here from the below
  x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                  to_char(ldt_shipment, 'HH24MI');
  i := i + 1;

  -- First Level HL
  x12_table(i) := 'HL*01**S';
  i := i + 1;
  --Alex Gerlants. 10/16/2018. Changed from "MEA*PD*G*" to "MEA*WT*G*"
  x12_table(i) := 'MEA*WT*G*' || to_char(ll_shipment_gt) || '*LB';
  i := i + 1;
  x12_table(i) := 'MEA*WT*N*' || to_char(ll_shipment_nt) || '*LB';
  i := i + 1;
  x12_table(i) := 'TD1*PLT90*' || to_char(li_rowcount);
  li_td1 := i;
  i := i + 1;
  x12_table(i) := 'TD5*B*2*' || ls_scac || '*M*' || ls_carrier_full_name;
  i := i + 1;
  -- segment was modified to include trailer number.  Patrick Reynolds 11/30/2016
  x12_table(i) := 'TD3*' || ls_carrier_desc_code || '*' || ls_scac || '*' || ls_vehicle_id_prefix;
  i := i + 1;
  x12_table(i) := 'REF*BM*' || to_char(al_packing_list);
  i := i + 1;
  x12_table(i) := 'REF*PK*' || to_char(al_packing_list);
  i := i + 1;
  -- segment was modified to include equipment type.  Patrick Reynolds 11/30/2016
  x12_table(i) := 'REF*EQ*' || ls_eq_type;
  i := i + 1; --waiting for Novilis, ----tony
  --- Testing for multi order ASN ----Tony

  x12_table(i) := 'REF*MB*' || to_char(ll_bill_of_lading);
  i := i + 1;
  SELECT COUNT(*)
    INTO ll_temp
    FROM shipment
   WHERE shipment.bill_of_lading = ll_bill_of_lading
     AND shipment.shipment_status = 0;
     
  --Alex Gerlants. 10/16/2018. Removed 2 lines below
  --x12_table(i) := 'REF*SS*' || to_char(ll_temp);
  --i := i + 1;
  li_des_id := 1;
  
  --Alex Gerlants. 10/16/2018. Removed 7 lines below
  /*
  FOR c_stop IN c_ship_to LOOP
    IF li_des_sh_cust_id = c_stop.des_sh_cust_id THEN
      x12_table(i) := 'REF*QN*' || to_char(li_des_id);
      i := i + 1;
    END IF;
    li_des_id := li_des_id + 1;
  END LOOP;
  */

  /*
  IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
     x12_table(i):= 'REF*ZZ*' || ls_st;i:=i+1;
  end if;
  */

  ----Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  --x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
  --                to_char(ldt_shipment, 'HH24MI');
  --i := i + 1;
  
  x12_table(i) := 'N1*ST*' || ls_des_cust_name || '*1*' || ls_st_duns;
  i := i + 1;
  x12_table(i) := 'N1*SF*Aluminum Blanking Co*1*' || ls_sf;
  i := i + 1;
  x12_table(i) := 'N1*SU**1*' || ls_su;
  i := i + 1;

  --if not (li_des_sh_cust_id = 1096 or li_des_sh_cust_id = 1251) then
  --         x12_table(i):= 'N1*IC**92*' || ls_ic; i := i +1;        --- Deleted 04-30-03 by Tony according to alcan Julia's email
  --end if;

  --         x12_table(i):= 'N1*CN**92*' || ls_st_duns; i := i +1; --Ship to DUNs --- Deleted 04-30-03 by Tony according to alcan Julia's email

  -- Second Level HL based on End User PO( only one part# is included in one shipement per FORD's request)
  OPEN alcan_ford_856_cur;
  FETCH alcan_ford_856_cur
    INTO skidinfo_rec;
  --    ls_enduser_part := skidinfo_rec.ENDUSER_PART_NUM;
  --    ls_enduser_po := skidinfo_rec.ENDUSER_PO;

  /*
    if skidinfo_rec.ORIG_CUSTOMER_PO IN ('68Q68517') then    --Do NOT send 856 to Ford for some flipping related POs )
         edi_file_prefix := 'nosend_alcan_ford_ford';
    end if;
  */

  SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
    INTO ls_enduser_part
    FROM "ORDER_ITEM", "SHEET_SKID"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
     AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
     AND ("SHEET_SKID"."SHEET_SKID_NUM" = skidinfo_rec.sheet_skid_num);

  /*
      SELECT "CUSTOMER_ORDER"."ENDUSER_PO" into ls_enduser_po
             FROM "SHEET_SKID",
                  "CUSTOMER_ORDER"
                  WHERE ( "SHEET_SKID"."REF_ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM" ) and
                        (SHEET_SKID.SHEET_SKID_NUM = skidinfo_rec.SHEET_SKID_NUM);
  */

  x12_table(i) := 'HL*02*01*O';
  i := i + 1;
  IF ls_enduser_part IS NULL THEN
    ls_enduser_part := 'NA';
  END IF;
  x12_table(i) := 'LIN**BP*' || ls_enduser_part;
  i := i + 1;
  x12_table(i) := 'SN1**' || to_char(ll_shipment_pc) || '*EA*0';
  i := i + 1;

  --
  --ls_po := skidinfo_rec.ORIG_CUSTOMER_PO;
  SELECT "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO"
    INTO ls_po
    FROM "SHEET_SKID", "CUSTOMER_ORDER"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
         "CUSTOMER_ORDER"."ORDER_ABC_NUM")
     AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num);

  --IF INSTR(skidinfo_rec.ORIG_CUSTOMER_PO,'-') > 0
  --New PO format for Novelis SAP include '-'
  /*IF instr(ls_po, '-') > 0 THEN
    ls_po := substr(ls_po, 0, instr(ls_po, '-') - 1);
  END IF;*/

  --   IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
  x12_table(i) := 'PRF*' || ls_po || '***' ||
                  to_char(skidinfo_rec.created_date, 'YYYYMMDD');
  i := i + 1;
  --   end if;

  CLOSE alcan_ford_856_cur;

   --  Novelis SAP order number
 x12_table(i) := 'REF*IL*' || ls_auth_code;
 i := i + 1;
  --  end if;

  -- Third Level HL Under a P.O.
  li_hl01 := 3;

  --Skid loop begin ----------------------------------------------------------------
  FOR skidinfo_rec IN alcan_ford_856_cur LOOP
    
      --In case of a split skid, we are creating just 1 HL for this skid
      --with just 1 coil for this skid.
      select distinct 
             coil.coil_org_num,
             coil.coil_gauge,
             coil.coil_width,
             coil.lot_num,
             nvl(skid_type_if_whed, -1) --Alex Gerlants. 04/01/2019
      into   ls_coil_org_num,
             ll_coil_gauge,
             ll_coil_width,
             ls_lot_num,
             ln_skid_type_if_whed --Alex Gerlants. 04/01/2019
      FROM "COIL",   
           "PRODUCTION_SHEET_ITEM",   
           "SHEET_SKID",   
           "SHEET_SKID_DETAIL",   
           "PROCESS_COIL"  
     WHERE ( "COIL"."COIL_ABC_NUM" = "PRODUCTION_SHEET_ITEM"."COIL_ABC_NUM" ) and  
           ( "SHEET_SKID_DETAIL"."SHEET_SKID_NUM" = "SHEET_SKID"."SHEET_SKID_NUM" ) and  
           ( "SHEET_SKID_DETAIL"."PROD_ITEM_NUM" = "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NUM" ) and  
           ( "COIL"."COIL_ABC_NUM" = "PROCESS_COIL"."COIL_ABC_NUM" ) and  
           ( "PRODUCTION_SHEET_ITEM"."AB_JOB_NUM" = "PROCESS_COIL"."AB_JOB_NUM" ) and  
           ( (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num)  ) and
           ( (rownum = 1)  ); --We need just 1 coil for each skid
  
      --Alex Gerlants. 04/01/2019. Begin
      if ln_skid_type_if_whed > -1 then --Warehouse skid
          --Get gauge and part width
          select distinct order_item.gauge,
                 f_get_part_width_per_job(ab_job.ab_job_num) 
          into   ll_coil_gauge,
                 ll_coil_width
          from   sheet_skid
                 join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
                 join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
                 join customer_order on customer_order.order_abc_num = order_item.order_abc_num
          where  sheet_skid_num = skidinfo_rec.sheet_skid_num
          and    (order_item.gauge is not null and f_get_part_width_per_job(sheet_skid.ab_job_num) is not null)
          and    rownum = 1;
      end if;
      --Alex Gerlants. 04/01/2019. End
  
      IF length(to_char(li_hl01)) = 1 THEN
        x12_table(i) := 'HL*0' || to_char(li_hl01) || '*02*I';
        i := i + 1;
      ELSE
        x12_table(i) := 'HL*' || to_char(li_hl01) || '*02*I';
        i := i + 1;
      END IF;

      --    IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
      --       x12_table(i) := 'SN1**'||to_char(skidinfo_rec.skid_pieces)||'*EA';i:=i+1;
      --    else
      x12_table(i) := 'SN1**1*PF';
      i := i + 1;
      --    end if;

      --if li_des_sh_cust_id = 1096 -- To Budd or li_des_sh_cust_id = 1251 then
      --   then
      --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; i := i +1;
      --      x12_table(i) :=  'MEA*PD*TH*' || to_char(skidinfo_rec.sheet_net_wt) || '*24'; i := i +1;
      --elsif   li_des_sh_cust_id = 1251   --To Eagle Steel
      --  then
      --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; i := i +1;
      --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*24'; i := i +1;
      --      x12_table(i) :=  'MEA*PD*TH*' || to_char(skidinfo_rec.gauge) || '*EM'; i:=i+1;
      --    x12_table(i) :=  'MEA*PD*WD*'||'44.875'||'*IN'; i:=i+1;
      --    x12_table(i) :=  'MEA*PD*LN*'||to_char(skidinfo_rec.skid_pieces)||'*LF';  i:=i+1;
      --else  --All else, Ford dirct shiping program
                        
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*N" to "MEA*WT*N"
      x12_table(i) := 'MEA*WT*N*' || to_char(skidinfo_rec.sheet_net_wt) ||
                      '*01';
      i := i + 1;
                        
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*WT" to "MEA*CT*NL"
      x12_table(i) := 'MEA*CT*NL*' || to_char(skidinfo_rec.skid_pieces) ||
                      '*PC';
      i := i + 1;

      -- changed to all gross wt per novelis 1/30/2015
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*G" to "MEA*WT*G"
      x12_table(i) := 'MEA*WT*G*' || to_char(skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt) || '*01';
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      x12_table(i) := 'MEA*PD*GG*' || ll_coil_gauge;
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      x12_table(i) := 'MEA*PD*WD*' || ll_coil_width;
      i := i + 1;

      /*
      IF (skidinfo_rec.sheet_theoretical_wt IS NULL) OR
         (skidinfo_rec.sheet_theoretical_wt = 0) THEN
        x12_table(i) := 'MEA*PD*G*' || to_char(ll_shipment_gt) || '*01';
        i := i + 1;
      ELSE
        x12_table(i) := 'MEA*PD*G*' ||
                        to_char(skidinfo_rec.sheet_theoretical_wt) || '*01';
        i := i + 1;
      END IF;
      */
      --end if;

      -- fill in lot num
      /*
      SELECT COUNT(*)
        INTO li_rc
        FROM sheet_skid_detail
       WHERE sheet_skid_detail.sheet_skid_num = skidinfo_rec.sheet_skid_num;

      ls_lot_num := skidinfo_rec.lot_num;
      ls_coil_id := skidinfo_rec.coil_id;

      IF li_rc = 1 THEN
        SELECT lot_num, coil_org_num
          INTO ls_lot_num, ls_coil_id
          FROM coil
         WHERE coil.coil_abc_num =
               (SELECT coil_abc_num
                  FROM production_sheet_item
                 WHERE production_sheet_item.prod_item_num =
                       (SELECT prod_item_num
                          FROM sheet_skid_detail
                         WHERE sheet_skid_detail.sheet_skid_num =
                               skidinfo_rec.sheet_skid_num));
      END IF;
      */
      --if li_des_sh_cust_id = 1251   --Eagle need coil ID here instead of lot number
      --then
      --x12_table(i) :=  'REF*HC*' || skidinfo_rec.coil_id ; i := i +1;
      --else
                        
      --Alex Gerlants. 10/18/2018. Changed from "REF*HC" to "REF*BT"
      x12_table(i) := 'REF*BT*' || ls_lot_num;
      i := i + 1;
      --end if;

      --x12_table(i) := 'REF*LS*' || to_char(skidinfo_rec.sheet_skid_num);
      --Alex Gerlants. 10/18/2018. Changed from "REF*LS" to "REF*SE"
      x12_table(i) := 'REF*SE*' || skidinfo_rec.sheet_skid_display_num; --added by Victor H. on 06-2012 for Novelis locatio code request
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      x12_table(i) := 'REF*LS*' || ls_coil_org_num;
      i := i + 1;
      
      li_hl01 := li_hl01 + 1;
      li_rowcount := alcan_ford_856_cur%ROWCOUNT;
      x12_table(li_td1) := 'TD1*PLT90*' || to_char(li_rowcount);
  END LOOP; --End of 'FOR skidinfo_rec IN alcan_ford_856_cur LOOP'
  --Skid loop end ------------------------------------------------------------------

  -- DBMS_OUTPUT.PUT_LINE ('rowcount' || to_char(li_rowcount));

  -- if li_des_sh_cust_id = 1096 or li_des_sh_cust_id = 1251 then
  --   x12_table(i) :=  'CTT*' || to_char(li_HL01 - 1) ||'*' || to_char(ll_shipment_pc*2) ;
  --   i := i +1;
  -- else
  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                  to_char(li_rowcount + ll_shipment_pc);
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  -- Write X.12 to file
  -- To FORD

  /** Write file to /templar/templar/incoming/senddata
  /*
  **/

  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  --edi_file:= 'S_alcan_ford_ford_' || to_char(ll_edi_file_id) ||'.x12';

  -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
  -- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
    --        v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
  END LOOP;
  utl_file.fclose(edi_file_handle);

  --To ALCAN

  /*
  SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;
  SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id_alcan FROM DUAL;
  edi_file:= 'S_alcan_ford_alcan_' || to_char(ll_edi_file_id_alcan) ||'.x12';
  edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');
  x12_table(0) := 'ISA*00*'||'          *00*          *01*039630926T     *09*0015049350011G *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0')||'*0*P**';
  x12_table(1) := 'GS*SH*R0P7A*'||'001504935001' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  x12_table(i-1) :=  'GE*1*' || to_char (ll_gs_log);
  x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');
  for j in 0..i loop
   UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
       v_edi_text_alcan:=v_edi_text_alcan||x12_table(j)||CHR(10);
  end loop;
  UTL_FILE.FCLOSE(edi_file_handle);

  */

  /* The following code added by Tony, for update archive*/

  --  INSERT INTO edi_log (edi_log_timestamp,customer_id,
  --         customer_edi_name,edi_log_contents,edi_file_id,edi_text)
  --    VALUES (SYSDATE,li_customer_id,ll_customer_edi_name,
  --           'EDI:'||ll_customer_edi_name||' generated successfully.',ll_edi_file_id,v_edi_text);
  --   COMMIT;

  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  /*
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE,
         edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;
*/   
--  COMMIT;

  /* --added by Victor Huang on 06/05 for function acknowlegement
  INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
  VALUES(ll_gs_log, ls_su, sysdate, edi_file);
  COMMIT;*/

  --added by Victor Huang on 12/07 for verifying 997
  INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (ll_edi_file_id,
     '039630926',
     ls_su,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856');
  COMMIT;

  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  --exception
  --   when invalid_operation
  --   then
  --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

  --  when others
  --  then
  --      DBMS_OUTPUT.PUT_LINE ('System Error');
  --      UTL_FILE.FCLOSE(edi_file_handle);

  RETURN 1;
END edi_novelis_856_X12_10012019;
--------------------------------------------------------
--  DDL for Function EDI_NOVELIS_856_X12_ALEX
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_NOVELIS_856_X12_ALEX" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*
  Aluminum Blanking: Ford Supplier Code: ZZ R0P7A
                     DUNS: 01 039630926T
  Customer: ALCAN(34,35,10,1153)
  Alcan Rolled Product    X.121       0015049350011G
  End User: Ford (ZZ F159B)
            Ford Chicago Stamping Plant(51) MS02A
            Ford Walton Hills Stamping Plant(77) MS03A
            Ford Woodhaven Stamping Plant(71) AF30A MS09A
            Ford Maumee Stamping Plant(78)    AF06A MS08A

            Budd Company (Customer ID: 1096) B821L
            Eagle Steel (1251) MZF6B
            (not in use)Ford Monroe Stamping              AP06A

            (not in use) Warehouses: IDS(41)               R5G3B
            (not in use) Wayne Steel Distribution Center(79) RWSDC

  */

  --v_edi_text_ford varchar2(32767);
  --v_edi_text_alcan varchar2(32767);
  --ll_customer_edi_name VARCHAR2(20);

   --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50);

  --edi_loc varchar2(50):='/tmp';
  edi_file        VARCHAR2(50) := 'edi_out.txt';
  --edi_file_prefix VARCHAR2(50) := 'S_novelis_856_'; --Production
  edi_file_prefix VARCHAR2(50) := 's_novelis_856_'; --Development
  edi_file_handle utl_file.file_type;

  li_customer_id    shipment.customer_id%TYPE;
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;

  -- ls_sender_vanid varchar2 (50);
  -- ls_receiver_vanid varchar2 (50);
  -- ls_customer_vanid varchar2(50);
  -- ls_receiver_gs03 varchar2(50);
  -- ls_customer_gs03 varchar2(50);
  --ls_st varchar2(50);
  ls_sf VARCHAR2(50);
  ls_eq_type VARCHAR2(10);  -- Added by Patrick Reynolds 11/30/2016
  ls_su      VARCHAR2(50);
  ls_st_duns VARCHAR2(50);
  ls_po      VARCHAR2(30);
  ls_auth_code   VARCHAR2(32);
  ll_gs_log  INTEGER;
  ll_st_log  INTEGER;
  ll_bsn_log INTEGER;

  ls_today VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD'); --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  ls_today_2digits_year VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD'); --Alex Gerlants. 10/16/2018. Test
  ls_now   VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  li_rowcount INTEGER;
  li_hl01 INTEGER;
  ll_shipment_nt INTEGER;
  ll_shipment_gt INTEGER;
  ll_shipment_pc INTEGER;
  li_td1 INTEGER;
  li_rc  INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_vehicle_id_prefix VARCHAR2(50);  -- Added by Patrick Reynolds 11/30/2016
  ls_scac              carrier.scac%TYPE;
  ls_carrier_full_name VARCHAR2(18);
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_carrier_initial   VARCHAR2(50);  -- Not used in stored procedure.  Discovered by Patrick Reynolds 11/30/2016
  ldt_shipment         DATE;
   ll_temp         INTEGER;
  ls_enduser_part VARCHAR2(50);
  li_des_id       INTEGER;

  ll_edi_file_id INTEGER;

  ls_lot_num VARCHAR2(32);
  ls_coil_id VARCHAR2(32);
  ls_des_cust_name VARCHAR2(18);
  
  ls_coil_org_num		        coil.coil_org_num%TYPE; --Alex Gerlants. 01/25/2019
  ll_coil_gauge		          coil.coil_gauge%TYPE;   --Alex Gerlants. 01/25/2019
  ll_coil_width		          coil.coil_width%TYPE;   --Alex Gerlants. 01/25/2019
  ld_ship_date              date;
  li_is_novelis             integer;
  ln_skid_type_if_whed      sheet_skid.skid_type_if_whed%TYPE;   --Alex Gerlants. 04/01/2019
  ls_time                   char(4); --Alex Gerlants. 01/09/2020

  CURSOR alcan_ford_856_cur IS
    SELECT sheet_packing_item.sh_packing_item,
           'MULTIPLE' lot_num,
           'MULTIPLE' coil_id,
           customer_order.orig_customer_po,
           customer_order.order_abc_num,
           customer_order.enduser_po,
           customer_order.created_date,
           order_item.order_item_num,
           order_item.enduser_part_num,
           order_item.supplier_code,
           order_item.gauge,
           sheet_skid. ab_job_num,
           sheet_skid.sheet_skid_num,
           sheet_skid.sheet_skid_display_num, --added by Victor H. on 06-2012 for Novelis locatio code request
           sheet_skid.sheet_net_wt,
           sheet_skid.sheet_tare_wt,
           sheet_skid. skid_pieces,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_theoretical_wt,
           NULL done
      FROM customer_order,
           order_item,
           sheet_skid,
           ab_job,
           shipment,
           sheet_packing_item
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
/*      
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
  --      (SHIPMENT.SHIPMENT_EDI856_DATE is NULL);
*/
  --TYPE skidinfo_tabletype IS TABLE OF alcan_ford_856_cur%ROWTYPE INDEX BY BINARY_INTEGER;
  --skidinfo_table skidinfo_tabletype;
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table    store_tabletype;
  i            BINARY_INTEGER := 0;
  skidinfo_rec alcan_ford_856_cur%ROWTYPE;

  /*CURSOR packing_list_same_bol IS
  SELECT packing_list
    FROM shipment
   WHERE bill_of_lading = ll_bill_of_lading;*/

  CURSOR c_ship_to IS
    SELECT DISTINCT des_sh_cust_id --, PACKING_LIST
      FROM shipment
     WHERE bill_of_lading = ll_bill_of_lading
       AND shipment.shipment_status = 0;
  --ORDER BY PACKING_LIST;
  
  cursor c_coil is
  select distinct 
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num,
         coil.coil_gauge,
         coil.coil_width
         --process_coil.coil_abc_num
         --outbound_edi_transaction.transaction_time,
         --outbound_edi_transaction.edi_file_name
  from   customer_order
         join order_item on order_item.order_abc_num = customer_order.order_abc_num
         join ab_job on ab_job.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
         join sheet_skid on sheet_skid.ab_job_num = ab_job.ab_job_num
         join sheet_packing_item on sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
         join shipment on shipment.packing_list = sheet_packing_item.packing_list
         join process_coil on process_coil.ab_job_num = ab_job.ab_job_num
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         --join outbound_edi_transaction on outbound_edi_transaction.edi_file_id = shipment.edi_file_id_856
  --where  shipment.packing_list = 105586 --Production
  where  shipment.packing_list = al_packing_list --Develpment
  order by
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num;

BEGIN
  
  select f_is_novelis(al_packing_list)
  into   li_is_novelis
  from   dual;
  
  if li_is_novelis = 0 then --Customer is NOT Novelis
    return 1; --Nothing to do here
  end if;
  
  select shipment_edi856_date
  into   ld_ship_date
  from   shipment
  where  shipment.packing_list = al_packing_list;
   
  if not (ld_ship_date is null) then --ASN already sent
    return 100;
  end if;

  edi_loc := dbo.get_edi_destination('EDI_DIR'); --Alex Gerlants. 11/15/2016

  -- Get Customer ID, End user ID, authorization code
  SELECT customer_id, des_sh_cust_id, nvl(shipment_athorization_code, 'NA')
    INTO li_customer_id, li_des_sh_cust_id, ls_auth_code
  FROM shipment
  WHERE shipment.packing_list = al_packing_list;
  IF NOT SQL%FOUND THEN
   RETURN - 1;
  END IF;

  -- dbms_output.put_line (to_char(li_customer_id) || '  ' || to_char(li_des_sh_cust_id) );

  IF NOT (li_customer_id IN (34, 35, 10, 1153, 1459, 2582)) -- AND (li_des_sh_cust_id IN (
  --10,41,51,69,70,71,72,77,78,79,1055,1062,1073,1086,1096,1099,1114,1112,1153,
  --1206,1251,1253,1268,1269,1270,1322,1325,1328,1331,1332,1346,1347, 1382, 1383)))
   THEN

    --***********************************************************************************************88
    --IF NOT ((li_customer_id IN (34,35,10,1153)) AND (li_des_sh_cust_id IN (SELECT CUSTOMER_ID
    --FROM CUSTOMER
    --WHERE CUSTOMER_DUNS_NUMBER_STRING is not null))) THEN

    RETURN 200;
  END IF;

  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(sheet_skid.sheet_net_wt),
         SUM(sheet_skid.sheet_net_wt) + SUM(sheet_skid.sheet_tare_wt),
         SUM(sheet_skid.skid_pieces)
    INTO ll_shipment_nt, ll_shipment_gt, ll_shipment_pc
    FROM sheet_skid, sheet_packing_item, shipment
   WHERE shipment.packing_list = sheet_packing_item.packing_list
     AND sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
     AND shipment.packing_list = al_packing_list;
  IF ll_shipment_pc = 0 THEN
    RETURN 100;
  END IF; -- empty shipment

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  -- Retrieve ABCO info
  -- ls_sender_vanid := '3010007080';
  --ls_ic := 'R0P7A';

  -- Retrieve ALCAN supply code and Ford Stamping Plant location code
  --SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf
  --FROM customer_customer  WHERE o_customer_id = li_customer_id and e_customer_id = 49;  --Ford customer_id =49

  ls_sf := '039630926';
  --SELECT NVL(communication_code,'UNKNOWN') INTO ls_st FROM customer_system
  --WHERE customer_id = li_des_sh_cust_id;

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.vehicle_id_prefix, '9999'),
         nvl(shipment.equipment_type, 'NA'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'PT'), -- Protected Trailer
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE)
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_vehicle_id_prefix,
         ls_eq_type,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_carrier_initial,
         ldt_shipment
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;

  --Check all packing_lists are done against a BOL
  /*
  for pl_rec in packing_list_same_bol loop
      select shipment.shipment_status into ll_temp from shipment
             where shipment.packing_list = pl_rec.packing_list;
      if ll_temp > 0 then
         return pl_rec.packing_list;
      end if;

  end loop;
  */
  --End of packing list checking

  SELECT nvl(customer_duns_number_string, '00000000'), customer_short_name
    INTO ls_st_duns, ls_des_cust_name
    FROM customer
   WHERE customer_id = li_des_sh_cust_id;

  IF (ls_st_duns = '00000000') THEN
    RETURN 200;
  END IF; --No Ship to DUNS

  SELECT nvl(customer_duns_number_string, '00000000')
    INTO ls_su
    FROM customer
   WHERE customer_id = li_customer_id;
  IF (ls_su = '00000000') THEN
    RETURN 200;
  END IF; --No Supplier DUNS

  -- Get SCAC(Standard Carrier Alpha Code)
  SELECT nvl(carrier.scac, 'NONE'), LPAD(carrier.carrier_full_name, 17)
    INTO ls_scac, ls_carrier_full_name
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);

  -- Get Receiver and Customer VAN ID
  -- SELECT NVL(customer_system.van_account_num, 'nothing'), NVL(customer_system.gs03, 'nothing')
  -- INTO ls_receiver_vanid, ls_receiver_gs03    -- ls_receiver_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --   (select shipment.des_sh_cust_id  from shipment  where shipment.packing_list = al_packing_list);

  -- SELECT NVL(customer_system.van_account_num, 'nothing'),NVL(customer_system.gs03, 'nothing')
  -- INTO   ls_customer_vanid, ls_customer_gs03   -- ls_customer_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --       (select shipment.customer_id from shipment where shipment.packing_list = al_packing_list);

  -- Generate Header Info.
  --x12_table(i) := 'ISA*00*'||'          *00*          *ZZ*R0P7A          *ZZ*F159B          *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0') ||'*0*P**';
  --x12_table(i) := 'GS*SH*R0P7A*'||ls_st || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  --Alex Gerlants. 10/16/2018. Changed from "00200" to "00401"
  --Production
  --x12_table(i) := 'ISA*00*' ||
  --                '          *00*          *01*039630926T     *09*0015049350011G *' ||
  --                ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
  --                lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
  
  --Development                
  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *ZZ*2NDSFTP        *ZZ*NOVLSTEST      *' ||
                  ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';
                  
  i := i + 1;

  --Alex Gerlants. 10/16/2018. Changed from "002002" to "004010"
  --Production
  --x12_table(1) := 'GS*SH*R0P7A*' || '001504935001' || '*' || ls_today || '*' ||
  --                ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  --Development
  x12_table(1) := 'GS*SH*2NDSFTP*' || 'NOVLSTEST' || '*' || ls_today || '*' ||
                 ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;
  --x12_table(i):= 'BSN*00*' || to_char(ll_bill_of_lading) || '*' || ls_today || '*' || ls_now;
  x12_table(i) := 'BSN*00*' || to_char(al_packing_list) || '*' || ls_today || '*' ||
                  ls_now;
  i := i + 1;
  
  --Alex Gerlants. 08/07/2018.
  --Changed to populate with actual ship date instead of current date and time.
  --The reason is that when we send 856 on a later date, this date is not correct.
  --x12_table(i) := 'DTM*011*' || ls_today || '*' || ls_now;
  --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  
  --Alex Gerlants. 01/09/2020. Added the IF statement below.
  --If users do not enter time part in shipment.shipment_actualed_date_time,
  --856 will have system time in 'DTM*011*' and 'DTM*017*'
  
  ls_time := to_char(ldt_shipment, 'HH24MI');
  
  if ls_time <> '0000' then --User entered time
    x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                                                        to_char(ldt_shipment, 'HH24MI');
  else --User did not enter time  
    x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                                                        to_char(sysdate, 'HH24MI');
  end if;
  i := i + 1;
  
  --Alex Gerlants. 10/18/2018. Changed from "YYMMDD" to "YYYYMMDD"
  --Moved here from the below
  if ls_time <> '0000' then --User entered time
    x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                    to_char(ldt_shipment, 'HH24MI');
  else --User did not enter time
    x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                    to_char(sysdate, 'HH24MI');
  end if;
  i := i + 1;

  -- First Level HL
  x12_table(i) := 'HL*01**S';
  i := i + 1;
  --Alex Gerlants. 10/16/2018. Changed from "MEA*PD*G*" to "MEA*WT*G*"
  x12_table(i) := 'MEA*WT*G*' || to_char(ll_shipment_gt) || '*LB';
  i := i + 1;
  x12_table(i) := 'MEA*WT*N*' || to_char(ll_shipment_nt) || '*LB';
  i := i + 1;
  x12_table(i) := 'TD1*PLT90*' || to_char(li_rowcount);
  li_td1 := i;
  i := i + 1;
  x12_table(i) := 'TD5*B*2*' || ls_scac || '*M*' || ls_carrier_full_name;
  i := i + 1;
  -- segment was modified to include trailer number.  Patrick Reynolds 11/30/2016
  x12_table(i) := 'TD3*' || ls_carrier_desc_code || '*' || ls_scac || '*' || ls_vehicle_id_prefix;
  i := i + 1;
  x12_table(i) := 'REF*BM*' || to_char(al_packing_list);
  i := i + 1;
  x12_table(i) := 'REF*PK*' || to_char(al_packing_list);
  i := i + 1;
  -- segment was modified to include equipment type.  Patrick Reynolds 11/30/2016
  x12_table(i) := 'REF*EQ*' || ls_eq_type;
  i := i + 1; --waiting for Novilis, ----tony
  --- Testing for multi order ASN ----Tony

  x12_table(i) := 'REF*MB*' || to_char(ll_bill_of_lading);
  i := i + 1;
  SELECT COUNT(*)
    INTO ll_temp
    FROM shipment
   WHERE shipment.bill_of_lading = ll_bill_of_lading
     AND shipment.shipment_status = 0;
     
  --Alex Gerlants. 10/16/2018. Removed 2 lines below
  --x12_table(i) := 'REF*SS*' || to_char(ll_temp);
  --i := i + 1;
  li_des_id := 1;
  
  --Alex Gerlants. 10/16/2018. Removed 7 lines below
  /*
  FOR c_stop IN c_ship_to LOOP
    IF li_des_sh_cust_id = c_stop.des_sh_cust_id THEN
      x12_table(i) := 'REF*QN*' || to_char(li_des_id);
      i := i + 1;
    END IF;
    li_des_id := li_des_id + 1;
  END LOOP;
  */

  /*
  IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
     x12_table(i):= 'REF*ZZ*' || ls_st;i:=i+1;
  end if;
  */

  ----Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  --x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
  --                to_char(ldt_shipment, 'HH24MI');
  --i := i + 1;
  
  x12_table(i) := 'N1*ST*' || ls_des_cust_name || '*1*' || ls_st_duns;
  i := i + 1;
  x12_table(i) := 'N1*SF*Aluminum Blanking Co*1*' || ls_sf;
  i := i + 1;
  x12_table(i) := 'N1*SU**1*' || ls_su;
  i := i + 1;

  --if not (li_des_sh_cust_id = 1096 or li_des_sh_cust_id = 1251) then
  --         x12_table(i):= 'N1*IC**92*' || ls_ic; i := i +1;        --- Deleted 04-30-03 by Tony according to alcan Julia's email
  --end if;

  --         x12_table(i):= 'N1*CN**92*' || ls_st_duns; i := i +1; --Ship to DUNs --- Deleted 04-30-03 by Tony according to alcan Julia's email

  -- Second Level HL based on End User PO( only one part# is included in one shipement per FORD's request)
  OPEN alcan_ford_856_cur;
  FETCH alcan_ford_856_cur
    INTO skidinfo_rec;
  --    ls_enduser_part := skidinfo_rec.ENDUSER_PART_NUM;
  --    ls_enduser_po := skidinfo_rec.ENDUSER_PO;

  /*
    if skidinfo_rec.ORIG_CUSTOMER_PO IN ('68Q68517') then    --Do NOT send 856 to Ford for some flipping related POs )
         edi_file_prefix := 'nosend_alcan_ford_ford';
    end if;
  */

  SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
    INTO ls_enduser_part
    FROM "ORDER_ITEM", "SHEET_SKID"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
     AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
     AND ("SHEET_SKID"."SHEET_SKID_NUM" = skidinfo_rec.sheet_skid_num);

  /*
      SELECT "CUSTOMER_ORDER"."ENDUSER_PO" into ls_enduser_po
             FROM "SHEET_SKID",
                  "CUSTOMER_ORDER"
                  WHERE ( "SHEET_SKID"."REF_ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM" ) and
                        (SHEET_SKID.SHEET_SKID_NUM = skidinfo_rec.SHEET_SKID_NUM);
  */

  x12_table(i) := 'HL*02*01*O';
  i := i + 1;
  IF ls_enduser_part IS NULL THEN
    ls_enduser_part := 'NA';
  END IF;
  x12_table(i) := 'LIN**BP*' || ls_enduser_part;
  i := i + 1;
  x12_table(i) := 'SN1**' || to_char(ll_shipment_pc) || '*EA*0';
  i := i + 1;

  --
  --ls_po := skidinfo_rec.ORIG_CUSTOMER_PO;
  SELECT "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO"
    INTO ls_po
    FROM "SHEET_SKID", "CUSTOMER_ORDER"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
         "CUSTOMER_ORDER"."ORDER_ABC_NUM")
     AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num);

  --IF INSTR(skidinfo_rec.ORIG_CUSTOMER_PO,'-') > 0
  --New PO format for Novelis SAP include '-'
  /*IF instr(ls_po, '-') > 0 THEN
    ls_po := substr(ls_po, 0, instr(ls_po, '-') - 1);
  END IF;*/

  --   IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
  x12_table(i) := 'PRF*' || ls_po || '***' ||
                  to_char(skidinfo_rec.created_date, 'YYYYMMDD');
  i := i + 1;
  --   end if;

  CLOSE alcan_ford_856_cur;

   --  Novelis SAP order number
 x12_table(i) := 'REF*IL*' || ls_auth_code;
 i := i + 1;
  --  end if;

  -- Third Level HL Under a P.O.
  li_hl01 := 3;

  --Skid loop begin ----------------------------------------------------------------
  FOR skidinfo_rec IN alcan_ford_856_cur LOOP
    
      --In case of a split skid, we are creating just 1 HL for this skid
      --with just 1 coil for this skid.
      select distinct 
             coil.coil_org_num,
             coil.coil_gauge,
             coil.coil_width,
             coil.lot_num,
             nvl(skid_type_if_whed, -1) --Alex Gerlants. 04/01/2019
      into   ls_coil_org_num,
             ll_coil_gauge,
             ll_coil_width,
             ls_lot_num,
             ln_skid_type_if_whed --Alex Gerlants. 04/01/2019
      FROM "COIL",   
           "PRODUCTION_SHEET_ITEM",   
           "SHEET_SKID",   
           "SHEET_SKID_DETAIL",   
           "PROCESS_COIL"  
     WHERE ( "COIL"."COIL_ABC_NUM" = "PRODUCTION_SHEET_ITEM"."COIL_ABC_NUM" ) and  
           ( "SHEET_SKID_DETAIL"."SHEET_SKID_NUM" = "SHEET_SKID"."SHEET_SKID_NUM" ) and  
           ( "SHEET_SKID_DETAIL"."PROD_ITEM_NUM" = "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NUM" ) and  
           ( "COIL"."COIL_ABC_NUM" = "PROCESS_COIL"."COIL_ABC_NUM" ) and  
           ( "PRODUCTION_SHEET_ITEM"."AB_JOB_NUM" = "PROCESS_COIL"."AB_JOB_NUM" ) and  
           ( (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num)  ) and
           ( (rownum = 1)  ); --We need just 1 coil for each skid
  
      --Alex Gerlants. 04/01/2019. Begin
      if ln_skid_type_if_whed > -1 then --Warehouse skid
          --Get gauge and part width
          select distinct order_item.gauge,
                 f_get_part_width_per_job(ab_job.ab_job_num) 
          into   ll_coil_gauge,
                 ll_coil_width
          from   sheet_skid
                 join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
                 join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
                 join customer_order on customer_order.order_abc_num = order_item.order_abc_num
          where  sheet_skid_num = skidinfo_rec.sheet_skid_num
          and    (order_item.gauge is not null and f_get_part_width_per_job(sheet_skid.ab_job_num) is not null)
          and    rownum = 1;
      end if;
      --Alex Gerlants. 04/01/2019. End
  
      IF length(to_char(li_hl01)) = 1 THEN
        x12_table(i) := 'HL*0' || to_char(li_hl01) || '*02*I';
        i := i + 1;
      ELSE
        x12_table(i) := 'HL*' || to_char(li_hl01) || '*02*I';
        i := i + 1;
      END IF;

      --    IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
      --       x12_table(i) := 'SN1**'||to_char(skidinfo_rec.skid_pieces)||'*EA';i:=i+1;
      --    else
      x12_table(i) := 'SN1**1*PF';
      i := i + 1;
      --    end if;

      --if li_des_sh_cust_id = 1096 -- To Budd or li_des_sh_cust_id = 1251 then
      --   then
      --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; i := i +1;
      --      x12_table(i) :=  'MEA*PD*TH*' || to_char(skidinfo_rec.sheet_net_wt) || '*24'; i := i +1;
      --elsif   li_des_sh_cust_id = 1251   --To Eagle Steel
      --  then
      --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; i := i +1;
      --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*24'; i := i +1;
      --      x12_table(i) :=  'MEA*PD*TH*' || to_char(skidinfo_rec.gauge) || '*EM'; i:=i+1;
      --    x12_table(i) :=  'MEA*PD*WD*'||'44.875'||'*IN'; i:=i+1;
      --    x12_table(i) :=  'MEA*PD*LN*'||to_char(skidinfo_rec.skid_pieces)||'*LF';  i:=i+1;
      --else  --All else, Ford dirct shiping program
                        
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*N" to "MEA*WT*N"
      x12_table(i) := 'MEA*WT*N*' || to_char(skidinfo_rec.sheet_net_wt) ||
                      '*01';
      i := i + 1;
                        
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*WT" to "MEA*CT*NL"
      x12_table(i) := 'MEA*CT*NL*' || to_char(skidinfo_rec.skid_pieces) ||
                      '*PC';
      i := i + 1;

      -- changed to all gross wt per novelis 1/30/2015
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*G" to "MEA*WT*G"
      x12_table(i) := 'MEA*WT*G*' || to_char(skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt) || '*01';
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      x12_table(i) := 'MEA*PD*GG*' || ll_coil_gauge;
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      x12_table(i) := 'MEA*PD*WD*' || ll_coil_width;
      i := i + 1;

      /*
      IF (skidinfo_rec.sheet_theoretical_wt IS NULL) OR
         (skidinfo_rec.sheet_theoretical_wt = 0) THEN
        x12_table(i) := 'MEA*PD*G*' || to_char(ll_shipment_gt) || '*01';
        i := i + 1;
      ELSE
        x12_table(i) := 'MEA*PD*G*' ||
                        to_char(skidinfo_rec.sheet_theoretical_wt) || '*01';
        i := i + 1;
      END IF;
      */
      --end if;

      -- fill in lot num
      /*
      SELECT COUNT(*)
        INTO li_rc
        FROM sheet_skid_detail
       WHERE sheet_skid_detail.sheet_skid_num = skidinfo_rec.sheet_skid_num;

      ls_lot_num := skidinfo_rec.lot_num;
      ls_coil_id := skidinfo_rec.coil_id;

      IF li_rc = 1 THEN
        SELECT lot_num, coil_org_num
          INTO ls_lot_num, ls_coil_id
          FROM coil
         WHERE coil.coil_abc_num =
               (SELECT coil_abc_num
                  FROM production_sheet_item
                 WHERE production_sheet_item.prod_item_num =
                       (SELECT prod_item_num
                          FROM sheet_skid_detail
                         WHERE sheet_skid_detail.sheet_skid_num =
                               skidinfo_rec.sheet_skid_num));
      END IF;
      */
      --if li_des_sh_cust_id = 1251   --Eagle need coil ID here instead of lot number
      --then
      --x12_table(i) :=  'REF*HC*' || skidinfo_rec.coil_id ; i := i +1;
      --else
                        
      --Alex Gerlants. 10/18/2018. Changed from "REF*HC" to "REF*BT"
      x12_table(i) := 'REF*BT*' || ls_lot_num;
      i := i + 1;
      --end if;

      --x12_table(i) := 'REF*LS*' || to_char(skidinfo_rec.sheet_skid_num);
      --Alex Gerlants. 10/18/2018. Changed from "REF*LS" to "REF*SE"
      x12_table(i) := 'REF*SE*' || skidinfo_rec.sheet_skid_display_num; --added by Victor H. on 06-2012 for Novelis locatio code request
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      x12_table(i) := 'REF*LS*' || ls_coil_org_num;
      i := i + 1;
      
      li_hl01 := li_hl01 + 1;
      li_rowcount := alcan_ford_856_cur%ROWCOUNT;
      x12_table(li_td1) := 'TD1*PLT90*' || to_char(li_rowcount);
  END LOOP; --End of 'FOR skidinfo_rec IN alcan_ford_856_cur LOOP'
  --Skid loop end ------------------------------------------------------------------

  -- DBMS_OUTPUT.PUT_LINE ('rowcount' || to_char(li_rowcount));

  -- if li_des_sh_cust_id = 1096 or li_des_sh_cust_id = 1251 then
  --   x12_table(i) :=  'CTT*' || to_char(li_HL01 - 1) ||'*' || to_char(ll_shipment_pc*2) ;
  --   i := i +1;
  -- else
  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                  to_char(li_rowcount + ll_shipment_pc);
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  -- Write X.12 to file
  -- To FORD

  /** Write file to /templar/templar/incoming/senddata
  /*
  **/

  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  --edi_file:= 'S_alcan_ford_ford_' || to_char(ll_edi_file_id) ||'.x12';

  -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
  -- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
    --        v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
  END LOOP;
  utl_file.fclose(edi_file_handle);

  --To ALCAN

  /*
  SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;
  SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id_alcan FROM DUAL;
  edi_file:= 'S_alcan_ford_alcan_' || to_char(ll_edi_file_id_alcan) ||'.x12';
  edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');
  x12_table(0) := 'ISA*00*'||'          *00*          *01*039630926T     *09*0015049350011G *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0')||'*0*P**';
  x12_table(1) := 'GS*SH*R0P7A*'||'001504935001' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  x12_table(i-1) :=  'GE*1*' || to_char (ll_gs_log);
  x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');
  for j in 0..i loop
   UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
       v_edi_text_alcan:=v_edi_text_alcan||x12_table(j)||CHR(10);
  end loop;
  UTL_FILE.FCLOSE(edi_file_handle);

  */

  /* The following code added by Tony, for update archive*/

  --  INSERT INTO edi_log (edi_log_timestamp,customer_id,
  --         customer_edi_name,edi_log_contents,edi_file_id,edi_text)
  --    VALUES (SYSDATE,li_customer_id,ll_customer_edi_name,
  --           'EDI:'||ll_customer_edi_name||' generated successfully.',ll_edi_file_id,v_edi_text);
  --   COMMIT;

  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE,
         edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;
--  COMMIT;

  /* --added by Victor Huang on 06/05 for function acknowlegement
  INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
  VALUES(ll_gs_log, ls_su, sysdate, edi_file);
  COMMIT;*/

  --added by Victor Huang on 12/07 for verifying 997
  INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (ll_edi_file_id,
     '039630926',
     ls_su,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856');
  COMMIT;

  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  --exception
  --   when invalid_operation
  --   then
  --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

  --  when others
  --  then
  --      DBMS_OUTPUT.PUT_LINE ('System Error');
  --      UTL_FILE.FCLOSE(edi_file_handle);

  RETURN 1;
END edi_novelis_856_X12_alex;
--------------------------------------------------------
--  DDL for Function EDI_NOVELIS_REJCOIL_856_RERUN
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_NOVELIS_REJCOIL_856_RERUN" (al_packing_list shipment.packing_list%TYPE)
  return integer
/*
  Returns:   integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*
  Aluminum Blanking: DUNS: 01 039630926T
  Customer: Novelis(34,35,10,1153)
  Customer Duns   X.121        0015049350011G
  */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc varchar2(50) := '/templar/templar/incoming/senddata'; --
  edi_loc varchar2(50) := dbo.get_edi_destination('EDI_DIR');
  edi_file                       VARCHAR2(50) := 'edi_out.txt'; --
  
  edi_file_prefix VARCHAR2(50) := 's_novelis_'; --Production
  --edi_file_prefix                VARCHAR2(50) := 's_novelis_'; --Development
  
  edi_file_handle utl_file.file_type; --

  li_customer_id                 shipment.customer_id%TYPE; --
  li_des_sh_cust_id              shipment.des_sh_cust_id%TYPE; --
  ll_gs_log                      integer;
  ll_st_log                      integer;
  ll_bsn_log                     integer;

  shipment_skid_count            integer;

  ls_today                       VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD'); --
  ls_now                         VARCHAR2(20) := to_char(SYSDATE, 'HH24MI'); --
  ls_today_4digits               VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD'); --

  alloy_po                       alloy_type.alcan_scrap_po%TYPE;
  ll_alloy                       alloy_type.alloy%TYPE;
  hl_order                       integer;

  li_hl01                        integer;
  ll_shipment_nt                 integer;
  ll_shipment_gt                 integer;
  ll_shipment_tt                 integer;
  po_nt                          integer;

  ll_bill_of_lading              integer;
  ls_vehicle_id                  VARCHAR2(50);
  ls_scac                        carrier.scac%TYPE;
  ls_tran_method_code            VARCHAR2(50);
  ls_carrier_desc_code           VARCHAR2(50);
  ls_caarrier_initial            VARCHAR2(50);
  su_duns                        VARCHAR2(20);
  ldt_shipment                   DATE;

  ll_edi_file_id                 integer;
  li_count                       integer;
  ld_ship_date                   date;
  ls_eq_type                     VARCHAR2(10);
  ls_customer_short_name         customer.customer_short_name%TYPE;
  ls_shipment_athorization_code  shipment.shipment_athorization_code%TYPE;
  ls_bsn_1_value                 VARCHAR2(2);
  ls_lin_3_value                 VARCHAR2(30);
  li_coil_status                 coil.coil_status%TYPE;
  ls_orig_customer_name          customer.customer_short_name%TYPE;
  ls_dest_customer_name          customer.customer_short_name%TYPE;
  ls_auth_code                   varchar2(32);
  ls_dest_duns                   varchar2(20);
  li_is_novelis                  integer;
  ls_carrier_full_name           carrier.carrier_full_name%TYPE;
  ll_coil_abc_num                coil.coil_abc_num%TYPE;

  cursor coil_info_cur is
    select coil.coil_abc_num,
           coil.coil_org_num,
           coil.lot_num,
           coil.coil_gauge,
           coil.coil_width,
           coil.coil_temper,
           coil.coil_alloy2 coil_alloy2,
           coil.net_wt_balance,
           coil.coil_status
    from   reject_coil_packing_item
           join coil on coil.coil_abc_num = reject_coil_packing_item.coil_abc_num
           join shipment on shipment.packing_list = reject_coil_packing_item.packing_list
    where  shipment.packing_list = al_packing_list;
/*

  CURSOR alcan_scrap_856_cur IS
    SELECT DISTINCT scrap_skid.scrap_alloy2
      FROM scrap_skid, shipment, scrap_packing_item
     WHERE shipment.packing_list = al_packing_list
       AND scrap_packing_item.packing_list = shipment.packing_list
       AND scrap_skid.scrap_skid_num = scrap_packing_item.scrap_skid_num;
*/

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table     store_tabletype;
  i             BINARY_INTEGER := 0;
  --coil_info_rec alcan_scrap_856_cur%ROWTYPE;

  /*
  CURSOR item_cur IS
    SELECT scrap_skid.scrap_skid_num,
           scrap_skid.scrap_alloy2,
           scrap_skid.scrap_net_wt,
           scrap_skid.scrap_tare_wt,
           coil.coil_org_num,
           coil.lot_num,
           coil.coil_gauge,
           coil.coil_width,
           coil.coil_temper,
           coil.coil_alloy2 coil_alloy
      FROM scrap_packing_item
           join scrap_skid on scrap_packing_item.scrap_skid_num = scrap_skid.scrap_skid_num
           join ab_job on ab_job.ab_job_num = scrap_skid.scrap_ab_job_num
           join process_coil on process_coil.ab_job_num = ab_job.ab_job_num
           join coil on coil.coil_abc_num = process_coil.coil_abc_num
     WHERE scrap_packing_item.packing_list = al_packing_list
       --AND scrap_packing_item.scrap_skid_num = scrap_skid.scrap_skid_num
       AND scrap_skid.scrap_alloy2 = ll_alloy
     order by scrap_skid.scrap_skid_num, coil.coil_org_num;
  */
  
  --TYPE item_table_type IS table of item_cur%ROWTYPE INDEX BY BINARY_INTEGER;
  --item_table item_table_type;
  --item_rec item_cur%ROWTYPE;

BEGIN
  
  select f_is_novelis(al_packing_list)
  into   li_is_novelis
  from   dual;
  
  if li_is_novelis = 0 then --Customer is NOT Novelis
    return 1; --Nothing to do here
  end if;
  
  /*
  select shipment_edi856_date
  into   ld_ship_date
  from   shipment
  where  shipment.packing_list = al_packing_list;
   
  if not (ld_ship_date is null) then --ASN already sent
    return 100;
  end if;
  */
  
  select customer_id, des_sh_cust_id
  into   li_customer_id, li_des_sh_cust_id
  from   shipment
  where  shipment.packing_list = al_packing_list;
  
  
  if not sql%found then --Shipment does not exist
    return - 1;
  end if;
  
  select   count(*)
  into     li_count
  from     customer
  where    customer_id = li_customer_id
  and      (
                lower(customer_full_name) like '%novelis%'
             or lower(customer_short_name) like '%novelis%'
           );

  if li_count <= 0 Then --Customer is NOT Novelis
    return 200;
  end if;

  --IF NOT (li_customer_id IN (34, 35, 10, 1153, 1459, 2582)) -- AND (li_des_sh_cust_id IN (
  ----10,41,51,69,70,71,72,77,78,79,1055,1062,1073,1086,1096,1099,1114,1112,1153,
  ----1206,1251,1253,1268,1269,1270,1322,1325,1328,1331,1332,1346,1347, 1382, 1383)))
  -- THEN
  --  RETURN 200;
  --END IF;
 

  select count(distinct coil.coil_status)
  into   li_count
  from   reject_coil_packing_item
         join coil on coil.coil_abc_num = reject_coil_packing_item.coil_abc_num
         join shipment on shipment.packing_list = reject_coil_packing_item.packing_list
  where  shipment.packing_list = al_packing_list;
  
  if li_count = 1 then --Good
    /*
    select distinct coil.coil_status
    into   li_coil_status
    from   reject_coil_packing_item
           join coil on coil.coil_abc_num = reject_coil_packing_item.coil_abc_num
           join shipment on shipment.packing_list = reject_coil_packing_item.packing_list
    where  shipment.packing_list = al_packing_list;
    */
    
    select max(coil_track.coil_pre_status)
    into   li_coil_status
    from   reject_coil_packing_item
           join coil on coil.coil_abc_num = reject_coil_packing_item.coil_abc_num
           join shipment on shipment.packing_list = reject_coil_packing_item.packing_list
           join coil_track on coil.coil_abc_num = coil_track.coil_abc_num
    where  shipment.packing_list = al_packing_list
    and    coil_track_date = (select max(coil_track_date) from coil_track where coil_abc_num = coil.coil_abc_num);
    
  else
    return 300; --We must not have coils with different status on the same packing_list
  end if;

  select customer.customer_duns_number_string, customer.customer_short_name
    INTO su_duns, ls_customer_short_name
    FROM customer
   WHERE customer.customer_id = li_customer_id;

  -- Get gs, st and bsn log sequence number
  select edi_gs_log_seq.nextval into ll_gs_log from dual;
  select edi_st_log_seq.nextval into ll_st_log from dual;
  select edi_bsn_log_seq.nextval into ll_bsn_log from dual;

  -- Get Shipment Info.

  select shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'TL'), -- Protected Trailer
         carrier.carrier_full_name,
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE),
         nvl(shipment.equipment_type, 'NA'),
         nvl(shipment.shipment_athorization_code, 'NA') shipment_athorization_code
  into   ll_bill_of_lading,
         ls_vehicle_id,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_carrier_full_name,
         ls_caarrier_initial,
         ldt_shipment,
         ls_eq_type,
         ls_shipment_athorization_code
  from   shipment
         join carrier on carrier.carrier_id = shipment.carrier_id
  where  shipment.packing_list = al_packing_list;

  
  select nvl(carrier.scac, 'NONE')
  into   ls_scac
  from   carrier
  where  carrier_id =
         (select carrier_id
          from   shipment
          where  shipment.packing_list = al_packing_list
         );
         
  -- Get Customer ID, End user ID, authorization code, custome name, and destination customer name
  SELECT shipment.customer_id, 
         shipment.des_sh_cust_id, 
         nvl(shipment_athorization_code, 'NA'), 
         orig_customer.customer_short_name, 
         dest_customer.customer_short_name,
         nvl(dest_customer.customer_duns_number_string, '00000000')
    INTO li_customer_id, 
         li_des_sh_cust_id, 
         ls_auth_code, 
         ls_orig_customer_name, 
         ls_dest_customer_name,
         ls_dest_duns
  FROM shipment
       join customer orig_customer on orig_customer.customer_id = shipment.des_sh_cust_id
       join customer dest_customer on dest_customer.customer_id = shipment.des_sh_cust_id
  WHERE shipment.packing_list = al_packing_list;
  
  IF NOT SQL%FOUND THEN
   RETURN - 1;
  END IF;
  
  IF (ls_dest_duns = '00000000') THEN
    RETURN 200;
  END IF; 

  --Production
  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *01*039630926T     *09*0015049350011G *' ||
                  ls_today || '*' || ls_now || '*U*00401*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*P**'; 

  --Development
  --x12_table(i) := 'ISA*00*' ||
  --                '          *00*          *ZZ*2NDSFTP        *ZZ*NOVLSTEST      *' ||
  --                ls_today || '*' || ls_now || '*U*00401*' ||
  --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';
                  
  i := i + 1;
  
  --Production
  x12_table(1) := 'GS*SH*R0P7A*' || '001504935001' || '*' ||
                  ls_today_4digits || '*' || ls_now || '*' ||
                  to_char(ll_gs_log) || '*X*' || '004010';
  
  --Develpment                
  --x12_table(1) := 'GS*SH*2NDSFTP*' || 'NOVLSTEST' || '*' ||
  --                ls_today_4digits || '*' || ls_now || '*' ||
  --                to_char(ll_gs_log) || '*X*' || '004010';
                  
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;  

  if li_coil_status = 14 Then --Scrap coil
    ls_bsn_1_value := '32';
    ls_lin_3_value := 'SCRAP';
    edi_file_prefix := edi_file_prefix || 'scrapcoil_';
  elsif li_coil_status = 6 or li_coil_status = 3 Then --Return or rejected coil
    ls_bsn_1_value := '00';
    ls_lin_3_value := 'RETURN';
    edi_file_prefix := edi_file_prefix || 'returncoil_';
  else --Should not happen because Coil select window on shipping screen 
       --selects coils in status 3 (Rejected), 6 (Returned), and 14 (Scrap).
       --It also is checked in f_edi_856
    ls_bsn_1_value := '??';
    ls_lin_3_value := 'ERROR: COIL ALREADY SHIPPED';
    edi_file_prefix := edi_file_prefix || 'error_coil_shipped_';
  end if;
  
  --For return colis sent to Novelis: '32'
  --For return colis sent to PSI: '00'
  x12_table(i) := 'BSN*' || ls_bsn_1_value || '*' || to_char(al_packing_list) || '*' ||
                  ls_today_4digits || '*' || ls_now;
  i := i + 1;
  x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                  to_char(ldt_shipment, 'HH24MI');
  i := i + 1;

  x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD');
  i := i + 1;

  li_hl01 := 1;
  
  select sum(coil.net_wt_balance)  
  into     ll_shipment_gt       
    from   reject_coil_packing_item
           join coil on coil.coil_abc_num = reject_coil_packing_item.coil_abc_num
           join shipment on shipment.packing_list = reject_coil_packing_item.packing_list
    where  shipment.packing_list = al_packing_list;

  -- First Level HL shipment level
  x12_table(i) := 'HL*' || to_char(li_hl01) || '**S';
  li_hl01 := li_hl01 + 1;
  i := i + 1;
  x12_table(i) := 'MEA*WT*G*' || to_char(ll_shipment_gt) || '*LB';
  i := i + 1;
  
  x12_table(i) := 'MEA*WT*N*' || to_char(ll_shipment_gt) || '*LB';
  i := i + 1;

  x12_table(i) := 'MEA*WT*T*' || to_char(0) || '*LB';
  i := i + 1;
  
  --x12_table(i) := 'MEA*CT*NOR*' || to_char(shipment_skid_count) || '*EA';
  --i := i + 1;

  --x12_table(i) := 'TD1*PLT90*' || to_char(shipment_skid_count);
  --i := i + 1;

  x12_table(i) := 'TD5*B*2*' || ls_scac || '*M*' || ls_carrier_full_name;
  i := i + 1;
   
  x12_table(i) := 'TD3*TL**' || ls_vehicle_id;
  i := i + 1;  

  x12_table(i) := 'REF*MB*' || to_char(ll_bill_of_lading);
  i := i + 1;
  
  x12_table(i) := 'REF*BM*' || to_char(al_packing_list);
  i := i + 1;

  x12_table(i) := 'REF*PK*' || to_char(al_packing_list);
  i := i + 1;

  x12_table(i) := 'REF*EQ*' || ls_eq_type;
  i := i + 1;
  
  x12_table(i) := 'FOB*PD*';
  i := i + 1;
  
  /*
  IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
     x12_table(i):= 'REF*ZZ*' || ls_st;i:=i+1;
  end if;
  */

  --x12_table(i):= 'DTM*017*' || to_char(ldt_shipment,'YYMMDD') || '*' || to_char(ldt_shipment,'HHMI');
  --i := i+1;
  --x12_table(i):= 'N1*ST**1*' || ls_st_duns; i := i +1;
  x12_table(i) := 'N1*OU*Aluminum Blanking Co*1*039630926';
  i := i + 1;

  x12_table(i) := 'N1*SF*Aluminum Blanking Co*1*039630926';
  i := i + 1;
  
  x12_table(i) := 'N1*SU**1*' || su_duns;
  i := i + 1;
  
  x12_table(i) := 'N1*ST*' || ltrim(rtrim(ls_dest_customer_name)) || '*1*' || ls_dest_duns;
  i := i + 1;

  for coil_info_rec IN coil_info_cur loop

    hl_order := li_hl01;
    x12_table(i) := 'HL*' || to_char(li_hl01) || '*1*O';
    
    li_hl01 := li_hl01 + 1;
    i := i + 1;
    
    --For scrap coil: 'SCRAP"
    --For rejected or return coil: 'RETURN"
    x12_table(i) := 'LIN**BP*' || ls_lin_3_value;
    i := i + 1;
    
    x12_table(i) := 'REF*IL*' || ls_auth_code;
     i := i + 1;
    

    --ll_alloy := coil_info_rec.coil_alloy2;
    
    /*
    select nvl(alcan_scrap_po, '6800' || ll_alloy)
    into   alloy_po
    from   alloy_type
    where  alloy = upper(rtrim(ltrim(ll_alloy)))
    and    customer_id = li_customer_id;

    select SUM(scrap_skid.scrap_net_wt)
    into   po_nt
    from   scrap_skid, scrap_packing_item
    where  scrap_packing_item.packing_list = al_packing_list
    and    scrap_packing_item.scrap_skid_num = scrap_skid.scrap_skid_num
    and    scrap_skid.scrap_alloy2 = ll_alloy;
    */
    
    --x12_table(i) := 'SN1**' || po_nt || '*01';  --01 - Actual Pounds
                                                --50 - Actual Kilograms
                                                --KG - Kilogram
                                                --LB - Pound
                                                --PF - Pallet (Lift)
    --i := i + 1;

    --x12_table(i) := 'PRF*' || alloy_po || '***' || ls_today_4digits;
    --i := i + 1;
    
    --x12_table(i) := 'REF*IL*NA';
   -- i := i + 1;
    
    --x12_table(i) := 'PER*SR*PROD CONTROL*TE*248-338-4422';
    --i := i + 1;

    --open item_cur;
    --fetch item_cur INTO item_rec;
    --FOR item_rec IN item_cur LOOP

      x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(hl_order) || '*I';
      li_hl01 := li_hl01 + 1;
      i := i + 1;
      
      x12_table(i) := 'SN1**' || to_char(coil_info_rec.net_wt_balance) || '*01'; --01 Actual Pounds
                                                                                                   --50 Actual Kilograms
                                                                                                   --KG Kilogram
                                                                                                   --LB Pound
                                                                                                   --PF Pallet (Lift)
      i := i + 1;
      
      x12_table(i) := 'PID*S*55***' || upper(rtrim(ltrim(coil_info_rec.coil_alloy2))); --55 - Alloy
                                                                      --16 - Temper
                                                                      --08 - Product
      i := i + 1;
      
      --DN Density
      --GG Gauge
      --ID Inside Diameter
      --LN Length
      --OD Outside Diameter
      --TH Thickness
      --WD Width
      
      x12_table(i) := 'MEA*PD*GG*' || to_char(coil_info_rec.coil_gauge) || '*IN';
      i := i + 1;
      
      x12_table(i) := 'MEA*PD*WD*' || to_char(coil_info_rec.coil_width) || '*IN';
      i := i + 1;
      
      x12_table(i) := 'MEA*WT*N*' || to_char(coil_info_rec.net_wt_balance) || '*LB';
      i := i + 1;
      
      x12_table(i) := 'MEA*WT*G*' || to_char(coil_info_rec.net_wt_balance) || '*LB';
      i := i + 1;
      
      x12_table(i) := 'MEA*CT*NL*1*PC';
      i := i + 1;
      
      --x12_table(i) := 'MEA*PD*N*' || to_char(item_rec.scrap_net_wt) || '*01';
      --i := i + 1;
      
      x12_table(i) := 'REF*LS*' || to_char(coil_info_rec.coil_org_num);
      i := i + 1;
      
      --x12_table(i) := 'REF*SE*' || to_char(coil_info_rec.coil_org_num);
      --i := i + 1;
      
      --x12_table(i) := 'REF*SE*' || to_char(item_rec.scrap_skid_num);
      --i := i + 1;
      
      x12_table(i) := 'REF*BT*' || to_char(coil_info_rec.lot_num);
      i := i + 1;
      
      x12_table(i) := 'REF*LT*' || to_char(coil_info_rec.lot_num);
      i := i + 1;
      
      x12_table(i) := 'REF*SE*' || to_char(coil_info_rec.lot_num);
      i := i + 1;
      
      x12_table(i) := 'DTM*206*' || to_char(sysdate, 'YYYYMMDD*HH24MI') || '*ET';
      i := i + 1;
    --END LOOP;
    --close item_cur;
    
      update    coil
      set       coil_status = 10 --Gone
      where     coil_abc_num = coil_info_rec.coil_abc_num;
      
  END LOOP;
  --close alcan_scrap_856_cur;

  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                  to_char(ll_shipment_gt);
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  -- Write X.12 to file
  -- To alcan

  /** Write file to /templar/templar/incoming/senddata
  /*
  **/

  select edi_file_id_seq.nextval INTO ll_edi_file_id from dual;
  --edi_file:= 'S_alcan_ford_ford_' || to_char(ll_edi_file_id) ||'.x12';
-- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
-- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  
  for j in 0 .. i loop
    utl_file.put_line(edi_file_handle, x12_table(j));
    --        v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
  end loop;
  
  utl_file.fclose(edi_file_handle);

  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  /*
  update shipment
  set    shipment_des_edi856_date = sysdate,
         shipment_edi856_date = sysdate,
         edi_file_id_856 = ll_edi_file_id
  where  shipment.packing_list = al_packing_list;
  
  commit;
  */

  /*--added by Victor Huang on 06/05 for function acknowlegement
    INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
    VALUES(ll_gs_log, su_duns, sysdate, edi_file);
    COMMIT;
  */
  --added by Victor Huang on 12/07 for verifying 997
  /*
  insert into outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  values
    (ll_edi_file_id,
     '039630926',
     su_duns,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856 Scrap');
     
  commit;
  */
  
  --Update coil.coil_status to 10 (Gone) here 
  --instead of updating in wf_shipment_sent() for w_shipping_2 in silverdome5.pbl
  /*
  for coil_info_rec in coil_info_cur loop
    ll_coil_abc_num := coil_info_rec.coil_abc_num;

    update	coil
    set	    coil_status = 10
    where	  coil_abc_num = ll_coil_abc_num;
  end loop;

  commit;
  */

  /*
  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856 Scrap');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);
  */

  --exception
  --   when invalid_operation
  --   then
  --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

  --  when others
  --  then
  --      DBMS_OUTPUT.PUT_LINE ('System Error');
  --      UTL_FILE.FCLOSE(edi_file_handle);

  return 1;
end edi_novelis_rejcoil_856_rerun;
--------------------------------------------------------
--  DDL for Function EDI_NOVELIS_REJCOIL_856_X12
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_NOVELIS_REJCOIL_856_X12" (al_packing_list shipment.packing_list%TYPE)
  return integer
/*
  Returns:   integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*
  Aluminum Blanking: DUNS: 01 039630926T
  Customer: Novelis(34,35,10,1153)
  Customer Duns   X.121        0015049350011G
  */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc varchar2(50) := '/templar/templar/incoming/senddata'; --
  edi_loc varchar2(50) := dbo.get_edi_destination('EDI_DIR');
  edi_file                       VARCHAR2(50) := 'edi_out.txt'; --
  
  edi_file_prefix VARCHAR2(50) := 'S_novelis_'; --Production
  --edi_file_prefix                VARCHAR2(50) := 's_novelis_'; --Development
  
  edi_file_handle utl_file.file_type; --

  li_customer_id                 shipment.customer_id%TYPE; --
  li_des_sh_cust_id              shipment.des_sh_cust_id%TYPE; --
  ll_gs_log                      integer;
  ll_st_log                      integer;
  ll_bsn_log                     integer;

  shipment_skid_count            integer;

  ls_today                       VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD'); --
  ls_now                         VARCHAR2(20) := to_char(SYSDATE, 'HH24MI'); --
  ls_today_4digits               VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD'); --

  alloy_po                       alloy_type.alcan_scrap_po%TYPE;
  ll_alloy                       alloy_type.alloy%TYPE;
  hl_order                       integer;

  li_hl01                        integer;
  ll_shipment_nt                 integer;
  ll_shipment_gt                 integer;
  ll_shipment_tt                 integer;
  po_nt                          integer;

  ll_bill_of_lading              integer;
  ls_vehicle_id                  VARCHAR2(50);
  ls_scac                        carrier.scac%TYPE;
  ls_tran_method_code            VARCHAR2(50);
  ls_carrier_desc_code           VARCHAR2(50);
  ls_caarrier_initial            VARCHAR2(50);
  su_duns                        VARCHAR2(20);
  ldt_shipment                   DATE;

  ll_edi_file_id                 integer;
  li_count                       integer;
  ld_ship_date                   date;
  ls_eq_type                     VARCHAR2(10);
  ls_customer_short_name         customer.customer_short_name%TYPE;
  ls_shipment_athorization_code  shipment.shipment_athorization_code%TYPE;
  ls_bsn_1_value                 VARCHAR2(2);
  ls_lin_3_value                 VARCHAR2(30);
  li_coil_status                 coil.coil_status%TYPE;
  ls_orig_customer_name          customer.customer_short_name%TYPE;
  ls_dest_customer_name          customer.customer_short_name%TYPE;
  ls_auth_code                   varchar2(32);
  ls_dest_duns                   varchar2(20);
  li_is_novelis                  integer;
  ls_carrier_full_name           carrier.carrier_full_name%TYPE;
  ll_coil_abc_num                coil.coil_abc_num%TYPE;

  cursor coil_info_cur is
    select coil.coil_abc_num,
           coil.coil_org_num,
           coil.lot_num,
           coil.coil_gauge,
           coil.coil_width,
           coil.coil_temper,
           coil.coil_alloy2 coil_alloy2,
           coil.net_wt_balance,
           coil.coil_status
    from   reject_coil_packing_item
           join coil on coil.coil_abc_num = reject_coil_packing_item.coil_abc_num
           join shipment on shipment.packing_list = reject_coil_packing_item.packing_list
    where  shipment.packing_list = al_packing_list;
/*

  CURSOR alcan_scrap_856_cur IS
    SELECT DISTINCT scrap_skid.scrap_alloy2
      FROM scrap_skid, shipment, scrap_packing_item
     WHERE shipment.packing_list = al_packing_list
       AND scrap_packing_item.packing_list = shipment.packing_list
       AND scrap_skid.scrap_skid_num = scrap_packing_item.scrap_skid_num;
*/

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table     store_tabletype;
  i             BINARY_INTEGER := 0;
  --coil_info_rec alcan_scrap_856_cur%ROWTYPE;

  /*
  CURSOR item_cur IS
    SELECT scrap_skid.scrap_skid_num,
           scrap_skid.scrap_alloy2,
           scrap_skid.scrap_net_wt,
           scrap_skid.scrap_tare_wt,
           coil.coil_org_num,
           coil.lot_num,
           coil.coil_gauge,
           coil.coil_width,
           coil.coil_temper,
           coil.coil_alloy2 coil_alloy
      FROM scrap_packing_item
           join scrap_skid on scrap_packing_item.scrap_skid_num = scrap_skid.scrap_skid_num
           join ab_job on ab_job.ab_job_num = scrap_skid.scrap_ab_job_num
           join process_coil on process_coil.ab_job_num = ab_job.ab_job_num
           join coil on coil.coil_abc_num = process_coil.coil_abc_num
     WHERE scrap_packing_item.packing_list = al_packing_list
       --AND scrap_packing_item.scrap_skid_num = scrap_skid.scrap_skid_num
       AND scrap_skid.scrap_alloy2 = ll_alloy
     order by scrap_skid.scrap_skid_num, coil.coil_org_num;
  */
  
  --TYPE item_table_type IS table of item_cur%ROWTYPE INDEX BY BINARY_INTEGER;
  --item_table item_table_type;
  --item_rec item_cur%ROWTYPE;

BEGIN
  
  select f_is_novelis(al_packing_list)
  into   li_is_novelis
  from   dual;
  
  if li_is_novelis = 0 then --Customer is NOT Novelis
    return 1; --Nothing to do here
  end if;
  
  select shipment_edi856_date
  into   ld_ship_date
  from   shipment
  where  shipment.packing_list = al_packing_list;
   
  if not (ld_ship_date is null) then --ASN already sent
    return 100;
  end if;

  
  select customer_id, des_sh_cust_id
  into   li_customer_id, li_des_sh_cust_id
  from   shipment
  where  shipment.packing_list = al_packing_list;
  
  
  if not sql%found then --Shipment does not exist
    return - 1;
  end if;
  
  select   count(*)
  into     li_count
  from     customer
  where    customer_id = li_customer_id
  and      (
                lower(customer_full_name) like '%novelis%'
             or lower(customer_short_name) like '%novelis%'
           );

  if li_count <= 0 Then --Customer is NOT Novelis
    return 200;
  end if;

  --IF NOT (li_customer_id IN (34, 35, 10, 1153, 1459, 2582)) -- AND (li_des_sh_cust_id IN (
  ----10,41,51,69,70,71,72,77,78,79,1055,1062,1073,1086,1096,1099,1114,1112,1153,
  ----1206,1251,1253,1268,1269,1270,1322,1325,1328,1331,1332,1346,1347, 1382, 1383)))
  -- THEN
  --  RETURN 200;
  --END IF;
 

  select count(distinct coil.coil_status)
  into   li_count
  from   reject_coil_packing_item
         join coil on coil.coil_abc_num = reject_coil_packing_item.coil_abc_num
         join shipment on shipment.packing_list = reject_coil_packing_item.packing_list
  where  shipment.packing_list = al_packing_list;
  
  if li_count = 1 then --Good
    select distinct coil.coil_status
    into   li_coil_status
    from   reject_coil_packing_item
           join coil on coil.coil_abc_num = reject_coil_packing_item.coil_abc_num
           join shipment on shipment.packing_list = reject_coil_packing_item.packing_list
    where  shipment.packing_list = al_packing_list;
  else
    return 300; --We must not have coils with different status on the same packing_list
  end if;

  select customer.customer_duns_number_string, customer.customer_short_name
    INTO su_duns, ls_customer_short_name
    FROM customer
   WHERE customer.customer_id = li_customer_id;

  -- Get gs, st and bsn log sequence number
  select edi_gs_log_seq.nextval into ll_gs_log from dual;
  select edi_st_log_seq.nextval into ll_st_log from dual;
  select edi_bsn_log_seq.nextval into ll_bsn_log from dual;

  -- Get Shipment Info.

  select shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'TL'), -- Protected Trailer
         carrier.carrier_full_name,
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE),
         nvl(shipment.equipment_type, 'NA'),
         nvl(shipment.shipment_athorization_code, 'NA') shipment_athorization_code
  into   ll_bill_of_lading,
         ls_vehicle_id,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_carrier_full_name,
         ls_caarrier_initial,
         ldt_shipment,
         ls_eq_type,
         ls_shipment_athorization_code
  from   shipment
         join carrier on carrier.carrier_id = shipment.carrier_id
  where  shipment.packing_list = al_packing_list;

  
  select nvl(carrier.scac, 'NONE')
  into   ls_scac
  from   carrier
  where  carrier_id =
         (select carrier_id
          from   shipment
          where  shipment.packing_list = al_packing_list
         );
         
  -- Get Customer ID, End user ID, authorization code, custome name, and destination customer name
  SELECT shipment.customer_id, 
         shipment.des_sh_cust_id, 
         nvl(shipment_athorization_code, 'NA'), 
         orig_customer.customer_short_name, 
         dest_customer.customer_short_name,
         nvl(dest_customer.customer_duns_number_string, '00000000')
    INTO li_customer_id, 
         li_des_sh_cust_id, 
         ls_auth_code, 
         ls_orig_customer_name, 
         ls_dest_customer_name,
         ls_dest_duns
  FROM shipment
       join customer orig_customer on orig_customer.customer_id = shipment.des_sh_cust_id
       join customer dest_customer on dest_customer.customer_id = shipment.des_sh_cust_id
  WHERE shipment.packing_list = al_packing_list;
  
  IF NOT SQL%FOUND THEN
   RETURN - 1;
  END IF;
  
  IF (ls_dest_duns = '00000000') THEN
    RETURN 200;
  END IF; 

  --Production
  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *01*039630926T     *09*0015049350011G *' ||
                  ls_today || '*' || ls_now || '*U*00401*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*P**'; 

  --Development
  --x12_table(i) := 'ISA*00*' ||
  --                '          *00*          *ZZ*2NDSFTP        *ZZ*NOVLSTEST      *' ||
  --                ls_today || '*' || ls_now || '*U*00401*' ||
  --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';
                  
  i := i + 1;
  
  --Production
  x12_table(1) := 'GS*SH*R0P7A*' || '001504935001' || '*' ||
                  ls_today_4digits || '*' || ls_now || '*' ||
                  to_char(ll_gs_log) || '*X*' || '004010';
  
  --Develpment                
  --x12_table(1) := 'GS*SH*2NDSFTP*' || 'NOVLSTEST' || '*' ||
  --                ls_today_4digits || '*' || ls_now || '*' ||
  --                to_char(ll_gs_log) || '*X*' || '004010';
                  
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;  

  if li_coil_status = 14 Then --Scrap coil
    ls_bsn_1_value := '32';
    ls_lin_3_value := 'SCRAP';
    edi_file_prefix := edi_file_prefix || 'scrapcoil_';
  elsif li_coil_status = 6 or li_coil_status = 3 Then --Return or rejected coil
    ls_bsn_1_value := '00';
    ls_lin_3_value := 'RETURN';
    edi_file_prefix := edi_file_prefix || 'returncoil_';
  else --Should not happen because Coil select window on shipping screen 
       --selects coils in status 3 (Rejected), 6 (Returned), and 14 (Scrap).
       --It also is checked in f_edi_856
    ls_bsn_1_value := '??';
    ls_lin_3_value := 'ERROR: COIL ALREADY SHIPPED';
    edi_file_prefix := edi_file_prefix || 'error_coil_shipped_';
  end if;
  
  --For return colis sent to Novelis: '32'
  --For return colis sent to PSI: '00'
  x12_table(i) := 'BSN*' || ls_bsn_1_value || '*' || to_char(al_packing_list) || '*' ||
                  ls_today_4digits || '*' || ls_now;
  i := i + 1;
  x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                  to_char(ldt_shipment, 'HH24MI');
  i := i + 1;

  x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD');
  i := i + 1;

  li_hl01 := 1;
  
  select sum(coil.net_wt_balance)  
  into     ll_shipment_gt       
    from   reject_coil_packing_item
           join coil on coil.coil_abc_num = reject_coil_packing_item.coil_abc_num
           join shipment on shipment.packing_list = reject_coil_packing_item.packing_list
    where  shipment.packing_list = al_packing_list;

  -- First Level HL shipment level
  x12_table(i) := 'HL*' || to_char(li_hl01) || '**S';
  li_hl01 := li_hl01 + 1;
  i := i + 1;
  x12_table(i) := 'MEA*WT*G*' || to_char(ll_shipment_gt) || '*LB';
  i := i + 1;
  
  x12_table(i) := 'MEA*WT*N*' || to_char(ll_shipment_gt) || '*LB';
  i := i + 1;

  x12_table(i) := 'MEA*WT*T*' || to_char(0) || '*LB';
  i := i + 1;
  
  --x12_table(i) := 'MEA*CT*NOR*' || to_char(shipment_skid_count) || '*EA';
  --i := i + 1;

  --x12_table(i) := 'TD1*PLT90*' || to_char(shipment_skid_count);
  --i := i + 1;

  x12_table(i) := 'TD5*B*2*' || ls_scac || '*M*' || ls_carrier_full_name;
  i := i + 1;
   
  x12_table(i) := 'TD3*TL**' || ls_vehicle_id;
  i := i + 1;  

  x12_table(i) := 'REF*MB*' || to_char(ll_bill_of_lading);
  i := i + 1;
  
  x12_table(i) := 'REF*BM*' || to_char(al_packing_list);
  i := i + 1;

  x12_table(i) := 'REF*PK*' || to_char(al_packing_list);
  i := i + 1;

  x12_table(i) := 'REF*EQ*' || ls_eq_type;
  i := i + 1;
  
  x12_table(i) := 'FOB*PD*';
  i := i + 1;
  
  /*
  IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
     x12_table(i):= 'REF*ZZ*' || ls_st;i:=i+1;
  end if;
  */

  --x12_table(i):= 'DTM*017*' || to_char(ldt_shipment,'YYMMDD') || '*' || to_char(ldt_shipment,'HHMI');
  --i := i+1;
  --x12_table(i):= 'N1*ST**1*' || ls_st_duns; i := i +1;
  x12_table(i) := 'N1*OU*Aluminum Blanking Co*1*039630926';
  i := i + 1;

  x12_table(i) := 'N1*SF*Aluminum Blanking Co*1*039630926';
  i := i + 1;
  
  x12_table(i) := 'N1*SU**1*' || su_duns;
  i := i + 1;
  
  x12_table(i) := 'N1*ST*' || ltrim(rtrim(ls_dest_customer_name)) || '*1*' || ls_dest_duns;
  i := i + 1;

  for coil_info_rec IN coil_info_cur loop

    hl_order := li_hl01;
    x12_table(i) := 'HL*' || to_char(li_hl01) || '*1*O';
    
    li_hl01 := li_hl01 + 1;
    i := i + 1;
    
    --For scrap coil: 'SCRAP"
    --For rejected or return coil: 'RETURN"
    x12_table(i) := 'LIN**BP*' || ls_lin_3_value;
    i := i + 1;
    
    x12_table(i) := 'REF*IL*' || ls_auth_code;
     i := i + 1;
    

    --ll_alloy := coil_info_rec.coil_alloy2;
    
    /*
    select nvl(alcan_scrap_po, '6800' || ll_alloy)
    into   alloy_po
    from   alloy_type
    where  alloy = upper(rtrim(ltrim(ll_alloy)))
    and    customer_id = li_customer_id;

    select SUM(scrap_skid.scrap_net_wt)
    into   po_nt
    from   scrap_skid, scrap_packing_item
    where  scrap_packing_item.packing_list = al_packing_list
    and    scrap_packing_item.scrap_skid_num = scrap_skid.scrap_skid_num
    and    scrap_skid.scrap_alloy2 = ll_alloy;
    */
    
    --x12_table(i) := 'SN1**' || po_nt || '*01';  --01 - Actual Pounds
                                                --50 - Actual Kilograms
                                                --KG - Kilogram
                                                --LB - Pound
                                                --PF - Pallet (Lift)
    --i := i + 1;

    --x12_table(i) := 'PRF*' || alloy_po || '***' || ls_today_4digits;
    --i := i + 1;
    
    --x12_table(i) := 'REF*IL*NA';
   -- i := i + 1;
    
    --x12_table(i) := 'PER*SR*PROD CONTROL*TE*248-338-4422';
    --i := i + 1;

    --open item_cur;
    --fetch item_cur INTO item_rec;
    --FOR item_rec IN item_cur LOOP

      x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(hl_order) || '*I';
      li_hl01 := li_hl01 + 1;
      i := i + 1;
      
      x12_table(i) := 'SN1**' || to_char(coil_info_rec.net_wt_balance) || '*01'; --01 Actual Pounds
                                                                                                   --50 Actual Kilograms
                                                                                                   --KG Kilogram
                                                                                                   --LB Pound
                                                                                                   --PF Pallet (Lift)
      i := i + 1;
      
      x12_table(i) := 'PID*S*55***' || upper(rtrim(ltrim(coil_info_rec.coil_alloy2))); --55 - Alloy
                                                                      --16 - Temper
                                                                      --08 - Product
      i := i + 1;
      
      --DN Density
      --GG Gauge
      --ID Inside Diameter
      --LN Length
      --OD Outside Diameter
      --TH Thickness
      --WD Width
      
      x12_table(i) := 'MEA*PD*GG*' || to_char(coil_info_rec.coil_gauge) || '*IN';
      i := i + 1;
      
      x12_table(i) := 'MEA*PD*WD*' || to_char(coil_info_rec.coil_width) || '*IN';
      i := i + 1;
      
      x12_table(i) := 'MEA*WT*N*' || to_char(coil_info_rec.net_wt_balance) || '*LB';
      i := i + 1;
      
      x12_table(i) := 'MEA*WT*G*' || to_char(coil_info_rec.net_wt_balance) || '*LB';
      i := i + 1;
      
      x12_table(i) := 'MEA*CT*NL*1*PC';
      i := i + 1;
      
      --x12_table(i) := 'MEA*PD*N*' || to_char(item_rec.scrap_net_wt) || '*01';
      --i := i + 1;
      
      x12_table(i) := 'REF*LS*' || to_char(coil_info_rec.coil_org_num);
      i := i + 1;
      
      --x12_table(i) := 'REF*SE*' || to_char(coil_info_rec.coil_org_num);
      --i := i + 1;
      
      --x12_table(i) := 'REF*SE*' || to_char(item_rec.scrap_skid_num);
      --i := i + 1;
      
      x12_table(i) := 'REF*BT*' || to_char(coil_info_rec.lot_num);
      i := i + 1;
      
      x12_table(i) := 'REF*LT*' || to_char(coil_info_rec.lot_num);
      i := i + 1;
      
      x12_table(i) := 'REF*SE*' || to_char(coil_info_rec.lot_num);
      i := i + 1;
      
      x12_table(i) := 'DTM*206*' || to_char(sysdate, 'YYYYMMDD*HH24MI') || '*ET';
      i := i + 1;
    --END LOOP;
    --close item_cur;
    
      update    coil
      set       coil_status = 10 --Gone
      where     coil_abc_num = coil_info_rec.coil_abc_num;
      
  END LOOP;
  --close alcan_scrap_856_cur;

  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                  to_char(ll_shipment_gt);
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  -- Write X.12 to file
  -- To alcan

  /** Write file to /templar/templar/incoming/senddata
  /*
  **/

  select edi_file_id_seq.nextval INTO ll_edi_file_id from dual;
  --edi_file:= 'S_alcan_ford_ford_' || to_char(ll_edi_file_id) ||'.x12';
-- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
-- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  
  for j in 0 .. i loop
    utl_file.put_line(edi_file_handle, x12_table(j));
    --        v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
  end loop;
  
  utl_file.fclose(edi_file_handle);

  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  update shipment
  set    shipment_des_edi856_date = sysdate,
         shipment_edi856_date = sysdate,
         edi_file_id_856 = ll_edi_file_id
  where  shipment.packing_list = al_packing_list;

  commit;

  /*--added by Victor Huang on 06/05 for function acknowlegement
    INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
    VALUES(ll_gs_log, su_duns, sysdate, edi_file);
    COMMIT;
  */
  --added by Victor Huang on 12/07 for verifying 997
  insert into outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  values
    (ll_edi_file_id,
     '039630926',
     su_duns,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856 Scrap');
     
  commit;
  
  --Update coil.coil_status to 10 (Gone) here 
  --instead of updating in wf_shipment_sent() for w_shipping_2 in silverdome5.pbl
  for coil_info_rec in coil_info_cur loop
    ll_coil_abc_num := coil_info_rec.coil_abc_num;

    update	coil
    set	    coil_status = 10
    where	  coil_abc_num = ll_coil_abc_num;
    
  end loop;

  commit;

  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856 Scrap');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  --exception
  --   when invalid_operation
  --   then
  --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

  --  when others
  --  then
  --      DBMS_OUTPUT.PUT_LINE ('System Error');
  --      UTL_FILE.FCLOSE(edi_file_handle);

  return 1;
end edi_novelis_rejcoil_856_X12;
--------------------------------------------------------
--  DDL for Function EDI_NOVELIS_SCRAP_856_RERUN
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_NOVELIS_SCRAP_856_RERUN" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*

  This is edi_alcan_alcan_scrap_856_x12_alex in Production


  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*
  Aluminum Blanking: DUNS: 01 039630926T
  Customer: ALCAN(34,35,10,1153)
  Alcan Rolled Product    X.121       0015049350011G
  */

   --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  
  edi_loc VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR'); --Alex Gerlants. CAR_10042017. Comment out for test
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/test'; --Alex Gerlants. CAR_10042017. This is test location
  
  --edi_loc varchar2(50):='/tmp';--
  edi_file        VARCHAR2(50) := 'edi_out.txt'; --
  
  edi_file_prefix VARCHAR2(50) := 's_novelis_scrap_'; --Production
  --edi_file_prefix VARCHAR2(50) := 's_novelis_scrap_'; --Development. Alex Gerlants. CAR_10042017. Changed to lower case "s"

  edi_file_handle utl_file.file_type; --

  li_customer_id    shipment.customer_id%TYPE; --
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE; --
  ll_gs_log         INTEGER;
  ll_st_log         INTEGER;
  ll_bsn_log        INTEGER;

  shipment_skid_count INTEGER;

  ls_today         VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD'); --
  ls_now           VARCHAR2(20) := to_char(SYSDATE, 'HH24MI'); --
  ls_today_4digits VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD'); --

  alloy_po alloy_type.alcan_scrap_po%TYPE;
  ll_alloy alloy_type.alloy%TYPE;
  hl_order INTEGER;

  li_hl01        INTEGER;
  ll_shipment_nt INTEGER;
  ll_shipment_gt INTEGER;
  po_nt          INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_scac              carrier.scac%TYPE;
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_caarrier_initial  VARCHAR2(50);
  su_duns              VARCHAR2(20);
  ldt_shipment         DATE;

  ll_edi_file_id       INTEGER;
  ls_orig_customer_name          customer.customer_short_name%TYPE;
  ls_dest_customer_name          customer.customer_short_name%TYPE;
  ls_auth_code                   varchar2(32);
  ls_dest_duns                   varchar2(20);
  ld_ship_date                   date;
  li_is_novelis                  integer;
  ls_carrier_full_name           carrier.carrier_full_name%TYPE;
  ls_time                   char(4); --Alex Gerlants. 01/23/2020

  CURSOR alcan_scrap_856_cur IS
    SELECT DISTINCT scrap_skid.scrap_alloy2
      FROM scrap_skid, shipment, scrap_packing_item
     WHERE shipment.packing_list = al_packing_list
       AND scrap_packing_item.packing_list = shipment.packing_list
       AND scrap_skid.scrap_skid_num = scrap_packing_item.scrap_skid_num;

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table     store_tabletype;
  i             BINARY_INTEGER := 0;
  alloyinfo_rec alcan_scrap_856_cur%ROWTYPE;

  CURSOR item_cur IS
    SELECT scrap_skid.scrap_skid_num,
           scrap_skid.scrap_skid_display_num,
           scrap_skid.scrap_alloy2,
           scrap_skid.scrap_net_wt,
           scrap_skid.scrap_tare_wt
      FROM scrap_skid, scrap_packing_item
     WHERE scrap_packing_item.packing_list = al_packing_list
       AND scrap_packing_item.scrap_skid_num = scrap_skid.scrap_skid_num
       AND scrap_skid.scrap_alloy2 = ll_alloy;

  --TYPE item_table_type IS table of item_cur%ROWTYPE INDEX BY BINARY_INTEGER;
  --item_table item_table_type;
  item_rec item_cur%ROWTYPE;

BEGIN
  
  select f_is_novelis(al_packing_list)
  into   li_is_novelis
  from   dual;
  
  if li_is_novelis = 0 then --Customer is NOT Novelis
    return 1; --Nothing to do here
  end if;
  
  /*
  select shipment_edi856_date
  into   ld_ship_date
  from   shipment
  where  shipment.packing_list = al_packing_list;
   
  if not (ld_ship_date is null) then --ASN already sent
    return 100;
  end if;
  */
  
  SELECT customer_id, des_sh_cust_id
    INTO li_customer_id, li_des_sh_cust_id
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;
  IF NOT SQL%FOUND THEN
    RETURN - 1;
  END IF;

  --Alex Gerlants. CAR_10042017. commented out IF statement below.
  /*
  IF NOT (li_customer_id IN (34, 35, 10, 1153, 1459, 2582)) -- AND (li_des_sh_cust_id IN (
  --10,41,51,69,70,71,72,77,78,79,1055,1062,1073,1086,1096,1099,1114,1112,1153,
  --1206,1251,1253,1268,1269,1270,1322,1325,1328,1331,1332,1346,1347, 1382, 1383)))
   THEN
    RETURN 200;
  END IF;
  */

  SELECT COUNT(*)
    INTO shipment_skid_count
    FROM scrap_packing_item
   WHERE packing_list = al_packing_list;

  IF shipment_skid_count = 0 THEN
    RETURN 100;
  END IF;

  SELECT customer.customer_duns_number_string
    INTO su_duns
    FROM customer
   WHERE customer.customer_id = li_customer_id;

  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(scrap_skid.scrap_net_wt),
         SUM(scrap_skid.scrap_net_wt) + SUM(scrap_skid.scrap_tare_wt)
    INTO ll_shipment_nt, ll_shipment_gt
    FROM scrap_skid, scrap_packing_item, shipment
   WHERE shipment.packing_list = scrap_packing_item.packing_list
     AND scrap_packing_item.scrap_skid_num = scrap_skid.scrap_skid_num
     AND shipment.packing_list = al_packing_list;

  IF ll_shipment_nt <= 0 THEN
    RETURN 100;
  END IF; -- empty shipment

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  -- Retrieve ABCO info
  -- ls_sender_vanid := '3010007080';
  --    ls_ic := 'R0P7A';

  -- Retrieve ALCAN supply code and Ford Stamping Plant location code
  --   SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf
  --          FROM customer_customer
  --               WHERE o_customer_id = li_customer_id and e_customer_id = 49;  --Ford customer_id =49

  --SELECT NVL(communication_code,'UNKNOWN') INTO ls_st FROM customer_system
  --WHERE customer_id = li_des_sh_cust_id;

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'TL'), -- Protected Trailer
         carrier.carrier_full_name,
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE),
         
         shipment.customer_id, 
         shipment.des_sh_cust_id, 
         nvl(shipment_athorization_code, 'NA'), 
         orig_customer.customer_short_name, 
         dest_customer.customer_short_name,
         nvl(dest_customer.customer_duns_number_string, '00000000')
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_carrier_full_name,
         ls_caarrier_initial,
         ldt_shipment,
         
         li_customer_id, 
         li_des_sh_cust_id, 
         ls_auth_code, 
         ls_orig_customer_name, 
         ls_dest_customer_name,
         ls_dest_duns
    FROM shipment
         join customer orig_customer on orig_customer.customer_id = shipment.des_sh_cust_id
         join customer dest_customer on dest_customer.customer_id = shipment.des_sh_cust_id
         join carrier on carrier.carrier_id = shipment.carrier_id
   WHERE shipment.packing_list = al_packing_list;
   
   IF (ls_dest_duns = '00000000') THEN
    RETURN 200;
   END IF;

  SELECT nvl(carrier.scac, 'NONE')
    INTO ls_scac
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);

  -- Get Resceiver and Customer VAN ID
  -- SELECT NVL(customer_system.van_account_num, 'nothing'), NVL(customer_system.gs03, 'nothing')
  -- INTO ls_receiver_vanid, ls_receiver_gs03    -- ls_receiver_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --   (select shipment.des_sh_cust_id  from shipment  where shipment.packing_list = al_packing_list);

  -- SELECT NVL(customer_system.van_account_num, 'nothing'),NVL(customer_system.gs03, 'nothing')
  -- INTO   ls_customer_vanid, ls_customer_gs03   -- ls_customer_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --       (select shipment.customer_id from shipment where shipment.packing_list = al_packing_list);

  -- Generate Header Info.
  --x12_table(i) := 'ISA*00*'||'          *00*          *ZZ*R0P7A          *ZZ*F159B          *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0') ||'*0*P**';
  --x12_table(i) := 'GS*SH*R0P7A*'||ls_st || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';

  -----------------------------------------
  -- New Code Start from here . TONY     --
  -----------------------------------------

  --Production
  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *01*039630926T     *09*0015049350011G *' ||
                  ls_today || '*' || ls_now || '*U*00401*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
  
  --Development                
  --x12_table(i) := 'ISA*00*' ||
  --                '          *00*          *ZZ*2NDSFTP        *ZZ*NOVLSTEST      *' ||
  --                ls_today || '*' || ls_now || '*U*00401*' ||
  --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';
                                    
  i := i + 1;
  
  --Production
  x12_table(1) := 'GS*SH*R0P7A*' || '001504935001' || '*' ||
                  ls_today_4digits || '*' || ls_now || '*' ||
                  to_char(ll_gs_log) || '*X*' || '004010';
   
  --Development               
  --x12_table(1) := 'GS*SH*2NDSFTP*' || 'NOVLSTEST' || '*' ||
  --                ls_today_4digits || '*' || ls_now || '*' ||
  --                to_char(ll_gs_log) || '*X*' || '004010';
                  
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'BSN*32*' || to_char(al_packing_list) || '*' ||
                  ls_today_4digits || '*' || ls_now;
  i := i + 1;
  
  --Alex Gerlants. 01/23/2020. Added the IF statement below.
  --If users do not enter time part in shipment.shipment_actualed_date_time,
  --856 will have system time in 'DTM*011*' and 'DTM*017*'
  
  ls_time := to_char(ldt_shipment, 'HH24MI');
  
  if ls_time <> '0000' then --User entered time
    x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                     to_char(ldt_shipment, 'HH24MI');
  else --User did not enter time 
    x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                     to_char(sysdate, 'HH24MI');
  end if;
  i := i + 1;

  if ls_time <> '0000' then --User entered time
    x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                    to_char(ldt_shipment, 'HH24MI');
  else --User did not enter time
    x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                    to_char(sysdate, 'HH24MI');
  end if;
  i := i + 1;

  li_hl01 := 1;

  -- First Level HL shipment level
  x12_table(i) := 'HL*' || to_char(li_hl01) || '**S';
  li_hl01 := li_hl01 + 1;
  i := i + 1;
  x12_table(i) := 'MEA*WT*G*' || to_char(ll_shipment_gt) || '*LB';
  i := i + 1;
  x12_table(i) := 'MEA*WT*N*' || to_char(ll_shipment_nt) || '*LB';
  i := i + 1;
  --x12_table(i) := 'MEA*PD**0.0000*BB';
  --i := i + 1;

  x12_table(i) := 'TD1*LIF52*' || to_char(shipment_skid_count);
  --li_td1 :=i;
  i := i + 1;
  x12_table(i) := 'TD5*B*2*' || ls_scac || '*M*' || ls_carrier_full_name;
  i := i + 1;
   
  x12_table(i) := 'TD3*TL**' || ls_vehicle_id;
  i := i + 1;
  
  x12_table(i) := 'REF*MB*' || to_char(ll_bill_of_lading);
  i := i + 1;
  x12_table(i) := 'REF*BM*' || to_char(al_packing_list);
  i := i + 1;
  x12_table(i) := 'REF*PK*' || to_char(al_packing_list);
  i := i + 1;
  x12_table(i) := 'REF*EQ*FB';
  i := i + 1;
  /*
  IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
     x12_table(i):= 'REF*ZZ*' || ls_st;i:=i+1;
  end if;
  */

  --x12_table(i):= 'DTM*017*' || to_char(ldt_shipment,'YYMMDD') || '*' || to_char(ldt_shipment,'HHMI');
  --i := i+1;
  --x12_table(i):= 'N1*ST**1*' || ls_st_duns; i := i +1;
  x12_table(i) := 'N1*OU*Aluminum Blanking Co*1*039630926';
  i := i + 1;

  x12_table(i) := 'N1*SF*Aluminum Blanking Co*1*039630926';
  i := i + 1;
  
  x12_table(i) := 'N1*SU**1*' || su_duns;
  i := i + 1;
  
  x12_table(i) := 'N1*ST*' || ltrim(rtrim(ls_dest_customer_name)) || '*1*' || ls_dest_duns;
  i := i + 1;

  --may not be needed
  --open alcan_scrap_856_cur;
  --fetch alcan_scrap_856_cur INTO alloyinfo_rec;

  --These may not be needed
  
  hl_order := li_hl01;
  x12_table(i) := 'HL*' || to_char(li_hl01) || '*1*O';
  li_hl01 := li_hl01 + 1;
  i := i + 1;
      
  x12_table(i) := 'LIN**BP*SCRAP';
  i := i + 1;
  
  SELECT SUM(scrap_skid.scrap_net_wt)
  INTO po_nt
  FROM scrap_skid, scrap_packing_item
  WHERE scrap_packing_item.packing_list = al_packing_list
  AND scrap_packing_item.scrap_skid_num = scrap_skid.scrap_skid_num;
  
  x12_table(i) := 'SN1**' || po_nt || '*01';
  i := i + 1;
  
  x12_table(i) := 'PRF*' || 'NA' || '***20030102';
  i := i + 1;
    
  x12_table(i) := 'REF*IL*' || ls_auth_code;
  i := i + 1;
  
  FOR alloyinfo_rec IN alcan_scrap_856_cur LOOP
    ll_alloy := alloyinfo_rec.scrap_alloy2;

    --open item_cur;
    --fetch item_cur INTO item_rec;
    FOR item_rec IN item_cur LOOP

      x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(hl_order) || '*I';
      li_hl01 := li_hl01 + 1;
      i := i + 1;
      x12_table(i) := 'PID*S*55***' || upper(rtrim(ltrim(ll_alloy)));
      i := i + 1;
      x12_table(i) := 'MEA*WT*G*' ||
                      to_char(item_rec.scrap_net_wt +
                              item_rec.scrap_tare_wt) || '*01';
      i := i + 1;
      x12_table(i) := 'MEA*WT*N*' || to_char(item_rec.scrap_net_wt) ||
                      '*01';
      i := i + 1;
      
      x12_table(i) := 'REF*SE*' || to_char(item_rec.scrap_skid_display_num);
      i := i + 1;
      x12_table(i) := 'REF*LS*' || to_char(item_rec.scrap_skid_display_num);
      i := i + 1;

    END LOOP;
    --close item_cur;

  END LOOP;
  --close alcan_scrap_856_cur;

  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                  to_char(ll_shipment_nt);
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  -- Write X.12 to file
  -- To alcan

  /** Write file to /templar/templar/incoming/senddata
  /*
  **/

  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  --edi_file:= 'S_alcan_ford_ford_' || to_char(ll_edi_file_id) ||'.x12';

  -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
  -- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
    --        v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
  END LOOP;
  utl_file.fclose(edi_file_handle);

  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  /*
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
     shipment_edi856_date = SYSDATE,
     edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;
   */
  --COMMIT;

  /*--added by Victor Huang on 06/05 for function acknowlegement
    INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
    VALUES(ll_gs_log, su_duns, sysdate, edi_file);
    COMMIT;
  */
  --added by Victor Huang on 12/07 for verifying 997
  
  /*
  INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (ll_edi_file_id,
     '039630926',
     su_duns,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856 Scrap');
  COMMIT;
  */
  
  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856 Scrap');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  --exception
  --   when invalid_operation
  --   then
  --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

  --  when others
  --  then
  --      DBMS_OUTPUT.PUT_LINE ('System Error');
  --      UTL_FILE.FCLOSE(edi_file_handle);

  RETURN 1;
END edi_novelis_scrap_856_rerun;
--------------------------------------------------------
--  DDL for Function EDI_NOVELIS_SCRAP_856_X12
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_NOVELIS_SCRAP_856_X12" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*

  This is edi_alcan_alcan_scrap_856_x12_alex in Production


  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*
  Aluminum Blanking: DUNS: 01 039630926T
  Customer: ALCAN(34,35,10,1153)
  Alcan Rolled Product    X.121       0015049350011G
  */

   --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  
  edi_loc VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR'); --Alex Gerlants. CAR_10042017. Comment out for test
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/test'; --Alex Gerlants. CAR_10042017. This is test location
  
  --edi_loc varchar2(50):='/tmp';--
  edi_file        VARCHAR2(50) := 'edi_out.txt'; --
  
  edi_file_prefix VARCHAR2(50) := 'S_novelis_scrap_'; --Production
  --edi_file_prefix VARCHAR2(50) := 's_novelis_scrap_'; --Development. Alex Gerlants. CAR_10042017. Changed to lower case "s"

  edi_file_handle utl_file.file_type; --

  li_customer_id    shipment.customer_id%TYPE; --
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE; --
  ll_gs_log         INTEGER;
  ll_st_log         INTEGER;
  ll_bsn_log        INTEGER;

  shipment_skid_count INTEGER;

  ls_today         VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD'); --
  ls_now           VARCHAR2(20) := to_char(SYSDATE, 'HH24MI'); --
  ls_today_4digits VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD'); --

  alloy_po alloy_type.alcan_scrap_po%TYPE;
  ll_alloy alloy_type.alloy%TYPE;
  hl_order INTEGER;

  li_hl01        INTEGER;
  ll_shipment_nt INTEGER;
  ll_shipment_gt INTEGER;
  po_nt          INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_scac              carrier.scac%TYPE;
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_caarrier_initial  VARCHAR2(50);
  su_duns              VARCHAR2(20);
  ldt_shipment         DATE;

  ll_edi_file_id       INTEGER;
  ls_orig_customer_name          customer.customer_short_name%TYPE;
  ls_dest_customer_name          customer.customer_short_name%TYPE;
  ls_auth_code                   varchar2(32);
  ls_dest_duns                   varchar2(20);
  ld_ship_date                   date;
  li_is_novelis                  integer;
  ls_carrier_full_name           carrier.carrier_full_name%TYPE;
  ls_time                   char(4); --Alex Gerlants. 01/23/2020

  CURSOR alcan_scrap_856_cur IS
    SELECT DISTINCT scrap_skid.scrap_alloy2
      FROM scrap_skid, shipment, scrap_packing_item
     WHERE shipment.packing_list = al_packing_list
       AND scrap_packing_item.packing_list = shipment.packing_list
       AND scrap_skid.scrap_skid_num = scrap_packing_item.scrap_skid_num;

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table     store_tabletype;
  i             BINARY_INTEGER := 0;
  alloyinfo_rec alcan_scrap_856_cur%ROWTYPE;

  CURSOR item_cur IS
    SELECT scrap_skid.scrap_skid_num,
           scrap_skid.scrap_skid_display_num,
           scrap_skid.scrap_alloy2,
           scrap_skid.scrap_net_wt,
           scrap_skid.scrap_tare_wt
      FROM scrap_skid, scrap_packing_item
     WHERE scrap_packing_item.packing_list = al_packing_list
       AND scrap_packing_item.scrap_skid_num = scrap_skid.scrap_skid_num
       AND scrap_skid.scrap_alloy2 = ll_alloy;

  --TYPE item_table_type IS table of item_cur%ROWTYPE INDEX BY BINARY_INTEGER;
  --item_table item_table_type;
  item_rec item_cur%ROWTYPE;

BEGIN
  
  select f_is_novelis(al_packing_list)
  into   li_is_novelis
  from   dual;
  
  if li_is_novelis = 0 then --Customer is NOT Novelis
    return 1; --Nothing to do here
  end if;
  
  select shipment_edi856_date
  into   ld_ship_date
  from   shipment
  where  shipment.packing_list = al_packing_list;
   
  if not (ld_ship_date is null) then --ASN already sent
    return 100;
  end if;
  
  SELECT customer_id, des_sh_cust_id
    INTO li_customer_id, li_des_sh_cust_id
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;
  IF NOT SQL%FOUND THEN
    RETURN - 1;
  END IF;

  --Alex Gerlants. CAR_10042017. commented out IF statement below.
  /*
  IF NOT (li_customer_id IN (34, 35, 10, 1153, 1459, 2582)) -- AND (li_des_sh_cust_id IN (
  --10,41,51,69,70,71,72,77,78,79,1055,1062,1073,1086,1096,1099,1114,1112,1153,
  --1206,1251,1253,1268,1269,1270,1322,1325,1328,1331,1332,1346,1347, 1382, 1383)))
   THEN
    RETURN 200;
  END IF;
  */

  SELECT COUNT(*)
    INTO shipment_skid_count
    FROM scrap_packing_item
   WHERE packing_list = al_packing_list;

  IF shipment_skid_count = 0 THEN
    RETURN 100;
  END IF;

  SELECT customer.customer_duns_number_string
    INTO su_duns
    FROM customer
   WHERE customer.customer_id = li_customer_id;

  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(scrap_skid.scrap_net_wt),
         SUM(scrap_skid.scrap_net_wt) + SUM(scrap_skid.scrap_tare_wt)
    INTO ll_shipment_nt, ll_shipment_gt
    FROM scrap_skid, scrap_packing_item, shipment
   WHERE shipment.packing_list = scrap_packing_item.packing_list
     AND scrap_packing_item.scrap_skid_num = scrap_skid.scrap_skid_num
     AND shipment.packing_list = al_packing_list;

  IF ll_shipment_nt <= 0 THEN
    RETURN 100;
  END IF; -- empty shipment

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  -- Retrieve ABCO info
  -- ls_sender_vanid := '3010007080';
  --    ls_ic := 'R0P7A';

  -- Retrieve ALCAN supply code and Ford Stamping Plant location code
  --   SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf
  --          FROM customer_customer
  --               WHERE o_customer_id = li_customer_id and e_customer_id = 49;  --Ford customer_id =49

  --SELECT NVL(communication_code,'UNKNOWN') INTO ls_st FROM customer_system
  --WHERE customer_id = li_des_sh_cust_id;

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'TL'), -- Protected Trailer
         carrier.carrier_full_name,
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE),
         
         shipment.customer_id, 
         shipment.des_sh_cust_id, 
         nvl(shipment_athorization_code, 'NA'), 
         orig_customer.customer_short_name, 
         dest_customer.customer_short_name,
         nvl(dest_customer.customer_duns_number_string, '00000000')
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_carrier_full_name,
         ls_caarrier_initial,
         ldt_shipment,
         
         li_customer_id, 
         li_des_sh_cust_id, 
         ls_auth_code, 
         ls_orig_customer_name, 
         ls_dest_customer_name,
         ls_dest_duns
    FROM shipment
         join customer orig_customer on orig_customer.customer_id = shipment.des_sh_cust_id
         join customer dest_customer on dest_customer.customer_id = shipment.des_sh_cust_id
         join carrier on carrier.carrier_id = shipment.carrier_id
   WHERE shipment.packing_list = al_packing_list;
   
   IF (ls_dest_duns = '00000000') THEN
    RETURN 200;
   END IF;

  SELECT nvl(carrier.scac, 'NONE')
    INTO ls_scac
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);

  -- Get Resceiver and Customer VAN ID
  -- SELECT NVL(customer_system.van_account_num, 'nothing'), NVL(customer_system.gs03, 'nothing')
  -- INTO ls_receiver_vanid, ls_receiver_gs03    -- ls_receiver_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --   (select shipment.des_sh_cust_id  from shipment  where shipment.packing_list = al_packing_list);

  -- SELECT NVL(customer_system.van_account_num, 'nothing'),NVL(customer_system.gs03, 'nothing')
  -- INTO   ls_customer_vanid, ls_customer_gs03   -- ls_customer_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --       (select shipment.customer_id from shipment where shipment.packing_list = al_packing_list);

  -- Generate Header Info.
  --x12_table(i) := 'ISA*00*'||'          *00*          *ZZ*R0P7A          *ZZ*F159B          *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0') ||'*0*P**';
  --x12_table(i) := 'GS*SH*R0P7A*'||ls_st || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';

  -----------------------------------------
  -- New Code Start from here . TONY     --
  -----------------------------------------

  --Production
  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *01*039630926T     *09*0015049350011G *' ||
                  ls_today || '*' || ls_now || '*U*00401*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
  
  --Development                
  --x12_table(i) := 'ISA*00*' ||
  --                '          *00*          *ZZ*2NDSFTP        *ZZ*NOVLSTEST      *' ||
  --                ls_today || '*' || ls_now || '*U*00401*' ||
  --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';
                                    
  i := i + 1;
  
  --Production
  x12_table(1) := 'GS*SH*R0P7A*' || '001504935001' || '*' ||
                  ls_today_4digits || '*' || ls_now || '*' ||
                  to_char(ll_gs_log) || '*X*' || '004010';
   
  --Development               
  --x12_table(1) := 'GS*SH*2NDSFTP*' || 'NOVLSTEST' || '*' ||
  --                ls_today_4digits || '*' || ls_now || '*' ||
  --                to_char(ll_gs_log) || '*X*' || '004010';
                  
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'BSN*32*' || to_char(al_packing_list) || '*' ||
                  ls_today_4digits || '*' || ls_now;
  i := i + 1;
  
  --Alex Gerlants. 01/23/2020. Added the IF statement below.
  --If users do not enter time part in shipment.shipment_actualed_date_time,
  --856 will have system time in 'DTM*011*' and 'DTM*017*'
  
  ls_time := to_char(ldt_shipment, 'HH24MI');
  
  if ls_time <> '0000' then --User entered time
    x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                     to_char(ldt_shipment, 'HH24MI');
  else --User did not enter time 
    x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                     to_char(sysdate, 'HH24MI');
  end if;
  i := i + 1;

  if ls_time <> '0000' then --User entered time
    x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                    to_char(ldt_shipment, 'HH24MI');
  else --User did not enter time
    x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                    to_char(sysdate, 'HH24MI');
  end if;
  i := i + 1;

  li_hl01 := 1;

  -- First Level HL shipment level
  x12_table(i) := 'HL*' || to_char(li_hl01) || '**S';
  li_hl01 := li_hl01 + 1;
  i := i + 1;
  x12_table(i) := 'MEA*WT*G*' || to_char(ll_shipment_gt) || '*LB';
  i := i + 1;
  x12_table(i) := 'MEA*WT*N*' || to_char(ll_shipment_nt) || '*LB';
  i := i + 1;
  --x12_table(i) := 'MEA*PD**0.0000*BB';
  --i := i + 1;

  x12_table(i) := 'TD1*LIF52*' || to_char(shipment_skid_count);
  --li_td1 :=i;
  i := i + 1;
  x12_table(i) := 'TD5*B*2*' || ls_scac || '*M*' || ls_carrier_full_name;
  i := i + 1;
   
  x12_table(i) := 'TD3*TL**' || ls_vehicle_id;
  i := i + 1;
  
  x12_table(i) := 'REF*MB*' || to_char(ll_bill_of_lading);
  i := i + 1;
  x12_table(i) := 'REF*BM*' || to_char(al_packing_list);
  i := i + 1;
  x12_table(i) := 'REF*PK*' || to_char(al_packing_list);
  i := i + 1;
  x12_table(i) := 'REF*EQ*FB';
  i := i + 1;
  /*
  IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
     x12_table(i):= 'REF*ZZ*' || ls_st;i:=i+1;
  end if;
  */

  --x12_table(i):= 'DTM*017*' || to_char(ldt_shipment,'YYMMDD') || '*' || to_char(ldt_shipment,'HHMI');
  --i := i+1;
  --x12_table(i):= 'N1*ST**1*' || ls_st_duns; i := i +1;
  x12_table(i) := 'N1*OU*Aluminum Blanking Co*1*039630926';
  i := i + 1;

  x12_table(i) := 'N1*SF*Aluminum Blanking Co*1*039630926';
  i := i + 1;
  
  x12_table(i) := 'N1*SU**1*' || su_duns;
  i := i + 1;
  
  x12_table(i) := 'N1*ST*' || ltrim(rtrim(ls_dest_customer_name)) || '*1*' || ls_dest_duns;
  i := i + 1;

  --may not be needed
  --open alcan_scrap_856_cur;
  --fetch alcan_scrap_856_cur INTO alloyinfo_rec;

  --These may not be needed
  
  hl_order := li_hl01;
  x12_table(i) := 'HL*' || to_char(li_hl01) || '*1*O';
  li_hl01 := li_hl01 + 1;
  i := i + 1;
      
  x12_table(i) := 'LIN**BP*SCRAP';
  i := i + 1;
  
  SELECT SUM(scrap_skid.scrap_net_wt)
  INTO po_nt
  FROM scrap_skid, scrap_packing_item
  WHERE scrap_packing_item.packing_list = al_packing_list
  AND scrap_packing_item.scrap_skid_num = scrap_skid.scrap_skid_num;
  
  x12_table(i) := 'SN1**' || po_nt || '*01';
  i := i + 1;
  
  x12_table(i) := 'PRF*' || 'NA' || '***20030102';
  i := i + 1;
    
  x12_table(i) := 'REF*IL*' || ls_auth_code;
  i := i + 1;
  
  FOR alloyinfo_rec IN alcan_scrap_856_cur LOOP
    ll_alloy := alloyinfo_rec.scrap_alloy2;

    --open item_cur;
    --fetch item_cur INTO item_rec;
    FOR item_rec IN item_cur LOOP

      x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(hl_order) || '*I';
      li_hl01 := li_hl01 + 1;
      i := i + 1;
      x12_table(i) := 'PID*S*55***' || upper(rtrim(ltrim(ll_alloy)));
      i := i + 1;
      x12_table(i) := 'MEA*WT*G*' ||
                      to_char(item_rec.scrap_net_wt +
                              item_rec.scrap_tare_wt) || '*01';
      i := i + 1;
      x12_table(i) := 'MEA*WT*N*' || to_char(item_rec.scrap_net_wt) ||
                      '*01';
      i := i + 1;
      
      x12_table(i) := 'REF*SE*' || to_char(item_rec.scrap_skid_display_num);
      i := i + 1;
      x12_table(i) := 'REF*LS*' || to_char(item_rec.scrap_skid_display_num);
      i := i + 1;

    END LOOP;
    --close item_cur;

  END LOOP;
  --close alcan_scrap_856_cur;

  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                  to_char(ll_shipment_nt);
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  -- Write X.12 to file
  -- To alcan

  /** Write file to /templar/templar/incoming/senddata
  /*
  **/

  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  --edi_file:= 'S_alcan_ford_ford_' || to_char(ll_edi_file_id) ||'.x12';

  -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
  -- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
    --        v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
  END LOOP;
  utl_file.fclose(edi_file_handle);

  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
     shipment_edi856_date = SYSDATE,
     edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;
  --COMMIT;

  /*--added by Victor Huang on 06/05 for function acknowlegement
    INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
    VALUES(ll_gs_log, su_duns, sysdate, edi_file);
    COMMIT;
  */
  --added by Victor Huang on 12/07 for verifying 997
  
  INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (ll_edi_file_id,
     '039630926',
     su_duns,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856 Scrap');
  COMMIT;
  
  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856 Scrap');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  --exception
  --   when invalid_operation
  --   then
  --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

  --  when others
  --  then
  --      DBMS_OUTPUT.PUT_LINE ('System Error');
  --      UTL_FILE.FCLOSE(edi_file_handle);

  RETURN 1;
END edi_novelis_scrap_856_x12;
  GRANT EXECUTE ON "DBO"."EDI_NOVELIS_SCRAP_856_X12" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function EDI_NOVELIS_SCRAP_856_X12_ALEX
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_NOVELIS_SCRAP_856_X12_ALEX" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*

  This is edi_alcan_alcan_scrap_856_x12_alex in Production


  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*
  Aluminum Blanking: DUNS: 01 039630926T
  Customer: ALCAN(34,35,10,1153)
  Alcan Rolled Product    X.121       0015049350011G
  */

   --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  
  edi_loc VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR'); --Alex Gerlants. CAR_10042017. Comment out for test
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/test'; --Alex Gerlants. CAR_10042017. This is test location
  
  --edi_loc varchar2(50):='/tmp';--
  edi_file        VARCHAR2(50) := 'edi_out.txt'; --
  
  --edi_file_prefix VARCHAR2(50) := 'S_novelis_scrap_'; --Production
  edi_file_prefix VARCHAR2(50) := 's_novelis_scrap_'; --Development. Alex Gerlants. CAR_10042017. Changed to lower case "s"

  edi_file_handle utl_file.file_type; --

  li_customer_id    shipment.customer_id%TYPE; --
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE; --
  ll_gs_log         INTEGER;
  ll_st_log         INTEGER;
  ll_bsn_log        INTEGER;

  shipment_skid_count INTEGER;

  ls_today         VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD'); --
  ls_now           VARCHAR2(20) := to_char(SYSDATE, 'HH24MI'); --
  ls_today_4digits VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD'); --

  alloy_po alloy_type.alcan_scrap_po%TYPE;
  ll_alloy alloy_type.alloy%TYPE;
  hl_order INTEGER;

  li_hl01        INTEGER;
  ll_shipment_nt INTEGER;
  ll_shipment_gt INTEGER;
  po_nt          INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_scac              carrier.scac%TYPE;
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_caarrier_initial  VARCHAR2(50);
  su_duns              VARCHAR2(20);
  ldt_shipment         DATE;

  ll_edi_file_id       INTEGER;
  ls_orig_customer_name          customer.customer_short_name%TYPE;
  ls_dest_customer_name          customer.customer_short_name%TYPE;
  ls_auth_code                   varchar2(32);
  ls_dest_duns                   varchar2(20);
  ld_ship_date                   date;
  li_is_novelis                  integer;
  ls_carrier_full_name           carrier.carrier_full_name%TYPE;
  ls_time                   char(4); --Alex Gerlants. 01/23/2020

  CURSOR alcan_scrap_856_cur IS
    SELECT DISTINCT scrap_skid.scrap_alloy2
      FROM scrap_skid, shipment, scrap_packing_item
     WHERE shipment.packing_list = al_packing_list
       AND scrap_packing_item.packing_list = shipment.packing_list
       AND scrap_skid.scrap_skid_num = scrap_packing_item.scrap_skid_num;

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table     store_tabletype;
  i             BINARY_INTEGER := 0;
  alloyinfo_rec alcan_scrap_856_cur%ROWTYPE;

  CURSOR item_cur IS
    SELECT scrap_skid.scrap_skid_num,
           scrap_skid.scrap_skid_display_num,
           scrap_skid.scrap_alloy2,
           scrap_skid.scrap_net_wt,
           scrap_skid.scrap_tare_wt
      FROM scrap_skid, scrap_packing_item
     WHERE scrap_packing_item.packing_list = al_packing_list
       AND scrap_packing_item.scrap_skid_num = scrap_skid.scrap_skid_num
       AND scrap_skid.scrap_alloy2 = ll_alloy;

  --TYPE item_table_type IS table of item_cur%ROWTYPE INDEX BY BINARY_INTEGER;
  --item_table item_table_type;
  item_rec item_cur%ROWTYPE;

BEGIN
  
  select f_is_novelis(al_packing_list)
  into   li_is_novelis
  from   dual;
  
  if li_is_novelis = 0 then --Customer is NOT Novelis
    return 1; --Nothing to do here
  end if;
  
  select shipment_edi856_date
  into   ld_ship_date
  from   shipment
  where  shipment.packing_list = al_packing_list;
   
  if not (ld_ship_date is null) then --ASN already sent
    return 100;
  end if;
  
  SELECT customer_id, des_sh_cust_id
    INTO li_customer_id, li_des_sh_cust_id
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;
  IF NOT SQL%FOUND THEN
    RETURN - 1;
  END IF;

  --Alex Gerlants. CAR_10042017. commented out IF statement below.
  /*
  IF NOT (li_customer_id IN (34, 35, 10, 1153, 1459, 2582)) -- AND (li_des_sh_cust_id IN (
  --10,41,51,69,70,71,72,77,78,79,1055,1062,1073,1086,1096,1099,1114,1112,1153,
  --1206,1251,1253,1268,1269,1270,1322,1325,1328,1331,1332,1346,1347, 1382, 1383)))
   THEN
    RETURN 200;
  END IF;
  */

  SELECT COUNT(*)
    INTO shipment_skid_count
    FROM scrap_packing_item
   WHERE packing_list = al_packing_list;

  IF shipment_skid_count = 0 THEN
    RETURN 100;
  END IF;

  SELECT customer.customer_duns_number_string
    INTO su_duns
    FROM customer
   WHERE customer.customer_id = li_customer_id;

  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(scrap_skid.scrap_net_wt),
         SUM(scrap_skid.scrap_net_wt) + SUM(scrap_skid.scrap_tare_wt)
    INTO ll_shipment_nt, ll_shipment_gt
    FROM scrap_skid, scrap_packing_item, shipment
   WHERE shipment.packing_list = scrap_packing_item.packing_list
     AND scrap_packing_item.scrap_skid_num = scrap_skid.scrap_skid_num
     AND shipment.packing_list = al_packing_list;

  IF ll_shipment_nt <= 0 THEN
    RETURN 100;
  END IF; -- empty shipment

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  -- Retrieve ABCO info
  -- ls_sender_vanid := '3010007080';
  --    ls_ic := 'R0P7A';

  -- Retrieve ALCAN supply code and Ford Stamping Plant location code
  --   SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf
  --          FROM customer_customer
  --               WHERE o_customer_id = li_customer_id and e_customer_id = 49;  --Ford customer_id =49

  --SELECT NVL(communication_code,'UNKNOWN') INTO ls_st FROM customer_system
  --WHERE customer_id = li_des_sh_cust_id;

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'TL'), -- Protected Trailer
         carrier.carrier_full_name,
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE),
         
         shipment.customer_id, 
         shipment.des_sh_cust_id, 
         nvl(shipment_athorization_code, 'NA'), 
         orig_customer.customer_short_name, 
         dest_customer.customer_short_name,
         nvl(dest_customer.customer_duns_number_string, '00000000')
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_carrier_full_name,
         ls_caarrier_initial,
         ldt_shipment,
         
         li_customer_id, 
         li_des_sh_cust_id, 
         ls_auth_code, 
         ls_orig_customer_name, 
         ls_dest_customer_name,
         ls_dest_duns
    FROM shipment
         join customer orig_customer on orig_customer.customer_id = shipment.des_sh_cust_id
         join customer dest_customer on dest_customer.customer_id = shipment.des_sh_cust_id
         join carrier on carrier.carrier_id = shipment.carrier_id
   WHERE shipment.packing_list = al_packing_list;
   
   IF (ls_dest_duns = '00000000') THEN
    RETURN 200;
   END IF;

  SELECT nvl(carrier.scac, 'NONE')
    INTO ls_scac
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);

  -- Get Resceiver and Customer VAN ID
  -- SELECT NVL(customer_system.van_account_num, 'nothing'), NVL(customer_system.gs03, 'nothing')
  -- INTO ls_receiver_vanid, ls_receiver_gs03    -- ls_receiver_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --   (select shipment.des_sh_cust_id  from shipment  where shipment.packing_list = al_packing_list);

  -- SELECT NVL(customer_system.van_account_num, 'nothing'),NVL(customer_system.gs03, 'nothing')
  -- INTO   ls_customer_vanid, ls_customer_gs03   -- ls_customer_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --       (select shipment.customer_id from shipment where shipment.packing_list = al_packing_list);

  -- Generate Header Info.
  --x12_table(i) := 'ISA*00*'||'          *00*          *ZZ*R0P7A          *ZZ*F159B          *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0') ||'*0*P**';
  --x12_table(i) := 'GS*SH*R0P7A*'||ls_st || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';

  -----------------------------------------
  -- New Code Start from here . TONY     --
  -----------------------------------------

  --Production
  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *01*039630926T     *09*0015049350011G *' ||
                  ls_today || '*' || ls_now || '*U*00401*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
  
  --Development                
  --x12_table(i) := 'ISA*00*' ||
  --                '          *00*          *ZZ*2NDSFTP        *ZZ*NOVLSTEST      *' ||
  --                ls_today || '*' || ls_now || '*U*00401*' ||
  --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';
                                    
  i := i + 1;
  
  --Production
  x12_table(1) := 'GS*SH*R0P7A*' || '001504935001' || '*' ||
                  ls_today_4digits || '*' || ls_now || '*' ||
                  to_char(ll_gs_log) || '*X*' || '004010';
   
  --Development               
  --x12_table(1) := 'GS*SH*2NDSFTP*' || 'NOVLSTEST' || '*' ||
  --                ls_today_4digits || '*' || ls_now || '*' ||
  --                to_char(ll_gs_log) || '*X*' || '004010';
                  
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'BSN*32*' || to_char(al_packing_list) || '*' ||
                  ls_today_4digits || '*' || ls_now;
  i := i + 1;
  
  --Alex Gerlants. 01/23/2020. Added the IF statement below.
  --If users do not enter time part in shipment.shipment_actualed_date_time,
  --856 will have system time in 'DTM*011*' and 'DTM*017*'
  
  ls_time := to_char(ldt_shipment, 'HH24MI');
  
  if ls_time <> '0000' then --User entered time
    x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                     to_char(ldt_shipment, 'HH24MI');
  else --User did not enter time 
    x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                     to_char(sysdate, 'HH24MI');
  end if;
  i := i + 1;

  if ls_time <> '0000' then --User entered time
    x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                    to_char(ldt_shipment, 'HH24MI');
  else --User did not enter time
    x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                    to_char(sysdate, 'HH24MI');
  end if;
  i := i + 1;

  li_hl01 := 1;

  -- First Level HL shipment level
  x12_table(i) := 'HL*' || to_char(li_hl01) || '**S';
  li_hl01 := li_hl01 + 1;
  i := i + 1;
  x12_table(i) := 'MEA*WT*G*' || to_char(ll_shipment_gt) || '*LB';
  i := i + 1;
  x12_table(i) := 'MEA*WT*N*' || to_char(ll_shipment_nt) || '*LB';
  i := i + 1;
  --x12_table(i) := 'MEA*PD**0.0000*BB';
  --i := i + 1;

  x12_table(i) := 'TD1*LIF52*' || to_char(shipment_skid_count);
  --li_td1 :=i;
  i := i + 1;
  x12_table(i) := 'TD5*B*2*' || ls_scac || '*M*' || ls_carrier_full_name;
  i := i + 1;
   
  x12_table(i) := 'TD3*TL**' || ls_vehicle_id;
  i := i + 1;
  
  x12_table(i) := 'REF*MB*' || to_char(ll_bill_of_lading);
  i := i + 1;
  x12_table(i) := 'REF*BM*' || to_char(al_packing_list);
  i := i + 1;
  x12_table(i) := 'REF*PK*' || to_char(al_packing_list);
  i := i + 1;
  x12_table(i) := 'REF*EQ*FB';
  i := i + 1;
  /*
  IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
     x12_table(i):= 'REF*ZZ*' || ls_st;i:=i+1;
  end if;
  */

  --x12_table(i):= 'DTM*017*' || to_char(ldt_shipment,'YYMMDD') || '*' || to_char(ldt_shipment,'HHMI');
  --i := i+1;
  --x12_table(i):= 'N1*ST**1*' || ls_st_duns; i := i +1;
  x12_table(i) := 'N1*OU*Aluminum Blanking Co*1*039630926';
  i := i + 1;

  x12_table(i) := 'N1*SF*Aluminum Blanking Co*1*039630926';
  i := i + 1;
  
  x12_table(i) := 'N1*SU**1*' || su_duns;
  i := i + 1;
  
  x12_table(i) := 'N1*ST*' || ltrim(rtrim(ls_dest_customer_name)) || '*1*' || ls_dest_duns;
  i := i + 1;

  --may not be needed
  --open alcan_scrap_856_cur;
  --fetch alcan_scrap_856_cur INTO alloyinfo_rec;

  --These may not be needed
  
  hl_order := li_hl01;
  x12_table(i) := 'HL*' || to_char(li_hl01) || '*1*O';
  li_hl01 := li_hl01 + 1;
  i := i + 1;
      
  x12_table(i) := 'LIN**BP*SCRAP';
  i := i + 1;
  
  SELECT SUM(scrap_skid.scrap_net_wt)
  INTO po_nt
  FROM scrap_skid, scrap_packing_item
  WHERE scrap_packing_item.packing_list = al_packing_list
  AND scrap_packing_item.scrap_skid_num = scrap_skid.scrap_skid_num;
  
  x12_table(i) := 'SN1**' || po_nt || '*01';
  i := i + 1;
  
  x12_table(i) := 'PRF*' || 'NA' || '***20030102';
  i := i + 1;
    
  x12_table(i) := 'REF*IL*' || ls_auth_code;
  i := i + 1;
  
  FOR alloyinfo_rec IN alcan_scrap_856_cur LOOP
    ll_alloy := alloyinfo_rec.scrap_alloy2;

    --open item_cur;
    --fetch item_cur INTO item_rec;
    FOR item_rec IN item_cur LOOP

      x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(hl_order) || '*I';
      li_hl01 := li_hl01 + 1;
      i := i + 1;
      x12_table(i) := 'PID*S*55***' || upper(rtrim(ltrim(ll_alloy)));
      i := i + 1;
      x12_table(i) := 'MEA*WT*G*' ||
                      to_char(item_rec.scrap_net_wt +
                              item_rec.scrap_tare_wt) || '*01';
      i := i + 1;
      x12_table(i) := 'MEA*WT*N*' || to_char(item_rec.scrap_net_wt) ||
                      '*01';
      i := i + 1;
      
      x12_table(i) := 'REF*SE*' || to_char(item_rec.scrap_skid_display_num);
      i := i + 1;
      x12_table(i) := 'REF*LS*' || to_char(item_rec.scrap_skid_display_num);
      i := i + 1;

    END LOOP;
    --close item_cur;

  END LOOP;
  --close alcan_scrap_856_cur;

  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                  to_char(ll_shipment_nt);
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  -- Write X.12 to file
  -- To alcan

  /** Write file to /templar/templar/incoming/senddata
  /*
  **/

  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  --edi_file:= 'S_alcan_ford_ford_' || to_char(ll_edi_file_id) ||'.x12';

  -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
  -- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
    --        v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
  END LOOP;
  utl_file.fclose(edi_file_handle);

  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
     shipment_edi856_date = SYSDATE,
     edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;
  --COMMIT;

  /*--added by Victor Huang on 06/05 for function acknowlegement
    INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
    VALUES(ll_gs_log, su_duns, sysdate, edi_file);
    COMMIT;
  */
  --added by Victor Huang on 12/07 for verifying 997
  
  INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (ll_edi_file_id,
     '039630926',
     su_duns,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856 Scrap');
  COMMIT;
  
  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856 Scrap');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  --exception
  --   when invalid_operation
  --   then
  --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

  --  when others
  --  then
  --      DBMS_OUTPUT.PUT_LINE ('System Error');
  --      UTL_FILE.FCLOSE(edi_file_handle);

  RETURN 1;
END edi_novelis_scrap_856_x12_alex;
--------------------------------------------------------
--  DDL for Function EDI_NOVELIS_SCRAP_856_X12_SAVE
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_NOVELIS_SCRAP_856_X12_SAVE" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*

  This is edi_alcan_alcan_scrap_856_x12_alex in Production


  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*
  Aluminum Blanking: DUNS: 01 039630926T
  Customer: ALCAN(34,35,10,1153)
  Alcan Rolled Product    X.121       0015049350011G
  */

   --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  
  edi_loc VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR'); --Alex Gerlants. CAR_10042017. Comment out for test
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/test'; --Alex Gerlants. CAR_10042017. This is test location
  
  --edi_loc varchar2(50):='/tmp';--
  edi_file        VARCHAR2(50) := 'edi_out.txt'; --
  
  edi_file_prefix VARCHAR2(50) := 'S_novelis_scrap_'; --Production
  --edi_file_prefix VARCHAR2(50) := 's_novelis_scrap_'; --Development. Alex Gerlants. CAR_10042017. Changed to lower case "s"

  edi_file_handle utl_file.file_type; --

  li_customer_id    shipment.customer_id%TYPE; --
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE; --
  ll_gs_log         INTEGER;
  ll_st_log         INTEGER;
  ll_bsn_log        INTEGER;

  shipment_skid_count INTEGER;

  ls_today         VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD'); --
  ls_now           VARCHAR2(20) := to_char(SYSDATE, 'HH24MI'); --
  ls_today_4digits VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD'); --

  alloy_po alloy_type.alcan_scrap_po%TYPE;
  ll_alloy alloy_type.alloy%TYPE;
  hl_order INTEGER;

  li_hl01        INTEGER;
  ll_shipment_nt INTEGER;
  ll_shipment_gt INTEGER;
  po_nt          INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_scac              carrier.scac%TYPE;
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_caarrier_initial  VARCHAR2(50);
  su_duns              VARCHAR2(20);
  ldt_shipment         DATE;

  ll_edi_file_id       INTEGER;
  ls_orig_customer_name          customer.customer_short_name%TYPE;
  ls_dest_customer_name          customer.customer_short_name%TYPE;
  ls_auth_code                   varchar2(32);
  ls_dest_duns                   varchar2(20);
  ld_ship_date                   date;
  li_is_novelis                  integer;
  ls_carrier_full_name           carrier.carrier_full_name%TYPE;

  CURSOR alcan_scrap_856_cur IS
    SELECT DISTINCT scrap_skid.scrap_alloy2
      FROM scrap_skid, shipment, scrap_packing_item
     WHERE shipment.packing_list = al_packing_list
       AND scrap_packing_item.packing_list = shipment.packing_list
       AND scrap_skid.scrap_skid_num = scrap_packing_item.scrap_skid_num;

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table     store_tabletype;
  i             BINARY_INTEGER := 0;
  alloyinfo_rec alcan_scrap_856_cur%ROWTYPE;

  CURSOR item_cur IS
    SELECT scrap_skid.scrap_skid_num,
           scrap_skid.scrap_skid_display_num,
           scrap_skid.scrap_alloy2,
           scrap_skid.scrap_net_wt,
           scrap_skid.scrap_tare_wt
      FROM scrap_skid, scrap_packing_item
     WHERE scrap_packing_item.packing_list = al_packing_list
       AND scrap_packing_item.scrap_skid_num = scrap_skid.scrap_skid_num
       AND scrap_skid.scrap_alloy2 = ll_alloy;

  --TYPE item_table_type IS table of item_cur%ROWTYPE INDEX BY BINARY_INTEGER;
  --item_table item_table_type;
  item_rec item_cur%ROWTYPE;

BEGIN
  
  select f_is_novelis(al_packing_list)
  into   li_is_novelis
  from   dual;
  
  if li_is_novelis = 0 then --Customer is NOT Novelis
    return 1; --Nothing to do here
  end if;
  
  select shipment_edi856_date
  into   ld_ship_date
  from   shipment
  where  shipment.packing_list = al_packing_list;
   
  if not (ld_ship_date is null) then --ASN already sent
    return 100;
  end if;
  
  SELECT customer_id, des_sh_cust_id
    INTO li_customer_id, li_des_sh_cust_id
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;
  IF NOT SQL%FOUND THEN
    RETURN - 1;
  END IF;

  --Alex Gerlants. CAR_10042017. commented out IF statement below.
  /*
  IF NOT (li_customer_id IN (34, 35, 10, 1153, 1459, 2582)) -- AND (li_des_sh_cust_id IN (
  --10,41,51,69,70,71,72,77,78,79,1055,1062,1073,1086,1096,1099,1114,1112,1153,
  --1206,1251,1253,1268,1269,1270,1322,1325,1328,1331,1332,1346,1347, 1382, 1383)))
   THEN
    RETURN 200;
  END IF;
  */

  SELECT COUNT(*)
    INTO shipment_skid_count
    FROM scrap_packing_item
   WHERE packing_list = al_packing_list;

  IF shipment_skid_count = 0 THEN
    RETURN 100;
  END IF;

  SELECT customer.customer_duns_number_string
    INTO su_duns
    FROM customer
   WHERE customer.customer_id = li_customer_id;

  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(scrap_skid.scrap_net_wt),
         SUM(scrap_skid.scrap_net_wt) + SUM(scrap_skid.scrap_tare_wt)
    INTO ll_shipment_nt, ll_shipment_gt
    FROM scrap_skid, scrap_packing_item, shipment
   WHERE shipment.packing_list = scrap_packing_item.packing_list
     AND scrap_packing_item.scrap_skid_num = scrap_skid.scrap_skid_num
     AND shipment.packing_list = al_packing_list;

  IF ll_shipment_nt <= 0 THEN
    RETURN 100;
  END IF; -- empty shipment

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  -- Retrieve ABCO info
  -- ls_sender_vanid := '3010007080';
  --    ls_ic := 'R0P7A';

  -- Retrieve ALCAN supply code and Ford Stamping Plant location code
  --   SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf
  --          FROM customer_customer
  --               WHERE o_customer_id = li_customer_id and e_customer_id = 49;  --Ford customer_id =49

  --SELECT NVL(communication_code,'UNKNOWN') INTO ls_st FROM customer_system
  --WHERE customer_id = li_des_sh_cust_id;

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'TL'), -- Protected Trailer
         carrier.carrier_full_name,
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE),
         
         shipment.customer_id, 
         shipment.des_sh_cust_id, 
         nvl(shipment_athorization_code, 'NA'), 
         orig_customer.customer_short_name, 
         dest_customer.customer_short_name,
         nvl(dest_customer.customer_duns_number_string, '00000000')
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_carrier_full_name,
         ls_caarrier_initial,
         ldt_shipment,
         
         li_customer_id, 
         li_des_sh_cust_id, 
         ls_auth_code, 
         ls_orig_customer_name, 
         ls_dest_customer_name,
         ls_dest_duns
    FROM shipment
         join customer orig_customer on orig_customer.customer_id = shipment.des_sh_cust_id
         join customer dest_customer on dest_customer.customer_id = shipment.des_sh_cust_id
         join carrier on carrier.carrier_id = shipment.carrier_id
   WHERE shipment.packing_list = al_packing_list;
   
   IF (ls_dest_duns = '00000000') THEN
    RETURN 200;
   END IF;

  SELECT nvl(carrier.scac, 'NONE')
    INTO ls_scac
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);

  -- Get Resceiver and Customer VAN ID
  -- SELECT NVL(customer_system.van_account_num, 'nothing'), NVL(customer_system.gs03, 'nothing')
  -- INTO ls_receiver_vanid, ls_receiver_gs03    -- ls_receiver_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --   (select shipment.des_sh_cust_id  from shipment  where shipment.packing_list = al_packing_list);

  -- SELECT NVL(customer_system.van_account_num, 'nothing'),NVL(customer_system.gs03, 'nothing')
  -- INTO   ls_customer_vanid, ls_customer_gs03   -- ls_customer_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --       (select shipment.customer_id from shipment where shipment.packing_list = al_packing_list);

  -- Generate Header Info.
  --x12_table(i) := 'ISA*00*'||'          *00*          *ZZ*R0P7A          *ZZ*F159B          *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0') ||'*0*P**';
  --x12_table(i) := 'GS*SH*R0P7A*'||ls_st || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';

  -----------------------------------------
  -- New Code Start from here . TONY     --
  -----------------------------------------

  --Production
  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *01*039630926T     *09*0015049350011G *' ||
                  ls_today || '*' || ls_now || '*U*00401*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
  
  --Development                
  --x12_table(i) := 'ISA*00*' ||
  --                '          *00*          *ZZ*2NDSFTP        *ZZ*NOVLSTEST      *' ||
  --                ls_today || '*' || ls_now || '*U*00401*' ||
  --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';
                                    
  i := i + 1;
  
  --Production
  x12_table(1) := 'GS*SH*R0P7A*' || '001504935001' || '*' ||
                  ls_today_4digits || '*' || ls_now || '*' ||
                  to_char(ll_gs_log) || '*X*' || '004010';
   
  --Development               
  --x12_table(1) := 'GS*SH*2NDSFTP*' || 'NOVLSTEST' || '*' ||
  --                ls_today_4digits || '*' || ls_now || '*' ||
  --                to_char(ll_gs_log) || '*X*' || '004010';
                  
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'BSN*32*' || to_char(al_packing_list) || '*' ||
                  ls_today_4digits || '*' || ls_now;
  i := i + 1;
  x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                  to_char(ldt_shipment, 'HH24MI');
  i := i + 1;

  x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD');
  i := i + 1;

  li_hl01 := 1;

  -- First Level HL shipment level
  x12_table(i) := 'HL*' || to_char(li_hl01) || '**S';
  li_hl01 := li_hl01 + 1;
  i := i + 1;
  x12_table(i) := 'MEA*WT*G*' || to_char(ll_shipment_gt) || '*LB';
  i := i + 1;
  x12_table(i) := 'MEA*WT*N*' || to_char(ll_shipment_nt) || '*LB';
  i := i + 1;
  --x12_table(i) := 'MEA*PD**0.0000*BB';
  --i := i + 1;

  x12_table(i) := 'TD1*LIF52*' || to_char(shipment_skid_count);
  --li_td1 :=i;
  i := i + 1;
  x12_table(i) := 'TD5*B*2*' || ls_scac || '*M*' || ls_carrier_full_name;
  i := i + 1;
   
  x12_table(i) := 'TD3*TL**' || ls_vehicle_id;
  i := i + 1;
  
  x12_table(i) := 'REF*MB*' || to_char(ll_bill_of_lading);
  i := i + 1;
  x12_table(i) := 'REF*BM*' || to_char(al_packing_list);
  i := i + 1;
  x12_table(i) := 'REF*PK*' || to_char(al_packing_list);
  i := i + 1;
  x12_table(i) := 'REF*EQ*FB';
  i := i + 1;
  /*
  IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
     x12_table(i):= 'REF*ZZ*' || ls_st;i:=i+1;
  end if;
  */

  --x12_table(i):= 'DTM*017*' || to_char(ldt_shipment,'YYMMDD') || '*' || to_char(ldt_shipment,'HHMI');
  --i := i+1;
  --x12_table(i):= 'N1*ST**1*' || ls_st_duns; i := i +1;
  x12_table(i) := 'N1*OU*Aluminum Blanking Co*1*039630926';
  i := i + 1;

  x12_table(i) := 'N1*SF*Aluminum Blanking Co*1*039630926';
  i := i + 1;
  
  x12_table(i) := 'N1*SU**1*' || su_duns;
  i := i + 1;
  
  x12_table(i) := 'N1*ST*' || ltrim(rtrim(ls_dest_customer_name)) || '*1*' || ls_dest_duns;
  i := i + 1;

  --may not be needed
  --open alcan_scrap_856_cur;
  --fetch alcan_scrap_856_cur INTO alloyinfo_rec;

  --These may not be needed
  
  hl_order := li_hl01;
  x12_table(i) := 'HL*' || to_char(li_hl01) || '*1*O';
  li_hl01 := li_hl01 + 1;
  i := i + 1;
      
  x12_table(i) := 'LIN**BP*SCRAP';
  i := i + 1;
  
  SELECT SUM(scrap_skid.scrap_net_wt)
  INTO po_nt
  FROM scrap_skid, scrap_packing_item
  WHERE scrap_packing_item.packing_list = al_packing_list
  AND scrap_packing_item.scrap_skid_num = scrap_skid.scrap_skid_num;
  
  x12_table(i) := 'SN1**' || po_nt || '*01';
  i := i + 1;
  
  x12_table(i) := 'PRF*' || 'NA' || '***20030102';
  i := i + 1;
    
  x12_table(i) := 'REF*IL*' || ls_auth_code;
  i := i + 1;
  
  FOR alloyinfo_rec IN alcan_scrap_856_cur LOOP
    ll_alloy := alloyinfo_rec.scrap_alloy2;

    --open item_cur;
    --fetch item_cur INTO item_rec;
    FOR item_rec IN item_cur LOOP

      x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(hl_order) || '*I';
      li_hl01 := li_hl01 + 1;
      i := i + 1;
      x12_table(i) := 'PID*S*55***' || upper(rtrim(ltrim(ll_alloy)));
      i := i + 1;
      x12_table(i) := 'MEA*WT*G*' ||
                      to_char(item_rec.scrap_net_wt +
                              item_rec.scrap_tare_wt) || '*01';
      i := i + 1;
      x12_table(i) := 'MEA*WT*N*' || to_char(item_rec.scrap_net_wt) ||
                      '*01';
      i := i + 1;
      
      x12_table(i) := 'REF*SE*' || to_char(item_rec.scrap_skid_display_num);
      i := i + 1;
      x12_table(i) := 'REF*LS*' || to_char(item_rec.scrap_skid_display_num);
      i := i + 1;

    END LOOP;
    --close item_cur;

  END LOOP;
  --close alcan_scrap_856_cur;

  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                  to_char(ll_shipment_nt);
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  -- Write X.12 to file
  -- To alcan

  /** Write file to /templar/templar/incoming/senddata
  /*
  **/

  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  --edi_file:= 'S_alcan_ford_ford_' || to_char(ll_edi_file_id) ||'.x12';

  -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
  -- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
    --        v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
  END LOOP;
  utl_file.fclose(edi_file_handle);

  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
     shipment_edi856_date = SYSDATE,
     edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;
  --COMMIT;

  /*--added by Victor Huang on 06/05 for function acknowlegement
    INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
    VALUES(ll_gs_log, su_duns, sysdate, edi_file);
    COMMIT;
  */
  --added by Victor Huang on 12/07 for verifying 997
  
  INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (ll_edi_file_id,
     '039630926',
     su_duns,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856 Scrap');
  COMMIT;
  
  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856 Scrap');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  --exception
  --   when invalid_operation
  --   then
  --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

  --  when others
  --  then
  --      DBMS_OUTPUT.PUT_LINE ('System Error');
  --      UTL_FILE.FCLOSE(edi_file_handle);

  RETURN 1;
END edi_novelis_scrap_856_x12_save;
--------------------------------------------------------
--  DDL for Function EDI_OLYMPIC_856_X12
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_OLYMPIC_856_X12" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*
  Alex Gerlants. 02/19/2018
  This function has been created using Olympic 856 spec.
    Version :         1.5
    Publication Date: May 2011
  */

  /*
  Aluminum Blanking: Ford Supplier Code: ZZ R0P7A
                     DUNS: 01 039630926T
  Customer: ALCAN(34,35,10,1153)
  Alcan Rolled Product    X.121       0015049350011G
  End User: Ford (ZZ F159B)
            Ford Chicago Stamping Plant(51) MS02A
            Ford Walton Hills Stamping Plant(77) MS03A
            Ford Woodhaven Stamping Plant(71) AF30A MS09A
            Ford Maumee Stamping Plant(78)    AF06A MS08A

            Budd Company (Customer ID: 1096) B821L
            Eagle Steel (1251) MZF6B
            (not in use)Ford Monroe Stamping              AP06A

            (not in use) Warehouses: IDS(41)               R5G3B
            (not in use) Wayne Steel Distribution Center(79) RWSDC

  */

  --v_edi_text_ford varchar2(32767);
  --v_edi_text_alcan varchar2(32767);
  --ll_customer_edi_name VARCHAR2(20);

   --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50);

  --edi_loc varchar2(50):='/tmp';
  edi_file        VARCHAR2(50) := 'edi_out.txt';
  --edi_file_prefix VARCHAR2(50) := 'S_olympic_856_'; --PRODUCTION
  edi_file_prefix VARCHAR2(50) := 's_olympic_856_'; --DEVELOPMENT
  edi_file_handle utl_file.file_type;

  li_customer_id    shipment.customer_id%TYPE;
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;

  -- ls_sender_vanid varchar2 (50);
  -- ls_receiver_vanid varchar2 (50);
  -- ls_customer_vanid varchar2(50);
  -- ls_receiver_gs03 varchar2(50);
  -- ls_customer_gs03 varchar2(50);
  --ls_st varchar2(50);
  ls_sf VARCHAR2(50);
  ls_eq_type VARCHAR2(10);  -- Added by Patrick Reynolds 11/30/2016
  ls_su      VARCHAR2(50);
  --ls_st_duns VARCHAR2(50);
  ls_po      VARCHAR2(30);
  ls_auth_code   VARCHAR2(32);
  ll_gs_log  INTEGER;
  ll_st_log  INTEGER;
  ll_bsn_log INTEGER;

  ls_today VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  ls_now   VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  --ll_newrow integer;
  --ll_sheet_skid_num integer;
  li_rowcount INTEGER;
  --li_rownum integer;
  --li_rownum1 integer;
  li_hl01 INTEGER;
  --li_HL02 integer;
  ll_shipment_nt INTEGER;
  ll_shipment_gt INTEGER;
  ll_shipment_pc INTEGER;
  --li_enduser_id integer;
  li_td1 INTEGER;
  li_rc  INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_vehicle_id_prefix VARCHAR2(50);  -- Added by Patrick Reynolds 11/30/2016
  ls_scac              carrier.scac%TYPE;
  ls_carrier_full_name VARCHAR2(18);
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_carrier_initial   VARCHAR2(50);  -- Not used in stored procedure.  Discovered by Patrick Reynolds 11/30/2016
  ldt_shipment         DATE;
  --ld_shipdate date;
  ll_temp         INTEGER;
  ls_enduser_part VARCHAR2(50);
  --li_des_id       INTEGER; --Removed for Olympic
  --li_stop         INTEGER;
  ls_enduser_po varchar2(50);

  ll_edi_file_id INTEGER;
  --ll_edi_file_id_alcan integer;

  ls_lot_num VARCHAR2(32);
  ls_coil_id VARCHAR2(32);
  ls_des_cust_name VARCHAR2(18);
  
  ls_shipment_notes            shipment.shipment_notes%TYPE; --Added for Olympic
  ln_coil_width                coil.coil_width%TYPE; --Added for Olympic
  --ll_length                    number(10,5); --Added for Olympic
  --ll_width                     number(10,5); --Added for Olympic
  ls_customer_external_id      varchar(150);
  ln_coil_abc_num              coil.coil_abc_num%TYPE; --Added for Olympic
  ln_order_item_num            order_item.order_item_num%TYPE; --Added for Olympic
  ls_cash_date                 coil.cash_date%TYPE; --Added for Olympic

  CURSOR alcan_ford_856_cur IS
    SELECT sheet_packing_item.sh_packing_item,
           'MULTIPLE' lot_num,
           'MULTIPLE' coil_id,
           customer_order.orig_customer_po,
           customer_order.order_abc_num,
           customer_order.enduser_po,
           customer_order.created_date,
           order_item.order_item_num,
           order_item.enduser_part_num,
           order_item.supplier_code,
           order_item.gauge,
           sheet_skid. ab_job_num,
           sheet_skid.sheet_skid_num,
           sheet_skid.sheet_skid_display_num, --added by Victor H. on 06-2012 for Novelis locatio code request
           sheet_skid.sheet_net_wt,
           sheet_skid.sheet_tare_wt,
           sheet_skid. skid_pieces,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_theoretical_wt,
           NULL done,
           (dbo.f_get_part_dims_4order_item(customer_order.order_abc_num, order_item.order_item_num, 'length')) part_length,
           (dbo.f_get_part_dims_4order_item(customer_order.order_abc_num, order_item.order_item_num, 'width')) part_width
      FROM customer_order,
           order_item,
           sheet_skid,
           ab_job,
           shipment,
           sheet_packing_item
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
  --      (SHIPMENT.SHIPMENT_EDI856_DATE is NULL);

  --TYPE skidinfo_tabletype IS TABLE OF alcan_ford_856_cur%ROWTYPE INDEX BY BINARY_INTEGER;
  --skidinfo_table skidinfo_tabletype;
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table    store_tabletype;
  i            BINARY_INTEGER := 0;
  skidinfo_rec alcan_ford_856_cur%ROWTYPE;

  /*CURSOR packing_list_same_bol IS
  SELECT packing_list
    FROM shipment
   WHERE bill_of_lading = ll_bill_of_lading;*/

  /* --Removed for Olympic. Begin
  CURSOR c_ship_to IS
    SELECT DISTINCT des_sh_cust_id --, PACKING_LIST
      FROM shipment
     WHERE bill_of_lading = ll_bill_of_lading
       AND shipment.shipment_status = 0;
  */
  --Removed for Olympic. End
  --ORDER BY PACKING_LIST;

BEGIN

  edi_loc := dbo.get_edi_destination('EDI_DIR'); --Alex Gerlants. 11/15/2016

  -- edi_alcan_870; -- Send 870 first

  -- Get Customer ID, End user ID
  --SELECT customer_id, des_sh_cust_id
  --  INTO li_customer_id, li_des_sh_cust_id
  -- FROM shipment
  -- WHERE shipment.packing_list = al_packing_list;
  --IF NOT SQL%FOUND THEN
 --   RETURN - 1;
  --END IF;

  -- Get Customer ID, End user ID, authorization code
  SELECT customer_id, des_sh_cust_id, nvl(shipment_athorization_code, 'NA')
    INTO li_customer_id, li_des_sh_cust_id, ls_auth_code
  FROM shipment
  WHERE shipment.packing_list = al_packing_list;
  IF NOT SQL%FOUND THEN
   RETURN - 1;
  END IF;

  -- dbms_output.put_line (to_char(li_customer_id) || '  ' || to_char(li_des_sh_cust_id) );

  if not li_customer_id in (2475, 2574, 2695, 2834) then
    return 200;
  end if;

  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(sheet_skid.sheet_net_wt),
         SUM(sheet_skid.sheet_net_wt) + SUM(sheet_skid.sheet_tare_wt),
         SUM(sheet_skid.skid_pieces)
    INTO ll_shipment_nt, ll_shipment_gt, ll_shipment_pc
    FROM sheet_skid, sheet_packing_item, shipment
   WHERE shipment.packing_list = sheet_packing_item.packing_list
     AND sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
     AND shipment.packing_list = al_packing_list;
  IF ll_shipment_pc = 0 THEN
    RETURN 100;
  END IF; -- empty shipment

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  -- Retrieve ABCO info
  -- ls_sender_vanid := '3010007080';
  --ls_ic := 'R0P7A';

  -- Retrieve ALCAN supply code and Ford Stamping Plant location code
  --SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf
  --FROM customer_customer  WHERE o_customer_id = li_customer_id and e_customer_id = 49;  --Ford customer_id =49

  ls_sf := '039630926';
  --SELECT NVL(communication_code,'UNKNOWN') INTO ls_st FROM customer_system
  --WHERE customer_id = li_des_sh_cust_id;

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.vehicle_id_prefix, '9999'),
         nvl(shipment.equipment_type, 'NA'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'PT'), -- Protected Trailer
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE),
         nvl(shipment.shipment_notes, 'NA') --Added for Olympic
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_vehicle_id_prefix,
         ls_eq_type,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_carrier_initial,
         ldt_shipment,
         ls_shipment_notes --Added for Olympic
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;

  --Check all packing_lists are done against a BOL
  /*
  for pl_rec in packing_list_same_bol loop
      select shipment.shipment_status into ll_temp from shipment
             where shipment.packing_list = pl_rec.packing_list;
      if ll_temp > 0 then
         return pl_rec.packing_list;
      end if;

  end loop;
  */
  --End of packing list checking

  --SELECT nvl(customer_external_id, '00000000'), customer_short_name
  --  INTO ls_customer_external_id, ls_des_cust_name
   -- FROM customer
   --WHERE customer_id = li_des_sh_cust_id;
   
   --SELECT nvl(customer_duns_number_string, '00000000'), customer_short_name
   select   nvl(customer_external_id, '00000000'), customer_short_name
   INTO     ls_customer_external_id, ls_des_cust_name
   FROM     customer
   WHERE    customer_id = li_des_sh_cust_id;

  --IF (ls_customer_external_id = '00000000') THEN
  IF (ls_customer_external_id = '00000000') THEN
    RETURN 200;
  END IF; --No Ship to DUNS

  SELECT nvl(customer_duns_number_string, '00000000')
    INTO ls_su
    FROM customer
   WHERE customer_id = li_customer_id;
   
  IF (ls_su = '00000000') THEN
    RETURN 200;
  END IF; --No Supplier DUNS

  -- Get SCAC(Standard Carrier Alpha Code)
  SELECT nvl(carrier.scac, 'NONE'), LPAD(carrier.carrier_full_name, 17)
    INTO ls_scac, ls_carrier_full_name
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);

  -- Get Receiver and Customer VAN ID
  -- SELECT NVL(customer_system.van_account_num, 'nothing'), NVL(customer_system.gs03, 'nothing')
  -- INTO ls_receiver_vanid, ls_receiver_gs03    -- ls_receiver_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --   (select shipment.des_sh_cust_id  from shipment  where shipment.packing_list = al_packing_list);

  -- SELECT NVL(customer_system.van_account_num, 'nothing'),NVL(customer_system.gs03, 'nothing')
  -- INTO   ls_customer_vanid, ls_customer_gs03   -- ls_customer_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --       (select shipment.customer_id from shipment where shipment.packing_list = al_packing_list);

  -- Generate Header Info.
  --x12_table(i) := 'ISA*00*'||'          *00*          *ZZ*R0P7A          *ZZ*F159B          *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0') ||'*0*P**';
  --x12_table(i) := 'GS*SH*R0P7A*'||ls_st || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';


  --Production
  --x12_table(i) := 'ISA*00*' ||
  --                '          *00*          *01*039630926T     *01*008861627R     *' ||
  --                ls_today || '*' || ls_now || '*U*00200*' ||
  --               lpad(to_char(ll_gs_log), 9, '0') || '*0*P*@';
  
  --Development                
  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *ZZ*2NDSFTP        *ZZ*008861627T     *' ||
                  ls_today || '*' || ls_now || '*U*00200*' ||
                 lpad(to_char(ll_gs_log), 9, '0') || '*0*T*@' || '~';
  
   --TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY 
  --x12_table(i) := 'ISA*00*          *00*          *01*039630926T     *ZZ*008861627T     *20180222*1621*U*00200*000130722*0*T**';
  i := i + 1;

  x12_table(1) := 'GS*SH*R0P7A*' || '017763731' || '*' || ls_today || '*' ||
                  ls_now || '*' || to_char(ll_gs_log) || '*X*' || '002002' || '~';
  
  --TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY 
  --x12_table(i) := 'GS*SH*R0P7A*017763731*20180222*1621*130722*X*002002';
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log) || '~';
  i := i + 1;
  --x12_table(i):= 'BSN*00*' || to_char(ll_bill_of_lading) || '*' || ls_today || '*' || ls_now;
  ls_today := to_char(SYSDATE, 'YYYYMMDD');
  x12_table(i) := 'BSN*00*' || to_char(al_packing_list) || '*' || ls_today || '*' ||
                  ls_now || '*TS' || '~'; --Added '*TS' for Olympic. TS is Transaction Code: Transfer Statement (Stock Transfer)
  i := i + 1;
  x12_table(i) := 'DTM*011*' || ls_today || '*' || ls_now || '*ES' || '~'; --Added '*ES' for Olympic. ES - Time Zone: Eastern Standard Time
  i := i + 1;
  
    ------------------------------------------------------------------------------------------
    ------------------------------  Shipment Level Begin  ------------------------------------
    ------------------------------------------------------------------------------------------

  -- First Level HL
  x12_table(i) := 'HL*01**S' || '~';
  i := i + 1;
  x12_table(i) := 'MEA*PD*G*' || to_char(ll_shipment_gt) || '*LB' || '~';
  i := i + 1;
  x12_table(i) := 'MEA*PD*N*' || to_char(ll_shipment_nt) || '*LB' || '~';
  i := i + 1;
    
  x12_table(i) := 'TD1*PLT90*' || to_char(li_rowcount) || '~'; --"PLT90" means "Wood Pallet".
                                                        --li_rowcount is Number Of Pallets in al_packing_list.
  li_td1 := i;
  i := i + 1;
  x12_table(i) := 'TD5*B*02*' || ls_scac || '*M*' || ltrim(rtrim(ls_carrier_full_name)) || '~';
  i := i + 1;
  -- segment was modified to include trailer number.  Patrick Reynolds 11/30/2016
  x12_table(i) := 'TD3*' || ls_carrier_desc_code || '*' || ls_scac || '*' || ls_vehicle_id_prefix || '~';
  i := i + 1;
  x12_table(i) := 'REF*BM*' || to_char(al_packing_list) || '~';
  i := i + 1;
  --x12_table(i) := 'REF*PK*' || to_char(al_packing_list); --Removed for Olympic
  --i := i + 1; --Removed for Olympic
  
  -- segment was modified to include equipment type.  Patrick Reynolds 11/30/2016
  --x12_table(i) := 'REF*EQ*' || ls_eq_type; --Removed for Olympic
  --i := i + 1; --waiting for Novilis, ----tony --Removed for Olympic
  --- Testing for multi order ASN ----Tony

  x12_table(i) := 'REF*MB*' || to_char(ll_bill_of_lading) || '~';
  i := i + 1;
  
  x12_table(i) := 'FOB*PP' || '~'; --Payment method. Always "PP" - Prepaid. Added for Olympic
  i := i + 1; --Added for Olympic
  
  SELECT COUNT(*)
    INTO ll_temp
    FROM shipment
   WHERE shipment.bill_of_lading = ll_bill_of_lading
     AND shipment.shipment_status = 0;
     
  --x12_table(i) := 'REF*SS*' || to_char(ll_temp); --Removed for Olympic
  --i := i + 1; --Removed for Olympic
  
  /* --Removed for Olympic. Begin
  li_des_id := 1;
  FOR c_stop IN c_ship_to LOOP
    IF li_des_sh_cust_id = c_stop.des_sh_cust_id THEN
      x12_table(i) := 'REF*QN*' || to_char(li_des_id);
      i := i + 1;
    END IF;
    li_des_id := li_des_id + 1;
  END LOOP;
  */
  --Removed for Olympic. End

  /*
  IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
     x12_table(i):= 'REF*ZZ*' || ls_st;i:=i+1;
  end if;
  */

  --x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYMMDD') || '*' || --Removed for Olympic
  --                to_char(ldt_shipment, 'HH24MI'); --Removed for Olympic
  --i := i + 1; --Removed for Olympic
  
  --x12_table(i) := 'N1*SF*Aluminum Blanking Co*1*' || ls_sf;
  x12_table(i) := 'N1*SF**1*' || ls_sf || '~'; --Ship from. ALBL DUNS: '039630926'
  i := i + 1;
  
  --x12_table(i) := 'N1*ST*' || ls_des_cust_name || '*1*' || ls_st_duns || '~';
  x12_table(i) := 'N1*ST*' || '*1*' || ls_customer_external_id; --Ship to. This is DUNS of Chrysler customer
  i := i + 1;
  
  --"04000" is Chrysler?s Sold To DUNS number as assigned to Olympic
  x12_table(i) := 'N1*SO**1*' || '04000' || '~'; --Sold to. Changed for Olympic. From "'N1*SU*" to "'N1*SO*"
  i := i + 1;

  --if not (li_des_sh_cust_id = 1096 or li_des_sh_cust_id = 1251) then
  --         x12_table(i):= 'N1*IC**92*' || ls_ic; i := i +1;        --- Deleted 04-30-03 by Tony according to alcan Julia's email
  --end if;

  --         x12_table(i):= 'N1*CN**92*' || ls_st_duns; i := i +1; --Ship to DUNs --- Deleted 04-30-03 by Tony according to alcan Julia's email

  -- Second Level HL based on End User PO( only one part# is included in one shipement per FORD's request)
  OPEN alcan_ford_856_cur;
  FETCH alcan_ford_856_cur
    INTO skidinfo_rec;
  --    ls_enduser_part := skidinfo_rec.ENDUSER_PART_NUM;
  --    ls_enduser_po := skidinfo_rec.ENDUSER_PO;

  /*
    if skidinfo_rec.ORIG_CUSTOMER_PO IN ('68Q68517') then    --Do NOT send 856 to Ford for some flipping related POs )
         edi_file_prefix := 'nosend_alcan_ford_ford';
    end if;
  */
  
  /*
  SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
    INTO ls_enduser_part
    FROM "ORDER_ITEM", "SHEET_SKID"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
     AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
     AND ("SHEET_SKID"."SHEET_SKID_NUM" = skidinfo_rec.sheet_skid_num);

 
      SELECT "CUSTOMER_ORDER"."ENDUSER_PO" into ls_enduser_po
             FROM "SHEET_SKID",
                  "CUSTOMER_ORDER"
                  WHERE ( "SHEET_SKID"."REF_ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM" ) and
                        (SHEET_SKID.SHEET_SKID_NUM = skidinfo_rec.SHEET_SKID_NUM);
   */
               
   --Alex Gerlants. 04/27/2018. Added:  "and order_item.order_item_num = sheet_skid.ref_order_abc_item"         
   select   distinct customer_order.enduser_po, order_item.enduser_part_num, order_item.order_item_num
   into     ls_enduser_po, ls_enduser_part, ln_order_item_num
   from     sheet_skid
            join customer_order on customer_order.order_abc_num = sheet_skid.ref_order_abc_num
            join order_item on customer_order.order_abc_num = order_item.order_abc_num and order_item.order_item_num = sheet_skid.ref_order_abc_item
   where    sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num;

  
  ------------------------------------------------------------------------------------------
  ------------------------------  Order Level Begin  ---------------------------------------
  ------------------------------------------------------------------------------------------  

  x12_table(i) := 'HL*02*01*O' || '~';
  i := i + 1;
  
  IF ls_enduser_part IS NULL THEN
    ls_enduser_part := 'NA';
  END IF;
  x12_table(i) := 'LIN**BP*' || ls_enduser_part || '*PO*' || ls_enduser_po || '*PL*' 
                  || to_char(ln_order_item_num) || '~';
  i := i + 1;
  x12_table(i) := 'SN1**' || to_char(ll_shipment_pc) || '*PC*0' || '~'; --Changed for Olympic from "EA" to "PC"
  i := i + 1;

  --
  --ls_po := skidinfo_rec.ORIG_CUSTOMER_PO;
  SELECT "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO"
    INTO ls_po
    FROM "SHEET_SKID", "CUSTOMER_ORDER"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
         "CUSTOMER_ORDER"."ORDER_ABC_NUM")
     AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num);

  --IF INSTR(skidinfo_rec.ORIG_CUSTOMER_PO,'-') > 0
  --New PO format for Novelis SAP include '-'
  /*IF instr(ls_po, '-') > 0 THEN
    ls_po := substr(ls_po, 0, instr(ls_po, '-') - 1);
  END IF;*/

  --   IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
  --x12_table(i) := 'PRF*' || ls_po || '***' || --Removed for Olympic
  --                to_char(skidinfo_rec.created_date, 'YYMMDD'); --Removed for Olympic
  --i := i + 1; --Removed for Olympic
  --   end if;

  CLOSE alcan_ford_856_cur;

   --  Novelis SAP order number
   --x12_table(i) := 'REF*IL*' || ls_auth_code; --Removed for Olympic
   --i := i + 1; --Removed for Olympic
  --  end if;

  -- Third Level HL Under a P.O.
  li_hl01 := 3;

  ------------------------------------------------------------------------------------------
  ------------------------------  Item (skid) Level Begin  ---------------------------------
  ------------------------------------------------------------------------------------------
  
  --Skid loop begins
  FOR skidinfo_rec IN alcan_ford_856_cur LOOP
    IF length(to_char(li_hl01)) = 1 THEN
      x12_table(i) := 'HL*0' || to_char(li_hl01) || '*02*I*0' || '~'; --Added for Olympic. "*0". It means that there are no children (subordinates) for this level.
      i := i + 1;
    ELSE
      x12_table(i) := 'HL*' || to_char(li_hl01) || '*02*I*0' || '~'; --Added for Olympic. "*0". It means that there are no children (subordinates) for this level.
      i := i + 1;
    END IF;
    
    --Addded for Olympic. Begin
    
    --Fill in lot num
    SELECT COUNT(*)
      INTO li_rc
      FROM sheet_skid_detail
     WHERE sheet_skid_detail.sheet_skid_num = skidinfo_rec.sheet_skid_num;

    ls_lot_num := skidinfo_rec.lot_num;
    ls_coil_id := skidinfo_rec.coil_id;

    IF li_rc = 1 THEN
      SELECT lot_num, coil_org_num, coil_width, coil_abc_num, cash_date
        INTO ls_lot_num, ls_coil_id, ln_coil_width, ln_coil_abc_num, ls_cash_date
        FROM coil
       WHERE coil.coil_abc_num =
             (SELECT coil_abc_num
                FROM production_sheet_item
               WHERE production_sheet_item.prod_item_num =
                     (SELECT prod_item_num
                        FROM sheet_skid_detail
                       WHERE sheet_skid_detail.sheet_skid_num =
                             skidinfo_rec.sheet_skid_num));
    END IF;

    --if li_des_sh_cust_id = 1251   --Eagle need coil ID here instead of lot number
    --then
    --x12_table(i) :=  'REF*HC*' || skidinfo_rec.coil_id ; i := i +1;
    --else
    
    x12_table(i) := 'LIN**HN*' || ls_lot_num || '*SN*' || skidinfo_rec.sheet_skid_display_num || '*SE*' || to_char(ln_coil_abc_num) || '~';
    --x12_table(i) := 'LIN**HN*' || ls_lot_num || '*SN*' || skidinfo_rec.sheet_skid_display_num;
    i := i + 1;
    --end if;    
    
    --Added for Olympic. Begin    

    --    IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
    --       x12_table(i) := 'SN1**'||to_char(skidinfo_rec.skid_pieces)||'*EA';i:=i+1;
    --    else
    
    /*
    ls_cash_date := to_char(to_date(ls_cash_date, 'mm/dd/yyyy'), 'yyyymmdd');
    
    --"DTA" is made up Cash Date code. Olympic wanted this code.
    ----"0000" is made up Cash Time
    x12_table(i) := 'DTM*DTA*'|| ls_cash_date || '*0000*ES'; --Added for Olympic' 
    i := i + 1;
    
    --x12_table(i) := 'SN1**1*PF'; --Removed for Olympic
    x12_table(i) := 'SN1**'||to_char(skidinfo_rec.skid_pieces)||'*EA'; --Added for Olympic
    i := i + 1;
    */
    --    end if;

    --if li_des_sh_cust_id = 1096 -- To Budd or li_des_sh_cust_id = 1251 then
    --   then
    --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; i := i +1;
    --      x12_table(i) :=  'MEA*PD*TH*' || to_char(skidinfo_rec.sheet_net_wt) || '*24'; i := i +1;
    --elsif   li_des_sh_cust_id = 1251   --To Eagle Steel
    --  then
    --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; i := i +1;
    --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*24'; i := i +1;
    --      x12_table(i) :=  'MEA*PD*TH*' || to_char(skidinfo_rec.gauge) || '*EM'; i:=i+1;
    --    x12_table(i) :=  'MEA*PD*WD*'||'44.875'||'*IN'; i:=i+1;
    --    x12_table(i) :=  'MEA*PD*LN*'||to_char(skidinfo_rec.skid_pieces)||'*LF';  i:=i+1;
    --else  --All else, Ford dirct shiping program
    
    --x12_table(i) := 'MEA*PD*WT*' || to_char(skidinfo_rec.skid_pieces) || '*PC'; --Removed for Olympic
    x12_table(i) := 'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt) || '*01' || '~'; --Added for Olympic. Gross weight. "01" means "Actual Pounds".
    i := i + 1;
    
    --**********************************************************************************
    
    x12_table(i) :=  'MEA*PD*TH*' || ltrim(rtrim(to_char(skidinfo_rec.gauge, '0.9999'))) || '*IN' || '~'; --Added for Olympic
    i := i + 1; --Added for Olympic
    
    x12_table(i) :=  'MEA*PD*WD*' || to_char(ln_coil_width) || '*IN' || '~'; --Added for Olympic
    i := i + 1; --Added for Olympic
    
    --This is Coil length. It is available only for Novelis-Oswego in coil_quality.gross_coil_length
    --x12_table(i) :=  'MEA*PD*LN*' || 'NA' || '*LF'; --Added for Olympic
    --i := i + 1; --Added for Olympic
    
    /*
    select dbo.f_get_part_dims_4order_item(skidinfo_rec.order_abc_num, skidinfo_rec.order_item_num, 'length')
    into   ll_length
    from   dual;
    */
    
    x12_table(i) :=  'MEA*PD*LN*' || to_char(skidinfo_rec.part_length) || '*IN' || '~'; --Added for Olympic
    i := i + 1; --Added for Olympic
    
    x12_table(i) :=  'MEA*OD*TH*' || to_char(skidinfo_rec.gauge) || '*IN' || '~'; --Added for Olympic
    i := i + 1; --Added for Olympic
    
    /*
    select dbo.f_get_part_dims_4order_item(skidinfo_rec.order_abc_num, skidinfo_rec.order_item_num, 'width')
    into   ll_width
    from   dual;
    */
    
    x12_table(i) :=  'MEA*OD*WD*' || to_char(skidinfo_rec.part_width) || '*IN' || '~'; --Added for Olympic
    i := i + 1; --Added for Olympic

    x12_table(i) :=  'MEA*OD*LN*' || to_char(skidinfo_rec.part_length) || '*IN' || '~'; --Added for Olympic
    i := i + 1; 
    
    ls_cash_date := to_char(to_date(ls_cash_date, 'mm/dd/yyyy'), 'yyyymmdd');
    
    --"DTA" is made up Cash Date code. Olympic wanted this code.
    ----"0000" is made up Cash Time
    x12_table(i) := 'DTM*CDA*'|| ls_cash_date || '*0000*ES' || '~'; --Added for Olympic' 
    i := i + 1;
    
    --x12_table(i) := 'SN1**1*PF'; --Removed for Olympic
    x12_table(i) := 'SN1**'||to_char(skidinfo_rec.skid_pieces)||'*EA' || '~'; --Added for Olympic
    i := i + 1;
    
    --Added for Olympic
    
    --**********************************************************************************
    
    --x12_table(i) := 'MEA*PD*N*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; --Removed for Olympic
    --i := i + 1; --Removed for Olympic
    


    -- changed to all gross wt per novelis 1/30/2015
    --x12_table(i) := 'MEA*PD*G*' || to_char(skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt) || '*01'; --Removed for Olympic
    --i := i + 1; --Removed for Olympic

    /*
    IF (skidinfo_rec.sheet_theoretical_wt IS NULL) OR
       (skidinfo_rec.sheet_theoretical_wt = 0) THEN
      x12_table(i) := 'MEA*PD*G*' || to_char(ll_shipment_gt) || '*01';
      i := i + 1;
    ELSE
      x12_table(i) := 'MEA*PD*G*' ||
                      to_char(skidinfo_rec.sheet_theoretical_wt) || '*01';
      i := i + 1;
    END IF;
    */
    --end if;

    --x12_table(i) :=  'REF*HC*' || skidinfo_rec.coil_id ;
    --x12_table(i) :=  'REF*HC*' || ls_coil_id || '~'; --Changed for Olympic
    --i := i +1;

    --x12_table(i) := 'REF*LS*' || to_char(skidinfo_rec.sheet_skid_num);
    --x12_table(i) := 'REF*LS*' || skidinfo_rec.sheet_skid_display_num || '~'; --added by Victor H. on 06-2012 for Novelis locatio code request
    --i := i + 1;
    
    li_hl01 := li_hl01 + 1;
    
    --li_rowcount := alcan_ford_856_cur%ROWCOUNT;
    
    select count(*)
    into   li_rowcount
    from   sheet_packing_item
    where packing_list = al_packing_list;
    
    x12_table(li_td1) := 'TD1*PLT90*' || to_char(li_rowcount) || '~';
  END LOOP;

  -- DBMS_OUTPUT.PUT_LINE ('rowcount' || to_char(li_rowcount));

  -- if li_des_sh_cust_id = 1096 or li_des_sh_cust_id = 1251 then
  --   x12_table(i) :=  'CTT*' || to_char(li_HL01 - 1) ||'*' || to_char(ll_shipment_pc*2) ;
  --   i := i +1;
  -- else
  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                  to_char(li_rowcount + ll_shipment_pc) || '~';
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log) || '~';
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log) || '~';
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0') || '~';

  -- Write X.12 to file
  -- To FORD

  /** Write file to /templar/templar/incoming/senddata
  /*
  **/

  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  --edi_file:= 'S_alcan_ford_ford_' || to_char(ll_edi_file_id) ||'.x12';

  -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
  -- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
    --        v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
  END LOOP;
  utl_file.fclose(edi_file_handle);

  --To ALCAN

  /*
  SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;
  SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id_alcan FROM DUAL;
  edi_file:= 'S_alcan_ford_alcan_' || to_char(ll_edi_file_id_alcan) ||'.x12';
  edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');
  x12_table(0) := 'ISA*00*'||'          *00*          *01*039630926T     *09*0015049350011G *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0')||'*0*P**';
  x12_table(1) := 'GS*SH*R0P7A*'||'001504935001' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  x12_table(i-1) :=  'GE*1*' || to_char (ll_gs_log);
  x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');
  for j in 0..i loop
   UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
       v_edi_text_alcan:=v_edi_text_alcan||x12_table(j)||CHR(10);
  end loop;
  UTL_FILE.FCLOSE(edi_file_handle);

  */

  /* The following code added by Tony, for update archive*/

  --  INSERT INTO edi_log (edi_log_timestamp,customer_id,
  --         customer_edi_name,edi_log_contents,edi_file_id,edi_text)
  --    VALUES (SYSDATE,li_customer_id,ll_customer_edi_name,
  --           'EDI:'||ll_customer_edi_name||' generated successfully.',ll_edi_file_id,v_edi_text);
  --   COMMIT;

  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE,
         edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;
--  COMMIT;

  /* --added by Victor Huang on 06/05 for function acknowlegement
  INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
  VALUES(ll_gs_log, ls_su, sysdate, edi_file);
  COMMIT;*/

  --added by Victor Huang on 12/07 for verifying 997
  INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (ll_edi_file_id,
     '039630926',
     ls_su,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856');
  COMMIT;

  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  --exception
  --   when invalid_operation
  --   then
  --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

  --  when others
  --  then
  --      DBMS_OUTPUT.PUT_LINE ('System Error');
  --      UTL_FILE.FCLOSE(edi_file_handle);

  RETURN 1;
END edi_olympic_856_x12;
--------------------------------------------------------
--  DDL for Function EDI_STELLANTIS_856_X12
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_STELLANTIS_856_X12" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*
  Aluminum Blanking: Ford Supplier Code: ZZ R0P7A
                     DUNS: 01 039630926T
  Customer: ALCAN(34,35,10,1153)
  Alcan Rolled Product    X.121       0015049350011G
  End User: Ford (ZZ F159B)
            Ford Chicago Stamping Plant(51) MS02A
            Ford Walton Hills Stamping Plant(77) MS03A
            Ford Woodhaven Stamping Plant(71) AF30A MS09A
            Ford Maumee Stamping Plant(78)    AF06A MS08A

            Budd Company (Customer ID: 1096) B821L
            Eagle Steel (1251) MZF6B
            (not in use)Ford Monroe Stamping              AP06A

            (not in use) Warehouses: IDS(41)               R5G3B
            (not in use) Wayne Steel Distribution Center(79) RWSDC

  */

  --v_edi_text_ford varchar2(32767);
  --v_edi_text_alcan varchar2(32767);
  --ll_customer_edi_name VARCHAR2(20);

   --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc VARCHAR2(50);

  --edi_loc varchar2(50):='/tmp';
  edi_file        VARCHAR2(50) := 'edi_out.txt';
  --edi_file_prefix VARCHAR2(50) := 'S_stellantis_856_'; --Production
  edi_file_prefix VARCHAR2(50) := 's_stellantis_856_'; --Development
  edi_file_handle utl_file.file_type;

  li_customer_id    shipment.customer_id%TYPE;
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;

  -- ls_sender_vanid varchar2 (50);
  -- ls_receiver_vanid varchar2 (50);
  -- ls_customer_vanid varchar2(50);
  -- ls_receiver_gs03 varchar2(50);
  -- ls_customer_gs03 varchar2(50);
  --ls_st varchar2(50);
  --ls_sf VARCHAR2(50);
  ls_eq_type VARCHAR2(10);  -- Added by Patrick Reynolds 11/30/2016
  ls_su      VARCHAR2(50);
  ls_st_duns VARCHAR2(50);
  ls_po      VARCHAR2(30);
  ls_auth_code   VARCHAR2(32);
  ll_gs_log  INTEGER;
  ll_st_log  INTEGER;
  ll_bsn_log INTEGER;

  --ls_today VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD'); --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  ls_today_2digits_year VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD'); --Alex Gerlants. 10/16/2018. Test
  ls_now   VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  li_rowcount INTEGER;
  li_hl01 INTEGER;
  ll_shipment_nt INTEGER;
  ll_shipment_gt INTEGER;
  ll_shipment_pc INTEGER;
  li_td1 INTEGER;
  --li_rc  INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_vehicle_id_prefix VARCHAR2(50);  -- Added by Patrick Reynolds 11/30/2016
  ls_scac              carrier.scac%TYPE;
  ls_carrier_full_name VARCHAR2(18);
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_carrier_initial   VARCHAR2(50);  -- Not used in stored procedure.  Discovered by Patrick Reynolds 11/30/2016
  ldt_shipment         DATE;
   ll_temp         INTEGER;
  ls_enduser_part VARCHAR2(50);
  --li_des_id       INTEGER;

  ll_edi_file_id INTEGER;

  ls_lot_num VARCHAR2(32);
  --ls_coil_id VARCHAR2(32);
  ls_des_cust_name VARCHAR2(18);
  
  ls_coil_org_num		        coil.coil_org_num%TYPE; --Alex Gerlants. 01/25/2019
  ll_coil_gauge		          coil.coil_gauge%TYPE;   --Alex Gerlants. 01/25/2019
  ll_coil_width		          coil.coil_width%TYPE;   --Alex Gerlants. 01/25/2019
  ld_ship_date              date;
  li_is_stellantis             integer;
  ln_skid_type_if_whed      sheet_skid.skid_type_if_whed%TYPE;   --Alex Gerlants. 04/01/2019
  ls_time                   char(4); --Alex Gerlants. 01/09/2020
  ls_plant_code             customer.plant_code%TYPE;
  ldt_time_date_finished    ab_job.time_date_finished%TYPE;

  CURSOR alcan_ford_856_cur IS
    SELECT sheet_packing_item.sh_packing_item,
           'MULTIPLE' lot_num,
           'MULTIPLE' coil_id,
           customer_order.orig_customer_po,
           customer_order.order_abc_num,
           customer_order.enduser_po,
           customer_order.created_date,
           order_item.order_item_num,
           order_item.enduser_part_num,
           order_item.supplier_code,
           order_item.gauge,
           sheet_skid. ab_job_num,
           sheet_skid.sheet_skid_num,
           sheet_skid.sheet_skid_display_num,
           sheet_skid.sheet_net_wt,
           sheet_skid.sheet_tare_wt,
           sheet_skid. skid_pieces,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_theoretical_wt,
           NULL done
      FROM customer_order,
           order_item,
           sheet_skid,
           ab_job,
           shipment,
           sheet_packing_item
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
/*      
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);
  --      (SHIPMENT.SHIPMENT_EDI856_DATE is NULL);
*/
  --TYPE skidinfo_tabletype IS TABLE OF alcan_ford_856_cur%ROWTYPE INDEX BY BINARY_INTEGER;
  --skidinfo_table skidinfo_tabletype;
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table    store_tabletype;
  i            BINARY_INTEGER := 0;
  skidinfo_rec alcan_ford_856_cur%ROWTYPE;

  /*CURSOR packing_list_same_bol IS
  SELECT packing_list
    FROM shipment
   WHERE bill_of_lading = ll_bill_of_lading;*/
  /*
  CURSOR c_ship_to IS
    SELECT DISTINCT des_sh_cust_id --, PACKING_LIST
      FROM shipment
     WHERE bill_of_lading = ll_bill_of_lading
       AND shipment.shipment_status = 0;
  ORDER BY PACKING_LIST;
  */
  
  /*
  cursor c_coil is
  select distinct 
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num,
         coil.coil_gauge,
         coil.coil_width
         --process_coil.coil_abc_num
         --outbound_edi_transaction.transaction_time,
         --outbound_edi_transaction.edi_file_name
  from   customer_order
         join order_item on order_item.order_abc_num = customer_order.order_abc_num
         join ab_job on ab_job.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
         join sheet_skid on sheet_skid.ab_job_num = ab_job.ab_job_num
         join sheet_packing_item on sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
         join shipment on shipment.packing_list = sheet_packing_item.packing_list
         join process_coil on process_coil.ab_job_num = ab_job.ab_job_num
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         --join outbound_edi_transaction on outbound_edi_transaction.edi_file_id = shipment.edi_file_id_856
  --where  shipment.packing_list = 105586 --Production
  where  shipment.packing_list = al_packing_list --Develpment
  order by
         shipment.packing_list,
         sheet_skid.sheet_skid_num,
         coil.coil_org_num;
   */
BEGIN
  
  select f_is_stellantis(al_packing_list)
  into   li_is_stellantis
  from   dual;
  
  if li_is_stellantis = 0 then --Customer is NOT stellantis
    return 1; --Nothing to do here
  end if;
  
  select shipment_edi856_date
  into   ld_ship_date
  from   shipment
  where  shipment.packing_list = al_packing_list;
   
  if not (ld_ship_date is null) then --ASN already sent
    return 100;
  end if;

  edi_loc := dbo.get_edi_destination('EDI_DIR'); --Alex Gerlants. 11/15/2016

  -- Get Customer ID, End user ID, authorization code
  SELECT customer_id, des_sh_cust_id, nvl(shipment_athorization_code, 'NA')
    INTO li_customer_id, li_des_sh_cust_id, ls_auth_code
  FROM shipment
  WHERE shipment.packing_list = al_packing_list;
  IF NOT SQL%FOUND THEN
   RETURN - 1;
  END IF;

  
  IF NOT (li_customer_id IN (2851)) -- AND (li_des_sh_cust_id IN (
  --10,41,51,69,70,71,72,77,78,79,1055,1062,1073,1086,1096,1099,1114,1112,1153,
  --1206,1251,1253,1268,1269,1270,1322,1325,1328,1331,1332,1346,1347, 1382, 1383)))
   THEN

    --***********************************************************************************************88
    --IF NOT ((li_customer_id IN (34,35,10,1153)) AND (li_des_sh_cust_id IN (SELECT CUSTOMER_ID
    --FROM CUSTOMER
    --WHERE CUSTOMER_DUNS_NUMBER_STRING is not null))) THEN

    RETURN 200;
  END IF;

  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(sheet_skid.sheet_net_wt),
         SUM(sheet_skid.sheet_net_wt) + SUM(sheet_skid.sheet_tare_wt),
         SUM(sheet_skid.skid_pieces)
    INTO ll_shipment_nt, ll_shipment_gt, ll_shipment_pc
    FROM sheet_skid, sheet_packing_item, shipment
   WHERE shipment.packing_list = sheet_packing_item.packing_list
     AND sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
     AND shipment.packing_list = al_packing_list;
  IF ll_shipment_pc = 0 THEN
    RETURN 100;
  END IF; -- empty shipment

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  -- Retrieve ABCO info
  -- ls_sender_vanid := '3010007080';
  --ls_ic := 'R0P7A';

  -- Retrieve ALCAN supply code and Ford Stamping Plant location code
  --SELECT NVL(supply_code, 'D5X8F')  INTO ls_sf
  --FROM customer_customer  WHERE o_customer_id = li_customer_id and e_customer_id = 49;  --Ford customer_id =49

  --ls_sf := '039630926';
  --SELECT NVL(communication_code,'UNKNOWN') INTO ls_st FROM customer_system
  --WHERE customer_id = li_des_sh_cust_id;

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.vehicle_id_prefix, '9999'),
         nvl(shipment.equipment_type, 'NA'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'PT'), -- Protected Trailer
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE)
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_vehicle_id_prefix,
         ls_eq_type,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_carrier_initial,
         ldt_shipment
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;

  --Check all packing_lists are done against a BOL
  /*
  for pl_rec in packing_list_same_bol loop
      select shipment.shipment_status into ll_temp from shipment
             where shipment.packing_list = pl_rec.packing_list;
      if ll_temp > 0 then
         return pl_rec.packing_list;
      end if;

  end loop;
  */
  --End of packing list checking

  SELECT nvl(customer_duns_number_string, '00000000'), customer_short_name
    INTO ls_st_duns, ls_des_cust_name
    FROM customer
   WHERE customer_id = li_des_sh_cust_id;

  IF (ls_st_duns = '00000000') THEN
    RETURN 200;
  END IF; --No Ship to DUNS

  SELECT nvl(customer_duns_number_string, '00000000')
    INTO ls_su
    FROM customer
   WHERE customer_id = li_customer_id;
  IF (ls_su = '00000000') THEN
    RETURN 200;
  END IF; --No Supplier DUNS

  -- Get SCAC(Standard Carrier Alpha Code)
  SELECT nvl(carrier.scac, 'NONE'), LPAD(carrier.carrier_full_name, 17)
    INTO ls_scac, ls_carrier_full_name
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);

  -- Get Receiver and Customer VAN ID
  -- SELECT NVL(customer_system.van_account_num, 'nothing'), NVL(customer_system.gs03, 'nothing')
  -- INTO ls_receiver_vanid, ls_receiver_gs03    -- ls_receiver_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --   (select shipment.des_sh_cust_id  from shipment  where shipment.packing_list = al_packing_list);

  -- SELECT NVL(customer_system.van_account_num, 'nothing'),NVL(customer_system.gs03, 'nothing')
  -- INTO   ls_customer_vanid, ls_customer_gs03   -- ls_customer_vanid
  -- FROM  customer_system WHERE customer_system.customer_id =
  --       (select shipment.customer_id from shipment where shipment.packing_list = al_packing_list);

  -- Generate Header Info.
  --x12_table(i) := 'ISA*00*'||'          *00*          *ZZ*R0P7A          *ZZ*F159B          *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0') ||'*0*P**';
  --x12_table(i) := 'GS*SH*R0P7A*'||ls_st || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  --Alex Gerlants. 10/16/2018. Changed from "00200" to "00401"
  --Production
  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *ZZ*28889          *ZZ*04000          *' ||
                  ls_today_2digits_year || '*' || ls_now || '*U*00204*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
  
  --Development                
  --x12_table(i) := 'ISA*00*' ||
  --                '          *00*          *ZZ*2NDSFTP        *ZZ**04000          *' ||
  --                ls_today_2digits_year || '*' || ls_now || '*U*00204*' ||
  --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';
                  
  i := i + 1;

  --Alex Gerlants. 10/16/2018. Changed from "002002" to "004010"
  --Production
  x12_table(1) := 'GS*SH*28889*' || '04000' || '*' || ls_today_2digits_year || '*' ||
                  ls_now || '*' || to_char(ll_gs_log) || '*X*' || '00204';
                  
  --Development
  --x12_table(1) := 'GS*SH*2NDSFTP*' || 'NOVLSTEST' || '*' || ls_today || '*' ||
  --               ls_now || '*' || to_char(ll_gs_log) || '*X*' || '00204';
                  
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;
  --x12_table(i):= 'BSN*00*' || to_char(ll_bill_of_lading) || '*' || ls_today || '*' || ls_now;
  x12_table(i) := 'BSN*00*' || to_char(al_packing_list) || '*' || ls_today_2digits_year || '*' ||
                  ls_now;
  i := i + 1;
  
  --Alex Gerlants. 08/07/2018.
  --Changed to populate with actual ship date instead of current date and time.
  --The reason is that when we send 856 on a later date, this date is not correct.
  --x12_table(i) := 'DTM*011*' || ls_today || '*' || ls_now;
  --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  
  --Alex Gerlants. 01/09/2020. Added the IF statement below.
  --If users do not enter time part in shipment.shipment_actualed_date_time,
  --856 will have system time in 'DTM*011*' and 'DTM*017*'
  
  ls_time := to_char(ldt_shipment, 'HH24MI');
  
  if ls_time <> '0000' then --User entered time
    x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                                                        to_char(ldt_shipment, 'HH24MI');
  else --User did not enter time  
    x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                                           to_char(sysdate, 'HH24MI') || '*ET';
  end if;
  i := i + 1;
  
  --Alex Gerlants. 10/18/2018. Changed from "YYMMDD" to "YYYYMMDD"
  --Moved here from the below
  /*
  if ls_time <> '0000' then --User entered time
    x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                    to_char(ldt_shipment, 'HH24MI') || '*ET';
  else --User did not enter time
    x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                    to_char(sysdate, 'HH24MI') || '*ET';
  end if;
  i := i + 1;
  */

  -- First Level HL
  x12_table(i) := 'HL*01**S';
  i := i + 1;
  
  x12_table(i) := 'N1*SU**92*' || '01000AA'; --For Customer EDI only: '04006' = FCA US
  i := i + 1;
  
  x12_table(i) := 'N1*SF**92*' || '01000BB';
  i := i + 1;
  
  select   nvl(plant_code, 'NA')
  into     ls_plant_code
  from     customer
  where    customer_id = li_customer_id;
  
  x12_table(i) := 'N1*ST**92*' || ls_plant_code;
  i := i + 1;
  
  x12_table(i) := 'N1*MA**92*' || ls_plant_code;
  i := i + 1;
  
  --Alex Gerlants. 10/16/2018. Changed from "MEA*PD*G*" to "MEA*WT*G*"
  x12_table(i) := 'MEA*PD*G*' || to_char(ll_shipment_gt) || '*LB';
  i := i + 1;
  x12_table(i) := 'MEA*PD*N*' || to_char(ll_shipment_nt) || '*LB';
  i := i + 1;
  x12_table(i) := 'TD1*PLT71*' || to_char(li_rowcount);
  li_td1 := i;
  i := i + 1;
  x12_table(i) := 'TD5*B*2*' || ls_scac || '*M*' || ltrim(rtrim(ls_carrier_full_name));
  i := i + 1;
  -- segment was modified to include trailer number.  Patrick Reynolds 11/30/2016
  x12_table(i) := 'TD3*' || ls_carrier_desc_code || '*' || ls_scac || '*' || ls_vehicle_id_prefix;
  i := i + 1;
  x12_table(i) := 'REF*BM*' || to_char(al_packing_list);
  i := i + 1;
  x12_table(i) := 'REF*PK*' || to_char(al_packing_list);
  i := i + 1;
  -- segment was modified to include equipment type.  Patrick Reynolds 11/30/2016
  x12_table(i) := 'REF*EQ*' || ls_eq_type;
  i := i + 1; --waiting for Novilis, ----tony
  --- Testing for multi order ASN ----Tony

  x12_table(i) := 'REF*MB*' || to_char(ll_bill_of_lading);
  i := i + 1;
  SELECT COUNT(*)
    INTO ll_temp
    FROM shipment
   WHERE shipment.bill_of_lading = ll_bill_of_lading
     AND shipment.shipment_status = 0;
     
  --Alex Gerlants. 10/16/2018. Removed 2 lines below
  --x12_table(i) := 'REF*SS*' || to_char(ll_temp);
  --i := i + 1;
  --li_des_id := 1;
  
  --Alex Gerlants. 10/16/2018. Removed 7 lines below
  /*
  FOR c_stop IN c_ship_to LOOP
    IF li_des_sh_cust_id = c_stop.des_sh_cust_id THEN
      x12_table(i) := 'REF*QN*' || to_char(li_des_id);
      i := i + 1;
    END IF;
    li_des_id := li_des_id + 1;
  END LOOP;
  */

  /*
  IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
     x12_table(i):= 'REF*ZZ*' || ls_st;i:=i+1;
  end if;
  */

  ----Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  --x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
  --                to_char(ldt_shipment, 'HH24MI');
  --i := i + 1;
  
  
  
  
  --x12_table(i) := 'N1*SU**91*' || ls_su;
  

  --if not (li_des_sh_cust_id = 1096 or li_des_sh_cust_id = 1251) then
  --         x12_table(i):= 'N1*IC**92*' || ls_ic; i := i +1;        --- Deleted 04-30-03 by Tony according to alcan Julia's email
  --end if;

  --         x12_table(i):= 'N1*CN**92*' || ls_st_duns; i := i +1; --Ship to DUNs --- Deleted 04-30-03 by Tony according to alcan Julia's email

  -- Second Level HL based on End User PO( only one part# is included in one shipement per FORD's request)
  OPEN alcan_ford_856_cur;
  FETCH alcan_ford_856_cur
    INTO skidinfo_rec;
  --    ls_enduser_part := skidinfo_rec.ENDUSER_PART_NUM;
  --    ls_enduser_po := skidinfo_rec.ENDUSER_PO;

  /*
    if skidinfo_rec.ORIG_CUSTOMER_PO IN ('68Q68517') then    --Do NOT send 856 to Ford for some flipping related POs )
         edi_file_prefix := 'nosend_alcan_ford_ford';
    end if;
  */

  SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
    INTO ls_enduser_part
    FROM "ORDER_ITEM", "SHEET_SKID"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
     AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
     AND ("SHEET_SKID"."SHEET_SKID_NUM" = skidinfo_rec.sheet_skid_num);

  /*
      SELECT "CUSTOMER_ORDER"."ENDUSER_PO" into ls_enduser_po
             FROM "SHEET_SKID",
                  "CUSTOMER_ORDER"
                  WHERE ( "SHEET_SKID"."REF_ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM" ) and
                        (SHEET_SKID.SHEET_SKID_NUM = skidinfo_rec.SHEET_SKID_NUM);
  */

  x12_table(i) := 'HL*02*01*O';
  i := i + 1;
  IF ls_enduser_part IS NULL THEN
    ls_enduser_part := 'NA';
  END IF;
  x12_table(i) := 'LIN**BP*' || ls_enduser_part;
  i := i + 1;
  x12_table(i) := 'SN1**' || to_char(ll_shipment_pc) || '*EA*0';
  i := i + 1;

  --
  
  /*
  --ls_po := skidinfo_rec.ORIG_CUSTOMER_PO;
  SELECT "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO"
    INTO ls_po
    FROM "SHEET_SKID", "CUSTOMER_ORDER"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
         "CUSTOMER_ORDER"."ORDER_ABC_NUM")
     AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num);
  */
  
  select  max(ab_job.time_date_finished)
  into    ldt_time_date_finished
  from    sheet_skid
          join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
          join sheet_skid_detail on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
          join sheet_packing_item on sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
  where   sheet_packing_item.packing_list = al_packing_list;
    
  select  distinct customer_order.orig_customer_po
  into    ls_po
  from    sheet_skid
          join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
          join sheet_skid_detail on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
          join sheet_packing_item on sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
          join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
  where   sheet_packing_item.packing_list = al_packing_list
  and     ab_job.time_date_finished = ldt_time_date_finished;

  --x12_table(i) := 'PRF*' || ls_po || '***' || to_char(skidinfo_rec.created_date, 'YYYYMMDD');
  x12_table(i) := 'PRF*' || ls_po;
  i := i + 1;
  --   end if;

  CLOSE alcan_ford_856_cur;

 --x12_table(i) := 'REF*IL*' || ls_auth_code;
 x12_table(i) := 'REF*PK*' || to_char(al_packing_list);
 i := i + 1;
  --  end if;

  -- Third Level HL Under a P.O.
  li_hl01 := 3;

  --Skid loop begin ----------------------------------------------------------------
  FOR skidinfo_rec IN alcan_ford_856_cur LOOP
    
      --In case of a split skid, we are creating just 1 HL for this skid
      --with just 1 coil for this skid.
      select distinct 
             coil.coil_org_num,
             coil.coil_gauge,
             coil.coil_width,
             coil.lot_num,
             nvl(skid_type_if_whed, -1) --Alex Gerlants. 04/01/2019
      into   ls_coil_org_num,
             ll_coil_gauge,
             ll_coil_width,
             ls_lot_num,
             ln_skid_type_if_whed --Alex Gerlants. 04/01/2019
      FROM "COIL",   
           "PRODUCTION_SHEET_ITEM",   
           "SHEET_SKID",   
           "SHEET_SKID_DETAIL",   
           "PROCESS_COIL"  
     WHERE ( "COIL"."COIL_ABC_NUM" = "PRODUCTION_SHEET_ITEM"."COIL_ABC_NUM" ) and  
           ( "SHEET_SKID_DETAIL"."SHEET_SKID_NUM" = "SHEET_SKID"."SHEET_SKID_NUM" ) and  
           ( "SHEET_SKID_DETAIL"."PROD_ITEM_NUM" = "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NUM" ) and  
           ( "COIL"."COIL_ABC_NUM" = "PROCESS_COIL"."COIL_ABC_NUM" ) and  
           ( "PRODUCTION_SHEET_ITEM"."AB_JOB_NUM" = "PROCESS_COIL"."AB_JOB_NUM" ) and  
           ( (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num)  ) and
           ( (rownum = 1)  ); --We need just 1 coil for each skid
  
      --Alex Gerlants. 04/01/2019. Begin
      if ln_skid_type_if_whed > -1 then --Warehouse skid
          --Get gauge and part width
          select distinct order_item.gauge,
                 f_get_part_width_per_job(ab_job.ab_job_num) 
          into   ll_coil_gauge,
                 ll_coil_width
          from   sheet_skid
                 join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
                 join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
                 join customer_order on customer_order.order_abc_num = order_item.order_abc_num
          where  sheet_skid_num = skidinfo_rec.sheet_skid_num
          and    (order_item.gauge is not null and f_get_part_width_per_job(sheet_skid.ab_job_num) is not null)
          and    rownum = 1;
      end if;
      --Alex Gerlants. 04/01/2019. End
  
      IF length(to_char(li_hl01)) = 1 THEN
        x12_table(i) := 'HL*0' || to_char(li_hl01) || '*02*I';
        i := i + 1;
      ELSE
        x12_table(i) := 'HL*' || to_char(li_hl01) || '*02*I';
        i := i + 1;
      END IF;

      --    IF li_des_sh_cust_id=1096 or li_des_sh_cust_id = 1251 then
      --       x12_table(i) := 'SN1**'||to_char(skidinfo_rec.skid_pieces)||'*EA';i:=i+1;
      --    else
      --x12_table(i) := 'SN1**1*PF';
      x12_table(i) := 'SN1**1*EA';
      x12_table(i) := 'SN1**' || to_char(skidinfo_rec.skid_pieces) || '*UN';
      i := i + 1;
      --    end if;

      --if li_des_sh_cust_id = 1096 -- To Budd or li_des_sh_cust_id = 1251 then
      --   then
      --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; i := i +1;
      --      x12_table(i) :=  'MEA*PD*TH*' || to_char(skidinfo_rec.sheet_net_wt) || '*24'; i := i +1;
      --elsif   li_des_sh_cust_id = 1251   --To Eagle Steel
      --  then
      --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*01'; i := i +1;
      --      x12_table(i) :=  'MEA*PD*WT*' || to_char(skidinfo_rec.sheet_net_wt) || '*24'; i := i +1;
      --      x12_table(i) :=  'MEA*PD*TH*' || to_char(skidinfo_rec.gauge) || '*EM'; i:=i+1;
      --    x12_table(i) :=  'MEA*PD*WD*'||'44.875'||'*IN'; i:=i+1;
      --    x12_table(i) :=  'MEA*PD*LN*'||to_char(skidinfo_rec.skid_pieces)||'*LF';  i:=i+1;
      --else  --All else, Ford dirct shiping program
                        
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*N" to "MEA*WT*N"
      --x12_table(i) := 'MEA*WT*N*' || to_char(skidinfo_rec.sheet_net_wt) || '*01';
      x12_table(i) := 'MEA*PD*N*' || to_char(skidinfo_rec.sheet_net_wt) || '*01';
      i := i + 1;
                        
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*WT" to "MEA*CT*NL"
      --x12_table(i) := 'MEA*CT*NL*' || to_char(skidinfo_rec.skid_pieces) || '*PC';
      --i := i + 1;

      --x12_table(i) := 'MEA*WT*G*' || to_char(skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt) || '*01';
      x12_table(i) := 'MEA*PD*G*' || to_char(skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt) || '*01';
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      --x12_table(i) := 'MEA*PD*GG*' || ll_coil_gauge;
      --i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      --x12_table(i) := 'MEA*PD*WD*' || ll_coil_width;
      --i := i + 1;

      /*
      IF (skidinfo_rec.sheet_theoretical_wt IS NULL) OR
         (skidinfo_rec.sheet_theoretical_wt = 0) THEN
        x12_table(i) := 'MEA*PD*G*' || to_char(ll_shipment_gt) || '*01';
        i := i + 1;
      ELSE
        x12_table(i) := 'MEA*PD*G*' ||
                        to_char(skidinfo_rec.sheet_theoretical_wt) || '*01';
        i := i + 1;
      END IF;
      */
      --end if;

      -- fill in lot num
      /*
      SELECT COUNT(*)
        INTO li_rc
        FROM sheet_skid_detail
       WHERE sheet_skid_detail.sheet_skid_num = skidinfo_rec.sheet_skid_num;

      ls_lot_num := skidinfo_rec.lot_num;
      ls_coil_id := skidinfo_rec.coil_id;

      IF li_rc = 1 THEN
        SELECT lot_num, coil_org_num
          INTO ls_lot_num, ls_coil_id
          FROM coil
         WHERE coil.coil_abc_num =
               (SELECT coil_abc_num
                  FROM production_sheet_item
                 WHERE production_sheet_item.prod_item_num =
                       (SELECT prod_item_num
                          FROM sheet_skid_detail
                         WHERE sheet_skid_detail.sheet_skid_num =
                               skidinfo_rec.sheet_skid_num));
      END IF;
      */
      --if li_des_sh_cust_id = 1251   --Eagle need coil ID here instead of lot number
      --then
      --x12_table(i) :=  'REF*HC*' || skidinfo_rec.coil_id ; i := i +1;
      --else
                        
      --Alex Gerlants. 10/18/2018. Changed from "REF*HC" to "REF*BT"
      x12_table(i) := 'REF*HC*' || ls_lot_num;
      i := i + 1;
      --end if;

      --x12_table(i) := 'REF*LS*' || to_char(skidinfo_rec.sheet_skid_num);
      --Alex Gerlants. 10/18/2018. Changed from "REF*LS" to "REF*SE"
      x12_table(i) := 'REF*SE*' || skidinfo_rec.sheet_skid_display_num;
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      x12_table(i) := 'REF*LS*' || ls_coil_org_num;
      i := i + 1;
      
      li_hl01 := li_hl01 + 1;
      li_rowcount := alcan_ford_856_cur%ROWCOUNT;
      x12_table(li_td1) := 'TD1*PLT71*' || to_char(li_rowcount);
  END LOOP; --End of 'FOR skidinfo_rec IN alcan_ford_856_cur LOOP'
  --Skid loop end ------------------------------------------------------------------

  -- DBMS_OUTPUT.PUT_LINE ('rowcount' || to_char(li_rowcount));

  -- if li_des_sh_cust_id = 1096 or li_des_sh_cust_id = 1251 then
  --   x12_table(i) :=  'CTT*' || to_char(li_HL01 - 1) ||'*' || to_char(ll_shipment_pc*2) ;
  --   i := i +1;
  -- else
  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '*' ||
                  to_char(li_rowcount + ll_shipment_pc);
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  --x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0') || chr(10); --Line feed character at end 
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0') || chr(13); --Carriage Return  at end

  -- Write X.12 to file
  -- To FORD

  /** Write file to /templar/templar/incoming/senddata
  /*
  **/

  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  --edi_file:= 'S_alcan_ford_ford_' || to_char(ll_edi_file_id) ||'.x12';

  -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
  -- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
    --        v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
  END LOOP;
  utl_file.fclose(edi_file_handle);

  --To ALCAN

  /*
  SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;
  SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id_alcan FROM DUAL;
  edi_file:= 'S_alcan_ford_alcan_' || to_char(ll_edi_file_id_alcan) ||'.x12';
  edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');
  x12_table(0) := 'ISA*00*'||'          *00*          *01*039630926T     *09*0015049350011G *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0')||'*0*P**';
  x12_table(1) := 'GS*SH*R0P7A*'||'001504935001' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  x12_table(i-1) :=  'GE*1*' || to_char (ll_gs_log);
  x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');
  for j in 0..i loop
   UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
       v_edi_text_alcan:=v_edi_text_alcan||x12_table(j)||CHR(10);
  end loop;
  UTL_FILE.FCLOSE(edi_file_handle);

  */

  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  /* Temporary comment out during development *********************************************
  
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE,
         edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;

  INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (ll_edi_file_id,
     '039630926',
     ls_su,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856');
  COMMIT;
  */

  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  --exception
  --   when invalid_operation
  --   then
  --      DBMS_--OUTPUT.PUT_LINE('Invalid operation.');

  --  when others
  --  then
  --      DBMS_OUTPUT.PUT_LINE ('System Error');
  --      UTL_FILE.FCLOSE(edi_file_handle);

  RETURN 1;
END edi_stellantis_856_X12;
--------------------------------------------------------
--  DDL for Function EDI_TWB_856_X12
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_TWB_856_X12" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*
  Aluminum Blanking: DUNS: 01 039630926T
  Customer:   2992 - TWB
  End User:   1840 - GM-LANSING    
              2611 - GM-FLINT -D - 3
              2850 - GM-PONT  P14-4 1/2

  */


  edi_loc VARCHAR2(50);
  --edi_loc varchar2(50):='/tmp';
  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_prefix VARCHAR2(50) := 'S_twb_856_'; --Production
  --edi_file_prefix VARCHAR2(50) := 's_twb_856_'; --Development
  edi_file_handle utl_file.file_type;

  li_customer_id    shipment.customer_id%TYPE;
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;
  ls_sf VARCHAR2(50);
  ls_eq_type VARCHAR2(10);
  ls_su      VARCHAR2(50);
  ls_st_duns VARCHAR2(50);
  ls_po      VARCHAR2(30);
  ls_auth_code   VARCHAR2(32);
  ll_gs_log  INTEGER;
  ll_st_log  INTEGER;
  ll_bsn_log INTEGER;

  ls_today VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD');
  ls_today_2digits_year VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  ls_now   VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  li_rowcount INTEGER;
  li_hl01 INTEGER;
  ll_shipment_nt INTEGER;
  ll_shipment_gt INTEGER;
  ll_shipment_pc INTEGER;
  li_td1 INTEGER;
  li_rc  INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_vehicle_id_prefix VARCHAR2(50);
  ls_scac              carrier.scac%TYPE;
  ls_carrier_full_name VARCHAR2(18);
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_carrier_initial   VARCHAR2(50);
  ldt_shipment         DATE;
   ll_temp         INTEGER;
  ls_enduser_part VARCHAR2(50);
  li_des_id       INTEGER;

  ll_edi_file_id INTEGER;

  ls_lot_num VARCHAR2(32);
  ls_coil_id VARCHAR2(32);
  ls_des_cust_name VARCHAR2(18);
  
  ls_coil_org_num		        coil.coil_org_num%TYPE; 
  ll_coil_gauge		          coil.coil_gauge%TYPE;
  ll_coil_width		          coil.coil_width%TYPE;
  ld_ship_date              date;
  li_is_novelis             integer;
  ln_skid_type_if_whed      sheet_skid.skid_type_if_whed%TYPE;
  ls_time                   char(4);
  ls_orig_customer_po       customer_order.orig_customer_po%TYPE;
  ll_width                  number(10,5);
  ll_skid_ticket_if_whed    sheet_skid.skid_ticket_if_whed%TYPE;

  CURSOR alcan_ford_856_cur IS
    SELECT sheet_packing_item.sh_packing_item,
           'MULTIPLE' lot_num,
           'MULTIPLE' coil_id,
           customer_order.orig_customer_po,
           customer_order.order_abc_num,
           customer_order.enduser_po,
           customer_order.created_date,
           order_item.order_item_num,
           order_item.enduser_part_num,
           order_item.supplier_code,
           order_item.gauge,
           sheet_skid. ab_job_num,
           sheet_skid.sheet_skid_num,
           sheet_skid.sheet_skid_display_num,
           sheet_skid.sheet_net_wt,
           sheet_skid.sheet_tare_wt,
           sheet_skid. skid_pieces,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_theoretical_wt,
           NULL done
      FROM customer_order,
           order_item,
           sheet_skid,
           ab_job,
           shipment,
           sheet_packing_item
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list);

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table    store_tabletype;
  i            BINARY_INTEGER := 0;
  skidinfo_rec alcan_ford_856_cur%ROWTYPE;

BEGIN
  
  edi_loc := dbo.get_edi_destination('EDI_DIR');

  -- Get Customer ID, End user ID, authorization code
  SELECT customer_id, des_sh_cust_id, nvl(shipment_athorization_code, 'NA')
    INTO li_customer_id, li_des_sh_cust_id, ls_auth_code
  FROM shipment
  WHERE shipment.packing_list = al_packing_list;
  
  IF NOT SQL%FOUND THEN
   RETURN - 1;
  END IF;
  
  if li_customer_id <> 2992 then --Customer is NOT TWB
    return 1; --Nothing to do here
  end if;
  
  select shipment_edi856_date, des_sh_cust_id
  into   ld_ship_date, li_des_sh_cust_id
  from   shipment
  where  shipment.packing_list = al_packing_list;
   
  if not (ld_ship_date is null) then --ASN already sent
    return 100;
  end if;

  --1840 - GM-LANSING    
  --2611 - GM-FLINT -D - 3
  --2850 - GM-PONT  P14-4 1/2
  IF NOT (li_des_sh_cust_id IN (2850, 2611, 1840)) THEN
    RETURN 200; --Wrong destination customer
  END IF;

  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(sheet_skid.sheet_net_wt),
         SUM(sheet_skid.sheet_net_wt) + SUM(sheet_skid.sheet_tare_wt),
         SUM(sheet_skid.skid_pieces)
    INTO ll_shipment_nt, ll_shipment_gt, ll_shipment_pc
    FROM sheet_skid, sheet_packing_item, shipment
   WHERE shipment.packing_list = sheet_packing_item.packing_list
     AND sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
     AND shipment.packing_list = al_packing_list;
  IF ll_shipment_pc = 0 THEN
    RETURN 100;
  END IF; -- empty shipment

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  ls_sf := '039630926'; --Production
  --ls_sf := '2NDSFTP'; --Development

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.vehicle_id_prefix, '9999'),
         nvl(shipment.equipment_type, 'NA'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'PT'), -- 'PT' = Protected Trailer
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE)
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_vehicle_id_prefix,
         ls_eq_type,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_carrier_initial,
         ldt_shipment
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;

  SELECT nvl(customer_duns_number_string, '00000000'), customer_short_name
    INTO ls_st_duns, ls_des_cust_name
    FROM customer
   WHERE customer_id = li_des_sh_cust_id;

  IF (ls_st_duns = '00000000') THEN
    RETURN 200;
  END IF; --No Ship to DUNS

  SELECT nvl(customer_duns_number_string, '00000000')
    INTO ls_su
    FROM customer
   WHERE customer_id = li_customer_id;
  IF (ls_su = '00000000') THEN
    RETURN 200;
  END IF; --No Supplier DUNS

  -- Get SCAC(Standard Carrier Alpha Code)
  SELECT nvl(carrier.scac, 'NONE'), LPAD(carrier.carrier_full_name, 17)
    INTO ls_scac, ls_carrier_full_name
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);

  --Production
  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *01*039630926T     *01*789153079      *' ||
                  ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*P*>';
  
  --Development                
  --x12_table(i) := 'ISA*00*' ||
  --                '          *00*          *ZZ*2NDSFTP        *01*789153079      *' ||
  --                ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
  --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T*>';
                  
  i := i + 1;

  --Alex Gerlants. 10/16/2018. Changed from "002002" to "004010"
  --Production
  x12_table(1) := 'GS*SH*R0P7A*' || '789153079' || '*' || ls_today || '*' ||
                  ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  --Development
  --x12_table(1) := 'GS*SH*2NDSFTP*' || '789153079' || '*' || ls_today || '*' ||
  --               ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;
  --x12_table(i):= 'BSN*00*' || to_char(ll_bill_of_lading) || '*' || ls_today || '*' || ls_now;
  x12_table(i) := 'BSN*00*' || to_char(al_packing_list) || '*' || ls_today || '*' ||
                  ls_now;
  i := i + 1;
  
  --Alex Gerlants. 08/07/2018.
  --Changed to populate with actual ship date instead of current date and time.
  --The reason is that when we send 856 on a later date, this date is not correct.
  --x12_table(i) := 'DTM*011*' || ls_today || '*' || ls_now;
  --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  
  --Alex Gerlants. 01/09/2020. Added the IF statement below.
  --If users do not enter time part in shipment.shipment_actualed_date_time,
  --856 will have system time in 'DTM*011*' and 'DTM*017*'
  
  ls_time := to_char(ldt_shipment, 'HH24MI');
  
  if ls_time <> '0000' then --User entered time
    x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                                                        to_char(ldt_shipment, 'HH24MI');
  else --User did not enter time  
    x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                                                        to_char(sysdate, 'HH24MI');
  end if;
  i := i + 1;
  
  --Alex Gerlants. 10/18/2018. Changed from "YYMMDD" to "YYYYMMDD"
  --Moved here from the below
  if ls_time <> '0000' then --User entered time
    x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                    to_char(ldt_shipment, 'HH24MI');
  else --User did not enter time
    x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                    to_char(sysdate, 'HH24MI');
  end if;
  i := i + 1;

  -- First Level HL
  --Shipment information **********************************************************
  x12_table(i) := 'HL*1**S*1';
  i := i + 1;
  --Alex Gerlants. 10/16/2018. Changed from "MEA*PD*G*" to "MEA*WT*G*"
  x12_table(i) := 'TD1*COL52*1****N*' || to_char(ll_shipment_nt) || '*LB';
  i := i + 1;
  
  x12_table(i) := 'TD1*COL52*1****G*' || to_char(ll_shipment_gt) || '*LB';
  li_td1 := i;
  i := i + 1;
  
  x12_table(i) := 'TD5**2*' || ltrim(rtrim(ls_carrier_full_name)) || '*M*1*CL';
  i := i + 1;
  
  --x12_table(i) := 'TD3*TL*' || ls_carrier_desc_code || '*' || ls_scac || '*' || ls_vehicle_id_prefix;
  x12_table(i) := 'TD3*TL*' || ls_scac || '*1';
  i := i + 1;
  
  x12_table(i) := 'REF*MB*' || to_char(ll_bill_of_lading);
  i := i + 1;
  
  select   distinct customer_order.orig_customer_po, order_item.enduser_part_num, f_get_width_4order_item(order_item.order_abc_num, order_item.order_item_num)
  into     ls_orig_customer_po, ls_enduser_part, ll_width
  from     sheet_packing_item
           join sheet_skid on sheet_skid.sheet_skid_num = sheet_packing_item.sheet_skid_num
           join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
           join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
           join order_item on customer_order.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
  where    sheet_packing_item.packing_list = al_packing_list;
  
  x12_table(i) := 'FOB*PO';
  i := i + 1;
  
  x12_table(i) := 'N1*OU*' || 'Aluminum Blanking Co*1*' || ls_sf;
  i := i + 1;
  
  li_des_id := 1;

  x12_table(i) := 'N1*ST**1*' || ls_st_duns;
  i := i + 1;
  
    x12_table(i) := 'N1*SF*' || 'Aluminum Blanking Co*1*' || ls_sf;
  i := i + 1;
  
  -- Second Level HL based on End User PO
  OPEN alcan_ford_856_cur;
  FETCH alcan_ford_856_cur
    INTO skidinfo_rec;
      ls_enduser_part := skidinfo_rec.ENDUSER_PART_NUM;

  SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
    INTO ls_enduser_part
    FROM "ORDER_ITEM", "SHEET_SKID"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
     AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
     AND ("SHEET_SKID"."SHEET_SKID_NUM" = skidinfo_rec.sheet_skid_num);

  --Order information **********************************************************
  x12_table(i) := 'HL*2*1*O*1';
  i := i + 1;
  IF ls_enduser_part IS NULL THEN
    ls_enduser_part := 'NA';
  END IF;

  SELECT "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO"
    INTO ls_po
    FROM "SHEET_SKID", "CUSTOMER_ORDER"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
         "CUSTOMER_ORDER"."ORDER_ABC_NUM")
     AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num);

  x12_table(i) := 'LIN**VO*' || ls_po;
  i := i + 1;
  
  x12_table(i) := 'PRF*' || ls_po;
  i := i + 1;
  
  x12_table(i) := 'REF*PM*' || ls_enduser_part;
  i := i + 1;

  CLOSE alcan_ford_856_cur;

  -- Third Level HL Under a P.O.
  li_hl01 := 3;

  --Skid loop begin ----------------------------------------------------------------
  --Skid information **********************************************************
  FOR skidinfo_rec IN alcan_ford_856_cur LOOP
    
      --In case of a split skid, we are creating just 1 HL for this skid
      --with just 1 coil for this skid.
      select distinct 
             coil.coil_org_num,
             coil.coil_gauge,
             coil.coil_width,
             coil.lot_num,
             nvl(skid_type_if_whed, -1)
      into   ls_coil_org_num,
             ll_coil_gauge,
             ll_coil_width,
             ls_lot_num,
             ln_skid_type_if_whed
      FROM "COIL",   
           "PRODUCTION_SHEET_ITEM",   
           "SHEET_SKID",   
           "SHEET_SKID_DETAIL",   
           "PROCESS_COIL"  
     WHERE ( "COIL"."COIL_ABC_NUM" = "PRODUCTION_SHEET_ITEM"."COIL_ABC_NUM" ) and  
           ( "SHEET_SKID_DETAIL"."SHEET_SKID_NUM" = "SHEET_SKID"."SHEET_SKID_NUM" ) and  
           ( "SHEET_SKID_DETAIL"."PROD_ITEM_NUM" = "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NUM" ) and  
           ( "COIL"."COIL_ABC_NUM" = "PROCESS_COIL"."COIL_ABC_NUM" ) and  
           ( "PRODUCTION_SHEET_ITEM"."AB_JOB_NUM" = "PROCESS_COIL"."AB_JOB_NUM" ) and  
           ( (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num)  ) and
           ( (rownum = 1)  ); --We need just 1 coil for each skid
  
      --Alex Gerlants. 04/01/2019. Begin
      if ln_skid_type_if_whed > -1 then --Warehouse skid
          --Get gauge and part width
          select distinct order_item.gauge,
                 f_get_part_width_per_job(ab_job.ab_job_num) 
          into   ll_coil_gauge,
                 ll_coil_width
          from   sheet_skid
                 join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
                 join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
                 join customer_order on customer_order.order_abc_num = order_item.order_abc_num
          where  sheet_skid_num = skidinfo_rec.sheet_skid_num
          and    (order_item.gauge is not null and f_get_part_width_per_job(sheet_skid.ab_job_num) is not null)
          and    rownum = 1;
      end if;
      --Alex Gerlants. 04/01/2019. End
  
      x12_table(i) := 'HL*' || rtrim(ltrim(to_char(li_hl01, '99999'))) || '*2*I';
      i := i + 1;
      
      select   skid_ticket_if_whed
      into     ll_skid_ticket_if_whed
      from     sheet_skid
      where    sheet_skid_num = skidinfo_rec.sheet_skid_num;
      
      x12_table(i) := 'LIN**SN*' || to_char(ll_skid_ticket_if_whed); --Customer (TWB) skid number
      i := i + 1;
                        
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*N" to "MEA*WT*N"
      x12_table(i) := 'MEA*WT**' || to_char(skidinfo_rec.sheet_net_wt) ||
                      '*01';
      i := i + 1;
      
      x12_table(i) := 'MEA*PD*TH*' || to_char(ll_coil_gauge) || '*E8';
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      x12_table(i) := 'MEA*PD*WD*' || to_char(ll_width) || '*E8';
      i := i + 1;
                        
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*WT" to "MEA*CT*NL"
      x12_table(i) := 'MEA*CT*NL*' || to_char(skidinfo_rec.skid_pieces) || '*PC';
      i := i + 1;

      -- changed to all gross wt per novelis 1/30/2015
      --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*G" to "MEA*WT*G"
      --x12_table(i) := 'MEA*WT*G*' || to_char(skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt) || '*01';
      --i := i + 1;
      




      x12_table(i) := 'REF*SE*' || to_char(skidinfo_rec.sheet_skid_num); --added by Victor H. on 06-2012 for Novelis locatio code request
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. New line 
      --x12_table(i) := 'REF*LS*' || ls_coil_org_num;
      --i := i + 1;
      
      li_hl01 := li_hl01 + 1;
      li_rowcount := alcan_ford_856_cur%ROWCOUNT;
      --x12_table(li_td1) := 'TD1*PLT90*' || to_char(li_rowcount);
  END LOOP; --End of 'FOR skidinfo_rec IN alcan_ford_856_cur LOOP'
  --Skid loop end ------------------------------------------------------------------

  -- DBMS_OUTPUT.PUT_LINE ('rowcount' || to_char(li_rowcount));

  x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  -- Write X.12 to file
  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  --edi_file:= 'S_alcan_ford_ford_' || to_char(ll_edi_file_id) ||'.x12';

  -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
  -- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
    --        v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
  END LOOP;
  utl_file.fclose(edi_file_handle);

  --To ALCAN

  /*
  SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;
  SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id_alcan FROM DUAL;
  edi_file:= 'S_alcan_ford_alcan_' || to_char(ll_edi_file_id_alcan) ||'.x12';
  edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');
  x12_table(0) := 'ISA*00*'||'          *00*          *01*039630926T     *09*0015049350011G *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0')||'*0*P**';
  x12_table(1) := 'GS*SH*R0P7A*'||'001504935001' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  x12_table(i-1) :=  'GE*1*' || to_char (ll_gs_log);
  x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');
  for j in 0..i loop
   UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
       v_edi_text_alcan:=v_edi_text_alcan||x12_table(j)||CHR(10);
  end loop;
  UTL_FILE.FCLOSE(edi_file_handle);

  */

  /* The following code added by Tony, for update archive*/

    --INSERT INTO edi_log (edi_log_timestamp,customer_id,
    --       customer_edi_name,edi_log_contents,edi_file_id,edi_text)
    --  VALUES (SYSDATE,li_customer_id,ll_customer_edi_name,
    --         'EDI:'||ll_customer_edi_name||' generated successfully.',ll_edi_file_id,v_edi_text);
    -- COMMIT;

  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE,
         edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;

  --added by Victor Huang on 12/07 for verifying 997
  INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (ll_edi_file_id,
     '039630926',
     ls_su,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856');
  COMMIT;

  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  RETURN 1;
END edi_twb_856_X12;
--------------------------------------------------------
--  DDL for Function EDI_TWB_856_X12_2
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_TWB_856_X12_2" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*
  Aluminum Blanking: DUNS: 01 039630926T
  Customer:   2992 - TWB
  End User:   1840 - GM-LANSING    
              2611 - GM-FLINT -D - 3
              2850 - GM-PONT  P14-4 1/2

  */


  edi_loc VARCHAR2(50);
  --edi_loc varchar2(50):='/tmp';
  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_prefix VARCHAR2(50) := 'S_twb_856_'; --Production
  --edi_file_prefix VARCHAR2(50) := 's_twb_856_'; --Development
  edi_file_handle utl_file.file_type;

  li_customer_id    shipment.customer_id%TYPE;
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;
  ls_sf VARCHAR2(50);
  ls_eq_type VARCHAR2(10);
  ls_su      VARCHAR2(50);
  ls_st_duns VARCHAR2(50);
  ls_po      VARCHAR2(30);
  ls_auth_code   VARCHAR2(32);
  ll_gs_log  INTEGER;
  ll_st_log  INTEGER;
  ll_bsn_log INTEGER;

  ls_today VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD');
  ls_today_2digits_year VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  ls_now   VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  li_rowcount INTEGER;
  li_hl01 INTEGER;
  hl_order integer;
  ll_shipment_nt INTEGER;
  ll_shipment_gt INTEGER;
  ll_shipment_pc INTEGER;
  li_td1 INTEGER;
  li_rc  INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_vehicle_id_prefix VARCHAR2(50);
  ls_scac              carrier.scac%TYPE;
  ls_carrier_full_name VARCHAR2(18);
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_carrier_initial   VARCHAR2(50);
  ldt_shipment         DATE;
   ll_temp         INTEGER;
  ls_enduser_part VARCHAR2(50);
  li_des_id       INTEGER;

  ll_edi_file_id INTEGER;

  ls_lot_num VARCHAR2(32);
  ls_coil_id VARCHAR2(32);
  ls_des_cust_name VARCHAR2(18);
  
  ls_coil_org_num		        coil.coil_org_num%TYPE; 
  ll_coil_gauge		          coil.coil_gauge%TYPE;
  ll_coil_width		          coil.coil_width%TYPE;
  ld_ship_date              date;
  li_is_novelis             integer;
  ln_skid_type_if_whed      sheet_skid.skid_type_if_whed%TYPE;
  ls_time                   char(4);
  ls_orig_customer_po       customer_order.orig_customer_po%TYPE;
  ll_width                  number(10,5);
  ll_skid_ticket_if_whed    sheet_skid.skid_ticket_if_whed%TYPE;
  ll_order_abc_num          customer_order.order_abc_num%TYPE;
  ll_order_item_num         order_item.order_item_num%TYPE;
  
  cursor order_info_cur is
  select   distinct ab_job.order_abc_num, ab_job.order_item_num, customer_order.orig_customer_po, order_item.enduser_part_num
  from     sheet_packing_item
           join sheet_skid on sheet_skid.sheet_skid_num = sheet_packing_item.sheet_skid_num
           join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
           join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
           join order_item on ab_job.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
  where    sheet_packing_item.packing_list = al_packing_list;
  
  order_info_rec order_info_cur%ROWTYPE;

  CURSOR alcan_ford_856_cur IS
    SELECT sheet_packing_item.sh_packing_item,
           'MULTIPLE' lot_num,
           'MULTIPLE' coil_id,
           customer_order.orig_customer_po,
           customer_order.order_abc_num,
           customer_order.enduser_po,
           customer_order.created_date,
           order_item.order_item_num,
           order_item.enduser_part_num,
           order_item.supplier_code,
           order_item.gauge,
           sheet_skid. ab_job_num,
           sheet_skid.sheet_skid_num,
           sheet_skid.sheet_skid_display_num,
           sheet_skid.sheet_net_wt,
           sheet_skid.sheet_tare_wt,
           sheet_skid. skid_pieces,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_theoretical_wt,
           NULL done
      FROM customer_order,
           order_item,
           sheet_skid,
           ab_job,
           shipment,
           sheet_packing_item
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list)
       and customer_order.order_abc_num = ll_order_abc_num and order_item.order_item_num = ll_order_item_num;
       
  skidinfo_rec alcan_ford_856_cur%ROWTYPE;

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table    store_tabletype;
  i            BINARY_INTEGER := 0;
  

BEGIN
  
  edi_loc := dbo.get_edi_destination('EDI_DIR');

  -- Get Customer ID, End user ID, authorization code
  SELECT customer_id, des_sh_cust_id, nvl(shipment_athorization_code, 'NA')
    INTO li_customer_id, li_des_sh_cust_id, ls_auth_code
  FROM shipment
  WHERE shipment.packing_list = al_packing_list;
  
  IF NOT SQL%FOUND THEN
   RETURN - 1;
  END IF;
  
  if li_customer_id <> 2992 then --Customer is NOT TWB
    return 1; --Nothing to do here
  end if;
  
  select shipment_edi856_date, des_sh_cust_id
  into   ld_ship_date, li_des_sh_cust_id
  from   shipment
  where  shipment.packing_list = al_packing_list;
   
  if not (ld_ship_date is null) then --ASN already sent
    return 100;
  end if;

  --1840 - GM-LANSING    
  --2611 - GM-FLINT -D - 3
  --2850 - GM-PONT  P14-4 1/2
  IF NOT (li_des_sh_cust_id IN (2850, 2611, 1840)) THEN
    RETURN 200; --Wrong destination customer
  END IF;

  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(sheet_skid.sheet_net_wt),
         SUM(sheet_skid.sheet_net_wt) + SUM(sheet_skid.sheet_tare_wt),
         SUM(sheet_skid.skid_pieces)
    INTO ll_shipment_nt, ll_shipment_gt, ll_shipment_pc
    FROM sheet_skid, sheet_packing_item, shipment
   WHERE shipment.packing_list = sheet_packing_item.packing_list
     AND sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
     AND shipment.packing_list = al_packing_list;
  IF ll_shipment_pc = 0 THEN
    RETURN 100;
  END IF; -- empty shipment

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  ls_sf := '039630926'; --Production
  --ls_sf := '2NDSFTP'; --Development

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.vehicle_id_prefix, '9999'),
         nvl(shipment.equipment_type, 'NA'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'PT'), -- 'PT' = Protected Trailer
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE)
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_vehicle_id_prefix,
         ls_eq_type,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_carrier_initial,
         ldt_shipment
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;

  SELECT nvl(customer_duns_number_string, '00000000'), customer_short_name
    INTO ls_st_duns, ls_des_cust_name
    FROM customer
   WHERE customer_id = li_des_sh_cust_id;

  IF (ls_st_duns = '00000000') THEN
    RETURN 200;
  END IF; --No Ship to DUNS

  SELECT nvl(customer_duns_number_string, '00000000')
    INTO ls_su
    FROM customer
   WHERE customer_id = li_customer_id;
  IF (ls_su = '00000000') THEN
    RETURN 200;
  END IF; --No Supplier DUNS

  -- Get SCAC(Standard Carrier Alpha Code)
  SELECT nvl(carrier.scac, 'NONE'), LPAD(carrier.carrier_full_name, 17)
    INTO ls_scac, ls_carrier_full_name
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);

  --Production
  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *01*039630926T     *01*789153079      *' ||
                  ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*P*>';
  
  --Development                
  --x12_table(i) := 'ISA*00*' ||
  --                '          *00*          *ZZ*2NDSFTP        *01*789153079      *' ||
  --                ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
  --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T*>';
                  
  i := i + 1;

  --Alex Gerlants. 10/16/2018. Changed from "002002" to "004010"
  --Production
  x12_table(1) := 'GS*SH*R0P7A*' || '789153079' || '*' || ls_today || '*' ||
                  ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  --Development
  --x12_table(1) := 'GS*SH*2NDSFTP*' || '789153079' || '*' || ls_today || '*' ||
  --               ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;
  --x12_table(i):= 'BSN*00*' || to_char(ll_bill_of_lading) || '*' || ls_today || '*' || ls_now;
  x12_table(i) := 'BSN*00*' || to_char(al_packing_list) || '*' || ls_today || '*' ||
                  ls_now;
  i := i + 1;
  
  --Alex Gerlants. 08/07/2018.
  --Changed to populate with actual ship date instead of current date and time.
  --The reason is that when we send 856 on a later date, this date is not correct.
  --x12_table(i) := 'DTM*011*' || ls_today || '*' || ls_now;
  --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  
  --Alex Gerlants. 01/09/2020. Added the IF statement below.
  --If users do not enter time part in shipment.shipment_actualed_date_time,
  --856 will have system time in 'DTM*011*' and 'DTM*017*'
  
  ls_time := to_char(ldt_shipment, 'HH24MI');
  
  if ls_time <> '0000' then --User entered time
    x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                                                        to_char(ldt_shipment, 'HH24MI');
  else --User did not enter time  
    x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                                                        to_char(sysdate, 'HH24MI');
  end if;
  i := i + 1;
  
  --Alex Gerlants. 10/18/2018. Changed from "YYMMDD" to "YYYYMMDD"
  --Moved here from the below
  if ls_time <> '0000' then --User entered time
    x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                    to_char(ldt_shipment, 'HH24MI');
  else --User did not enter time
    x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                    to_char(sysdate, 'HH24MI');
  end if;
  i := i + 1;

  -- First Level HL
  --Shipment information **********************************************************
  x12_table(i) := 'HL*1**S*1';
  i := i + 1;
  --Alex Gerlants. 10/16/2018. Changed from "MEA*PD*G*" to "MEA*WT*G*"
  x12_table(i) := 'TD1*COL52*1****N*' || to_char(ll_shipment_nt) || '*LB';
  i := i + 1;
  
  x12_table(i) := 'TD1*COL52*1****G*' || to_char(ll_shipment_gt) || '*LB';
  li_td1 := i;
  i := i + 1;
  
  x12_table(i) := 'TD5**2*' || ltrim(rtrim(ls_carrier_full_name)) || '*M*1*CL';
  i := i + 1;
  
  --x12_table(i) := 'TD3*TL*' || ls_carrier_desc_code || '*' || ls_scac || '*' || ls_vehicle_id_prefix;
  x12_table(i) := 'TD3*TL*' || ls_scac || '*1';
  i := i + 1;
  
  x12_table(i) := 'REF*MB*' || to_char(ll_bill_of_lading);
  i := i + 1;
  
  /*
  select   distinct customer_order.orig_customer_po, order_item.enduser_part_num, f_get_width_4order_item(order_item.order_abc_num, order_item.order_item_num)
  into     ls_orig_customer_po, ls_enduser_part, ll_width
  from     sheet_packing_item
           join sheet_skid on sheet_skid.sheet_skid_num = sheet_packing_item.sheet_skid_num
           join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
           join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
           join order_item on customer_order.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
  where    sheet_packing_item.packing_list = al_packing_list;
  */
  
  x12_table(i) := 'FOB*PO';
  i := i + 1;
  
  x12_table(i) := 'N1*OU*' || 'Aluminum Blanking Co*1*' || ls_sf;
  i := i + 1;
  
  li_des_id := 1;

  x12_table(i) := 'N1*ST**1*' || ls_st_duns;
  i := i + 1;
  
    x12_table(i) := 'N1*SF*' || 'Aluminum Blanking Co*1*' || ls_sf;
  i := i + 1;
  
  /*
  -- Second Level HL based on End User PO
  OPEN alcan_ford_856_cur;
  FETCH alcan_ford_856_cur
    INTO skidinfo_rec;
      ls_enduser_part := skidinfo_rec.ENDUSER_PART_NUM;

  SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
    INTO ls_enduser_part
    FROM "ORDER_ITEM", "SHEET_SKID"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
     AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
     AND ("SHEET_SKID"."SHEET_SKID_NUM" = skidinfo_rec.sheet_skid_num);

  --Order information **********************************************************
  
  x12_table(i) := 'HL*2*1*O*1';
  i := i + 1;
  IF ls_enduser_part IS NULL THEN
    ls_enduser_part := 'NA';
  END IF;

  SELECT "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO"
    INTO ls_po
    FROM "SHEET_SKID", "CUSTOMER_ORDER"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
         "CUSTOMER_ORDER"."ORDER_ABC_NUM")
     AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num);

  x12_table(i) := 'LIN**VO*' || ls_po;
  i := i + 1;
  
  x12_table(i) := 'PRF*' || ls_po;
  i := i + 1;
  
  x12_table(i) := 'REF*PM*' || ls_enduser_part;
  i := i + 1;

  CLOSE alcan_ford_856_cur;
  */
  
  li_hl01 := 1;

  -- Order information
  --OPEN order_info_cur;
  --FETCH order_info_cur
  --  INTO order_info_rec;
  
  hl_order := 0;
    
  for order_info_rec in order_info_cur loop
      
      li_hl01 := li_hl01 + 1;
      hl_order := li_hl01;
      
      x12_table(i) := 'HL*' || li_hl01 || '*1*O*1';
      i := i + 1;
      
      
    
      ls_enduser_part := order_info_rec.ENDUSER_PART_NUM;
      
      if ls_enduser_part is null then
        ls_enduser_part := 'NA';
      end if;
      
      ls_po := order_info_rec.orig_customer_po;
      ll_order_abc_num := order_info_rec.order_abc_num;
      ll_order_item_num := order_info_rec.order_item_num;
            
      select  f_get_width_4order_item(ll_order_abc_num, ll_order_item_num)
      into    ll_width  
      from dual;
      
      x12_table(i) := 'LIN**VO*' || ls_po;
      i := i + 1;
  
      x12_table(i) := 'PRF*' || ls_po;
      i := i + 1;
  
      x12_table(i) := 'REF*PM*' || ls_enduser_part;
      i := i + 1;
  
            --Skid loop begin ----------------------------------------------------------------
            --Skid information **********************************************************
            FOR skidinfo_rec IN alcan_ford_856_cur LOOP
              
                --In case of a split skid, we are creating just 1 HL for this skid
                --with just 1 coil for this skid.
                select distinct 
                       coil.coil_org_num,
                       coil.coil_gauge,
                       coil.coil_width,
                       coil.lot_num,
                       nvl(skid_type_if_whed, -1)
                into   ls_coil_org_num,
                       ll_coil_gauge,
                       ll_coil_width,
                       ls_lot_num,
                       ln_skid_type_if_whed
                FROM "COIL",   
                     "PRODUCTION_SHEET_ITEM",   
                     "SHEET_SKID",   
                     "SHEET_SKID_DETAIL",   
                     "PROCESS_COIL"  
               WHERE ( "COIL"."COIL_ABC_NUM" = "PRODUCTION_SHEET_ITEM"."COIL_ABC_NUM" ) and  
                     ( "SHEET_SKID_DETAIL"."SHEET_SKID_NUM" = "SHEET_SKID"."SHEET_SKID_NUM" ) and  
                     ( "SHEET_SKID_DETAIL"."PROD_ITEM_NUM" = "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NUM" ) and  
                     ( "COIL"."COIL_ABC_NUM" = "PROCESS_COIL"."COIL_ABC_NUM" ) and  
                     ( "PRODUCTION_SHEET_ITEM"."AB_JOB_NUM" = "PROCESS_COIL"."AB_JOB_NUM" ) and  
                     ( (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num)  ) and
                     ( (rownum = 1)  ); --We need just 1 coil for each skid
            
                --Alex Gerlants. 04/01/2019. Begin
                if ln_skid_type_if_whed > -1 then --Warehouse skid
                    --Get gauge and part width
                    select distinct order_item.gauge,
                           f_get_part_width_per_job(ab_job.ab_job_num) 
                    into   ll_coil_gauge,
                           ll_coil_width
                    from   sheet_skid
                           join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
                           join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
                           join customer_order on customer_order.order_abc_num = order_item.order_abc_num
                    where  sheet_skid_num = skidinfo_rec.sheet_skid_num
                    and    (order_item.gauge is not null and f_get_part_width_per_job(sheet_skid.ab_job_num) is not null)
                    and    rownum = 1;
                end if;
                --Alex Gerlants. 04/01/2019. End
            
                li_hl01 := li_hl01 + 1;
                
                x12_table(i) := 'HL*' || rtrim(ltrim(to_char(li_hl01, '99999'))) || '*' || hl_order || '*I';
                i := i + 1;
                
                
                
                select   skid_ticket_if_whed
                into     ll_skid_ticket_if_whed
                from     sheet_skid
                where    sheet_skid_num = skidinfo_rec.sheet_skid_num;
                
                x12_table(i) := 'LIN**SN*' || to_char(skidinfo_rec.sheet_skid_num); --ALBL skid number
                i := i + 1;
                                  
                --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*N" to "MEA*WT*N"
                x12_table(i) := 'MEA*WT**' || to_char(skidinfo_rec.sheet_net_wt) ||
                                '*01';
                i := i + 1;
                
                x12_table(i) := 'MEA*PD*TH*' || to_char(ll_coil_gauge) || '*E8';
                i := i + 1;
                
                --Alex Gerlants. 10/18/2018. New line 
                x12_table(i) := 'MEA*PD*WD*' || to_char(ll_width) || '*E8';
                i := i + 1;
                                  
                --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*WT" to "MEA*CT*NL"
                x12_table(i) := 'MEA*CT*NL*' || to_char(skidinfo_rec.skid_pieces) || '*PC';
                i := i + 1;

                x12_table(i) := 'REF*SE*' || to_char(ll_skid_ticket_if_whed); --TWB skid number
                i := i + 1;
                
                --Alex Gerlants. 10/18/2018. New line 
                --x12_table(i) := 'REF*LS*' || ls_coil_org_num;
                --i := i + 1;
                
                --li_hl01 := li_hl01 + 1;
                li_rowcount := alcan_ford_856_cur%ROWCOUNT;
                --x12_table(li_td1) := 'TD1*PLT90*' || to_char(li_rowcount);
            END LOOP; --End of 'FOR skidinfo_rec IN alcan_ford_856_cur LOOP'
            --Skid loop end ------------------------------------------------------------------
            
   end loop;

  -- DBMS_OUTPUT.PUT_LINE ('rowcount' || to_char(li_rowcount));

  x12_table(i) := 'CTT*' || to_char(li_hl01);
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  -- Write X.12 to file
  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  --edi_file:= 'S_alcan_ford_ford_' || to_char(ll_edi_file_id) ||'.x12';

  -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
  -- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
    --        v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
  END LOOP;
  utl_file.fclose(edi_file_handle);

  --To ALCAN

  /*
  SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;
  SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id_alcan FROM DUAL;
  edi_file:= 'S_alcan_ford_alcan_' || to_char(ll_edi_file_id_alcan) ||'.x12';
  edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');
  x12_table(0) := 'ISA*00*'||'          *00*          *01*039630926T     *09*0015049350011G *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0')||'*0*P**';
  x12_table(1) := 'GS*SH*R0P7A*'||'001504935001' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  x12_table(i-1) :=  'GE*1*' || to_char (ll_gs_log);
  x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');
  for j in 0..i loop
   UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
       v_edi_text_alcan:=v_edi_text_alcan||x12_table(j)||CHR(10);
  end loop;
  UTL_FILE.FCLOSE(edi_file_handle);

  */

  /* The following code added by Tony, for update archive*/

    --INSERT INTO edi_log (edi_log_timestamp,customer_id,
    --       customer_edi_name,edi_log_contents,edi_file_id,edi_text)
    --  VALUES (SYSDATE,li_customer_id,ll_customer_edi_name,
    --         'EDI:'||ll_customer_edi_name||' generated successfully.',ll_edi_file_id,v_edi_text);
    -- COMMIT;

  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE,
         edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;

  --added by Victor Huang on 12/07 for verifying 997
  INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (ll_edi_file_id,
     '039630926',
     ls_su,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856');
  COMMIT;

  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  RETURN 1;
END edi_twb_856_X12_2;
--------------------------------------------------------
--  DDL for Function EDI_TWB_856_X12_2_TEST
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_TWB_856_X12_2_TEST" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*
  Aluminum Blanking: DUNS: 01 039630926T
  Customer:   2992 - TWB
  End User:   1840 - GM-LANSING    
              2611 - GM-FLINT -D - 3
              2850 - GM-PONT  P14-4 1/2

  */


  edi_loc VARCHAR2(50);
  --edi_loc varchar2(50):='/tmp';
  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_prefix VARCHAR2(50) := 's_twb_856_'; --Production
  --edi_file_prefix VARCHAR2(50) := 's_twb_856_'; --Development
  edi_file_handle utl_file.file_type;

  li_customer_id    shipment.customer_id%TYPE;
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;
  ls_sf VARCHAR2(50);
  ls_eq_type VARCHAR2(10);
  ls_su      VARCHAR2(50);
  ls_st_duns VARCHAR2(50);
  ls_po      VARCHAR2(30);
  ls_auth_code   VARCHAR2(32);
  ll_gs_log  INTEGER;
  ll_st_log  INTEGER;
  ll_bsn_log INTEGER;

  ls_today VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD');
  ls_today_2digits_year VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  ls_now   VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  li_rowcount INTEGER;
  li_hl01 INTEGER;
  hl_order integer;
  ll_shipment_nt INTEGER;
  ll_shipment_gt INTEGER;
  ll_shipment_pc INTEGER;
  li_td1 INTEGER;
  li_rc  INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_vehicle_id_prefix VARCHAR2(50);
  ls_scac              carrier.scac%TYPE;
  ls_carrier_full_name VARCHAR2(18);
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_carrier_initial   VARCHAR2(50);
  ldt_shipment         DATE;
   ll_temp         INTEGER;
  ls_enduser_part VARCHAR2(50);
  li_des_id       INTEGER;

  ll_edi_file_id INTEGER;

  ls_lot_num VARCHAR2(32);
  ls_coil_id VARCHAR2(32);
  ls_des_cust_name VARCHAR2(18);
  
  ls_coil_org_num		        coil.coil_org_num%TYPE; 
  ll_coil_gauge		          coil.coil_gauge%TYPE;
  ll_coil_width		          coil.coil_width%TYPE;
  ld_ship_date              date;
  li_is_novelis             integer;
  ln_skid_type_if_whed      sheet_skid.skid_type_if_whed%TYPE;
  ls_time                   char(4);
  ls_orig_customer_po       customer_order.orig_customer_po%TYPE;
  ll_width                  number(10,5);
  ll_skid_ticket_if_whed    sheet_skid.skid_ticket_if_whed%TYPE;
  ll_order_abc_num          customer_order.order_abc_num%TYPE;
  ll_order_item_num         order_item.order_item_num%TYPE;
  
  cursor order_info_cur is
  select   distinct ab_job.order_abc_num, ab_job.order_item_num, customer_order.orig_customer_po, order_item.enduser_part_num
  from     sheet_packing_item
           join sheet_skid on sheet_skid.sheet_skid_num = sheet_packing_item.sheet_skid_num
           join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
           join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
           join order_item on ab_job.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
  where    sheet_packing_item.packing_list = al_packing_list;
  
  order_info_rec order_info_cur%ROWTYPE;

  CURSOR alcan_ford_856_cur IS
    SELECT sheet_packing_item.sh_packing_item,
           'MULTIPLE' lot_num,
           'MULTIPLE' coil_id,
           customer_order.orig_customer_po,
           customer_order.order_abc_num,
           customer_order.enduser_po,
           customer_order.created_date,
           order_item.order_item_num,
           order_item.enduser_part_num,
           order_item.supplier_code,
           order_item.gauge,
           sheet_skid. ab_job_num,
           sheet_skid.sheet_skid_num,
           sheet_skid.sheet_skid_display_num,
           sheet_skid.sheet_net_wt,
           sheet_skid.sheet_tare_wt,
           sheet_skid. skid_pieces,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_theoretical_wt,
           NULL done
      FROM customer_order,
           order_item,
           sheet_skid,
           ab_job,
           shipment,
           sheet_packing_item
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list)
       and customer_order.order_abc_num = ll_order_abc_num and order_item.order_item_num = ll_order_item_num;
       
  skidinfo_rec alcan_ford_856_cur%ROWTYPE;

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table    store_tabletype;
  i            BINARY_INTEGER := 0;
  

BEGIN
  
  edi_loc := dbo.get_edi_destination('EDI_DIR');

  -- Get Customer ID, End user ID, authorization code
  SELECT customer_id, des_sh_cust_id, nvl(shipment_athorization_code, 'NA')
    INTO li_customer_id, li_des_sh_cust_id, ls_auth_code
  FROM shipment
  WHERE shipment.packing_list = al_packing_list;
  
  IF NOT SQL%FOUND THEN
   RETURN - 1;
  END IF;
  
  if li_customer_id <> 2992 then --Customer is NOT TWB
    return 1; --Nothing to do here
  end if;
  
  select shipment_edi856_date, des_sh_cust_id
  into   ld_ship_date, li_des_sh_cust_id
  from   shipment
  where  shipment.packing_list = al_packing_list;
   
  if not (ld_ship_date is null) then --ASN already sent
    return 100;
  end if;

  --1840 - GM-LANSING    
  --2611 - GM-FLINT -D - 3
  --2850 - GM-PONT  P14-4 1/2
  IF NOT (li_des_sh_cust_id IN (2850, 2611, 1840)) THEN
    RETURN 200; --Wrong destination customer
  END IF;

  -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
  SELECT SUM(sheet_skid.sheet_net_wt),
         SUM(sheet_skid.sheet_net_wt) + SUM(sheet_skid.sheet_tare_wt),
         SUM(sheet_skid.skid_pieces)
    INTO ll_shipment_nt, ll_shipment_gt, ll_shipment_pc
    FROM sheet_skid, sheet_packing_item, shipment
   WHERE shipment.packing_list = sheet_packing_item.packing_list
     AND sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
     AND shipment.packing_list = al_packing_list;
  IF ll_shipment_pc = 0 THEN
    RETURN 100;
  END IF; -- empty shipment

  -- Get gs, st and bsn log sequence number
  SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
  SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
  SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

  ls_sf := '039630926'; --Production
  --ls_sf := '2NDSFTP'; --Development

  -- Get Shipment Info.
  SELECT shipment.bill_of_lading,
         nvl(shipment.vehicle_id, '9999'),
         nvl(shipment.vehicle_id_prefix, '9999'),
         nvl(shipment.equipment_type, 'NA'),
         nvl(shipment.transportation_method_code, 'Motor'),
         nvl(shipment.carrier_description_code, 'PT'), -- 'PT' = Protected Trailer
         nvl(shipment.carrier_initial, 'NA'),
         nvl(shipment.shipment_actualed_date_time, SYSDATE)
    INTO ll_bill_of_lading,
         ls_vehicle_id,
         ls_vehicle_id_prefix,
         ls_eq_type,
         ls_tran_method_code,
         ls_carrier_desc_code,
         ls_carrier_initial,
         ldt_shipment
    FROM shipment
   WHERE shipment.packing_list = al_packing_list;

  SELECT nvl(customer_duns_number_string, '00000000'), customer_short_name
    INTO ls_st_duns, ls_des_cust_name
    FROM customer
   WHERE customer_id = li_des_sh_cust_id;

  IF (ls_st_duns = '00000000') THEN
    RETURN 200;
  END IF; --No Ship to DUNS

  SELECT nvl(customer_duns_number_string, '00000000')
    INTO ls_su
    FROM customer
   WHERE customer_id = li_customer_id;
  IF (ls_su = '00000000') THEN
    RETURN 200;
  END IF; --No Supplier DUNS

  -- Get SCAC(Standard Carrier Alpha Code)
  SELECT nvl(carrier.scac, 'NONE'), LPAD(carrier.carrier_full_name, 17)
    INTO ls_scac, ls_carrier_full_name
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = al_packing_list);

  --Production
  x12_table(i) := 'ISA*00*' ||
                  '          *00*          *01*039630926T     *01*789153079      *' ||
                  ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*P*>';
  
  --Development                
  --x12_table(i) := 'ISA*00*' ||
  --                '          *00*          *ZZ*2NDSFTP        *01*789153079      *' ||
  --                ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
  --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T*>';
                  
  i := i + 1;

  --Alex Gerlants. 10/16/2018. Changed from "002002" to "004010"
  --Production
  x12_table(1) := 'GS*SH*R0P7A*' || '789153079' || '*' || ls_today || '*' ||
                  ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  --Development
  --x12_table(1) := 'GS*SH*2NDSFTP*' || '789153079' || '*' || ls_today || '*' ||
  --               ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                  
  i := i + 1;

  x12_table(i) := 'ST*856*' || to_char(ll_st_log);
  i := i + 1;
  --x12_table(i):= 'BSN*00*' || to_char(ll_bill_of_lading) || '*' || ls_today || '*' || ls_now;
  x12_table(i) := 'BSN*00*' || to_char(al_packing_list) || '*' || ls_today || '*' ||
                  ls_now;
  i := i + 1;
  
  --Alex Gerlants. 08/07/2018.
  --Changed to populate with actual ship date instead of current date and time.
  --The reason is that when we send 856 on a later date, this date is not correct.
  --x12_table(i) := 'DTM*011*' || ls_today || '*' || ls_now;
  --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
  
  --Alex Gerlants. 01/09/2020. Added the IF statement below.
  --If users do not enter time part in shipment.shipment_actualed_date_time,
  --856 will have system time in 'DTM*011*' and 'DTM*017*'
  
  ls_time := to_char(ldt_shipment, 'HH24MI');
  
  if ls_time <> '0000' then --User entered time
    x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                                                        to_char(ldt_shipment, 'HH24MI');
  else --User did not enter time  
    x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                                                        to_char(sysdate, 'HH24MI');
  end if;
  i := i + 1;
  
  --Alex Gerlants. 10/18/2018. Changed from "YYMMDD" to "YYYYMMDD"
  --Moved here from the below
  if ls_time <> '0000' then --User entered time
    x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                    to_char(ldt_shipment, 'HH24MI');
  else --User did not enter time
    x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                    to_char(sysdate, 'HH24MI');
  end if;
  i := i + 1;

  -- First Level HL
  --Shipment information **********************************************************
  x12_table(i) := 'HL*1**S*1';
  i := i + 1;
  --Alex Gerlants. 10/16/2018. Changed from "MEA*PD*G*" to "MEA*WT*G*"
  x12_table(i) := 'TD1*COL52*1****N*' || to_char(ll_shipment_nt) || '*LB';
  i := i + 1;
  
  x12_table(i) := 'TD1*COL52*1****G*' || to_char(ll_shipment_gt) || '*LB';
  li_td1 := i;
  i := i + 1;
  
  x12_table(i) := 'TD5**2*' || ltrim(rtrim(ls_carrier_full_name)) || '*M*1*CL';
  i := i + 1;
  
  --x12_table(i) := 'TD3*TL*' || ls_carrier_desc_code || '*' || ls_scac || '*' || ls_vehicle_id_prefix;
  x12_table(i) := 'TD3*TL*' || ls_scac || '*1';
  i := i + 1;
  
  x12_table(i) := 'REF*MB*' || to_char(ll_bill_of_lading);
  i := i + 1;
  
  /*
  select   distinct customer_order.orig_customer_po, order_item.enduser_part_num, f_get_width_4order_item(order_item.order_abc_num, order_item.order_item_num)
  into     ls_orig_customer_po, ls_enduser_part, ll_width
  from     sheet_packing_item
           join sheet_skid on sheet_skid.sheet_skid_num = sheet_packing_item.sheet_skid_num
           join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
           join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
           join order_item on customer_order.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
  where    sheet_packing_item.packing_list = al_packing_list;
  */
  
  x12_table(i) := 'FOB*PO';
  i := i + 1;
  
  x12_table(i) := 'N1*OU*' || 'Aluminum Blanking Co*1*' || ls_sf;
  i := i + 1;
  
  li_des_id := 1;

  x12_table(i) := 'N1*ST**1*' || ls_st_duns;
  i := i + 1;
  
    x12_table(i) := 'N1*SF*' || 'Aluminum Blanking Co*1*' || ls_sf;
  i := i + 1;
  
  /*
  -- Second Level HL based on End User PO
  OPEN alcan_ford_856_cur;
  FETCH alcan_ford_856_cur
    INTO skidinfo_rec;
      ls_enduser_part := skidinfo_rec.ENDUSER_PART_NUM;

  SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
    INTO ls_enduser_part
    FROM "ORDER_ITEM", "SHEET_SKID"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
     AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
     AND ("SHEET_SKID"."SHEET_SKID_NUM" = skidinfo_rec.sheet_skid_num);

  --Order information **********************************************************
  
  x12_table(i) := 'HL*2*1*O*1';
  i := i + 1;
  IF ls_enduser_part IS NULL THEN
    ls_enduser_part := 'NA';
  END IF;

  SELECT "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO"
    INTO ls_po
    FROM "SHEET_SKID", "CUSTOMER_ORDER"
   WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
         "CUSTOMER_ORDER"."ORDER_ABC_NUM")
     AND (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num);

  x12_table(i) := 'LIN**VO*' || ls_po;
  i := i + 1;
  
  x12_table(i) := 'PRF*' || ls_po;
  i := i + 1;
  
  x12_table(i) := 'REF*PM*' || ls_enduser_part;
  i := i + 1;

  CLOSE alcan_ford_856_cur;
  */
  
  li_hl01 := 1;

  -- Order information
  --OPEN order_info_cur;
  --FETCH order_info_cur
  --  INTO order_info_rec;
  
  hl_order := 0;
    
  for order_info_rec in order_info_cur loop
      
      li_hl01 := li_hl01 + 1;
      hl_order := li_hl01;
      
      x12_table(i) := 'HL*' || li_hl01 || '*1*O*1';
      i := i + 1;
      
      
    
      ls_enduser_part := order_info_rec.ENDUSER_PART_NUM;
      
      if ls_enduser_part is null then
        ls_enduser_part := 'NA';
      end if;
      
      ls_po := order_info_rec.orig_customer_po;
      ll_order_abc_num := order_info_rec.order_abc_num;
      ll_order_item_num := order_info_rec.order_item_num;
            
      
      
      x12_table(i) := 'LIN**VO*' || ls_po;
      i := i + 1;
  
      x12_table(i) := 'PRF*' || ls_po;
      i := i + 1;
  
      x12_table(i) := 'REF*PM*' || ls_enduser_part;
      i := i + 1;
  
            --Skid loop begin ----------------------------------------------------------------
            --Skid information **********************************************************
            FOR skidinfo_rec IN alcan_ford_856_cur LOOP
              
                --In case of a split skid, we are creating just 1 HL for this skid
                --with just 1 coil for this skid.
                select distinct 
                       coil.coil_org_num,
                       coil.coil_gauge,
                       coil.coil_width,
                       coil.lot_num,
                       nvl(skid_type_if_whed, -1)
                into   ls_coil_org_num,
                       ll_coil_gauge,
                       ll_coil_width,
                       ls_lot_num,
                       ln_skid_type_if_whed
                FROM "COIL",   
                     "PRODUCTION_SHEET_ITEM",   
                     "SHEET_SKID",   
                     "SHEET_SKID_DETAIL",   
                     "PROCESS_COIL"  
               WHERE ( "COIL"."COIL_ABC_NUM" = "PRODUCTION_SHEET_ITEM"."COIL_ABC_NUM" ) and  
                     ( "SHEET_SKID_DETAIL"."SHEET_SKID_NUM" = "SHEET_SKID"."SHEET_SKID_NUM" ) and  
                     ( "SHEET_SKID_DETAIL"."PROD_ITEM_NUM" = "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NUM" ) and  
                     ( "COIL"."COIL_ABC_NUM" = "PROCESS_COIL"."COIL_ABC_NUM" ) and  
                     ( "PRODUCTION_SHEET_ITEM"."AB_JOB_NUM" = "PROCESS_COIL"."AB_JOB_NUM" ) and  
                     ( (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num)  ) and
                     ( (rownum = 1)  ); --We need just 1 coil for each skid
            
                --Alex Gerlants. 04/01/2019. Begin
                if ln_skid_type_if_whed > -1 then --Warehouse skid
                    --Get gauge and part width
                    select distinct order_item.gauge,
                           f_get_part_width_per_job(ab_job.ab_job_num) 
                    into   ll_coil_gauge,
                           ll_coil_width
                    from   sheet_skid
                           join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
                           join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
                           join customer_order on customer_order.order_abc_num = order_item.order_abc_num
                    where  sheet_skid_num = skidinfo_rec.sheet_skid_num
                    and    (order_item.gauge is not null and f_get_part_width_per_job(sheet_skid.ab_job_num) is not null)
                    and    rownum = 1;
                end if;
                --Alex Gerlants. 04/01/2019. End
            
                li_hl01 := li_hl01 + 1;
                
                x12_table(i) := 'HL*' || rtrim(ltrim(to_char(li_hl01, '99999'))) || '*' || hl_order || '*I';
                i := i + 1;
                
                
                
                select   skid_ticket_if_whed
                into     ll_skid_ticket_if_whed
                from     sheet_skid
                where    sheet_skid_num = skidinfo_rec.sheet_skid_num;
                
                x12_table(i) := 'LIN**SN*' || to_char(ll_skid_ticket_if_whed); --Customer (TWB) skid number
                i := i + 1;
                                  
                --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*N" to "MEA*WT*N"
                x12_table(i) := 'MEA*WT**' || to_char(skidinfo_rec.sheet_net_wt) ||
                                '*01';
                i := i + 1;
                
                x12_table(i) := 'MEA*PD*TH*' || to_char(ll_coil_gauge) || '*E8';
                i := i + 1;
                
                --Alex Gerlants. 10/18/2018. New line 
                x12_table(i) := 'MEA*PD*WD*' || to_char(ll_width) || '*E8';
                i := i + 1;
                                  
                --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*WT" to "MEA*CT*NL"
                x12_table(i) := 'MEA*CT*NL*' || to_char(skidinfo_rec.skid_pieces) || '*PC';
                i := i + 1;

                -- changed to all gross wt per novelis 1/30/2015
                --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*G" to "MEA*WT*G"
                --x12_table(i) := 'MEA*WT*G*' || to_char(skidinfo_rec.sheet_net_wt + skidinfo_rec.sheet_tare_wt) || '*01';
                --i := i + 1;
                




                x12_table(i) := 'REF*SE*' || to_char(skidinfo_rec.sheet_skid_num); --added by Victor H. on 06-2012 for Novelis locatio code request
                i := i + 1;
                
                --Alex Gerlants. 10/18/2018. New line 
                --x12_table(i) := 'REF*LS*' || ls_coil_org_num;
                --i := i + 1;
                
                --li_hl01 := li_hl01 + 1;
                li_rowcount := alcan_ford_856_cur%ROWCOUNT;
                --x12_table(li_td1) := 'TD1*PLT90*' || to_char(li_rowcount);
            END LOOP; --End of 'FOR skidinfo_rec IN alcan_ford_856_cur LOOP'
            --Skid loop end ------------------------------------------------------------------
            
   end loop;

  -- DBMS_OUTPUT.PUT_LINE ('rowcount' || to_char(li_rowcount));

  x12_table(i) := 'CTT*' || to_char(li_hl01);
  i := i + 1;
  -- end if;
  x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
  i := i + 1;
  x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
  i := i + 1;
  x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

  -- Write X.12 to file
  SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;
  --edi_file:= 'S_alcan_ford_ford_' || to_char(ll_edi_file_id) ||'.x12';

  -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
  -- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
  edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
  FOR j IN 0 .. i LOOP
    utl_file.put_line(edi_file_handle, x12_table(j));
    --        v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
  END LOOP;
  utl_file.fclose(edi_file_handle);

  --To ALCAN

  /*
  SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;
  SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id_alcan FROM DUAL;
  edi_file:= 'S_alcan_ford_alcan_' || to_char(ll_edi_file_id_alcan) ||'.x12';
  edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');
  x12_table(0) := 'ISA*00*'||'          *00*          *01*039630926T     *09*0015049350011G *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0')||'*0*P**';
  x12_table(1) := 'GS*SH*R0P7A*'||'001504935001' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
  x12_table(i-1) :=  'GE*1*' || to_char (ll_gs_log);
  x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');
  for j in 0..i loop
   UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
       v_edi_text_alcan:=v_edi_text_alcan||x12_table(j)||CHR(10);
  end loop;
  UTL_FILE.FCLOSE(edi_file_handle);

  */

  /* The following code added by Tony, for update archive*/

    --INSERT INTO edi_log (edi_log_timestamp,customer_id,
    --       customer_edi_name,edi_log_contents,edi_file_id,edi_text)
    --  VALUES (SYSDATE,li_customer_id,ll_customer_edi_name,
    --         'EDI:'||ll_customer_edi_name||' generated successfully.',ll_edi_file_id,v_edi_text);
    -- COMMIT;

  /* Alex Gerlants. 09/01/2016. Added ", edi_file_id_856 = ll_edi_file_id". */
  /*
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE,
         edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;

  --added by Victor Huang on 12/07 for verifying 997
  INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (ll_edi_file_id,
     '039630926',
     ls_su,
     ll_gs_log,
     ll_gs_log,
     SYSDATE,
     edi_file,
     0,
     li_customer_id,
     ll_st_log,
     '856');
  COMMIT;
  */

  edi_file        := 'send_edi_log';
  edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
  utl_file.put_line(edi_file_handle, 'Type: 856');
  utl_file.put_line(edi_file_handle,
                    'Sending Time: ' ||
                    to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,
                    'Interchange Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
  utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
  utl_file.put_line(edi_file_handle, '');
  utl_file.put_line(edi_file_handle, '');
  utl_file.fclose(edi_file_handle);

  RETURN 1;
END edi_twb_856_X12_2_test;
--------------------------------------------------------
--  DDL for Function EDI_TWB_856_X12_3
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."EDI_TWB_856_X12_3" (al_packing_list shipment.packing_list%TYPE)
  RETURN INTEGER
/*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = no process data
               200 = no EDI defined
  */
 IS
  /*
  Aluminum Blanking: DUNS: 01 039630926T
  Customer:   2992 - TWB
  End User:   1840 - GM-LANSING    
              2611 - GM-FLINT -D - 3
              2850 - GM-PONT  P14-4 1/2

  */


  edi_loc VARCHAR2(50);
  --edi_loc varchar2(50):='/tmp';
  edi_file        VARCHAR2(50) := 'edi_out.txt';
  edi_file_prefix VARCHAR2(50) := 'S_twb_856_'; --Production
  --edi_file_prefix VARCHAR2(50) := 's_twb_856_'; --Development
  edi_file_handle utl_file.file_type;

  li_customer_id    shipment.customer_id%TYPE;
  li_des_sh_cust_id shipment.des_sh_cust_id%TYPE;
  ls_sf VARCHAR2(50);
  ls_eq_type VARCHAR2(10);
  ls_su      VARCHAR2(50);
  ls_st_duns VARCHAR2(50);
  ls_po      VARCHAR2(30);
  ls_auth_code   VARCHAR2(32);
  ll_gs_log  INTEGER;
  ll_st_log  INTEGER;
  ll_bsn_log INTEGER;

  ls_today VARCHAR2(20) := to_char(SYSDATE, 'YYYYMMDD');
  ls_today_2digits_year VARCHAR2(20) := to_char(SYSDATE, 'YYMMDD');
  ls_now   VARCHAR2(20) := to_char(SYSDATE, 'HH24MI');

  li_rowcount INTEGER;
  li_hl01 INTEGER;
  hl_order integer;
  ll_shipment_nt INTEGER;
  ll_shipment_gt INTEGER;
  ll_shipment_pc INTEGER;
  li_td1 INTEGER;
  li_rc  INTEGER;

  ll_bill_of_lading    INTEGER;
  ls_vehicle_id        VARCHAR2(50);
  ls_vehicle_id_prefix VARCHAR2(50);
  ls_scac              carrier.scac%TYPE;
  ls_carrier_full_name VARCHAR2(18);
  ls_tran_method_code  VARCHAR2(50);
  ls_carrier_desc_code VARCHAR2(50);
  ls_carrier_initial   VARCHAR2(50);
  ldt_shipment         DATE;
   ll_temp         INTEGER;
  ls_enduser_part VARCHAR2(50);
  li_des_id       INTEGER;

  ll_edi_file_id INTEGER;

  ls_lot_num VARCHAR2(32);
  ls_coil_id VARCHAR2(32);
  ls_des_cust_name VARCHAR2(18);
  
  ls_coil_org_num		        coil.coil_org_num%TYPE; 
  ll_coil_gauge		          coil.coil_gauge%TYPE;
  ll_coil_width		          coil.coil_width%TYPE;
  ld_ship_date              date;
  li_is_novelis             integer;
  ln_skid_type_if_whed      sheet_skid.skid_type_if_whed%TYPE;
  ls_time                   char(4);
  ls_orig_customer_po       customer_order.orig_customer_po%TYPE;
  ll_width                  number(10,5);
  ll_skid_ticket_if_whed    sheet_skid.skid_ticket_if_whed%TYPE;
  ll_order_abc_num          customer_order.order_abc_num%TYPE;
  ll_order_item_num         order_item.order_item_num%TYPE;
  li_bol_counter            number := 0;
  ll_table_count            number;
  
  cursor order_info_cur is
  select   distinct ab_job.order_abc_num, ab_job.order_item_num, customer_order.orig_customer_po, order_item.enduser_part_num
  from     sheet_packing_item
           join sheet_skid on sheet_skid.sheet_skid_num = sheet_packing_item.sheet_skid_num
           join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
           join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
           join order_item on ab_job.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
  where    sheet_packing_item.packing_list = al_packing_list;
  
  order_info_rec order_info_cur%ROWTYPE;

  CURSOR skid_info_cur IS
    SELECT sheet_packing_item.sh_packing_item,
           'MULTIPLE' lot_num,
           'MULTIPLE' coil_id,
           customer_order.orig_customer_po,
           customer_order.order_abc_num,
           customer_order.enduser_po,
           customer_order.created_date,
           order_item.order_item_num,
           order_item.enduser_part_num,
           order_item.supplier_code,
           order_item.gauge,
           sheet_skid. ab_job_num,
           sheet_skid.sheet_skid_num,
           sheet_skid.sheet_skid_display_num,
           sheet_skid.sheet_net_wt,
           sheet_skid.sheet_tare_wt,
           sheet_skid. skid_pieces,
           sheet_skid.skid_sheet_status,
           sheet_skid.sheet_theoretical_wt,
           NULL done
      FROM customer_order,
           order_item,
           sheet_skid,
           ab_job,
           shipment,
           sheet_packing_item
     WHERE (order_item.order_abc_num = customer_order.order_abc_num)
       AND (ab_job.order_abc_num = order_item.order_abc_num)
       AND (ab_job.order_item_num = order_item.order_item_num)
       AND (sheet_skid.ab_job_num = ab_job.ab_job_num)
       AND (shipment.packing_list = sheet_packing_item.packing_list)
       AND (sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num)
       AND (shipment.packing_list = al_packing_list)
       and customer_order.order_abc_num = ll_order_abc_num and order_item.order_item_num = ll_order_item_num;
       
  skidinfo_rec skid_info_cur%ROWTYPE;

  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table    store_tabletype;
  i            BINARY_INTEGER := 0;
  

BEGIN
  
  edi_loc := dbo.get_edi_destination('EDI_DIR');

  -- Get Customer ID, End user ID, authorization code
  SELECT customer_id, des_sh_cust_id, nvl(shipment_athorization_code, 'NA')
    INTO li_customer_id, li_des_sh_cust_id, ls_auth_code
  FROM shipment
  WHERE shipment.packing_list = al_packing_list;
  
  IF NOT SQL%FOUND THEN
   RETURN - 1;
  END IF;
  
  --Alex Gerlants. 02/15/2023. Added "2998 - TWB-ANTIOCH" as per Dan Polkinhorne's email received on Wed 2/15/2023 9:09 AM.
  if li_customer_id not in (2992, 2998)  then --Customer is NOT TWB
    return 1; --Nothing to do here
  end if;
  
  select shipment_edi856_date, des_sh_cust_id
  into   ld_ship_date, li_des_sh_cust_id
  from   shipment
  where  shipment.packing_list = al_packing_list;
   
  if not (ld_ship_date is null) then --ASN already sent
    return 100;
  end if;

  --1840 - GM-LANSING    
  --2611 - GM-FLINT -D - 3
  --2850 - GM-PONT  P14-4 1/2
  IF NOT (li_des_sh_cust_id IN (2850, 2611, 1840)) THEN
    RETURN 200; --Wrong destination customer
  END IF;
  
  for order_info_rec in order_info_cur loop
      i := 0;
      
      --ll_table_count := x12_table.count;
      
      --if ll_table_count > 0 then
      --  clear x12_table;
      --end if;
      
      --delete x12_table;
      li_bol_counter := li_bol_counter + 1;

      -- Get Net and Cross Shipment Weight and Total Package Num, and total piece count
      SELECT SUM(sheet_skid.sheet_net_wt),
             SUM(sheet_skid.sheet_net_wt) + SUM(sheet_skid.sheet_tare_wt),
             SUM(sheet_skid.skid_pieces)
        INTO ll_shipment_nt, ll_shipment_gt, ll_shipment_pc
        FROM sheet_skid, sheet_packing_item, shipment
       WHERE shipment.packing_list = sheet_packing_item.packing_list
         AND sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
         AND shipment.packing_list = al_packing_list;
      IF ll_shipment_pc = 0 THEN
        RETURN 100;
      END IF; -- empty shipment

      -- Get gs, st and bsn log sequence number
      SELECT edi_gs_log_seq.nextval INTO ll_gs_log FROM dual;
      SELECT edi_st_log_seq.nextval INTO ll_st_log FROM dual;
      SELECT edi_bsn_log_seq.nextval INTO ll_bsn_log FROM dual;

      ls_sf := '039630926'; --Production
      --ls_sf := '2NDSFTP'; --Development

      -- Get Shipment Info.
      SELECT shipment.bill_of_lading,
             nvl(shipment.vehicle_id, '9999'),
             nvl(shipment.vehicle_id_prefix, '9999'),
             nvl(shipment.equipment_type, 'NA'),
             nvl(shipment.transportation_method_code, 'Motor'),
             nvl(shipment.carrier_description_code, 'PT'), -- 'PT' = Protected Trailer
             nvl(shipment.carrier_initial, 'NA'),
             nvl(shipment.shipment_actualed_date_time, SYSDATE)
        INTO ll_bill_of_lading,
             ls_vehicle_id,
             ls_vehicle_id_prefix,
             ls_eq_type,
             ls_tran_method_code,
             ls_carrier_desc_code,
             ls_carrier_initial,
             ldt_shipment
        FROM shipment
       WHERE shipment.packing_list = al_packing_list;

      SELECT nvl(customer_duns_number_string, '00000000'), customer_short_name
        INTO ls_st_duns, ls_des_cust_name
        FROM customer
       WHERE customer_id = li_des_sh_cust_id;

      IF (ls_st_duns = '00000000') THEN
        RETURN 200;
      END IF; --No Ship to DUNS

      SELECT nvl(customer_duns_number_string, '00000000')
        INTO ls_su
        FROM customer
       WHERE customer_id = li_customer_id;
      IF (ls_su = '00000000') THEN
        RETURN 200;
      END IF; --No Supplier DUNS

      -- Get SCAC(Standard Carrier Alpha Code)
      SELECT nvl(carrier.scac, 'NONE'), LPAD(carrier.carrier_full_name, 17)
        INTO ls_scac, ls_carrier_full_name
        FROM carrier
       WHERE carrier_id =
             (SELECT carrier_id
                FROM shipment
               WHERE shipment.packing_list = al_packing_list);

      --Production
      x12_table(i) := 'ISA*00*' ||
                      '          *00*          *01*039630926T     *01*789153079      *' ||
                      ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                      lpad(to_char(ll_gs_log), 9, '0') || '*0*P*>';
      
      --Development                
      --x12_table(i) := 'ISA*00*' ||
      --                '          *00*          *ZZ*2NDSFTP        *01*789153079      *' ||
      --                ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
      --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T*>';
                      
      i := i + 1;

      --Alex Gerlants. 10/16/2018. Changed from "002002" to "004010"
      --Production
      x12_table(1) := 'GS*SH*R0P7A*' || '789153079' || '*' || ls_today || '*' ||
                      ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                      
      --Development
      --x12_table(1) := 'GS*SH*2NDSFTP*' || '789153079' || '*' || ls_today || '*' ||
      --               ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                      
      i := i + 1;

      x12_table(i) := 'ST*856*' || to_char(ll_st_log);
      i := i + 1;
      --x12_table(i):= 'BSN*00*' || to_char(ll_bill_of_lading) || '*' || ls_today || '*' || ls_now;
      x12_table(i) := 'BSN*00*' || to_char(al_packing_list) || '-' || to_char(li_bol_counter) || '*' || ls_today || '*' || ls_now;
      i := i + 1;
      
      --Alex Gerlants. 08/07/2018.
      --Changed to populate with actual ship date instead of current date and time.
      --The reason is that when we send 856 on a later date, this date is not correct.
      --x12_table(i) := 'DTM*011*' || ls_today || '*' || ls_now;
      --Alex Gerlants. 10/16/2018. Changed from "YYMMDD" to "YYYYMMDD"
      
      --Alex Gerlants. 01/09/2020. Added the IF statement below.
      --If users do not enter time part in shipment.shipment_actualed_date_time,
      --856 will have system time in 'DTM*011*' and 'DTM*017*'
      
      ls_time := to_char(ldt_shipment, 'HH24MI');
      
      if ls_time <> '0000' then --User entered time
        x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                                                            to_char(ldt_shipment, 'HH24MI');
      else --User did not enter time  
        x12_table(i) := 'DTM*011*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                                                            to_char(sysdate, 'HH24MI');
      end if;
      i := i + 1;
      
      --Alex Gerlants. 10/18/2018. Changed from "YYMMDD" to "YYYYMMDD"
      --Moved here from the below
      if ls_time <> '0000' then --User entered time
        x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                        to_char(ldt_shipment, 'HH24MI');
      else --User did not enter time
        x12_table(i) := 'DTM*017*' || to_char(ldt_shipment, 'YYYYMMDD') || '*' ||
                        to_char(sysdate, 'HH24MI');
      end if;
      i := i + 1;

      -- First Level HL
      --Shipment information **********************************************************
      x12_table(i) := 'HL*1**S*1';
      i := i + 1;
      --Alex Gerlants. 10/16/2018. Changed from "MEA*PD*G*" to "MEA*WT*G*"
      x12_table(i) := 'TD1*COL52*1****N*' || to_char(ll_shipment_nt) || '*LB';
      i := i + 1;
      
      x12_table(i) := 'TD1*COL52*1****G*' || to_char(ll_shipment_gt) || '*LB';
      li_td1 := i;
      i := i + 1;
      
      x12_table(i) := 'TD5**2*' || ltrim(rtrim(ls_carrier_full_name)) || '*M*1*CL';
      i := i + 1;
      
      --x12_table(i) := 'TD3*TL*' || ls_carrier_desc_code || '*' || ls_scac || '*' || ls_vehicle_id_prefix;
      x12_table(i) := 'TD3*TL*' || ls_scac || '*1';
      i := i + 1;
      
      x12_table(i) := 'REF*MB*' || to_char(ll_bill_of_lading) || '-' || to_char(li_bol_counter);
      i := i + 1;
      
      x12_table(i) := 'FOB*PO';
      i := i + 1;
      
      x12_table(i) := 'N1*OU*' || 'Aluminum Blanking Co*1*' || ls_sf;
      i := i + 1;
      
      li_des_id := 1;

      x12_table(i) := 'N1*ST**1*' || ls_st_duns;
      i := i + 1;
      
      x12_table(i) := 'N1*SF*' || 'Aluminum Blanking Co*1*' || ls_sf;
      i := i + 1;
      
     
      li_hl01 := 1;
      hl_order := 0;
    
  --for order_info_rec in order_info_cur loop
      
      li_hl01 := li_hl01 + 1;
      hl_order := li_hl01;
      
      x12_table(i) := 'HL*' || li_hl01 || '*1*O*1';
      i := i + 1;
      
      
    
      ls_enduser_part := order_info_rec.ENDUSER_PART_NUM;
      
      if ls_enduser_part is null then
        ls_enduser_part := 'NA';
      end if;
      
      ls_po := order_info_rec.orig_customer_po;
      ll_order_abc_num := order_info_rec.order_abc_num;
      ll_order_item_num := order_info_rec.order_item_num;
            
      select  f_get_width_4order_item(ll_order_abc_num, ll_order_item_num)
      into    ll_width  
      from dual;      
      
      x12_table(i) := 'LIN**VO*' || ls_po;
      i := i + 1;
  
      x12_table(i) := 'PRF*' || ls_po;
      i := i + 1;
  
      x12_table(i) := 'REF*PM*' || ls_enduser_part;
      i := i + 1;
  
            --Skid loop begin ----------------------------------------------------------------
            --Skid information **********************************************************
            FOR skidinfo_rec IN skid_info_cur LOOP
              
                --In case of a split skid, we are creating just 1 HL for this skid
                --with just 1 coil for this skid.
                select distinct 
                       coil.coil_org_num,
                       coil.coil_gauge,
                       coil.coil_width,
                       coil.lot_num,
                       nvl(skid_type_if_whed, -1)
                into   ls_coil_org_num,
                       ll_coil_gauge,
                       ll_coil_width,
                       ls_lot_num,
                       ln_skid_type_if_whed
                FROM "COIL",   
                     "PRODUCTION_SHEET_ITEM",   
                     "SHEET_SKID",   
                     "SHEET_SKID_DETAIL",   
                     "PROCESS_COIL"  
               WHERE ( "COIL"."COIL_ABC_NUM" = "PRODUCTION_SHEET_ITEM"."COIL_ABC_NUM" ) and  
                     ( "SHEET_SKID_DETAIL"."SHEET_SKID_NUM" = "SHEET_SKID"."SHEET_SKID_NUM" ) and  
                     ( "SHEET_SKID_DETAIL"."PROD_ITEM_NUM" = "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NUM" ) and  
                     ( "COIL"."COIL_ABC_NUM" = "PROCESS_COIL"."COIL_ABC_NUM" ) and  
                     ( "PRODUCTION_SHEET_ITEM"."AB_JOB_NUM" = "PROCESS_COIL"."AB_JOB_NUM" ) and  
                     ( (sheet_skid.sheet_skid_num = skidinfo_rec.sheet_skid_num)  ) and
                     ( (rownum = 1)  ); --We need just 1 coil for each skid
            
                --Alex Gerlants. 04/01/2019. Begin
                if ln_skid_type_if_whed > -1 then --Warehouse skid
                    --Get gauge and part width
                    select distinct order_item.gauge,
                           f_get_part_width_per_job(ab_job.ab_job_num) 
                    into   ll_coil_gauge,
                           ll_coil_width
                    from   sheet_skid
                           join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
                           join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
                           join customer_order on customer_order.order_abc_num = order_item.order_abc_num
                    where  sheet_skid_num = skidinfo_rec.sheet_skid_num
                    and    (order_item.gauge is not null and f_get_part_width_per_job(sheet_skid.ab_job_num) is not null)
                    and    rownum = 1;
                end if;
                --Alex Gerlants. 04/01/2019. End
            
                li_hl01 := li_hl01 + 1;
                
                x12_table(i) := 'HL*' || rtrim(ltrim(to_char(li_hl01, '99999'))) || '*' || hl_order || '*I';
                i := i + 1;
                
                
                
                select   skid_ticket_if_whed
                into     ll_skid_ticket_if_whed
                from     sheet_skid
                where    sheet_skid_num = skidinfo_rec.sheet_skid_num;
                
                x12_table(i) := 'LIN**SN*' || to_char(skidinfo_rec.sheet_skid_num); --ALBL skid number
                i := i + 1;
                                  
                --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*N" to "MEA*WT*N"
                x12_table(i) := 'MEA*WT**' || to_char(skidinfo_rec.sheet_net_wt) ||
                                '*01';
                i := i + 1;
                
                x12_table(i) := 'MEA*PD*TH*' || to_char(ll_coil_gauge) || '*E8';
                i := i + 1;
                
                --Alex Gerlants. 10/18/2018. New line 
                x12_table(i) := 'MEA*PD*WD*' || to_char(ll_width) || '*E8';
                i := i + 1;
                                  
                --Alex Gerlants. 10/18/2018. Changed from "MEA*PD*WT" to "MEA*CT*NL"
                x12_table(i) := 'MEA*CT*NL*' || to_char(skidinfo_rec.skid_pieces) || '*PC';
                i := i + 1;

                x12_table(i) := 'REF*SE*' || to_char(ll_skid_ticket_if_whed); --TWB skid number
                i := i + 1;
                
                --Alex Gerlants. 10/18/2018. New line 
                --x12_table(i) := 'REF*LS*' || ls_coil_org_num;
                --i := i + 1;
                
                --li_hl01 := li_hl01 + 1;
                li_rowcount := skid_info_cur%ROWCOUNT;
                --x12_table(li_td1) := 'TD1*PLT90*' || to_char(li_rowcount);
            END LOOP; --End of 'FOR skidinfo_rec IN skid_info_cur LOOP'
            --Skid loop end ------------------------------------------------------------------
            
   --end loop; --for order_info_rec in order_info_cur loop

            -- DBMS_OUTPUT.PUT_LINE ('rowcount' || to_char(li_rowcount));

            x12_table(i) := 'CTT*' || to_char(li_hl01);
            i := i + 1;
            -- end if;
            x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
            i := i + 1;
            x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
            i := i + 1;
            x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');
                
            -- Write X.12 to file
            SELECT edi_file_id_seq.nextval INTO ll_edi_file_id FROM dual;

            -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
            -- edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.x12';
            edi_file := edi_file_prefix || to_char(ll_edi_file_id) || '.edi';

            edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');
            
            FOR j IN 0 .. i LOOP
              utl_file.put_line(edi_file_handle, x12_table(j));
              --        v_edi_text_ford:=v_edi_text_ford||x12_table(j)||CHR(10);
           END LOOP;
                
           utl_file.fclose(edi_file_handle);

            /*
            SELECT edi_gs_log_seq.NEXTVAL INTO ll_gs_log FROM DUAL;
            SELECT edi_file_id_seq.NEXTVAL INTO ll_edi_file_id_alcan FROM DUAL;
            edi_file:= 'S_alcan_ford_alcan_' || to_char(ll_edi_file_id_alcan) ||'.x12';
            edi_file_handle := UTL_FILE.FOPEN(edi_loc, edi_file, 'W');
            x12_table(0) := 'ISA*00*'||'          *00*          *01*039630926T     *09*0015049350011G *'||ls_today ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(ll_gs_log),9,'0')||'*0*P**';
            x12_table(1) := 'GS*SH*R0P7A*'||'001504935001' || '*' || ls_today ||'*' || ls_now || '*' ||to_char(ll_gs_log) || '*X*' || '002002';
            x12_table(i-1) :=  'GE*1*' || to_char (ll_gs_log);
            x12_table(i) :=  'IEA*1*' || LPAD(to_char(ll_gs_log),9,'0');
            for j in 0..i loop
             UTL_FILE.PUT_LINE(edi_file_handle, x12_table(j));
                 v_edi_text_alcan:=v_edi_text_alcan||x12_table(j)||CHR(10);
            end loop;
            UTL_FILE.FCLOSE(edi_file_handle);

            */

            /* The following code added by Tony, for update archive*/

              --INSERT INTO edi_log (edi_log_timestamp,customer_id,
              --       customer_edi_name,edi_log_contents,edi_file_id,edi_text)
              --  VALUES (SYSDATE,li_customer_id,ll_customer_edi_name,
              --         'EDI:'||ll_customer_edi_name||' generated successfully.',ll_edi_file_id,v_edi_text);
              -- COMMIT;


            UPDATE shipment
               SET shipment_des_edi856_date = SYSDATE,
                   shipment_edi856_date = SYSDATE,
                   edi_file_id_856 = ll_edi_file_id
             WHERE shipment.packing_list = al_packing_list;

            --added by Victor Huang on 12/07 for verifying 997
            INSERT INTO outbound_edi_transaction
              (edi_file_id,
               duns_from,
               duns_to,
               interchange_control_number,
               group_control_number,
               transaction_time,
               edi_file_name,
               fa_receive_status,
               customer_id,
               set_control_num,
               transaction_type_id)
            VALUES
              (ll_edi_file_id,
               '039630926',
               ls_su,
               ll_gs_log,
               ll_gs_log,
               SYSDATE,
               edi_file,
               0,
               li_customer_id,
               ll_st_log,
               '856');
            COMMIT;


            edi_file        := 'send_edi_log';
            edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
            utl_file.put_line(edi_file_handle, 'Type: 856');
            utl_file.put_line(edi_file_handle,
                              'Sending Time: ' ||
                              to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
            utl_file.put_line(edi_file_handle,
                              'Interchange Control #: ' || ll_gs_log);
            utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
            utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
            utl_file.put_line(edi_file_handle, '');
            utl_file.put_line(edi_file_handle, '');
            utl_file.fclose(edi_file_handle);
   end loop; --for order_info_rec in order_info_cur loop
   
   /*
   UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE,
         edi_file_id_856 = ll_edi_file_id
   WHERE shipment.packing_list = al_packing_list;

  --added by Victor Huang on 12/07 for verifying 997
  INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
