   edi_846(j) := 'ISA*00*          *00*          *01*039630926T     *01*606072130      *'
    ||  ls_today_short  || '*' ||  ls_now  || '*U*00401*' || 
                     lpad(to_char(li_gs_log),9,'0') || '*0*P*|' || '~'; j := j + 1;

