--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_863_4OTHER_COILS_ON_SKID" 
(
   as_coil_org_num    in coil.coil_org_num%type,
   al_sheet_skid_num  in sheet_skid.sheet_skid_num%type
)
return integer
is

result                 number(1);
ls_coil_org_num        coil.coil_org_num%type;
ll_sheet_skid_num      sheet_skid.sheet_skid_num%type;
ln_coil_count          number(2);
ln_863_count           number(2);

/*
--Skids in status 16 for as_coil_org_num
cursor skid_cur is
select distinct sheet_skid.sheet_skid_num
from   production_sheet_item  
       join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
       join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
       join coil on coil.coil_abc_num = production_sheet_item.coil_abc_num
                 
where  coil.coil_org_num = as_coil_org_num
and    sheet_skid.skid_sheet_status = 16;

skid_cur_rec  skid_cur_cur%rowtype;
*/

---

/*
--Number of coils on each skid in status 16
cursor num_of_coils_on_skid_cur is
select sheet_skid.sheet_skid_num, count(distinct coil.coil_org_num)  coil_count
from   production_sheet_item  
       join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
       join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
       join coil on coil.coil_abc_num = production_sheet_item.coil_abc_num
where  sheet_skid.sheet_skid_num in
(
    select distinct sheet_skid.sheet_skid_num
    from   production_sheet_item  
           join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
           join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
           join coil on coil.coil_abc_num = production_sheet_item.coil_abc_num
    where  coil.coil_org_num = as_coil_org_num
    and    sheet_skid.skid_sheet_status = 16 --Hold For Cert
)
group by sheet_skid.sheet_skid_num
order by sheet_skid.sheet_skid_num;

num_of_coils_on_skid_rec  num_of_coils_on_skid_cur%rowtype;
*/

---

--coil_org_num on each skid in status 16
--Inside this loop I select data from data_in_863 for each coil_org_num
cursor coils_on_skid_cur is
select coil.coil_org_num
from   production_sheet_item  
       join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
       join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
       join coil on coil.coil_abc_num = production_sheet_item.coil_abc_num
where  sheet_skid.sheet_skid_num = al_sheet_skid_num
and    coil.coil_org_num <> as_coil_org_num;

coils_on_skid_rec  coils_on_skid_cur%rowtype;

---

begin

    result := 1; --Initialize to OK
     
    for coils_on_skid_rec in coils_on_skid_cur loop
      ls_coil_org_num := coils_on_skid_rec.coil_org_num;
        
      select   count(*)
      into     ln_863_count
      from     data_in_863
      where    coil_num = ls_coil_org_num;
        
      if ln_863_count <= 0 then
        result := 0;
      end If;
    end loop; --for coils_on_skid_rec in coils_on_skid_cur loop

    return(result);
    
end f_863_4other_coils_on_skid;

