--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_ALL_SKID_COILS_HAVE_863" (al_skid_sheet_num sheet_skid.sheet_skid_num%TYPE)
return integer is

result              integer;
ll_count            integer;
--ls_coil_num_863     data_in_863.coil_num%TYPE;
ll_coil_org_num     coil.coil_org_num%TYPE;

cursor  info_cur is
select  distinct
        nvl(coil.coil_org_num, 'NA') coil_org_num
from    production_sheet_item
        --join ab_job on ab_job.ab_job_num = production_sheet_item.ab_job_num
        join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
        join coil on coil.coil_abc_num = production_sheet_item.coil_abc_num
        left outer join dbo.data_in_863 data_in_863 on data_in_863.coil_num = coil.coil_org_num
where   sheet_skid_detail.sheet_skid_num = al_skid_sheet_num;
  
begin

 result := 1; --Initialize
 
 for info_rec in info_cur
 loop
   ll_coil_org_num := info_rec.coil_org_num;
   
   select  count(*)
