--  DDL for Function F_CHECK_SHIFT_TIME_CONFLICT
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_CHECK_SHIFT_TIME_CONFLICT" (par_date_time date, par_line_num int, par_shift_num int) return integer is
  
  cursor shift_planned_time_cursor is     
  select s.planned_starting_time, s.planned_ending_time
  from shift s
  where s.line_num = par_line_num
        and s.shift_num <> par_shift_num;  
  
begin
  for cloop in shift_planned_time_cursor loop
      if (par_date_time > cloop.planned_starting_time) and (par_date_time < cloop.planned_ending_time) then
         return -1;
      end if;
  end loop;
  
  return 1;
end F_CHECK_SHIFT_TIME_CONFLICT;
  GRANT EXECUTE ON "DBO"."F_CHECK_SHIFT_TIME_CONFLICT" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function F_CHECK_SKID_ITEM_INFO
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_CHECK_SKID_ITEM_INFO" (skid_id in sheet_skid.sheet_skid_num%type) return integer is
  Result integer;
  skidpc NUMBER(8);
  skidtheo NUMBER(8);
  skidnet NUMBER(8);
  itempc NUMBER(8);
  itemtheo NUMBER(8);
  itemnet NUMBER(8);
begin
--0 item and skid info match
--1 item pieces count not match skid pieces count
--2 item netwt not match skid netwt
--3 item theo wt not match skid theo wt
  Result := 0;

  select sheet_net_wt, skid_pieces, sheet_theoretical_wt into skidnet, skidpc, skidtheo
  from sheet_skid
  where sheet_skid_num = skid_id;

  SELECT  SUM(a.PROD_ITEM_PIECES),    SUM(a.PROD_ITEM_NET_WT) ,   SUM(a.PROD_ITEM_THEORETICAL_WT)  
  INTO itempc, itemnet, itemtheo 
    FROM PRODUCTION_SHEET_ITEM a,   
         SHEET_SKID b,   
         SHEET_SKID_DETAIL c  
   WHERE (  c. SHEET_SKID_NUM  =  b.SHEET_SKID_NUM  ) and  
         (  c.PROD_ITEM_NUM  =  a.PROD_ITEM_NUM  ) and  
         (  b.SHEET_SKID_NUM  = skid_id ) ;  
  
    IF (skidpc <> itempc) THEN 
       Result := 1;
       return(Result);
  END IF;

  IF (skidnet <> itemnet) THEN 
       Result := 2;
       return(Result);
  END IF;

  IF NOT(skidtheo is NULL) AND NOT(itemtheo is NULL) AND (skidtheo <> itemtheo) THEN 
       Result := 3;
       return(Result);
  END IF;

  return(Result);
end F_CHECK_SKID_ITEM_INFO;
  GRANT EXECUTE ON "DBO"."F_CHECK_SKID_ITEM_INFO" TO PUBLIC
  GRANT EXECUTE ON "DBO"."F_CHECK_SKID_ITEM_INFO" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function F_COILS_WEIGHT_ZEROED_OUT
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_COILS_WEIGHT_ZEROED_OUT" 
       (
          adt_date_from     date,
          adt_date_to       date
       )
return integer
is

ll_coil_abc_num          coil.coil_abc_num%TYPE;
ll_ab_job_num            ab_job.ab_job_num%TYPE;
ll_coil_net_wt           coil.net_wt%TYPE;
ll_sum_process_wt        process_coil.process_quantity%TYPE;
--ls_edi_file              varchar(50) := 'coils_zeroed_out.txt';
edi_file_handle          utl_file.file_type;
--ls_edi_loc               varchar(500) := '/templar/templar/alex';
ls_customer_name         customer.customer_id%TYPE;
ls_line_desc             line.line_desc%TYPE;
ld_process_date          process_coil.process_date%TYPE;

  cursor coils_cur is
    select   coil.coil_abc_num coil_abc_num,
             coil.net_wt coil_net_wt,
             sum(process_coil.process_quantity) sum_process_wt
    from     process_coil 
             join coil on coil.coil_abc_num = process_coil.coil_abc_num
    where    process_coil_status = 0
    and      process_coil.process_date between adt_date_from and adt_date_to
    group by coil.coil_abc_num,
             coil.net_wt
    having   sum(process_coil.process_quantity) > coil.net_wt
    order by coil.coil_abc_num desc;

  coils_rec coils_cur%ROWTYPE;
    
  cursor process_coils_cur is  
    select   ab_job_num,
             process_date
    from     process_coil
    where    coil_abc_num = ll_coil_abc_num;

  process_coils_rec process_coils_cur%ROWTYPE;

begin
  --delete from coils_weight_zeroed_out;
  
  edi_file_handle := utl_file.fopen('/tmp', 'coils.csv', 'W');
  
  --utl_file.put_line(edi_file_handle, 'Run Time: ' || to_char(sysdate, 'MM/DD/YY HH24:MI'));
  --utl_file.put_line(edi_file_handle, 'Date From: ' || to_char(adt_date_from) || '  Date To: ' || to_char(adt_date_to));
  --utl_file.put_line(edi_file_handle, 'Coils Zeroed Out Report');
  
  --utl_file.put_line(edi_file_handle, 'Job Num   Coil ABC Num    Coil Net Wt    Processed Wt');

  for coils_rec in coils_cur loop
    ll_coil_abc_num := coils_rec.coil_abc_num;
    ll_coil_net_wt := coils_rec.coil_net_wt;
    ll_sum_process_wt := coils_rec.sum_process_wt;
    
    select     customer.customer_short_name
    into       ls_customer_name
    from       coil
               join customer on customer.customer_id = coil.customer_id
    where      coil.coil_abc_num = ll_coil_abc_num;
    
    for process_coils_rec in process_coils_cur loop
      ll_ab_job_num := process_coils_rec.ab_job_num;
      ld_process_date := process_coils_rec.process_date;
      
      select   line.line_desc
      into     ls_line_desc
      from     ab_job
               join line on line.line_num = ab_job.line_num
      where    ab_job.ab_job_num = ll_ab_job_num;
      
      --utl_file.put_line(edi_file_handle, to_char(ll_ab_job_num) || '     ' || to_char(ll_coil_abc_num) || '           ' || to_char(ll_coil_net_wt) || '           ' || to_char(ll_sum_process_wt));
      
      insert into coils_weight_zeroed_out 
      
         (
            customer_name,
            coil_abc_num,
            ab_job_num,
            coil_net_wt,
            sum_process_wt,
            line_desc,
            time_date_finished
         )
         values
         (
            ls_customer_name, 
            ll_coil_abc_num, 
            ll_ab_job_num,
            ll_coil_net_wt, 
            ll_sum_process_wt,
            ls_line_desc,
            ld_process_date
         );
    end loop;
  end loop;

  commit;
  
  --utl_file.fclose(edi_file_handle);
  
  return 1;
end f_coils_weight_zeroed_out;
