--  DDL for Function F_COIL_ASSED_JOB_NOT_PROCED
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_COIL_ASSED_JOB_NOT_PROCED" 
(
   al_coil_abc_num in coil.coil_abc_num%type
) 

return varchar2 

is

  result               varchar(256);
  
  ll_count             number;
  ll_ab_job_num        ab_job.ab_job_num%type;
  li_priority_status   line_priority.status%type;
  li_job_status        ab_job.job_status%type;
  li_coil_status       coil.coil_status%type;
  
  cursor jobs_4coil_cur is
  select   ab_job_num
  from     line_current_status
  where    coil_abc_num = al_coil_abc_num;

  jobs_4coil_rec jobs_4coil_cur%ROWTYPE;

begin
 
  result := '';
 
  select   count(*)
  into     ll_count
  from     line_current_status
  where    coil_abc_num = al_coil_abc_num;

  if ll_count > 0 then
    
    for jobs_4coil_rec in jobs_4coil_cur loop
      ll_ab_job_num := jobs_4coil_rec.ab_job_num;
      result := result || to_char(ll_ab_job_num) || ';';
    end loop; --for jobs_4coil_rec in jobs_4coil_cur loop
    
    If length(result) > 0 then
      --Remove the last semicolon
      result := substr(result, 1, length(result) - 1);
    end if;
  end if;

  return (result);
           
end f_coil_assed_job_not_proced;

