--------------------------------------------------------
--  DDL for Function F_COIL_IN_JOB_PROCESSED_WT
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_COIL_IN_JOB_PROCESSED_WT" (a_coil_id in coil.coil_abc_num%type, a_job_num in ab_job.ab_job_num%type) return Integer is 
  Result Integer; 
  ll_wt process_coil.process_quantity%type := 0; 
  ll_shift_end_wt process_coil.process_end_wt%type := 0; 
  ll_wt1 coil.net_wt_balance%type := 0; 
  ll_wt2 process_coil.process_quantity%type := 0; 
begin 
  result := 0; 
 
  SELECT NVL(process_quantity,0), process_end_wt INTO ll_wt, ll_shift_end_wt 
  FROM process_coil 
  WHERE (coil_abc_num = a_coil_id ) AND (ab_job_num = a_job_num); 
   
   IF ll_shift_end_wt is NULL THEN 
   SELECT NVL(net_wt_balance,0) INTO ll_wt1 
   FROM coil 
   WHERE coil_abc_num = a_coil_id; 
  ELSE 
   ll_wt1 := ll_shift_end_wt; 
  END IF; 
 
  SELECT nvl(MAX(process_quantity),0) INTO ll_wt2 
  FROM process_coil 
  WHERE (coil_abc_num = a_coil_id) AND (process_quantity < ll_wt); 
   
   IF ll_wt1 >= ll_wt2 THEN 
       Result:= ll_wt - ll_wt1; 
    ELSE  
       Result := ll_wt - ll_wt2; 
    END IF; 
     
  return(Result); 
end f_coil_in_job_processed_wt;
  GRANT EXECUTE ON "DBO"."F_COIL_IN_JOB_PROCESSED_WT" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function F_COIL_WEIGHT
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_COIL_WEIGHT" (p_ab_job in ab_job.ab_job_num%type) return number is
  Result number :=0;
  process_wt process_coil.process_quantity%type :=0; --total wt of coils(NEW) assigned to job
  wt_reband_total process_coil.process_quantity%type :=0;    --total wt of coils(REBANDED) assigned to job
  wt_reband process_coil.process_quantity%type :=0;
  coil_st coil.coil_status%type :=0;
  coil_wt_bal coil.net_wt_balance%type :=0;
  process_coil_st process_coil.process_coil_status%type :=0;
  process_coil_wt process_coil.process_quantity%type :=0;  
  
  cursor rebanded_coil_cursor is     
   SELECT "COIL"."COIL_ABC_NUM"
   FROM "COIL",   
         "PROCESS_COIL"  
   WHERE "COIL"."COIL_ABC_NUM" = "PROCESS_COIL"."COIL_ABC_NUM" and  
         "PROCESS_COIL"."PROCESS_COIL_STATUS" = 7 AND  
         "PROCESS_COIL"."AB_JOB_NUM" = P_AB_JOB; 
         
begin
   SELECT NVL(SUM(process_quantity),0) INTO process_wt
   FROM process_coil
   WHERE ab_job_num = p_ab_job AND process_coil_status = 2;
   
             
   for cloop in rebanded_coil_cursor loop
       SELECT coil_status, NVL(net_wt_balance,0) INTO coil_st, coil_wt_bal
       FROM coil
       WHERE (coil_abc_num = cloop.coil_abc_num);
              
       IF coil_st = 7 THEN
          SELECT process_coil_status, NVL(process_quantity,0) INTO process_coil_st, process_coil_wt
          FROM process_coil
          WHERE (coil_abc_num = cloop.coil_abc_num) AND (ab_job_num = p_ab_job);
                    
          IF process_coil_wt > coil_wt_bal THEN
             wt_reband := 0;
          ELSE 
             wt_reband := process_coil_wt;
          END IF;
          
          wt_reband_total :=  wt_reband_total + wt_reband;
       END IF;
   end loop;
   
   Result := process_wt + wt_reband_total;
     
  return(Result);
end F_COIL_WEIGHT;
  GRANT EXECUTE ON "DBO"."F_COIL_WEIGHT" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function F_CONVERT_BACK_TO_SHEET
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_CONVERT_BACK_TO_SHEET" (p_scrap_skid_num in scrap_skid.scrap_skid_num%type) return  int is
  Result integer := 1;
  
  Cursor cur_sss IS
  SELECT  *
  FROM scraped_sheet_skid sss	
  WHERE sss.scrap_skid_num = p_scrap_skid_num;
  
  Cursor cur_spps IS
  SELECT  *
  FROM scraped_process_partial_skid	spps	
  WHERE spps.scrap_skid_num = p_scrap_skid_num;
  
  Cursor cur_sssd IS
  SELECT  *
  FROM scraped_sheet_skid_detail sssd	
  WHERE sssd.scrap_skid_num = p_scrap_skid_num;
  
  Cursor cur_spsi IS
  SELECT  spsi.*
  FROM scraped_production_sheet_item spsi, scraped_sheet_skid_detail sssd
  WHERE spsi.prod_item_num = sssd.prod_item_num
    and sssd.scrap_skid_num = p_scrap_skid_num;
  
  Cursor cur_rsin Is
  Select ssd.return_scrap_item_num
  from scrap_skid_detail ssd
  where ssd.scrap_skid_num = p_scrap_skid_num;
  
  --Alex Gerlants. 01/06/2020. Begin
  cursor cur_return_scrap_item is
  select  *
  from    return_scrap_item
  WHERE return_scrap_item_num in
  (
    Select ssd.return_scrap_item_num
    from scrap_skid_detail ssd
    where ssd.scrap_skid_num = p_scrap_skid_num
  );
  
  ll_return_scrap_item_num     return_scrap_item.return_scrap_item_num%type;
  ls_num_string   varchar(2000);
  ls_return_scrap_item_num   varchar(20);
  ll_pos_comma               number(4);
  ll_start                   number(4);
  --Alex Gerlants. 01/06/2020. End
  
begin
  --copy scraped_sheet_skid_num.* to sheet_skid_num
  for rec_sss in cur_sss loop
      insert into sheet_skid (sheet_skid_num,ab_job_num,sheet_net_wt,sheet_tare_wt,skid_edi856_date,skid_location,skid_date,skid_sheet_status,skid_pieces,sheet_theoretical_wt,skid_from_if_whed,skid_ticket_if_whed,ref_order_abc_num,skid_type_if_whed,ref_order_abc_item,skid_sheet_status_held_by_qc)
      values (rec_sss.sheet_skid_num,rec_sss.ab_job_num,rec_sss.sheet_net_wt,rec_sss.sheet_tare_wt,rec_sss.skid_edi856_date,rec_sss.skid_location,rec_sss.skid_date,rec_sss.skid_sheet_status,rec_sss.skid_pieces,rec_sss.sheet_theoretical_wt,rec_sss.skid_from_if_whed,rec_sss.skid_ticket_if_whed,rec_sss.ref_order_abc_num,rec_sss.skid_type_if_whed,rec_sss.ref_order_abc_item,rec_sss.skid_sheet_status_held_by_qc);
      --commit; 
  end loop;   
  
   --copy scraped_production_sheet_item.* to production_sheet_item.
  for rec_spsi in cur_spsi loop
      insert into production_sheet_item (prod_item_num,coil_abc_num,ab_job_num,prod_item_status,prod_item_pieces,prod_item_net_wt,prod_item_theoretical_wt,prod_item_edi870_date,prod_item_date,prod_item_note,prod_item_placement)
      values  (rec_spsi.prod_item_num,rec_spsi.coil_abc_num,rec_spsi.ab_job_num,rec_spsi.prod_item_status,rec_spsi.prod_item_pieces,rec_spsi.prod_item_net_wt,rec_spsi.prod_item_theoretical_wt,rec_spsi.prod_item_edi870_date,rec_spsi.prod_item_date,rec_spsi.prod_item_note,rec_spsi.prod_item_placement);
      --commit;
  end loop;
  
  --copy process_partial_skid.* to scraped_process_partial_skid.
  for rec_spps in cur_spps loop
      insert into process_partial_skid (ab_job_num,sheet_skid_num,partial_skid_ab_job_num,partial_sheet_net_wt,partial_skid_location,partial_skid_date,partial_skid_pieces,partial_sheet_theoretical_wt)
      values (rec_spps.ab_job_num,rec_spps.sheet_skid_num,rec_spps.partial_skid_ab_job_num,rec_spps.partial_sheet_net_wt,rec_spps.partial_skid_location,rec_spps.partial_skid_date,rec_spps.partial_skid_pieces,rec_spps.partial_sheet_theoretical_wt);
      --commit;
  end loop;
  
  --copy sheet_skid_detail.* to scraped_sheet_skid_detail.
  for rec_sssd in cur_sssd loop
      insert into sheet_skid_detail (prod_item_num,sheet_skid_num)
      values (rec_sssd.prod_item_num,rec_sssd.sheet_skid_num);
      --commit;
  end loop;
  
   
  --delete records from scraped_ tables.
  delete from scraped_sheet_skid_detail
  where scrap_skid_num = p_scrap_skid_num;
  --commit;
  
  delete from scraped_production_sheet_item
  where scrap_skid_num = p_scrap_skid_num;  
  --commit;
  
  delete from scraped_process_partial_skid
  where scrap_skid_num = p_scrap_skid_num;
  --commit;
  
  delete from scraped_sheet_skid
  where scrap_skid_num = p_scrap_skid_num;
  
  ---------------------------------------------------------------
  --Alex Gerlants. 01/06/2020. Begin
  --Collect all return_scrap_item_num in ls_num_string
  for rec_return_scrap_item in cur_return_scrap_item loop
    ll_return_scrap_item_num := rec_return_scrap_item.return_scrap_item_num;
    
    ls_num_string := ls_num_string || to_char(ll_return_scrap_item_num) || ',';
  end loop;
  --Alex Gerlants. 01/06/2020. End
  ----------------------------------------------------------------
  
  --delete record from scrap_skid table
  delete from scrap_skid_detail ssd
  where ssd.scrap_skid_num = p_scrap_skid_num;
  
  delete from scrap_skid
  where scrap_skid_num = p_scrap_skid_num;
  
  --Alex Gerlants. 01/06/2020. Begin  
  /*
  for rec_rsin in cur_rsin loop
      delete from return_scrap_item rsi
      where rsi.return_scrap_item_num = rec_rsin.return_scrap_item_num;
  end loop;
  */
  --Delete from return_scrap_item using return_scrap_item_num in ls_num_string
  if length(ls_num_string) > 0 then
    ls_num_string := substr(ls_num_string, 1, length(ls_num_string) - 1); --Remove the last comma
  
    ll_start := 1;
    ll_pos_comma := instr(ls_num_string, ',', ll_start);
    
    if ll_pos_comma > 0 then --ls_num_string has more than 1 value
        while ll_pos_comma > 0 loop
          ls_return_scrap_item_num := substr(ls_num_string, ll_start, ll_pos_comma - 1);
          ll_return_scrap_item_num := to_number(ls_return_scrap_item_num);
          
          delete from return_scrap_item
          where return_scrap_item_num = ll_return_scrap_item_num;
          
          ll_start := ll_pos_comma + 1;
          ll_pos_comma := instr(ls_num_string, ',', ll_start);
          
          if ll_pos_comma = 0 then --Last value in ls_num_string
            ls_return_scrap_item_num := substr(ls_num_string, ll_start, Length(ls_num_string) + 1);
            ll_return_scrap_item_num := to_number(ls_return_scrap_item_num);
            
            delete from return_scrap_item
            where return_scrap_item_num = ll_return_scrap_item_num;
          end if;
        end loop;
    else --ls_num_string has 1 value
      ls_return_scrap_item_num := ls_num_string;
      ll_return_scrap_item_num := to_number(ls_return_scrap_item_num);
      
      delete from return_scrap_item
      where return_scrap_item_num = ll_return_scrap_item_num;
    end if;
  end if;

  commit;  --Comment out. TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY
  --rollback; --TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY
  --Alex Gerlants. 01/06/2020. End
  
  return(Result);
  
  EXCEPTION
     WHEN dup_val_on_index then
          rollback;
          return -100;     
     WHEN OTHERS THEN
          rollback;  
          RETURN -1; 
  
  
end F_CONVERT_BACK_TO_SHEET;
  GRANT EXECUTE ON "DBO"."F_CONVERT_BACK_TO_SHEET" TO "AGERLANTS"
