  --commit;
  
  delete from scraped_production_sheet_item
  where scrap_skid_num = p_scrap_skid_num;  
  --commit;
  
  delete from scraped_process_partial_skid
  where scrap_skid_num = p_scrap_skid_num;
  --commit;
  
  delete from scraped_sheet_skid
  where scrap_skid_num = p_scrap_skid_num;
  
  --delete record from scrap_skid table
