  where ssd.scrap_skid_num = p_scrap_skid_num;
  
  delete from scrap_skid
  where scrap_skid_num = p_scrap_skid_num;
  
  for rec_rsin in cur_rsin loop
      delete from return_scrap_item rsi
      where rsi.return_scrap_item_num = rec_rsin.return_scrap_item_num;
  end loop;
  
  commit;  
  
  return(Result);
  
  EXCEPTION
     WHEN dup_val_on_index then
          rollback;
          return -100;     
     WHEN OTHERS THEN
          rollback;  
          RETURN -1; 
  
  
end F_CONVERT_BACK_TO_SHEET_1;
