--  DDL for Function F_CONVERT_TO_SCRAP
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_CONVERT_TO_SCRAP" (p_sheet_skid_num IN sheet_skid.sheet_skid_num%TYPE)
  RETURN INTEGER IS

  RESULT INTEGER := 1;

  CURSOR cur_ss IS
    SELECT * FROM sheet_skid ss WHERE ss.sheet_skid_num = p_sheet_skid_num;

  CURSOR cur_pps IS
    SELECT *
      FROM process_partial_skid pps
     WHERE pps.sheet_skid_num = p_sheet_skid_num;

  CURSOR cur_ssd IS
    SELECT *
      FROM sheet_skid_detail ssd
     WHERE ssd.sheet_skid_num = p_sheet_skid_num;

  CURSOR cur_psi IS
    SELECT psi.*
      FROM production_sheet_item psi, sheet_skid_detail ssd
     WHERE psi.prod_item_num = ssd.prod_item_num
       AND ssd.sheet_skid_num = p_sheet_skid_num;

  CURSOR cur_pin IS
    SELECT ssd.prod_item_num
      FROM sheet_skid_detail ssd
     WHERE sheet_skid_num = p_sheet_skid_num;

  li_scrap_skid_num       INT;
  li_return_scrap_item_id INT;
  li_customer_id          INT;
  ls_alloy2               VARCHAR2(8);
  ls_temper               VARCHAR2(8);
  ls_customer_po          customer_order.orig_customer_po%TYPE;
  li_ab_job               INT;
  li_net_wt               INT;
  li_tare_wt              INT;

  t INT := 0;
BEGIN
  SELECT scrap_skid_num_seq.nextval INTO li_scrap_skid_num FROM dual;

  --create new scrap skid
  SELECT co.orig_customer_id, co.orig_customer_po
    INTO li_customer_id, ls_customer_po
    FROM customer_order co, sheet_skid ss
   WHERE co.order_abc_num = ss.ref_order_abc_num
     AND ss.sheet_skid_num = p_sheet_skid_num;

  SELECT oi.alloy2, oi.temper, aj.ab_job_num
    INTO ls_alloy2, ls_temper, li_ab_job
    FROM order_item oi, ab_job aj, sheet_skid ss
   WHERE oi.order_item_num = aj.order_item_num
     AND oi.order_abc_num = aj.order_abc_num
     AND aj.ab_job_num = ss.ab_job_num
     AND ss.sheet_skid_num = p_sheet_skid_num;

  SELECT ss.sheet_net_wt, ss.sheet_tare_wt
    INTO li_net_wt, li_tare_wt
    FROM sheet_skid ss
   WHERE ss.sheet_skid_num = p_sheet_skid_num;

  INSERT INTO scrap_skid
    (scrap_skid_num,
     customer_id,
     scrap_type,
     scrap_temper,
     scrap_net_wt,
     scrap_tare_wt,
     scrap_cust_po,
     scrap_ab_job_num,
     scrap_date,
     skid_scrap_status,
     scrap_notes,
     scrap_alloy2)
  VALUES
    (li_scrap_skid_num,
     li_customer_id,
     1,
     ls_temper,
     li_net_wt,
     li_tare_wt,
     ls_customer_po,
     li_ab_job,
     SYSDATE,
     2,
     'SK # ' || p_sheet_skid_num,
     ls_alloy2);
  --commit;  

  --copy sheet_skid_num.* to scraped_sheet_skid_num
  FOR rec_ss IN cur_ss LOOP
    INSERT INTO scraped_sheet_skid
      (sheet_skid_num,
       ab_job_num,
       sheet_net_wt,
       sheet_tare_wt,
       skid_edi856_date,
       skid_location,
       skid_date,
       skid_sheet_status,
       skid_pieces,
       sheet_theoretical_wt,
       skid_from_if_whed,
       skid_ticket_if_whed,
       ref_order_abc_num,
       skid_type_if_whed,
       ref_order_abc_item,
       skid_sheet_status_held_by_qc,
       scrap_skid_num)
    VALUES
      (rec_ss.sheet_skid_num,
       rec_ss.ab_job_num,
       rec_ss.sheet_net_wt,
       rec_ss.sheet_tare_wt,
       rec_ss.skid_edi856_date,
       rec_ss.skid_location,
       rec_ss.skid_date,
       rec_ss.skid_sheet_status,
       rec_ss.skid_pieces,
       rec_ss.sheet_theoretical_wt,
       rec_ss.skid_from_if_whed,
       rec_ss.skid_ticket_if_whed,
       rec_ss.ref_order_abc_num,
       rec_ss.skid_type_if_whed,
       rec_ss.ref_order_abc_item,
       rec_ss.skid_sheet_status_held_by_qc,
       li_scrap_skid_num);
    --commit; 
  END LOOP;

  --copy production_sheet_item.* to scraped_production_sheet_item.
  FOR rec_psi IN cur_psi LOOP
    INSERT INTO scraped_production_sheet_item
      (prod_item_num,
       coil_abc_num,
       ab_job_num,
       prod_item_status,
       prod_item_pieces,
       prod_item_net_wt,
       prod_item_theoretical_wt,
       prod_item_edi870_date,
       prod_item_date,
       prod_item_note,
       prod_item_placement,
       scrap_skid_num)
    VALUES
      (rec_psi.prod_item_num,
       rec_psi.coil_abc_num,
       rec_psi.ab_job_num,
       rec_psi.prod_item_status,
       rec_psi.prod_item_pieces,
       rec_psi.prod_item_net_wt,
       rec_psi.prod_item_theoretical_wt,
       rec_psi.prod_item_edi870_date,
       rec_psi.prod_item_date,
       rec_psi.prod_item_note,
       rec_psi.prod_item_placement,
       li_scrap_skid_num);
  
    SELECT return_scrap_item_id_seq.nextval
      INTO li_return_scrap_item_id
      FROM dual;
  
    INSERT INTO return_scrap_item
      (return_scrap_item_num,
       coil_abc_num,
       ab_job_num,
       return_item_net_wt,
       return_item_date)
    VALUES
      (li_return_scrap_item_id,
       rec_psi.coil_abc_num,
       rec_psi.ab_job_num,
       rec_psi.prod_item_net_wt,
       SYSDATE);
    INSERT INTO scrap_skid_detail
      (scrap_skid_num, return_scrap_item_num)
    VALUES
      (li_scrap_skid_num, li_return_scrap_item_id);
    --commit;
  END LOOP;

  --copy process_partial_skid.* to scraped_process_partial_skid.
  FOR rec_pps IN cur_pps LOOP
    INSERT INTO scraped_process_partial_skid
      (ab_job_num,
       sheet_skid_num,
       partial_skid_ab_job_num,
       partial_sheet_net_wt,
       partial_skid_location,
       partial_skid_date,
       partial_skid_pieces,
       partial_sheet_theoretical_wt,
       scrap_skid_num)
    VALUES
      (rec_pps.ab_job_num,
       rec_pps.sheet_skid_num,
       rec_pps.partial_skid_ab_job_num,
       rec_pps.partial_sheet_net_wt,
       rec_pps.partial_skid_location,
       rec_pps.partial_skid_date,
       rec_pps.partial_skid_pieces,
       rec_pps.partial_sheet_theoretical_wt,
       li_scrap_skid_num);
    --commit;
  END LOOP;

  --copy sheet_skid_detail.* to scraped_sheet_skid_detail.
  FOR rec_ssd IN cur_ssd LOOP
    INSERT INTO scraped_sheet_skid_detail
      (prod_item_num, sheet_skid_num, scrap_skid_num)
    VALUES
      (rec_ssd.prod_item_num, rec_ssd.sheet_skid_num, li_scrap_skid_num);
    --commit;
  END LOOP;

  --delete records from sheet skid tables.
  FOR rec_pin IN cur_pin LOOP
    DELETE FROM sheet_skid_detail
     WHERE prod_item_num = rec_pin.prod_item_num;
  
    DELETE FROM production_sheet_item
     WHERE prod_item_num = rec_pin.prod_item_num;
  END LOOP;
  --commit;

  DELETE FROM process_partial_skid WHERE sheet_skid_num = p_sheet_skid_num;
  --commit;

  DELETE FROM sheet_skid WHERE sheet_skid_num = p_sheet_skid_num;
  COMMIT;

  RETURN(RESULT);

EXCEPTION
  WHEN dup_val_on_index THEN
    ROLLBACK;
    RETURN - 100;
  WHEN OTHERS THEN
    ROLLBACK;
    RETURN - 1;
  
END f_convert_to_scrap;
  GRANT EXECUTE ON "DBO"."F_CONVERT_TO_SCRAP" TO "AGERLANTS"
