  CREATE OR REPLACE FUNCTION "DBO"."F_CREATE_EDI_861_BY_BOL" (par_bol in inbound_shipment.bol%type, par_edi_file_id in inbound_shipment.edi_file_id%type, par_received_time in varchar2) return integer is
  
  li_return integer :=1;
 /* Returns:   Integer
               1 = if it succeeds
              -1 = if system error occurs
              -2 = if errors with UTL_FILE
             
 */
  li_gs_log INTEGER; 
  li_st_log INTEGER;
  ls_today_short VARCHAR2(20) := to_char(SYSDATE, 'yymmdd');
  ls_today VARCHAR2(20) := to_char(SYSDATE, 'yyyymmdd');
  ls_now VARCHAR2(20) := to_char(SYSDATE, 'hh24mi');
  ls_received_time varchar2(13);
  ld_received_time date;
  
  type edi_861_tabletype is table of varchar2(32767) index by binary_integer;
  edi_861 edi_861_tabletype;
  j binary_integer := 0;
  i integer;
  coil_count integer :=0;
  li_customer_id integer;
  ls_po varchar2(20);
  ls_coil_number varchar2(40);
  ls_ps_coil_number varchar2(40);
  ls_temper varchar2(8);
  ln_net_weight number(8,0);
  ln_gross_weight number(8,0);
  ln_lineal_feed number(7,2);
  ln_coil_width number(7,2);
  ln_coil_gauge number(5,4);
  ln_density number;
  ls_lot varchar2(40);
  ls_pack_id varchar2(40);
  ls_alloy varchar2(40);
  ln_damage_fault number(1);
  ln_damage_code number(3);
  
  cursor bol_cursor is     --this cursor collect all coils under the po# and edi_file_id.
  select a.coil_number, a.temper, a.net_weight, a.gross_weight, a.lineal_feed, a.coil_width, a.coil_gauge, a.density, a.lot, a.pack_id, a.alloy, a.ps_coil_number, b.damaged_code, b.damaged_fault
  from inbound_coil a, inbound_coil_status b
  where a.bol = par_bol and a.edi_file_id = par_edi_file_id and
        a.bol = b.bol and a.edi_file_id = b.edi_file_id and
        a.item_num = b.item_num;
  
  edi_location varchar2(50):='/templar/templar/incoming/senddata';
  edi_file varchar2 (50) := 'edi_out.txt';
  edi_file_handle UTL_FILE.FILE_TYPE;
  li_edi_861_id integer;
  ls_dun varchar2(32);  --duns# will be determined by ship_from customer.
  ls_ship_from varchar2(40);    --getting from inbound_shipment.
  
begin
  /*SELECT EDI_ST_LOG_SEQ.NEXTVAL INTO li_st_log FROM dual;
  SELECT EDI_GS_LOG_SEQ.NEXTVAL INTO li_gs_log FROM dual;
  
  select po into ls_po from inbound_shipment
  where bol = par_bol and edi_file_id = par_edi_file_id;

  --will be used in edi file at 'yyyymmddhrmi' format.
