  --change it to "yyyymmdd*hr24mi" format.
  ls_received_time := substr(par_received_time, 7, 4)||substr(par_received_time, 1, 2)||substr(par_received_time, 4, 2)||'*'||substr(par_received_time, 12, 2)||substr(par_received_time, 15, 2);
    
  edi_861(j):= 'ISA*00*          *00*          *01*039630926T     *09*0015049350011G *'
  || ls_today_short ||'*'|| ls_now ||'*U*00200*'||LPAD(to_char(li_gs_log),9,'0')||'*0*P**'; j := j + 1;
  edi_861(j):= 'GS*RC*039630926T*0015049350011G*'|| ls_today ||'*'||ls_now||'*'||li_gs_log||'*X*004010'   ; j :=j + 1;
  edi_861(j):= 'ST*861*'||li_st_log ; j :=j + 1;
  edi_861(j):= 'BRA*'||par_bol||'*'||ls_today ||'*00*1*'||ls_now; j := j + 1;
  edi_861(j):= 'DTM*050*'||ls_received_time||'*ED'; j := j + 1;
  edi_861(j):= 'N1*OU**1*039630926'; j := j + 1;
  
  select ship_from into ls_ship_from from inbound_shipment
  where edi_file_id = par_edi_file_id and bol = par_bol;
  select customer_id into li_customer_id from inbound_shipment_customer
  where ship_from = ls_ship_from;
  if li_customer_id = 1153 then
     ls_dun := '241003755';--'Novelis Kingston'
  elsif  li_customer_id = 1459 then
     ls_dun := '003980216';--'Novelis Oswego'
  else
     ls_dun := '241003755';
  end if;
   
  edi_861(j):= 'N1*SU**1*'||ls_dun; j := j + 1;
  
  for cloop in bol_cursor loop      --get coil's data.
      ls_coil_number := cloop.coil_number;
      ls_temper := cloop.temper;
      ln_net_weight := cloop.net_weight;
      ln_gross_weight := cloop.gross_weight;
      ln_lineal_feed := cloop.lineal_feed;
      ln_coil_width := cloop.coil_width;
      ln_coil_gauge := cloop.coil_gauge;
      ln_density := cloop.density;
      ls_lot := cloop.lot;
      ls_pack_id := cloop.pack_id;
      ls_alloy := cloop.alloy;
      ls_ps_coil_number := cloop.ps_coil_number;
      ln_damage_fault := cloop.damaged_fault;
      ln_damage_code := cloop.damaged_code;
            
      if (ls_ps_coil_number is null)then
         ls_ps_coil_number := ls_coil_number;
      end if;
      
      edi_861(j):= 'RCD**1*CX'; j := j + 1;
      edi_861(j):= 'LIN**VO*'||ls_po||'*SN*'||ls_coil_number||'*HN*'||ls_lot||'*PK*'||ls_pack_id; j := j + 1;
      edi_861(j):= 'PID*S*MAC*ST*01'; j := j + 1;
      edi_861(j):= 'PID*S*MA*ST*7'; j := j + 1;
      
      --add these two segment only for damaged coils
      if ln_damage_code <> 0 then
         edi_861(j):= 'PID*S*DAC*ST*'||ln_damage_code; j := j + 1;
      end if;
      if ln_damage_fault <> 0 then
      \* DAF??? *\
         edi_861(j):= 'PID*S*DAF*ST*'||ln_damage_fault; j := j + 1;
      end if;
      
      edi_861(j):= 'PID*S*QAS*ST*2'; j := j + 1; 
      edi_861(j):= 'REF*SE*'||ls_coil_number; j := j + 1;  
      edi_861(j):= 'REF*BM*'||par_bol; j := j + 1; 
      edi_861(j):= 'REF*RV*'||ls_ps_coil_number; j := j + 1;
      edi_861(j):= 'PRF*'||ls_po; j := j + 1; 
      edi_861(j):= 'MEA*WT**'||ln_net_weight||'*01'; j := j + 1;  
      edi_861(j):= 'MEA*WT**'||ln_gross_weight||'*24'; j := j + 1; 
      edi_861(j):= 'MEA*PD*TH*'||to_char(ln_coil_gauge,'FM90.0000')||'*IN'; j := j + 1;
      edi_861(j):= 'MEA*PD*WD*'||to_char(ln_coil_width,'FM99990.0000')||'*IN'; j := j + 1; 
      edi_861(j):= 'MEA*CT**'||ln_lineal_feed||'*LF'; j := j + 1;  
            
      coil_count := coil_count + 1;
  end loop;
  
  edi_861(j):= 'CTT*'||coil_count; j := j + 1; 
  edi_861(j):= 'SE*'||to_char(j-1)||'*'||li_st_log; j := j + 1;
  edi_861(j):= 'GE*1*'||li_gs_log; j := j + 1;
  edi_861(j):= 'IEA*1*'||LPAD(to_char(li_gs_log),9,'0');
  
  SELECT edi_file_id_seq.NEXTVAL INTO li_edi_861_id FROM DUAL;
  
  edi_file := 'S_alcan_'||to_char(li_edi_861_id)||'.861';
  edi_file_handle :=utl_file.fopen(edi_location,edi_file,'W');
  
  --write edi to file
  FOR i IN 0..j LOOP
    utl_file.put_line(edi_file_handle,edi_861(i));
  END LOOP;
  
  utl_file.fclose(edi_file_handle);
  
 \*--added by Victor Huang on 06/05 for funtion aknowlegement
  INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
  VALUES(li_gs_log, ls_dun, sysdate, edi_file);
  COMMIT;*\
  
  --added by Victor Huang on 12/07 for verifying 997
  INSERT INTO outbound_edi_transaction(edi_file_id,duns_from,duns_to,interchange_control_number,
  group_control_number,transaction_time,edi_file_name,fa_receive_status,customer_id,set_control_num,transaction_type_id)
  VALUES(li_edi_861_id,'039630926',ls_dun,li_gs_log,li_gs_log, sysdate, edi_file,0,li_customer_id,li_st_log,'861');
  COMMIT;
  
  edi_file := 'send_edi_log';
  edi_file_handle :=utl_file.fopen(edi_location,edi_file,'a');
  utl_file.put_line(edi_file_handle,'Type: 861');
  utl_file.put_line(edi_file_handle,'Sending Time: '||to_char(sysdate, 'MM/DD/YY HH24:MI'));
  utl_file.put_line(edi_file_handle,'Interchange Control #: '||li_gs_log);
  utl_file.put_line(edi_file_handle,'Group Control #: '||li_gs_log);
  utl_file.put_line(edi_file_handle,'Set Control #: '||li_st_log);
  utl_file.put_line(edi_file_handle,'');
  utl_file.put_line(edi_file_handle,'');
  utl_file.fclose(edi_file_handle);
  
  UPDATE "INBOUND_SHIPMENT_STATUS"  
    SET "RECEIVED_TIME" = ld_received_time,   
        "STATUS" = 1 
	 where "BOL" = par_bol AND "EDI_FILE_ID" = par_edi_file_id;*/
  
  return li_return;
  
  EXCEPTION
     WHEN UTL_FILE.INVALID_PATH THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN -2; 
     WHEN UTL_FILE.INVALID_MODE THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN -2;
    WHEN UTL_FILE.INVALID_OPERATION THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN -2;   
    WHEN UTL_FILE.WRITE_ERROR THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN -2;      
    WHEN OTHERS THEN
     UTL_FILE.FCLOSE_ALL;
      RETURN -1;
  
  
end F_CREATE_EDI_861_BY_BOL;
  GRANT EXECUTE ON "DBO"."F_CREATE_EDI_861_BY_BOL" TO "AGERLANTS"
