--  DDL for Function F_CREATE_EDI_863_FILE_BY_COIL
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_CREATE_EDI_863_FILE_BY_COIL" 
(par_sample_id varchar2,par_coil_org_num varchar2,par_operator varchar2, par_file_id integer,
par_test_type integer, par_n integer, par_r integer)
return integer is
/* Returns:   Integer
               1 = if it succeeds
              -1 = if system error occurs
              -2 = if errors with UTL_FILE
             
 */
  li_need_retest_date integer :=0;
  li_test_type integer;--Test type : 1.First Test
                       --            2.First Test Redo
                       --            3.First Full Test
                       --            4.Full Test
  li_n integer;
  li_r integer;
  
  ln_r number := 0;
  ln_n number := 0;
  
  ls_sample_id varchar2(20) := par_sample_id;
  ls_coil_org_num varchar2(32) := par_coil_org_num;
  li_file_id integer := par_file_id;
  ls_operator VARCHAR2(20) := par_operator;
  
  cursor data_string_cursor is 
   select data_string from processing_string_863
   where sample_id = ls_sample_id and coil_org_num = ls_coil_org_num and send_status = 0;

  type edi_863_tabletype is table of varchar2(32767) index by binary_integer;
  edi_863 edi_863_tabletype;
  j binary_integer := 0;
  k integer; -- edi_863(k) for holding the value of retest day
    
  li_customer_id INTEGER;
  ls_duns VARCHAR2(20);
  ln_coil_width NUMBER(2,0) := 0;
  ln_coil_thickness NUMBER(17,16) :=0;

  ls_today_short VARCHAR2(20) := to_char(SYSDATE, 'yymmdd');
  ls_today VARCHAR2(20) := to_char(SYSDATE, 'yyyymmdd');
  ls_now VARCHAR2(20) := to_char(SYSDATE, 'hh24mi');

  li_gs_log INTEGER;
  li_st_log INTEGER;

  i INTEGER;
     
  ls_action_coil_pos VARCHAR2(255); --these variables handling the action string
  ls_action_ps1 CHAR(1);
  ls_action_ps2 CHAR(1);
  ln_action_thickness NUMBER(17,16);
  ln_action_yts NUMBER;
  ln_action_uts NUMBER;
  ln_action_elongation NUMBER;
  ls_action_string VARCHAR2(32767);
  ls_tmp CHAR(2);
  ls_tmd CHAR(3);
  ls_pos CHAR(2);
  
  
  li_edi_863_id INTEGER; --for table edi_863_data and the id of each edi_863 sending file
  ls_edi_data_file_send VARCHAR2(32767);--holding the send edi_863_file string
  li_coil_abc_num integer;
  
  ls_coil_alloy varchar2(8);--for calculating retest date
  ls_coil_temper varchar2(8);
  ld_retest_date DATE;
  ld_test_date DATE;  
  
  edi_location varchar2(50):='/templar/templar/incoming/senddata';
  edi_file varchar2 (50) := 'edi_out.txt';
  edi_file_handle UTL_FILE.FILE_TYPE;
  
  li_source_customer_id int;
  li_lube_weight_ready integer := 0; -- if >0 ready
  ln_lube_weight number;
  
  li_count integer;
  
  --ls_process_by varchar2(32);
  --li_lw_required int := 1;
    
  
  BEGIN
  li_test_type := par_test_type;
  li_n := par_n;
  li_r := par_r;
  ld_test_date := to_date(par_sample_id, 'yyyymmddhh24mi');
    
  --* creat edi8683 files here
  SELECT EDI_ST_LOG_SEQ.NEXTVAL INTO li_st_log FROM dual;
  SELECT EDI_GS_LOG_SEQ.NEXTVAL INTO li_gs_log FROM dual;

  SELECT customer_id INTO li_customer_id FROM coil 
         WHERE ( (coil_org_num = ls_coil_org_num ) and (coil_status != 20) and customer_id in (1153,1459));
  SELECT customer_duns_number_string INTO ls_duns FROM customer 
         WHERE customer_id = li_customer_id ;
  
  SELECT coil_abc_num INTO li_coil_abc_num
  FROM coil
  WHERE ( (coil_org_num = ls_coil_org_num ) and (coil_status != 20) );--assign coil_abc_number according to coil_org_num
  
  select coil_alloy2, upper(coil_temper) into 
  ls_coil_alloy, ls_coil_temper from coil
  where coil_abc_num = li_coil_abc_num;
    
  
  edi_863(j):= 'ISA*00*          *00*          *01*039630926T     *09*0015049350011G *'
  || ls_today_short ||'*'|| ls_now ||'*U*00401*'||LPAD(to_char(li_gs_log),9,'0')|| '*0*P**'; j := j + 1;
  edi_863(j) :='GS*RT*039630926T*0015049350011W*' || ls_today ||'*'||ls_now||'*'||li_gs_log||'*X*004010'   ; j :=j + 1;
  edi_863(j) :='ST*863*'||li_st_log ; j :=j + 1;
  edi_863(j) :='BTR*00*'||ls_today||'*'||ls_now ; j :=j + 1;
  edi_863(j) :='NTE*SPH*I CERTIFY THAT THE MATERIALS DETAILED HEREIN HAVE BEEN SELEC'; j :=j + 1;
  edi_863(j) :='NTE*SPH*TED FROM PROPERLY CLASSIFIED STOCK, OF WHICH REPRESENTATIVE'; j :=j + 1;
  edi_863(j) :='NTE*SPH*SAMPLES HAVE BEEN TESTED TO PROVE CONFORNITY WITH THE APPROP'; j :=j + 1;
  edi_863(j) :='NTE*SPH*RIATE SPECIFICATION, AND THAT DOCUMENTARY EVIDENCE OF THE TE'; j :=j + 1;
  edi_863(j) :='NTE*SPH*ST OF RELEASE CERTIFICATION IS ON FILE IN THE OFFICES OF ALCAN'; j :=j + 1;
  edi_863(j) :='NTE*SPH*ALUMINUM CORPORATION.'; j :=j + 1;
  edi_863(j) :='REF*MI*000000000'; j :=j + 1;
  edi_863(j) :='REF*BM*000000000'; j :=j + 1;
  
  -- modified by victor huang on 02/2004 as per ALCAN's request
  -- F: Full Test, P: Partial Test
  if li_test_type in (3,4,5) then
     edi_863(j) :='REF*SI*'||ls_coil_org_num||'*F'; j :=j + 1;
  else
     edi_863(j) :='REF*SI*'||ls_coil_org_num||'*P'; j :=j + 1; 
  end if; 
  --edi_863(j) :='REF*SI*'||ls_coil_org_num; j :=j + 1;
  
  edi_863(j) :='DTM*011*'||ls_today||'*'||ls_now; j :=j + 1;
  edi_863(j) :='N1*SU*NOVELIS INC.*1*'||ls_duns; j :=j + 1;
  edi_863(j) :='N3*6060 PARKLAND BLVD.'; j :=j + 1;
  edi_863(j) :='N4*MAYFIELD HTS.*OH*441244185'; j :=j + 1;
  edi_863(j) :='N1*PV*'||ls_operator||'*1*039630926'; j :=j + 1;
  edi_863(j) :='LIN**VO*00000*BP*00000*VN*001*VS*'||ls_coil_org_num||'*SN*00000*VU*'||to_char(li_coil_abc_num); j :=j + 1;
  edi_863(j) :='PID*F*16*AA*O'; j :=j + 1;
  edi_863(j) :='PID*F*11*AA*081131DDD000*ALCAN'; j :=j + 1;
  edi_863(j) :='PID*F*38*AA*5182'; j :=j + 1;
  edi_863(j) :='PID*S*PR*ST*20'; j :=j + 1;
  edi_863(j) :='DTM*009*'||ls_today||'*'||ls_now; j :=j + 1;
  edi_863(j) :='DTM*222*'||ls_today||'*'||ls_now; j :=j + 1;
  
  if li_test_type in (1,2,3) and  ls_coil_alloy = '6111' and
   ls_coil_temper in ('T4P','T4PB','T4PD') then
   edi_863(j) :=''; k := j; j := j+1; -- edi_863(k) for holding the value of retest day
   li_need_retest_date :=1;
  end if;
  
  OPEN data_string_cursor;

  LOOP
