                                                                  where coil_abc_num = li_coil_abc_num);
    if ls_process_by = 'ALCAN' then 
       li_lw_required := 0;    --assuming if got lw from ALCAN, then do NOT need to process lw here
    else
       li_lw_required := 1;    --otherwise, need to process lw here
    end if;
  else  --if not available lw data, need to check it with lw_flag in I841  
    select count(*) into li_count
    from inbound_841 a, customer_order b, ab_job c, process_coil d, coil e
    where a.po = b.orig_customer_po and
          b.order_abc_num = c.order_abc_num and
          c.ab_job_num = d.ab_job_num and
          d.coil_abc_num = li_coil_abc_num;
    
    if li_count > 0 then
       --select a.two_min, a.two_max into ls_lw_min, ls_lw_max
       select to_number(a.lw_flag) into li_lw_required
       from inbound_841 a, customer_order b, ab_job c, process_coil d, coil e
       where a.po = b.orig_customer_po and
              b.order_abc_num = c.order_abc_num and
              c.ab_job_num = d.ab_job_num and
              d.coil_abc_num = li_coil_abc_num
              and a.edi_file_id = (select max(a.edi_file_id) 
                                   from inbound_841 a, customer_order b, ab_job c, process_coil d, coil e
                                   where a.po = b.orig_customer_po and
                                   b.order_abc_num = c.order_abc_num and
                                   c.ab_job_num = d.ab_job_num and
                                   d.coil_abc_num = li_coil_abc_num);
    else
      li_lw_required := 1;  --if no available I841, assuming li_lw_required := 1
    end if;
  end if;
     
  if (li_lw_required = 1) and ( li_lube_weight_ready = 1 ) then
    
    select avg(lube_weight) into ln_lube_weight
    from lube_weight
    where coil_abc_num = li_coil_abc_num;
    
    edi_863(j) := 'CID**71'; j :=j + 1;
    edi_863(j) := 'PSD*******11*sample'; j :=j + 1;
    edi_863(j) := 'PSD*******21*position'; j :=j + 1;
    edi_863(j) := 'TMD*32*AA*TWO****'||ls_today; j :=j + 1;
    edi_863(j) := 'MEA*TR**'||TO_CHAR(ln_lube_weight,'FM90.000000')||'*MF'; j :=j + 1;
    
    edi_863(j) :='CTT*1*54'; j :=j + 1;
    edi_863(j) :='SE*'||to_char(j-1)||'*'||to_char(li_st_log); j :=j + 1;
    edi_863(j) :='GE*1*'||to_char(li_gs_log); j :=j + 1;
    edi_863(j) :='IEA*1*'||LPAD(to_char(li_gs_log),9,'0');
  else
    edi_863(j) :='CTT*1*54'; j :=j + 1;
    edi_863(j) :='SE*'||to_char(j-1)||'*'||to_char(li_st_log); j :=j + 1;
    edi_863(j) :='GE*1*'||to_char(li_gs_log); j :=j + 1;
    edi_863(j) :='IEA*1*'||LPAD(to_char(li_gs_log),9,'0'); 
  end if;  
  */
  
  
  --recreate the retest date line if needed
  if li_need_retest_date =1 then
   select nvl(max(retest_date),sysdate) into ld_retest_date
   from alcan_coil_retest_date where coil_org_num = ls_coil_org_num;
   edi_863(k) := 'DTM*036*'||to_char(ld_retest_date,'yyyymmdd');
  end if;
    
  SELECT edi_file_id_seq.NEXTVAL INTO li_edi_863_id FROM DUAL;
  
  edi_file := 'S_alcan_'||to_char(li_edi_863_id)||'.863';
  edi_file_handle :=utl_file.fopen(edi_location,edi_file,'W');
  
  --write edi to file
  FOR i IN 0..j LOOP
    utl_file.put_line(edi_file_handle,edi_863(i));
  END LOOP;
  
  utl_file.fclose(edi_file_handle);
  
  ls_edi_data_file_send := edi_863(0);
  for i in 1..j loop
   ls_edi_data_file_send := ls_edi_data_file_send ||'|'|| edi_863(i);
  end loop;
  ls_edi_data_file_send := ls_edi_data_file_send ||'|';
  
  --create a row in edi_file_863 table
  INSERT INTO edi_file_863(edi_863_id, file_id, coil_abc_num, edi_file, coil_org_num, created_date, send_status)
  VALUES(li_gs_log, li_file_id, li_coil_abc_num,ls_edi_data_file_send,ls_coil_org_num,SYSDATE,1);
  COMMIT;
  
  /*  --added by Victor Huang on 06/05 for funtion aknowlegement
  INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
  VALUES(li_gs_log, ls_duns, sysdate, edi_file);
  COMMIT;*/
  
  --added by Victor Huang on 12/07 for verifying 997
  INSERT INTO outbound_edi_transaction(edi_file_id,duns_from,duns_to,interchange_control_number,
  group_control_number,transaction_time,edi_file_name,fa_receive_status,customer_id,set_control_num,transaction_type_id)
  VALUES(li_edi_863_id,'039630926',ls_duns,li_gs_log,li_gs_log, sysdate, edi_file,0,li_customer_id,li_st_log,'863');
  COMMIT;
  
    edi_file := 'send_edi_log';
    edi_file_handle :=utl_file.fopen(edi_location,edi_file,'a');
    utl_file.put_line(edi_file_handle,'Type: 863');
    utl_file.put_line(edi_file_handle,'Sending Time: '||to_char(sysdate, 'MM/DD/YY HH24:MI'));
    utl_file.put_line(edi_file_handle,'Interchange Control #: '||li_gs_log);
    utl_file.put_line(edi_file_handle,'Group Control #: '||li_gs_log);
    utl_file.put_line(edi_file_handle,'Set Control #: '||li_st_log);
    utl_file.put_line(edi_file_handle,'');
    utl_file.put_line(edi_file_handle,'');
    utl_file.fclose(edi_file_handle);
  
  
  return 1;

EXCEPTION
     WHEN dup_val_on_index then
     rollback;
     return -100;     
     WHEN UTL_FILE.INVALID_PATH THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN -2; 
     WHEN UTL_FILE.INVALID_MODE THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN -2;
    WHEN UTL_FILE.INVALID_OPERATION THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN -2;   
    WHEN UTL_FILE.WRITE_ERROR THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN -2;      
    --WHEN OTHERS THEN
     --UTL_FILE.FCLOSE_ALL;
      --RETURN -1;

 
end f_create_edi_863_file_by_coil;
  GRANT EXECUTE ON "DBO"."F_CREATE_EDI_863_FILE_BY_COIL" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function F_CREATE_EDI_863_FILE_RESEND
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_CREATE_EDI_863_FILE_RESEND" (test_file_string varchar2,
test_type integer, n integer, r integer) return integer is
 /* Returns:   Integer
               1 = if it succeeds
              -100 = if a duplication on index occurs
              -2 = if errors with UTL_FILE
             
 */
  li_return integer;
 
 i integer;
 
 li_test_type integer; --Test type : 1.First Test
                       --            2.First Test Redo
                       --            3.First Full Test
                       --            4.Full Test
 li_n integer;
 li_r integer;
 
 --Variables for table Imported_file_863
 ls_test_file_string varchar2(32767);
 li_file_id integer;
 ls_sample_id varchar2(20);
 ld_created_date date;
 ls_notes varchar2(255);
 
 -- Variables for splitting to header line and data line 
 type data_line_type is table of varchar2(32767) index by binary_integer; 
 ls_data_line data_line_type;

 ls_header_line varchar2(32767);
 li_data_line_num integer; -- the number of data lines in each instron test file
 temp_pos1 integer;
 temp_pos2 integer;

 --Variables for table Processing_string_863
 ls_coil_org_num varchar2(32);
 li_test_line_num integer;
 li_send_status integer;
 ls_data_string varchar2(32767);
 ls_coil_pos varchar2(100);

 ls_operator varchar2(20);
 
 li_count integer;
 
 cursor distinct_coil_org_num_cursor(sampleid varchar2) is
  select distinct coil_org_num
  from processing_string_863
  where sample_id = sampleid and send_status =0;
  
begin
 li_test_type := test_type;
 li_n := n;
 li_r := r;
 
 -- Create a record in table Imported_file_863.
 select edi_863_imported_file_id_seq.nextval into li_file_id from dual; 
 ls_test_file_string := test_file_string; 
 ls_sample_id := to_char(sysdate,'yyyy')||f_get_substring_comma(ls_test_file_string, 1);
 ld_created_date :=sysdate;

 insert into imported_file_863 (file_id, file_string, sample_id, created_date, notes)
 values (li_file_id, ls_test_file_string, ls_sample_id, ld_created_date, null);

 --commit;
 
 ls_operator := f_get_substring_comma(test_file_string, 10);
 
--Split test file string into one header string and data strings;
 temp_pos1 := instr(ls_test_file_string, '|', 1, 1); --'|' is the seperator between every two lines in the importing instron test file.
 ls_header_line := substr(ls_test_file_string, 1, temp_pos1 - 1);

 li_data_line_num := to_number(f_get_substring_comma(ls_header_line, 4));
 
 for i in 1..li_data_line_num loop
  temp_pos1 := instr(ls_test_file_string, '|',1, i);--the position of ith '|'
  temp_pos2 := instr(ls_test_file_string, '|',1, i+1);-- the position of (i+1)th '|'
  ls_data_line(i) := substr(ls_test_file_string, temp_pos1 + 1, temp_pos2 - temp_pos1 - 1); 
 end loop;

 --Create records in table Processsing_string_863
 select count(*) into li_count from processing_string_863
 where sample_id = ls_sample_id;
 
 if li_count > 0 then
   delete from processing_string_863
   where sample_id = ls_sample_id;
   commit;
 end if;
 
 for i in 1..li_data_line_num loop
  li_test_line_num := to_number(f_get_substring_comma(ls_data_line(i),4));
  ls_coil_pos :=f_get_substring_comma(ls_data_line(i),40);
  ls_coil_org_num := f_get_coil_num(ls_coil_pos);
  
  insert into processing_string_863(sample_id, test_num, send_status, data_string, coil_org_num,test_type,created_date)
  values(ls_sample_id, li_test_line_num, 0, ls_data_line(i), ls_coil_org_num, li_test_type, sysdate);
 
  end loop; 
 
 --commit;
 
 --Create edi 863 file by coil number
 open distinct_coil_org_num_cursor(ls_sample_id);
 for i in 1..li_data_line_num loop
  fetch distinct_coil_org_num_cursor into ls_coil_org_num;
  exit when (distinct_coil_org_num_cursor%notfound or li_return <>1 );
   
 li_return := f_create_edi_863_file_by_coil(ls_sample_id, ls_coil_org_num, ls_operator, li_file_id, li_test_type, li_n, li_r);
 
 end loop;
 
 if li_return =1 then
  update processing_string_863
  set send_status = 1
  where sample_id = ls_sample_id;
 else
  delete processing_string_863
  where send_status =0 and sample_id = ls_sample_id;
 end if;
 
 commit;
 
 return li_return;
 
exception
 when dup_val_on_index then
 rollback;
 return -100;

 
end f_create_edi_863_file_resend;
  GRANT EXECUTE ON "DBO"."F_CREATE_EDI_863_FILE_RESEND" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function F_CREATE_TEMP_PROCESSING
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_CREATE_TEMP_PROCESSING" (coil_abc_num number) return integer is
/* Returns:   Integer number of test record found.
              0 = if no processing_string found 
                   
*/  
  ln_coil_abc_number number;
  ls_coil_org_num varchar2(32);
  ls_action_string varchar2(2000);
  
  ld_created_date date;
  li_test_type number;
  --ls_test_type varchar2(30);
  ls_pos char(2);
  ln_yts number;
  ln_uts number;
  ln_elongation number;
  ln_r number;
  ln_n number;
  ln_width number;
  ln_thickness number;
    
  i integer := 0; 
  
  cursor by_coil_cursor(coil varchar2) is
  select data_string, created_date, test_type from processing_string_863
  where coil_org_num = coil;
  
begin
  ln_coil_abc_number := coil_abc_num;
  
  select coil_org_num into ls_coil_org_num from coil
  where ( coil_abc_num = ln_coil_abc_number ) and 
        ( customer_id in (select customer_id from customer where customer_short_name like 'ALCAN%')) ;
  
  
  
  for data_by_coil in by_coil_cursor(ls_coil_org_num) loop
      
         i := i+1;    --number of record found
         ls_action_string := data_by_coil.data_string;
         ld_created_date := data_by_coil.created_date;
         li_test_type := data_by_coil.test_type;
         /*
         if data_by_coil.test_type = 1 then
             ls_test_type := 'First Test';
             elsif data_by_coil.test_type = 2 then
              ls_test_type := 'First Test Redo';     
             elsif data_by_coil.test_type = 3 then
              ls_test_type := 'First Full Test';
             elsif data_by_coil.test_type = 4 then
              ls_test_type := 'Full Test';
         end if;
         */
         
         
         ls_pos := substr( f_get_substring_comma(ls_action_string,40), 
                         length(f_get_substring_comma(ls_action_string,40))-1, 2 );
         ln_yts:=to_number(f_get_substring_comma(ls_action_string,47));
         ln_uts:=to_number(f_get_substring_comma(ls_action_string,51));
         ln_elongation:=to_number(f_get_substring_comma(ls_action_string,59)); 
         ln_width := to_number(f_get_substring_comma(ls_action_string, 71));
         ln_thickness := to_number(f_get_substring_comma(ls_action_string, 75));
         ln_n := to_number(f_get_substring_comma(ls_action_string, 63));
         ln_r := to_number(f_get_substring_comma(ls_action_string, 67)); 
            
         insert into temp_test_result (created_date, test_type,position,yts,uts,elongation,r,n,width,thickness,coil_org_num)
         values (ld_created_date, li_test_type, ls_pos, ln_yts, ln_uts, ln_elongation, ln_r, ln_n, ln_width, ln_thickness,ls_coil_org_num);
          
      
  end loop;
  
  if i=0 then
     return i;
  else 
     commit;
     return i;
  end if;
  
end f_create_temp_processing;
  GRANT EXECUTE ON "DBO"."F_CREATE_TEMP_PROCESSING" TO "AGERLANTS"
