--  DDL for Function F_CUSTOMER_863
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_CUSTOMER_863" (al_skid_sheet_num sheet_skid.sheet_skid_num%TYPE)
return integer is

result              integer;
ll_customer_id      coil.customer_id%TYPE;
ll_cust_863         coil.customer_id%TYPE;

cursor  cust_863_cur is
select  distinct coil.customer_id customer_id
from    dbo.data_in_863 data_in_863
        join coil on data_in_863.coil_num = coil.coil_org_num;

begin
   result := 0; --Initialize
  
   select distinct coil.customer_id
          into ll_customer_id
   from   production_sheet_item
          --join ab_job on ab_job.ab_job_num = production_sheet_item.ab_job_num
          join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
          join coil on coil.coil_abc_num = production_sheet_item.coil_abc_num
   where  sheet_skid_detail.sheet_skid_num = al_skid_sheet_num;
   
    for cust_863_rec in cust_863_cur
    loop
       ll_cust_863 := cust_863_rec.customer_id;
       
       if ll_cust_863 = ll_customer_id then
         result := 1;
         exit;
       end if;
    end loop;
  
   return(result);
end f_customer_863;
