  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_856" (packing_list_no shipment.packing_list%TYPE)
  RETURN INTEGER IS
  /*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = EDI had aleady been sent
               200 = No EDI defined

  Customer: ALCAN(34,35,10)
  Alcan Rolled Product    X.121       0015049350011G
  End User: Ford (ZZ F159B)
            Ford Chicago Stamping Plant(51) MS02A
            Ford Walton Hills Stamping Plant(77) MS03A
            Ford Woodhaven Stamping Plant(71) AF30A MS09A
            Ford Maumee Stamping Plant(78)    AF06A MS08A
            Republic same as Ford WoodHaven
            Ford Ogihara  (1579)           F7BFC

            (not in use)Ford Monroe Stamping              AP06A

            (not in use) Warehouses: IDS(41)               R5G3B
            (not in use) Wayne Steel Distribution Center(79) RWSDC


  Customer Alcan for GM send EDIFACT DESADV
      End user: Grand Rapid
                Pontiac plant 14
                Pontiac Plant 15
                GM Lansing Stamping 1840

  Customer Kaiser(45) send x12
      End User: Kaiser
                Capital Tech
                Hayes
                Hayes/Northville
                Lorbec (Scrap)
  Customer Alcoa Texacana(1188) End User Hayes(45) send X12 4010
  */

  --l_return number(5);
  exce_des_sh_cust_id EXCEPTION;
  exce_nodata         EXCEPTION;
  exce_sent           EXCEPTION;

  l_customer_id    INTEGER;
  l_des_sh_cust_id INTEGER;
  l_enduser_id     INTEGER;
  rr               INTEGER;
  scrap_item       INTEGER;
  l_ship_date      DATE;

  ll_bol           shipment.bill_of_lading%TYPE;
  
  rr_856                    integer;                            --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017
  rr_desadv                 integer;                            --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017 
  rr_ford                   integer;                            --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017
  ll_des_sh_cust_id         shipment.des_sh_cust_id%TYPE;       --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017
  ls_customer_short_name    customer.customer_short_name%TYPE;  --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017
  
  ll_count                  integer;                            --Alex Gerlants. novelis testing
  li_coil_status            coil.coil_status%TYPE;              --Alex Gerlants. 02/05/2019. Added for Novelis
  rr_rejcoil                integer;                            --Alex Gerlants. 02/05/2019. Added for Novelis
  li_is_constellium         integer;                            --Alex Gerlants. Constellium EDI 856  
  
  CURSOR packing_list_same_bol IS
    SELECT packing_list
      FROM shipment
     WHERE shipment.bill_of_lading = ll_bol
       AND shipment.shipment_status <> 3;
  ll_temp INTEGER;
BEGIN
  
  delete from dbo.error_message; --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017

  edi_alcan_870;

  SELECT shipment.bill_of_lading,
         customer_id,
         des_sh_cust_id,
         shipment_enduser_id,
         shipment_status
    INTO ll_bol, l_customer_id, l_des_sh_cust_id, l_enduser_id, ll_temp
    FROM shipment
   WHERE shipment.packing_list = packing_list_no;
  IF NOT SQL%FOUND THEN
    RETURN - 1;
  END IF;

  IF ll_temp <> 0 THEN
    RETURN packing_list_no;
  END IF;
  
  --Alex Gerlants. 01/12/2023. 1778_TWB project
  --Alex Gerlants. 02/15/2023. Added "2998 - TWB-ANTIOCH" as per Dan Polkinhorne's email received on Wed 2/15/2023 9:09 AM.
  if (l_customer_id in (2992, 2998)) then
    return edi_twb_856_X12_3(packing_list_no);
  end if;
  --Alex Gerlants. 06/13/2019. Arconic EDI. Added IF statement below for 2784-Arconic-TN
  
  --Alex Gerlants. 06/13/2019. Arconic EDI. Added IF statement below for 2784-Arconic-TN
  if (l_customer_id in (2784)) then
    return edi_arconic_856_X12(packing_list_no);
  end if;
  
  --Alex Gerlants. Constellium EDI 856. Begin
  select dbo.f_is_constellium(packing_list_no)
  into   li_is_constellium
  from   dual;
    
  if li_is_constellium = 1 then --Customer is Constellium
    return edi_const_856_X12(packing_list_no);
  end if;
  --Alex Gerlants. Constellium EDI 856. End  
  
  --Alex Gerlants. 10/22/2019. Begin
  --This is a temporary measure to help Arconic Davenport.
  --It is commented out in Production until they tell us to activate it.
  /*
  if (l_customer_id in (50)) then --Arconic Davenport
     if l_des_sh_cust_id in (69, 70, 2850, 72, 1840, 2079, 2164, 2181, 2360, 1648, 2495, 2611, 2680, 2814) then
           
       return f_edi_desadv2_arconic_davenprt(packing_list_no); --Send GM EDIFACT
     end if;
  end if; --if (l_customer_id in (50) then
  */
  --Alex Gerlants. 10/22/2019. End

  --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. Replaced "RETURN" with "rr_desadv :="
  --Alex Gerlants. 12/04/2017. Added "2776" to the line below. Shipping to GM
  IF (l_customer_id in (1429, 2795, 2830, 2776)) THEN
    --SAMUEL-HAMILTON, SAMUEL-TENN, SAMUEL-COLUMBIA
    rr_desadv := f_edi_desadv_bolt(packing_list_no);
    
    --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. Begin
    --rr_desadv := 200; --TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY
    
    if rr_desadv = 1 or rr_desadv = 100 then --"EDI generated successfully" or "EDI previously sent."
      return rr_desadv;
    else
      if rr_desadv = -1 then
         insert into dbo.error_message values('f_edi_desadv_bolt. Packing list ' || to_char(packing_list_no) || ' does not exist');
         commit;
         return -14;
      elsif rr_desadv = -3 then
         select  shipment.des_sh_cust_id, customer.customer_short_name
         into    ll_des_sh_cust_id, ls_customer_short_name
         from    shipment
         join    customer on customer.customer_id = shipment.des_sh_cust_id
         where   shipment.packing_list = packing_list_no;
            
         insert into dbo.error_message values('f_edi_desadv_bolt. Communication code is NOT set up in table customer_system for Destination Customer ' || to_char(l_des_sh_cust_id) || '-' || ls_customer_short_name);
         commit;
         return -13;
       elsif rr_desadv = 200 then
         insert into dbo.error_message values('f_edi_desadv_bolt. Customer DUNS not set up in table customer.');
         commit;
         return -12;
       else
          return rr_desadv;
       end if;
     end if;
     --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. End
     
  END IF;
  
  --Alex Gerlants. 03/03/2021. Added '2950'  to the list below <== NOVELIS-GUTHRIE
  IF NOT (l_customer_id IN (10, 34, 35, 188, 1153, 1188, 1364, 1459, 1980, 2505, 2582, 2950)) THEN
    --1459 Alcan Oswego, 1364 Wise Alloys
    RETURN 200;
  END IF;

  SELECT shipment_edi856_date
    INTO l_ship_date
    FROM shipment
   WHERE shipment.packing_list = packing_list_no;
  IF NOT (l_ship_date IS NULL) THEN
    RETURN 100;
  END IF;

  --Check all packing_lists are done or cancel against a BOL
  FOR pl_rec IN packing_list_same_bol LOOP
    SELECT shipment.shipment_status
      INTO ll_temp
      FROM shipment
     WHERE shipment.packing_list = pl_rec.packing_list;
    IF ll_temp <> 0 THEN
      RETURN pl_rec.packing_list;
    END IF;
  END LOOP;
  --End of packing list checking
  
  --------------------------------------------------------------------------
  
  --Alex Gerlants. 02/05/2019. Added for Novelis
  select count(*)
  into   ll_count
  from   reject_coil_packing_item
         join coil on coil.coil_abc_num = reject_coil_packing_item.coil_abc_num
         join shipment on shipment.packing_list = reject_coil_packing_item.packing_list
         join customer on customer.customer_id = shipment.customer_id
  where  shipment.packing_list = packing_list_no;
  
  if ll_count > 0 then
    select distinct customer.customer_short_name, coil.coil_status
    into   ls_customer_short_name, li_coil_status
    from   reject_coil_packing_item
           join coil on coil.coil_abc_num = reject_coil_packing_item.coil_abc_num
           join shipment on shipment.packing_list = reject_coil_packing_item.packing_list
           join customer on customer.customer_id = shipment.customer_id
    where  shipment.packing_list = packing_list_no;
  
    if lower(ls_customer_short_name) like '%novelis%' then
      if li_coil_status in (3, 6, 14) then --Rejected coil (3), Return coil (6), Scrap coil (14)
           rr_rejcoil := edi_novelis_rejcoil_856_x12(packing_list_no);
           return rr_rejcoil;
      else --coi_status is other than Rejected coil (3), Return coil (6), Scrap coil (14)
        return 100; --"EDI previously sent.".
                    --Should not happen though
                    --because this validation "IF NOT (l_ship_date IS NULL) THEN"
                    --is done above.
      end if;
    else--Not Novelis. We send ASN for these coils to Novelis only.
      return 1; --Nothing to do here
    end if;
  end if;
  
  --------------------------------------------------------------------------

  scrap_item := 0;

  --add by Victor Huang for "Wise Alloys"
  IF (l_customer_id = 1364) THEN
    --1364 Wise Alloys
    RETURN edi_wise_856(packing_list_no);
  END IF;


   --add by James Ni for "Aleris"
  IF (l_customer_id = 1980) THEN
     RETURN edi_aleris_856_x12_multi_po(packing_list_no);
  END IF;

  --Alex Gerlants. 06/10/2025. Removed ', 2950' to create 856 for BOL 132889
  --Alex Gerlants. 06/10/2025. Added '3047 - SIGNAL MACHINE COMPANY, INC'. Email from Dan received on Tue 6/10/2025 7:20 AM.
  --Alex Gerlants. 03/20/2025. Added '3044- This is GENERAL MOTORS CORP/METAL FAB DIV'
  --Alex Gerlants. 02/11/2025. Added '3040- This is DIVERSIFIED TECH INTL'
  --Alex Gerlants. 00/15/2024. Added '3036' to the list below. This is 3036 - NUMIT LLC'.
  --Alex Gerlants. 09/27/2024. Added '3034' to the list below. This is 3034 - ROYAL EG NORTH AMERICA INC. Email from Dan received on Fri 9/27/2024 @10:42 AM.
  --Alex Gerlants. 09/20/2017. Added '2850' to the list below
  --Alex Gerlants. 05/13/2019. Added '2903' to the list below
  --Alex Gerlants. 05/14/2019. Added '2906' to the list below
  --Alex Gerlants. 03/03/2021. Added '2950'  to the list below <== NOVELIS-GUTHRIE. In case if we ship to there.
  --Alex Gerlants. 05/10/2021. Added '2955'  to the list below
  --Alex Gerlants. 09/13/2021. Added 1532 - NOVELIS-NOVI, 1749 - NOVELIS-NOVI A.F.
  --Alex Gerlants. 06/28/2023. Added 3010 - A PHASE II to the list below
  IF ((l_des_sh_cust_id IN -- if the destination we are shipping to is in this list...
     (69, 70, 2850, 72, 1840, 2079, 2164, 2181, 2360, 2495, 2611, 2680, 2814, 2903, 2906, 2955, 1532, 1749, 3010, 3034, 3036, 3040, 3044, 3047)) OR (l_customer_id = 2505)) THEN
    --GM
    
    rr_856 := 1; --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017
    rr_desadv := 1; --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017
    
    IF (l_customer_id != 2505) THEN
      --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. Replaced "rr" with "rr_856" 
        --rr_856 := edi_alcan_alcan_856_x12(packing_list_no); --Alex Gerlants. 02/05/2019. Commented out
        rr_856 := edi_novelis_856_X12(packing_list_no); --Alex Gerlants. 02/05/2019. Added for Novelis
    END IF;
    
    --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. Replaced "RETURN" with "rr_desadv :="
    --Alex Gerlants. 04/09/2019. Do not run f_edi_desadv2 for Novelis.   
    select distinct customer.customer_short_name
    into   ls_customer_short_name
    from   shipment
           join customer on customer.customer_id = shipment.customer_id
    where  shipment.packing_list = packing_list_no;

    if lower(ls_customer_short_name) not like '%novelis%' then
       rr_desadv := f_edi_desadv2(packing_list_no); --Send GM EDIFACT
    end if;
    --                                                              Republic(1104 shipment as as woodhaven, and Gerstenslager 1401
    --                                                              Karmax(1149),WindsorMatchPlate(1388)
    --elsif l_des_sh_cust_id in (51,77,71,78,41,79, 1347, 1382, 1383, 1104, 1401, 1388, 1149, 1579) then  --Ford
    --Delete 1382 per Alcan 03/29/04  by Tony
    
    --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. Begin
    
    --rr_856 := 100; --TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY
    --rr_desadv := 500; --TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY
    
    
    if rr_856 = 1 and rr_desadv = 1 then
       return 1;
    elsif rr_desadv = 100 then --"EDI previously sent.".
                               --Should not happen though
                               --because this validation "IF NOT (l_ship_date IS NULL) THEN"
                               --is done above.
       return 100;
    elsif rr_desadv = 200 then --Not the right customer.
                               --Should not happent though because this check is done
                               --in this function above, just before edi_alcan_alcan_856_x12() is called
       return 200;
    else
       if rr_856 = -1 then
          insert into dbo.error_message values('edi_alcan_alcan_856_x12. Packing List ' || to_char(packing_list_no) || ' does not exist.');
       end If;
       
       if rr_desadv = -1 then
          insert into dbo.error_message values('f_edi_desadv2. Packing List ' || to_char(packing_list_no) || ' does not exist.');
       end If;
       
       if rr_desadv = 500 then
          insert into dbo.error_message values('f_edi_desadv2. Customer DUNS not set up in table customer. Please set it up.');
       end if;
       
       if rr_856 = 100 then
           insert into dbo.error_message values('edi_alcan_alcan_856_x12. This shipment ' || to_char(packing_list_no) || ' has zero piece count.');
        end if;
        
       if rr_desadv = -3 then
          select  shipment.des_sh_cust_id, customer.customer_short_name
          into    ll_des_sh_cust_id, ls_customer_short_name
          from    shipment
          join    customer on customer.customer_id = shipment.des_sh_cust_id
          where   shipment.packing_list = packing_list_no;
          
          insert into dbo.error_message values('f_edi_desadv2. Communication code is NOT set up in table customer_system for Destination Customer ' || to_char(l_des_sh_cust_id) || '-' || ls_customer_short_name);
       end if;
       
       commit; --This commit is for table dbo.error_message that is populated above
    
       if rr_856 <> 1 and rr_desadv <> 1 then
          if rr_desadv <> 500 then
             return -8; --Both, customer 856 and OEM files not created
          else
             return -15; --Only customer file not created. OEM file is created, but customer.customer_duns_number_string not set up for customer
          end if;
       else --one of them is not 1
          if rr_856 <> 1 then
             return -7;
          else --rr_desadv <> 1
             if rr_desadv = 500 then
                return -16; --OEM file is created, but customer.customer_duns_number_string not set up for customer
             else
                return -6; --OEM file not created
             end if;
          end if;
       end if;
    end if;
    --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. End
    
  ELSIF l_des_sh_cust_id IN
        (51, 77, 71, 78, 41, 79, 1347, 1383, 1104, 1401, 1388, 1149, 1579) THEN
    --Ford
    
    rr_ford := 1; --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017
    rr_856 := 1; --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017
    
    --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. Replaced "rr" with "rr_856"
    rr_856 := edi_alcan_ford_856_x12(packing_list_no); --Send Ford
    
    --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. Replaced "RETURN" with "rr_desadv :="
    --rr_desadv := edi_alcan_alcan_856_x12(packing_list_no); --Alex Gerlants. 02/05/2019. Commented out
    rr_856 := edi_novelis_856_X12(packing_list_no); --Alex Gerlants. 02/05/2019. Added for Novelis

    --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. Begin
    if rr_ford = 1 and rr_856 = 1 then
       return 1;
    else --rr_ford <> 1 or rr_856 <> 1
       if rr_ford = -1 then
          insert into dbo.error_message values('edi_alcan_ford_856_x12. Packing List ' || to_char(packing_list_no) || ' does not exist.');
       end If;
       
       if rr_856 = -1 then
          insert into dbo.error_message values('edi_alcan_alcan_856_x12. Packing List ' || to_char(packing_list_no) || ' does not exist.');
       end If;
       
       if rr_ford = 200 then
          insert into dbo.error_message values('edi_alcan_ford_856_x12. Customer does NOT require EDI transaction. Customer or destination customer DUNS not set up in table customer.');
       end if;
       
       if rr_856 = 200 then
          insert into dbo.error_message values('edi_alcan_alcan_856_x12. Customer does NOT require EDI transaction. Customer or destination customer DUNS not set up in table customer.');
       end if;
       
       if rr_856 = 100 then
           insert into dbo.error_message values('edi_alcan_alcan_856_x12. This shipment ' || to_char(packing_list_no) || ' has zero piece count.');
       end if;
       
       if rr_ford = 100 then
           insert into dbo.error_message values('edi_alcan_ford_856_x12. This shipment ' || to_char(packing_list_no) || ' has zero piece count.');
       end if;
       
       commit; --This commit is for table dbo.error_message that is populated above
    
       if rr_ford <> 1 and rr_856 <> 1 then
          return -11;
       else --one of them is not 1
          if rr_ford <> 1 then
             return -10;
          else
             return -9;
          end if;
       end if;
    end if;
    --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. End

  ELSIF l_customer_id = 188 THEN
    --Kaiser
    RETURN edi_kaiser_856(packing_list_no);

  ELSIF l_des_sh_cust_id = 1096 THEN
    --BUDD Company or Eagle Steel
    --        return edi_alcan_ford_856_x12(packing_list_no);
    --rr:=edi_alcan_budd_856(packing_list_no);           --Send Budd per budd and eagle, they no longer receive ASN from ABC
    --rr:= edi_alcan_ford_856_x12(packing_list_no);  --Send Eagle using Ford code
    --RETURN edi_alcan_alcan_856_x12(packing_list_no); --Alex Gerlants. 02/05/2019. Commented out
    return edi_novelis_856_X12(packing_list_no); --Alex Gerlants. 02/05/2019. Added for Noveli

  ELSIF l_des_sh_cust_id = 1251 THEN
    --Eagle steel, send to Budd and Eagle(ford format)
    --rr:=edi_alcan_budd_856(packing_list_no);  -- per budd and eagle, they no longer receive ASN from ABC
    --rr:= edi_alcan_ford_856_x12(packing_list_no);  --Send Eagle using Ford code
    --return rr;
    --RETURN edi_alcan_alcan_856_x12(packing_list_no); --Alex Gerlants. 02/05/2019. Commented out
    return edi_novelis_856_X12(packing_list_no); --Alex Gerlants. 02/05/2019. Added for Novelis

    --elsif l_des_sh_cust_id = 79 then                  --WSDC send Alcan only
    --      return edi_alcan_alcan_856_x12(packing_list_no);

  --Alex Gerlants. 09/27/2021. Added 2950 - Novelis-Guthrey
  ELSIF l_customer_id IN (35, 10, 1153, 1459, 2582, 2950) THEN
    SELECT MAX(sc_packing_item)
      INTO scrap_item
      FROM scrap_packing_item
     WHERE packing_list = packing_list_no;
    IF scrap_item > 0 THEN
      --RETURN edi_alcan_alcan_scrap_856_x12(packing_list_no); --Alex Gerlants. 02/05/2019. Commented out
      return edi_novelis_scrap_856_x12(packing_list_no); --Alex Gerlants. 02/05/2019. Added for Novelis
    ELSE -- All else destination send Alcan only
      --RETURN edi_alcan_alcan_856_x12(packing_list_no);  --Alex Gerlants. 02/05/2019. Commented out
      return edi_novelis_856_X12(packing_list_no); --Alex Gerlants. 02/05/2019. Added for Novelis 
    END IF;

  ELSIF l_des_sh_cust_id = 45 THEN
    RETURN edi_alcoa_hayes_856_x12(packing_list_no);
  ELSE
    RETURN 200;
  END IF;

EXCEPTION
  WHEN exce_sent THEN
    --    raise_application_error(-20101,'STOP! EDI had been sent');
    RETURN 100;
  WHEN exce_nodata THEN
    --     raise_application_error(-20101,'No shipment data found!');
    RETURN - 1;
  WHEN exce_des_sh_cust_id THEN
    --    raise_application_error(-20101,'This shipment does not required EDIFACT DESADV EDI!');
    RETURN 200;
  WHEN OTHERS THEN
    --    raise_application_error(-20101,'INTERNAL ERROR! PLEASE CALL 1519.');
    RETURN - 1;

  --   return l_return;
END;
  GRANT EXECUTE ON "DBO"."F_EDI_856" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function F_EDI_856_08072025
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_856_08072025" (packing_list_no shipment.packing_list%TYPE)
  RETURN INTEGER IS
  /*
  Returns:   Integer
                 1 = if it succeeds
                -1 = if a system error occurs
               100 = EDI had aleady been sent
               200 = No EDI defined

  Customer: ALCAN(34,35,10)
  Alcan Rolled Product    X.121       0015049350011G
  End User: Ford (ZZ F159B)
            Ford Chicago Stamping Plant(51) MS02A
            Ford Walton Hills Stamping Plant(77) MS03A
            Ford Woodhaven Stamping Plant(71) AF30A MS09A
            Ford Maumee Stamping Plant(78)    AF06A MS08A
            Republic same as Ford WoodHaven
            Ford Ogihara  (1579)           F7BFC

            (not in use)Ford Monroe Stamping              AP06A

            (not in use) Warehouses: IDS(41)               R5G3B
            (not in use) Wayne Steel Distribution Center(79) RWSDC


  Customer Alcan for GM send EDIFACT DESADV
      End user: Grand Rapid
                Pontiac plant 14
                Pontiac Plant 15
                GM Lansing Stamping 1840

  Customer Kaiser(45) send x12
      End User: Kaiser
                Capital Tech
                Hayes
                Hayes/Northville
                Lorbec (Scrap)
  Customer Alcoa Texacana(1188) End User Hayes(45) send X12 4010
  */

  --l_return number(5);
  exce_des_sh_cust_id EXCEPTION;
  exce_nodata         EXCEPTION;
  exce_sent           EXCEPTION;

  l_customer_id    INTEGER;
  l_des_sh_cust_id INTEGER;
  l_enduser_id     INTEGER;
  --rr               INTEGER;
  scrap_item       INTEGER;
  l_ship_date      DATE;

  ll_bol           shipment.bill_of_lading%TYPE;
  
  rr_856                    integer;                            --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017
  rr_desadv                 integer;                            --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017 
  rr_ford                   integer;                            --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017
  ll_des_sh_cust_id         shipment.des_sh_cust_id%TYPE;       --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017
  ls_customer_short_name    customer.customer_short_name%TYPE;  --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017
  
  ll_count                  integer;                            --Alex Gerlants. novelis testing
  li_coil_status            coil.coil_status%TYPE;              --Alex Gerlants. 02/05/2019. Added for Novelis
  rr_rejcoil                integer;                            --Alex Gerlants. 02/05/2019. Added for Novelis
  li_is_constellium         integer;                            --Alex Gerlants. Constellium EDI 856  
  ls_rtn                    char(5);
  
  CURSOR li_count_sheet IS
    SELECT packing_list
      FROM shipment
     WHERE shipment.bill_of_lading = ll_bol
       AND shipment.shipment_status <> 3;
  ll_temp INTEGER;
BEGIN
  
  delete from dbo.error_message; --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017

  edi_alcan_870;

  SELECT shipment.bill_of_lading,
         customer_id,
         des_sh_cust_id,
         shipment_enduser_id,
         shipment_status
    INTO ll_bol, l_customer_id, l_des_sh_cust_id, l_enduser_id, ll_temp
    FROM shipment
   WHERE shipment.packing_list = packing_list_no;
  IF NOT SQL%FOUND THEN
    RETURN - 1;
  END IF;

  IF ll_temp <> 0 THEN
    RETURN packing_list_no;
  END IF;
  
  --Alex Gerlants. 01/12/2023. 1778_TWB project
  --Alex Gerlants. 02/15/2023. Added "2998 - TWB-ANTIOCH" as per Dan Polkinhorne's email received on Wed 2/15/2023 9:09 AM.
  if (l_customer_id in (2992, 2998)) then
    return edi_twb_856_X12_3(packing_list_no);
  end if;
  --Alex Gerlants. 06/13/2019. Arconic EDI. Added IF statement below for 2784-Arconic-TN
  
  --Alex Gerlants. 06/13/2019. Arconic EDI. Added IF statement below for 2784-Arconic-TN
  if (l_customer_id in (2784)) then
    return edi_arconic_856_X12(packing_list_no);
  end if;
  
  --Alex Gerlants. Constellium EDI 856. Begin
  select dbo.f_is_constellium(packing_list_no)
  into   li_is_constellium
  from   dual;
    
  if li_is_constellium = 1 then --Customer is Constellium
    return edi_const_856_X12(packing_list_no);
  end if;
  --Alex Gerlants. Constellium EDI 856. End  
  
  --Alex Gerlants. 10/22/2019. Begin
  --This is a temporary measure to help Arconic Davenport.
  --It is commented out in Production until they tell us to activate it.
  /*
  if (l_customer_id in (50)) then --Arconic Davenport
     if l_des_sh_cust_id in (69, 70, 2850, 72, 1840, 2079, 2164, 2181, 2360, 1648, 2495, 2611, 2680, 2814) then
           
       return f_edi_desadv2_arconic_davenprt(packing_list_no); --Send GM EDIFACT
     end if;
  end if; --if (l_customer_id in (50) then
  */
  --Alex Gerlants. 10/22/2019. End

  --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. Replaced "RETURN" with "rr_desadv :="
  --Alex Gerlants. 12/04/2017. Added "2776" to the line below. Shipping to GM
  IF (l_customer_id in (1429, 2795, 2830, 2776)) THEN
    --SAMUEL-HAMILTON, SAMUEL-TENN, SAMUEL-COLUMBIA
    rr_desadv := f_edi_desadv_bolt(packing_list_no);
    
    --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. Begin
    --rr_desadv := 200; --TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY
    
    if rr_desadv = 1 or rr_desadv = 100 then --"EDI generated successfully" or "EDI previously sent."
      return rr_desadv;
    else
      if rr_desadv = -1 then
         insert into dbo.error_message values('f_edi_desadv_bolt. Packing list ' || to_char(packing_list_no) || ' does not exist');
         commit;
         return -14;
      elsif rr_desadv = -3 then
         select  shipment.des_sh_cust_id, customer.customer_short_name
         into    ll_des_sh_cust_id, ls_customer_short_name
         from    shipment
         join    customer on customer.customer_id = shipment.des_sh_cust_id
         where   shipment.packing_list = packing_list_no;
            
         insert into dbo.error_message values('f_edi_desadv_bolt. Communication code is NOT set up in table customer_system for Destination Customer ' || to_char(l_des_sh_cust_id) || '-' || ls_customer_short_name);
         commit;
         return -13;
       elsif rr_desadv = 200 then
         insert into dbo.error_message values('f_edi_desadv_bolt. Customer DUNS not set up in table customer.');
         commit;
         return -12;
       else
          return rr_desadv;
       end if;
     end if;
     --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. End
     
  END IF;
  
  --Alex Gerlants. 03/03/2021. Added '2950'  to the list below <== NOVELIS-GUTHRIE
  IF NOT (l_customer_id IN (10, 34, 35, 188, 1153, 1188, 1364, 1459, 1980, 2505, 2582, 2950)) THEN
    --1459 Alcan Oswego, 1364 Wise Alloys
    RETURN 200;
  END IF;

  SELECT shipment_edi856_date
    INTO l_ship_date
    FROM shipment
   WHERE shipment.packing_list = packing_list_no;
  IF NOT (l_ship_date IS NULL) THEN
    RETURN 100;
  END IF;

  --Check all packing_lists are done or cancel against a BOL
  FOR pl_rec IN li_count_sheet LOOP
    SELECT shipment.shipment_status
      INTO ll_temp
      FROM shipment
     WHERE shipment.packing_list = pl_rec.packing_list;
    IF ll_temp <> 0 THEN
      RETURN pl_rec.packing_list;
    END IF;
  END LOOP;
  --End of packing list checking
  
  --------------------------------------------------------------------------
  
  --Alex Gerlants. 02/05/2019. Added for Novelis
  select count(*)
  into   ll_count
  from   reject_coil_packing_item
         join coil on coil.coil_abc_num = reject_coil_packing_item.coil_abc_num
         join shipment on shipment.packing_list = reject_coil_packing_item.packing_list
         join customer on customer.customer_id = shipment.customer_id
  where  shipment.packing_list = packing_list_no;
  
  if ll_count > 0 then
    select distinct customer.customer_short_name, coil.coil_status
    into   ls_customer_short_name, li_coil_status
    from   reject_coil_packing_item
           join coil on coil.coil_abc_num = reject_coil_packing_item.coil_abc_num
           join shipment on shipment.packing_list = reject_coil_packing_item.packing_list
           join customer on customer.customer_id = shipment.customer_id
    where  shipment.packing_list = packing_list_no;
  
    if lower(ls_customer_short_name) like '%novelis%' then
      if li_coil_status in (3, 6, 14) then --Rejected coil (3), Return coil (6), Scrap coil (14)
           rr_rejcoil := edi_novelis_rejcoil_856_x12(packing_list_no);
           return rr_rejcoil;
      else --coi_status is other than Rejected coil (3), Return coil (6), Scrap coil (14)
        return 100; --"EDI previously sent.".
                    --Should not happen though
                    --because this validation "IF NOT (l_ship_date IS NULL) THEN"
                    --is done above.
      end if;
    else--Not Novelis. We send ASN for these coils to Novelis only.
      return 1; --Nothing to do here
    end if;
  end if;
  
  --------------------------------------------------------------------------

  scrap_item := 0;

  --add by Victor Huang for "Wise Alloys"
  IF (l_customer_id = 1364) THEN
    --1364 Wise Alloys
    RETURN edi_wise_856(packing_list_no);
  END IF;


   --add by James Ni for "Aleris"
  IF (l_customer_id = 1980) THEN
     RETURN edi_aleris_856_x12_multi_po(packing_list_no);
  END IF;

  --Alex Gerlants. 06/10/2025. Removed ', 2950' to create 856 for BOL 132889
  --Alex Gerlants. 06/10/2025. Added '3047 - SIGNAL MACHINE COMPANY, INC'. Email from Dan received on Tue 6/10/2025 7:20 AM.
  --Alex Gerlants. 03/20/2025. Added '3044- This is GENERAL MOTORS CORP/METAL FAB DIV'
  --Alex Gerlants. 02/11/2025. Added '3040- This is DIVERSIFIED TECH INTL'
  --Alex Gerlants. 00/15/2024. Added '3036' to the list below. This is 3036 - NUMIT LLC'.
  --Alex Gerlants. 09/27/2024. Added '3034' to the list below. This is 3034 - ROYAL EG NORTH AMERICA INC. Email from Dan received on Fri 9/27/2024 @10:42 AM.
  --Alex Gerlants. 09/20/2017. Added '2850' to the list below
  --Alex Gerlants. 05/13/2019. Added '2903' to the list below
  --Alex Gerlants. 05/14/2019. Added '2906' to the list below
  --Alex Gerlants. 03/03/2021. Added '2950'  to the list below <== NOVELIS-GUTHRIE. In case if we ship to there.
  --Alex Gerlants. 05/10/2021. Added '2955'  to the list below
  --Alex Gerlants. 09/13/2021. Added 1532 - NOVELIS-NOVI, 1749 - NOVELIS-NOVI A.F.
  --Alex Gerlants. 06/28/2023. Added 3010 - A PHASE II to the list below
  IF ((l_des_sh_cust_id IN -- if the destination we are shipping to is in this list...
     (69, 70, 2850, 72, 1840, 2079, 2164, 2181, 2360, 2495, 2611, 2680, 2814, 2903, 2906, 2955, 1532, 1749, 3010, 3034, 3036, 3040, 3044, 3047, 2950)) OR (l_customer_id = 2505)) THEN
    --GM
    
    rr_856 := 1; --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017
    rr_desadv := 1; --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017
    
    IF (l_customer_id != 2505) THEN
      --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. Replaced "rr" with "rr_856" 
        --rr_856 := edi_alcan_alcan_856_x12(packing_list_no); --Alex Gerlants. 02/05/2019. Commented out
        --rr_856 := edi_novelis_856_X12(packing_list_no); --Alex Gerlants. 08/06/2025. 2404_Novelis_856_EDI_Sheets_and_Scrap. Comment out. 
        
        --Alex Gerlants. 08/06/2025. 2404_Novelis_856_EDI_Sheets_and_Scrap. Begin
        ls_rtn := f_sheet_or_scrap_shipment(packing_list_no);
        
        if ls_rtn = 'SHEET' then
          rr_856 := edi_novelis_856_X12(packing_list_no);
        elsif ls_rtn = 'SCRAP' then
          if l_customer_id IN (35, 10, 1153, 1459, 2582, 2950) then
            rr_856 := edi_novelis_scrap_856_x12(packing_list_no);
          end if;
        --else --'BOTH'
          --return edi_novelis_856_sheets_scrap(packing_list_no)
        end if;
        --Alex Gerlants. 08/06/2025. 2404_Novelis_856_EDI_Sheets_and_Scrap. End
        
    END IF;
    
    --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. Replaced "RETURN" with "rr_desadv :="
    --Alex Gerlants. 04/09/2019. Do not run f_edi_desadv2 for Novelis.   
    select distinct customer.customer_short_name
    into   ls_customer_short_name
    from   shipment
           join customer on customer.customer_id = shipment.customer_id
    where  shipment.packing_list = packing_list_no;

    if lower(ls_customer_short_name) not like '%novelis%' then
       rr_desadv := f_edi_desadv2(packing_list_no); --Send GM EDIFACT
    end if;
    --                                                              Republic(1104 shipment as as woodhaven, and Gerstenslager 1401
    --                                                              Karmax(1149),WindsorMatchPlate(1388)
    --elsif l_des_sh_cust_id in (51,77,71,78,41,79, 1347, 1382, 1383, 1104, 1401, 1388, 1149, 1579) then  --Ford
    --Delete 1382 per Alcan 03/29/04  by Tony
    
    --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. Begin
    
    --rr_856 := 100; --TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY
    --rr_desadv := 500; --TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY
    
    
    if rr_856 = 1 and rr_desadv = 1 then
       return 1;
    elsif rr_desadv = 100 then --"EDI previously sent.".
                               --Should not happen though
                               --because this validation "IF NOT (l_ship_date IS NULL) THEN"
                               --is done above.
       return 100;
    elsif rr_desadv = 200 then --Not the right customer.
                               --Should not happent though because this check is done
                               --in this function above, just before edi_alcan_alcan_856_x12() is called
       return 200;
    else
       if rr_856 = -1 then
          insert into dbo.error_message values('edi_alcan_alcan_856_x12. Packing List ' || to_char(packing_list_no) || ' does not exist.');
       end If;
       
       if rr_desadv = -1 then
          insert into dbo.error_message values('f_edi_desadv2. Packing List ' || to_char(packing_list_no) || ' does not exist.');
       end If;
       
       if rr_desadv = 500 then
          insert into dbo.error_message values('f_edi_desadv2. Customer DUNS not set up in table customer. Please set it up.');
       end if;
       
       if rr_856 = 100 then
           insert into dbo.error_message values('edi_alcan_alcan_856_x12. This shipment ' || to_char(packing_list_no) || ' has zero piece count.');
        end if;
        
       if rr_desadv = -3 then
          select  shipment.des_sh_cust_id, customer.customer_short_name
          into    ll_des_sh_cust_id, ls_customer_short_name
          from    shipment
          join    customer on customer.customer_id = shipment.des_sh_cust_id
          where   shipment.packing_list = packing_list_no;
          
          insert into dbo.error_message values('f_edi_desadv2. Communication code is NOT set up in table customer_system for Destination Customer ' || to_char(l_des_sh_cust_id) || '-' || ls_customer_short_name);
       end if;
       
       commit; --This commit is for table dbo.error_message that is populated above
    
       if rr_856 <> 1 and rr_desadv <> 1 then
          if rr_desadv <> 500 then
             return -8; --Both, customer 856 and OEM files not created
          else
             return -15; --Only customer file not created. OEM file is created, but customer.customer_duns_number_string not set up for customer
          end if;
       else --one of them is not 1
          if rr_856 <> 1 then
             return -7;
          else --rr_desadv <> 1
             if rr_desadv = 500 then
                return -16; --OEM file is created, but customer.customer_duns_number_string not set up for customer
             else
                return -6; --OEM file not created
             end if;
          end if;
       end if;
    end if;
    --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. End
    
  ELSIF l_des_sh_cust_id IN
        (51, 77, 71, 78, 41, 79, 1347, 1383, 1104, 1401, 1388, 1149, 1579) THEN
    --Ford
    
    rr_ford := 1; --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017
    rr_856 := 1; --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017
    
    --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. Replaced "rr" with "rr_856"
    rr_856 := edi_alcan_ford_856_x12(packing_list_no); --Send Ford
    
    --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. Replaced "RETURN" with "rr_desadv :="
    --rr_desadv := edi_alcan_alcan_856_x12(packing_list_no); --Alex Gerlants. 02/05/2019. Commented out
    rr_856 := edi_novelis_856_X12(packing_list_no); --Alex Gerlants. 02/05/2019. Added for Novelis

    --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. Begin
    if rr_ford = 1 and rr_856 = 1 then
       return 1;
    else --rr_ford <> 1 or rr_856 <> 1
       if rr_ford = -1 then
          insert into dbo.error_message values('edi_alcan_ford_856_x12. Packing List ' || to_char(packing_list_no) || ' does not exist.');
       end If;
       
       if rr_856 = -1 then
          insert into dbo.error_message values('edi_alcan_alcan_856_x12. Packing List ' || to_char(packing_list_no) || ' does not exist.');
       end If;
       
       if rr_ford = 200 then
          insert into dbo.error_message values('edi_alcan_ford_856_x12. Customer does NOT require EDI transaction. Customer or destination customer DUNS not set up in table customer.');
       end if;
       
       if rr_856 = 200 then
          insert into dbo.error_message values('edi_alcan_alcan_856_x12. Customer does NOT require EDI transaction. Customer or destination customer DUNS not set up in table customer.');
       end if;
       
       if rr_856 = 100 then
           insert into dbo.error_message values('edi_alcan_alcan_856_x12. This shipment ' || to_char(packing_list_no) || ' has zero piece count.');
       end if;
       
       if rr_ford = 100 then
           insert into dbo.error_message values('edi_alcan_ford_856_x12. This shipment ' || to_char(packing_list_no) || ' has zero piece count.');
       end if;
       
       commit; --This commit is for table dbo.error_message that is populated above
    
       if rr_ford <> 1 and rr_856 <> 1 then
          return -11;
       else --one of them is not 1
          if rr_ford <> 1 then
             return -10;
          else
             return -9;
          end if;
       end if;
    end if;
    --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. End

  ELSIF l_customer_id = 188 THEN
    --Kaiser
    RETURN edi_kaiser_856(packing_list_no);

  ELSIF l_des_sh_cust_id = 1096 THEN
    --BUDD Company or Eagle Steel
    --        return edi_alcan_ford_856_x12(packing_list_no);
    --rr:=edi_alcan_budd_856(packing_list_no);           --Send Budd per budd and eagle, they no longer receive ASN from ABC
    --rr:= edi_alcan_ford_856_x12(packing_list_no);  --Send Eagle using Ford code
    --RETURN edi_alcan_alcan_856_x12(packing_list_no); --Alex Gerlants. 02/05/2019. Commented out
    return edi_novelis_856_X12(packing_list_no); --Alex Gerlants. 02/05/2019. Added for Noveli

  ELSIF l_des_sh_cust_id = 1251 THEN
    --Eagle steel, send to Budd and Eagle(ford format)
    --rr:=edi_alcan_budd_856(packing_list_no);  -- per budd and eagle, they no longer receive ASN from ABC
    --rr:= edi_alcan_ford_856_x12(packing_list_no);  --Send Eagle using Ford code
    --return rr;
    --RETURN edi_alcan_alcan_856_x12(packing_list_no); --Alex Gerlants. 02/05/2019. Commented out
    return edi_novelis_856_X12(packing_list_no); --Alex Gerlants. 02/05/2019. Added for Novelis

    --elsif l_des_sh_cust_id = 79 then                  --WSDC send Alcan only
    --      return edi_alcan_alcan_856_x12(packing_list_no);

  --Alex Gerlants. 09/27/2021. Added 2950 - Novelis-Guthrey
  ELSIF l_customer_id IN (35, 10, 1153, 1459, 2582, 2950) THEN
    SELECT MAX(sc_packing_item)
      INTO scrap_item
      FROM scrap_packing_item
     WHERE packing_list = packing_list_no;
    IF scrap_item > 0 THEN
      --RETURN edi_alcan_alcan_scrap_856_x12(packing_list_no); --Alex Gerlants. 02/05/2019. Commented out
      return edi_novelis_scrap_856_x12(packing_list_no); --Alex Gerlants. 02/05/2019. Added for Novelis
    ELSE -- All else destination send Alcan only
      --RETURN edi_alcan_alcan_856_x12(packing_list_no);  --Alex Gerlants. 02/05/2019. Commented out
      return edi_novelis_856_X12(packing_list_no); --Alex Gerlants. 02/05/2019. Added for Novelis 
    END IF;

  ELSIF l_des_sh_cust_id = 45 THEN
    RETURN edi_alcoa_hayes_856_x12(packing_list_no);
  ELSE
    RETURN 200;
  END IF;

EXCEPTION
  WHEN exce_sent THEN
    --    raise_application_error(-20101,'STOP! EDI had been sent');
    RETURN 100;
  WHEN exce_nodata THEN
    --     raise_application_error(-20101,'No shipment data found!');
    RETURN - 1;
  WHEN exce_des_sh_cust_id THEN
    --    raise_application_error(-20101,'This shipment does not required EDIFACT DESADV EDI!');
    RETURN 200;
  WHEN OTHERS THEN
    --    raise_application_error(-20101,'INTERNAL ERROR! PLEASE CALL 1519.');
    RETURN - 1;

  --   return l_return;
END;
