--------------------------------------------------------
--  DDL for Function F_EDI_ALERIS_861
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_ALERIS_861" 
(
   al_customer_id in customer.customer_id%TYPE,
   as_bol         in inbound_shipment.bol%TYPE
)
   
return integer 
is

  FunctionResult              integer;
  
  /*
  This function creates Aleris EDI 861.
  edi_file_id and bol are from inbound_shipment table, received_time is generated the current moment by the system.
  This function will be called from Coil Receiving after a successful saving
  */

  type edi_861_tabletype is table of varchar2(32767) index by binary_integer;
  edi_861                     edi_861_tabletype;
  
  j                           binary_integer;
  i                           integer;
  
  ---
  ----Create table of edi_file_id's
  --type edi_file_id_tabletype is table of integer index by binary_integer;
  --edi_id     edi_file_id_tabletype;
  --k          binary_integer;
  --m          integer;
  
  ---

  edi_file_prefix             varchar2(50) := 'S_aleris_861_'; --Production
  --edi_file_prefix             varchar2(50) := 's_aleris_861_'; --Development
  
  li_coil_ready               integer;
  li_gs_log                   integer;
  li_st_log                   integer;
  ls_today_short              varchar2(20);
  ls_today                    varchar2(20);
  ls_now                      varchar2(20);
  ld_received_time            date;
  ls_received_time            varchar2(13);
  li_customer_id              integer;
  ls_vo                       varchar2(20);
  ls_coil_number              varchar2(40);
  ls_ps_coil_number           varchar2(40);
  ls_temper                   varchar2(8);
  ln_net_weight               number(8, 0);
  ln_gross_weight             number(8, 0);
  ln_lineal_feed              number(7, 2);
  ln_coil_width               number(9, 4);
  ln_coil_gauge               number(5, 4);
  ln_density                  number;
  ls_lot                      varchar2(40);
  ls_pack_id                  varchar2(40);
  ls_alloy                    varchar2(40);
  ln_damage_fault             number(1);
  ln_damage_code              number(3);
  
  --edi_location                varchar2(50) := '/templar/templar/incoming/senddata';
  edi_location                VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR');
  
  edi_file                    varchar2(50) := 'edi_out.txt';
  edi_file_handle             utl_file.file_type;
  li_edi_861_id               integer;
  ls_dun                      varchar2(32);
  ls_ship_from                varchar2(40);
  coil_count                  integer;
  li_coil_abc_num             integer;
  li_count                    integer;
  ls_received_date            varchar2(13);
  li_inbound_shipment_status  inbound_shipment_status.status%TYPE;
  ll_edi_file_id              inbound_shipment_status.edi_file_id%TYPE;
  is_create_861_at_receiving  char(1);
  ls_po                       inbound_coil.po%TYPE;
  ls_part_num                 VARCHAR2(40);

/*
  CURSOR shipment_cursor IS
    SELECT ss.bol, ss.edi_file_id
      FROM inbound_shipment_status   ss,
           inbound_shipment          s,
           inbound_shipment_customer c
     WHERE ss.edi_file_id = s.edi_file_id
       AND ss.bol = s.bol
       AND s.ship_from = c.ship_from
       and s.bol = as_bol
       AND c.customer_id IN (2784) --ARCONIC-TN
       AND -- customers for 861
           ss.status = 3;
*/          
           
  /*cursor shipment_cursor is
  select bol, edi_file_id
  from inbound_shipment_status
  where status = 3 ;
*/

  --Table data_861 is populated in w_coil_receiving
  cursor data_861_cursor is
  select    customer_id,
            bol,
            edi_file_id,
            coil_org_num,
            receiving_bol_id,
            coil_abc_num,
            coil_status,
            damaged_fault,
            damaged_code,
            temper,
            net_weight,
            gross_weight,
            lineal_feed,
            coil_width,
            coil_gauge,
            density,
            lot,
            pack_id,
            alloy,
            part_num,
            supplier_sales_num,
            consumed_coil_num,
            material_num,
            cash_date,
            coil_from_cust_id,
            created_date,
            received_date,
            po,
            po_line_num,
            customer_duns_number,
            mill_duns_number,
            packaging_code,
            loading_qty
  from      dbo.data_861
  where     customer_id = al_customer_id
  and       bol = as_bol
  and       edi_file_id = ll_edi_file_id
  order by  edi_file_id;

  cursor edi_file_id_cursor(as_bol varchar2) is
     select  distinct edi_file_id
     from    dbo.data_861
     where   customer_id = al_customer_id
      and    bol = as_bol;

begin

/*  
    --This is also checked in wf_create_861_4customer for w_coil_receiving
    select	upper(nvl(create_861_at_receiving, 'N'))
    into		is_create_861_at_receiving
    from		customer
    where		customer_id = al_customer_id;
    
    if is_create_861_at_receiving <> 'Y' then 
      return 2; --Nothing to do here
    end if;
*/
    
   
    select count(*)
    into   li_count
    from   customer
    where  customer_id = al_customer_id
    --and    lower(customer_full_name) like '%aleris%'
    ;
    
    If li_count <= 0 then
       return 3; --Wrong customer
    end if;
/*    
    --Check 861 has already been created
    select    count(distinct status)
    into      li_count
    from      inbound_shipment_status
    where     bol = as_bol
    and       status = 1;
    
    if li_count >= 1 then
      return 3; --861 already created
    end if;
*/
 
    FunctionResult := 1;

      --coil_count := 0;
      --j          := 0;
      
    
    for edi_file_id_cloop in edi_file_id_cursor(as_bol) loop 
      
        coil_count := 0;
        j          := 0;
      
        ll_edi_file_id := edi_file_id_cloop.edi_file_id;
        
        SELECT po, part_number
        INTO ls_po, ls_part_num
        FROM inbound_shipment
       WHERE bol = as_bol
         AND edi_file_id = ll_edi_file_id;
    
      --IF (li_coil_ready = 1) THEN
        SELECT edi_st_log_seq.nextval INTO li_st_log FROM dual;
        SELECT edi_gs_log_seq.nextval INTO li_gs_log FROM dual;
        ls_today_short := to_char(SYSDATE, 'yymmdd');
        ls_today       := to_char(SYSDATE, 'yyyymmdd');
        ls_now         := to_char(SYSDATE, 'hh24mi');

        SELECT distinct vo
          INTO ls_vo
          FROM inbound_shipment
         WHERE bol = as_bol
         and   edi_file_id = ll_edi_file_id;

        ld_received_time := sysdate;   --set the received time as current system time*/
                        
        SELECT distinct ship_from
          INTO ls_ship_from
          FROM inbound_shipment
         WHERE bol = as_bol;
                           
        SELECT distinct customer_id
          INTO li_customer_id
          FROM inbound_shipment_customer
         WHERE ship_from = ls_ship_from;

        SELECT customer.customer_duns_number_string
          INTO ls_dun
          FROM customer
         WHERE customer.customer_id = al_customer_id;      

        ls_received_time := to_char(ld_received_time, 'yymmdd*hh24mi'); --Format as YYMMDD for ISA and GS lines

        --Production
        edi_861(j) := 'ISA*00*          *00*          *01*039630926T     *ZZ*964790856      *' ||
                        ls_received_time || '*U*00401*' ||
                        lpad(to_char(li_gs_log), 9, '0') || '*0*P*>';
                        
        --Development                
        --edi_861(j) := 'ISA*00*' ||
        --                '          *00*          *ZZ*2NDSFTP        *ZZ*964790856      *' ||
        --                ls_received_time || '*U*00401*' ||
        --                lpad(to_char(li_gs_log), 9, '0') || '*0*T*>';
                                        
        j := j + 1;
        
        ls_received_time := to_char(ld_received_time, 'yyyymmdd*hh24mi'); --Format as YYMMDD for DTM*050* line

        --Production
        edi_861(j) := 'GS*RC*039630926T*' || '964790856' || '*' || ls_today || '*' ||
                        ls_now || '*' || to_char(li_gs_log) || '*X*' || '004010';
                                        
        --Development
        --edi_861(j) := 'GS*RC*2NDSFTP' || '*964790856' || '*' || ls_today || '*' ||
        --               ls_now || '*' || to_char(li_gs_log) || '*X*' || '004010';
        
        j := j + 1;
                        
        edi_861(j) := 'ST*861*' || li_st_log;
        j := j + 1;
                        
        edi_861(j) := 'BRA*' || as_bol || '*' || ls_today ||
                      '*00*1*' || ls_now;
        j := j + 1;
                        
        edi_861(j) := 'REF*BM*' || as_bol;
        j := j + 1;
                        
        edi_861(j) := 'DTM*050*' || ls_received_time || '*ET';
        j := j + 1;
        
        edi_861(j) := 'N1*OU**1*039630926';
        j := j + 1;
        
        edi_861(j) := 'N1*MF*Commonwealth*1*117791081';
        j := j + 1;
                        
  /*
        SELECT distinct ship_from
          INTO ls_ship_from
          FROM inbound_shipment
         WHERE bol = as_bol;
                           
        SELECT distinct customer_id
          INTO li_customer_id
          FROM inbound_shipment_customer
         WHERE ship_from = ls_ship_from;

        SELECT customer.customer_duns_number_string
          INTO ls_dun
          FROM customer
         WHERE customer.customer_id = li_customer_id;
  */
  
        SELECT ship_from
        INTO ls_ship_from
        FROM inbound_shipment
       WHERE edi_file_id = ll_edi_file_id
         AND bol = as_bol;
         
      SELECT customer_id
        INTO li_customer_id
        FROM inbound_shipment_customer
       WHERE ship_from = ls_ship_from;

      SELECT customer.customer_duns_number_string
        INTO ls_dun
        FROM customer
       WHERE customer.customer_id = li_customer_id;
                         
       edi_861(j) := 'N1*SU**1*' || ls_dun;
       j := j + 1;

        /*if li_customer_id = 1153 then
           ls_dun := '241003755';--'Novelis Kingston'
        elsif  li_customer_id = 1459 then
           ls_dun := '003980216';--'Novelis Oswego'
        else
           ls_dun := '241003755';
        end if;*/

        --edi_861(j) := 'N1*SU**1*' || ls_dun;
        --j := j + 1;

        for cloop in data_861_cursor() loop
          ls_coil_number    := cloop.coil_org_num;
          li_coil_abc_num   := cloop.coil_abc_num;
          ls_temper         := cloop.temper;
          ln_net_weight     := cloop.net_weight;
          ln_gross_weight   := cloop.gross_weight;
          ln_lineal_feed    := cloop.lineal_feed;
          ln_coil_width     := cloop.coil_width;
          ln_coil_gauge     := cloop.coil_gauge;
          ln_density        := cloop.density;
          ls_lot            := cloop.lot;
          ls_pack_id        := cloop.pack_id;
          ls_alloy          := cloop.alloy;
          --ls_ps_coil_number := cloop.ps_coil_number;
          ln_damage_fault   := cloop.damaged_fault;
          ln_damage_code    := cloop.damaged_code;

          IF (ls_ps_coil_number IS NULL) OR (length(ls_ps_coil_number) = 0) THEN
            ls_ps_coil_number := ls_coil_number;
          END IF;

       edi_861(j) := 'RCD**1*CX';
        j := j + 1;
        
        --Alex Gerlants. 09/06/2019. 
        --ls_pack_id is Aleris skid number. It comes from 856, segment: LIN, element4 = "SN", element5 = Aleris skid number.
        --Thus Aleris wants skid number back in 861 in ls_pack_id.
        --Pack_Id is in inbound_coil.pack_id
        --edi_861(j) := 'LIN**VO*' || ls_po || '*BP*' || ls_part_num || '*HN*' || ls_lot || '*SN*' || ls_coil_number; --Alex Gerlants. 09/06/2019. Comment out
        edi_861(j) := 'LIN**VO*' || ls_po || '*BP*' || ls_part_num || '*HN*' || ls_lot || '*SN*' || ls_pack_id; --Alex Gerlants. 09/06/2019. New line
        j := j + 1;
        
        edi_861(j) := 'PID*S*MAC*ST*01';
        j := j + 1;
        edi_861(j) := 'PID*S*MA*ST*7';
        j := j + 1;

        --add these two segments only for damaged coils
        IF ln_damage_code <> 0 THEN
          edi_861(j) := 'PID*S*DAC*ST*' || ln_damage_code;
          j := j + 1;
        END IF;
        IF ln_damage_fault <> 0 THEN
          /* DAF??? */
          edi_861(j) := 'PID*S*DAF*ST*' || ln_damage_fault;
          j := j + 1;
        END IF;

        edi_861(j) := 'PID*S*QAS*ST*2';
        j := j + 1;

/*       
        select   max(coil_abc_num)
        into     li_coil_abc_num
        from     coil
        where    coil_org_num = ls_coil_number
        and      coil_mid_num = ls_pack_id
        and      customer_id = al_customer_id;
*/
        
        --edi_861(j) := 'REF*RV*' || ls_ps_coil_number; --Alex Gerlants. 09/06/2019. Comment out
        edi_861(j) := 'REF*RV*' || ls_coil_number; --Alex Gerlants. 09/06/2019. New line
        j := j + 1;
        
        edi_861(j) := 'REF*SE*' || to_char(li_coil_abc_num); --Alex Gerlants. 09/06/2019. New line
        j := j + 1; --Alex Gerlants. 09/06/2019. New line
        
        edi_861(j) := 'PRF*' || ls_po;
        j := j + 1;
        edi_861(j) := 'MEA*WT*WT*' || ln_net_weight || '*01';
        j := j + 1;
        edi_861(j) := 'MEA*WT**' || ln_gross_weight || '*24';
        j := j + 1;
        edi_861(j) := 'MEA*PD*TH*' || to_char(ln_coil_gauge, 'FM90.0000') ||
                      '*IN';
        j := j + 1;
        edi_861(j) := 'MEA*PD*WD*' ||
                      to_char(ln_coil_width, 'FM99990.0000') || '*IN';
        j := j + 1;
        edi_861(j) := 'MEA*CT**' || ln_lineal_feed || '*LF';
        j := j + 1;

        coil_count := coil_count + 1;
        END LOOP; --for cloop in data_861_cursor() loop

        edi_861(j) := 'CTT*' || coil_count;
        j := j + 1;
        edi_861(j) := 'SE*' || to_char(j - 1) || '*' || li_st_log;
        j := j + 1;
        edi_861(j) := 'GE*1*' || li_gs_log;
        j := j + 1;
        edi_861(j) := 'IEA*1*' || lpad(to_char(li_gs_log), 9, '0');

        IF coil_count > 0 THEN
          --IF skip_edi = 0 THEN
            SELECT edi_file_id_seq.nextval INTO li_edi_861_id FROM dual;
            edi_file        := edi_file_prefix || to_char(li_edi_861_id) || '.edi';
            edi_file_handle := utl_file.fopen(edi_location, edi_file, 'W');
            --write edi to file
            FOR i IN 0 .. j LOOP
              utl_file.put_line(edi_file_handle, edi_861(i));
            END LOOP;
            utl_file.fclose(edi_file_handle);
          --END IF;
                          
        update inbound_shipment_status
        set    status = 1,
               filename_861 = edi_file,
               created_861_date_time = sysdate
        where  bol = as_bol
        and    edi_file_id = ll_edi_file_id;        
        
        insert into outbound_edi_transaction
            (edi_file_id,
             duns_from,
             duns_to,
             interchange_control_number,
             group_control_number,
             transaction_time,
             edi_file_name,
             fa_receive_status,
             customer_id,
             set_control_num,
             transaction_type_id)
        values
            (li_edi_861_id,
             '039630926',
             ls_dun,
             li_gs_log,
             li_gs_log,
             sysdate,
             edi_file,
             0,
             li_customer_id,
             li_st_log,
             '861');
           
          commit;
                          

          edi_file        := 'send_edi_log';
          edi_file_handle := utl_file.fopen(edi_location, edi_file, 'a');
          utl_file.put_line(edi_file_handle, 'Type: 861');
          utl_file.put_line(edi_file_handle,
                            'Sending Time: ' ||
                            to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
          utl_file.put_line(edi_file_handle,
                            'Interchange Control #: ' || li_gs_log);
          utl_file.put_line(edi_file_handle,
                            'Group Control #: ' || li_gs_log);
          utl_file.put_line(edi_file_handle, 'Set Control #: ' || li_st_log);
          utl_file.put_line(edi_file_handle, '');
          utl_file.put_line(edi_file_handle, '');
          utl_file.fclose(edi_file_handle);

  /*
          UPDATE inbound_shipment_status
             SET status = 1
           WHERE bol = as_bol
             AND edi_file_id = ai_edi_file_id;

          COMMIT;
  */

        END IF;
      --END IF;
    --END LOOP; --loop end for edi_file_id/bol
    end loop; --for edi_file_id_cloop in coil_status_cursor(as_bol) loop                    
  
  return(FunctionResult);
  
end f_edi_aleris_861;
--------------------------------------------------------
--  DDL for Function F_EDI_ALERIS_870_PER_JOB
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_ALERIS_870_PER_JOB" (al_ab_job_num  ab_job.ab_job_num%type)
  return integer
  
is

  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   Customer: Aleris(1980) DUNS:964790856     EDI ID:964790856      QUALIFIER: ZZ
   This version of the stored procedure was copied from production on
   May 23, 2016 by Patrick Reynolds.
   The only main difference between the DEV and PROD version of the stored prcedure is that
   the DEV version had the update section all commented out.
   There was also an additional index (p) variable in the PROD code
   that the DEV version did not have.
   End User: Aleris, Customer ID 1980
   */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc                varchar2(50) := dbo.get_edi_destination('EDI_DIR');
  edi_file               varchar2(50) := 'edi_out.txt';
  --edi_file_prefix        varchar2(50) := 'S_aleris_870_'; --Production
  edi_file_prefix        varchar2(50) := 's_aleris_870_'; --Develpment
  edi_file_handle        utl_file.file_type;
  su_duns                varchar2(10);
  ll_customer_id         integer := 1980;
  li_scrap_job_done      integer := 2;
  ll_cur_job             ab_job.ab_job_num%type;
  ll_gs_log              integer;
  ll_st_log              integer;
  ls_today               varchar2(20) := to_char(sysdate, 'YYYYMMDD');
  ls_today_4             varchar2(20) := to_char(sysdate, 'YYMMDD');
  ls_now                 varchar2(20) := to_char(sysdate, 'HH24MI');
  ls_po                  varchar2(32);
  ls_enduser_po          varchar2(32);
  ls_enduser_item_po     varchar2(32);
  ld_scrap_870_date      ab_job.scrap_870_date%type;
  ls_coil_org_num        coil.coil_org_num%type;
  ls_heat                coil.lot_num%type;
  ln_coil_thickness      coil.coil_gauge%type;
  ln_width               rectangle.rt_width%type;
  ln_length              rectangle.rt_length%type;
  ll_ref_order_abc_num   sheet_skid.ref_order_abc_num%type;
  ll_ref_order_abc_item  sheet_skid.ref_order_abc_item%type;
  ls_sheet_type          order_item.sheet_type%type;
  ll_prime_nw            coil.net_wt%type;
  ll_scrap_nw            coil.net_wt%type;
  -- ll_process_quantity  coil.net_wt%type;
  -- ll_process_end_wt  coil.net_wt%type;
  lr_theo_unit_wt        order_item.theoretical_unit_wt%type;
  --ll_edi_file_id         integer;
  ll_edi_file_id_aleris  integer;
  ll_item_count          integer;
  ll_job_count           integer;
  li_hl01                integer;
  li_hllin               integer;
  ll_edi_file_id_870     integer;
  ld_edi_date_870        ab_job.edi_date_870%type;

/*
  cursor cust_cur is
  select customer_id from customer where customer_id in (1980); ---add customer id here if you want to send 870 for more customers

  cursor job_cur is
  select     unique production_sheet_item.ab_job_num
  from       sheet_skid,
             production_sheet_item,
             sheet_skid_detail,
             coil,
             customer_order
  --where      (sheet_skid.skid_sheet_status in (2, 8))
  --and        (production_sheet_item.prod_item_edi870_date is null)
  where      (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
  and        (sheet_skid_detail.prod_item_num =
             production_sheet_item.prod_item_num)
  and        (coil.coil_abc_num = production_sheet_item.coil_abc_num)
  and        (coil.customer_id = 1980)
  and        (sheet_skid.ref_order_abc_num = customer_order.order_abc_num)
  and        (production_sheet_item.ab_job_num = al_ab_job_num) --alex gerlants. 02/25/2020

  union

  select     unique a.ab_job_num
  from       ab_job a, customer_order b
  where      (a.order_abc_num = b.order_abc_num) and
             (a.job_status = 0) and
             (b.orig_customer_id = 1980)
             --and (a.scrap_870_date is null)
  and        (a.ab_job_num = al_ab_job_num); --Alex Gerlants. 02/25/2020
*/

  cursor     aleris_870_cur is
  select     production_sheet_item.ab_job_num,
             production_sheet_item.coil_abc_num,
             production_sheet_item.prod_item_pieces,
             production_sheet_item.prod_item_num,
             sheet_skid.sheet_skid_num,
             production_sheet_item.prod_item_net_wt,
             sheet_skid.skid_sheet_status,
             sheet_skid.sheet_net_wt,
             sheet_skid.skid_pieces,
             coil.coil_org_num,
             coil.lot_num,
             nvl(customer_order.sales_order, ' ') sales_order,
             nvl(customer_order.orig_customer_po, 'NA') customer_po,
             nvl(customer_order.enduser_po, 'NA') enduser_po,
             nvl(order_item.enduser_part_num, ' ') enduser_parts,
             (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
             null done
      from   sheet_skid,
             production_sheet_item,
             sheet_skid_detail,
             coil,
             order_item,
			       ab_job,
             customer_order
     --where   (sheet_skid.skid_sheet_status in (2, 4, 7, 8, 13)) -- 2: ready; 8: warehouse ready; 4: onhold 13: partial ready
     --  and   (production_sheet_item.prod_item_edi870_date is null)
     where   (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
       and   (sheet_skid_detail.prod_item_num =
             production_sheet_item.prod_item_num)
       and   (coil.coil_abc_num = production_sheet_item.coil_abc_num)
       and   (coil.customer_id = ll_customer_id)
       and   (sheet_skid.ref_order_abc_num = customer_order.order_abc_num)
 		   and   (production_sheet_item.ab_job_num = ab_job.ab_job_num)
		   and   (ab_job.order_abc_num = order_item.order_abc_num)
		   and   (ab_job.order_item_num = order_item.order_item_num)
      and    (production_sheet_item.ab_job_num = al_ab_job_num); --Alex Gerlants. 02/25/2020
      

      cursor aleris_scrap_870_cur is
      select coil_abc_num,
             nvl(process_quantity, 0) process_quan,
             nvl(process_end_wt, 0) process_end_wt
      from   process_coil
      where  (process_coil.ab_job_num = al_ab_job_num); --Alex Gerlants. 02/25/2020

  type store_tabletype is table of varchar2(32767) index by binary_integer;
  x12_table store_tabletype;
  i         binary_integer := 0;
  item_rec  aleris_870_cur%rowtype;

  type prod_item_type is table of production_sheet_item.prod_item_num%type index by binary_integer;
  item_num prod_item_type;
  k        binary_integer := 0;

  type job_num_type is table of ab_job.ab_job_num%type index by binary_integer;
  job_num job_num_type;
  p binary_integer :=0;

begin
  
  --Check if 870 has already been created for al_ab_job_num
  select edi_file_id_870, edi_date_870
  into   ll_edi_file_id_870, ld_edi_date_870
  from   ab_job
  where  ab_job_num = al_ab_job_num;
   
  if not (ll_edi_file_id_870 is null and ld_edi_date_870 is null) then --870 already created for al_ab_job_num
    return 100;
  end if;

  --for cust_rec in cust_cur loop
    --- outer loop of customer_id
    --ll_customer_id := cust_rec.customer_id;
    
    select   customer_order.orig_customer_id
    into     ll_customer_id
    from     ab_job
             join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
    where    ab_job.ab_job_num = al_ab_job_num;
    
    if ll_customer_id <> 1980 then --Not Aleris job
      return 110;
    end if;
    
    i              := 0;
    k              := 0;
    p              := 0;

    select count(*)
    into   ll_item_count
    from   sheet_skid,
           production_sheet_item,
           sheet_skid_detail,
           coil,
           customer_order
    --where  (sheet_skid.skid_sheet_status in (2, 8)) -- 2: ready; 8: warehouse ready; 13: partial ready
    --and    (production_sheet_item.prod_item_edi870_date is null)
    where  (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num)
    and    (sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num)
    and    (coil.coil_abc_num = production_sheet_item.coil_abc_num)
    and    (coil.customer_id = ll_customer_id)
    and    (production_sheet_item.ab_job_num = al_ab_job_num) --alex gerlants. 02/25/2020
    and    (sheet_skid.ref_order_abc_num = customer_order.order_abc_num);

    select count(a.ab_job_num)
    into   ll_job_count
    from   ab_job a, customer_order b
    where  (a.order_abc_num = b.order_abc_num) and
           (a.job_status = 0) and
           (b.orig_customer_id = 1980)
           --and (a.scrap_870_date is null)
           and (a.ab_job_num = al_ab_job_num); --alex gerlants. 02/25/2020


    if (ll_item_count <> 0) or (ll_job_count <> 0)then

      select edi_st_log_seq.nextval into ll_st_log from dual;
      select edi_gs_log_seq.nextval into ll_gs_log from dual;

      select customer.customer_duns_number_string
      into   su_duns
      from   customer
      where  customer.customer_id = ll_customer_id;

      --Production
      --x12_table(i) := 'ISA*00*' ||
      --                '          *00*          *01*039630926T     *ZZ*964790856      *' ||
      --                ls_today_4 || '*' || ls_now || '*U*00401*' ||
      --                lpad(to_char(ll_gs_log), 9, '0') || '*0*P*>';
      
      --Development                
      x12_table(i) := 'ISA*00*' ||
                      '          *00*          *01*2NDSFTP        *ZZ*964790856      *' ||
                      ls_today_4 || '*' || ls_now || '*U*00401*' ||
                      lpad(to_char(ll_gs_log), 9, '0') || '*0*T*>';
      i := i + 1;

      --Production      
      --x12_table(i) := 'GS*RS*039630926T*' || '964790856' || '*' || ls_today || '*' ||
      --                ls_now || '*' || to_char(ll_gs_log) || '*X*' ||
      --                '004010';

      --Development                      
      x12_table(i) := 'GS*RS*2NDSFTP*' || '964790856' || '*' || ls_today || '*' ||
                      ls_now || '*' || to_char(ll_gs_log) || '*X*' ||
                      '004010';
      i := i + 1;
      
      x12_table(i) := 'ST*870*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                      '***' || ls_now || '*****';
      i := i + 1;

      x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926T';
      i := i + 1;

       x12_table(i) := 'N1*MF**1*' || su_duns;
      i := i + 1;

      li_hl01 := 0;


      --for job_rec in job_cur loop    -- job loop


          ll_cur_job := al_ab_job_num;

          job_num(p) := ll_cur_job;
          p := p + 1;

             select nvl(customer_order.orig_customer_po, 'NA'), nvl(customer_order.enduser_po, 'NA')
              into ls_po, ls_enduser_po
              from ab_job, customer_order
              where (ab_job.ab_job_num = ll_cur_job)
              and (ab_job.order_abc_num = customer_order.order_abc_num);


        li_hl01 := li_hl01 + 1;

        x12_table(i) := 'HL*' || to_char(li_hl01) || '**O*1';
        i := i + 1;

        x12_table(i) := 'PRF*' || ls_enduser_po || '***' || ls_today;
        i := i + 1;

        li_hl01 := li_hl01 + 1;

         x12_table(i) := 'HL*' || to_char(li_hl01) || '*1*I*1';
        i := i + 1;

        x12_table(i) := 'PRF*RV*300578504';
        i := i + 1;

        li_hllin := li_hl01;

     for item_rec in aleris_870_cur loop  -- item loop


        li_hl01 := li_hl01 + 1;

        x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*F';
        i := i + 1;

        ls_po := item_rec.customer_po;
        ls_enduser_item_po := item_rec.enduser_po;

        x12_table(i) := 'PRF*' || ls_enduser_item_po || '***' || ls_today;
        i := i + 1;

        x12_table(i) := 'REF*SE*' || item_rec.sheet_skid_num;
         i := i + 1;

        x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now || '*ES';
        i := i + 1;

        x12_table(i) := 'DTM*206*' || ls_today;
        i := i + 1;


        x12_table(i) := 'PO1**1*UN***VO*' || ls_enduser_item_po ||
                          '*SN*' || item_rec.coil_org_num || '*HN*' || item_rec.lot_num || '***BP*' || item_rec.enduser_parts;
         i := i + 1;


         x12_table(i) := 'PID*S*MAC*ST*01***67';
          i := i + 1;
         x12_table(i) := 'PID*S*22*ST*20***22';
          i := i + 1;

       if item_rec.skid_sheet_status = 2 then
          x12_table(i) := 'PID*S*MA*ST*1***70' ;
          i := i + 1;
        elsif item_rec.skid_sheet_status = 13 then
          x12_table(i) := 'PID*S*MA*ST*8***70';
          i := i + 1;
        elsif item_rec.skid_sheet_status = 4 then
          x12_table(i) := 'PID*S*MA*ST*6***70';
          i := i + 1;
        else
          x12_table(i) := 'PID*S*MA*ST*3***70';
          i := i + 1;
        end if;

        x12_table(i) := 'PID*S*PR*ST*19***66';
          i := i + 1;


    select max(coil_gauge)
      into ln_coil_thickness
      from coil
     where coil.coil_abc_num in
           (select coil_abc_num
              from production_sheet_item
             where production_sheet_item.prod_item_num in
                   (select prod_item_num
                      from sheet_skid_detail
                     where sheet_skid_detail.sheet_skid_num =
                           item_rec.sheet_skid_num));

    x12_table(i) := 'MEA*PD*TH*' ||
                    trim(to_char(ln_coil_thickness, '99999.99')) || '*ED';
    i := i + 1;
    x12_table(i) := 'MEA*PD*TH*' ||
                    trim(to_char(ln_coil_thickness * 25.4, '99999.99')) ||
                    '*MB';
    i := i + 1;

    select ss.ref_order_abc_num, ss.ref_order_abc_item
      into ll_ref_order_abc_num, ll_ref_order_abc_item
      from sheet_skid ss
     where ss.sheet_skid_num = item_rec.sheet_skid_num;

    select sheet_type, nvl(theoretical_unit_wt, 0)
      into ls_sheet_type, lr_theo_unit_wt
      from order_item
     where order_abc_num = ll_ref_order_abc_num
       and order_item_num = ll_ref_order_abc_item;

    case trim(upper(ls_sheet_type))
      when 'RECTANGLE' then
        select t.rt_length, t.rt_width
          into ln_length, ln_width
          from rectangle t
         where t.order_abc_num = ll_ref_order_abc_num
           and t.order_item_num = ll_ref_order_abc_item;
      when 'PARALLELOGRAM' then
        select t.p_length, t.p_width
          into ln_length, ln_width
          from parallelogram t
         where t.order_abc_num = ll_ref_order_abc_num
           and t.order_item_num = ll_ref_order_abc_item;
      when 'FENDER' then
        select t.fe_length, t.fe_side
          into ln_length, ln_width
          from fender t
         where t.order_abc_num = ll_ref_order_abc_num
           and t.order_item_num = ll_ref_order_abc_item;
      when 'CHEVRON' then
        select t.ch_length, t.ch_width
          into ln_length, ln_width
          from chevron t
         where t.order_abc_num = ll_ref_order_abc_num
           and t.order_item_num = ll_ref_order_abc_item;
      when 'CIRCLE' then
        select t.c_diameter, t.c_diameter
          into ln_length, ln_width
          from circle t
         where t.order_abc_num = ll_ref_order_abc_num
           and t.order_item_num = ll_ref_order_abc_item;
      when 'TRAPEZOID' then
        select t.tr_long_length, t.tr_width
          into ln_length, ln_width
          from trapezoid t
         where t.order_abc_num = ll_ref_order_abc_num
           and t.order_item_num = ll_ref_order_abc_item;
      when 'L.TRAPEZOID' then
        select t.ltr_long_length, t.ltr_width
          into ln_length, ln_width
          from left_trapezoid t
         where t.order_abc_num = ll_ref_order_abc_num
           and t.order_item_num = ll_ref_order_abc_item;
      when 'R.TRAPEZOID' then
        select t.rtr_long_length, t.rtr_width
          into ln_length, ln_width
          from right_trapezoid t
         where t.order_abc_num = ll_ref_order_abc_num
           and t.order_item_num = ll_ref_order_abc_item;
      when 'REINFORCEMENT' then
        select t.re_length, t.re_width
          into ln_length, ln_width
          from reinforcement t
         where t.order_abc_num = ll_ref_order_abc_num
           and t.order_item_num = ll_ref_order_abc_item;
      when 'LIFTGATE' then
        select t.li_length, t.li_width
          into ln_length, ln_width
          from liftgate_shape t
         where t.order_abc_num = ll_ref_order_abc_num
           and t.order_item_num = ll_ref_order_abc_item;
      else
        select t.x_1, t.x_2
          into ln_length, ln_width
          from x1_shape t
         where t.order_abc_num = ll_ref_order_abc_num
           and t.order_item_num = ll_ref_order_abc_item;
    end case;

    x12_table(i) := 'MEA*PD*WD*' || TRIM(to_char(ln_width, '99999.99')) ||
                    '*ED';
    i := i + 1;

    x12_table(i) := 'MEA*PD*WD*' ||
                    TRIM(to_char(ln_width * 25.4, '99999.99')) || '*MB';
    i := i + 1;

    x12_table(i) := 'MEA*CT*LN*' || TRIM(to_char(ln_length, '99999.99')) ||
                    '*ED';
    i := i + 1;

    x12_table(i) := 'MEA*PD*LN*' ||
                    TRIM(to_char(ln_length * 25.4, '99999.99')) || '*MB'; -- Linear MillMeter
    i := i + 1;

   x12_table(i) := 'MEA*CT*NL*' || to_char(item_rec.prod_item_pieces) ||
                    '*PC';
    i := i + 1;

    x12_table(i) := 'MEA*WT*WT*' || to_char(item_rec.prod_item_pieces * lr_theo_unit_wt, '99999') ||
                    '*24';
    i := i + 1;

    x12_table(i) := 'MEA*WT*WT*' || to_char(item_rec.prod_item_pieces * lr_theo_unit_wt * 0.4536, '99999') || '*53';
    i := i + 1;

    x12_table(i) := 'MEA*WT*WT*' || to_char(item_rec.prod_item_net_wt) ||
                    '*01';
    i := i + 1;

    x12_table(i) := 'MEA*WT*WT*' ||
                    to_char(item_rec.prod_item_net_wt * 0.4536, '99999') || '*50';
    i := i + 1;



 --       x12_table(i) := 'MEA*WT*G*' || to_char(item_rec.skid_gross_wt) ||'*LB*01';
 --       i := i + 1;
 --       x12_table(i) := 'MEA*CT*NA*' || to_char(item_rec.prod_item_pieces) || '*PC';
--        i := i + 1;
        item_num(k) := item_rec.prod_item_num;
        k := k + 1;

     end loop;  -- item loop

     select scrap_870_date, job_status
     into   ld_scrap_870_date, li_scrap_job_done
     from   ab_job
     where  ab_job_num = ll_cur_job;

     if (ld_scrap_870_date is null) and (li_scrap_job_done = 0) then  -- scrap not sent and job is done

      for scrap_rec in aleris_scrap_870_cur loop    -- scrap loop

        --scrap info

        select coil_org_num, lot_num
        into   ls_coil_org_num, ls_heat
        from   coil
        where  coil_abc_num = scrap_rec.coil_abc_num;

        select nvl(sum(production_sheet_item.prod_item_net_wt),0)
        into   ll_prime_nw
        from   production_sheet_item
        where  (production_sheet_item.ab_job_num = ll_cur_job) and
               (production_sheet_item.coil_abc_num = scrap_rec.coil_abc_num);

        ll_scrap_nw := scrap_rec.process_quan - scrap_rec.process_end_wt - ll_prime_nw;

        if ll_scrap_nw > 0 then

           li_hl01 := li_hl01 + 1;

           x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*F';
           i := i + 1;

           x12_table(i) := 'PRF*' || ls_enduser_po || '***' || ls_today;
           i := i +1;

            x12_table(i) := 'PO1**1*UN***VO*' || ls_enduser_po ||
                  '*SN*' || ls_coil_org_num || '*HN*' || ls_heat || '***BP* ';
             i := i + 1;

            x12_table(i) := 'PID*S*MAC*ST*05***67';
            i := i + 1;
            x12_table(i) := 'PID*S*DAF*ST*3***72';
             i := i + 1;
            x12_table(i) := 'PID*S*DAC*ST*258***73';
             i := i + 1;

           x12_table(i) := 'MEA*WT*WT*' || to_char(ll_scrap_nw) || '*01';
           i := i+1;
           x12_table(i) := 'MEA*WT*WT*' || to_char(ll_scrap_nw * 0.4536, '99999') || '*50';
           i := i+1;
         end if;

        end loop;  -- scrap loop
      end if;  -- scrap not sent


     --end loop;   -- job loop

      x12_table(i) := 'CTT*' || to_char(li_hl01);
      i := i + 1;
      x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
      i := i + 1;
      x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
      i := i + 1;
      x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

      -- Write EDI to file

      IF li_hl01 > 1 THEN
        -- WRITE EDI FILE ONLY IF ITEM > 0
        SELECT edi_file_id_seq.nextval
          INTO ll_edi_file_id_aleris
          FROM dual;
-- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
--        edi_file        := 's_aleris_' || to_char(ll_edi_file_id_aleris) ||
--                           '.870';
         edi_file        := edi_file_prefix || to_char(ll_edi_file_id_aleris) || '.edi';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        FOR j IN 0 .. i LOOP
          utl_file.put_line(edi_file_handle, x12_table(j));

        END LOOP;
        utl_file.fclose(edi_file_handle);
      END IF; -- END WRITING EDI FILE

     --edi_file        := 'send_edi_log'; /* Alex Gerlants. 04/14/2017. Commented out. */
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      --For verifying 997
/*      
      insert into outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
        values
          (ll_edi_file_id_aleris,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           sysdate,
           edi_file,
           0,
           ll_customer_id,
           ll_st_log,
           '870');
*/           

 -- Release this commented section
 --    1. when testing the update portion of this stored procedure, or
 --    2. before releasing the SP to PROD.
 -- Patrick Reynolds May 23, 2016

/*
     for m in 0 .. k - 1 loop
       update production_sheet_item
           set prod_item_edi870_date = sysdate,
               edi_file_id_870 = ll_edi_file_id_aleris
        where production_sheet_item.prod_item_num = item_num(m);
     end loop;
*/     
     
--     update    ab_job  
--     set       edi_file_id_870 = ll_edi_file_id_870,  /* Alex Gerlants. 02/14/2020. New column */
--               edi_date_870 = sysdate, /* Alex Gerlants. 02/14/2020. New column */
--               ab_job.scrap_870_date = sysdate
--     where     ab_job_num = al_ab_job_num;

     commit;

    end if; --end if in select count(*)

  --end loop; ------ End of outer loop customer_id

/*
EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN;
*/    
    

  return 1;
end f_edi_aleris_870_per_job;
--------------------------------------------------------
--  DDL for Function F_EDI_ARCONIC_861
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_ARCONIC_861" 
(
   al_customer_id in customer.customer_id%TYPE,
   as_bol         in inbound_shipment.bol%TYPE
)
   
return integer 
is

  FunctionResult              integer;
  
  /*
  This function creates Arconic EDI 861.
  edi_file_id and bol are from inbound_shipment table, received_time is generated the current moment by the system.
  This function will be called from Coil Receiving after a successful saving
  */

  type edi_861_tabletype is table of varchar2(32767) index by binary_integer;
  edi_861                     edi_861_tabletype;
  
  j                           binary_integer;
  i                           integer;
  
  ---
  ----Create table of edi_file_id's
  --type edi_file_id_tabletype is table of integer index by binary_integer;
  --edi_id     edi_file_id_tabletype;
  --k          binary_integer;
  --m          integer;
  
  ---

  edi_file_prefix             varchar2(50) := 'S_arconic_861_'; --Production
  --edi_file_prefix             varchar2(50) := 's_arconic_861_'; --Development
  
  li_coil_ready               integer;
  li_gs_log                   integer;
  li_st_log                   integer;
  ls_today_short              varchar2(20);
  ls_today                    varchar2(20);
  ls_now                      varchar2(20);
  ld_received_time            date;
  ls_received_time            varchar2(13);
  li_customer_id              integer;
  ls_vo                       varchar2(20);
  ls_coil_number              varchar2(40);
  ls_ps_coil_number           varchar2(40);
  ls_temper                   varchar2(8);
  ln_net_weight               number(8, 0);
  ln_gross_weight             number(8, 0);
  ln_lineal_feed              number(7, 2);
  ln_coil_width               number(7, 2);
  ln_coil_gauge               number(5, 4);
  ln_density                  number;
  ls_lot                      varchar2(40);
  ls_pack_id                  varchar2(40);
  ls_alloy                    varchar2(40);
  ln_damage_fault             number(1);
  ln_damage_code              number(3);
  
  --edi_location                varchar2(50) := '/templar/templar/incoming/senddata'; --Alex Gerlants. 10/07/2019
  edi_location                VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR'); --Alex Gerlants. 10/07/2019
  
  edi_file                    varchar2(50) := 'edi_out.txt';
  edi_file_handle             utl_file.file_type;
  li_edi_861_id               integer;
  ls_dun                      varchar2(32);
  ls_ship_from                varchar2(40);
  coil_count                  integer;
  li_coil_abc_num             integer;
  li_count                    integer;
  ls_received_date            varchar2(8);
  li_inbound_shipment_status  inbound_shipment_status.status%TYPE;
  ll_edi_file_id              inbound_shipment_status.edi_file_id%TYPE;
  is_create_861_at_receiving  char(1);

/*
  CURSOR shipment_cursor IS
    SELECT ss.bol, ss.edi_file_id
      FROM inbound_shipment_status   ss,
           inbound_shipment          s,
           inbound_shipment_customer c
     WHERE ss.edi_file_id = s.edi_file_id
       AND ss.bol = s.bol
       AND s.ship_from = c.ship_from
       and s.bol = as_bol
       AND c.customer_id IN (2784) --ARCONIC-TN
       AND -- customers for 861
           ss.status = 3;
*/          
           
  /*cursor shipment_cursor is
  select bol, edi_file_id
  from inbound_shipment_status
  where status = 3 ;
*/

  --Table data_861 is populated in w_coil_receiving
  cursor data_861_cursor is
  select    customer_id,
            bol,
            edi_file_id,
            coil_org_num,
            receiving_bol_id,
            coil_abc_num,
            coil_status,
            damaged_fault,
            damaged_code,
            temper,
            net_weight,
            gross_weight,
            lineal_feed,
            coil_width,
            coil_gauge,
            density,
            lot,
            pack_id,
            alloy,
            part_num,
            supplier_sales_num,
            consumed_coil_num,
            material_num,
            cash_date,
            coil_from_cust_id,
            created_date,
            received_date,
            po,
            po_line_num,
            customer_duns_number,
            mill_duns_number,
            packaging_code,
            loading_qty
  from      dbo.data_861
  where     customer_id = al_customer_id
  and       bol = as_bol
  and       edi_file_id = ll_edi_file_id
  order by  edi_file_id;

  cursor edi_file_id_cursor(as_bol varchar2) is
     select  distinct edi_file_id
     from    dbo.data_861
     where   customer_id = al_customer_id
      and    bol = as_bol;

/*
  CURSOR coil_status_cursor(as_bol varchar2) is
    SELECT distinct status
      FROM inbound_coil_status
     WHERE bol = as_bol
     and edi_file_id = ll_edi_file_id;
*/     
     /*
     and edi_file_id = 
     (
       select    max(edi_file_id)
       from      inbound_shipment_status
       where     bol = as_bol
       and       status = 3
     );
     */

/*
  CURSOR bol_and_edi_file_id_cursor IS
    SELECT distinct
           a.coil_number,
           a.temper,
           a.net_weight,
           a.gross_weight,
           a.lineal_feed,
           a.coil_width,
           a.coil_gauge,
           a.density,
           a.lot,
           a.pack_id,
           a.alloy,
           a.ps_coil_number,
           b.damaged_code,
           b.damaged_fault
      FROM inbound_coil a, inbound_coil_status b
     WHERE a.bol = b.bol
       and a.edi_file_id = b.edi_file_id
       AND a.item_num = b.item_num
       and a.bol = as_bol
       AND a.edi_file_id = ll_edi_file_id;
*/       
       /*
       and a.edi_file_id = 
         (
           select    max(edi_file_id)
           from      inbound_shipment_status
           where     bol = as_bol
           and       status = 3
         );
       */

begin

/*  
    --This is also checked in wf_create_861_4customer for w_coil_receiving
    select	upper(nvl(create_861_at_receiving, 'N'))
    into		is_create_861_at_receiving
    from		customer
    where		customer_id = al_customer_id;
    
    if is_create_861_at_receiving <> 'Y' then 
      return 2; --Nothing to do here
    end if;
*/
    
    if al_customer_id <> 2784 then
      return 3; --Wrong customer
    end if;
    
/*    
    --Check 861 has already been created
    select    count(distinct status)
    into      li_count
    from      inbound_shipment_status
    where     bol = as_bol
    and       status = 1;
    
    if li_count >= 1 then
      return 3; --861 already created
    end if;
*/
 
    FunctionResult := 1;
/*    
    --Load table of edi_file_id's into table edi_id
    --Cannot update the table used in a cursor
    m := 0;
    for edi_file_id_cloop in edi_file_id_cursor(as_bol) loop
      ll_edi_file_id := edi_file_id_cloop.edi_file_id;
      edi_id(m) := ll_edi_file_id;
      m := m + 1;
    end loop; 
    m := m - 1;
  

    --for edi_file_id_cloop in edi_file_id_cursor(as_bol) loop
    for k in 0 .. m loop
      --ll_edi_file_id := edi_file_id_cloop.edi_file_id;
      ll_edi_file_id := edi_id(k);
      
      li_coil_ready := 0;

      --if not all coils are imported or mark damaged yet, don't send them
      FOR coil_status_cloop IN coil_status_cursor(as_bol) loop
                                                  --shipment_cloop.edi_file_id) LOOP
        IF (coil_status_cloop.status = 1 OR coil_status_cloop.status = 2) THEN
          --status 1:imported  2:marked damaged
          li_coil_ready := 1;
        ELSE
          li_coil_ready := 0;
        END IF;
                        
        EXIT WHEN li_coil_ready = 0;
      END LOOP;
*/
      --coil_count := 0;
      --j          := 0;
      
    
    for edi_file_id_cloop in edi_file_id_cursor(as_bol) loop 
      
        coil_count := 0;
        j          := 0;
      
        ll_edi_file_id := edi_file_id_cloop.edi_file_id;
    
      --IF (li_coil_ready = 1) THEN
        SELECT edi_st_log_seq.nextval INTO li_st_log FROM dual;
        SELECT edi_gs_log_seq.nextval INTO li_gs_log FROM dual;
        ls_today_short := to_char(SYSDATE, 'yymmdd');
        ls_today       := to_char(SYSDATE, 'yyyymmdd');
        ls_now         := to_char(SYSDATE, 'hh24mi');

        SELECT distinct vo
          INTO ls_vo
          FROM inbound_shipment
         WHERE bol = as_bol
         and   edi_file_id = ll_edi_file_id;

        /*ld_received_time := sysdate;   --set the received time as current system time*/
        SELECT COUNT(*)
          INTO li_count
          FROM receiving_bol
         WHERE bol = as_bol;

        IF li_count = 1 THEN
          SELECT distinct nvl(created_date, sysdate)
            INTO ld_received_time
            FROM receiving_bol
           WHERE bol = as_bol;
        ELSE
          ld_received_time := SYSDATE;
        END IF;
                        
        SELECT distinct ship_from
          INTO ls_ship_from
          FROM inbound_shipment
         WHERE bol = as_bol;
                           
        SELECT distinct customer_id
          INTO li_customer_id
          FROM inbound_shipment_customer
         WHERE ship_from = ls_ship_from;

        SELECT customer.customer_duns_number_string
          INTO ls_dun
          FROM customer
         WHERE customer.customer_id = al_customer_id;      

        ls_received_time := to_char(ld_received_time, 'yymmdd*hh24mi');

        --Production
        edi_861(j) := 'ISA*00*' ||
                        '          *00*          *01*039630926T     *01*961613887      *' ||
                        ls_received_time || '*U*00401*' ||
                        lpad(to_char(li_gs_log), 9, '0') || '*0*P*>';
                        
        --Development                
        --edi_861(j) := 'ISA*00*' ||
        --                '          *00*          *ZZ*2NDSFTP        *ZZ*ARNCQFMW       *' ||
        --                ls_received_time || '*U*00401*' ||
        --                lpad(to_char(li_gs_log), 9, '0') || '*0*T*>';
                                        
        j := j + 1;

        --Production
        edi_861(j) := 'GS*SH*R0P7ATN*' || '961613887' || '*' || ls_today || '*' ||
                        ls_now || '*' || to_char(li_gs_log) || '*X*' || '004010';
                                        
        --Development
        --edi_861(j) := 'GS*SH*2NDSFTP' || 'TN*ARNCQFMW' || '*' || ls_today || '*' ||
        --               ls_now || '*' || to_char(li_gs_log) || '*X*' || '004010';
        j := j + 1;
                        
        edi_861(j) := 'ST*861*' || li_st_log;
        j := j + 1;
                        
        edi_861(j) := 'BRA*' || as_bol || '*' || ls_today ||
                      '*00*1*' || ls_now;
        j := j + 1;
                        
        edi_861(j) := 'REF*MA*' || as_bol;
        j := j + 1;
                        
        edi_861(j) := 'DTM*050*' || ls_received_time || '*ED';
        j := j + 1;
                        
  /*
        SELECT distinct ship_from
          INTO ls_ship_from
          FROM inbound_shipment
         WHERE bol = as_bol;
                           
        SELECT distinct customer_id
          INTO li_customer_id
          FROM inbound_shipment_customer
         WHERE ship_from = ls_ship_from;

        SELECT customer.customer_duns_number_string
          INTO ls_dun
          FROM customer
         WHERE customer.customer_id = li_customer_id;
  */
                         
        edi_861(j) := 'N1*MF**1*' || ls_dun; --Arconic DUNS
        j := j + 1;
                        
        edi_861(j) := 'N1*OU**1*039630926'; --ALBL DUNS
        j := j + 1;

        /*if li_customer_id = 1153 then
           ls_dun := '241003755';--'Novelis Kingston'
        elsif  li_customer_id = 1459 then
           ls_dun := '003980216';--'Novelis Oswego'
        else
           ls_dun := '241003755';
        end if;*/

        edi_861(j) := 'N1*SU**1*' || ls_dun;
        j := j + 1;

        for cloop in data_861_cursor() loop
          ls_coil_number    := cloop.coil_org_num;
          li_coil_abc_num   := cloop.coil_abc_num;
          ls_temper         := cloop.temper;
          ln_net_weight     := cloop.net_weight;
          ln_gross_weight   := cloop.gross_weight;
          ln_lineal_feed    := cloop.lineal_feed;
          ln_coil_width     := cloop.coil_width;
          ln_coil_gauge     := cloop.coil_gauge;
          ln_density        := cloop.density;
          ls_lot            := cloop.lot;
          ls_pack_id        := cloop.pack_id;
          ls_alloy          := cloop.alloy;
          --ls_ps_coil_number := cloop.ps_coil_number;
          ln_damage_fault   := cloop.damaged_fault;
          ln_damage_code    := cloop.damaged_code;

          IF (ls_ps_coil_number IS NULL) OR (length(ls_ps_coil_number) = 0) THEN
            ls_ps_coil_number := ls_coil_number;
          END IF;

          edi_861(j) := 'RCD**1*UN';
          j := j + 1;
                          
          edi_861(j) := 'LIN**VO*' || ls_vo || '*VN*01' || '*SN*' || ls_coil_number ||
                        '*HN*' || ls_lot;
          j := j + 1;
          edi_861(j) := 'PID*S*MAC*ST*01***67';
          j := j + 1;
                          
          edi_861(j) := 'PID*S*MA*ST*7***70';
          j := j + 1;


          --add these two segments only for damaged coils
  /*        
          IF ln_damage_code <> 0 THEN
            edi_861(j) := 'PID*S*DAC*ST*' || ln_damage_code;
            j := j + 1;
          END IF;
          IF ln_damage_fault <> 0 THEN
            edi_861(j) := 'PID*S*DAF*ST*' || ln_damage_fault;
            j := j + 1;
          END IF;

          edi_861(j) := 'PID*S*QAS*ST*2';
          j := j + 1;

  */
          /*
          SELECT COUNT(*)
            INTO li_count
            FROM coil c
           WHERE c.coil_org_num = ls_coil_number
             --AND c.coil_mid_num = ls_pack_id
             AND c.customer_id IN (li_customer_id);

          IF li_count = 1 THEN
            SELECT nvl(c.coil_abc_num, 0)
              INTO li_coil_abc_num
              FROM coil c
             WHERE c.coil_org_num = ls_coil_number
               --AND c.coil_mid_num = ls_pack_id
               AND c.customer_id IN (2784);
          ELSE
            li_coil_abc_num := 0;
          END IF;
          */

          edi_861(j) := 'REF*SE*' || li_coil_abc_num;
          j := j + 1;
                          
          ls_received_date := to_char(ld_received_time, 'yyyymmdd');
                          
          edi_861(j) := 'DTM*206*' || ls_received_date;
          j := j + 1;
                          
          --edi_861(j) := 'REF*BM*' || shipment_cloop.bol;
          --j := j + 1;
                          
          --edi_861(j) := 'REF*RV*' || ls_ps_coil_number;
          --j := j + 1;
                          
          --edi_861(j) := 'PRF*' || ls_vo;
          --j := j + 1;
                          
          edi_861(j) := 'MEA*WT**' || ln_net_weight || '*01';
          j := j + 1;
                          
          edi_861(j) := 'MEA*WT**' || ln_gross_weight || '*24';
          j := j + 1;
                          
          edi_861(j) := 'MEA*PD*TH*' || to_char(ln_coil_gauge, 'FM90.0000') || '*ED';
          j := j + 1;
          edi_861(j) := 'MEA*PD*WD*' || to_char(ln_coil_width, 'FM99990.0000') || '*ED';
          j := j + 1;
                          
          edi_861(j) := 'MEA*PD*LN*' || ln_lineal_feed || '*LF';
          j := j + 1;

          coil_count := coil_count + 1;
          
          update    inbound_coil_status
          set       coil_abc_num = li_coil_abc_num
          where     bol = as_bol
          and       edi_file_id = ll_edi_file_id
          and       coil_number = ls_coil_number;
        END LOOP; --for cloop in data_861_cursor() loop

        edi_861(j) := 'CTT*' || coil_count;
        j := j + 1;
        edi_861(j) := 'SE*' || to_char(j - 1) || '*' || li_st_log;
        j := j + 1;
        edi_861(j) := 'GE*1*' || li_gs_log;
        j := j + 1;
        edi_861(j) := 'IEA*1*' || lpad(to_char(li_gs_log), 9, '0');

        IF coil_count > 0 THEN
          --IF skip_edi = 0 THEN
            SELECT edi_file_id_seq.nextval INTO li_edi_861_id FROM dual;
  -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
  --          edi_file        := 's_Novelis_' || to_char(li_edi_861_id) || '.861';
            edi_file        := edi_file_prefix || to_char(li_edi_861_id) || '.edi';
            edi_file_handle := utl_file.fopen(edi_location, edi_file, 'W');
            --write edi to file
            FOR i IN 0 .. j LOOP
              utl_file.put_line(edi_file_handle, edi_861(i));
            END LOOP;
            utl_file.fclose(edi_file_handle);
          --END IF;

          /*--added by Victor Huang on 06/05 for function acknowlegement
           INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
           VALUES(li_gs_log, ls_dun, sysdate, edi_file);
           COMMIT;
          */
          --added by Victor Huang on 12/07 for verifying 997
                          
        update inbound_shipment_status
          set    status = 1,
                 filename_861 = edi_file,
                 created_861_date_time = sysdate
          where  bol = as_bol
          and    edi_file_id = ll_edi_file_id;        
        
          INSERT INTO outbound_edi_transaction
            (edi_file_id,
             duns_from,
             duns_to,
             interchange_control_number,
             group_control_number,
             transaction_time,
             edi_file_name,
             fa_receive_status,
             customer_id,
             set_control_num,
             transaction_type_id)
          VALUES
            (li_edi_861_id,
             '039630926',
             ls_dun,
             li_gs_log,
             li_gs_log,
             sysdate,
             edi_file,
             0,
             li_customer_id,
             li_st_log,
             '861');
           
          commit;
                          

          edi_file        := 'send_edi_log';
          edi_file_handle := utl_file.fopen(edi_location, edi_file, 'a');
          utl_file.put_line(edi_file_handle, 'Type: 861');
          utl_file.put_line(edi_file_handle,
                            'Sending Time: ' ||
                            to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
          utl_file.put_line(edi_file_handle,
                            'Interchange Control #: ' || li_gs_log);
          utl_file.put_line(edi_file_handle,
                            'Group Control #: ' || li_gs_log);
          utl_file.put_line(edi_file_handle, 'Set Control #: ' || li_st_log);
          utl_file.put_line(edi_file_handle, '');
          utl_file.put_line(edi_file_handle, '');
          utl_file.fclose(edi_file_handle);

  /*
          UPDATE inbound_shipment_status
             SET status = 1
           WHERE bol = as_bol
             AND edi_file_id = ai_edi_file_id;

          COMMIT;
  */

        END IF;
      --END IF;
    --END LOOP; --loop end for edi_file_id/bol
    end loop; --for edi_file_id_cloop in coil_status_cursor(as_bol) loop                    
  
  return(FunctionResult);
  
end f_edi_arconic_861;
--------------------------------------------------------
--  DDL for Function F_EDI_ARCONIC_861_TEST
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_ARCONIC_861_TEST" 
(
   as_bol         in inbound_shipment.bol%TYPE
)
   
return integer 
is

  FunctionResult              integer;
  
  /*
  This function creates Arconic EDI 861.
  edi_file_id and bol are from inbound_shipment table, received_time is generated the current moment by the system.
  This function will be called from Coil Receiving after a successful saving
  */

  type edi_861_tabletype is table of varchar2(32767) index by binary_integer;
  edi_861                     edi_861_tabletype;
  
  j                           binary_integer;
  i                           integer;

  --edi_file_prefix             varchar2(50) := 'S_arconic_861_'; --Production
  edi_file_prefix             varchar2(50) := 's_arconic_861_'; --Development
  
  li_coil_ready               integer;
  li_gs_log                   integer;
  li_st_log                   integer;
  ls_today_short              varchar2(20);
  ls_today                    varchar2(20);
  ls_now                      varchar2(20);
  ld_received_time            date;
  ls_received_time            varchar2(13);
  li_customer_id              integer;
  ls_vo                       varchar2(20);
  ls_coil_number              varchar2(40);
  ls_ps_coil_number           varchar2(40);
  ls_temper                   varchar2(8);
  ln_net_weight               number(8, 0);
  ln_gross_weight             number(8, 0);
  ln_lineal_feed              number(7, 2);
  ln_coil_width               number(7, 2);
  ln_coil_gauge               number(5, 4);
  ln_density                  number;
  ls_lot                      varchar2(40);
  ls_pack_id                  varchar2(40);
  ls_alloy                    varchar2(40);
  ln_damage_fault             number(1);
  ln_damage_code              number(3);
  edi_location                varchar2(50) := '/templar/templar/incoming/senddata';
  edi_file                    varchar2(50) := 'edi_out.txt';
  edi_file_handle             utl_file.file_type;
  li_edi_861_id               integer;
  ls_dun                      varchar2(32);
  ls_ship_from                varchar2(40);
  coil_count                  integer;
  li_coil_abc_num             integer;
  li_count                    integer;
  ls_received_date            varchar2(8);
  li_inbound_shipment_status  inbound_shipment_status.status%TYPE;
  ll_edi_file_id              inbound_shipment_status.edi_file_id%TYPE;

/*
  CURSOR shipment_cursor IS
    SELECT ss.bol, ss.edi_file_id
      FROM inbound_shipment_status   ss,
           inbound_shipment          s,
           inbound_shipment_customer c
     WHERE ss.edi_file_id = s.edi_file_id
       AND ss.bol = s.bol
       AND s.ship_from = c.ship_from
       and s.bol = as_bol
       AND c.customer_id IN (2784) --ARCONIC-TN
       AND -- customers for 861
           ss.status = 3;
*/          
           
  /*cursor shipment_cursor is
  select bol, edi_file_id
  from inbound_shipment_status
  where status = 3 ;
*/

  cursor edi_file_id_cursor(as_bol varchar2) is
     select   edi_file_id
     from     inbound_shipment_status
     where    bol = as_bol
     and      status = 3;

  CURSOR coil_status_cursor(as_bol varchar2) is
    SELECT distinct status
      FROM inbound_coil_status
     WHERE bol = as_bol
     and edi_file_id = ll_edi_file_id;
     /*
     and edi_file_id = 
     (
       select    max(edi_file_id)
       from      inbound_shipment_status
       where     bol = as_bol
       and       status = 3
     );
     */

  CURSOR bol_and_edi_file_id_cursor IS
    SELECT distinct
           a.coil_number,
           a.temper,
           a.net_weight,
           a.gross_weight,
           a.lineal_feed,
           a.coil_width,
           a.coil_gauge,
           a.density,
           a.lot,
           a.pack_id,
           a.alloy,
           a.ps_coil_number,
           b.damaged_code,
           b.damaged_fault
      FROM inbound_coil a, inbound_coil_status b
     WHERE a.bol = b.bol
       and a.edi_file_id = b.edi_file_id
       AND a.item_num = b.item_num
       and a.bol = as_bol
       AND a.edi_file_id = ll_edi_file_id;
       /*
       and a.edi_file_id = 
         (
           select    max(edi_file_id)
           from      inbound_shipment_status
           where     bol = as_bol
           and       status = 3
         );
       */

begin
    
/* This check below is performed in wf_861_alrady_sent for w_coil_receiving

    select    status
    into      li_inbound_shipment_status
    from      inbound_shipment_status
    where     bol = as_bol
    and       edi_file_id = ai_edi_file_id;
    
    if li_inbound_shipment_status = 1 then --861 already created
      return 2;
    end if;
*/  
    FunctionResult := 1;

    for edi_file_id_cloop in edi_file_id_cursor(as_bol) loop
      ll_edi_file_id := edi_file_id_cloop.edi_file_id;
      
      li_coil_ready := 0;

      --if not all coils are imported or mark damaged yet, don't send them
      FOR coil_status_cloop IN coil_status_cursor(as_bol) loop
                                                  --shipment_cloop.edi_file_id) LOOP
        IF (coil_status_cloop.status = 1 OR coil_status_cloop.status = 2) THEN
          --status 1:imported  2:marked damaged
          li_coil_ready := 1;
        ELSE
          li_coil_ready := 0;
        END IF;
                        
        EXIT WHEN li_coil_ready = 0;
      END LOOP;

      coil_count := 0;
      j          := 0;

      IF (li_coil_ready = 1) THEN
        SELECT edi_st_log_seq.nextval INTO li_st_log FROM dual;
        SELECT edi_gs_log_seq.nextval INTO li_gs_log FROM dual;
        ls_today_short := to_char(SYSDATE, 'yymmdd');
        ls_today       := to_char(SYSDATE, 'yyyymmdd');
        ls_now         := to_char(SYSDATE, 'hh24mi');

        SELECT distinct vo
          INTO ls_vo
          FROM inbound_shipment
         WHERE bol = as_bol
         and   edi_file_id = ll_edi_file_id;

        /*ld_received_time := sysdate;   --set the received time as current system time*/
        SELECT COUNT(*)
          INTO li_count
          FROM receiving_bol
         WHERE bol = as_bol;

        IF li_count = 1 THEN
          SELECT distinct nvl(created_date, sysdate)
            INTO ld_received_time
            FROM receiving_bol
           WHERE bol = as_bol;
        ELSE
          ld_received_time := SYSDATE;
        END IF;
                        
        SELECT distinct ship_from
          INTO ls_ship_from
          FROM inbound_shipment
         WHERE bol = as_bol;
                           
        SELECT distinct customer_id
          INTO li_customer_id
          FROM inbound_shipment_customer
         WHERE ship_from = ls_ship_from;

        SELECT customer.customer_duns_number_string
          INTO ls_dun
          FROM customer
         WHERE customer.customer_id = li_customer_id;      

        ls_received_time := to_char(ld_received_time, 'yyyymmdd*hh24mi'); --need this format in EDI861 file

        --Production
        --edi_861(j) := 'ISA*00*' ||
        --                '          *00*          *01*039630926T     *09*' || rpad(ls_dun, 15, ' ') || '*' ||
        --                ls_received_time || '*U*00401*' ||
        --                lpad(to_char(li_gs_log), 9, '0') || '*0*P*>';
                        
        --Development                
        edi_861(j) := 'ISA*00*' ||
                        '          *00*          *ZZ*2NDSFTP        *ZZ*ARNCQFMW       *' ||
                        ls_received_time || '*U*00401*' ||
                        lpad(to_char(li_gs_log), 9, '0') || '*0*T*>';
                                        
        j := j + 1;

        --Production
        --edi_861(j) := 'GS*SH*R0P7A' || 'TN*961613887' || '*' || ls_today || '*' ||
        --                ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010';
                                        
        --Development
        edi_861(j) := 'GS*SH*2NDSFTP' || 'TN*ARNCQFMW' || '*' || ls_today || '*' ||
                       ls_now || '*' || to_char(li_gs_log) || '*X*' || '004010';
        j := j + 1;
                        
        edi_861(j) := 'ST*861*' || li_st_log;
        j := j + 1;
                        
        edi_861(j) := 'BRA*' || as_bol || '*' || ls_today ||
                      '*00*1*' || ls_now;
        j := j + 1;
                        
        edi_861(j) := 'REF*MA*' || as_bol;
        j := j + 1;
                        
        edi_861(j) := 'DTM*050*' || ls_received_time || '*ED';
        j := j + 1;
                        
  /*
        SELECT distinct ship_from
          INTO ls_ship_from
          FROM inbound_shipment
         WHERE bol = as_bol;
                           
        SELECT distinct customer_id
          INTO li_customer_id
          FROM inbound_shipment_customer
         WHERE ship_from = ls_ship_from;

        SELECT customer.customer_duns_number_string
          INTO ls_dun
          FROM customer
         WHERE customer.customer_id = li_customer_id;
  */
                         
        edi_861(j) := 'N1*MF**1*' || ls_dun; --Arconic DUNS
        j := j + 1;
                        
        edi_861(j) := 'N1*OU**1*039630926'; --ALBL DUNS
        j := j + 1;

        /*if li_customer_id = 1153 then
           ls_dun := '241003755';--'Novelis Kingston'
        elsif  li_customer_id = 1459 then
           ls_dun := '003980216';--'Novelis Oswego'
        else
           ls_dun := '241003755';
        end if;*/

        edi_861(j) := 'N1*SU**1*' || ls_dun;
        j := j + 1;

        FOR cloop IN bol_and_edi_file_id_cursor() LOOP
          ls_coil_number    := cloop.coil_number;
          ls_temper         := cloop.temper;
          ln_net_weight     := cloop.net_weight;
          ln_gross_weight   := cloop.gross_weight;
          ln_lineal_feed    := cloop.lineal_feed;
          ln_coil_width     := cloop.coil_width;
          ln_coil_gauge     := cloop.coil_gauge;
          ln_density        := cloop.density;
          ls_lot            := cloop.lot;
          ls_pack_id        := cloop.pack_id;
          ls_alloy          := cloop.alloy;
          ls_ps_coil_number := cloop.ps_coil_number;
          ln_damage_fault   := cloop.damaged_fault;
          ln_damage_code    := cloop.damaged_code;

          IF (ls_ps_coil_number IS NULL) OR (length(ls_ps_coil_number) = 0) THEN
            ls_ps_coil_number := ls_coil_number;
          END IF;

          edi_861(j) := 'RCD**1*UN';
          j := j + 1;
                          
          edi_861(j) := 'LIN**VO*' || ls_vo || '*VN*01' || '*SN*' || ls_coil_number ||
                        '*HN*' || ls_lot;
          j := j + 1;
          edi_861(j) := 'PID*S*MAC*ST*01***67';
          j := j + 1;
                          
          edi_861(j) := 'PID*S*MA*ST*7***70';
          j := j + 1;


          --add these two segments only for damaged coils
  /*        
          IF ln_damage_code <> 0 THEN
            edi_861(j) := 'PID*S*DAC*ST*' || ln_damage_code;
            j := j + 1;
          END IF;
          IF ln_damage_fault <> 0 THEN
            edi_861(j) := 'PID*S*DAF*ST*' || ln_damage_fault;
            j := j + 1;
          END IF;

          edi_861(j) := 'PID*S*QAS*ST*2';
          j := j + 1;

  */
          SELECT COUNT(*)
            INTO li_count
            FROM coil c
           WHERE c.coil_org_num = ls_coil_number
             --AND c.coil_mid_num = ls_pack_id
             AND c.customer_id IN (li_customer_id);

          IF li_count = 1 THEN
            SELECT nvl(c.coil_abc_num, 0)
              INTO li_coil_abc_num
              FROM coil c
             WHERE c.coil_org_num = ls_coil_number
               --AND c.coil_mid_num = ls_pack_id
               AND c.customer_id IN (2784);
          ELSE
            li_coil_abc_num := 0;
          END IF;

          edi_861(j) := 'REF*SE*' || li_coil_abc_num;
          j := j + 1;
                          
          ls_received_date := to_char(ld_received_time, 'yyyymmdd');
                          
          edi_861(j) := 'DTM*206*' || ls_received_date;
          j := j + 1;
                          
          --edi_861(j) := 'REF*BM*' || shipment_cloop.bol;
          --j := j + 1;
                          
          --edi_861(j) := 'REF*RV*' || ls_ps_coil_number;
          --j := j + 1;
                          
          --edi_861(j) := 'PRF*' || ls_vo;
          --j := j + 1;
                          
          edi_861(j) := 'MEA*WT**' || ln_net_weight || '*01';
          j := j + 1;
                          
          edi_861(j) := 'MEA*WT**' || ln_gross_weight || '*24';
          j := j + 1;
                          
          edi_861(j) := 'MEA*PD*TH*' || to_char(ln_coil_gauge, 'FM90.0000') || '*ED';
          j := j + 1;
          edi_861(j) := 'MEA*PD*WD*' || to_char(ln_coil_width, 'FM99990.0000') || '*ED';
          j := j + 1;
                          
          edi_861(j) := 'MEA*PD*LN*' || ln_lineal_feed || '*LF';
          j := j + 1;

          coil_count := coil_count + 1;
        END LOOP;

        edi_861(j) := 'CTT*' || coil_count;
        j := j + 1;
        edi_861(j) := 'SE*' || to_char(j - 1) || '*' || li_st_log;
        j := j + 1;
        edi_861(j) := 'GE*1*' || li_gs_log;
        j := j + 1;
        edi_861(j) := 'IEA*1*' || lpad(to_char(li_gs_log), 9, '0');

        IF coil_count > 0 THEN
          --IF skip_edi = 0 THEN
            SELECT edi_file_id_seq.nextval INTO li_edi_861_id FROM dual;
  -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
  --          edi_file        := 's_Novelis_' || to_char(li_edi_861_id) || '.861';
            edi_file        := edi_file_prefix || to_char(li_edi_861_id) || '.edi';
            edi_file_handle := utl_file.fopen(edi_location, edi_file, 'W');
            --write edi to file
            FOR i IN 0 .. j LOOP
              utl_file.put_line(edi_file_handle, edi_861(i));
            END LOOP;
            utl_file.fclose(edi_file_handle);
          --END IF;

          /*--added by Victor Huang on 06/05 for function acknowlegement
           INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
           VALUES(li_gs_log, ls_dun, sysdate, edi_file);
           COMMIT;
          */
          --added by Victor Huang on 12/07 for verifying 997
/*                      
          update inbound_shipment_status
          set    status = 1,
                 filename_861 = edi_file,
                 created_861_date_time = sysdate
          where  bol = as_bol
          and    edi_file_id = ai_edi_file_id;        
*/
                          
  /*        
          INSERT INTO outbound_edi_transaction
            (edi_file_id,
             duns_from,
             duns_to,
             interchange_control_number,
             group_control_number,
             transaction_time,
             edi_file_name,
             fa_receive_status,
             customer_id,
             set_control_num,
             transaction_type_id)
          VALUES
            (li_edi_861_id,
             '039630926',
             ls_dun,
             li_gs_log,
             li_gs_log,
             sysdate,
             edi_file,
             0,
             li_customer_id,
             li_st_log,
             '861');
  */           
          --COMMIT;
                          

          edi_file        := 'send_edi_log';
          edi_file_handle := utl_file.fopen(edi_location, edi_file, 'a');
          utl_file.put_line(edi_file_handle, 'Type: 861');
          utl_file.put_line(edi_file_handle,
                            'Sending Time: ' ||
                            to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
          utl_file.put_line(edi_file_handle,
                            'Interchange Control #: ' || li_gs_log);
          utl_file.put_line(edi_file_handle,
                            'Group Control #: ' || li_gs_log);
          utl_file.put_line(edi_file_handle, 'Set Control #: ' || li_st_log);
          utl_file.put_line(edi_file_handle, '');
          utl_file.put_line(edi_file_handle, '');
          utl_file.fclose(edi_file_handle);

  /*
          UPDATE inbound_shipment_status
             SET status = 1
           WHERE bol = as_bol
             AND edi_file_id = ai_edi_file_id;

          COMMIT;
  */

        END IF;
      END IF;
    --END LOOP; --loop end for edi_file_id/bol
  end loop; --for edi_file_id_cloop in coil_status_cursor(as_bol) loop                    
  
  return(FunctionResult);
  
end f_edi_arconic_861_test;
--------------------------------------------------------
--  DDL for Function F_EDI_COMMONWEALTH_861
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_COMMONWEALTH_861" 
(
   al_customer_id in customer.customer_id%TYPE,
   as_bol         in inbound_shipment.bol%TYPE
)
   
return integer 
is

  FunctionResult              integer;
  
  /*
  This function creates Commonwealth EDI 861.
  edi_file_id and bol are from inbound_shipment table, received_time is generated the current moment by the system.
  This function will be called from Coil Receiving after a successful saving
  */

  type edi_861_tabletype is table of varchar2(32767) index by binary_integer;
  edi_861                     edi_861_tabletype;
  
  j                           binary_integer;
  i                           integer;
  
  ---
  ----Create table of edi_file_id's
  --type edi_file_id_tabletype is table of integer index by binary_integer;
  --edi_id     edi_file_id_tabletype;
  --k          binary_integer;
  --m          integer;
  
  ---

  edi_file_prefix             varchar2(50) := 'S_Commonwealth_861_'; --Production
  --edi_file_prefix             varchar2(50) := 's_Commonwealth_861_'; --Development
  
 -- li_coil_ready               integer;
  li_gs_log                   integer;
  li_st_log                   integer;
  ls_today_short              varchar2(20);
  ls_today                    varchar2(20);
  ls_now                      varchar2(20);
  ld_received_time            date;
  ls_received_time            varchar2(13);
  li_customer_id              integer;
  ls_vo                       varchar2(20);
  ls_coil_number              varchar2(40);
  ls_ps_coil_number           varchar2(40);
  ls_temper                   varchar2(8);
  ln_net_weight               number(8, 0);
  ln_gross_weight             number(8, 0);
  ln_lineal_feed              number(7, 2);
  ln_coil_width               number(9, 4);
  ln_coil_gauge               number(5, 4);
  ln_density                  number;
  ls_lot                      varchar2(40);
  ls_pack_id                  varchar2(40);
  ls_alloy                    varchar2(40);
  ln_damage_fault             number(1);
  ln_damage_code              number(3);
 
  --edi_location                varchar2(50) := '/templar/templar/incoming/senddata';
  edi_location                VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR');
  
  edi_file                    varchar2(50) := 'edi_out.txt';
  edi_file_handle             utl_file.file_type;
  li_edi_861_id               integer;
  ls_dun                      varchar2(32);
  ls_ship_from                varchar2(40);
  coil_count                  integer;
  li_coil_abc_num             integer;
  li_count                    integer;
--  ls_received_date            varchar2(13);
--  li_inbound_shipment_status  inbound_shipment_status.status%TYPE;
  ll_edi_file_id              inbound_shipment_status.edi_file_id%TYPE;
--  is_create_861_at_receiving  char(1);
  ls_po                       inbound_coil.po%TYPE;
  ls_part_num                 VARCHAR2(40);

/*
  CURSOR shipment_cursor IS
    SELECT ss.bol, ss.edi_file_id
      FROM inbound_shipment_status   ss,
           inbound_shipment          s,
           inbound_shipment_customer c
     WHERE ss.edi_file_id = s.edi_file_id
       AND ss.bol = s.bol
       AND s.ship_from = c.ship_from
       and s.bol = as_bol
       AND c.customer_id IN (2784) --ARCONIC-TN
       AND -- customers for 861
           ss.status = 3;
*/          
           
  /*cursor shipment_cursor is
  select bol, edi_file_id
  from inbound_shipment_status
  where status = 3 ;
*/

  --Table data_861 is populated in w_coil_receiving
  cursor data_861_cursor is
  select    customer_id,
            bol,
            edi_file_id,
            coil_org_num,
            receiving_bol_id,
            coil_abc_num,
            coil_status,
            damaged_fault,
            damaged_code,
            temper,
            net_weight,
            gross_weight,
            lineal_feed,
            coil_width,
            coil_gauge,
            density,
            lot,
            pack_id,
            alloy,
            part_num,
            supplier_sales_num,
            consumed_coil_num,
            material_num,
            cash_date,
            coil_from_cust_id,
            created_date,
            received_date,
            po,
            po_line_num,
            customer_duns_number,
            mill_duns_number,
            packaging_code,
            loading_qty
  from      dbo.data_861
  where     customer_id = al_customer_id
  and       bol = as_bol
  and       edi_file_id = ll_edi_file_id
  order by  edi_file_id;

  cursor edi_file_id_cursor(as_bol varchar2) is
     select  distinct edi_file_id
     from    dbo.data_861
     where   customer_id = al_customer_id
      and    bol = as_bol;

begin

/*  
    --This is also checked in wf_create_861_4customer for w_coil_receiving
    select	upper(nvl(create_861_at_receiving, 'N'))
    into		is_create_861_at_receiving
    from		customer
    where		customer_id = al_customer_id;
    
    if is_create_861_at_receiving <> 'Y' then 
      return 2; --Nothing to do here
    end if;
*/
    
   
    select count(*)
    into   li_count
    from   customer
    where  customer_id = al_customer_id
    --and    lower(customer_full_name) like '%Commonwealth%'
    ;
    
    If li_count <= 0 then
       return 3; --Wrong customer
    end if;
/*    
    --Check 861 has already been created
    select    count(distinct status)
    into      li_count
    from      inbound_shipment_status
    where     bol = as_bol
    and       status = 1;
    
    if li_count >= 1 then
      return 3; --861 already created
    end if;
*/
 
    FunctionResult := 1;

      --coil_count := 0;
      --j          := 0;
      
    
    for edi_file_id_cloop in edi_file_id_cursor(as_bol) loop 
      
        coil_count := 0;
        j          := 0;
      
        ll_edi_file_id := edi_file_id_cloop.edi_file_id;
        
        SELECT po, part_number
        INTO ls_po, ls_part_num
        FROM inbound_shipment
       WHERE bol = as_bol
         AND edi_file_id = ll_edi_file_id;
    
      --IF (li_coil_ready = 1) THEN
        SELECT edi_st_log_seq.nextval INTO li_st_log FROM dual;
        SELECT edi_gs_log_seq.nextval INTO li_gs_log FROM dual;
        ls_today_short := to_char(SYSDATE, 'yymmdd');
        ls_today       := to_char(SYSDATE, 'yyyymmdd');
        ls_now         := to_char(SYSDATE, 'hh24mi');

        SELECT distinct vo
          INTO ls_vo
          FROM inbound_shipment
         WHERE bol = as_bol
         and   edi_file_id = ll_edi_file_id;

        ld_received_time := sysdate;   --set the received time as current system time*/
                        
        SELECT distinct ship_from
          INTO ls_ship_from
          FROM inbound_shipment
         WHERE bol = as_bol;
                           
        SELECT distinct customer_id
          INTO li_customer_id
          FROM inbound_shipment_customer
         WHERE ship_from = ls_ship_from;

        SELECT customer.customer_duns_number_string
          INTO ls_dun
          FROM customer
         WHERE customer.customer_id = al_customer_id;      

        ls_received_time := to_char(ld_received_time, 'yymmdd*hh24mi'); --Format as YYMMDD for ISA and GS lines

        --Production
        edi_861(j) := 'ISA*00*          *00*          *01*039630926T     *ZZ*964790856      *' ||
                        ls_received_time || '*U*00401*' ||
                        lpad(to_char(li_gs_log), 9, '0') || '*0*P*>';
                        
        --Development                
        --edi_861(j) := 'ISA*00*' ||
        --                '          *00*          *ZZ*2NDSFTP        *ZZ*964790856      *' ||
        --                ls_received_time || '*U*00401*' ||
        --                lpad(to_char(li_gs_log), 9, '0') || '*0*T*>';
                                        
        j := j + 1;
        
        ls_received_time := to_char(ld_received_time, 'yyyymmdd*hh24mi'); --Format as YYMMDD for DTM*050* line

        --Production
        edi_861(j) := 'GS*RC*039630926T*' || '964790856' || '*' || ls_today || '*' ||
                        ls_now || '*' || to_char(li_gs_log) || '*X*' || '004010';
                                        
        --Development
        --edi_861(j) := 'GS*RC*2NDSFTP' || '*964790856' || '*' || ls_today || '*' ||
        --               ls_now || '*' || to_char(li_gs_log) || '*X*' || '004010';
        
        j := j + 1;
                        
        edi_861(j) := 'ST*861*' || li_st_log;
        j := j + 1;
                        
        edi_861(j) := 'BRA*' || as_bol || '*' || ls_today ||
                      '*00*1*' || ls_now;
        j := j + 1;
                        
        edi_861(j) := 'REF*BM*' || as_bol;
        j := j + 1;
                        
        edi_861(j) := 'DTM*050*' || ls_received_time || '*ET';
        j := j + 1;
        
        edi_861(j) := 'N1*OU**1*039630926';
        j := j + 1;
        
        edi_861(j) := 'N1*MF*Commonwealth*1*117791081';
        j := j + 1;
                        
  /*
        SELECT distinct ship_from
          INTO ls_ship_from
          FROM inbound_shipment
         WHERE bol = as_bol;
                           
        SELECT distinct customer_id
          INTO li_customer_id
          FROM inbound_shipment_customer
         WHERE ship_from = ls_ship_from;

        SELECT customer.customer_duns_number_string
          INTO ls_dun
          FROM customer
         WHERE customer.customer_id = li_customer_id;
  */
  
        SELECT ship_from
        INTO ls_ship_from
        FROM inbound_shipment
       WHERE edi_file_id = ll_edi_file_id
         AND bol = as_bol;
         
      SELECT customer_id
        INTO li_customer_id
        FROM inbound_shipment_customer
       WHERE ship_from = ls_ship_from;

      SELECT customer.customer_duns_number_string
        INTO ls_dun
        FROM customer
       WHERE customer.customer_id = li_customer_id;
                         
       edi_861(j) := 'N1*SU**1*' || ls_dun;
       j := j + 1;

        /*if li_customer_id = 1153 then
           ls_dun := '241003755';--'Novelis Kingston'
        elsif  li_customer_id = 1459 then
           ls_dun := '003980216';--'Novelis Oswego'
        else
           ls_dun := '241003755';
        end if;*/

        --edi_861(j) := 'N1*SU**1*' || ls_dun;
        --j := j + 1;

        for cloop in data_861_cursor() loop
          ls_coil_number    := cloop.coil_org_num;
          li_coil_abc_num   := cloop.coil_abc_num;
          ls_temper         := cloop.temper;
          ln_net_weight     := cloop.net_weight;
          ln_gross_weight   := cloop.gross_weight;
          ln_lineal_feed    := cloop.lineal_feed;
          ln_coil_width     := cloop.coil_width;
          ln_coil_gauge     := cloop.coil_gauge;
          ln_density        := cloop.density;
          ls_lot            := cloop.lot;
          ls_pack_id        := cloop.pack_id;
          ls_alloy          := cloop.alloy;
          --ls_ps_coil_number := cloop.ps_coil_number;
          ln_damage_fault   := cloop.damaged_fault;
          ln_damage_code    := cloop.damaged_code;

          IF (ls_ps_coil_number IS NULL) OR (length(ls_ps_coil_number) = 0) THEN
            ls_ps_coil_number := ls_coil_number;
          END IF;

       edi_861(j) := 'RCD**1*CX';
        j := j + 1;
        
        --Alex Gerlants. 09/06/2019. 
        --ls_pack_id is Commonwealth skid number. It comes from 856, segment: LIN, element4 = "SN", element5 = Commonwealth skid number.
        --Thus Commonwealth wants skid number back in 861 in ls_pack_id.
        --Pack_Id is in inbound_coil.pack_id
        --edi_861(j) := 'LIN**VO*' || ls_po || '*BP*' || ls_part_num || '*HN*' || ls_lot || '*SN*' || ls_coil_number; --Alex Gerlants. 09/06/2019. Comment out
        edi_861(j) := 'LIN**VO*' || ls_po || '*BP*' || ls_part_num || '*HN*' || ls_lot || '*SN*' || ls_pack_id; --Alex Gerlants. 09/06/2019. New line
        j := j + 1;
        
        edi_861(j) := 'PID*S*MAC*ST*01';
        j := j + 1;
        edi_861(j) := 'PID*S*MA*ST*7';
        j := j + 1;

        --add these two segments only for damaged coils
        IF ln_damage_code <> 0 THEN
          edi_861(j) := 'PID*S*DAC*ST*' || ln_damage_code;
          j := j + 1;
        END IF;
        IF ln_damage_fault <> 0 THEN
          /* DAF??? */
          edi_861(j) := 'PID*S*DAF*ST*' || ln_damage_fault;
          j := j + 1;
        END IF;

        edi_861(j) := 'PID*S*QAS*ST*2';
        j := j + 1;

/*       
        select   max(coil_abc_num)
        into     li_coil_abc_num
        from     coil
        where    coil_org_num = ls_coil_number
        and      coil_mid_num = ls_pack_id
        and      customer_id = al_customer_id;
*/
        
        --edi_861(j) := 'REF*RV*' || ls_ps_coil_number; --Alex Gerlants. 09/06/2019. Comment out
        edi_861(j) := 'REF*RV*' || ls_coil_number; --Alex Gerlants. 09/06/2019. New line
        j := j + 1;
        
        edi_861(j) := 'REF*SE*' || to_char(li_coil_abc_num); --Alex Gerlants. 09/06/2019. New line
        j := j + 1; --Alex Gerlants. 09/06/2019. New line
        
        --ls_received_time := to_char(ld_received_time, 'yyyymmdd*hh24mi');
        edi_861(j) := 'DTM*206*' || ls_received_time || '*ET';
        j := j + 1;
        
        edi_861(j) := 'PRF*' || ls_po;
        j := j + 1;
        edi_861(j) := 'MEA*WT*WT*' || ln_net_weight || '*01';
        j := j + 1;
        edi_861(j) := 'MEA*WT*WT*' || ln_gross_weight || '*24';
        j := j + 1;
        edi_861(j) := 'MEA*PD*TH*' || to_char(ln_coil_gauge, 'FM90.0000') ||
                      '*IN';
        j := j + 1;
        edi_861(j) := 'MEA*PD*WD*' ||
                      to_char(ln_coil_width, 'FM99990.0000') || '*IN';
        j := j + 1;
        edi_861(j) := 'MEA*CT*NL*1*PC';
        j := j + 1;

        coil_count := coil_count + 1;
        END LOOP; --for cloop in data_861_cursor() loop

        edi_861(j) := 'CTT*' || coil_count;
        j := j + 1;
        edi_861(j) := 'SE*' || to_char(j - 1) || '*' || li_st_log;
        j := j + 1;
        edi_861(j) := 'GE*1*' || li_gs_log;
        j := j + 1;
        edi_861(j) := 'IEA*1*' || lpad(to_char(li_gs_log), 9, '0');

        IF coil_count > 0 THEN
          --IF skip_edi = 0 THEN
            SELECT edi_file_id_seq.nextval INTO li_edi_861_id FROM dual;
            edi_file        := edi_file_prefix || to_char(li_edi_861_id) || '.edi';
            edi_file_handle := utl_file.fopen(edi_location, edi_file, 'W');
            --write edi to file
            FOR i IN 0 .. j LOOP
              utl_file.put_line(edi_file_handle, edi_861(i));
            END LOOP;
            utl_file.fclose(edi_file_handle);
          --END IF;
                          
        update inbound_shipment_status
        set    edi_file_id = li_edi_861_id,
               status = 1,
               filename_861 = edi_file,
               created_861_date_time = sysdate
        where  bol = as_bol
        and    edi_file_id = ll_edi_file_id;        
        
        insert into outbound_edi_transaction
            (edi_file_id,
             duns_from,
             duns_to,
             interchange_control_number,
             group_control_number,
             transaction_time,
             edi_file_name,
             fa_receive_status,
             customer_id,
             set_control_num,
             transaction_type_id)
        values
            (li_edi_861_id,
             '039630926',
             ls_dun,
             li_gs_log,
             li_gs_log,
             sysdate,
             edi_file,
             0,
             li_customer_id,
             li_st_log,
             '861');
           
          commit;
                          

          edi_file        := 'send_edi_log';
          edi_file_handle := utl_file.fopen(edi_location, edi_file, 'a');
          utl_file.put_line(edi_file_handle, 'Type: 861');
          utl_file.put_line(edi_file_handle,
                            'Sending Time: ' ||
                            to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
          utl_file.put_line(edi_file_handle,
                            'Interchange Control #: ' || li_gs_log);
          utl_file.put_line(edi_file_handle,
                            'Group Control #: ' || li_gs_log);
          utl_file.put_line(edi_file_handle, 'Set Control #: ' || li_st_log);
          utl_file.put_line(edi_file_handle, '');
          utl_file.put_line(edi_file_handle, '');
          utl_file.fclose(edi_file_handle);
          
  /*
          UPDATE inbound_shipment_status
             SET status = 1
           WHERE bol = as_bol
             AND edi_file_id = ai_edi_file_id;

          COMMIT;
  */

        END IF;
      --END IF;
    --END LOOP; --loop end for edi_file_id/bol
    end loop; --for edi_file_id_cloop in coil_status_cursor(as_bol) loop                    
  
  return(FunctionResult);
  
end f_edi_commonwealth_861;
--------------------------------------------------------
--  DDL for Function F_EDI_CONSTELLIUM_861
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_CONSTELLIUM_861" 
(
   al_customer_id in customer.customer_id%TYPE,
   as_bol         in inbound_shipment.bol%TYPE
)
   
return integer 
is

  FunctionResult              integer;
  
  /*
  This function creates Constellium EDI 861.
  edi_file_id and bol are from inbound_shipment table, received_time is generated the current moment by the system.
  This function will be called from Coil Receiving after a successful saving
  */

  type edi_861_tabletype is table of varchar2(32767) index by binary_integer;
  edi_861                     edi_861_tabletype;
  
  j                           binary_integer;
  i                           integer;
  
  ---
  ----Create table of edi_file_id's
  --type edi_file_id_tabletype is table of integer index by binary_integer;
  --edi_id     edi_file_id_tabletype;
  --k          binary_integer;
  --m          integer;
  
  ---

  edi_file_prefix             varchar2(50) := 'S_constellium_861_'; --Production
  --edi_file_prefix             varchar2(50) := 's_Constellium_861_'; --Development
  
  li_coil_ready               integer;
  li_gs_log                   integer;
  li_st_log                   integer;
  ls_today_short              varchar2(20);
  ls_today                    varchar2(20);
  ls_now                      varchar2(20);
  ld_received_time            date;
  ls_received_time            varchar2(13);
  li_customer_id              integer;
  ls_vo                       varchar2(20);
  ls_coil_number              varchar2(40);
  ls_ps_coil_number           varchar2(40);
  ls_temper                   varchar2(8);
  ln_net_weight               number(8, 0);
  ln_gross_weight             number(8, 0);
  ln_lineal_feed              number(7, 2);
  ln_coil_width               number(7, 4);
  ln_coil_gauge               number(5, 4);
  ln_density                  number;
  ls_lot                      varchar2(40);
  ls_pack_id                  varchar2(40);
  ls_alloy                    varchar2(40);
  ln_damage_fault             number(1);
  ln_damage_code              number(3);
  
  --edi_location                varchar2(50) := '/templar/templar/incoming/senddata';
  edi_location                VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR');
  
  edi_file                    varchar2(50) := 'edi_out.txt';
  edi_file_handle             utl_file.file_type;
  li_edi_861_id               integer;
  ls_dun                      varchar2(32);
  ls_ship_from                varchar2(40);
  coil_count                  integer;
  li_coil_abc_num             integer;
  li_count                    integer;
  ls_received_date            varchar2(13);
  li_inbound_shipment_status  inbound_shipment_status.status%TYPE;
  ll_edi_file_id              inbound_shipment_status.edi_file_id%TYPE;
  is_create_861_at_receiving  char(1);
  ls_po                       inbound_coil.po%TYPE;



  --Table data_861 is populated in w_coil_receiving
  cursor data_861_cursor is
  select    customer_id,
            bol,
            edi_file_id,
            coil_org_num,
            receiving_bol_id,
            coil_abc_num,
            coil_status,
            damaged_fault,
            damaged_code,
            temper,
            net_weight,
            gross_weight,
            lineal_feed,
            coil_width,
            coil_gauge,
            density,
            lot,
            pack_id,
            alloy,
            part_num,
            supplier_sales_num,
            consumed_coil_num,
            material_num,
            cash_date,
            coil_from_cust_id,
            created_date,
            received_date,
            po,
            po_line_num,
            customer_duns_number,
            mill_duns_number,
            packaging_code,
            loading_qty
  from      dbo.data_861
  where     customer_id = al_customer_id
  and       bol = as_bol
  and       edi_file_id = ll_edi_file_id
  order by  edi_file_id;

  cursor edi_file_id_cursor(as_bol varchar2) is
     select  distinct edi_file_id
     from    dbo.data_861
     where   customer_id = al_customer_id
      and    bol = as_bol;

begin

  
    --This is also checked in wf_create_861_4customer for w_coil_receiving
    select	upper(nvl(create_861_at_receiving, 'N'))
    into		is_create_861_at_receiving
    from		customer
    where		customer_id = al_customer_id;
    
    if is_create_861_at_receiving <> 'Y' then 
      return 2; --Nothing to do here
    end if;

    
   
    select count(*)
    into   li_count
    from   customer
    where  customer_id = al_customer_id
    and    lower(customer_full_name) like '%constellium%';
    
    If li_count <= 0 then
       return 3; --Wrong customer
    end if;
/*    
    --Check 861 has already been created
    select    count(distinct status)
    into      li_count
    from      inbound_shipment_status
    where     bol = as_bol
    and       status = 1;
    
    if li_count >= 1 then
      return 3; --861 already created
    end if;
*/
 
    FunctionResult := 1;

 
    for edi_file_id_cloop in edi_file_id_cursor(as_bol) loop 
      
        coil_count := 0;
        j          := 0;
      
        ll_edi_file_id := edi_file_id_cloop.edi_file_id;
    
      --IF (li_coil_ready = 1) THEN
        SELECT edi_st_log_seq.nextval INTO li_st_log FROM dual;
        SELECT edi_gs_log_seq.nextval INTO li_gs_log FROM dual;
        ls_today_short := to_char(SYSDATE, 'yymmdd');
        ls_today       := to_char(SYSDATE, 'yyyymmdd');
        ls_now         := to_char(SYSDATE, 'hh24mi');

        SELECT distinct vo
          INTO ls_vo
          FROM inbound_shipment
         WHERE bol = as_bol
         and   edi_file_id = ll_edi_file_id;

        ld_received_time := sysdate;   --set the received time as current system time*/
        
        /*
        SELECT COUNT(*)
          INTO li_count
          FROM receiving_bol
         WHERE bol = as_bol;

        IF li_count = 1 THEN
          SELECT distinct nvl(created_date, sysdate)
            INTO ld_received_time
            FROM receiving_bol
           WHERE bol = as_bol;
        ELSE
          ld_received_time := SYSDATE;
        END IF;
        */
                        
        SELECT distinct ship_from
          INTO ls_ship_from
          FROM inbound_shipment
         WHERE bol = as_bol;
                           
        SELECT distinct customer_id
          INTO li_customer_id
          FROM inbound_shipment_customer
         WHERE ship_from = ls_ship_from;

        SELECT customer.customer_duns_number_string
          INTO ls_dun
          FROM customer
         WHERE customer.customer_id = al_customer_id;      

        ls_received_time := to_char(ld_received_time, 'yymmdd*hh24mi'); --Format as YYMMDD for ISA and GS lines

        --Email from Troy Haag received on Fri 5/20/2022 4:29 PM
        --Approval email from Lisa received on Mon 5/23/2022 10:10 AM.
        --Change the last character from "*" to "@"
        --Production
        edi_861(j) := 'ISA*00*' ||
                        '          *00*          *01*039630926T     *01*043207177      *' ||
                        ls_received_time || '*U*00401*' ||
                        lpad(to_char(li_gs_log), 9, '0') || '*0*P*@';
                        
        --Development                
        --edi_861(j) := 'ISA*00*' ||
        --                '          *00*          *ZZ*2NDSFTP        *01*043207177      *' ||
        --                ls_received_time || '*U*00401*' ||
         --               lpad(to_char(li_gs_log), 9, '0') || '*0*T**';
                                        
        j := j + 1;
        
        ls_received_time := to_char(ld_received_time, 'yyyymmdd*hh24mi'); --Format as YYMMDD for DTM*050* line

        --Production
        edi_861(j) := 'GS*SH*039630926T*' || '043207177' || '*' || ls_today || '*' ||
                        ls_now || '*' || to_char(li_gs_log) || '*X*' || '004010';
                                        
        --Development
        --edi_861(j) := 'GS*SH*2NDSFTP' || '*043207177' || '*' || ls_today || '*' ||
        --               ls_now || '*' || to_char(li_gs_log) || '*X*' || '004010';
        j := j + 1;
                        
        edi_861(j) := 'ST*861*' || li_st_log;
        j := j + 1;
                        
        edi_861(j) := 'BRA*' || as_bol || '*' || ls_today ||
                      '*00*1*' || ls_now;
        j := j + 1;
                        
        edi_861(j) := 'REF*MA*' || as_bol;
        j := j + 1;
                        
        edi_861(j) := 'DTM*050*' || ls_received_time || '*ET';
        j := j + 1;
                        
                       
        edi_861(j) := 'N1*MF**1*' || ls_dun; --Constellium DUNS
        j := j + 1;
                        
        edi_861(j) := 'N1*OU**1*039630926'; --ALBL DUNS
        j := j + 1;

        for cloop in data_861_cursor() loop
          ls_coil_number    := cloop.coil_org_num;
          li_coil_abc_num   := cloop.coil_abc_num;
          ls_temper         := cloop.temper;
          ln_net_weight     := cloop.net_weight;
          ln_gross_weight   := cloop.gross_weight;
          ln_lineal_feed    := cloop.lineal_feed;
          ln_coil_width     := cloop.coil_width;
          ln_coil_gauge     := cloop.coil_gauge;
          ln_density        := cloop.density;
          ls_lot            := cloop.lot;
          ls_pack_id        := cloop.pack_id;
          ls_alloy          := cloop.alloy;
          --ls_ps_coil_number := cloop.ps_coil_number;
          ln_damage_fault   := cloop.damaged_fault;
          ln_damage_code    := cloop.damaged_code;

          IF (ls_ps_coil_number IS NULL) OR (length(ls_ps_coil_number) = 0) THEN
            ls_ps_coil_number := ls_coil_number;
          END IF;

          edi_861(j) := 'RCD**1*UN';
          j := j + 1;
          
          select    po
          into      ls_po
          from      inbound_coil
          where     bol = as_bol
          and       coil_number = ls_coil_number
          and       edi_file_id = ll_edi_file_id;
                          
          edi_861(j) := 'LIN**VO*' || ls_po || '**' || '*SN*' || ls_coil_number ||
                        '*HN*' || ls_lot;
          j := j + 1;
          edi_861(j) := 'PID*S*MAC*ST*01***67';
          j := j + 1;
                          
          edi_861(j) := 'PID*S*MA*ST*7***70';
          j := j + 1;
          
          edi_861(j) := 'PID*S*QAS*ST*1***68';
          j := j + 1;


          --add these two segments only for damaged coils
  /*        
          IF ln_damage_code <> 0 THEN
            edi_861(j) := 'PID*S*DAC*ST*' || ln_damage_code;
            j := j + 1;
          END IF;
          IF ln_damage_fault <> 0 THEN
            edi_861(j) := 'PID*S*DAF*ST*' || ln_damage_fault;
            j := j + 1;
          END IF;

          edi_861(j) := 'PID*S*QAS*ST*2';
          j := j + 1;

  */
          /*
          SELECT COUNT(*)
            INTO li_count
            FROM coil c
           WHERE c.coil_org_num = ls_coil_number
             --AND c.coil_mid_num = ls_pack_id
             AND c.customer_id IN (li_customer_id);

          IF li_count = 1 THEN
            SELECT nvl(c.coil_abc_num, 0)
              INTO li_coil_abc_num
              FROM coil c
             WHERE c.coil_org_num = ls_coil_number
               --AND c.coil_mid_num = ls_pack_id
               AND c.customer_id IN (2784);
          ELSE
            li_coil_abc_num := 0;
          END IF;
          */

          edi_861(j) := 'REF*SE*' || li_coil_abc_num;
          j := j + 1;
                          
          ls_received_date := to_char(ld_received_time, 'yyyymmdd hhmi');
                          
          edi_861(j) := 'DTM*206*' || ls_received_date || '*ET';
          j := j + 1;
                          
          --edi_861(j) := 'REF*BM*' || shipment_cloop.bol;
          --j := j + 1;
                          
          --edi_861(j) := 'REF*RV*' || ls_ps_coil_number;
          --j := j + 1;
                          
          --edi_861(j) := 'PRF*' || ls_vo;
          --j := j + 1;
                          
          edi_861(j) := 'MEA*WT*WT*' || ln_net_weight || '*01';
          j := j + 1;
                          
          edi_861(j) := 'MEA*WT*WT*' || ln_gross_weight || '*24';
          j := j + 1;
                          
          edi_861(j) := 'MEA*PD*TH*' || to_char(ln_coil_gauge, 'FM90.0000') || '*ED';
          j := j + 1;
          
          --edi_861(j) := 'MEA*PD*WD*' || to_char(ln_coil_width, 'FM99990.0000') || '*IN';
          edi_861(j) := 'MEA*PD*WD*' || to_char(ln_coil_width) || '*IN';
          j := j + 1;
                          
          edi_861(j) := 'MEA*PD*LN*' || ln_lineal_feed || '*LF';
          j := j + 1;

          coil_count := coil_count + 1;
          
          edi_861(j) := 'MEA*CT**' || to_char(coil_count) || '*PC';
          j := j + 1;
          
          update    inbound_coil_status
          set       coil_abc_num = li_coil_abc_num
          where     bol = as_bol
          and       edi_file_id = ll_edi_file_id
          and       coil_number = ls_coil_number;
        END LOOP; --for cloop in data_861_cursor() loop

        edi_861(j) := 'CTT*' || coil_count;
        j := j + 1;
        edi_861(j) := 'SE*' || to_char(j - 1) || '*' || li_st_log;
        j := j + 1;
        edi_861(j) := 'GE*1*' || li_gs_log;
        j := j + 1;
        edi_861(j) := 'IEA*1*' || lpad(to_char(li_gs_log), 9, '0');

        IF coil_count > 0 THEN
          --IF skip_edi = 0 THEN
            SELECT edi_file_id_seq.nextval INTO li_edi_861_id FROM dual;
  -- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
  --          edi_file        := 's_Novelis_' || to_char(li_edi_861_id) || '.861';
            edi_file        := edi_file_prefix || to_char(li_edi_861_id) || '.edi';
            edi_file_handle := utl_file.fopen(edi_location, edi_file, 'W');
            --write edi to file
            FOR i IN 0 .. j LOOP
              utl_file.put_line(edi_file_handle, edi_861(i));
            END LOOP;
            utl_file.fclose(edi_file_handle);
          --END IF;

          /*--added by Victor Huang on 06/05 for function acknowlegement
           INSERT INTO edi_fa(gs_num, duns_num, send_time,edi_file_name)
           VALUES(li_gs_log, ls_dun, sysdate, edi_file);
           COMMIT;
          */
          --added by Victor Huang on 12/07 for verifying 997
                          
        update inbound_shipment_status
          set    status = 1,
                 filename_861 = edi_file,
                 created_861_date_time = sysdate
          where  bol = as_bol
          and    edi_file_id = ll_edi_file_id;        
        
          INSERT INTO outbound_edi_transaction
            (edi_file_id,
             duns_from,
             duns_to,
             interchange_control_number,
             group_control_number,
             transaction_time,
             edi_file_name,
             fa_receive_status,
             customer_id,
             set_control_num,
             transaction_type_id)
          VALUES
            (li_edi_861_id,
             '039630926',
             ls_dun,
             li_gs_log,
             li_gs_log,
             sysdate,
             edi_file,
             0,
             li_customer_id,
             li_st_log,
             '861');
           
          commit;
                          

          edi_file        := 'send_edi_log';
          edi_file_handle := utl_file.fopen(edi_location, edi_file, 'a');
          utl_file.put_line(edi_file_handle, 'Type: 861');
          utl_file.put_line(edi_file_handle,
                            'Sending Time: ' ||
                            to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
          utl_file.put_line(edi_file_handle,
                            'Interchange Control #: ' || li_gs_log);
          utl_file.put_line(edi_file_handle,
                            'Group Control #: ' || li_gs_log);
          utl_file.put_line(edi_file_handle, 'Set Control #: ' || li_st_log);
          utl_file.put_line(edi_file_handle, '');
          utl_file.put_line(edi_file_handle, '');
          utl_file.fclose(edi_file_handle);

  /*
          UPDATE inbound_shipment_status
             SET status = 1
           WHERE bol = as_bol
             AND edi_file_id = ai_edi_file_id;

          COMMIT;
  */

        END IF;
      --END IF;
    --END LOOP; --loop end for edi_file_id/bol
    end loop; --for edi_file_id_cloop in coil_status_cursor(as_bol) loop                    
  
  return(FunctionResult);
  
end f_edi_constellium_861;
--------------------------------------------------------
--  DDL for Function F_EDI_CONSTELLIUM_BG_870_4JOB
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_CONSTELLIUM_BG_870_4JOB" 
 ( 
    al_ab_job_num           ab_job.ab_job_num%type,
    as_user_id              ab_job_870_history.user_id%type,
    al_coil_abc_num         coil.coil_abc_num%type,
    as_original_or_resend   varchar2
    
 )
  return integer
  
is

  /*
  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   Customer: Aleris(1980) DUNS:964790856     EDI ID:964790856      QUALIFIER: ZZ

   End User: Aleris, Customer ID 1980
   */

  --alex gerlants. 11/15/2016. commented out, and added the line after.
  --edi_loc               varchar2(50) := '/templar/templar/incoming/senddata';
  edi_loc                                       varchar2(50) := get_edi_destination('EDI_DIR');

  edi_file                                      varchar2(50) := 'edi_out.txt';
  edi_file_prefix                             varchar2(50) := 'S_const_870_';   --production
  --edi_file_prefix                               varchar2(50) := 's_const_870_';   --development
  edi_file_handle                               utl_file.file_type;
  su_duns                                       varchar2(10);
  ll_customer_id                                customer.customer_id%type;
  ll_cur_coil                                   coil.coil_abc_num%type;
  ll_gs_log                                     integer;
  ll_st_log                                     integer;
  ls_today                                      varchar2(20) := to_char(sysdate, 'YYYYMMDD');
  ls_now                                        varchar2(20) := to_char(sysdate, 'HH24MI');
  ls_po                                         customer_order.orig_customer_po%type;
  ls_enduser_po                                 customer_order.enduser_po%type;
  ls_finished_goods                             varchar2(32);
  ls_cust_prod_line                             varchar2(8);
  ls_today_2digits_year                         varchar2(20) := to_char(sysdate, 'YYMMDD');
  ld_scrap_870_date                             ab_job.scrap_870_date%type;
  ls_coil_org_num                               coil.coil_org_num%type;
  ls_heat                                       coil.lot_num%type;
  ll_scrap_nw                                   coil.net_wt%type;
  ll_edi_file_id_870                            integer;
  li_hl01                                       integer;
  ls_created_date                               varchar(8);
  ls_vo                                         coil.vo%type;
  ls_lot_num                                    coil.lot_num%type;
  ls_enduser_part                               order_item.enduser_part_num%type;
  ll_parent_coil                                number(8);
  ll_parent_po                                  number(8);
  ll_ab_job_num                                 number(8);
  ls_letter                                     char(1);   --12/23/2019
  ll_sheet_skid_count_4coil                     number(8);
  li_rtn                                        number(4);
  ll_psi_870_count                              number(3);
  ll_coil_gauge                                 coil.coil_gauge%type;
  ll_coil_width                                 coil.coil_width%type;
  ll_part_length                                rectangle.rt_length%type;
  ll_part_width                                 rectangle.rt_width%type;
  ls_finished_goods_material_num                order_item.finished_goods_material_num%type;
  ls_consumed_coil_num                          coil.consumed_coil_num%type;
  ls_material_num                               coil.material_num%type;
  li_sheet_skid_count                           number(3);
  li_count                                      number(2);
  li_split_skid_count                           number(2);
  ll_coil_length_left                           number(10);   --07/24/2023. Extra block for rejected coil
  li_coil_status                                coil.coil_status%type;
  ll_lfeed                                      coil.lfeed%type;
  ll_net_wt                                     coil.net_wt%type;
  ll_net_wt_balance                             coil.net_wt_balance%type;
  
  
  cursor const_870_item_cur is
  select production_sheet_item.ab_job_num,
         production_sheet_item.coil_abc_num,
         production_sheet_item.prod_item_pieces,
         production_sheet_item.prod_item_num,
         sheet_skid.sheet_skid_num,
         production_sheet_item.prod_item_net_wt,
         sheet_skid.skid_sheet_status,
         sheet_skid.sheet_skid_display_num,
         sheet_skid.sheet_net_wt,
         sheet_skid.skid_pieces,
         coil.coil_org_num,
         coil.lot_num,
         nvl(coil.consumed_coil_num, ' ') consumed_coil,
         nvl(coil.material_num, ' ') material_num,
         nvl(customer_order.sales_order, ' ') sales_order,
         nvl(customer_order.orig_customer_po, 'NA') customer_po,
         nvl(order_item.enduser_part_num, ' ') enduser_parts,
         nvl(order_item.cust_prod_line_id, 'NA') customer_line_id,
         nvl(order_item.finished_goods_material_num, 'NA') finished_goods,
         (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
         null done,
         order_item.pieces_skid
  from   production_sheet_item
         join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num       
         join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
         join coil on coil.coil_abc_num = production_sheet_item.coil_abc_num
         join ab_job on production_sheet_item.ab_job_num = ab_job.ab_job_num
         join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
         join order_item on customer_order.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
  where  coil.customer_id = ll_customer_id
  and    ab_job.ab_job_num = al_ab_job_num
  and    customer_order.enduser_po = ls_enduser_po
  and    sheet_skid.skid_sheet_status in (0, 2, 4, 7, 13, 12, 16) -- 2: ready; 8: warehouse ready; 13: partial ready; 7: partial; 12: sample; 4: onhold
                                                                    --alex gerlants. 03/22/2019. added new status 16-hold for cert
  and    production_sheet_item.coil_abc_num = ll_cur_coil
  order by
         sheet_skid.sheet_skid_num
  ;
  
  item_rec  const_870_item_cur%ROWTYPE;

  cursor const_scrap_870_cur is
  select process_coil.coil_abc_num,
         process_coil.process_coil_status,
         process_coil.process_quantity,
         nvl(process_coil.process_end_wt, 0),
         sum(nvl(process_coil.process_end_wt, 0)),
         sum(nvl(production_sheet_item.prod_item_net_wt, 0)),
         case process_coil.process_coil_status
            when 7 then --Rebanded coils
               --(process_coil.process_quantity - sum(production_sheet_item.prod_item_net_wt) - (select process_end_wt from process_coil pc where pc.ab_job_num = 101143 and pc.coil_abc_num = process_coil.coil_abc_num))
               (process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - nvl(process_coil.process_end_wt, 0))
            when 3 then --Rejected coils
               case (select count(*) from production_sheet_item psi where psi.ab_job_num = al_ab_job_num and psi.coil_abc_num = process_coil.coil_abc_num)
                 when 0 then --Rejected coils without sheets
                   (process_coil.process_quantity - sum(nvl(process_coil.process_end_wt, 0)))
                 else --Rejected coils with sheets
                   (process_coil.process_quantity - nvl(process_coil.process_end_wt, 0) - sum(nvl(production_sheet_item.prod_item_net_wt, 0)))     
                end
                
                
                
             else
               (process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - sum(nvl(process_coil.process_end_wt, 0)))
         end scrap_net_wt
  from   process_coil
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         join ab_job on ab_job.ab_job_num = process_coil.ab_job_num and coil.coil_abc_num = process_coil.coil_abc_num
         left outer join production_sheet_item on production_sheet_item.ab_job_num = process_coil.ab_job_num and production_sheet_item.coil_abc_num = process_coil.coil_abc_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    coil.coil_abc_num = ll_cur_coil
  group by
         process_coil.coil_abc_num,
         process_coil.process_coil_status,
         process_coil.process_quantity,
         process_coil.process_end_wt
  order by
         process_coil.coil_abc_num;
  
  scrap_rec  const_scrap_870_cur%ROWTYPE;

  type store_tabletype is table of varchar2(32767) index by binary_integer;
  x12_table store_tabletype;
  
  i         binary_integer := 0;

  type prod_item_type is table of production_sheet_item.prod_item_num%type index by binary_integer;
  item_num prod_item_type;
  
  k        binary_integer := 0;

  type coil_num_type is table of coil.coil_abc_num%type index by binary_integer;
  coil_num coil_num_type;
  
  p binary_integer :=0;


BEGIN
  
  --Check if correct customer
  select  customer_order.orig_customer_id, customer.customer_duns_number_string
  into    ll_customer_id, su_duns
  from    ab_job
          join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
          join customer on customer.customer_id = customer_order.orig_customer_id
  where   ab_job.ab_job_num = al_ab_job_num;
  
  if ll_customer_id <> 2776 then
    return 200; --Wrong customer
  end if;
  
  --Alex Gerlants. 01/08/2021
  --Added this check to avoid sending 870 for jobs that had 870 created by the old batch processing.
  --Check if 870 has already been created for al_ab_job_num using the old data fields
  select count(distinct prod_item_edi870_date)
  into   ll_psi_870_count
  from   production_sheet_item
  where  ab_job_num = al_ab_job_num
  and    coil_abc_num = al_coil_abc_num
  and    prod_item_edi870_date is not null;
  
  --if (not (ll_edi_file_id_870 is null and ld_edi_date_870 is null)) or ll_psi_870_count > 0 then --870 already created for al_ab_job_num
  if ll_psi_870_count > 0 then --870 already created for al_ab_job_num
    return 100;
  end if;

    i              := 0;
    k              := 0;
    p              := 0;

    select customer_order.orig_customer_po, enduser_po
    into   ls_po, ls_enduser_po
    from   ab_job
           join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
    where  ab_job.ab_job_num = al_ab_job_num;

    /*
    select count(distinct coil.coil_abc_num)
    into   ll_item_count
    from   production_sheet_item
           join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num       
           join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
           join coil on coil.coil_abc_num = production_sheet_item.coil_abc_num
           join ab_job on production_sheet_item.ab_job_num = ab_job.ab_job_num
           join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
    where  ab_job.ab_job_num = al_ab_job_num
    and    customer_order.orig_customer_po = ls_po
    and    (
                sheet_skid.skid_sheet_status in (0, 2, 4, 13, 12, 16)
             or sheet_skid.skid_sheet_status is null --This is for rejected coils without sheets  
           )
    ;
    */

    --if (ll_item_count <> 0) then

      select edi_st_log_seq.nextval into ll_st_log from dual;
      select edi_gs_log_seq.nextval into ll_gs_log from dual;

      --select customer.customer_duns_number_string
      --into   su_duns
      --from   customer
      --where  customer.customer_id = ll_customer_id;

       --Production
       x12_table(i) := 'ISA*00*' ||
                      '          *00*          *01*039630926T     *01*043207177      *' ||
                      ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                      lpad(to_char(ll_gs_log), 9, '0') || '*0*P*@~';
      --Development                
      --x12_table(i) := 'ISA*00*' ||
      --            '          *00*          *ZZ*2NDSFTP        *01*043207177      *' ||
      --            ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
      --            lpad(to_char(ll_gs_log), 9, '0') || '*0*T*@~';
      i := i + 1;
      
      --Production
      x12_table(i) := 'GS*RS*039630926T*' || '043207177' || '*' || ls_today || '*' 
                      || ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010~';
                      
      --Development
      --x12_table(1) := 'GS*RS*2NDSFTP*' || '043207177' || '*' || ls_today || '*' ||
      --               ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010~';
      i := i + 1;
      
      x12_table(i) := 'ST*870*' || to_char(ll_st_log) || '~';
      i := i + 1;
      x12_table(i) := 'BSR*2*PA*' || to_char(ll_st_log) || '*' || ls_today ||
                      '***' || ls_now || '*****~';
      i := i + 1;
      
      x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now || '*ED~';
      i := i + 1;
      
      x12_table(i) := 'N1*MF**1*' || su_duns || '~';
      i := i + 1;
      
      x12_table(i) := 'N1*OU*ALUMINUM BLANKING COMPANY*1*039630926~';
      i := i + 1;
 
      li_hl01 := 0;

      --for po_rec in po_cur loop --po loop
          li_hl01 := li_hl01 + 1;

          x12_table(i) := 'HL*' || to_char(li_hl01) || '**O*1~';
          ll_parent_po := li_hl01;
          i := i + 1;
          
          --ls_po := po_rec.orig_customer_po;
          
          select    to_char(max(created_date), 'yyyymmdd')
          into      ls_created_date
          from      customer_order
          where     orig_customer_po = ls_enduser_po;
          
          --ls_created_date := to_char(po_rec.created_date, 'yyyymmdd');
          
          x12_table(i) := 'PRF*' || ls_enduser_po || '*0*0*' || ls_created_date || '~';
          i := i + 1;
          
--********************************* Coil loop begin ***********************************************************          
                        
          --for coil_rec in coil_cur loop    -- coil loop
              --ll_cur_coil := coil_rec.coil_abc_num;
              ll_cur_coil := al_coil_abc_num;
              
              select   coil_org_num
              into     ls_coil_org_num
              from     coil
              where    coil_abc_num = ll_cur_coil;
              
              --ls_coil_org_num := coil_rec.coil_org_num;
              
              select   count(*)
              into     ll_sheet_skid_count_4coil
              from     production_sheet_item
              where    ab_job_num = al_ab_job_num
              and      coil_abc_num = ll_cur_coil;

              coil_num(p) := ll_cur_coil;
              --p := p + 1;
                          
              li_hl01 := li_hl01 + 1;

              x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(ll_parent_po) || '*I*1~';
              ll_parent_coil := li_hl01;
              i := i + 1;
                          
              --x12_table(i) := 'PRF*' || ls_po || '***' || ls_created_date || '~';
              --i := i + 1;
                          
              --x12_table(i) := 'REF*RV*' || ls_coil_org_num || '~';                                      
              x12_table(i) := 'REF*RV*' || to_char(ll_cur_coil) || '~';
              i := i + 1;
              
              select  coil_org_num, consumed_coil_num, material_num, coil.vo, coil.lot_num, coil.coil_gauge, coil.coil_width
              into    ls_coil_org_num, ls_consumed_coil_num, ls_material_num, ls_vo, ls_lot_num, ll_coil_gauge, ll_coil_width
              from    coil
              where   coil_abc_num = al_coil_abc_num;
               
              select  order_item.finished_goods_material_num, enduser_part_num
              into    ls_finished_goods_material_num, ls_enduser_part
              from    ab_job   
                       join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
              where   ab_job.ab_job_num = al_ab_job_num;
               
              x12_table(i) := 'PO1**1*UN**' || '*VO*' || ls_enduser_po || '*SN*' ||
                             ls_coil_org_num || '*HN*' || ls_lot_num || 
                             '*JN*' || substr(ls_enduser_po, 1, instr(ls_vo, '-') - 1) || '*PN*' || ls_enduser_part ||'~';
              i := i + 1 ;

              select count(*)
              into   li_count
              from   production_sheet_item
              join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num       
              join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
              join coil on coil.coil_abc_num = production_sheet_item.coil_abc_num
              join ab_job on production_sheet_item.ab_job_num = ab_job.ab_job_num
              join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
              join order_item on customer_order.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
              where  coil.customer_id = ll_customer_id
              and    ab_job.ab_job_num = al_ab_job_num
              and    customer_order.enduser_po = ls_enduser_po
              and    sheet_skid.skid_sheet_status in (0, 2, 4, 7, 13, 12, 16) -- 2: ready; 8: warehouse ready; 13: partial ready; 7: partial; 12: sample; 4: onhold
                                                                                  --alex gerlants. 03/22/2019. added new status 16-hold for cert
              and    production_sheet_item.coil_abc_num = ll_cur_coil;

              for item_rec in const_870_item_cur loop   -- item loop

                  li_hl01 := li_hl01 + 1;
                  

                  x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(ll_parent_coil) || '*F~';
                  i := i + 1;

                  select nvl(customer_order.enduser_po, 'NA'),
                         nvl(order_item.cust_prod_line_id, 'NA'),
                         nvl(order_item.finished_goods_material_num, 'NA')
                  into   ls_enduser_po, ls_cust_prod_line, ls_finished_goods
                  from   ab_job
                         join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
                         join order_item on customer_order.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
                  where  ab_job.ab_job_num = item_rec.ab_job_num;

                  x12_table(i) := 'PRF*' || ls_enduser_po || '***' || ls_created_date || '~';
                  i := i + 1;
                  
                  -----------------------------------------------------------------------------------------
                  
                  if item_rec.prod_item_pieces >= item_rec.pieces_skid then --Full skid
                    ls_letter := null;
                  else --Partial skid
                    select    count(*)
                    into      li_split_skid_count
                    from      split_skid
                    --where     ab_job_num = al_ab_job_num
                    where     sheet_skid_num = item_rec.sheet_skid_num;
                        
                          
                        
                    if li_split_skid_count <= 0 then --No rows for job and skid
                        ls_letter := 'A';
                        item_rec.sheet_skid_display_num := item_rec.sheet_skid_num || ls_letter;
                            
                        insert into split_skid values
                        (
                           al_ab_job_num,
                           ll_cur_coil,
                           item_rec.sheet_skid_num,
                           item_rec.sheet_skid_display_num,
                           ls_coil_org_num,
                           item_rec.prod_item_net_wt,
                           item_rec.prod_item_pieces,
                           ls_letter
                        );
                            
                        commit;
                    else --There is/are rows for job and skid. Check if there is a row for skid and coil
                          
                         
                      select    count(*)
                      into      li_sheet_skid_count
                      from      split_skid
                      --where     ab_job_num = al_ab_job_num
                      where     sheet_skid_num = item_rec.sheet_skid_num  
                      and       coil_abc_num = ll_cur_coil;
                          
                        
                      if li_sheet_skid_count <= 0 then --There is no row for for job, skid and coil
                        --Identify max(suffix) for 
                        select    max(suffix)
                        into      ls_letter
                        from      split_skid
                        --where     ab_job_num = al_ab_job_num
                        where     sheet_skid_num = item_rec.sheet_skid_num;
                            
                        --Select the next letter to assign to item_rec.sheet_skid_num
                        select    upper(a2.letter)
                        into      ls_letter
                        from      alphabet a1
                                  join alphabet a2 on a2.letter_number = a1.letter_number + 1
                        where     upper(a1.letter) = upper(ls_letter);
                            
                        item_rec.sheet_skid_display_num := item_rec.sheet_skid_num || ls_letter;
                            
                        insert into split_skid values
                        (
                           al_ab_job_num,
                           ll_cur_coil,
                           item_rec.sheet_skid_num,
                           item_rec.sheet_skid_display_num,
                           ls_coil_org_num,
                           item_rec.prod_item_net_wt,
                           item_rec.prod_item_pieces,
                           ls_letter
                        );
                            
                        commit;
                      else--There is a row for for skid, and coil. Just take suffix from this row
                        select    suffix
                        into      ls_letter
                        from      split_skid
                        where     ab_job_num = al_ab_job_num
                        and       coil_abc_num = ll_cur_coil
                        and       sheet_skid_num = item_rec.sheet_skid_num;
                      end if;
                    end if; 
                  end if;
                    
                  -------------------------------------------------------------------------------------------------

                  --if li_split_skid = 0 then --Not a split skid
                  --  x12_table(i) := 'REF*SE*' || to_char(item_rec.sheet_skid_num) || '~';
                  --else --Split skid
                    x12_table(i) := 'REF*SE*' || to_char(item_rec.sheet_skid_num) || ls_letter || '~';
                  --x12_table(i) := 'REF*SE*' || ls_coil_org_num || '~';
                  --end if;
                  i := i + 1;
                              
                  x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now || '*ED~';
                  i := i + 1;
                              
                  x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED~';
                  i := i + 1;
                  
                   
                  select distinct 
                            coil.vo, coil.lot_num, coil.coil_gauge, coil.coil_width, coil.coil_status
                  into      ls_vo, ls_lot_num, ll_coil_gauge, ll_coil_width, li_coil_status
                  from      coil
                            --join inbound_coil_status on inbound_coil_status.coil_number = inbound_coil.coil_number
                  where     coil.coil_abc_num = ll_cur_coil;
             
                  --Take part_num from inbound_coil table instead of order_item table
                  --Select inbound_coil.part_num from the latest BOL
                  select   inbound_coil.part_num
                  into     ls_enduser_part
                  from     inbound_coil
                           join coil on coil.coil_org_num = inbound_coil.coil_number
                  where    coil.coil_abc_num = ll_cur_coil
                  and      inbound_coil.edi_file_id =
                  (
                     select   max(inbound_coil.edi_file_id)
                     from     inbound_coil
                              join coil on coil.coil_org_num = inbound_coil.coil_number
                     where    coil.coil_abc_num = ll_cur_coil
                  );
                        
                  --x12_table(i) := 'PO1**1*UN***VO*' || ls_po || '*SN*' ||
                  --                  to_char(ll_cur_coil) || '*HN*' || ls_lot_num || 
                  --                  '*JN*' || ls_vo || '*PN*' || item_rec.enduser_parts;
                  x12_table(i) := 'PO1**1*UN***VO*' || ls_enduser_po || '*SN*' ||
                                    ls_coil_org_num || '*HN*' || ls_lot_num || 
                                    '*JN*' || substr(ls_enduser_po, 1, instr(ls_vo, '-') - 1) || '*PN*' || ls_enduser_part || '~';
                  i := i + 1;

                  ll_ab_job_num := item_rec.ab_job_num;

                  --x12_table(i) := 'REF*MI*' || to_char(item_rec.ab_job_num) || '~';
                  --i := i + 1;

                  --x12_table(i) := 'REF*RV*' || to_char(item_rec.prod_item_num) ||
                  --                '*NA';
                  --i := i + 1;

                  --x12_table(i) := 'REF*IX*' || to_char(item_rec.consumed_coil);
                  --i := i + 1;
                  
                  IF item_rec.skid_sheet_status = 2 THEN
                    --x12_table(i) := 'PID*S*MA*ST*1***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
                    x12_table(i) := 'PID*S*MA*ST*1***70' || '~';
                    i := i + 1;
                  ELSIF item_rec.skid_sheet_status = 4 THEN
                    --x12_table(i) := 'PID*S*MA*ST*3***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
                    x12_table(i) := 'PID*S*MA*ST*3***70' ||'~';
                    i := i + 1;
                  ELSIF item_rec.skid_sheet_status = 13 THEN
                    --x12_table(i) := 'PID*S*MA*ST*8***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
                    x12_table(i) := 'PID*S*MA*ST*1***70' ||'~';
                    i := i + 1;
                  ELSE
                    --x12_table(i) := 'PID*S*MA*ST*4***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
                    x12_table(i) := 'PID*S*MA*ST*4***70' ||'~';
                    i := i + 1;
                  END IF;
                  
                  x12_table(i) := 'PID*S*MAC*ST*01***67~';
                  i := i + 1;
                              
                  x12_table(i) := 'PID*S*PR*ST*19***66A' ||'~';
                  i := i + 1;

                  --As per Troy. 12/09/2022. Do not include the 2 segments below
                  --x12_table(i) := 'PID*S*DAC*ST*263***73' ||'~';
                  --i := i + 1;
                                             
                  --x12_table(i) := 'PID*S*DAF*ST*1***72' ||'~';
                  --i := i + 1;
                                          
                  x12_table(i) := 'MEA*PD*TH*' || to_char(ll_coil_gauge) ||'*ED~';
                  i := i + 1;
                  
                  select   f_get_part_width_per_job(al_ab_job_num)
                  into     ll_part_width
                  from     dual;
                  
                  --x12_table(i) := 'MEA*PD*WD*' || to_char(ll_coil_width) ||'~';
                  x12_table(i) := 'MEA*PD*WD*' || to_char(ll_part_width) ||'*ED~';
                  i := i + 1;
                  
                  select   f_get_part_length_per_job(al_ab_job_num)
                  into     ll_part_length
                  from     dual;
                  
                  x12_table(i) := 'MEA*PD*LN*' || to_char(ll_part_length) ||'*ED~';
                  i := i + 1;
                              
                  x12_table(i) := 'MEA*WT*WT*' || to_char(item_rec.prod_item_net_wt) || '*01' ||'~';
                  i := i + 1;
                              
                  --x12_table(i) := 'MEA*WT*WT*G*' || to_char(item_rec.skid_gross_wt) || '*01' ||'~';
                  --i := i + 1;
                              
                  x12_table(i) := 'MEA*CT*NA*' || to_char(item_rec.prod_item_pieces) ||
                                  '*PC' ||'~';
                  i := i + 1;

                   item_num(k) := item_rec.prod_item_num;
                  k := k + 1;

              end loop; --for item_rec in const_870_item_cur loop   -- item loop

              select scrap_870_date, coil_org_num, lot_num
              into   ld_scrap_870_date, ls_coil_org_num, ls_heat
              from   coil
              where  coil_abc_num = ll_cur_coil;

              --if (ld_scrap_870_date is null) then  -- scrap not sent

                 for scrap_rec in const_scrap_870_cur loop    -- scrap loop
                    --ll_scrap_nw := scrap_rec.process_quan - scrap_rec.process_end_wt - ll_prime_nw;
                    ll_scrap_nw := scrap_rec.scrap_net_wt;

                    if ll_scrap_nw > 0 then
                      
                       select   coil_status
                       into     li_coil_status
                       from     coil
                       where    coil_abc_num = ll_cur_coil;
                    
                       if li_coil_status = 3 and ll_sheet_skid_count_4coil <= 0 then --ll_cur_coil is a fully scrapped (rejected) coil without good material
                         --li_rtn := f_edi_const_870_reject_4job(al_ab_job_num, ll_cur_coil, as_user_id, as_original_or_resend);
                         li_rtn := 2;
                         
                         --return 1; --TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY
                         
                         continue; --06/19/2020. bypass for fully scrapped coil.
                                   --It is in a separate 870 created in f_edi_novelis_870_scrap_coil()
                       end if;

                       li_hl01 := li_hl01 + 1;

                       --x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*F' ||'~';
                       x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(ll_parent_coil) || '*F' ||'~';
                       i := i + 1;

                       if (ls_po <> ls_finished_goods) and (ls_po <> 'NA' ) then
                          x12_table(i) := 'PRF*' || ls_enduser_po || '***' || ls_created_date ||'~';
                          i := i + 1;
                       end if;

                       x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now || '*ED' ||'~';
                       i := i + 1;
                                            
                       x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED' ||'~';
                       i := i + 1;

                        --x12_table(i) := 'PO1**1*UN****' || '***SN*' || scrap_rec.coil_org_num ;
                                            
                        --ls_temp := 'PO1**1*UN**' || '*VO*' || ls_po || '*SN*' ||
                        --      ls_coil_org_num || '*HN*' || ls_lot_num || 
                        --      '*JN*' || ls_vo ||'~';
                                            
                        x12_table(i) := 'PO1**1*UN**' || '*VO*' || ls_enduser_po || '*SN*' ||
                              ls_coil_org_num || '*HN*' || ls_lot_num || 
                              '*JN*' || substr(ls_enduser_po, 1, instr(ls_enduser_po, '-') - 1) ||'~';
                        i := i + 1;
                        
                        x12_table(i) := 'PID*S*MA*ST*S***70~';
                        i := i + 1;

                        x12_table(i) := 'PID*S*MAC*ST*05***67' ||'~'; --65 means process scrap
                        i := i + 1;
                                            
                        x12_table(i) := 'PID*S*PR*ST*14***66A' ||'~';
                        i := i + 1;
                                             
                        x12_table(i) := 'PID*S*DAC*ST*263***73' ||'~';
                        i := i + 1;
                                             
                        x12_table(i) := 'PID*S*DAF*ST*1***72' ||'~';
                        i := i + 1;

                        x12_table(i) := 'MEA*WT*WT*' || to_char(ll_scrap_nw) || '*01' ||'~';
                        i := i+1;
                    end if; --if ll_scrap_nw > 0 then
                        
                 end loop; --for scrap_rec in const_scrap_870_cur loop
                 
                 if li_coil_status = 3 and ll_sheet_skid_count_4coil <= 0 then --No sheets for coil ll_cur_coil is a fully scrapped (rejected
                   return li_rtn; --870 for rejected coil is created in f_edi_const_870_reject_4job() called above
                 --07/24/2023. Extra block for rejected coil. Begin
                 --elsif li_coil_status = 3 and ll_sheet_skid_count_4coil > 0 then --ll_cur_coil is scrapped (rejected) with good material
                 elsif (li_coil_status = 3 or li_coil_status = 7) and ll_sheet_skid_count_4coil > 0 then --ll_cur_coil is scrapped (rejected) or rebanded with good material
                   li_hl01 := li_hl01 + 1;
                   
                   x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(ll_parent_coil) || '*F' ||'~';
                   i := i + 1;
                   
                   x12_table(i) := 'PRF*' || ls_enduser_po || '***' || ls_created_date || '~';
                   i := i + 1;
                   
                   x12_table(i) := 'REF*SE*' || to_char(al_coil_abc_num) || '~'; --???. This is production_sheet_item.prod_item_num
                   i := i + 1;
                   
                   x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now || '*ED~';
                   i := i + 1;
                   
                   x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED~';
                   i := i + 1;
                   
                   x12_table(i) := 'PO1**1*UN***VO*' || ls_enduser_po || '*SN*' ||
                                    ls_coil_org_num || '*HN*' || ls_lot_num || 
                                    '*JN*' || substr(ls_enduser_po, 1, instr(ls_enduser_po, '-') - 1) || '*PN*' || ls_enduser_part || '~';
                   i := i + 1;
                   
                   x12_table(i) := 'PID*S*MA*ST*7***68~';
                   i := i + 1;
                   
                   x12_table(i) := 'PID*S*MAC*ST*01***67~';
                   i := i + 1;
                   
                   x12_table(i) := 'PID*S*PR*ST*19***66A~';
                   i := i + 1;
                   
                   x12_table(i) := 'MEA*PD*TH*' || to_char(ll_coil_gauge) ||'*ED~';
                   i := i + 1;
                   
                   x12_table(i) := 'MEA*PD*WD*' || to_char(ll_part_width) ||'*ED~';
                   i := i + 1;
                   
                   select  coil.net_wt_balance, lfeed, net_wt
                   into    ll_net_wt_balance, ll_lfeed, ll_net_wt
                   from    coil
                   where   coil_abc_num = al_coil_abc_num;
                   
                   --ll_coil_length_left := 7764; --Troy has to provide formula to calculate ll_coil_length_left
                   ll_coil_length_left := ll_net_wt_balance / ll_net_wt * ll_lfeed;
                   
                   x12_table(i) := 'MEA*PD*LN*' || to_char(ll_coil_length_left) || '*LF~';
                   i := i + 1;
                   
                   --If li_coil_status = 3 then --Rejected coil
                   --   x12_table(i) := 'MEA*WT*WT*' || to_char(ll_net_wt_balance) || '*01' ||'~';
                   --else --li_coil_status = 7 <==Rebanded coil
                   --   x12_table(i) := 'MEA*WT*WT*' || to_char(ll_net_wt_balance) || '*01' ||'~';
                   --end if;
                   
                   x12_table(i) := 'MEA*WT*WT*' || to_char(ll_net_wt_balance) || '*01' ||'~';
                   i := i + 1;
                 --07/24/2023. Extra block for rejected coil. End
                 end if;
                    
              --end if; --if (ld_scrap_870_date is null) then
          --end loop; --for coil_rec in coil_cur loop
          
--********************************* Coil loop end ***********************************************************          
          
      --end loop; --for po_rec in po_cur loop
     
     
     
      x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) ||'~';
      i := i + 1;
      x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log) ||'~';
      i := i + 1;
      x12_table(i) := 'GE*1*' || to_char(ll_gs_log) ||'~';
      i := i + 1;
      x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0') ||'~';

      -- Write EDI to file

      if li_hl01 > 1 then
        -- write edi file only if item > 0
        select edi_file_id_seq.nextval
          into ll_edi_file_id_870
          from dual;
     -- edi_file        := edi_file_prefix || to_char(ll_edi_file_id_870) || '.edi';
     -- edi_file        := 's_const_' || to_char(ll_edi_file_id_870) || '.870';
        edi_file        := edi_file_prefix || to_char(ll_edi_file_id_870) || '_Job-' || to_char(al_ab_job_num) || '.edi';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        for j in 0 .. i loop
          utl_file.put_line(edi_file_handle, x12_table(j));
        end loop;
        
        utl_file.fclose(edi_file_handle);
      end if; -- end writing edi file

      --edi_file        := 'send_edi_log'; /* Alex Gerlants. 04/14/2017. Commented out. */
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      --For verifying 997
      
      insert into outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
      values
          (ll_edi_file_id_870,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           SYSDATE,
           edi_file,
           0,
           ll_customer_id,
           ll_st_log,
           '870');
           
      --update    ab_job
      --set       edi_file_id_870 = ll_edi_file_id_870,
      --          edi_date_870 = sysdate
      --where     ab_job_num = al_ab_job_num;
 
     
      insert into ab_job_870_history
      (
         ab_job_num,
         edi_file_id,
         edi_file_name,
         create_870_date_time,
         user_id,
         notes
      )
      values
      (
         al_ab_job_num ,
         ll_edi_file_id_870,
         edi_file,
         sysdate,
         as_user_id,
         as_original_or_resend
      );

        update    ab_job
        set       edi_file_id_870 = ll_edi_file_id_870,
                  edi_date_870 = sysdate
        where     ab_job_num = al_ab_job_num;  

       --FOR m IN 0 .. k - 1 LOOP
         UPDATE production_sheet_item
         SET    prod_item_edi870_date = SYSDATE,
                edi_file_id_870 = ll_edi_file_id_870
         --WHERE  production_sheet_item.prod_item_num = item_num(m);
         WHERE  ab_job_num = al_ab_job_num
         and    production_sheet_item.coil_abc_num = al_coil_abc_num;
       --END LOOP;

        --FOR m in 0..p - 1 LOOP
          UPDATE coil
					SET    coil.scrap_870_date = sysdate
          --WHERE  coil.coil_abc_num = coil_num(m);
          WHERE  coil.coil_abc_num = al_coil_abc_num;

          UPDATE process_coil
					SET    scrap_870_date = sysdate
          --WHERE  ( coil_abc_num = coil_num(m)) AND (scrap_870_date is NULL);
          where  process_coil.coil_abc_num = al_coil_abc_num;
         --END LOOP;

        commit;
        
    --end if; --end if in select count(*)

return 1;


EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN -1;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN -2;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN -3;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN -4;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN -5;
END;
--------------------------------------------------------
--  DDL for Function F_EDI_CONST_870_PER_JOB
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_CONST_870_PER_JOB" 
 ( 
    al_ab_job_num  ab_job.ab_job_num%type,
    as_user_id     ab_job_870_history.user_id%type
    
 )
  return integer
  
is

  /*
  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   Customer: Aleris(1980) DUNS:964790856     EDI ID:964790856      QUALIFIER: ZZ

   End User: Aleris, Customer ID 1980
   */

  --alex gerlants. 11/15/2016. commented out, and added the line after.
  --edi_loc               varchar2(50) := '/templar/templar/incoming/senddata';
  edi_loc                varchar2(50) := get_edi_destination('EDI_DIR');

  edi_file               varchar2(50) := 'edi_out.txt';
  --edi_file_prefix       varchar2(50) := 'S_constellium_870_';   --production
  edi_file_prefix        varchar2(50) := 's_constellium_870_';   --development
  edi_file_handle        utl_file.file_type;
  su_duns                varchar2(10);
  ll_customer_id         customer.customer_id%type;
  ll_cur_coil            coil.coil_abc_num%type;

--  ll_cur_job ab_job.ab_job_num%type;

  ll_gs_log              integer;
  ll_st_log              integer;

  ls_today               varchar2(20) := to_char(sysdate, 'YYYYMMDD');
  ls_today_4             varchar2(20) := to_char(sysdate, 'YYMMDD');
  ls_now                 varchar2(20) := to_char(sysdate, 'HH24MI');

  ls_po                  varchar2(20);
  ls_finished_goods      varchar2(32);
  ls_cust_prod_line      varchar2(8);
  ls_today_2digits_year  varchar2(20) := to_char(sysdate, 'YYMMDD');

  ld_scrap_870_date      ab_job.scrap_870_date%type;

  ls_coil_org_num        coil.coil_org_num%type;
  ls_heat                coil.lot_num%type;

--  ll_ref_order_abc_num sheet_skid.ref_order_abc_num%type;
--  ll_ref_order_abc_item sheet_skid.ref_order_abc_item%type;
--  ls_sheet_type order_item.sheet_type%type;

  ll_prime_nw            coil.net_wt%type;
  ll_scrap_nw            coil.net_wt%type;
--  ll_process_quantity  coil.net_wt%type;
--  ll_process_end_wt  coil.net_wt%type;
--  lr_theo_unit_wt order_item.theoretical_unit_wt%type;

  --ll_edi_file_id_870 integer;
  ll_edi_file_id_870     integer;

  ll_item_count          integer;

  li_hl01                integer;
  li_hllin               integer;
  ls_enduser_id          customer_order.enduser_id%type;
  ls_orig_customer_po    customer_order.orig_customer_po%type;
  ls_enduser_po          customer_order.enduser_po%type;
  ls_created_date        varchar(8);
  ls_vo                  coil.vo%type;
  ls_lot_num             coil.lot_num%type;
  ls_enduser_parts       order_item.enduser_part_num%type;
  
  ls_temp                varchar(256);
  ll_parent_coil         number(8);
  ll_parent_po           number(8);
  ll_ab_job_num          number(8);
  
  ls_letter              char(1);   --12/23/2019
  ls_suffix              char(1);   --12/23/2019
  li_letter_number       number(2); --12/23/2019
  ls_enduser_part_num    order_item.enduser_part_num%type;
  ls_coil_gauge          varchar(10);
  ls_lineal_feed         varchar(20);
  li_coil_count          number(2);
  ls_coil_width          varchar(20);

  --cursor cust_cur is
  --  select customer_id from customer where customer_id in (2776); ---add customer id here if you want to send 870 for more customers

  cursor po_cur is
  --select distinct customer_order.orig_customer_po, co.created_date
  select distinct customer_order.orig_customer_po
  from   production_sheet_item
         join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num       
         join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
         join coil on coil.coil_abc_num = production_sheet_item.coil_abc_num
         join ab_job on production_sheet_item.ab_job_num = ab_job.ab_job_num
         join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
  where  ab_job.ab_job_num = al_ab_job_num
  and    (
              sheet_skid.skid_sheet_status in (0, 2, 4, 13, 12, 16)
           or sheet_skid.skid_sheet_status is null --This is for rejected coils without sheets  
         );
         
  po_rec    po_cur%ROWTYPE;
         
/*    
  where (ab.job_status = 0) and
    ( c.coil_status in (0, 3) ) and
    ( co.orig_customer_id = ll_customer_id ) and
    ( psi.prod_item_edi870_date is null ) and
    ( c.scrap_870_date is null ) and
    ( sk.skid_sheet_status in (0,2,4,12,13, 16) );
*/
    
  cursor skid_cur is
  select distinct sheet_skid.sheet_skid_num
  from   production_sheet_item
         join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num       
         join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
         join coil on coil.coil_abc_num = production_sheet_item.coil_abc_num
         join ab_job on production_sheet_item.ab_job_num = ab_job.ab_job_num
         join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
  where  ab_job.ab_job_num = al_ab_job_num
  and    coil.coil_abc_num = ll_cur_coil
  order by
         production_sheet_item.coil_abc_num,
         sheet_skid.sheet_skid_display_num;
         
  skid_rec  skid_cur%ROWTYPE;
    
/*    
  where (ab.job_status = 0) and
    ( c.coil_status in (0, 3) ) and
    ( co.orig_customer_id = ll_customer_id ) and
    ( psi.prod_item_edi870_date is null ) and
    ( c.scrap_870_date is null ) and
    ( sk.skid_sheet_status in (0,2,4,12,13, 16) )
    and ( co.orig_customer_po = ls_po );  --Alex. 12/05/2019
*/

    
  cursor coil_cur is
  select distinct coil.coil_abc_num,
         coil.coil_org_num,
         coil.lot_num,
         to_char(coil.coil_gauge) coil_gauge,
         to_char(coil_width) coil_width,
         customer_order.orig_customer_po,
         order_item.enduser_part_num
  from   production_sheet_item
         join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num       
         join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
         join coil on coil.coil_abc_num = production_sheet_item.coil_abc_num
         join ab_job on production_sheet_item.ab_job_num = ab_job.ab_job_num
         join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
         join order_item on customer_order.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
  where  ab_job.ab_job_num = al_ab_job_num
  and    customer_order.orig_customer_po = ls_po
  and    (
              sheet_skid.skid_sheet_status in (0, 2, 4, 13, 12, 16)
           or sheet_skid.skid_sheet_status is null --This is for rejected coils without sheets  
         )
  ;
  
  coil_rec  coil_cur%ROWTYPE;

  cursor const_870_item_cur is
  select production_sheet_item.ab_job_num,
         production_sheet_item.coil_abc_num,
         production_sheet_item.prod_item_pieces,
         production_sheet_item.prod_item_num,
         sheet_skid.sheet_skid_num,
         production_sheet_item.prod_item_net_wt,
         sheet_skid.skid_sheet_status,
         sheet_skid.sheet_skid_display_num,
         sheet_skid.sheet_net_wt,
         sheet_skid.skid_pieces,
         coil.coil_org_num,
         coil.lot_num,
         nvl(coil.consumed_coil_num, ' ') consumed_coil,
         nvl(coil.material_num, ' ') material_num,
         nvl(customer_order.sales_order, ' ') sales_order,
         nvl(customer_order.orig_customer_po, 'NA') customer_po,
         nvl(order_item.enduser_part_num, ' ') enduser_parts,
         nvl(order_item.cust_prod_line_id, 'NA') customer_line_id,
         nvl(order_item.finished_goods_material_num, 'NA') finished_goods,
         (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
         null done,
         order_item.pieces_skid
  from   production_sheet_item
         join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num       
         join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
         join coil on coil.coil_abc_num = production_sheet_item.coil_abc_num
         join ab_job on production_sheet_item.ab_job_num = ab_job.ab_job_num
         join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
         join order_item on customer_order.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
  where  coil.customer_id = ll_customer_id
  and    ab_job.ab_job_num = al_ab_job_num
  and    customer_order.orig_customer_po = ls_po
  and    sheet_skid.skid_sheet_status in (0, 2, 4, 13, 12, 16) -- 2: ready; 8: warehouse ready; 13: partial ready; 7: partial; 12: sample; 4: onhold
                                                                    --alex gerlants. 03/22/2019. added new status 16-hold for cert
  and    production_sheet_item.coil_abc_num = ll_cur_coil
  and    production_sheet_item.prod_item_edi870_date is null
  order by
         sheet_skid.sheet_skid_num
  ;
  
  item_rec  const_870_item_cur%ROWTYPE;

  cursor const_scrap_870_cur is
  select process_coil.coil_abc_num,
         process_coil.process_coil_status,
         process_coil.process_quantity,
         nvl(process_coil.process_end_wt, 0),
         sum(nvl(process_coil.process_end_wt, 0)),
         sum(nvl(production_sheet_item.prod_item_net_wt, 0)),
         case process_coil.process_coil_status
            when 7 then --Rebanded coils
               --(process_coil.process_quantity - sum(production_sheet_item.prod_item_net_wt) - (select process_end_wt from process_coil pc where pc.ab_job_num = 101143 and pc.coil_abc_num = process_coil.coil_abc_num))
               (process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - nvl(process_coil.process_end_wt, 0))
            when 3 then --Rejected coils
               case (select count(*) from production_sheet_item psi where psi.ab_job_num = al_ab_job_num and psi.coil_abc_num = process_coil.coil_abc_num)
                 when 0 then --Rejected coils without sheets
                   (process_coil.process_quantity - sum(nvl(process_coil.process_end_wt, 0)))
                 else --Rejected coils with sheets
                   (process_coil.process_quantity - nvl(process_coil.process_end_wt, 0) - sum(nvl(production_sheet_item.prod_item_net_wt, 0)))     
                end   
             else
               (process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - sum(nvl(process_coil.process_end_wt, 0)))
         end scrap_net_wt
  from   process_coil
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         join ab_job on ab_job.ab_job_num = process_coil.ab_job_num and coil.coil_abc_num = process_coil.coil_abc_num
         left outer join production_sheet_item on production_sheet_item.ab_job_num = process_coil.ab_job_num and production_sheet_item.coil_abc_num = process_coil.coil_abc_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    coil.coil_abc_num = ll_cur_coil
  group by
         process_coil.coil_abc_num,
         process_coil.process_coil_status,
         process_coil.process_quantity,
         process_coil.process_end_wt
  order by
         process_coil.coil_abc_num;
  
  scrap_rec  const_scrap_870_cur%ROWTYPE;

  type store_tabletype is table of varchar2(32767) index by binary_integer;
  x12_table store_tabletype;
  
  i         binary_integer := 0;

  type prod_item_type is table of production_sheet_item.prod_item_num%type index by binary_integer;
  item_num prod_item_type;
  
  k        binary_integer := 0;

  type coil_num_type is table of coil.coil_abc_num%type index by binary_integer;
  coil_num coil_num_type;
  
  p binary_integer :=0;


BEGIN
  
  --Check if correct customer
  select  customer_order.orig_customer_id, customer.customer_duns_number_string, customer.customer_id
  into    ll_customer_id, su_duns, ll_customer_id
  from    ab_job
          join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
          join customer on customer.customer_id = customer_order.orig_customer_id
  where   ab_job.ab_job_num = al_ab_job_num;
  
  if ll_customer_id <> 2776 then
    return 200; --Wrong customer
  end if;
  
  --delete from sheet_skid_display_num; --12/23/2019

  --for cust_rec in cust_cur loop
    --- outer loop of customer_id
    --ll_customer_id := cust_rec.customer_id;
    i              := 0;
    k              := 0;
    p              := 0;

    select count(distinct coil.coil_abc_num)
    into   ll_item_count
    from   production_sheet_item
           join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num       
           join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
           join coil on coil.coil_abc_num = production_sheet_item.coil_abc_num
           join ab_job on production_sheet_item.ab_job_num = ab_job.ab_job_num
           join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
    where  ab_job.ab_job_num = al_ab_job_num
    and    (
                sheet_skid.skid_sheet_status in (0, 2, 4, 13, 12, 16)
             or sheet_skid.skid_sheet_status is null --This is for rejected coils without sheets  
           )
    ;

    if (ll_item_count <> 0) then

      select edi_st_log_seq.nextval into ll_st_log from dual;
      select edi_gs_log_seq.nextval into ll_gs_log from dual;

      --select customer.customer_duns_number_string
      --into   su_duns
      --from   customer
      --where  customer.customer_id = ll_customer_id;

      --Production
      --x12_table(i) := 'ISA*00*' ||
      --                '          *00*          *01*043207177      *01*043207177      *' ||
      --                ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
      --                lpad(to_char(ll_gs_log), 9, '0') || '*0*P**~';
      --Development                
      x12_table(i) := 'ISA*00*' ||
                  '          *00*          *ZZ*2NDSFTP        *01*043207177      *' ||
                  ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                  lpad(to_char(ll_gs_log), 9, '0') || '*0*T**~';
      i := i + 1;
      
      --Production
      --x12_table(i) := 'GS*RS*039630926T*' || '043207177' || '*' || ls_today || '*' 
      --                || ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010~';
                      
      --Development
      x12_table(1) := 'GS*SH*2NDSFTP*' || '043207177' || '*' || ls_today || '*' ||
                     ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010~';
      i := i + 1;
      
      x12_table(i) := 'ST*870*' || to_char(ll_st_log) || '~';
      i := i + 1;
      x12_table(i) := 'BSR*2*PA*' || to_char(ll_st_log) || '*' || ls_today ||
                      '***' || ls_now || '*****~';
      i := i + 1;
      
      x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
      i := i + 1;
      
      x12_table(i) := 'N1*MF**1*' || su_duns || '~';
      i := i + 1;
      
      x12_table(i) := 'N1*OU**1*039630926~';
      i := i + 1;
 
      li_hl01 := 0;

      for po_rec in po_cur loop --PO loop
          li_hl01 := li_hl01 + 1;

          x12_table(i) := 'HL*' || to_char(li_hl01) || '**O~';
          ll_parent_po := li_hl01;
          i := i + 1;
          
          ls_po := po_rec.orig_customer_po;
          
          select    to_char(max(created_date), 'yyyymmdd')
          into      ls_created_date
          from      customer_order
          where     orig_customer_po = ls_po;
          
          --ls_created_date := to_char(po_rec.created_date, 'yyyymmdd');
          
          x12_table(i) := 'PRF*' || ls_po || '*0*0*' || ls_created_date || '~';
          i := i + 1;
                        
          for coil_rec in coil_cur loop    -- coil loop
              ll_cur_coil := coil_rec.coil_abc_num;
              ls_coil_org_num := coil_rec.coil_org_num;
              ls_orig_customer_po := coil_rec.orig_customer_po;
              ls_lot_num := coil_rec.lot_num;
              ls_coil_gauge := coil_rec.coil_gauge;
              ls_coil_width := coil_rec.coil_width;
              ls_enduser_part_num := coil_rec.enduser_part_num; 
              
              select   count(*)
              into     li_coil_count
              from     inbound_coil
              where    coil_number = ls_coil_org_num;
              
              if li_coil_count > 0 then
                  select   ltrim(rtrim(to_char(lineal_feed, '9999999999')))
                  into     ls_lineal_feed
                  from     inbound_coil
                  where    coil_number = ls_coil_org_num;
              else
                  ls_lineal_feed := 'NA';
              end if;

              coil_num(p) := ll_cur_coil;
              p := p + 1;
                          
              li_hl01 := li_hl01 + 1;

              x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(ll_parent_po) || '*I~';
              ll_parent_coil := li_hl01;
              i := i + 1;
                          
              x12_table(i) := 'PRF*' || ls_po || '***' || ls_created_date || '~';
              i := i + 1;
                          
              --x12_table(i) := 'REF*RV*' || ls_coil_org_num || '~';                                      
              x12_table(i) := 'REF*RV*' || to_char(ll_cur_coil) || '~';
              i := i + 1;
              
              --                      customer_order.    coil.      coil.    order_item.
              --                     orig_customer_po coil_org_num   lot  enduser_part_num
              --Example: PO1**1*UN***VO*124985-83808*SN*26420AA*HN*224273***PN*KB3B16854~
              x12_table(i) := 'PO1**1*UN***VO*' || ls_orig_customer_po || '*SN*' || ls_coil_org_num ||
                         '*HN*' || ls_lot_num || '***PN*' || ls_enduser_part_num || '~';
              i := i + 1;

              for item_rec in const_870_item_cur loop   -- item loop

                  li_hl01 := li_hl01 + 1;

                  x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(ll_parent_coil) || '*F~';
                  i := i + 1;

                  select nvl(customer_order.orig_customer_po, 'NA'),
                         nvl(order_item.cust_prod_line_id, 'NA'),
                         nvl(order_item.finished_goods_material_num, 'NA')
                  into   ls_po, ls_cust_prod_line, ls_finished_goods
                  from   ab_job
                         join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
                         join order_item on customer_order.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
                  where  ab_job.ab_job_num = item_rec.ab_job_num;

                  x12_table(i) := 'PRF*' || ls_po || '***' || ls_created_date || '~';
                  i := i + 1;
                  
                  --12/23/2019. Begin
                  if item_rec.skid_pieces > item_rec.prod_item_pieces and item_rec.skid_sheet_status <> 13 then
                      select    max(sheet_skid_display_num_suffix)
                      into      ls_suffix
                      from      sheet_skid
                      where     sheet_skid_display_num = item_rec.sheet_skid_display_num;
                      
                      if ls_suffix is null then
                        ls_letter := 'A';
                      else
                        --select   letter_number + 1
                        --into     li_letter_number
                        --from     alphabet
                        --where    upper(letter) = upper(ls_suffix);              
                        --
                        --select    upper(letter)
                        --into      ls_letter
                        --from      alphabet
                        --where     letter_number = li_letter_number;
                         
                        select    upper(a2.letter)
                        into      ls_letter
                        from      alphabet a1
                                  join alphabet a2 on a2.letter_number = a1.letter_number + 1
                        where     upper(a1.letter) = upper(ls_suffix);
                      end if;
                     
                      update      sheet_skid
                      set         sheet_skid_display_num_suffix = ls_letter
                      where       sheet_skid_display_num = item_rec.sheet_skid_display_num;
                      
                      item_rec.sheet_skid_display_num := item_rec.sheet_skid_display_num || ls_letter;
                  end if; --if item_rec.skid_pieces > item_rec.prod_item_pieces and item_rec.skid_sheet_status <> 13 then
                  --12/23/2019. End

                  x12_table(i) := 'REF*SE*' || to_char(item_rec.sheet_skid_display_num) || '~';
                  --x12_table(i) := 'REF*SE*' || ls_coil_org_num || '~';
                  i := i + 1;
                              
                  x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now || '*ED~';
                  i := i + 1;
                              
                  x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED~';
                  i := i + 1;
                  
                   
                  select distinct 
                            coil.vo, coil.lot_num
                  into      ls_vo, ls_lot_num
                  from      coil
                            --join inbound_coil_status on inbound_coil_status.coil_number = inbound_coil.coil_number
                  where     coil.coil_abc_num = ll_cur_coil;
             
                        
                  --x12_table(i) := 'PO1**1*UN***VO*' || ls_po || '*SN*' ||
                  --                  to_char(ll_cur_coil) || '*HN*' || ls_lot_num || 
                  --                  '*JN*' || ls_vo || '*PN*' || item_rec.enduser_parts;
                  x12_table(i) := 'PO1**1*UN***VO*' || ls_po || '*SN*' ||
                                    ls_coil_org_num || '*HN*' || ls_lot_num || 
                                    '*JN*' || ls_vo || '*PN*' || item_rec.enduser_parts || '~';
                  i := i + 1;

                  ll_ab_job_num := item_rec.ab_job_num;

                  --x12_table(i) := 'REF*MI*' || to_char(item_rec.ab_job_num);
                  --i := i + 1;

                  --x12_table(i) := 'REF*RV*' || to_char(item_rec.prod_item_num) ||
                  --                '*NA';
                  --i := i + 1;

                  --x12_table(i) := 'REF*IX*' || to_char(item_rec.consumed_coil);
                  --i := i + 1;

                  x12_table(i) := 'PID*S*MAC*ST*01***67~';
                  i := i + 1;

                  IF item_rec.skid_sheet_status = 2 THEN
                    --x12_table(i) := 'PID*S*MA*ST*1***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
                    x12_table(i) := 'PID*S*MA*ST*1***70' || '~';
                    i := i + 1;
                  ELSIF item_rec.skid_sheet_status = 4 THEN
                    --x12_table(i) := 'PID*S*MA*ST*3***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
                    x12_table(i) := 'PID*S*MA*ST*3***70' ||'~';
                    i := i + 1;
                  ELSIF item_rec.skid_sheet_status = 13 THEN
                    --x12_table(i) := 'PID*S*MA*ST*8***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
                    x12_table(i) := 'PID*S*MA*ST*8***70' ||'~';
                    i := i + 1;
                   ELSE
                    --x12_table(i) := 'PID*S*MA*ST*4***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
                    x12_table(i) := 'PID*S*MA*ST*4***70' ||'~';
                    i := i + 1;
                  END IF;
                              
                  x12_table(i) := 'PID*S*PR*ST*19***66A' ||'~';
                  i := i + 1;
                  
                  x12_table(i) := 'PID*S*DAC*ST*598***73' ||'~';
                  i := i + 1;
                  
                  x12_table(i) := 'PID*S*DAF*ST*1***72~' ||'~';
                  i := i + 1;
                  
                  --ls_coil_gauge
                  
                  x12_table(i) := 'MEA*PD*TH*' || ls_coil_gauge || '*ED' ||'~';
                  i := i + 1;
                  
                  x12_table(i) := 'MEA*PD*WD*' || ls_coil_width || '*ED' ||'~';
                  i := i + 1;
                  
                  x12_table(i) := 'MEA*PD*LN*' || ls_lineal_feed || '*ED' ||'~';
                  i := i + 1;
                              
                  x12_table(i) := 'MEA*WT*WT*' || to_char(item_rec.prod_item_net_wt) || '*01' ||'~';
                  i := i + 1;
                              
                  --x12_table(i) := 'MEA*WT*WT*G*' || to_char(item_rec.skid_gross_wt) || '*01' ||'~';
                  --i := i + 1;
                              
                  --x12_table(i) := 'MEA*CT*NA*' || to_char(item_rec.prod_item_pieces) ||
                  --                '*PC' ||'~';
                  --i := i + 1;

                   item_num(k) := item_rec.prod_item_num;
                  k := k + 1;

              end loop; --for item_rec in const_870_item_cur loop   -- item loop

              select scrap_870_date, coil_org_num, lot_num
              into   ld_scrap_870_date, ls_coil_org_num, ls_heat
              from   coil
              where  coil_abc_num = ll_cur_coil;

              if (ld_scrap_870_date is null) then  -- scrap not sent

                 for scrap_rec in const_scrap_870_cur loop    -- scrap loop
                    --ll_scrap_nw := scrap_rec.process_quan - scrap_rec.process_end_wt - ll_prime_nw;
                    ll_scrap_nw := scrap_rec.scrap_net_wt;

                    if ll_scrap_nw > 0 then

                       li_hl01 := li_hl01 + 1;

                       --x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*F' ||'~';
                       x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(ll_parent_coil) || '*F' ||'~';
                       i := i + 1;
                       
                       x12_table(i) := 'PRF*NA***' || ls_today ||'~';
                       i := i + 1;

                       if (ls_po <> ls_finished_goods) and (ls_po <> 'NA' ) then
                          x12_table(i) := 'PRF*' || ls_po || '***' || ls_created_date ||'~';
                          i := i + 1;
                       end if;

                       x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now || '*ED' ||'~';
                       i := i + 1;
                                            
                       x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED' ||'~';
                       i := i + 1;

                        --x12_table(i) := 'PO1**1*UN****' || '***SN*' || scrap_rec.coil_org_num ;
                                            
                        --ls_temp := 'PO1**1*UN**' || '*VO*' || ls_po || '*SN*' ||
                        --      ls_coil_org_num || '*HN*' || ls_lot_num || 
                        --      '*JN*' || ls_vo ||'~';
                                            
                        x12_table(i) := 'PO1**1*UN**' || '*VO*' || ls_vo || '*SN*' ||
                              ls_coil_org_num || '*HN*' || ls_lot_num || 
                              '*JN*' || ls_vo ||'~';
                        i := i + 1;

                        x12_table(i) := 'PID*S*MAC*ST*05***67' ||'~';
                        i := i + 1;
                                            
                        x12_table(i) := 'PID*S*PR*ST*14***66A' ||'~';
                        i := i + 1;
                                             
                        x12_table(i) := 'PID*S*DAC*ST*263***73' ||'~';
                        i := i + 1;
                                             
                        x12_table(i) := 'PID*S*DAF*ST*1***72' ||'~';
                        i := i + 1;

                        x12_table(i) := 'MEA*WT*WT*' || to_char(ll_scrap_nw) || '*01' ||'~';
                        i := i+1;
                    end if; --if ll_scrap_nw > 0 then
                 end loop; --for scrap_rec in const_scrap_870_cur loop
              end if; --if (ld_scrap_870_date is null) then
          end loop; --for coil_rec in coil_cur loop
      end loop; --for po_rec in po_cur loop
     
     
     
      x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) ||'~';
      i := i + 1;
      x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log) ||'~';
      i := i + 1;
      x12_table(i) := 'GE*1*' || to_char(ll_gs_log) ||'~';
      i := i + 1;
      x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0') ||'~';

      -- Write EDI to file

      if li_hl01 > 1 then
        -- write edi file only if item > 0
        select edi_file_id_seq.nextval
          into ll_edi_file_id_870
          from dual;
        edi_file        := edi_file_prefix || to_char(ll_edi_file_id_870) || '_Job-' || to_char(al_ab_job_num) || '.edi';
     -- edi_file        := 's_const_' || to_char(ll_edi_file_id_870) || '.870';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        for j in 0 .. i loop
          utl_file.put_line(edi_file_handle, x12_table(j));
        end loop;
        
        utl_file.fclose(edi_file_handle);
      end if; -- end writing edi file

      --edi_file        := 'send_edi_log'; /* Alex Gerlants. 04/14/2017. Commented out. */
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      --For verifying 997
/*      
      insert into outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
      values
          (ll_edi_file_id_870,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           SYSDATE,
           edi_file,
           0,
           ll_customer_id,
           ll_st_log,
           '870');
           
      update    ab_job
      set       edi_file_id_870 = ll_edi_file_id_870_870,
                edi_date_870 = sysdate
      where     ab_job_num = al_ab_job_num;
*/ 
     
      insert into ab_job_870_history
      (
         ab_job_num,
         edi_file_id,
         edi_file_name,
         create_870_date_time,
         user_id
      )
      values
      (
         al_ab_job_num ,
         ll_edi_file_id_870,
         edi_file,
         sysdate,
         as_user_id
      );

/*           

     FOR m IN 0 .. k - 1 LOOP
       UPDATE production_sheet_item
           SET prod_item_edi870_date = SYSDATE,
               edi_file_id_870 = ll_edi_file_id_870
         WHERE production_sheet_item.prod_item_num = item_num(m);
    END LOOP;

        FOR m in 0..p - 1 LOOP
                UPDATE coil
					SET coil.scrap_870_date = sysdate
                WHERE coil.coil_abc_num = coil_num(m);

               UPDATE process_coil
					SET scrap_870_date = sysdate
                WHERE ( coil_abc_num = coil_num(m)) AND (scrap_870_date is NULL);

             END LOOP;
*/
        commit;
        
       

    end if; --end if in select count(*)

  --END LOOP; ------ End of outer loop customer_id
return 1;

EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN -1;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN -2;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN -3;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN -4;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN -5;
END;
--------------------------------------------------------
--  DDL for Function F_EDI_CONST_870_REJECT_4JOB
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_CONST_870_REJECT_4JOB" 
 ( 
    al_ab_job_num           ab_job.ab_job_num%type,
    al_coil_abc_num         coil.coil_abc_num%type,
    as_user_id              ab_job_870_history.user_id%type,
    as_original_or_resend   varchar2
    
 )
  return integer
  
is

  /*
  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc                                     varchar2(50) := get_edi_destination('EDI_DIR');

  edi_file                                    varchar2(256) := 'edi_out.txt';
  edi_file_prefix                             varchar2(50) := 'S_const_870_rej_'; --production
  --edi_file_prefix                             varchar2(50) := 's_const_870_rej_'; --development
  edi_file_handle                             utl_file.file_type;
  su_duns                                     varchar2(10);
  ll_customer_id                              customer.customer_id%type;
  --ll_cur_coil                                 coil.coil_abc_num%type;
  ll_gs_log                                   integer;
  ll_st_log                                   integer;
  ls_today                                    varchar2(20) := to_char(sysdate, 'YYYYMMDD');
  --ls_today_4                                  varchar2(20) := to_char(sysdate, 'YYMMDD');
  ls_now                                      varchar2(20) := to_char(sysdate, 'HH24MI');
  ls_po                                       varchar2(20);
  --ls_finished_goods                           varchar2(32);
  --ls_cust_prod_line                           varchar2(8);
  --ld_scrap_870_date                           process_coil.scrap_870_date%type;
  ls_coil_org_num                             coil.coil_org_num%type;
  --ls_heat                                     coil.lot_num%type;
  --ll_prime_nw                                 coil.net_wt%type;
  ll_scrap_nw                                 coil.net_wt%type;
  --ll_item_count                               integer;
  li_hl01                                     integer;
  --li_hllin                                    integer;
  ll_rowcount                                 number(8);
  ll_edi_file_id_870                          integer;
  ld_edi_date_870                             ab_job.edi_date_870%type;
  --ls_sheet_skid_exists                        char(1);
  ls_consumed_coil_num                        coil.consumed_coil_num%type;
  ls_customer_short_name                      customer.customer_short_name%type;
  ll_sheet_skid_count_4coil                   number(8);
  ll_total_act_scrap_wt_4job                  number(8);
  ll_total_theo_scrap_wt_4job                 number(8);
  --ll_heavy_light                              number(8);
  ls_notes                                    varchar2(512);
  ls_material_num                             coil.material_num%type;
  ls_finished_goods_material_num              order_item.finished_goods_material_num%type;
  
  ls_vo                                       coil.vo%type;
  ls_lot_num                                  coil.lot_num%type;
  ll_coil_gauge                               coil.coil_gauge%type;
  ll_coil_width                               coil.coil_width%type; 
  ls_enduser_part_num                         order_item.enduser_part_num%type;
  ls_created_date                             varchar(8);
  ll_parent_po                                number(8);
  ll_parent_coil                              number(8);
  ls_today_2digits_year                       varchar2(20) := to_char(sysdate, 'YYMMDD');
  ll_net_wt_balance                           coil.net_wt_balance%type;
  ll_net_wt                                   coil.net_wt%type;
  ll_lfeed                                    coil.lfeed%type;
  ll_length_balance                           number(10);

--------------------------------------------------------------------------------------------------   
------------------------------------ Cursors Begin -----------------------------------------------
--------------------------------------------------------------------------------------------------

  /*
  cursor coil_cur is
  select distinct process_coil.coil_abc_num
  from   process_coil
         left outer join production_sheet_item on production_sheet_item.coil_abc_num = process_coil.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    (
              sheet_skid.skid_sheet_status in (0, 2, 4, 13, 12, 16)
           or sheet_skid.skid_sheet_status is null --This is for rejected coils without sheets  
         )
  order by process_coil.coil_abc_num;
  
  coil_rec  coil_cur%ROWTYPE;
  */
   
  --Cursor skid_coil_cur will select data for ab_job and coil_abc_num with skids.
  --If there is a reject coil without sheet skids, this cursor will not select it.
  /*
  cursor skid_coil_cur is
  select coil.coil_abc_num,   
         coil.lot_num,   
         coil.coil_org_num,   
         coil.coil_mid_num,
         nvl(coil.consumed_coil_num, ' ') consumed_coil,
         nvl(coil.material_num, ' ') material_num,
         coil.net_wt,   
         sheet_skid.sheet_tare_wt,   
         sheet_skid.sheet_net_wt,
         sheet_skid.skid_pieces,
         production_sheet_item.prod_item_pieces,
         production_sheet_item.prod_item_num,
         sheet_skid.skid_sheet_status,
         sheet_skid.sheet_skid_num,   
         production_sheet_item.prod_item_note,   
         sheet_skid.sheet_theoretical_wt,   
         production_sheet_item.prod_item_placement,   
         process_coil.process_quantity,   
         production_sheet_item.prod_item_net_wt,   
         sheet_skid.sheet_skid_display_num,
         nvl(customer_order.sales_order, ' ') sales_order,
         nvl(customer_order.orig_customer_po, 'NA') orig_customer_po,
         nvl(order_item.enduser_part_num, ' ') enduser_part_num,
         nvl(order_item.cust_prod_line_id, 'NA') cust_prod_line_id,
         nvl(order_item.finished_goods_material_num, 'NA') finished_goods_material_num,
         (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
         NULL done  
  from   coil   
         join process_coil on coil.coil_abc_num = process_coil.coil_abc_num
         join ab_job on ab_job.ab_job_num = process_coil.ab_job_num
         join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
         join customer_order on customer_order.order_abc_num = order_item.order_abc_num
         left outer join production_sheet_item on coil.coil_abc_num = production_sheet_item.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  ab_job.ab_job_num = al_ab_job_num
  and    coil.coil_abc_num = ll_cur_coil
  order by
         production_sheet_item.coil_abc_num,
         sheet_skid.sheet_skid_display_num;

  skid_coil_rec  skid_coil_cur%rowtype;
  */
  
  cursor scrap_cur is
  select process_coil.coil_abc_num,
         process_coil.process_coil_status,
         process_coil.process_quantity,
         nvl(process_coil.process_end_wt, 0),
         sum(nvl(process_coil.process_end_wt, 0)),
         sum(nvl(production_sheet_item.prod_item_net_wt, 0)),
         case process_coil.process_coil_status
            when 7 then --Rebanded coils
               --(process_coil.process_quantity - sum(production_sheet_item.prod_item_net_wt) - (select process_end_wt from process_coil pc where pc.ab_job_num = 101143 and pc.coil_abc_num = process_coil.coil_abc_num))
               (process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - nvl(process_coil.process_end_wt, 0))
            when 3 then --Rejected coils
               case (select count(*) from production_sheet_item psi where psi.ab_job_num = al_ab_job_num and psi.coil_abc_num = process_coil.coil_abc_num)
                 when 0 then --Rejected coils without sheets
                   (process_coil.process_quantity - sum(nvl(process_coil.process_end_wt, 0)))
                 else --Rejected coils with sheets
                   (process_coil.process_quantity - nvl(process_coil.process_end_wt, 0) - sum(nvl(production_sheet_item.prod_item_net_wt, 0)))     
                end   
             else
               (process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - sum(nvl(process_coil.process_end_wt, 0)))
         end scrap_net_wt
  from   process_coil
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         join ab_job on ab_job.ab_job_num = process_coil.ab_job_num and coil.coil_abc_num = process_coil.coil_abc_num
         left outer join production_sheet_item on production_sheet_item.ab_job_num = process_coil.ab_job_num and production_sheet_item.coil_abc_num = process_coil.coil_abc_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    coil.coil_abc_num = al_coil_abc_num
  group by
         process_coil.coil_abc_num,
         process_coil.process_coil_status,
         process_coil.process_quantity,
         process_coil.process_end_wt
  order by
         process_coil.coil_abc_num;
         
  scrap_rec  scrap_cur%rowtype;
   
--------------------------------------------------------------------------------------------------   
------------------------------------- Cursors End ------------------------------------------------
--------------------------------------------------------------------------------------------------   

  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;

  TYPE coil_num_type IS TABLE OF coil.coil_abc_num%type INDEX BY BINARY_INTEGER;
  coil_num coil_num_type;
  p binary_integer :=0;
  
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;  

BEGIN
  
  --Check if correct customer
  select  customer_order.orig_customer_id,
          customer.customer_duns_number_string,
          customer.customer_short_name
  into    ll_customer_id,
          su_duns,
          ls_customer_short_name
  from    ab_job
          join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
          join customer on customer.customer_id = customer_order.orig_customer_id
  where   ab_job.ab_job_num = al_ab_job_num;
  
  if lower(ls_customer_short_name) not like '%constellium%' then
    return 200; --Wrong customer
  end if;
  

  --Check if 870 has already been created for al_ab_job_num
  select edi_file_id_870, edi_date_870
  into   ll_edi_file_id_870, ld_edi_date_870
  from   ab_job
  where  ab_job_num = al_ab_job_num;
   
  if (not ll_edi_file_id_870 is null) or (not ld_edi_date_870 is null) then --870 already created for al_ab_job_num
    return 100;
  end if;


  i              := 0;
  k              := 0;
  p              := 0;
  
  select count(distinct process_coil.coil_abc_num)
  into   ll_rowcount
  from   process_coil
         left outer join production_sheet_item on production_sheet_item.coil_abc_num = process_coil.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    (
              sheet_skid.skid_sheet_status in (0, 2, 4, 13, 12, 16)
           or sheet_skid.skid_sheet_status is null --This is for rejected coils without sheets  
         );
    
  if ll_rowcount > 0 then
    
    select customer_order.orig_customer_po
    into   ls_po
    from   ab_job
           join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
    where  ab_job.ab_job_num = al_ab_job_num;
    
    select    to_char(max(created_date), 'yyyymmdd')
    into      ls_created_date
    from      customer_order
    where     orig_customer_po = ls_po;

    select edi_st_log_seq.nextval into ll_st_log from dual;
    select edi_gs_log_seq.nextval into ll_gs_log from dual;
    
    /*
    select  customer_order.orig_customer_id
    into    ll_customer_id
    from    ab_job
            join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
    where   ab_job.ab_job_num = al_ab_job_num;
    
    select  customer.customer_duns_number_string
    into    su_duns
    from    customer
    where   customer.customer_id = ll_customer_id;
    */

    --Production
    x12_table(i) := 'ISA*00*' ||
                    '          *00*          *01*039630926T     *01*043207177      *' ||
                    ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                    lpad(to_char(ll_gs_log), 9, '0') || '*0*P*@~';
    --Development                
    --x12_table(i) := 'ISA*00*' ||
    --            '          *00*          *ZZ*2NDSFTP        *01*043207177      *' ||
    --            ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
    --            lpad(to_char(ll_gs_log), 9, '0') || '*0*T*@~';
    i := i + 1;
          
    --Production
    x12_table(i) := 'GS*RS*039630926T*' || '043207177' || '*' || ls_today || '*' 
                    || ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010~';
                      
    --Development
    --x12_table(1) := 'GS*RS*2NDSFTP*' || '043207177' || '*' || ls_today || '*' ||
    --               ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010~';
    i := i + 1;
        
    x12_table(i) := 'ST*870*' || to_char(ll_st_log) || '~';
    i := i + 1;
    x12_table(i) := 'BSR*2*PA*' || to_char(ll_st_log) || '*' || ls_today ||
                    '***' || ls_now || '*****' || '~'; --"AO means scrapped
    i := i + 1;
    x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now || '~';
    i := i + 1;
    x12_table(i) := 'N1*SU**1*' || su_duns || '~';
    i := i + 1;
    x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926' || '~';
    i := i + 1;

    li_hl01 := 1;
    
    x12_table(i) := 'HL*' || to_char(li_hl01) || '**O*1~';
    ll_parent_po := li_hl01;
    i := i + 1;
    
    x12_table(i) := 'PRF*' || ls_po || '*0*0*' || ls_created_date || '~';
    i := i + 1;
    
    for scrap_rec in scrap_cur loop --Scrap loop
        ll_scrap_nw := scrap_rec.scrap_net_wt;

        if ll_scrap_nw > 0 then --Theo scrap weight
                 
           if ll_sheet_skid_count_4coil > 0 then --Just in case. Should not happen
             continue; 
           end if;
                
           ll_total_theo_scrap_wt_4job := 0;
                
           select    nvl(sum(return_item_net_wt),0) 
           into      ll_total_act_scrap_wt_4job
           from      return_scrap_item
           where     ab_job_num = al_ab_job_num;

           li_hl01 := li_hl01 + 1;

           --x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(ll_parent_po) || '*I*1~';
           x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(ll_parent_po) || '*I*1~';
           ll_parent_coil := li_hl01;
           i := i + 1;
           
           --x12_table(i) := 'PRF*' || ls_po || '***' || ls_created_date || '~';
           --i := i + 1;
           
           x12_table(i) := 'REF*RV*' || to_char(al_coil_abc_num) || '~';
           i := i + 1;
           
           select  coil_org_num, consumed_coil_num, material_num, coil.vo, coil.lot_num, coil.coil_gauge, coil.coil_width, coil.net_wt_balance, lfeed, net_wt
           into    ls_coil_org_num, ls_consumed_coil_num, ls_material_num, ls_vo, ls_lot_num, ll_coil_gauge, ll_coil_width, ll_net_wt_balance, ll_lfeed, ll_net_wt
           from    coil
           where   coil_abc_num = al_coil_abc_num;
           
           select  order_item.finished_goods_material_num, enduser_part_num
           into    ls_finished_goods_material_num, ls_enduser_part_num
           from    ab_job   
                   join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
           where   ab_job.ab_job_num = al_ab_job_num;
           
           x12_table(i) := 'PO1**1*UN**' || '*VO*' || ls_vo || '*SN*' ||
                          ls_coil_org_num || '*HN*' || ls_lot_num || 
                          '*JN*' || substr(ls_vo, 1, instr(ls_vo, '-') - 1) || '*PN*' || ls_enduser_part_num ||'~';
           i := i + 1 ;
           
           ----------------------------------------------------------------------------------------------------------------------
           ----------------------------------------------------------------------------------------------------------------------
           ----------------------------------------------------------------------------------------------------------------------
           
           li_hl01 := li_hl01 + 1;

           x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(ll_parent_coil) || '*F~';
           i := i + 1;
           
           x12_table(i) := 'PRF*' || ls_po || '***' || ls_created_date || '~';
           i := i + 1;
           
           x12_table(i) := 'REF*SE*' || to_char(al_coil_abc_num) || '~'; --???. This is production_sheet_item.prod_item_num
           i := i + 1;

           --IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
           --   x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
           --   i := i + 1;
           --END IF;

           x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now || '*ED' || '~';
           i := i + 1;
           
           x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED' || '~';
           i := i + 1;

           --if ll_sheet_skid_count_4coil <= 0 then
           --x12_table(i) := 'REF*MI*' || to_char(al_ab_job_num) || '~';
           --i := i + 1;
           
           --select  coil_org_num, consumed_coil_num, material_num, coil.vo, coil.lot_num, coil.coil_gauge, coil.coil_width
           --into    ls_coil_org_num, ls_consumed_coil_num, ls_material_num, ls_vo, ls_lot_num, ll_coil_gauge, ll_coil_width
           --from    coil
           --where   coil_abc_num = al_coil_abc_num;
                      
           
                      
           --x12_table(i) := 'REF*RV*' || to_char(al_coil_abc_num) || '~';
           --i := i + 1;
           --end if;
           
           --select  order_item.finished_goods_material_num, enduser_part_num
           --into    ls_finished_goods_material_num, ls_enduser_part_num
           --from    ab_job   
           --        join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
           --where   ab_job.ab_job_num = al_ab_job_num;
                  
           --x12_table(i) := 'PO1**1*UN****' || '***SN*' || ls_coil_org_num || '***VP*' || ls_finished_goods_material_num;
           x12_table(i) := 'PO1**1*UN**' || '*VO*' || ls_vo || '*SN*' ||
                          ls_coil_org_num || '*HN*' || ls_lot_num || 
                          '*JN*' || substr(ls_vo, 1, instr(ls_vo, '-') - 1) || '*PN*' || ls_enduser_part_num ||'~';
           i := i + 1 ;

           x12_table(i) := 'PID*S*MA*ST*7' || '***68~';
           i := i + 1;

           x12_table(i) := 'PID*S*MAC*ST*01' || '***67~'; --"02" means rejected coil
           i := i + 1;

           x12_table(i) := 'PID*S*PR*ST*19' || '***66A~';
           i := i + 1;
           
           --x12_table(i) := 'PID*S*DAC*ST*263' || '***73~';
          -- i := i + 1;
           
           --x12_table(i) := 'PID*S*DAF*ST*1' || '***72~';
           --i := i + 1;
           
           x12_table(i) := 'MEA*PD*TH*' || to_char(ll_coil_gauge) || '*ED~';
           i := i+1;
           
           x12_table(i) := 'MEA*PD*WD*' || to_char(ll_coil_width) || '*ED~';
           i := i+1;

           ll_length_balance := ll_net_wt_balance / ll_net_wt * ll_lfeed;
           
           x12_table(i) := 'MEA*PD*LN*' || to_char(ll_length_balance) || '*LF' || '~';
           i := i+1;
           
           x12_table(i) := 'MEA*WT*WT*' || to_char(ll_net_wt_balance) || '*01' || '~';
           i := i+1;
                 
           --ll_total_theo_scrap_wt_4job := ll_total_theo_scrap_wt_4job + ll_scrap_nw;
           
           ----------------------------------------------------------------------------------------------------------------------
           ----------------------------------------------------------------------------------------------------------------------
           ----------------------------------------------------------------------------------------------------------------------
           
           li_hl01 := li_hl01 + 1;

           x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(ll_parent_coil) || '*F~';
           i := i + 1;
           
           x12_table(i) := 'PRF*' || ls_po || '***' || ls_created_date || '~';
           i := i + 1;

           --IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
           --   x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
           --   i := i + 1;
           --END IF;

           x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now || '*ED' || '~';
           i := i + 1;
           
           x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED' || '~';
           i := i + 1;

           --if ll_sheet_skid_count_4coil <= 0 then
           --x12_table(i) := 'REF*MI*' || to_char(al_ab_job_num) || '~';
           --i := i + 1;
           
           --select  coil_org_num, consumed_coil_num, material_num, coil.vo, coil.lot_num, coil.coil_gauge, coil.coil_width
           --into    ls_coil_org_num, ls_consumed_coil_num, ls_material_num, ls_vo, ls_lot_num, ll_coil_gauge, ll_coil_width
           --from    coil
           --where   coil_abc_num = al_coil_abc_num;
                      
           x12_table(i) := 'REF*SE*' || to_char(al_coil_abc_num) || '~'; --???. This is production_sheet_item.prod_item_num
           i := i + 1;
                      
           --x12_table(i) := 'REF*RV*' || to_char(al_coil_abc_num) || '~';
           --i := i + 1;
           --end if;
           
           --select  order_item.finished_goods_material_num, enduser_part_num
           --into    ls_finished_goods_material_num, ls_enduser_part_num
           --from    ab_job   
           --        join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
           --where   ab_job.ab_job_num = al_ab_job_num;
                  
           --x12_table(i) := 'PO1**1*UN****' || '***SN*' || ls_coil_org_num || '***VP*' || ls_finished_goods_material_num;
           x12_table(i) := 'PO1**1*UN**' || '*VO*' || ls_vo || '*SN*' ||
                          ls_coil_org_num || '*HN*' || ls_lot_num || 
                          '*JN*' || substr(ls_vo, 1, instr(ls_vo, '-') - 1) || '*PN*' || ls_enduser_part_num ||'~';
           i := i + 1 ;

           x12_table(i) := 'PID*S*MA*ST*S' || '***70~';
           i := i + 1;

           x12_table(i) := 'PID*S*MAC*ST*05' || '***67~'; --"02" means rejected coil
           i := i + 1;

           x12_table(i) := 'PID*S*PR*ST*14' || '***66A~';
           i := i + 1;
           
           x12_table(i) := 'PID*S*DAC*ST*263' || '***73~';
           i := i + 1;
           
           x12_table(i) := 'PID*S*DAF*ST*1' || '***72~';
           i := i + 1;

           x12_table(i) := 'MEA*WT*WT*' || to_char(ll_scrap_nw) || '*01' || '~';
           i := i+1;
                 
           ll_total_theo_scrap_wt_4job := ll_total_theo_scrap_wt_4job + ll_scrap_nw;
                 
        end if; --if ll_scrap_nw > 0 then
    end loop; --for scrap_rec in alcan_scrap_870_cur loop scrap loop
    
    x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) || '~';
    i := i + 1;

    x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log) || '~';
    i := i + 1;

    x12_table(i) := 'GE*1*' || to_char(ll_gs_log) || '~';
    i := i + 1;

    x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0') || '~';

    -- Write EDI to file

    if li_hl01 > 0 then
        -- WRITE EDI FILE ONLY IF ITEM > 0
        SELECT edi_file_id_seq.nextval
          INTO ll_edi_file_id_870
          FROM dual;
        edi_file        := edi_file_prefix || to_char(ll_edi_file_id_870) || '_Job-' || to_char(al_ab_job_num) || '.edi';
     -- edi_file        := 's_alcan_' || to_char(ll_edi_file_id_870) || '.870';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        FOR j IN 0 .. i LOOP
          utl_file.put_line(edi_file_handle, x12_table(j));

        END LOOP;
        utl_file.fclose(edi_file_handle);
      END IF; -- END WRITING EDI FILE

      --edi_file        := 'send_edi_log'; /* Alex Gerlants. 04/14/2017. Commented out. */
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      --For verifying 997

      INSERT INTO outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
        VALUES
          (ll_edi_file_id_870,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           SYSDATE,
           edi_file,
           0,
           ll_customer_id,
           ll_st_log,
           '870');

  /*
        update    ab_job
        set       edi_file_id_870 = ll_edi_file_id_870,
                  edi_date_870 = sysdate
        where     ab_job_num = al_ab_job_num;
  */      
  
        ls_notes :=  ' Fully rejected coil. AB Job: ' || to_char(al_ab_job_num) 
                     || ' coil_abc_num: ' || to_char(al_coil_abc_num) 
                     || ' coil_org_num: ' || ls_coil_org_num
                     || ' Rejected weight: ' || to_char(ll_scrap_nw);
        
        insert into ab_job_870_history
        (
           ab_job_num,
           edi_file_id,
           edi_file_name,
           create_870_date_time,
           user_id,
           notes
        )
        values
        (
           al_ab_job_num ,
           ll_edi_file_id_870,
           edi_file,
           sysdate,
           as_user_id,
           as_original_or_resend || ' ' || ls_notes
        );
        
       
        update    ab_job
        set       edi_file_id_870 = ll_edi_file_id_870,
                  edi_date_870 = sysdate
        where     ab_job_num = al_ab_job_num;
        

        for m in 0 .. k - 1 loop
           update   production_sheet_item
           set      prod_item_edi870_date = sysdate,
                    edi_file_id_870 = ll_edi_file_id_870 
           where    production_sheet_item.prod_item_num = item_num(m);
        end loop;

        for m in 0..p - 1 loop
           update   coil
           set      coil.scrap_870_date = sysdate
           where    coil.coil_abc_num = coil_num(m);

           update   process_coil
           set      scrap_870_date = sysdate
           where    ( coil_abc_num = coil_num(m)) and (scrap_870_date is null);

         end loop;

         commit;

  end if; --end if in select count(*)

  --END LOOP; ------ End of outer loop customer_id

return 1;


EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN -1;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN -2;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN -3;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN -4;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN -9;

    
  
end f_edi_const_870_reject_4job;
--------------------------------------------------------
--  DDL for Function F_EDI_CONST_BG_870PP_4JOB
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_CONST_BG_870PP_4JOB" 
 ( 
    al_ab_job_num           ab_job.ab_job_num%type
 )
  return integer
  
is

  edi_loc                      varchar2(50) := get_edi_destination('EDI_DIR');

  edi_file                     varchar2(50) := 'edi_out.txt';
  edi_file_prefix              varchar2(50) := 'S_const_870PP_';   --Production
  --edi_file_prefix              varchar2(50) := 's_const_870PP_';   --Development
  edi_file_handle              utl_file.file_type;
  su_duns                      varchar2(10);
  ll_customer_id               customer.customer_id%type;
  ll_cur_coil                  coil.coil_abc_num%type;
  ll_gs_log                    integer;
  ll_st_log                    integer;
  ls_today                     varchar2(20) := to_char(sysdate, 'YYYYMMDD');
  ls_now                       varchar2(20) := to_char(sysdate, 'HH24MI');
  ls_po                        customer_order.orig_customer_po%type;
  ls_enduser_po                customer_order.enduser_po%type;
  ls_today_2digits_year        varchar2(20) := to_char(sysdate, 'YYMMDD');
  ls_coil_org_num              coil.coil_org_num%type;
  ll_edi_file_id_870           integer;
  ll_item_count                integer;
  li_hl01                      integer;
  ls_created_date              varchar(8);
  ls_vo                        coil.vo%type;
  ls_lot_num                   coil.lot_num%type;
  ls_enduser_part              order_item.enduser_part_num%type;
  ll_parent_coil               number(8);
  ll_parent_po                 number(8);
  ll_sheet_skid_count_4coil    number(8);
  ll_coil_gauge                coil.coil_gauge%type;
  ll_part_length               rectangle.rt_length%type;
  ll_part_width                rectangle.rt_width%type;
  ll_sheet_skid_num_cur        sheet_skid.sheet_skid_num%type;
  ls_coil_org_num_temp         coil.coil_org_num%type;
  ll_coil_abc_num_temp         coil.coil_abc_num%type;
  li_skid_sheet_status         sheet_skid.skid_sheet_status%type;
  ll_skid_sheet_net_wt         sheet_skid.sheet_net_wt%type;
  li_skid_pieces               sheet_skid.skid_pieces%type;
  li_alphabet_pointer          number(2) := 0;
  li_split_skid_count          number(2);
  li_test                      number(3);
  ll_order_po                  number(8);
  li_skid_pieces_actual        number(4);
  li_skid_pieces_required      number(4);
  li_count                     number(1);

  cursor split_skid_cur is
  select   sheet_skid_num, 
           sum(item_skid_pieces) total_skid_pieces
  from     split_skid
  where    ab_job_num = al_ab_job_num
  group by sheet_skid_num
  order by sheet_skid_num;
  
  split_skid_rec  split_skid_cur%ROWTYPE;
  
  cursor split_skid_detail_cur is
  select   ab_job_num,
           coil_abc_num,
           sheet_skid_num,
           sheet_skid_num_with_letter,
           coil_org_num,
           item_sheet_net_wt,
           item_skid_pieces,
           nvl(suffix, '')
  from     split_skid
  where    sheet_skid_num = ll_sheet_skid_num_cur
  order by sheet_skid_num,
           nvl(suffix, '');
  
  split_skid_detail_rec  split_skid_detail_cur%ROWTYPE;

  type store_tabletype is table of varchar2(32767) index by binary_integer;
  x12_table store_tabletype;
  
  i         binary_integer := 0;

  type coil_num_type is table of coil.coil_abc_num%type index by binary_integer;
  coil_num coil_num_type;
  
  p binary_integer :=0;


BEGIN
  
    --Check if correct customer
    select  customer_order.orig_customer_id, customer.customer_duns_number_string
    into    ll_customer_id, su_duns
    from    ab_job
            join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
            join customer on customer.customer_id = customer_order.orig_customer_id
    where   ab_job.ab_job_num = al_ab_job_num;
    
    if ll_customer_id <> 2776 then
      return 200; --Wrong customer
    end if;

    i              := 0;
    p              := 0;

    
    select customer_order.orig_customer_po, enduser_po
    into   ls_po, ls_enduser_po
    from   ab_job
           join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
    where  ab_job.ab_job_num = al_ab_job_num;
    
    select   count(*)
    into     ll_item_count
    from     split_skid
    where    ab_job_num = al_ab_job_num
    order by sheet_skid_num;
    
    select count(*)
    into   ll_item_count
    from   split_skid
    where  ab_job_num = al_ab_job_num;
    
    select distinct customer_order.orig_customer_po, to_char(customer_order.created_date, 'yyyymmdd'), enduser_po
    into   ls_po, ls_created_date, ls_enduser_po
    from   ab_job
           join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
    where  ab_job.ab_job_num = al_ab_job_num;
    
    if (ll_item_count <> 0) then
    
       ---------  Split skid loop ------------------------------------
        for split_skid_rec in split_skid_cur loop
          
          --Alex Gerlants. 04/24/2026. Begin
          ll_sheet_skid_num_cur := split_skid_rec.sheet_skid_num;
          
          select   count(*)
          into     li_count
          from     split_skid
          where    sheet_skid_num = ll_sheet_skid_num_cur; 
          --Alex Gerlants. 04/24/2026. End
         
        ---------------------------------------------------------------------------------
        /*
         select distinct customer_order.orig_customer_po, to_char(customer_order.created_date, 'yyyymmdd'), enduser_po
         into   ls_po, ls_created_date, ls_enduser_po
         from   ab_job
                join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
         where  ab_job.ab_job_num = al_ab_job_num; 
         */
         
         if li_count > 1 then ----Alex Gerlants. 04/24/2026
           select edi_st_log_seq.nextval into ll_st_log from dual;
           select edi_gs_log_seq.nextval into ll_gs_log from dual;
                
           --Production
           x12_table(i) := 'ISA*00*' ||
                      '          *00*          *01*039630926T     *01*043207177      *' ||
                      ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                      lpad(to_char(ll_gs_log), 9, '0') || '*0*P*@~';

            --Development                
            --x12_table(i) := 'ISA*00*' ||
            --            '          *00*          *ZZ*2NDSFTP        *01*043207177      *' ||
            --            ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
            --            lpad(to_char(ll_gs_log), 9, '0') || '*0*T*@~';
            i := i + 1;
                
            --Production
            x12_table(i) := 'GS*RS*039630926T*' || '043207177' || '*' || ls_today || '*' 
                            || ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010~';
                                
            --Development
            --x12_table(1) := 'GS*RS*2NDSFTP*' || '043207177' || '*' || ls_today || '*' ||
            --               ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010~';
            i := i + 1;
                
            x12_table(i) := 'ST*870PP*' || to_char(ll_st_log) || '~';
            i := i + 1;
            x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                            '***' || ls_now || '*****~';
            i := i + 1;
                
            x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now || '*ED~';
            i := i + 1;
                
            x12_table(i) := 'N1*MF**1*' || su_duns || '~';
            i := i + 1;
                
            x12_table(i) := 'N1*OU*ALUMINUM BLANKING COMPANY*1*039630926~';
            i := i + 1;
            
            li_hl01 := 0;
            li_hl01 := li_hl01 + 1;

            x12_table(i) := 'HL*' || to_char(li_hl01) || '**O*1~';
            i := i + 1;
          end if; --Alex Gerlants. 04/24/2026
          
          ----------------------------------------------------------------------
        
          ll_sheet_skid_num_cur := split_skid_rec.sheet_skid_num;
          ll_order_po := li_hl01;

          select   count(*)
          into     li_split_skid_count
          from     split_skid
          where    sheet_skid_num = ll_sheet_skid_num_cur;
          
          --Alex Gerlants. 01/26/2026. Begin
          select   order_item.pieces_skid
          into     li_skid_pieces_required
          from     order_item
                   join ab_job on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
          where    ab_job.ab_job_num = al_ab_job_num;
          
          /*
          select   distinct order_item.pieces_skid
          into     li_skid_pieces_required
          from     production_sheet_item
                   join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num       
                   join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
                   join ab_job on production_sheet_item.ab_job_num = ab_job.ab_job_num
                   join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
                   join order_item on customer_order.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
          where    sheet_skid.sheet_skid_num = ll_sheet_skid_num_cur;
          */
          --Alex Gerlants. 01/26/2026. End
         
          select   sum(item_skid_pieces) --Actual pieces on skid
          into    li_skid_pieces_actual
          from     split_skid
          where    sheet_skid_num = ll_sheet_skid_num_cur
          and
          (
            ab_job_num = al_ab_job_num
            or
            suffix <= (select max(suffix) from split_skid where ab_job_num = al_ab_job_num)
          );
          
          if li_split_skid_count > 1 and li_skid_pieces_actual >= li_skid_pieces_required then --ll_sheet_skid_num_cur is not a combined skid or skid not full
            li_split_skid_count := li_split_skid_count; --This is just a dummy statement to fill the space for true condition
          else
            continue;
          end if;  
          
          x12_table(i) := 'PRF*' || ls_enduser_po || '*0*0*' || ls_created_date || '~';
          i := i + 1;
          
          li_hl01 := li_hl01 + 1;
          
          x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(ll_order_po) || '*F~';
          i := i + 1;
          
          x12_table(i) := 'PRF*' || ls_enduser_po || '***' || ls_created_date || '~';
          i := i + 1;
          
          x12_table(i) := 'REF*SE*' || to_char(ll_sheet_skid_num_cur) || '~';
          i := i + 1;
          
          x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now || '*ED~';
          i := i + 1;
                              
          x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED~';
          i := i + 1;
          
          select   max(coil_org_num)
          into     ls_coil_org_num_temp
          from     split_skid
          where    ab_job_num = al_ab_job_num
          and      sheet_skid_num = ll_sheet_skid_num_cur;
          
          select   coil_abc_num
          into     ll_coil_abc_num_temp
          from     split_skid
          where    ab_job_num = al_ab_job_num
          and      sheet_skid_num = ll_sheet_skid_num_cur
          and      coil_org_num = ls_coil_org_num_temp;
          
          select   lot_num, vo, coil_gauge
          into     ls_lot_num, ls_vo, ll_coil_gauge
          from     coil
          where    coil_abc_num = ll_coil_abc_num_temp;
          
          select   inbound_coil.part_num
          into     ls_enduser_part
          from     inbound_coil
                   join coil on coil.coil_org_num = inbound_coil.coil_number
          where    coil.coil_abc_num = ll_coil_abc_num_temp
          and      inbound_coil.edi_file_id =
          (
             select   max(inbound_coil.edi_file_id)
             from     inbound_coil
                      join coil on coil.coil_org_num = inbound_coil.coil_number
             where    coil.coil_abc_num = ll_coil_abc_num_temp
          );
          
          x12_table(i) := 'PO1**1*UN***VO*' || ls_vo || 
                  '*SN*' || ls_coil_org_num_temp || 
                  '*HN*' || ls_lot_num || 
                  '*JN*' || substr(ls_enduser_po, 1, instr(ls_enduser_po, '-') - 1) 
                   || '~';
          i := i + 1;
          
          x12_table(i) := 'PID*S*MAC*ST*01***67~';
          i := i + 1;
          
          select   skid_sheet_status
          into     li_skid_sheet_status
          from     sheet_skid
          where    sheet_skid_num = ll_sheet_skid_num_cur;
          
          IF li_skid_sheet_status = 2 THEN
            --x12_table(i) := 'PID*S*MA*ST*1***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
            x12_table(i) := 'PID*S*MA*ST*1***70' || '~';
            i := i + 1;
          ELSIF li_skid_sheet_status = 4 THEN
            --x12_table(i) := 'PID*S*MA*ST*3***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
            x12_table(i) := 'PID*S*MA*ST*3***70' ||'~';
            i := i + 1;
          ELSIF li_skid_sheet_status = 13 THEN
            --x12_table(i) := 'PID*S*MA*ST*8***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
            x12_table(i) := 'PID*S*MA*ST*8***70' ||'~';
            i := i + 1;
           ELSE
            --x12_table(i) := 'PID*S*MA*ST*4***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
            x12_table(i) := 'PID*S*MA*ST*4***70' ||'~';
            i := i + 1;
          END IF;
          
          x12_table(i) := 'PID*S*PR*ST*27***66A' ||'~';
          i := i + 1;
          
          x12_table(i) := 'PID*S*DAC*ST*598***73' ||'~';
          i := i + 1;
          
          x12_table(i) := 'PID*S*DAF*ST*1***72' ||'~';
          i := i + 1;
          
           x12_table(i) := 'MEA*PD*TH*' || to_char(ll_coil_gauge) ||'*ED~';
           i := i + 1;
                    
           select   f_get_part_width_per_job(al_ab_job_num)
           into     ll_part_width
           from     dual;
                    
           --x12_table(i) := 'MEA*PD*WD*' || to_char(ll_coil_width) ||'~';
           x12_table(i) := 'MEA*PD*WD*' || to_char(ll_part_width) ||'*ED~';
           i := i + 1;
                    
           select   f_get_part_length_per_job(al_ab_job_num)
           into     ll_part_length
           from     dual;
                    
           x12_table(i) := 'MEA*PD*LN*' || to_char(ll_part_length) ||'*ED~';
           i := i + 1;
           
           select   sheet_net_wt, skid_pieces
           into     ll_skid_sheet_net_wt, li_skid_pieces
           from     sheet_skid
           where    sheet_skid_num = ll_sheet_skid_num_cur;
           
           x12_table(i) := 'MEA*WT*WT*' || to_char(ll_skid_sheet_net_wt) || '*01' ||'~';
           i := i + 1;
           
           --x12_table(i) := 'MEA*CT*NA*' || to_char(li_skid_pieces) || '*PC' ||'~';
           x12_table(i) := 'MEA*CT*NA*' || to_char(li_skid_pieces) || '*PC' ||'~';
           i := i + 1;
           
           ll_parent_po := li_hl01;
            
--********************************************************************************************          
          
          for split_skid_detail_rec in split_skid_detail_cur loop 
              ll_sheet_skid_num_cur := ll_sheet_skid_num_cur; --For debugging
              ll_cur_coil := split_skid_detail_rec.coil_abc_num;
              ls_coil_org_num := split_skid_detail_rec.coil_org_num;
              
              select   count(*)
              into     ll_sheet_skid_count_4coil
              from     production_sheet_item
              where    ab_job_num = al_ab_job_num
              and      coil_abc_num = ll_cur_coil;

              coil_num(p) := ll_cur_coil;
              p := p + 1;
                          
              
              li_hl01 := li_hl01 + 1;
              
              ------------------ Changed from 'I' to 'F' ----------------------------------------
              ---- 02/06/2023 -- Changed from 'F' to 'I' ----------------------------------------
              x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(ll_parent_po) || '*I~';
              ll_parent_coil := li_hl01;
              i := i + 1;
              
              li_alphabet_pointer := li_alphabet_pointer + 1;
              --ls_letter := substr(ls_alphabet, li_alphabet_pointer, 1);
                          
              --x12_table(i) := 'PRF*' || ls_po || '***' || ls_created_date || '~';
              --i := i + 1;
                          
              --x12_table(i) := 'REF*RV*' || ls_coil_org_num || '~';                                      
              x12_table(i) := 'REF*RV*' || to_char(split_skid_detail_rec.sheet_skid_num_with_letter) || '~';
              --x12_table(i) := 'REF*RV*' || to_char(split_skid_detail_rec.sheet_skid_num) || substr(ls_alphabet, li_alphabet_pointer, 1) || '~';
              i := i + 1;
              
              x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now || '*ED~';
              i := i + 1;
                                  
              x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED~';
              i := i + 1;
              select   lot_num, vo, coil_gauge
              into     ls_lot_num, ls_vo, ll_coil_gauge
              from     coil
              where    coil_abc_num = ll_cur_coil;
              
              x12_table(i) := 'PO1**1*UN***VO*' || ls_vo || 
                      '*SN*' || ls_coil_org_num || 
                      '*HN*' || ls_lot_num || 
                      '*JN*' || substr(ls_enduser_po, 1, instr(ls_enduser_po, '-') - 1) || 
                      '*PN*' || ls_enduser_part || '~';
              i := i + 1;
              
              x12_table(i) := 'PID*S*MAC*ST*01***67~';
              i := i + 1;

              select   skid_sheet_status
              into     li_skid_sheet_status
              from     sheet_skid
              where    sheet_skid_num = ll_sheet_skid_num_cur;
              
              IF li_skid_sheet_status = 2 THEN
                --x12_table(i) := 'PID*S*MA*ST*1***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
                x12_table(i) := 'PID*S*MA*ST*1***70' || '~';
                i := i + 1;
              ELSIF li_skid_sheet_status = 4 THEN
                --x12_table(i) := 'PID*S*MA*ST*3***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
                x12_table(i) := 'PID*S*MA*ST*3***70' ||'~';
                i := i + 1;
              ELSIF li_skid_sheet_status = 13 THEN
                --x12_table(i) := 'PID*S*MA*ST*8***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
                x12_table(i) := 'PID*S*MA*ST*8***70' ||'~';
                i := i + 1;
               ELSE
                --x12_table(i) := 'PID*S*MA*ST*4***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
                x12_table(i) := 'PID*S*MA*ST*4***70' ||'~';
                i := i + 1;
              END IF;
              
              x12_table(i) := 'PID*S*PR*ST*29***66' ||'~';
              i := i + 1;
              
              x12_table(i) := 'PID*S*DAC*ST*598***73' ||'~';
              i := i + 1;
              
              x12_table(i) := 'PID*S*DAF*ST*1***72' ||'~';
              i := i + 1;
              
               x12_table(i) := 'MEA*PD*TH*' || to_char(ll_coil_gauge) ||'*ED~';
               i := i + 1;
                        
               --x12_table(i) := 'MEA*PD*WD*' || to_char(ll_coil_width) ||'~';
               x12_table(i) := 'MEA*PD*WD*' || to_char(ll_part_width) ||'*ED~';
               i := i + 1;
                        
               x12_table(i) := 'MEA*PD*LN*' || to_char(ll_part_length) ||'*ED~';
               i := i + 1;
                            
               x12_table(i) := 'MEA*WT*WT*' || to_char(split_skid_detail_rec.item_sheet_net_wt) || '*01' ||'~';
               i := i + 1;
               
               x12_table(i) := 'MEA*CT*NA*' || to_char(split_skid_detail_rec.item_skid_pieces) || '*PC' ||'~';
               i := i + 1;
               
          end loop; --for split_skid_detail_rec in split_skid_detail_cur 
    

          x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) ||'~';
          i := i + 1;
                
          x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log) ||'~';
          i := i + 1;
                
          x12_table(i) := 'GE*1*' || to_char(ll_gs_log) ||'~';
          i := i + 1;
                
          x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0') ||'~';
          i := i + 1;

          -- Write EDI to file

          if li_hl01 > 1 then
            -- write edi file only if item > 0
            select edi_file_id_seq.nextval
              into ll_edi_file_id_870
              from dual;

            edi_file        := edi_file_prefix || to_char(ll_edi_file_id_870) || '_Job-' || to_char(al_ab_job_num) || '.edi';
            edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

            for j in 0 .. i loop
              utl_file.put_line(edi_file_handle, x12_table(j));
              li_test := j;
                      
              if li_test = i - 1 then
                exit;
              end if;
            end loop;
                  
            utl_file.fclose(edi_file_handle);
          --end if; -- end writing edi file

            --edi_file        := 'send_edi_log'; /* Alex Gerlants. 04/14/2017. Commented out. */
            edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
            utl_file.put_line(edi_file_handle, 'Type: 870');
            utl_file.put_line(edi_file_handle,
                              'Sending Time: ' ||
                              to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
            utl_file.put_line(edi_file_handle,
                              'Interchange Control #: ' || ll_gs_log);
            utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
            utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
            utl_file.put_line(edi_file_handle, '');
            utl_file.put_line(edi_file_handle, '');
            utl_file.fclose(edi_file_handle);

            --For verifying 997
                  
            insert into outbound_edi_transaction
                (edi_file_id,
                 duns_from,
                 duns_to,
                 interchange_control_number,
                 group_control_number,
                 transaction_time,
                 edi_file_name,
                 fa_receive_status,
                 customer_id,
                 set_control_num,
                 transaction_type_id)
            values
                (ll_edi_file_id_870,
                 '039630926',
                 su_duns,
                 ll_gs_log,
                 ll_gs_log,
                 SYSDATE,
                 edi_file,
                 0,
                 ll_customer_id,
                 ll_st_log,
                 '870PP');   
                 
            commit;
                  
          end if; 
              
          i := 0;
          li_hl01 := 0;       
         end loop; --for split_skid_rec in split_skid_cur loop

  end if; --if (ll_item_count <> 0) then

return 1;

EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN -1;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN -2;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN -3;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN -4;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN -5;
END;
--------------------------------------------------------
--  DDL for Function F_EDI_CONST_BG_870PP_4JOB_FIX
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_CONST_BG_870PP_4JOB_FIX" 
 ( 
    al_ab_job_num           ab_job.ab_job_num%type
 )
  return integer
  
is

  edi_loc                      varchar2(50) := get_edi_destination('EDI_DIR');

  edi_file                     varchar2(50) := 'edi_out.txt';
  edi_file_prefix              varchar2(50) := 'S_const_870PP_';   --Production
  --edi_file_prefix              varchar2(50) := 's_const_870PP_';   --Development
  edi_file_handle              utl_file.file_type;
  su_duns                      varchar2(10);
  ll_customer_id               customer.customer_id%type;
  ll_cur_coil                  coil.coil_abc_num%type;
  ll_gs_log                    integer;
  ll_st_log                    integer;
  ls_today                     varchar2(20) := to_char(sysdate, 'YYYYMMDD');
  ls_now                       varchar2(20) := to_char(sysdate, 'HH24MI');
  ls_po                        customer_order.orig_customer_po%type;
  ls_enduser_po                customer_order.enduser_po%type;
  ls_today_2digits_year        varchar2(20) := to_char(sysdate, 'YYMMDD');
  ls_coil_org_num              coil.coil_org_num%type;
  ll_edi_file_id_870           integer;
  ll_item_count                integer;
  li_hl01                      integer;
  ls_created_date              varchar(8);
  ls_vo                        coil.vo%type;
  ls_lot_num                   coil.lot_num%type;
  ls_enduser_part              order_item.enduser_part_num%type;
  ll_parent_coil               number(8);
  ll_parent_po                 number(8);
  ll_sheet_skid_count_4coil    number(8);
  ll_coil_gauge                coil.coil_gauge%type;
  ll_part_length               rectangle.rt_length%type;
  ll_part_width                rectangle.rt_width%type;
  ll_sheet_skid_num_cur        sheet_skid.sheet_skid_num%type;
  ls_coil_org_num_temp         coil.coil_org_num%type;
  ll_coil_abc_num_temp         coil.coil_abc_num%type;
  li_skid_sheet_status         sheet_skid.skid_sheet_status%type;
  ll_skid_sheet_net_wt         sheet_skid.sheet_net_wt%type;
  li_skid_pieces               sheet_skid.skid_pieces%type;
  li_alphabet_pointer          number(2) := 0;
  li_split_skid_count          number(2);
  li_test                      number(3);
  ll_order_po                  number(8);
  li_skid_pieces_actual        number(4);
  li_skid_pieces_required      number(4);
  --li_count                     number(1);

  cursor split_skid_cur is
  select   sheet_skid_num, 
           sum(item_skid_pieces) total_skid_pieces
  from     split_skid
  where    ab_job_num = al_ab_job_num
  group by sheet_skid_num
  order by sheet_skid_num;
  
  split_skid_rec  split_skid_cur%ROWTYPE;
  
  cursor split_skid_detail_cur is
  select   ab_job_num,
           coil_abc_num,
           sheet_skid_num,
           sheet_skid_num_with_letter,
           coil_org_num,
           item_sheet_net_wt,
           item_skid_pieces,
           nvl(suffix, '')
  from     split_skid
  where    sheet_skid_num = ll_sheet_skid_num_cur
  order by sheet_skid_num,
           nvl(suffix, '');
  
  split_skid_detail_rec  split_skid_detail_cur%ROWTYPE;

  type store_tabletype is table of varchar2(32767) index by binary_integer;
  x12_table store_tabletype;
  
  i         binary_integer := 0;

  type coil_num_type is table of coil.coil_abc_num%type index by binary_integer;
  coil_num coil_num_type;
  
  p binary_integer :=0;


BEGIN
  
    --Check if correct customer
    select  customer_order.orig_customer_id, customer.customer_duns_number_string
    into    ll_customer_id, su_duns
    from    ab_job
            join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
            join customer on customer.customer_id = customer_order.orig_customer_id
    where   ab_job.ab_job_num = al_ab_job_num;
    
    if ll_customer_id <> 2776 then
      return 200; --Wrong customer
    end if;

    i              := 0;
    p              := 0;

    
    select customer_order.orig_customer_po, enduser_po
    into   ls_po, ls_enduser_po
    from   ab_job
           join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
    where  ab_job.ab_job_num = al_ab_job_num;
    
    select   count(*)
    into     ll_item_count
    from     split_skid
    where    ab_job_num = al_ab_job_num
    order by sheet_skid_num;
    
    select count(*)
    into   ll_item_count
    from   split_skid
    where  ab_job_num = al_ab_job_num;
    
    select distinct customer_order.orig_customer_po, to_char(customer_order.created_date, 'yyyymmdd'), enduser_po
    into   ls_po, ls_created_date, ls_enduser_po
    from   ab_job
           join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
    where  ab_job.ab_job_num = al_ab_job_num;
        
    select   order_item.pieces_skid
    into     li_skid_pieces_required
    from     order_item
             join ab_job on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
    where    ab_job.ab_job_num = al_ab_job_num;
    
    if (ll_item_count <> 0) then
    
       ---------  Split skid loop ------------------------------------
        for split_skid_rec in split_skid_cur loop
          
          --Alex Gerlants. 04/24/2026. Begin
          ll_sheet_skid_num_cur := split_skid_rec.sheet_skid_num;
          ll_order_po := li_hl01;
          
          select   count(*)
          into     li_split_skid_count
          from     split_skid
          where    sheet_skid_num = ll_sheet_skid_num_cur;
          
          --select   count(*)
          --into     li_count
          --from     split_skid
          --where    sheet_skid_num = ll_sheet_skid_num_cur; 
          --Alex Gerlants. 04/24/2026. End
         
        ---------------------------------------------------------------------------------
        /*
         select distinct customer_order.orig_customer_po, to_char(customer_order.created_date, 'yyyymmdd'), enduser_po
         into   ls_po, ls_created_date, ls_enduser_po
         from   ab_job
                join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
         where  ab_job.ab_job_num = al_ab_job_num; 
         */
         
          select   sum(item_skid_pieces) --Actual pieces on skid
          into    li_skid_pieces_actual
          from     split_skid
          where    sheet_skid_num = ll_sheet_skid_num_cur
          and
          (
            ab_job_num = al_ab_job_num
            or
            suffix <= (select max(suffix) from split_skid where ab_job_num = al_ab_job_num)
          );
          
          if li_split_skid_count > 1 and li_skid_pieces_actual >= li_skid_pieces_required then --ll_sheet_skid_num_cur is not a combined skid or skid not full
            li_split_skid_count := li_split_skid_count; --Fall through. This is just a dummy statement to fill the space for true condition
          else
            continue;
          end if;
         
         --if li_count > 1 then ----Alex Gerlants. 04/24/2026
           select edi_st_log_seq.nextval into ll_st_log from dual;
           select edi_gs_log_seq.nextval into ll_gs_log from dual;
                
           --Production
           x12_table(i) := 'ISA*00*' ||
                      '          *00*          *01*039630926T     *01*043207177      *' ||
                      ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                      lpad(to_char(ll_gs_log), 9, '0') || '*0*P*@~';

            --Development                
            --x12_table(i) := 'ISA*00*' ||
            --            '          *00*          *ZZ*2NDSFTP        *01*043207177      *' ||
            --            ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
            --            lpad(to_char(ll_gs_log), 9, '0') || '*0*T*@~';
            i := i + 1;
                
            --Production
            x12_table(i) := 'GS*RS*039630926T*' || '043207177' || '*' || ls_today || '*' 
                            || ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010~';
                                
            --Development
            --x12_table(1) := 'GS*RS*2NDSFTP*' || '043207177' || '*' || ls_today || '*' ||
            --               ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010~';
            i := i + 1;
                
            x12_table(i) := 'ST*870PP*' || to_char(ll_st_log) || '~';
            i := i + 1;
            x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                            '***' || ls_now || '*****~';
            i := i + 1;
                
            x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now || '*ED~';
            i := i + 1;
                
            x12_table(i) := 'N1*MF**1*' || su_duns || '~';
            i := i + 1;
                
            x12_table(i) := 'N1*OU*ALUMINUM BLANKING COMPANY*1*039630926~';
            i := i + 1;
            
            li_hl01 := 0;
            li_hl01 := li_hl01 + 1;

            x12_table(i) := 'HL*' || to_char(li_hl01) || '**O*1~';
            i := i + 1;
          --end if; --Alex Gerlants. 04/24/2026
          
          ----------------------------------------------------------------------

          /* Alex Gerlants. 05/04/2026. Moved up to the beginning of the loop        
          ll_sheet_skid_num_cur := split_skid_rec.sheet_skid_num;
          ll_order_po := li_hl01;

          select   count(*)
          into     li_split_skid_count
          from     split_skid
          where    sheet_skid_num = ll_sheet_skid_num_cur;
          */
          
          /* Alex Gerlants. 05/04/2026. Moved up, before the loop
          --Alex Gerlants. 01/26/2026. Begin
          select   order_item.pieces_skid
          into     li_skid_pieces_required
          from     order_item
                   join ab_job on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
          where    ab_job.ab_job_num = al_ab_job_num;
          */
          
          /*
          select   distinct order_item.pieces_skid
          into     li_skid_pieces_required
          from     production_sheet_item
                   join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num       
                   join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
                   join ab_job on production_sheet_item.ab_job_num = ab_job.ab_job_num
                   join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
                   join order_item on customer_order.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
          where    sheet_skid.sheet_skid_num = ll_sheet_skid_num_cur;
          */
          --Alex Gerlants. 01/26/2026. End
         
         /* Alex Gerlants. Moved up, before ISA segment
          select   sum(item_skid_pieces) --Actual pieces on skid
          into    li_skid_pieces_actual
          from     split_skid
          where    sheet_skid_num = ll_sheet_skid_num_cur
          and
          (
            ab_job_num = al_ab_job_num
            or
            suffix <= (select max(suffix) from split_skid where ab_job_num = al_ab_job_num)
          );
          
          if li_split_skid_count > 1 and li_skid_pieces_actual >= li_skid_pieces_required then --ll_sheet_skid_num_cur is not a combined skid or skid not full
            li_split_skid_count := li_split_skid_count; --This is just a dummy statement to fill the space for true condition
          else
            continue;
          end if;
          */
          
          x12_table(i) := 'PRF*' || ls_enduser_po || '*0*0*' || ls_created_date || '~';
          i := i + 1;
          
          li_hl01 := li_hl01 + 1;
          
          x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(ll_order_po) || '*F~';
          i := i + 1;
          
          x12_table(i) := 'PRF*' || ls_enduser_po || '***' || ls_created_date || '~';
          i := i + 1;
          
          x12_table(i) := 'REF*SE*' || to_char(ll_sheet_skid_num_cur) || '~';
          i := i + 1;
          
          x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now || '*ED~';
          i := i + 1;
                              
          x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED~';
          i := i + 1;
          
          select   max(coil_org_num)
          into     ls_coil_org_num_temp
          from     split_skid
          where    ab_job_num = al_ab_job_num
          and      sheet_skid_num = ll_sheet_skid_num_cur;
          
          select   coil_abc_num
          into     ll_coil_abc_num_temp
          from     split_skid
          where    ab_job_num = al_ab_job_num
          and      sheet_skid_num = ll_sheet_skid_num_cur
          and      coil_org_num = ls_coil_org_num_temp;
          
          select   lot_num, vo, coil_gauge
          into     ls_lot_num, ls_vo, ll_coil_gauge
          from     coil
          where    coil_abc_num = ll_coil_abc_num_temp;
          
          select   inbound_coil.part_num
          into     ls_enduser_part
          from     inbound_coil
                   join coil on coil.coil_org_num = inbound_coil.coil_number
          where    coil.coil_abc_num = ll_coil_abc_num_temp
          and      inbound_coil.edi_file_id =
          (
             select   max(inbound_coil.edi_file_id)
             from     inbound_coil
                      join coil on coil.coil_org_num = inbound_coil.coil_number
             where    coil.coil_abc_num = ll_coil_abc_num_temp
          );
          
          x12_table(i) := 'PO1**1*UN***VO*' || ls_vo || 
                  '*SN*' || ls_coil_org_num_temp || 
                  '*HN*' || ls_lot_num || 
                  '*JN*' || substr(ls_enduser_po, 1, instr(ls_enduser_po, '-') - 1) 
                   || '~';
          i := i + 1;
          
          x12_table(i) := 'PID*S*MAC*ST*01***67~';
          i := i + 1;
          
          select   skid_sheet_status
          into     li_skid_sheet_status
          from     sheet_skid
          where    sheet_skid_num = ll_sheet_skid_num_cur;
          
          IF li_skid_sheet_status = 2 THEN
            --x12_table(i) := 'PID*S*MA*ST*1***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
            x12_table(i) := 'PID*S*MA*ST*1***70' || '~';
            i := i + 1;
          ELSIF li_skid_sheet_status = 4 THEN
            --x12_table(i) := 'PID*S*MA*ST*3***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
            x12_table(i) := 'PID*S*MA*ST*3***70' ||'~';
            i := i + 1;
          ELSIF li_skid_sheet_status = 13 THEN
            --x12_table(i) := 'PID*S*MA*ST*8***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
            x12_table(i) := 'PID*S*MA*ST*8***70' ||'~';
            i := i + 1;
           ELSE
            --x12_table(i) := 'PID*S*MA*ST*4***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
            x12_table(i) := 'PID*S*MA*ST*4***70' ||'~';
            i := i + 1;
          END IF;
          
          x12_table(i) := 'PID*S*PR*ST*27***66A' ||'~';
          i := i + 1;
          
          x12_table(i) := 'PID*S*DAC*ST*598***73' ||'~';
          i := i + 1;
          
          x12_table(i) := 'PID*S*DAF*ST*1***72' ||'~';
          i := i + 1;
          
           x12_table(i) := 'MEA*PD*TH*' || to_char(ll_coil_gauge) ||'*ED~';
           i := i + 1;
                    
           select   f_get_part_width_per_job(al_ab_job_num)
           into     ll_part_width
           from     dual;
                    
           --x12_table(i) := 'MEA*PD*WD*' || to_char(ll_coil_width) ||'~';
           x12_table(i) := 'MEA*PD*WD*' || to_char(ll_part_width) ||'*ED~';
           i := i + 1;
                    
           select   f_get_part_length_per_job(al_ab_job_num)
           into     ll_part_length
           from     dual;
                    
           x12_table(i) := 'MEA*PD*LN*' || to_char(ll_part_length) ||'*ED~';
           i := i + 1;
           
           select   sheet_net_wt, skid_pieces
           into     ll_skid_sheet_net_wt, li_skid_pieces
           from     sheet_skid
           where    sheet_skid_num = ll_sheet_skid_num_cur;
           
           x12_table(i) := 'MEA*WT*WT*' || to_char(ll_skid_sheet_net_wt) || '*01' ||'~';
           i := i + 1;
           
           --x12_table(i) := 'MEA*CT*NA*' || to_char(li_skid_pieces) || '*PC' ||'~';
           x12_table(i) := 'MEA*CT*NA*' || to_char(li_skid_pieces) || '*PC' ||'~';
           i := i + 1;
           
           ll_parent_po := li_hl01;
            
--********************************************************************************************          
          
          for split_skid_detail_rec in split_skid_detail_cur loop 
              ll_sheet_skid_num_cur := ll_sheet_skid_num_cur; --For debugging
              ll_cur_coil := split_skid_detail_rec.coil_abc_num;
              ls_coil_org_num := split_skid_detail_rec.coil_org_num;
              
              select   count(*)
              into     ll_sheet_skid_count_4coil
              from     production_sheet_item
              where    ab_job_num = al_ab_job_num
              and      coil_abc_num = ll_cur_coil;

              coil_num(p) := ll_cur_coil;
              p := p + 1;
                          
              
              li_hl01 := li_hl01 + 1;
              
              ------------------ Changed from 'I' to 'F' ----------------------------------------
              ---- 02/06/2023 -- Changed from 'F' to 'I' ----------------------------------------
              x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(ll_parent_po) || '*I~';
              ll_parent_coil := li_hl01;
              i := i + 1;
              
              li_alphabet_pointer := li_alphabet_pointer + 1;
              --ls_letter := substr(ls_alphabet, li_alphabet_pointer, 1);
                          
              --x12_table(i) := 'PRF*' || ls_po || '***' || ls_created_date || '~';
              --i := i + 1;
                          
              --x12_table(i) := 'REF*RV*' || ls_coil_org_num || '~';                                      
              x12_table(i) := 'REF*RV*' || to_char(split_skid_detail_rec.sheet_skid_num_with_letter) || '~';
              --x12_table(i) := 'REF*RV*' || to_char(split_skid_detail_rec.sheet_skid_num) || substr(ls_alphabet, li_alphabet_pointer, 1) || '~';
              i := i + 1;
              
              x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now || '*ED~';
              i := i + 1;
                                  
              x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED~';
              i := i + 1;
              select   lot_num, vo, coil_gauge
              into     ls_lot_num, ls_vo, ll_coil_gauge
              from     coil
              where    coil_abc_num = ll_cur_coil;
              
              x12_table(i) := 'PO1**1*UN***VO*' || ls_vo || 
                      '*SN*' || ls_coil_org_num || 
                      '*HN*' || ls_lot_num || 
                      '*JN*' || substr(ls_enduser_po, 1, instr(ls_enduser_po, '-') - 1) || 
                      '*PN*' || ls_enduser_part || '~';
              i := i + 1;
              
              x12_table(i) := 'PID*S*MAC*ST*01***67~';
              i := i + 1;

              select   skid_sheet_status
              into     li_skid_sheet_status
              from     sheet_skid
              where    sheet_skid_num = ll_sheet_skid_num_cur;
              
              IF li_skid_sheet_status = 2 THEN
                --x12_table(i) := 'PID*S*MA*ST*1***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
                x12_table(i) := 'PID*S*MA*ST*1***70' || '~';
                i := i + 1;
              ELSIF li_skid_sheet_status = 4 THEN
                --x12_table(i) := 'PID*S*MA*ST*3***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
                x12_table(i) := 'PID*S*MA*ST*3***70' ||'~';
                i := i + 1;
              ELSIF li_skid_sheet_status = 13 THEN
                --x12_table(i) := 'PID*S*MA*ST*8***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
                x12_table(i) := 'PID*S*MA*ST*8***70' ||'~';
                i := i + 1;
               ELSE
                --x12_table(i) := 'PID*S*MA*ST*4***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
                x12_table(i) := 'PID*S*MA*ST*4***70' ||'~';
                i := i + 1;
              END IF;
              
              x12_table(i) := 'PID*S*PR*ST*29***66' ||'~';
              i := i + 1;
              
              x12_table(i) := 'PID*S*DAC*ST*598***73' ||'~';
              i := i + 1;
              
              x12_table(i) := 'PID*S*DAF*ST*1***72' ||'~';
              i := i + 1;
              
               x12_table(i) := 'MEA*PD*TH*' || to_char(ll_coil_gauge) ||'*ED~';
               i := i + 1;
                        
               --x12_table(i) := 'MEA*PD*WD*' || to_char(ll_coil_width) ||'~';
               x12_table(i) := 'MEA*PD*WD*' || to_char(ll_part_width) ||'*ED~';
               i := i + 1;
                        
               x12_table(i) := 'MEA*PD*LN*' || to_char(ll_part_length) ||'*ED~';
               i := i + 1;
                            
               x12_table(i) := 'MEA*WT*WT*' || to_char(split_skid_detail_rec.item_sheet_net_wt) || '*01' ||'~';
               i := i + 1;
               
               x12_table(i) := 'MEA*CT*NA*' || to_char(split_skid_detail_rec.item_skid_pieces) || '*PC' ||'~';
               i := i + 1;
               
          end loop; --for split_skid_detail_rec in split_skid_detail_cur 
    

          x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) ||'~';
          i := i + 1;
                
          x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log) ||'~';
          i := i + 1;
                
          x12_table(i) := 'GE*1*' || to_char(ll_gs_log) ||'~';
          i := i + 1;
                
          x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0') ||'~';
          i := i + 1;

          -- Write EDI to file

          if li_hl01 > 1 then
            -- write edi file only if item > 0
            select edi_file_id_seq.nextval
              into ll_edi_file_id_870
              from dual;

            edi_file        := edi_file_prefix || to_char(ll_edi_file_id_870) || '_Job-' || to_char(al_ab_job_num) || '.edi';
            edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

            for j in 0 .. i loop
              utl_file.put_line(edi_file_handle, x12_table(j));
              li_test := j;
                      
              if li_test = i - 1 then
                exit;
              end if;
            end loop;
                  
            utl_file.fclose(edi_file_handle);
          --end if; -- end writing edi file

            --edi_file        := 'send_edi_log'; /* Alex Gerlants. 04/14/2017. Commented out. */
            edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
            utl_file.put_line(edi_file_handle, 'Type: 870');
            utl_file.put_line(edi_file_handle,
                              'Sending Time: ' ||
                              to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
            utl_file.put_line(edi_file_handle,
                              'Interchange Control #: ' || ll_gs_log);
            utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
            utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
            utl_file.put_line(edi_file_handle, '');
            utl_file.put_line(edi_file_handle, '');
            utl_file.fclose(edi_file_handle);

            --For verifying 997
                  
            insert into outbound_edi_transaction
                (edi_file_id,
                 duns_from,
                 duns_to,
                 interchange_control_number,
                 group_control_number,
                 transaction_time,
                 edi_file_name,
                 fa_receive_status,
                 customer_id,
                 set_control_num,
                 transaction_type_id)
            values
                (ll_edi_file_id_870,
                 '039630926',
                 su_duns,
                 ll_gs_log,
                 ll_gs_log,
                 SYSDATE,
                 edi_file,
                 0,
                 ll_customer_id,
                 ll_st_log,
                 '870PP');   
                 
            commit;
                  
          end if; 
              
          i := 0;
          li_hl01 := 0;       
         end loop; --for split_skid_rec in split_skid_cur loop

  end if; --if (ll_item_count <> 0) then

return 1;

EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN -1;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN -2;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN -3;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN -4;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN -5;
END;
--------------------------------------------------------
--  DDL for Function F_EDI_CONST_BG_870PP_4JOB_TEST
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_CONST_BG_870PP_4JOB_TEST" 
 ( 
    al_ab_job_num           ab_job.ab_job_num%type
 )
  return integer
  
is

  edi_loc                      varchar2(50) := get_edi_destination('EDI_DIR');

  edi_file                     varchar2(50) := 'edi_out.txt';
  edi_file_prefix              varchar2(50) := 'S_const_870PP_';   --Production
  --edi_file_prefix              varchar2(50) := 's_const_870PP_';   --Development
  edi_file_handle              utl_file.file_type;
  su_duns                      varchar2(10);
  ll_customer_id               customer.customer_id%type;
  ll_cur_coil                  coil.coil_abc_num%type;
  ll_gs_log                    integer;
  ll_st_log                    integer;
  ls_today                     varchar2(20) := to_char(sysdate, 'YYYYMMDD');
  ls_now                       varchar2(20) := to_char(sysdate, 'HH24MI');
  ls_po                        customer_order.orig_customer_po%type;
  ls_enduser_po                customer_order.enduser_po%type;
  ls_today_2digits_year        varchar2(20) := to_char(sysdate, 'YYMMDD');
  ls_coil_org_num              coil.coil_org_num%type;
  ll_edi_file_id_870           integer;
  ll_item_count                integer;
  li_hl01                      integer;
  ls_created_date              varchar(8);
  ls_vo                        coil.vo%type;
  ls_lot_num                   coil.lot_num%type;
  ls_enduser_part              order_item.enduser_part_num%type;
  ll_parent_coil               number(8);
  ll_parent_po                 number(8);
  ll_sheet_skid_count_4coil    number(8);
  ll_coil_gauge                coil.coil_gauge%type;
  ll_part_length               rectangle.rt_length%type;
  ll_part_width                rectangle.rt_width%type;
  ll_sheet_skid_num_cur        sheet_skid.sheet_skid_num%type;
  ls_coil_org_num_temp         coil.coil_org_num%type;
  ll_coil_abc_num_temp         coil.coil_abc_num%type;
  li_skid_sheet_status         sheet_skid.skid_sheet_status%type;
  ll_skid_sheet_net_wt         sheet_skid.sheet_net_wt%type;
  li_skid_pieces               sheet_skid.skid_pieces%type;
  li_alphabet_pointer          number(2) := 0;
  li_split_skid_count          number(2);
  li_test                      number(3);
  ll_order_po                  number(8);
  li_skid_pieces_actual        number(4);
  li_skid_pieces_required      number(4);

  cursor split_skid_cur is
  select   sheet_skid_num, 
           sum(item_skid_pieces) total_skid_pieces
  from     split_skid
  where    ab_job_num = al_ab_job_num
  group by sheet_skid_num
  order by sheet_skid_num;
  
  split_skid_rec  split_skid_cur%ROWTYPE;
  
  cursor split_skid_detail_cur is
  select   ab_job_num,
           coil_abc_num,
           sheet_skid_num,
           sheet_skid_num_with_letter,
           coil_org_num,
           item_sheet_net_wt,
           item_skid_pieces,
           nvl(suffix, '')
  from     split_skid
  where    sheet_skid_num = ll_sheet_skid_num_cur
  order by sheet_skid_num,
           nvl(suffix, '');
  
  split_skid_detail_rec  split_skid_detail_cur%ROWTYPE;

  type store_tabletype is table of varchar2(32767) index by binary_integer;
  x12_table store_tabletype;
  
  i         binary_integer := 0;

  type coil_num_type is table of coil.coil_abc_num%type index by binary_integer;
  coil_num coil_num_type;
  
  p binary_integer :=0;


BEGIN
  
    --Check if correct customer
    select  customer_order.orig_customer_id, customer.customer_duns_number_string
    into    ll_customer_id, su_duns
    from    ab_job
            join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
            join customer on customer.customer_id = customer_order.orig_customer_id
    where   ab_job.ab_job_num = al_ab_job_num;
    
    if ll_customer_id <> 2776 then
      return 200; --Wrong customer
    end if;

    i              := 0;
    p              := 0;

    
    select customer_order.orig_customer_po, enduser_po
    into   ls_po, ls_enduser_po
    from   ab_job
           join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
    where  ab_job.ab_job_num = al_ab_job_num;
    
    select   count(*)
    into     ll_item_count
    from     split_skid
    where    ab_job_num = al_ab_job_num
    order by sheet_skid_num;
    
    select count(*)
    into   ll_item_count
    from   split_skid
    where  ab_job_num = al_ab_job_num;

    if (ll_item_count <> 0) then
    
       ---------  Split skid loop ------------------------------------
        for split_skid_rec in split_skid_cur loop
         
        ---------------------------------------------------------------------------------
         select distinct customer_order.orig_customer_po, to_char(customer_order.created_date, 'yyyymmdd'), enduser_po
         into   ls_po, ls_created_date, ls_enduser_po
         from   ab_job
                join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
         where  ab_job.ab_job_num = al_ab_job_num; 
         
         select edi_st_log_seq.nextval into ll_st_log from dual;
         select edi_gs_log_seq.nextval into ll_gs_log from dual;
              
         --Production
         x12_table(i) := 'ISA*00*' ||
                    '          *00*          *01*039630926T     *01*043207177      *' ||
                    ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                    lpad(to_char(ll_gs_log), 9, '0') || '*0*P*@~';

          --Development                
          --x12_table(i) := 'ISA*00*' ||
          --            '          *00*          *ZZ*2NDSFTP        *01*043207177      *' ||
          --            ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
          --            lpad(to_char(ll_gs_log), 9, '0') || '*0*T*@~';
          i := i + 1;
              
          --Production
          x12_table(i) := 'GS*RS*039630926T*' || '043207177' || '*' || ls_today || '*' 
                          || ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010~';
                              
          --Development
          --x12_table(1) := 'GS*RS*2NDSFTP*' || '043207177' || '*' || ls_today || '*' ||
          --               ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010~';
          i := i + 1;
              
          x12_table(i) := 'ST*870PP*' || to_char(ll_st_log) || '~';
          i := i + 1;
          x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                          '***' || ls_now || '*****~';
          i := i + 1;
              
          x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now || '*ED~';
          i := i + 1;
              
          x12_table(i) := 'N1*MF**1*' || su_duns || '~';
          i := i + 1;
              
          x12_table(i) := 'N1*OU*ALUMINUM BLANKING COMPANY*1*039630926~';
          i := i + 1;
          
          li_hl01 := 0;
          li_hl01 := li_hl01 + 1;

          x12_table(i) := 'HL*' || to_char(li_hl01) || '**O*1~';
          i := i + 1;
          
          ----------------------------------------------------------------------
        
          ll_sheet_skid_num_cur := split_skid_rec.sheet_skid_num;
          ll_order_po := li_hl01;

          select   count(*)
          into     li_split_skid_count
          from     split_skid
          where    sheet_skid_num = ll_sheet_skid_num_cur;
          
          select   order_item.pieces_skid
          into     li_skid_pieces_required
          from     order_item
                   join ab_job on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
          where    ab_job.ab_job_num = al_ab_job_num;
          
          /*
          select   distinct order_item.pieces_skid
          into     li_skid_pieces_required
          from     production_sheet_item
                   join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num       
                   join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
                   join ab_job on production_sheet_item.ab_job_num = ab_job.ab_job_num
                   join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
                   join order_item on customer_order.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
          where    sheet_skid.sheet_skid_num = ll_sheet_skid_num_cur
          and      production_sheet_item.ab_job_num = al_ab_job_num;
          */   
         
          select   sum(item_skid_pieces) --Actual pieces on skid
          into    li_skid_pieces_actual
          from     split_skid
          where    sheet_skid_num = ll_sheet_skid_num_cur
          and
          (
            ab_job_num = al_ab_job_num
            or
            suffix <= (select max(suffix) from split_skid where ab_job_num = al_ab_job_num)
          );
          
          if li_split_skid_count > 1 and li_skid_pieces_actual >= li_skid_pieces_required then --ll_sheet_skid_num_cur is not a combined skid or skid not full
            li_split_skid_count := li_split_skid_count; --This is just a dummy statement to fill the space for true condition
          else
            continue;
          end if;  
          
          x12_table(i) := 'PRF*' || ls_enduser_po || '*0*0*' || ls_created_date || '~';
          i := i + 1;
          
          li_hl01 := li_hl01 + 1;
          
          x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(ll_order_po) || '*F~';
          i := i + 1;
          
          x12_table(i) := 'PRF*' || ls_enduser_po || '***' || ls_created_date || '~';
          i := i + 1;
          
          x12_table(i) := 'REF*SE*' || to_char(ll_sheet_skid_num_cur) || '~';
          i := i + 1;
          
          x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now || '*ED~';
          i := i + 1;
                              
          x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED~';
          i := i + 1;
          
          select   max(coil_org_num)
          into     ls_coil_org_num_temp
          from     split_skid
          where    ab_job_num = al_ab_job_num
          and      sheet_skid_num = ll_sheet_skid_num_cur;
          
          select   coil_abc_num
          into     ll_coil_abc_num_temp
          from     split_skid
          where    ab_job_num = al_ab_job_num
          and      sheet_skid_num = ll_sheet_skid_num_cur
          and      coil_org_num = ls_coil_org_num_temp;
          
          select   lot_num, vo, coil_gauge
          into     ls_lot_num, ls_vo, ll_coil_gauge
          from     coil
          where    coil_abc_num = ll_coil_abc_num_temp;
          
          select   inbound_coil.part_num
          into     ls_enduser_part
          from     inbound_coil
                   join coil on coil.coil_org_num = inbound_coil.coil_number
          where    coil.coil_abc_num = ll_coil_abc_num_temp
          and      inbound_coil.edi_file_id =
          (
             select   max(inbound_coil.edi_file_id)
             from     inbound_coil
                      join coil on coil.coil_org_num = inbound_coil.coil_number
             where    coil.coil_abc_num = ll_coil_abc_num_temp
          );
          
          x12_table(i) := 'PO1**1*UN***VO*' || ls_vo || 
                  '*SN*' || ls_coil_org_num_temp || 
                  '*HN*' || ls_lot_num || 
                  '*JN*' || substr(ls_enduser_po, 1, instr(ls_enduser_po, '-') - 1) 
                   || '~';
          i := i + 1;
          
          x12_table(i) := 'PID*S*MAC*ST*01***67~';
          i := i + 1;
          
          select   skid_sheet_status
          into     li_skid_sheet_status
          from     sheet_skid
          where    sheet_skid_num = ll_sheet_skid_num_cur;
          
          IF li_skid_sheet_status = 2 THEN
            --x12_table(i) := 'PID*S*MA*ST*1***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
            x12_table(i) := 'PID*S*MA*ST*1***70' || '~';
            i := i + 1;
          ELSIF li_skid_sheet_status = 4 THEN
            --x12_table(i) := 'PID*S*MA*ST*3***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
            x12_table(i) := 'PID*S*MA*ST*3***70' ||'~';
            i := i + 1;
          ELSIF li_skid_sheet_status = 13 THEN
            --x12_table(i) := 'PID*S*MA*ST*8***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
            x12_table(i) := 'PID*S*MA*ST*8***70' ||'~';
            i := i + 1;
           ELSE
            --x12_table(i) := 'PID*S*MA*ST*4***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
            x12_table(i) := 'PID*S*MA*ST*4***70' ||'~';
            i := i + 1;
          END IF;
          
          x12_table(i) := 'PID*S*PR*ST*27***66A' ||'~';
          i := i + 1;
          
          x12_table(i) := 'PID*S*DAC*ST*598***73' ||'~';
          i := i + 1;
          
          x12_table(i) := 'PID*S*DAF*ST*1***72' ||'~';
          i := i + 1;
          
           x12_table(i) := 'MEA*PD*TH*' || to_char(ll_coil_gauge) ||'*ED~';
           i := i + 1;
                    
           select   f_get_part_width_per_job(al_ab_job_num)
           into     ll_part_width
           from     dual;
                    
           --x12_table(i) := 'MEA*PD*WD*' || to_char(ll_coil_width) ||'~';
           x12_table(i) := 'MEA*PD*WD*' || to_char(ll_part_width) ||'*ED~';
           i := i + 1;
                    
           select   f_get_part_length_per_job(al_ab_job_num)
           into     ll_part_length
           from     dual;
                    
           x12_table(i) := 'MEA*PD*LN*' || to_char(ll_part_length) ||'*ED~';
           i := i + 1;
           
           select   sheet_net_wt, skid_pieces
           into     ll_skid_sheet_net_wt, li_skid_pieces
           from     sheet_skid
           where    sheet_skid_num = ll_sheet_skid_num_cur;
           
           x12_table(i) := 'MEA*WT*WT*' || to_char(ll_skid_sheet_net_wt) || '*01' ||'~';
           i := i + 1;
           
           --x12_table(i) := 'MEA*CT*NA*' || to_char(li_skid_pieces) || '*PC' ||'~';
           x12_table(i) := 'MEA*CT*NA*' || to_char(li_skid_pieces) || '*PC' ||'~';
           i := i + 1;
           
           ll_parent_po := li_hl01;
            
--********************************************************************************************          
          
          for split_skid_detail_rec in split_skid_detail_cur loop 
              ll_sheet_skid_num_cur := ll_sheet_skid_num_cur; --For debugging
              ll_cur_coil := split_skid_detail_rec.coil_abc_num;
              ls_coil_org_num := split_skid_detail_rec.coil_org_num;
              
              select   count(*)
              into     ll_sheet_skid_count_4coil
              from     production_sheet_item
              where    ab_job_num = al_ab_job_num
              and      coil_abc_num = ll_cur_coil;

              coil_num(p) := ll_cur_coil;
              p := p + 1;
                          
              
              li_hl01 := li_hl01 + 1;
              
              ------------------ Changed from 'I' to 'F' ----------------------------------------
              ---- 02/06/2023 -- Changed from 'F' to 'I' ----------------------------------------
              x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(ll_parent_po) || '*I~';
              ll_parent_coil := li_hl01;
              i := i + 1;
              
              li_alphabet_pointer := li_alphabet_pointer + 1;
              --ls_letter := substr(ls_alphabet, li_alphabet_pointer, 1);
                          
              --x12_table(i) := 'PRF*' || ls_po || '***' || ls_created_date || '~';
              --i := i + 1;
                          
              --x12_table(i) := 'REF*RV*' || ls_coil_org_num || '~';                                      
              x12_table(i) := 'REF*RV*' || to_char(split_skid_detail_rec.sheet_skid_num_with_letter) || '~';
              --x12_table(i) := 'REF*RV*' || to_char(split_skid_detail_rec.sheet_skid_num) || substr(ls_alphabet, li_alphabet_pointer, 1) || '~';
              i := i + 1;
              
              x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now || '*ED~';
              i := i + 1;
                                  
              x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED~';
              i := i + 1;
              select   lot_num, vo, coil_gauge
              into     ls_lot_num, ls_vo, ll_coil_gauge
              from     coil
              where    coil_abc_num = ll_cur_coil;
              
              x12_table(i) := 'PO1**1*UN***VO*' || ls_vo || 
                      '*SN*' || ls_coil_org_num || 
                      '*HN*' || ls_lot_num || 
                      '*JN*' || substr(ls_enduser_po, 1, instr(ls_enduser_po, '-') - 1) || 
                      '*PN*' || ls_enduser_part || '~';
              i := i + 1;
              
              x12_table(i) := 'PID*S*MAC*ST*01***67~';
              i := i + 1;

              select   skid_sheet_status
              into     li_skid_sheet_status
              from     sheet_skid
              where    sheet_skid_num = ll_sheet_skid_num_cur;
              
              IF li_skid_sheet_status = 2 THEN
                --x12_table(i) := 'PID*S*MA*ST*1***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
                x12_table(i) := 'PID*S*MA*ST*1***70' || '~';
                i := i + 1;
              ELSIF li_skid_sheet_status = 4 THEN
                --x12_table(i) := 'PID*S*MA*ST*3***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
                x12_table(i) := 'PID*S*MA*ST*3***70' ||'~';
                i := i + 1;
              ELSIF li_skid_sheet_status = 13 THEN
                --x12_table(i) := 'PID*S*MA*ST*8***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
                x12_table(i) := 'PID*S*MA*ST*8***70' ||'~';
                i := i + 1;
               ELSE
                --x12_table(i) := 'PID*S*MA*ST*4***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
                x12_table(i) := 'PID*S*MA*ST*4***70' ||'~';
                i := i + 1;
              END IF;
              
              x12_table(i) := 'PID*S*PR*ST*29***66' ||'~';
              i := i + 1;
              
              x12_table(i) := 'PID*S*DAC*ST*598***73' ||'~';
              i := i + 1;
              
              x12_table(i) := 'PID*S*DAF*ST*1***72' ||'~';
              i := i + 1;
              
               x12_table(i) := 'MEA*PD*TH*' || to_char(ll_coil_gauge) ||'*ED~';
               i := i + 1;
                        
               --x12_table(i) := 'MEA*PD*WD*' || to_char(ll_coil_width) ||'~';
               x12_table(i) := 'MEA*PD*WD*' || to_char(ll_part_width) ||'*ED~';
               i := i + 1;
                        
               x12_table(i) := 'MEA*PD*LN*' || to_char(ll_part_length) ||'*ED~';
               i := i + 1;
                            
               x12_table(i) := 'MEA*WT*WT*' || to_char(split_skid_detail_rec.item_sheet_net_wt) || '*01' ||'~';
               i := i + 1;
               
               x12_table(i) := 'MEA*CT*NA*' || to_char(split_skid_detail_rec.item_skid_pieces) || '*PC' ||'~';
               i := i + 1;
               
          end loop; --for split_skid_detail_rec in split_skid_detail_cur 
    

          x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) ||'~';
          i := i + 1;
                
          x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log) ||'~';
          i := i + 1;
                
          x12_table(i) := 'GE*1*' || to_char(ll_gs_log) ||'~';
          i := i + 1;
                
          x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0') ||'~';
          i := i + 1;

          -- Write EDI to file

          if li_hl01 > 1 then
            -- write edi file only if item > 0
            select edi_file_id_seq.nextval
              into ll_edi_file_id_870
              from dual;

            edi_file        := edi_file_prefix || to_char(ll_edi_file_id_870) || '_Job-' || to_char(al_ab_job_num) || '.edi';
            edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

            for j in 0 .. i loop
              utl_file.put_line(edi_file_handle, x12_table(j));
              li_test := j;
                      
              if li_test = i - 1 then
                exit;
              end if;
            end loop;
                  
            utl_file.fclose(edi_file_handle);
          --end if; -- end writing edi file

            --edi_file        := 'send_edi_log'; /* Alex Gerlants. 04/14/2017. Commented out. */
            edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
            utl_file.put_line(edi_file_handle, 'Type: 870');
            utl_file.put_line(edi_file_handle,
                              'Sending Time: ' ||
                              to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
            utl_file.put_line(edi_file_handle,
                              'Interchange Control #: ' || ll_gs_log);
            utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
            utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
            utl_file.put_line(edi_file_handle, '');
            utl_file.put_line(edi_file_handle, '');
            utl_file.fclose(edi_file_handle);

            --For verifying 997
                  
            insert into outbound_edi_transaction
                (edi_file_id,
                 duns_from,
                 duns_to,
                 interchange_control_number,
                 group_control_number,
                 transaction_time,
                 edi_file_name,
                 fa_receive_status,
                 customer_id,
                 set_control_num,
                 transaction_type_id)
            values
                (ll_edi_file_id_870,
                 '039630926',
                 su_duns,
                 ll_gs_log,
                 ll_gs_log,
                 SYSDATE,
                 edi_file,
                 0,
                 ll_customer_id,
                 ll_st_log,
                 '870PP');   
                 
            commit;
                  
          end if; 
              
          i := 0;
          li_hl01 := 0;       
         end loop; --for split_skid_rec in split_skid_cur loop

  end if; --if (ll_item_count <> 0) then

return 1;

EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN -1;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN -2;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN -3;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN -4;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN -5;
END;
--------------------------------------------------------
--  DDL for Function F_EDI_CONST_BG_870_4JOB_FIX
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_CONST_BG_870_4JOB_FIX" 
 ( 
    al_ab_job_num           ab_job.ab_job_num%type,
    as_user_id              ab_job_870_history.user_id%type,
    al_coil_abc_num         coil.coil_abc_num%type,
    as_original_or_resend   varchar2
    
 )
  return integer
  
is

  /*
  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   Customer: Aleris(1980) DUNS:964790856     EDI ID:964790856      QUALIFIER: ZZ

   End User: Aleris, Customer ID 1980
   */

  --alex gerlants. 11/15/2016. commented out, and added the line after.
  --edi_loc               varchar2(50) := '/templar/templar/incoming/senddata';
  edi_loc                                       varchar2(50) := get_edi_destination('EDI_DIR');

  edi_file                                      varchar2(50) := 'edi_out.txt';
  edi_file_prefix                             varchar2(50) := 'S_const_870_';   --production
  --edi_file_prefix                               varchar2(50) := 's_const_870_';   --development
  edi_file_handle                               utl_file.file_type;
  su_duns                                       varchar2(10);
  ll_customer_id                                customer.customer_id%type;
  ll_cur_coil                                   coil.coil_abc_num%type;
  ll_gs_log                                     integer;
  ll_st_log                                     integer;
  ls_today                                      varchar2(20) := to_char(sysdate, 'YYYYMMDD');
  ls_now                                        varchar2(20) := to_char(sysdate, 'HH24MI');
  ls_po                                         customer_order.orig_customer_po%type;
  ls_enduser_po                                 customer_order.enduser_po%type;
  ls_finished_goods                             varchar2(32);
  ls_cust_prod_line                             varchar2(8);
  ls_today_2digits_year                         varchar2(20) := to_char(sysdate, 'YYMMDD');
  ld_scrap_870_date                             ab_job.scrap_870_date%type;
  ls_coil_org_num                               coil.coil_org_num%type;
  ls_heat                                       coil.lot_num%type;
  ll_scrap_nw                                   coil.net_wt%type;
  ll_edi_file_id_870                            integer;
  li_hl01                                       integer;
  ls_created_date                               varchar(8);
  ls_vo                                         coil.vo%type;
  ls_lot_num                                    coil.lot_num%type;
  ls_enduser_part                               order_item.enduser_part_num%type;
  ll_parent_coil                                number(8);
  ll_parent_po                                  number(8);
  ll_ab_job_num                                 number(8);
  ls_letter                                     char(1);   --12/23/2019
  ll_sheet_skid_count_4coil                     number(8);
  li_rtn                                        number(4);
  ll_psi_870_count                              number(3);
  ll_coil_gauge                                 coil.coil_gauge%type;
  ll_coil_width                                 coil.coil_width%type;
  ll_part_length                                rectangle.rt_length%type;
  ll_part_width                                 rectangle.rt_width%type;
  ls_finished_goods_material_num                order_item.finished_goods_material_num%type;
  ls_consumed_coil_num                          coil.consumed_coil_num%type;
  ls_material_num                               coil.material_num%type;
  li_sheet_skid_count                           number(3);
  li_count                                      number(2);
  li_split_skid_count                           number(2);
  ll_coil_length_left                           number(10);   --07/24/2023. Extra block for rejected coil
  li_coil_status                                coil.coil_status%type;
  ll_lfeed                                      coil.lfeed%type;
  ll_net_wt                                     coil.net_wt%type;
  ll_net_wt_balance                             coil.net_wt_balance%type;
  
  
  cursor const_870_item_cur is
  select production_sheet_item.ab_job_num,
         production_sheet_item.coil_abc_num,
         production_sheet_item.prod_item_pieces,
         production_sheet_item.prod_item_num,
         sheet_skid.sheet_skid_num,
         production_sheet_item.prod_item_net_wt,
         sheet_skid.skid_sheet_status,
         sheet_skid.sheet_skid_display_num,
         sheet_skid.sheet_net_wt,
         sheet_skid.skid_pieces,
         coil.coil_org_num,
         coil.lot_num,
         nvl(coil.consumed_coil_num, ' ') consumed_coil,
         nvl(coil.material_num, ' ') material_num,
         nvl(customer_order.sales_order, ' ') sales_order,
         nvl(customer_order.orig_customer_po, 'NA') customer_po,
         nvl(order_item.enduser_part_num, ' ') enduser_parts,
         nvl(order_item.cust_prod_line_id, 'NA') customer_line_id,
         nvl(order_item.finished_goods_material_num, 'NA') finished_goods,
         (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
         null done,
         order_item.pieces_skid
  from   production_sheet_item
         join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num       
         join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
         join coil on coil.coil_abc_num = production_sheet_item.coil_abc_num
         join ab_job on production_sheet_item.ab_job_num = ab_job.ab_job_num
         join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
         join order_item on customer_order.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
  where  coil.customer_id = ll_customer_id
  and    ab_job.ab_job_num = al_ab_job_num
  and    customer_order.enduser_po = ls_enduser_po
  and    sheet_skid.skid_sheet_status in (0, 2, 4, 7, 13, 12, 16) -- 2: ready; 8: warehouse ready; 13: partial ready; 7: partial; 12: sample; 4: onhold
                                                                    --alex gerlants. 03/22/2019. added new status 16-hold for cert
  and    production_sheet_item.coil_abc_num = ll_cur_coil
  order by
         sheet_skid.sheet_skid_num
  ;
  
  item_rec  const_870_item_cur%ROWTYPE;

  cursor const_scrap_870_cur is
  select process_coil.coil_abc_num,
         process_coil.process_coil_status,
         process_coil.process_quantity,
         nvl(process_coil.process_end_wt, 0),
         sum(nvl(process_coil.process_end_wt, 0)),
         sum(nvl(production_sheet_item.prod_item_net_wt, 0)),
         case process_coil.process_coil_status
            when 7 then --Rebanded coils
               --(process_coil.process_quantity - sum(production_sheet_item.prod_item_net_wt) - (select process_end_wt from process_coil pc where pc.ab_job_num = 101143 and pc.coil_abc_num = process_coil.coil_abc_num))
               (process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - nvl(process_coil.process_end_wt, 0))
            when 3 then --Rejected coils
               case (select count(*) from production_sheet_item psi where psi.ab_job_num = al_ab_job_num and psi.coil_abc_num = process_coil.coil_abc_num)
                 when 0 then --Rejected coils without sheets
                   (process_coil.process_quantity - sum(nvl(process_coil.process_end_wt, 0)))
                 else --Rejected coils with sheets
                   (process_coil.process_quantity - nvl(process_coil.process_end_wt, 0) - sum(nvl(production_sheet_item.prod_item_net_wt, 0)))     
                end
                
                
                
             else
               (process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - sum(nvl(process_coil.process_end_wt, 0)))
         end scrap_net_wt
  from   process_coil
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         join ab_job on ab_job.ab_job_num = process_coil.ab_job_num and coil.coil_abc_num = process_coil.coil_abc_num
         left outer join production_sheet_item on production_sheet_item.ab_job_num = process_coil.ab_job_num and production_sheet_item.coil_abc_num = process_coil.coil_abc_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    coil.coil_abc_num = ll_cur_coil
  group by
         process_coil.coil_abc_num,
         process_coil.process_coil_status,
         process_coil.process_quantity,
         process_coil.process_end_wt
  order by
         process_coil.coil_abc_num;
  
  scrap_rec  const_scrap_870_cur%ROWTYPE;

  type store_tabletype is table of varchar2(32767) index by binary_integer;
  x12_table store_tabletype;
  
  i         binary_integer := 0;

  type prod_item_type is table of production_sheet_item.prod_item_num%type index by binary_integer;
  item_num prod_item_type;
  
  k        binary_integer := 0;

  type coil_num_type is table of coil.coil_abc_num%type index by binary_integer;
  coil_num coil_num_type;
  
  p binary_integer :=0;


BEGIN
  
  --Check if correct customer
  select  customer_order.orig_customer_id, customer.customer_duns_number_string
  into    ll_customer_id, su_duns
  from    ab_job
          join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
          join customer on customer.customer_id = customer_order.orig_customer_id
  where   ab_job.ab_job_num = al_ab_job_num;
  
  if ll_customer_id <> 2776 then
    return 200; --Wrong customer
  end if;
  
  --Alex Gerlants. 01/08/2021
  --Added this check to avoid sending 870 for jobs that had 870 created by the old batch processing.
  --Check if 870 has already been created for al_ab_job_num using the old data fields
  select count(distinct prod_item_edi870_date)
  into   ll_psi_870_count
  from   production_sheet_item
  where  ab_job_num = al_ab_job_num
  and    coil_abc_num = al_coil_abc_num
  and    prod_item_edi870_date is not null;
  
  --if (not (ll_edi_file_id_870 is null and ld_edi_date_870 is null)) or ll_psi_870_count > 0 then --870 already created for al_ab_job_num
  if ll_psi_870_count > 0 then --870 already created for al_ab_job_num
    return 100;
  end if;

    i              := 0;
    k              := 0;
    p              := 0;

    select customer_order.orig_customer_po, enduser_po
    into   ls_po, ls_enduser_po
    from   ab_job
           join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
    where  ab_job.ab_job_num = al_ab_job_num;

    /*
    select count(distinct coil.coil_abc_num)
    into   ll_item_count
    from   production_sheet_item
           join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num       
           join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
           join coil on coil.coil_abc_num = production_sheet_item.coil_abc_num
           join ab_job on production_sheet_item.ab_job_num = ab_job.ab_job_num
           join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
    where  ab_job.ab_job_num = al_ab_job_num
    and    customer_order.orig_customer_po = ls_po
    and    (
                sheet_skid.skid_sheet_status in (0, 2, 4, 13, 12, 16)
             or sheet_skid.skid_sheet_status is null --This is for rejected coils without sheets  
           )
    ;
    */

    --if (ll_item_count <> 0) then

      select edi_st_log_seq.nextval into ll_st_log from dual;
      select edi_gs_log_seq.nextval into ll_gs_log from dual;

      --select customer.customer_duns_number_string
      --into   su_duns
      --from   customer
      --where  customer.customer_id = ll_customer_id;

       --Production
       x12_table(i) := 'ISA*00*' ||
                      '          *00*          *01*039630926T     *01*043207177      *' ||
                      ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
                      lpad(to_char(ll_gs_log), 9, '0') || '*0*P*@~';
      --Development                
      --x12_table(i) := 'ISA*00*' ||
      --            '          *00*          *ZZ*2NDSFTP        *01*043207177      *' ||
      --            ls_today_2digits_year || '*' || ls_now || '*U*00401*' ||
      --            lpad(to_char(ll_gs_log), 9, '0') || '*0*T*@~';
      i := i + 1;
      
      --Production
      x12_table(i) := 'GS*RS*039630926T*' || '043207177' || '*' || ls_today || '*' 
                      || ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010~';
                      
      --Development
      --x12_table(1) := 'GS*RS*2NDSFTP*' || '043207177' || '*' || ls_today || '*' ||
      --               ls_now || '*' || to_char(ll_gs_log) || '*X*' || '004010~';
      i := i + 1;
      
      x12_table(i) := 'ST*870*' || to_char(ll_st_log) || '~';
      i := i + 1;
      x12_table(i) := 'BSR*2*PA*' || to_char(ll_st_log) || '*' || ls_today ||
                      '***' || ls_now || '*****~';
      i := i + 1;
      
      x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now || '*ED~';
      i := i + 1;
      
      x12_table(i) := 'N1*MF**1*' || su_duns || '~';
      i := i + 1;
      
      x12_table(i) := 'N1*OU*ALUMINUM BLANKING COMPANY*1*039630926~';
      i := i + 1;
 
      li_hl01 := 0;

      --for po_rec in po_cur loop --po loop
          li_hl01 := li_hl01 + 1;

          x12_table(i) := 'HL*' || to_char(li_hl01) || '**O*1~';
          ll_parent_po := li_hl01;
          i := i + 1;
          
          --ls_po := po_rec.orig_customer_po;
          
          select    to_char(max(created_date), 'yyyymmdd')
          into      ls_created_date
          from      customer_order
          where     orig_customer_po = ls_enduser_po;
          
          --ls_created_date := to_char(po_rec.created_date, 'yyyymmdd');
          
          x12_table(i) := 'PRF*' || ls_enduser_po || '*0*0*' || ls_created_date || '~';
          i := i + 1;
          
--********************************* Coil loop begin ***********************************************************          
                        
          --for coil_rec in coil_cur loop    -- coil loop
              --ll_cur_coil := coil_rec.coil_abc_num;
              ll_cur_coil := al_coil_abc_num;
              
              select   coil_org_num
              into     ls_coil_org_num
              from     coil
              where    coil_abc_num = ll_cur_coil;
              
              --ls_coil_org_num := coil_rec.coil_org_num;
              
              select   count(*)
              into     ll_sheet_skid_count_4coil
              from     production_sheet_item
              where    ab_job_num = al_ab_job_num
              and      coil_abc_num = ll_cur_coil;

              coil_num(p) := ll_cur_coil;
              --p := p + 1;
                          
              li_hl01 := li_hl01 + 1;

              x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(ll_parent_po) || '*I*1~';
              ll_parent_coil := li_hl01;
              i := i + 1;
                          
              --x12_table(i) := 'PRF*' || ls_po || '***' || ls_created_date || '~';
              --i := i + 1;
                          
              --x12_table(i) := 'REF*RV*' || ls_coil_org_num || '~';                                      
              x12_table(i) := 'REF*RV*' || to_char(ll_cur_coil) || '~';
              i := i + 1;
              
              select  coil_org_num, consumed_coil_num, material_num, coil.vo, coil.lot_num, coil.coil_gauge, coil.coil_width
              into    ls_coil_org_num, ls_consumed_coil_num, ls_material_num, ls_vo, ls_lot_num, ll_coil_gauge, ll_coil_width
              from    coil
              where   coil_abc_num = al_coil_abc_num;
               
              select  order_item.finished_goods_material_num, enduser_part_num
              into    ls_finished_goods_material_num, ls_enduser_part
              from    ab_job   
                       join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
              where   ab_job.ab_job_num = al_ab_job_num;
               
              x12_table(i) := 'PO1**1*UN**' || '*VO*' || ls_enduser_po || '*SN*' ||
                             ls_coil_org_num || '*HN*' || ls_lot_num || 
                             '*JN*' || substr(ls_enduser_po, 1, instr(ls_vo, '-') - 1) || '*PN*' || ls_enduser_part ||'~';
              i := i + 1 ;

              select count(*)
              into   li_count
              from   production_sheet_item
              join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num       
              join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
              join coil on coil.coil_abc_num = production_sheet_item.coil_abc_num
              join ab_job on production_sheet_item.ab_job_num = ab_job.ab_job_num
              join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
              join order_item on customer_order.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
              where  coil.customer_id = ll_customer_id
              and    ab_job.ab_job_num = al_ab_job_num
              and    customer_order.enduser_po = ls_enduser_po
              and    sheet_skid.skid_sheet_status in (0, 2, 4, 7, 13, 12, 16) -- 2: ready; 8: warehouse ready; 13: partial ready; 7: partial; 12: sample; 4: onhold
                                                                                  --alex gerlants. 03/22/2019. added new status 16-hold for cert
              and    production_sheet_item.coil_abc_num = ll_cur_coil;

              for item_rec in const_870_item_cur loop   -- item loop

                  li_hl01 := li_hl01 + 1;
                  

                  x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(ll_parent_coil) || '*F~';
                  i := i + 1;

                  select nvl(customer_order.enduser_po, 'NA'),
                         nvl(order_item.cust_prod_line_id, 'NA'),
                         nvl(order_item.finished_goods_material_num, 'NA')
                  into   ls_enduser_po, ls_cust_prod_line, ls_finished_goods
                  from   ab_job
                         join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
                         join order_item on customer_order.order_abc_num = order_item.order_abc_num and ab_job.order_item_num = order_item.order_item_num
                  where  ab_job.ab_job_num = item_rec.ab_job_num;

                  x12_table(i) := 'PRF*' || ls_enduser_po || '***' || ls_created_date || '~';
                  i := i + 1;
                  
                  -----------------------------------------------------------------------------------------
                  
                  if item_rec.prod_item_pieces >= item_rec.pieces_skid then --Full skid
                    ls_letter := null;
                  else --Partial skid
                    select    count(*)
                    into      li_split_skid_count
                    from      split_skid
                    --where     ab_job_num = al_ab_job_num
                    where     sheet_skid_num = item_rec.sheet_skid_num;
                        
                          
                        
                    if li_split_skid_count <= 0 then --No rows for job and skid
                        ls_letter := 'A';
                        item_rec.sheet_skid_display_num := item_rec.sheet_skid_num || ls_letter;
                            
                        insert into split_skid values
                        (
                           al_ab_job_num,
                           ll_cur_coil,
                           item_rec.sheet_skid_num,
                           item_rec.sheet_skid_display_num,
                           ls_coil_org_num,
                           item_rec.prod_item_net_wt,
                           item_rec.prod_item_pieces,
                           ls_letter
                        );
                            
                        commit;
                    else --There is/are rows for job and skid. Check if there is a row for skid and coil
                          
                         
                      select    count(*)
                      into      li_sheet_skid_count
                      from      split_skid
                      --where     ab_job_num = al_ab_job_num
                      where     sheet_skid_num = item_rec.sheet_skid_num  
                      and       coil_abc_num = ll_cur_coil;
                          
                        
                      if li_sheet_skid_count <= 0 then --There is no row for for job, skid and coil
                        --Identify max(suffix) for 
                        select    max(suffix)
                        into      ls_letter
                        from      split_skid
                        --where     ab_job_num = al_ab_job_num
                        where     sheet_skid_num = item_rec.sheet_skid_num;
                            
                        --Select the next letter to assign to item_rec.sheet_skid_num
                        select    upper(a2.letter)
                        into      ls_letter
                        from      alphabet a1
                                  join alphabet a2 on a2.letter_number = a1.letter_number + 1
                        where     upper(a1.letter) = upper(ls_letter);
                            
                        item_rec.sheet_skid_display_num := item_rec.sheet_skid_num || ls_letter;
                            
                        insert into split_skid values
                        (
                           al_ab_job_num,
                           ll_cur_coil,
                           item_rec.sheet_skid_num,
                           item_rec.sheet_skid_display_num,
                           ls_coil_org_num,
                           item_rec.prod_item_net_wt,
                           item_rec.prod_item_pieces,
                           ls_letter
                        );
                            
                        commit;
                      else--There is a row for for skid, and coil. Just take suffix from this row
                        select    suffix
                        into      ls_letter
                        from      split_skid
                        where     ab_job_num = al_ab_job_num
                        and       coil_abc_num = ll_cur_coil
                        and       sheet_skid_num = item_rec.sheet_skid_num;
                      end if;
                    end if; 
                  end if;
                    
                  -------------------------------------------------------------------------------------------------

                  --if li_split_skid = 0 then --Not a split skid
                  --  x12_table(i) := 'REF*SE*' || to_char(item_rec.sheet_skid_num) || '~';
                  --else --Split skid
                    x12_table(i) := 'REF*SE*' || to_char(item_rec.sheet_skid_num) || ls_letter || '~';
                  --x12_table(i) := 'REF*SE*' || ls_coil_org_num || '~';
                  --end if;
                  i := i + 1;
                              
                  x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now || '*ED~';
                  i := i + 1;
                              
                  x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED~';
                  i := i + 1;
                  
                   
                  select distinct 
                            coil.vo, coil.lot_num, coil.coil_gauge, coil.coil_width, coil.coil_status
                  into      ls_vo, ls_lot_num, ll_coil_gauge, ll_coil_width, li_coil_status
                  from      coil
                            --join inbound_coil_status on inbound_coil_status.coil_number = inbound_coil.coil_number
                  where     coil.coil_abc_num = ll_cur_coil;
             
                  --Take part_num from inbound_coil table instead of order_item table
                  --Select inbound_coil.part_num from the latest BOL
                  /*
                  select   inbound_coil.part_num
                  into     ls_enduser_part
                  from     inbound_coil
                           join coil on coil.coil_org_num = inbound_coil.coil_number
                  where    coil.coil_abc_num = ll_cur_coil
                  and      inbound_coil.edi_file_id =
                  (
                     select   max(inbound_coil.edi_file_id)
                     from     inbound_coil
                              join coil on coil.coil_org_num = inbound_coil.coil_number
                     where    coil.coil_abc_num = ll_cur_coil
                  );
                  */
                  
                  --ls_enduser_part := '68362277-1';
                  ls_enduser_part := '68185636-3';
                        
                  --x12_table(i) := 'PO1**1*UN***VO*' || ls_po || '*SN*' ||
                  --                  to_char(ll_cur_coil) || '*HN*' || ls_lot_num || 
                  --                  '*JN*' || ls_vo || '*PN*' || item_rec.enduser_parts;
                  x12_table(i) := 'PO1**1*UN***VO*' || ls_enduser_po || '*SN*' ||
                                    ls_coil_org_num || '*HN*' || ls_lot_num || 
                                    '*JN*' || substr(ls_enduser_po, 1, instr(ls_vo, '-') - 1) || '*PN*' || ls_enduser_part || '~';
                  i := i + 1;

                  ll_ab_job_num := item_rec.ab_job_num;

                  --x12_table(i) := 'REF*MI*' || to_char(item_rec.ab_job_num) || '~';
                  --i := i + 1;

                  --x12_table(i) := 'REF*RV*' || to_char(item_rec.prod_item_num) ||
                  --                '*NA';
                  --i := i + 1;

                  --x12_table(i) := 'REF*IX*' || to_char(item_rec.consumed_coil);
                  --i := i + 1;
                  
                  IF item_rec.skid_sheet_status = 2 THEN
                    --x12_table(i) := 'PID*S*MA*ST*1***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
                    x12_table(i) := 'PID*S*MA*ST*1***70' || '~';
                    i := i + 1;
                  ELSIF item_rec.skid_sheet_status = 4 THEN
                    --x12_table(i) := 'PID*S*MA*ST*3***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
                    x12_table(i) := 'PID*S*MA*ST*3***70' ||'~';
                    i := i + 1;
                  ELSIF item_rec.skid_sheet_status = 13 THEN
                    --x12_table(i) := 'PID*S*MA*ST*8***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
                    x12_table(i) := 'PID*S*MA*ST*1***70' ||'~';
                    i := i + 1;
                  ELSE
                    --x12_table(i) := 'PID*S*MA*ST*4***70' || to_char(item_rec.sheet_skid_display_num) ||'~';
                    x12_table(i) := 'PID*S*MA*ST*4***70' ||'~';
                    i := i + 1;
                  END IF;
                  
                  x12_table(i) := 'PID*S*MAC*ST*01***67~';
                  i := i + 1;
                              
                  x12_table(i) := 'PID*S*PR*ST*19***66A' ||'~';
                  i := i + 1;

                  --As per Troy. 12/09/2022. Do not include the 2 segments below
                  --x12_table(i) := 'PID*S*DAC*ST*263***73' ||'~';
                  --i := i + 1;
                                             
                  --x12_table(i) := 'PID*S*DAF*ST*1***72' ||'~';
                  --i := i + 1;
                                          
                  x12_table(i) := 'MEA*PD*TH*' || to_char(ll_coil_gauge) ||'*ED~';
                  i := i + 1;
                  
                  select   f_get_part_width_per_job(al_ab_job_num)
                  into     ll_part_width
                  from     dual;
                  
                  --x12_table(i) := 'MEA*PD*WD*' || to_char(ll_coil_width) ||'~';
                  x12_table(i) := 'MEA*PD*WD*' || to_char(ll_part_width) ||'*ED~';
                  i := i + 1;
                  
                  select   f_get_part_length_per_job(al_ab_job_num)
                  into     ll_part_length
                  from     dual;
                  
                  x12_table(i) := 'MEA*PD*LN*' || to_char(ll_part_length) ||'*ED~';
                  i := i + 1;
                              
                  x12_table(i) := 'MEA*WT*WT*' || to_char(item_rec.prod_item_net_wt) || '*01' ||'~';
                  i := i + 1;
                              
                  --x12_table(i) := 'MEA*WT*WT*G*' || to_char(item_rec.skid_gross_wt) || '*01' ||'~';
                  --i := i + 1;
                              
                  x12_table(i) := 'MEA*CT*NA*' || to_char(item_rec.prod_item_pieces) ||
                                  '*PC' ||'~';
                  i := i + 1;

                   item_num(k) := item_rec.prod_item_num;
                  k := k + 1;

              end loop; --for item_rec in const_870_item_cur loop   -- item loop

              select scrap_870_date, coil_org_num, lot_num
              into   ld_scrap_870_date, ls_coil_org_num, ls_heat
              from   coil
              where  coil_abc_num = ll_cur_coil;

              --if (ld_scrap_870_date is null) then  -- scrap not sent

                 for scrap_rec in const_scrap_870_cur loop    -- scrap loop
                    --ll_scrap_nw := scrap_rec.process_quan - scrap_rec.process_end_wt - ll_prime_nw;
                    ll_scrap_nw := scrap_rec.scrap_net_wt;

                    if ll_scrap_nw > 0 then
                      
                       select   coil_status
                       into     li_coil_status
                       from     coil
                       where    coil_abc_num = ll_cur_coil;
                    
                       if li_coil_status = 3 and ll_sheet_skid_count_4coil <= 0 then --ll_cur_coil is a fully scrapped (rejected) coil without good material
                         --li_rtn := f_edi_const_870_reject_4job(al_ab_job_num, ll_cur_coil, as_user_id, as_original_or_resend);
                         li_rtn := 2;
                         
                         --return 1; --TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY TEST ONLY
                         
                         continue; --06/19/2020. bypass for fully scrapped coil.
                                   --It is in a separate 870 created in f_edi_novelis_870_scrap_coil()
                       end if;

                       li_hl01 := li_hl01 + 1;

                       --x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*F' ||'~';
                       x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(ll_parent_coil) || '*F' ||'~';
                       i := i + 1;

                       if (ls_po <> ls_finished_goods) and (ls_po <> 'NA' ) then
                          x12_table(i) := 'PRF*' || ls_enduser_po || '***' || ls_created_date ||'~';
                          i := i + 1;
                       end if;

                       x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now || '*ED' ||'~';
                       i := i + 1;
                                            
                       x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED' ||'~';
                       i := i + 1;

                        --x12_table(i) := 'PO1**1*UN****' || '***SN*' || scrap_rec.coil_org_num ;
                                            
                        --ls_temp := 'PO1**1*UN**' || '*VO*' || ls_po || '*SN*' ||
                        --      ls_coil_org_num || '*HN*' || ls_lot_num || 
                        --      '*JN*' || ls_vo ||'~';
                                            
                        x12_table(i) := 'PO1**1*UN**' || '*VO*' || ls_enduser_po || '*SN*' ||
                              ls_coil_org_num || '*HN*' || ls_lot_num || 
                              '*JN*' || substr(ls_enduser_po, 1, instr(ls_enduser_po, '-') - 1) ||'~';
                        i := i + 1;
                        
                        x12_table(i) := 'PID*S*MA*ST*S***70~';
                        i := i + 1;

                        x12_table(i) := 'PID*S*MAC*ST*05***67' ||'~'; --65 means process scrap
                        i := i + 1;
                                            
                        x12_table(i) := 'PID*S*PR*ST*14***66A' ||'~';
                        i := i + 1;
                                             
                        x12_table(i) := 'PID*S*DAC*ST*263***73' ||'~';
                        i := i + 1;
                                             
                        x12_table(i) := 'PID*S*DAF*ST*1***72' ||'~';
                        i := i + 1;

                        x12_table(i) := 'MEA*WT*WT*' || to_char(ll_scrap_nw) || '*01' ||'~';
                        i := i+1;
                    end if; --if ll_scrap_nw > 0 then
                        
                 end loop; --for scrap_rec in const_scrap_870_cur loop
                 
                 if li_coil_status = 3 and ll_sheet_skid_count_4coil <= 0 then --No sheets for coil ll_cur_coil is a fully scrapped (rejected
                   return li_rtn; --870 for rejected coil is created in f_edi_const_870_reject_4job() called above
                 --07/24/2023. Extra block for rejected coil. Begin
                 --elsif li_coil_status = 3 and ll_sheet_skid_count_4coil > 0 then --ll_cur_coil is scrapped (rejected) with good material
                 elsif (li_coil_status = 3 or li_coil_status = 7) and ll_sheet_skid_count_4coil > 0 then --ll_cur_coil is scrapped (rejected) or rebanded with good material
                   li_hl01 := li_hl01 + 1;
                   
                   x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(ll_parent_coil) || '*F' ||'~';
                   i := i + 1;
                   
                   x12_table(i) := 'PRF*' || ls_enduser_po || '***' || ls_created_date || '~';
                   i := i + 1;
                   
                   x12_table(i) := 'REF*SE*' || to_char(al_coil_abc_num) || '~'; --???. This is production_sheet_item.prod_item_num
                   i := i + 1;
                   
                   x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now || '*ED~';
                   i := i + 1;
                   
                   x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED~';
                   i := i + 1;
                   
                   x12_table(i) := 'PO1**1*UN***VO*' || ls_enduser_po || '*SN*' ||
                                    ls_coil_org_num || '*HN*' || ls_lot_num || 
                                    '*JN*' || substr(ls_enduser_po, 1, instr(ls_enduser_po, '-') - 1) || '*PN*' || ls_enduser_part || '~';
                   i := i + 1;
                   
                   x12_table(i) := 'PID*S*MA*ST*7***68~';
                   i := i + 1;
                   
                   x12_table(i) := 'PID*S*MAC*ST*01***67~';
                   i := i + 1;
                   
                   x12_table(i) := 'PID*S*PR*ST*19***66A~';
                   i := i + 1;
                   
                   x12_table(i) := 'MEA*PD*TH*' || to_char(ll_coil_gauge) ||'*ED~';
                   i := i + 1;
                   
                   x12_table(i) := 'MEA*PD*WD*' || to_char(ll_part_width) ||'*ED~';
                   i := i + 1;
                   
                   select  coil.net_wt_balance, lfeed, net_wt
                   into    ll_net_wt_balance, ll_lfeed, ll_net_wt
                   from    coil
                   where   coil_abc_num = al_coil_abc_num;
                   
                   --ll_coil_length_left := 7764; --Troy has to provide formula to calculate ll_coil_length_left
                   ll_coil_length_left := ll_net_wt_balance / ll_net_wt * ll_lfeed;
                   
                   x12_table(i) := 'MEA*PD*LN*' || to_char(ll_coil_length_left) || '*LF~';
                   i := i + 1;
                   
                   --If li_coil_status = 3 then --Rejected coil
                   --   x12_table(i) := 'MEA*WT*WT*' || to_char(ll_net_wt_balance) || '*01' ||'~';
                   --else --li_coil_status = 7 <==Rebanded coil
                   --   x12_table(i) := 'MEA*WT*WT*' || to_char(ll_net_wt_balance) || '*01' ||'~';
                   --end if;
                   
                   x12_table(i) := 'MEA*WT*WT*' || to_char(ll_net_wt_balance) || '*01' ||'~';
                   i := i + 1;
                 --07/24/2023. Extra block for rejected coil. End
                 end if;
                    
              --end if; --if (ld_scrap_870_date is null) then
          --end loop; --for coil_rec in coil_cur loop
          
--********************************* Coil loop end ***********************************************************          
          
      --end loop; --for po_rec in po_cur loop
     
     
     
      x12_table(i) := 'CTT*' || to_char(li_hl01 - 1) ||'~';
      i := i + 1;
      x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log) ||'~';
      i := i + 1;
      x12_table(i) := 'GE*1*' || to_char(ll_gs_log) ||'~';
      i := i + 1;
      x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0') ||'~';

      -- Write EDI to file

      if li_hl01 > 1 then
        -- write edi file only if item > 0
        select edi_file_id_seq.nextval
          into ll_edi_file_id_870
          from dual;
     -- edi_file        := edi_file_prefix || to_char(ll_edi_file_id_870) || '.edi';
     -- edi_file        := 's_const_' || to_char(ll_edi_file_id_870) || '.870';
        edi_file        := edi_file_prefix || to_char(ll_edi_file_id_870) || '_Job-' || to_char(al_ab_job_num) || '.edi';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        for j in 0 .. i loop
          utl_file.put_line(edi_file_handle, x12_table(j));
        end loop;
        
        utl_file.fclose(edi_file_handle);
      end if; -- end writing edi file

      --edi_file        := 'send_edi_log'; /* Alex Gerlants. 04/14/2017. Commented out. */
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      --For verifying 997
      
      insert into outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
      values
          (ll_edi_file_id_870,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           SYSDATE,
           edi_file,
           0,
           ll_customer_id,
           ll_st_log,
           '870');
           
      --update    ab_job
      --set       edi_file_id_870 = ll_edi_file_id_870,
      --          edi_date_870 = sysdate
      --where     ab_job_num = al_ab_job_num;
 
     
      insert into ab_job_870_history
      (
         ab_job_num,
         edi_file_id,
         edi_file_name,
         create_870_date_time,
         user_id,
         notes
      )
      values
      (
         al_ab_job_num ,
         ll_edi_file_id_870,
         edi_file,
         sysdate,
         as_user_id,
         as_original_or_resend
      );

        update    ab_job
        set       edi_file_id_870 = ll_edi_file_id_870,
                  edi_date_870 = sysdate
        where     ab_job_num = al_ab_job_num;  

       --FOR m IN 0 .. k - 1 LOOP
         UPDATE production_sheet_item
         SET    prod_item_edi870_date = SYSDATE,
                edi_file_id_870 = ll_edi_file_id_870
         --WHERE  production_sheet_item.prod_item_num = item_num(m);
         WHERE  ab_job_num = al_ab_job_num
         and    production_sheet_item.coil_abc_num = al_coil_abc_num;
       --END LOOP;

        --FOR m in 0..p - 1 LOOP
          UPDATE coil
					SET    coil.scrap_870_date = sysdate
          --WHERE  coil.coil_abc_num = coil_num(m);
          WHERE  coil.coil_abc_num = al_coil_abc_num;

          UPDATE process_coil
					SET    scrap_870_date = sysdate
          --WHERE  ( coil_abc_num = coil_num(m)) AND (scrap_870_date is NULL);
          where  process_coil.coil_abc_num = al_coil_abc_num;
         --END LOOP;

        commit;
        
    --end if; --end if in select count(*)

return 1;


EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN -1;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN -2;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN -3;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN -4;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN -5;
END;
--------------------------------------------------------
--  DDL for Function F_EDI_DESADV2
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_DESADV2" (v_packing_list shipment.packing_list%TYPE)
  RETURN NUMBER IS
  v_holder              NUMBER(6, 0);
  v_cumulated_pcs       NUMBER(18, 0);
  v_outstring           VARCHAR2(32767);
  v_gs_log              NUMBER(8, 0);
  v_communication_code  VARCHAR2(128);
--  These 4 added by Patrick Reynolds 2016/02/05 for DESADV for GM GFSS
  v_address             VARCHAR2(3);
  v_bgm                 VARCHAR2(3);
  v_skip                int(3) := 0;
  v_DUNS                VARCHAR2(13) := '039630926T:01';  -- DUNS for ALBL
  DUNS                  VARCHAR2(13) := '001504935::16';  -- DUNS for NOVELIS
--
  v_carrier_description shipment.carrier_description_code%TYPE;
  v_customer_id         shipment.customer_id%TYPE;
  v_des_sh_cust_id      shipment.des_sh_cust_id%TYPE;
  v_enduser_id          shipment.shipment_enduser_id%TYPE;
  v_vehicle_prefix      shipment.vehicle_id_prefix%TYPE;
  v_vehicle_id          shipment.vehicle_id%TYPE;
--  v_return              INT(3) := 1;
  v_enduser_po          customer_order.enduser_po%TYPE;
  v_enduser_part        order_item.enduser_part_num%TYPE;
  i                     INT(3) := 1;
  cps_hl                INT(3) := 1;

  edi_file_prefix VARCHAR2(50) := 'S_alcan_gm_gm';

  exce_des_sh_cust_id EXCEPTION;
  exce_nodata         EXCEPTION;
  exce_sent           EXCEPTION;
  /* Declare output file */
  out_file       utl_file.file_type;
--  v_sender_vanid CHAR(25) := '3010007080';
  v_edi_st_seq   NUMBER(6, 0);
  CURSOR c1_cursor IS
    SELECT edi_st_log_seq.nextval FROM dual;
  CURSOR c4_cursor IS
    SELECT edi_file_id_seq.nextval FROM dual;
  v_file_id VARCHAR2(32767);
  --  v_boon_edi_sent boolean;
--  v_max_line_no  NUMBER(3, 0) := 0;
--   v_tagstring    VARCHAR2(32767);
  v_skids_count  NUMBER(3, 0);
  v_piece_count  NUMBER(8, 0) := 0;
  v_gross_weight NUMBER(12, 0) := 0;
  v_net_weight   NUMBER(12, 0) := 0;
  v_shipdate     DATE;
  v_scac         carrier.scac%TYPE;

  ls_su             VARCHAR2(50); /* Alex Gerlants. 09/02/2016 */
  ls_edi_file_name  VARCHAR2(50); /* Alex Gerlants. 09/02/2016 */

--  v_tare_weight  sheet_skid.sheet_tare_wt%TYPE := 0;
  --v_skid_num     sheet_skid.sheet_skid_num%TYPE;
  v_skid_num sheet_skid.sheet_skid_display_num%TYPE;
  TYPE name_type IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  tab_tag name_type;
  j       INT(3) := 1;

  edi_loc VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR'); --Alex Gerlants. 11/15/2016

  /*CURSOR c3_cursor IS
    SELECT "CUSTOMER_ORDER"."ENDUSER_PO",
           "ORDER_ITEM"."ENDUSER_PART_NUM",
           "ORDER_ITEM"."ORDER_ITEM_DESC",
           "PRODUCTION_SHEET_ITEM"."PROD_ITEM_PIECES",
           "SHEET_SKID_DETAIL"."PROD_ITEM_NUM",
           "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NET_WT"
      FROM "CUSTOMER_ORDER",
           "ORDER_ITEM",
           "AB_JOB",
           "PRODUCTION_SHEET_ITEM",
           "SHEET_SKID_DETAIL",
           "SHEET_SKID"
     WHERE ("ORDER_ITEM"."ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM")
       AND ("AB_JOB"."ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
       AND ("AB_JOB"."ORDER_ITEM_NUM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
       AND ("PRODUCTION_SHEET_ITEM"."AB_JOB_NUM" = "AB_JOB"."AB_JOB_NUM")
       AND ("SHEET_SKID_DETAIL"."PROD_ITEM_NUM" =
           "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NUM")
       AND ("SHEET_SKID"."SHEET_SKID_NUM" =
           "SHEET_SKID_DETAIL"."SHEET_SKID_NUM")
       AND ("SHEET_SKID"."SHEET_SKID_NUM" = v_skid_num);
*/
  CURSOR c2_cursor IS
    SELECT "SHEET_PACKING_ITEM"."SH_PACKING_ITEM",
           'MULTIPLE' "LOT_NUM",
           "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO",
           "CUSTOMER_ORDER"."ORDER_ABC_NUM",
           "CUSTOMER_ORDER"."ENDUSER_PO",
           "ORDER_ITEM"."ORDER_ITEM_NUM",
           "ORDER_ITEM"."ENDUSER_PART_NUM",
           "ORDER_ITEM"."SUPPLIER_CODE",
           "SHEET_SKID". "AB_JOB_NUM",
           "SHEET_SKID"."SHEET_SKID_NUM",
           "SHEET_SKID"."SHEET_SKID_DISPLAY_NUM",
           "SHEET_SKID"."SHEET_NET_WT",
           "SHEET_SKID"."SHEET_TARE_WT",
           "SHEET_SKID". "SKID_PIECES",
           "SHEET_SKID"."SKID_SHEET_STATUS",
           NULL "DONE"
      FROM "CUSTOMER_ORDER",
           "ORDER_ITEM",
           "SHEET_SKID",
           "AB_JOB",
           "SHIPMENT",
           "SHEET_PACKING_ITEM"
     WHERE ("ORDER_ITEM"."ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM")
       AND ("AB_JOB"."ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
       AND ("AB_JOB"."ORDER_ITEM_NUM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
       AND ("SHEET_SKID"."AB_JOB_NUM" = "AB_JOB"."AB_JOB_NUM")
       AND ("SHIPMENT"."PACKING_LIST" = "SHEET_PACKING_ITEM"."PACKING_LIST")
       AND ("SHEET_PACKING_ITEM"."SHEET_SKID_NUM" =
           "SHEET_SKID"."SHEET_SKID_NUM")
       AND ("SHIPMENT"."PACKING_LIST" = v_packing_list);
  --         and ("SHIPMENT"."SHIPMENT_EDI856_DATE" is NULL)

  --

BEGIN

  /*   SELECT shipment_edi856_date
    INTO v_shipdate
     FROM shipment
     WHERE shipment.packing_list=v_packing_list;
  IF NOT (v_shipdate IS NULL) THEN
    RETURN 100;
  END IF;  */

  SELECT customer_id, des_sh_cust_id, shipment_enduser_id
    INTO v_customer_id, v_des_sh_cust_id, v_enduser_id
    FROM shipment
   WHERE shipment.packing_list = v_packing_list;
  IF NOT SQL%FOUND THEN
    --         RAISE exce_nodata;
    RETURN - 1;
  END IF;

  /* FOR ALCAN customer only, ship to GM Pontiac plant 14/Grand Rapids/Dock15 only.
     Not sure that this check is needed as a similar one is done in F_EDI_856, lINE 120 */
     
  --Alex Gerlants. 09/20/2017. Added '2850' to the list below
  IF NOT ((v_customer_id IN (10, 35, 1153, 1459, 2505)) AND
      (v_des_sh_cust_id IN
      (69, 70, 2850, 72, 1840, 2079, 2164, 2181, 2360, 2495, 2611, 2680, 2814))) THEN
    --          RAISE exce_des_sh_cust_id;
    RETURN 200;
  END IF;
  -- Deleted 34, added 1459 6/5/2014 by James Ni
  -- Added 2505 01/25/2016 by Patrick Reynolds

  IF NOT c1_cursor%ISOPEN THEN
    OPEN c1_cursor;
  END IF;
  FETCH c1_cursor
    INTO v_edi_st_seq;
  CLOSE c1_cursor;

  SELECT edi_gs_log_seq.nextval INTO v_gs_log FROM dual;

  --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. Comment out Begin
  /*
  -- If the customer is not in the table or he has no communication_code then this will return nothing
  -- and thus throw an ORA-01403 Error.
  SELECT communication_code
    INTO v_communication_code
    FROM customer_system
   WHERE customer_id = v_des_sh_cust_id;
  */
  --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. Comment out End

  --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. Begin
  select f_get_sisco_code(v_des_sh_cust_id) --New function
  into   v_communication_code
  from   dual;
  
  if lower(nvl(v_communication_code, 'unknown')) = 'unknown' then
    return -3;  --Ship user will get message "Communication code is NOT set up in table customer_system for Destination Customer ..."
  end if;
  --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. End

  IF (v_customer_id = 2505) THEN
    v_address := 'MZ7';
    v_DUNS := 'XYY:ZZ';
    v_communication_code := '51972';
    v_bgm := '';
    v_skip := 1;
    DUNS := '039630926::16';  -- Change default DUNS from NOVELIS to ALBL;
  ELSE
    v_address := 'ALV';
    v_bgm := '351';
  END IF;

  tab_tag(j) := 'UNA:+.? ''';
  j := j + 1;

  tab_tag(j) := 'UNB+UNOA:2+' || v_DUNS || ':01+' || v_address || ':ZZ+' ||
                to_char(SYSDATE, 'YYMMDD:HH24MI') || '+' ||
                to_char(v_gs_log) || '++GMDESADV''';
  j := j + 1;

  /*     tab_tag(j) := 'UNB+UNOA:2+039630926T:01+ALV:ZZ+'
              ||to_char(sysdate,'YYMMDD:HHMM')||'+'||to_char(v_gs_log)||'++DESADVT''';
              j := j + 1;
  */

  --    tab_tag(j) := 'UNG+039630926T:01+'||v_communication_code||':92+'
  --           ||to_char(sysdate,'YYMMDD:HHMM+')||to_char(v_gs_log)||'+UN+D:97A''';
  --           j := j + 1;

  tab_tag(j) := 'UNH+' || to_char(v_edi_st_seq) || '+DESADV:D:97A:UN''';
  j := j + 1;
  tab_tag(j) := 'BGM+' || v_bgm || '+' || to_char(v_packing_list) || '+9''';
  j := j + 1;
  tab_tag(j) := 'DTM+137:' || to_char(SYSDATE, 'YYYYMMDDHH24MI') ||
                ':203''';
  j := j + 1;

  SELECT nvl(shipment_actualed_date_time, SYSDATE)
    INTO v_shipdate
    FROM shipment
   WHERE packing_list = v_packing_list;
  tab_tag(j) := 'DTM+11:' || to_char(v_shipdate, 'YYYYMMDDHH24MI') ||
                ':203''';
  j := j + 1;

  SELECT MAX(sh_packing_item)
    INTO v_skids_count
    FROM sheet_packing_item
   WHERE sheet_packing_item.packing_list = v_packing_list;

  /*if v_skids_count > 5 then
      return 300;
  end if;*/

  FOR c2_record IN c2_cursor LOOP
    v_piece_count  := v_piece_count + c2_record.skid_pieces;
    v_gross_weight := v_gross_weight + c2_record.sheet_net_wt * 0.45359 +
                      c2_record.sheet_tare_wt * 0.45359;
    v_net_weight   := v_net_weight + c2_record.sheet_net_wt * 0.45359;
    --      v_tare_weight := v_tare_weight + c2_record.SHEET_TARE_WT;
  --    Put more item here
  END LOOP;

  --    v_skids_count := c2_cursor%ROWCOUNT;

  tab_tag(j) := 'MEA+AAX+SQ+C62:' || to_char(v_skids_count) || '''';
  j := j + 1;
  tab_tag(j) := 'MEA+AAX+G+KG:' || to_char(v_gross_weight) || '''';
  j := j + 1;
  tab_tag(j) := 'MEA+AAX+N+KG:' || to_char(v_net_weight) || '''';
  j := j + 1;
  tab_tag(j) := 'RFF+MB:' || to_char(v_packing_list) || '''';
  j := j + 1;

  --tab_tag(j) := 'NAD+MI+88120::92''';
  --  j := j + 1;

  IF v_des_sh_cust_id IN (2164) THEN
    tab_tag(j) := 'NAD+MI+88835::92''';
  ELSE
    tab_tag(j) := 'NAD+MI+88120::92''';
  END IF;
  j := j + 1;
  --    tab_tag(j) := 'NAD+SU+039630926::16''';      Supplier is ABCo

  --- GM can only accept ALCAN Warren now, enable Konston in the future
  --    if v_customer_id = 1153 then
  tab_tag(j) := 'NAD+SU+' || DUNS || ''''; --Supplier is Novelis Kingston Feb8-06 by tony
  --001504935
  j := j + 1;
  --    else
  -- tab_tag(j) := 'NAD+SU+003980216::16';        --Supplier is Alcan Warren
  --  j := j + 1;
  --  end if;

  tab_tag(j) := 'NAD+ST+' || v_communication_code || '::92''';
  j := j + 1;

  /* LOC segment, need location code from Alcan or GM */

  /*    IF v_des_sh_cust_id = 69 THEN
      tab_tag(j) := 'NAD+ST+18024::92''';
      j := j + 1;
  --  ELSEIF v_des_sh_cust_id = 70 THEN
  --    tab_tag(j) := )
  --      VALUES ('NAD+ST+18231::92''');
    ELSE
      tab_tag(j) := 'NAD+ST+18231::92''';
      j := j + 1;
    END IF;    */

  tab_tag(j) := 'LOC+11+A1A2''';
  j := j + 1;

  SELECT nvl(carrier.scac, 'AAAA')
    INTO v_scac
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = v_packing_list);

  tab_tag(j) := 'TDT+25++M++' || v_scac || '::182''';
  j := j + 1;

  SELECT nvl(shipment.carrier_description_code, 'TL')
    INTO v_carrier_description
    FROM shipment
   WHERE shipment.packing_list = v_packing_list;
  IF v_carrier_description = 'TL' THEN
    v_carrier_description := 'TE';
  END IF;

  SELECT nvl(shipment.vehicle_id_prefix, 'AA'),
         nvl(shipment.vehicle_id, '1111')
    INTO v_vehicle_prefix, v_vehicle_id
    FROM shipment
   WHERE shipment.packing_list = v_packing_list;

  tab_tag(j) := 'EQD+' || v_carrier_description || '+' || v_vehicle_prefix ||
                v_vehicle_id || '''';
  j := j + 1;

  /* DETAIL LOOP BEGIN */
  --   cps_hl := 1;
  FOR c2_record IN c2_cursor LOOP

    SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
      INTO v_enduser_part
      FROM "ORDER_ITEM", "SHEET_SKID"
     WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
       AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" =
           "ORDER_ITEM"."ORDER_ITEM_NUM")
       AND ("SHEET_SKID"."SHEET_SKID_NUM" = c2_record.sheet_skid_num);

    SELECT "CUSTOMER_ORDER"."ENDUSER_PO"
      INTO v_enduser_po
      FROM "SHEET_SKID", "CUSTOMER_ORDER"
     WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
           "CUSTOMER_ORDER"."ORDER_ABC_NUM")
       AND (sheet_skid.sheet_skid_num = c2_record.sheet_skid_num);

    tab_tag(j) := 'CPS+' || to_char(cps_hl) || '++1''';
    j := j + 1;
--    tab_tag(j) := 'PAC+' || to_char(c2_record.skid_pieces) || '''';
      if (v_des_sh_cust_id IN (2611, 2814)) THEN
         tab_tag(j) := 'PAC+' || to_char(c2_record.skid_pieces) || '++AHB52679'''; -- Added by Patrick Reynolds 07-21-2016
      else
         tab_tag(j) := 'PAC+' || to_char(c2_record.skid_pieces) || ''''; -- Added by Patrick Reynolds 07-21-2016
      END IF;

    j := j + 1;
    /*    tab_tag(j) := 'QTY+52:'||TO_CHAR(c2_record.SKID_PIECES)||'''';
    j := j + 1;   */
    tab_tag(j) := 'PCI+16''';
    j := j + 1;
    /*    tab_tag(j) := 'RFF+CW:'||TO_CHAR(c2_record.SH_PACKING_ITEM)||'''';
      j := j + 1;
    tab_tag(j) := 'GIR+3+'||TO_CHAR(c2_record.SHEET_SKID_NUM)||':AW''';
      j := j + 1;  */

    v_skid_num := c2_record.sheet_skid_display_num;
    /*    FOR c3_record IN c3_cursor LOOP
        tab_tag(j) := 'LIN+++'||c3_record.ENDUSER_PART_NUM||':IN''';
        j := j + 1;
        tab_tag(j) := 'PIA+1+0:RY''';
        j := j + 1;
        tab_tag(j) := 'QTY+12:'||TO_CHAR(c3_record.PROD_ITEM_PIECES)||':EA''';
        j := j + 1;
        tab_tag(j) := 'RFF+ON:'||c3_record.ENDUSER_PO||'''';
        j := j + 1;

        tab_tag(j) := 'PCI+15+'||TO_CHAR(c2_record.SHEET_SKID_NUM)||'''';
        j := j + 1;
        tab_tag(j) := 'QTY+3:'||TO_CHAR(c3_record.PROD_ITEM_PIECES)||':EA''';
        j := j + 1;
        tab_tag(j) := 'QTY+12:'||TO_CHAR(c3_record.PROD_ITEM_PIECES)||':EA''';
        j := j + 1;
    END LOOP;
    */

    tab_tag(j) := 'LIN+++' || v_enduser_part || ':IN''';
    j := j + 1;

    -- changed to PIA+1+5:RY per Jeff Blaha 1/29/2015 email
    --  tab_tag(j) := 'PIA+1+0:RY''';
    tab_tag(j) := 'PIA+1+6:RY''';
    j := j + 1;

    /*
    SELECT SUM("SHEET_SKID"."SKID_PIECES") INTO v_cumulated_pcs
        FROM "CUSTOMER_ORDER",
             "ORDER_ITEM",
             "SHEET_SKID",
             "AB_JOB"
        WHERE  ("ORDER_ITEM"."ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM" ) and
               ("AB_JOB"."ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM") and
               ("AB_JOB"."ORDER_ITEM_NUM" = "ORDER_ITEM"."ORDER_ITEM_NUM") and
               ("SHEET_SKID"."AB_JOB_NUM" = "AB_JOB"."AB_JOB_NUM") and
               ("ORDER_ITEM"."ENDUSER_PART_NUM"=c2_record.ENDUSER_PART_NUM);
     */

    SELECT SUM(sheet_skid.skid_pieces)
      INTO v_cumulated_pcs
      FROM sheet_skid, order_item
     WHERE sheet_skid.ref_order_abc_num = order_item.order_abc_num
       AND sheet_skid.ref_order_abc_item = order_item.order_item_num
       AND order_item.enduser_part_num = c2_record.enduser_part_num;

    tab_tag(j) := 'QTY+3:' || to_char(v_cumulated_pcs) || ':EA''';
    j := j + 1;
    tab_tag(j) := 'QTY+12:' || to_char(c2_record.skid_pieces) || ':EA''';
    j := j + 1;
    tab_tag(j) := 'RFF+ON:' || v_enduser_po || '''';
    j := j + 1;
    --      tab_tag(j) := 'RFF+ON:'||c2_record.ORIG_CUSTOMER_PO||'''';
    --      j := j + 1;
  IF (v_skip = 0) THEN
      tab_tag(j) := 'PCI+15+' || to_char(c2_record.sheet_skid_display_num) || '''';
      j := j + 1;
      tab_tag(j) := 'QTY+12:' || to_char(c2_record.skid_pieces) || ':EA''';
      j := j + 1;
  END IF;

    cps_hl := cps_hl + 1;
  END LOOP;

  /* OUTPUT TO file*/
  IF NOT c4_cursor%ISOPEN THEN
    OPEN c4_cursor;
    FETCH c4_cursor
      INTO v_holder;
    CLOSE c4_cursor;
  END IF;
  v_file_id := to_char(v_holder);
--   out_file :=  UTL_FILE.FOPEN('/tmp','a','w');
-- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
--   out_file := utl_file.fopen('/templar/templar/incoming/senddata',
--                              'S_alcan_gm_gm' || v_file_id || '.desadv',  -- Change before moving to PROD
--                              'w',
--                              32767);

--Alex Gerlants. 11/15/2016. Commented out statement below, and added statement after.
  --out_file := utl_file.fopen('/templar/templar/incoming/senddata',
  --                           edi_file_prefix || v_file_id || '.edi',  -- Change before moving to PROD
  --                           'w',
  --                           32767);

  out_file := utl_file.fopen(edi_loc,
                             edi_file_prefix || v_file_id || '.edi',  -- Change before moving to PROD
                             'w',
                             32767);

  ls_edi_file_name := edi_file_prefix || v_file_id || '.edi'; /* Alex Gerlants. 09/02/2016 */

  --   out_file :=  UTL_FILE.FOPEN('/tmp','S_alcan_gm_gm'||v_file_id||'.desadv','w');
  tab_tag(j) := 'UNT+' || to_char(j - 2) || '+' || to_char(v_edi_st_seq) || '''';
  j := j + 1;

  --   tab_tag(j) := 'UNE+1+'||to_char(v_gs_log)||'''';
  --       j := j + 1;
  tab_tag(j) := 'UNZ+1+' || to_char(v_gs_log) || '''';

  FOR i IN 2 .. j LOOP
    v_outstring := tab_tag(i);
    utl_file.put(out_file, v_outstring);
    --         UTL_FILE.FFLUSH(out_file);
  END LOOP;
  utl_file.fflush(out_file);
  utl_file.fclose(out_file);

/*  This has been replaced by the UPDATE statement below.
    These columns are already updated in another function, edi_alcan_alcan_856_x12, so to update them here
    could be misleading as well as wiping out information from the aforementioned function hence the need for
    the shipment_desadv_date column in the shipment table.
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE
   WHERE shipment.packing_list = v_packing_list;
  COMMIT;
*/

--  Uncomment before moving to PROD
  --Alex Gerlants. 09/02/2016. Added ", edi_file_id_desadv = edi_file_id".
  UPDATE shipment
     SET shipment_desadv_date = SYSDATE, edi_file_id_desadv = v_file_id
   WHERE shipment.packing_list = v_packing_list;

   ----------------------------------------------------------------
   --Alex Gerlants. 09/02/2016. Begin

   select nvl(customer_duns_number_string, '00000000')
   into   ls_su
   from   customer
   where  customer_id = v_customer_id;

   If (ls_su = '00000000') Then
    Return 500; --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. Replaced "200" with "500".
   End If;

   INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (v_file_id,
     '039630926',
     ls_su,
     v_gs_log,
     v_gs_log,
     SYSDATE,
     ls_edi_file_name,
     0,
     v_customer_id,
     v_edi_st_seq,
     'desadv');


   --Alex Gerlants. 09/02/2016. End
   ----------------------------------------------------------------

  COMMIT;


  RETURN 1;

EXCEPTION
  WHEN exce_sent THEN
    --    raise_application_error(-20101,'STOP! EDI had been sent');
    --    UTL_FILE.FCLOSE(out_file);
    RETURN 100;
  WHEN exce_nodata THEN
    --     raise_application_error(-20101,'No shipment data found!');
    RETURN - 1;
  WHEN exce_des_sh_cust_id THEN
    --    raise_application_error(-20101,'This shipment does not required EDIFACT DESADV EDI!');
    RETURN 200;
  WHEN OTHERS THEN
    --    raise_application_error(-20101,'INTERNAL ERROR! PLEASE CALL 1519.');
   --  raise_application_error(-20101,'An error was encountered - ' || SQLCODE || ' -ERROR- ' || SQLERRM);
    utl_file.fclose(out_file);
    RETURN - 2;
END;
  GRANT EXECUTE ON "DBO"."F_EDI_DESADV2" TO "AGERLANTS"
--------------------------------------------------------
