--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_DESADV2_11132017" (v_packing_list shipment.packing_list%TYPE)
  RETURN NUMBER IS
  v_holder              NUMBER(6, 0);
  v_cumulated_pcs       NUMBER(18, 0);
  v_outstring           VARCHAR2(32767);
  v_gs_log              NUMBER(8, 0);
  v_communication_code  VARCHAR2(128);
--  These 4 added by Patrick Reynolds 2016/02/05 for DESADV for GM GFSS
  v_address             VARCHAR2(3);
  v_bgm                 VARCHAR2(3);
  v_skip                int(3) := 0;
  v_DUNS                VARCHAR2(13) := '039630926T:01';  -- DUNS for ALBL
  DUNS                  VARCHAR2(13) := '001504935::16';  -- DUNS for NOVELIS
--
  v_carrier_description shipment.carrier_description_code%TYPE;
  v_customer_id         shipment.customer_id%TYPE;
  v_des_sh_cust_id      shipment.des_sh_cust_id%TYPE;
  v_enduser_id          shipment.shipment_enduser_id%TYPE;
  v_vehicle_prefix      shipment.vehicle_id_prefix%TYPE;
  v_vehicle_id          shipment.vehicle_id%TYPE;
--  v_return              INT(3) := 1;
  v_enduser_po          customer_order.enduser_po%TYPE;
  v_enduser_part        order_item.enduser_part_num%TYPE;
  i                     INT(3) := 1;
  cps_hl                INT(3) := 1;

  edi_file_prefix VARCHAR2(50) := 'S_alcan_gm_gm';

  exce_des_sh_cust_id EXCEPTION;
  exce_nodata         EXCEPTION;
  exce_sent           EXCEPTION;
  /* Declare output file */
  out_file       utl_file.file_type;
--  v_sender_vanid CHAR(25) := '3010007080';
  v_edi_st_seq   NUMBER(6, 0);
  CURSOR c1_cursor IS
    SELECT edi_st_log_seq.nextval FROM dual;
  CURSOR c4_cursor IS
    SELECT edi_file_id_seq.nextval FROM dual;
  v_file_id VARCHAR2(32767);
  --  v_boon_edi_sent boolean;
--  v_max_line_no  NUMBER(3, 0) := 0;
--   v_tagstring    VARCHAR2(32767);
  v_skids_count  NUMBER(3, 0);
  v_piece_count  NUMBER(8, 0) := 0;
  v_gross_weight NUMBER(12, 0) := 0;
  v_net_weight   NUMBER(12, 0) := 0;
  v_shipdate     DATE;
  v_scac         carrier.scac%TYPE;

  ls_su             VARCHAR2(50); /* Alex Gerlants. 09/02/2016 */
  ls_edi_file_name  VARCHAR2(50); /* Alex Gerlants. 09/02/2016 */

--  v_tare_weight  sheet_skid.sheet_tare_wt%TYPE := 0;
  --v_skid_num     sheet_skid.sheet_skid_num%TYPE;
  v_skid_num sheet_skid.sheet_skid_display_num%TYPE;
  TYPE name_type IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  tab_tag name_type;
  j       INT(3) := 1;

  edi_loc VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR'); --Alex Gerlants. 11/15/2016

  /*CURSOR c3_cursor IS
    SELECT "CUSTOMER_ORDER"."ENDUSER_PO",
           "ORDER_ITEM"."ENDUSER_PART_NUM",
           "ORDER_ITEM"."ORDER_ITEM_DESC",
           "PRODUCTION_SHEET_ITEM"."PROD_ITEM_PIECES",
           "SHEET_SKID_DETAIL"."PROD_ITEM_NUM",
           "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NET_WT"
      FROM "CUSTOMER_ORDER",
           "ORDER_ITEM",
           "AB_JOB",
           "PRODUCTION_SHEET_ITEM",
           "SHEET_SKID_DETAIL",
           "SHEET_SKID"
     WHERE ("ORDER_ITEM"."ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM")
       AND ("AB_JOB"."ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
       AND ("AB_JOB"."ORDER_ITEM_NUM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
       AND ("PRODUCTION_SHEET_ITEM"."AB_JOB_NUM" = "AB_JOB"."AB_JOB_NUM")
       AND ("SHEET_SKID_DETAIL"."PROD_ITEM_NUM" =
           "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NUM")
       AND ("SHEET_SKID"."SHEET_SKID_NUM" =
           "SHEET_SKID_DETAIL"."SHEET_SKID_NUM")
       AND ("SHEET_SKID"."SHEET_SKID_NUM" = v_skid_num);
*/
  CURSOR c2_cursor IS
    SELECT "SHEET_PACKING_ITEM"."SH_PACKING_ITEM",
           'MULTIPLE' "LOT_NUM",
           "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO",
           "CUSTOMER_ORDER"."ORDER_ABC_NUM",
           "CUSTOMER_ORDER"."ENDUSER_PO",
           "ORDER_ITEM"."ORDER_ITEM_NUM",
           "ORDER_ITEM"."ENDUSER_PART_NUM",
           "ORDER_ITEM"."SUPPLIER_CODE",
           "SHEET_SKID". "AB_JOB_NUM",
           "SHEET_SKID"."SHEET_SKID_NUM",
           "SHEET_SKID"."SHEET_SKID_DISPLAY_NUM",
           "SHEET_SKID"."SHEET_NET_WT",
           "SHEET_SKID"."SHEET_TARE_WT",
           "SHEET_SKID". "SKID_PIECES",
           "SHEET_SKID"."SKID_SHEET_STATUS",
           NULL "DONE"
      FROM "CUSTOMER_ORDER",
           "ORDER_ITEM",
           "SHEET_SKID",
           "AB_JOB",
           "SHIPMENT",
           "SHEET_PACKING_ITEM"
     WHERE ("ORDER_ITEM"."ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM")
       AND ("AB_JOB"."ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
       AND ("AB_JOB"."ORDER_ITEM_NUM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
       AND ("SHEET_SKID"."AB_JOB_NUM" = "AB_JOB"."AB_JOB_NUM")
       AND ("SHIPMENT"."PACKING_LIST" = "SHEET_PACKING_ITEM"."PACKING_LIST")
       AND ("SHEET_PACKING_ITEM"."SHEET_SKID_NUM" =
           "SHEET_SKID"."SHEET_SKID_NUM")
       AND ("SHIPMENT"."PACKING_LIST" = v_packing_list);
  --         and ("SHIPMENT"."SHIPMENT_EDI856_DATE" is NULL)

  --

BEGIN

  /*   SELECT shipment_edi856_date
    INTO v_shipdate
     FROM shipment
     WHERE shipment.packing_list=v_packing_list;
  IF NOT (v_shipdate IS NULL) THEN
    RETURN 100;
  END IF;  */

  SELECT customer_id, des_sh_cust_id, shipment_enduser_id
    INTO v_customer_id, v_des_sh_cust_id, v_enduser_id
    FROM shipment
   WHERE shipment.packing_list = v_packing_list;
  IF NOT SQL%FOUND THEN
    --         RAISE exce_nodata;
    RETURN - 1;
  END IF;

  /* FOR ALCAN customer only, ship to GM Pontiac plant 14/Grand Rapids/Dock15 only.
     Not sure that this check is needed as a similar one is done in F_EDI_856, lINE 120 */
     
  --Alex Gerlants. 09/20/2017. Added '2850' to the list below
  IF NOT ((v_customer_id IN (10, 35, 1153, 1459, 2505)) AND
      (v_des_sh_cust_id IN
      (69, 70, 2850, 72, 1840, 2079, 2164, 2181, 2360, 2495, 2611, 2680, 2814))) THEN
    --          RAISE exce_des_sh_cust_id;
    RETURN 200;
  END IF;
  -- Deleted 34, added 1459 6/5/2014 by James Ni
  -- Added 2505 01/25/2016 by Patrick Reynolds

  IF NOT c1_cursor%ISOPEN THEN
    OPEN c1_cursor;
  END IF;
  FETCH c1_cursor
    INTO v_edi_st_seq;
  CLOSE c1_cursor;

  SELECT edi_gs_log_seq.nextval INTO v_gs_log FROM dual;

  -- If the customer is not in the table or he has no communication_code then this will return nothing
  -- and thus throw an ORA-01403 Error.
  SELECT communication_code
    INTO v_communication_code
    FROM customer_system
   WHERE customer_id = v_des_sh_cust_id;

  IF (v_customer_id = 2505) THEN
    v_address := 'MZ7';
    v_DUNS := 'XYY:ZZ';
    v_communication_code := '51972';
    v_bgm := '';
    v_skip := 1;
    DUNS := '039630926::16';  -- Change default DUNS from NOVELIS to ALBL;
  ELSE
    v_address := 'ALV';
    v_bgm := '351';
  END IF;

  tab_tag(j) := 'UNA:+.? ''';
  j := j + 1;

  tab_tag(j) := 'UNB+UNOA:2+' || v_DUNS || ':01+' || v_address || ':ZZ+' ||
                to_char(SYSDATE, 'YYMMDD:HH24MI') || '+' ||
                to_char(v_gs_log) || '++GMDESADV''';
  j := j + 1;

  /*     tab_tag(j) := 'UNB+UNOA:2+039630926T:01+ALV:ZZ+'
              ||to_char(sysdate,'YYMMDD:HHMM')||'+'||to_char(v_gs_log)||'++DESADVT''';
              j := j + 1;
  */

  --    tab_tag(j) := 'UNG+039630926T:01+'||v_communication_code||':92+'
  --           ||to_char(sysdate,'YYMMDD:HHMM+')||to_char(v_gs_log)||'+UN+D:97A''';
  --           j := j + 1;

  tab_tag(j) := 'UNH+' || to_char(v_edi_st_seq) || '+DESADV:D:97A:UN''';
  j := j + 1;
  tab_tag(j) := 'BGM+' || v_bgm || '+' || to_char(v_packing_list) || '+9''';
  j := j + 1;
  tab_tag(j) := 'DTM+137:' || to_char(SYSDATE, 'YYYYMMDDHH24MI') ||
                ':203''';
  j := j + 1;

  SELECT nvl(shipment_actualed_date_time, SYSDATE)
    INTO v_shipdate
    FROM shipment
   WHERE packing_list = v_packing_list;
  tab_tag(j) := 'DTM+11:' || to_char(v_shipdate, 'YYYYMMDDHH24MI') ||
                ':203''';
  j := j + 1;

  SELECT MAX(sh_packing_item)
    INTO v_skids_count
    FROM sheet_packing_item
   WHERE sheet_packing_item.packing_list = v_packing_list;

  /*if v_skids_count > 5 then
      return 300;
  end if;*/

  FOR c2_record IN c2_cursor LOOP
    v_piece_count  := v_piece_count + c2_record.skid_pieces;
    v_gross_weight := v_gross_weight + c2_record.sheet_net_wt * 0.45359 +
                      c2_record.sheet_tare_wt * 0.45359;
    v_net_weight   := v_net_weight + c2_record.sheet_net_wt * 0.45359;
    --      v_tare_weight := v_tare_weight + c2_record.SHEET_TARE_WT;
  --    Put more item here
  END LOOP;

  --    v_skids_count := c2_cursor%ROWCOUNT;

  tab_tag(j) := 'MEA+AAX+SQ+C62:' || to_char(v_skids_count) || '''';
  j := j + 1;
  tab_tag(j) := 'MEA+AAX+G+KG:' || to_char(v_gross_weight) || '''';
  j := j + 1;
  tab_tag(j) := 'MEA+AAX+N+KG:' || to_char(v_net_weight) || '''';
  j := j + 1;
  tab_tag(j) := 'RFF+MB:' || to_char(v_packing_list) || '''';
  j := j + 1;

  --tab_tag(j) := 'NAD+MI+88120::92''';
  --  j := j + 1;

  IF v_des_sh_cust_id IN (2164) THEN
    tab_tag(j) := 'NAD+MI+88835::92''';
  ELSE
    tab_tag(j) := 'NAD+MI+88120::92''';
  END IF;
  j := j + 1;
  --    tab_tag(j) := 'NAD+SU+039630926::16''';      Supplier is ABCo

  --- GM can only accept ALCAN Warren now, enable Konston in the future
  --    if v_customer_id = 1153 then
  tab_tag(j) := 'NAD+SU+' || DUNS || ''''; --Supplier is Novelis Kingston Feb8-06 by tony
  --001504935
  j := j + 1;
  --    else
  -- tab_tag(j) := 'NAD+SU+003980216::16';        --Supplier is Alcan Warren
  --  j := j + 1;
  --  end if;

  tab_tag(j) := 'NAD+ST+' || v_communication_code || '::92''';
  j := j + 1;

  /* LOC segment, need location code from Alcan or GM */

  /*    IF v_des_sh_cust_id = 69 THEN
      tab_tag(j) := 'NAD+ST+18024::92''';
      j := j + 1;
  --  ELSEIF v_des_sh_cust_id = 70 THEN
  --    tab_tag(j) := )
  --      VALUES ('NAD+ST+18231::92''');
    ELSE
      tab_tag(j) := 'NAD+ST+18231::92''';
      j := j + 1;
    END IF;    */

  tab_tag(j) := 'LOC+11+A1A2''';
  j := j + 1;

  SELECT nvl(carrier.scac, 'AAAA')
    INTO v_scac
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = v_packing_list);

  tab_tag(j) := 'TDT+25++M++' || v_scac || '::182''';
  j := j + 1;

  SELECT nvl(shipment.carrier_description_code, 'TL')
    INTO v_carrier_description
    FROM shipment
   WHERE shipment.packing_list = v_packing_list;
  IF v_carrier_description = 'TL' THEN
    v_carrier_description := 'TE';
  END IF;

  SELECT nvl(shipment.vehicle_id_prefix, 'AA'),
         nvl(shipment.vehicle_id, '1111')
    INTO v_vehicle_prefix, v_vehicle_id
    FROM shipment
   WHERE shipment.packing_list = v_packing_list;

  tab_tag(j) := 'EQD+' || v_carrier_description || '+' || v_vehicle_prefix ||
                v_vehicle_id || '''';
  j := j + 1;

  /* DETAIL LOOP BEGIN */
  --   cps_hl := 1;
  FOR c2_record IN c2_cursor LOOP

    SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
      INTO v_enduser_part
      FROM "ORDER_ITEM", "SHEET_SKID"
     WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
       AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" =
           "ORDER_ITEM"."ORDER_ITEM_NUM")
       AND ("SHEET_SKID"."SHEET_SKID_NUM" = c2_record.sheet_skid_num);

    SELECT "CUSTOMER_ORDER"."ENDUSER_PO"
      INTO v_enduser_po
      FROM "SHEET_SKID", "CUSTOMER_ORDER"
     WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
           "CUSTOMER_ORDER"."ORDER_ABC_NUM")
       AND (sheet_skid.sheet_skid_num = c2_record.sheet_skid_num);

    tab_tag(j) := 'CPS+' || to_char(cps_hl) || '++1''';
    j := j + 1;
--    tab_tag(j) := 'PAC+' || to_char(c2_record.skid_pieces) || '''';
      if (v_des_sh_cust_id IN (2611, 2814)) THEN
         tab_tag(j) := 'PAC+' || to_char(c2_record.skid_pieces) || '++AHB52679'''; -- Added by Patrick Reynolds 07-21-2016
      else
         tab_tag(j) := 'PAC+' || to_char(c2_record.skid_pieces) || ''''; -- Added by Patrick Reynolds 07-21-2016
      END IF;

    j := j + 1;
    /*    tab_tag(j) := 'QTY+52:'||TO_CHAR(c2_record.SKID_PIECES)||'''';
    j := j + 1;   */
    tab_tag(j) := 'PCI+16''';
    j := j + 1;
    /*    tab_tag(j) := 'RFF+CW:'||TO_CHAR(c2_record.SH_PACKING_ITEM)||'''';
      j := j + 1;
    tab_tag(j) := 'GIR+3+'||TO_CHAR(c2_record.SHEET_SKID_NUM)||':AW''';
      j := j + 1;  */

    v_skid_num := c2_record.sheet_skid_display_num;
    /*    FOR c3_record IN c3_cursor LOOP
        tab_tag(j) := 'LIN+++'||c3_record.ENDUSER_PART_NUM||':IN''';
        j := j + 1;
        tab_tag(j) := 'PIA+1+0:RY''';
        j := j + 1;
        tab_tag(j) := 'QTY+12:'||TO_CHAR(c3_record.PROD_ITEM_PIECES)||':EA''';
        j := j + 1;
        tab_tag(j) := 'RFF+ON:'||c3_record.ENDUSER_PO||'''';
        j := j + 1;

        tab_tag(j) := 'PCI+15+'||TO_CHAR(c2_record.SHEET_SKID_NUM)||'''';
        j := j + 1;
        tab_tag(j) := 'QTY+3:'||TO_CHAR(c3_record.PROD_ITEM_PIECES)||':EA''';
        j := j + 1;
        tab_tag(j) := 'QTY+12:'||TO_CHAR(c3_record.PROD_ITEM_PIECES)||':EA''';
        j := j + 1;
    END LOOP;
    */

    tab_tag(j) := 'LIN+++' || v_enduser_part || ':IN''';
    j := j + 1;

    -- changed to PIA+1+5:RY per Jeff Blaha 1/29/2015 email
    --  tab_tag(j) := 'PIA+1+0:RY''';
    tab_tag(j) := 'PIA+1+6:RY''';
    j := j + 1;

    /*
    SELECT SUM("SHEET_SKID"."SKID_PIECES") INTO v_cumulated_pcs
        FROM "CUSTOMER_ORDER",
             "ORDER_ITEM",
             "SHEET_SKID",
             "AB_JOB"
        WHERE  ("ORDER_ITEM"."ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM" ) and
               ("AB_JOB"."ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM") and
               ("AB_JOB"."ORDER_ITEM_NUM" = "ORDER_ITEM"."ORDER_ITEM_NUM") and
               ("SHEET_SKID"."AB_JOB_NUM" = "AB_JOB"."AB_JOB_NUM") and
               ("ORDER_ITEM"."ENDUSER_PART_NUM"=c2_record.ENDUSER_PART_NUM);
     */

    SELECT SUM(sheet_skid.skid_pieces)
      INTO v_cumulated_pcs
      FROM sheet_skid, order_item
     WHERE sheet_skid.ref_order_abc_num = order_item.order_abc_num
       AND sheet_skid.ref_order_abc_item = order_item.order_item_num
       AND order_item.enduser_part_num = c2_record.enduser_part_num;

    tab_tag(j) := 'QTY+3:' || to_char(v_cumulated_pcs) || ':EA''';
    j := j + 1;
    tab_tag(j) := 'QTY+12:' || to_char(c2_record.skid_pieces) || ':EA''';
    j := j + 1;
    tab_tag(j) := 'RFF+ON:' || v_enduser_po || '''';
    j := j + 1;
    --      tab_tag(j) := 'RFF+ON:'||c2_record.ORIG_CUSTOMER_PO||'''';
    --      j := j + 1;
  IF (v_skip = 0) THEN
      tab_tag(j) := 'PCI+15+' || to_char(c2_record.sheet_skid_display_num) || '''';
      j := j + 1;
      tab_tag(j) := 'QTY+12:' || to_char(c2_record.skid_pieces) || ':EA''';
      j := j + 1;
  END IF;

    cps_hl := cps_hl + 1;
  END LOOP;

  /* OUTPUT TO file*/
  IF NOT c4_cursor%ISOPEN THEN
    OPEN c4_cursor;
    FETCH c4_cursor
      INTO v_holder;
    CLOSE c4_cursor;
  END IF;
  v_file_id := to_char(v_holder);
--   out_file :=  UTL_FILE.FOPEN('/tmp','a','w');
-- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
--   out_file := utl_file.fopen('/templar/templar/incoming/senddata',
--                              'S_alcan_gm_gm' || v_file_id || '.desadv',  -- Change before moving to PROD
--                              'w',
--                              32767);

--Alex Gerlants. 11/15/2016. Commented out statement below, and added statement after.
  --out_file := utl_file.fopen('/templar/templar/incoming/senddata',
  --                           edi_file_prefix || v_file_id || '.edi',  -- Change before moving to PROD
  --                           'w',
  --                           32767);

  out_file := utl_file.fopen(edi_loc,
                             edi_file_prefix || v_file_id || '.edi',  -- Change before moving to PROD
                             'w',
                             32767);

  ls_edi_file_name := edi_file_prefix || v_file_id || '.edi'; /* Alex Gerlants. 09/02/2016 */

  --   out_file :=  UTL_FILE.FOPEN('/tmp','S_alcan_gm_gm'||v_file_id||'.desadv','w');
  tab_tag(j) := 'UNT+' || to_char(j - 2) || '+' || to_char(v_edi_st_seq) || '''';
  j := j + 1;

  --   tab_tag(j) := 'UNE+1+'||to_char(v_gs_log)||'''';
  --       j := j + 1;
  tab_tag(j) := 'UNZ+1+' || to_char(v_gs_log) || '''';

  FOR i IN 2 .. j LOOP
    v_outstring := tab_tag(i);
    utl_file.put(out_file, v_outstring);
    --         UTL_FILE.FFLUSH(out_file);
  END LOOP;
  utl_file.fflush(out_file);
  utl_file.fclose(out_file);

/*  This has been replaced by the UPDATE statement below.
    These columns are already updated in another function, edi_alcan_alcan_856_x12, so to update them here
    could be misleading as well as wiping out information from the aforementioned function hence the need for
    the shipment_desadv_date column in the shipment table.
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE
   WHERE shipment.packing_list = v_packing_list;
  COMMIT;
*/

--  Uncomment before moving to PROD
  --Alex Gerlants. 09/02/2016. Added ", edi_file_id_desadv = edi_file_id".
  UPDATE shipment
     SET shipment_desadv_date = SYSDATE, edi_file_id_desadv = v_file_id
   WHERE shipment.packing_list = v_packing_list;

   ----------------------------------------------------------------
   --Alex Gerlants. 09/02/2016. Begin

   select nvl(customer_duns_number_string, '00000000')
   into   ls_su
   from   customer
   where  customer_id = v_customer_id;

   If (ls_su = '00000000') Then
    Return 200;
   End If;

   INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (v_file_id,
     '039630926',
     ls_su,
     v_gs_log,
     v_gs_log,
     SYSDATE,
     ls_edi_file_name,
     0,
     v_customer_id,
     v_edi_st_seq,
     'desadv');


   --Alex Gerlants. 09/02/2016. End
   ----------------------------------------------------------------

  COMMIT;


  RETURN 1;

EXCEPTION
  WHEN exce_sent THEN
    --    raise_application_error(-20101,'STOP! EDI had been sent');
    --    UTL_FILE.FCLOSE(out_file);
    RETURN 100;
  WHEN exce_nodata THEN
    --     raise_application_error(-20101,'No shipment data found!');
    RETURN - 1;
  WHEN exce_des_sh_cust_id THEN
    --    raise_application_error(-20101,'This shipment does not required EDIFACT DESADV EDI!');
    RETURN 200;
  WHEN OTHERS THEN
    --    raise_application_error(-20101,'INTERNAL ERROR! PLEASE CALL 1519.');
   --  raise_application_error(-20101,'An error was encountered - ' || SQLCODE || ' -ERROR- ' || SQLERRM);
    utl_file.fclose(out_file);
    RETURN - 2;
END;
--------------------------------------------------------
--  DDL for Function F_EDI_DESADV2_ARCONIC_DAVENPRT
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_DESADV2_ARCONIC_DAVENPRT" (v_packing_list shipment.packing_list%type)
  return number is
  v_holder              number(6, 0);
  v_cumulated_pcs       number(18, 0);
  v_outstring           varchar2(32767);
  v_gs_log              number(8, 0);
  v_communication_code  varchar2(128);
--  these 4 added by patrick reynolds 2016/02/05 for desadv for gm gfss
  v_address             varchar2(3);
  v_bgm                 varchar2(3);
  v_skip                int(3) := 0;
  v_duns                varchar2(13) := '039630926T:01';  -- DUNS for ALBL
  duns                  varchar2(13) := '001339472::16';  -- DUNS for Arconic Davenport
--
  v_carrier_description shipment.carrier_description_code%type;
  v_customer_id         shipment.customer_id%type;
  v_des_sh_cust_id      shipment.des_sh_cust_id%type;
  v_enduser_id          shipment.shipment_enduser_id%type;
  v_vehicle_prefix      shipment.vehicle_id_prefix%type;
  v_vehicle_id          shipment.vehicle_id%type;
--  v_return              int(3) := 1;
  v_enduser_po          customer_order.enduser_po%type;
  v_enduser_part        order_item.enduser_part_num%type;
  i                     int(3) := 1;
  cps_hl                int(3) := 1;

  --edi_file_prefix varchar2(50) := 'S_arconic_gm_'; --Production
  edi_file_prefix varchar2(50) := 's_arconic_gm_'; --Development

  exce_des_sh_cust_id exception;
  exce_nodata         exception;
  exce_sent           exception;
  /* declare output file */
  out_file       utl_file.file_type;
--  v_sender_vanid char(25) := '3010007080';
  v_edi_st_seq   number(6, 0);
  cursor c1_cursor is
    select edi_st_log_seq.nextval from dual;
  cursor c4_cursor is
    select edi_file_id_seq.nextval from dual;
  v_file_id varchar2(32767);
  --  v_boon_edi_sent boolean;
--  v_max_line_no  number(3, 0) := 0;
--   v_tagstring    varchar2(32767);
  v_skids_count  number(3, 0);
  v_piece_count  number(8, 0) := 0;
  v_gross_weight number(12, 0) := 0;
  v_net_weight   number(12, 0) := 0;
  v_shipdate     date;
  v_scac         carrier.scac%type;

  ls_su             varchar2(50); /* alex gerlants. 09/02/2016 */
  ls_edi_file_name  varchar2(50); /* alex gerlants. 09/02/2016 */

--  v_tare_weight  sheet_skid.sheet_tare_wt%type := 0;
  --v_skid_num     sheet_skid.sheet_skid_num%type;
  v_skid_num sheet_skid.sheet_skid_display_num%type;
  type name_type is table of varchar2(32767) index by binary_integer;
  tab_tag name_type;
  j       int(3) := 1;

  edi_loc varchar2(50) := dbo.get_edi_destination('EDI_DIR'); --alex gerlants. 11/15/2016

  /*cursor c3_cursor is
    select "CUSTOMER_ORDER"."ENDUSER_PO",
           "ORDER_ITEM"."ENDUSER_PART_NUM",
           "ORDER_ITEM"."ORDER_ITEM_DESC",
           "PRODUCTION_SHEET_ITEM"."PROD_ITEM_PIECES",
           "SHEET_SKID_DETAIL"."PROD_ITEM_NUM",
           "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NET_WT"
      from "CUSTOMER_ORDER",
           "ORDER_ITEM",
           "AB_JOB",
           "PRODUCTION_SHEET_ITEM",
           "SHEET_SKID_DETAIL",
           "SHEET_SKID"
     where ("ORDER_ITEM"."ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM")
       and ("AB_JOB"."ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
       and ("AB_JOB"."ORDER_ITEM_NUM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
       and ("PRODUCTION_SHEET_ITEM"."AB_JOB_NUM" = "AB_JOB"."AB_JOB_NUM")
       and ("SHEET_SKID_DETAIL"."PROD_ITEM_NUM" =
           "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NUM")
       and ("SHEET_SKID"."SHEET_SKID_NUM" =
           "SHEET_SKID_DETAIL"."SHEET_SKID_NUM")
       and ("SHEET_SKID"."SHEET_SKID_NUM" = v_skid_num);
*/
  cursor c2_cursor is
    select "SHEET_PACKING_ITEM"."SH_PACKING_ITEM",
           'MULTIPLE' "LOT_NUM",
           "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO",
           "CUSTOMER_ORDER"."ORDER_ABC_NUM",
           "CUSTOMER_ORDER"."ENDUSER_PO",
           "ORDER_ITEM"."ORDER_ITEM_NUM",
           "ORDER_ITEM"."ENDUSER_PART_NUM",
           "ORDER_ITEM"."SUPPLIER_CODE",
           "SHEET_SKID". "AB_JOB_NUM",
           "SHEET_SKID"."SHEET_SKID_NUM",
           "SHEET_SKID"."SHEET_SKID_DISPLAY_NUM",
           "SHEET_SKID"."SHEET_NET_WT",
           "SHEET_SKID"."SHEET_TARE_WT",
           "SHEET_SKID". "SKID_PIECES",
           "SHEET_SKID"."SKID_SHEET_STATUS",
           null "DONE"
      from "CUSTOMER_ORDER",
           "ORDER_ITEM",
           "SHEET_SKID",
           "AB_JOB",
           "SHIPMENT",
           "SHEET_PACKING_ITEM"
     where ("ORDER_ITEM"."ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM")
       and ("AB_JOB"."ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
       and ("AB_JOB"."ORDER_ITEM_NUM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
       and ("SHEET_SKID"."AB_JOB_NUM" = "AB_JOB"."AB_JOB_NUM")
       and ("SHIPMENT"."PACKING_LIST" = "SHEET_PACKING_ITEM"."PACKING_LIST")
       and ("SHEET_PACKING_ITEM"."SHEET_SKID_NUM" =
           "SHEET_SKID"."SHEET_SKID_NUM")
       and ("SHIPMENT"."PACKING_LIST" = v_packing_list);
  --         and ("SHIPMENT"."SHIPMENT_EDI856_DATE" is null)

  --

begin

/*
  select shipment_edi856_date
    into v_shipdate
     from shipment
     where shipment.packing_list = v_packing_list;
     
  if not (v_shipdate is null) then
    return 100;
  end if; 
*/  

  select customer_id, des_sh_cust_id, shipment_enduser_id
    into v_customer_id, v_des_sh_cust_id, v_enduser_id
    from shipment
   where shipment.packing_list = v_packing_list;
  if not sql%found then
    --         raise exce_nodata;
    return - 1;
  end if;

  --alex gerlants. 09/20/2017. added '2850' to the list below
  if not ((v_customer_id in (50, 2505)) and --Arconic Davenport, GM GFSS
      (v_des_sh_cust_id in
      (69, 70, 2850, 72, 1840, 2079, 2164, 2181, 2360, 1648, 2495, 2611, 2680, 2814))) then
    --          raise exce_des_sh_cust_id;
    return 200;
  end if;
  -- deleted 34, added 1459 6/5/2014 by james ni
  -- added 2505 01/25/2016 by patrick reynolds

  if not c1_cursor%isopen then
    open c1_cursor;
  end if;
  fetch c1_cursor
    into v_edi_st_seq;
  close c1_cursor;

  select edi_gs_log_seq.nextval into v_gs_log from dual;

  --alex gerlants. communication_code_error_message. 11/01/2017. begin
  select f_get_sisco_code(v_des_sh_cust_id) --new function
  into   v_communication_code
  from   dual;
  
  if lower(nvl(v_communication_code, 'unknown')) = 'unknown' then
    return -3;  --ship user will get message "Communication code is NOT set up in table customer_system for Destination Customer ..."
  end if;
  --alex gerlants. communication_code_error_message. 11/01/2017. end

  if (v_customer_id = 2505) then
    v_address := 'MZ7';
    v_duns := 'XYY:ZZ';
    v_communication_code := '51972';
    v_bgm := '';
    v_skip := 1;
    duns := '039630926::16';  -- change default duns from Arconic to ALBL;
  else
    v_address := 'ALV';
    v_bgm := '351';
  end if;

  tab_tag(j) := 'UNA:+.? ''';
  j := j + 1;

  tab_tag(j) := 'UNB+UNOA:2+' || v_duns || ':01+' || v_address || ':ZZ+' ||
                to_char(sysdate, 'YYMMDD:HH24MI') || '+' ||
                to_char(v_gs_log) || '++GMDESADV''';
  j := j + 1;

  /*     tab_tag(j) := 'UNB+UNOA:2+039630926T:01+ALV:ZZ+'
              ||to_char(sysdate,'YYMMDD:HHMM')||'+'||to_char(v_gs_log)||'++DESADVT''';
              j := j + 1;
  */

  --    tab_tag(j) := 'UNG+039630926T:01+'||v_communication_code||':92+'
  --           ||to_char(sysdate,'YYMMDD:HHMM+')||to_char(v_gs_log)||'+UN+D:97A''';
  --           j := j + 1;

  tab_tag(j) := 'UNH+' || to_char(v_edi_st_seq) || '+DESADV:D:97A:UN''';
  j := j + 1;
  tab_tag(j) := 'BGM+' || v_bgm || '+' || to_char(v_packing_list) || '+9''';
  j := j + 1;
  tab_tag(j) := 'DTM+137:' || to_char(sysdate, 'YYYYMMDDHH24MI') ||
                ':203''';
  j := j + 1;

  select nvl(shipment_actualed_date_time, sysdate)
    into v_shipdate
    from shipment
   where packing_list = v_packing_list;
  tab_tag(j) := 'DTM+11:' || to_char(v_shipdate, 'YYYYMMDDHH24MI') ||
                ':203''';
  j := j + 1;

  select max(sh_packing_item)
    into v_skids_count
    from sheet_packing_item
   where sheet_packing_item.packing_list = v_packing_list;

  /*if v_skids_count > 5 then
      return 300;
  end if;*/

  for c2_record in c2_cursor loop
    v_piece_count  := v_piece_count + c2_record.skid_pieces;
    v_gross_weight := v_gross_weight + c2_record.sheet_net_wt * 0.45359 +
                      c2_record.sheet_tare_wt * 0.45359;
    v_net_weight   := v_net_weight + c2_record.sheet_net_wt * 0.45359;
    --      v_tare_weight := v_tare_weight + c2_record.sheet_tare_wt;
  --    put more item here
  end loop;

  --    v_skids_count := c2_cursor%rowcount;

  tab_tag(j) := 'MEA+AAX+SQ+C62:' || to_char(v_skids_count) || '''';
  j := j + 1;
  tab_tag(j) := 'MEA+AAX+G+KG:' || to_char(v_gross_weight) || '''';
  j := j + 1;
  tab_tag(j) := 'MEA+AAX+N+KG:' || to_char(v_net_weight) || '''';
  j := j + 1;
  tab_tag(j) := 'RFF+MB:' || to_char(v_packing_list) || '''';
  j := j + 1;

  --tab_tag(j) := 'NAD+MI+88120::92''';
  --  j := j + 1;

  if v_des_sh_cust_id in (2164) then
    tab_tag(j) := 'NAD+MI+88835::92''';
  else
    tab_tag(j) := 'NAD+MI+88120::92''';
  end if;
  j := j + 1;

  tab_tag(j) := 'NAD+SU+' || duns || ''''; --supplier is Arconic

  j := j + 1;

  tab_tag(j) := 'NAD+ST+' || v_communication_code || '::92''';
  j := j + 1;

  tab_tag(j) := 'LOC+11+A1A2''';
  j := j + 1;

  select nvl(carrier.scac, 'AAAA')
    into v_scac
    from carrier
   where carrier_id =
         (select carrier_id
            from shipment
           where shipment.packing_list = v_packing_list);

  tab_tag(j) := 'TDT+25++M++' || v_scac || '::182''';
  j := j + 1;

  select nvl(shipment.carrier_description_code, 'TL')
    into v_carrier_description
    from shipment
   where shipment.packing_list = v_packing_list;
  if v_carrier_description = 'TL' then
    v_carrier_description := 'TE';
  end if;

  select nvl(shipment.vehicle_id_prefix, 'AA'),
         nvl(shipment.vehicle_id, '1111')
    into v_vehicle_prefix, v_vehicle_id
    from shipment
   where shipment.packing_list = v_packing_list;

  tab_tag(j) := 'EQD+' || v_carrier_description || '+' || v_vehicle_prefix ||
                v_vehicle_id || '''';
  j := j + 1;

  /* detail loop begin */
  --   cps_hl := 1;
  for c2_record in c2_cursor loop

    select "ORDER_ITEM"."ENDUSER_PART_NUM"
      into v_enduser_part
      from "ORDER_ITEM", "SHEET_SKID"
     where ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
       and ("SHEET_SKID"."REF_ORDER_ABC_ITEM" =
           "ORDER_ITEM"."ORDER_ITEM_NUM")
       and ("SHEET_SKID"."SHEET_SKID_NUM" = c2_record.sheet_skid_num);

    select "CUSTOMER_ORDER"."ENDUSER_PO"
      into v_enduser_po
      from "SHEET_SKID", "CUSTOMER_ORDER"
     where ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
           "CUSTOMER_ORDER"."ORDER_ABC_NUM")
       and (sheet_skid.sheet_skid_num = c2_record.sheet_skid_num);

    tab_tag(j) := 'CPS+' || to_char(cps_hl) || '++1''';
    j := j + 1;
--    tab_tag(j) := 'PAC+' || to_char(c2_record.skid_pieces) || '''';
      if (v_des_sh_cust_id in (2611, 2814)) then
         tab_tag(j) := 'PAC+' || to_char(c2_record.skid_pieces) || '++AHB52679'''; -- added by patrick reynolds 07-21-2016
      else
         tab_tag(j) := 'PAC+' || to_char(c2_record.skid_pieces) || ''''; -- added by patrick reynolds 07-21-2016
      end if;

    j := j + 1;
    /*    tab_tag(j) := 'QTY+52:'||to_char(c2_record.skid_pieces)||'''';
    j := j + 1;   */
    tab_tag(j) := 'PCI+16''';
    j := j + 1;
    /*    tab_tag(j) := 'RFF+CW:'||to_char(c2_record.sh_packing_item)||'''';
      j := j + 1;
    tab_tag(j) := 'GIR+3+'||to_char(c2_record.sheet_skid_num)||':AW''';
      j := j + 1;  */

    v_skid_num := c2_record.sheet_skid_display_num;
    /*    for c3_record in c3_cursor loop
        tab_tag(j) := 'LIN+++'||c3_record.enduser_part_num||':IN''';
        j := j + 1;
        tab_tag(j) := 'PIA+1+0:RY''';
        j := j + 1;
        tab_tag(j) := 'QTY+12:'||to_char(c3_record.prod_item_pieces)||':EA''';
        j := j + 1;
        tab_tag(j) := 'RFF+ON:'||c3_record.enduser_po||'''';
        j := j + 1;

        tab_tag(j) := 'PCI+15+'||to_char(c2_record.sheet_skid_num)||'''';
        j := j + 1;
        tab_tag(j) := 'QTY+3:'||to_char(c3_record.prod_item_pieces)||':EA''';
        j := j + 1;
        tab_tag(j) := 'QTY+12:'||to_char(c3_record.prod_item_pieces)||':EA''';
        j := j + 1;
    end loop;
    */

    tab_tag(j) := 'LIN+++' || v_enduser_part || ':IN''';
    j := j + 1;

    -- changed to pia+1+5:ry per jeff blaha 1/29/2015 email
    --  tab_tag(j) := 'PIA+1+0:RY''';
    tab_tag(j) := 'PIA+1+6:RY''';
    j := j + 1;

    /*
    select sum("SHEET_SKID"."SKID_PIECES") into v_cumulated_pcs
        from "CUSTOMER_ORDER",
             "ORDER_ITEM",
             "SHEET_SKID",
             "AB_JOB"
        where  ("ORDER_ITEM"."ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM" ) and
               ("AB_JOB"."ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM") and
               ("AB_JOB"."ORDER_ITEM_NUM" = "ORDER_ITEM"."ORDER_ITEM_NUM") and
               ("SHEET_SKID"."AB_JOB_NUM" = "AB_JOB"."AB_JOB_NUM") and
               ("ORDER_ITEM"."ENDUSER_PART_NUM"=c2_record.enduser_part_num);
     */

    select sum(sheet_skid.skid_pieces)
      into v_cumulated_pcs
      from sheet_skid, order_item
     where sheet_skid.ref_order_abc_num = order_item.order_abc_num
       and sheet_skid.ref_order_abc_item = order_item.order_item_num
       and order_item.enduser_part_num = c2_record.enduser_part_num;

    tab_tag(j) := 'QTY+3:' || to_char(v_cumulated_pcs) || ':EA''';
    j := j + 1;
    tab_tag(j) := 'QTY+12:' || to_char(c2_record.skid_pieces) || ':EA''';
    j := j + 1;
    tab_tag(j) := 'RFF+ON:' || v_enduser_po || '''';
    j := j + 1;
    --      tab_tag(j) := 'RFF+ON:'||c2_record.orig_customer_po||'''';
    --      j := j + 1;
  if (v_skip = 0) then
      tab_tag(j) := 'PCI+15+' || to_char(c2_record.sheet_skid_display_num) || '''';
      j := j + 1;
      tab_tag(j) := 'QTY+12:' || to_char(c2_record.skid_pieces) || ':EA''';
      j := j + 1;
  end if;

    cps_hl := cps_hl + 1;
  end loop;

  /* output to file*/
  if not c4_cursor%isopen then
    open c4_cursor;
    fetch c4_cursor
      into v_holder;
    close c4_cursor;
  end if;
  v_file_id := to_char(v_holder);

  out_file := utl_file.fopen(edi_loc,
                             edi_file_prefix || v_file_id || '.edi',  -- change before moving to prod
                             'w',
                             32767);

  ls_edi_file_name := edi_file_prefix || v_file_id || '.edi'; /* alex gerlants. 09/02/2016 */

  tab_tag(j) := 'UNT+' || to_char(j - 2) || '+' || to_char(v_edi_st_seq) || '''';
  j := j + 1;

  tab_tag(j) := 'UNZ+1+' || to_char(v_gs_log) || '''';

  for i in 2 .. j loop
    v_outstring := tab_tag(i);
    utl_file.put(out_file, v_outstring);
    --         utl_file.fflush(out_file);
  end loop;
  utl_file.fflush(out_file);
  utl_file.fclose(out_file);

--  uncomment before moving to prod
  --alex gerlants. 09/02/2016. added ", edi_file_id_desadv = edi_file_id".
  update shipment
     set shipment_desadv_date = sysdate, edi_file_id_desadv = v_file_id
   where shipment.packing_list = v_packing_list;

   ----------------------------------------------------------------
   --alex gerlants. 09/02/2016. begin

   select nvl(customer_duns_number_string, '00000000')
   into   ls_su
   from   customer
   where  customer_id = v_customer_id;

   if (ls_su = '00000000') then
    return 500; --alex gerlants. communication_code_error_message. 11/01/2017. replaced "200" with "500".
   end if;

   insert into outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  values
    (v_file_id,
     '039630926',
     ls_su,
     v_gs_log,
     v_gs_log,
     sysdate,
     ls_edi_file_name,
     0,
     v_customer_id,
     v_edi_st_seq,
     'desadv');


   --alex gerlants. 09/02/2016. end
   ----------------------------------------------------------------

  commit;


  return 1;

exception
  when exce_sent then
    --    raise_application_error(-20101,'STOP! EDI had been sent');
    --    utl_file.fclose(out_file);
    return 100;
  when exce_nodata then
    --     raise_application_error(-20101,'No shipment data found!');
    return - 1;
  when exce_des_sh_cust_id then
    --    raise_application_error(-20101,'This shipment does not required EDIFACT DESADV EDI!');
    return 200;
  when others then
    --    raise_application_error(-20101,'INTERNAL ERROR! PLEASE CALL 1519.');
   --  raise_application_error(-20101,'An error was encountered - ' || sqlcode || ' -ERROR- ' || sqlerrm);
    utl_file.fclose(out_file);
    return - 2;
end;
--------------------------------------------------------
--  DDL for Function F_EDI_DESADV2_ORIG
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_DESADV2_ORIG" (v_packing_list shipment.packing_list%TYPE)
  RETURN NUMBER IS
  v_holder              NUMBER(6, 0);
  v_cumulated_pcs       NUMBER(18, 0);
  v_outstring           VARCHAR2(32767);
  v_gs_log              NUMBER(8, 0);
  v_communication_code  VARCHAR2(128);
  v_carrier_description shipment.carrier_description_code%TYPE;
  v_customer_id         shipment.customer_id%TYPE;
  v_des_sh_cust_id      shipment.des_sh_cust_id%TYPE;
  v_enduser_id          shipment.shipment_enduser_id%TYPE;
  v_vehicle_prefix      shipment.vehicle_id_prefix%TYPE;
  v_vehicle_id          shipment.vehicle_id%TYPE;
  v_return              INT(3) := 1;
  v_enduser_po          customer_order.enduser_po%TYPE;
  v_enduser_part        order_item.enduser_part_num%TYPE;
  i                     INT(3) := 1;
  cps_hl                INT(3) := 1;
  exce_des_sh_cust_id EXCEPTION;
  exce_nodata         EXCEPTION;
  exce_sent           EXCEPTION;
  /* Declare output file */
  out_file       utl_file.file_type;
  v_sender_vanid CHAR(25) := '3010007080';
  v_edi_st_seq   NUMBER(6, 0);
  CURSOR c1_cursor IS
    SELECT edi_st_log_seq.nextval FROM dual;
  CURSOR c4_cursor IS
    SELECT edi_file_id_seq.nextval FROM dual;
  v_file_id VARCHAR2(32767);
  --  v_boon_edi_sent boolean; 
  v_max_line_no  NUMBER(3, 0) := 0;
  v_tagstring    VARCHAR2(32767);
  v_skids_count  NUMBER(3, 0);
  v_piece_count  NUMBER(8, 0) := 0;
  v_gross_weight NUMBER(12, 0) := 0;
  v_net_weight   NUMBER(12, 0) := 0;
  v_shipdate     DATE;
  v_scac         carrier.scac%TYPE;
  v_tare_weight  sheet_skid.sheet_tare_wt%TYPE := 0;
  v_skid_num     sheet_skid.sheet_skid_num%TYPE;
  TYPE name_type IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  tab_tag name_type;
  j       INT(3) := 1;
  CURSOR c3_cursor IS
    SELECT "CUSTOMER_ORDER"."ENDUSER_PO",
           "ORDER_ITEM"."ENDUSER_PART_NUM",
           "ORDER_ITEM"."ORDER_ITEM_DESC",
           "PRODUCTION_SHEET_ITEM"."PROD_ITEM_PIECES",
           "SHEET_SKID_DETAIL"."PROD_ITEM_NUM",
           "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NET_WT"
      FROM "CUSTOMER_ORDER",
           "ORDER_ITEM",
           "AB_JOB",
           "PRODUCTION_SHEET_ITEM",
           "SHEET_SKID_DETAIL",
           "SHEET_SKID"
     WHERE ("ORDER_ITEM"."ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM")
       AND ("AB_JOB"."ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
       AND ("AB_JOB"."ORDER_ITEM_NUM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
       AND ("PRODUCTION_SHEET_ITEM"."AB_JOB_NUM" = "AB_JOB"."AB_JOB_NUM")
       AND ("SHEET_SKID_DETAIL"."PROD_ITEM_NUM" =
           "PRODUCTION_SHEET_ITEM"."PROD_ITEM_NUM")
       AND ("SHEET_SKID"."SHEET_SKID_NUM" =
           "SHEET_SKID_DETAIL"."SHEET_SKID_NUM")
       AND ("SHEET_SKID"."SHEET_SKID_NUM" = v_skid_num);

  CURSOR c2_cursor IS
    SELECT "SHEET_PACKING_ITEM"."SH_PACKING_ITEM",
           'MULTIPLE' "LOT_NUM",
           "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO",
           "CUSTOMER_ORDER"."ORDER_ABC_NUM",
           "CUSTOMER_ORDER"."ENDUSER_PO",
           "ORDER_ITEM"."ORDER_ITEM_NUM",
           "ORDER_ITEM"."ENDUSER_PART_NUM",
           "ORDER_ITEM"."SUPPLIER_CODE",
           "SHEET_SKID". "AB_JOB_NUM",
           "SHEET_SKID"."SHEET_SKID_NUM",
           "SHEET_SKID"."SHEET_NET_WT",
           "SHEET_SKID"."SHEET_TARE_WT",
           "SHEET_SKID". "SKID_PIECES",
           "SHEET_SKID"."SKID_SHEET_STATUS",
           NULL "DONE"
      FROM "CUSTOMER_ORDER",
           "ORDER_ITEM",
           "SHEET_SKID",
           "AB_JOB",
           "SHIPMENT",
           "SHEET_PACKING_ITEM"
     WHERE ("ORDER_ITEM"."ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM")
       AND ("AB_JOB"."ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
       AND ("AB_JOB"."ORDER_ITEM_NUM" = "ORDER_ITEM"."ORDER_ITEM_NUM")
       AND ("SHEET_SKID"."AB_JOB_NUM" = "AB_JOB"."AB_JOB_NUM")
       AND ("SHIPMENT"."PACKING_LIST" = "SHEET_PACKING_ITEM"."PACKING_LIST")
       AND ("SHEET_PACKING_ITEM"."SHEET_SKID_NUM" =
           "SHEET_SKID"."SHEET_SKID_NUM")
       AND ("SHIPMENT"."PACKING_LIST" = v_packing_list);
  --         and ("SHIPMENT"."SHIPMENT_EDI856_DATE" is NULL) 

  --

BEGIN

  /*   SELECT shipment_edi856_date
    INTO v_shipdate
     FROM shipment 
     WHERE shipment.packing_list=v_packing_list;
  IF NOT(v_shipdate IS NULL) THEN
    RETURN 100;
  END IF;  */

  SELECT customer_id, des_sh_cust_id, shipment_enduser_id
    INTO v_customer_id, v_des_sh_cust_id, v_enduser_id
    FROM shipment
   WHERE shipment.packing_list = v_packing_list;
  IF NOT SQL%FOUND THEN
    --         RAISE exce_nodata;
    RETURN - 1;
  END IF;

  /* FOR ALCAN customer only, ship to GM Pontiac plant 14/Grand Rapids/Dock15 only.   */

  IF NOT ((v_customer_id IN (34, 35, 10, 1153)) AND
      (v_des_sh_cust_id IN (69, 70, 72, 1840, 2164, 2181, 2079, 2360))) THEN
    --          RAISE exce_des_sh_cust_id;
    RETURN 200;
  END IF;

  IF NOT c1_cursor%ISOPEN THEN
    OPEN c1_cursor;
  END IF;
  FETCH c1_cursor
    INTO v_edi_st_seq;
  CLOSE c1_cursor;

  SELECT edi_gs_log_seq.nextval INTO v_gs_log FROM dual;

  tab_tag(j) := 'UNA:+.? ''';
  j := j + 1;

  tab_tag(j) := 'UNB+UNOA:2+039630926T:01+ALV:ZZ+' ||
                to_char(SYSDATE, 'YYMMDD:HH24MI') || '+' ||
                to_char(v_gs_log) || '++GMDESADV''';
  j := j + 1;

  /*     tab_tag(j):='UNB+UNOA:2+039630926T:01+ALV:ZZ+'
              ||to_char(sysdate,'YYMMDD:HHMM')||'+'||to_char(v_gs_log)||'++DESADVT''';
              j:=j+1;    
  */
  SELECT communication_code
    INTO v_communication_code
    FROM customer_system
   WHERE customer_id = v_des_sh_cust_id;

  --    tab_tag(j):='UNG+039630926T:01+'||v_communication_code||':92+'
  --           ||to_char(sysdate,'YYMMDD:HHMM+')||to_char(v_gs_log)||'+UN+D:97A''';
  --           j:=j+1; 

  tab_tag(j) := 'UNH+' || to_char(v_edi_st_seq) || '+DESADV:D:97A:UN''';
  j := j + 1;
  tab_tag(j) := 'BGM+351+' || to_char(v_packing_list) || '+9''';
  j := j + 1;
  tab_tag(j) := 'DTM+137:' || to_char(SYSDATE, 'YYYYMMDDHH24MI') ||
                ':203''';
  j := j + 1;

  SELECT nvl(shipment_actualed_date_time, SYSDATE)
    INTO v_shipdate
    FROM shipment
   WHERE packing_list = v_packing_list;
  tab_tag(j) := 'DTM+11:' || to_char(v_shipdate, 'YYYYMMDDHH24MI') ||
                ':203''';
  j := j + 1;

  SELECT MAX(sh_packing_item)
    INTO v_skids_count
    FROM sheet_packing_item
   WHERE sheet_packing_item.packing_list = v_packing_list;

  /*if v_skids_count>5 then
      return 300;
  end if;*/

  FOR c2_record IN c2_cursor LOOP
    v_piece_count  := v_piece_count + c2_record.skid_pieces;
    v_gross_weight := v_gross_weight + c2_record.sheet_net_wt * 0.45359 +
                      c2_record.sheet_tare_wt * 0.45359;
    v_net_weight   := v_net_weight + c2_record.sheet_net_wt * 0.45359;
    --      v_tare_weight:=v_tare_weight+c2_record.SHEET_TARE_WT;
  --    Put more item here
  END LOOP;

  --    v_skids_count:=c2_cursor%ROWCOUNT; 

  tab_tag(j) := 'MEA+AAX+SQ+C62:' || to_char(v_skids_count) || '''';
  j := j + 1;
  tab_tag(j) := 'MEA+AAX+G+KG:' || to_char(v_gross_weight) || '''';
  j := j + 1;
  tab_tag(j) := 'MEA+AAX+N+KG:' || to_char(v_net_weight) || '''';
  j := j + 1;
  tab_tag(j) := 'RFF+MB:' || to_char(v_packing_list) || '''';
  j := j + 1;

  --tab_tag(j):='NAD+MI+88120::92''';
  --  j:=j+1;

  IF v_des_sh_cust_id IN (2164) THEN
    tab_tag(j) := 'NAD+MI+88835::92''';
  ELSE
    tab_tag(j) := 'NAD+MI+88120::92''';
  END IF;
  j := j + 1;
  --    tab_tag(j):='NAD+SU+039630926::16''';      Supplier is ABCo

  --- GM can only accept ALCAN Warren now, enable Konston in the future
  --    if v_customer_id=1153 then
  tab_tag(j) := 'NAD+SU+001504935::16'''; --Supplier is Novelis Kingston Feb8-06 by tony
  --001504935
  j := j + 1;
  --    else      
  --tab_tag(j):='NAD+SU+003980216::16''';        --Supplier is Alcan Warren
  --  j:=j+1;
  --    end if;

  tab_tag(j) := 'NAD+ST+' || v_communication_code || '::92''';
  j := j + 1;

  /* LOC segment, need location code from Alcan or GM */

  /*    IF v_des_sh_cust_id=69 THEN
      tab_tag(j):='NAD+ST+18024::92''';      
      j:=j+1;
  --  ELSEIF v_des_sh_cust_id=70 THEN
  --    tab_tag(j):=)
  --      VALUES ('NAD+ST+18231::92''');
    ELSE
      tab_tag(j):='NAD+ST+18231::92''';
      j:=j+1;
    END IF;    */

  tab_tag(j) := 'LOC+11+A1A2''';
  j := j + 1;

  SELECT nvl(carrier.scac, 'AAAA')
    INTO v_scac
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = v_packing_list);

  tab_tag(j) := 'TDT+25++M++' || v_scac || '::182''';
  j := j + 1;

  SELECT nvl(shipment.carrier_description_code, 'TL')
    INTO v_carrier_description
    FROM shipment
   WHERE shipment.packing_list = v_packing_list;
  IF v_carrier_description = 'TL' THEN
    v_carrier_description := 'TE';
  END IF;

  SELECT nvl(shipment.vehicle_id_prefix, 'AA'),
         nvl(shipment.vehicle_id, '1111')
    INTO v_vehicle_prefix, v_vehicle_id
    FROM shipment
   WHERE shipment.packing_list = v_packing_list;

  tab_tag(j) := 'EQD+' || v_carrier_description || '+' || v_vehicle_prefix ||
                v_vehicle_id || '''';
  j := j + 1;

  /* DETAIL LOOP BEGIN */
  --   cps_hl:=1;  
  FOR c2_record IN c2_cursor LOOP
  
    SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
      INTO v_enduser_part
      FROM "ORDER_ITEM", "SHEET_SKID"
     WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
       AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" =
           "ORDER_ITEM"."ORDER_ITEM_NUM")
       AND ("SHEET_SKID"."SHEET_SKID_NUM" = c2_record.sheet_skid_num);
  
    SELECT "CUSTOMER_ORDER"."ENDUSER_PO"
      INTO v_enduser_po
      FROM "SHEET_SKID", "CUSTOMER_ORDER"
     WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
           "CUSTOMER_ORDER"."ORDER_ABC_NUM")
       AND (sheet_skid.sheet_skid_num = c2_record.sheet_skid_num);
  
    tab_tag(j) := 'CPS+' || to_char(cps_hl) || '++1''';
    j := j + 1;
  
    /*tab_tag(j) := 'PAC+' || to_char(c2_record.skid_pieces) || '''';*/
    CASE v_des_sh_cust_id
      WHEN 2360 THEN
        tab_tag(j) := 'PAC+1++AHB52679'''; --GM Flint container#
      WHEN 1840 THEN
        tab_tag(j) := 'PAC+1++AHB52578'''; --GM Lansing container#
      ELSE
        tab_tag(j) := 'PAC+1++AHB52679'''; --GM Default container#
    END CASE;
    j := j + 1;
    /*    tab_tag(j):='QTY+52:'||TO_CHAR(c2_record.SKID_PIECES)||'''';
    j:=j+1;   */
    tab_tag(j) := 'PCI+16''';
    j := j + 1;
    /*    tab_tag(j):='RFF+CW:'||TO_CHAR(c2_record.SH_PACKING_ITEM)||'''';
      j:=j+1;
    tab_tag(j):='GIR+3+'||TO_CHAR(c2_record.SHEET_SKID_NUM)||':AW''';
      j:=j+1;  */
  
    v_skid_num := c2_record.sheet_skid_num;
    /*    FOR c3_record IN c3_cursor LOOP
        tab_tag(j):='LIN+++'||c3_record.ENDUSER_PART_NUM||':IN''';
        j:=j+1;
        tab_tag(j):='PIA+1+0:RY''';
        j:=j+1;
        tab_tag(j):='QTY+12:'||TO_CHAR(c3_record.PROD_ITEM_PIECES)||':EA''';
        j:=j+1; 
        tab_tag(j):='RFF+ON:'||c3_record.ENDUSER_PO||'''';
        j:=j+1;
    
        tab_tag(j):='PCI+15+'||TO_CHAR(c2_record.SHEET_SKID_NUM)||'''';
        j:=j+1;
        tab_tag(j):='QTY+3:'||TO_CHAR(c3_record.PROD_ITEM_PIECES)||':EA''';
        j:=j+1;
        tab_tag(j):='QTY+12:'||TO_CHAR(c3_record.PROD_ITEM_PIECES)||':EA''';
        j:=j+1;
    END LOOP;
    */
  
    tab_tag(j) := 'LIN+++' || v_enduser_part || ':IN''';
    j := j + 1;
    tab_tag(j) := 'PIA+1+0:RY''';
    j := j + 1;
  
    /*
    SELECT SUM("SHEET_SKID"."SKID_PIECES") INTO v_cumulated_pcs
        FROM "CUSTOMER_ORDER",   
             "ORDER_ITEM",   
             "SHEET_SKID",   
             "AB_JOB"
        WHERE  ("ORDER_ITEM"."ORDER_ABC_NUM" = "CUSTOMER_ORDER"."ORDER_ABC_NUM" ) and  
               ("AB_JOB"."ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM") and
               ("AB_JOB"."ORDER_ITEM_NUM" = "ORDER_ITEM"."ORDER_ITEM_NUM") and
               ("SHEET_SKID"."AB_JOB_NUM" = "AB_JOB"."AB_JOB_NUM") and
               ("ORDER_ITEM"."ENDUSER_PART_NUM"=c2_record.ENDUSER_PART_NUM);
     */
  
    SELECT SUM(sheet_skid.skid_pieces)
      INTO v_cumulated_pcs
      FROM sheet_skid, order_item
     WHERE sheet_skid.ref_order_abc_num = order_item.order_abc_num
       AND sheet_skid.ref_order_abc_item = order_item.order_item_num
       AND order_item.enduser_part_num = c2_record.enduser_part_num;
  
    tab_tag(j) := 'QTY+3:' || to_char(v_cumulated_pcs) || ':EA''';
    j := j + 1;
    tab_tag(j) := 'QTY+12:' || to_char(c2_record.skid_pieces) || ':EA''';
    j := j + 1;
    tab_tag(j) := 'RFF+ON:' || v_enduser_po || '''';
    j := j + 1;
    --      tab_tag(j):='RFF+ON:'||c2_record.ORIG_CUSTOMER_PO||'''';
    --      j:=j+1;
    tab_tag(j) := 'PCI+15+' || to_char(c2_record.sheet_skid_num) || '''';
    j := j + 1;
    tab_tag(j) := 'QTY+12:' || to_char(c2_record.skid_pieces) || ':EA''';
    j := j + 1;
  
    cps_hl := cps_hl + 1;
  END LOOP;

  /* OUTPUT TO file*/
  IF NOT c4_cursor%ISOPEN THEN
    OPEN c4_cursor;
    FETCH c4_cursor
      INTO v_holder;
    CLOSE c4_cursor;
  END IF;
  v_file_id := to_char(v_holder);
  --   out_file:= UTL_FILE.FOPEN('/tmp','a','w');
  out_file := utl_file.fopen('/templar/templar/incoming/senddata',
                             'S_alcan_gm_gm' || v_file_id || '.desadv',
                             'w',
                             32767);
  --   out_file:= UTL_FILE.FOPEN('/tmp','S_alcan_gm_gm'||v_file_id||'.desadv','w');
  tab_tag(j) := 'UNT+' || to_char(j - 2) || '+' || to_char(v_edi_st_seq) || '''';
  j := j + 1;

  --   tab_tag(j):='UNE+1+'||to_char(v_gs_log)||'''';
  --       j:=j+1;
  tab_tag(j) := 'UNZ+1+' || to_char(v_gs_log) || '''';

  FOR i IN 2 .. j LOOP
    v_outstring := tab_tag(i);
    utl_file.put(out_file, v_outstring);
    --         UTL_FILE.FFLUSH(out_file);
  END LOOP;
  utl_file.fflush(out_file);
  utl_file.fclose(out_file);

  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE, shipment_edi856_date = SYSDATE
   WHERE shipment.packing_list = v_packing_list;
  COMMIT;

  RETURN 1;

EXCEPTION
  WHEN exce_sent THEN
    --    raise_application_error(-20101,'STOP! EDI had been sent');
    --    UTL_FILE.FCLOSE(out_file);
    RETURN 100;
  WHEN exce_nodata THEN
    --     raise_application_error(-20101,'No shipment data found!');
    RETURN - 1;
  WHEN exce_des_sh_cust_id THEN
    --    raise_application_error(-20101,'This shipment does not required EDIFACT DESADV EDI!');
    RETURN 200;
  WHEN OTHERS THEN
    --    raise_application_error(-20101,'INTERNAL ERROR! PLEASE CALL 1519.');
    utl_file.fclose(out_file);
    RETURN - 1;
END;
  GRANT EXECUTE ON "DBO"."F_EDI_DESADV2_ORIG" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function F_EDI_DESADV_BOLT
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_DESADV_BOLT" (v_packing_list shipment.packing_list%TYPE)
  RETURN NUMBER IS
  v_holder              NUMBER(6, 0);
  v_cumulated_pcs       NUMBER(18, 0);
  v_outstring           VARCHAR2(32767);
  v_gs_log              NUMBER(8, 0);
  v_communication_code  VARCHAR2(128);
--  These 4 added by Patrick Reynolds 2016/02/05 for DESADV for GM GFSS
  v_address             VARCHAR2(3);
  v_bgm                 VARCHAR2(3);
  v_skip                int(3) := 0;
  v_DUNS                VARCHAR2(13) := '039630926T:01';  -- DUNS for ALBL...With "T" ???
  --v_DUNS                VARCHAR2(13) := '043207177';  -- DUNS for Constellium
  --DUNS                  VARCHAR2(13) := '001504935::16';  -- DUNS for NOVELIS
  DUNS                  VARCHAR2(13) := '043207177::16';  -- DUNS for Constellium
--
  v_carrier_description shipment.carrier_description_code%TYPE;
  v_customer_id         shipment.customer_id%TYPE;
  v_des_sh_cust_id      shipment.des_sh_cust_id%TYPE;
  v_enduser_id          shipment.shipment_enduser_id%TYPE;
  v_vehicle_prefix      shipment.vehicle_id_prefix%TYPE;
  v_vehicle_id          shipment.vehicle_id%TYPE;
--  v_return              INT(3) := 1;
  v_enduser_po          customer_order.enduser_po%TYPE;
  v_enduser_part        order_item.enduser_part_num%TYPE;
  i                     INT(3) := 1;
  cps_hl                INT(3) := 1;
  
  l_ship_date           date; --Alex Gerlants. 10/17/2017

  edi_file_prefix VARCHAR2(50) := 'S_alcan_gm_gm';

  exce_des_sh_cust_id EXCEPTION;
  exce_nodata         EXCEPTION;
  exce_sent           EXCEPTION;
  /* Declare output file */
  out_file       utl_file.file_type;
--  v_sender_vanid CHAR(25) := '3010007080';
  v_edi_st_seq   NUMBER(6, 0);
  CURSOR c1_cursor IS
    SELECT edi_st_log_seq.nextval FROM dual;
  CURSOR c4_cursor IS
    SELECT edi_file_id_seq.nextval FROM dual;
  v_file_id VARCHAR2(32767);
  v_skids_count  NUMBER(3, 0);
  v_piece_count  NUMBER(8, 0) := 0;
  v_gross_weight NUMBER(12, 0) := 0;
  v_net_weight   NUMBER(12, 0) := 0;
  v_shipdate     DATE;
  v_scac         carrier.scac%TYPE;

  ls_su             VARCHAR2(50); /* Alex Gerlants. 09/02/2016 */
  ls_edi_file_name  VARCHAR2(50); /* Alex Gerlants. 09/02/2016 */

  --ll_tier1_customer_id  number(8); /* Alex Gerlants. 02/09/2017 */

  v_skid_num sheet_skid.sheet_skid_display_num%TYPE;
  TYPE name_type IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  tab_tag name_type;
  j       INT(3) := 1;

  edi_loc VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR'); --Alex Gerlants. 11/15/2016

  CURSOR c2_cursor IS
    SELECT "SHEET_PACKING_ITEM"."SH_PACKING_ITEM",
           'MULTIPLE' "LOT_NUM",
           "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO",
           "CUSTOMER_ORDER"."ORDER_ABC_NUM",
           "CUSTOMER_ORDER"."ENDUSER_PO",
           "ORDER_ITEM"."ORDER_ITEM_NUM",
           "ORDER_ITEM"."ENDUSER_PART_NUM",
           "ORDER_ITEM"."SUPPLIER_CODE",
           "SHEET_SKID". "AB_JOB_NUM",
           "SHEET_SKID"."SHEET_SKID_NUM",
           "SHEET_SKID"."SHEET_SKID_DISPLAY_NUM",
           "SHEET_SKID"."SHEET_NET_WT",
           "SHEET_SKID"."SHEET_TARE_WT",
           "SHEET_SKID". "SKID_PIECES",
           "SHEET_SKID"."SKID_SHEET_STATUS",
           NULL "DONE"
      FROM customer_order
           join order_item on order_item.order_abc_num = customer_order.order_abc_num
           join ab_job on order_item.order_abc_num = ab_job.order_abc_num and ab_job.order_item_num = order_item.order_item_num
           join sheet_skid on sheet_skid.ab_job_num = ab_job.ab_job_num
           join sheet_packing_item on sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
           join shipment on shipment.packing_list = sheet_packing_item.packing_list
     where ("SHIPMENT"."PACKING_LIST" = v_packing_list);
  --         and ("SHIPMENT"."SHIPMENT_EDI856_DATE" is NULL)

  /*
  cursor c5_cursor is
      select distinct nvl(customer_order.tier1_customer_id, -99)
      from   customer_order
             join order_item on order_item.order_abc_num = customer_order.order_abc_num
             join ab_job on order_item.order_abc_num = ab_job.order_abc_num and ab_job.order_item_num = order_item.order_item_num
             join sheet_skid on sheet_skid.ab_job_num = ab_job.ab_job_num
             join sheet_packing_item on sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
             join shipment on shipment.packing_list = sheet_packing_item.packing_list
      where  shipment.packing_list = v_packing_list;
   */
  --

BEGIN
  
  --Alex Gerlants. 10/17/2017. Begin
  --This is to fix a problem when an ASN (DESADV) for a shipment can be resent without reversing.
  SELECT shipment_desadv_date
    INTO l_ship_date
    FROM shipment
   WHERE shipment.packing_list = v_packing_list;
   
  IF NOT (l_ship_date IS NULL) THEN
    RETURN 100;
  END IF; 
  --Alex Gerlants. 10/17/2017. End

  SELECT customer_id, des_sh_cust_id, shipment_enduser_id
    INTO v_customer_id, v_des_sh_cust_id, v_enduser_id
    FROM shipment
   WHERE shipment.packing_list = v_packing_list;
  IF NOT SQL%FOUND THEN
    --         RAISE exce_nodata;
    RETURN - 1;
  END IF;

  /* Alex Gerlants. 02/09/2017. Begin */
  --Roy said that they would not ship orders with diferent tier1_customers
  --on the same packing_list.
  --To be on the safe side however, I am looping through all distinct order_abc_num's
  --and if at least one of them > 0, then we create DESADV.
  /*
  if not c5_cursor%ISOPEN then
    open c5_cursor;
  end if;

  loop
    fetch c5_cursor
      into ll_tier1_customer_id;
      
    exit when ll_tier1_customer_id > 0; --Valid tier1_customer_id found
    exit when c5_cursor%NOTFOUND;
  end loop;
  
  if c5_cursor%ISOPEN then
    close c5_cursor;
  end if;

  if ll_tier1_customer_id <= 0 then --Nothing to do
    return 200;
  end if;
  */
  /* Alex Gerlants. 02/09/2017. End */

  IF NOT c1_cursor%ISOPEN THEN
    OPEN c1_cursor;
  END IF;
  FETCH c1_cursor
    INTO v_edi_st_seq;
  CLOSE c1_cursor;

  SELECT edi_gs_log_seq.nextval INTO v_gs_log FROM dual;

  --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. Comment out Begin
  /*
  -- If the customer is not in the table or he has no communication_code then this will return nothing
  -- and thus throw an ORA-01403 Error.
  SELECT communication_code
    INTO v_communication_code
    FROM customer_system
   WHERE customer_id = v_des_sh_cust_id;
  */
  --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. Comment out End

  --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. Begin
  select f_get_sisco_code(v_des_sh_cust_id) --New function
  into   v_communication_code
  from   dual;
  
  if lower(nvl(v_communication_code, 'unknown')) = 'unknown' then
    return -3;  --Ship user will get message "Communication code is NOT set up in table customer_system for Destination Customer ..."
                --It will not get to the next statement.
  end if;
  --Alex Gerlants. Communication_Code_Error_Message. 11/01/2017. End

  --Commented Alex Gerlants. 02/09/2017
  --IF (v_customer_id = 2505) THEN
  --  v_address := 'MZ7';
  --   v_DUNS := 'XYY:ZZ';
  --  v_communication_code := '51972';
  --  v_bgm := '';
  -- v_skip := 1;
  --  DUNS := '039630926::16';  -- Change default DUNS from NOVELIS to ALBL;
  --ELSE
    --v_address := 'ALV';
    v_address := 'MZ7';
    v_bgm := '351';
  --END IF;

  tab_tag(j) := 'UNA:+.? ''';
  j := j + 1;

  
  --Alex Gerlants. 06/06/2017. Commented out
  /*
  tab_tag(j) := 'UNB+UNOA:2+' || v_DUNS || ':01+' || v_address || ':ZZ+' ||
                to_char(SYSDATE, 'YYMMDD:HH24MI') || '+' ||
                to_char(v_gs_log) || '++GMDESADV''';
  */
  
  v_DUNS := 'XYY'; --Alex Gerlants. 06/06/2017. As per Lisa Dingman
                
  tab_tag(j) := 'UNB+UNOA:2+' || v_DUNS || ':ZZ+' || v_address || ':ZZ+' ||
                to_char(SYSDATE, 'YYMMDD:HH24MI') || '+' ||
                to_char(v_gs_log) || '++GMDESADV''';
                                
  j := j + 1;

  tab_tag(j) := 'UNH+' || to_char(v_edi_st_seq) || '+DESADV:D:97A:UN''';
  j := j + 1;
  tab_tag(j) := 'BGM+' || v_bgm || '+' || to_char(v_packing_list) || '+9''';
  j := j + 1;
  tab_tag(j) := 'DTM+137:' || to_char(SYSDATE, 'YYYYMMDDHH24MI') ||
                ':203''';
  j := j + 1;

  SELECT nvl(shipment_actualed_date_time, SYSDATE)
    INTO v_shipdate
    FROM shipment
   WHERE packing_list = v_packing_list;
  tab_tag(j) := 'DTM+11:' || to_char(v_shipdate, 'YYYYMMDDHH24MI') ||
                ':203''';
  j := j + 1;

  SELECT MAX(sh_packing_item)
    INTO v_skids_count
    FROM sheet_packing_item
   WHERE sheet_packing_item.packing_list = v_packing_list;

  FOR c2_record IN c2_cursor LOOP
    v_piece_count  := v_piece_count + c2_record.skid_pieces;
    v_gross_weight := v_gross_weight + c2_record.sheet_net_wt * 0.45359 +
                      c2_record.sheet_tare_wt * 0.45359;
    v_net_weight   := v_net_weight + c2_record.sheet_net_wt * 0.45359;
    --      v_tare_weight := v_tare_weight + c2_record.SHEET_TARE_WT;
  --    Put more item here
  END LOOP;

  --    v_skids_count := c2_cursor%ROWCOUNT;

  tab_tag(j) := 'MEA+AAX+SQ+C62:' || to_char(v_skids_count) || '''';
  j := j + 1;
  tab_tag(j) := 'MEA+AAX+G+KG:' || to_char(v_gross_weight) || '''';
  j := j + 1;
  tab_tag(j) := 'MEA+AAX+N+KG:' || to_char(v_net_weight) || '''';
  j := j + 1;
  tab_tag(j) := 'RFF+MB:' || to_char(v_packing_list) || '''';
  j := j + 1;

  tab_tag(j) := 'NAD+MI+88120::92''';

  j := j + 1;

  tab_tag(j) := 'NAD+SU+' || DUNS || ''''; --Supplier is Novelis Kingston Feb8-06 by tony
  --001504935
  j := j + 1;

  tab_tag(j) := 'NAD+ST+' || v_communication_code || '::92''';
  j := j + 1;

  /* LOC segment, need location code from Alcan or GM */

  tab_tag(j) := 'LOC+11+A1A2''';
  j := j + 1;

  SELECT nvl(carrier.scac, 'AAAA')
    INTO v_scac
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = v_packing_list);

  tab_tag(j) := 'TDT+25++M++' || v_scac || '::182''';
  j := j + 1;

  SELECT nvl(shipment.carrier_description_code, 'TL')
    INTO v_carrier_description
    FROM shipment
   WHERE shipment.packing_list = v_packing_list;
  IF v_carrier_description = 'TL' THEN
    v_carrier_description := 'TE';
  END IF;

  SELECT nvl(shipment.vehicle_id_prefix, 'AA'),
         nvl(shipment.vehicle_id, '1111')
    INTO v_vehicle_prefix, v_vehicle_id
    FROM shipment
   WHERE shipment.packing_list = v_packing_list;

  tab_tag(j) := 'EQD+' || v_carrier_description || '+' || v_vehicle_prefix ||
                v_vehicle_id || '''';
  j := j + 1;

  /* DETAIL LOOP BEGIN */
  --   cps_hl := 1;
  FOR c2_record IN c2_cursor LOOP

    SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
      INTO v_enduser_part
      FROM "ORDER_ITEM", "SHEET_SKID"
     WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
       AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" =
           "ORDER_ITEM"."ORDER_ITEM_NUM")
       AND ("SHEET_SKID"."SHEET_SKID_NUM" = c2_record.sheet_skid_num);

    SELECT "CUSTOMER_ORDER"."ENDUSER_PO"
      INTO v_enduser_po
      FROM "SHEET_SKID", "CUSTOMER_ORDER"
     WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
           "CUSTOMER_ORDER"."ORDER_ABC_NUM")
       AND (sheet_skid.sheet_skid_num = c2_record.sheet_skid_num);

    tab_tag(j) := 'CPS+' || to_char(cps_hl) || '++1''';
    j := j + 1;
--    tab_tag(j) := 'PAC+' || to_char(c2_record.skid_pieces) || '''';
      if (v_des_sh_cust_id IN (2611, 2814)) THEN
         tab_tag(j) := 'PAC+' || to_char(c2_record.skid_pieces) || '++AHB52679'''; -- Added by Patrick Reynolds 07-21-2016
      else
         tab_tag(j) := 'PAC+' || to_char(c2_record.skid_pieces) || ''''; -- Added by Patrick Reynolds 07-21-2016
      END IF;

    j := j + 1;
    /*    tab_tag(j) := 'QTY+52:'||TO_CHAR(c2_record.SKID_PIECES)||'''';
    j := j + 1;   */
    tab_tag(j) := 'PCI+16''';
    j := j + 1;
    /*    tab_tag(j) := 'RFF+CW:'||TO_CHAR(c2_record.SH_PACKING_ITEM)||'''';
      j := j + 1;
    tab_tag(j) := 'GIR+3+'||TO_CHAR(c2_record.SHEET_SKID_NUM)||':AW''';
      j := j + 1;  */

    v_skid_num := c2_record.sheet_skid_display_num;
 
    tab_tag(j) := 'LIN+++' || v_enduser_part || ':IN''';
    j := j + 1;

    -- changed to PIA+1+5:RY per Jeff Blaha 1/29/2015 email
    --  tab_tag(j) := 'PIA+1+0:RY''';
    tab_tag(j) := 'PIA+1+6:RY''';
    j := j + 1;

    SELECT SUM(sheet_skid.skid_pieces)
      INTO v_cumulated_pcs
      FROM sheet_skid, order_item
     WHERE sheet_skid.ref_order_abc_num = order_item.order_abc_num
       AND sheet_skid.ref_order_abc_item = order_item.order_item_num
       AND order_item.enduser_part_num = c2_record.enduser_part_num;

    tab_tag(j) := 'QTY+3:' || to_char(v_cumulated_pcs) || ':EA''';
    j := j + 1;
    tab_tag(j) := 'QTY+12:' || to_char(c2_record.skid_pieces) || ':EA''';
    j := j + 1;
    tab_tag(j) := 'RFF+ON:' || v_enduser_po || '''';
    j := j + 1;

  IF (v_skip = 0) THEN
      tab_tag(j) := 'PCI+15+' || to_char(c2_record.sheet_skid_display_num) || '''';
      j := j + 1;
      tab_tag(j) := 'QTY+12:' || to_char(c2_record.skid_pieces) || ':EA''';
      j := j + 1;
  END IF;

    cps_hl := cps_hl + 1;
  END LOOP;

  /* OUTPUT TO file*/
  IF NOT c4_cursor%ISOPEN THEN
    OPEN c4_cursor;
    FETCH c4_cursor
      INTO v_holder;
    CLOSE c4_cursor;
  END IF;
  v_file_id := to_char(v_holder);

--Alex Gerlants. 11/15/2016. Commented out statement below, and added statement after.
  --out_file := utl_file.fopen('/templar/templar/incoming/senddata',
  --                           edi_file_prefix || v_file_id || '.edi',  -- Change before moving to PROD
  --                           'w',
  --                           32767);

  out_file := utl_file.fopen(edi_loc,
                             edi_file_prefix || v_file_id || '.edi',  -- Change before moving to PROD
                             'w',
                             32767);

  ls_edi_file_name := edi_file_prefix || v_file_id || '.edi'; /* Alex Gerlants. 09/02/2016 */

  --   out_file :=  UTL_FILE.FOPEN('/tmp','S_alcan_gm_gm'||v_file_id||'.desadv','w');
  tab_tag(j) := 'UNT+' || to_char(j - 2) || '+' || to_char(v_edi_st_seq) || '''';
  j := j + 1;

  --   tab_tag(j) := 'UNE+1+'||to_char(v_gs_log)||'''';
  --       j := j + 1;
  tab_tag(j) := 'UNZ+1+' || to_char(v_gs_log) || '''';

  FOR i IN 2 .. j LOOP
    v_outstring := tab_tag(i);
    utl_file.put(out_file, v_outstring);
    --         UTL_FILE.FFLUSH(out_file);
  END LOOP;
  utl_file.fflush(out_file);
  utl_file.fclose(out_file);

/*  This has been replaced by the UPDATE statement below.
    These columns are already updated in another function, edi_alcan_alcan_856_x12, so to update them here
    could be misleading as well as wiping out information from the aforementioned function hence the need for
    the shipment_desadv_date column in the shipment table.
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE
   WHERE shipment.packing_list = v_packing_list;
  COMMIT;
*/

--  Uncomment before moving to PROD
  --Alex Gerlants. 09/02/2016. Added ", edi_file_id_desadv = edi_file_id".
  --Alex Gerlants. 03/17/2017. Added shipment_des_edi856_date = SYSDATE
  UPDATE shipment
     SET shipment_desadv_date = SYSDATE,
         edi_file_id_desadv = v_file_id,
         shipment_des_edi856_date = SYSDATE
   WHERE shipment.packing_list = v_packing_list;

   ----------------------------------------------------------------
   --Alex Gerlants. 09/02/2016. Begin

   select nvl(customer_duns_number_string, '00000000')
   into   ls_su
   from   customer
   where  customer_id = v_customer_id;

   If (ls_su = '00000000') Then
    Return 200;
   End If;

   INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (v_file_id,
     '039630926',
     ls_su,
     v_gs_log,
     v_gs_log,
     SYSDATE,
     ls_edi_file_name,
     0,
     v_customer_id,
     v_edi_st_seq,
     'desadv');


   --Alex Gerlants. 09/02/2016. End
   ----------------------------------------------------------------

  COMMIT;


  RETURN 1;

EXCEPTION
  WHEN exce_sent THEN
    --    raise_application_error(-20101,'STOP! EDI had been sent');
    --    UTL_FILE.FCLOSE(out_file);
    RETURN 100;
  WHEN exce_nodata THEN
    --     raise_application_error(-20101,'No shipment data found!');
    RETURN - 1;
  WHEN exce_des_sh_cust_id THEN
    --    raise_application_error(-20101,'This shipment does not required EDIFACT DESADV EDI!');
    RETURN 200;
  WHEN OTHERS THEN
    --    raise_application_error(-20101,'INTERNAL ERROR! PLEASE CALL 1519.');
   --  raise_application_error(-20101,'An error was encountered - ' || SQLCODE || ' -ERROR- ' || SQLERRM);
    utl_file.fclose(out_file);
    RETURN - 2;
END;
  GRANT EXECUTE ON "DBO"."F_EDI_DESADV_BOLT" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function F_EDI_DESADV_BOLT_11132017
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_DESADV_BOLT_11132017" (v_packing_list shipment.packing_list%TYPE)
  RETURN NUMBER IS
  v_holder              NUMBER(6, 0);
  v_cumulated_pcs       NUMBER(18, 0);
  v_outstring           VARCHAR2(32767);
  v_gs_log              NUMBER(8, 0);
  v_communication_code  VARCHAR2(128);
--  These 4 added by Patrick Reynolds 2016/02/05 for DESADV for GM GFSS
  v_address             VARCHAR2(3);
  v_bgm                 VARCHAR2(3);
  v_skip                int(3) := 0;
  v_DUNS                VARCHAR2(13) := '039630926T:01';  -- DUNS for ALBL...With "T" ???
  --v_DUNS                VARCHAR2(13) := '043207177';  -- DUNS for Constellium
  --DUNS                  VARCHAR2(13) := '001504935::16';  -- DUNS for NOVELIS
  DUNS                  VARCHAR2(13) := '043207177::16';  -- DUNS for Constellium
--
  v_carrier_description shipment.carrier_description_code%TYPE;
  v_customer_id         shipment.customer_id%TYPE;
  v_des_sh_cust_id      shipment.des_sh_cust_id%TYPE;
  v_enduser_id          shipment.shipment_enduser_id%TYPE;
  v_vehicle_prefix      shipment.vehicle_id_prefix%TYPE;
  v_vehicle_id          shipment.vehicle_id%TYPE;
--  v_return              INT(3) := 1;
  v_enduser_po          customer_order.enduser_po%TYPE;
  v_enduser_part        order_item.enduser_part_num%TYPE;
  i                     INT(3) := 1;
  cps_hl                INT(3) := 1;
  
  l_ship_date           date; --Alex Gerlants. 10/17/2017

  edi_file_prefix VARCHAR2(50) := 'S_alcan_gm_gm';

  exce_des_sh_cust_id EXCEPTION;
  exce_nodata         EXCEPTION;
  exce_sent           EXCEPTION;
  /* Declare output file */
  out_file       utl_file.file_type;
--  v_sender_vanid CHAR(25) := '3010007080';
  v_edi_st_seq   NUMBER(6, 0);
  CURSOR c1_cursor IS
    SELECT edi_st_log_seq.nextval FROM dual;
  CURSOR c4_cursor IS
    SELECT edi_file_id_seq.nextval FROM dual;
  v_file_id VARCHAR2(32767);
  v_skids_count  NUMBER(3, 0);
  v_piece_count  NUMBER(8, 0) := 0;
  v_gross_weight NUMBER(12, 0) := 0;
  v_net_weight   NUMBER(12, 0) := 0;
  v_shipdate     DATE;
  v_scac         carrier.scac%TYPE;

  ls_su             VARCHAR2(50); /* Alex Gerlants. 09/02/2016 */
  ls_edi_file_name  VARCHAR2(50); /* Alex Gerlants. 09/02/2016 */

  --ll_tier1_customer_id  number(8); /* Alex Gerlants. 02/09/2017 */

  v_skid_num sheet_skid.sheet_skid_display_num%TYPE;
  TYPE name_type IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  tab_tag name_type;
  j       INT(3) := 1;

  edi_loc VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR'); --Alex Gerlants. 11/15/2016

  CURSOR c2_cursor IS
    SELECT "SHEET_PACKING_ITEM"."SH_PACKING_ITEM",
           'MULTIPLE' "LOT_NUM",
           "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO",
           "CUSTOMER_ORDER"."ORDER_ABC_NUM",
           "CUSTOMER_ORDER"."ENDUSER_PO",
           "ORDER_ITEM"."ORDER_ITEM_NUM",
           "ORDER_ITEM"."ENDUSER_PART_NUM",
           "ORDER_ITEM"."SUPPLIER_CODE",
           "SHEET_SKID". "AB_JOB_NUM",
           "SHEET_SKID"."SHEET_SKID_NUM",
           "SHEET_SKID"."SHEET_SKID_DISPLAY_NUM",
           "SHEET_SKID"."SHEET_NET_WT",
           "SHEET_SKID"."SHEET_TARE_WT",
           "SHEET_SKID". "SKID_PIECES",
           "SHEET_SKID"."SKID_SHEET_STATUS",
           NULL "DONE"
      FROM customer_order
           join order_item on order_item.order_abc_num = customer_order.order_abc_num
           join ab_job on order_item.order_abc_num = ab_job.order_abc_num and ab_job.order_item_num = order_item.order_item_num
           join sheet_skid on sheet_skid.ab_job_num = ab_job.ab_job_num
           join sheet_packing_item on sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
           join shipment on shipment.packing_list = sheet_packing_item.packing_list
     where ("SHIPMENT"."PACKING_LIST" = v_packing_list);
  --         and ("SHIPMENT"."SHIPMENT_EDI856_DATE" is NULL)

  /*
  cursor c5_cursor is
      select distinct nvl(customer_order.tier1_customer_id, -99)
      from   customer_order
             join order_item on order_item.order_abc_num = customer_order.order_abc_num
             join ab_job on order_item.order_abc_num = ab_job.order_abc_num and ab_job.order_item_num = order_item.order_item_num
             join sheet_skid on sheet_skid.ab_job_num = ab_job.ab_job_num
             join sheet_packing_item on sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
             join shipment on shipment.packing_list = sheet_packing_item.packing_list
      where  shipment.packing_list = v_packing_list;
   */
  --

BEGIN
  
  --Alex Gerlants. 10/17/2017. Begin
  --This is to fix a problem when an ASN (DESADV) for a shipment can be resent without reversing.
  SELECT shipment_desadv_date
    INTO l_ship_date
    FROM shipment
   WHERE shipment.packing_list = v_packing_list;
   
  IF NOT (l_ship_date IS NULL) THEN
    RETURN 100;
  END IF; 
  --Alex Gerlants. 10/17/2017. End

  SELECT customer_id, des_sh_cust_id, shipment_enduser_id
    INTO v_customer_id, v_des_sh_cust_id, v_enduser_id
    FROM shipment
   WHERE shipment.packing_list = v_packing_list;
  IF NOT SQL%FOUND THEN
    --         RAISE exce_nodata;
    RETURN - 1;
  END IF;

  /* Alex Gerlants. 02/09/2017. Begin */
  --Roy said that they would not ship orders with diferent tier1_customers
  --on the same packing_list.
  --To be on the safe side however, I am looping through all distinct order_abc_num's
  --and if at least one of them > 0, then we create DESADV.
  /*
  if not c5_cursor%ISOPEN then
    open c5_cursor;
  end if;

  loop
    fetch c5_cursor
      into ll_tier1_customer_id;
      
    exit when ll_tier1_customer_id > 0; --Valid tier1_customer_id found
    exit when c5_cursor%NOTFOUND;
  end loop;
  
  if c5_cursor%ISOPEN then
    close c5_cursor;
  end if;

  if ll_tier1_customer_id <= 0 then --Nothing to do
    return 200;
  end if;
  */
  /* Alex Gerlants. 02/09/2017. End */

  IF NOT c1_cursor%ISOPEN THEN
    OPEN c1_cursor;
  END IF;
  FETCH c1_cursor
    INTO v_edi_st_seq;
  CLOSE c1_cursor;

  SELECT edi_gs_log_seq.nextval INTO v_gs_log FROM dual;

  -- If the customer is not in the table or he has no communication_code then this will return nothing
  -- and thus throw an ORA-01403 Error.
  SELECT communication_code
    INTO v_communication_code
    FROM customer_system
   WHERE customer_id = v_des_sh_cust_id;

  --Commented Alex Gerlants. 02/09/2017
  --IF (v_customer_id = 2505) THEN
  --  v_address := 'MZ7';
  --   v_DUNS := 'XYY:ZZ';
  --  v_communication_code := '51972';
  --  v_bgm := '';
  -- v_skip := 1;
  --  DUNS := '039630926::16';  -- Change default DUNS from NOVELIS to ALBL;
  --ELSE
    --v_address := 'ALV';
    v_address := 'MZ7';
    v_bgm := '351';
  --END IF;

  tab_tag(j) := 'UNA:+.? ''';
  j := j + 1;

  
  --Alex Gerlants. 06/06/2017. Commented out
  /*
  tab_tag(j) := 'UNB+UNOA:2+' || v_DUNS || ':01+' || v_address || ':ZZ+' ||
                to_char(SYSDATE, 'YYMMDD:HH24MI') || '+' ||
                to_char(v_gs_log) || '++GMDESADV''';
  */
  
  v_DUNS := 'XYY'; --Alex Gerlants. 06/06/2017. As per Lisa Dingman
                
  tab_tag(j) := 'UNB+UNOA:2+' || v_DUNS || ':ZZ+' || v_address || ':ZZ+' ||
                to_char(SYSDATE, 'YYMMDD:HH24MI') || '+' ||
                to_char(v_gs_log) || '++GMDESADV''';
                                
  j := j + 1;

  tab_tag(j) := 'UNH+' || to_char(v_edi_st_seq) || '+DESADV:D:97A:UN''';
  j := j + 1;
  tab_tag(j) := 'BGM+' || v_bgm || '+' || to_char(v_packing_list) || '+9''';
  j := j + 1;
  tab_tag(j) := 'DTM+137:' || to_char(SYSDATE, 'YYYYMMDDHH24MI') ||
                ':203''';
  j := j + 1;

  SELECT nvl(shipment_actualed_date_time, SYSDATE)
    INTO v_shipdate
    FROM shipment
   WHERE packing_list = v_packing_list;
  tab_tag(j) := 'DTM+11:' || to_char(v_shipdate, 'YYYYMMDDHH24MI') ||
                ':203''';
  j := j + 1;

  SELECT MAX(sh_packing_item)
    INTO v_skids_count
    FROM sheet_packing_item
   WHERE sheet_packing_item.packing_list = v_packing_list;

  FOR c2_record IN c2_cursor LOOP
    v_piece_count  := v_piece_count + c2_record.skid_pieces;
    v_gross_weight := v_gross_weight + c2_record.sheet_net_wt * 0.45359 +
                      c2_record.sheet_tare_wt * 0.45359;
    v_net_weight   := v_net_weight + c2_record.sheet_net_wt * 0.45359;
    --      v_tare_weight := v_tare_weight + c2_record.SHEET_TARE_WT;
  --    Put more item here
  END LOOP;

  --    v_skids_count := c2_cursor%ROWCOUNT;

  tab_tag(j) := 'MEA+AAX+SQ+C62:' || to_char(v_skids_count) || '''';
  j := j + 1;
  tab_tag(j) := 'MEA+AAX+G+KG:' || to_char(v_gross_weight) || '''';
  j := j + 1;
  tab_tag(j) := 'MEA+AAX+N+KG:' || to_char(v_net_weight) || '''';
  j := j + 1;
  tab_tag(j) := 'RFF+MB:' || to_char(v_packing_list) || '''';
  j := j + 1;

  tab_tag(j) := 'NAD+MI+88120::92''';

  j := j + 1;

  tab_tag(j) := 'NAD+SU+' || DUNS || ''''; --Supplier is Novelis Kingston Feb8-06 by tony
  --001504935
  j := j + 1;

  tab_tag(j) := 'NAD+ST+' || v_communication_code || '::92''';
  j := j + 1;

  /* LOC segment, need location code from Alcan or GM */

  tab_tag(j) := 'LOC+11+A1A2''';
  j := j + 1;

  SELECT nvl(carrier.scac, 'AAAA')
    INTO v_scac
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = v_packing_list);

  tab_tag(j) := 'TDT+25++M++' || v_scac || '::182''';
  j := j + 1;

  SELECT nvl(shipment.carrier_description_code, 'TL')
    INTO v_carrier_description
    FROM shipment
   WHERE shipment.packing_list = v_packing_list;
  IF v_carrier_description = 'TL' THEN
    v_carrier_description := 'TE';
  END IF;

  SELECT nvl(shipment.vehicle_id_prefix, 'AA'),
         nvl(shipment.vehicle_id, '1111')
    INTO v_vehicle_prefix, v_vehicle_id
    FROM shipment
   WHERE shipment.packing_list = v_packing_list;

  tab_tag(j) := 'EQD+' || v_carrier_description || '+' || v_vehicle_prefix ||
                v_vehicle_id || '''';
  j := j + 1;

  /* DETAIL LOOP BEGIN */
  --   cps_hl := 1;
  FOR c2_record IN c2_cursor LOOP

    SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
      INTO v_enduser_part
      FROM "ORDER_ITEM", "SHEET_SKID"
     WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
       AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" =
           "ORDER_ITEM"."ORDER_ITEM_NUM")
       AND ("SHEET_SKID"."SHEET_SKID_NUM" = c2_record.sheet_skid_num);

    SELECT "CUSTOMER_ORDER"."ENDUSER_PO"
      INTO v_enduser_po
      FROM "SHEET_SKID", "CUSTOMER_ORDER"
     WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
           "CUSTOMER_ORDER"."ORDER_ABC_NUM")
       AND (sheet_skid.sheet_skid_num = c2_record.sheet_skid_num);

    tab_tag(j) := 'CPS+' || to_char(cps_hl) || '++1''';
    j := j + 1;
--    tab_tag(j) := 'PAC+' || to_char(c2_record.skid_pieces) || '''';
      if (v_des_sh_cust_id IN (2611, 2814)) THEN
         tab_tag(j) := 'PAC+' || to_char(c2_record.skid_pieces) || '++AHB52679'''; -- Added by Patrick Reynolds 07-21-2016
      else
         tab_tag(j) := 'PAC+' || to_char(c2_record.skid_pieces) || ''''; -- Added by Patrick Reynolds 07-21-2016
      END IF;

    j := j + 1;
    /*    tab_tag(j) := 'QTY+52:'||TO_CHAR(c2_record.SKID_PIECES)||'''';
    j := j + 1;   */
    tab_tag(j) := 'PCI+16''';
    j := j + 1;
    /*    tab_tag(j) := 'RFF+CW:'||TO_CHAR(c2_record.SH_PACKING_ITEM)||'''';
      j := j + 1;
    tab_tag(j) := 'GIR+3+'||TO_CHAR(c2_record.SHEET_SKID_NUM)||':AW''';
      j := j + 1;  */

    v_skid_num := c2_record.sheet_skid_display_num;
 
    tab_tag(j) := 'LIN+++' || v_enduser_part || ':IN''';
    j := j + 1;

    -- changed to PIA+1+5:RY per Jeff Blaha 1/29/2015 email
    --  tab_tag(j) := 'PIA+1+0:RY''';
    tab_tag(j) := 'PIA+1+6:RY''';
    j := j + 1;

    SELECT SUM(sheet_skid.skid_pieces)
      INTO v_cumulated_pcs
      FROM sheet_skid, order_item
     WHERE sheet_skid.ref_order_abc_num = order_item.order_abc_num
       AND sheet_skid.ref_order_abc_item = order_item.order_item_num
       AND order_item.enduser_part_num = c2_record.enduser_part_num;

    tab_tag(j) := 'QTY+3:' || to_char(v_cumulated_pcs) || ':EA''';
    j := j + 1;
    tab_tag(j) := 'QTY+12:' || to_char(c2_record.skid_pieces) || ':EA''';
    j := j + 1;
    tab_tag(j) := 'RFF+ON:' || v_enduser_po || '''';
    j := j + 1;

  IF (v_skip = 0) THEN
      tab_tag(j) := 'PCI+15+' || to_char(c2_record.sheet_skid_display_num) || '''';
      j := j + 1;
      tab_tag(j) := 'QTY+12:' || to_char(c2_record.skid_pieces) || ':EA''';
      j := j + 1;
  END IF;

    cps_hl := cps_hl + 1;
  END LOOP;

  /* OUTPUT TO file*/
  IF NOT c4_cursor%ISOPEN THEN
    OPEN c4_cursor;
    FETCH c4_cursor
      INTO v_holder;
    CLOSE c4_cursor;
  END IF;
  v_file_id := to_char(v_holder);

--Alex Gerlants. 11/15/2016. Commented out statement below, and added statement after.
  --out_file := utl_file.fopen('/templar/templar/incoming/senddata',
  --                           edi_file_prefix || v_file_id || '.edi',  -- Change before moving to PROD
  --                           'w',
  --                           32767);

  out_file := utl_file.fopen(edi_loc,
                             edi_file_prefix || v_file_id || '.edi',  -- Change before moving to PROD
                             'w',
                             32767);

  ls_edi_file_name := edi_file_prefix || v_file_id || '.edi'; /* Alex Gerlants. 09/02/2016 */

  --   out_file :=  UTL_FILE.FOPEN('/tmp','S_alcan_gm_gm'||v_file_id||'.desadv','w');
  tab_tag(j) := 'UNT+' || to_char(j - 2) || '+' || to_char(v_edi_st_seq) || '''';
  j := j + 1;

  --   tab_tag(j) := 'UNE+1+'||to_char(v_gs_log)||'''';
  --       j := j + 1;
  tab_tag(j) := 'UNZ+1+' || to_char(v_gs_log) || '''';

  FOR i IN 2 .. j LOOP
    v_outstring := tab_tag(i);
    utl_file.put(out_file, v_outstring);
    --         UTL_FILE.FFLUSH(out_file);
  END LOOP;
  utl_file.fflush(out_file);
  utl_file.fclose(out_file);

/*  This has been replaced by the UPDATE statement below.
    These columns are already updated in another function, edi_alcan_alcan_856_x12, so to update them here
    could be misleading as well as wiping out information from the aforementioned function hence the need for
    the shipment_desadv_date column in the shipment table.
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE
   WHERE shipment.packing_list = v_packing_list;
  COMMIT;
*/

--  Uncomment before moving to PROD
  --Alex Gerlants. 09/02/2016. Added ", edi_file_id_desadv = edi_file_id".
  --Alex Gerlants. 03/17/2017. Added shipment_des_edi856_date = SYSDATE
  UPDATE shipment
     SET shipment_desadv_date = SYSDATE,
         edi_file_id_desadv = v_file_id,
         shipment_des_edi856_date = SYSDATE
   WHERE shipment.packing_list = v_packing_list;

   ----------------------------------------------------------------
   --Alex Gerlants. 09/02/2016. Begin

   select nvl(customer_duns_number_string, '00000000')
   into   ls_su
   from   customer
   where  customer_id = v_customer_id;

   If (ls_su = '00000000') Then
    Return 200;
   End If;

   INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (v_file_id,
     '039630926',
     ls_su,
     v_gs_log,
     v_gs_log,
     SYSDATE,
     ls_edi_file_name,
     0,
     v_customer_id,
     v_edi_st_seq,
     'desadv');


   --Alex Gerlants. 09/02/2016. End
   ----------------------------------------------------------------

  COMMIT;


  RETURN 1;

EXCEPTION
  WHEN exce_sent THEN
    --    raise_application_error(-20101,'STOP! EDI had been sent');
    --    UTL_FILE.FCLOSE(out_file);
    RETURN 100;
  WHEN exce_nodata THEN
    --     raise_application_error(-20101,'No shipment data found!');
    RETURN - 1;
  WHEN exce_des_sh_cust_id THEN
    --    raise_application_error(-20101,'This shipment does not required EDIFACT DESADV EDI!');
    RETURN 200;
  WHEN OTHERS THEN
    --    raise_application_error(-20101,'INTERNAL ERROR! PLEASE CALL 1519.');
   --  raise_application_error(-20101,'An error was encountered - ' || SQLCODE || ' -ERROR- ' || SQLERRM);
    utl_file.fclose(out_file);
    RETURN - 2;
END;
--------------------------------------------------------
--  DDL for Function F_EDI_DESADV_BOLT_ALEX
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_DESADV_BOLT_ALEX" (v_packing_list shipment.packing_list%TYPE)
  RETURN NUMBER IS
  v_holder              NUMBER(6, 0);
  v_cumulated_pcs       NUMBER(18, 0);
  v_outstring           VARCHAR2(32767);
  v_gs_log              NUMBER(8, 0);
  v_communication_code  VARCHAR2(128);
--  These 4 added by Patrick Reynolds 2016/02/05 for DESADV for GM GFSS
  v_address             VARCHAR2(3);
  v_bgm                 VARCHAR2(3);
  v_skip                int(3) := 0;
  v_DUNS                VARCHAR2(13) := '039630926T:01';  -- DUNS for ALBL...With "T" ???
  --v_DUNS                VARCHAR2(13) := '043207177';  -- DUNS for Constellium
  --DUNS                  VARCHAR2(13) := '001504935::16';  -- DUNS for NOVELIS
  DUNS                  VARCHAR2(13) := '043207177::16';  -- DUNS for Constellium
--
  v_carrier_description shipment.carrier_description_code%TYPE;
  v_customer_id         shipment.customer_id%TYPE;
  v_des_sh_cust_id      shipment.des_sh_cust_id%TYPE;
  v_enduser_id          shipment.shipment_enduser_id%TYPE;
  v_vehicle_prefix      shipment.vehicle_id_prefix%TYPE;
  v_vehicle_id          shipment.vehicle_id%TYPE;
--  v_return              INT(3) := 1;
  v_enduser_po          customer_order.enduser_po%TYPE;
  v_enduser_part        order_item.enduser_part_num%TYPE;
  i                     INT(3) := 1;
  cps_hl                INT(3) := 1;

  edi_file_prefix VARCHAR2(50) := 'alex_alcan_gm_gm';

  exce_des_sh_cust_id EXCEPTION;
  exce_nodata         EXCEPTION;
  exce_sent           EXCEPTION;
  /* Declare output file */
  out_file       utl_file.file_type;
--  v_sender_vanid CHAR(25) := '3010007080';
  v_edi_st_seq   NUMBER(6, 0);
  CURSOR c1_cursor IS
    SELECT edi_st_log_seq.nextval FROM dual;
  CURSOR c4_cursor IS
    SELECT edi_file_id_seq.nextval FROM dual;
  v_file_id VARCHAR2(32767);
  v_skids_count  NUMBER(3, 0);
  v_piece_count  NUMBER(8, 0) := 0;
  v_gross_weight NUMBER(12, 0) := 0;
  v_net_weight   NUMBER(12, 0) := 0;
  v_shipdate     DATE;
  v_scac         carrier.scac%TYPE;

  ls_su             VARCHAR2(50); /* Alex Gerlants. 09/02/2016 */
  ls_edi_file_name  VARCHAR2(50); /* Alex Gerlants. 09/02/2016 */

  --ll_tier1_customer_id  number(8); /* Alex Gerlants. 02/09/2017 */

  v_skid_num sheet_skid.sheet_skid_display_num%TYPE;
  TYPE name_type IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  tab_tag name_type;
  j       INT(3) := 1;

  edi_loc VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR'); --Alex Gerlants. 11/15/2016

  CURSOR c2_cursor IS
    SELECT "SHEET_PACKING_ITEM"."SH_PACKING_ITEM",
           'MULTIPLE' "LOT_NUM",
           "CUSTOMER_ORDER"."ORIG_CUSTOMER_PO",
           "CUSTOMER_ORDER"."ORDER_ABC_NUM",
           "CUSTOMER_ORDER"."ENDUSER_PO",
           "ORDER_ITEM"."ORDER_ITEM_NUM",
           "ORDER_ITEM"."ENDUSER_PART_NUM",
           "ORDER_ITEM"."SUPPLIER_CODE",
           "SHEET_SKID". "AB_JOB_NUM",
           "SHEET_SKID"."SHEET_SKID_NUM",
           "SHEET_SKID"."SHEET_SKID_DISPLAY_NUM",
           "SHEET_SKID"."SHEET_NET_WT",
           "SHEET_SKID"."SHEET_TARE_WT",
           "SHEET_SKID". "SKID_PIECES",
           "SHEET_SKID"."SKID_SHEET_STATUS",
           NULL "DONE"
      FROM customer_order
           join order_item on order_item.order_abc_num = customer_order.order_abc_num
           join ab_job on order_item.order_abc_num = ab_job.order_abc_num and ab_job.order_item_num = order_item.order_item_num
           join sheet_skid on sheet_skid.ab_job_num = ab_job.ab_job_num
           join sheet_packing_item on sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
           join shipment on shipment.packing_list = sheet_packing_item.packing_list
     where ("SHIPMENT"."PACKING_LIST" = v_packing_list);
  --         and ("SHIPMENT"."SHIPMENT_EDI856_DATE" is NULL)

  /*
  cursor c5_cursor is
      select distinct nvl(customer_order.tier1_customer_id, -99)
      from   customer_order
             join order_item on order_item.order_abc_num = customer_order.order_abc_num
             join ab_job on order_item.order_abc_num = ab_job.order_abc_num and ab_job.order_item_num = order_item.order_item_num
             join sheet_skid on sheet_skid.ab_job_num = ab_job.ab_job_num
             join sheet_packing_item on sheet_packing_item.sheet_skid_num = sheet_skid.sheet_skid_num
             join shipment on shipment.packing_list = sheet_packing_item.packing_list
      where  shipment.packing_list = v_packing_list;
   */
  --

BEGIN

  SELECT customer_id, des_sh_cust_id, shipment_enduser_id
    INTO v_customer_id, v_des_sh_cust_id, v_enduser_id
    FROM shipment
   WHERE shipment.packing_list = v_packing_list;
  IF NOT SQL%FOUND THEN
    --         RAISE exce_nodata;
    RETURN - 1;
  END IF;

  /* Alex Gerlants. 02/09/2017. Begin */
  --Roy said that they would not ship orders with diferent tier1_customers
  --on the same packing_list.
  --To be on the safe side however, I am looping through all distinct order_abc_num's
  --and if at least one of them > 0, then we create DESADV.
  /*
  if not c5_cursor%ISOPEN then
    open c5_cursor;
  end if;

  loop
    fetch c5_cursor
      into ll_tier1_customer_id;
      
    exit when ll_tier1_customer_id > 0; --Valid tier1_customer_id found
    exit when c5_cursor%NOTFOUND;
  end loop;
  
  if c5_cursor%ISOPEN then
    close c5_cursor;
  end if;

  if ll_tier1_customer_id <= 0 then --Nothing to do
    return 200;
  end if;
  */
  /* Alex Gerlants. 02/09/2017. End */

  IF NOT c1_cursor%ISOPEN THEN
    OPEN c1_cursor;
  END IF;
  FETCH c1_cursor
    INTO v_edi_st_seq;
  CLOSE c1_cursor;

  SELECT edi_gs_log_seq.nextval INTO v_gs_log FROM dual;

  -- If the customer is not in the table or he has no communication_code then this will return nothing
  -- and thus throw an ORA-01403 Error.
  SELECT communication_code
    INTO v_communication_code
    FROM customer_system
   WHERE customer_id = v_des_sh_cust_id;

  --Commented Alex Gerlants. 02/09/2017
  --IF (v_customer_id = 2505) THEN
  --  v_address := 'MZ7';
  --   v_DUNS := 'XYY:ZZ';
  --  v_communication_code := '51972';
  --  v_bgm := '';
  -- v_skip := 1;
  --  DUNS := '039630926::16';  -- Change default DUNS from NOVELIS to ALBL;
  --ELSE
    --v_address := 'ALV';
    v_address := 'MZ7';
    v_bgm := '351';
  --END IF;

  tab_tag(j) := 'UNA:+.? ''';
  j := j + 1;

  
  --Alex Gerlants. 06/06/2017. Commented out
  /*
  tab_tag(j) := 'UNB+UNOA:2+' || v_DUNS || ':01+' || v_address || ':ZZ+' ||
                to_char(SYSDATE, 'YYMMDD:HH24MI') || '+' ||
                to_char(v_gs_log) || '++GMDESADV''';
  */
  
  v_DUNS := 'XYY'; --Alex Gerlants. 06/06/2017. As per Lisa Dingman
                
  tab_tag(j) := 'UNB+UNOA:2+' || v_DUNS || ':ZZ+' || v_address || ':ZZ+' ||
                to_char(SYSDATE, 'YYMMDD:HH24MI') || '+' ||
                to_char(v_gs_log) || '++GMDESADV''';
                                
  j := j + 1;

  tab_tag(j) := 'UNH+' || to_char(v_edi_st_seq) || '+DESADV:D:97A:UN''';
  j := j + 1;
  tab_tag(j) := 'BGM+' || v_bgm || '+' || to_char(v_packing_list) || '+9''';
  j := j + 1;
  tab_tag(j) := 'DTM+137:' || to_char(SYSDATE, 'YYYYMMDDHH24MI') ||
                ':203''';
  j := j + 1;

  SELECT nvl(shipment_actualed_date_time, SYSDATE)
    INTO v_shipdate
    FROM shipment
   WHERE packing_list = v_packing_list;
  tab_tag(j) := 'DTM+11:' || to_char(v_shipdate, 'YYYYMMDDHH24MI') ||
                ':203''';
  j := j + 1;

  SELECT MAX(sh_packing_item)
    INTO v_skids_count
    FROM sheet_packing_item
   WHERE sheet_packing_item.packing_list = v_packing_list;

  FOR c2_record IN c2_cursor LOOP
    v_piece_count  := v_piece_count + c2_record.skid_pieces;
    v_gross_weight := v_gross_weight + c2_record.sheet_net_wt * 0.45359 +
                      c2_record.sheet_tare_wt * 0.45359;
    v_net_weight   := v_net_weight + c2_record.sheet_net_wt * 0.45359;
    --      v_tare_weight := v_tare_weight + c2_record.SHEET_TARE_WT;
  --    Put more item here
  END LOOP;

  --    v_skids_count := c2_cursor%ROWCOUNT;

  tab_tag(j) := 'MEA+AAX+SQ+C62:' || to_char(v_skids_count) || '''';
  j := j + 1;
  tab_tag(j) := 'MEA+AAX+G+KG:' || to_char(v_gross_weight) || '''';
  j := j + 1;
  tab_tag(j) := 'MEA+AAX+N+KG:' || to_char(v_net_weight) || '''';
  j := j + 1;
  tab_tag(j) := 'RFF+MB:' || to_char(v_packing_list) || '''';
  j := j + 1;

  tab_tag(j) := 'NAD+MI+88120::92''';

  j := j + 1;

  tab_tag(j) := 'NAD+SU+' || DUNS || ''''; --Supplier is Novelis Kingston Feb8-06 by tony
  --001504935
  j := j + 1;

  tab_tag(j) := 'NAD+ST+' || v_communication_code || '::92''';
  j := j + 1;

  /* LOC segment, need location code from Alcan or GM */

  tab_tag(j) := 'LOC+11+A1A2''';
  j := j + 1;

  SELECT nvl(carrier.scac, 'AAAA')
    INTO v_scac
    FROM carrier
   WHERE carrier_id =
         (SELECT carrier_id
            FROM shipment
           WHERE shipment.packing_list = v_packing_list);

  tab_tag(j) := 'TDT+25++M++' || v_scac || '::182''';
  j := j + 1;

  SELECT nvl(shipment.carrier_description_code, 'TL')
    INTO v_carrier_description
    FROM shipment
   WHERE shipment.packing_list = v_packing_list;
  IF v_carrier_description = 'TL' THEN
    v_carrier_description := 'TE';
  END IF;

  SELECT nvl(shipment.vehicle_id_prefix, 'AA'),
         nvl(shipment.vehicle_id, '1111')
    INTO v_vehicle_prefix, v_vehicle_id
    FROM shipment
   WHERE shipment.packing_list = v_packing_list;

  tab_tag(j) := 'EQD+' || v_carrier_description || '+' || v_vehicle_prefix ||
                v_vehicle_id || '''';
  j := j + 1;

  /* DETAIL LOOP BEGIN */
  --   cps_hl := 1;
  FOR c2_record IN c2_cursor LOOP

    SELECT "ORDER_ITEM"."ENDUSER_PART_NUM"
      INTO v_enduser_part
      FROM "ORDER_ITEM", "SHEET_SKID"
     WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" = "ORDER_ITEM"."ORDER_ABC_NUM")
       AND ("SHEET_SKID"."REF_ORDER_ABC_ITEM" =
           "ORDER_ITEM"."ORDER_ITEM_NUM")
       AND ("SHEET_SKID"."SHEET_SKID_NUM" = c2_record.sheet_skid_num);

    SELECT "CUSTOMER_ORDER"."ENDUSER_PO"
      INTO v_enduser_po
      FROM "SHEET_SKID", "CUSTOMER_ORDER"
     WHERE ("SHEET_SKID"."REF_ORDER_ABC_NUM" =
           "CUSTOMER_ORDER"."ORDER_ABC_NUM")
       AND (sheet_skid.sheet_skid_num = c2_record.sheet_skid_num);

    tab_tag(j) := 'CPS+' || to_char(cps_hl) || '++1''';
    j := j + 1;
--    tab_tag(j) := 'PAC+' || to_char(c2_record.skid_pieces) || '''';
      if (v_des_sh_cust_id IN (2611, 2814)) THEN
         tab_tag(j) := 'PAC+' || to_char(c2_record.skid_pieces) || '++AHB52679'''; -- Added by Patrick Reynolds 07-21-2016
      else
         tab_tag(j) := 'PAC+' || to_char(c2_record.skid_pieces) || ''''; -- Added by Patrick Reynolds 07-21-2016
      END IF;

    j := j + 1;
    /*    tab_tag(j) := 'QTY+52:'||TO_CHAR(c2_record.SKID_PIECES)||'''';
    j := j + 1;   */
    tab_tag(j) := 'PCI+16''';
    j := j + 1;
    /*    tab_tag(j) := 'RFF+CW:'||TO_CHAR(c2_record.SH_PACKING_ITEM)||'''';
      j := j + 1;
    tab_tag(j) := 'GIR+3+'||TO_CHAR(c2_record.SHEET_SKID_NUM)||':AW''';
      j := j + 1;  */

    v_skid_num := c2_record.sheet_skid_display_num;
 
    tab_tag(j) := 'LIN+++' || v_enduser_part || ':IN''';
    j := j + 1;

    -- changed to PIA+1+5:RY per Jeff Blaha 1/29/2015 email
    --  tab_tag(j) := 'PIA+1+0:RY''';
    tab_tag(j) := 'PIA+1+6:RY''';
    j := j + 1;

    SELECT SUM(sheet_skid.skid_pieces)
      INTO v_cumulated_pcs
      FROM sheet_skid, order_item
     WHERE sheet_skid.ref_order_abc_num = order_item.order_abc_num
       AND sheet_skid.ref_order_abc_item = order_item.order_item_num
       AND order_item.enduser_part_num = c2_record.enduser_part_num;

    tab_tag(j) := 'QTY+3:' || to_char(v_cumulated_pcs) || ':EA''';
    j := j + 1;
    tab_tag(j) := 'QTY+12:' || to_char(c2_record.skid_pieces) || ':EA''';
    j := j + 1;
    tab_tag(j) := 'RFF+ON:' || v_enduser_po || '''';
    j := j + 1;

  IF (v_skip = 0) THEN
      tab_tag(j) := 'PCI+15+' || to_char(c2_record.sheet_skid_display_num) || '''';
      j := j + 1;
      tab_tag(j) := 'QTY+12:' || to_char(c2_record.skid_pieces) || ':EA''';
      j := j + 1;
  END IF;

    cps_hl := cps_hl + 1;
  END LOOP;

  /* OUTPUT TO file*/
  IF NOT c4_cursor%ISOPEN THEN
    OPEN c4_cursor;
    FETCH c4_cursor
      INTO v_holder;
    CLOSE c4_cursor;
  END IF;
  v_file_id := to_char(v_holder);

--Alex Gerlants. 11/15/2016. Commented out statement below, and added statement after.
  --out_file := utl_file.fopen('/templar/templar/incoming/senddata',
  --                           edi_file_prefix || v_file_id || '.edi',  -- Change before moving to PROD
  --                           'w',
  --                           32767);

  out_file := utl_file.fopen(edi_loc,
                             edi_file_prefix || v_file_id || '.edi',  -- Change before moving to PROD
                             'w',
                             32767);

  ls_edi_file_name := edi_file_prefix || v_file_id || '.edi'; /* Alex Gerlants. 09/02/2016 */

  --   out_file :=  UTL_FILE.FOPEN('/tmp','S_alcan_gm_gm'||v_file_id||'.desadv','w');
  tab_tag(j) := 'UNT+' || to_char(j - 2) || '+' || to_char(v_edi_st_seq) || '''';
  j := j + 1;

  --   tab_tag(j) := 'UNE+1+'||to_char(v_gs_log)||'''';
  --       j := j + 1;
  tab_tag(j) := 'UNZ+1+' || to_char(v_gs_log) || '''';

  FOR i IN 2 .. j LOOP
    v_outstring := tab_tag(i);
    utl_file.put(out_file, v_outstring);
    --         UTL_FILE.FFLUSH(out_file);
  END LOOP;
  utl_file.fflush(out_file);
  utl_file.fclose(out_file);

/*  This has been replaced by the UPDATE statement below.
    These columns are already updated in another function, edi_alcan_alcan_856_x12, so to update them here
    could be misleading as well as wiping out information from the aforementioned function hence the need for
    the shipment_desadv_date column in the shipment table.
  UPDATE shipment
     SET shipment_des_edi856_date = SYSDATE,
         shipment_edi856_date = SYSDATE
   WHERE shipment.packing_list = v_packing_list;
  COMMIT;
*/

--  Uncomment before moving to PROD
  --Alex Gerlants. 09/02/2016. Added ", edi_file_id_desadv = edi_file_id".
  --Alex Gerlants. 03/17/2017. Added shipment_des_edi856_date = SYSDATE
  UPDATE shipment
     SET shipment_desadv_date = SYSDATE,
         edi_file_id_desadv = v_file_id,
         shipment_des_edi856_date = SYSDATE
   WHERE shipment.packing_list = v_packing_list;

   ----------------------------------------------------------------
   --Alex Gerlants. 09/02/2016. Begin

   select nvl(customer_duns_number_string, '00000000')
   into   ls_su
   from   customer
   where  customer_id = v_customer_id;

   If (ls_su = '00000000') Then
    Return 200;
   End If;

   INSERT INTO outbound_edi_transaction
    (edi_file_id,
     duns_from,
     duns_to,
     interchange_control_number,
     group_control_number,
     transaction_time,
     edi_file_name,
     fa_receive_status,
     customer_id,
     set_control_num,
     transaction_type_id)
  VALUES
    (v_file_id,
     '039630926',
     ls_su,
     v_gs_log,
     v_gs_log,
     SYSDATE,
     ls_edi_file_name,
     0,
     v_customer_id,
     v_edi_st_seq,
     'desadv');


   --Alex Gerlants. 09/02/2016. End
   ----------------------------------------------------------------

  COMMIT;


  RETURN 1;

EXCEPTION
  WHEN exce_sent THEN
    --    raise_application_error(-20101,'STOP! EDI had been sent');
    --    UTL_FILE.FCLOSE(out_file);
    RETURN 100;
  WHEN exce_nodata THEN
    --     raise_application_error(-20101,'No shipment data found!');
    RETURN - 1;
  WHEN exce_des_sh_cust_id THEN
    --    raise_application_error(-20101,'This shipment does not required EDIFACT DESADV EDI!');
    RETURN 200;
  WHEN OTHERS THEN
    --    raise_application_error(-20101,'INTERNAL ERROR! PLEASE CALL 1519.');
   --  raise_application_error(-20101,'An error was encountered - ' || SQLCODE || ' -ERROR- ' || SQLERRM);
    utl_file.fclose(out_file);
    RETURN - 2;
END;
  GRANT EXECUTE ON "DBO"."F_EDI_DESADV_BOLT_ALEX" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function F_EDI_MISA_870_4JOB
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_MISA_870_4JOB" 
 ( 
    al_ab_job_num           ab_job.ab_job_num%type,
    as_user_id              ab_job_870_history.user_id%type,
    as_original_or_resend   varchar2
    
 )
  return integer
  
is

  /*
  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc                varchar2(50) := get_edi_destination('EDI_DIR');
  edi_file                     varchar2(50) := 'edi_out.txt';
  edi_file_prefix              varchar2(50) := 'S_misa_870_'; --production
  --edi_file_prefix              varchar2(50) := 's_misa_870_'; --development
  edi_file_handle              utl_file.file_type;
  su_duns                      varchar2(10);
  ll_customer_id               customer.customer_id%type;
  ll_cur_coil                  coil.coil_abc_num%type;
  ll_gs_log                    integer;
  ll_st_log                    integer;
  ls_today                     varchar2(20) := to_char(sysdate, 'YYYYMMDD');
  ls_today_4                   varchar2(20) := to_char(sysdate, 'YYMMDD');
  ls_now                       varchar2(20) := to_char(sysdate, 'HH24MI');
  ls_po                        varchar2(20);
  ls_finished_goods            varchar2(32);
  ls_cust_prod_line            varchar2(8);
  ld_scrap_870_date            process_coil.scrap_870_date%type;
  ls_coil_org_num              coil.coil_org_num%type;
  ls_heat                      coil.lot_num%type;
  ll_prime_nw                  coil.net_wt%type;
  ll_scrap_nw                  coil.net_wt%type;
  ll_item_count                integer;
  li_hl01                      integer;
  li_hllin                     integer;
  ll_rowcount                  number(8);
  ll_edi_file_id_870           integer;
  ld_edi_date_870              ab_job.edi_date_870%type;
  --ls_sheet_skid_exists         char(1);
  ls_consumed_coil_num         coil.consumed_coil_num%type;
  ls_customer_short_name       customer.customer_short_name%type;
  ll_sheet_skid_count_4coil    number(8);
  ll_total_act_scrap_wt_4job   number(8);
  ll_total_theo_scrap_wt_4job  number(8);
  ll_heavy_light               number(8);
  li_rtn                       number(4); --Alex Gerlants. Changed from number(1) to number(4)
  ll_psi_870_count             number(3); --Alex Gerlants. 01/08/2021
  ll_coil_870_count            number(3); --Alex Gerlants. 01/08/2021
  ll_process_coil_870_count    number(3); --Alex Gerlants. 01/08/2021
  ld_order_date                ab_job.create_date%type;
  ls_order_date                varchar2(20);
  ls_order_time                varchar2(20);
  ls_customer_po_date          coil.customer_po_date%type;
  ls_enduser_po                customer_order.enduser_po%type;

  ln_coil_intial_net_wt        coil.net_wt%type;
  ln_coil_current_net_wt       coil.net_wt_balance%type; 
  ln_coil_width                coil.coil_width%type; 
  ln_coil_gauge                coil.coil_gauge%type;
  ln_coil_initial_length       coil.lfeed%type;
  ln_coil_current_length       coil.lfeed%type default 0;
  ll_part_width                number(10,4);
  ll_part_length               number(10,4);
  ls_ps_coil_number            inbound_coil.ps_coil_number%type;
  ln_finished_goods_material_num   order_item.finished_goods_material_num%type;
  ls_suffix_numberic           varchar2(10); -- partial_skid.suffix_numeric%type;   
  li_split_skid_count          integer;
  li_sheet_skid_count          integer;
  ll_send_870B                 integer default 0;
  ls_prev_processor_coil_num   coil.prev_processor_coil_num%type;

--------------------------------------------------------------------------------------------------   
------------------------------------ Cursors Begin -----------------------------------------------
--------------------------------------------------------------------------------------------------

  cursor coil_cur is
  select distinct process_coil.coil_abc_num
  from   process_coil
         left outer join production_sheet_item on production_sheet_item.coil_abc_num = process_coil.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    (
              sheet_skid.skid_sheet_status in (0, 2, 4, 13, 12, 16)
           or sheet_skid.skid_sheet_status is null --This is for rejected coils without sheets  
         )
  order by process_coil.coil_abc_num;
  
  coil_rec  coil_cur%ROWTYPE;
   
  --Cursor skid_coil_cur will select data for ab_job and coil_abc_num with skids.
  --If there is a reject coil without sheet skids, this cursor will not select it.
  cursor skid_coil_cur is
  select max(coil.coil_abc_num) coil_abc_num,            
         max(coil.lot_num) lot_num,   
         max(coil.coil_org_num) coil_org_num,   
         max(coil.coil_mid_num) coil_mid_num,
         max(coil.coil_status) coil_status,
         max(nvl(coil.consumed_coil_num, ' ')) consumed_coil,
         max(nvl(coil.material_num, ' ')) material_num,
         max(coil.net_wt) net_wt,   
         max(coil.vo) vo,
         max(coil.prev_processor_coil_num) prev_processor_coil_num,
         max(coil.prev_processor_id) prev_processor_id,
         max(production_sheet_item.prod_item_pieces) prod_item_pieces,
         max(production_sheet_item.prod_item_num) prod_item_num,
         max(sheet_skid.skid_sheet_status) skid_sheet_status,
         max(production_sheet_item.prod_item_note) prod_item_note,   
         max(sheet_skid.sheet_theoretical_wt) sheet_theoretical_wt,   
         max(production_sheet_item.prod_item_placement) prod_item_placement,   
         max(process_coil.process_quantity) process_quantity,   
         max(nvl(customer_order.sales_order, ' ')) sales_order,
         max(coalesce( trim(customer_order.orig_customer_po), trim(customer_order.enduser_po),'NA')) orig_customer_po,
         max(nvl(order_item.enduser_part_num, ' ')) enduser_part_num,
         max(nvl(order_item.cust_prod_line_id, 'NA')) cust_prod_line_id,
         max(sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
         max(order_item.order_item_num) order_item_num, 
         max(sheet_skid.sheet_tare_wt) sheet_tare_wt,   
         max(sheet_skid.sheet_net_wt) sheet_net_wt,
         max(sheet_skid.skid_pieces) skid_pieces,
         max(production_sheet_item.prod_item_net_wt) prod_item_net_wt,   
         max(sheet_skid.sheet_skid_num) sheet_skid_num,   
         max(sheet_skid.sheet_skid_display_num) sheet_skid_display_num,
         max(nvl(order_item.finished_goods_material_num, 'NA')) finished_goods_material_num,
         max(order_item.pieces_skid) pieces_skid,
         max(coalesce(order_item.trimmed_coil_width,order_item.incoming_coil_width,coil.coil_width)) width,
         max(order_item.quantity) ordered_qty,
         
         NULL done           
  from   coil   
         join process_coil on coil.coil_abc_num = process_coil.coil_abc_num
         join ab_job on ab_job.ab_job_num = process_coil.ab_job_num
         join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
         join customer_order on customer_order.order_abc_num = order_item.order_abc_num
         left outer join production_sheet_item on coil.coil_abc_num = production_sheet_item.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
         left outer join inbound_coil on coil.coil_org_num=inbound_coil.coil_number
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  ab_job.ab_job_num = al_ab_job_num
  and    coil.coil_abc_num = ll_cur_coil
  group by sheet_skid.sheet_skid_display_num
  order by
         max(production_sheet_item.coil_abc_num),
         max(order_item.order_item_num),
         max(sheet_skid.sheet_skid_display_num);

  skid_coil_rec  skid_coil_cur%rowtype;

  
  cursor scrap_cur is
  select process_coil.coil_abc_num,
         process_coil.process_coil_status,
         process_coil.process_quantity,
         nvl(process_coil.process_end_wt, 0),
         sum(nvl(process_coil.process_end_wt, 0)),
         sum(nvl(production_sheet_item.prod_item_net_wt, 0)),
         case process_coil.process_coil_status
            when 7 then --Rebanded coils
               --(process_coil.process_quantity - sum(production_sheet_item.prod_item_net_wt) - (select process_end_wt from process_coil pc where pc.ab_job_num = 101143 and pc.coil_abc_num = process_coil.coil_abc_num))
               --(process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - nvl(process_coil.process_end_wt, 0)) --Alex Gerlants. Commented out on 12/15/2020
               (process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - nvl(f_get_coil_rebanded_wt(process_coil.coil_abc_num, process_coil.process_quantity), -99)) --Alex Gerlants. Added on 12/15/2020
            when 3 then --Rejected coils
               case (select count(*) from production_sheet_item psi where psi.ab_job_num = al_ab_job_num and psi.coil_abc_num = process_coil.coil_abc_num)
                 when 0 then --Rejected coils without sheets
                   (process_coil.process_quantity - sum(nvl(process_coil.process_end_wt, 0)))
                 else --Rejected coils with sheets
                   (process_coil.process_quantity - nvl(process_coil.process_end_wt, 0) - sum(nvl(production_sheet_item.prod_item_net_wt, 0)))     
                end   
             else
               (process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - sum(nvl(process_coil.process_end_wt, 0)))
         end scrap_net_wt
  from   process_coil
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         join ab_job on ab_job.ab_job_num = process_coil.ab_job_num and coil.coil_abc_num = process_coil.coil_abc_num
         left outer join production_sheet_item on production_sheet_item.ab_job_num = process_coil.ab_job_num and production_sheet_item.coil_abc_num = process_coil.coil_abc_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    coil.coil_abc_num = ll_cur_coil
  group by
         process_coil.coil_abc_num,
         process_coil.process_coil_status,
         process_coil.process_quantity,
         process_coil.process_end_wt
  order by
         process_coil.coil_abc_num;
         
  scrap_rec  scrap_cur%rowtype;
   
--------------------------------------------------------------------------------------------------   
------------------------------------- Cursors End ------------------------------------------------
--------------------------------------------------------------------------------------------------   

  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;

  TYPE coil_num_type IS TABLE OF coil.coil_abc_num%type INDEX BY BINARY_INTEGER;
  coil_num coil_num_type;
  p binary_integer :=0;
  
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;  

BEGIN
  
  --Check if correct customer
  select  customer_order.orig_customer_id,
          customer.customer_duns_number_string,
          customer.customer_short_name,
          customer_order.created_date -- ab_job.create_date          
  into    ll_customer_id,
          su_duns,
          ls_customer_short_name,
          ld_order_date
  from    ab_job
          join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
          join customer on customer.customer_id = customer_order.orig_customer_id
  where   ab_job.ab_job_num = al_ab_job_num;


  ls_order_date := to_char(ld_order_date, 'YYYYMMDD');
  ls_order_time := to_char(ld_order_date, 'HH24MI');
  
  if lower(ls_customer_short_name) not like '%misa%' then
    null;
    --return 200; --Wrong customer
  end if;
  
  --Check if 870 has already been created for al_ab_job_num
  select edi_file_id_870, edi_date_870
  into   ll_edi_file_id_870, ld_edi_date_870
  from   ab_job
  where  ab_job_num = al_ab_job_num;
  
  --Alex Gerlants. 01/08/2021
  --Added this check to avoid sending 870 for jobs that had 870 created by the old batch processing.
  --Check if 870 has already been created for al_ab_job_num using the old data fields
  select count(distinct prod_item_edi870_date)
  into   ll_psi_870_count
  from   production_sheet_item
  where  ab_job_num = al_ab_job_num
  and    prod_item_edi870_date is not null;
  
  --Alex Gerlants. 02/19/2021. Comment out Begin
  --In case of more than 1 job for the same coil, this script updates process_coil and coil
  --for the first job.
  --When the second job for this coil, tries to run this script to create 870, 
  --it returns 100 - 870 already created
  --Checking table production_sheet_item is sufficient to prevent 870 creation for jobs that had 870 
  --created by the old batch processing.

  /* 
  select count(distinct scrap_870_date)
  into   ll_process_coil_870_count
  from   process_coil
  where  ab_job_num = al_ab_job_num
  and    scrap_870_date is not null;
  
  select count(distinct scrap_870_date)
  into   ll_coil_870_count
  from   coil
  where  coil_abc_num in
  (
      select   distinct coil_abc_num
      from     process_coil
      where    ab_job_num = al_ab_job_num
  )
  and    scrap_870_date is not null;
  */
  --Alex Gerlants. 02/19/2021. Comment out End
  
  --Alex Gerlants. 01/08/2021. Added " or ll_psi_870_count > 0 or ll_process_coil_870_count > 0 or ll_coil_870_count > 0"
  --Alex Gerlants. 02/19/2021. Removed "or ll_process_coil_870_count > 0 or ll_coil_870_count > 0"
  --Please see explanation above.
  if (not (ll_edi_file_id_870 is null and ld_edi_date_870 is null)) or ll_psi_870_count > 0 then --870 already created for al_ab_job_num
    return 100;
  end if;

  i              := 0;
  k              := 0;
  p              := 0;
  
  select count(distinct process_coil.coil_abc_num)
  into   ll_rowcount
  from   process_coil
         left outer join production_sheet_item on production_sheet_item.coil_abc_num = process_coil.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    (
              sheet_skid.skid_sheet_status in (0, 2, 4, 13, 12, 16)
           or sheet_skid.skid_sheet_status is null --This is for rejected coils without sheets  
         );
    
  if ll_rowcount > 0 then

    select edi_st_log_seq.nextval into ll_st_log from dual;
    select edi_gs_log_seq.nextval into ll_gs_log from dual;
    
    /*
    select  customer_order.orig_customer_id
    into    ll_customer_id
    from    ab_job
            join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
    where   ab_job.ab_job_num = al_ab_job_num;
    
    select  customer.customer_duns_number_string
    into    su_duns
    from    customer
    where   customer.customer_id = ll_customer_id;
    */

    --Production
    --x12_table(i) := 'ISA*00*' ||
    --                '          *00*          *01*039630926T     *14*0015049350011G *' ||
    --                ls_today_4 || '*' || ls_now || '*U*00401*' ||
    --                lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
          
    --Development                

    x12_table(i) := 'ISA*00*' ||
                '          *00*          *01*2NDSFTP        *14*0015049350011G *' ||
                ls_today_4 || '*' || ls_now || '*U*00401*' ||
                lpad(to_char(ll_gs_log), 9, '0') || '*0*T*|';
    i := i + 1;

    --Production
    --x12_table(i) := 'GS*RS*039630926T*' || '001504935001' || '*' ||
    --                ls_today || '*' || ls_now || '*' ||
    --                to_char(ll_gs_log) || '*X*' || '004010';
          
    --Development                
    -- BRB need to change send to misa, once I have it , this is novellis
    x12_table(i) := 'GS*RS*2NDSFTP*' || '0015049350011G' || '*' ||
                    ls_today || '*' || ls_now || '*' ||
                    to_char(ll_gs_log) || '*X*' || '004010';  -- GS02 should be RS from all 870?
    i := i + 1;
        
    x12_table(i) := 'ST*870*' || to_char(ll_st_log);
    i := i + 1;
    x12_table(i) := 'BSR*2*PA*' || trim(to_char(al_ab_job_num)) || '*' || ls_today ||
                    '***' || ls_now; -- || '*****'; -- BRB 6/19/2026 should be PA or PP?
    i := i + 1;
    x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now || '*ET' ;    --  ls_today_4  ld_order_date, should it do the orderdate?
    i := i + 1;
    --x12_table(i) := 'DTM*009*' || ls_order_date || '*' || ls_order_time || '*ET';  -- ls_today ld_order_date, should it do the orderdate?
    --i := i + 1;

    -- x12_table(i) := 'N1*SU**1*' || su_duns;
    --i := i + 1;
    x12_table(i) := 'N1*MF*' || su_duns; -- 043071377';
    i := i + 1;
    --x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926';
    --i := i + 1;
    x12_table(i) := 'N1*OU**1*039630926';
    i := i + 1;

    li_hl01 := 0;

       --ls_sheet_skid_exists := 'n';
       li_hl01 := li_hl01 + 1;

       x12_table(i) := 'HL*' || to_char(li_hl01) || '**O';
       i := i + 1;

       select max(coalesce( trim(customer_order.orig_customer_po), trim(customer_order.enduser_po),'NA')) orig_customer_po, max(coalesce(coil.customer_po_date,'')), -- if no customer_po_date, can be blank to_char(coil_entry_date,'YYYYMMDD')
          max(customer_order.enduser_po), max(nvl(order_item.cust_prod_line_id, 'NA')) cust_prod_line_id,
          max(nvl(order_item.finished_goods_material_num, 'NA')) finished_goods_material_num
       into ls_po, ls_customer_po_date, ls_enduser_po, ls_cust_prod_line, ln_finished_goods_material_num
       from   coil   
         join process_coil on coil.coil_abc_num = process_coil.coil_abc_num
         join ab_job on ab_job.ab_job_num = process_coil.ab_job_num
         join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
         join customer_order on customer_order.order_abc_num = order_item.order_abc_num
         --left outer join inbound_coil on coil.coil_org_num=inbound_coil.coil_number
  where  ab_job.ab_job_num = al_ab_job_num;
  --and    coil.coil_abc_num = ll_cur_coil;

       --IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
       if trim(ls_customer_po_date) is not null then
          x12_table(i) := 'PRF*' ||  ls_po || '****' || ls_customer_po_date;
          i := i + 1;
       else
          x12_table(i) := 'PRF*' ||  ls_po; 
          i := i + 1;
       end if;
       --END IF;

    for coil_rec in coil_cur loop --Coil loop
       ll_cur_coil := coil_rec.coil_abc_num;
       --ls_sheet_skid_exists := 'n';
       
       select   consumed_coil_num, coil.net_wt, coil.net_wt_balance, coil.coil_width, coil.coil_gauge, coil.lfeed, coil.prev_processor_coil_num
       into     ls_consumed_coil_num, ln_coil_intial_net_wt, ln_coil_current_net_wt, ln_coil_width, ln_coil_gauge, ln_coil_initial_length, ls_prev_processor_coil_num
       from     coil
       where    coil_abc_num = ll_cur_coil;

       
       select   count(*)
       into     ll_sheet_skid_count_4coil
       from     production_sheet_item
       where    ab_job_num = al_ab_job_num
       and      coil_abc_num = ll_cur_coil;
       
       coil_num(p) := ll_cur_coil;
       p := p + 1;

       select   coil.coil_org_num, coil.lot_num
       into     ls_coil_org_num, ls_heat
       from     coil
       where    coil.coil_abc_num = ll_cur_coil;
       li_hl01 := li_hl01 + 1;

       begin
         select inbound_coil.ps_coil_number
           into ls_ps_coil_number
         from inbound_coil
         where inbound_coil.coil_number = ls_coil_org_num ;
       exception
         when others then
           ls_ps_coil_number:='NA';
       end;

       x12_table(i) := 'HL*' || to_char(li_hl01) || '**I';
       i := i + 1;
      
       --IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
       if trim(ls_customer_po_date) is not null then
          x12_table(i) := 'PRF*' ||  ls_po || '****' || ls_customer_po_date;
          i := i + 1;
       else
          x12_table(i) := 'PRF*' ||  ls_po ;
          i := i + 1;
       end if;
       --END IF;
              --if nvl(ln_coil_initial_length,0)>0 and nvl(ln_coil_initial_weight,0)>0 then
              --   ll_coil_length := round(ln_coil_net_wt_balance/ln_coil_initial_weight * ln_coil_initial_length,4);
              --else
              --   ll_coil_length :=0;
              --end if;


              x12_table(i) := 'MEA*WT*WT*' || to_char(ln_coil_intial_net_wt) || '*01';  --  .prod_item_net_wt                              
              i := i + 1;
              x12_table(i) := 'MEA*WT*WT*' || to_char(f_convert_metric(ln_coil_intial_net_wt,'lb','kg')) || '*50';  --  .prod_item_net_wt                              
              i := i + 1;

              x12_table(i) := 'MEA*PD*WD*' || trim(to_char(ln_coil_width,'99990.9999')) || '*E8';
              i := i + 1;

              x12_table(i) := 'MEA*PD*WD*' || trim(to_char(f_convert_metric(ln_coil_width,'in','mm'),'99990.9999')) || '*E8';
              i := i + 1;

              --x12_table(i) := 'MEA*PD*TH*' || trim(to_char(ln_coil_gauage,'99990.9999')) || '*E8';
              --i := i + 1;

              --x12_table(i) := 'MEA*PD*TH*' || trim(to_char(f_convert_metric(ln_coil_gauage,'in','mm'),'99990.9999')) || '*MM';
              --i := i + 1;

              x12_table(i) := 'MEA*CT*NL*1*PC'; -- 1 coil, 1 pices
              i := i + 1;

              --if ln_coil_length>0 then
                 x12_table(i) := 'MEA*PD*LN*' || trim(to_char(round(ln_coil_initial_length,0),'999990')) || '*LF' ; -- length, part length?
                 i := i + 1;

                 x12_table(i) := 'MEA*PD*LN*' || trim(to_char(round(f_convert_metric(ln_coil_initial_length,'lf','mt'),0),'999990')) || '*MR' ; -- length, part length?
                 i := i + 1;

                 --x12_table(i) := 'MEA*CT**' || trim(to_char(ln_coil_initial_length,'99990.9999')) || '*LF' ; -- length, part length?
                 --i := i + 1;
             --end if;

             x12_table(i) := 'REF*RV*' || to_char(coil_rec.coil_abc_num) ;
             i := i + 1;

             x12_table(i) := 'REF*PM*' || to_char(nvl(ln_finished_goods_material_num,'NA') ) ;
             i := i + 1;

             x12_table(i) := 'REF*QP*' || to_char(coalesce(ls_consumed_coil_num,ls_prev_processor_coil_num,'NA')) ; -- ls_ps_coil_number
             i := i + 1;

       for skid_coil_rec in skid_coil_cur loop --Skid_coil loop
           if skid_coil_rec.prod_item_net_wt > 0 then
             
              --ls_sheet_skid_exists := 'y';
              li_hl01 := li_hl01 + 1;

              x12_table(i) := 'HL*' || to_char(li_hl01) || '**F';
              i := i + 1;
            
              ls_po := skid_coil_rec.orig_customer_po;
              ls_cust_prod_line := skid_coil_rec.cust_prod_line_id;
              ls_finished_goods := skid_coil_rec.finished_goods_material_num;

           -- BRB 6/22/2026 split skid start
           if skid_coil_rec.skid_sheet_status in ( 0, 2, 4, 7, 13, 16 ) then -- check status for partial skid 2: ready; 8: warehouse ready; 13: partial ready; 7: partial; 12: sample; 4: onhold

               -- BRB 5/5/2026 do not send 870B for partial 8,13 (But we do send the 870A)
                    -- BRB 6/1/2026, check to see if other jobs  have a 870 sent
                    --update production_sheet_item set prod_item_edi870_date=null where ab_job_num=:al_ab_job_num;
                   -- select count(*), sum(nvl(sheet_Skid.Skid_Pieces,0))
                   --    into ln_other_job_skid_count, ln_other_job_skid_sum
                   --    from sheet_skid                        
                   --      where sheet_skid_num=skid_coil_rec.sheet_skid_num and sheet_skid.ab_job_num<>al_ab_job_num;
                    
                  
                  if skid_coil_rec.prod_item_pieces >= skid_coil_rec.pieces_skid then --Full skid
                    ls_suffix_numberic := null;
                  else --Partial skid
                    select    count(*)
                    into      li_split_skid_count
                    from      split_skid
                    --where     ab_job_num = al_ab_job_num
                    where     sheet_skid_num = skid_coil_rec.sheet_skid_num;

                    if li_split_skid_count <= 0 then --No rows for job and skid
                        ls_suffix_numberic := '000';
                         --skid_coil_rec.sheet_skid_display_num := trim(skid_coil_rec.sheet_skid_num) || trim(ls_suffix_numberic);
                            
                        insert into split_skid 
                        ( ab_job_num, coil_abc_num, sheet_skid_num, sheet_skid_num_with_letter, coil_org_num, item_sheet_net_wt, item_skid_pieces, suffix_numeric )
                        values
                        (
                           al_ab_job_num,
                           ll_cur_coil,
                           skid_coil_rec.sheet_skid_num,
                           trim(skid_coil_rec.sheet_skid_num) || trim(ls_suffix_numberic),
                           ls_coil_org_num,
                           skid_coil_rec.prod_item_net_wt,
                           skid_coil_rec.prod_item_pieces,
                           ls_suffix_numberic
                        );
                            
                        commit;
                        ll_send_870B :=1;

                        -- BRB should we call f_EDI_CLIFFS_870_4PP_JOB to send?
                    else --There is/are rows for job and skid. Check if there is a row for skid and coi                         
                         
                      select    count(*)
                      into      li_sheet_skid_count
                      from      split_skid
                      where     ab_job_num = al_ab_job_num
                      and       sheet_skid_num = skid_coil_rec.sheet_skid_num  
                      and       coil_abc_num = ll_cur_coil;                          
                        
                      if li_sheet_skid_count <= 0 then --There is no row for for job, skid and coil
                        --Identify max(suffix) for 
                        select    max(suffix_numeric)
                        into      ls_suffix_numberic
                        from      split_skid
                        --where     ab_job_num = al_ab_job_num
                        where     sheet_skid_num = skid_coil_rec.sheet_skid_num;
                        
                        if ls_suffix_numberic is null then
                           ls_suffix_numberic:='000';
                        else
                           ls_suffix_numberic:= trim(to_char(to_number(trim(nvl(ls_suffix_numberic,'000')))+1,'000')); -- get next number                            
                        end if;
                        --skid_coil_rec.sheet_skid_display_num := trim(skid_coil_rec.sheet_skid_num) || trim(ls_suffix_numberic);
                            
                        insert into split_skid 
                        ( ab_job_num, coil_abc_num, sheet_skid_num, sheet_skid_num_with_letter, coil_org_num, item_sheet_net_wt, item_skid_pieces, suffix_numeric )
                        values
                        (
                           al_ab_job_num,
                           ll_cur_coil,
                           skid_coil_rec.sheet_skid_num,
                           trim(skid_coil_rec.sheet_skid_num) || trim(ls_suffix_numberic),
                           ls_coil_org_num,
                           skid_coil_rec.prod_item_net_wt,
                           skid_coil_rec.prod_item_pieces,
                           ls_suffix_numberic
                        );
                            
                        commit;
                        ll_send_870B :=1;
                      else--There is a row for for skid, and coil. Just take suffix from this row
                        select    suffix_numeric
                        into      ls_suffix_numberic
                        from      split_skid
                        where     ab_job_num = al_ab_job_num
                        and       coil_abc_num = ll_cur_coil
                        and       sheet_skid_num = skid_coil_rec.sheet_skid_num;
                      end if;
                    end if; 
                  end if;
           end if ; -- check status for partial skid
           -- BRB 6/22/2026 split skid end

              --IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
                -- x12_table(i) := 'PRF*' ||  ls_po || '****' || ls_cust_prod_line;
                -- i := i + 1;
              if trim(ls_customer_po_date) is not null then
                 x12_table(i) := 'PRF*' ||  ls_po || '****' || ls_customer_po_date;
                 i := i + 1;
              else
                 x12_table(i) := 'PRF*' ||  ls_po; 
                 i := i + 1;
              end if;
              --end if;

              x12_table(i) := 'REF*SE*' || to_char(skid_coil_rec.sheet_skid_num);
              i := i + 1;

              x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now || '*ET';    --  ls_today_4  ld_order_date, should it do the orderdate?
              i := i + 1;

              --x12_table(i) := 'DTM*009*' || ls_order_date || '*' || ls_order_time || '*ET';  -- ls_today ld_order_date, should it do the orderdate?
              --i := i + 1;

              x12_table(i) := 'DTM*206*' || ls_order_date || '*' || ls_order_time || '*ET';
              i := i + 1;

              --x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;    --  ls_today_4  ld_order_date, should it do the orderdate?
              --i := i + 1;




              --x12_table(i) := 'REF*MI*' || to_char(al_ab_job_num);
              --i := i + 1;

              --Alex Gerlants. 2193. Email from Lisa received on Wed 7/31/2024 4:52 PM
              --x12_table(i) := 'REF*RV*A' || to_char(skid_coil_rec.prod_item_num) || '*NA';
              --i := i + 1;

              --x12_table(i) := 'REF*IX*' || to_char(skid_coil_rec.consumed_coil);
              --i := i + 1;

             -- if trim(skid_coil_rec.vo) is not null then 
             --    x12_table(i) := 'PO1**1*UN***VO*' || skid_coil_rec.vo || '***SN*' ||
             --                   ls_coil_org_num || '***VP*' || skid_coil_rec.finished_goods_material_num;
             --    i := i + 1;
             -- else
                 x12_table(i) := 'PO1**1*UN***VO*' || skid_coil_rec.vo || '****SN*' ||
                                ls_coil_org_num || '*HN*' || skid_coil_rec.finished_goods_material_num;
                 i := i + 1;
              --end if;
              
              x12_table(i) := 'PID*S*MAC*ST*05***67';
              i := i + 1;

              if skid_coil_rec.skid_sheet_status = 2 then
                x12_table(i) := 'PID*S*MA*ST*S*' ||
                                to_char(skid_coil_rec.sheet_skid_display_num);
                i := i + 1;
              elsif skid_coil_rec.skid_sheet_status = 4 then
                x12_table(i) := 'PID*S*MA*ST*S*' ||
                                to_char(skid_coil_rec.sheet_skid_display_num);
                i := i + 1;
              elsif skid_coil_rec.skid_sheet_status = 13 then
                x12_table(i) := 'PID*S*MA*ST*S*' ||
                                to_char(skid_coil_rec.sheet_skid_display_num);
                i := i + 1;
              else
                x12_table(i) := 'PID*S*MA*ST*S*' ||
                                to_char(skid_coil_rec.sheet_skid_display_num);
                i := i + 1;
              end if;

              x12_table(i) := 'PID*S*PR*ST*19'; -- BRB not in spec but we hsould leave it in.
              i := i + 1;
              
              x12_table(i) := 'MEA*WT*WT*' || to_char(skid_coil_rec.sheet_net_wt) || '*01';  --  .prod_item_net_wt                              
              i := i + 1;
              x12_table(i) := 'MEA*WT*WT*' || to_char(f_convert_metric(skid_coil_rec.sheet_net_wt,'lb','kg')) || '*50';  --  .prod_item_net_wt                              
              i := i + 1;

             x12_table(i) := 'MEA*PD*TH*' || trim(to_char(0,'90.9999')) ||'*ED';
              i := i + 1;

             x12_table(i) := 'MEA*PD*TH*' || trim(to_char(0,'90.9999')) ||'*MM';
              i := i + 1;
                  
              select   f_get_part_width_per_job(al_ab_job_num)
              into     ll_part_width
              from     dual;
                  
              --x12_table(i) := 'MEA*PD*WD*' || to_char(ll_coil_width) ||'';
              x12_table(i) := 'MEA*PD*WD*' || trim(to_char(ll_part_width,'999990.9999')) ||'*ED';
              i := i + 1;

              x12_table(i) := 'MEA*PD*WD*' || trim(to_char(f_convert_metric(ll_part_width,'in','mm'),'999990.9999')) ||'*MM';
              i := i + 1;

              select   f_get_part_length_per_job(al_ab_job_num)
              into     ll_part_length
              from     dual;

              x12_table(i) := 'MEA*PD*LN*' || to_char(ll_part_length) ||'*ED';
              i := i + 1;

              x12_table(i) := 'MEA*PD*LN*' || to_char(f_convert_metric(ll_part_length,'in','mm')) ||'*MM';
              i := i + 1;

              --x12_table(i) := 'MEA*WT*G*' || to_char(skid_coil_rec.skid_gross_wt) || '*LB*01';                              
              --i := i + 1;
              x12_table(i) := 'MEA*CT*NL*' || to_char(skid_coil_rec.prod_item_pieces) ||                   '*PC';
              i := i + 1;



              item_num(k) := skid_coil_rec.prod_item_num;
              k := k + 1;
           end if; --if skid_coil_rec.prod_item_net_wt > 0
        end loop; --for skid_coil_rec IN skid_coil_cur loop

        for scrap_rec in scrap_cur loop --Scrap loop
          ll_scrap_nw := scrap_rec.scrap_net_wt;

          if ll_scrap_nw > 0 then --Theo scrap weight
                   
             if ll_sheet_skid_count_4coil <= 0 then --ll_cur_coil is a fully scrapped (rejected) coil without good material
               li_rtn := f_edi_misa_870_reject_4job(al_ab_job_num, ll_cur_coil, as_user_id, as_original_or_resend);
                     
               continue; --06/19/2020. bypass for fully scrapped coil.
                         --It is in a separate 870 created in f_edi_misa_870_scrap_coil()
             end if;
                  
             ll_total_theo_scrap_wt_4job := 0;
                  
             select    nvl(sum(return_item_net_wt),0) 
             into      ll_total_act_scrap_wt_4job
             from      return_scrap_item
             where     ab_job_num = al_ab_job_num;

             li_hl01 := li_hl01 + 1;

             x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*F';
             i := i + 1;

             ls_po := skid_coil_rec.orig_customer_po;
             ls_cust_prod_line := skid_coil_rec.cust_prod_line_id;
             ls_finished_goods := skid_coil_rec.finished_goods_material_num;

             IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
                x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
                i := i + 1;
             END IF;

             x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now || '*ET';    --  ls_today_4  ld_order_date, should it do the orderdate?
             i := i + 1;

             --x12_table(i) := 'DTM*009*' || ls_order_date || '*' || ls_order_time || '*ET';  -- ls_today ld_order_date, should it do the orderdate?
             --i := i + 1;

             x12_table(i) := 'DTM*206*' || ls_order_date || '*' || ls_order_time || '*ET';
             i := i + 1;

              if trim(skid_coil_rec.vo) is not null then 
                 x12_table(i) := 'PO1**' || trim(to_char(skid_coil_rec.ordered_qty,'999990')) || '*UN***VO*' || skid_coil_rec.vo || '*VN*1*SN*' ||
                                ls_coil_org_num || '***VP*' || skid_coil_rec.finished_goods_material_num;
                 i := i + 1;
              else
                 x12_table(i) := 'PO1**1*UN*****VN*1*SN*' ||
                                ls_coil_org_num || '***VP*' || skid_coil_rec.finished_goods_material_num;
                 i := i + 1;
              end if;

             x12_table(i) := 'PID*S*MAC*ST*05';
             i := i + 1;

             x12_table(i) := 'PID*S*MA*ST*S';
             i := i + 1;

             x12_table(i) := 'PID*S*PR*ST*19';
             i := i + 1;

             x12_table(i) := 'PID*S*DAF*ST*S****70'; -- BRB not in spec but we hsould leave it in.
             i := i + 1;
             x12_table(i) := 'PID*S*DAC*ST*259***73'; -- BRB not in spec but we hsould leave it in.
             i := i + 1;

              x12_table(i) := 'MEA*WT*WT*' || to_char(ll_scrap_nw) || '*01';  --  .prod_item_net_wt                              
              i := i + 1;
              x12_table(i) := 'MEA*WT*WT*' || to_char(f_convert_metric(ll_scrap_nw,'lb','kg')) || '*50';  --  .prod_item_net_wt                              
              i := i + 1;
                   

              --select   f_get_part_width_per_job(al_ab_job_num), f_get_part_length_per_job(al_ab_job_num)
              --into     ll_part_width, ll_part_length
              --from     dual;
              --x12_table(i) := 'MEA*PD*WD*' || trim(to_char(ll_part_width,'999990.9999')) ||'*ED';
              --i := i + 1;

              --x12_table(i) := 'MEA*PD*WD*' || trim(to_char(f_convert_metric(ll_part_width,'in','mm'),'999990.9999')) ||'*MM';
              --i := i + 1;

              x12_table(i) := 'MEA*PD*TH*' || trim(to_char(0,'90.9999')) ||'*ED';
              i := i + 1;

              x12_table(i) := 'MEA*PD*TH*' || trim(to_char(f_convert_metric(0,'in','mm'),'90.9999')) ||'*MM';
              i := i + 1;

             ll_total_theo_scrap_wt_4job := ll_total_theo_scrap_wt_4job + ll_scrap_nw;
             
           else --Alex Gerlants. 12/11/2020
             if ll_scrap_nw < 0 then
                --This is in case when the user didn't zero out coil before he changed job status to Done, and saved it
                --In this case, ll_scrap_nw < 0
                return 300; --Alex Gerlants. 12/11/2020 
             end if;                   
           end if; --if ll_scrap_nw > 0 then
        end loop; --for scrap_rec in alcan_scrap_870_cur loop scrap loop
              
          ll_heavy_light := ll_total_act_scrap_wt_4job - ll_total_theo_scrap_wt_4job;
            
        --end if; --if (ld_scrap_870_date is null) then --Scrap not sent
    end loop; --for coil_rec in coil_cur loop. Coil loop
    
    x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
    i := i + 1;

    x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
    i := i + 1;

    x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
    i := i + 1;

    x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

    -- Write EDI to file

    if li_hl01 > 0 then
        -- WRITE EDI FILE ONLY IF ITEM > 0
        SELECT edi_file_id_seq.nextval
          INTO ll_edi_file_id_870
          FROM dual;
        edi_file        := edi_file_prefix || to_char(ll_edi_file_id_870) || '_Job-' || to_char(al_ab_job_num) || '.edi';
     -- edi_file        := 's_alcan_' || to_char(ll_edi_file_id_870) || '.870';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        FOR j IN 0 .. i LOOP
          utl_file.put_line(edi_file_handle, x12_table(j));

        END LOOP;
        utl_file.fclose(edi_file_handle);
      --END IF; -- END WRITING EDI FILE

      --edi_file        := 'send_edi_log'; /* Alex Gerlants. 04/14/2017. Commented out. */
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      --For verifying 997
      /*
      INSERT INTO outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
        VALUES
          (ll_edi_file_id_870,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           SYSDATE,
           edi_file,
           0,
           ll_customer_id,
           ll_st_log,
           '870');


       --update    ab_job
       --set       edi_file_id_870 = ll_edi_file_id_870,
       --          edi_date_870 = sysdate
       --where     ab_job_num = al_ab_job_num;
          
       insert into ab_job_870_history
        (
           ab_job_num,
           edi_file_id,
           edi_file_name,
           create_870_date_time,
           user_id,
           notes
        )
        values
        (
           al_ab_job_num ,
           ll_edi_file_id_870,
           edi_file,
           sysdate,
           as_user_id,
           as_original_or_resend
        );

        for m in 0 .. k - 1 loop
           update   production_sheet_item
           set      prod_item_edi870_date = sysdate,
                    edi_file_id_870 = ll_edi_file_id_870 
           where    production_sheet_item.prod_item_num = item_num(m);
        end loop;

        for m in 0..p - 1 loop
           update   coil
           set      coil.scrap_870_date = sysdate
           where    coil.coil_abc_num = coil_num(m);

           update   process_coil
           set      scrap_870_date = sysdate
           where    ( coil_abc_num = coil_num(m)) and (scrap_870_date is null);

         end loop;
         
         update    ab_job
         set       edi_file_id_870 = ll_edi_file_id_870,
                   edi_date_870 = sysdate
         where     ab_job_num = al_ab_job_num;

         commit;
         */
      END IF; -- END WRITING EDI FILE

  end if; --end if in select count(*)

  --END LOOP; ------ End of outer loop customer_id

/*
EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN -1;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN -2;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN -3;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN -4;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN -9;
*/
    
  return 1;
end f_edi_misa_870_4job;
--------------------------------------------------------
--  DDL for Function F_EDI_NOVELIS_861
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_NOVELIS_861" 
(
   al_customer_id in customer.customer_id%TYPE,
   as_bol         in inbound_shipment.bol%TYPE
)
   
return integer 
is

  FunctionResult              integer;
  
  /*
  This function creates Novelis EDI 861.
  edi_file_id and bol are from inbound_shipment table, received_time is generated the current moment by the system.
  This function will be called from Coil Receiving after a successful saving
  */

  type edi_861_tabletype is table of varchar2(32767) index by binary_integer;
  edi_861                     edi_861_tabletype;
  
  j                           binary_integer;
  i                           integer;
  
  edi_file_prefix             varchar2(50) := 'S_novelis_861_'; --Production
  --edi_file_prefix             varchar2(50) := 's_novelis_861_'; --Development
  
  li_coil_ready               integer;
  li_gs_log                   integer;
  li_st_log                   integer;
  ls_today_short              varchar2(20);
  ls_today                    varchar2(20);
  ls_now                      varchar2(20);
  ld_received_time            date;
  ls_received_time            varchar2(13);
  ls_received_time_yy         varchar2(13);
  li_customer_id              integer;
  ls_vo                       varchar2(20);
  ls_coil_number              varchar2(40);
  ls_ps_coil_number           varchar2(40);
  ls_temper                   varchar2(8);
  ln_net_weight               number(8, 0);
  ln_gross_weight             number(8, 0);
  ln_lineal_feed              number(7, 2);
  ln_coil_width               number(7, 2);
  ln_coil_gauge               number(5, 4);
  ln_density                  number;
  ls_lot                      varchar2(40);
  ls_pack_id                  varchar2(40);
  ls_alloy                    varchar2(40);
  ln_damage_fault             number(1);
  ln_damage_code              number(3);
  --edi_location                varchar2(50) := '/templar/templar/incoming/senddata';
  edi_location                VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR');
  edi_file                    varchar2(50) := 'edi_out.txt';
  edi_file_handle             utl_file.file_type;
  li_edi_861_id               integer;
  ls_dun                      varchar2(32);
  ls_ship_from                varchar2(40);
  coil_count                  integer;
  li_coil_abc_num             integer;
  li_count                    integer;
  ls_received_date            varchar2(8);
  li_inbound_shipment_status  inbound_shipment_status.status%TYPE;
  ll_edi_file_id              inbound_shipment_status.edi_file_id%TYPE;
  is_create_861_at_receiving  char(1);
  ls_po                       receiving_bol_coil.purchase_order_num%TYPE;
  ls_customer_short_name      customer.customer_short_name%TYPE;
  ll_pos                      integer;

  --Table data_861 is populated in function wf_populate_data_861 for w_coil_receiving in coil_receiving.pbl
  cursor data_861_cursor is
  select    customer_id,
            bol,
            edi_file_id,
            coil_org_num,
            receiving_bol_id,
            coil_abc_num,
            coil_status,
            damaged_fault,
            damaged_code,
            temper,
            net_weight,
            gross_weight,
            lineal_feed,
            coil_width,
            coil_gauge,
            density,
            lot,
            pack_id,
            alloy,
            part_num,
            supplier_sales_num,
            consumed_coil_num,
            material_num,
            cash_date,
            coil_from_cust_id,
            created_date,
            received_date,
            po,
            po_line_num,
            customer_duns_number,
            mill_duns_number,
            packaging_code,
            loading_qty
  from      dbo.data_861
  where     customer_id = al_customer_id
  and       bol = as_bol
  and       edi_file_id = ll_edi_file_id
  order by  edi_file_id;

  cursor edi_file_id_cursor(as_bol varchar2) is
     select  distinct edi_file_id
     from    dbo.data_861
     where   customer_id = al_customer_id
      and    bol = as_bol;

begin
  
    --******************************************************************************************
    --Alex Gerlants. 10/08/2019, 09:30 AM. Activated this function by commenting out the next line
    --return 1; --********************** Disable this function pending Novelis approval **********
    --******************************************************************************************
  
/*
    --This is already checked in wf_create_861_4customer for w_coil_receiving
    select	upper(nvl(create_861_at_receiving, 'N'))
    into		is_create_861_at_receiving
    from		customer
    where		customer_id = al_customer_id;
    
    if is_create_861_at_receiving <> 'Y' then 
      return 2; --Nothing to do here
    end if;
*/    
    --Alex Gerlants. 03/09/2021. Added '2950' to the line below
    if not ( al_customer_id in (1153, 1459, 2582, 2950) ) then
      return 3; --Wrong customer
    end if;
 
    FunctionResult := 1;
    
    for edi_file_id_cloop in edi_file_id_cursor(as_bol) loop 
      
        coil_count := 0;
        j          := 0;
      
        ll_edi_file_id := edi_file_id_cloop.edi_file_id;
        
        select    distinct ps_coil_number
        into      ls_ps_coil_number
        from      inbound_coil
        where     bol = as_bol
        and       edi_file_id = ll_edi_file_id;
    
      --IF (li_coil_ready = 1) THEN
        SELECT edi_st_log_seq.nextval INTO li_st_log FROM dual;
        SELECT edi_gs_log_seq.nextval INTO li_gs_log FROM dual;
        ls_today_short := to_char(SYSDATE, 'yymmdd');
        ls_today       := to_char(SYSDATE, 'yyyymmdd');
        ls_now         := to_char(SYSDATE, 'hh24mi');

        SELECT distinct vo
          INTO ls_vo
          FROM inbound_shipment
         WHERE bol = as_bol
         and   edi_file_id = ll_edi_file_id;

        /*ld_received_time := sysdate;   --set the received time as current system time*/
        SELECT COUNT(*)
          INTO li_count
          FROM receiving_bol
         WHERE bol = as_bol;

        IF li_count = 1 THEN
          SELECT distinct nvl(created_date, sysdate)
            INTO ld_received_time
            FROM receiving_bol
           WHERE bol = as_bol;
        ELSE
          ld_received_time := SYSDATE;
        END IF;
                        
        SELECT distinct ship_from
          INTO ls_ship_from
          FROM inbound_shipment
         WHERE bol = as_bol;
                           
        SELECT distinct customer_id
          INTO li_customer_id
          FROM inbound_shipment_customer
         WHERE ship_from = ls_ship_from;

        SELECT customer.customer_duns_number_string
          INTO ls_dun
          FROM customer
         WHERE customer.customer_id = al_customer_id;      

        ls_received_time := to_char(ld_received_time, 'yyyymmdd*hh24mi'); --need this format in EDI861 file
        ls_received_time_yy := to_char(ld_received_time, 'yymmdd*hh24mi');

        --Production
        edi_861(j) := 'ISA*00*' ||
                       '          *00*          *01*039630926T     *09*0015049350011G *' ||
                        ls_received_time_yy || '*U*00401*' ||
                        lpad(to_char(li_gs_log), 9, '0') || '*0*P**';
                        
        --Development                
        --edi_861(j) := 'ISA*00*' ||
        --                '          *00*          *ZZ*2NDSFTP        *ZZ*NOVLSTEST      *' ||
        --                ls_received_time_yy || '*U*00401*' ||
        --                lpad(to_char(li_gs_log), 9, '0') || '*0*T**';
                                        
        j := j + 1;

        --Production
        edi_861(j) := 'GS*SH*R0P7A*' || '001504935001' || '*' || ls_today || '*' ||
                        ls_now || '*' || to_char(li_gs_log) || '*X*' || '004010';
                                        
        --Development
        --edi_861(j) := 'GS*SH*2NDSFTP*' || 'NOVLSTEST' || '*' || ls_today || '*' ||
        --               ls_now || '*' || to_char(li_gs_log) || '*X*' || '004010';
        
        j := j + 1;
                        
        edi_861(j) := 'ST*861*' || li_st_log;
        j := j + 1;
                        
        edi_861(j) := 'BRA*' || as_bol || '*' || ls_today ||
                      '*00*1*' || ls_now;
        j := j + 1;
                        
        edi_861(j) := 'REF*BM*' || as_bol;
        j := j + 1;
                        
        edi_861(j) := 'DTM*050*' || ls_received_time || '*ED';
        j := j + 1;
                        
        select customer.customer_short_name
          into ls_customer_short_name
          from customer
         where customer.customer_id = li_customer_id;
                         
        edi_861(j) := 'N1*MF*' || ltrim(rtrim(ls_customer_short_name)) || '*1*' || ls_dun;
        j := j + 1;
                        
        edi_861(j) := 'N1*OU*' || 'ALUMINUM BLANKING CO., INC.' || '*1*039630926'; --ALBL DUNS
        j := j + 1;
        
        edi_861(j) := 'N1*SU*' || ltrim(rtrim(ls_customer_short_name)) || '*1*' || ls_dun; --Novelis DUNS
        j := j + 1;

        for cloop in data_861_cursor() loop
          ls_coil_number    := cloop.coil_org_num;
          li_coil_abc_num   := cloop.coil_abc_num;
          ls_temper         := cloop.temper;
          ln_net_weight     := cloop.net_weight;
          ln_gross_weight   := cloop.gross_weight;
          ln_lineal_feed    := cloop.lineal_feed;
          ln_coil_width     := cloop.coil_width;
          ln_coil_gauge     := cloop.coil_gauge;
          ln_density        := cloop.density;
          ls_lot            := cloop.lot;
          ls_pack_id        := cloop.pack_id;
          ls_alloy          := cloop.alloy;
          ln_damage_fault   := cloop.damaged_fault;
          ln_damage_code    := cloop.damaged_code;
          ls_po             := cloop.po;

          IF (ls_ps_coil_number IS NULL) OR (length(ls_ps_coil_number) = 0) THEN
            ls_ps_coil_number := ls_coil_number;
          END IF;

          edi_861(j) := 'RCD**1*CX';
          j := j + 1;
          
          ll_pos := instr(ls_po, '-', 1);
          
          if ll_pos > 0 then
            ls_po := substr(ls_po, 1, ll_pos - 1);
          end if;

          edi_861(j) := 'LIN**VO*' || ls_po || '*SN*' || ls_coil_number || '*HN*' || ls_lot;
                        
          j := j + 1;
          
          edi_861(j) := 'PID*S*MAC*ST*01***67';
          j := j + 1;
          
          edi_861(j) := 'PID*S*MA*ST*7***70';
          j := j + 1;


          --add these two segments only for damaged coils
      
          IF ln_damage_code <> 0 THEN
            edi_861(j) := 'PID*S*DAC*ST*' || ln_damage_code;
            j := j + 1;
          END IF;
          
          IF ln_damage_fault <> 0 THEN
            edi_861(j) := 'PID*S*DAF*ST*' || ln_damage_fault;
            j := j + 1;
          END IF;

          edi_861(j) := 'REF*SE*' || li_coil_abc_num;
          j := j + 1;
                          
          ls_received_date := to_char(ld_received_time, 'yyyymmdd');
          
          if (ls_ps_coil_number is null) or (length(ls_ps_coil_number) = 0) then
            ls_ps_coil_number := ls_coil_number;
          end if;
                          
          edi_861(j) := 'REF*RV*' || ls_ps_coil_number;
          j := j + 1;
                          
          edi_861(j) := 'MEA*WT*N*' || ln_net_weight || '*01';
          j := j + 1;
                          
          edi_861(j) := 'MEA*WT*G*' || ln_gross_weight || '*24';
          j := j + 1;
                          
          edi_861(j) := 'MEA*PD*TH*' || to_char(ln_coil_gauge, 'FM90.0000') || '*IN';
          j := j + 1;
          
          edi_861(j) := 'MEA*PD*WD*' || to_char(ln_coil_width, 'FM99990.0000') || '*IN';
          j := j + 1;
          
          if not ln_lineal_feed is null then --Alex Gerlants. 12/02/2019. Email from Novelis 11/21/2019 @04:40PM
            edi_861(j) := 'MEA*PD*LN*' || ln_lineal_feed || '*LF';
            j := j + 1;
          end if;

          coil_count := coil_count + 1;
          
          update    inbound_coil_status
          set       coil_abc_num = li_coil_abc_num
          where     bol = as_bol
          and       edi_file_id = ll_edi_file_id
          and       coil_number = ls_coil_number;
        END LOOP; --for cloop in data_861_cursor() loop

        edi_861(j) := 'CTT*' || coil_count;
        j := j + 1;
        edi_861(j) := 'SE*' || to_char(j - 1) || '*' || li_st_log;
        j := j + 1;
        edi_861(j) := 'GE*1*' || li_gs_log;
        j := j + 1;
        edi_861(j) := 'IEA*1*' || lpad(to_char(li_gs_log), 9, '0');

        IF coil_count > 0 THEN
            SELECT edi_file_id_seq.nextval INTO li_edi_861_id FROM dual;
            
            edi_file        := edi_file_prefix || to_char(li_edi_861_id) || '.edi';
            edi_file_handle := utl_file.fopen(edi_location, edi_file, 'W');
            --write edi to file
            FOR i IN 0 .. j LOOP
              utl_file.put_line(edi_file_handle, edi_861(i));
            END LOOP;
            utl_file.fclose(edi_file_handle);
          --END IF;
                          
        update inbound_shipment_status
          set    status = 1,
                 filename_861 = edi_file,
                 created_861_date_time = sysdate
          where  bol = as_bol
          and    edi_file_id = ll_edi_file_id;        
        
          INSERT INTO outbound_edi_transaction
            (edi_file_id,
             duns_from,
             duns_to,
             interchange_control_number,
             group_control_number,
             transaction_time,
             edi_file_name,
             fa_receive_status,
             customer_id,
             set_control_num,
             transaction_type_id)
          VALUES
            (li_edi_861_id,
             '039630926',
             ls_dun,
             li_gs_log,
             li_gs_log,
             sysdate,
             edi_file,
             0,
             li_customer_id,
             li_st_log,
             '861');
           
          commit;
                          

          edi_file        := 'send_edi_log';
          edi_file_handle := utl_file.fopen(edi_location, edi_file, 'a');
          utl_file.put_line(edi_file_handle, 'Type: 861');
          utl_file.put_line(edi_file_handle,
                            'Sending Time: ' ||
                            to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
          utl_file.put_line(edi_file_handle,
                            'Interchange Control #: ' || li_gs_log);
          utl_file.put_line(edi_file_handle,
                            'Group Control #: ' || li_gs_log);
          utl_file.put_line(edi_file_handle, 'Set Control #: ' || li_st_log);
          utl_file.put_line(edi_file_handle, '');
          utl_file.put_line(edi_file_handle, '');
          utl_file.fclose(edi_file_handle);

        END IF;
    end loop; --for edi_file_id_cloop in coil_status_cursor(as_bol) loop                    
  
  return(FunctionResult);
  
end f_edi_novelis_861;
--------------------------------------------------------
--  DDL for Function F_EDI_NOVELIS_861_12022019
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_NOVELIS_861_12022019" 
(
   al_customer_id in customer.customer_id%TYPE,
   as_bol         in inbound_shipment.bol%TYPE
)
   
return integer 
is

  FunctionResult              integer;
  
  /*
  This function creates Novelis EDI 861.
  edi_file_id and bol are from inbound_shipment table, received_time is generated the current moment by the system.
  This function will be called from Coil Receiving after a successful saving
  */

  type edi_861_tabletype is table of varchar2(32767) index by binary_integer;
  edi_861                     edi_861_tabletype;
  
  j                           binary_integer;
  i                           integer;
  
  --edi_file_prefix             varchar2(50) := 'S_novelis_861_'; --Production
  edi_file_prefix             varchar2(50) := 's_novelis_861_'; --Development
  
  li_coil_ready               integer;
  li_gs_log                   integer;
  li_st_log                   integer;
  ls_today_short              varchar2(20);
  ls_today                    varchar2(20);
  ls_now                      varchar2(20);
  ld_received_time            date;
  ls_received_time            varchar2(13);
  ls_received_time_yy         varchar2(13);
  li_customer_id              integer;
  ls_vo                       varchar2(20);
  ls_coil_number              varchar2(40);
  ls_ps_coil_number           varchar2(40);
  ls_temper                   varchar2(8);
  ln_net_weight               number(8, 0);
  ln_gross_weight             number(8, 0);
  ln_lineal_feed              number(7, 2);
  ln_coil_width               number(7, 2);
  ln_coil_gauge               number(5, 4);
  ln_density                  number;
  ls_lot                      varchar2(40);
  ls_pack_id                  varchar2(40);
  ls_alloy                    varchar2(40);
  ln_damage_fault             number(1);
  ln_damage_code              number(3);
  --edi_location                varchar2(50) := '/templar/templar/incoming/senddata';
  edi_location                VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR');
  edi_file                    varchar2(50) := 'edi_out.txt';
  edi_file_handle             utl_file.file_type;
  li_edi_861_id               integer;
  ls_dun                      varchar2(32);
  ls_ship_from                varchar2(40);
  coil_count                  integer;
  li_coil_abc_num             integer;
  li_count                    integer;
  ls_received_date            varchar2(8);
  li_inbound_shipment_status  inbound_shipment_status.status%TYPE;
  ll_edi_file_id              inbound_shipment_status.edi_file_id%TYPE;
  is_create_861_at_receiving  char(1);
  ls_po                       receiving_bol_coil.purchase_order_num%TYPE;
  ls_customer_short_name      customer.customer_short_name%TYPE;
  ll_pos                      integer;

  --Table data_861 is populated in function wf_populate_data_861 for w_coil_receiving in coil_receiving.pbl
  cursor data_861_cursor is
  select    customer_id,
            bol,
            edi_file_id,
            coil_org_num,
            receiving_bol_id,
            coil_abc_num,
            coil_status,
            damaged_fault,
            damaged_code,
            temper,
            net_weight,
            gross_weight,
            lineal_feed,
            coil_width,
            coil_gauge,
            density,
            lot,
            pack_id,
            alloy,
            part_num,
            supplier_sales_num,
            consumed_coil_num,
            material_num,
            cash_date,
            coil_from_cust_id,
            created_date,
            received_date,
            po,
            po_line_num,
            customer_duns_number,
            mill_duns_number,
            packaging_code,
            loading_qty
  from      dbo.data_861
  where     customer_id = al_customer_id
  and       bol = as_bol
  and       edi_file_id = ll_edi_file_id
  order by  edi_file_id;

  cursor edi_file_id_cursor(as_bol varchar2) is
     select  distinct edi_file_id
     from    dbo.data_861
     where   customer_id = al_customer_id
      and    bol = as_bol;

begin
  
    --******************************************************************************************
    --Alex Gerlants. 10/08/2019, 09:30 AM. Activated this function by commenting out the next line
    --return 1; --********************** Disable this function pending Novelis approval **********
    --******************************************************************************************
  
/*
    --This is already checked in wf_create_861_4customer for w_coil_receiving
    select	upper(nvl(create_861_at_receiving, 'N'))
    into		is_create_861_at_receiving
    from		customer
    where		customer_id = al_customer_id;
    
    if is_create_861_at_receiving <> 'Y' then 
      return 2; --Nothing to do here
    end if;
*/    
    if not ( al_customer_id in (1153, 1459, 2582) ) then
      return 3; --Wrong customer
    end if;
 
    FunctionResult := 1;
    
    for edi_file_id_cloop in edi_file_id_cursor(as_bol) loop 
      
        coil_count := 0;
        j          := 0;
      
        ll_edi_file_id := edi_file_id_cloop.edi_file_id;
        
        select    distinct ps_coil_number
        into      ls_ps_coil_number
        from      inbound_coil
        where     bol = as_bol
        and       edi_file_id = ll_edi_file_id;
    
      --IF (li_coil_ready = 1) THEN
        SELECT edi_st_log_seq.nextval INTO li_st_log FROM dual;
        SELECT edi_gs_log_seq.nextval INTO li_gs_log FROM dual;
        ls_today_short := to_char(SYSDATE, 'yymmdd');
        ls_today       := to_char(SYSDATE, 'yyyymmdd');
        ls_now         := to_char(SYSDATE, 'hh24mi');

        SELECT distinct vo
          INTO ls_vo
          FROM inbound_shipment
         WHERE bol = as_bol
         and   edi_file_id = ll_edi_file_id;

        /*ld_received_time := sysdate;   --set the received time as current system time*/
        SELECT COUNT(*)
          INTO li_count
          FROM receiving_bol
         WHERE bol = as_bol;

        IF li_count = 1 THEN
          SELECT distinct nvl(created_date, sysdate)
            INTO ld_received_time
            FROM receiving_bol
           WHERE bol = as_bol;
        ELSE
          ld_received_time := SYSDATE;
        END IF;
                        
        SELECT distinct ship_from
          INTO ls_ship_from
          FROM inbound_shipment
         WHERE bol = as_bol;
                           
        SELECT distinct customer_id
          INTO li_customer_id
          FROM inbound_shipment_customer
         WHERE ship_from = ls_ship_from;

        SELECT customer.customer_duns_number_string
          INTO ls_dun
          FROM customer
         WHERE customer.customer_id = al_customer_id;      

        ls_received_time := to_char(ld_received_time, 'yyyymmdd*hh24mi'); --need this format in EDI861 file
        ls_received_time_yy := to_char(ld_received_time, 'yymmdd*hh24mi');

        --Production
        edi_861(j) := 'ISA*00*' ||
                       '          *00*          *01*039630926T     *09*0015049350011G *' ||
                        ls_received_time_yy || '*U*00401*' ||
                        lpad(to_char(li_gs_log), 9, '0') || '*0*P**';
                        
        --Development                
        --edi_861(j) := 'ISA*00*' ||
        --                '          *00*          *ZZ*2NDSFTP        *ZZ*NOVLSTEST      *' ||
        --                ls_received_time_yy || '*U*00401*' ||
        --                lpad(to_char(li_gs_log), 9, '0') || '*0*T**';
                                        
        j := j + 1;

        --Production
        edi_861(j) := 'GS*SH*R0P7A*' || '001504935001' || '*' || ls_today || '*' ||
                        ls_now || '*' || to_char(li_gs_log) || '*X*' || '004010';
                                        
        --Development
        --edi_861(j) := 'GS*SH*2NDSFTP*' || 'NOVLSTEST' || '*' || ls_today || '*' ||
        --               ls_now || '*' || to_char(li_gs_log) || '*X*' || '004010';
        
        j := j + 1;
                        
        edi_861(j) := 'ST*861*' || li_st_log;
        j := j + 1;
                        
        edi_861(j) := 'BRA*' || as_bol || '*' || ls_today ||
                      '*00*1*' || ls_now;
        j := j + 1;
                        
        edi_861(j) := 'REF*BM*' || as_bol;
        j := j + 1;
                        
        edi_861(j) := 'DTM*050*' || ls_received_time || '*ED';
        j := j + 1;
                        
        select customer.customer_short_name
          into ls_customer_short_name
          from customer
         where customer.customer_id = li_customer_id;
                         
        edi_861(j) := 'N1*MF*' || ltrim(rtrim(ls_customer_short_name)) || '*1*' || ls_dun;
        j := j + 1;
                        
        edi_861(j) := 'N1*OU*' || 'ALUMINUM BLANKING CO., INC.' || '*1*039630926'; --ALBL DUNS
        j := j + 1;
        
        edi_861(j) := 'N1*SU*' || ltrim(rtrim(ls_customer_short_name)) || '*1*' || ls_dun; --Novelis DUNS
        j := j + 1;

        for cloop in data_861_cursor() loop
          ls_coil_number    := cloop.coil_org_num;
          li_coil_abc_num   := cloop.coil_abc_num;
          ls_temper         := cloop.temper;
          ln_net_weight     := cloop.net_weight;
          ln_gross_weight   := cloop.gross_weight;
          ln_lineal_feed    := cloop.lineal_feed;
          ln_coil_width     := cloop.coil_width;
          ln_coil_gauge     := cloop.coil_gauge;
          ln_density        := cloop.density;
          ls_lot            := cloop.lot;
          ls_pack_id        := cloop.pack_id;
          ls_alloy          := cloop.alloy;
          ln_damage_fault   := cloop.damaged_fault;
          ln_damage_code    := cloop.damaged_code;
          ls_po             := cloop.po;

          IF (ls_ps_coil_number IS NULL) OR (length(ls_ps_coil_number) = 0) THEN
            ls_ps_coil_number := ls_coil_number;
          END IF;

          edi_861(j) := 'RCD**1*CX';
          j := j + 1;
          
          ll_pos := instr(ls_po, '-', 1);
          
          if ll_pos > 0 then
            ls_po := substr(ls_po, 1, ll_pos - 1);
          end if;

          edi_861(j) := 'LIN**VO*' || ls_po || '*SN*' || ls_coil_number || '*HN*' || ls_lot;
                        
          j := j + 1;
          
          edi_861(j) := 'PID*S*MAC*ST*01***67';
          j := j + 1;
          
          edi_861(j) := 'PID*S*MA*ST*7***70';
          j := j + 1;


          --add these two segments only for damaged coils
      
          IF ln_damage_code <> 0 THEN
            edi_861(j) := 'PID*S*DAC*ST*' || ln_damage_code;
            j := j + 1;
          END IF;
          
          IF ln_damage_fault <> 0 THEN
            edi_861(j) := 'PID*S*DAF*ST*' || ln_damage_fault;
            j := j + 1;
          END IF;

          edi_861(j) := 'REF*SE*' || li_coil_abc_num;
          j := j + 1;
                          
          ls_received_date := to_char(ld_received_time, 'yyyymmdd');
          
          if (ls_ps_coil_number is null) or (length(ls_ps_coil_number) = 0) then
            ls_ps_coil_number := ls_coil_number;
          end if;
                          
          edi_861(j) := 'REF*RV*' || ls_ps_coil_number;
          j := j + 1;
                          
          edi_861(j) := 'MEA*WT*N*' || ln_net_weight || '*01';
          j := j + 1;
                          
          edi_861(j) := 'MEA*WT*G*' || ln_gross_weight || '*24';
          j := j + 1;
                          
          edi_861(j) := 'MEA*PD*TH*' || to_char(ln_coil_gauge, 'FM90.0000') || '*IN';
          j := j + 1;
          
          edi_861(j) := 'MEA*PD*WD*' || to_char(ln_coil_width, 'FM99990.0000') || '*IN';
          j := j + 1;
          
          if not ln_lineal_feed is null then
            edi_861(j) := 'MEA*PD*LN*' || ln_lineal_feed || '*LF';
            j := j + 1;
          end if;

          coil_count := coil_count + 1;

/*          
          update    inbound_coil_status
          set       coil_abc_num = li_coil_abc_num
          where     bol = as_bol
          and       edi_file_id = ll_edi_file_id
          and       coil_number = ls_coil_number;
*/          
        END LOOP; --for cloop in data_861_cursor() loop

        edi_861(j) := 'CTT*' || coil_count;
        j := j + 1;
        edi_861(j) := 'SE*' || to_char(j - 1) || '*' || li_st_log;
        j := j + 1;
        edi_861(j) := 'GE*1*' || li_gs_log;
        j := j + 1;
        edi_861(j) := 'IEA*1*' || lpad(to_char(li_gs_log), 9, '0');

        IF coil_count > 0 THEN
            SELECT edi_file_id_seq.nextval INTO li_edi_861_id FROM dual;
            
            edi_file        := edi_file_prefix || to_char(li_edi_861_id) || '.edi';
            edi_file_handle := utl_file.fopen(edi_location, edi_file, 'W');
            --write edi to file
            FOR i IN 0 .. j LOOP
              utl_file.put_line(edi_file_handle, edi_861(i));
            END LOOP;
            utl_file.fclose(edi_file_handle);
          --END IF;

/*                          
        update inbound_shipment_status
          set    status = 1,
                 filename_861 = edi_file,
                 created_861_date_time = sysdate
          where  bol = as_bol
          and    edi_file_id = ll_edi_file_id;        
        
          INSERT INTO outbound_edi_transaction
            (edi_file_id,
             duns_from,
             duns_to,
             interchange_control_number,
             group_control_number,
             transaction_time,
             edi_file_name,
             fa_receive_status,
             customer_id,
             set_control_num,
             transaction_type_id)
          VALUES
            (li_edi_861_id,
             '039630926',
             ls_dun,
             li_gs_log,
             li_gs_log,
             sysdate,
             edi_file,
             0,
             li_customer_id,
             li_st_log,
             '861');
*/             
           
          commit;
                          

          edi_file        := 'send_edi_log';
          edi_file_handle := utl_file.fopen(edi_location, edi_file, 'a');
          utl_file.put_line(edi_file_handle, 'Type: 861');
          utl_file.put_line(edi_file_handle,
                            'Sending Time: ' ||
                            to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
          utl_file.put_line(edi_file_handle,
                            'Interchange Control #: ' || li_gs_log);
          utl_file.put_line(edi_file_handle,
                            'Group Control #: ' || li_gs_log);
          utl_file.put_line(edi_file_handle, 'Set Control #: ' || li_st_log);
          utl_file.put_line(edi_file_handle, '');
          utl_file.put_line(edi_file_handle, '');
          utl_file.fclose(edi_file_handle);

        END IF;
    end loop; --for edi_file_id_cloop in coil_status_cursor(as_bol) loop                    
  
  return(FunctionResult);
  
end f_edi_novelis_861_12022019;
--------------------------------------------------------
--  DDL for Function F_EDI_NOVELIS_870_4JOB
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_NOVELIS_870_4JOB" 
 ( 
    al_ab_job_num           ab_job.ab_job_num%type,
    as_user_id              ab_job_870_history.user_id%type,
    as_original_or_resend   varchar2
    
 )
  return integer
  
is

  /*
  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc                varchar2(50) := get_edi_destination('EDI_DIR');

  edi_file                     varchar2(50) := 'edi_out.txt';
  edi_file_prefix              varchar2(50) := 'S_novelis_870_'; --production
  --edi_file_prefix              varchar2(50) := 's_novelis_870_'; --development
  edi_file_handle              utl_file.file_type;
  su_duns                      varchar2(10);
  ll_customer_id               customer.customer_id%type;
  ll_cur_coil                  coil.coil_abc_num%type;
  ll_gs_log                    integer;
  ll_st_log                    integer;
  ls_today                     varchar2(20) := to_char(sysdate, 'YYYYMMDD');
  ls_today_4                   varchar2(20) := to_char(sysdate, 'YYMMDD');
  ls_now                       varchar2(20) := to_char(sysdate, 'HH24MI');
  ls_po                        varchar2(20);
  ls_finished_goods            varchar2(32);
  ls_cust_prod_line            varchar2(8);
  ld_scrap_870_date            process_coil.scrap_870_date%type;
  ls_coil_org_num              coil.coil_org_num%type;
  ls_heat                      coil.lot_num%type;
  ll_prime_nw                  coil.net_wt%type;
  ll_scrap_nw                  coil.net_wt%type;
  ll_item_count                integer;
  li_hl01                      integer;
  li_hllin                     integer;
  ll_rowcount                  number(8);
  ll_edi_file_id_870           integer;
  ld_edi_date_870              ab_job.edi_date_870%type;
  --ls_sheet_skid_exists         char(1);
  ls_consumed_coil_num         coil.consumed_coil_num%type;
  ls_customer_short_name       customer.customer_short_name%type;
  ll_sheet_skid_count_4coil    number(8);
  ll_total_act_scrap_wt_4job   number(8);
  ll_total_theo_scrap_wt_4job  number(8);
  ll_heavy_light               number(8);
  li_rtn                       number(4); --Alex Gerlants. Changed from number(1) to number(4)
  ll_psi_870_count             number(3); --Alex Gerlants. 01/08/2021
  ll_coil_870_count            number(3); --Alex Gerlants. 01/08/2021
  ll_process_coil_870_count    number(3); --Alex Gerlants. 01/08/2021

--------------------------------------------------------------------------------------------------   
------------------------------------ Cursors Begin -----------------------------------------------
--------------------------------------------------------------------------------------------------

  cursor coil_cur is
  select distinct process_coil.coil_abc_num
  from   process_coil
         left outer join production_sheet_item on production_sheet_item.coil_abc_num = process_coil.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    (
              sheet_skid.skid_sheet_status in (0, 2, 4, 13, 12, 16)
           or sheet_skid.skid_sheet_status is null --This is for rejected coils without sheets  
         )
  order by process_coil.coil_abc_num;
  
  coil_rec  coil_cur%ROWTYPE;
   
  --Cursor skid_coil_cur will select data for ab_job and coil_abc_num with skids.
  --If there is a reject coil without sheet skids, this cursor will not select it.
  cursor skid_coil_cur is
  select coil.coil_abc_num,   
         coil.lot_num,   
         coil.coil_org_num,   
         coil.coil_mid_num,
         nvl(coil.consumed_coil_num, ' ') consumed_coil,
         nvl(coil.material_num, ' ') material_num,
         coil.net_wt,   
         sheet_skid.sheet_tare_wt,   
         sheet_skid.sheet_net_wt,
         sheet_skid.skid_pieces,
         production_sheet_item.prod_item_pieces,
         production_sheet_item.prod_item_num,
         sheet_skid.skid_sheet_status,
         sheet_skid.sheet_skid_num,   
         production_sheet_item.prod_item_note,   
         sheet_skid.sheet_theoretical_wt,   
         production_sheet_item.prod_item_placement,   
         process_coil.process_quantity,   
         production_sheet_item.prod_item_net_wt,   
         sheet_skid.sheet_skid_display_num,
         nvl(customer_order.sales_order, ' ') sales_order,
         nvl(customer_order.orig_customer_po, 'NA') orig_customer_po,
         nvl(order_item.enduser_part_num, ' ') enduser_part_num,
         nvl(order_item.cust_prod_line_id, 'NA') cust_prod_line_id,
         nvl(order_item.finished_goods_material_num, 'NA') finished_goods_material_num,
         (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
         NULL done  
  from   coil   
         join process_coil on coil.coil_abc_num = process_coil.coil_abc_num
         join ab_job on ab_job.ab_job_num = process_coil.ab_job_num
         join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
         join customer_order on customer_order.order_abc_num = order_item.order_abc_num
         left outer join production_sheet_item on coil.coil_abc_num = production_sheet_item.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  ab_job.ab_job_num = al_ab_job_num
  and    coil.coil_abc_num = ll_cur_coil
  order by
         production_sheet_item.coil_abc_num,
         sheet_skid.sheet_skid_display_num;

  skid_coil_rec  skid_coil_cur%rowtype;
  
  cursor scrap_cur is
  select process_coil.coil_abc_num,
         process_coil.process_coil_status,
         process_coil.process_quantity,
         nvl(process_coil.process_end_wt, 0),
         sum(nvl(process_coil.process_end_wt, 0)),
         sum(nvl(production_sheet_item.prod_item_net_wt, 0)),
         case process_coil.process_coil_status
            when 7 then --Rebanded coils
               --(process_coil.process_quantity - sum(production_sheet_item.prod_item_net_wt) - (select process_end_wt from process_coil pc where pc.ab_job_num = 101143 and pc.coil_abc_num = process_coil.coil_abc_num))
               --(process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - nvl(process_coil.process_end_wt, 0)) --Alex Gerlants. Commented out on 12/15/2020
               (process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - nvl(f_get_coil_rebanded_wt(process_coil.coil_abc_num, process_coil.process_quantity), -99)) --Alex Gerlants. Added on 12/15/2020
            when 3 then --Rejected coils
               case (select count(*) from production_sheet_item psi where psi.ab_job_num = al_ab_job_num and psi.coil_abc_num = process_coil.coil_abc_num)
                 when 0 then --Rejected coils without sheets
                   (process_coil.process_quantity - sum(nvl(process_coil.process_end_wt, 0)))
                 else --Rejected coils with sheets
                   (process_coil.process_quantity - nvl(process_coil.process_end_wt, 0) - sum(nvl(production_sheet_item.prod_item_net_wt, 0)))     
                end   
             else
               (process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - sum(nvl(process_coil.process_end_wt, 0)))
         end scrap_net_wt
  from   process_coil
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         join ab_job on ab_job.ab_job_num = process_coil.ab_job_num and coil.coil_abc_num = process_coil.coil_abc_num
         left outer join production_sheet_item on production_sheet_item.ab_job_num = process_coil.ab_job_num and production_sheet_item.coil_abc_num = process_coil.coil_abc_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    coil.coil_abc_num = ll_cur_coil
  group by
         process_coil.coil_abc_num,
         process_coil.process_coil_status,
         process_coil.process_quantity,
         process_coil.process_end_wt
  order by
         process_coil.coil_abc_num;
         
  scrap_rec  scrap_cur%rowtype;
   
--------------------------------------------------------------------------------------------------   
------------------------------------- Cursors End ------------------------------------------------
--------------------------------------------------------------------------------------------------   

  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;

  TYPE coil_num_type IS TABLE OF coil.coil_abc_num%type INDEX BY BINARY_INTEGER;
  coil_num coil_num_type;
  p binary_integer :=0;
  
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;  

BEGIN
  
  --Check if correct customer
  select  customer_order.orig_customer_id,
          customer.customer_duns_number_string,
          customer.customer_short_name
  into    ll_customer_id,
          su_duns,
          ls_customer_short_name
  from    ab_job
          join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
          join customer on customer.customer_id = customer_order.orig_customer_id
  where   ab_job.ab_job_num = al_ab_job_num;
  
  if lower(ls_customer_short_name) not like '%novelis%' then
    return 200; --Wrong customer
  end if;
  
  --Check if 870 has already been created for al_ab_job_num
  select edi_file_id_870, edi_date_870
  into   ll_edi_file_id_870, ld_edi_date_870
  from   ab_job
  where  ab_job_num = al_ab_job_num;
  
  --Alex Gerlants. 01/08/2021
  --Added this check to avoid sending 870 for jobs that had 870 created by the old batch processing.
  --Check if 870 has already been created for al_ab_job_num using the old data fields
  select count(distinct prod_item_edi870_date)
  into   ll_psi_870_count
  from   production_sheet_item
  where  ab_job_num = al_ab_job_num
  and    prod_item_edi870_date is not null;
  
  --Alex Gerlants. 02/19/2021. Comment out Begin
  --In case of more than 1 job for the same coil, this script updates process_coil and coil
  --for the first job.
  --When the second job for this coil, tries to run this script to create 870, 
  --it returns 100 - 870 already created
  --Checking table production_sheet_item is sufficient to prevent 870 creation for jobs that had 870 
  --created by the old batch processing.

  /* 
  select count(distinct scrap_870_date)
  into   ll_process_coil_870_count
  from   process_coil
  where  ab_job_num = al_ab_job_num
  and    scrap_870_date is not null;
  
  select count(distinct scrap_870_date)
  into   ll_coil_870_count
  from   coil
  where  coil_abc_num in
  (
      select   distinct coil_abc_num
      from     process_coil
      where    ab_job_num = al_ab_job_num
  )
  and    scrap_870_date is not null;
  */
  --Alex Gerlants. 02/19/2021. Comment out End
  
  --Alex Gerlants. 01/08/2021. Added " or ll_psi_870_count > 0 or ll_process_coil_870_count > 0 or ll_coil_870_count > 0"
  --Alex Gerlants. 02/19/2021. Removed "or ll_process_coil_870_count > 0 or ll_coil_870_count > 0"
  --Please see explanation above.
  if (not (ll_edi_file_id_870 is null and ld_edi_date_870 is null)) or ll_psi_870_count > 0 then --870 already created for al_ab_job_num
    return 100;
  end if;

  i              := 0;
  k              := 0;
  p              := 0;
  
  select count(distinct process_coil.coil_abc_num)
  into   ll_rowcount
  from   process_coil
         left outer join production_sheet_item on production_sheet_item.coil_abc_num = process_coil.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    (
              sheet_skid.skid_sheet_status in (0, 2, 4, 13, 12, 16)
           or sheet_skid.skid_sheet_status is null --This is for rejected coils without sheets  
         );
    
  if ll_rowcount > 0 then

    select edi_st_log_seq.nextval into ll_st_log from dual;
    select edi_gs_log_seq.nextval into ll_gs_log from dual;
    
    /*
    select  customer_order.orig_customer_id
    into    ll_customer_id
    from    ab_job
            join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
    where   ab_job.ab_job_num = al_ab_job_num;
    
    select  customer.customer_duns_number_string
    into    su_duns
    from    customer
    where   customer.customer_id = ll_customer_id;
    */

    --Production
    x12_table(i) := 'ISA*00*' ||
                    '          *00*          *01*039630926T     *09*0015049350011G *' ||
                    ls_today_4 || '*' || ls_now || '*U*00401*' ||
                    lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
          
    --Development                
    --x12_table(i) := 'ISA*00*' ||
    --                '          *00*          *ZZ*2NDSFTP        *ZZ*NOVLSTEST      *' ||
    --                ls_today_4 || '*' || ls_now || '*U*00401*' ||
    --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';    
                         
    i := i + 1;
          
    --Production
    x12_table(i) := 'GS*RS*039630926T*' || '001504935001' || '*' ||
                    ls_today || '*' || ls_now || '*' ||
                    to_char(ll_gs_log) || '*X*' || '004010';
          
    --Development                
    --x12_table(i) := 'GS*RS*2NDSFTP*' || 'NOVLSTEST' || '*' ||
    --                ls_today || '*' || ls_now || '*' ||
    --                to_char(ll_gs_log) || '*X*' || '004010';
                          
    i := i + 1;
        
    x12_table(i) := 'ST*870*' || to_char(ll_st_log);
    i := i + 1;
    x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                    '***' || ls_now || '*****';
    i := i + 1;
    x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
    i := i + 1;
    x12_table(i) := 'N1*SU**1*' || su_duns;
    i := i + 1;
    x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926';
    i := i + 1;

    li_hl01 := 0;

    for coil_rec in coil_cur loop --Coil loop
       ll_cur_coil := coil_rec.coil_abc_num;
       ls_consumed_coil_num := to_char(skid_coil_rec.consumed_coil);
       --ls_sheet_skid_exists := 'n';
       
       select   consumed_coil_num
       into     ls_consumed_coil_num
       from     coil
       where    coil_abc_num = ll_cur_coil;
       
       select   count(*)
       into     ll_sheet_skid_count_4coil
       from     production_sheet_item
       where    ab_job_num = al_ab_job_num
       and      coil_abc_num = ll_cur_coil;
       
       coil_num(p) := ll_cur_coil;
       p := p + 1;

       select   coil.coil_org_num, coil.lot_num
       into     ls_coil_org_num, ls_heat
       from     coil
       where    coil.coil_abc_num = ll_cur_coil;
        
       --ls_sheet_skid_exists := 'n';

       for skid_coil_rec in skid_coil_cur loop --Skid_coil loop
           if skid_coil_rec.prod_item_net_wt > 0 then
             
              --ls_sheet_skid_exists := 'y';
              li_hl01 := li_hl01 + 1;

              x12_table(i) := 'HL*' || to_char(li_hl01) || '**I';
              i := i + 1;
            
              ls_po := skid_coil_rec.orig_customer_po;
              ls_cust_prod_line := skid_coil_rec.cust_prod_line_id;
              ls_finished_goods := skid_coil_rec.finished_goods_material_num;

              IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
                 x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
                 i := i + 1;
              END IF;

              x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
              i := i + 1;

              --Alex Gerlants. 2193. Email from Lisa received on Wed 7/31/2024 4:52 PM
              x12_table(i) := 'REF*SE*A' || to_char(skid_coil_rec.prod_item_num);
              i := i + 1;


              x12_table(i) := 'REF*MI*' || to_char(al_ab_job_num);
              i := i + 1;

              --Alex Gerlants. 2193. Email from Lisa received on Wed 7/31/2024 4:52 PM
              x12_table(i) := 'REF*RV*A' || to_char(skid_coil_rec.prod_item_num) ||
                              '*NA';
              i := i + 1;

              x12_table(i) := 'REF*IX*' || to_char(skid_coil_rec.consumed_coil);
              i := i + 1;

              x12_table(i) := 'PO1**1*UN****' || '***SN*' ||
                                ls_coil_org_num || '***VP*' || skid_coil_rec.finished_goods_material_num;
              i := i + 1;

              if skid_coil_rec.skid_sheet_status = 2 then
                x12_table(i) := 'PID*S*MA*ST*1*' ||
                                to_char(skid_coil_rec.sheet_skid_display_num);
                i := i + 1;
              elsif skid_coil_rec.skid_sheet_status = 4 then
                x12_table(i) := 'PID*S*MA*ST*3*' ||
                                to_char(skid_coil_rec.sheet_skid_display_num);
                i := i + 1;
              elsif skid_coil_rec.skid_sheet_status = 13 then
                x12_table(i) := 'PID*S*MA*ST*8*' ||
                                to_char(skid_coil_rec.sheet_skid_display_num);
                i := i + 1;
              else
                x12_table(i) := 'PID*S*MA*ST*4*' ||
                                to_char(skid_coil_rec.sheet_skid_display_num);
                i := i + 1;
              end if;

              x12_table(i) := 'PID*S*MAC*ST*01';
              i := i + 1;
              x12_table(i) := 'PID*S*PR*ST*19';
              i := i + 1;
              x12_table(i) := 'MEA*WT*N*' || to_char(skid_coil_rec.prod_item_net_wt) ||
                              '*LB*01';
              i := i + 1;
              x12_table(i) := 'MEA*WT*G*' || to_char(skid_coil_rec.skid_gross_wt) ||
                              '*LB*01';
              i := i + 1;
              x12_table(i) := 'MEA*CT*NA*' || to_char(skid_coil_rec.prod_item_pieces) ||
                              '*PC';
              i := i + 1;

              item_num(k) := skid_coil_rec.prod_item_num;
              k := k + 1;
           end if; --if skid_coil_rec.prod_item_net_wt > 0
        end loop; --for skid_coil_rec IN skid_coil_cur loop

        for scrap_rec in scrap_cur loop --Scrap loop
          ll_scrap_nw := scrap_rec.scrap_net_wt;

          if ll_scrap_nw > 0 then --Theo scrap weight
                   
             if ll_sheet_skid_count_4coil <= 0 then --ll_cur_coil is a fully scrapped (rejected) coil without good material
               li_rtn := f_edi_novelis_870_reject_4job(al_ab_job_num, ll_cur_coil, as_user_id, as_original_or_resend);
                     
               continue; --06/19/2020. bypass for fully scrapped coil.
                         --It is in a separate 870 created in f_edi_novelis_870_scrap_coil()
             end if;
                  
             ll_total_theo_scrap_wt_4job := 0;
                  
             select    nvl(sum(return_item_net_wt),0) 
             into      ll_total_act_scrap_wt_4job
             from      return_scrap_item
             where     ab_job_num = al_ab_job_num;

             li_hl01 := li_hl01 + 1;

             x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*I';
             i := i + 1;

             IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
                x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
                i := i + 1;
             END IF;

             x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
             i := i + 1;
                   
             x12_table(i) := 'PO1**1*UN****' || '***SN*' || ls_coil_org_num ;
             i := i + 1;

             x12_table(i) := 'PID*S*MA*ST*S';
             i := i + 1;

             x12_table(i) := 'PID*S*MAC*ST*05';
             i := i + 1;

             x12_table(i) := 'PID*S*PR*ST*19';
             i := i + 1;

             x12_table(i) := 'MEA*WT*N*' || to_char(ll_scrap_nw) || '*LB*01';
             i := i+1;
                   
             ll_total_theo_scrap_wt_4job := ll_total_theo_scrap_wt_4job + ll_scrap_nw;
             
           else --Alex Gerlants. 12/11/2020
             if ll_scrap_nw < 0 then
                --This is in case when the user didn't zero out coil before he changed job status to Done, and saved it
                --In this case, ll_scrap_nw < 0
                return 300; --Alex Gerlants. 12/11/2020 
             end if;                   
           end if; --if ll_scrap_nw > 0 then
        end loop; --for scrap_rec in alcan_scrap_870_cur loop scrap loop
              
          ll_heavy_light := ll_total_act_scrap_wt_4job - ll_total_theo_scrap_wt_4job;
            
        --end if; --if (ld_scrap_870_date is null) then --Scrap not sent
    end loop; --for coil_rec in coil_cur loop. Coil loop
    
    x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
    i := i + 1;

    x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
    i := i + 1;

    x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
    i := i + 1;

    x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

    -- Write EDI to file

    if li_hl01 > 0 then
        -- WRITE EDI FILE ONLY IF ITEM > 0
        SELECT edi_file_id_seq.nextval
          INTO ll_edi_file_id_870
          FROM dual;
        edi_file        := edi_file_prefix || to_char(ll_edi_file_id_870) || '_Job-' || to_char(al_ab_job_num) || '.edi';
     -- edi_file        := 's_alcan_' || to_char(ll_edi_file_id_870) || '.870';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        FOR j IN 0 .. i LOOP
          utl_file.put_line(edi_file_handle, x12_table(j));

        END LOOP;
        utl_file.fclose(edi_file_handle);
      --END IF; -- END WRITING EDI FILE

      --edi_file        := 'send_edi_log'; /* Alex Gerlants. 04/14/2017. Commented out. */
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      --For verifying 997
      INSERT INTO outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
        VALUES
          (ll_edi_file_id_870,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           SYSDATE,
           edi_file,
           0,
           ll_customer_id,
           ll_st_log,
           '870');


       --update    ab_job
       --set       edi_file_id_870 = ll_edi_file_id_870,
       --          edi_date_870 = sysdate
       --where     ab_job_num = al_ab_job_num;
          
       insert into ab_job_870_history
        (
           ab_job_num,
           edi_file_id,
           edi_file_name,
           create_870_date_time,
           user_id,
           notes
        )
        values
        (
           al_ab_job_num ,
           ll_edi_file_id_870,
           edi_file,
           sysdate,
           as_user_id,
           as_original_or_resend
        );

        for m in 0 .. k - 1 loop
           update   production_sheet_item
           set      prod_item_edi870_date = sysdate,
                    edi_file_id_870 = ll_edi_file_id_870 
           where    production_sheet_item.prod_item_num = item_num(m);
        end loop;

        for m in 0..p - 1 loop
           update   coil
           set      coil.scrap_870_date = sysdate
           where    coil.coil_abc_num = coil_num(m);

           update   process_coil
           set      scrap_870_date = sysdate
           where    ( coil_abc_num = coil_num(m)) and (scrap_870_date is null);

         end loop;
         
         update    ab_job
         set       edi_file_id_870 = ll_edi_file_id_870,
                   edi_date_870 = sysdate
         where     ab_job_num = al_ab_job_num;

         commit;
      END IF; -- END WRITING EDI FILE

  end if; --end if in select count(*)

  --END LOOP; ------ End of outer loop customer_id

/*
EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN -1;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN -2;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN -3;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN -4;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN -9;
*/
    
  return 1;
end f_edi_novelis_870_4job;
--------------------------------------------------------
--  DDL for Function F_EDI_NOVELIS_870_4JOB_120920
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_NOVELIS_870_4JOB_120920" 
 ( 
    al_ab_job_num           ab_job.ab_job_num%type,
    as_user_id              ab_job_870_history.user_id%type,
    as_original_or_resend   varchar2
    
 )
  return integer
  
is

  /*
  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc                varchar2(50) := get_edi_destination('EDI_DIR');

  edi_file                     varchar2(50) := 'edi_out.txt';
  --edi_file_prefix              varchar2(50) := 'S_novelis_870_'; --production
  edi_file_prefix              varchar2(50) := 's_novelis_870_'; --development
  edi_file_handle              utl_file.file_type;
  su_duns                      varchar2(10);
  ll_customer_id               customer.customer_id%type;
  ll_cur_coil                  coil.coil_abc_num%type;
  ll_gs_log                    integer;
  ll_st_log                    integer;
  ls_today                     varchar2(20) := to_char(sysdate, 'YYYYMMDD');
  ls_today_4                   varchar2(20) := to_char(sysdate, 'YYMMDD');
  ls_now                       varchar2(20) := to_char(sysdate, 'HH24MI');
  ls_po                        varchar2(20);
  ls_finished_goods            varchar2(32);
  ls_cust_prod_line            varchar2(8);
  ld_scrap_870_date            process_coil.scrap_870_date%type;
  ls_coil_org_num              coil.coil_org_num%type;
  ls_heat                      coil.lot_num%type;
  ll_prime_nw                  coil.net_wt%type;
  ll_scrap_nw                  coil.net_wt%type;
  ll_item_count                integer;
  li_hl01                      integer;
  li_hllin                     integer;
  ll_rowcount                  number(8);
  ll_edi_file_id_870           integer;
  ld_edi_date_870              ab_job.edi_date_870%type;
  --ls_sheet_skid_exists         char(1);
  ls_consumed_coil_num         coil.consumed_coil_num%type;
  ls_customer_short_name       customer.customer_short_name%type;
  ll_sheet_skid_count_4coil    number(8);
  ll_total_act_scrap_wt_4job   number(8);
  ll_total_theo_scrap_wt_4job  number(8);
  ll_heavy_light               number(8);
  li_rtn                       number(1);

--------------------------------------------------------------------------------------------------   
------------------------------------ Cursors Begin -----------------------------------------------
--------------------------------------------------------------------------------------------------

  cursor coil_cur is
  select distinct process_coil.coil_abc_num
  from   process_coil
         left outer join production_sheet_item on production_sheet_item.coil_abc_num = process_coil.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    (
              sheet_skid.skid_sheet_status in (0, 2, 4, 13, 12, 16)
           or sheet_skid.skid_sheet_status is null --This is for rejected coils without sheets  
         )
  order by process_coil.coil_abc_num;
  
  coil_rec  coil_cur%ROWTYPE;
   
  --Cursor skid_coil_cur will select data for ab_job and coil_abc_num with skids.
  --If there is a reject coil without sheet skids, this cursor will not select it.
  cursor skid_coil_cur is
  select coil.coil_abc_num,   
         coil.lot_num,   
         coil.coil_org_num,   
         coil.coil_mid_num,
         nvl(coil.consumed_coil_num, ' ') consumed_coil,
         nvl(coil.material_num, ' ') material_num,
         coil.net_wt,   
         sheet_skid.sheet_tare_wt,   
         sheet_skid.sheet_net_wt,
         sheet_skid.skid_pieces,
         production_sheet_item.prod_item_pieces,
         production_sheet_item.prod_item_num,
         sheet_skid.skid_sheet_status,
         sheet_skid.sheet_skid_num,   
         production_sheet_item.prod_item_note,   
         sheet_skid.sheet_theoretical_wt,   
         production_sheet_item.prod_item_placement,   
         process_coil.process_quantity,   
         production_sheet_item.prod_item_net_wt,   
         sheet_skid.sheet_skid_display_num,
         nvl(customer_order.sales_order, ' ') sales_order,
         nvl(customer_order.orig_customer_po, 'NA') orig_customer_po,
         nvl(order_item.enduser_part_num, ' ') enduser_part_num,
         nvl(order_item.cust_prod_line_id, 'NA') cust_prod_line_id,
         nvl(order_item.finished_goods_material_num, 'NA') finished_goods_material_num,
         (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
         NULL done  
  from   coil   
         join process_coil on coil.coil_abc_num = process_coil.coil_abc_num
         join ab_job on ab_job.ab_job_num = process_coil.ab_job_num
         join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
         join customer_order on customer_order.order_abc_num = order_item.order_abc_num
         left outer join production_sheet_item on coil.coil_abc_num = production_sheet_item.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  ab_job.ab_job_num = al_ab_job_num
  and    coil.coil_abc_num = ll_cur_coil
  order by
         production_sheet_item.coil_abc_num,
         sheet_skid.sheet_skid_display_num;

  skid_coil_rec  skid_coil_cur%rowtype;
  
  cursor scrap_cur is
  select process_coil.coil_abc_num,
         process_coil.process_coil_status,
         process_coil.process_quantity,
         nvl(process_coil.process_end_wt, 0),
         sum(nvl(process_coil.process_end_wt, 0)),
         sum(nvl(production_sheet_item.prod_item_net_wt, 0)),
         case process_coil.process_coil_status
            when 7 then --Rebanded coils
               --(process_coil.process_quantity - sum(production_sheet_item.prod_item_net_wt) - (select process_end_wt from process_coil pc where pc.ab_job_num = 101143 and pc.coil_abc_num = process_coil.coil_abc_num))
               --(process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - nvl(process_coil.process_end_wt, 0)) --Alex Gerlants. Commented out on 12/15/2020
               (process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - nvl(f_get_coil_rebanded_wt(process_coil.coil_abc_num, process_coil.process_quantity), -99)) --Alex Gerlants. Added on 12/15/2020
            when 3 then --Rejected coils
               case (select count(*) from production_sheet_item psi where psi.ab_job_num = al_ab_job_num and psi.coil_abc_num = process_coil.coil_abc_num)
                 when 0 then --Rejected coils without sheets
                   (process_coil.process_quantity - sum(nvl(process_coil.process_end_wt, 0)))
                 else --Rejected coils with sheets
                   (process_coil.process_quantity - nvl(process_coil.process_end_wt, 0) - sum(nvl(production_sheet_item.prod_item_net_wt, 0)))     
                end   
             else
               (process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - sum(nvl(process_coil.process_end_wt, 0)))
         end scrap_net_wt
  from   process_coil
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         join ab_job on ab_job.ab_job_num = process_coil.ab_job_num and coil.coil_abc_num = process_coil.coil_abc_num
         left outer join production_sheet_item on production_sheet_item.ab_job_num = process_coil.ab_job_num and production_sheet_item.coil_abc_num = process_coil.coil_abc_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    coil.coil_abc_num = ll_cur_coil
  group by
         process_coil.coil_abc_num,
         process_coil.process_coil_status,
         process_coil.process_quantity,
         process_coil.process_end_wt
  order by
         process_coil.coil_abc_num;
         
  scrap_rec  scrap_cur%rowtype;
   
--------------------------------------------------------------------------------------------------   
------------------------------------- Cursors End ------------------------------------------------
--------------------------------------------------------------------------------------------------   

  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;

  TYPE coil_num_type IS TABLE OF coil.coil_abc_num%type INDEX BY BINARY_INTEGER;
  coil_num coil_num_type;
  p binary_integer :=0;
  
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;  

BEGIN
  
  --Check if correct customer
  select  customer_order.orig_customer_id,
          customer.customer_duns_number_string,
          customer.customer_short_name
  into    ll_customer_id,
          su_duns,
          ls_customer_short_name
  from    ab_job
          join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
          join customer on customer.customer_id = customer_order.orig_customer_id
  where   ab_job.ab_job_num = al_ab_job_num;
  
  if lower(ls_customer_short_name) not like '%novelis%' then
    return 200; --Wrong customer
  end if;
  
  --Check if 870 has already been created for al_ab_job_num
  select edi_file_id_870, edi_date_870
  into   ll_edi_file_id_870, ld_edi_date_870
  from   ab_job
  where  ab_job_num = al_ab_job_num;
   
  if not (ll_edi_file_id_870 is null and ld_edi_date_870 is null) then --870 already created for al_ab_job_num
    return 100;
  end if;

  i              := 0;
  k              := 0;
  p              := 0;
  
  select count(distinct process_coil.coil_abc_num)
  into   ll_rowcount
  from   process_coil
         left outer join production_sheet_item on production_sheet_item.coil_abc_num = process_coil.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    (
              sheet_skid.skid_sheet_status in (0, 2, 4, 13, 12, 16)
           or sheet_skid.skid_sheet_status is null --This is for rejected coils without sheets  
         );
    
  if ll_rowcount > 0 then

    select edi_st_log_seq.nextval into ll_st_log from dual;
    select edi_gs_log_seq.nextval into ll_gs_log from dual;
    
    /*
    select  customer_order.orig_customer_id
    into    ll_customer_id
    from    ab_job
            join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
    where   ab_job.ab_job_num = al_ab_job_num;
    
    select  customer.customer_duns_number_string
    into    su_duns
    from    customer
    where   customer.customer_id = ll_customer_id;
    */

    --Production
    x12_table(i) := 'ISA*00*' ||
                    '          *00*          *01*039630926T     *09*0015049350011G *' ||
                    ls_today_4 || '*' || ls_now || '*U*00401*' ||
                    lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
          
    --Development                
    --x12_table(i) := 'ISA*00*' ||
    --                '          *00*          *ZZ*2NDSFTP        *ZZ*NOVLSTEST      *' ||
    --                ls_today_4 || '*' || ls_now || '*U*00401*' ||
    --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';    
                         
    i := i + 1;
          
    --Production
    x12_table(i) := 'GS*RS*039630926T*' || '001504935001' || '*' ||
                    ls_today || '*' || ls_now || '*' ||
                    to_char(ll_gs_log) || '*X*' || '004010';
          
    --Development                
    --x12_table(i) := 'GS*RS*2NDSFTP*' || 'NOVLSTEST' || '*' ||
    --                ls_today || '*' || ls_now || '*' ||
    --                to_char(ll_gs_log) || '*X*' || '004010';
                          
    i := i + 1;
        
    x12_table(i) := 'ST*870*' || to_char(ll_st_log);
    i := i + 1;
    x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                    '***' || ls_now || '*****';
    i := i + 1;
    x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
    i := i + 1;
    x12_table(i) := 'N1*SU**1*' || su_duns;
    i := i + 1;
    x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926';
    i := i + 1;

    li_hl01 := 0;

    for coil_rec in coil_cur loop --Coil loop
       ll_cur_coil := coil_rec.coil_abc_num;
       ls_consumed_coil_num := to_char(skid_coil_rec.consumed_coil);
       --ls_sheet_skid_exists := 'n';
       
       select   consumed_coil_num
       into     ls_consumed_coil_num
       from     coil
       where    coil_abc_num = ll_cur_coil;
       
       select   count(*)
       into     ll_sheet_skid_count_4coil
       from     production_sheet_item
       where    ab_job_num = al_ab_job_num
       and      coil_abc_num = ll_cur_coil;
       
       coil_num(p) := ll_cur_coil;
       p := p + 1;

       select   coil.coil_org_num, coil.lot_num
       into     ls_coil_org_num, ls_heat
       from     coil
       where    coil.coil_abc_num = ll_cur_coil;
        
       --ls_sheet_skid_exists := 'n';

       for skid_coil_rec in skid_coil_cur loop --Skid_coil loop
           if skid_coil_rec.prod_item_net_wt > 0 then
             
              --ls_sheet_skid_exists := 'y';
              li_hl01 := li_hl01 + 1;

              x12_table(i) := 'HL*' || to_char(li_hl01) || '**I';
              i := i + 1;
            
              ls_po := skid_coil_rec.orig_customer_po;
              ls_cust_prod_line := skid_coil_rec.cust_prod_line_id;
              ls_finished_goods := skid_coil_rec.finished_goods_material_num;

              IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
                 x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
                 i := i + 1;
              END IF;

              x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
              i := i + 1;

              x12_table(i) := 'REF*SE*' || to_char(skid_coil_rec.prod_item_num);
              i := i + 1;


              x12_table(i) := 'REF*MI*' || to_char(al_ab_job_num);
              i := i + 1;

              x12_table(i) := 'REF*RV*' || to_char(skid_coil_rec.prod_item_num) ||
                              '*NA';
              i := i + 1;

              x12_table(i) := 'REF*IX*' || to_char(skid_coil_rec.consumed_coil);
              i := i + 1;

              x12_table(i) := 'PO1**1*UN****' || '***SN*' ||
                                ls_coil_org_num || '***VP*' || skid_coil_rec.finished_goods_material_num;
              i := i + 1;

              if skid_coil_rec.skid_sheet_status = 2 then
                x12_table(i) := 'PID*S*MA*ST*1*' ||
                                to_char(skid_coil_rec.sheet_skid_display_num);
                i := i + 1;
              elsif skid_coil_rec.skid_sheet_status = 4 then
                x12_table(i) := 'PID*S*MA*ST*3*' ||
                                to_char(skid_coil_rec.sheet_skid_display_num);
                i := i + 1;
              elsif skid_coil_rec.skid_sheet_status = 13 then
                x12_table(i) := 'PID*S*MA*ST*8*' ||
                                to_char(skid_coil_rec.sheet_skid_display_num);
                i := i + 1;
              else
                x12_table(i) := 'PID*S*MA*ST*4*' ||
                                to_char(skid_coil_rec.sheet_skid_display_num);
                i := i + 1;
              end if;

              x12_table(i) := 'PID*S*MAC*ST*01';
              i := i + 1;
              x12_table(i) := 'PID*S*PR*ST*19';
              i := i + 1;
              x12_table(i) := 'MEA*WT*N*' || to_char(skid_coil_rec.prod_item_net_wt) ||
                              '*LB*01';
              i := i + 1;
              x12_table(i) := 'MEA*WT*G*' || to_char(skid_coil_rec.skid_gross_wt) ||
                              '*LB*01';
              i := i + 1;
              x12_table(i) := 'MEA*CT*NA*' || to_char(skid_coil_rec.prod_item_pieces) ||
                              '*PC';
              i := i + 1;

              item_num(k) := skid_coil_rec.prod_item_num;
              k := k + 1;
           end if; --if skid_coil_rec.prod_item_net_wt > 0
        end loop; --for skid_coil_rec IN skid_coil_cur loop

        for scrap_rec in scrap_cur loop --Scrap loop
          ll_scrap_nw := scrap_rec.scrap_net_wt;

          if ll_scrap_nw > 0 then --Theo scrap weight
                   
             if ll_sheet_skid_count_4coil <= 0 then --ll_cur_coil is a fully scrapped (rejected) coil without good material
               li_rtn := f_edi_novelis_870_reject_4job(al_ab_job_num, ll_cur_coil, as_user_id, as_original_or_resend);
                     
               continue; --06/19/2020. bypass for fully scrapped coil.
                         --It is in a separate 870 created in f_edi_novelis_870_scrap_coil()
             end if;
                  
             ll_total_theo_scrap_wt_4job := 0;
                  
             select    nvl(sum(return_item_net_wt),0) 
             into      ll_total_act_scrap_wt_4job
             from      return_scrap_item
             where     ab_job_num = al_ab_job_num;

             li_hl01 := li_hl01 + 1;

             x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*I';
             i := i + 1;

             IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
                x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
                i := i + 1;
             END IF;

             x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
             i := i + 1;
                   
             x12_table(i) := 'PO1**1*UN****' || '***SN*' || ls_coil_org_num ;
             i := i + 1;

             x12_table(i) := 'PID*S*MA*ST*S';
             i := i + 1;

             x12_table(i) := 'PID*S*MAC*ST*05';
             i := i + 1;

             x12_table(i) := 'PID*S*PR*ST*19';
             i := i + 1;

             x12_table(i) := 'MEA*WT*N*' || to_char(ll_scrap_nw) || '*LB*01';
             i := i+1;
                   
             ll_total_theo_scrap_wt_4job := ll_total_theo_scrap_wt_4job + ll_scrap_nw;
                   
           end if; --if ll_scrap_nw > 0 then
        end loop; --for scrap_rec in alcan_scrap_870_cur loop scrap loop
              
          ll_heavy_light := ll_total_act_scrap_wt_4job - ll_total_theo_scrap_wt_4job;
            
        --end if; --if (ld_scrap_870_date is null) then --Scrap not sent
    end loop; --for coil_rec in coil_cur loop. Coil loop
    
    x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
    i := i + 1;

    x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
    i := i + 1;

    x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
    i := i + 1;

    x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

    -- Write EDI to file

    if li_hl01 > 0 then
        -- WRITE EDI FILE ONLY IF ITEM > 0
        SELECT edi_file_id_seq.nextval
          INTO ll_edi_file_id_870
          FROM dual;
        edi_file        := edi_file_prefix || to_char(ll_edi_file_id_870) || '_Job-' || to_char(al_ab_job_num) || '.edi';
     -- edi_file        := 's_alcan_' || to_char(ll_edi_file_id_870) || '.870';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        FOR j IN 0 .. i LOOP
          utl_file.put_line(edi_file_handle, x12_table(j));

        END LOOP;
        utl_file.fclose(edi_file_handle);
      --END IF; -- END WRITING EDI FILE

      --edi_file        := 'send_edi_log'; /* Alex Gerlants. 04/14/2017. Commented out. */
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      --For verifying 997
      /*
      INSERT INTO outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
        VALUES
          (ll_edi_file_id_870,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           SYSDATE,
           edi_file,
           0,
           ll_customer_id,
           ll_st_log,
           '870');

        
        update    ab_job
        set       edi_file_id_870 = ll_edi_file_id_870,
                  edi_date_870 = sysdate
        where     ab_job_num = al_ab_job_num;
          
       insert into ab_job_870_history
        (
           ab_job_num,
           edi_file_id,
           edi_file_name,
           create_870_date_time,
           user_id,
           notes
        )
        values
        (
           al_ab_job_num ,
           ll_edi_file_id_870,
           edi_file,
           sysdate,
           as_user_id,
           as_original_or_resend
        );

        for m in 0 .. k - 1 loop
           update   production_sheet_item
           set      prod_item_edi870_date = sysdate,
                    edi_file_id_870 = ll_edi_file_id_870 
           where    production_sheet_item.prod_item_num = item_num(m);
        end loop;

        for m in 0..p - 1 loop
           update   coil
           set      coil.scrap_870_date = sysdate
           where    coil.coil_abc_num = coil_num(m);

           update   process_coil
           set      scrap_870_date = sysdate
           where    ( coil_abc_num = coil_num(m)) and (scrap_870_date is null);

         end loop;
         */

         commit;
      END IF; -- END WRITING EDI FILE

  end if; --end if in select count(*)

  --END LOOP; ------ End of outer loop customer_id

/*
EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN -1;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN -2;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN -3;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN -4;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN -9;
*/
    
  return 1;
end f_edi_novelis_870_4job_120920;
--------------------------------------------------------
--  DDL for Function F_EDI_NOVELIS_870_4JOB_4SCRAP
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_NOVELIS_870_4JOB_4SCRAP" 
 ( 
    al_ab_job_num           ab_job.ab_job_num%type,
    as_user_id              ab_job_870_history.user_id%type,
    as_original_or_resend   varchar2
    
 )
  return integer
  
is

  /*
  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc                varchar2(50) := get_edi_destination('EDI_DIR');

  edi_file                     varchar2(50) := 'edi_out.txt';
  edi_file_prefix              varchar2(50) := 's_novelis_870_'; --production
  --edi_file_prefix              varchar2(50) := 's_novelis_870_'; --development
  edi_file_handle              utl_file.file_type;
  su_duns                      varchar2(10);
  ll_customer_id               customer.customer_id%type;
  ll_cur_coil                  coil.coil_abc_num%type;
  ll_gs_log                    integer;
  ll_st_log                    integer;
  ls_today                     varchar2(20) := to_char(sysdate, 'YYYYMMDD');
  ls_today_4                   varchar2(20) := to_char(sysdate, 'YYMMDD');
  ls_now                       varchar2(20) := to_char(sysdate, 'HH24MI');
  ls_po                        varchar2(20);
  ls_finished_goods            varchar2(32);
  ls_cust_prod_line            varchar2(8);
  ld_scrap_870_date            process_coil.scrap_870_date%type;
  ls_coil_org_num              coil.coil_org_num%type;
  ls_heat                      coil.lot_num%type;
  ll_prime_nw                  coil.net_wt%type;
  ll_scrap_nw                  coil.net_wt%type;
  ll_item_count                integer;
  li_hl01                      integer;
  li_hllin                     integer;
  ll_rowcount                  number(8);
  ll_edi_file_id_870           integer;
  ld_edi_date_870              ab_job.edi_date_870%type;
  --ls_sheet_skid_exists         char(1);
  ls_consumed_coil_num         coil.consumed_coil_num%type;
  ls_customer_short_name       customer.customer_short_name%type;
  ll_sheet_skid_count_4coil    number(8);
  ll_total_act_scrap_wt_4job   number(8);
  ll_total_theo_scrap_wt_4job  number(8);
  ll_heavy_light               number(8);
  li_rtn                       number(1);

--------------------------------------------------------------------------------------------------   
------------------------------------ Cursors Begin -----------------------------------------------
--------------------------------------------------------------------------------------------------

  cursor coil_cur is
  select distinct process_coil.coil_abc_num
  from   process_coil
         left outer join production_sheet_item on production_sheet_item.coil_abc_num = process_coil.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    (
              sheet_skid.skid_sheet_status in (0, 2, 4, 13, 12, 16)
           or sheet_skid.skid_sheet_status is null --This is for rejected coils without sheets  
         )
  order by process_coil.coil_abc_num;
  
  coil_rec  coil_cur%ROWTYPE;
   
  --Cursor skid_coil_cur will select data for ab_job and coil_abc_num with skids.
  --If there is a reject coil without sheet skids, this cursor will not select it.
  cursor skid_coil_cur is
  select coil.coil_abc_num,   
         coil.lot_num,   
         coil.coil_org_num,   
         coil.coil_mid_num,
         nvl(coil.consumed_coil_num, ' ') consumed_coil,
         nvl(coil.material_num, ' ') material_num,
         coil.net_wt,   
         sheet_skid.sheet_tare_wt,   
         sheet_skid.sheet_net_wt,
         sheet_skid.skid_pieces,
         production_sheet_item.prod_item_pieces,
         production_sheet_item.prod_item_num,
         sheet_skid.skid_sheet_status,
         sheet_skid.sheet_skid_num,   
         production_sheet_item.prod_item_note,   
         sheet_skid.sheet_theoretical_wt,   
         production_sheet_item.prod_item_placement,   
         process_coil.process_quantity,   
         production_sheet_item.prod_item_net_wt,   
         sheet_skid.sheet_skid_display_num,
         nvl(customer_order.sales_order, ' ') sales_order,
         nvl(customer_order.orig_customer_po, 'NA') orig_customer_po,
         nvl(order_item.enduser_part_num, ' ') enduser_part_num,
         nvl(order_item.cust_prod_line_id, 'NA') cust_prod_line_id,
         nvl(order_item.finished_goods_material_num, 'NA') finished_goods_material_num,
         (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
         NULL done  
  from   coil   
         join process_coil on coil.coil_abc_num = process_coil.coil_abc_num
         join ab_job on ab_job.ab_job_num = process_coil.ab_job_num
         join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
         join customer_order on customer_order.order_abc_num = order_item.order_abc_num
         left outer join production_sheet_item on coil.coil_abc_num = production_sheet_item.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  ab_job.ab_job_num = al_ab_job_num
  and    coil.coil_abc_num = ll_cur_coil
  order by
         production_sheet_item.coil_abc_num,
         sheet_skid.sheet_skid_display_num;

  skid_coil_rec  skid_coil_cur%rowtype;
  
  cursor scrap_cur is
  select process_coil.coil_abc_num,
         process_coil.process_coil_status,
         process_coil.process_quantity,
         nvl(process_coil.process_end_wt, 0),
         sum(nvl(process_coil.process_end_wt, 0)),
         sum(nvl(production_sheet_item.prod_item_net_wt, 0)),
         case process_coil.process_coil_status
            when 7 then --Rebanded coils
               --(process_coil.process_quantity - sum(production_sheet_item.prod_item_net_wt) - (select process_end_wt from process_coil pc where pc.ab_job_num = 101143 and pc.coil_abc_num = process_coil.coil_abc_num))
               (process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - nvl(process_coil.process_end_wt, 0))
            when 3 then --Rejected coils
               case (select count(*) from production_sheet_item psi where psi.ab_job_num = al_ab_job_num and psi.coil_abc_num = process_coil.coil_abc_num)
                 when 0 then --Rejected coils without sheets
                   (process_coil.process_quantity - sum(nvl(process_coil.process_end_wt, 0)))
                 else --Rejected coils with sheets
                   (process_coil.process_quantity - nvl(process_coil.process_end_wt, 0) - sum(nvl(production_sheet_item.prod_item_net_wt, 0)))     
                end   
             else
               (process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - sum(nvl(process_coil.process_end_wt, 0)))
         end scrap_net_wt
  from   process_coil
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         join ab_job on ab_job.ab_job_num = process_coil.ab_job_num and coil.coil_abc_num = process_coil.coil_abc_num
         left outer join production_sheet_item on production_sheet_item.ab_job_num = process_coil.ab_job_num and production_sheet_item.coil_abc_num = process_coil.coil_abc_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    coil.coil_abc_num = ll_cur_coil
  group by
         process_coil.coil_abc_num,
         process_coil.process_coil_status,
         process_coil.process_quantity,
         process_coil.process_end_wt
  order by
         process_coil.coil_abc_num;
         
  scrap_rec  scrap_cur%rowtype;
   
--------------------------------------------------------------------------------------------------   
------------------------------------- Cursors End ------------------------------------------------
--------------------------------------------------------------------------------------------------   

  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;

  TYPE coil_num_type IS TABLE OF coil.coil_abc_num%type INDEX BY BINARY_INTEGER;
  coil_num coil_num_type;
  p binary_integer :=0;
  
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;  

BEGIN
  
  --Check if correct customer
  select  customer_order.orig_customer_id,
          customer.customer_duns_number_string,
          customer.customer_short_name
  into    ll_customer_id,
          su_duns,
          ls_customer_short_name
  from    ab_job
          join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
          join customer on customer.customer_id = customer_order.orig_customer_id
  where   ab_job.ab_job_num = al_ab_job_num;
  
  if lower(ls_customer_short_name) not like '%novelis%' then
    return 200; --Wrong customer
  end if;
  
  --Check if 870 has already been created for al_ab_job_num
  select edi_file_id_870, edi_date_870
  into   ll_edi_file_id_870, ld_edi_date_870
  from   ab_job
  where  ab_job_num = al_ab_job_num;
   
  if not (ll_edi_file_id_870 is null and ld_edi_date_870 is null) then --870 already created for al_ab_job_num
    return 100;
  end if;

  i              := 0;
  k              := 0;
  p              := 0;
  
  select count(distinct process_coil.coil_abc_num)
  into   ll_rowcount
  from   process_coil
         left outer join production_sheet_item on production_sheet_item.coil_abc_num = process_coil.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    (
              sheet_skid.skid_sheet_status in (0, 2, 4, 13, 12, 16)
           or sheet_skid.skid_sheet_status is null --This is for rejected coils without sheets  
         );
    
  if ll_rowcount > 0 then

    select edi_st_log_seq.nextval into ll_st_log from dual;
    select edi_gs_log_seq.nextval into ll_gs_log from dual;
    
    /*
    select  customer_order.orig_customer_id
    into    ll_customer_id
    from    ab_job
            join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
    where   ab_job.ab_job_num = al_ab_job_num;
    
    select  customer.customer_duns_number_string
    into    su_duns
    from    customer
    where   customer.customer_id = ll_customer_id;
    */

    --Production
    x12_table(i) := 'ISA*00*' ||
                    '          *00*          *01*039630926T     *09*0015049350011G *' ||
                    ls_today_4 || '*' || ls_now || '*U*00401*' ||
                    lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';
          
    --Development                
    --x12_table(i) := 'ISA*00*' ||
    --                '          *00*          *ZZ*2NDSFTP        *ZZ*NOVLSTEST      *' ||
    --                ls_today_4 || '*' || ls_now || '*U*00401*' ||
    --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';    
                         
    i := i + 1;
          
    --Production
    x12_table(i) := 'GS*RS*039630926T*' || '001504935001' || '*' ||
                    ls_today || '*' || ls_now || '*' ||
                    to_char(ll_gs_log) || '*X*' || '004010';
          
    --Development                
    --x12_table(i) := 'GS*RS*2NDSFTP*' || 'NOVLSTEST' || '*' ||
    --                ls_today || '*' || ls_now || '*' ||
    --                to_char(ll_gs_log) || '*X*' || '004010';
                          
    i := i + 1;
        
    x12_table(i) := 'ST*870*' || to_char(ll_st_log);
    i := i + 1;
    x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                    '***' || ls_now || '*****';
    i := i + 1;
    x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
    i := i + 1;
    x12_table(i) := 'N1*SU**1*' || su_duns;
    i := i + 1;
    x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926';
    i := i + 1;

    li_hl01 := 0;

    for coil_rec in coil_cur loop --Coil loop
       ll_cur_coil := coil_rec.coil_abc_num;
       ls_consumed_coil_num := to_char(skid_coil_rec.consumed_coil);
       --ls_sheet_skid_exists := 'n';
       
       select   consumed_coil_num
       into     ls_consumed_coil_num
       from     coil
       where    coil_abc_num = ll_cur_coil;
       
       select   count(*)
       into     ll_sheet_skid_count_4coil
       from     production_sheet_item
       where    ab_job_num = al_ab_job_num
       and      coil_abc_num = ll_cur_coil;
       
       coil_num(p) := ll_cur_coil;
       p := p + 1;

       select   coil.coil_org_num, coil.lot_num
       into     ls_coil_org_num, ls_heat
       from     coil
       where    coil.coil_abc_num = ll_cur_coil;
        
       --ls_sheet_skid_exists := 'n';
       
     
       for skid_coil_rec in skid_coil_cur loop --Skid_coil loop
           if skid_coil_rec.prod_item_net_wt > 0 then
             
              --ls_sheet_skid_exists := 'y';
              li_hl01 := li_hl01 + 1;

              x12_table(i) := 'HL*' || to_char(li_hl01) || '**I';
              i := i + 1;
            
              ls_po := skid_coil_rec.orig_customer_po;
              ls_cust_prod_line := skid_coil_rec.cust_prod_line_id;
              ls_finished_goods := skid_coil_rec.finished_goods_material_num;

              IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
                 x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
                 i := i + 1;
              END IF;

              x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
              i := i + 1;

              x12_table(i) := 'REF*SE*' || to_char(skid_coil_rec.prod_item_num);
              i := i + 1;


              x12_table(i) := 'REF*MI*' || to_char(al_ab_job_num);
              i := i + 1;

              x12_table(i) := 'REF*RV*' || to_char(skid_coil_rec.prod_item_num) ||
                              '*NA';
              i := i + 1;

              x12_table(i) := 'REF*IX*' || to_char(skid_coil_rec.consumed_coil);
              i := i + 1;

              x12_table(i) := 'PO1**1*UN****' || '***SN*' ||
                                ls_coil_org_num || '***VP*' || skid_coil_rec.finished_goods_material_num;
              i := i + 1;

              if skid_coil_rec.skid_sheet_status = 2 then
                x12_table(i) := 'PID*S*MA*ST*1*' ||
                                to_char(skid_coil_rec.sheet_skid_display_num);
                i := i + 1;
              elsif skid_coil_rec.skid_sheet_status = 4 then
                x12_table(i) := 'PID*S*MA*ST*3*' ||
                                to_char(skid_coil_rec.sheet_skid_display_num);
                i := i + 1;
              elsif skid_coil_rec.skid_sheet_status = 13 then
                x12_table(i) := 'PID*S*MA*ST*8*' ||
                                to_char(skid_coil_rec.sheet_skid_display_num);
                i := i + 1;
              else
                x12_table(i) := 'PID*S*MA*ST*4*' ||
                                to_char(skid_coil_rec.sheet_skid_display_num);
                i := i + 1;
              end if;

              x12_table(i) := 'PID*S*MAC*ST*01';
              i := i + 1;
              x12_table(i) := 'PID*S*PR*ST*19';
              i := i + 1;
              x12_table(i) := 'MEA*WT*N*' || to_char(skid_coil_rec.prod_item_net_wt) ||
                              '*LB*01';
              i := i + 1;
              x12_table(i) := 'MEA*WT*G*' || to_char(skid_coil_rec.skid_gross_wt) ||
                              '*LB*01';
              i := i + 1;
              x12_table(i) := 'MEA*CT*NA*' || to_char(skid_coil_rec.prod_item_pieces) ||
                              '*PC';
              i := i + 1;

              item_num(k) := skid_coil_rec.prod_item_num;
              k := k + 1;
           end if; --if skid_coil_rec.prod_item_net_wt > 0
        end loop; --for skid_coil_rec IN skid_coil_cur loop
        

        for scrap_rec in scrap_cur loop --Scrap loop
          ll_scrap_nw := scrap_rec.scrap_net_wt;

          if ll_scrap_nw > 0 then --Theo scrap weight
                   
             if ll_sheet_skid_count_4coil <= 0 then --ll_cur_coil is a fully scrapped (rejected) coil without good material
               li_rtn := f_edi_novelis_870_reject_4job(al_ab_job_num, ll_cur_coil, as_user_id, as_original_or_resend);
                     
               continue; --06/19/2020. bypass for fully scrapped coil.
                         --It is in a separate 870 created in f_edi_novelis_870_scrap_coil()
             end if;
                  
             ll_total_theo_scrap_wt_4job := 0;
                  
             select    nvl(sum(return_item_net_wt),0) 
             into      ll_total_act_scrap_wt_4job
             from      return_scrap_item
             where     ab_job_num = al_ab_job_num;

             li_hl01 := li_hl01 + 1;

             x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*I';
             i := i + 1;

             IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
                x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
                i := i + 1;
             END IF;

             x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
             i := i + 1;
                   
             x12_table(i) := 'PO1**1*UN****' || '***SN*' || ls_coil_org_num ;
             i := i + 1;

             x12_table(i) := 'PID*S*MA*ST*S';
             i := i + 1;

             x12_table(i) := 'PID*S*MAC*ST*05';
             i := i + 1;

             x12_table(i) := 'PID*S*PR*ST*19';
             i := i + 1;

             x12_table(i) := 'MEA*WT*N*' || to_char(ll_scrap_nw) || '*LB*01';
             i := i+1;
                   
             ll_total_theo_scrap_wt_4job := ll_total_theo_scrap_wt_4job + ll_scrap_nw;
                   
           end if; --if ll_scrap_nw > 0 then
        end loop; --for scrap_rec in alcan_scrap_870_cur loop scrap loop
              
          ll_heavy_light := ll_total_act_scrap_wt_4job - ll_total_theo_scrap_wt_4job;
            
        --end if; --if (ld_scrap_870_date is null) then --Scrap not sent
    end loop; --for coil_rec in coil_cur loop. Coil loop
    
    x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
    i := i + 1;

    x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
    i := i + 1;

    x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
    i := i + 1;

    x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

    -- Write EDI to file

    if li_hl01 > 0 then
        -- WRITE EDI FILE ONLY IF ITEM > 0
        SELECT edi_file_id_seq.nextval
          INTO ll_edi_file_id_870
          FROM dual;
        edi_file        := edi_file_prefix || to_char(ll_edi_file_id_870) || '_Job-' || to_char(al_ab_job_num) || '.edi';
     -- edi_file        := 's_alcan_' || to_char(ll_edi_file_id_870) || '.870';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        FOR j IN 0 .. i LOOP
          utl_file.put_line(edi_file_handle, x12_table(j));

        END LOOP;
        utl_file.fclose(edi_file_handle);
      --END IF; -- END WRITING EDI FILE

      --edi_file        := 'send_edi_log'; /* Alex Gerlants. 04/14/2017. Commented out. */
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      --For verifying 997
      INSERT INTO outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
        VALUES
          (ll_edi_file_id_870,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           SYSDATE,
           edi_file,
           0,
           ll_customer_id,
           ll_st_log,
           '870');


        update    ab_job
        set       edi_file_id_870 = ll_edi_file_id_870,
                  edi_date_870 = sysdate
        where     ab_job_num = al_ab_job_num;
          
       insert into ab_job_870_history
        (
           ab_job_num,
           edi_file_id,
           edi_file_name,
           create_870_date_time,
           user_id,
           notes
        )
        values
        (
           al_ab_job_num ,
           ll_edi_file_id_870,
           edi_file,
           sysdate,
           as_user_id,
           as_original_or_resend
        );

        for m in 0 .. k - 1 loop
           update   production_sheet_item
           set      prod_item_edi870_date = sysdate,
                    edi_file_id_870 = ll_edi_file_id_870 
           where    production_sheet_item.prod_item_num = item_num(m);
        end loop;

        for m in 0..p - 1 loop
           update   coil
           set      coil.scrap_870_date = sysdate
           where    coil.coil_abc_num = coil_num(m);

           update   process_coil
           set      scrap_870_date = sysdate
           where    ( coil_abc_num = coil_num(m)) and (scrap_870_date is null);

         end loop;

         commit;
      END IF; -- END WRITING EDI FILE

  end if; --end if in select count(*)

  --END LOOP; ------ End of outer loop customer_id

/*
EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN -1;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN -2;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN -3;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN -4;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN -9;
*/
    
  return 1;
end f_edi_novelis_870_4job_4scrap;
--------------------------------------------------------
--  DDL for Function F_EDI_NOVELIS_870_4JOB_RESEND
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_NOVELIS_870_4JOB_RESEND" 
 ( 
    al_ab_job_num           ab_job.ab_job_num%type,
    as_user_id              ab_job_870_history.user_id%type,
    as_original_or_resend   varchar2
    
 )
  return integer
  
is

  /*
  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc                varchar2(50) := get_edi_destination('EDI_DIR');

  edi_file                     varchar2(50) := 'edi_out.txt';
  edi_file_prefix              varchar2(50) := 'S_novelis_870_'; --production
  --edi_file_prefix              varchar2(50) := 's_novelis_870_'; --development
  edi_file_handle              utl_file.file_type;
  su_duns                      varchar2(10);
  ll_customer_id               customer.customer_id%type;
  ll_cur_coil                  coil.coil_abc_num%type;
  ll_gs_log                    integer;
  ll_st_log                    integer;
  ls_today                     varchar2(20) := to_char(sysdate, 'YYYYMMDD');
  ls_today_4                   varchar2(20) := to_char(sysdate, 'YYMMDD');
  ls_now                       varchar2(20) := to_char(sysdate, 'HH24MI');
  ls_po                        varchar2(20);
  ls_finished_goods            varchar2(32);
  ls_cust_prod_line            varchar2(8);
  ld_scrap_870_date            process_coil.scrap_870_date%type;
  ls_coil_org_num              coil.coil_org_num%type;
  ls_heat                      coil.lot_num%type;
  ll_prime_nw                  coil.net_wt%type;
  ll_scrap_nw                  coil.net_wt%type;
  ll_item_count                integer;
  li_hl01                      integer;
  li_hllin                     integer;
  ll_rowcount                  number(8);
  ll_edi_file_id_870           integer;
  ld_edi_date_870              ab_job.edi_date_870%type;
  --ls_sheet_skid_exists         char(1);
  ls_consumed_coil_num         coil.consumed_coil_num%type;
  ls_customer_short_name       customer.customer_short_name%type;
  ll_sheet_skid_count_4coil    number(8);
  ll_total_act_scrap_wt_4job   number(8);
  ll_total_theo_scrap_wt_4job  number(8);
  ll_heavy_light               number(8);
  li_rtn                       number(4); --Alex Gerlants. Changed from number(1) to number(4)
  ll_psi_870_count             number(3); --Alex Gerlants. 01/08/2021
  ll_coil_870_count            number(3); --Alex Gerlants. 01/08/2021
  ll_process_coil_870_count    number(3); --Alex Gerlants. 01/08/2021

--------------------------------------------------------------------------------------------------   
------------------------------------ Cursors Begin -----------------------------------------------
--------------------------------------------------------------------------------------------------

  cursor coil_cur is
  select distinct process_coil.coil_abc_num
  from   process_coil
         left outer join production_sheet_item on production_sheet_item.coil_abc_num = process_coil.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    (
              sheet_skid.skid_sheet_status in (0, 2, 4, 13, 12, 16)
           or sheet_skid.skid_sheet_status is null --This is for rejected coils without sheets  
         )
  order by process_coil.coil_abc_num;
  
  coil_rec  coil_cur%ROWTYPE;
   
  --Cursor skid_coil_cur will select data for ab_job and coil_abc_num with skids.
  --If there is a reject coil without sheet skids, this cursor will not select it.
  cursor skid_coil_cur is
  select coil.coil_abc_num,   
         coil.lot_num,   
         coil.coil_org_num,   
         coil.coil_mid_num,
         nvl(coil.consumed_coil_num, ' ') consumed_coil,
         nvl(coil.material_num, ' ') material_num,
         coil.net_wt,   
         sheet_skid.sheet_tare_wt,   
         sheet_skid.sheet_net_wt,
         sheet_skid.skid_pieces,
         production_sheet_item.prod_item_pieces,
         production_sheet_item.prod_item_num,
         sheet_skid.skid_sheet_status,
         sheet_skid.sheet_skid_num,   
         production_sheet_item.prod_item_note,   
         sheet_skid.sheet_theoretical_wt,   
         production_sheet_item.prod_item_placement,   
         process_coil.process_quantity,   
         production_sheet_item.prod_item_net_wt,   
         sheet_skid.sheet_skid_display_num,
         nvl(customer_order.sales_order, ' ') sales_order,
         nvl(customer_order.orig_customer_po, 'NA') orig_customer_po,
         nvl(order_item.enduser_part_num, ' ') enduser_part_num,
         nvl(order_item.cust_prod_line_id, 'NA') cust_prod_line_id,
         nvl(order_item.finished_goods_material_num, 'NA') finished_goods_material_num,
         (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
         NULL done  
  from   coil   
         join process_coil on coil.coil_abc_num = process_coil.coil_abc_num
         join ab_job on ab_job.ab_job_num = process_coil.ab_job_num
         join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
         join customer_order on customer_order.order_abc_num = order_item.order_abc_num
         left outer join production_sheet_item on coil.coil_abc_num = production_sheet_item.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  ab_job.ab_job_num = al_ab_job_num
  and    coil.coil_abc_num = ll_cur_coil
  order by
         production_sheet_item.coil_abc_num,
         sheet_skid.sheet_skid_display_num;

  skid_coil_rec  skid_coil_cur%rowtype;
  
  cursor scrap_cur is
  select process_coil.coil_abc_num,
         process_coil.process_coil_status,
         process_coil.process_quantity,
         nvl(process_coil.process_end_wt, 0),
         sum(nvl(process_coil.process_end_wt, 0)),
         sum(nvl(production_sheet_item.prod_item_net_wt, 0)),
         case process_coil.process_coil_status
            when 7 then --Rebanded coils
               --(process_coil.process_quantity - sum(production_sheet_item.prod_item_net_wt) - (select process_end_wt from process_coil pc where pc.ab_job_num = 101143 and pc.coil_abc_num = process_coil.coil_abc_num))
               --(process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - nvl(process_coil.process_end_wt, 0)) --Alex Gerlants. Commented out on 12/15/2020
               (process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - nvl(f_get_coil_rebanded_wt(process_coil.coil_abc_num, process_coil.process_quantity), -99)) --Alex Gerlants. Added on 12/15/2020
            when 3 then --Rejected coils
               case (select count(*) from production_sheet_item psi where psi.ab_job_num = al_ab_job_num and psi.coil_abc_num = process_coil.coil_abc_num)
                 when 0 then --Rejected coils without sheets
                   (process_coil.process_quantity - sum(nvl(process_coil.process_end_wt, 0)))
                 else --Rejected coils with sheets
                   (process_coil.process_quantity - nvl(process_coil.process_end_wt, 0) - sum(nvl(production_sheet_item.prod_item_net_wt, 0)))     
                end   
             else
               (process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - sum(nvl(process_coil.process_end_wt, 0)))
         end scrap_net_wt
  from   process_coil
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         join ab_job on ab_job.ab_job_num = process_coil.ab_job_num and coil.coil_abc_num = process_coil.coil_abc_num
         left outer join production_sheet_item on production_sheet_item.ab_job_num = process_coil.ab_job_num and production_sheet_item.coil_abc_num = process_coil.coil_abc_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    coil.coil_abc_num = ll_cur_coil
  group by
         process_coil.coil_abc_num,
         process_coil.process_coil_status,
         process_coil.process_quantity,
         process_coil.process_end_wt
  order by
         process_coil.coil_abc_num;
         
  scrap_rec  scrap_cur%rowtype;
   
--------------------------------------------------------------------------------------------------   
------------------------------------- Cursors End ------------------------------------------------
--------------------------------------------------------------------------------------------------   

  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;

  TYPE coil_num_type IS TABLE OF coil.coil_abc_num%type INDEX BY BINARY_INTEGER;
  coil_num coil_num_type;
  p binary_integer :=0;
  
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;  

BEGIN
  
  --Check if correct customer
  select  customer_order.orig_customer_id,
          customer.customer_duns_number_string,
          customer.customer_short_name
  into    ll_customer_id,
          su_duns,
          ls_customer_short_name
  from    ab_job
          join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
          join customer on customer.customer_id = customer_order.orig_customer_id
  where   ab_job.ab_job_num = al_ab_job_num;
  
  if lower(ls_customer_short_name) not like '%novelis%' then
    return 200; --Wrong customer
  end if;
  
  --Check if 870 has already been created for al_ab_job_num
  select edi_file_id_870, edi_date_870
  into   ll_edi_file_id_870, ld_edi_date_870
  from   ab_job
  where  ab_job_num = al_ab_job_num;
  
  --Alex Gerlants. 01/08/2021
  --Added this check to avoid sending 870 for jobs that had 870 created by the old batch processing.
  --Check if 870 has already been created for al_ab_job_num using the old data fields
  select count(distinct prod_item_edi870_date)
  into   ll_psi_870_count
  from   production_sheet_item
  where  ab_job_num = al_ab_job_num
  and    prod_item_edi870_date is not null;
  
  --Alex Gerlants. 02/19/2021. Comment out Begin
  --In case of more than 1 job for the same coil, this script updates process_coil and coil
  --for the first job.
  --When the second job for this coil, tries to run this script to create 870, 
  --it returns 100 - 870 already created
  --Checking table production_sheet_item is sufficient to prevent 870 creation for jobs that had 870 
  --created by the old batch processing.

  /* 
  select count(distinct scrap_870_date)
  into   ll_process_coil_870_count
  from   process_coil
  where  ab_job_num = al_ab_job_num
  and    scrap_870_date is not null;
  
  select count(distinct scrap_870_date)
  into   ll_coil_870_count
  from   coil
  where  coil_abc_num in
  (
      select   distinct coil_abc_num
      from     process_coil
      where    ab_job_num = al_ab_job_num
  )
  and    scrap_870_date is not null;
  */
  --Alex Gerlants. 02/19/2021. Comment out End
  
  --Alex Gerlants. 01/08/2021. Added " or ll_psi_870_count > 0 or ll_process_coil_870_count > 0 or ll_coil_870_count > 0"
  --Alex Gerlants. 02/19/2021. Removed "or ll_process_coil_870_count > 0 or ll_coil_870_count > 0"
  --Please see explanation above.
  if (not (ll_edi_file_id_870 is null and ld_edi_date_870 is null)) or ll_psi_870_count > 0 then --870 already created for al_ab_job_num
    return 100;
  end if;

  i              := 0;
  k              := 0;
  p              := 0;
  
  select count(distinct process_coil.coil_abc_num)
  into   ll_rowcount
  from   process_coil
         left outer join production_sheet_item on production_sheet_item.coil_abc_num = process_coil.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    (
              sheet_skid.skid_sheet_status in (0, 2, 4, 13, 12, 16)
           or sheet_skid.skid_sheet_status is null --This is for rejected coils without sheets  
         );
    
  if ll_rowcount > 0 then

    select edi_st_log_seq.nextval into ll_st_log from dual;
    select edi_gs_log_seq.nextval into ll_gs_log from dual;
    
    /*
    select  customer_order.orig_customer_id
    into    ll_customer_id
    from    ab_job
            join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
    where   ab_job.ab_job_num = al_ab_job_num;
    
    select  customer.customer_duns_number_string
    into    su_duns
    from    customer
    where   customer.customer_id = ll_customer_id;
    */

    --Production
    x12_table(i) := 'ISA*00*' ||
                    '          *00*          *01*039630926T     *09*0015049350011G *' ||
                    ls_today_4 || '*' || ls_now || '*U*00401*' ||
                    lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
          
    --Development                
    --x12_table(i) := 'ISA*00*' ||
    --                '          *00*          *ZZ*2NDSFTP        *ZZ*NOVLSTEST      *' ||
    --                ls_today_4 || '*' || ls_now || '*U*00401*' ||
    --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';    
                         
    i := i + 1;
          
    --Production
    x12_table(i) := 'GS*RS*039630926T*' || '001504935001' || '*' ||
                    ls_today || '*' || ls_now || '*' ||
                    to_char(ll_gs_log) || '*X*' || '004010';
          
    --Development                
    --x12_table(i) := 'GS*RS*2NDSFTP*' || 'NOVLSTEST' || '*' ||
    --                ls_today || '*' || ls_now || '*' ||
    --                to_char(ll_gs_log) || '*X*' || '004010';
                          
    i := i + 1;
        
    x12_table(i) := 'ST*870*' || to_char(ll_st_log);
    i := i + 1;
    x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                    '***' || ls_now || '*****';
    i := i + 1;
    x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
    i := i + 1;
    x12_table(i) := 'N1*SU**1*' || su_duns;
    i := i + 1;
    x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926';
    i := i + 1;

    li_hl01 := 0;

    for coil_rec in coil_cur loop --Coil loop
       ll_cur_coil := coil_rec.coil_abc_num;
       ls_consumed_coil_num := to_char(skid_coil_rec.consumed_coil);
       --ls_sheet_skid_exists := 'n';
       
       select   consumed_coil_num
       into     ls_consumed_coil_num
       from     coil
       where    coil_abc_num = ll_cur_coil;
       
       select   count(*)
       into     ll_sheet_skid_count_4coil
       from     production_sheet_item
       where    ab_job_num = al_ab_job_num
       and      coil_abc_num = ll_cur_coil;
       
       coil_num(p) := ll_cur_coil;
       p := p + 1;

       select   coil.coil_org_num, coil.lot_num
       into     ls_coil_org_num, ls_heat
       from     coil
       where    coil.coil_abc_num = ll_cur_coil;
        
       --ls_sheet_skid_exists := 'n';

       for skid_coil_rec in skid_coil_cur loop --Skid_coil loop
           if skid_coil_rec.prod_item_net_wt > 0 then
             
              --ls_sheet_skid_exists := 'y';
              li_hl01 := li_hl01 + 1;

              x12_table(i) := 'HL*' || to_char(li_hl01) || '**I';
              i := i + 1;
            
              ls_po := skid_coil_rec.orig_customer_po;
              ls_cust_prod_line := skid_coil_rec.cust_prod_line_id;
              ls_finished_goods := skid_coil_rec.finished_goods_material_num;

              IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
                 x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
                 i := i + 1;
              END IF;

              x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
              i := i + 1;

              x12_table(i) := 'REF*SE*' || to_char(skid_coil_rec.prod_item_num);
              i := i + 1;


              x12_table(i) := 'REF*MI*' || to_char(al_ab_job_num);
              i := i + 1;

              x12_table(i) := 'REF*RV*' || to_char(skid_coil_rec.prod_item_num) ||
                              '*NA';
              i := i + 1;

              x12_table(i) := 'REF*IX*' || to_char(skid_coil_rec.consumed_coil);
              i := i + 1;

              x12_table(i) := 'PO1**1*UN****' || '***SN*' ||
                                ls_coil_org_num || '***VP*' || skid_coil_rec.finished_goods_material_num;
              i := i + 1;

              if skid_coil_rec.skid_sheet_status = 2 then
                x12_table(i) := 'PID*S*MA*ST*1*' ||
                                to_char(skid_coil_rec.sheet_skid_display_num);
                i := i + 1;
              elsif skid_coil_rec.skid_sheet_status = 4 then
                x12_table(i) := 'PID*S*MA*ST*3*' ||
                                to_char(skid_coil_rec.sheet_skid_display_num);
                i := i + 1;
              elsif skid_coil_rec.skid_sheet_status = 13 then
                x12_table(i) := 'PID*S*MA*ST*8*' ||
                                to_char(skid_coil_rec.sheet_skid_display_num);
                i := i + 1;
              else
                x12_table(i) := 'PID*S*MA*ST*4*' ||
                                to_char(skid_coil_rec.sheet_skid_display_num);
                i := i + 1;
              end if;

              x12_table(i) := 'PID*S*MAC*ST*01';
              i := i + 1;
              x12_table(i) := 'PID*S*PR*ST*19';
              i := i + 1;
              --x12_table(i) := 'MEA*WT*N*' || to_char(skid_coil_rec.prod_item_net_wt) ||
              --                '*LB*01';
              
              --Alex Gerlants. 02/01/2022. Changed from "skid_coil_rec.prod_item_net_wt" to "skid_coil_rec.sheet_net_wt"
              x12_table(i) := 'MEA*WT*N*' || to_char(skid_coil_rec.sheet_net_wt) ||
                              '*LB*01';
              
              i := i + 1;
              x12_table(i) := 'MEA*WT*G*' || to_char(skid_coil_rec.skid_gross_wt) ||
                              '*LB*01';
              i := i + 1;
              x12_table(i) := 'MEA*CT*NA*' || to_char(skid_coil_rec.prod_item_pieces) ||
                              '*PC';
              i := i + 1;

              item_num(k) := skid_coil_rec.prod_item_num;
              k := k + 1;
           end if; --if skid_coil_rec.prod_item_net_wt > 0
        end loop; --for skid_coil_rec IN skid_coil_cur loop

        for scrap_rec in scrap_cur loop --Scrap loop
          ll_scrap_nw := scrap_rec.scrap_net_wt;

          if ll_scrap_nw > 0 then --Theo scrap weight
                   
             if ll_sheet_skid_count_4coil <= 0 then --ll_cur_coil is a fully scrapped (rejected) coil without good material
               li_rtn := f_edi_novelis_870_reject_4job(al_ab_job_num, ll_cur_coil, as_user_id, as_original_or_resend);
                     
               continue; --06/19/2020. bypass for fully scrapped coil.
                         --It is in a separate 870 created in f_edi_novelis_870_scrap_coil()
             end if;
                  
             ll_total_theo_scrap_wt_4job := 0;
                  
             select    nvl(sum(return_item_net_wt),0) 
             into      ll_total_act_scrap_wt_4job
             from      return_scrap_item
             where     ab_job_num = al_ab_job_num;

             li_hl01 := li_hl01 + 1;

             x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*I';
             i := i + 1;

             IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
                x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
                i := i + 1;
             END IF;

             x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
             i := i + 1;
                   
             x12_table(i) := 'PO1**1*UN****' || '***SN*' || ls_coil_org_num ;
             i := i + 1;

             x12_table(i) := 'PID*S*MA*ST*S';
             i := i + 1;

             x12_table(i) := 'PID*S*MAC*ST*05';
             i := i + 1;

             x12_table(i) := 'PID*S*PR*ST*19';
             i := i + 1;

             x12_table(i) := 'MEA*WT*N*' || to_char(ll_scrap_nw) || '*LB*01';
             i := i+1;
                   
             ll_total_theo_scrap_wt_4job := ll_total_theo_scrap_wt_4job + ll_scrap_nw;
             
           else --Alex Gerlants. 12/11/2020
             if ll_scrap_nw < 0 then
                --This is in case when the user didn't zero out coil before he changed job status to Done, and saved it
                --In this case, ll_scrap_nw < 0
                return 300; --Alex Gerlants. 12/11/2020 
             end if;                   
           end if; --if ll_scrap_nw > 0 then
        end loop; --for scrap_rec in alcan_scrap_870_cur loop scrap loop
              
          ll_heavy_light := ll_total_act_scrap_wt_4job - ll_total_theo_scrap_wt_4job;
            
        --end if; --if (ld_scrap_870_date is null) then --Scrap not sent
    end loop; --for coil_rec in coil_cur loop. Coil loop
    
    x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
    i := i + 1;

    x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
    i := i + 1;

    x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
    i := i + 1;

    x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

    -- Write EDI to file

    if li_hl01 > 0 then
        -- WRITE EDI FILE ONLY IF ITEM > 0
        SELECT edi_file_id_seq.nextval
          INTO ll_edi_file_id_870
          FROM dual;
        edi_file        := edi_file_prefix || to_char(ll_edi_file_id_870) || '_Job-' || to_char(al_ab_job_num) || '.edi';
     -- edi_file        := 's_alcan_' || to_char(ll_edi_file_id_870) || '.870';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        FOR j IN 0 .. i LOOP
          utl_file.put_line(edi_file_handle, x12_table(j));

        END LOOP;
        utl_file.fclose(edi_file_handle);
      --END IF; -- END WRITING EDI FILE

      --edi_file        := 'send_edi_log'; /* Alex Gerlants. 04/14/2017. Commented out. */
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      --For verifying 997
      INSERT INTO outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
        VALUES
          (ll_edi_file_id_870,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           SYSDATE,
           edi_file,
           0,
           ll_customer_id,
           ll_st_log,
           '870');


       --update    ab_job
       --set       edi_file_id_870 = ll_edi_file_id_870,
       --          edi_date_870 = sysdate
       --where     ab_job_num = al_ab_job_num;
          
       insert into ab_job_870_history
        (
           ab_job_num,
           edi_file_id,
           edi_file_name,
           create_870_date_time,
           user_id,
           notes
        )
        values
        (
           al_ab_job_num ,
           ll_edi_file_id_870,
           edi_file,
           sysdate,
           as_user_id,
           as_original_or_resend
        );

        for m in 0 .. k - 1 loop
           update   production_sheet_item
           set      prod_item_edi870_date = sysdate,
                    edi_file_id_870 = ll_edi_file_id_870 
           where    production_sheet_item.prod_item_num = item_num(m);
        end loop;

        for m in 0..p - 1 loop
           update   coil
           set      coil.scrap_870_date = sysdate
           where    coil.coil_abc_num = coil_num(m);

           update   process_coil
           set      scrap_870_date = sysdate
           where    ( coil_abc_num = coil_num(m)) and (scrap_870_date is null);

         end loop;
         
         update    ab_job
         set       edi_file_id_870 = ll_edi_file_id_870,
                   edi_date_870 = sysdate
         where     ab_job_num = al_ab_job_num;

         commit;
      END IF; -- END WRITING EDI FILE

  end if; --end if in select count(*)

  --END LOOP; ------ End of outer loop customer_id

/*
EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN -1;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN -2;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN -3;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN -4;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN -9;
*/
    
  return 1;
end f_edi_novelis_870_4job_resend;
--------------------------------------------------------
--  DDL for Function F_EDI_NOVELIS_870_4JOB_SKID
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_NOVELIS_870_4JOB_SKID" 
 ( 
    al_ab_job_num           ab_job.ab_job_num%type,
    al_sheet_skid_num       sheet_skid.sheet_skid_num%type,
    as_user_id              ab_job_870_history.user_id%type,
    as_original_or_resend   varchar2
    
 )
  return integer
  
is

  /*
  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc                varchar2(50) := get_edi_destination('EDI_DIR');

  edi_file                     varchar2(50) := 'edi_out.txt';
  edi_file_prefix              varchar2(50) := 'S_novelis_870_'; --production
  --edi_file_prefix              varchar2(50) := 's_novelis_870_'; --development
  edi_file_handle              utl_file.file_type;
  su_duns                      varchar2(10);
  ll_customer_id               customer.customer_id%type;
  ll_cur_coil                  coil.coil_abc_num%type;
  ll_gs_log                    integer;
  ll_st_log                    integer;
  ls_today                     varchar2(20) := to_char(sysdate, 'YYYYMMDD');
  ls_today_4                   varchar2(20) := to_char(sysdate, 'YYMMDD');
  ls_now                       varchar2(20) := to_char(sysdate, 'HH24MI');
  ls_po                        varchar2(20);
  ls_finished_goods            varchar2(32);
  ls_cust_prod_line            varchar2(8);
  ld_scrap_870_date            process_coil.scrap_870_date%type;
  ls_coil_org_num              coil.coil_org_num%type;
  ls_heat                      coil.lot_num%type;
  ll_prime_nw                  coil.net_wt%type;
  ll_scrap_nw                  coil.net_wt%type;
  ll_item_count                integer;
  li_hl01                      integer;
  li_hllin                     integer;
  ll_rowcount                  number(8);
  ll_edi_file_id_870           integer;
  ld_edi_date_870              ab_job.edi_date_870%type;
  --ls_sheet_skid_exists         char(1);
  ls_consumed_coil_num         coil.consumed_coil_num%type;
  ls_customer_short_name       customer.customer_short_name%type;
  ll_sheet_skid_count_4coil    number(8);
  ll_total_act_scrap_wt_4job   number(8);
  ll_total_theo_scrap_wt_4job  number(8);
  ll_heavy_light               number(8);
  li_rtn                       number(4); --Alex Gerlants. Changed from number(1) to number(4)
  ll_psi_870_count             number(3); --Alex Gerlants. 01/08/2021
  ll_coil_870_count            number(3); --Alex Gerlants. 01/08/2021
  ll_process_coil_870_count    number(3); --Alex Gerlants. 01/08/2021

--------------------------------------------------------------------------------------------------   
------------------------------------ Cursors Begin -----------------------------------------------
--------------------------------------------------------------------------------------------------

  cursor coil_cur is
  select distinct process_coil.coil_abc_num
  from   process_coil
         left outer join production_sheet_item on production_sheet_item.coil_abc_num = process_coil.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    (
              sheet_skid.skid_sheet_status in (0, 2, 4, 13, 12, 16)
           or sheet_skid.skid_sheet_status is null --This is for rejected coils without sheets  
         )
  order by process_coil.coil_abc_num;
  
  coil_rec  coil_cur%ROWTYPE;
   
  --Cursor skid_coil_cur will select data for ab_job and coil_abc_num with skids.
  --If there is a reject coil without sheet skids, this cursor will not select it.
  cursor skid_coil_cur is
  select coil.coil_abc_num,   
         coil.lot_num,   
         coil.coil_org_num,   
         coil.coil_mid_num,
         nvl(coil.consumed_coil_num, ' ') consumed_coil,
         nvl(coil.material_num, ' ') material_num,
         coil.net_wt,   
         sheet_skid.sheet_tare_wt,   
         sheet_skid.sheet_net_wt,
         sheet_skid.skid_pieces,
         production_sheet_item.prod_item_pieces,
         production_sheet_item.prod_item_num,
         sheet_skid.skid_sheet_status,
         sheet_skid.sheet_skid_num,   
         production_sheet_item.prod_item_note,   
         sheet_skid.sheet_theoretical_wt,   
         production_sheet_item.prod_item_placement,   
         process_coil.process_quantity,   
         production_sheet_item.prod_item_net_wt,   
         sheet_skid.sheet_skid_display_num,
         nvl(customer_order.sales_order, ' ') sales_order,
         nvl(customer_order.orig_customer_po, 'NA') orig_customer_po,
         nvl(order_item.enduser_part_num, ' ') enduser_part_num,
         nvl(order_item.cust_prod_line_id, 'NA') cust_prod_line_id,
         nvl(order_item.finished_goods_material_num, 'NA') finished_goods_material_num,
         (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
         NULL done  
  from   coil   
         join process_coil on coil.coil_abc_num = process_coil.coil_abc_num
         join ab_job on ab_job.ab_job_num = process_coil.ab_job_num
         join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
         join customer_order on customer_order.order_abc_num = order_item.order_abc_num
         left outer join production_sheet_item on coil.coil_abc_num = production_sheet_item.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  ab_job.ab_job_num = al_ab_job_num
  and    coil.coil_abc_num = ll_cur_coil
  and    sheet_skid.sheet_skid_num = al_sheet_skid_num
  order by
         production_sheet_item.coil_abc_num,
         sheet_skid.sheet_skid_display_num;

  skid_coil_rec  skid_coil_cur%rowtype;
  
  cursor scrap_cur is
  select process_coil.coil_abc_num,
         process_coil.process_coil_status,
         process_coil.process_quantity,
         nvl(process_coil.process_end_wt, 0),
         sum(nvl(process_coil.process_end_wt, 0)),
         sum(nvl(production_sheet_item.prod_item_net_wt, 0)),
         case process_coil.process_coil_status
            when 7 then --Rebanded coils
               --(process_coil.process_quantity - sum(production_sheet_item.prod_item_net_wt) - (select process_end_wt from process_coil pc where pc.ab_job_num = 101143 and pc.coil_abc_num = process_coil.coil_abc_num))
               --(process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - nvl(process_coil.process_end_wt, 0)) --Alex Gerlants. Commented out on 12/15/2020
               (process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - nvl(f_get_coil_rebanded_wt(process_coil.coil_abc_num, process_coil.process_quantity), -99)) --Alex Gerlants. Added on 12/15/2020
            when 3 then --Rejected coils
               case (select count(*) from production_sheet_item psi where psi.ab_job_num = al_ab_job_num and psi.coil_abc_num = process_coil.coil_abc_num)
                 when 0 then --Rejected coils without sheets
                   (process_coil.process_quantity - sum(nvl(process_coil.process_end_wt, 0)))
                 else --Rejected coils with sheets
                   (process_coil.process_quantity - nvl(process_coil.process_end_wt, 0) - sum(nvl(production_sheet_item.prod_item_net_wt, 0)))     
                end   
             else
               (process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - sum(nvl(process_coil.process_end_wt, 0)))
         end scrap_net_wt
  from   process_coil
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         join ab_job on ab_job.ab_job_num = process_coil.ab_job_num and coil.coil_abc_num = process_coil.coil_abc_num
         left outer join production_sheet_item on production_sheet_item.ab_job_num = process_coil.ab_job_num and production_sheet_item.coil_abc_num = process_coil.coil_abc_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    coil.coil_abc_num = ll_cur_coil
  group by
         process_coil.coil_abc_num,
         process_coil.process_coil_status,
         process_coil.process_quantity,
         process_coil.process_end_wt
  order by
         process_coil.coil_abc_num;
         
  scrap_rec  scrap_cur%rowtype;
   
--------------------------------------------------------------------------------------------------   
------------------------------------- Cursors End ------------------------------------------------
--------------------------------------------------------------------------------------------------   

  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;

  TYPE coil_num_type IS TABLE OF coil.coil_abc_num%type INDEX BY BINARY_INTEGER;
  coil_num coil_num_type;
  p binary_integer :=0;
  
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;  

BEGIN
  
  --Check if correct customer
  select  customer_order.orig_customer_id,
          customer.customer_duns_number_string,
          customer.customer_short_name
  into    ll_customer_id,
          su_duns,
          ls_customer_short_name
  from    ab_job
          join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
          join customer on customer.customer_id = customer_order.orig_customer_id
  where   ab_job.ab_job_num = al_ab_job_num;
  
  if lower(ls_customer_short_name) not like '%novelis%' then
    return 200; --Wrong customer
  end if;
  
  --Check if 870 has already been created for al_ab_job_num
  select edi_file_id_870, edi_date_870
  into   ll_edi_file_id_870, ld_edi_date_870
  from   ab_job
  where  ab_job_num = al_ab_job_num;
  
  --Alex Gerlants. 01/08/2021
  --Added this check to avoid sending 870 for jobs that had 870 created by the old batch processing.
  --Check if 870 has already been created for al_ab_job_num using the old data fields
  select count(distinct prod_item_edi870_date)
  into   ll_psi_870_count
  from   production_sheet_item
  where  ab_job_num = al_ab_job_num
  and    prod_item_edi870_date is not null;
  
  --Alex Gerlants. 02/19/2021. Comment out Begin
  --In case of more than 1 job for the same coil, this script updates process_coil and coil
  --for the first job.
  --When the second job for this coil, tries to run this script to create 870, 
  --it returns 100 - 870 already created
  --Checking table production_sheet_item is sufficient to prevent 870 creation for jobs that had 870 
  --created by the old batch processing.

  /* 
  select count(distinct scrap_870_date)
  into   ll_process_coil_870_count
  from   process_coil
  where  ab_job_num = al_ab_job_num
  and    scrap_870_date is not null;
  
  select count(distinct scrap_870_date)
  into   ll_coil_870_count
  from   coil
  where  coil_abc_num in
  (
      select   distinct coil_abc_num
      from     process_coil
      where    ab_job_num = al_ab_job_num
  )
  and    scrap_870_date is not null;
  */
  --Alex Gerlants. 02/19/2021. Comment out End
  
  --Alex Gerlants. 01/08/2021. Added " or ll_psi_870_count > 0 or ll_process_coil_870_count > 0 or ll_coil_870_count > 0"
  --Alex Gerlants. 02/19/2021. Removed "or ll_process_coil_870_count > 0 or ll_coil_870_count > 0"
  --Please see explanation above.

  /*
  if (not (ll_edi_file_id_870 is null and ld_edi_date_870 is null)) or ll_psi_870_count > 0 then --870 already created for al_ab_job_num
    return 100;
  end if;
  */

  i              := 0;
  k              := 0;
  p              := 0;
  
  select count(distinct process_coil.coil_abc_num)
  into   ll_rowcount
  from   process_coil
         left outer join production_sheet_item on production_sheet_item.coil_abc_num = process_coil.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    (
              sheet_skid.skid_sheet_status in (0, 2, 4, 13, 12, 16)
           or sheet_skid.skid_sheet_status is null --This is for rejected coils without sheets  
         );
    
  if ll_rowcount > 0 then

    select edi_st_log_seq.nextval into ll_st_log from dual;
    select edi_gs_log_seq.nextval into ll_gs_log from dual;
    
    /*
    select  customer_order.orig_customer_id
    into    ll_customer_id
    from    ab_job
            join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
    where   ab_job.ab_job_num = al_ab_job_num;
    
    select  customer.customer_duns_number_string
    into    su_duns
    from    customer
    where   customer.customer_id = ll_customer_id;
    */

    --Production
    x12_table(i) := 'ISA*00*' ||
                    '          *00*          *01*039630926T     *09*0015049350011G *' ||
                    ls_today_4 || '*' || ls_now || '*U*00401*' ||
                    lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
          
    --Development                
    --x12_table(i) := 'ISA*00*' ||
    --                '          *00*          *ZZ*2NDSFTP        *ZZ*NOVLSTEST      *' ||
    --                ls_today_4 || '*' || ls_now || '*U*00401*' ||
    --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';    
                         
    i := i + 1;
          
    --Production
    x12_table(i) := 'GS*RS*039630926T*' || '001504935001' || '*' ||
                    ls_today || '*' || ls_now || '*' ||
                    to_char(ll_gs_log) || '*X*' || '004010';
          
    --Development                
    --x12_table(i) := 'GS*RS*2NDSFTP*' || 'NOVLSTEST' || '*' ||
    --                ls_today || '*' || ls_now || '*' ||
    --                to_char(ll_gs_log) || '*X*' || '004010';
                          
    i := i + 1;
        
    x12_table(i) := 'ST*870*' || to_char(ll_st_log);
    i := i + 1;
    x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                    '***' || ls_now || '*****';
    i := i + 1;
    x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
    i := i + 1;
    x12_table(i) := 'N1*SU**1*' || su_duns;
    i := i + 1;
    x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926';
    i := i + 1;

    li_hl01 := 0;

    for coil_rec in coil_cur loop --Coil loop
       ll_cur_coil := coil_rec.coil_abc_num;
       ls_consumed_coil_num := to_char(skid_coil_rec.consumed_coil);
       --ls_sheet_skid_exists := 'n';
       
       select   consumed_coil_num
       into     ls_consumed_coil_num
       from     coil
       where    coil_abc_num = ll_cur_coil;
       
       select   count(*)
       into     ll_sheet_skid_count_4coil
       from     production_sheet_item
       where    ab_job_num = al_ab_job_num
       and      coil_abc_num = ll_cur_coil;
       
       coil_num(p) := ll_cur_coil;
       p := p + 1;

       select   coil.coil_org_num, coil.lot_num
       into     ls_coil_org_num, ls_heat
       from     coil
       where    coil.coil_abc_num = ll_cur_coil;
        
       --ls_sheet_skid_exists := 'n';

       for skid_coil_rec in skid_coil_cur loop --Skid_coil loop
           if skid_coil_rec.prod_item_net_wt > 0 then
             
              --ls_sheet_skid_exists := 'y';
              li_hl01 := li_hl01 + 1;

              x12_table(i) := 'HL*' || to_char(li_hl01) || '**I';
              i := i + 1;
            
              ls_po := skid_coil_rec.orig_customer_po;
              ls_cust_prod_line := skid_coil_rec.cust_prod_line_id;
              ls_finished_goods := skid_coil_rec.finished_goods_material_num;

              IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
                 x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
                 i := i + 1;
              END IF;

              x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
              i := i + 1;

              x12_table(i) := 'REF*SE*' || to_char(skid_coil_rec.prod_item_num);
              i := i + 1;


              x12_table(i) := 'REF*MI*' || to_char(al_ab_job_num);
              i := i + 1;

              x12_table(i) := 'REF*RV*' || to_char(skid_coil_rec.prod_item_num) ||
                              '*NA';
              i := i + 1;

              x12_table(i) := 'REF*IX*' || to_char(skid_coil_rec.consumed_coil);
              i := i + 1;

              x12_table(i) := 'PO1**1*UN****' || '***SN*' ||
                                ls_coil_org_num || '***VP*' || skid_coil_rec.finished_goods_material_num;
              i := i + 1;

              if skid_coil_rec.skid_sheet_status = 2 then
                x12_table(i) := 'PID*S*MA*ST*1*' ||
                                to_char(skid_coil_rec.sheet_skid_display_num);
                i := i + 1;
              elsif skid_coil_rec.skid_sheet_status = 4 then
                x12_table(i) := 'PID*S*MA*ST*3*' ||
                                to_char(skid_coil_rec.sheet_skid_display_num);
                i := i + 1;
              elsif skid_coil_rec.skid_sheet_status = 13 then
                x12_table(i) := 'PID*S*MA*ST*8*' ||
                                to_char(skid_coil_rec.sheet_skid_display_num);
                i := i + 1;
              else
                x12_table(i) := 'PID*S*MA*ST*4*' ||
                                to_char(skid_coil_rec.sheet_skid_display_num);
                i := i + 1;
              end if;

              x12_table(i) := 'PID*S*MAC*ST*01';
              i := i + 1;
              x12_table(i) := 'PID*S*PR*ST*19';
              i := i + 1;
              x12_table(i) := 'MEA*WT*N*' || to_char(skid_coil_rec.prod_item_net_wt) ||
                              '*LB*01';
              i := i + 1;
              x12_table(i) := 'MEA*WT*G*' || to_char(skid_coil_rec.skid_gross_wt) ||
                              '*LB*01';
              i := i + 1;
              x12_table(i) := 'MEA*CT*NA*' || to_char(skid_coil_rec.prod_item_pieces) ||
                              '*PC';
              i := i + 1;

              item_num(k) := skid_coil_rec.prod_item_num;
              k := k + 1;
           end if; --if skid_coil_rec.prod_item_net_wt > 0
        end loop; --for skid_coil_rec IN skid_coil_cur loop

        for scrap_rec in scrap_cur loop --Scrap loop
          ll_scrap_nw := scrap_rec.scrap_net_wt;

          if ll_scrap_nw > 0 then --Theo scrap weight
                   
             if ll_sheet_skid_count_4coil <= 0 then --ll_cur_coil is a fully scrapped (rejected) coil without good material
               li_rtn := f_edi_novelis_870_reject_4job(al_ab_job_num, ll_cur_coil, as_user_id, as_original_or_resend);
                     
               continue; --06/19/2020. bypass for fully scrapped coil.
                         --It is in a separate 870 created in f_edi_novelis_870_scrap_coil()
             end if;
                  
             ll_total_theo_scrap_wt_4job := 0;
                  
             select    nvl(sum(return_item_net_wt),0) 
             into      ll_total_act_scrap_wt_4job
             from      return_scrap_item
             where     ab_job_num = al_ab_job_num;

             li_hl01 := li_hl01 + 1;

             x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*I';
             i := i + 1;

             IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
                x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
                i := i + 1;
             END IF;

             x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
             i := i + 1;
                   
             x12_table(i) := 'PO1**1*UN****' || '***SN*' || ls_coil_org_num ;
             i := i + 1;

             x12_table(i) := 'PID*S*MA*ST*S';
             i := i + 1;

             x12_table(i) := 'PID*S*MAC*ST*05';
             i := i + 1;

             x12_table(i) := 'PID*S*PR*ST*19';
             i := i + 1;

             x12_table(i) := 'MEA*WT*N*' || to_char(ll_scrap_nw) || '*LB*01';
             i := i+1;
                   
             ll_total_theo_scrap_wt_4job := ll_total_theo_scrap_wt_4job + ll_scrap_nw;
             
           else --Alex Gerlants. 12/11/2020
             if ll_scrap_nw < 0 then
                --This is in case when the user didn't zero out coil before he changed job status to Done, and saved it
                --In this case, ll_scrap_nw < 0
                return 300; --Alex Gerlants. 12/11/2020 
             end if;                   
           end if; --if ll_scrap_nw > 0 then
        end loop; --for scrap_rec in alcan_scrap_870_cur loop scrap loop
              
          ll_heavy_light := ll_total_act_scrap_wt_4job - ll_total_theo_scrap_wt_4job;
            
        --end if; --if (ld_scrap_870_date is null) then --Scrap not sent
    end loop; --for coil_rec in coil_cur loop. Coil loop
    
    x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
    i := i + 1;

    x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
    i := i + 1;

    x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
    i := i + 1;

    x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

    -- Write EDI to file

    if li_hl01 > 0 then
        -- WRITE EDI FILE ONLY IF ITEM > 0
        SELECT edi_file_id_seq.nextval
          INTO ll_edi_file_id_870
          FROM dual;
        edi_file        := edi_file_prefix || to_char(ll_edi_file_id_870) || '_Job-' || to_char(al_ab_job_num) || '.edi';
     -- edi_file        := 's_alcan_' || to_char(ll_edi_file_id_870) || '.870';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        FOR j IN 0 .. i LOOP
          utl_file.put_line(edi_file_handle, x12_table(j));

        END LOOP;
        utl_file.fclose(edi_file_handle);
      --END IF; -- END WRITING EDI FILE

      --edi_file        := 'send_edi_log'; /* Alex Gerlants. 04/14/2017. Commented out. */
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      --For verifying 997
      INSERT INTO outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
        VALUES
          (ll_edi_file_id_870,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           SYSDATE,
           edi_file,
           0,
           ll_customer_id,
           ll_st_log,
           '870');


       --update    ab_job
       --set       edi_file_id_870 = ll_edi_file_id_870,
       --          edi_date_870 = sysdate
       --where     ab_job_num = al_ab_job_num;
          
       insert into ab_job_870_history
        (
           ab_job_num,
           edi_file_id,
           edi_file_name,
           create_870_date_time,
           user_id,
           notes
        )
        values
        (
           al_ab_job_num ,
           ll_edi_file_id_870,
           edi_file,
           sysdate,
           as_user_id,
           as_original_or_resend
        );

        for m in 0 .. k - 1 loop
           update   production_sheet_item
           set      prod_item_edi870_date = sysdate,
                    edi_file_id_870 = ll_edi_file_id_870 
           where    production_sheet_item.prod_item_num = item_num(m);
        end loop;

        for m in 0..p - 1 loop
           update   coil
           set      coil.scrap_870_date = sysdate
           where    coil.coil_abc_num = coil_num(m);

           update   process_coil
           set      scrap_870_date = sysdate
           where    ( coil_abc_num = coil_num(m)) and (scrap_870_date is null);

         end loop;
         
         update    ab_job
         set       edi_file_id_870 = ll_edi_file_id_870,
                   edi_date_870 = sysdate
         where     ab_job_num = al_ab_job_num;

         commit;
      END IF; -- END WRITING EDI FILE

  end if; --end if in select count(*)

  --END LOOP; ------ End of outer loop customer_id

/*
EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN -1;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN -2;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN -3;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN -4;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN -9;
*/
    
  return 1;
end f_edi_novelis_870_4job_skid;
--------------------------------------------------------
--  DDL for Function F_EDI_NOVELIS_870_4JOB_TEST
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_NOVELIS_870_4JOB_TEST" 
 ( 
    al_ab_job_num           ab_job.ab_job_num%type,
    as_user_id              ab_job_870_history.user_id%type,
    as_original_or_resend   varchar2
    
 )
  return integer
  
is

  /*
  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc                varchar2(50) := get_edi_destination('EDI_DIR');

  edi_file                     varchar2(50) := 'edi_out.txt';
  --edi_file_prefix              varchar2(50) := 'S_novelis_870_'; --production
  edi_file_prefix              varchar2(50) := 's_novelis_870_'; --development
  edi_file_handle              utl_file.file_type;
  su_duns                      varchar2(10);
  ll_customer_id               customer.customer_id%type;
  ll_cur_coil                  coil.coil_abc_num%type;
  ll_gs_log                    integer;
  ll_st_log                    integer;
  ls_today                     varchar2(20) := to_char(sysdate, 'YYYYMMDD');
  ls_today_4                   varchar2(20) := to_char(sysdate, 'YYMMDD');
  ls_now                       varchar2(20) := to_char(sysdate, 'HH24MI');
  ls_po                        varchar2(20);
  ls_finished_goods            varchar2(32);
  ls_cust_prod_line            varchar2(8);
  --ld_scrap_870_date            process_coil.scrap_870_date%type;
  ls_coil_org_num              coil.coil_org_num%type;
  ls_heat                      coil.lot_num%type;
  --ll_prime_nw                  coil.net_wt%type;
  ll_scrap_nw                  coil.net_wt%type;
  --ll_item_count                integer;
  li_hl01                      integer;
  li_hllin                     integer;
  ll_rowcount                  number(8);
  ll_edi_file_id_870           integer;
  ld_edi_date_870              ab_job.edi_date_870%type;
  --ls_sheet_skid_exists         char(1);
  ls_consumed_coil_num         coil.consumed_coil_num%type;
  ls_customer_short_name       customer.customer_short_name%type;
  ll_sheet_skid_count_4coil    number(8);
  ll_total_act_scrap_wt_4job   number(8);
  ll_total_theo_scrap_wt_4job  number(8);
  ll_heavy_light               number(8);
  li_rtn                       number(4); --Alex Gerlants. Changed from number(1) to number(4)
  ll_psi_870_count             number(3); --Alex Gerlants. 01/08/2021
  --ll_coil_870_count            number(3); --Alex Gerlants. 01/08/2021
  --ll_process_coil_870_count    number(3); --Alex Gerlants. 01/08/2021
  li_skid_count                number(3);

--------------------------------------------------------------------------------------------------   
------------------------------------ Cursors Begin -----------------------------------------------
--------------------------------------------------------------------------------------------------

  cursor coil_cur is
  select distinct process_coil.coil_abc_num
  from   process_coil
         left outer join production_sheet_item on production_sheet_item.coil_abc_num = process_coil.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    (
              sheet_skid.skid_sheet_status in (0, 2, 4, 13, 12, 16)
           or sheet_skid.skid_sheet_status is null --This is for rejected coils without sheets  
         )
  order by process_coil.coil_abc_num;
  
  coil_rec  coil_cur%ROWTYPE;
   
  --Cursor skid_coil_cur will select data for ab_job and coil_abc_num with skids.
  --If there is a reject coil without sheet skids, this cursor will not select it.
  cursor skid_coil_cur is
  select coil.coil_abc_num,   
         coil.lot_num,   
         coil.coil_org_num,   
         coil.coil_mid_num,
         nvl(coil.consumed_coil_num, ' ') consumed_coil,
         nvl(coil.material_num, ' ') material_num,
         coil.net_wt,   
         sheet_skid.sheet_tare_wt,   
         sheet_skid.sheet_net_wt,
         sheet_skid.skid_pieces,
         production_sheet_item.prod_item_pieces,
         production_sheet_item.prod_item_num,
         sheet_skid.skid_sheet_status,
         sheet_skid.sheet_skid_num,   
         production_sheet_item.prod_item_note,   
         sheet_skid.sheet_theoretical_wt,   
         production_sheet_item.prod_item_placement,   
         process_coil.process_quantity,   
         production_sheet_item.prod_item_net_wt,   
         sheet_skid.sheet_skid_display_num,
         nvl(customer_order.sales_order, ' ') sales_order,
         nvl(customer_order.orig_customer_po, 'NA') orig_customer_po,
         nvl(order_item.enduser_part_num, ' ') enduser_part_num,
         nvl(order_item.cust_prod_line_id, 'NA') cust_prod_line_id,
         nvl(order_item.finished_goods_material_num, 'NA') finished_goods_material_num,
         (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
         NULL done  
  from   coil   
         join process_coil on coil.coil_abc_num = process_coil.coil_abc_num
         join ab_job on ab_job.ab_job_num = process_coil.ab_job_num
         join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
         join customer_order on customer_order.order_abc_num = order_item.order_abc_num
         left outer join production_sheet_item on coil.coil_abc_num = production_sheet_item.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  ab_job.ab_job_num = al_ab_job_num
  and    coil.coil_abc_num = ll_cur_coil
  order by
         production_sheet_item.coil_abc_num,
         sheet_skid.sheet_skid_display_num;

  skid_coil_rec  skid_coil_cur%rowtype;
  
  cursor scrap_cur is
  select process_coil.coil_abc_num,
         process_coil.process_coil_status,
         process_coil.process_quantity,
         nvl(process_coil.process_end_wt, 0),
         sum(nvl(process_coil.process_end_wt, 0)),
         sum(nvl(production_sheet_item.prod_item_net_wt, 0)),
         case process_coil.process_coil_status
            when 7 then --Rebanded coils
               --(process_coil.process_quantity - sum(production_sheet_item.prod_item_net_wt) - (select process_end_wt from process_coil pc where pc.ab_job_num = 101143 and pc.coil_abc_num = process_coil.coil_abc_num))
               --(process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - nvl(process_coil.process_end_wt, 0)) --Alex Gerlants. Commented out on 12/15/2020
               (process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - nvl(f_get_coil_rebanded_wt(process_coil.coil_abc_num, process_coil.process_quantity), -99)) --Alex Gerlants. Added on 12/15/2020
            when 3 then --Rejected coils
               case (select count(*) from production_sheet_item psi where psi.ab_job_num = al_ab_job_num and psi.coil_abc_num = process_coil.coil_abc_num)
                 when 0 then --Rejected coils without sheets
                   (process_coil.process_quantity - sum(nvl(process_coil.process_end_wt, 0)))
                 else --Rejected coils with sheets
                   (process_coil.process_quantity - nvl(process_coil.process_end_wt, 0) - sum(nvl(production_sheet_item.prod_item_net_wt, 0)))     
                end   
             else
               (process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - sum(nvl(process_coil.process_end_wt, 0)))
         end scrap_net_wt
  from   process_coil
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         join ab_job on ab_job.ab_job_num = process_coil.ab_job_num and coil.coil_abc_num = process_coil.coil_abc_num
         left outer join production_sheet_item on production_sheet_item.ab_job_num = process_coil.ab_job_num and production_sheet_item.coil_abc_num = process_coil.coil_abc_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    coil.coil_abc_num = ll_cur_coil
  group by
         process_coil.coil_abc_num,
         process_coil.process_coil_status,
         process_coil.process_quantity,
         process_coil.process_end_wt
  order by
         process_coil.coil_abc_num;
         
  scrap_rec  scrap_cur%rowtype;
   
--------------------------------------------------------------------------------------------------   
------------------------------------- Cursors End ------------------------------------------------
--------------------------------------------------------------------------------------------------   

  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;

  TYPE coil_num_type IS TABLE OF coil.coil_abc_num%type INDEX BY BINARY_INTEGER;
  coil_num coil_num_type;
  p binary_integer :=0;
  
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;  

BEGIN
  
  --Check if correct customer
  select  customer_order.orig_customer_id,
          customer.customer_duns_number_string,
          customer.customer_short_name
  into    ll_customer_id,
          su_duns,
          ls_customer_short_name
  from    ab_job
          join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
          join customer on customer.customer_id = customer_order.orig_customer_id
  where   ab_job.ab_job_num = al_ab_job_num;
  
  if lower(ls_customer_short_name) not like '%novelis%' then
    return 200; --Wrong customer
  end if;
  
  --Check if 870 has already been created for al_ab_job_num
  select edi_file_id_870, edi_date_870
  into   ll_edi_file_id_870, ld_edi_date_870
  from   ab_job
  where  ab_job_num = al_ab_job_num;
  
  --Alex Gerlants. 01/08/2021
  --Added this check to avoid sending 870 for jobs that had 870 created by the old batch processing.
  --Check if 870 has already been created for al_ab_job_num using the old data fields
  select count(distinct prod_item_edi870_date)
  into   ll_psi_870_count
  from   production_sheet_item
  where  ab_job_num = al_ab_job_num
  and    prod_item_edi870_date is not null;
  
  --Alex Gerlants. 02/19/2021. Comment out Begin
  --In case of more than 1 job for the same coil, this script updates process_coil and coil
  --for the first job.
  --When the second job for this coil, tries to run this script to create 870, 
  --it returns 100 - 870 already created
  --Checking table production_sheet_item is sufficient to prevent 870 creation for jobs that had 870 
  --created by the old batch processing.

  /* 
  select count(distinct scrap_870_date)
  into   ll_process_coil_870_count
  from   process_coil
  where  ab_job_num = al_ab_job_num
  and    scrap_870_date is not null;
  
  select count(distinct scrap_870_date)
  into   ll_coil_870_count
  from   coil
  where  coil_abc_num in
  (
      select   distinct coil_abc_num
      from     process_coil
      where    ab_job_num = al_ab_job_num
  )
  and    scrap_870_date is not null;
  */
  --Alex Gerlants. 02/19/2021. Comment out End
  
  --Alex Gerlants. 01/08/2021. Added " or ll_psi_870_count > 0 or ll_process_coil_870_count > 0 or ll_coil_870_count > 0"
  --Alex Gerlants. 02/19/2021. Removed "or ll_process_coil_870_count > 0 or ll_coil_870_count > 0"
  --Please see explanation above.
  if (not (ll_edi_file_id_870 is null and ld_edi_date_870 is null)) or ll_psi_870_count > 0 then --870 already created for al_ab_job_num
    return 100;
  end if;

  i              := 0;
  k              := 0;
  p              := 0;
  
  select count(distinct process_coil.coil_abc_num)
  into   ll_rowcount
  from   process_coil
         left outer join production_sheet_item on production_sheet_item.coil_abc_num = process_coil.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    (
              sheet_skid.skid_sheet_status in (0, 2, 4, 13, 12, 16)
           or sheet_skid.skid_sheet_status is null --This is for rejected coils without sheets  
         );
    
  if ll_rowcount > 0 then

    select edi_st_log_seq.nextval into ll_st_log from dual;
    select edi_gs_log_seq.nextval into ll_gs_log from dual;
    
    /*
    select  customer_order.orig_customer_id
    into    ll_customer_id
    from    ab_job
            join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
    where   ab_job.ab_job_num = al_ab_job_num;
    
    select  customer.customer_duns_number_string
    into    su_duns
    from    customer
    where   customer.customer_id = ll_customer_id;
    */

    --Production
    x12_table(i) := 'ISA*00*' ||
                    '          *00*          *01*039630926T     *09*0015049350011G *' ||
                    ls_today_4 || '*' || ls_now || '*U*00401*' ||
                    lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
          
    --Development                
    --x12_table(i) := 'ISA*00*' ||
    --                '          *00*          *ZZ*2NDSFTP        *ZZ*NOVLSTEST      *' ||
    --                ls_today_4 || '*' || ls_now || '*U*00401*' ||
    --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';    
                         
    i := i + 1;
          
    --Production
    x12_table(i) := 'GS*RS*039630926T*' || '001504935001' || '*' ||
                    ls_today || '*' || ls_now || '*' ||
                    to_char(ll_gs_log) || '*X*' || '004010';
          
    --Development                
    --x12_table(i) := 'GS*RS*2NDSFTP*' || 'NOVLSTEST' || '*' ||
    --                ls_today || '*' || ls_now || '*' ||
    --                to_char(ll_gs_log) || '*X*' || '004010';
                          
    i := i + 1;
        
    x12_table(i) := 'ST*870*' || to_char(ll_st_log);
    i := i + 1;
    x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                    '***' || ls_now || '*****';
    i := i + 1;
    x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
    i := i + 1;
    x12_table(i) := 'N1*SU**1*' || su_duns;
    i := i + 1;
    x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926';
    i := i + 1;

    li_hl01 := 0;

    for coil_rec in coil_cur loop --Coil loop
       ll_cur_coil := coil_rec.coil_abc_num;
       
       select   count(distinct sheet_skid.sheet_skid_num) 
       into     li_skid_count
       from     process_coil
                left outer join production_sheet_item on production_sheet_item.coil_abc_num = process_coil.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
                left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
                left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
       where    process_coil.ab_job_num = al_ab_job_num
       and      process_coil.coil_abc_num = ll_cur_coil;
       
       --if li_skid_count <= 0 then 
       --  continue;
       --end if;
       
       ls_consumed_coil_num := to_char(skid_coil_rec.consumed_coil);
       --ls_sheet_skid_exists := 'n';
       
       select   consumed_coil_num
       into     ls_consumed_coil_num
       from     coil
       where    coil_abc_num = ll_cur_coil;
       
       select   count(*)
       into     ll_sheet_skid_count_4coil
       from     production_sheet_item
       where    ab_job_num = al_ab_job_num
       and      coil_abc_num = ll_cur_coil;
       
       coil_num(p) := ll_cur_coil;
       p := p + 1;

       select   coil.coil_org_num, coil.lot_num
       into     ls_coil_org_num, ls_heat
       from     coil
       where    coil.coil_abc_num = ll_cur_coil;
        
       --ls_sheet_skid_exists := 'n';

        if li_skid_count > 0 then
           for skid_coil_rec in skid_coil_cur loop --Skid_coil loop
               if skid_coil_rec.prod_item_net_wt > 0 then
                 
                  --ls_sheet_skid_exists := 'y';
                  li_hl01 := li_hl01 + 1;

                  x12_table(i) := 'HL*' || to_char(li_hl01) || '**I';
                  i := i + 1;
                
                  ls_po := skid_coil_rec.orig_customer_po;
                  ls_cust_prod_line := skid_coil_rec.cust_prod_line_id;
                  ls_finished_goods := skid_coil_rec.finished_goods_material_num;

                  IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
                     x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
                     i := i + 1;
                  END IF;

                  x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
                  i := i + 1;

                  x12_table(i) := 'REF*SE*' || to_char(skid_coil_rec.prod_item_num);
                  i := i + 1;


                  x12_table(i) := 'REF*MI*' || to_char(al_ab_job_num);
                  i := i + 1;

                  x12_table(i) := 'REF*RV*' || to_char(skid_coil_rec.prod_item_num) ||
                                  '*NA';
                  i := i + 1;

                  x12_table(i) := 'REF*IX*' || to_char(skid_coil_rec.consumed_coil);
                  i := i + 1;

                  x12_table(i) := 'PO1**1*UN****' || '***SN*' ||
                                    ls_coil_org_num || '***VP*' || skid_coil_rec.finished_goods_material_num;
                  i := i + 1;

                  if skid_coil_rec.skid_sheet_status = 2 then
                    x12_table(i) := 'PID*S*MA*ST*1*' ||
                                    to_char(skid_coil_rec.sheet_skid_display_num);
                    i := i + 1;
                  elsif skid_coil_rec.skid_sheet_status = 4 then
                    x12_table(i) := 'PID*S*MA*ST*3*' ||
                                    to_char(skid_coil_rec.sheet_skid_display_num);
                    i := i + 1;
                  elsif skid_coil_rec.skid_sheet_status = 13 then
                    x12_table(i) := 'PID*S*MA*ST*8*' ||
                                    to_char(skid_coil_rec.sheet_skid_display_num);
                    i := i + 1;
                  else
                    x12_table(i) := 'PID*S*MA*ST*4*' ||
                                    to_char(skid_coil_rec.sheet_skid_display_num);
                    i := i + 1;
                  end if;

                  x12_table(i) := 'PID*S*MAC*ST*01';
                  i := i + 1;
                  x12_table(i) := 'PID*S*PR*ST*19';
                  i := i + 1;
                  x12_table(i) := 'MEA*WT*N*' || to_char(skid_coil_rec.prod_item_net_wt) ||
                                  '*LB*01';
                  i := i + 1;
                  x12_table(i) := 'MEA*WT*G*' || to_char(skid_coil_rec.skid_gross_wt) ||
                                  '*LB*01';
                  i := i + 1;
                  x12_table(i) := 'MEA*CT*NA*' || to_char(skid_coil_rec.prod_item_pieces) ||
                                  '*PC';
                  i := i + 1;

                  item_num(k) := skid_coil_rec.prod_item_num;
                  k := k + 1;
               end if; --if skid_coil_rec.prod_item_net_wt > 0
            end loop; --for skid_coil_rec IN skid_coil_cur loop
        end if;

        for scrap_rec in scrap_cur loop --Scrap loop
          ll_scrap_nw := scrap_rec.scrap_net_wt;

          if ll_scrap_nw > 0 then --Theo scrap weight
                   
             if ll_sheet_skid_count_4coil <= 0 then --ll_cur_coil is a fully scrapped (rejected) coil without good material
               li_rtn := f_edi_novelis_870_reject_4job(al_ab_job_num, ll_cur_coil, as_user_id, as_original_or_resend);
                     
               continue; --06/19/2020. bypass for fully scrapped coil.
                         --It is in a separate 870 created in f_edi_novelis_870_scrap_coil()
             end if;
                  
             ll_total_theo_scrap_wt_4job := 0;
                  
             select    nvl(sum(return_item_net_wt),0) 
             into      ll_total_act_scrap_wt_4job
             from      return_scrap_item
             where     ab_job_num = al_ab_job_num;

             li_hl01 := li_hl01 + 1;

             x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*I';
             i := i + 1;

             IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
                x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
                i := i + 1;
             END IF;

             x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
             i := i + 1;
                   
             x12_table(i) := 'PO1**1*UN****' || '***SN*' || ls_coil_org_num ;
             i := i + 1;

             x12_table(i) := 'PID*S*MA*ST*S';
             i := i + 1;

             x12_table(i) := 'PID*S*MAC*ST*05';
             i := i + 1;

             x12_table(i) := 'PID*S*PR*ST*19';
             i := i + 1;

             x12_table(i) := 'MEA*WT*N*' || to_char(ll_scrap_nw) || '*LB*01';
             i := i+1;
                   
             ll_total_theo_scrap_wt_4job := ll_total_theo_scrap_wt_4job + ll_scrap_nw;
             
           else --Alex Gerlants. 12/11/2020
             if ll_scrap_nw < 0 then
                --This is in case when the user didn't zero out coil before he changed job status to Done, and saved it
                --In this case, ll_scrap_nw < 0
                return 300; --Alex Gerlants. 12/11/2020 
             end if;                   
           end if; --if ll_scrap_nw > 0 then
        end loop; --for scrap_rec in alcan_scrap_870_cur loop scrap loop
              
          ll_heavy_light := ll_total_act_scrap_wt_4job - ll_total_theo_scrap_wt_4job;
            
        --end if; --if (ld_scrap_870_date is null) then --Scrap not sent
    end loop; --for coil_rec in coil_cur loop. Coil loop
    
    x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
    i := i + 1;

    x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
    i := i + 1;

    x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
    i := i + 1;

    x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

    -- Write EDI to file

    if li_hl01 > 0 then
        -- WRITE EDI FILE ONLY IF ITEM > 0
        SELECT edi_file_id_seq.nextval
          INTO ll_edi_file_id_870
          FROM dual;
        edi_file        := edi_file_prefix || to_char(ll_edi_file_id_870) || '_Job-' || to_char(al_ab_job_num) || '.edi';
     -- edi_file        := 's_alcan_' || to_char(ll_edi_file_id_870) || '.870';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        FOR j IN 0 .. i LOOP
          utl_file.put_line(edi_file_handle, x12_table(j));

        END LOOP;
        utl_file.fclose(edi_file_handle);
      --END IF; -- END WRITING EDI FILE

      --edi_file        := 'send_edi_log'; /* Alex Gerlants. 04/14/2017. Commented out. */
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      --For verifying 997
      INSERT INTO outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
        VALUES
          (ll_edi_file_id_870,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           SYSDATE,
           edi_file,
           0,
           ll_customer_id,
           ll_st_log,
           '870');


       --update    ab_job
       --set       edi_file_id_870 = ll_edi_file_id_870,
       --          edi_date_870 = sysdate
       --where     ab_job_num = al_ab_job_num;
          
       insert into ab_job_870_history
        (
           ab_job_num,
           edi_file_id,
           edi_file_name,
           create_870_date_time,
           user_id,
           notes
        )
        values
        (
           al_ab_job_num ,
           ll_edi_file_id_870,
           edi_file,
           sysdate,
           as_user_id,
           as_original_or_resend
        );

        for m in 0 .. k - 1 loop
           update   production_sheet_item
           set      prod_item_edi870_date = sysdate,
                    edi_file_id_870 = ll_edi_file_id_870 
           where    production_sheet_item.prod_item_num = item_num(m);
        end loop;

        for m in 0..p - 1 loop
           update   coil
           set      coil.scrap_870_date = sysdate
           where    coil.coil_abc_num = coil_num(m);

           update   process_coil
           set      scrap_870_date = sysdate
           where    ( coil_abc_num = coil_num(m)) and (scrap_870_date is null);

         end loop;
         
         update    ab_job
         set       edi_file_id_870 = ll_edi_file_id_870,
                   edi_date_870 = sysdate
         where     ab_job_num = al_ab_job_num;

         commit;
      END IF; -- END WRITING EDI FILE

  end if; --end if in select count(*)

  --END LOOP; ------ End of outer loop customer_id

/*
EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN -1;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN -2;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN -3;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN -4;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN -9;
*/
    
  return 1;
end f_edi_novelis_870_4job_test;
--------------------------------------------------------
--  DDL for Function F_EDI_NOVELIS_870_PER_JOB
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_NOVELIS_870_PER_JOB" 
 ( 
    al_ab_job_num  ab_job.ab_job_num%type,
    as_user_id     ab_job_870_history.user_id%type
    
 )
  return integer
  
is

  /*
  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc                varchar2(50) := get_edi_destination('EDI_DIR');

  edi_file                     varchar2(50) := 'edi_out.txt';
  --edi_file_prefix              varchar2(50) := 'S_novelis_870_'; --production
  edi_file_prefix              varchar2(50) := 's_novelis_870_'; --development
  edi_file_handle              utl_file.file_type;
  su_duns                      varchar2(10);
  ll_customer_id               customer.customer_id%type;
  ll_cur_coil                  coil.coil_abc_num%type;
  ll_gs_log                    integer;
  ll_st_log                    integer;
  ls_today                     varchar2(20) := to_char(sysdate, 'YYYYMMDD');
  ls_today_4                   varchar2(20) := to_char(sysdate, 'YYMMDD');
  ls_now                       varchar2(20) := to_char(sysdate, 'HH24MI');
  ls_po                        varchar2(20);
  ls_finished_goods            varchar2(32);
  ls_cust_prod_line            varchar2(8);
  ld_scrap_870_date            process_coil.scrap_870_date%type;
  ls_coil_org_num              coil.coil_org_num%type;
  ls_heat                      coil.lot_num%type;
  ll_prime_nw                  coil.net_wt%type;
  ll_scrap_nw                  coil.net_wt%type;
  ll_item_count                integer;
  li_hl01                      integer;
  li_hllin                     integer;
  ll_rowcount                  number(8);
  ll_edi_file_id_870           integer;
  ld_edi_date_870              ab_job.edi_date_870%type;
  --ls_sheet_skid_exists         char(1);
  ls_consumed_coil_num         coil.consumed_coil_num%type;
  ls_customer_short_name       customer.customer_short_name%type;
  ll_sheet_skid_count_4coil    number(8);
  ll_total_act_scrap_wt_4job   number(8);
  ll_total_theo_scrap_wt_4job  number(8);
  ll_heavy_light               number(8);

--------------------------------------------------------------------------------------------------   
------------------------------------ Cursors Begin -----------------------------------------------
--------------------------------------------------------------------------------------------------

  cursor coil_cur is
  select distinct process_coil.coil_abc_num
  from   process_coil
         left outer join production_sheet_item on production_sheet_item.coil_abc_num = process_coil.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    (
              sheet_skid.skid_sheet_status in (0, 2, 4, 13, 12, 16)
           or sheet_skid.skid_sheet_status is null --This is for rejected coils without sheets  
         )
  order by process_coil.coil_abc_num;
  
  coil_rec  coil_cur%ROWTYPE;
   
  --Cursor skid_coil_cur will select data for ab_job and coil_abc_num with skids.
  --If there is a reject coil without sheet skids, this cursor will not select it.
  cursor skid_coil_cur is
  select coil.coil_abc_num,   
         coil.lot_num,   
         coil.coil_org_num,   
         coil.coil_mid_num,
         nvl(coil.consumed_coil_num, ' ') consumed_coil,
         nvl(coil.material_num, ' ') material_num,
         coil.net_wt,   
         sheet_skid.sheet_tare_wt,   
         sheet_skid.sheet_net_wt,
         sheet_skid.skid_pieces,
         production_sheet_item.prod_item_pieces,
         production_sheet_item.prod_item_num,
         sheet_skid.skid_sheet_status,
         sheet_skid.sheet_skid_num,   
         production_sheet_item.prod_item_note,   
         sheet_skid.sheet_theoretical_wt,   
         production_sheet_item.prod_item_placement,   
         process_coil.process_quantity,   
         production_sheet_item.prod_item_net_wt,   
         sheet_skid.sheet_skid_display_num,
         nvl(customer_order.sales_order, ' ') sales_order,
         nvl(customer_order.orig_customer_po, 'NA') orig_customer_po,
         nvl(order_item.enduser_part_num, ' ') enduser_part_num,
         nvl(order_item.cust_prod_line_id, 'NA') cust_prod_line_id,
         nvl(order_item.finished_goods_material_num, 'NA') finished_goods_material_num,
         (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
         NULL done  
  from   coil   
         join process_coil on coil.coil_abc_num = process_coil.coil_abc_num
         join ab_job on ab_job.ab_job_num = process_coil.ab_job_num
         join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
         join customer_order on customer_order.order_abc_num = order_item.order_abc_num
         left outer join production_sheet_item on coil.coil_abc_num = production_sheet_item.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  ab_job.ab_job_num = al_ab_job_num
  and    coil.coil_abc_num = ll_cur_coil
  order by
         production_sheet_item.coil_abc_num,
         sheet_skid.sheet_skid_display_num;

  skid_coil_rec  skid_coil_cur%rowtype;
  
  cursor scrap_cur is
  select process_coil.coil_abc_num,
         process_coil.process_coil_status,
         process_coil.process_quantity,
         nvl(process_coil.process_end_wt, 0),
         sum(nvl(process_coil.process_end_wt, 0)),
         sum(nvl(production_sheet_item.prod_item_net_wt, 0)),
         case process_coil.process_coil_status
            when 7 then --Rebanded coils
               --(process_coil.process_quantity - sum(production_sheet_item.prod_item_net_wt) - (select process_end_wt from process_coil pc where pc.ab_job_num = 101143 and pc.coil_abc_num = process_coil.coil_abc_num))
               (process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - nvl(process_coil.process_end_wt, 0))
            when 3 then --Rejected coils
               case (select count(*) from production_sheet_item psi where psi.ab_job_num = al_ab_job_num and psi.coil_abc_num = process_coil.coil_abc_num)
                 when 0 then --Rejected coils without sheets
                   (process_coil.process_quantity - sum(nvl(process_coil.process_end_wt, 0)))
                 else --Rejected coils with sheets
                   (process_coil.process_quantity - nvl(process_coil.process_end_wt, 0) - sum(nvl(production_sheet_item.prod_item_net_wt, 0)))     
                end   
             else
               (process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - sum(nvl(process_coil.process_end_wt, 0)))
         end scrap_net_wt
  from   process_coil
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         join ab_job on ab_job.ab_job_num = process_coil.ab_job_num and coil.coil_abc_num = process_coil.coil_abc_num
         left outer join production_sheet_item on production_sheet_item.ab_job_num = process_coil.ab_job_num and production_sheet_item.coil_abc_num = process_coil.coil_abc_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    coil.coil_abc_num = ll_cur_coil
  group by
         process_coil.coil_abc_num,
         process_coil.process_coil_status,
         process_coil.process_quantity,
         process_coil.process_end_wt
  order by
         process_coil.coil_abc_num;
         
  scrap_rec  scrap_cur%rowtype;
   
--------------------------------------------------------------------------------------------------   
------------------------------------- Cursors End ------------------------------------------------
--------------------------------------------------------------------------------------------------   

  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;

  TYPE coil_num_type IS TABLE OF coil.coil_abc_num%type INDEX BY BINARY_INTEGER;
  coil_num coil_num_type;
  p binary_integer :=0;
  
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;  

BEGIN
  
  --Check if correct customer
  select  customer_order.orig_customer_id,
          customer.customer_duns_number_string,
          customer.customer_short_name
  into    ll_customer_id,
          su_duns,
          ls_customer_short_name
  from    ab_job
          join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
          join customer on customer.customer_id = customer_order.orig_customer_id
  where   ab_job.ab_job_num = al_ab_job_num;
  
  if lower(ls_customer_short_name) not like '%novelis%' then
    return 200; --Wrong customer
  end if;
  
  --Check if 870 has already been created for al_ab_job_num
  select edi_file_id_870, edi_date_870
  into   ll_edi_file_id_870, ld_edi_date_870
  from   ab_job
  where  ab_job_num = al_ab_job_num;
   
  if not (ll_edi_file_id_870 is null and ld_edi_date_870 is null) then --870 already created for al_ab_job_num
    return 100;
  end if;

  i              := 0;
  k              := 0;
  p              := 0;
  
  select count(distinct process_coil.coil_abc_num)
  into   ll_rowcount
  from   process_coil
         left outer join production_sheet_item on production_sheet_item.coil_abc_num = process_coil.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    (
              sheet_skid.skid_sheet_status in (0, 2, 4, 13, 12, 16)
           or sheet_skid.skid_sheet_status is null --This is for rejected coils without sheets  
         );
    
  if ll_rowcount > 0 then

    select edi_st_log_seq.nextval into ll_st_log from dual;
    select edi_gs_log_seq.nextval into ll_gs_log from dual;
    
    /*
    select  customer_order.orig_customer_id
    into    ll_customer_id
    from    ab_job
            join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
    where   ab_job.ab_job_num = al_ab_job_num;
    
    select  customer.customer_duns_number_string
    into    su_duns
    from    customer
    where   customer.customer_id = ll_customer_id;
    */

    --Production
    --x12_table(i) := 'ISA*00*' ||
    --                '          *00*          *01*039630926T     *09*0015049350011G *' ||
    --                ls_today_4 || '*' || ls_now || '*U*00401*' ||
    --                lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
          
    --Development                
    x12_table(i) := 'ISA*00*' ||
                    '          *00*          *ZZ*2NDSFTP        *ZZ*NOVLSTEST      *' ||
                    ls_today_4 || '*' || ls_now || '*U*00401*' ||
                    lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';    
                         
    i := i + 1;
          
    --Production
    --x12_table(i) := 'GS*RS*039630926T*' || '001504935001' || '*' ||
    --                ls_today || '*' || ls_now || '*' ||
    --                to_char(ll_gs_log) || '*X*' || '004010';
          
    --Development                
    x12_table(i) := 'GS*RS*2NDSFTP*' || 'NOVLSTEST' || '*' ||
                    ls_today || '*' || ls_now || '*' ||
                    to_char(ll_gs_log) || '*X*' || '004010';
                          
    i := i + 1;
        
    x12_table(i) := 'ST*870*' || to_char(ll_st_log);
    i := i + 1;
    x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                    '***' || ls_now || '*****';
    i := i + 1;
    x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
    i := i + 1;
    x12_table(i) := 'N1*SU**1*' || su_duns;
    i := i + 1;
    x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926';
    i := i + 1;

    li_hl01 := 0;

    for coil_rec in coil_cur loop --Coil loop
       ll_cur_coil := coil_rec.coil_abc_num;
       ls_consumed_coil_num := to_char(skid_coil_rec.consumed_coil);
       --ls_sheet_skid_exists := 'n';
       
       select   consumed_coil_num
       into     ls_consumed_coil_num
       from     coil
       where    coil_abc_num = ll_cur_coil;
       
       select   count(*)
       into     ll_sheet_skid_count_4coil
       from     production_sheet_item
       where    ab_job_num = al_ab_job_num
       and      coil_abc_num = ll_cur_coil;
       
       coil_num(p) := ll_cur_coil;
       p := p + 1;

       select   coil.coil_org_num, coil.lot_num
       into     ls_coil_org_num, ls_heat
       from     coil
       where    coil.coil_abc_num = ll_cur_coil;
        
       --ls_sheet_skid_exists := 'n';

       for skid_coil_rec in skid_coil_cur loop --Skid_coil loop
           if skid_coil_rec.prod_item_net_wt > 0 then
             
              --ls_sheet_skid_exists := 'y';
              li_hl01 := li_hl01 + 1;

              x12_table(i) := 'HL*' || to_char(li_hl01) || '**I';
              i := i + 1;

      /* 
                    SELECT nvl(customer_order.orig_customer_po, 'NA'),
                           nvl(order_item.cust_prod_line_id, 'NA'),
                           nvl(order_item.finished_goods_material_num, 'NA')
                    INTO ls_po, ls_cust_prod_line, ls_finished_goods
                    FROM   order_item,
                           ab_job,
                           customer_order
                   WHERE (ab_job.order_abc_num = customer_order.order_abc_num)
                   AND (ab_job.order_abc_num = order_item.order_abc_num)
                   AND (ab_job.order_item_num = order_item.order_item_num)
                    AND (ab_job.ab_job_num = item_rec.ab_job_num);
      */              
              ls_po := skid_coil_rec.orig_customer_po;
              ls_cust_prod_line := skid_coil_rec.cust_prod_line_id;
              ls_finished_goods := skid_coil_rec.finished_goods_material_num;

              IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
                 x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
                 i := i + 1;
              END IF;

              x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
              i := i + 1;

              x12_table(i) := 'REF*SE*' || to_char(skid_coil_rec.prod_item_num);
              i := i + 1;


              x12_table(i) := 'REF*MI*' || to_char(al_ab_job_num);
              i := i + 1;

              x12_table(i) := 'REF*RV*' || to_char(skid_coil_rec.prod_item_num) ||
                              '*NA';
              i := i + 1;

              x12_table(i) := 'REF*IX*' || to_char(skid_coil_rec.consumed_coil);
              i := i + 1;

              x12_table(i) := 'PO1**1*UN****' || '***SN*' ||
                                ls_coil_org_num || '***VP*' || skid_coil_rec.finished_goods_material_num;
              i := i + 1;

              if skid_coil_rec.skid_sheet_status = 2 then
                x12_table(i) := 'PID*S*MA*ST*1*' ||
                                to_char(skid_coil_rec.sheet_skid_display_num);
                i := i + 1;
              elsif skid_coil_rec.skid_sheet_status = 4 then
                x12_table(i) := 'PID*S*MA*ST*3*' ||
                                to_char(skid_coil_rec.sheet_skid_display_num);
                i := i + 1;
              elsif skid_coil_rec.skid_sheet_status = 13 then
                x12_table(i) := 'PID*S*MA*ST*8*' ||
                                to_char(skid_coil_rec.sheet_skid_display_num);
                i := i + 1;
              else
                x12_table(i) := 'PID*S*MA*ST*4*' ||
                                to_char(skid_coil_rec.sheet_skid_display_num);
                i := i + 1;
              end if;

              x12_table(i) := 'PID*S*MAC*ST*01';
              i := i + 1;
              x12_table(i) := 'PID*S*PR*ST*19';
              i := i + 1;
              x12_table(i) := 'MEA*WT*N*' || to_char(skid_coil_rec.prod_item_net_wt) ||
                              '*LB*01';
              i := i + 1;
              x12_table(i) := 'MEA*WT*G*' || to_char(skid_coil_rec.skid_gross_wt) ||
                              '*LB*01';
              i := i + 1;
              x12_table(i) := 'MEA*CT*NA*' || to_char(skid_coil_rec.prod_item_pieces) ||
                              '*PC';
              i := i + 1;

              item_num(k) := skid_coil_rec.prod_item_num;
              k := k + 1;
           end if; --if skid_coil_rec.prod_item_net_wt > 0
        end loop; --for skid_coil_rec IN skid_coil_cur loop

        /*
        select   process_coil.scrap_870_date, coil.coil_org_num, coil.lot_num
        into     ld_scrap_870_date, ls_coil_org_num, ls_heat
        from     coil
                 join process_coil on coil.coil_abc_num = process_coil.coil_abc_num
        where    coil.coil_abc_num = ll_cur_coil;
        */

        --if (ld_scrap_870_date is null) then --Scrap not sent

           for scrap_rec in scrap_cur loop --Scrap loop

              --Scrap info
              /*
              SELECT   NVL(sum(production_sheet_item.prod_item_net_wt),0)
              into     ll_prime_nw
              FROM     production_sheet_item
              WHERE (  production_sheet_item.ab_job_num = scrap_rec.ab_job_num) and
                       (production_sheet_item.coil_abc_num = ll_cur_coil);
              */

              --ll_scrap_nw := scrap_rec.process_quan - scrap_rec.process_end_wt - ll_prime_nw;
              ll_scrap_nw := scrap_rec.scrap_net_wt;

              if ll_scrap_nw > 0 then --Theo scrap weight
                
                 ll_total_theo_scrap_wt_4job := 0;
                
                 select    nvl(sum(return_item_net_wt),0) 
                 into      ll_total_act_scrap_wt_4job
                 from      return_scrap_item
                 where     ab_job_num = al_ab_job_num;

                 li_hl01 := li_hl01 + 1;

                 x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*I';
                 i := i + 1;

                 IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
                    x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
                    i := i + 1;
                 END IF;

                 x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
                 i := i + 1;

                 if ll_sheet_skid_count_4coil <= 0 then
                    x12_table(i) := 'REF*MI*' || to_char(al_ab_job_num);
                    i := i + 1;
                    
                    x12_table(i) := 'REF*SE*' || to_char(ll_cur_coil);
                    i := i + 1;
                    
                    x12_table(i) := 'REF*IX*' || ls_consumed_coil_num;
                    i := i + 1;
                 end if;
                 
                 x12_table(i) := 'PO1**1*UN****' || '***SN*' || ls_coil_org_num ;
                 i := i + 1;

                 x12_table(i) := 'PID*S*MA*ST*S';
                 i := i + 1;

                 x12_table(i) := 'PID*S*MAC*ST*05';
                 i := i + 1;

                 x12_table(i) := 'PID*S*PR*ST*19';
                 i := i + 1;

                 x12_table(i) := 'MEA*WT*N*' || to_char(ll_scrap_nw) || '*LB*01';
                 i := i+1;
                 
                 ll_total_theo_scrap_wt_4job := ll_total_theo_scrap_wt_4job + ll_scrap_nw;
                 
               end if; --if ll_scrap_nw > 0 then
            end loop; --for scrap_rec in alcan_scrap_870_cur loop scrap loop
            
            ll_heavy_light := ll_total_act_scrap_wt_4job - ll_total_theo_scrap_wt_4job;
            
        --end if; --if (ld_scrap_870_date is null) then --Scrap not sent
    end loop; --for coil_rec in coil_cur loop. Coil loop
    
    x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
    i := i + 1;

    x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
    i := i + 1;

    x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
    i := i + 1;

    x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

    -- Write EDI to file

    if li_hl01 > 0 then
        -- WRITE EDI FILE ONLY IF ITEM > 0
        SELECT edi_file_id_seq.nextval
          INTO ll_edi_file_id_870
          FROM dual;
        edi_file        := edi_file_prefix || to_char(ll_edi_file_id_870) || '_Job-' || to_char(al_ab_job_num) || '.edi';
     -- edi_file        := 's_alcan_' || to_char(ll_edi_file_id_870) || '.870';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        FOR j IN 0 .. i LOOP
          utl_file.put_line(edi_file_handle, x12_table(j));

        END LOOP;
        utl_file.fclose(edi_file_handle);
      END IF; -- END WRITING EDI FILE

      --edi_file        := 'send_edi_log'; /* Alex Gerlants. 04/14/2017. Commented out. */
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      --For verifying 997
  /*
      INSERT INTO outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
        VALUES
          (ll_edi_file_id_870,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           SYSDATE,
           edi_file,
           0,
           ll_customer_id,
           ll_st_log,
           '870');


        update    ab_job
        set       edi_file_id_870 = ll_edi_file_id_870,
                  edi_date_870 = sysdate
        where     ab_job_num = al_ab_job_num;
  */      
        insert into ab_job_870_history
        (
           ab_job_num,
           edi_file_id,
           edi_file_name,
           create_870_date_time,
           user_id
        )
        values
        (
           al_ab_job_num ,
           ll_edi_file_id_870,
           edi_file,
           sysdate,
           as_user_id
        );

  /*
        for m in 0 .. k - 1 loop
           update   production_sheet_item
           set      prod_item_edi870_date = sysdate,
                    edi_file_id_870 = ll_edi_file_id_870 
           where    production_sheet_item.prod_item_num = item_num(m);
        end loop;

        for m in 0..p - 1 loop
           update   coil
           set      coil.scrap_870_date = sysdate
           where    coil.coil_abc_num = coil_num(m);

           update   process_coil
           set      scrap_870_date = sysdate
           where    ( coil_abc_num = coil_num(m)) and (scrap_870_date is null);

         end loop;
  */
         commit;

  end if; --end if in select count(*)

  --END LOOP; ------ End of outer loop customer_id

/*
EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN -1;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN -2;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN -3;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN -4;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN -9;
*/
    
  return 1;
end f_edi_novelis_870_per_job;
--------------------------------------------------------
--  DDL for Function F_EDI_NOVELIS_870_REJECT_4JOB
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_NOVELIS_870_REJECT_4JOB" 
 ( 
    al_ab_job_num           ab_job.ab_job_num%type,
    al_coil_abc_num         coil.coil_abc_num%type,
    as_user_id              ab_job_870_history.user_id%type,
    as_original_or_resend   varchar2
    
 )
  return integer
  
is

  /*
  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc                                     varchar2(50) := get_edi_destination('EDI_DIR');

  edi_file                                    varchar2(256) := 'edi_out.txt';
  edi_file_prefix                             varchar2(50) := 'S_novelis_870_'; --production
  --edi_file_prefix                             varchar2(50) := 's_novelis_870_rej_'; --development
  edi_file_handle                             utl_file.file_type;
  su_duns                                     varchar2(10);
  ll_customer_id                              customer.customer_id%type;
  ll_cur_coil                                 coil.coil_abc_num%type;
  ll_gs_log                                   integer;
  ll_st_log                                   integer;
  ls_today                                    varchar2(20) := to_char(sysdate, 'YYYYMMDD');
  ls_today_4                                  varchar2(20) := to_char(sysdate, 'YYMMDD');
  ls_now                                      varchar2(20) := to_char(sysdate, 'HH24MI');
  ls_po                                       varchar2(20);
  ls_finished_goods                           varchar2(32);
  ls_cust_prod_line                           varchar2(8);
  ld_scrap_870_date                           process_coil.scrap_870_date%type;
  ls_coil_org_num                             coil.coil_org_num%type;
  ls_heat                                     coil.lot_num%type;
  ll_prime_nw                                 coil.net_wt%type;
  ll_scrap_nw                                 coil.net_wt%type;
  ll_item_count                               integer;
  li_hl01                                     integer;
  li_hllin                                    integer;
  ll_rowcount                                 number(8);
  ll_edi_file_id_870                          integer;
  ld_edi_date_870                             ab_job.edi_date_870%type;
  --ls_sheet_skid_exists                        char(1);
  ls_consumed_coil_num                        coil.consumed_coil_num%type;
  ls_customer_short_name                      customer.customer_short_name%type;
  ll_sheet_skid_count_4coil                   number(8);
  ll_total_act_scrap_wt_4job                  number(8);
  ll_total_theo_scrap_wt_4job                 number(8);
  ll_heavy_light                              number(8);
  ls_notes                                    varchar2(512);
  ls_material_num                             coil.material_num%type;
  ls_finished_goods_material_num              order_item.finished_goods_material_num%type;

--------------------------------------------------------------------------------------------------   
------------------------------------ Cursors Begin -----------------------------------------------
--------------------------------------------------------------------------------------------------

  /*
  cursor coil_cur is
  select distinct process_coil.coil_abc_num
  from   process_coil
         left outer join production_sheet_item on production_sheet_item.coil_abc_num = process_coil.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    (
              sheet_skid.skid_sheet_status in (0, 2, 4, 13, 12, 16)
           or sheet_skid.skid_sheet_status is null --This is for rejected coils without sheets  
         )
  order by process_coil.coil_abc_num;
  
  coil_rec  coil_cur%ROWTYPE;
  */
   
  --Cursor skid_coil_cur will select data for ab_job and coil_abc_num with skids.
  --If there is a reject coil without sheet skids, this cursor will not select it.
  /*
  cursor skid_coil_cur is
  select coil.coil_abc_num,   
         coil.lot_num,   
         coil.coil_org_num,   
         coil.coil_mid_num,
         nvl(coil.consumed_coil_num, ' ') consumed_coil,
         nvl(coil.material_num, ' ') material_num,
         coil.net_wt,   
         sheet_skid.sheet_tare_wt,   
         sheet_skid.sheet_net_wt,
         sheet_skid.skid_pieces,
         production_sheet_item.prod_item_pieces,
         production_sheet_item.prod_item_num,
         sheet_skid.skid_sheet_status,
         sheet_skid.sheet_skid_num,   
         production_sheet_item.prod_item_note,   
         sheet_skid.sheet_theoretical_wt,   
         production_sheet_item.prod_item_placement,   
         process_coil.process_quantity,   
         production_sheet_item.prod_item_net_wt,   
         sheet_skid.sheet_skid_display_num,
         nvl(customer_order.sales_order, ' ') sales_order,
         nvl(customer_order.orig_customer_po, 'NA') orig_customer_po,
         nvl(order_item.enduser_part_num, ' ') enduser_part_num,
         nvl(order_item.cust_prod_line_id, 'NA') cust_prod_line_id,
         nvl(order_item.finished_goods_material_num, 'NA') finished_goods_material_num,
         (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
         NULL done  
  from   coil   
         join process_coil on coil.coil_abc_num = process_coil.coil_abc_num
         join ab_job on ab_job.ab_job_num = process_coil.ab_job_num
         join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
         join customer_order on customer_order.order_abc_num = order_item.order_abc_num
         left outer join production_sheet_item on coil.coil_abc_num = production_sheet_item.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  ab_job.ab_job_num = al_ab_job_num
  and    coil.coil_abc_num = ll_cur_coil
  order by
         production_sheet_item.coil_abc_num,
         sheet_skid.sheet_skid_display_num;

  skid_coil_rec  skid_coil_cur%rowtype;
  */
  
  cursor scrap_cur is
  select process_coil.coil_abc_num,
         process_coil.process_coil_status,
         process_coil.process_quantity,
         nvl(process_coil.process_end_wt, 0),
         sum(nvl(process_coil.process_end_wt, 0)),
         sum(nvl(production_sheet_item.prod_item_net_wt, 0)),
         case process_coil.process_coil_status
            when 7 then --Rebanded coils
               --(process_coil.process_quantity - sum(production_sheet_item.prod_item_net_wt) - (select process_end_wt from process_coil pc where pc.ab_job_num = 101143 and pc.coil_abc_num = process_coil.coil_abc_num))
               (process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - nvl(process_coil.process_end_wt, 0))
            when 3 then --Rejected coils
               case (select count(*) from production_sheet_item psi where psi.ab_job_num = al_ab_job_num and psi.coil_abc_num = process_coil.coil_abc_num)
                 when 0 then --Rejected coils without sheets
                   (process_coil.process_quantity - sum(nvl(process_coil.process_end_wt, 0)))
                 else --Rejected coils with sheets
                   (process_coil.process_quantity - nvl(process_coil.process_end_wt, 0) - sum(nvl(production_sheet_item.prod_item_net_wt, 0)))     
                end   
             else
               (process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - sum(nvl(process_coil.process_end_wt, 0)))
         end scrap_net_wt
  from   process_coil
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         join ab_job on ab_job.ab_job_num = process_coil.ab_job_num and coil.coil_abc_num = process_coil.coil_abc_num
         left outer join production_sheet_item on production_sheet_item.ab_job_num = process_coil.ab_job_num and production_sheet_item.coil_abc_num = process_coil.coil_abc_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    coil.coil_abc_num = al_coil_abc_num
  group by
         process_coil.coil_abc_num,
         process_coil.process_coil_status,
         process_coil.process_quantity,
         process_coil.process_end_wt
  order by
         process_coil.coil_abc_num;
         
  scrap_rec  scrap_cur%rowtype;
   
--------------------------------------------------------------------------------------------------   
------------------------------------- Cursors End ------------------------------------------------
--------------------------------------------------------------------------------------------------   

  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;

  TYPE coil_num_type IS TABLE OF coil.coil_abc_num%type INDEX BY BINARY_INTEGER;
  coil_num coil_num_type;
  p binary_integer :=0;
  
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;  

BEGIN
  
  --Check if correct customer
  select  customer_order.orig_customer_id,
          customer.customer_duns_number_string,
          customer.customer_short_name
  into    ll_customer_id,
          su_duns,
          ls_customer_short_name
  from    ab_job
          join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
          join customer on customer.customer_id = customer_order.orig_customer_id
  where   ab_job.ab_job_num = al_ab_job_num;
  
  if lower(ls_customer_short_name) not like '%novelis%' then
    return 200; --Wrong customer
  end if;
  
  /* Alex Gerlants. Commented out because if there us more than 1 coil is rejected, the first coil
                    updates ab_job.edi_file_id_870 and ab_job.edi_date_870.
                    Therefore, this script will never create 870 for the subsequent coils.
  --Check if 870 has already been created for al_ab_job_num
  select edi_file_id_870, edi_date_870
  into   ll_edi_file_id_870, ld_edi_date_870
  from   ab_job
  where  ab_job_num = al_ab_job_num;
   
  if not (ll_edi_file_id_870 is null and ld_edi_date_870 is null) then --870 already created for al_ab_job_num
    return 100;
  end if;
  */

  i              := 0;
  k              := 0;
  p              := 0;
  
  select count(distinct process_coil.coil_abc_num)
  into   ll_rowcount
  from   process_coil
         left outer join production_sheet_item on production_sheet_item.coil_abc_num = process_coil.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    (
              sheet_skid.skid_sheet_status in (0, 2, 4, 13, 12, 16)
           or sheet_skid.skid_sheet_status is null --This is for rejected coils without sheets  
         );
    
  if ll_rowcount > 0 then

    select edi_st_log_seq.nextval into ll_st_log from dual;
    select edi_gs_log_seq.nextval into ll_gs_log from dual;
    
    /*
    select  customer_order.orig_customer_id
    into    ll_customer_id
    from    ab_job
            join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
    where   ab_job.ab_job_num = al_ab_job_num;
    
    select  customer.customer_duns_number_string
    into    su_duns
    from    customer
    where   customer.customer_id = ll_customer_id;
    */

    --Production
    x12_table(i) := 'ISA*00*' ||
                    '          *00*          *01*039630926T     *09*0015049350011G *' ||
                    ls_today_4 || '*' || ls_now || '*U*00401*' ||
                    lpad(to_char(ll_gs_log), 9, '0') || '*0*P**';
          
    --Development                
    --x12_table(i) := 'ISA*00*' ||
    --                '          *00*          *ZZ*2NDSFTP        *ZZ*NOVLSTEST      *' ||
    --                ls_today_4 || '*' || ls_now || '*U*00401*' ||
    --                lpad(to_char(ll_gs_log), 9, '0') || '*0*T**';    
                         
    i := i + 1;
          
    --Production
    x12_table(i) := 'GS*RS*039630926T*' || '001504935001' || '*' ||
                    ls_today || '*' || ls_now || '*' ||
                    to_char(ll_gs_log) || '*X*' || '004010';
          
    --Development                
    --x12_table(i) := 'GS*RS*2NDSFTP*' || 'NOVLSTEST' || '*' ||
    --                ls_today || '*' || ls_now || '*' ||
    --                to_char(ll_gs_log) || '*X*' || '004010';
                          
    i := i + 1;
        
    x12_table(i) := 'ST*870*' || to_char(ll_st_log);
    i := i + 1;
    x12_table(i) := 'BSR*2*PP*' || to_char(ll_st_log) || '*' || ls_today ||
                    '***' || ls_now || '*****'; --"AO means scrapped
    i := i + 1;
    x12_table(i) := 'DTM*009*' || ls_today || '*' || ls_now;
    i := i + 1;
    x12_table(i) := 'N1*SU**1*' || su_duns;
    i := i + 1;
    x12_table(i) := 'N1*OU*ALUMINUM BLANKING/MI*1*039630926';
    i := i + 1;

    li_hl01 := 0;
    
    
    
    for scrap_rec in scrap_cur loop --Scrap loop
        ll_scrap_nw := scrap_rec.scrap_net_wt;

        if ll_scrap_nw > 0 then --Theo scrap weight
                 
           if ll_sheet_skid_count_4coil > 0 then --Just in case. Should not happen
             continue; 
           end if;
                
           ll_total_theo_scrap_wt_4job := 0;
                
           select    nvl(sum(return_item_net_wt),0) 
           into      ll_total_act_scrap_wt_4job
           from      return_scrap_item
           where     ab_job_num = al_ab_job_num;

           li_hl01 := li_hl01 + 1;

           x12_table(i) := 'HL*' || to_char(li_hl01) || '*' || to_char(li_hllin) || '*I';
           i := i + 1;

           --IF (ls_po <> ls_finished_goods) AND (ls_po <> 'NA' ) THEN
           --   x12_table(i) := 'PRF*' || ls_po || '****' || ls_cust_prod_line;
           --   i := i + 1;
           --END IF;

           x12_table(i) := 'DTM*206*' || ls_today || '*' || ls_now || '*ED';
           i := i + 1;

           --if ll_sheet_skid_count_4coil <= 0 then
           x12_table(i) := 'REF*MI*' || to_char(al_ab_job_num);
           i := i + 1;
           
           select  coil_org_num, consumed_coil_num, material_num
           into    ls_coil_org_num, ls_consumed_coil_num, ls_material_num
           from    coil
           where   coil_abc_num = al_coil_abc_num;
                      
           --x12_table(i) := 'REF*SE*' || to_char(al_coil_abc_num); --???. This is production_sheet_item.prod_item_num
           --i := i + 1;
                      
           x12_table(i) := 'REF*IX*' || ls_consumed_coil_num;
           i := i + 1;
           --end if;
           
           select  order_item.finished_goods_material_num
           into    ls_finished_goods_material_num
           from    ab_job   
                   join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
           where   ab_job.ab_job_num = al_ab_job_num;
                  
           x12_table(i) := 'PO1**1*UN****' || '***SN*' || ls_coil_org_num || '***VP*' || ls_finished_goods_material_num;
           i := i + 1 ;

           x12_table(i) := 'PID*S*MA*ST*S';
           i := i + 1;

           x12_table(i) := 'PID*S*MAC*ST*02'; --"02" means rejected coil
           i := i + 1;

           x12_table(i) := 'PID*S*PR*ST*19';
           i := i + 1;

           x12_table(i) := 'MEA*WT*N*' || to_char(ll_scrap_nw) || '*LB*01';
           i := i+1;
                 
           ll_total_theo_scrap_wt_4job := ll_total_theo_scrap_wt_4job + ll_scrap_nw;
                 
        end if; --if ll_scrap_nw > 0 then
    end loop; --for scrap_rec in alcan_scrap_870_cur loop scrap loop
    
    x12_table(i) := 'CTT*' || to_char(li_hl01 - 1);
    i := i + 1;

    x12_table(i) := 'SE*' || to_char(i - 1) || '*' || to_char(ll_st_log);
    i := i + 1;

    x12_table(i) := 'GE*1*' || to_char(ll_gs_log);
    i := i + 1;

    x12_table(i) := 'IEA*1*' || lpad(to_char(ll_gs_log), 9, '0');

    -- Write EDI to file

    if li_hl01 > 0 then
        -- WRITE EDI FILE ONLY IF ITEM > 0
        SELECT edi_file_id_seq.nextval
          INTO ll_edi_file_id_870
          FROM dual;
        edi_file        := edi_file_prefix || to_char(ll_edi_file_id_870) || '_Job-' || to_char(al_ab_job_num) || '.edi';
     -- edi_file        := 's_alcan_' || to_char(ll_edi_file_id_870) || '.870';
        edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'W');

        FOR j IN 0 .. i LOOP
          utl_file.put_line(edi_file_handle, x12_table(j));

        END LOOP;
        utl_file.fclose(edi_file_handle);
      END IF; -- END WRITING EDI FILE

      --edi_file        := 'send_edi_log'; /* Alex Gerlants. 04/14/2017. Commented out. */
      edi_file_handle := utl_file.fopen(edi_loc, edi_file, 'a');
      utl_file.put_line(edi_file_handle, 'Type: 870');
      utl_file.put_line(edi_file_handle,
                        'Sending Time: ' ||
                        to_char(SYSDATE, 'MM/DD/YY HH24:MI'));
      utl_file.put_line(edi_file_handle,
                        'Interchange Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Group Control #: ' || ll_gs_log);
      utl_file.put_line(edi_file_handle, 'Set Control #: ' || ll_st_log);
      utl_file.put_line(edi_file_handle, '');
      utl_file.put_line(edi_file_handle, '');
      utl_file.fclose(edi_file_handle);

      --For verifying 997
 
      INSERT INTO outbound_edi_transaction
          (edi_file_id,
           duns_from,
           duns_to,
           interchange_control_number,
           group_control_number,
           transaction_time,
           edi_file_name,
           fa_receive_status,
           customer_id,
           set_control_num,
           transaction_type_id)
        VALUES
          (ll_edi_file_id_870,
           '039630926',
           su_duns,
           ll_gs_log,
           ll_gs_log,
           SYSDATE,
           edi_file,
           0,
           ll_customer_id,
           ll_st_log,
           '870');


        update    ab_job
        set       edi_file_id_870 = ll_edi_file_id_870,
                  edi_date_870 = sysdate
        where     ab_job_num = al_ab_job_num;
      
  
        ls_notes :=  ' Fully rejected coil. AB Job: ' || to_char(al_ab_job_num) 
                     || ' coil_abc_num: ' || to_char(al_coil_abc_num) 
                     || ' coil_org_num: ' || ls_coil_org_num
                     || ' Rejected weight: ' || to_char(ll_scrap_nw);
        
        insert into ab_job_870_history
        (
           ab_job_num,
           edi_file_id,
           edi_file_name,
           create_870_date_time,
           user_id,
           notes
        )
        values
        (
           al_ab_job_num ,
           ll_edi_file_id_870,
           edi_file,
           sysdate,
           as_user_id,
           as_original_or_resend || ' ' || ls_notes
        );
        
        update    ab_job
        set       edi_file_id_870 = ll_edi_file_id_870,
                  edi_date_870 = sysdate
        where     ab_job_num = al_ab_job_num;


        for m in 0 .. k - 1 loop
           update   production_sheet_item
           set      prod_item_edi870_date = sysdate,
                    edi_file_id_870 = ll_edi_file_id_870 
           where    production_sheet_item.prod_item_num = item_num(m);
        end loop;

        for m in 0..p - 1 loop
           update   coil
           set      coil.scrap_870_date = sysdate
           where    coil.coil_abc_num = coil_num(m);

           update   process_coil
           set      scrap_870_date = sysdate
           where    ( coil_abc_num = coil_num(m)) and (scrap_870_date is null);

         end loop;

         commit;

  end if; --end if in select count(*)

  --END LOOP; ------ End of outer loop customer_id

/*
EXCEPTION
  WHEN utl_file.invalid_path THEN
    utl_file.fclose_all;
    RETURN -1;
  WHEN utl_file.invalid_mode THEN
    utl_file.fclose_all;
    RETURN -2;
  WHEN utl_file.invalid_operation THEN
    utl_file.fclose_all;
    RETURN -3;
  WHEN utl_file.write_error THEN
    utl_file.fclose_all;
    RETURN -4;
  WHEN OTHERS THEN
    utl_file.fclose_all;
    RETURN -9;
*/
    
  return 1;
end f_edi_novelis_870_reject_4job;
--------------------------------------------------------
--  DDL for Function F_EDI_WISE_870
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_WISE_870" return integer is
NoCoilFound integer := 0;
Success integer :=1;
/*Send 870 to Wise Alloys LLC
Customer_id = 1364 
*/
/*
If sucess, then return 1
If fail, return the coil_abc_num that fails
*/
li_rc integer := 0;
li_count integer:=0;
ll_customer_id integer :=1364;

--As per customer's request, one 870 file contains skids under one coil
Cursor cur_coil_abc_num IS
SELECT distinct coil.coil_abc_num
FROM 		SHEET_SKID, production_sheet_item, sheet_skid_detail,coil
WHERE        (sheet_skid.skid_sheet_status in ( 2, 4)) and
             (production_sheet_item.prod_item_edi870_date is NULL ) and 
             (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num) and
			       (sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num) and
			       (coil.coil_abc_num = production_sheet_item.coil_abc_num ) and
             (coil.customer_id = ll_customer_id);

begin

SELECT count(*) into li_count
FROM 		SHEET_SKID, production_sheet_item, sheet_skid_detail,coil
WHERE        (sheet_skid.skid_sheet_status in ( 2, 4)) and
             (production_sheet_item.prod_item_edi870_date is NULL ) and 
             (sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num) and
			       (sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num) and
			       (coil.coil_abc_num = production_sheet_item.coil_abc_num ) and
             (coil.customer_id = ll_customer_id);
            
if li_count <> 0 then   
   for coil_abc_num_rec in cur_coil_abc_num loop
       --As per customer's request, one 870 file contains skids under one coil
       li_rc := f_edi_wise_870_by_coil(coil_abc_num_rec.coil_abc_num); 
       
       if li_rc <> 1 then
       return coil_abc_num_rec.coil_abc_num ;
       end if;         
   end loop;
   
   return Success;
end if;  
  
return(NoCoilFound);
end F_EDI_WISE_870;
  GRANT EXECUTE ON "DBO"."F_EDI_WISE_870" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function F_EDI_WISE_870_BY_COIL
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_EDI_WISE_870_BY_COIL" (al_coil_abc_num coil.coil_abc_num%type ) return integer is
Result integer :=1;

li_skid_count integer:=0;
li_hl_num integer:=0;
li_customer_id integer :=1364;  --Wise Alloy
ls_coil_org_num varchar2(32);
ln_coil_net_wt number(8,0);
ls_sheet_type varchar2(18);
ln_width number(10,5);
ln_length number(10,5);

edi_file_prefix VARCHAR2(50) := 'S_wisealloys_';

ls_today_short VARCHAR2(20) := to_char(SYSDATE, 'yymmdd');
ls_today VARCHAR2(20) := to_char(SYSDATE, 'yyyymmdd');
ls_now VARCHAR2(20) := to_char(SYSDATE, 'hh24mi');

li_gs_log INTEGER;
li_st_log INTEGER;

Cursor cur_skid IS
SELECT  s.sheet_skid_num, s.sheet_net_wt, s.sheet_tare_wt, s.skid_pieces, d.prod_item_num, c.coil_gauge, o.orig_customer_po, j.order_item_num, j.order_abc_num
FROM 		sheet_skid s, production_sheet_item p, sheet_skid_detail d, coil c, customer_order o, ab_job j
WHERE        (s.skid_sheet_status in ( 2, 4)) and
             (p.prod_item_edi870_date is NULL ) and
             (s.sheet_skid_num = d.sheet_skid_num) and
			       (d.prod_item_num = p.prod_item_num) and
             (s.ref_order_abc_num = o.order_abc_num) and
             (s.ab_job_num = j.ab_job_num) and
             (p.coil_abc_num = c.coil_abc_num) and
			       (c.coil_abc_num = al_coil_abc_num ) and
             (c.customer_id = li_customer_id);

type edi_870_tabletype is table of varchar2(32767) index by binary_integer;
edi_870 edi_870_tabletype;
j binary_integer := 0;

--Alex Gerlants. 11/15/2016. Commented out, and added the line after.
--edi_location varchar2(50):='/templar/templar/incoming/senddata';
edi_location VARCHAR2(50) := dbo.get_edi_destination('EDI_DIR');

edi_file varchar2 (50) := 'edi_out.txt';
edi_file_handle UTL_FILE.FILE_TYPE;
li_edi_870_id integer;

TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%type INDEX BY BINARY_INTEGER;
item_num prod_item_type;
k binary_integer :=0;


begin

--* creat edi8683 files here
SELECT EDI_ST_LOG_SEQ.NEXTVAL INTO li_st_log FROM dual;
SELECT EDI_GS_LOG_SEQ.NEXTVAL INTO li_gs_log FROM dual;

edi_870(j):= 'ISA*00*          *00*          *01*039630926T     *ZZ*WISEALLOYS     *'
  || ls_today_short ||'*'|| ls_now ||'*U*00401*'||LPAD(to_char(li_gs_log),9,'0')|| '*0*P**'; j := j + 1;
edi_870(j) := 'GS*RS*039630926T*WISEALLOYS*' || ls_today ||'*'||ls_now||'*'||li_gs_log||'*X*004010'   ; j :=j + 1;
edi_870(j) := 'ST*870*'|| li_st_log; j :=j + 1;
edi_870(j) := 'BSR*2*PP*' || li_st_log || '*' || ls_today || '***' || ls_now ; j :=j + 1;
edi_870(j) := 'DTM*009*' || ls_today || '*' || ls_now; j := j +1;
edi_870(j) := 'N1*MP**9*' || '001344202005'; j := j +1;
edi_870(j) := 'N1*OU**1*039630926'; j := j + 1;

li_hl_num := li_hl_num +1;
edi_870(j) := 'HL*1**I'; j := j + 1;   --Coil level


select c.coil_org_num, c.net_wt into ls_coil_org_num, ln_coil_net_wt
from coil c
where c.coil_abc_num = al_coil_abc_num;
edi_870(j) := 'PO1**' || to_char(ln_coil_net_wt) || '*UN***VU*' || al_coil_abc_num || '*CA*' || ls_coil_org_num || '*CU*01'; j := j + 1;

-- Skid level
for skid_rec in cur_skid loop
  li_skid_count := li_skid_count + 1;
  item_num(k) := skid_rec.prod_item_num;
  k := k+1;

  li_hl_num := li_hl_num +1;
  edi_870(j) := 'HL*' || to_char(li_hl_num) || '*1*F'; j := j + 1;

  edi_870(j) := 'PO1**' || to_char(skid_rec.sheet_net_wt) || '*01***VU*' || skid_rec.sheet_skid_num|| '*ON*' || skid_rec.orig_customer_po ||
                '*IN*' || skid_rec.order_item_num ; j := j + 1;
  edi_870(j) := 'PID*S*67*ST*01'; j := j + 1;
  edi_870(j) := 'MEA**TH*' || to_char(skid_rec.coil_gauge) || '*ED'; j := j + 1;

  select sheet_type into ls_sheet_type
  from order_item o
  where o.order_abc_num = skid_rec.order_abc_num and  o.order_item_num = skid_rec.order_item_num;
  ls_sheet_type := upper(ltrim(rtrim(ls_sheet_type)));

  IF ls_sheet_type = 'RECTANGLE' THEN
     select rt_length, rt_width into ln_length, ln_width
     from rectangle
     where order_abc_num =  skid_rec.order_abc_num and order_item_num = skid_rec.order_item_num;
  ELSIF ls_sheet_type = 'FENDER' THEN
     select fe_side, fe_side into ln_length, ln_width
     from fender
     where order_abc_num =  skid_rec.order_abc_num and order_item_num = skid_rec.order_item_num;
  ELSIF ls_sheet_type = 'PARALLELOGRAM' THEN
     select p_length, p_width into ln_length, ln_width
     from parallelogram
     where order_abc_num =  skid_rec.order_abc_num and order_item_num = skid_rec.order_item_num;
  ELSIF ls_sheet_type = 'CHEVRON' THEN
     select ch_length, ch_width into ln_length, ln_width
     from chevron
     where order_abc_num =  skid_rec.order_abc_num and order_item_num = skid_rec.order_item_num;
  ELSIF ls_sheet_type = 'CIRCLE' THEN
     select c_diameter, c_diameter into ln_length, ln_width
     from circle
     where order_abc_num =  skid_rec.order_abc_num and order_item_num = skid_rec.order_item_num;
  ELSIF ls_sheet_type = 'TRAPEZOID' THEN
     select tr_long_length, tr_width into ln_length, ln_width
     from trapezoid
     where order_abc_num =  skid_rec.order_abc_num and order_item_num = skid_rec.order_item_num;
  ELSIF ls_sheet_type = 'L.TRAPEZOID' THEN
     select ltr_long_length, ltr_width into ln_length, ln_width
     from left_trapezoid
     where order_abc_num =  skid_rec.order_abc_num and order_item_num = skid_rec.order_item_num;
  ELSIF ls_sheet_type = 'R.TRAPEZOID' THEN
     select rtr_long_length, rtr_width into ln_length, ln_width
     from right_trapezoid
     where order_abc_num =  skid_rec.order_abc_num and order_item_num = skid_rec.order_item_num;
  ELSIF ls_sheet_type = 'LIFTGATE' THEN
     select li_length, li_width into ln_length, ln_width
     from liftgate_shape
     where order_abc_num =  skid_rec.order_abc_num and order_item_num = skid_rec.order_item_num;
  ELSIF ls_sheet_type = 'REINFORCEMENT' THEN
     select re_length, re_width into ln_length, ln_width
     from reinforcement
     where order_abc_num =  skid_rec.order_abc_num and order_item_num = skid_rec.order_item_num;
  ELSIF ls_sheet_type = 'OTHER' THEN
     select x_1, x_1 into ln_length, ln_width
     from x1_shape
     where order_abc_num =  skid_rec.order_abc_num and order_item_num = skid_rec.order_item_num;
  END IF;

  edi_870(j) := 'MEA**WD*' || to_char(ln_width) || '*ED'; j := j + 1;
  edi_870(j) := 'MEA**LN*' || to_char(ln_length * skid_rec.skid_pieces) || '*ED'; j := j + 1;
  edi_870(j) := 'MEA**NH*' || to_char(skid_rec.skid_pieces) || '*PC'; j := j + 1;
  edi_870(j) := 'MEA**N*' || to_char(skid_rec.sheet_net_wt) || '*01'; j := j + 1;
  edi_870(j) := 'MEA**G*' || to_char(skid_rec.sheet_net_wt + skid_rec.sheet_tare_wt) || '*01'; j := j + 1;

end loop;

edi_870(j) := 'CTT*' || li_hl_num; j := j + 1;
edi_870(j) :='SE*'|| to_char(j-1) || '*' || to_char(li_st_log); j :=j + 1;
edi_870(j) :='GE*1*' || to_char(li_gs_log); j :=j + 1;
edi_870(j) :='IEA*1*' || LPAD(to_char(li_gs_log),9,'0');

SELECT edi_file_id_seq.NEXTVAL INTO li_edi_870_id FROM DUAL;
-- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
-- edi_file := 'S_wisealloys_'|| li_edi_870_id ||'.870';
-- edi_file := 'S_wisealloys_'|| li_edi_870_id ||'.edi';
edi_file := edi_file_prefix   || li_edi_870_id ||'.edi';
edi_file_handle :=utl_file.fopen(edi_location,edi_file,'W');
--write edi to file
FOR i IN 0..j LOOP
    utl_file.put_line(edi_file_handle,edi_870(i));
END LOOP;

utl_file.fclose(edi_file_handle);

--Update edi870 sent time in table:production_sheet_item.
for m in 0..k-1
loop
     UPDATE production_sheet_item
     SET prod_item_edi870_date = SYSDATE,
         edi_file_id_870 = li_edi_870_id /* Alex Gerlants. 09/06/2016. New column */
     WHERE production_sheet_item.prod_item_num = item_num(m);
end loop;
COMMIT;

return(Result);

EXCEPTION
     WHEN UTL_FILE.INVALID_PATH THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN -2;
     WHEN UTL_FILE.INVALID_MODE THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN -2;
    WHEN UTL_FILE.INVALID_OPERATION THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN -2;
    WHEN UTL_FILE.WRITE_ERROR THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN -2;
    WHEN OTHERS THEN
     UTL_FILE.FCLOSE_ALL;
      RETURN -2;


end F_EDI_WISE_870_BY_COIL;
