--  DDL for Function F_GET_COIL_BALANCE_IN_JOB
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_COIL_BALANCE_IN_JOB" (a_coil_id in coil.coil_abc_num%type, a_job_num in ab_job.ab_job_num%type) return  INTEGER is
  Result Integer;
  Skid_wt Integer;
  Scrap_wt Integer;
  Coil_wt Integer;
begin
  SELECT NVL(sum(production_sheet_item.prod_item_net_wt),0) into Skid_wt
                FROM production_sheet_item
                WHERE (production_sheet_item.ab_job_num = a_job_num) and
                      (production_sheet_item.coil_abc_num = a_coil_id);
 
  SELECT NVL(sum(return_scrap_item.return_item_net_wt),0) into Scrap_wt
                FROM return_scrap_item
                WHERE (return_scrap_item.ab_job_num= a_job_num) and
                      (return_scrap_item.coil_abc_num =a_coil_id)   ; 
  
  select ( process_coil.process_quantity - NVL(process_coil.process_end_wt, process_coil.process_quantity) )into Coil_wt
  from process_coil
  where process_coil.ab_job_num = a_job_num and process_coil.coil_abc_num = a_coil_id;

  Result := -(Coil_wt - Skid_wt - Scrap_wt);
  return(Result);
end F_GET_COIL_BALANCE_IN_JOB;
  GRANT EXECUTE ON "DBO"."F_GET_COIL_BALANCE_IN_JOB" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function F_GET_COIL_BAL_PERCENT_JOB
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_COIL_BAL_PERCENT_JOB" (a_coil_id in coil.coil_abc_num%type, a_job_num in ab_job.ab_job_num%type) return number is
  Result number (6,3);
  coil_init_wt coil.net_wt%type;
begin
  --Result := 0;
  select coil.net_wt into coil_init_wt
  from coil
  where coil.coil_abc_num = a_coil_id;
  result := (f_get_coil_balance_in_job(a_coil_id, a_job_num )) / coil_init_wt * 100;
  return(Result);
end F_GET_COIL_BAL_PERCENT_JOB;
  GRANT EXECUTE ON "DBO"."F_GET_COIL_BAL_PERCENT_JOB" TO "AGERLANTS"
