  CREATE OR REPLACE FUNCTION "DBO"."F_GET_COIL_CERT_RECEVD" (as_coil_org_num in varchar2) return char
is

  result           char(1);
  li_counter       number(2);
  li_counter_863   number(2);
  
begin
  -- Author: Alex Gerlants
  -- Date: May 1, 2019
 
  select   count(*) 
  into     li_counter_863
  from     cert_label_customers
  where    customer_id = 
  (
     select max(customer_id) from coil where coil_org_num = as_coil_org_num
  );
  
  if li_counter_863 <= 0 then --863 not required for customer
    result := null;
    return(result);
  end if;

  select count(*)
  into   li_counter
  from   data_in_863
  where  coil_num = as_coil_org_num;
  
  --if li_counter_863 > 0 then --863 required for customer
    if li_counter > 0 then
        result := 'Y';
    else
        result := 'N';
    end if;
  --else --863 not required for customer
  --   result := null;
  --end if;

  return(result);
end f_get_coil_cert_recevd;
