--  DDL for Function F_GET_COIL_DATE_RECEIVED
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_COIL_DATE_RECEIVED" (i_coil_id in coil.coil_org_num%type) return date is
  Result           date;
  temp             date;
  li_coil_status   coil.coil_status%type;
  li_counter       integer; --Alex Gerlants, 05/17/2019. Transfer_Coil_Duration_Calculation
  ld_transfer_date date; --Alex Gerlants, 05/17/2019. Transfer_Coil_Duration_Calculation
  ll_coil_abc_num  coil.coil_abc_num%type;
  ld_date_received coil.date_received%type;
  
begin
  
  select count(*)
  into   li_counter 
  from   dbo.coil_ownership_transfer
  where  coil_org_num = i_coil_id;
  
  if li_counter > 0 then --Coil has been transferred
    select  max(coil_abc_num_new), max(transfer_datetime)
    into    ll_coil_abc_num, ld_transfer_date
    from    dbo.coil_ownership_transfer
    where  coil_org_num = i_coil_id;
  end if;
 
  /*
  select coil_status, date_received 
  into   li_coil_status, ld_date_received
  from   coil 
  where  coil_org_num =  i_coil_id;
  */
  
  select max(date_received), max(coil_status)
  into   ld_date_received, li_coil_status
  from   coil 
  where  coil_org_num =  i_coil_id;
  --group by date_received;
  
  if li_counter > 0 then --Coil has been transferred
    Result := ld_transfer_date;
  else
    Result := ld_date_received;
  end if;
  
  return(Result);
end f_get_coil_date_received;

--create or replace public synonym f_get_coil_date_received for dbo.f_get_coil_date_received;
