  CREATE OR REPLACE FUNCTION "DBO"."F_GET_COIL_DURATION" (i_coil_id in coil.coil_abc_num%type) return integer is
  Result integer;
  temp date;
  coilstatus integer;
begin
  SELECT COIL_STATUS, DATE_RECEIVED into coilstatus, temp
  FROM COIL 
  WHERE COIL_ABC_NUM =  i_coil_id;
  
  if (coilstatus = 10) or (coilstatus = 0) then Result := 0;
  else 
       select (sysdate - NVL(max(coil_track_date), temp)) into Result from coil_track
       WHERE COIL_ABC_NUM =  i_coil_id; 
  end if;
  
  return(Result);
end f_get_coil_duration;
