--------------------------------------------------------
--  DDL for Function F_GET_COIL_PROCESS_WT_4JOB
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_COIL_PROCESS_WT_4JOB" (p_ab_job in ab_job.ab_job_num%type, p_coil_abc_num in coil.coil_abc_num%type) return number is

  result number :=0;

  /*
  Calculate the beginning coil weight for ab_job_num, and coil_abc_num.

  This function is a logical copy of code in wf_set_values for w_prod_order_summary
  in silverdome6.pbl.
  This is a calculation of the 3 values to populate processed_t.Text: ll_coilnet, ll_unprocessednet, ll_rejnet.

  ls_modstring = "processed_t.Text = ~"" + String((ll_coilnet - ll_unprocessednet - ll_rejnet), "###,###,###") + "~""
  */

  ll_wt                    number;
  ll_shift_end_wt          number;
  ll_wt1                   number;
  ll_wt2                   number;
  ll_sum                   number;
  ll_processed_wt          number;
  ll_unprocessed_wt        number;

begin

    ll_sum := 0;

    --Select processed weight
    select   nvl(sum(process_quantity), 0)
    into     ll_processed_wt
    from     process_coil
    where    ab_job_num = p_ab_job
    and      coil_abc_num = p_coil_abc_num;

    --Calculate unprocessed weight
    select nvl(process_quantity, 0), nvl(process_end_wt,0)
    into   ll_wt, ll_shift_end_wt
    from   process_coil
    where  coil_abc_num = p_coil_abc_num
    and    ab_job_num = p_ab_job;

    ll_wt := coalesce(ll_wt, 0);

    if ll_shift_end_wt is null then
      select  net_wt_balance
      into    ll_wt1
      from    coil
      where   coil_abc_num = p_coil_abc_num;

      ll_wt1 := coalesce(ll_wt1, 0);
    else
      ll_wt1 := ll_shift_end_wt;
    end if;

    select max(process_quantity)
    into   ll_wt2
    from   process_coil
    where  coil_abc_num = p_coil_abc_num
    and    process_quantity < ll_wt;


    ll_wt2 := coalesce(ll_wt2, 0);

    if ll_wt1 > ll_wt2 then
       ll_unprocessed_wt := ll_wt1;
     else
       ll_unprocessed_wt := ll_wt2;
    end if;

   result := ll_processed_wt - ll_unprocessed_wt;

   return(result);
end f_get_coil_process_wt_4job;
  GRANT EXECUTE ON "DBO"."F_GET_COIL_PROCESS_WT_4JOB" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function F_GET_COIL_QA_ONHOLD_WEIGHT
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_COIL_QA_ONHOLD_WEIGHT" (i_coil_id in coil.coil_abc_num%type, i_job_num in ab_job.ab_job_num%type) 
return number is
  result number;
begin
  
    result := 0;
    
    select nvl(sum(prod_item_net_wt) , 0)
    into   result
		from   production_sheet_item
		where  ab_job_num = i_job_num 
    and    coil_abc_num = i_coil_id 
    and    prod_item_status = 4;
    
    return(result);
end f_get_coil_qa_onhold_weight;
