--  DDL for Function F_GET_COIL_QR_RECEVD
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_COIL_QR_RECEVD" 
       (
          al_customer_id  in coil.customer_id%type,
          as_coil_org_num in varchar2
       ) 
return char

is

  result          char(3);
  li_counter      number(2);
  li_counter_qr   number(2);
  
begin
  -- Alex Gerlants. 1382_Add_QR_Received_To_Coil_and_Prod_Screens
  -- Date: 01/20/2022

  select   count(*) 
  into     li_counter_qr
  from     qr_required_customers
  where    customer_id = al_customer_id;
  
  if li_counter_qr <= 0 then --QR not required for customer
    result := null;
    return (result);
  end if;
  
  select count(*)
  into   li_counter
  from   inbound_coil_status
  where  coil_number = as_coil_org_num
  and    barcode_string is not null;
  
  --if li_counter_qr > 0 then --QR required for customer
     if li_counter > 0 then
        result := 'Y';
     else
       --Try to get it from table barcode_string. It is populated in w_qr_manual in inv_coil.pbl
       select  count(*)
       into    li_counter
       from    dbo.barcode_string
       where   coil_org_num = as_coil_org_num;
       
       if li_counter > 0 then
         result := 'Y';
       else
         result := 'N';
       end if;
     end if;
  --else --QR not required for customer
  --   result := null;
  --end if;

  return(result);
end f_get_coil_qr_recevd;
