--  DDL for Function F_GET_COIL_REBANDED_WT
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_COIL_REBANDED_WT" (i_coil_id in coil.coil_abc_num%type, coil_begin_wt in coil.net_wt%type) return coil.net_wt%type is
  Result coil.net_wt%type;
--  temp date;
--  coilstatus integer;
  Cursor info_cur IS
         SELECT COIL_CUR_NETWT
         FROM COIL_TRACK
         WHERE COIL_ABC_NUM = i_coil_id and COIL_PRE_NETWT = coil_begin_wt and COIL_PRE_NETWT > COIL_CUR_NETWT and COIL_CUR_STATUS = 7;
  Cursor process_cur IS
         select process_coil.process_end_wt 
         from process_coil
         where coil_abc_num = i_coil_id and process_coil.process_quantity = coil_begin_wt and process_coil.process_coil_status = 7;
  --Type info_tabletype IS table of info_cur%ROWTYPE INDEX by binary_integer;
  --info_table info_tabletype;
  --info_rec info_cur%rowtype;
begin
 result := null;
 for process_rec in process_cur
 loop
     result :=process_rec.process_end_wt;
 end loop;
 
 if result is null then
       FOR info_rec in info_cur
           loop
           result := info_rec.coil_cur_netwt;
           end loop;
 end if;
  return(Result);
end f_get_coil_rebanded_wt;
  GRANT EXECUTE ON "DBO"."F_GET_COIL_REBANDED_WT" TO "AGERLANTS"
