  Cursor process_cur IS
         select process_coil.process_end_wt 
         from process_coil
         where coil_abc_num = i_coil_id and process_coil.process_quantity = coil_begin_wt and process_coil.process_coil_status = 7;
  --Type info_tabletype IS table of info_cur%ROWTYPE INDEX by binary_integer;
  --info_table info_tabletype;
  --info_rec info_cur%rowtype;
begin
 result := null;
 
 --Alex Gerlants. 05/18/2021. Begin
 select   coil_status
 into     li_coil_status
 from     coil
 where    coil_abc_num = i_coil_id;
 
 if li_coil_status <> 7 then
   return result;
