--------------------------------------------------------
--  DDL for Function F_GET_COIL_REBANDED_WT_PER_JOB
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_COIL_REBANDED_WT_PER_JOB" 
 ( 
    al_ab_job_num  ab_job.ab_job_num%type    
 )
  return integer
  
is

  ll_cur_coil                  coil.coil_abc_num%type;
  ll_rowcount                  number(8);
  ll_total_rej_coil_wt_4job    number(8);
  ll_wt1                       number(8);
  ll_wt2                       number(8);
  ll_wt                        number(8);
  ll_shift_end_wt              number(8);

--------------------------------------------------------------------------------------------------   
------------------------------------ Cursors Begin -----------------------------------------------
--------------------------------------------------------------------------------------------------

  cursor coil_cur is
  select distinct coil.coil_abc_num
  from   coil   
         join process_coil on coil.coil_abc_num = process_coil.coil_abc_num
  where  process_coil.process_coil_status = 7
  and    process_coil.ab_job_num = al_ab_job_num
  order by 
         process_coil.coil_abc_num;
  
  coil_rec  coil_cur%ROWTYPE;

--------------------------------------------------------------------------------------------------   
------------------------------------- Cursors End ------------------------------------------------
--------------------------------------------------------------------------------------------------   

begin

  select count(distinct coil.coil_abc_num)
  into   ll_rowcount
  from   coil   
         join process_coil on coil.coil_abc_num = process_coil.coil_abc_num
  where  process_coil.process_coil_status = 7
  and    process_coil.ab_job_num = al_ab_job_num;
  
  if ll_rowcount > 0 then

    ll_total_rej_coil_wt_4job := 0;

    for coil_rec in coil_cur loop --Coil loop
       ll_cur_coil := coil_rec.coil_abc_num;
-------------

       select nvl(process_quantity, 0), nvl(process_end_wt, 0)
       into   ll_wt, ll_shift_end_wt
       from   process_coil
       where  coil_abc_num = ll_cur_coil
       and    ab_job_num = al_ab_job_num;

       if ll_shift_end_wt = 0 then
         select nvl(net_wt_balance , 0)
         into   ll_wt1
         from   coil
         where  coil_abc_num = ll_cur_coil;
       else
         ll_wt1 := ll_shift_end_wt;
       end if;

       if ll_wt1 <> 0 then 
         ll_wt1 := ll_shift_end_wt;
       end if;

       select nvl(max(process_quantity) , 0)
       into   ll_wt2
       from   process_coil
       where  coil_abc_num = ll_cur_coil 
       and    process_quantity < ll_wt;
       
       if ll_wt1 > ll_wt2 then
         ll_total_rej_coil_wt_4job := ll_total_rej_coil_wt_4job + ll_wt1;
       else
         ll_total_rej_coil_wt_4job := ll_total_rej_coil_wt_4job + ll_wt2;
       end if;

-------------

    end loop; --for coil_rec in coil_cur loop. Coil loop
  end if; --end if in select count(*)
    
  ll_total_rej_coil_wt_4job := nvl(ll_total_rej_coil_wt_4job, 0); 
  return ll_total_rej_coil_wt_4job;

end f_get_coil_rebanded_wt_per_job;
