--  DDL for Function F_GET_COIL_SAMPLE_WT
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_COIL_SAMPLE_WT" (i_coil_id in coil.coil_abc_num%type, job_num in ab_job.ab_job_num%type) return coil.net_wt%type is
  result coil.net_wt%type;

begin
 
 result := 0;
 SELECT sum(psi.prod_item_net_wt) into result
                FROM production_sheet_item psi, sheet_skid ss, sheet_skid_detail ssd
                WHERE psi.prod_item_num = ssd.prod_item_num and ss.sheet_skid_num = ssd.sheet_skid_num and
                      psi.ab_job_num = job_num and psi.coil_abc_num = i_coil_id and
                      ss.skid_sheet_status = 12;
 return (result);
   
            
end f_get_coil_sample_wt;
  GRANT EXECUTE ON "DBO"."F_GET_COIL_SAMPLE_WT" TO "AGERLANTS"
