--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_COIL_SCRAP_COUNT" (al_coil_abc_num in integer) return integer
is

  result      integer;
  li_counter  number(2); --Alex Gerlants. 08/21/2019. Changed from (1) to (2)...just in case
  
begin
  -- Author: Alex Gerlants
  -- Date: September 11, 2020
  
  select count(*) 
  into   li_counter
  from   return_scrap_item 
  where  coil_abc_num = al_coil_abc_num;
  
  if li_counter > 0 then
      result := 1;
  else
      result := 0;
  end if;

  return(result);
end f_get_coil_scrap_count;
