  -- Author: Alex Gerlants
  -- Date: September 11, 2020
  
  select count(*) 
  into   li_counter
  from   production_sheet_item 
  where  coil_abc_num = al_coil_abc_num;
  
  if li_counter > 0 then
      result := 1;
  else
      result := 0;
  end if;

  return(result);
end f_get_coil_sheet_count;
