--  DDL for Function F_GET_COIL_SHIP_WT
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_COIL_SHIP_WT" (i_coil_id in coil.coil_abc_num%type, job_num in ab_job.ab_job_num%type) return coil.net_wt%type is
  result coil.net_wt%type;

begin
 
 result := 0;
 SELECT sum(psi.prod_item_net_wt) into result
                FROM production_sheet_item psi, sheet_skid ss, sheet_skid_detail ssd
                WHERE psi.prod_item_num = ssd.prod_item_num and ss.sheet_skid_num = ssd.sheet_skid_num and
                      psi.ab_job_num = job_num and psi.coil_abc_num = i_coil_id and
                      ss.skid_sheet_status in (0,2,8,13);           -- 0:Gone, 2:Ready, 8:Warehouse Ready, 13:Partial Ready
 return (result);
   
            
end f_get_coil_ship_wt;
  GRANT EXECUTE ON "DBO"."F_GET_COIL_SHIP_WT" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function F_GET_COIL_UNPROCESS_WT_4JOB
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_COIL_UNPROCESS_WT_4JOB" (p_ab_job in ab_job.ab_job_num%type, p_coil_abc_num in coil.coil_abc_num%type) return number is

  result number :=0;

  /*
  Calculate the processed coil weight for ab_job_num, and coil_abc_num.

  This function is a logical copy of code in wf_set_values for w_prod_order_summary
  in silverdome6.pbl.
  This is a calculation of the value to populate rejcoil_net_t.Text: ll_rejnet.

  ls_modstring = "rejcoil_net_t.Text = ~"" + String(ll_rejnet, "###,###,###") + "~""
  */

  ll_wt                    number;
  ll_shift_end_wt          number;
  ll_wt1                   number;
  ll_wt2                   number;
  ll_sum                   number;
  --ll_processed_wt          number;
  ll_unprocessed_wt        number;

begin

    ll_sum := 0;
/*
    --Select processed weight
    select   nvl(sum(process_quantity), 0)
    into     ll_processed_wt
    from     process_coil
    where    ab_job_num = p_ab_job
    and      coil_abc_num = p_coil_abc_num;
*/
    --Calculate unprocessed weight
    select nvl(process_quantity, 0), nvl(process_end_wt,0)
    into   ll_wt, ll_shift_end_wt
    from   process_coil
    where  coil_abc_num = p_coil_abc_num
    and    ab_job_num = p_ab_job;

    ll_wt := coalesce(ll_wt, 0);

    if ll_shift_end_wt is null then
      select  net_wt_balance
      into    ll_wt1
      from    coil
      where   coil_abc_num = p_coil_abc_num;

      ll_wt1 := coalesce(ll_wt1, 0);
    else
      ll_wt1 := ll_shift_end_wt;
    end if;

    select max(process_quantity)
    into   ll_wt2
    from   process_coil
    where  coil_abc_num = p_coil_abc_num
    and    process_quantity < ll_wt;


    ll_wt2 := coalesce(ll_wt2, 0);

    if ll_wt1 > ll_wt2 then
       ll_unprocessed_wt := ll_wt1;
     else
       ll_unprocessed_wt := ll_wt2;
    end if;

   result := ll_unprocessed_wt;

   return(result);
end f_get_coil_unprocess_wt_4job;
  GRANT EXECUTE ON "DBO"."F_GET_COIL_UNPROCESS_WT_4JOB" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function F_GET_COIL_UNPROCNETWT_PER_JOB
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_COIL_UNPROCNETWT_PER_JOB" 
 ( 
    al_ab_job_num  ab_job.ab_job_num%type    
 )
  return integer
  
is

  ll_total_coil_unprocnetwt_4job    number(8);

begin
  
  select nvl(sum(process_quantity),0) 
  into   ll_total_coil_unprocnetwt_4job
  from   process_coil
  where  ab_job_num = al_ab_job_num
  and    process_coil_status = 2;	--For those coil applied but never used in this ab_job
    
  ll_total_coil_unprocnetwt_4job := nvl(ll_total_coil_unprocnetwt_4job, 0); 
  return ll_total_coil_unprocnetwt_4job;

end f_get_coil_unprocnetwt_per_job;
