  CREATE OR REPLACE FUNCTION "DBO"."F_GET_CUSTOMER_NAME_4SKID" (ai_skid_id in sheet_skid.sheet_skid_num%type) return varchar is
  Result varchar(18);
begin
  select     customer.customer_short_name 
  into       Result
  from       sheet_skid
             join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
             join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
             join customer on customer.customer_id = customer_order.orig_customer_id
  where      (sheet_skid.sheet_skid_num = ai_skid_id);
  
  return(Result);
end f_get_customer_name_4skid;
