--  DDL for Function F_GET_DIE_ID
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_DIE_ID" (al_job in ab_job.ab_job_num%type) return integer is
  ls_sheet_type varchar2(18);
  li_order ab_job.order_abc_num%type;
  li_item ab_job.order_item_num%type;
  li_die_id   integer;

begin
  /*
     Alex Gerlants. 03/27/2017. Initial release
  */
   li_die_id := 0;
   
   select nvl(die_id, -99)
   into   li_die_id
   from   ab_job
   where  ab_job_num = al_job;
   
   --dbms_output.Put_line(li_die_id); --Display
   
   if li_die_id > 0 then
      return li_die_id;
   end if;
   
   --dbms_output.Put_line('After if li_die_id > 0 then'); --Display

   select lower(order_item.sheet_type), order_item.order_abc_num, order_item.order_item_num
   into   ls_sheet_type, li_order, li_item
   from   ab_job
          join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
   where  ab_job_num = al_job;

   --dbms_output.Put_line('After select. ls_sheet_type = ' || trim(ls_sheet_type) || ' li_order = ' || to_char(li_order) || '  li_item = ' || to_char(li_item)); --Display

   if trim(ls_sheet_type) = 'rectangle' then
      select die.die_id
      into   li_die_id
      from   rectangle
             join die on (die.die_name = rectangle.rt_die1 or to_char(die.die_id) = rectangle.rt_die1)
             join shape_die on shape_die.die_id = die.die_id
      where  rectangle.order_abc_num = li_order and rectangle.order_item_num = li_item
      and    lower(shape_die.sheet_type) = 'rectangle';

   elsif trim(ls_sheet_type) = 'parallelogram' then
      select die.die_id
      into   li_die_id
      from   parallelogram
             join die on (die.die_name = parallelogram.p_die1 or to_char(die.die_id) = parallelogram.p_die1)
             join shape_die on shape_die.die_id = die.die_id
      where  parallelogram.order_abc_num = li_order and parallelogram.order_item_num = li_item
      and    lower(shape_die.sheet_type) = 'parallelogram';      

   elsif trim(ls_sheet_type) = 'fender' then
      select die.die_id
      into   li_die_id
      from   fender
             join die on (die.die_name = fender.fe_die1 or to_char(die.die_id) = fender.fe_die1)
             join shape_die on shape_die.die_id = die.die_id
      where  fender.order_abc_num = li_order and fender.order_item_num = li_item
      and    lower(shape_die.sheet_type) = 'fender';

   elsif trim(ls_sheet_type) = 'chevron' then
      select die.die_id
      into   li_die_id
      from   chevron
             join die on (die.die_name = chevron.ch_die or to_char(die.die_id) = chevron.ch_die)
             join shape_die on shape_die.die_id = die.die_id
      where  chevron.order_abc_num = li_order and chevron.order_item_num = li_item
      and    lower(shape_die.sheet_type) = 'chevron';

    elsif trim(ls_sheet_type) = 'circle' then
      select die.die_id
      into   li_die_id
      from   circle
             join die on (die.die_name = circle.c_die1 or to_char(die.die_id) = circle.c_die1)
             join shape_die on shape_die.die_id = die.die_id
      where  circle.order_abc_num = li_order and circle.order_item_num = li_item
      and    lower(shape_die.sheet_type) = 'circle';

    elsif trim(ls_sheet_type) = 'trapezoid' then
      select die.die_id
      into   li_die_id
      from   trapezoid
             join die on (die.die_name = trapezoid.tr_die1 or to_char(die.die_id) = trapezoid.tr_die1)
             join shape_die on shape_die.die_id = die.die_id
      where  trapezoid.order_abc_num = li_order and trapezoid.order_item_num = li_item
      and    lower(shape_die.sheet_type) = 'trapezoid';

    elsif trim(ls_sheet_type) = 'l.trapezoid' then
      select die.die_id
      into   li_die_id
      from   left_trapezoid
             join die on (die.die_name = left_trapezoid.ltr_die1 or to_char(die.die_id) = left_trapezoid.ltr_die1)
             join shape_die on shape_die.die_id = die.die_id
      where  left_trapezoid.order_abc_num = li_order and left_trapezoid.order_item_num = li_item
      and    lower(shape_die.sheet_type) = 'l.trapezoid';

    elsif trim(ls_sheet_type) = 'r.trapezoid' then
      select die.die_id
      into   li_die_id
      from   right_trapezoid
             join die on (die.die_name = right_trapezoid.rtr_die1 or to_char(die.die_id) = right_trapezoid.rtr_die1)
             join shape_die on shape_die.die_id = die.die_id
      where  right_trapezoid.order_abc_num = li_order and right_trapezoid.order_item_num = li_item
      and    lower(shape_die.sheet_type) = 'r.trapezoid';

   elsif trim(ls_sheet_type) = 'reinforcement' then
      select die.die_id
      into   li_die_id
      from   reinforcement
             join die on (die.die_name = reinforcement.re_die1 or to_char(die.die_id) = reinforcement.re_die1)
             join shape_die on shape_die.die_id = die.die_id
      where  reinforcement.order_abc_num = li_order and reinforcement.order_item_num = li_item
      and    lower(shape_die.sheet_type) = 'reinforcement';

   elsif trim(ls_sheet_type) = 'liftgate' then
      select die.die_id
      into   li_die_id
      from   liftgate_shape
             join die on (die.die_name = liftgate_shape.li_die1 or to_char(die.die_id) = liftgate_shape.li_die1)
             join shape_die on shape_die.die_id = die.die_id
      where  liftgate_shape.order_abc_num = li_order and liftgate_shape.order_item_num = li_item
      and    lower(shape_die.sheet_type) = 'liftgate';

   else
      select die.die_id
      into   li_die_id
      from   x1_shape
             join die on (die.die_name = x1_shape.x_die or to_char(die.die_id) = x1_shape.x_die)
             join shape_die on shape_die.die_id = die.die_id
      where  x1_shape.order_abc_num = li_order and x1_shape.order_item_num = li_item
      and    lower(shape_die.sheet_type) = 'x1_shape';

   end if;

   return li_die_id;
end f_get_die_id;
  GRANT EXECUTE ON "DBO"."F_GET_DIE_ID" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function F_GET_DIE_NAME
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_DIE_NAME" (al_job in ab_job.ab_job_num%type) return varchar2 is
  ls_die varchar2(32);
  ls_sheet_type varchar2(18);
  li_order ab_job.order_abc_num%type;
  li_item ab_job.order_item_num%type;
  ls_die_name varchar2(32);

begin
  ls_die := ' ';
  
  select upper(a.sheet_type), b.order_abc_num, b.order_item_num
  into ls_sheet_type, li_order, li_item
  from order_item a, ab_job b
  where (a.order_item_num = b.order_item_num) AND
        (a.order_abc_num = b.order_abc_num) AND
        (b.ab_job_num = al_job);
        
 
   IF TRIM(ls_sheet_type) = 'RECTANGLE' THEN 

      select NVL(rt_die1, ' ') 
      into ls_die 
      from rectangle 
      where (order_abc_num = li_order) AND (order_item_num = li_item);
      
   ELSIF TRIM(ls_sheet_type) = 'PARALLELOGRAM' THEN   
      select NVL(p_die1, ' ') 
      into ls_die 
      from parallelogram 
      where (order_abc_num = li_order) AND (order_item_num = li_item);
   
   ELSIF TRIM(ls_sheet_type) = 'FENDER' THEN 
      select NVL(fe_die1, ' ') 
      into ls_die 
      from fender 
      where (order_abc_num = li_order) AND (order_item_num = li_item);
     
   ELSIF TRIM(ls_sheet_type) = 'CHEVRON' THEN 
       select NVL(ch_die, ' ') 
      into ls_die 
      from chevron 
      where (order_abc_num = li_order) AND (order_item_num = li_item);
      
    ELSIF TRIM(ls_sheet_type) = 'CIRCLE' THEN 
       select NVL(c_die1, ' ') 
      into ls_die 
      from circle
      where (order_abc_num = li_order) AND (order_item_num = li_item);
      
    ELSIF TRIM(ls_sheet_type) = 'TRAPEZOID' THEN 
       select NVL(tr_die1, ' ') 
      into ls_die 
      from trapezoid 
      where (order_abc_num = li_order) AND (order_item_num = li_item);
      
    ELSIF TRIM(ls_sheet_type) = 'L.TRAPEZOID' THEN 
      select NVL(ltr_die1, ' ') 
      into ls_die 
      from left_trapezoid 
      where (order_abc_num = li_order) AND (order_item_num = li_item);
      
    ELSIF TRIM(ls_sheet_type) = 'R.TRAPEZOID' THEN 
      select NVL(rtr_die1, ' ') 
      into ls_die 
      from right_trapezoid 
      where (order_abc_num = li_order) AND (order_item_num = li_item);
      
   ELSIF TRIM(ls_sheet_type) = 'REINFORCEMENT' THEN      
      select NVL(re_die1, ' ') 
      into ls_die 
      from reinforcement 
      where (order_abc_num = li_order) AND (order_item_num = li_item);
      
   ELSIF TRIM(ls_sheet_type) = 'LIFTGATE' THEN 
      select NVL(li_die1, ' ') 
      into ls_die 
      from liftgate_shape 
      where (order_abc_num = li_order) AND (order_item_num = li_item);
    
   ELSE 
       select NVL(x_die, ' ') 
       into ls_die 
       from x1_shape
       where (order_abc_num = li_order) AND (order_item_num = li_item);
        
   END IF;
   
   IF ls_die = ' ' THEN
      ls_die_name := ' ';
   ELSIF LENGTH(TRIM(TRANSLATE(ls_die, ' +-.0123456789', ' '))) is NULL THEN 
      select die_name
      into ls_die_name
      from die
      where die_id = to_number(TRIM(ls_die));
   ELSE
       ls_die_name := ' ';
   END IF;
   
  return ls_die_name;
end f_get_die_name;
  GRANT EXECUTE ON "DBO"."F_GET_DIE_NAME" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function F_GET_DIE_NAME_4ORDER_ITEM
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_DIE_NAME_4ORDER_ITEM" 
(
    al_order_abc_num  in order_item.order_abc_num%type,
    al_order_item_num in order_item.order_item_num%type
)
return varchar2

is

  ls_die            varchar2(32);
  ls_sheet_type     varchar2(18);
  ls_die_name       varchar2(32);
  ll_test           number;

begin
  
  ls_die := ' ';

  select trim(lower(sheet_type))
  into   ls_sheet_type
  from   order_item
  where  order_abc_num = al_order_abc_num
  and    order_item_num = al_order_item_num;


   if ls_sheet_type = 'rectangle' then
      select  nvl(rt_die1, 'NULL VALUE')
      into    ls_die
      from    rectangle
      where   order_abc_num = al_order_abc_num
      and     order_item_num = al_order_item_num;

   elsif ls_sheet_type = 'parallelogram' then
      select   nvl(p_die1, 'NULL VALUE')
      into     ls_die
      from     parallelogram
      where    order_abc_num = al_order_abc_num
      and      order_item_num = al_order_item_num;

   elsif ls_sheet_type = 'fender' then
      select   nvl(fe_die1, 'NULL VALUE')
      into     ls_die
      from     fender
      where    order_abc_num = al_order_abc_num
      and      order_item_num = al_order_item_num;

   elsif ls_sheet_type = 'chevron' then
       select  nvl(ch_die, 'NULL VALUE')
      into     ls_die
      from     chevron
      where    order_abc_num = al_order_abc_num
      and      order_item_num = al_order_item_num;

    elsif ls_sheet_type = 'circle' then
       select  nvl(c_die1, 'NULL VALUE')
      into     ls_die
      from     circle
      where    order_abc_num = al_order_abc_num
      and      order_item_num = al_order_item_num;

    elsif ls_sheet_type = 'trapezoid' then
       select  nvl(tr_die1, 'NULL VALUE')
      into     ls_die
      from     trapezoid
      where    order_abc_num = al_order_abc_num
      and      order_item_num = al_order_item_num;

    elsif ls_sheet_type = 'l.trapezoid' then
      select   nvl(ltr_die1, 'NULL VALUE')
      into     ls_die
      from     left_trapezoid
      where    order_abc_num = al_order_abc_num
      and      order_item_num = al_order_item_num;

    elsif ls_sheet_type = 'r.trapezoid' then
      select   nvl(rtr_die1, 'NULL VALUE')
      into     ls_die
      from     right_trapezoid
      where    order_abc_num = al_order_abc_num
      and      order_item_num = al_order_item_num;

   elsif ls_sheet_type = 'reinforcement' then
      select   nvl(re_die1, 'NULL VALUE')
      into     ls_die
      from     reinforcement
      where    order_abc_num = al_order_abc_num
      and      order_item_num = al_order_item_num;

   elsif ls_sheet_type = 'liftgate' then
      select   nvl(li_die1, 'NULL VALUE')
      into     ls_die
      from     liftgate_shape
      where    order_abc_num = al_order_abc_num
      and      order_item_num = al_order_item_num;

   else
       select  nvl(x_die, 'NULL VALUE')
       into    ls_die
       from    x1_shape
       where   order_abc_num = al_order_abc_num
       and     order_item_num = al_order_item_num;

   end if;

   if ls_die is null then
     ls_die := 'NULL VALUE';
   end if;
   
   ll_test := is_number(ls_die);

   --if length(trim(translate(ls_die, ' +-.0123456789', ''))) is null then --ls_die is numeric (contains only numbers: 0123456789)
   if ll_test = 1 then --ls_die is numeric (contains only numbers: 0123456789) 
      select   die_name
      into     ls_die_name
      from     die
      where    die_id = to_number(trim(ls_die));
   else
      ls_die_name := ls_die;
   end if;

   return ltrim(rtrim(ls_die_name));
   
end f_get_die_name_4order_item;
--------------------------------------------------------
--  DDL for Function F_GET_DIE_NAME_AB_JOB
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_DIE_NAME_AB_JOB" (al_job in ab_job.ab_job_num%type) return varchar2 is

  ls_die_name varchar2(32);

begin
  select die_name
  into ls_die_name
  from ab_job
       left outer join die on die.die_id = ab_job.die_id
  where ab_job_num = al_job;
     
  if ls_die_name is null then --Die is not on ab_job table
    --Get it from customer order
    select f_get_die_name(al_job)
    into   ls_die_name
    from   dual;
  end if;

  return ls_die_name;
  
end f_get_die_name_ab_job;
  GRANT EXECUTE ON "DBO"."F_GET_DIE_NAME_AB_JOB" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function F_GET_DOWNTIME_TOTAL_SEC
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_DOWNTIME_TOTAL_SEC" (al_shift_id in shift.shift_NUM%type) return integer is
  Result integer;
begin
  
  select 86400 * sum(dt_instance.ending_time - dt_instance.starting_time) into Result
  from dt_instance
  where dt_instance.shift_num = al_shift_id;
  
  return(Result);
end F_GET_DOWNTIME_TOTAL_SEC;
  GRANT EXECUTE ON "DBO"."F_GET_DOWNTIME_TOTAL_SEC" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function F_GET_D_REPORT_SHIPMENT_GROWT
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_D_REPORT_SHIPMENT_GROWT" (PACKING_ID in shipment.packing_list%type)
RETURN  sheet_skid.sheet_net_wt%type is
  Result sheet_skid.sheet_net_wt%type :=0;

	skid_sum sheet_skid.sheet_net_wt%type :=0;
	scrap_sum scrap_skid.scrap_net_wt%type :=0;
	coil_sum coil.net_wt%type :=0;

begin

SELECT NVL(SUM(sheet_skid.sheet_net_wt),0)+NVL(SUM(sheet_skid.sheet_tare_wt),0)
INTO skid_sum FROM sheet_skid, sheet_packing_item, shipment
WHERE SHIPMENT.PACKING_LIST =SHEET_PACKING_ITEM.PACKING_LIST and
      SHEET_PACKING_ITEM.SHEET_SKID_NUM = SHEET_SKID.SHEET_SKID_NUM and
      SHIPMENT.PACKING_LIST = PACKING_ID;

SELECT NVL(SUM(scrap_skid.scrap_net_wt),0)+NVL(SUM(scrap_skid.scrap_tare_wt),0)
INTO scrap_sum FROM scrap_skid, scrap_packing_item, shipment
WHERE SHIPMENT.PACKING_LIST =SCRAP_PACKING_ITEM.PACKING_LIST and
      SCRAP_PACKING_ITEM.SCRAP_SKID_NUM = SCRAP_SKID.SCRAP_SKID_NUM and
      SHIPMENT.PACKING_LIST = PACKING_ID;

SELECT NVL(SUM(coil.net_wt_balance),0)
INTO coil_sum FROM coil, reject_coil_packing_item, shipment
WHERE SHIPMENT.PACKING_LIST =REJECT_COIL_PACKING_ITEM.PACKING_LIST and
      REJECT_COIL_PACKING_ITEM.COIL_ABC_NUM = COIL.COIL_ABC_NUM and
      SHIPMENT.PACKING_LIST = PACKING_ID;

 Result := skid_sum + scrap_sum + coil_sum;

return(Result);
end F_GET_D_REPORT_SHIPMENT_GROWT;
  GRANT EXECUTE ON "DBO"."F_GET_D_REPORT_SHIPMENT_GROWT" TO PUBLIC
  GRANT EXECUTE ON "DBO"."F_GET_D_REPORT_SHIPMENT_GROWT" TO "AGERLANTS"
