--  DDL for Function F_GET_EDI_REQ_4PACKLIST
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_EDI_REQ_4PACKLIST" (al_packing_list in shipment.packing_list%type) return varchar2
is

  ls_customer_edi_req_y_n         varchar2(1);
  ls_destination_edi_req_y_n      varchar2(1);
  ls_edi_req_4packlist            varchar2(1);

begin
  
  select upper(customer_customer.edi_req),
         upper(destination_customer.edi_req)
  into   ls_customer_edi_req_y_n,
         ls_destination_edi_req_y_n
  from   shipment
         join customer customer_customer on customer_customer.customer_id = shipment.customer_id /* Alex Gerlants. 02/14/2023. 1464_Automating_Shipping_ASN */
         join customer destination_customer on destination_customer.customer_id = shipment.des_sh_cust_id /* Alex Gerlants. 02/14/2023. 1464_Automating_Shipping_ASN */
  where shipment.packing_list = al_packing_list;  

  if ls_customer_edi_req_y_n = 'Y' and ls_destination_edi_req_y_n = 'Y' then
   ls_edi_req_4packlist := 'Y';
  else
   ls_edi_req_4packlist := 'N';
  end if;
 
  return(ls_edi_req_4packlist);
end f_get_edi_req_4packlist;
/* Alex Gerlants. 02/14/2023. 1464_Automating_Shipping_ASN. End *
/
