--------------------------------------------------------
--  DDL for Function F_GET_END_COIL_WT_PER_DONE_JOB
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_END_COIL_WT_PER_DONE_JOB" (al_job_id in ab_job.ab_job_num%type) return integer is
  Result integer; 
  job_status integer;
  temp_wt Integer;
  ll_shift_end_wt Integer;
  ll_wt Integer;
  ll_wt1 Integer;
  ll_wt2 Integer;
	cursor c_cursor is
 	select coil_abc_num
  	from process_coil
  	where ab_job_num = al_job_id;

begin 

  SELECT status INTO job_status from line_priority where ab_job_num = al_job_id;
  
  IF job_status <> 0 THEN
	Result := NULL;
  ELSE
     	Result := 0;
	for cloop in c_cursor loop

		temp_wt := 0;
		SELECT process_end_wt INTO temp_wt 
		FROM process_coil 
		where ab_job_num = al_job_id and coil_abc_num = cloop.coil_abc_num;

		IF temp_wt is NULL THEN

			SELECT NVL(process_quantity, 0), process_end_wt INTO ll_wt, ll_shift_end_wt
			FROM process_coil
			WHERE (coil_abc_num = cloop.coil_abc_num) AND (ab_job_num = al_job_id);

			IF ll_shift_end_wt is NULL THEN
				SELECT NVL(net_wt_balance,0) INTO ll_wt1
				FROM coil
				WHERE coil_abc_num = cloop.coil_abc_num;

			ELSE
				ll_wt1 := ll_shift_end_wt;
			END IF;

			SELECT NVL(MAX(process_quantity),0) INTO ll_wt2
			FROM process_coil
			WHERE (coil_abc_num = cloop.coil_abc_num) AND (process_quantity < ll_wt);
 
			IF ll_wt1 > ll_wt2 THEN
				temp_wt := ll_wt1;
			ELSE
				temp_wt := ll_wt2;
			END IF;
 		END IF;

		Result := Result + temp_wt;	
	END LOOP;			
  END IF;
   
  return(Result); 
end f_get_end_coil_wt_per_done_job;
  GRANT EXECUTE ON "DBO"."F_GET_END_COIL_WT_PER_DONE_JOB" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function F_GET_EST_JOB_HOURS
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_EST_JOB_HOURS" 
 ( 
    al_ab_job_num           ab_job.ab_job_num%type
 )
  return number
   
  is

  FunctionResult decimal(12,2);
  
begin
  
  select   cast ((  (  (  (  (ab_job.job_process_quantity / order_item.theoretical_unit_wt) / routing.spm_planned  ) / (routing.effic_percent_planned / 100)  ) / die.num_of_parts_per_hit  ) / 60  )  as decimal(12,2))
  into     FunctionResult
  from     ab_job
           join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
           join routing on ab_job.routing_sequence = routing.routing_sequence
           join die on die.die_id = ab_job.die_id
  where    ab_job.ab_job_num = al_ab_job_num;

  return(FunctionResult);
end f_get_est_job_hours;
--------------------------------------------------------
--  DDL for Function F_GET_EST_JOB_MINUTES
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_EST_JOB_MINUTES" 
 ( 
    al_ab_job_num           ab_job.ab_job_num%type
 )
  return number
   
  is

  FunctionResult decimal(12,2);
  
begin
  
  select   cast ((  (  (  (ab_job.job_process_quantity / order_item.theoretical_unit_wt) / routing.spm_planned  ) / (routing.effic_percent_planned / 100)  ) / die.num_of_parts_per_hit  ) as decimal(12,2))
  into     FunctionResult
  from     ab_job
           join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
           join routing on ab_job.routing_sequence = routing.routing_sequence
           join die on die.die_id = ab_job.die_id
  where    ab_job.ab_job_num = al_ab_job_num;

  return(FunctionResult);
end f_get_est_job_minutes;
--------------------------------------------------------
--  DDL for Function F_GET_FIRST_REBAND_WT_4COIL
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_FIRST_REBAND_WT_4COIL" 
 ( 
    al_coil_abc_num  coil.coil_abc_num%type  
 )
  return coil.net_wt%type
  
is

ll_coil_rebanded_wt    coil.net_wt%type;

begin

  select   distinct coil_cur_netwt
  into     ll_coil_rebanded_wt
  from     coil_track
  where    coil_abc_num = al_coil_abc_num
  and      coil_track_date = 
     (
        select   min(coil_track_date)
        from     coil_track
        where    coil_abc_num = al_coil_abc_num
        and      coil_cur_status = 7
     );
  
  return ll_coil_rebanded_wt;
end ;
