--  DDL for Function F_GET_FORMATTED_DATE_YYYYMMDD
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_FORMATTED_DATE_YYYYMMDD" (date_in in varchar2) return varchar2 is
  FunctionResult varchar2(10);
begin
  if date_in is null then
    FunctionResult := date_in;
  else
    FunctionResult := substr(date_in, 5, 2) || '/' || substr(date_in, 7, 2) || '/' || substr(date_in, 1, 4);
  end if;

  return(FunctionResult);
end f_get_formatted_date_yyyymmdd;
--------------------------------------------------------
--  DDL for Function F_GET_FORMATTED_TIME_HHMI
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_FORMATTED_TIME_HHMI" (time_in in varchar2) return varchar2 is
  FunctionResult varchar2(5);
  
begin
  if time_in is null then
    FunctionResult := time_in;
  else
    FunctionResult := substr(time_in, 1, 2) || ':' || substr(time_in, 3, 2);
  end if;

  return(FunctionResult);
end f_get_formatted_time_hhmi;
--------------------------------------------------------
--  DDL for Function F_GET_GAUGE_STRING_4SKID
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_GAUGE_STRING_4SKID" 
(
       al_scrap_skid_num in scrap_skid.scrap_skid_num%type
) 
return varchar2 
is

  FunctionResult varchar2(40);
  ls_gauge       varchar2(20);
  
  cursor gauge_cur is
  select 	 distinct to_char(order_item.gauge) gauge
  from     scrap_skid_detail 
           join return_scrap_item on scrap_skid_detail.return_scrap_item_num = return_scrap_item.return_scrap_item_num
           join ab_job on ab_job.ab_job_num = return_scrap_item.ab_job_num
           join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
  where    scrap_skid_detail.scrap_skid_num = al_scrap_skid_num
  ;
  
  gauge_rec  gauge_cur%ROWTYPE;
  
begin
  for gauge_rec in gauge_cur loop
    ls_gauge := gauge_rec.gauge;
    
    if FunctionResult is null then
      FunctionResult := ls_gauge;
    else
      FunctionResult := FunctionResult || ' , ' || ls_gauge;
    end if;
  end loop;
  
  return(FunctionResult);
end f_get_gauge_string_4skid;

--create or replace public synonym f_get_order_item_gauge_4skid for dbo.f_get_order_item_gauge_4skid;
--------------------------------------------------------
--  DDL for Function F_GET_HEAVY_LIGHT_PER_JOB
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_HEAVY_LIGHT_PER_JOB" 
 ( 
    al_ab_job_num  ab_job.ab_job_num%type    
 )
  return integer
  
is

  /*
  /*
   Aluminum Blanking: DUNS:039630926     EDI ID:039630926T        QUALIFIER: 01
   */

  --Alex Gerlants. 11/15/2016. Commented out, and added the line after.
  --edi_loc VARCHAR2(50) := '/templar/templar/incoming/senddata';
  edi_loc                varchar2(50) := get_edi_destination('EDI_DIR');

  edi_file                     varchar2(50) := 'edi_out.txt';
  --edi_file_prefix              varchar2(50) := 'S_novelis_870_'; --production
  edi_file_prefix              varchar2(50) := 's_novelis_870_'; --development
  edi_file_handle              utl_file.file_type;
  su_duns                      varchar2(10);
  ll_customer_id               customer.customer_id%type;
  ll_cur_coil                  coil.coil_abc_num%type;
  ll_gs_log                    integer;
  ll_st_log                    integer;
  ls_today                     varchar2(20) := to_char(sysdate, 'YYYYMMDD');
  ls_today_4                   varchar2(20) := to_char(sysdate, 'YYMMDD');
  ls_now                       varchar2(20) := to_char(sysdate, 'HH24MI');
  ls_po                        varchar2(20);
  ls_finished_goods            varchar2(32);
  ls_cust_prod_line            varchar2(8);
  ld_scrap_870_date            process_coil.scrap_870_date%type;
  ls_coil_org_num              coil.coil_org_num%type;
  ls_heat                      coil.lot_num%type;
  ll_prime_nw                  coil.net_wt%type;
  ll_scrap_nw                  coil.net_wt%type;
  ll_item_count                integer;
  li_hl01                      integer;
  li_hllin                     integer;
  ll_rowcount                  number(8);
  ll_edi_file_id_870           integer;
  ld_edi_date_870              ab_job.edi_date_870%type;
  --ls_sheet_skid_exists         char(1);
  ls_consumed_coil_num         coil.consumed_coil_num%type;
  ls_customer_short_name       customer.customer_short_name%type;
  ll_sheet_skid_count_4coil    number(8);
  ll_total_act_scrap_wt_4job   number(8);
  ll_total_theo_scrap_wt_4job  number(8);
  ll_heavy_light               number(8);

--------------------------------------------------------------------------------------------------   
------------------------------------ Cursors Begin -----------------------------------------------
--------------------------------------------------------------------------------------------------

  cursor coil_cur is
  select distinct process_coil.coil_abc_num
  from   process_coil
         left outer join production_sheet_item on production_sheet_item.coil_abc_num = process_coil.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    (
              sheet_skid.skid_sheet_status in (0, 2, 4, 13, 12, 16)
           or sheet_skid.skid_sheet_status is null --This is for rejected coils without sheets  
         )
  order by process_coil.coil_abc_num;
  
  coil_rec  coil_cur%ROWTYPE;
   
  --Cursor skid_coil_cur will select data for ab_job and coil_abc_num with skids.
  --If there is a reject coil without sheet skids, this cursor will not select it.
  cursor skid_coil_cur is
  select coil.coil_abc_num,   
         coil.lot_num,   
         coil.coil_org_num,   
         coil.coil_mid_num,
         nvl(coil.consumed_coil_num, ' ') consumed_coil,
         nvl(coil.material_num, ' ') material_num,
         coil.net_wt,   
         sheet_skid.sheet_tare_wt,   
         sheet_skid.sheet_net_wt,
         sheet_skid.skid_pieces,
         production_sheet_item.prod_item_pieces,
         production_sheet_item.prod_item_num,
         sheet_skid.skid_sheet_status,
         sheet_skid.sheet_skid_num,   
         production_sheet_item.prod_item_note,   
         sheet_skid.sheet_theoretical_wt,   
         production_sheet_item.prod_item_placement,   
         process_coil.process_quantity,   
         production_sheet_item.prod_item_net_wt,   
         sheet_skid.sheet_skid_display_num,
         nvl(customer_order.sales_order, ' ') sales_order,
         nvl(customer_order.orig_customer_po, 'NA') orig_customer_po,
         nvl(order_item.enduser_part_num, ' ') enduser_part_num,
         nvl(order_item.cust_prod_line_id, 'NA') cust_prod_line_id,
         nvl(order_item.finished_goods_material_num, 'NA') finished_goods_material_num,
         (sheet_skid.sheet_net_wt + sheet_skid.sheet_tare_wt) skid_gross_wt,
         NULL done  
  from   coil   
         join process_coil on coil.coil_abc_num = process_coil.coil_abc_num
         join ab_job on ab_job.ab_job_num = process_coil.ab_job_num
         join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
         join customer_order on customer_order.order_abc_num = order_item.order_abc_num
         left outer join production_sheet_item on coil.coil_abc_num = production_sheet_item.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  ab_job.ab_job_num = al_ab_job_num
  and    coil.coil_abc_num = ll_cur_coil
  order by
         production_sheet_item.coil_abc_num,
         sheet_skid.sheet_skid_display_num;

  skid_coil_rec  skid_coil_cur%rowtype;
  
  cursor scrap_cur is
  select process_coil.coil_abc_num,
         process_coil.process_coil_status,
         process_coil.process_quantity,
         nvl(process_coil.process_end_wt, 0),
         sum(nvl(process_coil.process_end_wt, 0)),
         sum(nvl(production_sheet_item.prod_item_net_wt, 0)),
         case process_coil.process_coil_status
            when 7 then --Rebanded coils
               --(process_coil.process_quantity - sum(production_sheet_item.prod_item_net_wt) - (select process_end_wt from process_coil pc where pc.ab_job_num = 101143 and pc.coil_abc_num = process_coil.coil_abc_num))
               (process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - nvl(process_coil.process_end_wt, 0))
            when 3 then --Rejected coils
               case (select count(*) from production_sheet_item psi where psi.ab_job_num = al_ab_job_num and psi.coil_abc_num = process_coil.coil_abc_num)
                 when 0 then --Rejected coils without sheets
                   (process_coil.process_quantity - sum(nvl(process_coil.process_end_wt, 0)))
                 else --Rejected coils with sheets
                   (process_coil.process_quantity - nvl(process_coil.process_end_wt, 0) - sum(nvl(production_sheet_item.prod_item_net_wt, 0)))     
                end   
             else
               (process_coil.process_quantity - sum(nvl(production_sheet_item.prod_item_net_wt, 0)) - sum(nvl(process_coil.process_end_wt, 0)))
         end scrap_net_wt
  from   process_coil
         join coil on coil.coil_abc_num = process_coil.coil_abc_num
         join ab_job on ab_job.ab_job_num = process_coil.ab_job_num and coil.coil_abc_num = process_coil.coil_abc_num
         left outer join production_sheet_item on production_sheet_item.ab_job_num = process_coil.ab_job_num and production_sheet_item.coil_abc_num = process_coil.coil_abc_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    coil.coil_abc_num = ll_cur_coil
  group by
         process_coil.coil_abc_num,
         process_coil.process_coil_status,
         process_coil.process_quantity,
         process_coil.process_end_wt
  order by
         process_coil.coil_abc_num;
         
  scrap_rec  scrap_cur%rowtype;
   
--------------------------------------------------------------------------------------------------   
------------------------------------- Cursors End ------------------------------------------------
--------------------------------------------------------------------------------------------------   

  TYPE prod_item_type IS TABLE OF production_sheet_item.prod_item_num%TYPE INDEX BY BINARY_INTEGER;
  item_num prod_item_type;
  k        BINARY_INTEGER := 0;

  TYPE coil_num_type IS TABLE OF coil.coil_abc_num%type INDEX BY BINARY_INTEGER;
  coil_num coil_num_type;
  p binary_integer :=0;
  
  TYPE store_tabletype IS TABLE OF VARCHAR2(32767) INDEX BY BINARY_INTEGER;
  x12_table store_tabletype;
  i         BINARY_INTEGER := 0;  

BEGIN
  
  select count(distinct process_coil.coil_abc_num)
  into   ll_rowcount
  from   process_coil
         left outer join production_sheet_item on production_sheet_item.coil_abc_num = process_coil.coil_abc_num and production_sheet_item.ab_job_num = process_coil.ab_job_num
         left outer join sheet_skid_detail on sheet_skid_detail.prod_item_num = production_sheet_item.prod_item_num
         left outer join sheet_skid on sheet_skid.sheet_skid_num = sheet_skid_detail.sheet_skid_num
  where  process_coil.ab_job_num = al_ab_job_num
  and    (
              sheet_skid.skid_sheet_status in (0, 2, 4, 13, 12, 16)
           or sheet_skid.skid_sheet_status is null --This is for rejected coils without sheets  
         );
    
  if ll_rowcount > 0 then
    ll_total_theo_scrap_wt_4job := 0;

    for coil_rec in coil_cur loop --Coil loop
       ll_cur_coil := coil_rec.coil_abc_num;

       for scrap_rec in scrap_cur loop --Scrap loop
          ll_scrap_nw := scrap_rec.scrap_net_wt;

          if ll_scrap_nw > 0 then --Theo scrap weight
 
             select    nvl(sum(return_item_net_wt),0) 
             into      ll_total_act_scrap_wt_4job
             from      return_scrap_item
             where     ab_job_num = al_ab_job_num;
          
             ll_total_theo_scrap_wt_4job := ll_total_theo_scrap_wt_4job + ll_scrap_nw;
           end if; --if ll_scrap_nw > 0 then
         end loop; --for scrap_rec in alcan_scrap_870_cur loop scrap loop
              
         ll_heavy_light := ll_total_act_scrap_wt_4job - ll_total_theo_scrap_wt_4job;
            
        --end if; --if (ld_scrap_870_date is null) then --Scrap not sent
    end loop; --for coil_rec in coil_cur loop. Coil loop

  end if; --end if in select count(*)

  return ll_heavy_light;
end f_get_heavy_light_per_job;
