--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_JOB_BALANCE_PERCENT" (job_num in ab_job.ab_job_num%type) return NUMBER is
   Result number (10,4);
   coils_wt integer;
   --bal integer;
begin
  --Result := job_num/100;
  --skid_scrap := f_get_job_prime_wt(job_num) + f_get_job_scrap_wt(job_num);
--  coils_wt := f_get_job_processed_coils_wt(job_num);
  coils_wt := F_GET_JOB_PROCESSED_COILS_ORG(job_num);
  if coils_wt < 1 then
       Result := 999;
    else
       Result := (F_GET_JOB_BALANCE_WT(job_num) / coils_wt ) * 100;
    end if;
  return(Result);
end F_GET_JOB_BALANCE_PERCENT;
  GRANT EXECUTE ON "DBO"."F_GET_JOB_BALANCE_PERCENT" TO "AGERLANTS"
