--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_JOB_BALANCE_WT" (job_num in ab_job.ab_job_num%type) return coil.net_wt%type is
  balance coil.net_wt%type;
  Coil_total integer;
  
begin
  --Result := 0;
  balance := 0;
  select sum( process_coil.process_quantity - NVL(process_coil.process_end_wt, process_coil.process_quantity) )into Coil_total
  from process_coil
  where process_coil.ab_job_num = job_num;
  balance := -(Coil_total - f_get_job_prime_wt(job_num) - f_get_job_scrap_wt(job_num));
  return balance;
end F_GET_JOB_BALANCE_WT;
  GRANT EXECUTE ON "DBO"."F_GET_JOB_BALANCE_WT" TO "AGERLANTS"
