--  DDL for Function F_GET_JOB_COIL_REJECT_WT
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_JOB_COIL_REJECT_WT" 
   (
   al_ab_job_num in        ab_job.ab_job_num%type,
   al_coil_abc_num         coil.coil_abc_num%type
   ) 
   return number is
   
   ll_net_wt               coil.net_wt%type;
   ll_net_wt_balance       coil.net_wt_balance%type;
   ll_coil_status          coil.coil_status%type;
   ll_ps_wt                number(8);
	 ll_qc_wt                number(8);
	 ll_pc_wt                number(8);
	 ll_rej_coil_wt          number(8);

begin
   --Alex Gerlants. 10/20/2023. Initial release.
   
   ll_ps_wt := 0;
	 ll_qc_wt := 0;
	 ll_pc_wt := 0;
	 ll_rej_coil_wt := 0;
   
   select   coil_status, net_wt_balance 
   into     ll_coil_status, ll_net_wt_balance
	 from     coil
	 where    coil_abc_num = al_coil_abc_num;
   
   select   nvl(sum(prod_item_net_wt), 0)
   into     ll_ps_wt
	 from     production_sheet_item
	 where    ab_job_num = al_ab_job_num 
   and      coil_abc_num = al_coil_abc_num;
   
   select nvl(sum(prod_item_net_wt), 0)
   into   ll_qc_wt
	 from   production_sheet_item
	 where  ab_job_num = al_ab_job_num 
   and    coil_abc_num = al_coil_abc_num 
   and    prod_item_status = 4;
   
   ll_rej_coil_wt := ll_ps_wt - ll_qc_wt;
   
   if ll_coil_status = 3 then  --Rejected coil
      ll_rej_coil_wt := ll_net_wt_balance;
   else
      ll_rej_coil_wt := 0;
   end if;
  
   return ll_rej_coil_wt;

end f_get_job_coil_reject_wt;

--create or replace public synonym f_get_job_coil_reject_wt for dbo.f_get_job_coil_reject_wt;
--------------------------------------------------------
--  DDL for Function F_GET_JOB_COIL_SCRAP_WT
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_JOB_COIL_SCRAP_WT" 
   (
   al_ab_job_num in        ab_job.ab_job_num%type,
   al_coil_abc_num         coil.coil_abc_num%type
   ) 
   return number is
   
   ll_net_wt               coil.net_wt%type;
   ll_net_wt_balance       coil.net_wt_balance%type;
   ll_coil_status          coil.coil_status%type;
   ll_ps_wt                number(8);
	 ll_qc_wt                number(8);
	 ll_pc_wt                number(8);
	 ll_rej_coil_wt          number(8);
   ll_scrap_wt             number(8);

begin
   --Alex Gerlants. 10/20/2023. Initial release.
   
   ll_ps_wt := 0;
	 ll_qc_wt := 0;
	 ll_pc_wt := 0;
	 ll_rej_coil_wt := 0;
   
   select   coil_status, nvl(net_wt, 0), nvl(net_wt_balance, 0)
   into     ll_coil_status, ll_net_wt, ll_net_wt_balance
	 from     coil
	 where    coil_abc_num = al_coil_abc_num;
   
   
   select   nvl(sum(prod_item_net_wt), 0)
   into     ll_ps_wt
	 from     production_sheet_item
	 where    ab_job_num = al_ab_job_num 
   and      coil_abc_num = al_coil_abc_num;
   
   select nvl(sum(prod_item_net_wt), 0)
   into   ll_qc_wt
	 from   production_sheet_item
	 where  ab_job_num = al_ab_job_num 
   and    coil_abc_num = al_coil_abc_num 
   and    prod_item_status = 4;
   
   if ll_coil_status = 3 then  --Rejected coil
      ll_ps_wt := 0;
   else
      ll_ps_wt := ll_net_wt_balance;
   end if;
   
   ll_scrap_wt := ll_net_wt - ll_net_wt_balance - ll_ps_wt - ll_qc_wt;
  
   return ll_scrap_wt;

end f_get_job_coil_scrap_wt;

--create or replace public synonym f_get_job_coil_scrap_wt for dbo.f_get_job_coil_scrap_wt;
