--  DDL for Function F_GET_JOB_FINISH_PERCENT
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_JOB_FINISH_PERCENT" (al_job_id in ab_job.ab_job_num%type) return integer is
  --Result integer;
  li_status integer;
  li_percent integer;
  li_net integer;
  li_required_net integer;
  ld_finish_date ab_job.job_done_time%type;
  ld_time_date_finished ab_job.time_date_finished%type;
  
begin
  ld_finish_date := null;
  ld_time_date_finished :=null;
  select ab_job.job_status, ab_job.job_done_time, ab_job.time_date_finished, NVL(ab_job.job_sheet_wt, 0) into li_status, ld_finish_date, ld_time_date_finished, li_required_net
  from ab_job
  where ab_job.ab_job_num = al_job_id;
  
  --if ld_finish_date IS NOT NULL OR li_status = 0 then
  if ld_finish_date IS NOT NULL OR ld_time_date_finished IS NOT NULL OR li_status = 0 then
     return 100;
  end if;
  li_net:=0;
  SELECT NVL(SUM(SHEET_SKID.SHEET_NET_WT),0) INTO li_net
  FROM SHEET_SKID
  WHERE SHEET_SKID.AB_JOB_NUM = al_job_id;
  
  if li_required_net = 0 then
     return 100;
  end if;
  
  li_percent := (li_net/li_required_net) * 100;
  if li_percent > 100 then
     li_percent:=100;
  end if;

  return(li_percent);
end F_GET_JOB_FINISH_PERCENT;
  GRANT EXECUTE ON "DBO"."F_GET_JOB_FINISH_PERCENT" TO "AGERLANTS"
