--  DDL for Function F_GET_JOB_PROCESSED_COILS_ORG
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_JOB_PROCESSED_COILS_ORG" (a_job_num in ab_job.ab_job_num%type) return integer is
  Result integer := 0 ;
  Coil_wt integer := 0;
  Cursor c_coil is  
  SELECT DISTINCT process_coil.coil_abc_num 
  FROM process_coil 
  WHERE process_coil.ab_job_num = a_job_num and (process_coil.process_end_wt is not null );
begin
  FOR  c IN c_coil LOOP 
       select coil.net_wt into Coil_wt
       From coil
       where coil.coil_abc_num = c.coil_abc_num;
       Result := Result + Coil_wt;
  END LOOP;
  return(Result);
end F_GET_JOB_PROCESSED_COILS_ORG;
  GRANT EXECUTE ON "DBO"."F_GET_JOB_PROCESSED_COILS_ORG" TO "AGERLANTS"
