  CREATE OR REPLACE FUNCTION "DBO"."F_GET_JOB_PROCESSED_COILS_WT" (job_num in ab_job.ab_job_num%type) return integer is
  Coil_total integer;
begin
  select sum( process_coil.process_quantity - NVL(process_coil.process_end_wt, process_coil.process_quantity) )into Coil_total
  from process_coil
  where process_coil.ab_job_num = job_num;
  return(Coil_total);
end F_GET_JOB_PROCESSED_COILS_WT;
  GRANT EXECUTE ON "DBO"."F_GET_JOB_PROCESSED_COILS_WT" TO "AGERLANTS"
