--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_JOB_REVISED_DUE_DATE" 
(
   al_coil_abc_num in coil.coil_abc_num%type,
   al_ab_job_num   in ab_job.ab_job_num%type
) 
   
return varchar2 is

ld_coil_date_received    coil.date_received%type;
ld_job_due_date          ab_job.due_date%type;
ld_time_date_finished    ab_job.time_date_finished%type;
Result                   varchar2(12);

begin
  --select min(coil_track_date) into Result from coil_track where (coil_abc_num = ll_coil_abc_num) and (coil_cur_status = 4);
   select   date_received
   into     ld_coil_date_received
   from     coil
   where    coil_abc_num = al_coil_abc_num;
   
   select   due_date, time_date_finished
   into     ld_job_due_date, ld_time_date_finished
   from     ab_job
   where    ab_job_num = al_ab_job_num;
   
   --Convert the dates from 'mm/dd/yyyy hh24:mi:ss' to 'mm/dd/yyyy'
   --ld_coil_date_received := to_date(to_char(ld_coil_date_received, 'mm/dd/yyyy'), 'mm/dd/yyyy');
   --ld_job_due_date := to_date(to_char(ld_job_due_date, 'mm/dd/yyyy'), 'mm/dd/yyyy');
   
   if (ld_coil_date_received >= ld_job_due_date - 6) and (ld_time_date_finished > ld_job_due_date) then
     Result := to_char(ld_coil_date_received + 7, 'mm/dd/yyyy');
   else
     Result := 'n/a';
   end if;
  
  return(Result);
end f_get_job_revised_due_date;

