--------------------------------------------------------
--  DDL for Function F_GET_JOB_SPEC
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_JOB_SPEC" (al_job in ab_job.ab_job_num%type) return varchar2 is
  ls_shape     varchar2(18);
  li_order     ab_job.order_abc_num%type;
  li_item      ab_job.order_item_num%type;
  ls_spec      varchar2(70) := ' ';
  lr_gauge     order_item.gauge%type;
  lr_l         rectangle.rt_length%type;
  lr_w         rectangle.rt_width%type;
  lr_s         rectangle.rt_length%type;


begin
   --Alex Gerlants. 05/16/2017. Initial release.
  
   select order_abc_num, order_item_num 
   into   li_order, li_item
   from   ab_job 
   where  ab_job_num = al_job;
  
   select upper(sheet_type), gauge 
   into   ls_shape, lr_gauge
   from   order_item
   where  order_abc_num = li_order 
   and    order_item_num = li_item;
   
   ls_spec := ltrim(rtrim(to_char(lr_gauge, '9.99999')));    
 
   if ltrim(rtrim(ls_shape)) = 'RECTANGLE' then 

      select rt_length, rt_width 
      into   lr_l, lr_w
      from   rectangle 
      where  order_abc_num = li_order
      and    order_item_num = li_item;
      
      ls_spec := ltrim(rtrim(ls_spec)) || ' X ' || ltrim(rtrim(to_char(lr_w, '99999.99999'))) || ' X ' || ltrim(rtrim(to_char(lr_l, '99999.99999')));

   elsif ltrim(rtrim(ls_shape)) = 'PARALLELOGRAM' then   
      select p_length, p_width 
      into   lr_l, lr_w 
      from   parallelogram 
      where  order_abc_num = li_order
      and    order_item_num = li_item;
   
      ls_spec := ltrim(rtrim(ls_spec)) || ' X ' || ltrim(rtrim(to_char(lr_w, '99999.99999'))) || ' X ' || ltrim(rtrim(to_char(lr_l, '99999.99999')));

   elsif ltrim(rtrim(ls_shape)) = 'FENDER' then 
      select fe_side 
      into   lr_l 
      from   fender 
      where  order_abc_num = li_order
      and    order_item_num = li_item;
     
      ls_spec := ltrim(rtrim(ls_spec)) || ' X ' || ltrim(rtrim(to_char(lr_l, '99999.99999')));

   elsif ltrim(rtrim(ls_shape)) = 'CHEVRON' then 
      select ch_length, ch_width
      into   lr_l, lr_w     
      from   chevron 
      where  order_abc_num = li_order
      and    order_item_num = li_item;
      
      ls_spec := ltrim(rtrim(ls_spec)) || ' X ' || ltrim(rtrim(to_char(lr_w, '99999.99999'))) || ' X ' || ltrim(rtrim(to_char(lr_l, '99999.99999')));

    elsif ltrim(rtrim(ls_shape)) = 'CIRCLE' then 
      select c_diameter
      into   lr_l 
      from   circle
      where  order_abc_num = li_order
      and    order_item_num = li_item;
      
      ls_spec := ltrim(rtrim(ls_spec)) || ' X ' || ltrim(rtrim(to_char(lr_l, '99999.99999')));

    elsif ltrim(rtrim(ls_shape)) = 'TRAPEZOID' then 
      select tr_long_length, tr_short_length, tr_width
      into   lr_l, lr_s, lr_w 
      from   trapezoid 
      where  order_abc_num = li_order
      and    order_item_num = li_item;
      
      ls_spec := ltrim(rtrim(ls_spec)) || ' X ' || ltrim(rtrim(to_char(lr_w, '99999.99999'))) || ' X ' || ltrim(rtrim(to_char(lr_s, '99999.99999'))) || ' X ' || ltrim(rtrim(to_char(lr_l, '99999.99999')));

    elsif ltrim(rtrim(ls_shape)) = 'L.TRAPEZOID' then 
      select ltr_long_length, ltr_short_length, ltr_width
      into   lr_l, lr_s, lr_w
      from   left_trapezoid 
      where  order_abc_num = li_order and order_item_num = li_item;
      
      ls_spec := ltrim(rtrim(ls_spec)) || ' X ' || ltrim(rtrim(to_char(lr_w, '99999.99999'))) || ' X ' || ltrim(rtrim(to_char(lr_s, '99999.99999'))) || ' X ' || ltrim(rtrim(to_char(lr_l, '99999.99999')));

    elsif ltrim(rtrim(ls_shape)) = 'R.TRAPEZOID' then 
      select rtr_long_length, rtr_short_length, rtr_width 
      into   lr_l, lr_s, lr_w 
      from   right_trapezoid 
      where order_abc_num = li_order and order_item_num = li_item;
      
      ls_spec := ltrim(rtrim(ls_spec)) || ' X ' || ltrim(rtrim(to_char(lr_w, '99999.99999'))) ||' X ' || ltrim(rtrim(to_char(lr_s, '99999.99999'))) || ' X ' || ltrim(rtrim(to_char(lr_l, '99999.99999')));


   elsif ltrim(rtrim(ls_shape)) = 'REINFORCEMENT' then      
      select re_length, re_width
      into   lr_l, lr_w 
      from   reinforcement 
      where  order_abc_num = li_order and order_item_num = li_item;
      
      ls_spec := ltrim(rtrim(ls_spec)) || ' X ' || ltrim(rtrim(to_char(lr_w, '99999.99999'))) || ' X ' || ltrim(rtrim(to_char(lr_l, '99999.99999')));
      
   elsif ltrim(rtrim(ls_shape)) = 'LIFTGATE' then 
      select li_length, li_width 
      into   lr_l, lr_w 
      from   liftgate_shape 
      where  order_abc_num = li_order and order_item_num = li_item;
      
      ls_spec := ltrim(rtrim(ls_spec)) || ' X ' || ltrim(rtrim(to_char(lr_w, '99999.99999'))) || ' X ' || ltrim(rtrim(to_char(lr_l, '99999.99999')));
      
   else 
       select x_1, x_2 
       into   lr_w, lr_l 
       from   x1_shape
       where  order_abc_num = li_order and order_item_num = li_item;
       
       ls_spec := ltrim(rtrim(ls_spec)) || ' X ' || ltrim(rtrim(to_char(lr_w, '99999.99999'))) || ' X ' || ltrim(rtrim(to_char(lr_l, '99999.99999')));
        
   END IF;

  return ls_spec;

end f_get_job_spec;
  GRANT EXECUTE ON "DBO"."F_GET_JOB_SPEC" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function F_GET_LAST_PROCESS_COIL_DATE
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_LAST_PROCESS_COIL_DATE" (al_ab_job IN ab_job.ab_job_num%TYPE)
  RETURN DATE IS

  RESULT DATE;

  CURSOR coil_cursor IS
    SELECT pc.coil_abc_num, pc.process_date
      FROM process_coil pc
     WHERE pc.ab_job_num = al_ab_job
       AND pc.process_date IS NOT NULL;

  ld_previous DATE;
  ld_current  DATE;
  ld_last     DATE;

BEGIN

  FOR coil IN coil_cursor LOOP
  
    ld_previous := ld_current;
    ld_current  := coil.process_date;
  
    IF ld_previous IS NULL THEN
      ld_last := ld_current;
    ELSE
      IF ld_current > ld_previous THEN
        ld_last := ld_current;
      ELSE
        ld_last := ld_previous;
      END IF;
    END IF;
  
  END LOOP;

  IF ld_last IS NOT NULL THEN
    RESULT := ld_last;
  ELSE
    RESULT := SYSDATE;
  END IF;

  RETURN(RESULT);
END f_get_last_process_coil_date;
  GRANT EXECUTE ON "DBO"."F_GET_LAST_PROCESS_COIL_DATE" TO "AGERLANTS"
