  CREATE OR REPLACE FUNCTION "DBO"."F_GET_MATERIAL" (coil_alloy2 in varchar2, coil_temper in varchar2) return varchar2 is
--   temp    varchar2(30);
  Result  varchar2(30);
BEGIN
  -- Author: Alex Gerlants
  -- Date: May 16, 2016
  -- Concatenate coil_alloy2, ' -', and and coil_temper
  -- If resulting string = ' -', make result = ''
  select coil_alloy2 || ' -' || coil_temper into Result from dual;

  if Result = ' -' then
    Result := '';
  end if;

  -- Result := temp;

  return(Result);
END f_get_material;
