--  DDL for Function F_GET_ONHOLD_DATE
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_ONHOLD_DATE" (i_coil_id in coil.coil_abc_num%type) return date is
  Result date;
begin
  select min(coil_track_date) into Result from coil_track where (coil_abc_num = i_coil_id) and (coil_cur_status = 4);
  
  return(Result);
end f_get_onhold_date;
