--------------------------------------------------------
--  DDL for Function F_GET_ORDER_ITEM_ALLOY_4SKID
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_ORDER_ITEM_ALLOY_4SKID" 
(
   ai_skid_id in sheet_skid.sheet_skid_num%type
) return varchar 

is

ls_skid_ticket_if_whed           sheet_skid.skid_ticket_if_whed%type;
ll_sheet_skid_num_orig           sheet_skid.sheet_skid_num%type;
li_count                         number;
result                           varchar(8);
  
begin
  select    nvl(skid_ticket_if_whed, '')
  into      ls_skid_ticket_if_whed
  from      sheet_skid
  where     sheet_skid.sheet_skid_num = ai_skid_id;

  if length(ls_skid_ticket_if_whed) > 0 then --WH return skid
    --The statement below applies to Novelis WH skids that have skid_ticket_if_whed with suffix 'T1"
    --This applies to non-Novelis skids where sheet_skid_display_num is the same as sheet_skid_num
    select   sheet_skid_num
    into     ll_sheet_skid_num_orig
    from     sheet_skid
    where    sheet_skid_display_num = ls_skid_ticket_if_whed;
  
    select   count(*)
    into     li_count
    from     sheet_skid
             join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
             join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
    where    sheet_skid.sheet_skid_num = ll_sheet_skid_num_orig;
      
    if li_count > 0 then  
      select   nvl(order_item.alloy2, 'N/A')
      into     result
      from     sheet_skid
               join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
               join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
      where    sheet_skid.sheet_skid_num = ll_sheet_skid_num_orig;
    else
      result := 'N/A';
    end if;
  else
    select   nvl(order_item.alloy2, 'N/A')
    into     result
    from     sheet_skid
             join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
             join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
    where    sheet_skid.sheet_skid_num = ai_skid_id;
  end if;
  
  return(Result);
end f_get_order_item_alloy_4skid;

--create or replace public synonym f_get_order_item_alloy_4skid for dbo.f_get_order_item_alloy_4skid;
