li_count                         number;
result                           varchar(8);
  
begin
  select    nvl(skid_ticket_if_whed, '')
  into      ls_skid_ticket_if_whed
  from      sheet_skid
  where     sheet_skid.sheet_skid_num = ai_skid_id;

  if length(ls_skid_ticket_if_whed) > 0 then --WH return skid
  --The statement below applies to Novelis WH skids that have skid_ticket_if_whed with suffix 'T1"
    --This applies to non-Novelis skids where sheet_skid_display_num is the same as sheet_skid_num
    select   sheet_skid_num
    into     ll_sheet_skid_num_orig
    from     sheet_skid
    where    sheet_skid_display_num = ls_skid_ticket_if_whed;
    
    select   count(*)
    into     li_count
    from     sheet_skid
             join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
             join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
    where    sheet_skid.sheet_skid_num = ll_sheet_skid_num_orig;
      
    if li_count > 0 then
      select   order_item.temper
      into     result
      from     sheet_skid
               join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
               join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
      where    sheet_skid.sheet_skid_num = ll_sheet_skid_num_orig;
    else
      result := 'N/A';
    end if;
  else
    select   order_item.temper
    into     result
    from     sheet_skid
             join ab_job on sheet_skid.ab_job_num = ab_job.ab_job_num
             join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
    where    sheet_skid.sheet_skid_num = ai_skid_id;
  end if;
  
  return(Result);
end f_get_order_item_temper_4skid;

--create or replace public synonym f_get_order_item_temper_4skid for dbo.f_get_order_item_temper_4skid;
--------------------------------------------------------
--  DDL for Function F_GET_PART_DIMS_4ORDER_ITEM
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_PART_DIMS_4ORDER_ITEM" 
(
    al_order_abc_num  in order_item.order_abc_num%type,
    al_order_item_num in order_item.order_item_num%type,
    as_what_2return   in varchar2
)
return number

is

  ls_sheet_type     varchar2(18);
  ll_length         number(10,5);
  ll_width          number(10,5);
  ll_return         number(10,5);

begin
  
  ll_length := 0;
  
  select trim(lower(sheet_type))
  into   ls_sheet_type
  from   order_item
  where  order_abc_num = al_order_abc_num
  and    order_item_num = al_order_item_num;

  if ls_sheet_type = 'rectangle' then
      select  nvl(rt_length, 0), nvl(rt_width, 0)
      into    ll_length, ll_width
      from    rectangle
      where   order_abc_num = al_order_abc_num
      and     order_item_num = al_order_item_num;

   elsif ls_sheet_type = 'parallelogram' then
      select   nvl(p_length_minus, 0), nvl(p_width_minus, 0)
      into     ll_length, ll_width
      from     parallelogram
      where    order_abc_num = al_order_abc_num
      and      order_item_num = al_order_item_num;

   elsif ls_sheet_type = 'fender' then
      select   nvl(fe_length, 0), nvl(fe_side, 0)
      into     ll_length, ll_width
      from     fender
      where    order_abc_num = al_order_abc_num
      and      order_item_num = al_order_item_num;

   elsif ls_sheet_type = 'chevron' then
      select  nvl(ch_length, 0), nvl(ch_width, 0)
      into     ll_length, ll_width
      from     chevron
      where    order_abc_num = al_order_abc_num
      and      order_item_num = al_order_item_num;

    elsif ls_sheet_type = 'circle' then
      select   nvl(c_diameter, 0), nvl(c_diameter, 0)
      into     ll_length, ll_width
      from     circle
      where    order_abc_num = al_order_abc_num
      and      order_item_num = al_order_item_num;

    elsif ls_sheet_type = 'trapezoid' then
      select   nvl(tr_long_length, 0), nvl(tr_width, 0)
      into     ll_length, ll_width
      from     trapezoid
      where    order_abc_num = al_order_abc_num
      and      order_item_num = al_order_item_num;

  elsif ls_sheet_type = 'l.trapezoid' then
      select   nvl(ltr_long_length, 0), nvl(ltr_width, 0)
      into     ll_length, ll_width
      from     left_trapezoid
      where    order_abc_num = al_order_abc_num
      and      order_item_num = al_order_item_num;

  elsif ls_sheet_type = 'r.trapezoid' then
      select   nvl(rtr_long_length, 0), nvl(rtr_width, 0)
      into     ll_length, ll_width
      from     right_trapezoid
      where    order_abc_num = al_order_abc_num
      and      order_item_num = al_order_item_num;
      
    elsif ls_sheet_type = 'reinforcement' then
      select   nvl(re_length, 0), nvl(re_width, 0)
      into     ll_length, ll_width
      from     reinforcement
      where    order_abc_num = al_order_abc_num
      and      order_item_num = al_order_item_num;

   elsif ls_sheet_type = 'liftgate' then
      select   nvl(li_length, 0), nvl(li_width, 0)
      into     ll_length, ll_width
      from     liftgate_shape
      where    order_abc_num = al_order_abc_num
      and      order_item_num = al_order_item_num;

   elsif ls_sheet_type = 'other' then
       select  nvl(x_1, 0), nvl(x_2, 0)
       into    ll_length, ll_width
       from    x1_shape
       where   order_abc_num = al_order_abc_num
       and     order_item_num = al_order_item_num;

   else
      ll_length := 0;
      ll_width := 0;
   end if;
   
   if lower(as_what_2return) = 'length' then
     ll_return := ll_length;
   elsif lower(as_what_2return) = 'width' then
     ll_return := ll_width;
   else
     ll_return := 0;
   end if;

   return ll_return;
   
end f_get_part_dims_4order_item;
