--  DDL for Function F_GET_PART_LENGTH_PER_JOB
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_PART_LENGTH_PER_JOB" (al_job in ab_job.ab_job_num%type) return  rectangle.rt_length%type is
  Result rectangle.rt_length%type ;
  s_type order_item.sheet_type%type;
  abc_order_id order_item.order_abc_num%type;
  abc_order_item order_item.order_item_num%type;
begin
  
  select order_item.sheet_type, order_item.order_abc_num, order_item.order_item_num into s_type, abc_order_id, abc_order_item
  from order_item, ab_job
  where ab_job.order_item_num = order_item.order_item_num and
        ab_job.order_abc_num = order_item.order_abc_num and
        ab_job.ab_job_num = al_job;
        
  s_type := Upper(Trim(s_type));
  case s_type
       when 'RECTANGLE' then 
--            dbms_output.put_line('RECTANGLE');
            select rectangle.rt_length into Result from rectangle
            where rectangle.order_abc_num = abc_order_id and
                  rectangle.order_item_num = abc_order_item;
       when 'CHEVRON' then
--            dbms_output.put_line('CHEVRON');
            select chevron.ch_length into Result from chevron
            where chevron.order_abc_num = abc_order_id and
                  chevron.order_item_num = abc_order_item;
       when 'CIRCLE' then
--            dbms_output.put_line('CIRCLE');
            select circle.c_diameter into Result from circle
            where circle.order_abc_num = abc_order_id and
                  circle.order_item_num = abc_order_item;
       when 'FENDER' then
--            dbms_output.put_line('FENDER');
            select fender.fe_length into Result from fender
            where fender.order_abc_num = abc_order_id and
                  fender.order_item_num = abc_order_item;
       when 'LIFTGATE' then
--            dbms_output.put_line('LIFTGATE');
            select liftgate_shape.li_length into Result from liftgate_shape
            where liftgate_shape.order_abc_num = abc_order_id and
                  liftgate_shape.order_item_num = abc_order_item;
       when 'OTHER' then
--            dbms_output.put_line('OTHER');
            select x1_shape.x_2  into Result from x1_shape
            where x1_shape.order_abc_num = abc_order_id and
                  x1_shape.order_item_num = abc_order_item;
       when 'PARALLELOGRAM' then
--            dbms_output.put_line('PARALLELOGRAM');
            select parallelogram.p_length  into Result from parallelogram
            where parallelogram.order_abc_num = abc_order_id and
                  parallelogram.order_item_num = abc_order_item;
       when 'REINFORCEMENT' then
--          dbms_output.put_line('REINFORCEMENT');
            select reinforcement.re_length  into Result from reinforcement
            where reinforcement.order_abc_num = abc_order_id and
                  reinforcement.order_item_num = abc_order_item;
       when 'TRAPEZOID' then
--            dbms_output.put_line('TRAPEZOID');
            select trapezoid.tr_long_length into Result from trapezoid
            where trapezoid.order_abc_num = abc_order_id and
                  trapezoid.order_item_num = abc_order_item;
  end case;

  return(Result);
end f_get_part_length_per_job;
  GRANT EXECUTE ON "DBO"."F_GET_PART_LENGTH_PER_JOB" TO "AGERLANTS"
