  CREATE OR REPLACE FUNCTION "DBO"."F_GET_POSITION" (coil_pos varchar2) return varchar2 is
  /* This function gets the original coil number from the string combined with 
  coil number and test sample position number
  */
ls_coil_pos varchar2(30);
ls_pos varchar2(8);  

li_length integer;

begin
ls_coil_pos := coil_pos;

li_length := length(ls_coil_pos);

ls_pos := substr(ls_coil_pos, li_length - 1, 2 ); 

return ls_pos;
end f_get_position;
