  CREATE OR REPLACE FUNCTION "DBO"."F_GET_SCRAP_ACT_WT_PER_JOB" 
 ( 
    al_ab_job_num  ab_job.ab_job_num%type    
 )
  return integer
  
is

  ll_total_act_scrap_wt_4job   number(8);

begin
  
