  CREATE OR REPLACE FUNCTION "DBO"."F_GET_SHIPMENT_GROSSW" (PACKING_ID in shipment.packing_list%type) return  sheet_skid.sheet_net_wt%type is
  Result sheet_skid.sheet_net_wt%type;
begin
  SELECT SUM(sheet_skid.sheet_net_wt)+SUM(sheet_skid.sheet_tare_wt)
INTO Result FROM sheet_skid, sheet_packing_item, shipment
WHERE SHIPMENT.PACKING_LIST =SHEET_PACKING_ITEM.PACKING_LIST and
      SHEET_PACKING_ITEM.SHEET_SKID_NUM = SHEET_SKID.SHEET_SKID_NUM and
      SHIPMENT.PACKING_LIST = PACKING_ID;
  
  return(Result);
end F_GET_SHIPMENT_GROSSW;
  GRANT EXECUTE ON "DBO"."F_GET_SHIPMENT_GROSSW" TO "AGERLANTS"
