--  DDL for Function F_GET_SHIPMENT_GROSSW_ALL
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_SHIPMENT_GROSSW_ALL" (PACKING_ID in shipment.packing_list%type) return  sheet_skid.sheet_net_wt%type is
  Result sheet_skid.sheet_net_wt%type :=0;

skid_sum sheet_skid.sheet_net_wt%type :=0;
scrap_sum scrap_skid.scrap_net_wt%type :=0;
coil_sum coil.net_wt%type :=0;

begin

SELECT NVL(SUM(sheet_skid.sheet_net_wt),0)+NVL(SUM(sheet_skid.sheet_tare_wt),0)
INTO skid_sum FROM sheet_skid, sheet_packing_item, shipment
WHERE SHIPMENT.PACKING_LIST =SHEET_PACKING_ITEM.PACKING_LIST and
      SHEET_PACKING_ITEM.SHEET_SKID_NUM = SHEET_SKID.SHEET_SKID_NUM and
      SHIPMENT.PACKING_LIST = PACKING_ID;

SELECT NVL(SUM(scrap_skid.scrap_net_wt),0)+NVL(SUM(scrap_skid.scrap_tare_wt),0)
INTO scrap_sum FROM scrap_skid, scrap_packing_item, shipment
WHERE SHIPMENT.PACKING_LIST =SCRAP_PACKING_ITEM.PACKING_LIST and
      SCRAP_PACKING_ITEM.SCRAP_SKID_NUM = SCRAP_SKID.SCRAP_SKID_NUM and
      SHIPMENT.PACKING_LIST = PACKING_ID;

SELECT NVL(SUM(coil.net_wt),0)
INTO coil_sum FROM coil, reject_coil_packing_item, shipment
WHERE SHIPMENT.PACKING_LIST =REJECT_COIL_PACKING_ITEM.PACKING_LIST and
      REJECT_COIL_PACKING_ITEM.COIL_ABC_NUM = COIL.COIL_ABC_NUM and
      SHIPMENT.PACKING_LIST = PACKING_ID;

 Result := skid_sum + scrap_sum + coil_sum;

return(Result);
end F_GET_SHIPMENT_GROSSW_ALL;
