--  DDL for Function F_GET_SHIPMENT_NUM_OF_SKIDS
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_SHIPMENT_NUM_OF_SKIDS" (packing_id in shipment.packing_list%type)
return  integer is

result number(4) :=0;

skid_count   number(4) :=0;
scrap_count  number(4) :=0;
coil_count   number(4) :=0;

begin

--Alex Gerlants. 04/27/2017

    select count(distinct sheet_skid.sheet_skid_num)
    into   skid_count
    from   shipment
           join sheet_packing_item on sheet_packing_item.packing_list = shipment.packing_list
           join sheet_skid on sheet_skid.sheet_skid_num = sheet_packing_item.sheet_skid_num
    where  shipment.packing_list = packing_id;

    select count(distinct scrap_skid.scrap_skid_num)
    into   scrap_count
    from   shipment
           join scrap_packing_item on scrap_packing_item.packing_list = shipment.packing_list
           join scrap_skid on scrap_skid.scrap_skid_num = scrap_packing_item.scrap_skid_num
    where  shipment.packing_list = packing_id;

    select count(reject_coil_packing_item.coil_abc_num)
    into   coil_count
    from   shipment
           join reject_coil_packing_item on reject_coil_packing_item.packing_list = shipment.packing_list
           join coil on coil.coil_abc_num = reject_coil_packing_item.coil_abc_num
    where  shipment.packing_list = packing_id;

    result := skid_count + scrap_count + coil_count;

    return(Result);

end f_get_shipment_num_of_skids;
  GRANT EXECUTE ON "DBO"."F_GET_SHIPMENT_NUM_OF_SKIDS" TO "AGERLANTS"
