--  DDL for Function F_GET_SISCO_CODE
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_SISCO_CODE" 
(
       al_des_sh_cust_id shipment.des_sh_cust_id%TYPE
)
       return varchar2
is

  /*
     Alex Gerlants. Communication_Code_Error_Message. 11/01/2017.
	   Get communication (Sisco) code for the al_des_sh_cust_id.
	   This function is called (as of now) from f_edi_desadv2 and f_edi_desadv_bolt.
  */
  ll_count              number;
  ls_communication_code varchar2(18);

begin
  
  select count(*)
  into   ll_count
  from   customer_system
  where  customer_id = al_des_sh_cust_id;

  if ll_count > 0 then
    select nvl(communication_code, 'unknown')
    into   ls_communication_code
    from   customer_system
    where  customer_id = al_des_sh_cust_id;
  else
    ls_communication_code := 'unknown';  --Ship user will get message "Communication code is NOT set up in table customer_system for Destination Customer ..."
  end if;

  return ls_communication_code;
  
end f_get_sisco_code;
