--  DDL for Function F_GET_SKID_DURATION
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_SKID_DURATION" (i_skid_id in sheet_skid.sheet_skid_num%type) return integer is
  Result integer;
  temp date;
  skidstatus integer;
begin
  SELECT skid_sheet_status, sheet_skid.skid_date into skidstatus, temp
  FROM sheet_skid 
  WHERE sheet_skid_num=  i_skid_id;
  
  if (skidstatus = 11) or (skidstatus = 0) then Result := 0;
  else 
       select (sysdate - NVL(max(log_date), temp)) into Result from skid_track
       WHERE sheet_skid_num =  i_skid_id; 
  end if;
  
  return(Result);
end f_get_skid_duration;
  GRANT EXECUTE ON "DBO"."F_GET_SKID_DURATION" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function F_GET_SKID_LATEST_CHANGE_DATE
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_SKID_LATEST_CHANGE_DATE" (i_skid_id in sheet_skid.sheet_skid_num%type) return date is
  Result date;
  temp date;
begin
  SELECT skid_date into temp
  FROM sheet_skid 
  WHERE sheet_skid_num=  i_skid_id;
  
  select NVL(max(log_date), temp) into Result from skid_track
       WHERE sheet_skid_num=  i_skid_id;
  return(Result);

end f_get_skid_latest_change_date;
  GRANT EXECUTE ON "DBO"."F_GET_SKID_LATEST_CHANGE_DATE" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function F_GET_SKID_LIST_4BOL_SPEC
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_SKID_LIST_4BOL_SPEC" 
(
  packing_list_in    in shipment.packing_list%type,
  alloy2_in          in order_item.alloy2%type,
  temper_in          in order_item.temper%type,
  order_item_desc_in in order_item.order_item_desc%type
) return varchar2 is

  spec_in           varchar2(100);
  ls_skid_list_out  varchar2(1000);
  li_counter        number;
  li_loop_counter   number;
  ls_sheet_skid_num varchar2(12);
  
  cursor skid_numbers is
  select distinct nvl(to_char(sheet_skid.sheet_skid_num), '') sheet_skid_num
  from   sheet_packing_item
         join sheet_skid on sheet_skid.sheet_skid_num = sheet_packing_item.sheet_skid_num
         join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
         join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
         join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
         join shipment on shipment.packing_list = sheet_packing_item.packing_list
         join customer c_cust on c_cust.customer_id = shipment.customer_id
         join customer c_dest on c_dest.customer_id = shipment.des_sh_cust_id
  where  sheet_packing_item.packing_list = packing_list_in
  and    order_item.alloy2 || '-' || order_item.temper || ' ' || order_item.order_item_desc = spec_in;

begin
  ls_skid_list_out := ' ';
  spec_in := alloy2_in || '-' || temper_in || ' ' || order_item_desc_in;

  select count(*)
  into   li_counter
  from   sheet_packing_item
         join sheet_skid on sheet_skid.sheet_skid_num = sheet_packing_item.sheet_skid_num
         join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
         join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
         join order_item on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
         join shipment on shipment.packing_list = sheet_packing_item.packing_list
         join customer c_cust on c_cust.customer_id = shipment.customer_id
         join customer c_dest on c_dest.customer_id = shipment.des_sh_cust_id
  where  sheet_packing_item.packing_list = packing_list_in
  and    order_item.alloy2 || '-' || order_item.temper || ' ' || order_item.order_item_desc = spec_in;

  if li_counter > 0 then
     li_loop_counter := 0;  
  
     for skid_rec in skid_numbers loop
       li_loop_counter := li_loop_counter + 1;  
     
       ls_sheet_skid_num := skid_rec.sheet_skid_num;
       
       if li_loop_counter = 1 then
         ls_skid_list_out := ls_sheet_skid_num;
       else
         --if li_loop_counter = 4 or li_loop_counter = 7 or li_loop_counter = 10 or li_loop_counter = 19 then
         --    ls_skid_list_out := ls_skid_list_out || chr(13);
         --end if;
         
         --if li_loop_counter = 4 or li_loop_counter = 7 or li_loop_counter = 10 or li_loop_counter = 13 or li_loop_counter = 16 or li_loop_counter = 19 or li_loop_counter = 22 or li_loop_counter = 25 or li_loop_counter = 28 or li_loop_counter = 31 or li_loop_counter = 34 or li_loop_counter = 37 or li_loop_counter = 40 or li_loop_counter = 43 or li_loop_counter = 46 or li_loop_counter = 49 or li_loop_counter = 52 or li_loop_counter = 55 or li_loop_counter = 58 or li_loop_counter = 61 or li_loop_counter = 64 or li_loop_counter = 67 or li_loop_counter = 70 or li_loop_counter = 73 or li_loop_counter = 76 or li_loop_counter = 79 or li_loop_counter = 82 then 
         if li_loop_counter = 10 or li_loop_counter = 19 or li_loop_counter = 28 or li_loop_counter = 37 or li_loop_counter = 46 or li_loop_counter = 55 or li_loop_counter = 64 or li_loop_counter = 73 or li_loop_counter = 82 or li_loop_counter = 91 or li_loop_counter = 100 or li_loop_counter = 109 or li_loop_counter = 118 or li_loop_counter = 127 or li_loop_counter = 136 or li_loop_counter = 145 or li_loop_counter = 154 then 
             ls_skid_list_out := ls_skid_list_out || ls_sheet_skid_num;
         else
             ls_skid_list_out := ls_skid_list_out || ', ' || ls_sheet_skid_num;
         end if;
         
         --if li_loop_counter = 3 or li_loop_counter = 6 or li_loop_counter = 9 or li_loop_counter = 12 or li_loop_counter = 15 or li_loop_counter = 18 or li_loop_counter = 21 or li_loop_counter = 24 or li_loop_counter = 27 or li_loop_counter = 30 or li_loop_counter = 33 or li_loop_counter = 36 or li_loop_counter = 39 or li_loop_counter = 42 or li_loop_counter = 45 or li_loop_counter = 48 or li_loop_counter = 51 or li_loop_counter = 54 or li_loop_counter = 57 or li_loop_counter = 60 or li_loop_counter = 63 or li_loop_counter = 66 or li_loop_counter = 69 or li_loop_counter = 72 or li_loop_counter = 75 or li_loop_counter = 78 or li_loop_counter = 81 then
         if li_loop_counter = 9 or li_loop_counter = 18 or li_loop_counter = 27 or li_loop_counter = 36 or li_loop_counter = 45 or li_loop_counter = 54 or li_loop_counter = 63 or li_loop_counter = 72 or li_loop_counter = 81 or li_loop_counter = 90 or li_loop_counter = 99 or li_loop_counter = 108 or li_loop_counter = 117 or li_loop_counter = 126 or li_loop_counter = 135 or li_loop_counter = 144 or li_loop_counter = 153 then
           --if li_loop_counter < li_counter then
                 ls_skid_list_out := ls_skid_list_out || chr(13);
           --end if;
         end if;
       end if;
     end loop;
  end if;

  --ls_skid_list_out := ls_skid_list_out || chr(13) || chr(13) || chr(13);

  return ls_skid_list_out;
end f_get_skid_list_4bol_spec;
  GRANT EXECUTE ON "DBO"."F_GET_SKID_LIST_4BOL_SPEC" TO "AGERLANTS"
