--  DDL for Function F_GET_USE_PACKAGE_NUM
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_USE_PACKAGE_NUM" (al_sheet_skid_num in sheet_skid.sheet_skid_num%type)
return varchar2 is

FunctionResult  varchar2(1);


begin

  select   distinct lower(nvl(customer.use_package_num, 'n'))
  into     FunctionResult
  from     sheet_skid
           join ab_job on ab_job.ab_job_num = sheet_skid.ab_job_num
           join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
           join customer on customer.customer_id = customer_order.orig_customer_id
  where    sheet_skid.sheet_skid_num = al_sheet_skid_num;

  return(FunctionResult);

end f_get_use_package_num;
