--  DDL for Function F_GET_WIDTH_4ORDER_ITEM
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_GET_WIDTH_4ORDER_ITEM" 
(
    al_order_abc_num  in order_item.order_abc_num%type,
    al_order_item_num in order_item.order_item_num%type
)
return number

is

  ls_sheet_type varchar2(18);
  ll_width      number(10,5);

begin
  
  ll_width := 0;
  
  select trim(lower(sheet_type))
  into   ls_sheet_type
  from   order_item
  where  order_abc_num = al_order_abc_num
  and    order_item_num = al_order_item_num;

  if ls_sheet_type = 'rectangle' then
      select  nvl(rt_width, 0)
      into    ll_width
      from    rectangle
      where   order_abc_num = al_order_abc_num
      and     order_item_num = al_order_item_num;

   elsif ls_sheet_type = 'parallelogram' then
      select   nvl(p_width, 0)
      into     ll_width
      from     parallelogram
      where    order_abc_num = al_order_abc_num
      and      order_item_num = al_order_item_num;

   elsif ls_sheet_type = 'fender' then
      select   nvl(fe_side, 0)
      into     ll_width
      from     fender
      where    order_abc_num = al_order_abc_num
      and      order_item_num = al_order_item_num;

   elsif ls_sheet_type = 'chevron' then
       select  nvl(ch_width, 0)
      into     ll_width
      from     chevron
      where    order_abc_num = al_order_abc_num
      and      order_item_num = al_order_item_num;

    elsif ls_sheet_type = 'circle' then
       select  nvl(c_diameter, 0)
      into     ll_width
      from     circle
      where    order_abc_num = al_order_abc_num
      and      order_item_num = al_order_item_num;

    elsif ls_sheet_type = 'trapezoid' then
      select   nvl(tr_width, 0)
      into     ll_width
      from     trapezoid
      where    order_abc_num = al_order_abc_num
      and      order_item_num = al_order_item_num;

  elsif ls_sheet_type = 'l.trapezoid' then
      select   nvl(ltr_width, 0)
      into     ll_width
      from     left_trapezoid
      where    order_abc_num = al_order_abc_num
      and      order_item_num = al_order_item_num;

  elsif ls_sheet_type = 'r.trapezoid' then
      select   nvl(rtr_width, 0)
      into     ll_width
      from     right_trapezoid
      where    order_abc_num = al_order_abc_num
      and      order_item_num = al_order_item_num;
      
   elsif ls_sheet_type = 'reinforcement' then
      select   nvl(re_width, 0)
      into     ll_width
      from     reinforcement
      where    order_abc_num = al_order_abc_num
      and      order_item_num = al_order_item_num;

   elsif ls_sheet_type = 'liftgate' then
      select   nvl(li_width, 0)
      into     ll_width
      from     liftgate_shape
      where    order_abc_num = al_order_abc_num
      and      order_item_num = al_order_item_num;

   elsif ls_sheet_type = 'other' then
       select  nvl(x_2, 0)
       into    ll_width
       from    x1_shape
       where   order_abc_num = al_order_abc_num
       and     order_item_num = al_order_item_num;

   else
      ll_width := 0;
   end if;

   return ll_width;
   
end f_get_width_4order_item;
