--  DDL for Function F_HAVE_2CREATE_870_4JOB
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_HAVE_2CREATE_870_4JOB" (al_ab_job_num in ab_job.ab_job_num%type) return number is

  result number :=0;

begin
 
  result := 0;
 
  select  count(*)
  into    result
  from    ab_job
          join customer_order on customer_order.order_abc_num = ab_job.order_abc_num
          join customer_edi on customer_edi.customer_id = customer_order.orig_customer_id
  where   ab_job.ab_job_num = al_ab_job_num
  and     customer_edi.customer_id = customer_order.orig_customer_id
  and     customer_edi.edi_type_id = 870
  and     ltrim(rtrim(upper(customer_edi.customer_edi_name))) = 'ORDER_STATUS'
  and     ltrim(rtrim(upper(customer_edi.customer_edi_desc))) = '870 PER JOB';

  return (result);
   
           
end f_have_2create_870_4job;

--create or replace public synonym f_have_2create_870_4job for dbo.f_have_2create_870_4job;
