--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_IS_CONSTELLIUM" (al_packing_list in shipment.packing_list%TYPE)
return integer is

  FunctionResult           integer;
  ls_customer_short_name   customer.customer_short_name%TYPE;

begin
  
  select lower(customer.customer_short_name)
  into   ls_customer_short_name
  from   shipment
         join customer on customer.customer_id = shipment.customer_id
  where  shipment.packing_list = al_packing_list;
  
  if ls_customer_short_name like '%constellium%' then
    FunctionResult := 1;
  else
    FunctionResult := 0;
  end if;

  return(FunctionResult);
end f_is_constellium;
