--  DDL for Function F_JOB_PROCESSED_WT
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_JOB_PROCESSED_WT" (a_job_num in ab_job.ab_job_num%type) return Integer is 
  Result Integer := 0; 
  coil_id coil.coil_abc_num%type; 
   
  Cursor c_coil is  
  SELECT DISTINCT coil_abc_num 
  FROM process_coil 
  WHERE ab_job_num = a_job_num; 
 
begin 
  FOR  c IN c_coil LOOP 
       Result := result + f_coil_in_job_processed_wt(c.coil_abc_num, a_job_num); 
  END LOOP; 
 
  return(Result); 
end f_job_processed_wt;
  GRANT EXECUTE ON "DBO"."F_JOB_PROCESSED_WT" TO "AGERLANTS"
