--------------------------------------------------------
--  DDL for Function F_SEND_LUBE_WEIGHT
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_SEND_LUBE_WEIGHT" (par_coil_abc_num in coil_lube_weight.coil_abc_num%type) return integer is

  result integer := 1;
  /* Returns:   Integer
               1 = if it succeeds
              -1 = if system error occurs
              -2 = if errors with UTL_FILE

 */
  temp varchar2(32767);

  ls_st_line_num varchar2(5);
  li_st_line_num integer;

-- li_send_statue integer;
  li_count integer;
  li_edi_863_id integer;
  ls_today VARCHAR2(20) := to_char(SYSDATE, 'yyyymmdd');

  i integer;
  type edi_863_tabletype is table of varchar2(32767) index by binary_integer;
  edi_863 edi_863_tabletype;
  j binary_integer := 0;

-- temp_string varchar(2);
  cloop_remaining LONG;
  pos integer;
  done boolean;

  ln_lube_weight number;

  edi_location varchar2(50):='/templar/templar/incoming/senddata';
  edi_file varchar2 (50) := 'edi_out.txt';
  edi_file_prefix varchar2 (50) := 'S_alcan_';
  edi_file_handle UTL_FILE.FILE_TYPE;

  cursor unsend_edi863_by_coil is
  select edi_file
  from edi_file_863
  where coil_abc_num = par_coil_abc_num and -- (send_status = 0) );
        ( edi_863_id = (select max(edi_863_id) from edi_file_863
                       where coil_abc_num = par_coil_abc_num) );

begin

  --check if there are any not-sent-yet EDI863 files waiting for lube weight to send.
  SELECT count(*) INTO li_count FROM edi_file_863
  WHERE ( (coil_abc_num = par_coil_abc_num ));-- and (send_status = 0) );

  --average the lube weights of the same coil
  select avg(lube_weight) into ln_lube_weight from lube_weight
  where coil_abc_num = par_coil_abc_num;
      /*  and process_date = (select max(process_date) from lube_weight
                           where coil_abc_num = par_coil_abc_num);*/

  --if some EDI863 waiting for the lube wieght, insert the lube weight segment and send it.
  if li_count > 0 then
     for cloop in unsend_edi863_by_coil loop
         SELECT edi_file_id_seq.NEXTVAL INTO li_edi_863_id FROM DUAL;

-- Changed file suffix on 07/27/2016 to accomodate GXS change to SFTP - Patrick Reynolds
--       edi_file := 'S_alcan_' || to_char(li_edi_863_id) || '.863';
         edi_file := edi_file_prefix || to_char(li_edi_863_id) || '.edi';
         edi_file_handle :=utl_file.fopen(edi_location,edi_file,'W');

         cloop_remaining := cloop.edi_file;
         done := false;
         j := 0;

         --separate all lines in edi_file_863.edi_file.
         while NOT done loop
               pos := instr(cloop_remaining, '|');--the line in edi_file_863.edi_file are delimited by "|".

               if pos = length(cloop_remaining) then
                  done := true;
               end if;

               edi_863(j) := substr(cloop_remaining, 1, pos-1);
              --temp := edi_863(j);
               j := j+1;
               cloop_remaining := substr(cloop_remaining, pos+1);
         end loop;

         --move forward the last 5 lines for the insertion of the lube weight segment
         edi_863(j+1) := edi_863(j-4);
         edi_863(j+2) := edi_863(j-3);
         --add 5 to "SE*num...", because there are 5 more lines for lube weight segment.
         ls_st_line_num := substr(edi_863(j+2), 4, instr(edi_863(j+2), '*', 1, 2)-4 );
         li_st_line_num := to_number(ls_st_line_num) + 5;
         temp := replace(edi_863(j+2), ls_st_line_num, to_char(li_st_line_num));
         edi_863(j+2) := temp;
         edi_863(j+3) := edi_863(j-2);
         edi_863(j+4) := edi_863(j-1);
         --insert the lube weight segment.
         edi_863(j-4) := 'CID**71';
         edi_863(j-3) := 'PSD*******23';
         edi_863(j-2) := 'PSD*******16';
         edi_863(j-1) := 'TMD*32*AA*TWO****'||ls_today;
         edi_863(j) := 'MEA*TR**'||TO_CHAR(ln_lube_weight,'FM990.000000')||'*MF';

         --write edi to file
         FOR i IN 0..j+4 LOOP
             temp := edi_863(i);
             utl_file.put_line(edi_file_handle,edi_863(i));
         END LOOP;

         utl_file.fclose(edi_file_handle);

     end loop;
     /*
     --update send_status from 0 to 1
     update edi_file_863
     set send_status = 1 where (coil_abc_num = par_coil_abc_num) and (send_status = 0);
     */
  end if;

  update coil_lube_weight
  set set_ready_time = sysdate, READY_STATUS = 1 where coil_abc_num = par_coil_abc_num;
  if SQL%NOTFOUND then --update failed
     insert into coil_lube_weight(coil_abc_num, source_customer_id, ready_status, set_ready_time)
     values(par_coil_abc_num, 0, 1, sysdate);
  end if;

  commit;

  return result;

  EXCEPTION
     WHEN dup_val_on_index then
     rollback;
     return -100;
     WHEN UTL_FILE.INVALID_PATH THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN -2;
     WHEN UTL_FILE.INVALID_MODE THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN -2;
    WHEN UTL_FILE.INVALID_OPERATION THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN -2;
    WHEN UTL_FILE.WRITE_ERROR THEN
      UTL_FILE.FCLOSE_ALL;
      RETURN -2;
    WHEN OTHERS THEN
     UTL_FILE.FCLOSE_ALL;
      RETURN -1;

end F_SEND_LUBE_WEIGHT;
  GRANT EXECUTE ON "DBO"."F_SEND_LUBE_WEIGHT" TO "AGERLANTS"
