--  DDL for Function F_SHEET_OR_SCRAP_SHIPMENT
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_SHEET_OR_SCRAP_SHIPMENT" (al_packing_list shipment.packing_list%type)
  return varchar2 
  
  is
  
  li_count_sheet        number;
  li_count_scrap        number;
  FunctionResult        varchar2(5);
  
begin
  select count(*)
  into   li_count_sheet
  from   customer_order
         join order_item on customer_order.order_abc_num = order_item.order_abc_num
         join ab_job on order_item.order_abc_num = ab_job.order_abc_num and order_item.order_item_num = ab_job.order_item_num
         join sheet_skid on ab_job.ab_job_num = sheet_skid.ab_job_num
         join sheet_packing_item on sheet_skid.sheet_skid_num = sheet_packing_item.sheet_skid_num
         join shipment on shipment.packing_list = sheet_packing_item.packing_list
  where  shipment.packing_list = al_packing_list;
  
  select count(*)
  into   li_count_scrap
  from   scrap_skid
         join scrap_packing_item on scrap_skid.scrap_skid_num = scrap_packing_item.scrap_skid_num
         join shipment on shipment.packing_list = scrap_packing_item.packing_list
  where  shipment.packing_list = al_packing_list;
  
  if li_count_sheet > 0 and li_count_scrap > 0 then
    FunctionResult := 'BOTH';
  elsif li_count_sheet > 0 then
    FunctionResult := 'SHEET';
  else --li_count_scrap > 0
    FunctionResult := 'SCRAP';
  end if;
  
  return(FunctionResult);
end f_sheet_or_scrap_shipment;

--create or replace public synonym f_sheet_or_scrap_shipment for dbo.f_sheet_or_scrap_shipment;
