--  DDL for Function F_UNIX_FILE_EXISTS
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."F_UNIX_FILE_EXISTS" (as_directory in varchar2, as_file_name in varchar2)
  return number is

/*

utl.fgetattr(
   location    IN VARCHAR2,
   filename    IN VARCHAR2,
   exists      OUT BOOLEAN,
   file_length OUT NUMBER,
   blocksize   OUT NUMBER);

Parameters     Description
----------     -----------
location       Directory location of the source file, a DIRECTORY_NAME from the ALL_DIRECTORIES view (case sensitive)
filename	     The name of the source file to be copied
exists	       A BOOLEAN for whether or not the file exists
file_length	   The length of the file in bytes. NULL if file does not exist.
blocksize	     The file system block size in bytes. NULL if the file does not exist.

edi_loc        varchar2(50) := '/templar/templar/incoming/senddata';

*/

lb_exists          boolean;
li_file_length     integer;
ln_blocksize       number;

ln_result          number;

begin

  utl_file.fgetattr(as_directory, as_file_name, lb_exists, li_file_length, ln_blocksize);


  if lb_exists then
      ln_result := 1;
   else
      ln_result := 0;
   end if;

   --return nvl(li_file_length, 0);
   return ln_result;

end f_unix_file_exists;
/* Alex Gerlants. 09/07/2016. End *
/

  GRANT EXECUTE ON "DBO"."F_UNIX_FILE_EXISTS" TO "AGERLANTS"
