--  DDL for Function RESET_PROCESS_COIL_AND_COIL
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."RESET_PROCESS_COIL_AND_COIL" (p_ab_job_num in ab_job.ab_job_num%type) return integer is
--Given a ab_job_num,
--using this script to update:
-- 1. process_coil: process_coil_status to 2 (New), process_quanity to its initial wt
-- 2. coil: coil_status to 2 (New), net_wt_blance to its initial wt

  Result integer := 1;
  l_coil_net_wt coil.net_wt%type;
  l_net_wt_balance coil.net_wt_balance%type;
  l_coil_status coil.coil_status%type;
     
  cursor coils_applied  is
  select process_coil.coil_abc_num
  from process_coil
  where process_coil.ab_job_num = p_ab_job_num;
  
begin

for coils_applied_rec in coils_applied loop
   select coil.net_wt into l_coil_net_wt
   from coil
   where coil.coil_abc_num = coils_applied_rec.coil_abc_num;
   
   --update process_coil
   update process_coil
   set process_coil.process_coil_status = 2, process_coil.process_quantity = l_coil_net_wt
   where process_coil.ab_job_num = p_ab_job_num 
     and process_coil.coil_abc_num = coils_applied_rec.coil_abc_num;
     
   --update coil
   select coil.coil_status, coil.net_wt_balance into l_coil_status, l_net_wt_balance
   from coil
   where coil.coil_abc_num = coils_applied_rec.coil_abc_num;
   
   --if coil.coil status and coil.net_wt_balance have been reset, skid this step
   if NOT( (l_coil_status = 2) and (l_net_wt_balance = l_coil_net_wt) ) then   
     update coil
     set coil.coil_status = 2, net_wt_balance = l_coil_net_wt
     where coil.coil_abc_num = coils_applied_rec.coil_abc_num;
  end if;
  
end loop;

commit;
  
  return(Result);
end reset_process_coil_and_coil;
  GRANT EXECUTE ON "DBO"."RESET_PROCESS_COIL_AND_COIL" TO "AGERLANTS"
--------------------------------------------------------
--  DDL for Function SQL_TO_CSV
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."SQL_TO_CSV" ( p_query     in varchar2,
                                      p_separator in varchar2 default ',',
                                      p_dir       in varchar2 ,
                                      p_filename  in varchar2 )
return number
is
    l_output        utl_file.file_type;
    l_theCursor     integer default dbms_sql.open_cursor;
    l_columnValue   varchar2(2000);
    l_status        integer;
    l_colCnt        number default 0;
    l_separator     varchar2(10) default '';
    l_cnt           number default 0;
begin
    l_output := utl_file.fopen( p_dir, p_filename, 'w' );

    dbms_sql.parse(  l_theCursor,  p_query, dbms_sql.native );

    for i in 1 .. 255 loop
        begin
            dbms_sql.define_column( l_theCursor, i, l_columnValue, 2000 );
            l_colCnt := i;
        exception
            when others then
                if ( sqlcode = -1007 ) then exit;
                else
                    raise;
                end if;
        end;
    end loop;

    dbms_sql.define_column( l_theCursor, 1, l_columnValue, 2000 );

    l_status := dbms_sql.execute(l_theCursor);

    loop
        exit when ( dbms_sql.fetch_rows(l_theCursor) <= 0 );
        l_separator := '';
        for i in 1 .. l_colCnt loop
            dbms_sql.column_value( l_theCursor, i, l_columnValue );
            utl_file.put( l_output, l_separator || l_columnValue );
            l_separator := p_separator;
        end loop;
        utl_file.new_line( l_output );
        l_cnt := l_cnt+1;
    end loop;
    dbms_sql.close_cursor(l_theCursor);

    utl_file.fclose( l_output );
    return l_cnt;
end SQL_TO_CSV;
  GRANT EXECUTE ON "DBO"."SQL_TO_CSV" TO "AGERLANTS"
