--  DDL for Function UPDATE_SHIFT_DT_TOTAL
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "DBO"."UPDATE_SHIFT_DT_TOTAL" (p_shift_id shift.shift_num%type) return integer is
  Result integer;
  total shift.dt_total%type;
  cursor mid is
  select shift.shift_num from shift
  where shift.schedule_type = 3 and shift.line_num = 6;
begin
  /*
  for test in mid loop
      select 86400 * sum(dt_instance.ending_time - dt_instance.starting_time) into total
      from dt_instance
      where dt_instance.shift_num = test.shift_num;
      
      update shift set shift.dt_total = total
      where shift.shift_num = test.shift_num;
      
  
  
  end loop;
  commit;
  */
  
  select 86400 * sum(dt_instance.ending_time - dt_instance.starting_time) into total
  from dt_instance
  where dt_instance.shift_num = p_shift_id;
  
  update shift set shift.dt_total = total
  where shift.shift_num = p_shift_id;
  commit;
  
  return(total);
end update_shift_dt_total;
